/*
 * blink8.c:
 *	Simple sequence over the first 8 GPIO pins - LEDs
 *	Aimed at the Gertboard, but it's fairly generic.
 *
 * Copyright (c) 2012-2013 Gordon Henderson.
 ***********************************************************************
