// Constants
#define NUM_PINS 8

// Global variables
static volatile uint32_t interrupt_counts[NUM_PINS];
static volatile bool program_running = true;

// Function prototypes
void interrupt_handler(void);
void signal_handler(int signal);

// Interrupt handlers for each pin
void interrupt_handler_0(void) { ++interrupt_counts[0]; }
void interrupt_handler_1(void) { ++interrupt_counts[1]; }
void interrupt_handler_2(void) { ++interrupt_counts[2]; }
void interrupt_handler_3(void) { ++interrupt_counts[3]; }
void interrupt_handler_4(void) { ++interrupt_counts[4]; }
void interrupt_handler_5(void) { ++interrupt_counts[5]; }
void interrupt_handler_6(void) { ++interrupt_counts[6]; }
void interrupt_handler_7(void) { ++interrupt_counts[7]; }

// Array of interrupt handler function pointers
void (*interrupt_handlers[NUM_PINS])(void) = {
    interrupt_handler_0, interrupt_handler_1, interrupt_handler_2, interrupt_handler_3,
    interrupt_handler_4, interrupt_handler_5, interrupt_handler_6, interrupt_handler_7
};

int main(int argc, char *argv[]) {
    int pin;

    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error initializing WiringPi: %s\n", strerror(errno));
        return EXIT_FAILURE;
    }

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Set interrupt edge and attach interrupt service routines
    for (pin = 0; pin < NUM_PINS; ++pin) {
        if (wiringPiISR(pin, INT_EDGE_FALLING, interrupt_handlers[pin]) < 0) {
            fprintf(stderr, "Error setting up ISR for pin %d: %s\n", pin, strerror(errno));
            return EXIT_FAILURE;
        }
        interrupt_counts[pin] = 0; // Initialize interrupt counts
    }

    printf("Interrupt monitoring started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        // Print interrupt counts
        for (pin = 0; pin < NUM_PINS; ++pin) {
            printf("Pin %d: Interrupt Count = %u\n", pin, interrupt_counts[pin]);
        }
        delay(1000); // Delay for 1 second
    }

    printf("\nExiting program.\n");
    return EXIT_SUCCESS;
}

// Signal handler to catch Ctrl+C and exit gracefully
void signal_handler(int signal) {
    printf("\nCaught signal %d, exiting...\n", signal);
    program_running = false;
}

