        return 1;
    }

    while (1) {
        // Read Sensor Data
        if (readSensorData(&pm1_0, &pm2_5, &pm10) == 0) {
            // Calculate AQI
            aqi = calculateAQI(pm2_5);

            // Display AQI on OLED
            displayAQI(aqi);
        } else {
            // Handle Sensor Error
            handleError("Failed to read sensor data!");
        }

        delay(5000); // Delay for 5 seconds
    }

    return 0;
}

int initializeSensor()
{
    // Open serial port
    serial_fd = serialOpen(PMS5003_SERIAL_PORT, PMS5003_BAUD_RATE);
    if (serial_fd < 0) {
        perror("Failed to open serial port");
        return -1;
    }
    printf("PMS5003 sensor initialized successfully.\n");
    return 0;
}

int readSensorData(int *pm1_0, int *pm2_5, int *pm10)
{
    unsigned char buffer[32];
    int i = 0;
    unsigned short frame_length;
    unsigned short checksum_calculated, checksum_received;

    // Wait for the start bytes (0x42 0x4d)
    while (serialDataAvail(serial_fd) > 0) {
        if (serialGetchar(serial_fd) == 0x42) {
            if (serialGetchar(serial_fd) == 0x4d) {
                break;
            }
        }
    }

    // Read the rest of the data frame
    for (i = 0; i < 30; i++) {
        while (serialDataAvail(serial_fd) == 0) {
            delay(1);
        }
        buffer[i] = serialGetchar(serial_fd);
    }

    // Validate data and checksum
    frame_length = buffer[0] * 256 + buffer[1];
    if (frame_length != 28) {
        fprintf(stderr, "Invalid frame length: %d\n", frame_length);
        return -1;
    }

    checksum_calculated = 0x42 + 0x4d;
    for (i = 0; i < 30; i++) {
        checksum_calculated += buffer[i];
    }

    checksum_received = buffer[28] * 256 + buffer[29];

    if (checksum_calculated != checksum_received) {
        fprintf(stderr, "Checksum mismatch: calculated=0x%x, received=0x%x\n", checksum_calculated, checksum_received);
        return -1;
    }

    // Extract PM values
    *pm1_0 = buffer[2] * 256 + buffer[3];
    *pm2_5 = buffer[4] * 256 + buffer[5];
    *pm10 = buffer[6] * 256 + buffer[7];

    return 0;
}

int calculateAQI(int pm2_5)
{
    int aqi = 0;
    int i;

    for (i = 0; i < sizeof(aqi_breakpoints) / sizeof(aqi_breakpoints[0]); i++) {
        if (pm2_5 >= aqi_breakpoints[i].pm25_low && pm2_5 <= aqi_breakpoints[i].pm25_high) {
            aqi = ((float)(aqi_breakpoints[i].aqi_high - aqi_breakpoints[i].aqi_low) / (aqi_breakpoints[i].pm25_high - aqi_breakpoints[i].pm25_low)) * (pm2_5 - aqi_breakpoints[i].pm25_low) + aqi_breakpoints[i].aqi_low;
            break;
        }
    }

    return aqi;
}

int initializeOLED()
{
    oled_fd = wiringPiI2CSetup(OLED_ADDRESS);
    if (oled_fd < 0) {
        perror("Failed to initialize OLED");
        return -1;
    }

    // Initialization sequence (SSD1306 - adjust for your specific OLED)
    oledCommand(0xAE); // Display off
    oledCommand(0x00); // Set low column address
    oledCommand(0x10); // Set high column address
    oledCommand(0x40); // Set display start line
    oledCommand(0xB0); // Set page address
    oledCommand(0x81); // Contract control
    oledCommand(0xFF); // Set contrast
    oledCommand(0xA1); // Set segment remap
    oledCommand(0xA6); // Normal / reverse
    oledCommand(0xA8); // Multiplex ratio
    oledCommand(0x3F); // Duty cycle
    oledCommand(0xC8); // Com scan direction
    oledCommand(0xD3); // Set display offset
    oledCommand(0x00); // Offset
    oledCommand(0xD5); // Set osc division
    oledCommand(0x80); // Frequency
    oledCommand(0xD9); // Set pre-charge period
    oledCommand(0xF1); // Period
    oledCommand(0xDA); // Set com pins
    oledCommand(0x12); // Pins
    oledCommand(0xDB); // Set vcom detect
    oledCommand(0x40); // Vcom level
    oledCommand(0x20); // Set memory mode
    oledCommand(0x00); // Mode
    oledCommand(0x8D); // Charge pump
    oledCommand(0x14); // Enable
    oledCommand(0xAF); // Display on

    clearOLED();

    printf("OLED display initialized successfully.\n");
    return 0;
}

void clearOLED()
{
    int i, j;
    for (i = 0; i < 8; i++) {
        oledCommand(0xB0 + i); // Set page address
        oledCommand(0x00);   // Set column lower address
        oledCommand(0x10);   // Set column higher address
        for (j = 0; j < 128; j++) {
            oledData(0x00); // Clear all pixels in the page
        }
    }
}

