 #include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <unistd.h>
#include <fcntl.h>
#include <signal.h>
#include <time.h>
#include <sys/time.h>

// GPIO pins
#define PIR_SENSOR_GPIO 17
#define RELAY_GPIO 27

// Sysfs paths
#define GPIO_EXPORT_PATH "/sys/class/gpio/export"
#define GPIO_UNEXPORT_PATH "/sys/class/gpio/unexport"

#define GPIO_DIR_PATH_BASE "/sys/class/gpio/gpio%d"
#define GPIO_DIRECTION_PATH_SUFFIX "direction"
#define GPIO_VALUE_PATH_SUFFIX "value"

// Log file path
#define LOG_FILE "/var/log/door_unlocks.log"

// Debounce delay (milliseconds)
#define DEBOUNCE_DELAY_MS 100

// Unlock duration (milliseconds)
#define UNLOCK_DURATION_MS 500

// Global flag for signal handling
volatile sig_atomic_t terminate = 0;

// Function prototypes
int gpio_export(int gpio);
int gpio_unexport(int gpio);
int gpio_set_direction(int gpio, const char *direction);
int gpio_write(int gpio, int value);
int gpio_read(int gpio);
void log_event(const char *message);
void unlock_door();
void signal_handler(int sig);
void cleanup();

int main() {
    // Install signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Export GPIO pins
    if (gpio_export(PIR_SENSOR_GPIO) < 0 || gpio_export(RELAY_GPIO) < 0) {
        fprintf(stderr, "Failed to export GPIO pins. Exiting.\n");
        cleanup();
        return 1;
    }

    // Set GPIO directions
    if (gpio_set_direction(PIR_SENSOR_GPIO, "in") < 0 || gpio_set_direction(RELAY_GPIO, "out") < 0) {
        fprintf(stderr, "Failed to set GPIO directions. Exiting.\n");
        cleanup();
        return 1;
    }

    // Initialize relay to off state
    gpio_write(RELAY_GPIO, 0);

    printf("Door unlock system started. Press Ctrl+C to exit.\n");

    while (!terminate) {
        // Read PIR sensor value
        int pir_value = gpio_read(PIR_SENSOR_GPIO);

        if (pir_value == 1) {
            // Validate the PIR sensor's input

            // Debounce delay
            usleep(DEBOUNCE_DELAY_MS * 1000); // Convert milliseconds to microseconds

            int pir_value_validated = gpio_read(PIR_SENSOR_GPIO);

            if(pir_value_validated == 1){
                // Motion detected
                printf("Motion detected! Unlocking door.\n");
                log_event("Motion detected, unlocking door.");
                unlock_door();
            }
        }

        // Sleep for a short interval to avoid busy-waiting
        usleep(50 * 1000); // 50 milliseconds
    }

    printf("Door unlock system shutting down.\n");
    cleanup();
    return 0;
}

// Exports a GPIO pin
int gpio_export(int gpio) {
    char buffer[64];
    int fd;

    fd = open(GPIO_EXPORT_PATH, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Failed to open export file: %s\n", strerror(errno));
        return -1;
    }

    int len = snprintf(buffer, sizeof(buffer), "%d", gpio);
    if (write(fd, buffer, len) != len) {
        fprintf(stderr, "Failed to write to export file: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Unexports a GPIO pin
int gpio_unexport(int gpio) {
    char buffer[64];
    int fd;

    fd = open(GPIO_UNEXPORT_PATH, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Failed to open unexport file: %s\n", strerror(errno));
        return -1;
    }

    int len = snprintf(buffer, sizeof(buffer), "%d", gpio);
    if (write(fd, buffer, len) != len) {
        fprintf(stderr, "Failed to write to unexport file: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Sets the direction of a GPIO pin (in or out)
int gpio_set_direction(int gpio, const char *direction) {
    char path[128];
    int fd;

    snprintf(path, sizeof(path), GPIO_DIR_PATH_BASE "/" GPIO_DIRECTION_PATH_SUFFIX, gpio);

    fd = open(path, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Failed to open direction file: %s\n", strerror(errno));
        return -1;
    }

    if (write(fd, direction, strlen(direction)) != strlen(direction)) {
        fprintf(stderr, "Failed to write to direction file: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Writes a value to a GPIO pin (0 or 1)
int gpio_write(int gpio, int value) {
    char path[128];
    int fd;

    snprintf(path, sizeof(path), GPIO_DIR_PATH_BASE "/" GPIO_VALUE_PATH_SUFFIX, gpio);

    fd = open(path, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Failed to open value file: %s\n", strerror(errno));
        return -1;
    }

    char val_str[2];
    snprintf(val_str, sizeof(val_str), "%d", value);

    if (write(fd, val_str, 1) != 1) {
        fprintf(stderr, "Failed to write to value file: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Reads the value of a GPIO pin (0 or 1)
int gpio_read(int gpio) {
    char path[128];
    int fd;
    char value_str[3];

    snprintf(path, sizeof(path), GPIO_DIR_PATH_BASE "/" GPIO_VALUE_PATH_SUFFIX, gpio);

    fd = open(path, O_RDONLY);
    if (fd < 0) {
        fprintf(stderr, "Failed to open value file: %s\n", strerror(errno));
        return -1;
    }

    if (read(fd, value_str, 2) < 0) {
        fprintf(stderr, "Failed to read value file: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return atoi(value_str);
}

// Logs an event to the log file with a timestamp
void log_event(const char *message) {
    FILE *fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        fprintf(stderr, "Failed to open log file: %s\n", strerror(errno));
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(fp, "[%d-%02d-%02d %02d:%02d:%02d] %s\n", tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, message);

    fclose(fp);
}

// Unlocks the door by activating the relay for a short duration
void unlock_door() {
    gpio_write(RELAY_GPIO, 1); // Activate relay
    usleep(UNLOCK_DURATION_MS * 1000); // Keep activated for UNLOCK_DURATION_MS milliseconds
    gpio_write(RELAY_GPIO, 0); // Deactivate relay
}

// Signal handler for graceful shutdown
void signal_handler(int sig) {
    terminate = 1;
    printf("Signal received (%d).  Terminating...\n", sig);
}

// Cleanup function to unexport GPIO pins
void cleanup() {
    // Deactivate relay
    gpio_write(RELAY_GPIO, 0);

    // Unexport GPIO pins
    gpio_unexport(PIR_SENSOR_GPIO);
    gpio_unexport(RELAY_GPIO);
}

