// Constants
#define I2C_ADDR 0x40
#define HUMIDITY_CMD 0xE5
#define TEMPERATURE_CMD 0xE3
#define DEHUMIDIFIER_PIN 17 // WiringPi pin number
#define HUMIDITY_THRESHOLD_HIGH 60.0
#define HUMIDITY_THRESHOLD_LOW 55.0
#define MAX_I2C_ERRORS 3
#define MAX_SENSOR_FAILURES 3
#define BUFFER_SIZE 10

// Typedefs
typedef struct {
    time_t timestamp;
    float temperature;
    float humidity;
} SensorData;

// Global variables (minimize usage)
static volatile sig_atomic_t program_running = 1;
static int i2c_fd = -1;
static int i2c_error_count = 0;
static int sensor_failure_count = 0;
static bool dehumidifier_enabled = false;

// Circular buffer structure
typedef struct {
    SensorData data[BUFFER_SIZE];
    int head;
    int tail;
    int count;
} CircularBuffer;

// Function prototypes
int i2c_open_device(const char *device);
int i2c_write_byte(int fd, uint8_t data, void (*error_handler)(const char*));
int i2c_read_word(int fd, uint8_t command, uint16_t *data, void (*error_handler)(const char*));
uint8_t crc8(const uint8_t *data, size_t len);
float convert_temperature(uint16_t raw_temp);
float convert_humidity(uint16_t raw_humidity);
void dehumidifier_control(float humidity, void (*error_handler)(const char*));
void gpio_init(int pin, void (*error_handler)(const char*));
void gpio_write(int pin, int value, void (*error_handler)(const char*));
void add_to_buffer(CircularBuffer *buffer, SensorData data);
bool get_from_buffer(CircularBuffer *buffer, int index, SensorData *data);
void print_buffer(CircularBuffer *buffer);
void i2c_error_handler(const char* message);
void gpio_error_handler(const char* message);
void signal_handler(int signal);

// I2C device opening function
int i2c_open_device(const char *device) {
    int fd = open(device, O_RDWR);
    if (fd < 0) {
        perror("Error opening I2C device");
        return -1;
    }
    if (ioctl(fd, I2C_SLAVE, I2C_ADDR) < 0) {
        perror("Error setting I2C slave address");
        close(fd);
        return -1;
    }
    return fd;
}

// I2C write byte function
int i2c_write_byte(int fd, uint8_t data, void (*error_handler)(const char*)) {
    if (i2c_smbus_write_byte(fd, data) < 0) {
        error_handler("Error writing byte to I2C");
        return -1;
    }
    return 0;
}

// I2C read word function
int i2c_read_word(int fd, uint8_t command, uint16_t *data, void (*error_handler)(const char*)) {
    if (i2c_write_byte(fd, command, error_handler) < 0) {
        return -1;
    }
    // Delay to allow sensor to perform measurement (adjust as needed)
    usleep(100000); // 100 ms

    int result = i2c_smbus_read_word_data(fd, command); // Command is a dummy value here
    if (result < 0) {
        error_handler("Error reading word from I2C");
        return -1;
    }

    *data = (uint16_t)result;
    return 0;
}

// CRC-8 checksum calculation function
uint8_t crc8(const uint8_t *data, size_t len) {
    uint8_t crc = 0xFF;
    for (size_t i = 0; i < len; i++) {
        crc ^= data[i];
        for (int j = 0; j < 8; j++) {
            if (crc & 0x80) {
                crc = (crc << 1) ^ 0x31;
            } else {
                crc <<= 1;
            }
        }
    }
    return crc;
}

// Temperature conversion function
float convert_temperature(uint16_t raw_temp) {
    // Apply formula from HTU21D datasheet
    float temp = (float)raw_temp;
    temp /= 65536.0;
    temp *= 175.72;
    temp -= 46.85;
    return temp;
}

// Humidity conversion function
float convert_humidity(uint16_t raw_humidity) {
    // Apply formula from HTU21D datasheet
    float humidity = (float)raw_humidity;
    humidity /= 65536.0;
    humidity *= 125.0;
    humidity -= 6.0;
    if (humidity < 0.0) {
        humidity = 0.0;
    }
    if (humidity > 100.0) {
        humidity = 100.0;
    }
    return humidity;
}

// Dehumidifier control function
void dehumidifier_control(float humidity, void (*error_handler)(const char*)) {
    if (humidity > HUMIDITY_THRESHOLD_HIGH && !dehumidifier_enabled) {
        gpio_write(DEHUMIDIFIER_PIN, HIGH, error_handler);
        dehumidifier_enabled = true;
        printf("Dehumidifier ON (Humidity: %.2f%%)\n", humidity);
    } else if (humidity < HUMIDITY_THRESHOLD_LOW && dehumidifier_enabled) {
        gpio_write(DEHUMIDIFIER_PIN, LOW, error_handler);
        dehumidifier_enabled = false;
        printf("Dehumidifier OFF (Humidity: %.2f%%)\n", humidity);
    }
}

// GPIO initialization function
void gpio_init(int pin, void (*error_handler)(const char*)) {
    pinMode(pin, OUTPUT);
}

// GPIO write function
void gpio_write(int pin, int value, void (*error_handler)(const char*)) {
    digitalWrite(pin, value);
}

// Add data to circular buffer
void add_to_buffer(CircularBuffer *buffer, SensorData data) {
    buffer->data[buffer->head] = data;
    buffer->head = (buffer->head + 1) % BUFFER_SIZE;
    if (buffer->count < BUFFER_SIZE) {
        buffer->count++;
    } else {
        buffer->tail = (buffer->head + 1) % BUFFER_SIZE; // Advance tail if buffer is full
    }
}

// Get data from circular buffer
bool get_from_buffer(CircularBuffer *buffer, int index, SensorData *data) {
    if (index < 0 || index >= buffer->count) {
        return false; // Index out of bounds
    }
    int actual_index = (buffer->tail + index) % BUFFER_SIZE;
    *data = buffer->data[actual_index];
    return true;
}

// Print the circular buffer
void print_buffer(CircularBuffer *buffer) {
    printf("\nCircular Buffer Contents:\n");
    for (int i = 0; i < buffer->count; i++) {
        SensorData data;
        if (get_from_buffer(buffer, i, &data)) {
            struct tm *timeinfo = localtime(&data.timestamp);
            char timestamp_str[64];
            strftime(timestamp_str, sizeof(timestamp_str), "%Y-%m-%d %H:%M:%S", timeinfo);
            printf("[%d] %s - Temperature: %.2f°C, Humidity: %.2f%%\n", i, timestamp_str, data.temperature, data.humidity);
        } else {
            printf("Error retrieving data at index %d\n", i);
        }
    }
    printf("\n");
}

// I2C error handling function
void i2c_error_handler(const char* message) {
    perror(message);
    i2c_error_count++;
    fprintf(stderr, "I2C Error Count: %d\n", i2c_error_count);
    if (i2c_error_count >= MAX_I2C_ERRORS) {
        fprintf(stderr, "Too many I2C errors. Disabling dehumidifier.\n");
        gpio_write(DEHUMIDIFIER_PIN, LOW, gpio_error_handler); // Failsafe: turn off dehumidifier
        program_running = 0; // Stop the program
    }
}

// GPIO error handling function
void gpio_error_handler(const char* message) {
    perror(message);
    fprintf(stderr, "GPIO Error: %s\n", message);
}

// Signal handler function
void signal_handler(int signal) {
    printf("Caught signal %d. Exiting gracefully.\n", signal);
    program_running = 0;
}

int main() {
    // Initialize WiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi initialization failed. Exiting.\n");
        return 1;
    }

    // Initialize GPIO pin for dehumidifier control
    gpio_init(DEHUMIDIFIER_PIN, gpio_error_handler);
    gpio_write(DEHUMIDIFIER_PIN, LOW, gpio_error_handler); // Ensure dehumidifier is initially off

    // Open I2C device
    i2c_fd = i2c_open_device("/dev/i2c-1");
    if (i2c_fd < 0) {
        fprintf(stderr, "I2C device initialization failed. Exiting.\n");
        return 1;
    }

    // Initialize circular buffer
    CircularBuffer sensor_buffer = {{0}}; // Initialize all members to zero
    sensor_buffer.head = 0;
    sensor_buffer.tail = 0;
    sensor_buffer.count = 0;

    // Register signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    printf("Humidity Control System running. Press Ctrl+C to exit.\n");

    while (program_running) {
        uint16_t raw_humidity, raw_temperature;
        float humidity, temperature;

        // Read humidity
        if (i2c_read_word(i2c_fd, HUMIDITY_CMD, &raw_humidity, i2c_error_handler) == 0) {
            uint8_t data[2];
            data[0] = raw_humidity & 0xFF;
            data[1] = (raw_humidity >> 8) & 0xFF;
            uint8_t checksum = crc8(data, 2);
            uint8_t received_checksum = (raw_humidity >> 8) & 0xFF;

            if (checksum == received_checksum) {
                humidity = convert_humidity(raw_humidity & 0xFFFC); // Clear status bits
            } else {
                fprintf(stderr, "CRC Checksum Mismatch (Humidity). Ignoring reading.\n");
                sensor_failure_count++;
            }
        } else {
            sensor_failure_count++;
            humidity = -1.0; // Indicate error
        }

        // Read temperature
        if (i2c_read_word(i2c_fd, TEMPERATURE_CMD, &raw_temperature, i2c_error_handler) == 0) {
           uint8_t data[2];
            data[0] = raw_temperature & 0xFF;
            data[1] = (raw_temperature >> 8) & 0xFF;
            uint8_t checksum = crc8(data, 2);
            uint8_t received_checksum = (raw_temperature >> 8) & 0xFF;

            if (checksum == received_checksum) {
                temperature = convert_temperature(raw_temperature & 0xFFFC); // Clear status bits
            } else {
                fprintf(stderr, "CRC Checksum Mismatch (Temperature). Ignoring reading.\n");
                sensor_failure_count++;
            } 
        } else {
            sensor_failure_count++;
            temperature = -1.0; // Indicate error
        }

        if (sensor_failure_count >= MAX_SENSOR_FAILURES) {
            fprintf(stderr, "Too many sensor failures. Disabling dehumidifier.\n");
            gpio_write(DEHUMIDIFIER_PIN, LOW, gpio_error_handler); // Failsafe: turn off dehumidifier
            program_running = 0; // Stop the program
        }

        if (temperature != -1.0 && humidity != -1.0) {
            // Create sensor data struct
            SensorData sensor_data;
            sensor_data.timestamp = time(NULL);
            sensor_data.temperature = temperature;
            sensor_data.humidity = humidity;

            // Add data to circular buffer
            add_to_buffer(&sensor_buffer, sensor_data);

            // Control dehumidifier
            dehumidifier_control(humidity, gpio_error_handler);
            i2c_error_count = 0; // Reset error count on successful read
            sensor_failure_count = 0; // Reset sensor failure count

            printf("Temperature: %.2f°C, Humidity: %.2f%%\n", temperature, humidity);
            print_buffer(&sensor_buffer);
        } else {
            fprintf(stderr, "Invalid sensor data. Skipping control logic.\n");
        }

        sleep(5); // Read every 5 seconds
    }

    // Cleanup: Disable dehumidifier before exiting
    printf("Shutting down. Disabling dehumidifier.\n");
    gpio_write(DEHUMIDIFIER_PIN, LOW, gpio_error_handler);

    // Close I2C device
    if (i2c_fd >= 0) {
        close(i2c_fd);
    }

    return 0;
}

