// Global variable to track program termination
volatile sig_atomic_t program_running = 1;

// Signal handler for Ctrl+C
void signal_handler(int sig) {
    if (sig == SIGINT) {
        program_running = 0;
        printf("\nCtrl+C detected. Exiting gracefully...\n");
    }
}

// Function to export a GPIO pin
int gpio_export(int pin) {
    char buffer[64];
    int len;
    FILE *fp = NULL;

    fp = fopen("/sys/class/gpio/export", "w");
    if (fp == NULL) {
        perror("Failed to open /sys/class/gpio/export");
        return -1;
    }

    len = snprintf(buffer, sizeof(buffer), "%d", pin);
    if (fwrite(buffer, 1, len, fp) != len) {
        perror("Failed to write to /sys/class/gpio/export");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return 0;
}

// Function to unexport a GPIO pin
int gpio_unexport(int pin) {
    char buffer[64];
    int len;
    FILE *fp = NULL;

    fp = fopen("/sys/class/gpio/unexport", "w");
    if (fp == NULL) {
        perror("Failed to open /sys/class/gpio/unexport");
        return -1;
    }

    len = snprintf(buffer, sizeof(buffer), "%d", pin);
    if (fwrite(buffer, 1, len, fp) != len) {
        perror("Failed to write to /sys/class/gpio/unexport");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return 0;
}

// Function to set the direction of a GPIO pin (input or output)
int gpio_set_direction(int pin, char *direction) {
    char path[64];
    FILE *fp = NULL;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/direction", pin);
    fp = fopen(path, "w");
    if (fp == NULL) {
        perror("Failed to open GPIO direction file");
        return -1;
    }

    if (fwrite(direction, 1, strlen(direction), fp) != strlen(direction)) {
        perror("Failed to write to GPIO direction file");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return 0;
}

// Function to read the value of a GPIO pin
int gpio_read(int pin) {
    char path[64];
    char value_str[3];
    FILE *fp = NULL;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", pin);
    fp = fopen(path, "r");
    if (fp == NULL) {
        perror("Failed to open GPIO value file for reading");
        return -1;
    }

    if (fread(value_str, 1, 3, fp) == 0) {
        perror("Failed to read GPIO value");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return (atoi(value_str));
}

// Function to write a value to a GPIO pin
int gpio_write(int pin, int value) {
    char path[64];
    char value_str[3];
    FILE *fp = NULL;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", pin);
    fp = fopen(path, "w");
    if (fp == NULL) {
        perror("Failed to open GPIO value file for writing");
        return -1;
    }

    snprintf(value_str, sizeof(value_str), "%d", value);
    if (fwrite(value_str, 1, strlen(value_str), fp) != strlen(value_str)) {
        perror("Failed to write GPIO value");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return 0;
}

// Function to print the sensor status
void print_status(int flame_detected) {
    if (flame_detected) {
        printf("Flame Detected\n");
    } else {
        printf("No Flame\n");
    }
}

int main() {
    int flame_detected = 0; // 0: Flame detected, 1: No flame
    int previous_state = -1; // Initialize to an invalid state
    struct timespec delay;
    delay.tv_sec = 0;
    delay.tv_nsec = 100 * 1000 * 1000; // 100ms

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Export GPIO pins
    if (gpio_export(FLAME_SENSOR_PIN) || gpio_export(BUZZER_PIN) || gpio_export(LED_PIN)) {
        fprintf(stderr, "Failed to export GPIO pins. Exiting.\n");
        return 1;
    }

    // Set GPIO directions
    if (gpio_set_direction(FLAME_SENSOR_PIN, "in") ||
        gpio_set_direction(BUZZER_PIN, "out") ||
        gpio_set_direction(LED_PIN, "out")) {
        fprintf(stderr, "Failed to set GPIO directions. Exiting.\n");
        gpio_unexport(FLAME_SENSOR_PIN);
        gpio_unexport(BUZZER_PIN);
        gpio_unexport(LED_PIN);
        return 1;
    }

    printf("Flame sensor monitoring started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        int sensor_value = gpio_read(FLAME_SENSOR_PIN);

        if (sensor_value < 0) {
            fprintf(stderr, "Failed to read sensor value. Exiting.\n");
            break;
        }

        // Flame detected (sensor output LOW)
        if (sensor_value == 0) {
            flame_detected = 1;
            gpio_write(BUZZER_PIN, 1);
            gpio_write(LED_PIN, 1);
        } else {
            // No flame (sensor output HIGH)
            flame_detected = 0;
            gpio_write(BUZZER_PIN, 0);
            gpio_write(LED_PIN, 0);
        }

        // Print status only if it has changed
        if (flame_detected != previous_state) {
            print_status(flame_detected);
            previous_state = flame_detected;
        }

        nanosleep(&delay, NULL);
    }

    // Cleanup: Unexport GPIO pins
    gpio_unexport(FLAME_SENSOR_PIN);
    gpio_unexport(BUZZER_PIN);
    gpio_unexport(LED_PIN);

    printf("Program terminated.\n");
    return 0;
}

