#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>

// Define GPIO pins
#define SOUND_SENSOR_PIN 17
#define LED_PIN 27

// Define constants
#define CALIBRATION_DURATION 5 // seconds
#define THRESHOLD_PERCENTAGE 20 // %
#define DEBOUNCE_DELAY 50      // milliseconds
#define FLASH_DURATION 5      // seconds
#define FLASH_FREQUENCY 2     // Hz

// Global variable for the calibrated threshold
volatile int calibrated_threshold = 0;
volatile sig_atomic_t program_running = 1; // Flag for signal handling

// Function prototypes
int calibrate_threshold();
int read_sound_level();
void flash_led();
void log_alarm();
void signal_handler(int signal);

// Signal handler function
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("Ctrl+C detected. Exiting gracefully.\n");
        program_running = 0; // Set the flag to exit the main loop
    }
}

// Function to calibrate the sound threshold
int calibrate_threshold() {
    printf("Calibrating sound threshold...\n");
    int sum = 0;
    int samples = 0;
    time_t start_time = time(NULL);

    while (time(NULL) - start_time < CALIBRATION_DURATION) {
        sum += gpioRead(SOUND_SENSOR_PIN);
        samples++;
        gpioDelay(10); // Small delay to avoid overwhelming the CPU
    }

    if (samples > 0) {
        int average = sum / samples;
        calibrated_threshold = average + (average * THRESHOLD_PERCENTAGE / 100);
        printf("Calibration complete. Threshold set to: %d\n", calibrated_threshold);
        return 0; // Success
    } else {
        fprintf(stderr, "Error: Could not calibrate threshold.\n");
        return 1; // Failure
    }
}

// Function to read the sound level and debounce
int read_sound_level() {
    int count = 0;
    time_t start_time = time(NULL);

    while (time(NULL) - start_time < (double)DEBOUNCE_DELAY / 1000) {
        if (gpioRead(SOUND_SENSOR_PIN)) {
            count++;
        }
        gpioDelay(1); // Check every 1 ms
    }

    // If sound is consistently detected during the debounce period, return 1
    if (count > DEBOUNCE_DELAY / 2) { // More than half the time
        return 1;
    } else {
        return 0;
    }
}

// Function to flash the LED
void flash_led() {
    printf("Alarm triggered! Flashing LED...\n");
    time_t start_time = time(NULL);

    while (time(NULL) - start_time < FLASH_DURATION) {
        gpioWrite(LED_PIN, 1); // Turn LED on
        gpioDelay(500 / FLASH_FREQUENCY); // Delay for half the period
        gpioWrite(LED_PIN, 0); // Turn LED off
        gpioDelay(500 / FLASH_FREQUENCY); // Delay for half the period
    }
    printf("Flashing LED stopped.\n");
}

// Function to log the alarm event
void log_alarm() {
    FILE *fp;
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fp = fopen("alarm_log.txt", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error: Could not open alarm_log.txt for writing.\n");
        return;
    }

    fprintf(fp, "%s - Alarm triggered\n", timestamp);
    fclose(fp);
    printf("Alarm logged to alarm_log.txt\n");
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(SOUND_SENSOR_PIN, PI_INPUT);
    gpioSetMode(LED_PIN, PI_OUTPUT);

    // Calibrate the threshold
    if (calibrate_threshold() != 0) {
        gpioTerminate();
        return 1;
    }

    // Set up signal handling for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Alarm system started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        if (read_sound_level()) {
            flash_led();
            log_alarm();
            gpioDelay(1000); // Delay to avoid repeated triggers
        }
        gpioDelay(10); // Small delay to reduce CPU usage
    }

    // Clean up and terminate pigpio
    gpioWrite(LED_PIN, 0); // Turn off LED before exiting
    gpioTerminate();
    printf("Alarm system stopped.\n");

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <unistd.h>

// Define GPIO pins connected to the shift registers
#define DATA_PIN   0  // Serial Data Input (SDI)
#define LATCH_PIN  1  // Register Clock (RCLK / STCP)
#define CLOCK_PIN  2  // Shift Register Clock (SRCLK / SHCP)

// Define LED matrix dimensions
#define MATRIX_SIZE 20

// Predefined patterns for the LED matrix (adjust as needed)
const unsigned char high_byte[MATRIX_SIZE] = {
    0x01, 0xff, 0x80, 0xff, 0x01, 0x02, 0x04, 0x08, 0x10, 0x20, 0x40, 0x80, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff
};

const unsigned char low_byte[MATRIX_SIZE] = {
    0x00, 0x7f, 0x00, 0xfe, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0xfe, 0xfd, 0xfb, 0xf7, 0xef, 0xdf, 0xbf, 0x7f
};

// Function to initialize the GPIO pins
int initialize_gpio() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed!\n");
        return -1; // Indicate failure
    }

    pinMode(DATA_PIN, OUTPUT);
    pinMode(LATCH_PIN, OUTPUT);
    pinMode(CLOCK_PIN, OUTPUT);

    digitalWrite(DATA_PIN, LOW);
    digitalWrite(LATCH_PIN, LOW);
    digitalWrite(CLOCK_PIN, LOW);

    return 0; // Indicate success
}

// Function to shift out a byte of data to the 74HC595
void shift_out(unsigned char data) {
    for (int i = 0; i < 8; i++) {
        // Determine the bit value (MSB first)
        int bit_value = (data & (0x80 >> i)) ? HIGH : LOW;

        // Set the data pin
        digitalWrite(DATA_PIN, bit_value);

        // Pulse the clock pin to shift the bit
        digitalWrite(CLOCK_PIN, HIGH);
        delayMicroseconds(1); // Small delay for reliable clocking
        digitalWrite(CLOCK_PIN, LOW);
    }
}

// Function to latch the data to the output of the 74HC595
void latch_data() {
    digitalWrite(LATCH_PIN, HIGH);
    delayMicroseconds(1); // Small delay for reliable latching
    digitalWrite(LATCH_PIN, LOW);
}

// Function to display a frame on the LED matrix
void display_frame(unsigned char high_byte_data, unsigned char low_byte_data) {
    shift_out(low_byte_data);
    shift_out(high_byte_data);
    latch_data();
}

int main() {
    if (initialize_gpio() != 0) {
        fprintf(stderr, "GPIO initialization failed. Exiting.\n");
        return EXIT_FAILURE;
    }

    while (1) {
        // Display patterns forward
        for (int i = 0; i < MATRIX_SIZE; i++) {
            display_frame(high_byte[i], low_byte[i]);
            delay(100); // Adjust delay for desired speed
        }

       // Display patterns backward
        for (int i = MATRIX_SIZE - 1; i >= 0; i--) {
            display_frame(high_byte[i], low_byte[i]);
            delay(100);
        }
    }

    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
