#include <time.h>
#include <signal.h>
#include <errno.h>

// Define constants
#define SPI_CHANNEL 0
#define CE_PIN 8 // Chip Enable pin for MCP3008
#define FAN_PIN 18
#define TARGET_TEMP 25.0
#define KP 50.0
#define MCP3008_CLOCK_SPEED 2000000 // 2MHz

// Global variables
FILE *log_file;
volatile sig_atomic_t program_running = 1;

// Function prototypes
float read_tmp36(int channel);
void set_fan_speed(int speed);
int control_temperature(float current_temp, float target_temp);
void log_data(float temperature, int fan_speed);
void signal_handler(int signal);

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, exiting gracefully.\n", signal);
    program_running = 0;
    set_fan_speed(0);
    if (log_file != NULL) {
        fclose(log_file);
    }
    exit(0);
}

// Function to read temperature from TMP36 sensor using MCP3008
float read_tmp36(int channel) {
    unsigned char buffer[3];
    int adc_value;
    float voltage, temperature;

    buffer[0] = 0x01; // Start bit
    buffer[1] = (0x08 | channel) << 4; // Single-ended mode, channel selection
    buffer[2] = 0x00; // Don't care

    if (wiringPiSPIDataRW(SPI_CHANNEL, buffer, 3) == -1) {
        fprintf(stderr, "SPI read failed.\n");
        return -100.0; // Indicate error
    }

    adc_value = ((buffer[1] & 0x03) << 8) + buffer[2];

    // Check for invalid ADC values
    if (adc_value < 0 || adc_value > 1023) {
        fprintf(stderr, "Invalid ADC value: %d\n", adc_value);
        log_data(-273.15, -1); //Log error temperature and fan speed
        delay(100); // Wait before retry
        return -273.15; // Return absolute zero as error
    }

    voltage = (adc_value * 3.3) / 1024.0; // Convert to voltage (assuming 3.3V reference)
    temperature = (voltage - 0.5) * 100.0; // Convert to Celsius

    return temperature;
}

// Function to set fan speed using PWM
void set_fan_speed(int speed) {
    if (speed < 0) {
        speed = 0;
    } else if (speed > 1023) {
        speed = 1023;
    }
    pwmWrite(FAN_PIN, speed);
}

// Function to control temperature using a proportional controller
int control_temperature(float current_temp, float target_temp) {
    float error = target_temp - current_temp;
    int speed = (int)(KP * error);

    if (speed < 0) {
        speed = 0;
    } else if (speed > 1023) {
        speed = 1023;
    }

    return speed;
}

// Function to log data to file
void log_data(float temperature, int fan_speed) {
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    if (log_file == NULL){
        fprintf(stderr, "Log file is NULL.  Attempting to re-open.\n");
        log_file = fopen("cooling_log.txt", "a");
        if (log_file == NULL){
            perror("Error opening cooling_log.txt for appending");
            return;
        }
    }
    if (log_file != NULL) {
        fprintf(log_file, "%d-%02d-%02d %02d:%02d:%02d, Temperature: %.2f°C, Fan Speed: %d\n",
