#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <signal.h>
#include <pigpio.h>
#include <stdint.h>

// Constants
#define I2C_BUS 1
#define BME280_ADDRESS 0x76
#define BUZZER_GPIO 23
#define BUFFER_SIZE 10

// BME280 Registers
#define BME280_REG_TEMP_MSB 0xFA
#define BME280_REG_HUM_MSB 0xFD
#define BME280_REG_PRESS_MSB 0xF7
#define BME280_REG_CTRL_MEAS 0xF4
#define BME280_REG_CTRL_HUM 0xF2
#define BME280_REG_CONFIG 0xF5
#define BME280_REG_RESET 0xE0

// Oversampling settings
#define OVERSAMPLING_TEMP 1  // 1x oversampling
#define OVERSAMPLING_HUM 1   // 1x oversampling
#define OVERSAMPLING_PRESS 1 // 1x oversampling

// Global variables
int i2c_handle;
volatile sig_atomic_t terminate = 0;

// Circular buffer structure
typedef struct {
    float temperature[BUFFER_SIZE];
    float humidity[BUFFER_SIZE];
    float pressure[BUFFER_SIZE];
    int head;
    int count;
} CircularBuffer;

CircularBuffer sensor_buffer;

// Function prototypes
int init_i2c();
void read_bme280(float *temperature, float *humidity, float *pressure);
void add_to_buffer(CircularBuffer *buffer, float temperature, float humidity, float pressure);
float average(float *data, int count);
void check_thresholds(float avg_temp, float avg_humidity);
void buzzer_on(int duration_ms);
void signal_handler(int signal);
void cleanup();

// Function to initialize the I2C interface
int init_i2c() {
    i2c_handle = i2cOpen(I2C_BUS, BME280_ADDRESS, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C device: %d\n", i2c_handle);
        return -1;
    }

    // BME280 initialization sequence
    // Set humidity oversampling
    if (i2cWriteByteData(i2c_handle, BME280_REG_CTRL_HUM, OVERSAMPLING_HUM) < 0) {
        fprintf(stderr, "Error writing to CTRL_HUM register\n");
        i2cClose(i2c_handle);
        return -1;
    }

    // Set temperature and pressure oversampling and normal mode
    int ctrl_meas_setting = (OVERSAMPLING_TEMP << 5) | (OVERSAMPLING_PRESS << 2) | 3; // Normal mode
    if (i2cWriteByteData(i2c_handle, BME280_REG_CTRL_MEAS, ctrl_meas_setting) < 0) {
        fprintf(stderr, "Error writing to CTRL_MEAS register\n");
        i2cClose(i2c_handle);
        return -1;
    }

    return 0;
}

// Function to read data from the BME280 sensor
void read_bme280(float *temperature, float *humidity, float *pressure) {
    uint8_t data[8];
    int32_t temp_raw, hum_raw, press_raw;

    // Read raw temperature, pressure and humidity data
    data[0] = i2cReadByteData(i2c_handle, BME280_REG_PRESS_MSB); // pressure MSB
    data[1] = i2cReadByteData(i2c_handle, BME280_REG_PRESS_MSB + 1); // pressure LSB
    data[2] = i2cReadByteData(i2c_handle, BME280_REG_PRESS_MSB + 2); // pressure XLSB
    data[3] = i2cReadByteData(i2c_handle, BME280_REG_TEMP_MSB);  // temperature MSB
    data[4] = i2cReadByteData(i2c_handle, BME280_REG_TEMP_MSB + 1); // temperature LSB
    data[5] = i2cReadByteData(i2c_handle, BME280_REG_TEMP_MSB + 2); // temperature XLSB
    data[6] = i2cReadByteData(i2c_handle, BME280_REG_HUM_MSB); // humidity MSB
    data[7] = i2cReadByteData(i2c_handle, BME280_REG_HUM_MSB + 1); // humidity LSB

    // Combine the values to get the raw data
    press_raw = (data[0] << 12) | (data[1] << 4) | (data[2] >> 4);
    temp_raw = (data[3] << 12) | (data[4] << 4) | (data[5] >> 4);
    hum_raw = (data[6] << 8) | data[7];

    // Dummy conversion (replace with actual BME280 conversion formulas)
    *temperature = (float)temp_raw / 100.0;
    *humidity = (float)hum_raw / 100.0;
    *pressure = (float)press_raw / 100.0;
}

// Function to add new readings to the circular buffer
void add_to_buffer(CircularBuffer *buffer, float temperature, float humidity, float pressure) {
    buffer->temperature[buffer->head] = temperature;
    buffer->humidity[buffer->head] = humidity;
    buffer->pressure[buffer->head] = pressure;

    buffer->head = (buffer->head + 1) % BUFFER_SIZE;
    if (buffer->count < BUFFER_SIZE) {
        buffer->count++;
    }
}

// Function to calculate the average of an array
float average(float *data, int count) {
    if (count == 0) return 0.0;
    float sum = 0.0;
    for (int i = 0; i < count; i++) {
        sum += data[i];
    }
    return sum / count;
}

// Function to check if the average humidity or temperature exceeds the threshold
void check_thresholds(float avg_temp, float avg_humidity) {
    if (avg_humidity > 80.0 || avg_temp > 30.0) {
        printf("Threshold exceeded! Temperature: %.2f, Humidity: %.2f\n", avg_temp, avg_humidity);
        buzzer_on(1000); // Activate buzzer for 1 second
    }
}

// Function to activate the buzzer for a specified duration
void buzzer_on(int duration_ms) {
    gpioWrite(BUZZER_GPIO, 1); // Turn buzzer on
    gpioDelay(duration_ms * 1000); // Delay for specified duration
    gpioWrite(BUZZER_GPIO, 0); // Turn buzzer off
}

// Signal handler to catch SIGINT and SIGTERM signals
void signal_handler(int signal) {
    printf("Caught signal %d, terminating...\n", signal);
    terminate = 1;
}

// Cleanup function to release resources before exiting
void cleanup() {
    printf("Cleaning up...\n");
    i2cClose(i2c_handle);
    gpioTerminate();
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set buzzer GPIO as output
    gpioSetMode(BUZZER_GPIO, PI_OUTPUT);
    gpioWrite(BUZZER_GPIO, 0); // Ensure buzzer is off initially

    // Initialize I2C
    if (init_i2c() < 0) {
        cleanup();
        return 1;
    }

    // Initialize circular buffer
    sensor_buffer.head = 0;
    sensor_buffer.count = 0;

    // Set up signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    float temperature, humidity, pressure;

    // Main loop
    while (!terminate) {
        // Read sensor data
        if (init_i2c() != 0) {
            fprintf(stderr, "Failed to re-initialize I2C. Retrying in 5 seconds.\n");
            sleep(5);
            continue;
        }
        read_bme280(&temperature, &humidity, &pressure);
        printf("Temperature: %.2f °C, Humidity: %.2f %, Pressure: %.2f hPa\n", temperature, humidity, pressure);

        // Add data to circular buffer
        add_to_buffer(&sensor_buffer, temperature, humidity, pressure);

        // Calculate averages
        float avg_temp = average(sensor_buffer.temperature, sensor_buffer.count);
        float avg_humidity = average(sensor_buffer.humidity, sensor_buffer.count);
        float avg_pressure = average(sensor_buffer.pressure, sensor_buffer.count);

        // Check thresholds
        check_thresholds(avg_temp, avg_humidity);

        // Wait for 5 seconds
        sleep(5);
    }

    // Cleanup and exit
    cleanup();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <stdint.h>
#include <errno.h>
#include <string.h>

// ADXL345 I2C address
#define ADXL345_I2C_ADDR 0x53

// ADXL345 Registers
#define ADXL345_REG_POWER_CTL 0x2D
#define ADXL345_REG_DATA_FORMAT 0x31
#define ADXL345_REG_DATAX0 0x32

// Scaling factor (assuming +/- 16g range and full resolution)
#define SCALE_FACTOR (9.80665 / 256.0) // Earth's gravity in m/s^2 divided by values.

// Function to select the I2C device
int select_i2c_device(int file_descriptor, int device_address, const char *device_name) {
    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Error: Could not select I2C device 0x%02x (%s): %s\n", device_address, device_name, strerror(errno));
        return -1;
    }
    return 0;
}

// Function to write a single byte to an I2C register
int write_i2c_register(int file_descriptor, uint8_t register_address, uint8_t value) {
    uint8_t buffer[2];
    buffer[0] = register_address;
    buffer[1] = value;

    if (write(file_descriptor, buffer, 2) != 2) {
        fprintf(stderr, "Error: Could not write to I2C register 0x%02x: %s\n", register_address, strerror(errno));
        return -1;
    }
    return 0;
}

// Function to read multiple bytes from an I2C register
int read_i2c_registers(int file_descriptor, uint8_t register_address, uint8_t *data, int length) {
    if (write(file_descriptor, &register_address, 1) != 1) {
        fprintf(stderr, "Error: Could not write register address for reading: %s\n", strerror(errno));
        return -1;
    }

    if (read(file_descriptor, data, length) != length) {
        fprintf(stderr, "Error: Could not read data from I2C: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

int main(int argc, char **argv) {
    int i2c_bus = 1; // Default I2C bus
    int file_descriptor; // File descriptor for the I2C device
    char i2c_device_name[20];
    int16_t x, y, z; // Raw accelerometer values
    float x_g, y_g, z_g; // Acceleration values in g
    uint8_t data_buffer[6]; // Buffer to store raw data

    // Optionally, allow the user to specify the I2C bus
    if (argc > 1) {
        i2c_bus = atoi(argv[1]);
    }

    // Construct the I2C device name
    snprintf(i2c_device_name, sizeof(i2c_device_name), "/dev/i2c-%d", i2c_bus);

    // Open the I2C device
    file_descriptor = open(i2c_device_name, O_RDWR);
    if (file_descriptor < 0) {
        fprintf(stderr, "Error: Could not open I2C device %s: %s\n", i2c_device_name, strerror(errno));
        return 1;
    }

    // Select the ADXL345 device
    if (select_i2c_device(file_descriptor, ADXL345_I2C_ADDR, "ADXL345") < 0) {
        close(file_descriptor);
        return 1;
    }

    // Initialize the ADXL345
    if (write_i2c_register(file_descriptor, ADXL345_REG_POWER_CTL, 0) < 0) { // Reset POWER_CTL
        close(file_descriptor);
        return 1;
    }
    if (write_i2c_register(file_descriptor, ADXL345_REG_POWER_CTL, 8) < 0) { // Set POWER_CTL to measure
        close(file_descriptor);
        return 1;
    }
    if (write_i2c_register(file_descriptor, ADXL345_REG_DATA_FORMAT, 0) < 0) { // Reset DATA_FORMAT
        close(file_descriptor);
        return 1;
    }
    if (write_i2c_register(file_descriptor, ADXL345_REG_DATA_FORMAT, 0x0B) < 0) { // Set DATA_FORMAT for full resolution and +/- 16g range
        close(file_descriptor);
        return 1;
    }

    // Main loop to read and print accelerometer data
    while (1) {
        // Read the accelerometer data
        if (read_i2c_registers(file_descriptor, ADXL345_REG_DATAX0, data_buffer, 6) < 0) {
            fprintf(stderr, "Error reading accelerometer data. Retrying...");
            usleep(100000); // Wait before retrying
            continue;
        }

        // Combine the high and low bytes to get the signed 16-bit values
        x = (int16_t)((data_buffer[1] << 8) | data_buffer[0]);
        y = (int16_t)((data_buffer[3] << 8) | data_buffer[2]);
        z = (int16_t)((data_buffer[5] << 8) | data_buffer[4]);

        // Convert raw values to g
        x_g = x * SCALE_FACTOR;
        y_g = y * SCALE_FACTOR;
        z_g = z * SCALE_FACTOR;

        // Print the acceleration values
        printf("X: %.3f g, Y: %.3f g, Z: %.3f g\n", x_g, y_g, z_g);

        // Wait before the next reading
        usleep(100000); // 100ms
    }

    // Close the I2C device (this will never be reached in the current loop)
    close(file_descriptor);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <signal.h>
#include <unistd.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>

// Define LED pins (wiringPi numbers)
#define LED1 16
#define LED2 20
#define LED3 21

// Define BH1750 I2C address
#define BH1750_ADDR 0x23

// Define BH1750 command for continuous high-resolution mode
#define BH1750_CONTINUOUS_HIGH_RES_MODE 0x10

// Global variable for I2C file descriptor
int bh1750_fd;

// Global variable to indicate program termination
volatile sig_atomic_t terminate = 0;

// Function to set the state of an LED
void led_set(int led_number, int state) {
    digitalWrite(led_number, state);
}

// Function to read ambient light level from BH1750 sensor
int bh1750_read() {
    int light_level;

    // Write command to start measurement
    if (wiringPiI2CWrite(bh1750_fd, BH1750_CONTINUOUS_HIGH_RES_MODE) < 0) {
        fprintf(stderr, "Error writing to BH1750 sensor.\n");
        return -1;
    }

    // Wait for measurement to complete (at least 180ms)
    delay(200);

    // Read two bytes of data
    light_level = wiringPiI2CReadReg16(bh1750_fd, 0);
    if (light_level < 0) {
        fprintf(stderr, "Error reading from BH1750 sensor.\n");
        return -1;
    }

    // Swap bytes (BH1750 returns MSB first)
    light_level = (light_level >> 8) | (light_level << 8);

    return light_level;
}

// Function to calculate delay based on light level
int calculate_delay(int light_level) {
    // Map light level (0-65535) to delay (10ms - 500ms)
    // Invert the light level so that higher light means lower delay
    int delay_ms = 500 - (int)(((float)light_level / 65535.0) * 490.0);

    // Ensure delay is within the valid range
    if (delay_ms < 10) {
        delay_ms = 10;
    }
    if (delay_ms > 500) {
        delay_ms = 500;
    }

    return delay_ms;
}

// Function to move the lit LED in the specified direction
int knight_rider(int position, int direction) {
    // Turn off all LEDs
    led_set(LED1, LOW);
    led_set(LED2, LOW);
    led_set(LED3, LOW);

    // Update position
    position += direction;

    // Wrap around if necessary
    if (position < 1) {
        position = 3;
    } else if (position > 3) {
        position = 1;
    }

    // Turn on the LED at the new position
    switch (position) {
        case 1:
            led_set(LED1, HIGH);
            break;
        case 2:
            led_set(LED2, HIGH);
            break;
        case 3:
            led_set(LED3, HIGH);
            break;
    }

    return position;
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    fprintf(stderr, "Received signal %d, terminating.\n", signal);
    terminate = 1;
}

int main() {
    int current_position = 1;
    int direction = 1; // 1 for forward, -1 for backward
    int light_level, delay_ms;

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error initializing wiringPi.\n");
        return 1;
    }

    // Configure LED pins as output
    pinMode(LED1, OUTPUT);
    pinMode(LED2, OUTPUT);
    pinMode(LED3, OUTPUT);

    // Initialize I2C communication with BH1750 sensor
    bh1750_fd = wiringPiI2CSetup(BH1750_ADDR);
    if (bh1750_fd == -1) {
        fprintf(stderr, "Error initializing I2C communication with BH1750 sensor.\n");
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    fprintf(stderr, "Knight Rider LED chaser with BH1750 light sensor control started. Press Ctrl+C to exit.\n");

    // Main loop
    while (!terminate) {
        // Read ambient light level
        light_level = bh1750_read();
        if (light_level == -1) {
            fprintf(stderr, "Error reading light level, using default delay.\n");
            delay_ms = 250; // Default delay
        } else {
            // Calculate delay
            delay_ms = calculate_delay(light_level);
        }

        // Update LED chaser position
        current_position = knight_rider(current_position, direction);

        // Sleep for the calculated delay
        delay(delay_ms);

         // Reverse direction when reaching the end
        if (current_position == 1) {
            direction = 1; // Move forward
        } else if (current_position == 3) {
            direction = -1; // Move backward
        }
    }

    // Turn off all LEDs before exiting
    led_set(LED1, LOW);
    led_set(LED2, LOW);
    led_set(LED3, LOW);

    fprintf(stderr, "Program terminated.\n");

    return 0;
}

