// Define constants
#define BH1750_ADDR 0x23
#define RELAY_GPIO 23
#define LUX_THRESHOLD 150
#define MEASUREMENT_MODE 0x10 // Continuous high resolution mode

// Global flag for signal handling
std::atomic<bool> running(true);

// Forward declarations
class BH1750;
class Relay;

// Signal handler function
void signal_handler(int signal);

// Logger class
class Logger {
public:
    Logger(const std::string& filename) : filename_(filename) {
        log_file_.open(filename_, std::ios::app);
        if (!log_file_.is_open()) {
            std::cerr << "Error opening log file: " << filename_ << std::endl;
        }
    }

    ~Logger() {
        if (log_file_.is_open()) {
            log_file_.close();
        }
    }

    void log(const std::string& message) {
        auto now = std::chrono::system_clock::now();
        auto now_c = std::chrono::system_clock::to_time_t(now);
        std::tm now_tm = *std::localtime(&now_c);
        auto ms = std::chrono::duration_cast<std::chrono::milliseconds>(now.time_since_epoch()) % 1000;

        std::stringstream ss;
        ss << std::put_time(&now_tm, "%Y-%m-%d %H:%M:%S") << "." << std::setfill('0') << std::setw(3) << ms.count() << " - " << message;
        std::string formatted_message = ss.str();

        if (log_file_.is_open()) {
            log_file_ << formatted_message << std::endl;
        } else {
            std::cerr << "Log file not open. Message: " << formatted_message << std::endl;
        }
    }

private:
    std::string filename_;
    std::ofstream log_file_;
};

// BH1750 Light Sensor class
class BH1750 {
public:
    BH1750(int bus) : bus_(bus), handle_(-1) {
        handle_ = i2cOpen(bus_, BH1750_ADDR, 0);
        if (handle_ < 0) {
            std::cerr << "Error opening I2C device: " << handle_ << std::endl;
        }
    }

    ~BH1750() {
        if (handle_ >= 0) {
            i2cClose(handle_);
        }
    }

    float readLux() {
        if (handle_ < 0) {
            logger_.log("I2C device not initialized. Cannot read lux value.");
            return -1.0f; // Indicate error
        }

        char config[1] = {MEASUREMENT_MODE}; // Configure for continuous high resolution mode
        int wrc = i2cWriteDevice(handle_, config, 1);
        if (wrc != 0) {
          logger_.log("Error writing to I2C device.");
          return -1.0f;
        }

        gpioDelay(200); // Wait for measurement (at least 180ms)

        int reading = i2cReadWordData(handle_, 0x00);
        if (reading < 0) {
            logger_.log("Error reading lux value from BH1750: " + std::to_string(reading));
            return -1.0f; // Indicate error
        }

        // BH1750 returns big-endian, need to swap bytes
        int swapped_reading = (reading >> 8) | (reading << 8);

        return static_cast<float>(swapped_reading) / 1.2f; // Convert to lux
    }

private:
    int bus_;
    int handle_;
    Logger logger_ = Logger("grow_log.txt");
};

// Relay control class
class Relay {
public:
    Relay(int gpio) : gpio_(gpio) {
        gpioSetMode(gpio_, PI_OUTPUT);
        gpioWrite(gpio_, 0); // Initialize relay to OFF
    }

    ~Relay() {
        gpioWrite(gpio_, 0); // Ensure relay is OFF on exit
    }

    void turnOn() {
        gpioWrite(gpio_, 1); // Activate relay
        logger_.log("Relay turned ON");
    }

    void turnOff() {
        gpioWrite(gpio_, 0); // Deactivate relay
        logger_.log("Relay turned OFF");
    }

private:
    int gpio_;
    Logger logger_ = Logger("grow_log.txt");
};


void signal_handler(int signal) {
    std::cout << "Signal received, stopping..." << std::endl;
    running = false;
}

int main() {
    if (gpioInitialise() < 0) {
        std::cerr << "pigpio initialisation failed\n";
        return 1;
    }

    // Register signal handler
    signal(SIGINT, signal_handler);

    // Instantiate classes
    BH1750 lightSensor(1); // I2C bus 1
    Relay relay(RELAY_GPIO);
    Logger logger("grow_log.txt");

    while (running) {
        float lux = lightSensor.readLux();

        if (lux >= 0) {
            logger.log("Lux value: " + std::to_string(lux));

            if (lux < LUX_THRESHOLD) {
                relay.turnOn();
            } else {
                relay.turnOff();
            }
        } else {
            logger.log("Failed to read lux value.");
        }

        gpioDelay(5000); // Check every 5 seconds
    }

    gpioTerminate();
    std::cout << "Program terminated gracefully.\n";
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <unistd.h>

// Configuration
#define IR_RECEIVE_PIN 5       // BCM GPIO 24, WiringPi pin 5
#define PULSE_TIMEOUT_US 12000 // Maximum pulse length to consider (microseconds)

// Timing Constants (microseconds)
#define HEADER_HIGH_MIN_US 8000
#define HEADER_LOW_MIN_US 4000
#define BIT_ZERO_HIGH_MIN_US 400
#define BIT_ONE_HIGH_MIN_US 1500
#define BIT_SAMPLE_PERIOD_US 560 // Typical pulse width for a bit

// Data buffer
#define DATA_BITS 32
unsigned char received_data[4];

// Function prototypes
int read_pulse(int timeout_us);
int decode_irm_data();
void print_received_data();

int main() {
    if (wiringPiSetup() < 0) {
        fprintf(stderr, "WiringPi initialization failed!\n");
        return 1;
    }

    pinMode(IR_RECEIVE_PIN, INPUT);
    pullUpDnControl(IR_RECEIVE_PIN, PUD_UP); // Enable pull-up resistor

    printf("IRM Decoder Program running...\n");

    while (1) {
        if (decode_irm_data() == 0) {
            print_received_data();
        }
        usleep(10000); // Sleep for 10ms to reduce CPU usage
    }

    return 0;
}

// Function to read a pulse duration from the IR receiver
int read_pulse(int timeout_us) {
    long startTime = micros();
    while (digitalRead(IR_RECEIVE_PIN) == 0 && micros() - startTime < timeout_us); // Wait for signal change or timeout
    long pulseStart = micros();
    while (digitalRead(IR_RECEIVE_PIN) == 1 && micros() - pulseStart < timeout_us); // Measure pulse width or timeout
    long pulseEnd = micros();

    if (pulseEnd - startTime >= timeout_us) {
        return -1; // Timeout occurred
    }
    return (int)(pulseEnd - startTime);
}

// Function to decode IRM data
int decode_irm_data() {
    int pulse_width;

    // Read Header
    pulse_width = read_pulse(PULSE_TIMEOUT_US);
    if (pulse_width < 0) return -1; // Timeout, no signal
    if (pulse_width < HEADER_HIGH_MIN_US) return -1; // Invalid Header High

    pulse_width = read_pulse(PULSE_TIMEOUT_US);
    if (pulse_width < 0) return -1; // Timeout
    if (pulse_width < HEADER_LOW_MIN_US) return -1; // Invalid Header Low

    // Read Data Bits
    for (int i = 0; i < 4; i++) {
        received_data[i] = 0;
        for (int j = 0; j < 8; j++) {
            pulse_width = read_pulse(PULSE_TIMEOUT_US);
            if (pulse_width < 0) return -1; // Timeout

            if (pulse_width > BIT_ONE_HIGH_MIN_US) {
                received_data[i] |= (1 << j);
            } else if (pulse_width < BIT_ZERO_HIGH_MIN_US) {
				return -1; //Invalid Bit

			}
        }
    }

    // Checksum Validation
    if ((received_data[0] + received_data[1] == 0xFF) && (received_data[2] + received_data[3] == 0xFF)) {
        return 0; // Success
    } else {
        fprintf(stderr, "Checksum Validation Failed!\n");
        return -1; // Failure
    }
}

// Function to print received data
void print_received_data() {
    printf("Received Key: 0x%02x\n", received_data[2]);
}

