#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <string.h>

#define MOTOR_1_GPIO 17
#define MOTOR_2_GPIO 18
#define PWM_RANGE 255

// VibrationMotor class
typedef struct {
    int gpio_pin;
} VibrationMotor;

// GeigerCounter class
typedef struct {
    int min_radiation;
    int max_radiation;
    FILE *log_file;
} GeigerCounter;

// VibrationMotor methods
void VibrationMotor_init(VibrationMotor *self, int gpio_pin) {
    self->gpio_pin = gpio_pin;
    gpioSetMode(self->gpio_pin, PI_OUTPUT);
}

void VibrationMotor_set_intensity(VibrationMotor *self, int intensity) {
    if (intensity < 0) intensity = 0;
    if (intensity > PWM_RANGE) intensity = PWM_RANGE;
    gpioPWM(self->gpio_pin, intensity);
}

// GeigerCounter methods
void GeigerCounter_init(GeigerCounter *self, int min_radiation, int max_radiation, const char *log_file_name) {
    self->min_radiation = min_radiation;
    self->max_radiation = max_radiation;
    self->log_file = fopen(log_file_name, "a");
    if (self->log_file == NULL) {
        perror("Error opening log file");
        exit(EXIT_FAILURE);
    }
}

int GeigerCounter_generate_radiation(GeigerCounter *self) {
    return (rand() % (self->max_radiation - self->min_radiation + 1)) + self->min_radiation;
}

int GeigerCounter_calculate_intensity(GeigerCounter *self, int radiation_level) {
    // Scale radiation level to PWM range
    double scale = (double)PWM_RANGE / (self->max_radiation - self->min_radiation);
    int intensity = (int)((radiation_level - self->min_radiation) * scale);
    return intensity;
}

void GeigerCounter_log_radiation(GeigerCounter *self, int radiation_level) {
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    fprintf(self->log_file, "%s,Radiation Level: %d\n", timestamp, radiation_level);
    fflush(self->log_file); // Ensure data is written to file immediately
}

void GeigerCounter_cleanup(GeigerCounter *self) {
    if (self->log_file != NULL) {
        fclose(self->log_file);
    }
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    srand(time(NULL)); // Seed random number generator

    VibrationMotor motor1, motor2;
    GeigerCounter geiger_counter;

    VibrationMotor_init(&motor1, MOTOR_1_GPIO);
    VibrationMotor_init(&motor2, MOTOR_2_GPIO);
    GeigerCounter_init(&geiger_counter, 10, 100, "radiation_log.txt");

    printf("Geiger counter simulator running...\n");

    for (int i = 0; i < 100; ++i) { // Simulate for a while
        int radiation_level = GeigerCounter_generate_radiation(&geiger_counter);
        int intensity = GeigerCounter_calculate_intensity(&geiger_counter, radiation_level);

        VibrationMotor_set_intensity(&motor1, intensity);
        VibrationMotor_set_intensity(&motor2, intensity);
        GeigerCounter_log_radiation(&geiger_counter, radiation_level);

        printf("Radiation level: %d, Intensity: %d\n", radiation_level, intensity);
        gpioDelay(100); // Delay 100ms
    }

    VibrationMotor_set_intensity(&motor1, 0); // Stop motors
    VibrationMotor_set_intensity(&motor2, 0); // Stop motors
    GeigerCounter_cleanup(&geiger_counter);
    gpioTerminate();

    printf("Geiger counter simulator finished.\n");
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <math.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>

// MPU6050 I2C address
#define MPU6050_ADDRESS 0x68

// MPU6050 registers
#define PWR_MGMT_1 0x6B
#define ACCEL_XOUT_H 0x3B
#define ACCEL_YOUT_H 0x3D
#define ACCEL_ZOUT_H 0x3F

// LED GPIO pin
#define LED_PIN 17

// Acceleration threshold (in g)
#define ACCELERATION_THRESHOLD 2.0

// Sensitivity scale factor (LSB/g)
#define ACCELEROMETER_SENSITIVITY 16384.0

// Debounce delay (in milliseconds)
#define DEBOUNCE_DELAY 200

// Global variable to store the last LED state
static int lastLedState = LOW;
static unsigned long lastDebounceTime = 0;

// Function to initialize the MPU6050
int mpu6050_init(int fd) {
    // Wake up the MPU6050 (clear sleep bit)
    if (wiringPiI2CWriteReg8(fd, PWR_MGMT_1, 0) < 0) {
        fprintf(stderr, "Error: Could not wake up MPU6050\n");
        return -1;
    }
    return 0;
}

// Function to read a 16-bit value from the MPU6050
int16_t read_raw_data(int fd, int addr) {
    int16_t high_byte, low_byte, value;

    high_byte = wiringPiI2CReadReg8(fd, addr);
    low_byte = wiringPiI2CReadReg8(fd, addr + 1);

    if (high_byte < 0 || low_byte < 0) {
        fprintf(stderr, "Error: Could not read data from MPU6050 register 0x%02X\n", addr);
        return 0; // Return 0 on error
    }

    value = (high_byte << 8) | low_byte;
    return value;
}

// Function to read accelerometer data
void read_accelerometer_data(int fd, float *x, float *y, float *z) {
    int16_t raw_x, raw_y, raw_z;

    raw_x = read_raw_data(fd, ACCEL_XOUT_H);
    raw_y = read_raw_data(fd, ACCEL_YOUT_H);
    raw_z = read_raw_data(fd, ACCEL_ZOUT_H);

    *x = (float)raw_x / ACCELEROMETER_SENSITIVITY;
    *y = (float)raw_y / ACCELEROMETER_SENSITIVITY;
    *z = (float)raw_z / ACCELEROMETER_SENSITIVITY;
}

// Function to calculate the magnitude of acceleration
float calculate_acceleration_magnitude(float x, float y, float z) {
    return sqrt(x * x + y * y + z * z);
}

// Function to control the LED with debouncing
void control_led(float acceleration_magnitude) {
    int ledState = LOW;

    if (acceleration_magnitude > ACCELERATION_THRESHOLD) {
        ledState = HIGH;
    }

    unsigned long currentTime = millis();
    if (ledState != lastLedState) {
        if ((currentTime - lastDebounceTime) > DEBOUNCE_DELAY) {
            digitalWrite(LED_PIN, ledState);
            lastLedState = ledState;
            lastDebounceTime = currentTime;
        }
    }
}

int main() {
    int fd;
    float x, y, z, acceleration_magnitude;

    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error: Could not initialize wiringPi\n");
        return 1;
    }

    // Initialize I2C
    fd = wiringPiI2CSetup(MPU6050_ADDRESS);
    if (fd == -1) {
        fprintf(stderr, "Error: Could not initialize I2C communication\n");
        return 1;
    }

    // Initialize MPU6050
    if (mpu6050_init(fd) == -1) {
        return 1;
    }

    // Set LED pin as output
pinMode(LED_PIN, OUTPUT);

    printf("MPU6050 accelerometer data logging. Press Ctrl+C to exit.\n");

    while (1) {
        // Read accelerometer data
        read_accelerometer_data(fd, &x, &y, &z);

        // Calculate acceleration magnitude
        acceleration_magnitude = calculate_acceleration_magnitude(x, y, z);

        // Log data to console
        printf("X: %.2f g, Y: %.2f g, Z: %.2f g, Magnitude: %.2f g\n", x, y, z, acceleration_magnitude);

        // Control LED based on acceleration magnitude
        control_led(acceleration_magnitude);

        // Delay for a short period
delay(50);
    }

    return 0;
}

#include <pigpio.h>
