#define M1_ENA  13 
#define M2_INA1 19 
#define M2_INA2 26 
#define M2_ENA  16 

void setup() {
    if (gpioInitialise() < 0) return;
    gpioSetMode(M1_INA1, PI_OUTPUT);
    gpioSetMode(M1_INA2, PI_OUTPUT);
    gpioSetMode(M1_ENA, PI_OUTPUT);
    gpioSetMode(M2_INA1, PI_OUTPUT);
    gpioSetMode(M2_INA2, PI_OUTPUT);
    gpioSetMode(M2_ENA, PI_OUTPUT);
}

void turnLeft() {
    gpioWrite(M1_INA1, 1);
    gpioWrite(M1_INA2, 0);
    gpioWrite(M2_INA1, 1);
    gpioWrite(M2_INA2, 0);
    gpioPWM(M1_ENA, 100);
    gpioPWM(M2_ENA, 50);
}

void turnRight() {
    gpioWrite(M1_INA1, 1);
    gpioWrite(M1_INA2, 0);
    gpioWrite(M2_INA1, 1);
    gpioWrite(M2_INA2, 0);
    gpioPWM(M1_ENA, 50);
    gpioPWM(M2_ENA, 100);
}

void stopMotors() {
    gpioWrite(M1_INA1, 0);
    gpioWrite(M1_INA2, 0);
    gpioWrite(M2_INA1, 0);
    gpioWrite(M2_INA2, 0);
    gpioPWM(M1_ENA, 0);
    gpioPWM(M2_ENA, 0);
}

