#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <errno.h>
#include <wiringPi.h>
#include <wiringPiSPI.h>

#define SPI_CHANNEL 0
#define SPI_SPEED 1000000 // 1MHz
#define MCP3008_CHANNEL 0 // Channel connected to soil moisture sensor
#define CS_PIN 8            // Chip Select pin for MCP3008 (WiringPi pin 8)
#define LED_PIN 0           // GPIO 17 (WiringPi pin 0)
#define MOISTURE_THRESHOLD 300

FILE *log_file = NULL;

// Function prototypes
int init_wiringpi();
int init_spi();
int init_gpio();
int read_mcp3008(int channel);
void log_data(int adc_value);
void control_led(int adc_value);
void cleanup();
void signal_handler(int signal);

int main() {
    signal(SIGINT, signal_handler); // Register signal handler for Ctrl+C

    if (init_wiringpi() != 0) {
        fprintf(stderr, "Failed to initialize wiringPi. Exiting.\n");
        return 1;
    }

    if (init_spi() != 0) {
        fprintf(stderr, "Failed to initialize SPI. Exiting.\n");
        cleanup();
        return 1;
    }

    if (init_gpio() != 0) {
        fprintf(stderr, "Failed to initialize GPIO. Exiting.\n");
        cleanup();
        return 1;
    }

    log_file = fopen("soil_data.txt", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        cleanup();
        return 1;
    }

    printf("Soil Moisture Monitoring Started. Press Ctrl+C to exit.\n");

    while (1) {
        int adc_value = read_mcp3008(MCP3008_CHANNEL);
        if (adc_value == -1) {
            fprintf(stderr, "Failed to read ADC value. Retrying.\n");
            delay(100); // Small delay before retrying
            continue;    // Skip to the next iteration
        }

        log_data(adc_value);
        control_led(adc_value);
        delay(5000); // Read every 5 seconds
    }

    return 0;
}

// Initializes wiringPi library
int init_wiringpi() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

// Initializes SPI communication
int init_spi() {
    if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) == -1) {
        fprintf(stderr, "wiringPiSPISetup failed: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

// Initializes GPIO pins
int init_gpio() {
    pinMode(LED_PIN, OUTPUT);
    digitalWrite(LED_PIN, LOW); // Initially turn off the LED
    return 0;
}

// Reads data from MCP3008 ADC
int read_mcp3008(int channel) {
    if (channel < 0 || channel > 7) {
        fprintf(stderr, "Invalid MCP3008 channel: %d\n", channel);
        return -1;
    }

    unsigned char buffer[3];
    buffer[0] = 0x01;                                       // Start bit
    buffer[1] = (0x08 | channel) << 4;                       // SGL/DIFF, D2, D1, D0
    buffer[2] = 0x00;                                       // Don't care

    digitalWrite(CS_PIN, LOW); // Select the MCP3008
    wiringPiSPIDataRW(SPI_CHANNEL, buffer, 3);
    digitalWrite(CS_PIN, HIGH); // Deselect the MCP3008

    int adc_value = ((buffer[1] & 0x03) << 8) + buffer[2]; // Extract data from buffer
    return adc_value;
}

// Logs data to file with timestamp
void log_data(int adc_value) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(log_file, "%s,%d\n", timestamp, adc_value);
    fflush(log_file); // Ensure data is written to file immediately
    printf("%s,ADC Value: %d\n", timestamp, adc_value);
}

// Controls the LED based on moisture level
void control_led(int adc_value) {
    if (adc_value < MOISTURE_THRESHOLD) {
        digitalWrite(LED_PIN, HIGH); // Turn on LED if moisture is low
    } else {
        digitalWrite(LED_PIN, LOW);  // Turn off LED if moisture is sufficient
    }
}

// Cleanup function to close file and reset LED
void cleanup() {
    printf("Cleaning up and exiting.\n");
    if (log_file != NULL) {
        fclose(log_file);
    }
    digitalWrite(LED_PIN, LOW); // Turn off LED
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d\n", signal);
    cleanup();
    exit(0);
}

