#define GPIO_23 23

// Define GPIO path buffer size
#define GPIO_PATH_MAX 64

// Global variables for GPIO paths
char gpio17_path[GPIO_PATH_MAX];
char gpio18_path[GPIO_PATH_MAX];
char gpio22_path[GPIO_PATH_MAX];
char gpio23_path[GPIO_PATH_MAX];

// Function prototypes
int gpio_export(int gpio);
int gpio_unexport(int gpio);
int gpio_set_direction(int gpio, const char *direction);
