// Function to export a GPIO pin
int gpio_export(int gpio) {
    char buffer[3];
    int len;
    FILE *fp = fopen("/sys/class/gpio/export", "w");
    if (fp == NULL) {
        fprintf(stderr, "Error: Failed to open /sys/class/gpio/export for writing: %s\n", strerror(errno));
        return -1;
    }
    len = snprintf(buffer, sizeof(buffer), "%d", gpio);
    if (fwrite(buffer, 1, len, fp) != len) {
        fprintf(stderr, "Error: Failed to write to /sys/class/gpio/export: %s\n", strerror(errno));
        fclose(fp);
        return -1;
    }
    fclose(fp);
    return 0;
}

// Function to unexport a GPIO pin
int gpio_unexport(int gpio) {
    char buffer[3];
    int len;
    FILE *fp = fopen("/sys/class/gpio/unexport", "w");
    if (fp == NULL) {
        fprintf(stderr, "Error: Failed to open /sys/class/gpio/unexport for writing: %s\n", strerror(errno));
        return -1;
    }
    len = snprintf(buffer, sizeof(buffer), "%d", gpio);
    if (fwrite(buffer, 1, len, fp) != len) {
        fprintf(stderr, "Error: Failed to write to /sys/class/gpio/unexport: %s\n", strerror(errno));
        fclose(fp);
        return -1;
    }
    fclose(fp);
    return 0;
}

// Function to set the direction of a GPIO pin (in or out)
int gpio_set_direction(int gpio, const char *direction) {
    char path[GPIO_PATH_MAX];
    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/direction", gpio);
    FILE *fp = fopen(path, "w");
    if (fp == NULL) {
        fprintf(stderr, "Error: Failed to open %s for writing: %s\n", path, strerror(errno));
        return -1;
    }
    if (fprintf(fp, "%s", direction) < 0) {
        fprintf(stderr, "Error: Failed to write to %s: %s\n", path, strerror(errno));
        fclose(fp);
        return -1;
    }
    fclose(fp);
    return 0;
}

// Function to write a value (0 or 1) to a GPIO pin
int gpio_write(const char *path, int value) {
    FILE *fp = fopen(path, "w");
    if (fp == NULL) {
        fprintf(stderr, "Error: Failed to open %s for writing: %s\n", path, strerror(errno));
        return -1;
    }
    if (fprintf(fp, "%d", value) < 0) {
        fprintf(stderr, "Error: Failed to write to %s: %s\n", path, strerror(errno));
        fclose(fp);
        return -1;
    }
    fclose(fp);
    return 0;
}

// Motor control functions
void motor1_forward() {
    if (gpio_write(gpio17_path, 1) < 0 || gpio_write(gpio18_path, 0) < 0) {
        fprintf(stderr, "Error: Failed to set motor 1 forward\n");
    }
}

void motor1_reverse() {
    if (gpio_write(gpio17_path, 0) < 0 || gpio_write(gpio18_path, 1) < 0) {
        fprintf(stderr, "Error: Failed to set motor 1 reverse\n");
    }
}

void motor1_stop() {
    if (gpio_write(gpio17_path, 0) < 0 || gpio_write(gpio18_path, 0) < 0) {
        fprintf(stderr, "Error: Failed to stop motor 1\n");
    }
}

void motor2_forward() {
    if (gpio_write(gpio22_path, 1) < 0 || gpio_write(gpio23_path, 0) < 0) {
        fprintf(stderr, "Error: Failed to set motor 2 forward\n");
    }
}

void motor2_reverse() {
    if (gpio_write(gpio22_path, 0) < 0 || gpio_write(gpio23_path, 1) < 0) {
        fprintf(stderr, "Error: Failed to set motor 2 reverse\n");
    }
}

void motor2_stop() {
    if (gpio_write(gpio22_path, 0) < 0 || gpio_write(gpio23_path, 0) < 0) {
        fprintf(stderr, "Error: Failed to stop motor 2\n");
    }
}

// Simulated sun-tracking logic
void adjust_motors() {
    // Simulate sun movement (example: move slightly to the left)
    printf("Adjusting motors...\n");
    motor1_forward();
    motor2_reverse();
    usleep(100000); // 100ms
    motor1_stop();
    motor2_stop();
    printf("Adjustment complete.\n");
}

// Signal handler for Ctrl+C
void signal_handler(int signum) {
    if (signum == SIGINT) {
        printf("Caught SIGINT, cleaning up...\n");
        motor1_stop();
        motor2_stop();
        gpio_unexport(GPIO_17);
        gpio_unexport(GPIO_18);
        gpio_unexport(GPIO_22);
        gpio_unexport(GPIO_23);
        printf("Cleanup complete, exiting.\n");
        exit(0);
    }
}

int main() {
    // Setup signal handling
    signal(SIGINT, signal_handler);

    // Export GPIO pins
    if (gpio_export(GPIO_17) < 0 ||
        gpio_export(GPIO_18) < 0 ||
        gpio_export(GPIO_22) < 0 ||
        gpio_export(GPIO_23) < 0) {
        fprintf(stderr, "Error: Failed to export GPIO pins\n");
        exit(1);
    }

    // Set GPIO directions to output
    if (gpio_set_direction(GPIO_17, "out") < 0 ||
        gpio_set_direction(GPIO_18, "out") < 0 ||
        gpio_set_direction(GPIO_22, "out") < 0 ||
        gpio_set_direction(GPIO_23, "out") < 0) {
        fprintf(stderr, "Error: Failed to set GPIO directions\n");
        exit(1);
    }

    // Construct GPIO value paths
    snprintf(gpio17_path, sizeof(gpio17_path), "/sys/class/gpio/gpio%d/value", GPIO_17);
    snprintf(gpio18_path, sizeof(gpio18_path), "/sys/class/gpio/gpio%d/value", GPIO_18);
    snprintf(gpio22_path, sizeof(gpio22_path), "/sys/class/gpio/gpio%d/value", GPIO_22);
    snprintf(gpio23_path, sizeof(gpio23_path), "/sys/class/gpio/gpio%d/value", GPIO_23);

    printf("Sun tracker started. Press Ctrl+C to exit.\n");

    // Main loop: simulate sun tracking
    while (1) {
        adjust_motors();
        sleep(5); // Adjust every 5 seconds
    }

    return 0;
}

#include <wiringPi.h>
#include <stdio.h>
#define IN1 3
#define IN2 2
#define IN3 0
#define IN4 7
#define BUTTON 4
void set_step(int a, int b, int c, int d) {
    digitalWrite(IN1, a);
    digitalWrite(IN2, b);
    digitalWrite(IN3, c);
    digitalWrite(IN4, d);
}
void rotate_half_step(int steps) {
    for (int i = 0; i < steps; i++) {
        set_step(1, 0, 0, 0);
        delay(3);
        set_step(1, 1, 0, 0);
        delay(3);
        set_step(0, 1, 0, 0);
        delay(3);
        set_step(0, 1, 1, 0);
        delay(3);
        set_step(0, 0, 1, 0);
        delay(3);
        set_step(0, 0, 1, 1);
        delay(3);
        set_step(0, 0, 0, 1);
        delay(3);
        set_step(1, 0, 0, 1);
        delay(3);
    }
}
int main() {
    wiringPiSetup();
    pinMode(IN1, OUTPUT);
    pinMode(IN2, OUTPUT);
    pinMode(IN3, OUTPUT);
    pinMode(IN4, OUTPUT);
    pinMode(BUTTON, INPUT);
    pullUpDnControl(BUTTON, PUD_UP);
    while(1) {
        if (digitalRead(BUTTON) == 0) {
            rotate_half_step(512); // Open door
            delay(5000);
            rotate_half_step(-512); // Close door
        }
    }
    return 0;
}

