// Function to calculate CPU load as a percentage
float calculate_cpu_load() {
    struct sysinfo info1, info2;
    int ret1, ret2;
    long long cpu_usage1, cpu_usage2;
    float load;

    ret1 = sysinfo(&info1);
    if (ret1 != 0) {
        fprintf(stderr, "Error: Failed to get system info (1).\n");
        perror("sysinfo");
        return -1.0f; // Indicate error
    }

    usleep(100000); // Wait 100ms

    ret2 = sysinfo(&info2);
    if (ret2 != 0) {
        fprintf(stderr, "Error: Failed to get system info (2).\n");
        perror("sysinfo");
        return -1.0f; // Indicate error
    }

    cpu_usage1 = info1.totalram - info1.freeram;
    cpu_usage2 = info2.totalram - info2.freeram;

    load = (float)(cpu_usage2 - cpu_usage1) / (float)info1.totalram * 100.0f;

    return load;
}

// Function to determine the LED color based on CPU load
int determine_led_color(float cpu_load) {
    if (cpu_load >= 0.0f && cpu_load <= 33.0f) {
        return 0; // Red
    } else if (cpu_load > 33.0f && cpu_load <= 66.0f) {
        return 1; // Green
    } else if (cpu_load > 66.0f && cpu_load <= 100.0f) {
        return 2; // Blue
    } else {
        return -1; // Invalid load value
    }
}

// Function to set the LEDs based on the determined color
int set_leds(int red_gpio, int green_gpio, int blue_gpio, int color) {
    int red_value = 0, green_value = 0, blue_value = 0;

    switch (color) {
        case 0: // Red
            red_value = 1;
            break;
        case 1: // Green
            green_value = 1;
            break;
        case 2: // Blue
            blue_value = 1;
            break;
        default:
            fprintf(stderr, "Error: Invalid LED color: %d\n", color);
            return -1;
    }

    if (gpio_set_value(red_gpio, red_value) != 0) return -1;
    if (gpio_set_value(green_gpio, green_value) != 0) return -1;
    if (gpio_set_value(blue_gpio, blue_value) != 0) return -1;

    return 0;
}

int main() {
    // Install signal handler for graceful termination
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Export GPIO pins
    if (gpio_export(RED_GPIO) != 0 ||
        gpio_export(GREEN_GPIO) != 0 ||
        gpio_export(BLUE_GPIO) != 0) {
        fprintf(stderr, "Error: Failed to export GPIO pins. Exiting.\n");
        return 1;
    }

    // Set GPIO direction to output
    if (gpio_set_direction(RED_GPIO, "out") != 0 ||
        gpio_set_direction(GREEN_GPIO, "out") != 0 ||
        gpio_set_direction(BLUE_GPIO, "out") != 0) {
        fprintf(stderr, "Error: Failed to set GPIO direction. Exiting.\n");
        goto cleanup;
    }

    // Initialize LEDs to off
    if (set_leds(RED_GPIO, GREEN_GPIO, BLUE_GPIO, -1) != 0) { //Using -1 to turn all off
        fprintf(stderr, "Error: Failed to initialize LEDs. Exiting.\n");
        goto cleanup;
    }

    // Main loop
    while (program_running) {
        float cpu_load = calculate_cpu_load();
        if (cpu_load < 0.0f) {
            fprintf(stderr, "Error: Failed to calculate CPU load. Continuing.\n");
            sleep(1);
            continue;
        }

        int led_color = determine_led_color(cpu_load);
        if (led_color == -1) {
            fprintf(stderr, "Error: Invalid LED color. Continuing.\n");
            sleep(1);
            continue;
        }

        if (set_leds(RED_GPIO, GREEN_GPIO, BLUE_GPIO, led_color) != 0) {
            fprintf(stderr, "Error: Failed to set LEDs. Continuing.\n");
        }

        sleep(1);
    }

cleanup:
    // Cleanup: Turn off LEDs and unexport GPIO pins
    set_leds(RED_GPIO, GREEN_GPIO, BLUE_GPIO, -1); // Turn off all LEDs
    gpio_unexport(RED_GPIO);
    gpio_unexport(GREEN_GPIO);
    gpio_unexport(BLUE_GPIO);

    return 0;
}

