#define CONVERSION_REG 0x00
#define REF_VOLTAGE 4.096
int read_ads1115(int fd) {
    wiringPiI2CWriteReg16(fd, CONFIG_REG, 0xC283);
    usleep(9000);
    int val = wiringPiI2CReadReg16(fd, CONVERSION_REG);
    val = ((val << 8) & 0xFF00) | ((val >> 8) & 0x00FF);
    return val;
}
int read_mcp3008(int ch) {
    unsigned char buf[3] = {1, (0x80 | (ch << 4)), 0};
    wiringPiSPIDataRW(0, buf, 3);
    return ((buf[1] & 0x03) << 8) | buf[2];
}
