// Define GPIO pins for the seven segments (adjust to your wiring)
#define SEG_A 4
#define SEG_B 17
#define SEG_C 27
#define SEG_D 22
#define SEG_E 5
#define SEG_F 6
#define SEG_G 13

// Function to display a number on the seven-segment display
void display_number(int number) {
    // Turn off all segments initially
    gpioWrite(SEG_A, 0);
    gpioWrite(SEG_B, 0);
    gpioWrite(SEG_C, 0);
    gpioWrite(SEG_D, 0);
    gpioWrite(SEG_E, 0);
    gpioWrite(SEG_F, 0);
    gpioWrite(SEG_G, 0);

    switch (number) {
        case 0:
            gpioWrite(SEG_A, 1);
            gpioWrite(SEG_B, 1);
            gpioWrite(SEG_C, 1);
            gpioWrite(SEG_D, 1);
            gpioWrite(SEG_E, 1);
            gpioWrite(SEG_F, 1);
            break;
        case 1:
            gpioWrite(SEG_B, 1);
            gpioWrite(SEG_C, 1);
            break;
        case 2:
            gpioWrite(SEG_A, 1);
            gpioWrite(SEG_B, 1);
            gpioWrite(SEG_D, 1);
            gpioWrite(SEG_E, 1);
            gpioWrite(SEG_G, 1);
            break;
        case 3:
            gpioWrite(SEG_A, 1);
            gpioWrite(SEG_B, 1);
            gpioWrite(SEG_C, 1);
            gpioWrite(SEG_D, 1);
            gpioWrite(SEG_G, 1);
            break;
        default:
            break; // Handle invalid numbers (optional)
    }
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pins as outputs
    gpioSetMode(SEG_A, PI_OUTPUT);
    gpioSetMode(SEG_B, PI_OUTPUT);
    gpioSetMode(SEG_C, PI_OUTPUT);
    gpioSetMode(SEG_D, PI_OUTPUT);
    gpioSetMode(SEG_E, PI_OUTPUT);
    gpioSetMode(SEG_F, PI_OUTPUT);
    gpioSetMode(SEG_G, PI_OUTPUT);

    // Countdown from 3 to 0
    for (int i = 3; i >= 0; i--) {
        display_number(i);
        printf("Displaying: %d\n", i);
        usleep(1500000); // 1.5 seconds delay (1500000 microseconds)
    }

    // Clear the display
    gpioWrite(SEG_A, 0);
    gpioWrite(SEG_B, 0);
    gpioWrite(SEG_C, 0);
    gpioWrite(SEG_D, 0);
    gpioWrite(SEG_E, 0);
    gpioWrite(SEG_F, 0);
    gpioWrite(SEG_G, 0);

    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <pigpio.h>
#include <time.h>

// Configuration constants
#define SPI_SS_GPIO 25          // GPIO pin for Slave Select (Chip Select)
#define NUM_ADCS 5             // Number of connected MCP3202 ADCs
#define ADC_BITS 12             // Resolution of the ADC (12 bits)
#define DATA_BIT_START 6        // Starting bit position of the ADC data (B11)
#define MISO_GPIO_1 6           // MISO GPIO pin for ADC 1
#define MISO_GPIO_2 26          // MISO GPIO pin for ADC 2
#define MISO_GPIO_3 13          // MISO GPIO pin for ADC 3
#define MISO_GPIO_4 23          // MISO GPIO pin for ADC 4
#define MISO_GPIO_5 24          // MISO GPIO pin for ADC 5
#define WAVE_BUFFER_SIZE 250    // Size of the wave buffer (adjust for rescheduling)
#define SAMPLE_INTERVAL_US 40   // Time between readings (microseconds) - must be > SPI transaction time
#define NUM_SAMPLES 2000000     // Total number of samples to acquire

// SPI configuration structure
typedef struct {
    int clk_gpio;        // GPIO pin for SPI clock
    int mosi_gpio;       // GPIO pin for SPI MOSI
    int ss_gpio;         // GPIO pin for Slave Select
    int ss_polarity;     // Slave Select resting level (0 or 1)
    int ss_delay_us;    // Delay after asserting Slave Select (microseconds)
    int clk_polarity;    // Clock resting level (0 or 1)
    int clk_phase;       // Clock phase (0: sample on first edge, 1: sample on second edge)
    int clk_delay_us;    // Clock delay (microseconds, determines SPI speed)
} SPIConfig;

// Global variables
const int miso_gpios[NUM_ADCS] = {MISO_GPIO_1, MISO_GPIO_2, MISO_GPIO_3, MISO_GPIO_4, MISO_GPIO_5};

SPIConfig spi_config = {
    .clk_gpio = 5,          // SPI clock GPIO
    .mosi_gpio = 12,         // SPI MOSI GPIO
    .ss_gpio = SPI_SS_GPIO, // SPI Slave Select GPIO
    .ss_polarity = 1,       // Slave Select active low
    .ss_delay_us = 1,       // Delay after asserting Slave Select
    .clk_polarity = 0,       // SPI clock polarity
    .clk_phase = 0,          // SPI clock phase
    .clk_delay_us = 1         // SPI clock delay (adjust for SPI speed)
};

// Function prototypes
int setup_gpio();
int setup_spi_wave(int *wave_id_ptr);
void cleanup_gpio();
void read_adc_data(int wave_id, int top_ool, float cbs_per_reading);

// Helper function to extract a bit from a byte array
int get_bit(const char *buf, int bit_index) {
    int byte_index = bit_index / 8;
    int bit_offset = bit_index % 8;
    return (buf[byte_index] >> (7 - bit_offset)) & 1;
}

// Helper function to set a bit in a byte array
void set_bit(char *buf, int bit_index, int value) {
    int byte_index = bit_index / 8;
    int bit_offset = bit_index % 8;
    if (value) {
        buf[byte_index] |= (1 << (7 - bit_offset));
    } else {
        buf[byte_index] &= ~(1 << (7 - bit_offset));
    }
}


int main(int argc, char *argv[]) {
    int wave_id = -1; // Initialize to an invalid value
    int pause_duration = 0;

    if (argc > 1) {
        pause_duration = atoi(argv[1]);
    }

    // Initialize the pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Configure GPIO pins
    if (setup_gpio() != 0) {
        fprintf(stderr, "GPIO setup failed\n");
        cleanup_gpio();
        return 1;
    }

    // Set up the SPI wave for DMA transfer
    if (setup_spi_wave(&wave_id) != 0) {
        fprintf(stderr, "SPI wave setup failed\n");
        cleanup_gpio();
        return 1;
    }

    rawWaveInfo_t rwi = rawWaveInfo(wave_id);
    float cbs_per_reading = (float)rwi.numCB / (float)WAVE_BUFFER_SIZE;
    int top_ool = rwi.topOOL;

    fprintf(stderr, "Starting data acquisition...\n");

    if (pause_duration) {
        time_sleep(pause_duration);
    }

    // Start the wave transmission in repeat mode
    gpioWaveTxSend(wave_id, PI_WAVE_MODE_REPEAT);

    // Read data from the ADCs
    read_adc_data(wave_id, top_ool, cbs_per_reading);

    fprintf(stderr, "Ending data acquisition...\n");

    if (pause_duration) {
        time_sleep(pause_duration);
    }

    // Clean up and terminate the pigpio library
    cleanup_gpio();

    return 0;
}

// Function to set up the GPIO pins
int setup_gpio() {
    // Set MOSI, CLK, and SS as outputs
    if (gpioSetMode(spi_config.mosi_gpio, PI_OUTPUT) != 0 ||
        gpioSetMode(spi_config.clk_gpio, PI_OUTPUT) != 0 ||
        gpioSetMode(spi_config.ss_gpio, PI_OUTPUT) != 0) {
        fprintf(stderr, "Failed to set MOSI, CLK, or SS as outputs\n");
        return 1;
    }

    // Set MISO pins as inputs
    for (int i = 0; i < NUM_ADCS; ++i) {
        if (gpioSetMode(miso_gpios[i], PI_INPUT) != 0) {
            fprintf(stderr, "Failed to set MISO %d as input\n", i + 1);
            return 1;
        }
    }

    return 0;
}

// Function to set up the SPI wave for DMA transfer
int setup_spi_wave(int *wave_id_ptr) {
    int offset = 0;
    char spi_data[2];
    gpioPulse_t final_pulse[2];

    gpioWaveAddNew(); // Clear any existing wave data

    // Construct the SPI wave for reading data from the MCP3202 ADCs
    for (int i = 0; i < WAVE_BUFFER_SIZE; ++i) {
        // MCP3202 configuration: Start bit, single-ended, channel 0
        spi_data[0] = 0xC0; // 11000000

        if (rawWaveAddSPI(&(rawSPI_t){spi_config.clk_gpio, spi_config.mosi_gpio, spi_config.ss_polarity, spi_config.ss_delay_us, spi_config.clk_polarity, spi_config.clk_phase, spi_config.clk_delay_us}, offset, spi_config.ss_gpio, spi_data, 2, DATA_BIT_START, ADC_BITS + DATA_BIT_START -1, ADC_BITS + DATA_BIT_START -1) != 0) {
            fprintf(stderr, "Failed to add SPI data to wave\n");
            return 1;
        }

        offset += SAMPLE_INTERVAL_US; // Increment the offset for the next reading
    }

    // Add a final delay to ensure consistent timing
    final_pulse[0].gpioOn = 0;
    final_pulse[0].gpioOff = 0;
    final_pulse[0].usDelay = offset;

    final_pulse[1].gpioOn = 0; // Dummy pulse to force the final delay
    final_pulse[1].gpioOff = 0;
    final_pulse[1].usDelay = 0;

    gpioWaveAddGeneric(2, final_pulse);

    // Create the wave from the added data
    int wave_id = gpioWaveCreate();
    if (wave_id < 0) {
        fprintf(stderr, "Failed to create wave: %d (too much data?)\n", wave_id);
        return 1;
    }

    *wave_id_ptr = wave_id; // Store the wave ID
    return 0;
}

// Function to read data from the ADCs using DMA transfer
void read_adc_data(int wave_id, int top_ool, float cbs_per_reading) {
    double start_time, end_time;
    int current_sample = 0;
    int reading_index = 0;
    char raw_data[NUM_ADCS * 2]; // Buffer to store raw ADC data (2 bytes per ADC)
    int adc_values[NUM_ADCS];      // Array to store converted ADC values

    start_time = time_time();

    while (current_sample < NUM_SAMPLES) {
        // Calculate the current reading index based on the control block position
        int current_cb = rawWaveCB() - rawWaveInfo(wave_id).botCB;
        int now_reading_index = (float)current_cb / cbs_per_reading;

        // Process new readings
        while (now_reading_index != reading_index) {
            // Calculate the offset into the OOL data for the current reading
            int ool_offset = top_ool - ((reading_index % WAVE_BUFFER_SIZE) * ADC_BITS) - 1;

            // Read raw data from the OOL buffer
            for (int adc_index = 0; adc_index < NUM_ADCS; ++adc_index) {
                // Initialize the raw data buffer for each ADC
                for (int i = 0; i < 2; ++i) {
                    raw_data[adc_index * 2 + i] = 0;
                }

                // Extract the bits for each ADC from the wave buffer
                for (int bit_index = 0; bit_index < ADC_BITS; ++bit_index) {
                    uint32_t level = rawWaveGetOut(ool_offset - bit_index);
                    int bit_value = (level >> miso_gpios[adc_index]) & 1;
                    set_bit(&raw_data[adc_index * 2], bit_index, bit_value);
                }

                // Convert the raw data to an integer value
                adc_values[adc_index] = ((raw_data[adc_index * 2] & 0xFF) << 4) | ((raw_data[adc_index * 2 + 1] & 0xFF) >> 4);
            }

            // Print the sample number and ADC values
            printf("%d", ++current_sample);
            for (int i = 0; i < NUM_ADCS; ++i) {
                printf(" %d", adc_values[i]);
            }
            printf("\n");

            // Update the reading index
            reading_index = (reading_index + 1) % WAVE_BUFFER_SIZE;
        }
        usleep(1000); // Reduce CPU usage
    }

    end_time = time_time();

    printf("# %d samples in %.1f seconds (%.0f/s)\n",
           NUM_SAMPLES, end_time - start_time, (float)NUM_SAMPLES / (end_time - start_time));
}

// Function to clean up the GPIO pins
void cleanup_gpio() {
    gpioTerminate();
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/mman.h>
#include <sys/types.h>
#include <sys/stat.h>
#include <stdint.h>

// Define GPIO pin for the vibration sensor (GPIO4)
#define GPIO_PIN 4

// Define the systemd service name
#define SERVICE_NAME "vibration-alert.service"

// Define the threshold for vibration detection
#define VIBRATION_THRESHOLD 500

// Define the moving average window size
#define WINDOW_SIZE 5

// GPIO memory base address (will be dynamically determined)
static volatile uint32_t *gpio_map = NULL;

// File descriptor for memory mapping
static int mem_fd;

// Log file pointer
static FILE *log_file = NULL;

// Function prototypes (pure functions)
int read_gpio_pin(volatile uint32_t *gpio, int pin);
int calculate_moving_average(int *window, int window_size);
int is_vibration_detected(int average, int threshold);

// Signal handler function
static void signal_handler(int signo) {
    if (signo == SIGINT || signo == SIGTERM) {
        printf("\nCaught signal %s, cleaning up...\n", (signo == SIGINT) ? "SIGINT" : "SIGTERM");

        // Unmap GPIO memory
        if (gpio_map != NULL) {
            if (munmap((void *)gpio_map, sysconf(_SC_PAGE_SIZE)) == -1) {
                perror("munmap failed");
            }
        }

        // Close memory file descriptor
        if (mem_fd != -1) {
            close(mem_fd);
        }

        // Close log file
        if (log_file != NULL) {
            fclose(log_file);
        }

        exit(0);
    }
}

// Function to read the GPIO pin state (pure function)
int read_gpio_pin(volatile uint32_t *gpio, int pin) {
    if (gpio == NULL) return -1; // Handle null pointer
    return (*(gpio + 13)) & (1 << pin) ? 1 : 0; // GPIO16-21 reads
}

// Function to calculate the moving average (pure function)
int calculate_moving_average(int *window, int window_size) {
    int sum = 0;
    for (int i = 0; i < window_size; i++) {
        sum += window[i];
    }
    return sum / window_size;
}

// Function to compare the average to a threshold (pure function)
int is_vibration_detected(int average, int threshold) {
    return average > threshold;
}

// Function to trigger the systemd service
int trigger_service() {
    char command[100];
    snprintf(command, sizeof(command), "systemctl start %s", SERVICE_NAME);
    int status = system(command);
    if (status == -1) {
        perror("system() failed");
        return -1;
    }
    if (WEXITSTATUS(status) != 0) {
        fprintf(stderr, "Service start failed with exit code %d\n", WEXITSTATUS(status));
        return -1;
    }
    return 0;
}

// Function to read the GPIO base address from device tree
uint32_t get_gpio_base() {
    FILE *fp;
    char line[256];
    uint32_t address = 0;

    fp = fopen("/proc/device-tree/soc/ranges", "rb");
    if (fp == NULL) {
        perror("Failed to open /proc/device-tree/soc/ranges");
        return 0; // Or some error value
    }

    // Read the file and look for the line containing the GPIO address
    // Assuming the format is: 00000000 00000000 00000000 3f000000 for older Pis
    // For Pi 5 it will be 00000000 00000000 00000000 fe000000 (example)

    fseek(fp, 4, SEEK_SET); // Skip the first 4 bytes
    fread(&address, 4, 1, fp);
    fclose(fp);

    return address;
}

int main() {
    // Install signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Open log file
    log_file = fopen("/var/log/vibration.log", "a");
    if (log_file == NULL) {
        perror("Failed to open log file");
        return 1;
    }

    // Get GPIO base address from device tree
    uint32_t gpio_base = get_gpio_base();
    if (gpio_base == 0) {
        fprintf(stderr, "Failed to get GPIO base address\n");
        fclose(log_file);
        return 1;
    }

    // Open /dev/mem
    mem_fd = open("/dev/mem", O_RDWR | O_SYNC);
    if (mem_fd < 0) {
        perror("Failed to open /dev/mem, Run as root!");
        fclose(log_file);
        return 1;
    }

    // Map GPIO memory
    gpio_map = (volatile uint32_t *)mmap(NULL, sysconf(_SC_PAGE_SIZE), PROT_READ | PROT_WRITE, MAP_SHARED, mem_fd, gpio_base + 0x084000); // GPIO5 address offset
    if (gpio_map == MAP_FAILED) {
        perror("mmap failed");
        close(mem_fd);
        fclose(log_file);
        return 1;
    }

    // Initialize moving average window
    int vibration_data[WINDOW_SIZE] = {0};
    int window_index = 0;

    // Main loop
    while (1) {
        // Read GPIO pin state
        int sensor_value = read_gpio_pin(gpio_map, GPIO_PIN);
        if (sensor_value == -1) {
            fprintf(stderr, "Error reading GPIO pin\n");
            break;
        }

        // Log timestamp and sensor value
        time_t rawtime;
        struct tm timeinfo;
        time(&rawtime);
        localtime_r(&rawtime, &timeinfo);
        char timestamp[30];
        strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &timeinfo);
        fprintf(log_file, "%s: Sensor Value: %d\n", timestamp, sensor_value);
        fflush(log_file);

        // Update moving average window
        vibration_data[window_index] = sensor_value * 1000; // Simulate higher resolution data for averaging
        window_index = (window_index + 1) % WINDOW_SIZE;

        // Calculate moving average
        int average = calculate_moving_average(vibration_data, WINDOW_SIZE);

        // Check for vibration detection
        if (is_vibration_detected(average, VIBRATION_THRESHOLD)) {
            printf("%s: Vibration detected! Average: %d\n", timestamp, average);
            fprintf(log_file, "%s: Vibration detected! Average: %d\n", timestamp, average);

            // Trigger systemd service
            if (trigger_service() == 0) {
                printf("%s: Triggered systemd service %s\n", timestamp, SERVICE_NAME);
                fprintf(log_file, "%s: Triggered systemd service %s\n", timestamp, SERVICE_NAME);
            } else {
                fprintf(stderr, "%s: Failed to trigger systemd service %s\n", timestamp, SERVICE_NAME);
            }
            fflush(log_file);
        }

        // Delay for 1 millisecond
        struct timespec ts;
        ts.tv_sec = 0;
        ts.tv_nsec = 1000000; // 1 millisecond
        nanosleep(&ts, NULL);
    }

    // Cleanup (should not reach here normally due to signal handling)
    if (gpio_map != NULL) {
        if (munmap((void *)gpio_map, sysconf(_SC_PAGE_SIZE)) == -1) {
            perror("munmap failed");
        }
    }
    if (mem_fd != -1) {
        close(mem_fd);
    }
    if (log_file != NULL) {
        fclose(log_file);
    }

    return 0;
}

