#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>

// Define GPIO pins for the relays
#define RELAY1_PIN 4
#define RELAY2_PIN 17
#define RELAY3_PIN 27
#define RELAY4_PIN 22

// Structure to represent the RelayController class
typedef struct {
    int relay1_pin;
    int relay2_pin;
    int relay3_pin;
    int relay4_pin;
    int initialized;
} RelayController;

// Constructor (Initialization function)
int RelayController_init(RelayController *self) {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1; // Indicate failure
    }

    self->relay1_pin = RELAY1_PIN;
    self->relay2_pin = RELAY2_PIN;
    self->relay3_pin = RELAY3_PIN;
    self->relay4_pin = RELAY4_PIN;

    gpioSetMode(self->relay1_pin, PI_OUTPUT);
    gpioSetMode(self->relay2_pin, PI_OUTPUT);
    gpioSetMode(self->relay3_pin, PI_OUTPUT);
    gpioSetMode(self->relay4_pin, PI_OUTPUT);

    self->initialized = 1; // Set initialized flag
    return 0; // Indicate success
}

// Method to activate a specific relay
int RelayController_activateRelay(RelayController *self, int relayNumber) {
    if (!self->initialized) {
        fprintf(stderr, "RelayController not initialized\n");
        return -1;
    }

    int pin;
    switch (relayNumber) {
        case 1:
            pin = self->relay1_pin;
            break;
        case 2:
            pin = self->relay2_pin;
            break;
        case 3:
            pin = self->relay3_pin;
            break;
        case 4:
            pin = self->relay4_pin;
            break;
        default:
            fprintf(stderr, "Invalid relay number: %d\n", relayNumber);
            return -1; // Indicate failure
    }

    gpioWrite(pin, 1); // Activate the relay (HIGH)
    time_sleep(1);       // Wait for 1 second
    return 0; // Indicate success
}

// Method to deactivate a specific relay
int RelayController_deactivateRelay(RelayController *self, int relayNumber) {
    if (!self->initialized) {
        fprintf(stderr, "RelayController not initialized\n");
        return -1;
    }

    int pin;
    switch (relayNumber) {
        case 1:
            pin = self->relay1_pin;
            break;
        case 2:
            pin = self->relay2_pin;
            break;
        case 3:
            pin = self->relay3_pin;
            break;
        case 4:
            pin = self->relay4_pin;
            break;
        default:
            fprintf(stderr, "Invalid relay number: %d\n", relayNumber);
            return -1; // Indicate failure
    }

    gpioWrite(pin, 0); // Deactivate the relay (LOW)
    return 0; // Indicate success
}

// Destructor (Cleanup function)
void RelayController_destroy(RelayController *self) {
    if (self->initialized) {
        gpioTerminate();
        self->initialized = 0;
    }
}

int main() {
    RelayController relayController;

    if (RelayController_init(&relayController) != 0) {
        return 1; // Exit if initialization fails
    }

    while (1) {
        // Cycle through the relays
        if (RelayController_activateRelay(&relayController, 1) == 0) {
            RelayController_deactivateRelay(&relayController, 1);
        }
        if (RelayController_activateRelay(&relayController, 2) == 0) {
            RelayController_deactivateRelay(&relayController, 2);
        }
        if (RelayController_activateRelay(&relayController, 3) == 0) {
            RelayController_deactivateRelay(&relayController, 3);
        }
        if (RelayController_activateRelay(&relayController, 4) == 0) {
            RelayController_deactivateRelay(&relayController, 4);
        }

        // Small delay between cycles
        time_sleep(0.1); // Reduced delay to see faster cycling
    }

    // This point will not be reached in the current infinite loop
    RelayController_destroy(&relayController);
    return 0;
}

