// Constants
const int SOUND_SENSOR_GPIO = 17;
const int LED_GPIO = 18;
const int SOUND_THRESHOLD = 1; // Adjust based on sensor characteristics
const int ALARM_DURATION_SECONDS = 5;
const int DEBOUNCE_READINGS = 5; // Number of consistent readings for debounce
const int DEBOUNCE_DELAY_MS = 2;   // Delay between debounce readings

// Global variable for clean shutdown
volatile sig_atomic_t terminate = 0;

// Signal handler for Ctrl+C
void signal_handler(int sig)
{
    (void)sig; // Suppress unused parameter warning
    terminate = 1;
    fprintf(stderr, "\nCaught signal, exiting gracefully...\n");
}

// Function to read the sound sensor with debouncing
int read_sound_sensor(int gpio)
{
    int consistent_high_count = 0;
    for (int i = 0; i < DEBOUNCE_READINGS; ++i) {
        if (gpioRead(gpio) == 1) {
            consistent_high_count++;
        }
        gpioDelay(DEBOUNCE_DELAY_MS * 1000); // Convert ms to microseconds
    }

    return (consistent_high_count == DEBOUNCE_READINGS) ? 1 : 0;
}

// Function to activate the alarm (turn on LED)
void activate_alarm(int led_gpio, int duration_seconds)
{
    if (gpioWrite(led_gpio, 1) != 0) {
        fprintf(stderr, "Error: Failed to activate LED. GPIO: %d\n", led_gpio);
        return;
    }
    gpioDelay(duration_seconds * 1000000); // Delay in microseconds
    if (gpioWrite(led_gpio, 0) != 0) {
        fprintf(stderr, "Error: Failed to deactivate LED. GPIO: %d\n", led_gpio);
    }
}

int main()
{
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Register signal handler for clean shutdown
    signal(SIGINT, signal_handler);

    // Configure GPIOs
    if (gpioSetMode(SOUND_SENSOR_GPIO, PI_INPUT) != 0) {
        fprintf(stderr, "Error: Failed to set GPIO %d as input\n", SOUND_SENSOR_GPIO);
        gpioTerminate();
        return 1;
    }
    gpioSetPullUpDown(SOUND_SENSOR_GPIO, PI_PUD_DOWN); // Use pull-down resistor

    if (gpioSetMode(LED_GPIO, PI_OUTPUT) != 0) {
        fprintf(stderr, "Error: Failed to set GPIO %d as output\n", LED_GPIO);
        gpioTerminate();
        return 1;
    }

    // Main loop
    while (!terminate) {
        int sound_detected = read_sound_sensor(SOUND_SENSOR_GPIO);

        if (sound_detected == 1) {
            activate_alarm(LED_GPIO, ALARM_DURATION_SECONDS);
        }

        gpioDelay(100000); // Delay to prevent excessive CPU usage
    }

    // Clean up before exiting
    gpioWrite(LED_GPIO, 0); // Ensure LED is off
    gpioTerminate();

    return 0;
}

