#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
#include <errno.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <stdbool.h>
#include <time.h>
#include <math.h>

// Constants
#define D6F_ADDR 0x6C  // D6F-PH I2C client address (7-bit)
#define I2C_DEVICE "/dev/i2c-1" // I2C device file

// Function Prototypes
static int i2c_write_bytes(int file_descriptor, uint8_t device_address, uint16_t register_address, const uint8_t *data, uint8_t length);
static int i2c_read_bytes(int file_descriptor, uint8_t device_address, uint8_t register_address, uint8_t *data, uint8_t length);
static uint16_t bytes_to_uint16(const uint8_t *buffer);
static void delay_ms(int milliseconds);

// Main Function
int main() {
    int i2c_file_descriptor;
    uint8_t read_buffer[2];
    uint16_t raw_flow_data;
    float flow_rate;
    int status;

    // Open I2C device
    i2c_file_descriptor = open(I2C_DEVICE, O_RDWR);
    if (i2c_file_descriptor < 0) {
        fprintf(stderr, "Error opening I2C device: %s\n", strerror(errno));
        return EXIT_FAILURE;
    }

    // Initialize sensor (0Bh, 00h)
    status = i2c_write_bytes(i2c_file_descriptor, D6F_ADDR, 0x0B00, NULL, 0);
    if (status != 0) {
        fprintf(stderr, "Error initializing sensor\n");
        close(i2c_file_descriptor);
        return EXIT_FAILURE;
    }
    delay_ms(900);

    while (1) {
        // Trigger data acquisition (00h, D0h, 40h, 18h, 06h)
        uint8_t trigger_data[] = {0x40, 0x18, 0x06};
        status = i2c_write_bytes(i2c_file_descriptor, D6F_ADDR, 0x00D0, trigger_data, sizeof(trigger_data));
        if (status != 0) {
            fprintf(stderr, "Error triggering data acquisition\n");
            break; // Exit loop on error
        }

        delay_ms(50); // Wait for conversion

        // Request data (00h, D0h, 51h, 2Ch) and read (07h)
        uint8_t request_data[] = {0x51, 0x2C};
        status = i2c_write_bytes(i2c_file_descriptor, D6F_ADDR, 0x00D0, request_data, sizeof(request_data));
        if (status != 0) {
            fprintf(stderr, "Error requesting data\n");
            break; // Exit loop on error
        }

        status = i2c_read_bytes(i2c_file_descriptor, D6F_ADDR, 0x07, read_buffer, sizeof(read_buffer));
        if (status != 0) {
            fprintf(stderr, "Error reading sensor data\n");
            break; // Exit loop on error
        }

        // Convert raw data to flow rate
        raw_flow_data = bytes_to_uint16(read_buffer);
        flow_rate = ((float)raw_flow_data - 1024.0) * 1000.0 / 60000.0 - 500.0;

        // Print flow rate
        printf("Flow Rate: %6.2f [Pa]\n", flow_rate);

        delay_ms(1000); // Sample every 1 second
    }

    // Close I2C device
    close(i2c_file_descriptor);

    return (status == 0) ? EXIT_SUCCESS : EXIT_FAILURE;
}

// Helper Functions

/**
 * @brief Writes bytes to an I2C device.
 *
 * @param file_descriptor The I2C file descriptor.
 * @param device_address The I2C device address.
 * @param register_address The register address to write to.
 * @param data The data to write.
 * @param length The number of bytes to write.
 * @return 0 on success, -1 on failure.
 */
static int i2c_write_bytes(int file_descriptor, uint8_t device_address, uint16_t register_address, const uint8_t *data, uint8_t length) {
    uint8_t buffer[128]; // Increased buffer size for safety
    if (length > 122) { // Maximum data length is now 122 to accommodate register address
        fprintf(stderr, "Error: Data length exceeds maximum allowed (122 bytes).\n");
        return -1; // Indicate failure
    }

    buffer[0] = (register_address >> 8) & 0xFF; // MSB of register address
    buffer[1] = register_address & 0xFF;        // LSB of register address

    if (data != NULL && length > 0) {
        memcpy(buffer + 2, data, length);
    }

    int total_length = length + 2;

    // Set the I2C slave address for the file descriptor
    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Error: Could not set I2C device address: %s\n", strerror(errno));
        return -1; // Indicate failure
    }

    ssize_t bytes_written = write(file_descriptor, buffer, total_length);
    if (bytes_written != total_length) {
        fprintf(stderr, "Error: I2C write failed: %s (Wrote %zd bytes, expected %d)\n", strerror(errno), bytes_written, total_length);
        return -1; // Indicate failure
    }

    return 0; // Indicate success
}

/**
 * @brief Reads bytes from an I2C device.
 *
 * @param file_descriptor The I2C file descriptor.
 * @param device_address The I2C device address.
 * @param register_address The register address to read from.
 * @param data The buffer to store the read data.
 * @param length The number of bytes to read.
 * @return 0 on success, -1 on failure.
 */
static int i2c_read_bytes(int file_descriptor, uint8_t device_address, uint8_t register_address, uint8_t *data, uint8_t length) {
    // Set the I2C slave address for the file descriptor
    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Error: Could not set I2C device address: %s\n", strerror(errno));
        return -1; // Indicate failure
    }

    // Write the register address to be read from
    ssize_t bytes_written = write(file_descriptor, &register_address, 1);
    if (bytes_written != 1) {
        fprintf(stderr, "Error: Could not write register address: %s\n", strerror(errno));
        return -1; // Indicate failure
    }

    // Read the data from the I2C device
    ssize_t bytes_read = read(file_descriptor, data, length);
    if (bytes_read != length) {
        fprintf(stderr, "Error: I2C read failed: %s (Read %zd bytes, expected %d)\n", strerror(errno), bytes_read, length);
        return -1; // Indicate failure
    }

    return 0; // Indicate success
}

/**
 * @brief Converts two bytes (big-endian) to a 16-bit unsigned integer.
 *
 * @param buffer Pointer to the byte array.
 * @return The 16-bit unsigned integer.
 */
static uint16_t bytes_to_uint16(const uint8_t *buffer) {
    return ((uint16_t)buffer[0] << 8) | (uint16_t)buffer[1];
}

/**
 * @brief Delays execution for a specified number of milliseconds.
 *
 * @param milliseconds The number of milliseconds to delay.
 */
static void delay_ms(int milliseconds) {
    struct timespec ts;
    ts.tv_sec = milliseconds / 1000;
    ts.tv_nsec = (milliseconds % 1000) * 1000000;
    nanosleep(&ts, NULL);
}

