// Define GPIO pins
#define TRIGGER_PIN 17
#define ECHO_PIN 18
#define BUZZER_PIN 22

// Define musical notes and durations (adjust as needed)
#define NOTE_DING_FREQUENCY 440  // A4
#define NOTE_DONG_FREQUENCY 330  // E4
#define DURATION_DING 200       // milliseconds
#define DURATION_DONG 400       // milliseconds

// Function to send a 10us pulse to the trigger pin
void trigger_pulse() {
    gpioWrite(TRIGGER_PIN, 1); // Set trigger HIGH
    gpioDelay(10);             // Wait for 10us
    gpioWrite(TRIGGER_PIN, 0); // Set trigger LOW
}

// Function to measure the distance using the HC-SR04 sensor
float get_distance() {
    long long start_tick, end_tick, diff_tick;

    // Trigger the sensor
    trigger_pulse();

    // Wait for the echo pin to go HIGH (with timeout)
    int count = 0;
    while (gpioRead(ECHO_PIN) == 0 && count < 10000) {
        gpioDelay(1); // Small delay to prevent busy-waiting
        count++;
    }
    if (count >= 10000) {
        fprintf(stderr, "Error: Timeout waiting for echo start\n");
        return -1.0; // Indicate failure
    }

    start_tick = gpioTick();

    // Wait for the echo pin to go LOW (with timeout)
    count = 0;
    while (gpioRead(ECHO_PIN) == 1 && count < 20000) {
        gpioDelay(1); // Small delay to prevent busy-waiting
        count++;
    }
    if (count >= 20000) {
        fprintf(stderr, "Error: Timeout waiting for echo end\n");
        return -1.0; // Indicate failure
    }

    end_tick = gpioTick();

    diff_tick = end_tick - start_tick;

    // Calculate the pulse duration in seconds (converted from microseconds)
    double pulse_duration = (double)diff_tick / 1000000.0;

    // Calculate the distance in centimeters
    float distance = (pulse_duration * 34300.0) / 2.0; // Speed of sound is approximately 343 m/s or 34300 cm/s

    return distance;
}

// Function to play a tone on the buzzer
void play_tone(int frequency, int duration_ms) {
    if (frequency <= 0) return; // Avoid division by zero

    // Calculate the period of the wave
    float period = 1000000.0 / frequency; // in microseconds
    float half_period = period / 2.0;

    long long start_time = gpioTick();
    while ((gpioTick() - start_time) < (duration_ms * 1000)) {
        gpioWrite(BUZZER_PIN, 1); // HIGH
        gpioDelay(half_period);    // Delay for half the period
        gpioWrite(BUZZER_PIN, 0); // LOW
        gpioDelay(half_period);    // Delay for half the period
    }
}

// Function to play the doorbell melody
void play_melody() {
    play_tone(NOTE_DING_FREQUENCY, DURATION_DING);
    gpioDelay(50); // Short pause between notes
    play_tone(NOTE_DONG_FREQUENCY, DURATION_DONG);
}

int main() {
    // Initialize the pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);

    // Main loop
    while (1) {
        // Measure the distance
        float distance = get_distance();

        // Check for errors during distance measurement
        if (distance < 0) {
            fprintf(stderr, "Error: Distance measurement failed\n");
        } else {
            // Check if the distance is below the threshold (50cm)
            if (distance < 50.0) {
                printf("Distance: %.2f cm - Playing melody!\n", distance);
                play_melody();
            } else {
                printf("Distance: %.2f cm\n", distance);
            }
        }

        // Delay to avoid excessive sensor readings
        gpioDelay(100);
    }

    // Terminate the pigpio library before exiting
    gpioTerminate();

    return 0;
}

