// Controls the relay based on the moisture level
void control_relay(int moisture_level) {
    if (moisture_level < MOISTURE_THRESHOLD) {
        // Soil is dry, activate the relay (e.g., turn on a pump)
        digitalWrite(RELAY_PIN, HIGH);
        printf("Relay ON (Watering)\n");
    } else {
        // Soil is moist, deactivate the relay
        digitalWrite(RELAY_PIN, LOW);
        printf("Relay OFF (Not Watering)\n");
    }
}

