#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <signal.h>
#include <unistd.h>
#include <time.h>
#include <wiringPi.h>
#include <wiringPiSPI.h>

// Configuration
#define SPI_CHANNEL 0
#define SPI_SPEED 1000000  // 1 MHz
#define RELAY_PIN 18       // GPIO 18 for relay control
#define TARGET_TEMPERATURE 50.0 // Target temperature in Celsius
#define TEMPERATURE_COEFFICIENT 20.0 // Example: Temperature = Voltage * 20
#define PROPORTIONAL_GAIN 0.5  // Proportional gain for control loop

// Global variables
volatile sig_atomic_t program_running = 1;
FILE *log_file = NULL;

// Function prototypes
int spi_init();
int read_adc(int channel);
float estimate_temperature(float voltage);
void control_relay(float temperature);
void log_data(float voltage, float temperature);
void signal_handler(int signal);

// Function to initialize SPI
int spi_init() {
    if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) == -1) {
        fprintf(stderr, "SPI initialization failed!\n");
        return -1;
    }
    return 0;
}

// Function to read from MCP3008 ADC
int read_adc(int channel) {
    if (channel < 0 || channel > 7) {
        fprintf(stderr, "Invalid ADC channel: %d\n", channel);
        return -1;
    }

    unsigned char buffer[3];
    buffer[0] = 0x01;                  // Start bit
    buffer[1] = (0x08 | channel) << 4; // SGL/DIFF = 1, D2-D0 = channel
    buffer[2] = 0x00;

    if (wiringPiSPIDataRW(SPI_CHANNEL, buffer, 3) == -1) {
        fprintf(stderr, "SPI data read failed!\n");
        return -1;
    }

    int adc_value = ((buffer[1] & 0x03) << 8) + buffer[2];
    return adc_value;
}

// Function to estimate temperature from voltage
float estimate_temperature(float voltage) {
    return voltage * TEMPERATURE_COEFFICIENT;
}

// Function to control the relay based on temperature
void control_relay(float temperature) {
    float error = TARGET_TEMPERATURE - temperature;
    float control_signal = error * PROPORTIONAL_GAIN;

    // Simple on/off control based on the control signal
    if (control_signal > 0) {
        digitalWrite(RELAY_PIN, HIGH); // Turn relay ON
    } else {
        digitalWrite(RELAY_PIN, LOW);  // Turn relay OFF
    }
}

// Function to log data to file
void log_data(float voltage, float temperature) {
    if (log_file != NULL) {
        time_t rawtime;
        struct tm *timeinfo;
        time(&rawtime);
        timeinfo = localtime(&rawtime);

        fprintf(log_file, "%s Voltage: %.2f V, Temperature: %.2f °C\n", asctime(timeinfo), voltage, temperature);
        fflush(log_file); // Ensure data is written immediately
    } else {
        fprintf(stderr, "Log file is not open!\n");
    }
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    program_running = 0;
    printf("Caught signal %d, exiting gracefully.\n", signal);

    if (log_file != NULL) {
        fclose(log_file);
        printf("Log file closed.\n");
    }

    digitalWrite(RELAY_PIN, LOW); // Ensure relay is OFF on exit
    printf("Relay turned OFF.\n");

    exit(0);
}

int main() {
    // Set up signal handling
    signal(SIGINT, signal_handler);

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPi initialization failed!\n");
        return 1;
    }

    // Initialize SPI
    if (spi_init() == -1) {
        return 1;
    }

    // Set relay pin as output
    pinMode(RELAY_PIN, OUTPUT);
    digitalWrite(RELAY_PIN, LOW); // Initialize relay to OFF

    // Open log file
    log_file = fopen("heater_log.txt", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Failed to open log file!\n");
        return 1;
    }

    printf("Temperature control program started. Press Ctrl+C to exit.\n");

    while (program_running) {
        // Read ADC value from channel 0
        int adc_value = read_adc(0);
        if (adc_value == -1) {
            fprintf(stderr, "Failed to read ADC value.\n");
        } else {
            // Convert ADC value to voltage (assuming 3.3V reference)
            float voltage = (float)adc_value / 1023.0 * 3.3;

            // Estimate temperature
            float temperature = estimate_temperature(voltage);

            // Control the relay
            control_relay(temperature);

            // Log the data
            log_data(voltage, temperature);
        }

        delay(5000); // Wait 5 seconds
    }

    return 0;
}

#include <stdio.h>
