// Configuration
#define UART_PORT "/dev/ttyS0" // Or /dev/ttyAMA0, check your Pi's configuration
#define BAUD_RATE 9600
#define OLED_ADDRESS 0x3C // Replace with your OLED's I2C address
#define OLED_WIDTH 128
#define OLED_HEIGHT 64
#define FRAME_LENGTH 32

// Global variables
volatile sig_atomic_t terminate = 0;
int uart_fd;
int oled_fd;

// Function prototypes
int uart_setup(const char *port, int baud_rate);
int read_pms5003_frame(int fd, unsigned char *frame);
int validate_checksum(const unsigned char *frame);
void extract_pm_values(const unsigned char *frame, int *pm25, int *pm10);
int calculate_aqi(int pm25, int pm10);
const char *get_aqi_category(int aqi);
int oled_setup(int address);
void oled_command(int fd, unsigned char command);
void oled_data(int fd, unsigned char data);
void oled_clear(int fd);
void oled_set_cursor(int fd, int x, int y);
void oled_print(int fd, const char *text);
void display_aqi_data(int fd, int aqi, const char *category, int pm25, int pm10);
void signal_handler(int sig);

// US EPA AQI Breakpoints
typedef struct {
    int low;
    int high;
    int aqi_low;
    int aqi_high;
} AQIBreakpoint;

AQIBreakpoint pm25_breakpoints[] = {
    {0, 12, 0, 50},
    {12, 35, 51, 100},
    {35, 55, 101, 150},
    {55, 150, 151, 200},
    {150, 250, 201, 300},
    {250, 500, 301, 500}
};

AQIBreakpoint pm10_breakpoints[] = {
    {0, 54, 0, 50},
    {54, 154, 51, 100},
    {154, 254, 101, 150},
    {254, 354, 151, 200},
    {354, 424, 201, 300},
    {424, 604, 301, 500}
};

int main() {
    // Signal handling setup
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize UART
    uart_fd = uart_setup(UART_PORT, BAUD_RATE);
    if (uart_fd == -1) {
        fprintf(stderr, "Error initializing UART. Exiting.\n");
        return 1;
    }

    // Initialize OLED
    oled_fd = oled_setup(OLED_ADDRESS);
    if (oled_fd == -1) {
        fprintf(stderr, "Error initializing OLED. Exiting.\n");
        close(uart_fd);
        return 1;
    }

    // Main loop
    while (!terminate) {
        unsigned char frame[FRAME_LENGTH];
        int pm25, pm10;

        if (read_pms5003_frame(uart_fd, frame) == 0) {
            if (validate_checksum(frame) == 0) {
                extract_pm_values(frame, &pm25, &pm10);
                int aqi = calculate_aqi(pm25, pm10);
                const char *category = get_aqi_category(aqi);
                display_aqi_data(oled_fd, aqi, category, pm25, pm10);
            } else {
                fprintf(stderr, "Checksum validation failed.\n");
                oled_clear(oled_fd);
                oled_print(oled_fd, "Data Unavailable");
            }
        } else {
            fprintf(stderr, "Failed to read frame from PMS5003.\n");
            oled_clear(oled_fd);
            oled_print(oled_fd, "Data Unavailable");
        }

        sleep(5);
    }

    // Cleanup
    printf("Cleaning up and exiting.\n");
    close(uart_fd);
    //Turn off OLED Display
    oled_command(oled_fd, 0xAE); //Display Off
    return 0;
}

// UART setup function
int uart_setup(const char *port, int baud_rate) {
    int fd = open(port, O_RDWR | O_NOCTTY | O_NDELAY);
    if (fd == -1) {
        perror("open");
        return -1;
    }

    struct termios options;
    if (tcgetattr(fd, &options) != 0) {
        perror("tcgetattr");
        close(fd);
        return -1;
    }

    options.c_cflag = baud_rate | CS8 | CLOCAL | CREAD;
    options.c_iflag = IGNPAR;
    options.c_oflag = 0;
    options.c_lflag = 0; // Non-canonical mode
    options.c_cc[VMIN] = 0; // Read doesn't block
    options.c_cc[VTIME] = 10; // Timeout of 1 second

    if (tcflush(fd, TCIFLUSH) != 0) {
        perror("tcflush");
        close(fd);
        return -1;
    }

    if (tcsetattr(fd, TCSANOW, &options) != 0) {
        perror("tcsetattr");
        close(fd);
        return -1;
    }

    return fd;
}

// Read a frame from the PMS5003 sensor
int read_pms5003_frame(int fd, unsigned char *frame) {
    unsigned char buffer[1];
    int bytes_read = 0;
    time_t start_time = time(NULL);

    // Read until start bytes are found (0x42 0x4d)
    while (bytes_read < 2) {
        if (read(fd, buffer, 1) == 1) {
            if (bytes_read == 0 && buffer[0] == 0x42) {
                frame[bytes_read++] = buffer[0];
            } else if (bytes_read == 1 && buffer[0] == 0x4d) {
                frame[bytes_read++] = buffer[0];
            } else {
                bytes_read = 0; // Reset if incorrect start byte
            }
        } else {
            if(time(NULL) - start_time > 2) return -1; //Timeout
            continue; //Retry reading
        }
    }

    // Read the rest of the frame
    while (bytes_read < FRAME_LENGTH) {
        if (read(fd, buffer, 1) == 1) {
            frame[bytes_read++] = buffer[0];
        } else {
             if(time(NULL) - start_time > 2) return -1; //Timeout
             continue; //Retry reading
        }
    }

    return 0; // Success
}

// Validate the checksum of the PMS5003 frame
int validate_checksum(const unsigned char *frame) {
    unsigned short checksum = 0;
    for (int i = 0; i < FRAME_LENGTH - 2; i++) {
        checksum += frame[i];
    }
    unsigned short frame_checksum = (frame[FRAME_LENGTH - 2] << 8) | frame[FRAME_LENGTH - 1];
    return (checksum == frame_checksum) ? 0 : -1;
}

// Extract PM2.5 and PM10 values from the PMS5003 frame
void extract_pm_values(const unsigned char *frame, int *pm25, int *pm10) {
    *pm25 = (frame[8] << 8) | frame[9];
    *pm10 = (frame[10] << 8) | frame[11];
}

// Calculate AQI based on PM2.5 and PM10 values
int calculate_aqi(int pm25, int pm10) {
    int aqi_pm25 = -1, aqi_pm10 = -1;

    // Calculate AQI for PM2.5
    for (int i = 0; i < sizeof(pm25_breakpoints) / sizeof(AQIBreakpoint); i++) {
        if (pm25 >= pm25_breakpoints[i].low && pm25 <= pm25_breakpoints[i].high) {
            aqi_pm25 = ((float)(pm25 - pm25_breakpoints[i].low) / (pm25_breakpoints[i].high - pm25_breakpoints[i].low)) * (pm25_breakpoints[i].aqi_high - pm25_breakpoints[i].aqi_low) + pm25_breakpoints[i].aqi_low;
            break;
        }
    }

    // Calculate AQI for PM10
    for (int i = 0; i < sizeof(pm10_breakpoints) / sizeof(AQIBreakpoint); i++) {
        if (pm10 >= pm10_breakpoints[i].low && pm10 <= pm10_breakpoints[i].high) {
            aqi_pm10 = ((float)(pm10 - pm10_breakpoints[i].low) / (pm10_breakpoints[i].high - pm10_breakpoints[i].low)) * (pm10_breakpoints[i].aqi_high - pm10_breakpoints[i].aqi_low) + pm10_breakpoints[i].aqi_low;
            break;
        }
    }

    // Return the higher AQI value
    if (aqi_pm25 == -1 && aqi_pm10 == -1) return 0; // Both invalid
    if (aqi_pm25 == -1) return aqi_pm10; // PM2.5 invalid
    if (aqi_pm10 == -1) return aqi_pm25; // PM10 invalid

    return (aqi_pm25 > aqi_pm10) ? aqi_pm25 : aqi_pm10;
}

// Get AQI category based on AQI value
const char *get_aqi_category(int aqi) {
    if (aqi >= 0 && aqi <= 50) return "Good";
    else if (aqi <= 100) return "Moderate";
    else if (aqi <= 150) return "Unhealthy for Sensitive Groups";
    else if (aqi <= 200) return "Unhealthy";
    else if (aqi <= 300) return "Very Unhealthy";
    else return "Hazardous";
}

// OLED setup function
int oled_setup(int address) {
    wiringPiSetup();
    int fd = wiringPiI2CSetup(address);
    if (fd == -1) {
        perror("wiringPiI2CSetup");
        return -1;
    }

    // Initialization sequence (adjust based on your OLED's datasheet)
    oled_command(fd, 0xAE); // Display off
    oled_command(fd, 0x20); // Set Memory Addressing Mode
    oled_command(fd, 0x10); // 00,Horizontal Addressing Mode; 01,Vertical Addressing Mode; 10,Page Addressing Mode(RESET)
    oled_command(fd, 0xB0); // Set Page Start Address for Page Addressing Mode,0-7
    oled_command(fd, 0xC8); // Set COM Output Scan Direction
    oled_command(fd, 0x00); // Set low nibble of column address
    oled_command(fd, 0x10); // Set high nibble of column address
    oled_command(fd, 0x40); // Set start line address - set mapping RAM display start line(0x00~0x3F)
    oled_command(fd, 0x81); //--set contrast control register
    oled_command(fd, 0x7F); // Set SEG Output Current Brightness
    oled_command(fd, 0xA1); //--Set SEG/Column Re-map Default
    oled_command(fd, 0xA6); //--Set display mode; 0xA6,Normal; 0xA7,Inverse
    oled_command(fd, 0xA8); // Set multiplex ratio(1 to 64)
    oled_command(fd, 0x3F); // 1/64 duty
    oled_command(fd, 0xA4); // Output follows RAM content
    oled_command(fd, 0xD3); // Set display offset
    oled_command(fd, 0x00); // 0 offset
    oled_command(fd, 0xD5); // --set display clock divide ratio/oscillator frequency
    oled_command(fd, 0xF0); // --set divide ratio
    oled_command(fd, 0xD9); // Set pre-charge period
    oled_command(fd, 0x22); //
    oled_command(fd, 0xDA); // Set com pins hardware configuration
    oled_command(fd, 0x12);
    oled_command(fd, 0xDB); // Set vcomh
    oled_command(fd, 0x20); // 0.83*vref
    oled_command(fd, 0x8D); // Set DC-DC enable
    oled_command(fd, 0x14); //
    oled_command(fd, 0xAF); // Display on

    oled_clear(fd);

    return fd;
}

// Send a command to the OLED
void oled_command(int fd, unsigned char command) {
    wiringPiI2CWriteReg8(fd, 0x00, command);
}

// Send data to the OLED
void oled_data(int fd, unsigned char data) {
    wiringPiI2CWriteReg8(fd, 0x40, data);
}

// Clear the OLED display
void oled_clear(int fd) {
    for (int i = 0; i < OLED_WIDTH * OLED_HEIGHT / 8; i++) {
        oled_data(fd, 0x00);
    }
    oled_set_cursor(fd, 0, 0);
}

// Set the cursor position on the OLED
void oled_set_cursor(int fd, int x, int y) {
    oled_command(fd, 0xB0 + y);                       //set page address
    oled_command(fd, ((x & 0x0F)));                    //set lower column address
    oled_command(fd, ((x & 0xF0) >> 4) | 0x10);       //set higher column address
}

// Print text to the OLED
void oled_print(int fd, const char *text) {
    int i = 0;
    while (text[i] != '\0') {
        //Basic ASCII character support. Expand as needed.
        char c = text[i];
        if(c >= ' ' && c <= '~'){
            //Simplified character representation, each char is 8 pixels wide.
            //For a proper font, you'd need a lookup table.
            for(int j = 0; j < 8; j++){
                oled_data(fd, 0xFF); //Simple solid bar for each pixel.
            }
        } else {
            for(int j = 0; j < 8; j++){
                oled_data(fd, 0x00); //Blank for unsupported characters.
            }
        }
        i++;
    }
}

// Display AQI data on the OLED
void display_aqi_data(int fd, int aqi, const char *category, int pm25, int pm10) {
    char buffer[30];

    oled_clear(fd);
    oled_set_cursor(fd, 0, 0);
    sprintf(buffer, "AQI: %d", aqi);
    oled_print(fd, buffer);

    oled_set_cursor(fd, 0, 2);
    sprintf(buffer, "%s", category);
    oled_print(fd, buffer);

    oled_set_cursor(fd, 0, 4);
    sprintf(buffer, "PM2.5: %d ug/m3", pm25);
    oled_print(fd, buffer);

    oled_set_cursor(fd, 0, 6);
    sprintf(buffer, "PM10: %d ug/m3", pm10);
    oled_print(fd, buffer);
}

// Signal handler function
void signal_handler(int sig) {
    printf("Signal received: %d. Terminating...\n", sig);
    terminate = 1;
}

#include <stdlib.h>
