#define SSD1306_I2C_ADDR  0x3C
int i2c_fd;

void ssd1306_sendCommand(unsigned char command) {
    wiringPiI2CWriteReg8(i2c_fd, 0x00, command);
}

void ssd1306_init() {
    ssd1306_sendCommand(0xAE); // Display off
    ssd1306_sendCommand(0xA6); // Normal display (not inverted)
    ssd1306_sendCommand(0xAF); // Display on
}

void ssd1306_toggleInvert() {
    static int inverted = 0;
    inverted = !inverted;
    ssd1306_sendCommand(inverted ? 0xA7 : 0xA6);
}

int main(void) {
    if (wiringPiSetup() == -1) {
        printf("WiringPi Initialization Failed!\n");
        return -1;
    }
    i2c_fd = wiringPiI2CSetup(SSD1306_I2C_ADDR);
    if (i2c_fd < 0) {
        printf("Failed to connect to I2C device.\n");
        return -1;
    }

    ssd1306_init();

    while (1) {
        ssd1306_toggleInvert();
        sleep(1);
    }

    return 0;
}

#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>

// Define GPIO pins for L293D motor driver
#define MOTOR_PIN1 17 // GPIO17 - IN1
#define MOTOR_PIN2 18 // GPIO18 - IN2
#define ENABLE_PIN 27 // GPIO27 - EN

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pins as output
    gpioSetMode(MOTOR_PIN1, PI_OUTPUT);
    gpioSetMode(MOTOR_PIN2, PI_OUTPUT);
    gpioSetMode(ENABLE_PIN, PI_OUTPUT);

    // Enable the motor driver
    gpioWrite(ENABLE_PIN, 1); // Enable pin HIGH

    while (1) {
        // Move motor forward for a short burst
        gpioWrite(MOTOR_PIN1, 1);
        gpioWrite(MOTOR_PIN2, 0);
        gpioDelay(500); // 500 milliseconds

        // Stop the motor
        gpioWrite(MOTOR_PIN1, 0);
        gpioWrite(MOTOR_PIN2, 0);

        // Wait for 2 seconds
        sleep(2);

        //Move motor backward for a short burst
        gpioWrite(MOTOR_PIN1, 0);
        gpioWrite(MOTOR_PIN2, 1);
        gpioDelay(500); // 500 milliseconds

        // Stop the motor
        gpioWrite(MOTOR_PIN1, 0);
        gpioWrite(MOTOR_PIN2, 0);

        //Wait for 2 seconds
        sleep(2);
    }

    // Cleanup (this will never be reached in the current loop)
    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <string.h>
#include <errno.h>
#include <unistd.h>
#include <math.h>
#include <wiringPi.h>
#include <wiringPiSPI.h>

// Constants
#define SPI_CHANNEL 0  // SPI Channel (CE0)
#define SPI_SPEED 1000000 // 1MHz SPI speed
#define MAX31855_DATA_SIZE 4

// Function Prototypes
int initialize_spi();
int read_max31855(int channel, float *internal_temp_c, float *thermocouple_temp_c, int *fault_code);
float raw_to_thermocouple_temp(uint32_t raw);
float raw_to_internal_temp(uint32_t raw);
void print_fault(int fault_code);

int main(int argc, char *argv[]) {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return 1;
    }

    if (initialize_spi() != 0) {
        fprintf(stderr, "SPI initialization failed.\n");
        return 1;
    }

    float internal_temp_c, thermocouple_temp_c;
    int fault_code;

    while (1) {
        if (read_max31855(SPI_CHANNEL, &internal_temp_c, &thermocouple_temp_c, &fault_code) == 0) {
            printf("Internal Temperature: %.2f C, %.2f F\n", internal_temp_c, internal_temp_c * 9.0 / 5.0 + 32.0);
            printf("Thermocouple Temperature: %.2f C, %.2f F\n", thermocouple_temp_c, thermocouple_temp_c * 9.0 / 5.0 + 32.0);
            if (fault_code != 0) {
                print_fault(fault_code);
            }
        } else {
            fprintf(stderr, "Failed to read MAX31855 data.\n");
        }

        delay(1000); // Read every 1 second
    }

    return 0;
}

// Initialize SPI
int initialize_spi() {
    int fd = wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED);
    if (fd == -1) {
        fprintf(stderr, "wiringPiSPISetup failed: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

// Read data from MAX31855
int read_max31855(int channel, float *internal_temp_c, float *thermocouple_temp_c, int *fault_code) {
    uint8_t data[MAX31855_DATA_SIZE];
    uint32_t raw_data;

    if (wiringPiSPIDataRW(channel, data, MAX31855_DATA_SIZE) == -1) {
        fprintf(stderr, "SPI data transfer failed: %s\n", strerror(errno));
        return -1;
    }

    // Combine the bytes into a 32-bit word
    raw_data = (data[0] << 24) | (data[1] << 16) | (data[2] << 8) | data[3];

    // Check for fault
    *fault_code = raw_data & 0x00000007; // Extract fault bits
    if (*fault_code) {
        return 0; // Return even on fault to print the error.
    }

    // Extract and convert thermocouple temperature
    *thermocouple_temp_c = raw_to_thermocouple_temp(raw_data);

    // Extract and convert internal temperature
    *internal_temp_c = raw_to_internal_temp(raw_data);

    return 0;
}

// Convert raw thermocouple data to temperature (Celsius)
float raw_to_thermocouple_temp(uint32_t raw) {
    int32_t thermocouple_data = (raw >> 18) & 0x3FFF; // Extract 14-bit thermocouple data
    if (thermocouple_data & 0x2000) {
        thermocouple_data |= 0xFFFFC000; // Sign extend if negative
    }
    return thermocouple_data * 0.25;
}

// Convert raw internal temperature data to temperature (Celsius)
float raw_to_internal_temp(uint32_t raw) {
    int32_t internal_data = (raw >> 4) & 0xFFF; // Extract 12-bit internal data
    if (internal_data & 0x800) {
        internal_data |= 0xFFFFF000; // Sign extend if negative
    }
    return internal_data * 0.0625;
}

// Print fault status
void print_fault(int fault_code) {
    fprintf(stderr, "Fault Detected: ");
    switch (fault_code) {
        case 0x01:
            fprintf(stderr, "Open Circuit\n");
            break;
        case 0x02:
            fprintf(stderr, "Short to GND\n");
            break;
        case 0x04:
            fprintf(stderr, "Short to VCC\n");
            break;
        default:
            fprintf(stderr, "Unknown Fault (Code: %d)\n", fault_code);
            break;
    }
}

