#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <string.h>

// MPR121 I2C address
#define MPR121_ADDRESS 0x5A

// MPR121 Register Map
#define MPR121_TOUCHSTATUS_L 0x00
#define MPR121_TOUCHSTATUS_H 0x01
#define MPR121_FILTERTH_L 0x04
#define MPR121_FILTERTH_H 0x05
#define MPR121_BASELINE_L 0x06
#define MPR121_BASELINE_H 0x07
#define MPR121_TOUCHTH_0 0x41
#define MPR121_RELEASETH_0 0x42
#define MPR121_ELECTRODECONFIG 0x5E

// LED GPIO pin
#define LED_GPIO 17

// Function to read a register from the MPR121
int mpr121_read_register(int handle, int reg) {
    int value = i2cReadByteData(handle, reg);
    if (value < 0) {
        fprintf(stderr, "Error reading register 0x%02X: %d\n", reg, value);
        return -1; // Indicate an error
    }
    return value;
}

// Function to write a register to the MPR121
int mpr121_write_register(int handle, int reg, int value) {
    int result = i2cWriteByteData(handle, reg, value);
    if (result < 0) {
        fprintf(stderr, "Error writing register 0x%02X with value 0x%02X: %d\n", reg, value, result);
        return -1; // Indicate an error
    }
    return 0; // Indicate success
}

// Function to initialize the MPR121
int initialize_mpr121(int handle) {
    // Stop Mode
    if (mpr121_write_register(handle, MPR121_ELECTRODECONFIG, 0x00) < 0) return -1;
    gpioDelay(1); // Small delay after writes

    // Set electrode touch and release thresholds
    for (int i = 0; i < 12; i++) {
        if (mpr121_write_register(handle, MPR121_TOUCHTH_0 + 2 * i, 40) < 0) return -1; // Touch threshold
        gpioDelay(1);
        if (mpr121_write_register(handle, MPR121_RELEASETH_0 + 2 * i, 20) < 0) return -1; // Release threshold
        gpioDelay(1);
    }

    // Electrode Configuration: Enable all 12 electrodes
    if (mpr121_write_register(handle, MPR121_ELECTRODECONFIG, 0x3F) < 0) return -1; // Configure electrodes 0-5
    gpioDelay(1);
    if (mpr121_write_register(handle, MPR121_ELECTRODECONFIG + 1, 0x0F) < 0) return -1; // Configure electrodes 6-11
    gpioDelay(1);

    return 0; // Indicate success
}

// Function to read the touch status from the MPR121
int read_touch_status(int handle) {
    int touch_status_low = mpr121_read_register(handle, MPR121_TOUCHSTATUS_L);
    int touch_status_high = mpr121_read_register(handle, MPR121_TOUCHSTATUS_H);

    if (touch_status_low < 0 || touch_status_high < 0) {
        return -1; // Indicate an error
    }

    return (touch_status_high << 8) | touch_status_low;
}

// Function to control the LED
void control_led(int gpio, int state) {
    gpioWrite(gpio, state);
}

// Function to log touch events to a file
int log_touch_event(int electrode) {
    FILE *fp = fopen("touch_log.txt", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening touch_log.txt for writing.\n");
        return -1; // Indicate an error
    }

    time_t t = time(NULL);
    fprintf(fp, "%sElectrode %d touched.\n", ctime(&t), electrode);

    fclose(fp);
    return 0; // Indicate success
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C connection
    int handle = i2cOpen(1, MPR121_ADDRESS, 0);
    if (handle < 0) {
        fprintf(stderr, "Error opening I2C device: %d\n", handle);
        gpioTerminate();
        return 1;
    }

    // Initialize the MPR121
    if (initialize_mpr121(handle) < 0) {
        fprintf(stderr, "MPR121 initialization failed.\n");
        i2cClose(handle);
        gpioTerminate();
        return 1;
    }

    // Set LED GPIO pin as output
    gpioSetMode(LED_GPIO, PI_OUTPUT);

    int last_touch_status = 0; // Store the last touch status to detect transitions

    // Main loop
    while (1) {
        int touch_status = read_touch_status(handle);
        if (touch_status < 0) {
            fprintf(stderr, "Error reading touch status.\n");
            break; // Exit the loop on error
        }

        // Check each electrode for a touch event (transition from not touched to touched)
        for (int i = 0; i < 12; i++) {
            int current_touch = (touch_status >> i) & 1;
            int last_touch = (last_touch_status >> i) & 1;

            if (current_touch && !last_touch) {
                // Electrode touched
                control_led(LED_GPIO, 1); // Turn on LED
                log_touch_event(i);        // Log the event
                gpioDelay(500);           // Keep LED on for 500ms
                control_led(LED_GPIO, 0); // Turn off LED
            }
        }

        last_touch_status = touch_status; // Update the last touch status
        gpioDelay(10); // Small delay to avoid busy-waiting
    }

    // Cleanup
    i2cClose(handle);
    gpioTerminate();

    return 0;
}

#include <iostream>
#include <pigpio.h>
#include <unistd.h>

// Define GPIO pins
const int PIR_PIN = 17;
const int LED_PIN = 27;

// PIRSensor Class
class PIRSensor {
private:
    int gpio;

public:
    PIRSensor(int gpio_pin) : gpio(gpio_pin) {
        // Initialize pigpio library
        if (gpioInitialise() < 0) {
            fprintf(stderr, "pigpio initialisation failed\n");
            exit(1);
        }

        // Set GPIO mode for PIR sensor as input
        if (gpioSetMode(gpio, PI_INPUT) != 0) {
            fprintf(stderr, "Failed to set GPIO mode for PIR sensor\n");
            gpioTerminate();
            exit(1);
        }

        // Enable pull-down resistor (optional, depending on sensor wiring)
        gpioSetPullUpDown(gpio, PI_PUD_DOWN);
    }

    ~PIRSensor() {
        gpioTerminate(); // Terminate pigpio on destruction
    }

    bool motionDetected() {
        // Read the PIR sensor's state
        return (gpioRead(gpio) == 1);
    }
};

// LED Class
class LED {
private:
    int gpio;

public:
    LED(int gpio_pin) : gpio(gpio_pin) {
        // Set GPIO mode for LED as output
        if (gpioSetMode(gpio, PI_OUTPUT) != 0) {
            fprintf(stderr, "Failed to set GPIO mode for LED\n");
            gpioTerminate();
            exit(1);
        }
    }

    void blink(int duration_ms) {
        // Turn LED on
        gpioWrite(gpio, 1);
        // Wait for specified duration
        gpioDelay(duration_ms * 1000); // pigpioDelay takes microseconds
        // Turn LED off
        gpioWrite(gpio, 0);
    }
};

int main() {
    // Instantiate PIRSensor and LED objects
    PIRSensor pirSensor(PIR_PIN);
    LED led(LED_PIN);

    // Main loop
    while (true) {
        // Check for motion
        if (pirSensor.motionDetected()) {
            std::cout << "Motion detected! Blinking LED.\n";
            // Blink the LED for 1 second
            led.blink(1000);
        }

        // Small delay to avoid excessive CPU usage
        gpioDelay(100 * 1000); // 100ms delay
    }

    return 0;
}

