#include <stdio.h>
#include <wiringPi.h>
#include <unistd.h>

// Define GPIO pins
#define BUTTON_PIN  0   // GPIO 17
#define MOTOR_IN1   1   // GPIO 18
#define MOTOR_IN2   2   // GPIO 27

// Define motor control functions
void motor_forward(void) {
    digitalWrite(MOTOR_IN1, HIGH);
    digitalWrite(MOTOR_IN2, LOW);
}

void motor_backward(void) {
    digitalWrite(MOTOR_IN1, LOW);
    digitalWrite(MOTOR_IN2, HIGH);
}

void motor_stop(void) {
    digitalWrite(MOTOR_IN1, LOW);
    digitalWrite(MOTOR_IN2, LOW);
}

int main(void) {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed\n");
        return 1;
    }

    // Set pin modes
    pinMode(BUTTON_PIN, INPUT);
    pinMode(MOTOR_IN1, OUTPUT);
    pinMode(MOTOR_IN2, OUTPUT);

    // Main loop
    while (1) {
        // Check if button is pressed
        if (digitalRead(BUTTON_PIN) == HIGH) {
            printf("Button pressed! Raising barrier...\n");

            // Raise barrier (motor forward)
            motor_forward();
            delay(3000);  // 3 seconds

            // Stop motor and hold for 5 seconds
            motor_stop();
            delay(5000);  // 5 seconds

            printf("Lowering barrier...\n");

            // Lower barrier (motor backward)
            motor_backward();
            delay(3000);  // 3 seconds

            // Stop motor
            motor_stop();

            printf("Barrier cycle complete.\n");

            // Debounce delay (adjust as needed)
            delay(500);  // 0.5 seconds
        }

        // Small delay to avoid busy-waiting
        delay(100);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pigpio.h>

// Define the GPIO pin connected to the LED
#define LED_GPIO 16

// Volatile variable to signal program termination
volatile sig_atomic_t program_running = 1;

// Signal handler for SIGINT (Ctrl+C)
void signal_handler(int signal) {
    if (signal == SIGINT) {
        program_running = 0;
        printf("\nCaught SIGINT, exiting gracefully...\n");
    }
}

// Function to initialize the GPIO library and set up the LED pin
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "ERROR: pigpio initialisation failed\n");
        return -1;
    }

    gpioSetMode(LED_GPIO, PI_OUTPUT);
    gpioWrite(LED_GPIO, PI_LOW); // Initialize LED to off state

    return 0;
}

// Function to clean up GPIO resources before exiting
void cleanup_gpio() {
    gpioWrite(LED_GPIO, PI_LOW); // Ensure LED is off
    gpioSetMode(LED_GPIO, PI_INPUT); // Set pin back to input mode
    gpioTerminate();
}

int main() {
    // Register the signal handler for SIGINT
    if (signal(SIGINT, signal_handler) == SIG_ERR) {
        perror("ERROR: Could not register signal handler");
        return 1;
    }

    // Initialize GPIO
    if (initialize_gpio() != 0) {
        return 1;
    }

    printf("Blinking LED on GPIO %d. Press Ctrl+C to exit.\n", LED_GPIO);

    // Main loop to blink the LED
    while (program_running) {
        gpioWrite(LED_GPIO, PI_HIGH); // Turn LED on
        gpioDelay(1000000);           // Wait for 1 second (1000000 microseconds)

        gpioWrite(LED_GPIO, PI_LOW);  // Turn LED off
        gpioDelay(1000000);           // Wait for 1 second
    }

    // Cleanup GPIO resources before exiting
    cleanup_gpio();

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Constants
#define AHT20_I2C_ADDR 0x38
#define DEHUMIDIFIER_GPIO 17
#define HUMIDITY_THRESHOLD_HIGH 60.0
#define HUMIDITY_THRESHOLD_LOW 55.0
#define SLEEP_INTERVAL_SEC 5
#define LOG_FILE "dehumidifier_log.txt"

// Global variables
int i2c_handle;
FILE *log_file;
int dehumidifier_state = 0; // 0: OFF, 1: ON

// Function prototypes
float read_aht20_humidity();
int control_dehumidifier(float humidity);
void log_data(float humidity, int dehumidifier_state);
void signal_handler(int signal);
int initialize_aht20();

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);
    if (i2c_handle >= 0) {
        i2cClose(i2c_handle);
    }
    if (log_file != NULL) {
        fclose(log_file);
    }
    gpioWrite(DEHUMIDIFIER_GPIO, 0); // Ensure dehumidifier is OFF
    gpioTerminate();
    exit(0);
}

// Reads humidity from the AHT20 sensor
float read_aht20_humidity() {
    unsigned char buf[6];
    float humidity = -1.0; // Default value in case of error

    // Trigger measurement
    buf[0] = 0xAC; // Measurement command
    buf[1] = 0x33; // Argument 1
    buf[2] = 0x00; // Argument 2

    if (i2cWriteDevice(i2c_handle, (char *)buf, 3) != 0) {
        fprintf(stderr, "Error writing to I2C device.\n");
        log_data(-1.0, -1); // Log error
        return -1.0;
    }

    gpioDelay(80); // Wait for measurement (at least 75ms)

    if (i2cReadDevice(i2c_handle, (char *)buf, 6) != 6) {
        fprintf(stderr, "Error reading from I2C device.\n");
        log_data(-1.0, -1); // Log error
        return -1.0;
    }

    // Check status bit (bit 7 of byte 0). If set, sensor is busy.
    if (buf[0] & 0x80) {
        fprintf(stderr, "AHT20 busy.\n");
        log_data(-1.0, -1); // Log error
        return -1.0;
    }

    // Calculate humidity
    unsigned long humidity_data = ((unsigned long)buf[1] << 12) | ((unsigned long)buf[2] << 4) | ((unsigned long)buf[3] >> 4);

    humidity = ((float)humidity_data / 0x100000) * 100;

    return humidity;
}

// Controls the dehumidifier based on humidity
int control_dehumidifier(float humidity) {
    int new_state = dehumidifier_state;

    if (humidity > HUMIDITY_THRESHOLD_HIGH && dehumidifier_state == 0) {
        gpioWrite(DEHUMIDIFIER_GPIO, 1); // Turn ON
        new_state = 1;
        printf("Dehumidifier ON (Humidity: %.2f%%)\n", humidity);
    } else if (humidity < HUMIDITY_THRESHOLD_LOW && dehumidifier_state == 1) {
        gpioWrite(DEHUMIDIFIER_GPIO, 0); // Turn OFF
        new_state = 0;
        printf("Dehumidifier OFF (Humidity: %.2f%%)\n", humidity);
    }

    return new_state;
}

// Logs data to file
void log_data(float humidity, int dehumidifier_state) {
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp)-1, "%Y-%m-%d %H:%M:%S", t);

    if (log_file == NULL) {
        fprintf(stderr, "Error: Log file not opened.\n");
        return;
    }

    fprintf(log_file, "%s, Humidity: %.2f%%, Dehumidifier: %s\n",
            timestamp, humidity, (dehumidifier_state == 1) ? "ON" : ((dehumidifier_state == 0) ? "OFF" : "ERROR"));
    fflush(log_file); // Ensure data is written immediately
}

// Initializes the AHT20 sensor
int initialize_aht20() {
    unsigned char buf[3];

    // Initialization sequence
    buf[0] = 0xBE; // Initialization command
    buf[1] = 0x08; // Calibration enable
    buf[2] = 0x00; // No argument

    if (i2cWriteDevice(i2c_handle, (char *)buf, 3) != 0) {
        fprintf(stderr, "Error initializing AHT20 sensor.\n");
        return -1;
    }

    gpioDelay(10); // Wait for initialization (at least 10ms)

    // Trigger a measurement to ensure the sensor is ready
    buf[0] = 0xAC; // Measurement command
    buf[1] = 0x33; // Argument 1
    buf[2] = 0x00; // Argument 2

    if (i2cWriteDevice(i2c_handle, (char *)buf, 3) != 0) {
        fprintf(stderr, "Error triggering measurement after initialization.\n");
        return -1;
    }

    gpioDelay(80); // Wait for measurement (at least 75ms)

    return 0;
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C device
    i2c_handle = i2cOpen(1, AHT20_I2C_ADDR, 0); // Bus 1, address 0x38, no flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Open log file
    log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Configure GPIO for dehumidifier control
    gpioSetMode(DEHUMIDIFIER_GPIO, PI_OUTPUT);
    gpioWrite(DEHUMIDIFIER_GPIO, 0); // Initially OFF

    // Initialize AHT20 sensor
    if (initialize_aht20() != 0) {
        fprintf(stderr, "AHT20 initialization failed. Exiting.\n");
        fclose(log_file);
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Main loop
    while (1) {
        float humidity = read_aht20_humidity();
        if (humidity >= 0) {
            int new_state = control_dehumidifier(humidity);
            if (new_state != dehumidifier_state) {
                dehumidifier_state = new_state;
                log_data(humidity, dehumidifier_state);
            } else {
                log_data(humidity, dehumidifier_state);
            }
        } else {
            fprintf(stderr, "Error reading humidity.\n");
        }

        gpioDelay(SLEEP_INTERVAL_SEC * 1000); // Sleep for 5 seconds
    }

    // The following lines will never be reached due to the infinite loop,
    // but are included for completeness.
    fclose(log_file);
    i2cClose(i2c_handle);
    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <wiringPi.h>

// Define GPIO pins using wiringPi numbering
#define PIR_PIN 0   // GPIO 17
#define LED_PIN 1   // GPIO 18

// Function prototypes
void initializeGPIO(void);
void motionDetected(void);
void cleanup(int signal);
void handleError(const char *message);

// Global variable for clean exit
volatile sig_atomic_t program_running = 1;

int main(void) {
    // Set up signal handler for Ctrl+C
    signal(SIGINT, cleanup);

    // Initialize wiringPi and GPIO pins
    initializeGPIO();

    // Register interrupt handler for motion detection
    if (wiringPiISR(PIR_PIN, INT_EDGE_RISING, motionDetected) < 0) {
        handleError("Unable to setup ISR: ");
    }

    printf("Motion detection system started. Press Ctrl+C to exit.\n");

    // Main loop (program runs until Ctrl+C is pressed)
    while (program_running) {
        delay(100); // Reduce CPU usage
    }

    return 0;
}

// Initializes wiringPi and sets up GPIO pins
void initializeGPIO(void) {
    if (wiringPiSetup() == -1) {
        handleError("Unable to start wiringPi: ");
    }

    pinMode(PIR_PIN, INPUT);
    pinMode(LED_PIN, OUTPUT);
    digitalWrite(LED_PIN, LOW); // Initially turn the LED off
}

// Interrupt handler for motion detection
void motionDetected(void) {
    printf("Motion detected!\n");
    digitalWrite(LED_PIN, !digitalRead(LED_PIN)); // Toggle the LED state
    delay(1000); // Debounce: Disable interrupts for 1 second
}

// Cleans up GPIO pins before exiting
void cleanup(int signal) {
    program_running = 0;
    printf("\nCleaning up and exiting...\n");
    digitalWrite(LED_PIN, LOW); // Turn off the LED
    exit(0);
}

// Handles errors and exits the program
void handleError(const char *message) {
    fprintf(stderr, "%s", message);
    perror(NULL); // Print system error message
    exit(1);
}

#include <fcntl.h>
#include <linux/fb.h>
#include <stdint.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/ioctl.h>
#include <sys/mman.h>
#include <sys/stat.h>
#include <sys/types.h>
#include <unistd.h>
#include <errno.h>

// Constants
#define FB_DEVICE_PATH "/dev/fb1"
#define LED_MATRIX_WIDTH 8
#define LED_MATRIX_HEIGHT 8
#define NUM_PIXELS (LED_MATRIX_WIDTH * LED_MATRIX_HEIGHT)
#define FILE_SIZE (NUM_PIXELS * sizeof(uint16_t))

// Color definitions (RGB565 format)
#define COLOR_BLACK 0x0000
#define COLOR_RED 0xF800
#define COLOR_WHITE 0xFFFF

// Function prototypes
void delay_ms(int milliseconds);
int open_framebuffer(void);
void *map_framebuffer(int fd);
int unmap_framebuffer(void *map);
int close_framebuffer(int fd);
int clear_led_matrix(uint16_t *framebuffer);
int set_pixel_color(uint16_t *framebuffer, int x, int y, uint16_t color);
int check_sense_hat(int fd);

int main(void) {
    int framebuffer_fd = -1;       // File descriptor for the framebuffer
    uint16_t *framebuffer_ptr = NULL; // Pointer to the mapped framebuffer memory
    int i;

    // 1. Open the framebuffer device
    framebuffer_fd = open_framebuffer();
    if (framebuffer_fd == -1) {
        fprintf(stderr, "Error: Failed to open framebuffer: %s\n", strerror(errno));
        return EXIT_FAILURE;
    }

    // Check if the correct device is found
    if (check_sense_hat(framebuffer_fd) != 0) {
        fprintf(stderr, "Error: Sense HAT not found.\n");
        close_framebuffer(framebuffer_fd);
        return EXIT_FAILURE;
    }

    // 2. Map the framebuffer device into memory
    framebuffer_ptr = map_framebuffer(framebuffer_fd);
    if (framebuffer_ptr == MAP_FAILED) {
        fprintf(stderr, "Error: Failed to map framebuffer: %s\n", strerror(errno));
        close_framebuffer(framebuffer_fd);
        return EXIT_FAILURE;
    }

    // 3. Clear the LED matrix (set all pixels to black)
    if (clear_led_matrix(framebuffer_ptr) != 0) {
        fprintf(stderr, "Error: Failed to clear LED matrix.\n");
        unmap_framebuffer(framebuffer_ptr);
        close_framebuffer(framebuffer_fd);
        return EXIT_FAILURE;
    }

    // 4. Light up all LEDs in red
    for (i = 0; i < NUM_PIXELS; i++) {
        framebuffer_ptr[i] = COLOR_RED;
        delay_ms(25);
    }

    // 5. Flash the LED matrix white three times
    for (i = 0; i < 3; i++) {
        delay_ms(250);
        memset(framebuffer_ptr, 0xFF, FILE_SIZE); // White
        delay_ms(250);
        memset(framebuffer_ptr, 0x00, FILE_SIZE); // Black
    }
    delay_ms(250);

    // 6. Clear the LED matrix again
    if (clear_led_matrix(framebuffer_ptr) != 0) {
        fprintf(stderr, "Error: Failed to clear LED matrix.\n");
        unmap_framebuffer(framebuffer_ptr);
        close_framebuffer(framebuffer_fd);
        return EXIT_FAILURE;
    }

    // 7. Un-map the framebuffer from memory
    if (unmap_framebuffer(framebuffer_ptr) != 0) {
        fprintf(stderr, "Error: Failed to unmap framebuffer: %s\n", strerror(errno));
    }

    // 8. Close the framebuffer device
    if (close_framebuffer(framebuffer_fd) != 0) {
        fprintf(stderr, "Error: Failed to close framebuffer: %s\n", strerror(errno));
    }

    return EXIT_SUCCESS;
}

// Function to introduce a delay in milliseconds
void delay_ms(int milliseconds) {
    usleep(milliseconds * 1000);
}

// Function to open the framebuffer device
int open_framebuffer(void) {
    int fd = open(FB_DEVICE_PATH, O_RDWR);
    if (fd == -1) {
        perror("Error opening framebuffer device");
    }
    return fd;
}

// Function to map the framebuffer into memory
void *map_framebuffer(int fd) {
    void *map = mmap(NULL, FILE_SIZE, PROT_READ | PROT_WRITE, MAP_SHARED, fd, 0);
    if (map == MAP_FAILED) {
        perror("Error mapping framebuffer to memory");
    }
    return map;
}

// Function to unmap the framebuffer from memory
int unmap_framebuffer(void *map) {
    if (munmap(map, FILE_SIZE) == -1) {
        perror("Error unmapping framebuffer from memory");
        return -1;
    }
    return 0;
}

// Function to close the framebuffer device
int close_framebuffer(int fd) {
    if (close(fd) == -1) {
        perror("Error closing framebuffer device");
        return -1;
    }
    return 0;
}

// Function to clear the LED matrix (set all pixels to black)
int clear_led_matrix(uint16_t *framebuffer) {
    memset(framebuffer, 0, FILE_SIZE);
    return 0;
}

// Function to set the color of a specific pixel in the LED matrix
int set_pixel_color(uint16_t *framebuffer, int x, int y, uint16_t color) {
    if (x < 0 || x >= LED_MATRIX_WIDTH || y < 0 || y >= LED_MATRIX_HEIGHT) {
        fprintf(stderr, "Error: Pixel coordinates (%d, %d) are out of bounds.\n", x, y);
        return -1;
    }
    framebuffer[y * LED_MATRIX_WIDTH + x] = color;
    return 0;
}

int check_sense_hat(int fd) {
    struct fb_fix_screeninfo fix_info;

    if (ioctl(fd, FBIOGET_FSCREENINFO, &fix_info) == -1) {
        perror("Error (call to 'ioctl')");
        return -1;
    }

    /* now check the correct device has been found */
    if (strcmp(fix_info.id, "RPi-Sense FB") != 0) {
        printf("%s\n", "Error: RPi-Sense FB not found");
        return -1;
    }
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <signal.h>
#include <unistd.h>

// TCS34725 Registers
#define TCS34725_ADDRESS 0x29
#define TCS34725_ENABLE  0x00
#define TCS34725_ATIME   0x01
#define TCS34725_CONTROL 0x0F
#define TCS34725_CDATA   0x14
#define TCS34725_RDATA   0x16
#define TCS34725_GDATA   0x18
#define TCS34725_BDATA   0x1A

// GPIO for LED
#define LED_GPIO 17

// I2C bus
#define I2C_BUS 1

int i2c_handle;

// Structure to hold color data
typedef struct {
    unsigned int r;
    unsigned int g;
    unsigned int b;
    unsigned int c;
} color_data_t;

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);
    gpioWrite(LED_GPIO, 0); // Turn off LED
    i2cClose(i2c_handle);
    gpioTerminate();
    exit(0);
}

// Function to set the LED state
void set_led_state(int state) {
    gpioWrite(LED_GPIO, state);
}

// Function to read color data from the sensor
color_data_t read_color_data() {
    color_data_t color;
    int handle = i2c_handle; // Use the global I2C handle

    color.c = i2cReadWordData(handle, 0x80 | TCS34725_CDATA);
    color.r = i2cReadWordData(handle, 0x80 | TCS34725_RDATA);
    color.g = i2cReadWordData(handle, 0x80 | TCS34725_GDATA);
    color.b = i2cReadWordData(handle, 0x80 | TCS34725_BDATA);

    return color;
}

// Function to check if blue is dominant
int is_blue(unsigned int r, unsigned int g, unsigned int b) {
    return (b > r && b > g);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C connection
    i2c_handle = i2cOpen(I2C_BUS, TCS34725_ADDRESS, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Configure TCS34725
    if (i2cWriteByteData(i2c_handle, TCS34725_ATIME, 0xD9) < 0) {
        fprintf(stderr, "Error writing to ATIME register\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }
    if (i2cWriteByteData(i2c_handle, TCS34725_CONTROL, 0x00) < 0) {
        fprintf(stderr, "Error writing to CONTROL register\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }
    if (i2cWriteByteData(i2c_handle, TCS34725_ENABLE, 0x03) < 0) {
        fprintf(stderr, "Error writing to ENABLE register\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set LED GPIO as output
    gpioSetMode(LED_GPIO, PI_OUTPUT);

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Main loop
    while (1) {
        color_data_t color = read_color_data();
        printf("R: %u, G: %u, B: %u, C: %u\n", color.r, color.g, color.b, color.c);

        if (is_blue(color.r, color.g, color.b)) {
            set_led_state(1);
        } else {
            set_led_state(0);
        }

        gpioDelay(100000); // 100ms delay
    }

    // Cleanup (should not reach here due to the signal handler)
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <wiringPiI2C.h>
#include <wiringPi.h>

// Define the I2C address of the BME280 sensor
#define BME280_I2C_ADDR 0x76

// Define the filename to store the calibration data
#define CALIBRATION_FILE "bme280_calibration.dat"

// Structure to hold the BME280 calibration data
typedef struct {
    uint16_t dig_T1;
    int16_t dig_T2;
    int16_t dig_T3;
    uint16_t dig_P1;
    int16_t dig_P2;
    int16_t dig_P3;
    int16_t dig_P4;
    int16_t dig_P5;
    int16_t dig_P6;
    int16_t dig_P7;
    int16_t dig_P8;
    int16_t dig_P9;
    uint8_t dig_H1;
    int16_t dig_H2;
    uint8_t dig_H3;
    int16_t dig_H4;
    int16_t dig_H5;
    int8_t dig_H6;
} bme280_calibration_data;

// Function to read the calibration data from the BME280 sensor
int read_calibration_data(int fd, bme280_calibration_data *cal) {
    // Read temperature calibration data
    cal->dig_T1 = wiringPiI2CReadReg16(fd, 0x88);
    if (cal->dig_T1 == -1) { fprintf(stderr, "Error reading dig_T1 at 0x88\n"); return -1; }
    cal->dig_T2 = (int16_t)wiringPiI2CReadReg16(fd, 0x8A);
    if (cal->dig_T2 == -1) { fprintf(stderr, "Error reading dig_T2 at 0x8A\n"); return -1; }
    cal->dig_T3 = (int16_t)wiringPiI2CReadReg16(fd, 0x8C);
    if (cal->dig_T3 == -1) { fprintf(stderr, "Error reading dig_T3 at 0x8C\n"); return -1; }

    // Read pressure calibration data
    cal->dig_P1 = wiringPiI2CReadReg16(fd, 0x8E);
    if (cal->dig_P1 == -1) { fprintf(stderr, "Error reading dig_P1 at 0x8E\n"); return -1; }
    cal->dig_P2 = (int16_t)wiringPiI2CReadReg16(fd, 0x90);
    if (cal->dig_P2 == -1) { fprintf(stderr, "Error reading dig_P2 at 0x90\n"); return -1; }
    cal->dig_P3 = (int16_t)wiringPiI2CReadReg16(fd, 0x92);
    if (cal->dig_P3 == -1) { fprintf(stderr, "Error reading dig_P3 at 0x92\n"); return -1; }
    cal->dig_P4 = (int16_t)wiringPiI2CReadReg16(fd, 0x94);
    if (cal->dig_P4 == -1) { fprintf(stderr, "Error reading dig_P4 at 0x94\n"); return -1; }
    cal->dig_P5 = (int16_t)wiringPiI2CReadReg16(fd, 0x96);
    if (cal->dig_P5 == -1) { fprintf(stderr, "Error reading dig_P5 at 0x96\n"); return -1; }
    cal->dig_P6 = (int16_t)wiringPiI2CReadReg16(fd, 0x98);
    if (cal->dig_P6 == -1) { fprintf(stderr, "Error reading dig_P6 at 0x98\n"); return -1; }
    cal->dig_P7 = (int16_t)wiringPiI2CReadReg16(fd, 0x9A);
    if (cal->dig_P7 == -1) { fprintf(stderr, "Error reading dig_P7 at 0x9A\n"); return -1; }
    cal->dig_P8 = (int16_t)wiringPiI2CReadReg16(fd, 0x9C);
    if (cal->dig_P8 == -1) { fprintf(stderr, "Error reading dig_P8 at 0x9C\n"); return -1; }
    cal->dig_P9 = (int16_t)wiringPiI2CReadReg16(fd, 0x9E);
    if (cal->dig_P9 == -1) { fprintf(stderr, "Error reading dig_P9 at 0x9E\n"); return -1; }

    // Read humidity calibration data
    cal->dig_H1 = wiringPiI2CReadReg8(fd, 0xA1);
    if (cal->dig_H1 == -1) { fprintf(stderr, "Error reading dig_H1 at 0xA1\n"); return -1; }
    cal->dig_H2 = (int16_t)wiringPiI2CReadReg16(fd, 0xE1);
    if (cal->dig_H2 == -1) { fprintf(stderr, "Error reading dig_H2 at 0xE1\n"); return -1; }
    cal->dig_H3 = wiringPiI2CReadReg8(fd, 0xE3);
    if (cal->dig_H3 == -1) { fprintf(stderr, "Error reading dig_H3 at 0xE3\n"); return -1; }
    cal->dig_H4 = (wiringPiI2CReadReg8(fd, 0xE4) << 4) | (wiringPiI2CReadReg8(fd, 0xE5) & 0x0F);
    if (cal->dig_H4 == -1) { fprintf(stderr, "Error reading dig_H4 at 0xE4/0xE5\n"); return -1; }
    cal->dig_H5 = ((wiringPiI2CReadReg8(fd, 0xE6) << 4) | (wiringPiI2CReadReg8(fd, 0xE5) >> 4));
    if (cal->dig_H5 == -1) { fprintf(stderr, "Error reading dig_H5 at 0xE6/0xE5\n"); return -1; }
    cal->dig_H6 = (int8_t)wiringPiI2CReadReg8(fd, 0xE7);
    if (cal->dig_H6 == -1) { fprintf(stderr, "Error reading dig_H6 at 0xE7\n"); return -1; }

    return 0; // Success
}

// Function to write the calibration data to a file
int write_calibration_to_file(const char *filename, const bme280_calibration_data *cal) {
    FILE *fp = fopen(filename, "wb");
    if (fp == NULL) {
        fprintf(stderr, "Error opening file %s for writing\n", filename);
        return -1;
    }

    size_t bytes_written = fwrite(cal, sizeof(bme280_calibration_data), 1, fp);
    if (bytes_written != 1) {
        fprintf(stderr, "Error writing calibration data to file %s\n", filename);
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return 0;
}

int main() {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error initializing wiringPi\n");
        return 1;
    }

    // Initialize I2C
    int fd = wiringPiI2CSetup(BME280_I2C_ADDR);
    if (fd == -1) {
        fprintf(stderr, "Error initializing I2C communication\n");
        return 1;
    }

    // Declare a variable to store the calibration data
    bme280_calibration_data cal;

    // Read the calibration data from the sensor
    if (read_calibration_data(fd, &cal) != 0) {
        fprintf(stderr, "Error reading calibration data\n");
        return 1;
    }

    // Write the calibration data to a file
    if (write_calibration_to_file(CALIBRATION_FILE, &cal) != 0) {
        fprintf(stderr, "Error writing calibration data to file\n");
        return 1;
    }

    // Print a success message
    printf("Calibration data successfully read and saved to %s\n", CALIBRATION_FILE);

    return 0;
}

