#define FREQUENCY 1500

int main() {
    if (wiringPiSetup() == -1) return 1;
    pinMode(BUZZER, PWM_OUTPUT);
    pinMode(BUTTON, INPUT);
    pullUpDnControl(BUTTON, PUD_UP);
    pwmSetMode(PWM_MODE_MS);
    pwmSetClock(32);
    pwmSetRange(600000 / FREQUENCY);

    int pressCount = 0;
    clock_t startTime = 0;

    while (1) {
        if (digitalRead(BUTTON) == 0) {
            if (pressCount == 0) {
                startTime = clock();
            }
            pressCount++;
            delay(300);
        }

        if (pressCount == 2) {
            clock_t endTime = clock();
            double elapsedTime = ((double)(endTime - startTime)) / CLOCKS_PER_SEC;
            if (elapsedTime < 1) {
                pwmWrite(BUZZER, 300);
                printf("Alarm ON\n");
                delay(2000);
                pwmWrite(BUZZER, 0);
            }
            pressCount = 0;
        }
    }
    return 0;
}

#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>

// Motor control pins (L293D)
#define MOTOR_IN1 17
#define MOTOR_IN2 18
#define MOTOR_EN  22 // Enable pin (PWM if speed control needed)

// Button pin
#define BUTTON_PIN 4

// Door open time (seconds)
#define DOOR_OPEN_TIME 5

// Function to open the door
void openDoor() {
    gpioWrite(MOTOR_EN, 1); // Enable the motor
    gpioWrite(MOTOR_IN1, 1); // Motor forward
    gpioWrite(MOTOR_IN2, 0);
    printf("Opening door...\n");
    sleep(DOOR_OPEN_TIME);
    stopMotor();
}

// Function to close the door
void closeDoor() {
    gpioWrite(MOTOR_EN, 1); // Enable the motor
    gpioWrite(MOTOR_IN1, 0); // Motor backward
    gpioWrite(MOTOR_IN2, 1);
    printf("Closing door...\n");
    sleep(DOOR_OPEN_TIME);
    stopMotor();
}

// Function to stop the motor
void stopMotor() {
    gpioWrite(MOTOR_EN, 0); // Disable the motor
    gpioWrite(MOTOR_IN1, 0);
    gpioWrite(MOTOR_IN2, 0);
    printf("Motor stopped.\n");
}

// Button press handler
void buttonHandler(int gpio, int level, uint32_t tick) {
    if (level == 0) { // Button pressed (falling edge)
        printf("Button pressed!\n");
        openDoor();
        closeDoor();
    }
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set motor control pins as outputs
    gpioSetMode(MOTOR_IN1, PI_OUTPUT);
    gpioSetMode(MOTOR_IN2, PI_OUTPUT);
    gpioSetMode(MOTOR_EN, PI_OUTPUT);

    // Set button pin as input with pull-up resistor
    gpioSetMode(BUTTON_PIN, PI_INPUT);
    gpioSetPullUpDown(BUTTON_PIN, PI_PUD_UP); // Internal pull-up

    // Set callback for button press
    gpioSetAlertFunc(BUTTON_PIN, buttonHandler);

    printf("Automatic door simulation started. Press the button to open/close.\n");

    while (1) {
        // Keep the program running, waiting for button presses
        sleep(1); // Reduce CPU usage
    }

    gpioTerminate();
    return 0;
}

