#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Define GPIO pins
#define TRIG_PIN 23
#define ECHO_PIN 24
#define SERVO_PIN 18

// Distance threshold for logging (cm)
#define LOG_THRESHOLD 50.0
// Distance threshold for slowing down servo (cm)
#define PROXIMITY_THRESHOLD 30.0

// Servo angle limits (degrees)
#define SERVO_MIN_ANGLE 0
#define SERVO_MAX_ANGLE 180

// PWM pulse width limits (microseconds) - Adjust as needed for your servo
#define SERVO_MIN_PULSE_WIDTH 500
#define SERVO_MAX_PULSE_WIDTH 2500

// File path for the parking log
#define LOG_FILE_PATH "parking_log.txt"

// Global flag for graceful shutdown
volatile sig_atomic_t program_running = 1;

// Function prototypes
float measure_distance();
void set_servo_angle(int angle);
void log_entry(float distance, int angle);
void signal_handler(int signal);

// Error logging function
void log_error(const char *message) {
    FILE *error_log = fopen("error_log.txt", "a");
    if (error_log) {
        time_t now = time(NULL);
        fprintf(error_log, "%s: %s\n", ctime(&now), message);
        fclose(error_log);
    } else {
        fprintf(stderr, "Error opening error log file!\n");
    }
    perror(message); // Also print to stderr
}


// Function to measure distance using HC-SR04
float measure_distance() {
    gpioWrite(TRIG_PIN, 0); // Ensure trigger is low
    gpioDelay(2);
    gpioWrite(TRIG_PIN, 1);
    gpioDelay(10); // 10us trigger pulse
    gpioWrite(TRIG_PIN, 0);

    uint32_t start_tick = gpioTick();
    uint32_t end_tick = start_tick;

    // Wait for echo to go high (with timeout)
    int count = 0;
    while (gpioRead(ECHO_PIN) == 0 && count < 5000) {
        count++;
        gpioDelay(1); // Check every 1 us
    }

    if (count >= 5000) {
        log_error("Timeout waiting for ECHO high");
        return -1.0; // Indicate timeout error
    }

    start_tick = gpioTick();

    // Wait for echo to go low (with timeout)
    count = 0;
    while (gpioRead(ECHO_PIN) == 1 && count < 5000) {
        count++;
        gpioDelay(1);
    }

    if (count >= 5000) {
        log_error("Timeout waiting for ECHO low");
        return -1.0; // Indicate timeout error
    }

    end_tick = gpioTick();

    uint32_t diff = end_tick - start_tick;

    // Calculate distance in centimeters (speed of sound: 343 m/s)
    float distance = (float)diff * 343.0 / 20000.0; // cm

    return distance;
}

// Function to set the servo angle
void set_servo_angle(int angle) {
    if (angle < SERVO_MIN_ANGLE || angle > SERVO_MAX_ANGLE) {
        fprintf(stderr, "Error: Angle out of range (%d)\n", angle);
        log_error("Servo angle out of range");
        return;
    }

    // Map angle (0-180) to pulse width (500-2500)
    int pulse_width = SERVO_MIN_PULSE_WIDTH + (int)(((float)(angle - SERVO_MIN_ANGLE) / (SERVO_MAX_ANGLE - SERVO_MIN_ANGLE)) * (SERVO_MAX_PULSE_WIDTH - SERVO_MIN_PULSE_WIDTH));

    gpioServo(SERVO_PIN, pulse_width);
}

// Function to log entry access
void log_entry(float distance, int angle) {
    FILE *log_file = fopen(LOG_FILE_PATH, "a");
    if (log_file == NULL) {
        log_error("Error opening log file!");
        return;
    }

    time_t now = time(NULL);
    fprintf(log_file, "%s Distance: %.2f cm, Angle: %d degrees\n", ctime(&now), distance, angle);
    fclose(log_file);
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    program_running = 0;
    printf("\nCaught signal %d, exiting gracefully...\n", signal);
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        log_error("pigpio initialisation failed");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(TRIG_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);
    gpioSetMode(SERVO_PIN, PI_OUTPUT);

    // Register signal handler
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    int angle = SERVO_MIN_ANGLE;
    int direction = 1; // 1 for increasing, -1 for decreasing
    int delay_ms = 50; // Initial delay

    printf("Parking Assist System running...\n");

    while (program_running) {
        set_servo_angle(angle);
        float distance = measure_distance();

        if (distance > 0) { // Valid distance reading
            time_t now = time(NULL);
            printf("%s Angle: %d, Distance: %.2f cm\n", ctime(&now), angle, distance);

            if (distance < LOG_THRESHOLD) {
                log_entry(distance, angle);
            }

            // Adjust sweep speed based on proximity
            if (distance < PROXIMITY_THRESHOLD) {
                delay_ms = 200; // Slow down
            } else {
                delay_ms = 50; // Normal speed
            }
        } else {
            fprintf(stderr, "Invalid distance reading\n");
        }

        gpioDelay(delay_ms);

        // Update angle
        angle += direction;

        // Reverse direction at limits
        if (angle >= SERVO_MAX_ANGLE) {
            direction = -1;
        } else if (angle <= SERVO_MIN_ANGLE) {
            direction = 1;
        }
    }

    // Clean up and terminate
    gpioServo(SERVO_PIN, 0); // Stop servo
    gpioTerminate();
    printf("Program terminated.\n");

    return 0;
}

