#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <time.h>
#include <signal.h>
#include <pigpio.h>
#include <string.h>

// BMP280 I2C address
#define BMP280_I2C_ADDR 0x76

// BMP280 register addresses
#define BMP280_REG_TEMP_MSB 0xFA
#define BMP280_REG_PRESSURE_MSB 0xF7
#define BMP280_REG_CTRL_MEAS 0xF4
#define BMP280_REG_CONFIG 0xF5

// GPIO pin for button interrupt
#define BUTTON_GPIO 17

// Sea level pressure (hPa)
#define SEA_LEVEL_PRESSURE 1013.25

// Global flag for data logging
volatile int logging_enabled = 0;

// I2C handle
int i2c_handle;

// Function prototypes
int init_bmp280();
int read_bmp280_data(double *temperature, double *pressure);
double calculate_altitude(double pressure);
int write_data_to_csv(double temperature, double pressure, double altitude);
void button_interrupt_handler(int gpio, int level, uint32_t tick);
void signal_handler(int signal);

// Function to initialize the BMP280 sensor
int init_bmp280() {
    // Set control register to enable temperature and pressure measurement
    char ctrl_meas_val = 0b00110011; // Oversampling x1, normal mode
    if (i2cWriteI2CBlockData(i2c_handle, BMP280_REG_CTRL_MEAS, &ctrl_meas_val, 1) != 0) {
        fprintf(stderr, "Error writing to CTRL_MEAS register\n");
        return -1;
    }

    // Set config register for filter and standby time
    char config_val = 0b00010000; // Filter off, standby 0.5ms
    if (i2cWriteI2CBlockData(i2c_handle, BMP280_REG_CONFIG, &config_val, 1) != 0) {
        fprintf(stderr, "Error writing to CONFIG register\n");
        return -1;
    }

    return 0;
}

// Function to read temperature and pressure data from the BMP280 sensor
int read_bmp280_data(double *temperature, double *pressure) {
    char data[6];

    // Read 6 bytes of data (pressure MSB, LSB, XLSB, temp MSB, LSB, XLSB)
    if (i2cReadI2CBlockData(i2c_handle, BMP280_REG_PRESSURE_MSB, data, 6) != 6) {
        fprintf(stderr, "Error reading data from BMP280\n");
        return -1;
    }

    // Combine the values to get the raw temperature and pressure readings
    int32_t raw_pressure = (data[0] << 12) | (data[1] << 4) | (data[2] >> 4);
    int32_t raw_temperature = (data[3] << 12) | (data[4] << 4) | (data[5] >> 4);

    // Compensate temperature
    double var1 = (raw_temperature / 16384.0 - 256.0 / 16.0);
    double var2 = (raw_temperature / 131072.0 - 256.0 / 32768.0) * var1;
    double t_fine = var1 * (2048.0) + var2 * (65536.0);
    *temperature = (t_fine / 5120.0); // Temperature in degree C

    // Compensate pressure
    double var3 = (t_fine / 2.0) - 64000.0;
    double var4 = var3 * var3 * (1.0 / 131072.0);
    double var5 = var4 * var3 * (1.0 / 4194304.0);
    double offset = 32768.0 + var4 * 13932.0 + var5 * 8575.0;
    double var6 = var3 * (5.0 / 8.0);
    double var7 = var6 * var6 * (1.0 / 8192.0);
    double scale = 134479.0 + var6 * 6144.0 + var7 * 291.0;

    if (scale == 0)
        return -1; // Avoid exception caused by division by zero

    double p = 1048576.0 - raw_pressure;
    p = (p - (offset / 8192.0)) * scale;
    p = (p < 0x80000000 ? (p * 2.0) : (p / 2.0));
    p = (p / 33554432.0);
    *pressure = p; // Pressure in Pa

    return 0;
}

// Function to calculate altitude from pressure (using barometric formula)
double calculate_altitude(double pressure) {
    return 44330.0 * (1.0 - pow(pressure / (SEA_LEVEL_PRESSURE * 100.0), 0.1903));
}

// Function to write data to a CSV file
int write_data_to_csv(double temperature, double pressure, double altitude) {
    FILE *fp;
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    // Get current time
    time(&rawtime);
    timeinfo = localtime(&rawtime);
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    // Open the CSV file in append mode
    fp = fopen("altitude_log.csv", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening CSV file\n");
        return -1;
    }

    // Write the data to the CSV file
    fprintf(fp, "%s,%.2f,%.2f,%.2f\n", timestamp, temperature, pressure, altitude);

    // Close the file
    fclose(fp);

    return 0;
}

// Interrupt handler for the button press
void button_interrupt_handler(int gpio, int level, uint32_t tick) {
    // Toggle the logging enabled flag on button press (falling edge)
    if (level == 0) {
        logging_enabled = !logging_enabled;
        printf("Logging %s\n", logging_enabled ? "enabled" : "disabled");
    }
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, exiting gracefully...\n", signal);

    // Close I2C connection
    i2cClose(i2c_handle);

    // Terminate pigpio
    gpioTerminate();

    exit(0);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C bus
    i2c_handle = i2cOpen(1, BMP280_I2C_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C bus\n");
        gpioTerminate();
        return 1;
    }

    // Initialize the BMP280 sensor
    if (init_bmp280() != 0) {
        fprintf(stderr, "BMP280 initialisation failed\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set up interrupt handler for the button
    gpioSetMode(BUTTON_GPIO, PI_INPUT);
    gpioSetPullUpDown(BUTTON_GPIO, PI_PUD_UP); // Enable pull-up resistor
    gpioSetAlertFunc(BUTTON_GPIO, button_interrupt_handler);

    // Set up signal handlers for SIGINT and SIGTERM
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    double temperature, pressure, altitude;

    // Main loop
    while (1) {
        if (logging_enabled) {
            // Read data from the BMP280 sensor
            if (read_bmp280_data(&temperature, &pressure) == 0) {
                // Calculate altitude
                altitude = calculate_altitude(pressure);

                // Write data to CSV file
                if (write_data_to_csv(temperature, pressure, altitude) != 0) {
                    fprintf(stderr, "Error writing data to CSV file\n");
                }
            } else {
                fprintf(stderr, "Error reading data from BMP280 sensor\n");
            }
        }

        // Wait for 1 second
        gpioDelay(1000000); // 1 second in microseconds
    }

    return 0;
}

#include <stdio.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <stdlib.h>

// Define GPIO pins
#define TRIGGER_PIN 17
#define ECHO_PIN 18
#define SERVO_PIN 27

// Constants
#define SPEED_OF_SOUND 34300.0 // Speed of sound in cm/s
#define MIN_DISTANCE 2.0      // Minimum distance to consider (cm)
#define MAX_DISTANCE 30.0     // Maximum distance to consider (cm)
#define MIN_SERVO_PULSEWIDTH 500
#define MAX_SERVO_PULSEWIDTH 2500

// Global variable for program termination
volatile sig_atomic_t program_running = 1;

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    (void)signal; // Suppress unused parameter warning
    program_running = 0;
    printf("\nExiting gracefully...\n");
}

// Function to trigger the ultrasonic sensor
void triggerSensor() {
    gpioWrite(TRIGGER_PIN, 1);
    gpioDelay(10); // 10us trigger pulse
    gpioWrite(TRIGGER_PIN, 0);
}

// Function to read the distance from the ultrasonic sensor
float readDistance() {
    long long start_tick, end_tick;

    gpioSetMode(ECHO_PIN, PI_INPUT);

    // Wait for echo to go high
    int count = 0;
    while (gpioRead(ECHO_PIN) == 0 && count < 10000) { // Timeout after ~10ms
        count++;
        gpioDelay(1); // Small delay to prevent busy-waiting
    }

    if (count >= 10000) {
        fprintf(stderr, "Error: Echo signal not received (start)\n");
        return -1.0; // Indicate error
    }

    start_tick = gpioTick();

    // Wait for echo to go low
    count = 0;
    while (gpioRead(ECHO_PIN) == 1 && count < 10000) { // Timeout after ~10ms
        count++;
        gpioDelay(1); // Small delay to prevent busy-waiting
    }

    if (count >= 10000) {
        fprintf(stderr, "Error: Echo signal not received (end)\n");
        return -1.0; // Indicate error
    }

    end_tick = gpioTick();

    // Calculate pulse width in microseconds
    long long pulse_width = end_tick - start_tick;

    // Calculate distance in centimeters
    float distance = (pulse_width * SPEED_OF_SOUND) / 2000000.0;

    return distance;
}

// Function to map distance to servo angle
int mapDistanceToAngle(float distance) {
    // Linear mapping from distance (2-30cm) to angle (0-180 degrees)
    return (int)(((distance - MIN_DISTANCE) / (MAX_DISTANCE - MIN_DISTANCE)) * 180.0);
}

// Function to set the servo angle
void setServoAngle(int angle) {
    // Ensure angle is within valid range (0-180)
    if (angle < 0) angle = 0;
    if (angle > 180) angle = 180;

    // Convert angle to pulse width (500-2500 us)
    int pulse_width = MIN_SERVO_PULSEWIDTH + (int)(((float)angle / 180.0) * (MAX_SERVO_PULSEWIDTH - MIN_SERVO_PULSEWIDTH));

    gpioServo(SERVO_PIN, pulse_width);
}

// Function to log the distance with a timestamp
void logDistance(float distance) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    printf("[%s] Distance: %.2f cm\n", timestamp, distance);
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(SERVO_PIN, PI_OUTPUT);

    // Initialize trigger pin to low
    gpioWrite(TRIGGER_PIN, 0);

    // Set up signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    printf("Parking assist system started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        // Trigger the sensor
        triggerSensor();

        // Read the distance
        float distance = readDistance();

        // Check for errors
        if (distance < 0) {
            fprintf(stderr, "Error: Could not read distance\n");
        } else if (distance < MIN_DISTANCE || distance > MAX_DISTANCE) {
            fprintf(stderr, "Distance out of range (%.2f cm). Ignoring.\n", distance);
        } else {
            // Map distance to servo angle
            int angle = mapDistanceToAngle(distance);

            // Set the servo angle
            setServoAngle(angle);

            // Log the distance
            logDistance(distance);
        }

        // Delay to prevent excessive CPU usage
        gpioDelay(100); // 100ms delay
    }

    // Stop the servo motor
    gpioServo(SERVO_PIN, 0); // Disable servo pulses

    // Terminate pigpio library
    gpioTerminate();

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdarg.h>
#include <unistd.h>
#include <stdint.h>
#include <string.h>
#include <fcntl.h>
#include <errno.h>
#include <sys/mman.h>
#include <sys/stat.h>
#include <sys/types.h>

// Define Raspberry Pi hardware register offsets
#define GPIO_BASE  0x200000  // GPIO base address
#define CLK_BASE   0x101000  // Clock controller base address
#define SYST_BASE  0x003000  // System Timer base address

// Define register lengths for memory mapping
#define GPIO_LEN   0xB4
#define CLK_LEN    0xA8
#define SYST_LEN   0x1C

// GPIO pin function select modes
#define GPIO_MODE_INPUT  0
#define GPIO_MODE_OUTPUT 1
#define GPIO_MODE_ALT0   4

// GPIO pin pull-up/down control
#define GPIO_PUD_OFF  0
#define GPIO_PUD_DOWN 1
#define GPIO_PUD_UP   2

// Clock source definitions
#define CLK_SRC_OSC  1  // 19.2 MHz oscillator
#define CLK_SRC_PLLC 5  // 1000 MHz PLLC
#define CLK_SRC_PLLD 6  // 500 MHz PLLD
#define CLK_SRC_HDMI 7  // 216 MHz HDMI auxiliary

// Clock control register bits
#define CLK_CTL_MASH(x) ((x) << 9)
#define CLK_CTL_BUSY    (1 << 7)
#define CLK_CTL_KILL    (1 << 5)
#define CLK_CTL_ENAB    (1 << 4)
#define CLK_CTL_SRC(x)  ((x) << 0)

// Clock divider register bits
#define CLK_DIV_DIVI(x) ((x) << 12)
#define CLK_DIV_DIVF(x) ((x) << 0)

// Clock password for write access
#define CLK_PASSWD  (0x5A << 24)

// Clock registers (GP0, GP2)
#define CLK_GP0_CTL 28
#define CLK_GP0_DIV 29
#define CLK_GP2_CTL 32
#define CLK_GP2_DIV 33

// Pointers to memory-mapped registers
static volatile uint32_t *gpioReg = MAP_FAILED;
static volatile uint32_t *clkReg  = MAP_FAILED;
static volatile uint32_t *systReg = MAP_FAILED;

// Function prototypes
int  gpioInitialise(void);
void gpioTerminate(void);
void gpioSetMode(unsigned int gpioPin, unsigned int mode);
int  gpioGetMode(unsigned int gpioPin);
void gpioSetPullUpDown(unsigned int gpioPin, unsigned int pud);
int  initClock(int clockId, int source, int divI, int divF, int mash);
int  termClock(int clockId);
void fatal(int show_usage, const char *fmt, ...);
void usage(void);
int  initOpts(int argc, char *argv[]);

// Global option variables
static int opt_clock = 0;  // Default clock is GPCLK0
static int opt_mash  = 0;  // Default MASH value is 0
static int opt_source = 0; // Default clock source is PLLD
static int opt_quiet = 0;  // Default is to disable clock on exit

// Helper function to map physical memory to virtual memory
static uint32_t *mapPeripheral(uint32_t baseAddr, uint32_t len)
{
    int fd = open("/dev/mem", O_RDWR | O_SYNC);
    if (fd < 0) {
        fprintf(stderr, "Failed to open /dev/mem.  Try using sudo.\n");
        return MAP_FAILED;
    }

    uint32_t *map = (uint32_t *)mmap(NULL, len, PROT_READ | PROT_WRITE, MAP_SHARED, fd, baseAddr);
    close(fd);

    if (map == MAP_FAILED) {
        fprintf(stderr, "mmap failed.\n");
    }
    return map;
}

// Initializes the GPIO, clock, and system timer registers
int gpioInitialise(void)
{
    // Map GPIO registers
    gpioReg = mapPeripheral(GPIO_BASE, GPIO_LEN);
    if (gpioReg == MAP_FAILED) return -1;

    // Map Clock registers
    clkReg = mapPeripheral(CLK_BASE, CLK_LEN);
    if (clkReg == MAP_FAILED) {
        gpioTerminate(); // Clean up already mapped memory
        return -1;
    }

    // Map System Timer registers
    systReg = mapPeripheral(SYST_BASE, SYST_LEN);
    if (systReg == MAP_FAILED) {
        gpioTerminate(); // Clean up already mapped memory
        return -1;
    }

    return 0;
}

// Unmaps the GPIO, clock, and system timer registers
void gpioTerminate(void)
{
    if (gpioReg != MAP_FAILED) {
        munmap((void *)gpioReg, GPIO_LEN);
        gpioReg = MAP_FAILED;
    }
    if (clkReg != MAP_FAILED) {
        munmap((void *)clkReg, CLK_LEN);
        clkReg = MAP_FAILED;
    }
    if (systReg != MAP_FAILED) {
        munmap((void *)systReg, SYST_LEN);
        systReg = MAP_FAILED;
    }
}

// Sets the mode of a GPIO pin (input, output, alt0, etc.)
void gpioSetMode(unsigned int gpioPin, unsigned int mode)
{
    if (gpioReg == MAP_FAILED) {
        fprintf(stderr, "GPIO registers not initialized.\n");
        return;
    }

    int reg = gpioPin / 10;
    int shift = (gpioPin % 10) * 3;
    gpioReg[reg] = (gpioReg[reg] & ~(7 << shift)) | (mode << shift);
}

// Gets the mode of a GPIO pin
int gpioGetMode(unsigned int gpioPin)
{
    if (gpioReg == MAP_FAILED) {
        fprintf(stderr, "GPIO registers not initialized.\n");
        return -1; // Indicate error
    }

    int reg = gpioPin / 10;
    int shift = (gpioPin % 10) * 3;
    return (gpioReg[reg] >> shift) & 7;
}

// Sets the pull-up/down resistor for a GPIO pin
void gpioSetPullUpDown(unsigned int gpioPin, unsigned int pud)
{
    if (gpioReg == MAP_FAILED) {
        fprintf(stderr, "GPIO registers not initialized.\n");
        return;
    }

    gpioReg[37] = pud; // GPPUD register
    usleep(20);
    gpioReg[38 + (gpioPin / 32)] = (1 << (gpioPin % 32)); // GPPUDCLK register
    usleep(20);
    gpioReg[37] = 0; // Reset GPPUD register
    gpioReg[38 + (gpioPin / 32)] = 0; // Reset GPPUDCLK register
}

// Initializes the clock with the given parameters
int initClock(int clockId, int source, int divI, int divF, int mash)
{
    if (clkReg == MAP_FAILED) {
        fprintf(stderr, "Clock registers not initialized.\n");
        return -1;
    }

    if (clockId != 0 && clockId != 1) {
        fprintf(stderr, "Invalid clock ID. Must be 0 (GPCLK0) or 1 (GPCLK2).\n");
        return -1;
    }

    if (source < 0 || source > 3) {
        fprintf(stderr, "Invalid clock source. Must be 0-3.\n");
        return -1;
    }

    if (divI < 2 || divI > 4095) {
        fprintf(stderr, "Invalid integer divider. Must be between 2 and 4095.\n");
        return -1;
    }

    if (divF < 0 || divF > 4095) {
        fprintf(stderr, "Invalid fractional divider. Must be between 0 and 4095.\n");
        return -1;
    }

    if (mash < 0 || mash > 3) {
        fprintf(stderr, "Invalid MASH value. Must be between 0 and 3.\n");
        return -1;
    }

    // Determine the control and divider register offsets based on clockId
    int clkCtlReg = (clockId == 0) ? CLK_GP0_CTL : CLK_GP2_CTL;
    int clkDivReg = (clockId == 0) ? CLK_GP0_DIV : CLK_GP2_DIV;

    // Kill the clock first
    clkReg[clkCtlReg] = CLK_PASSWD | CLK_CTL_KILL;

    // Wait for the clock to stop
    while (clkReg[clkCtlReg] & CLK_CTL_BUSY) {
        usleep(10);
    }

    // Set the divider
    clkReg[clkDivReg] = CLK_PASSWD | CLK_DIV_DIVI(divI) | CLK_DIV_DIVF(divF);
    usleep(10);

    // Set the source and MASH
    clkReg[clkCtlReg] = CLK_PASSWD | CLK_CTL_MASH(mash) | CLK_CTL_SRC(source);
    usleep(10);

    // Enable the clock
    clkReg[clkCtlReg] |= (CLK_PASSWD | CLK_CTL_ENAB);

    return 0;
}

// Terminates the clock, disabling it
int termClock(int clockId)
{
    if (clkReg == MAP_FAILED) {
        fprintf(stderr, "Clock registers not initialized.\n");
        return -1;
    }

    if (clockId != 0 && clockId != 1) {
        fprintf(stderr, "Invalid clock ID. Must be 0 (GPCLK0) or 1 (GPCLK2).\n");
        return -1;
    }

    // Determine the control register offset based on clockId
    int clkCtlReg = (clockId == 0) ? CLK_GP0_CTL : CLK_GP2_CTL;

    // Kill the clock
    clkReg[clkCtlReg] = CLK_PASSWD | CLK_CTL_KILL;

    // Wait for the clock to stop
    while (clkReg[clkCtlReg] & CLK_CTL_BUSY) {
        usleep(10);
    }

    return 0;
}

// Prints usage information
void usage(void)
{
    fprintf(stderr,
            "Usage: minimal_clk x.x[KM] [OPTIONS]\n"
            "       minimal_clk x.xD [OPTIONS]\n"
            "\n"
            "  x.x  Frequency in Hz, kHz, or MHz.  Must be between 4.6875 kHz and 500 MHz.\n"
            "       K  kilo multiplier (x1000)\n"
            "       M  mega multiplier (x1000000)\n"
            "\n"
            "  x.xD Divider.  Must be >= 2.0 and < 4096.  Integer and fractional parts are used as dividers.\n"
            "\n"
            "Options:\n"
            "  -c <clock>   Clock to configure: 0=GPCLK0 (default), 1=GPCLK2\n"
            "  -s <source>  Clock source: 0=PLLD (default), 1=OSC, 2=HDMI, 3=PLLC\n"
            "  -m <mash>    MASH value: 0-3 (default=0)\n"
            "  -q           Quiet mode: Leave clock enabled on exit (default: disable clock)\n"
            "\n"
            "Examples:\n"
            "  minimal_clk 36.23M        # Set frequency to 36.23 MHz\n"
            "  minimal_clk 234.179D      # Set divider to 234.179 (I=234, F=0.179*4096)\n"
           );
}

// Prints an error message and exits
void fatal(int show_usage, const char *fmt, ...)
{
    va_list args;
    va_start(args, fmt);
    vfprintf(stderr, fmt, args);
    va_end(args);
    fprintf(stderr, "\n");
    if (show_usage) usage();
    exit(EXIT_FAILURE);
}

// Parses command-line options
int initOpts(int argc, char *argv[])
{
    int opt;
    while ((opt = getopt(argc, argv, "c:m:s:q")) != -1) {
        switch (opt) {
            case 'c':
                opt_clock = atoi(optarg);
                if (opt_clock != 0 && opt_clock != 1) {
                    fatal(1, "Invalid clock ID: %s", optarg);
                }
                break;
            case 'm':
                opt_mash = atoi(optarg);
                if (opt_mash < 0 || opt_mash > 3) {
                    fatal(1, "Invalid MASH value: %s", optarg);
                }
                break;
            case 's':
                opt_source = atoi(optarg);
                if (opt_source < 0 || opt_source > 3) {
                    fatal(1, "Invalid clock source: %s", optarg);
                }
                break;
            case 'q':
                opt_quiet = 1;
                break;
            default:
                usage();
                exit(EXIT_FAILURE);
        }
    }
    return optind;
}

int main(int argc, char *argv[])
{
    int non_options;
    double freq, div;
    char *endptr;

    // Clock source frequencies
    double clockFrequencies[] = {500e6, 19.2e6, 216e6, 1000e6};
    char *clockNames[] = {"PLLD", "OSC", "HDMI", "PLLC"};
    int divI, divF;

    // Parse command-line options
    non_options = initOpts(argc, argv);

    // Check if a frequency or divider value was provided
    if (non_options == (argc - 1)) {
        // Get the frequency/divider argument
        errno = 0;
        freq = strtod(argv[non_options], &endptr);
        if (errno) fatal(1, "Invalid frequency/divider value: %s", argv[non_options]);
        if (endptr == argv[non_options]) fatal(1, "Invalid frequency/divider value: %s", argv[non_options]);

        // Determine if it's a frequency or divider value
        switch (*endptr) {
            case 'm':
            case 'M':
                freq *= 1000000.0; // MHz
                break;
            case 'k':
            case 'K':
                freq *= 1000.0;    // kHz
                break;
            case 'd':
            case 'D':
                // Divider value
                if (freq < 2.0 || freq >= 4096.0) fatal(1, "Divider must be >= 2.0 and < 4096.0");
                divI = (int)freq;
                divF = (int)((freq - divI) * 4096.0);

                printf("Setting clock with divider: Integer=%d, Fractional=%d\n", divI, divF);

                // Initialize hardware and set clock
                if (gpioInitialise() < 0) {
                    fprintf(stderr, "Failed to initialize GPIO.\n");
                    return 1;
                }

                if (initClock(opt_clock, opt_source, divI, divF, opt_mash) < 0) {
                    fprintf(stderr, "Failed to initialize clock.\n");
                    gpioTerminate();
                    return 1;
                }

                // Set GPIO pin mode (GPCLK0=GPIO4, GPCLK2=GPIO6)
                if (opt_clock == 0) gpioSetMode(4, GPIO_MODE_ALT0);
                else gpioSetMode(6, GPIO_MODE_ALT0);

                // Wait for user input or terminate immediately
                if (!opt_quiet) {
                    printf("Press Enter to exit and disable clock...\n");
                    getchar();
                    if (opt_clock == 0) gpioSetMode(4, GPIO_MODE_INPUT);
                    else gpioSetMode(6, GPIO_MODE_INPUT);
                    termClock(opt_clock);
                }

                gpioTerminate();
                return 0;
            case '\0':
                // Frequency value
                if (freq < 4687.5 || freq > 500e6) fatal(1, "Frequency must be between 4.6875 kHz and 500 MHz");
                break;
            default:
                usage();
                exit(EXIT_FAILURE);
        }

         div = clockFrequencies[opt_source] / freq;
         divI = div;         
         divF = (div-divI) * 4096;

         if (gpioInitialise() < 0) {
             fprintf(stderr, "Failed to initialize GPIO.\n");
             return 1;
         }

         if (initClock(opt_clock, opt_source, divI, divF, opt_mash) < 0) {
             fprintf(stderr, "Failed to initialize clock.\n");
             gpioTerminate();
             return 1;
         }

         // Set GPIO pin mode (GPCLK0=GPIO4, GPCLK2=GPIO6)
         if (opt_clock == 0) gpioSetMode(4, GPIO_MODE_ALT0);
         else gpioSetMode(6, GPIO_MODE_ALT0);

         // Wait for user input or terminate immediately
         if (!opt_quiet) {
             printf("Press Enter to exit and disable clock...\n");
             getchar();
             if (opt_clock == 0) gpioSetMode(4, GPIO_MODE_INPUT);
             else gpioSetMode(6, GPIO_MODE_INPUT);
             termClock(opt_clock);
         }

         gpioTerminate();
         return 0;

    } else {
        usage();
        return 1;
    }

    return 0;
}

