#define SERVO_PIN 18
#define CW_BUTTON 23
#define CCW_BUTTON 24

int main(void) {
    if (gpioInitialise() < 0) {
        printf("pigpio initialization failed!\n");
        return 1;
    }
    gpioSetMode(SERVO_PIN, PI_OUTPUT);
    gpioSetMode(CW_BUTTON, PI_INPUT);
    gpioSetMode(CCW_BUTTON, PI_INPUT);
    gpioSetPullUpDown(CW_BUTTON, PI_PUD_UP);
    gpioSetPullUpDown(CCW_BUTTON, PI_PUD_UP);

    int position = 1500; // Start at neutral position

    while (1) {
        if (gpioRead(CW_BUTTON) == 0 && position < 2500) {
            position += 10;
            gpioServo(SERVO_PIN, position);
            printf("Moving clockwise to %d\n", position);
        }
        if (gpioRead(CCW_BUTTON) == 0 && position > 500) {
            position -= 10;
            gpioServo(SERVO_PIN, position);
            printf("Moving counterclockwise to %d\n", position);
        }
        gpioDelay(100000); // Debounce
    }
    gpioTerminate();
    return 0;
}

