// Define GPIO pins
#define SOUND_SENSOR_PIN 23
#define BUZZER_PIN 18

// Define constants
#define ALARM_DURATION 2  // seconds
#define CALIBRATION_DURATION 5 // seconds
#define SAMPLE_DELAY 10 // milliseconds

// Global variable for sound level threshold
volatile int sound_threshold = 500; // Initial value

// Global file pointer for logging
FILE *log_file = NULL;

// Function prototypes
int calibrate_threshold();
int read_sound_level();
void trigger_alarm();
void log_alarm_event();
void signal_handler(int signal);

// Signal handler function for clean shutdown
void signal_handler(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);

    // Disable buzzer
    gpioWrite(BUZZER_PIN, 0);

    // Close log file
    if (log_file != NULL) {
        fclose(log_file);
    }

    // Terminate pigpio
    gpioTerminate();

    exit(0);
}

// Function to calibrate the sound level threshold
int calibrate_threshold() {
    printf("Calibrating sound threshold for %d seconds...\n", CALIBRATION_DURATION);
    int sum = 0;
    int count = 0;
    time_t start_time = time(NULL);

    while (time(NULL) - start_time < CALIBRATION_DURATION) {
        sum += read_sound_level();
        count++;
        gpioDelay(SAMPLE_DELAY * 1000); // Convert milliseconds to microseconds
    }

    if (count > 0) {
        sound_threshold = (sum / count) + 100; // Set threshold slightly above average
        printf("Calibration complete. New threshold: %d\n", sound_threshold);
        return 0; // Success
    } else {
        fprintf(stderr, "Error: Could not calibrate threshold.\n");
        return -1; // Failure
    }
}

// Function to read the sound level from the sensor
int read_sound_level() {
    return gpioRead(SOUND_SENSOR_PIN);
}

// Function to trigger the piezo buzzer alarm
void trigger_alarm() {
    gpioWrite(BUZZER_PIN, 1); // Turn on buzzer
    gpioDelay(ALARM_DURATION * 1000000); // Wait for alarm duration (seconds to microseconds)
    gpioWrite(BUZZER_PIN, 0); // Turn off buzzer
}

// Function to log the alarm event to a file
void log_alarm_event() {
    time_t current_time = time(NULL);
    struct tm *time_info = localtime(&current_time);
    char timestamp[20]; // YYYY-MM-DD HH:MM:SS\0

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", time_info);

    log_file = fopen("alarm_log.txt", "a"); // Open in append mode
    if (log_file == NULL) {
        perror("Error opening alarm_log.txt");
        return;
    }

    fprintf(log_file, "%s - Alarm Triggered\n", timestamp);
    fclose(log_file);
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(SOUND_SENSOR_PIN, PI_INPUT);
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);
    gpioSetPullUpDown(SOUND_SENSOR_PIN, PI_PUD_DOWN); // Assuming sensor needs pull-down

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Calibrate the sound threshold
    if (calibrate_threshold() != 0) {
        gpioTerminate();
        return 1;
    }

    printf("Baby monitor started. Press Ctrl+C to exit.\n");

    // Main loop
    while (1) {
        int sound_level = read_sound_level();

        if (sound_level == 1) {
            if (sound_level > sound_threshold) {
                printf("Alarm triggered! Sound level: %d\n", sound_level);
                trigger_alarm();
                log_alarm_event();
            }
        }

        gpioDelay(SAMPLE_DELAY * 1000); // Delay to prevent busy-waiting
    }

    return 0; // This line will never be reached due to the infinite loop
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <signal.h>
#include <errno.h>
#include <string.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>
#include <softPwm.h>

// Define constants
#define SOLENOID_GPIO 18       // GPIO pin for solenoid valve control (PWM)
#define I2C_ADDR 0x28          // I2C address of MPX5700AP pressure sensor
#define PWM_RANGE 100          // PWM range (0-100)
#define MIN_PRESSURE 0.0       // Minimum pressure (PSI)
#define MAX_PRESSURE 700.0     // Maximum pressure (PSI) for MPX5700AP
#define V_SUPPLY 5.0           // Supply voltage for the sensor (V)
#define V_OFFSET 0.2 * V_SUPPLY // Offset voltage (V)
#define PRESSURE_SCALE (MAX_PRESSURE - MIN_PRESSURE) / (0.8 * V_SUPPLY)

// Global variables
int i2c_fd;                   // I2C file descriptor
volatile sig_atomic_t keep_running = 1; // Flag to control the main loop

// Function prototypes
void initialize_solenoid();
float read_pressure();
int calculate_pwm(float desired_pressure, float current_pressure); // Pass current pressure
void apply_pwm(int duty_cycle);
void signal_handler(int sig);

// Signal handler for clean shutdown
void signal_handler(int sig) {
  if (sig == SIGINT) {
    printf("\nCaught signal SIGINT, exiting gracefully.\n");
    keep_running = 0; // Stop the main loop
    softPwmWrite(SOLENOID_GPIO, 0); // Disable PWM
    close(i2c_fd);              // Close I2C connection
    exit(0);
  }
}

// Initialize solenoid valve (set GPIO to PWM mode)
void initialize_solenoid() {
  if (softPwmCreate(SOLENOID_GPIO, 0, PWM_RANGE) != 0) {
    fprintf(stderr, "Error initializing PWM on GPIO %d: %s\n", SOLENOID_GPIO, strerror(errno));
    exit(1);
  }
  printf("Solenoid valve initialized on GPIO %d.\n", SOLENOID_GPIO);
}

// Read pressure from MPX5700AP sensor (convert raw I2C data to PSI)
float read_pressure() {
  int raw_data;
  float voltage;
  float pressure;

  raw_data = wiringPiI2CReadReg16(i2c_fd, 0x00); // Read from register 0x00
  if (raw_data == -1) {
    fprintf(stderr, "Error reading I2C data: %s\n", strerror(errno));
    return -1.0; // Indicate error
  }

  //MPX5700AP returns data in big-endian format, so we need to swap bytes
  raw_data = ((raw_data & 0xFF) << 8) | ((raw_data >> 8) & 0xFF);

  voltage = ((float)raw_data / 65535.0) * V_SUPPLY;
  pressure = (voltage - V_OFFSET) * PRESSURE_SCALE;

  //Clamp pressure values to physically possible range.
  if (pressure < MIN_PRESSURE) {
    pressure = MIN_PRESSURE;
  }
  if (pressure > MAX_PRESSURE) {
    pressure = MAX_PRESSURE;
  }

  return pressure;
}

// Calculate PWM duty cycle based on desired pressure and current pressure
int calculate_pwm(float desired_pressure, float current_pressure) {
  // Implement a simple proportional control
  float error = desired_pressure - current_pressure;
  float proportional_gain = 0.1; // Adjust this value based on system response
  float pwm_signal = proportional_gain * error;

  // Clamp the PWM signal to the valid range (0-100)
  if (pwm_signal < 0.0) {
    pwm_signal = 0.0;
  }
  if (pwm_signal > 100.0) {
    pwm_signal = 100.0;
  }

  return (int)pwm_signal;
}

// Apply PWM signal to the solenoid valve
void apply_pwm(int duty_cycle) {
  softPwmWrite(SOLENOID_GPIO, duty_cycle);
  printf("Applying PWM duty cycle: %d\n", duty_cycle);
}

int main() {
  // Set up signal handling for Ctrl+C
  signal(SIGINT, signal_handler);

  // Initialize wiringPi with GPIO numbering
  if (wiringPiSetupGpio() == -1) {
    fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
    return 1;
  }

  // Initialize I2C communication
  i2c_fd = wiringPiI2CSetup(I2C_ADDR);
  if (i2c_fd == -1) {
    fprintf(stderr, "Error initializing I2C: %s\n", strerror(errno));
    return 1;
  }

  // Initialize solenoid valve
  initialize_solenoid();

  // Main control loop
  float desired_pressure = 350.0; // Desired pressure in PSI
  float current_pressure;
  int pwm_duty_cycle;

  while (keep_running) {
    // Read pressure from the sensor
    current_pressure = read_pressure();

    if (current_pressure < 0.0) {
      fprintf(stderr, "Error reading pressure, retrying...\n");
      delay(100); // Small delay before retrying
      continue;
    }

    printf("Current pressure: %.2f PSI\n", current_pressure);

    // Calculate PWM duty cycle
    pwm_duty_cycle = calculate_pwm(desired_pressure, current_pressure);

    // Apply PWM signal to the solenoid valve
    apply_pwm(pwm_duty_cycle);

    delay(100); // Control loop delay
  }

  // Clean up before exiting
  softPwmWrite(SOLENOID_GPIO, 0); // Disable PWM
  close(i2c_fd);              // Close I2C connection

  return 0;
}

