#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <string.h>
#include <time.h>
#include <signal.h>

// Motor A definitions
#define MOTOR_A_PWM 17
#define MOTOR_A_DIR 18

// Motor B definitions
#define MOTOR_B_PWM 22
#define MOTOR_B_DIR 23

// CSV filename
#define CSV_FILENAME "solar_angles.csv"

// Proportional gain for motor control
#define KP_AZIMUTH 1.0
#define KP_ELEVATION 1.0

// Maximum motor speed
#define MAX_SPEED 255

// Global variables
float *azimuth_angles = NULL;
float *elevation_angles = NULL;
int num_entries = 0;
int terminate = 0;

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    fprintf(stderr, "\nCaught signal %d, terminating gracefully.\n", signal);
    terminate = 1;

    // Stop both motors
    gpioWrite(MOTOR_A_DIR, 0);
    gpioPWM(MOTOR_A_PWM, 0);
    gpioWrite(MOTOR_B_DIR, 0);
    gpioPWM(MOTOR_B_PWM, 0);

    // Free allocated memory
    if (azimuth_angles != NULL) free(azimuth_angles);
    if (elevation_angles != NULL) free(elevation_angles);

    gpioTerminate();
    exit(0);
}

// Function to read solar angles from CSV file
int read_solar_angles(const char *filename, float *azimuth, float *elevation, int *num_entries) {
    FILE *fp = fopen(filename, "r");
    if (fp == NULL) {
        fprintf(stderr, "Error: Could not open file %s\n", filename);
        return -1;
    }

    char line[256];
    int count = 0;
    // First count the number of lines in the file
    while (fgets(line, sizeof(line), fp)) {
        count++;
    }
    rewind(fp);

    // Allocate memory for the arrays
    azimuth = (float *)malloc(count * sizeof(float));
    elevation = (float *)malloc(count * sizeof(float));

    if (azimuth == NULL || elevation == NULL) {
        fprintf(stderr, "Error: Memory allocation failed\n");
        fclose(fp);
        return -1;
    }

    char *token;
    int i = 0;
    // Skip the header line
    fgets(line, sizeof(line), fp);
    while (fgets(line, sizeof(line), fp)) {
        token = strtok(line, ",");
        if (token != NULL) {
            azimuth[i] = atof(token);
        }
        token = strtok(NULL, ",");
        if (token != NULL) {
            elevation[i] = atof(token);
        }
        i++;
    }

    fclose(fp);
    *num_entries = i;

    azimuth_angles = azimuth;
    elevation_angles = elevation;
    return 0;
}

// Function to set motor speed and direction
int set_motor_speed(int gpio_pwm, int gpio_dir, int speed) {
    if (speed > MAX_SPEED) speed = MAX_SPEED;
    if (speed < -MAX_SPEED) speed = -MAX_SPEED;

    if (speed == 0) {
        gpioWrite(gpio_dir, 0);
        gpioPWM(gpio_pwm, 0);
    } else if (speed > 0) {
        gpioWrite(gpio_dir, 1);
        gpioPWM(gpio_pwm, speed);
    } else {
        gpioWrite(gpio_dir, 0);
        gpioPWM(gpio_pwm, -speed);
    }
    return 0;
}

// Function to calculate motor speeds based on target and current angles
int calculate_motor_speeds(float current_azimuth, float current_elevation, float target_azimuth, float target_elevation, int *motor_a_speed, int *motor_b_speed) {
    float azimuth_error = target_azimuth - current_azimuth;
    float elevation_error = target_elevation - current_elevation;

    *motor_a_speed = (int)(KP_AZIMUTH * azimuth_error);
    *motor_b_speed = (int)(KP_ELEVATION * elevation_error);

    // Limit motor speeds
    if (*motor_a_speed > MAX_SPEED) *motor_a_speed = MAX_SPEED;
    if (*motor_a_speed < -MAX_SPEED) *motor_a_speed = -MAX_SPEED;
    if (*motor_b_speed > MAX_SPEED) *motor_b_speed = MAX_SPEED;
    if (*motor_b_speed < -MAX_SPEED) *motor_b_speed = -MAX_SPEED;

    return 0;
}

// Function to get target angles based on current time
int get_target_angles(float *azimuth, float *elevation, int num_entries) {
    time_t current_time = time(NULL);
    struct tm *time_info = localtime(&current_time);
    int current_minute = time_info->tm_hour * 60 + time_info->tm_min;

    // Assuming the CSV data is for the entire day (24 hours = 1440 minutes)
    // and the time intervals between rows are uniform.
    float interval = 1440.0 / num_entries;
    float index = current_minute / interval;

    int lower_index = (int)index;
    int upper_index = lower_index + 1;

    if (lower_index < 0) lower_index = 0;
    if (upper_index >= num_entries) upper_index = num_entries - 1;

    // Interpolate between the two closest data points
    float fraction = index - lower_index;

    *azimuth = azimuth_angles[lower_index] + fraction * (azimuth_angles[upper_index] - azimuth_angles[lower_index]);
    *elevation = elevation_angles[lower_index] + fraction * (elevation_angles[upper_index] - elevation_angles[lower_index]);

    return 0;
}

// Dummy function to simulate reading current azimuth and elevation from sensors
int get_current_azimuth_elevation(float *current_azimuth, float *current_elevation) {
    // Replace with actual sensor reading logic
    *current_azimuth = 0.0; // Example value
    *current_elevation = 0.0; // Example value
    return 0;
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(MOTOR_A_PWM, PI_OUTPUT);
    gpioSetMode(MOTOR_A_DIR, PI_OUTPUT);
    gpioSetMode(MOTOR_B_PWM, PI_OUTPUT);
    gpioSetMode(MOTOR_B_DIR, PI_OUTPUT);

    // Read solar angles from CSV file
    float *azimuth = NULL;
    float *elevation = NULL;
    if (read_solar_angles(CSV_FILENAME, azimuth, elevation, &num_entries) != 0) {
        gpioTerminate();
        return 1;
    }

    // Set up signal handling
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Main loop
    float current_azimuth, current_elevation, target_azimuth, target_elevation;
    int motor_a_speed, motor_b_speed;

    while (!terminate) {
        // Get target angles
        if (get_target_angles(&target_azimuth, &target_elevation, num_entries) != 0) {
            fprintf(stderr, "Error: Failed to get target angles\n");
        }

        // Read current angles
        if (get_current_azimuth_elevation(&current_azimuth, &current_elevation) != 0) {
            fprintf(stderr, "Error: Failed to read current angles\n");
        }

        // Calculate motor speeds
        if (calculate_motor_speeds(current_azimuth, current_elevation, target_azimuth, target_elevation, &motor_a_speed, &motor_b_speed) != 0) {
            fprintf(stderr, "Error: Failed to calculate motor speeds\n");
        }

        // Set motor speeds
        if (set_motor_speed(MOTOR_A_PWM, MOTOR_A_DIR, motor_a_speed) != 0) {
            fprintf(stderr, "Error: Failed to set motor A speed\n");
        }
        if (set_motor_speed(MOTOR_B_PWM, MOTOR_B_DIR, motor_b_speed) != 0) {
            fprintf(stderr, "Error: Failed to set motor B speed\n");
        }

        // Delay
        gpioDelay(1000); // 1 second
    }

    // Stop both motors
    gpioWrite(MOTOR_A_DIR, 0);
    gpioPWM(MOTOR_A_PWM, 0);
    gpioWrite(MOTOR_B_DIR, 0);
    gpioPWM(MOTOR_B_PWM, 0);

    // Free allocated memory
    if (azimuth_angles != NULL) free(azimuth_angles);
    if (elevation_angles != NULL) free(elevation_angles);

    // Terminate pigpio
    gpioTerminate();

    return 0;
}

#include <stdio.h>
