#include <string.h>
#include <wiringPi.h>
#include <wiringPiSPI.h>
#include <unistd.h>
#include <time.h>

#define MCP3008_CHANNEL_COUNT 8

int read_mcp3008(int spi_channel, int channel)
{
    unsigned char buffer[3];
    buffer[0] = 0x01; // Start bit
    buffer[1] = (0x08 | channel) << 4;
    buffer[2] = 0x00;

    wiringPiSPIDataRW(spi_channel, buffer, 3);

    int adc_value = ((buffer[1] & 0x03) << 8) + buffer[2];
    return adc_value;
}

int main(int argc, char *argv[])
{
    if (argc != 3) {
        fprintf(stderr, "Usage: %s <spi_channel> <output_file>\n", argv[0]);
        return 1;
    }

    int spi_channel = atoi(argv[1]);
    char *output_file_path = argv[2];

    if (spi_channel != 0 && spi_channel != 1) {
        fprintf(stderr, "Error: SPI channel must be 0 or 1\n");
        return 1;
    }

    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error: Failed to initialize wiringPi\n");
        return 1;
    }

    int spi_speed = 1000000; // 1 MHz
    if (wiringPiSPISetup(spi_channel, spi_speed) == -1) {
        fprintf(stderr, "Error: Failed to initialize SPI channel %d\n", spi_channel);
        return 1;
    }

    FILE *output_file = fopen(output_file_path, "w");
    if (output_file == NULL) {
        perror("Error opening output file");
        return 1;
    }

    printf("Logging MCP3008 data to %s (SPI channel %d). Press Ctrl+C to exit.\n", output_file_path, spi_channel);

    while (1) {
        for (int i = 0; i < MCP3008_CHANNEL_COUNT; i++) {
            int adc_value = read_mcp3008(spi_channel, i);
            fprintf(output_file, "%d ", adc_value);
        }
        fprintf(output_file, "\n");
        fflush(output_file); // Ensure data is written to file
        usleep(100000); // 100 ms delay (approximately 10 samples per second)
    }

    fclose(output_file);
    return 0;
}

#include <stdio.h>
