// Define GPIO pins
#define RELAY_GPIO 17
#define TOUCH_SENSOR_GPIO 4

// Debounce time in milliseconds
#define DEBOUNCE_TIME 10

// Global variable for relay state (0 = OFF, 1 = ON)
volatile int relayState = 0;

// Signal handler for graceful shutdown
void signalHandler(int signal)
{
    fprintf(stderr, "\nCaught signal %d, cleaning up...\n", signal);
    // Turn off the relay
    gpioWrite(RELAY_GPIO, 0);
    // Terminate pigpio
    gpioTerminate();
    exit(0);
}

// Function to initialize GPIO
int initializeGPIO()
{
    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }

    // Set GPIO 17 as output for relay control
    if (gpioSetMode(RELAY_GPIO, PI_OUTPUT) != 0)
    {
        fprintf(stderr, "Failed to set GPIO %d as output\n", RELAY_GPIO);
        gpioTerminate();
        return -1;
    }

    // Set GPIO 4 as input for touch sensor
    if (gpioSetMode(TOUCH_SENSOR_GPIO, PI_INPUT) != 0)
    {
        fprintf(stderr, "Failed to set GPIO %d as input\n", TOUCH_SENSOR_GPIO);
        gpioTerminate();
        return -1;
    }

    return 0;
}

// Function to detect touch with debouncing
int isTouched(int gpio)
{
    int i;
    int reading;
    int consistentReadings = 0;

    // Read the sensor multiple times for debouncing
    for (i = 0; i < 5; i++)
    {
        reading = gpioRead(gpio);
        if (reading == 0) // Touch sensor output is LOW when touched
        {
            consistentReadings++;
        }
        gpioDelay(DEBOUNCE_TIME * 1000); // Delay for debounce
    }

    // Consider it a touch if all readings are consistent
    if (consistentReadings == 5)
    {
        return 1;
    }
    else
    {
        return 0;
    }
}

// Function to toggle the relay state
void toggleRelay(int gpio, int *relayState)
{
    *relayState = !(*relayState);
    gpioWrite(gpio, *relayState);
    printf("Relay toggled to state: %d\n", *relayState);
}

int main()
{
    // Install signal handlers for graceful shutdown
    signal(SIGINT, signalHandler);
    signal(SIGTERM, signalHandler);

    // Initialize GPIO
    if (initializeGPIO() != 0)
    {
        return 1;
    }

    printf("Touch-activated lamp started. Press Ctrl+C to exit.\n");

    // Main loop
    while (1)
    {
        // Check for touch
        if (isTouched(TOUCH_SENSOR_GPIO))
        {
            // Toggle the relay
            toggleRelay(RELAY_GPIO, &relayState);

            // Wait for a short period to avoid multiple toggles from a single touch
            gpioDelay(50000); // 50ms
        }

        gpioDelay(50000); // 50ms delay to prevent excessive CPU usage
    }

    return 0; // This will never be reached, but it's good practice to include it
}

