#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <errno.h>

// Define GPIO pins using BCM numbering
#define SOUND_SENSOR_PIN 18 // GPIO18 (Physical pin 12)
#define LED_PIN 22          // GPIO22 (Physical pin 15)

// Define debounce delay (milliseconds)
#define DEBOUNCE_DELAY_MS 200

// Function prototypes
int initialize_gpio(void);
void sound_detection_loop(void);

int main(void) {
    // Print program instructions
    printf("Sound Detection Program\n");
    printf("Clap your hands near the sound sensor to trigger the LED.\n");
    printf("Press Ctrl+C to exit.\n");

    // Initialize WiringPi and GPIO pins
    if (initialize_gpio() != 0) {
        fprintf(stderr, "GPIO initialization failed. Exiting.\n");
        return EXIT_FAILURE;
    }

    // Main sound detection loop
    sound_detection_loop();

    return EXIT_SUCCESS;
}


// Function to initialize WiringPi and GPIO pins
int initialize_gpio(void) {
    // Initialize WiringPi using BCM pin numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return -1; // Indicate failure
    }

    // Set sound sensor pin as input with pull-up resistor
    pinMode(SOUND_SENSOR_PIN, INPUT);
    pullUpDnControl(SOUND_SENSOR_PIN, PUD_UP);

    // Set LED pin as output
    pinMode(LED_PIN, OUTPUT);
    digitalWrite(LED_PIN, HIGH); // Initialize LED to OFF

    return 0; // Indicate success
}


// Function containing the main sound detection loop
void sound_detection_loop(void) {
    int last_state = HIGH; // Assume no sound initially
    int current_state;
    unsigned long last_debounce_time = 0;

    while (1) {
        current_state = digitalRead(SOUND_SENSOR_PIN);

        // Debounce the sensor input
        if (current_state != last_state) {
            last_debounce_time = millis();
        }

        if ((millis() - last_debounce_time) > DEBOUNCE_DELAY_MS) {
            // If the sensor state has changed after debouncing
            if (current_state != last_state) {
                // If sound is detected (LOW signal)
                if (current_state == LOW) {
                    printf("Sound detected!\n");
                    digitalWrite(LED_PIN, LOW); // Turn LED ON
                    delay(500);                  // Keep LED ON for 500ms
                    digitalWrite(LED_PIN, HIGH); // Turn LED OFF
                }
                last_state = current_state;
            }
        }
    }
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
