#include <wiringPi.h>
#include <jansson.h>

#define ACCESS_LOG_FILE "access.log"
#define CONFIG_FILE "access_schedule.json"

// Structure to hold door configuration
typedef struct {
    int gpio_pin;
    json_t *schedule;
} DoorConfig;

// Function to parse the JSON configuration file
int parse_json_config(const char *filename, DoorConfig *door1, DoorConfig *door2) {
    json_t *root, *door1_obj, *door2_obj;
    json_error_t error;

    root = json_load_file(filename, 0, &error);
    if (!root) {
        fprintf(stderr, "Error: Could not load JSON from file: %s, line: %d, text: %s\n", filename, error.line, error.text);
        return 1;
    }

    door1_obj = json_object_get(root, "Door1");
    door2_obj = json_object_get(root, "Door2");

    if (!door1_obj || !door2_obj) {
        fprintf(stderr, "Error: Could not find Door1 or Door2 objects in JSON\n");
        json_decref(root);
        return 1;
    }

    // Parse Door1 configuration
    json_t *gpio1_json = json_object_get(door1_obj, "GPIO");
    if (!gpio1_json || !json_is_integer(gpio1_json)) {
        fprintf(stderr, "Error: Invalid GPIO for Door1\n");
        json_decref(root);
        return 1;
    }
    door1->gpio_pin = json_integer_value(gpio1_json);
    door1->schedule = json_object_get(door1_obj, "schedule");
    if (!door1->schedule || !json_is_object(door1->schedule)) {
        fprintf(stderr, "Error: Invalid schedule for Door1\n");
        json_decref(root);
        return 1;
    }

    // Parse Door2 configuration
    json_t *gpio2_json = json_object_get(door2_obj, "GPIO");
    if (!gpio2_json || !json_is_integer(gpio2_json)) {
        fprintf(stderr, "Error: Invalid GPIO for Door2\n");
        json_decref(root);
        return 1;
    }
    door2->gpio_pin = json_integer_value(gpio2_json);
    door2->schedule = json_object_get(door2_obj, "schedule");
    if (!door2->schedule || !json_is_object(door2->schedule)) {
        fprintf(stderr, "Error: Invalid schedule for Door2\n");
        json_decref(root);
        return 1;
    }

    json_decref(root);
    return 0;
}

// Function to convert HH:MM time string to minutes since midnight
int time_to_minutes(const char *time_str) {
    int hours, minutes;
    if (sscanf(time_str, "%d:%d", &hours, &minutes) != 2) {
        fprintf(stderr, "Error: Invalid time format\n");
        return -1;
    }
    return hours * 60 + minutes;
}

// Function to check if a given time falls within a scheduled time range
int is_time_in_range(const char *day_of_week, json_t *schedule, int current_minutes) {
    json_t *day_schedule, *time_range, *start_time_json, *end_time_json;
    const char *start_time_str, *end_time_str;
    int start_minutes, end_minutes, i;

    day_schedule = json_object_get(schedule, day_of_week);
    if (!day_schedule || !json_is_array(day_schedule)) {
        return 0; // No schedule for this day
    }

    for (i = 0; i < json_array_size(day_schedule); i++) {
        time_range = json_array_get(day_schedule, i);
        if (!time_range || !json_is_object(time_range)) {
            continue; // Skip invalid time ranges
        }

        start_time_json = json_object_get(time_range, "start");
        end_time_json = json_object_get(time_range, "end");

        if (!start_time_json || !end_time_json || !json_is_string(start_time_json) || !json_is_string(end_time_json)) {
            continue; // Skip invalid time ranges
        }

        start_time_str = json_string_value(start_time_json);
        end_time_str = json_string_value(end_time_json);

        start_minutes = time_to_minutes(start_time_str);
        end_minutes = time_to_minutes(end_time_str);

        if (start_minutes == -1 || end_minutes == -1) {
            continue; // Skip invalid time ranges
        }

        if (current_minutes >= start_minutes && current_minutes <= end_minutes) {
            return 1; // Time is within range
        }
    }

    return 0; // Time is not within any range
}

// Function to control the door lock (activate/deactivate GPIO)
void control_door_lock(int gpio_pin, int activate) {
    digitalWrite(gpio_pin, activate ? HIGH : LOW);
}

// Function to log an access event
void log_access(int door_number) {
    FILE *fp = fopen(ACCESS_LOG_FILE, "a");
    if (!fp) {
        fprintf(stderr, "Error: Could not open log file for writing\n");
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(fp, "Door %d accessed at: %d-%02d-%02d %02d:%02d:%02d\n", door_number, tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec);
    fclose(fp);
}

int main() {
    DoorConfig door1, door2;
    time_t current_time;
    struct tm *time_info;
    int current_minutes;
    char day_of_week[10];

    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error: Could not initialize wiringPi\n");
        return 1;
    }

    // Parse JSON configuration
    if (parse_json_config(CONFIG_FILE, &door1, &door2) != 0) {
        return 1;
    }

    // Set GPIO pins as output
    pinMode(door1.gpio_pin, OUTPUT);
    pinMode(door2.gpio_pin, OUTPUT);

    printf("Access control system started\n");

    // Main loop
    while (1) {
        // Get current time
        current_time = time(NULL);
        time_info = localtime(&current_time);
        current_minutes = time_info->tm_hour * 60 + time_info->tm_min;

        // Get day of the week
        strftime(day_of_week, sizeof(day_of_week), "%A", time_info);

        // Check door 1 schedule
        if (is_time_in_range(day_of_week, door1.schedule, current_minutes)) {
            control_door_lock(door1.gpio_pin, 1); // Activate door 1
        } else {
            control_door_lock(door1.gpio_pin, 0); // Deactivate door 1
        }

        // Check door 2 schedule
        if (is_time_in_range(day_of_week, door2.schedule, current_minutes)) {
            control_door_lock(door2.gpio_pin, 1); // Activate door 2
        } else {
            control_door_lock(door2.gpio_pin, 0); // Deactivate door 2
        }

        delay(1000); // Check every 1 second
    }

    return 0;
}

