#define SSD1306_I2C_ADDR  0x3C
int i2c_fd;
void ssd1306_sendCommand(unsigned char command) {
    unsigned char buffer[2] = {0x00, command};
    write(i2c_fd, buffer, 2);
}
void ssd1306_init() {
    ssd1306_sendCommand(0xAE);
    ssd1306_sendCommand(0xC0); // Flip COM output scan direction
    ssd1306_sendCommand(0xA0); // Flip segment re-map
    ssd1306_sendCommand(0xAF);
}
int main() {
    if ((i2c_fd = open("/dev/i2c-1", O_RDWR)) < 0) {
        perror("Failed to open I2C bus");
        return EXIT_FAILURE;
    }
    if (ioctl(i2c_fd, I2C_SLAVE, SSD1306_I2C_ADDR) < 0) {
        perror("Failed to communicate with SSD1306");
        return EXIT_FAILURE;
    }
    ssd1306_init();
    sleep(5);
    close(i2c_fd);
    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Define GPIO pins
#define BUZZER_PIN 18
#define SOUND_SENSOR_PIN 23

// Define constants
#define SOUND_THRESHOLD 1 // HIGH indicates sound detected
#define BUZZER_DURATION 1000000 // 1 second in microseconds
#define LOG_BUFFER_SIZE 10
#define TIMESTAMP_FORMAT "%Y-%m-%d %H:%M:%S"

// Global variables
volatile sig_atomic_t program_running = 1;

// Structure to hold log entry
typedef struct {
    char timestamp[20]; // YYYY-MM-DD HH:MM:SS\0
} LogEntry;

// Circular buffer for logging alarm events
LogEntry log_buffer[LOG_BUFFER_SIZE];
int log_index = 0;

// Function prototypes
void signal_handler(int signal);
void add_log_entry();
void print_log();

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    program_running = 0;
    gpioWrite(BUZZER_PIN, 0); // Turn off buzzer
    gpioTerminate(); // Terminate pigpio
    printf("\nProgram terminated gracefully.\n");
    exit(0);
}

// Function to add a log entry to the circular buffer
void add_log_entry() {
    time_t rawtime;
    struct tm *timeinfo;

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(log_buffer[log_index].timestamp, sizeof(log_buffer[log_index].timestamp), TIMESTAMP_FORMAT, timeinfo);

    log_index = (log_index + 1) % LOG_BUFFER_SIZE;
}

// Function to print the contents of the log buffer
void print_log() {
    printf("\n--- Alarm Log ---\n");
    for (int i = 0; i < LOG_BUFFER_SIZE; i++) {
        int index = (log_index + i) % LOG_BUFFER_SIZE; // Correct order
        if (log_buffer[index].timestamp[0] != '\0') {
            printf("[%d] %s\n", i + 1, log_buffer[index].timestamp);
        }
    }
    printf("--- End of Log ---\n\n");
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        perror("pigpio initialisation failed");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);
    gpioSetMode(SOUND_SENSOR_PIN, PI_INPUT);

    // Set pull-up/down resistor for sound sensor (optional, depends on sensor module)
    gpioSetPullUpDown(SOUND_SENSOR_PIN, PI_PUD_DOWN); // Or PI_PUD_UP, depending on your sensor

    // Initialize log buffer (optional, clear existing garbage data)
    for (int i = 0; i < LOG_BUFFER_SIZE; i++) {
        log_buffer[i].timestamp[0] = '\0';
    }

    // Set signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    printf("Sound sensor alarm running. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        // Read sound sensor value
        int sound_detected = gpioRead(SOUND_SENSOR_PIN);

        // Check if sound exceeds threshold
        if (sound_detected == SOUND_THRESHOLD) {
            printf("Sound detected! Triggering alarm.\n");

            // Activate buzzer
            gpioWrite(BUZZER_PIN, 1);

            // Add log entry
            add_log_entry();

            // Delay
            gpioDelay(BUZZER_DURATION);

            // Deactivate buzzer
            gpioWrite(BUZZER_PIN, 0);

            printf("Alarm silenced.\n");
            print_log(); // Display log after each alarm
        }

        // Small delay to prevent busy-waiting
        gpioDelay(100000); // 100ms
    }

    // Cleanup (should not be reached if signal handler works correctly)
    gpioWrite(BUZZER_PIN, 0);
    gpioTerminate();

    return 0;
}

