#define MIN_PULSE_WIDTH 1000  /* Minimum pulse width in microseconds */
#define MAX_PULSE_WIDTH 2000  /* Maximum pulse width in microseconds */
#define PULSE_RANGE (MAX_PULSE_WIDTH - MIN_PULSE_WIDTH)

#define SERVO_CENTER (MIN_PULSE_WIDTH + PULSE_RANGE/2)

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(SERVO_PIN, PI_OUTPUT);
    gpioSetMode(CW_BUTTON_PIN, PI_INPUT);
    gpioSetMode(CCW_BUTTON_PIN, PI_INPUT);
    gpioSetPullUpDown(CW_BUTTON_PIN, PI_PUD_UP); // Enable pull-up resistor
    gpioSetPullUpDown(CCW_BUTTON_PIN, PI_PUD_UP); // Enable pull-up resistor

    int current_pulse_width = SERVO_CENTER;
    gpioServo(SERVO_PIN, current_pulse_width);

    while (1) {
        if (gpioRead(CW_BUTTON_PIN) == 0) { // Button pressed (LOW)
            current_pulse_width += 10; // Increment pulse width for clockwise
            if (current_pulse_width > MAX_PULSE_WIDTH) {
                current_pulse_width = MAX_PULSE_WIDTH;
            }
            gpioServo(SERVO_PIN, current_pulse_width);
            usleep(100000); // Debounce and slow down movement (0.1 seconds)
        } else if (gpioRead(CCW_BUTTON_PIN) == 0) { // Button pressed (LOW)
            current_pulse_width -= 10; // Decrement pulse width for counter-clockwise
            if (current_pulse_width < MIN_PULSE_WIDTH) {
                current_pulse_width = MIN_PULSE_WIDTH;
            }
            gpioServo(SERVO_PIN, current_pulse_width);
            usleep(100000); // Debounce and slow down movement (0.1 seconds)
        }
        usleep(10000); // Short delay to prevent CPU hogging
    }

    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <stdint.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>
#include <wiringPiSPI.h>

// Constants
#define BH1750_ADDR 0x23
#define BH1750_CONTINUOUS_HIGH_RES_MODE 0x10
#define APA102_SPI_CHANNEL 0
#define NUM_LEDS 10 // Example number of LEDs

// Function Prototypes
int initBH1750();
int initAPA102();
float readBH1750();
void setAPA102Brightness(uint8_t brightness);
uint8_t mapLightToBrightness(float lux);
void handleError(const char *message);

// Global variables (try to minimize)
int bh1750_fd;
int apa102_fd;

int main() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed\n");
        return 1;
    }

    // Initialize BH1750
    if (initBH1750() == -1) {
        fprintf(stderr, "BH1750 initialization failed\n");
        return 1;
    }

    // Initialize APA102
    if (initAPA102() == -1) {
        fprintf(stderr, "APA102 initialization failed\n");
        return 1;
    }

    while (1) {
        // Read light intensity
        float lux = readBH1750();
        if (lux < 0) {
            fprintf(stderr, "Failed to read light intensity\n");
            continue; // Skip to the next iteration
        }

        // Map light intensity to brightness
        uint8_t brightness = mapLightToBrightness(lux);

        // Set APA102 brightness
        setAPA102Brightness(brightness);

        // Wait for a second
        sleep(1);
    }

    return 0;
}

// Initialize BH1750 I2C
int initBH1750() {
    bh1750_fd = wiringPiI2CSetup(BH1750_ADDR);
    if (bh1750_fd == -1) {
        perror("wiringPiI2CSetup failed");
        return -1;
    }
    return 0;
}

// Initialize APA102 SPI
int initAPA102() {
    apa102_fd = wiringPiSPISetup(APA102_SPI_CHANNEL, 1000000); // 1 MHz
    if (apa102_fd == -1) {
        perror("wiringPiSPISetup failed");
        return -1;
    }
    return 0;
}

// Read light intensity from BH1750
float readBH1750() {
    int result;

    // Send measurement command
    result = wiringPiI2CWrite(bh1750_fd, BH1750_CONTINUOUS_HIGH_RES_MODE);
    if (result == -1) {
        perror("wiringPiI2CWrite failed");
        return -1.0;
    }

    // Wait for measurement to complete (at least 180ms)
    delay(200);

    // Read 16-bit light intensity value
    int rawValue = wiringPiI2CReadReg16(bh1750_fd, 0x00);
    if (rawValue == -1) {
        perror("wiringPiI2CReadReg16 failed");
        return -1.0;
    }

    // Convert raw value to Lux
    float lux = (float)rawValue / 1.2;
    return lux;
}

// Set APA102 LED strip brightness
void setAPA102Brightness(uint8_t brightness) {
    unsigned char data[NUM_LEDS * 4 + 8]; // Start frame (4 bytes), LED data (NUM_LEDS * 4 bytes), end frame (4 bytes)
    int i, j;

    // Start frame (0x00000000)
    for (i = 0; i < 4; i++) {
        data[i] = 0x00;
    }

    // LED data (Global brightness, Blue, Green, Red)
    for (i = 0; i < NUM_LEDS; i++) {
        data[4 + i * 4] = 0xE0 | brightness; // Global brightness (MSB is always 111)
        data[4 + i * 4 + 1] = 0x00;        // Blue
        data[4 + i * 4 + 2] = 0xFF;        // Green
        data[4 + i * 4 + 3] = 0x00;        // Red
    }

    // End frame (0xFFFFFFFF)
    for (i = 0; i < 4; i++) {
        data[4 + NUM_LEDS * 4 + i] = 0xFF;
    }

    // Transmit data via SPI
    wiringPiSPIDataRW(APA102_SPI_CHANNEL, data, sizeof(data));
}

// Map light intensity to LED brightness
uint8_t mapLightToBrightness(float lux) {
    if (lux < 100) {
        return 31; // Max brightness
    } else if (lux < 500) {
        return (uint8_t)(31 - (lux - 100) * 31 / 400); // Scale brightness down
    } else {
        return 0; // Off
    }
}

// Error handling function
void handleError(const char *message) {
    fprintf(stderr, "Error: %s\n", message);
    exit(1);
}

#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>

#define BUZZER_PIN 18

// Define musical notes (frequencies in Hz)
#define NOTE_C4 261.63
#define NOTE_D4 293.66
#define NOTE_E4 329.63
#define NOTE_F4 349.23
#define NOTE_G4 392.00
#define NOTE_A4 440.00
#define NOTE_B4 493.88
#define NOTE_C5 523.25

// Function to play a note
void playNote(float frequency, float duration)
{
    int period = 1000000 / frequency; // Period in microseconds
    int halfPeriod = period / 2;
    int numCycles = (int)(duration * frequency); // Number of cycles to play

    for (int i = 0; i < numCycles; i++)
    {
        gpioWrite(BUZZER_PIN, 1);
        gpioDelay(halfPeriod);
        gpioWrite(BUZZER_PIN, 0);
        gpioDelay(halfPeriod);
    }
}

int main()
{
    if (gpioInitialise() < 0)
    {
        printf("pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(BUZZER_PIN, PI_OUTPUT);

    // Array of notes to play
    float notes[] = {NOTE_C4, NOTE_D4, NOTE_E4, NOTE_F4, NOTE_G4, NOTE_A4, NOTE_B4, NOTE_C5};
    int numNotes = sizeof(notes) / sizeof(notes[0]);

    // Play the scale
    for (int i = 0; i < numNotes; i++)
    {
        playNote(notes[i], 0.2); // Play each note for 0.2 seconds
        gpioDelay(10);           // Small delay between notes
    }

    gpioTerminate();
    return 0;
}

