#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Constants
#define SOUND_SENSOR_GPIO 23
#define BUZZER_GPIO 18
#define SOUND_THRESHOLD 1 // Digital High (1) indicates sound detected
#define LOG_FILE "alarm_log.txt"

// Global Variables
static volatile int keepRunning = 1;

// Function Prototypes
int initialize_pigpio();
int read_sound_sensor();
void trigger_buzzer(int duration_ms); // Buzzer on for a specified duration
void log_alarm_event(int sensor_value);
void signal_handler(int signal);

// Function to initialize pigpio
int initialize_pigpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Indicate failure
    }
    gpioSetMode(SOUND_SENSOR_GPIO, PI_INPUT);
    gpioSetMode(BUZZER_GPIO, PI_OUTPUT);
    gpioWrite(BUZZER_GPIO, 0); // Ensure buzzer is off initially
    return 0; // Indicate success
}

// Function to read the sound sensor
int read_sound_sensor() {
    return gpioRead(SOUND_SENSOR_GPIO);
}

// Function to trigger the buzzer
void trigger_buzzer(int duration_ms) {
    gpioWrite(BUZZER_GPIO, 1); // Turn buzzer on
    gpioDelay(duration_ms * 1000); // Delay for specified milliseconds
    gpioWrite(BUZZER_GPIO, 0); // Turn buzzer off
}

// Function to log alarm events
void log_alarm_event(int sensor_value) {
    FILE *fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    fprintf(fp, "%s, Sensor Value: %d\n", timestamp, sensor_value);
    fclose(fp);
}

// Signal handler for clean exit
void signal_handler(int signal) {
    fprintf(stdout, "Received signal %d, cleaning up...\n", signal);
    keepRunning = 0;
}

int main() {
    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize pigpio
    if (initialize_pigpio() != 0) {
        return 1; // Exit if initialization fails
    }

    printf("Sound monitoring system started. Press Ctrl+C to exit.\n");

    while (keepRunning) {
        int sensor_value = read_sound_sensor();

        if (sensor_value == SOUND_THRESHOLD) {
            printf("Sound detected!\n");
            log_alarm_event(sensor_value);
            trigger_buzzer(500); // Trigger buzzer for 500ms
        }

        gpioDelay(100); // Check every 100ms
    }

    // Cleanup before exiting
    gpioWrite(BUZZER_GPIO, 0); // Ensure buzzer is off
    gpioTerminate();
    printf("Exiting cleanly.\n");
    return 0;
}

