#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <signal.h>
#include <string.h>
#include <pigpio.h>

// Define GPIO pins for relays
#define RELAY1_PIN 17
#define RELAY2_PIN 18
#define RELAY3_PIN 27
#define RELAY4_PIN 22

// Define I2C address for BH1750 sensor
#define BH1750_ADDR 0x23

// Define I2C bus handle
int i2c_handle;

// Define log file name
#define LOG_FILE "lighting_log.txt"
FILE *log_file;

// Function prototypes
void relay_on(int pin);
void relay_off(int pin);
int bh1750_read_light_level();
void adjust_brightness(int light_level);
void log_data(int light_level, int relay1_state, int relay2_state, int relay3_state, int relay4_state);
void signal_handler(int signal);
int init_i2c();
void close_i2c();

// Global flag to indicate program termination
volatile sig_atomic_t program_running = 1;

// Function to turn a relay ON
void relay_on(int pin) {
    gpioWrite(pin, 1); // HIGH
}

// Function to turn a relay OFF
void relay_off(int pin) {
    gpioWrite(pin, 0); // LOW
}

// Function to initialize I2C
int init_i2c() {
    i2c_handle = i2cOpen(1, BH1750_ADDR, 0); // Bus 1, address 0x23, no flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C: %d\n", i2c_handle);
        log_data(-1, -1, -1, -1, -1); // Log error
        return -1;
    }
    return 0;
}

// Function to close I2C
void close_i2c() {
    i2cClose(i2c_handle);
}

// Function to read light level from BH1750 sensor
int bh1750_read_light_level() {
    // Send start command (0x10 for continuous high resolution mode)
    if (i2cWriteByte(i2c_handle, 0x10) < 0) {
        fprintf(stderr, "Error writing to I2C\n");
        log_data(-1, -1, -1, -1, -1); // Log error
        return -1;
    }

    // Wait for measurement (at least 180ms)
    gpioDelay(200000); // 200 ms

    // Read two bytes of data
    char buf[2];
    if (i2cReadDevice(i2c_handle, buf, 2) != 2) {
        fprintf(stderr, "Error reading from I2C\n");
        log_data(-1, -1, -1, -1, -1); // Log error
        return -1;
    }

    // Combine the bytes and convert to lux
    unsigned int raw_value = (buf[0] << 8) | buf[1];
    float lux = (float)raw_value / 1.2; // Empirical value

    return (int)lux;
}

// Function to adjust brightness based on light level
void adjust_brightness(int light_level) {
    if (light_level < 100) {
        // Turn on all relays
        relay_on(RELAY1_PIN);
        relay_on(RELAY2_PIN);
        relay_on(RELAY3_PIN);
        relay_on(RELAY4_PIN);
    } else if (light_level < 300) {
        // Turn on relays 1 and 2
        relay_on(RELAY1_PIN);
        relay_on(RELAY2_PIN);
        relay_off(RELAY3_PIN);
        relay_off(RELAY4_PIN);
    } else if (light_level < 500) {
        // Turn on relay 1 only
        relay_on(RELAY1_PIN);
        relay_off(RELAY2_PIN);
        relay_off(RELAY3_PIN);
        relay_off(RELAY4_PIN);
    } else {
        // Turn off all relays
        relay_off(RELAY1_PIN);
        relay_off(RELAY2_PIN);
        relay_off(RELAY3_PIN);
        relay_off(RELAY4_PIN);
    }

    // Log the data
    log_data(light_level, gpioRead(RELAY1_PIN), gpioRead(RELAY2_PIN), gpioRead(RELAY3_PIN), gpioRead(RELAY4_PIN));
}

// Function to log data to file
void log_data(int light_level, int relay1_state, int relay2_state, int relay3_state, int relay4_state) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        perror("Error opening log file");
        return;
    }

    fprintf(log_file, "%s | Light Level: %d lux | Relay States: 17=%s, 18=%s, 27=%s, 22=%s\n",
            timestamp,
            light_level,
            (relay1_state == 1) ? "ON" : "OFF",
            (relay2_state == 1) ? "ON" : "OFF",
            (relay3_state == 1) ? "ON" : "OFF",
            (relay4_state == 1) ? "ON" : "OFF");

    fclose(log_file);
}

// Signal handler function
void signal_handler(int signal) {
    printf("Signal received (%d). Shutting down gracefully...\n", signal);
    program_running = 0;
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pins as output
    gpioSetMode(RELAY1_PIN, PI_OUTPUT);
    gpioSetMode(RELAY2_PIN, PI_OUTPUT);
    gpioSetMode(RELAY3_PIN, PI_OUTPUT);
    gpioSetMode(RELAY4_PIN, PI_OUTPUT);

    // Initialize I2C
    if (init_i2c() != 0) {
        gpioTerminate();
        return 1;
    }

    // Set up signal handling
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    printf("Environmental Monitoring Smart Lighting System started.\n");

    while (program_running) {
        // Read light level
        int light_level = bh1750_read_light_level();

        if (light_level >= 0) {
            // Adjust brightness
            adjust_brightness(light_level);
        }

        // Wait for 5 seconds
        gpioDelay(5000000); // 5 seconds
    }

    // Clean up
    close_i2c();
    relay_off(RELAY1_PIN);
    relay_off(RELAY2_PIN);
    relay_off(RELAY3_PIN);
    relay_off(RELAY4_PIN);

    gpioTerminate();

    printf("Environmental Monitoring Smart Lighting System stopped.\n");

    return 0;
}

