#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <pigpio.h>
#include <signal.h>
#include <unistd.h>

// Define relay GPIO pins
#define RELAY1_GPIO 4
#define RELAY2_GPIO 17
#define RELAY3_GPIO 27
#define RELAY4_GPIO 22

// Global variable to track program termination
volatile sig_atomic_t program_running = 1;

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    printf("\nCaught signal %d, cleaning up and exiting...\n", signal);
    program_running = 0;
}

// Function to initialize a GPIO pin as output
int initialize_gpio(int gpio) {
    if (gpioSetMode(gpio, PI_OUTPUT) != 0) {
        fprintf(stderr, "Error setting GPIO %d as output\n", gpio);
        return -1;
    }
    return 0;
}

// Function to set the state of a relay (ON or OFF)
int set_relay_state(int gpio, int state) {
    if (gpioWrite(gpio, state) != 0) {
        fprintf(stderr, "Error writing state %d to GPIO %d\n", state, gpio);
        return -1;
    }
    return 0;
}

// Function to generate a random soil moisture value (0-100)
int generate_random_moisture() {
    return rand() % 101;
}

// Function to simulate watering a plant by activating a relay
int water_plant(int relay_gpio) {
    printf("Watering plant connected to relay on GPIO %d...\n", relay_gpio);
    if (set_relay_state(relay_gpio, 1) != 0) {
        fprintf(stderr, "Error activating relay on GPIO %d\n", relay_gpio);
        return -1;
    }
    gpioDelay(2000); // Water for 2 seconds
    if (set_relay_state(relay_gpio, 0) != 0) {
        fprintf(stderr, "Error deactivating relay on GPIO %d\n", relay_gpio);
        return -1;
    }
    printf("Watering complete for plant on GPIO %d\n", relay_gpio);
    return 0;
}

// Function to cleanup a GPIO pin by setting it as input
int cleanup_gpio(int gpio) {
    if (gpioSetMode(gpio, PI_INPUT) != 0) {
        fprintf(stderr, "Error setting GPIO %d as input during cleanup\n", gpio);
        return -1;
    }
    return 0;
}

int main() {
    // Initialize random number generator
    srand(time(NULL));

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Initialize relay GPIOs
    if (initialize_gpio(RELAY1_GPIO) != 0 ||
        initialize_gpio(RELAY2_GPIO) != 0 ||
        initialize_gpio(RELAY3_GPIO) != 0 ||
        initialize_gpio(RELAY4_GPIO) != 0) {
        fprintf(stderr, "GPIO initialization failed. Cleaning up and exiting.\n");
        gpioTerminate();
        return 1;
    }

    printf("Plant watering system started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        // Generate random soil moisture values
        int moisture1 = generate_random_moisture();
        int moisture2 = generate_random_moisture();
        int moisture3 = generate_random_moisture();
        int moisture4 = generate_random_moisture();

        printf("Moisture levels: Plant 1: %d, Plant 2: %d, Plant 3: %d, Plant 4: %d\n",
               moisture1, moisture2, moisture3, moisture4);

        // Water plants based on moisture levels
        if (moisture1 < 30) {
            if (water_plant(RELAY1_GPIO) != 0) {
                program_running = 0; // Exit loop on error
            }
        }
        if (moisture2 < 40) {
            if (water_plant(RELAY2_GPIO) != 0) {
                program_running = 0; // Exit loop on error
            }
        }
        if (moisture3 < 25) {
            if (water_plant(RELAY3_GPIO) != 0) {
                program_running = 0; // Exit loop on error
            }
        }
        if (moisture4 < 35) {
            if (water_plant(RELAY4_GPIO) != 0) {
                program_running = 0; // Exit loop on error
            }
        }

        gpioDelay(5000); // Wait 5 seconds
    }

    // Cleanup GPIOs
    cleanup_gpio(RELAY1_GPIO);
    cleanup_gpio(RELAY2_GPIO);
    cleanup_gpio(RELAY3_GPIO);
    cleanup_gpio(RELAY4_GPIO);

    // Terminate pigpio library
    gpioTerminate();

    printf("Plant watering system stopped.\n");
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pigpio.h>

// Define GPIO pins for buttons and LEDs
#define BUTTON_1_GPIO 6
#define BUTTON_2_GPIO 26
#define BUTTON_3_GPIO 5

#define LED_1_GPIO 22
#define LED_2_GPIO 23
#define LED_3_GPIO 17

// Array for easy iteration over buttons and LEDs
const int button_gpios[] = {BUTTON_1_GPIO, BUTTON_2_GPIO, BUTTON_3_GPIO};
const int led_gpios[] = {LED_1_GPIO, LED_2_GPIO, LED_3_GPIO};

// Volatile flag to signal program termination
volatile sig_atomic_t program_running = 1;

// Signal handler for Ctrl+C
void sigint_handler(int signal) {
    program_running = 0; // Set flag to terminate main loop
    printf("\nCtrl+C detected. Exiting gracefully...\n");
}

// Function to handle button press and toggle LED
void handle_button_press(int button_index) {
    // Debounce delay (milliseconds)
    const int debounce_delay_ms = 50;
    gpioDelay(debounce_delay_ms * 1000); // Convert ms to microseconds

    // Read button state again to confirm press after debounce
    if (gpioRead(button_gpios[button_index]) == PI_LOW) {
        int led_gpio = led_gpios[button_index];
        int current_led_state = gpioRead(led_gpio);

        // Toggle LED state
        if (current_led_state == PI_LOW) {
            gpioWrite(led_gpio, PI_HIGH); // Turn LED on
            printf("LED %d turned ON\n", button_index + 1);
        } else {
            gpioWrite(led_gpio, PI_LOW);  // Turn LED off
            printf("LED %d turned OFF\n", button_index + 1);
        }

        // Wait a bit to avoid multiple toggles from a single press
        gpioDelay(200 * 1000); // 200ms delay
    }
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "ERROR: pigpio initialisation failed\n");
        return 1;
    }

    // Set signal handler for Ctrl+C
    signal(SIGINT, sigint_handler);

    // Set button pins as input with pull-up resistors
    for (int i = 0; i < 3; ++i) {
        gpioSetMode(button_gpios[i], PI_INPUT);
        gpioSetPullUpDown(button_gpios[i], PI_PUD_UP); // Enable pull-up
    }

    // Set LED pins as output and initialize to OFF
    for (int i = 0; i < 3; ++i) {
        gpioSetMode(led_gpios[i], PI_OUTPUT);
        gpioWrite(led_gpios[i], PI_LOW); // Initially turn off the LEDs
    }

    printf("Program running. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        for (int i = 0; i < 3; ++i) {
            // Check if button is pressed (low signal due to pull-up)
            if (gpioRead(button_gpios[i]) == PI_LOW) {
                handle_button_press(i);
            }
        }
        gpioDelay(10 * 1000); // Reduce CPU usage
    }

    // Cleanup: Turn off LEDs and terminate pigpio
    for (int i = 0; i < 3; ++i) {
        gpioWrite(led_gpios[i], PI_LOW); // Ensure LEDs are off
    }

    gpioTerminate(); // Terminate pigpio
    return 0;
}

#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>

// Define GPIO pins for each segment (A-G)
#define SEG_A 4
#define SEG_B 17
#define SEG_C 27
#define SEG_D 22
#define SEG_E 5
#define SEG_F 6
#define SEG_G 13

// Define segment patterns for digits 0-9 (common cathode)
const int digits[] = {
    0b00111111, // 0 ABCDEF
    0b00000110, // 1 BC
    0b01011011, // 2 ABGED
    0b01001111, // 3 ABCGD
    0b01100110, // 4 BCFG
    0b01101101, // 5 ACDFG
    0b01111101, // 6 ACDEFG
    0b00000111, // 7 ABC
    0b01111111, // 8 ABCDEFG
    0b01101111  // 9 ABCDFG
};

// Function to display a digit on the seven-segment display
void displayDigit(int digit) {
    int pattern = digits[digit];

    gpioWrite(SEG_A, (pattern >> 6) & 1);
    gpioWrite(SEG_B, (pattern >> 5) & 1);
    gpioWrite(SEG_C, (pattern >> 4) & 1);
    gpioWrite(SEG_D, (pattern >> 3) & 1);
    gpioWrite(SEG_E, (pattern >> 2) & 1);
    gpioWrite(SEG_F, (pattern >> 1) & 1);
    gpioWrite(SEG_G, (pattern >> 0) & 1);
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pins as output
    gpioSetMode(SEG_A, PI_OUTPUT);
    gpioSetMode(SEG_B, PI_OUTPUT);
    gpioSetMode(SEG_C, PI_OUTPUT);
    gpioSetMode(SEG_D, PI_OUTPUT);
    gpioSetMode(SEG_E, PI_OUTPUT);
    gpioSetMode(SEG_F, PI_OUTPUT);
    gpioSetMode(SEG_G, PI_OUTPUT);

    // Countdown from 5 to 0
    for (int i = 5; i >= 0; i--) {
        displayDigit(i);
        printf("Displaying: %d\n", i);
        sleep(2); // Delay for 2 seconds
    }

    // Clear display after countdown
    displayDigit(0x00); // Display Blank by outputting nothing

    gpioTerminate();
    return 0;
}

#include <wiringPi.h>
#include <wiringPiSPI.h>
#include <stdio.h>

#define SPI_CHANNEL 0
#define REF_VOLTAGE 3.3

int read_adc(int channel) {
    unsigned char buffer[3];
    buffer[0] = 0x01;
    buffer[1] = (0x80 | (channel << 4));
    buffer[2] = 0x00;
    wiringPiSPIDataRW(SPI_CHANNEL, buffer, 3);
    int result = ((buffer[1] & 0x03) << 8) | buffer[2];
    return result;
}

int main() {
    wiringPiSetup();
    if (wiringPiSPISetup(SPI_CHANNEL, 1000000) < 0) {
        printf("SPI setup failed\n"); return 1;
    }

    int raw = read_adc(0);
    double voltage = (raw / 1023.0) * REF_VOLTAGE;
    printf("Channel 0: %d (%.2f V)\n", raw, voltage);
    return 0;
}

