// BME688 I2C address
#define BME688_I2C_ADDR 0x77

// GPIO pin for the ventilation fan relay
#define FAN_GPIO_PIN 18

// Gas resistance threshold (in ohms) - adjust as needed
#define GAS_RESISTANCE_THRESHOLD 10000.0f

// Log file name
#define LOG_FILE "fan_control.log"

// BME688 Register Addresses (Example, refer to datasheet for complete list)
#define BME688_REG_ID 0xD0
#define BME688_REG_CONFIG 0x75
#define BME688_REG_GAS_R_LSB 0x2B
#define BME688_REG_GAS_R_MSB 0x2A
#define BME688_REG_STATUS 0x73

// Function to initialize the BME688 sensor
int bme688_init(int fd) {
    // Example initialization sequence (refer to BME688 datasheet)
    // This is a minimal example and may need to be adjusted for optimal performance

    // Set sensor mode to forced mode
    if (wiringPiI2CWriteReg8(fd, BME688_REG_CONFIG, 0x01) < 0) {  // Example value
        fprintf(stderr, "%s", "Error writing to BME688_REG_CONFIG during init.\n");
        return -1;
    }

    // Configure gas sensor (example)
    if (wiringPiI2CWriteReg8(fd, 0x72, 0x05) < 0) { // Example value
        fprintf(stderr, "%s", "Error writing to gas sensor config during init.\n");
        return -1;
    }

    return 0;
}

// Function to read gas resistance from the BME688 sensor
int bme688_read_data(int fd, float *gas_resistance) {
    int msb, lsb, status;

    // Read gas resistance MSB
    msb = wiringPiI2CReadReg8(fd, BME688_REG_GAS_R_MSB);
    if (msb < 0) {
        fprintf(stderr, "%s", "Error reading gas resistance MSB.\n");
        return -1;
    }

    // Read gas resistance LSB
    lsb = wiringPiI2CReadReg8(fd, BME688_REG_GAS_R_LSB);
    if (lsb < 0) {
        fprintf(stderr, "%s", "Error reading gas resistance LSB.\n");
        return -1;
    }

    //Read status
    status = wiringPiI2CReadReg8(fd, BME688_REG_STATUS);
    if (status < 0) {
        fprintf(stderr, "%s", "Error reading status register.\n");
        return -1;
    }

    // Combine MSB and LSB to get the raw gas resistance value
    int raw_resistance = (msb << 2) | (lsb >> 6);

    // Apply calibration formula (refer to BME688 datasheet)
    // This is a placeholder; the actual formula depends on the sensor's calibration data
    *gas_resistance = (float)raw_resistance;  // Placeholder: replace with actual calibration

    return 0;
}

// Function to control the ventilation fan
void fan_control(float gas_resistance, int gpio_pin) {
    if (gas_resistance < GAS_RESISTANCE_THRESHOLD) {
        digitalWrite(gpio_pin, HIGH); // Activate fan
        printf("Fan ON (Gas Resistance: %.2f ohms)\n", gas_resistance);
    } else {
        digitalWrite(gpio_pin, LOW);  // Deactivate fan
        printf("Fan OFF (Gas Resistance: %.2f ohms)\n", gas_resistance);
    }
}

// Function to log data to a file
void log_data(float gas_resistance, const char *filename) {
    FILE *fp = fopen(filename, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file %s\n", filename);
        return;
    }

    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char s[64];
    strftime(s, sizeof(s), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(fp, "%s, Gas Resistance: %.2f ohms\n", s, gas_resistance);
    fclose(fp);
}

int main() {
    int fd;
    float gas_resistance;

    // Initialize wiringPi with GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi\n");
        return 1;
    }

    // Set GPIO pin for the fan as output
    pinMode(FAN_GPIO_PIN, OUTPUT);

    while (1) {
        // Initialize I2C connection
        fd = wiringPiI2CSetup(BME688_I2C_ADDR);
        if (fd == -1) {
            fprintf(stderr, "Error initializing I2C communication\n");
            log_data(-1, LOG_FILE);
            delay(1000); // Wait before retrying
            continue;
        }

        // Initialize the BME688 sensor
        if (bme688_init(fd) != 0) {
            fprintf(stderr, "Error initializing BME688 sensor\n");
            log_data(-1, LOG_FILE);
            close(fd);
            delay(1000); // Wait before retrying
            continue;
        }

        // Read gas resistance
        if (bme688_read_data(fd, &gas_resistance) != 0) {
            fprintf(stderr, "%s", "Error reading gas resistance.\n");
            gas_resistance = -1; // Indicate error in log
        }

        // Control the fan
        fan_control(gas_resistance, FAN_GPIO_PIN);

        // Log the data
        log_data(gas_resistance, LOG_FILE);

        // Close the I2C connection
        close(fd);

        // Delay before the next reading
        delay(5000);
    }

    return 0;
}

