#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <wiringPi.h>
#include <softPwm.h>

#define INA1 0  // BCM GPIO 17
#define INA2 2  // BCM GPIO 27
#define ENA  3  // BCM GPIO 22
#define BTN_FORWARD 4 // BCM GPIO 4
#define BTN_REVERSE 5 // BCM GPIO 5

void setup() {
    wiringPiSetup();
    pinMode(INA1, OUTPUT);
    pinMode(INA2, OUTPUT);
    softPwmCreate(ENA, 0, 100);
    pinMode(BTN_FORWARD, INPUT);
    pinMode(BTN_REVERSE, INPUT);
    pullUpDnControl(BTN_FORWARD, PUD_UP);
    pullUpDnControl(BTN_REVERSE, PUD_UP);
}

void forward() {
    digitalWrite(INA1, HIGH);
    digitalWrite(INA2, LOW);
    softPwmWrite(ENA, 80);
}

void reverse() {
    digitalWrite(INA1, LOW);
    digitalWrite(INA2, HIGH);
    softPwmWrite(ENA, 80);
}

void stopMotor() {
    digitalWrite(INA1, LOW);
    digitalWrite(INA2, LOW);
    softPwmWrite(ENA, 0);
}

int main() {
    setup();
    while (1) {
        if (digitalRead(BTN_FORWARD) == 0) {
            forward();
        } else if (digitalRead(BTN_REVERSE) == 0) {
            reverse();
        } else {
            stopMotor();
        }
        delay(100);
    }
    return 0;
}

#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <math.h>

// ADS1115 I2C address (default)
#define ADS1115_ADDR 0x48

// ADS1115 Registers
#define ADS1115_REG_CONFIG 0x01
#define ADS1115_REG_CONVERT 0x00

// ADS1115 Configuration bits
#define ADS1115_CONFIG_OS_SINGLE 0x8000  // Start single conversion
#define ADS1115_CONFIG_MUX_SINGLE_0 0x4000 // AIN0 - GND
#define ADS1115_CONFIG_MUX_SINGLE_1 0x5000 // AIN1 - GND
#define ADS1115_CONFIG_MUX_SINGLE_2 0x6000 // AIN2 - GND
#define ADS1115_CONFIG_MUX_SINGLE_3 0x7000 // AIN3 - GND
#define ADS1115_CONFIG_PGA_4_096V 0x0040  // +/- 4.096V range
#define ADS1115_CONFIG_MODE_SINGLE 0x0100 // Single-shot mode
#define ADS1115_CONFIG_DR_128SPS 0x0080   // 128 SPS
#define ADS1115_CONFIG_COMP_MODE_TRAD 0x0000 // Traditional comparator
#define ADS1115_CONFIG_COMP_POL_LOW 0x0002 // Comparator polarity
#define ADS1115_CONFIG_COMP_LAT_NON 0x0004 // Non-latching comparator
#define ADS1115_CONFIG_COMP_QUE_DISABLE 0x0003 // Disable comparator

// Full-Scale Range (FSR) values
#define ADS1115_FSR_4_096V 4.096

// Function to write a 16-bit value to the I2C device
int write_i2c_word(int fd, uint8_t reg, uint16_t value) {
    uint8_t buf[3];
    buf[0] = reg;
    buf[1] = (value >> 8) & 0xFF; // MSB
    buf[2] = value & 0xFF;      // LSB
    if (write(fd, buf, 3) != 3) {
        perror("Failed to write to I2C device");
        return -1;
    }
    return 0;
}

// Function to read a 16-bit value from the I2C device
int read_i2c_word(int fd, uint8_t reg, uint16_t *value) {
    uint8_t buf[2];
    if (write(fd, &reg, 1) != 1) {
        perror("Failed to write to I2C device");
        return -1;
    }
    if (read(fd, buf, 2) != 2) {
        perror("Failed to read from I2C device");
        return -1;
    }
    *value = (buf[0] << 8) | buf[1];
    return 0;
}

int main() {
    int fd;
    const char *i2c_device = "/dev/i2c-1"; // I2C device on Raspberry Pi
    uint16_t config;
    uint16_t conversion;
    float voltage;
    int i;

    // Open I2C device
    if ((fd = open(i2c_device, O_RDWR)) < 0) {
        perror("Failed to open I2C device");
        return 1;
    }

    // Specify slave address
    if (ioctl(fd, I2C_SLAVE, ADS1115_ADDR) < 0) {
        perror("Failed to acquire bus access and/or talk to slave");
        close(fd);
        return 1;
    }

    // Loop through AIN0 to AIN3
    for (i = 0; i < 4; i++) {
        // Configure the ADS1115 for single conversion
        switch (i) {
            case 0:
                config = ADS1115_CONFIG_OS_SINGLE | ADS1115_CONFIG_MUX_SINGLE_0 | ADS1115_CONFIG_PGA_4_096V | ADS1115_CONFIG_MODE_SINGLE | ADS1115_CONFIG_DR_128SPS | ADS1115_CONFIG_COMP_MODE_TRAD | ADS1115_CONFIG_COMP_POL_LOW | ADS1115_CONFIG_COMP_LAT_NON | ADS1115_CONFIG_COMP_QUE_DISABLE;
                break;
            case 1:
                config = ADS1115_CONFIG_OS_SINGLE | ADS1115_CONFIG_MUX_SINGLE_1 | ADS1115_CONFIG_PGA_4_096V | ADS1115_CONFIG_MODE_SINGLE | ADS1115_CONFIG_DR_128SPS | ADS1115_CONFIG_COMP_MODE_TRAD | ADS1115_CONFIG_COMP_POL_LOW | ADS1115_CONFIG_COMP_LAT_NON | ADS1115_CONFIG_COMP_QUE_DISABLE;
                break;
            case 2:
                config = ADS1115_CONFIG_OS_SINGLE | ADS1115_CONFIG_MUX_SINGLE_2 | ADS1115_CONFIG_PGA_4_096V | ADS1115_CONFIG_MODE_SINGLE | ADS1115_CONFIG_DR_128SPS | ADS1115_CONFIG_COMP_MODE_TRAD | ADS1115_CONFIG_COMP_POL_LOW | ADS1115_CONFIG_COMP_LAT_NON | ADS1115_CONFIG_COMP_QUE_DISABLE;
                break;
            case 3:
                config = ADS1115_CONFIG_OS_SINGLE | ADS1115_CONFIG_MUX_SINGLE_3 | ADS1115_CONFIG_PGA_4_096V | ADS1115_CONFIG_MODE_SINGLE | ADS1115_CONFIG_DR_128SPS | ADS1115_CONFIG_COMP_MODE_TRAD | ADS1115_CONFIG_COMP_POL_LOW | ADS1115_CONFIG_COMP_LAT_NON | ADS1115_CONFIG_COMP_QUE_DISABLE;
                break;
        }

        if (write_i2c_word(fd, ADS1115_REG_CONFIG, config) < 0) {
            close(fd);
            return 1;
        }

        // Wait for conversion to complete (at least 8ms for 128 SPS)
        usleep(10000); // 10 ms

        // Read the conversion result
        if (read_i2c_word(fd, ADS1115_REG_CONVERT, &conversion) < 0) {
            close(fd);
            return 1;
        }

        // Calculate voltage
        voltage = (float)conversion * (ADS1115_FSR_4_096V / 32768.0);

        // Print the voltage
        printf("AIN%d: %.4f V\n", i, voltage);
    }

    // Close I2C device
    close(fd);

    return 0;
}

#include <stdio.h>
