// Define LED matrix pins (adjust these according to your wiring)
#define A 4
#define B 17
#define C 27
#define D 22

#define OE 5
#define LAT 6
#define CLK 13
#define DAT 19

// 8x8 Matrix Dimensions
#define ROWS 8
#define COLS 8

// Function to clear the matrix
void clearMatrix() {
    for (int i = 0; i < ROWS; i++) {
        for (int j = 0; j < COLS; j++) {
            gpioWrite(DAT, 0);
            gpioWrite(CLK, 1);
            gpioWrite(CLK, 0);
        }
    }
    gpioWrite(LAT, 1);
    gpioWrite(LAT, 0);
}

// Function to set a single pixel
void setPixel(int row, int col, int value) {
    for (int i = 0; i < ROWS; i++) {
        for (int j = 0; j < COLS; j++) {
            if (i == row && j == col) {
                gpioWrite(DAT, value);
            } else {
                gpioWrite(DAT, 0);
            }
            gpioWrite(CLK, 1);
            gpioWrite(CLK, 0);
        }
    }
    gpioWrite(LAT, 1);
    gpioWrite(LAT, 0);
}

// Function to display a digit (0-9) on the matrix
void displayDigit(int digit, int x_offset, int y_offset) {
  // Basic digit patterns - you'll need to create more detailed patterns
    unsigned char digits[10][8] = {
        {0x3E, 0x63, 0x73, 0x73, 0x73, 0x73, 0x63, 0x3E}, // 0
        {0x0C, 0x1C, 0x0C, 0x0C, 0x0C, 0x0C, 0x0C, 0x3E}, // 1
        {0x3E, 0x63, 0x03, 0x06, 0x0C, 0x18, 0x30, 0x7E}, // 2
        {0x3E, 0x63, 0x03, 0x3E, 0x03, 0x03, 0x63, 0x3E}, // 3
        {0x66, 0x66, 0x66, 0x66, 0x7F, 0x06, 0x06, 0x06}, // 4
        {0x7F, 0x60, 0x60, 0x7E, 0x03, 0x03, 0x63, 0x3E}, // 5
        {0x3E, 0x63, 0x60, 0x7E, 0x63, 0x63, 0x63, 0x3E}, // 6
        {0x7F, 0x03, 0x06, 0x0C, 0x18, 0x30, 0x30, 0x30}, // 7
        {0x3E, 0x63, 0x63, 0x3E, 0x63, 0x63, 0x63, 0x3E}, // 8
        {0x3E, 0x63, 0x63, 0x3F, 0x03, 0x03, 0x63, 0x3E}  // 9
    };

    for (int i = 0; i < 8; i++) {
        for (int j = 0; j < 8; j++) {
            if ((digits[digit][i] >> j) & 1) {
                setPixel(i + y_offset, j + x_offset, 1); // Assuming 0,0 origin in top left
            }
        }
    }
}

// Function to display the time
void displayTime() {
    time_t rawtime;
    struct tm *timeinfo;
    time(&rawtime);
    timeinfo = localtime(&rawtime);

    int hours = timeinfo->tm_hour;
    int minutes = timeinfo->tm_min;

    clearMatrix();

    // Display hours (tens and ones)
    displayDigit(hours / 10, 0, 0);   // Tens digit
    displayDigit(hours % 10, 4, 0);   // Ones digit

    //Display Minutes (tens and ones)
    displayDigit(minutes / 10, 0, 0); // Tens digit
    displayDigit(minutes % 10, 4, 0); // Ones digit

}

