    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set pins to output mode
    gpioSetMode(A, PI_OUTPUT);
    gpioSetMode(B, PI_OUTPUT);
    gpioSetMode(C, PI_OUTPUT);
    gpioSetMode(D, PI_OUTPUT);
    gpioSetMode(OE, PI_OUTPUT);
    gpioSetMode(LAT, PI_OUTPUT);
    gpioSetMode(CLK, PI_OUTPUT);
    gpioSetMode(DAT, PI_OUTPUT);

    // Disable output initially
    gpioWrite(OE, 1);

    while (1) {
        displayTime();
        gpioWrite(OE, 0); // Enable output
