// Constants
#define ONBOARD_LED_PIN 1       // Raspberry Pi onboard LED pin
#define MCP23017_BASE_PIN 100  // Base pin number for MCP23017
#define MCP23017_I2C_ADDRESS 0x20 // I2C address of the MCP23017
#define MCP23017_LED_PIN 0       // MCP23017 pin connected to the LED
#define BLINK_DELAY_MS 500       // Blink delay in milliseconds

// Function prototypes
int initialize_wiringPi(void);
int initialize_mcp23017(int base_pin, int i2c_address);

int main(void) {
    // Initialize wiringPi
    if (initialize_wiringPi() != 0) {
        fprintf(stderr, "Failed to initialize wiringPi. Exiting.\n");
        return 1;
    }

    // Initialize MCP23017
    if (initialize_mcp23017(MCP23017_BASE_PIN, MCP23017_I2C_ADDRESS) != 0) {
        fprintf(stderr, "Failed to initialize MCP23017. Exiting.\n");
        return 1;
    }

    printf("Raspberry Pi - Quick2Wire MCP23017 Blink Test\n");

    // Set pin modes
    pinMode(ONBOARD_LED_PIN, OUTPUT);
    pinMode(MCP23017_BASE_PIN + MCP23017_LED_PIN, OUTPUT);

    // Blink loop
    while (1) {
        // Turn LEDs on
        digitalWrite(ONBOARD_LED_PIN, HIGH);
        digitalWrite(MCP23017_BASE_PIN + MCP23017_LED_PIN, HIGH);
        delay(BLINK_DELAY_MS);

