// Define GPIO pins (WiringPi numbering)
#define DHT22_PIN 4
#define RELAY_PIN 17

// Define humidity thresholds
#define HUMIDITY_HIGH 60.0
#define HUMIDITY_LOW 55.0

// Define error codes
#define DHT_OK 0
#define DHT_ERROR -1

// Structure to hold DHT22 sensor data
typedef struct {
    float temperature;
    float humidity;
    int status; // DHT_OK or DHT_ERROR
} DHT22Data;

// Global variables
FILE *log_file;
int running = 1; // Flag to control the main loop

// Function prototypes
DHT22Data read_dht22();
void control_dehumidifier(float humidity);
void log_event(float humidity);
void signal_handler(int signal);
char* get_timestamp();

// Dummy DHT22 read function (replace with actual DHT22 reading logic)
// This dummy function returns simulated data.
DHT22Data read_dht22() {
    DHT22Data data;
    // Simulate sensor reading
    data.temperature = 25.0 + (rand() % 5) - 2;
    data.humidity = 58.0 + (rand() % 10) - 5;
    data.status = DHT_OK; // Simulate successful read

    // Simulate occasional error
    if (rand() % 20 == 0) {
        data.status = DHT_ERROR;
    }

    return data;
}

// Function to control the dehumidifier relay
void control_dehumidifier(float humidity) {
    static int dehumidifier_state = 0; // 0 = OFF, 1 = ON

    if (humidity > HUMIDITY_HIGH && dehumidifier_state == 0) {
        digitalWrite(RELAY_PIN, HIGH); // Turn ON the relay
        dehumidifier_state = 1;
        printf("%s Dehumidifier ON (Humidity: %.2f%%)\n", get_timestamp(), humidity);
        fprintf(log_file, "%s Dehumidifier ON (Humidity: %.2f%%)\n", get_timestamp(), humidity);
        fflush(log_file);
    } else if (humidity < HUMIDITY_LOW && dehumidifier_state == 1) {
        digitalWrite(RELAY_PIN, LOW); // Turn OFF the relay
        dehumidifier_state = 0;
        printf("%s Dehumidifier OFF (Humidity: %.2f%%)\n", get_timestamp(), humidity);
        fprintf(log_file, "%s Dehumidifier OFF (Humidity: %.2f%%)\n", get_timestamp(), humidity);
        fflush(log_file);
    }
}

// Function to log events to a file
void log_event(float humidity) {
    char timestamp[20];
    time_t now = time(NULL);
    struct tm *tstruct = localtime(&now);
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tstruct);

    fprintf(log_file, "%s,%.2f\n", timestamp, humidity);
    fflush(log_file); // Flush the buffer to ensure data is written immediately
}

// Function to handle signals (e.g., Ctrl+C)
void signal_handler(int signal) {
    printf("\n%s Received signal %d, shutting down...\n", get_timestamp(), signal);
    running = 0; // Stop the main loop
    digitalWrite(RELAY_PIN, LOW); // Turn OFF the relay
    if (log_file != NULL) {
        fclose(log_file);
    }
    exit(0);
}

// Function to get the current timestamp as a string
char* get_timestamp() {
