#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pigpio.h>

// Define GPIO pins
#define TRIGGER_PIN 17
#define ECHO_PIN 18
#define BUZZER_PIN 27

// Constants
#define SPEED_OF_SOUND 0.0343 // cm/us
#define DISTANCE_THRESHOLD 20.0 // cm

// Global variables
volatile unsigned int pulseDuration = 0;
volatile unsigned int startTick = 0;
volatile unsigned int endTick = 0;
volatile int echoReceived = 0;

// Function prototypes
void triggerPulse();
void echoHandler(int gpio, int level, unsigned int tick);
float calculateDistance(unsigned int pulseDuration);
void controlBuzzer(float distance);
void signalHandler(int signal);

// pigpio initialization status
int pigpio_initialized = 0;

int main() {
    // Register signal handler for SIGINT (Ctrl+C)
    signal(SIGINT, signalHandler);

    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }
    pigpio_initialized = 1;

    // Configure GPIO pins
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);

    // Set trigger pin low initially
    gpioWrite(TRIGGER_PIN, 0);

    // Register interrupt handler for echo pin
    gpioSetISRFuncEx(ECHO_PIN, RISING_EDGE, 1000, echoHandler, NULL); // Timeout 1000us
    gpioSetISRFuncEx(ECHO_PIN, FALLING_EDGE, 1000, echoHandler, NULL);

    printf("Ultrasonic distance measurement started. Press Ctrl+C to exit.\n");

    while (1) {
        // Trigger a measurement
        triggerPulse();

        // Wait for 500ms
        gpioDelay(500000); // microseconds

        // Calculate distance
        float distance = calculateDistance(pulseDuration);

        if (distance < 0) {
            fprintf(stderr, "Error: Invalid distance reading\n");
        } else {
            printf("Distance: %.2f cm\n", distance);
        }

        // Control the buzzer
        controlBuzzer(distance);
    }

    return 0;
}

// Function to generate a 10us trigger pulse
void triggerPulse() {
    gpioWrite(TRIGGER_PIN, 1);
    gpioDelay(10); // 10 microseconds
    gpioWrite(TRIGGER_PIN, 0);
}

// Interrupt handler for echo pin
void echoHandler(int gpio, int level, unsigned int tick) {
    if (level == RISING_EDGE) {
        startTick = tick;
        echoReceived = 1; // Set flag to indicate rising edge received
    } else if (level == FALLING_EDGE && echoReceived) {
        endTick = tick;
        pulseDuration = endTick - startTick;
        echoReceived = 0; // Reset the flag
    } else if (level == PI_TIMEOUT) {
      pulseDuration = -1; // Indicate timeout
      echoReceived = 0; // Reset the flag
    }
}

// Function to calculate distance in centimeters
float calculateDistance(unsigned int pulseDuration) {
    if (pulseDuration > 0) {
        return (float)pulseDuration * SPEED_OF_SOUND / 2.0;
    } else {
        return -1.0; // Indicate an error or timeout
    }
}

// Function to control the buzzer
void controlBuzzer(float distance) {
    if (distance > 0 && distance < DISTANCE_THRESHOLD) {
        gpioWrite(BUZZER_PIN, 1); // Activate buzzer
    } else {
        gpioWrite(BUZZER_PIN, 0); // Deactivate buzzer
    }
}

// Signal handler for Ctrl+C
void signalHandler(int signal) {
    printf("Ctrl+C pressed. Exiting.\n");
    if (pigpio_initialized) {
        gpioTerminate(); // Terminate pigpio
    }
    exit(0);
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <errno.h>

// Define GPIO pins for LEDs
#define RED_LED_PIN   25  // BCM GPIO 26
#define YELLOW_LED_PIN 24  // BCM GPIO 19
#define BLUE_LED_PIN  23  // BCM GPIO 13

// Define GPIO pins for buttons
#define RED_BUTTON_PIN   4  // BCM GPIO 23
#define YELLOW_BUTTON_PIN 5  // BCM GPIO 24
#define BLUE_BUTTON_PIN  6  // BCM GPIO 25
#define RESET_BUTTON_PIN 1  // BCM GPIO 18

// Function prototypes
void clear_leds();
void red_button_handler();
void yellow_button_handler();
void blue_button_handler();

// Helper function to safely read a digital input
int safe_digital_read(int pin)
{
    int value = digitalRead(pin);
    if (value != LOW && value != HIGH)
    {
        fprintf(stderr, "Error: Invalid digital read value for pin %d\n", pin);
        return -1; // Indicate an error
    }
    return value;
}

// Function to turn off all LEDs
void clear_leds()
{
    digitalWrite(RED_LED_PIN, LOW);
    digitalWrite(YELLOW_LED_PIN, LOW);
    digitalWrite(BLUE_LED_PIN, LOW);
}

// Function to handle the red button press
void red_button_handler()
{
    while (safe_digital_read(RESET_BUTTON_PIN) == HIGH)
    {
        digitalWrite(RED_LED_PIN, HIGH);
        digitalWrite(YELLOW_LED_PIN, LOW);
        digitalWrite(BLUE_LED_PIN, LOW);
        delay(50); // Small delay to prevent busy-waiting
    }
    clear_leds();
}

// Function to handle the yellow button press
void yellow_button_handler()
{
    while (safe_digital_read(RESET_BUTTON_PIN) == HIGH)
    {
        digitalWrite(RED_LED_PIN, LOW);
        digitalWrite(YELLOW_LED_PIN, HIGH);
        digitalWrite(BLUE_LED_PIN, LOW);
        delay(50); // Small delay to prevent busy-waiting
    }
    clear_leds();
}

// Function to handle the blue button press
void blue_button_handler()
{
    while (safe_digital_read(RESET_BUTTON_PIN) == HIGH)
    {
        digitalWrite(RED_LED_PIN, LOW);
        digitalWrite(YELLOW_LED_PIN, LOW);
        digitalWrite(BLUE_LED_PIN, HIGH);
        delay(50); // Small delay to prevent busy-waiting
    }
    clear_leds();
}

int main()
{
    // Initialize wiringPi
    if (wiringPiSetup() == -1)
    {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return 1; // Exit with an error code
    }

    // Set pin modes
    pinMode(RED_LED_PIN, OUTPUT);
    pinMode(YELLOW_LED_PIN, OUTPUT);
    pinMode(BLUE_LED_PIN, OUTPUT);
    pinMode(RED_BUTTON_PIN, INPUT);
    pinMode(YELLOW_BUTTON_PIN, INPUT);
    pinMode(BLUE_BUTTON_PIN, INPUT);
    pinMode(RESET_BUTTON_PIN, INPUT);
    pullUpDnControl(RED_BUTTON_PIN, PUD_UP);   // Enable pull-up resistor
    pullUpDnControl(YELLOW_BUTTON_PIN, PUD_UP);
    pullUpDnControl(BLUE_BUTTON_PIN, PUD_UP);  // Enable pull-up resistor
    pullUpDnControl(RESET_BUTTON_PIN, PUD_UP); // Enable pull-up resistor

    // Main loop
    while (1)
    {
        // Read button states
        int red_button_state = safe_digital_read(RED_BUTTON_PIN);
        int yellow_button_state = safe_digital_read(YELLOW_BUTTON_PIN);
        int blue_button_state = safe_digital_read(BLUE_BUTTON_PIN);

        // Check for errors during digital read
        if (red_button_state == -1 || yellow_button_state == -1 || blue_button_state == -1)
        {
            fprintf(stderr, "Error reading button state. Exiting.\n");
            return 1; // Exit with an error code
        }

        // Button press detection (LOW when pressed because of pull-up resistors)
        if (red_button_state == LOW)
        {
            red_button_handler();
        }
        else if (yellow_button_state == LOW)
        {
            yellow_button_handler();
        }
        else if (blue_button_state == LOW)
        {
            blue_button_handler();
        }

        delay(10); // Small delay to prevent busy-waiting
    }

    return 0; // Exit normally
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <errno.h>
#include <string.h>
#include <wiringPi.h>
#include <wiringPiSPI.h>

// Define SPI channel and speed
#define SPI_CHANNEL 0
#define SPI_SPEED 1000000 // 1 MHz

// Define GPIO pin for PWM fan control
#define FAN_PIN 1

// Define temperature thresholds
#define TEMP_LOW 25.0f
#define TEMP_MED 30.0f
#define TEMP_HIGH 35.0f

// Function to read temperature from MAX31855 via SPI
float spi_read_temperature() {
    unsigned char data[4];
    int i;

    // Read 4 bytes from SPI
    if (wiringPiSPIDataRW(SPI_CHANNEL, data, 4) == -1) {
        fprintf(stderr, "Error: SPI communication failed: %s\n", strerror(errno));
        return -273.15f; // Return absolute zero on error
    }

    // Extract relevant data and perform error checking
    int32_t raw = (data[0] << 24) | (data[1] << 16) | (data[2] << 8) | data[3];

    // Check for fault conditions
    if (raw & 0x00000004) {
        fprintf(stderr, "Error: Thermocouple fault detected!\n");
        return -273.15f;
    }

    // Check for open circuit fault
    if (raw & 0x00000001) {
        fprintf(stderr, "Error: Thermocouple open circuit detected!\n");
        return -273.15f;
    }

    // Check for short to GND fault
    if (raw & 0x00000002) {
        fprintf(stderr, "Error: Thermocouple short to GND detected!\n");
        return -273.15f;
    }

    // Check for short to VCC fault
    if (raw & 0x00000004) {
        fprintf(stderr, "Error: Thermocouple short to VCC detected!\n");
        return -273.15f;
    }

    // Extract internal temperature (not used for fan control in this example)
    // int16_t internal_temp = ((data[2] << 8) | data[3]) >> 4;
    // float internal_temp_celsius = internal_temp * 0.0625;

    // Extract thermocouple temperature
    int16_t thermocouple_temp = ((data[0] << 8) | data[1]) >> 2;
    float thermocouple_temp_celsius = thermocouple_temp * 0.25;

    return thermocouple_temp_celsius;
}

// Function to set fan speed based on temperature
void set_fan_speed(float temperature) {
    int pwm_value;

    if (temperature < TEMP_LOW) {
        pwm_value = 0; // Fan off
    } else if (temperature < TEMP_MED) {
        pwm_value = 300; // 30% duty cycle
    } else if (temperature < TEMP_HIGH) {
        pwm_value = 600; // 60% duty cycle
    } else {
        pwm_value = 1024; // 100% duty cycle
    }

    pwmWrite(FAN_PIN, pwm_value);
}

int main() {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error: wiringPiSetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Initialize SPI
    if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) == -1) {
        fprintf(stderr, "Error: wiringPiSPISetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Configure GPIO18 (FAN_PIN) for PWM output
    pinMode(FAN_PIN, PWM_OUTPUT);
    pwmSetMode(PWM_MODE_MS);
    pwmSetRange(1024); // PWM range for duty cycle control
    pwmSetClock(192);   // PWM frequency = 19.2 MHz / clock / range = ~100Hz

    float temperature;

    // Main loop
    while (1) {
        temperature = spi_read_temperature();

        if (temperature > -273.0f) { // Valid temperature reading
            printf("Temperature: %.2f °C\n", temperature);
            set_fan_speed(temperature);
        } else {
            fprintf(stderr, "Error: Failed to read temperature. Retrying in 1 second.\n");
            // Optionally set fan to a safe default speed here
            pwmWrite(FAN_PIN, 0); // Turn off fan on error
            delay(1000); // Wait 1 second before retrying
            continue;      // Skip the rest of the loop and retry
        }

        delay(500); // Wait 500 milliseconds
    }

    return 0;
}

#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>

#define SERVO_PIN 18
#define MIN_PULSE_WIDTH 1000  /* Minimum pulse width (microseconds) */
#define MAX_PULSE_WIDTH 2000  /* Maximum pulse width (microseconds) */
#define STEP_SIZE 5           /* Step size for gradual movement */
#define DELAY_US 2000          /* Delay between steps (microseconds) */

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(SERVO_PIN, PI_OUTPUT);

    int current_pulse_width = MIN_PULSE_WIDTH;
    int direction = 1;  // 1 for increasing, -1 for decreasing

    while (1) {
        gpioServo(SERVO_PIN, current_pulse_width);
        usleep(DELAY_US);

        current_pulse_width += direction * STEP_SIZE;

        if (current_pulse_width >= MAX_PULSE_WIDTH) {
            current_pulse_width = MAX_PULSE_WIDTH;
            direction = -1;
            usleep(2000000); //Pause at end.
        } else if (current_pulse_width <= MIN_PULSE_WIDTH) {
            current_pulse_width = MIN_PULSE_WIDTH;
            direction = 1;
            usleep(2000000); //Pause at end.
        }
    }

    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <string.h>
#include <unistd.h>

// Constants
#define I2C_ADDR 0x48
#define FAN_GPIO 18
#define PWM_FREQ 100  // PWM frequency in Hz
#define PWM_RANGE 100 // PWM range (0-100 for percentage)

// Temperature thresholds (Celsius)
#define TEMP_LOW 50.0
#define TEMP_MEDIUM 60.0
#define TEMP_HIGH 70.0

// Function prototypes
float read_temperature(int i2c_handle);
void set_fan_speed(int fan_gpio, int speed);
void log_data(float temperature, int fan_speed);
void cleanup(int i2c_handle);

int main()
{
    // Initialize pigpio
    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C connection
    int i2c_handle = i2cOpen(1, I2C_ADDR, 0); // Bus 1, address 0x48, flags 0
    if (i2c_handle < 0)
    {
        fprintf(stderr, "Failed to open I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Configure FAN_GPIO as output
    gpioSetMode(FAN_GPIO, PI_OUTPUT);
    gpioSetPWMfrequency(FAN_GPIO, PWM_FREQ);
    gpioSetPWMrange(FAN_GPIO, PWM_RANGE);

    // Main loop
    while (1)
    {
        // Read temperature
        float temperature = read_temperature(i2c_handle);

        // Determine fan speed based on temperature
        int fan_speed = 0;
        if (temperature < TEMP_LOW)
        {
            fan_speed = 0;
        }
        else if (temperature < TEMP_MEDIUM)
        {
            fan_speed = 50;
        }
        else if (temperature < TEMP_HIGH)
        {
            fan_speed = 75;
        }
        else
        {
            fan_speed = 100;
        }

        // Set fan speed
        set_fan_speed(FAN_GPIO, fan_speed);

        // Log data
        log_data(temperature, fan_speed);

        // Wait 5 seconds
        sleep(5);
    }

    // Cleanup (this part will not be reached in the infinite loop)
    cleanup(i2c_handle);
    gpioTerminate();

    return 0;
}

float read_temperature(int i2c_handle)
{
    unsigned char buf[2];
    int result = i2cReadDevice(i2c_handle, buf, 2);

    if (result != 2)
    {
        FILE *fp = fopen("cooling_log.txt", "a");
        if (fp != NULL) {
            time_t t = time(NULL);
            struct tm tm = *localtime(&t);
            fprintf(fp, "%d-%02d-%02d %02d:%02d:%02d - ERROR: I2C read failed: %d\n", tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, result);
            fclose(fp);
        }
        return -1000.0; // Indicate error with a very low temperature
    }

    // Convert raw data to temperature (Celsius)
    int raw_temp = (buf[0] << 4) | (buf[1] >> 4);
    float temperature = (float)raw_temp * 0.0625;

    return temperature;
}

void set_fan_speed(int fan_gpio, int speed)
{
    if (speed < 0) speed = 0;
    if (speed > 100) speed = 100;
    gpioPWM(fan_gpio, speed);
}

void log_data(float temperature, int fan_speed)
{
    FILE *fp = fopen("cooling_log.txt", "a");
    if (fp == NULL)
    {
        fprintf(stderr, "Error opening log file!\n");
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);

    fprintf(fp, "%d-%02d-%02d %02d:%02d:%02d - Temperature: %.2f C, Fan Speed: %d%%\n",
            tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec,
            temperature, fan_speed);

    fclose(fp);
}

void cleanup(int i2c_handle)
{
    i2cClose(i2c_handle);
    gpioWrite(FAN_GPIO, 0); // Turn off the fan
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <pigpio.h>
#include <unistd.h>
#include <signal.h>
#include <time.h>
#include <string.h>

// Constants
#define FAN_GPIO 18
#define TEMP_FILE "/sys/class/thermal/thermal_zone0/temp"
#define LOG_FILE "fan_log.csv"
#define SLEEP_SECONDS 5

// Global variables (only for signal handling)
FILE *log_fp = NULL;

// Function prototypes
int read_cpu_temp();
int calculate_duty_cycle(int temp);
void set_fan_speed(int duty_cycle);
void log_data(int temp, int duty_cycle);
void signal_handler(int signal);

// Function to read CPU temperature from file
int read_cpu_temp() {
    FILE *fp;
    int temp = -1;

    fp = fopen(TEMP_FILE, "r");
    if (fp == NULL) {
        fprintf(stderr, "Error: Could not open temperature file.\n");
        return -1;
    }

    if (fscanf(fp, "%d", &temp) != 1) {
        fprintf(stderr, "Error: Could not read temperature from file.\n");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return temp;
}

// Function to calculate PWM duty cycle based on temperature
int calculate_duty_cycle(int temp) {
    if (temp < 50000) { // < 50°C
        return 0;       // Fan off
    } else if (temp < 60000) { // 50°C <= temp < 60°C
        return 300000;  // 30%
    } else if (temp < 70000) { // 60°C <= temp < 70°C
        return 600000;  // 60%
    } else {                   // temp >= 70°C
        return 1000000; // 100%
    }
}

// Function to set PWM duty cycle on GPIO18
void set_fan_speed(int duty_cycle) {
    gpioPWM(FAN_GPIO, duty_cycle / 1000); // pigpio uses 0-255 range
}

// Function to log temperature and duty cycle to file
void log_data(int temp, int duty_cycle) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(log_fp, "%s,%.2f,%d\n", timestamp, (float)temp / 1000.0, duty_cycle);
    fflush(log_fp);
}

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);
    gpioTerminate();
    if (log_fp != NULL) {
        fclose(log_fp);
    }
    exit(0);
}

int main() {
    int temp, duty_cycle;

    // Register signal handler
    signal(SIGINT, signal_handler);

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed.\n");
        return 1;
    }

    // Set GPIO18 as output
    gpioSetMode(FAN_GPIO, PI_OUTPUT);
    gpioSetPWMrange(FAN_GPIO, 1000000); // Set PWM range to 1000000
    gpioSetPWMfrequency(FAN_GPIO, 25); // Set PWM frequency to 25Hz

    // Open log file
    log_fp = fopen(LOG_FILE, "a");
    if (log_fp == NULL) {
        fprintf(stderr, "Error: Could not open log file.\n");
        gpioTerminate();
        return 1;
    }

    // Write header if the file is new
    fseek(log_fp, 0, SEEK_END);
    long fsize = ftell(log_fp);
    if (fsize == 0) {
        fprintf(log_fp, "Timestamp,Temperature(C),DutyCycle\n");
    }

    // Main loop
    while (1) {
        // Read CPU temperature
        temp = read_cpu_temp();
        if (temp == -1) {
            fprintf(stderr, "Error reading CPU temperature. Exiting.\n");
            break;
        }

        // Calculate duty cycle
        duty_cycle = calculate_duty_cycle(temp);

        // Set fan speed
        set_fan_speed(duty_cycle);

        // Log data
        log_data(temp, duty_cycle);

        // Sleep for a while
        sleep(SLEEP_SECONDS);
    }

    // Cleanup
    gpioTerminate();
    fclose(log_fp);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
#include <linux/i2c-dev.h>
#include <sys/ioctl.h>
#include <unistd.h>

#define SSD1306_I2C_ADDR  0x3C
int i2c_fd;
void ssd1306_sendCommand(unsigned char command) {
    unsigned char buffer[2] = {0x00, command};
    if (write(i2c_fd, buffer, 2) < 0) {
        perror("I2C Command Write Failed");
    }
}
void ssd1306_init() {
    ssd1306_sendCommand(0xAE);
    ssd1306_sendCommand(0xD5);
    ssd1306_sendCommand(0x80);
    ssd1306_sendCommand(0xA8);
    ssd1306_sendCommand(0x3F);
    ssd1306_sendCommand(0xD3);
    ssd1306_sendCommand(0x00);
    ssd1306_sendCommand(0x40);
    ssd1306_sendCommand(0x8D);
    ssd1306_sendCommand(0x14);
    ssd1306_sendCommand(0xA1);
    ssd1306_sendCommand(0xC8);
    ssd1306_sendCommand(0xDA);
    ssd1306_sendCommand(0x12);
