#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
#include <errno.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <stdbool.h>
#include <time.h>

// Configuration
#define D6F_I2C_ADDR 0x6C  // D6F-PH I2C address (7-bit)
#define I2C_DEVICE "/dev/i2c-1" // I2C device file

// Function Prototypes
static uint32_t i2c_write_reg16(uint8_t dev_addr, uint16_t reg_addr, const uint8_t *data, uint8_t length);
static uint32_t i2c_read_reg8(uint8_t dev_addr, uint8_t reg_addr, uint8_t *data, uint8_t length);
static uint16_t bytes_to_uint16(const uint8_t *buf);
static void delay_ms(int milliseconds);

/**
 * @brief Writes data to a 16-bit register on an I2C device.
 *
 * @param dev_addr The I2C device address.
 * @param reg_addr The 16-bit register address to write to.
 * @param data A pointer to the data to write.
 * @param length The number of bytes to write.
 * @return 0 on success, or an error code on failure.
 */
static uint32_t i2c_write_reg16(uint8_t dev_addr, uint16_t reg_addr, const uint8_t *data, uint8_t length) {
    if (length > 125) {
        fprintf(stderr, "Error: Write length exceeds maximum allowed (125 bytes).\n");
        return 1; // Error code for invalid length
    }

    int file_descriptor = open(I2C_DEVICE, O_RDWR);
    if (file_descriptor < 0) {
        fprintf(stderr, "Error: Failed to open I2C device %s: %s\n", I2C_DEVICE, strerror(errno));
        return 2; // Error code for failed to open device
    }

    uint8_t buffer[128]; // Buffer to hold register address and data
    buffer[0] = (reg_addr >> 8) & 0xFF; // MSB of register address
    buffer[1] = reg_addr & 0xFF;      // LSB of register address

    if (data != NULL && length > 0) {
        memcpy(buffer + 2, data, length);
    }

    ssize_t bytes_to_write = length + 2;

    if (ioctl(file_descriptor, I2C_SLAVE, dev_addr) < 0) {
        fprintf(stderr, "Error: Failed to acquire bus access and/or talk to slave: %s\n", strerror(errno));
        close(file_descriptor);
        return 3; // Error code for failed I2C_SLAVE ioctl
    }

    ssize_t bytes_written = write(file_descriptor, buffer, bytes_to_write);
    if (bytes_written != bytes_to_write) {
        fprintf(stderr, "Error: Failed to write to I2C device. Expected %zd bytes, wrote %zd bytes: %s\n",
                bytes_to_write, bytes_written, strerror(errno));
        close(file_descriptor);
        return 4; // Error code for short write
    }

    close(file_descriptor);
    return 0; // Success
}

/**
 * @brief Reads data from an 8-bit register on an I2C device.
 *
 * @param dev_addr The I2C device address.
 * @param reg_addr The 8-bit register address to read from.
 * @param data A pointer to the buffer to store the read data.
 * @param length The number of bytes to read.
 * @return 0 on success, or an error code on failure.
 */
static uint32_t i2c_read_reg8(uint8_t dev_addr, uint8_t reg_addr, uint8_t *data, uint8_t length) {
    int file_descriptor = open(I2C_DEVICE, O_RDWR);
    if (file_descriptor < 0) {
        fprintf(stderr, "Error: Failed to open I2C device %s: %s\n", I2C_DEVICE, strerror(errno));
        return 5; // Error code for failed to open device
    }

    if (ioctl(file_descriptor, I2C_SLAVE, dev_addr) < 0) {
        fprintf(stderr, "Error: Failed to acquire bus access and/or talk to slave: %s\n", strerror(errno));
        close(file_descriptor);
        return 6; // Error code for failed I2C_SLAVE ioctl
    }

    // Write the register address to be read from
    ssize_t bytes_written = write(file_descriptor, &reg_addr, 1);
    if (bytes_written != 1) {
        fprintf(stderr, "Error: Failed to write register address: %s\n", strerror(errno));
        close(file_descriptor);
        return 7; // Error code for failed register address write
    }

    // Read the data
    ssize_t bytes_read = read(file_descriptor, data, length);
    if (bytes_read != length) {
        fprintf(stderr, "Error: Failed to read from I2C device. Expected %zd bytes, read %zd bytes: %s\n",
                length, bytes_read, strerror(errno));
        close(file_descriptor);
        return 8; // Error code for short read
    }

    close(file_descriptor);
    return 0; // Success
}

/**
 * @brief Converts two bytes (big-endian) to a 16-bit unsigned integer.
 *
 * @param buf A pointer to the byte array.
 * @return The converted 16-bit unsigned integer.
 */
static uint16_t bytes_to_uint16(const uint8_t *buf) {
    return (uint16_t)(((uint32_t)buf[0] << 8) | (uint32_t)buf[1]);
}

/**
 * @brief Delays execution for a specified number of milliseconds.
 *
 * @param milliseconds The number of milliseconds to delay.
 */
static void delay_ms(int milliseconds) {
    struct timespec ts;
    ts.tv_sec = milliseconds / 1000;
    ts.tv_nsec = (milliseconds % 1000) * 1000000;
    nanosleep(&ts, NULL);
}

int main() {
    // 1. Initialize sensor (0Bh, 00h)
    uint32_t status = i2c_write_reg16(D6F_I2C_ADDR, 0x0B00, NULL, 0);
    if (status != 0) {
        fprintf(stderr, "Error: Sensor initialization failed with code %u\n", status);
        return 1;
    }
    delay_ms(900);

    while (1) {
        // 2. Trigger getting data (00h, D0h, 40h, 18h, 06h)
        const uint8_t trigger_data[] = {0x40, 0x18, 0x06};
        status = i2c_write_reg16(D6F_I2C_ADDR, 0x00D0, trigger_data, sizeof(trigger_data));
        if (status != 0) {
            fprintf(stderr, "Error: Trigger write failed with code %u\n", status);
            return 1;
        }

        delay_ms(50);  // wait 50ms

        // 3. Read data (00h, D0h, 51h, 2Ch) (07h)
        const uint8_t read_command[] = {0x51, 0x2C};
        status = i2c_write_reg16(D6F_I2C_ADDR, 0x00D0, read_command, sizeof(read_command));
        if (status != 0) {
            fprintf(stderr, "Error: Read command write failed with code %u\n", status);
            return 1;
        }

        uint8_t read_buffer[2];
        status = i2c_read_reg8(D6F_I2C_ADDR, 0x07, read_buffer, sizeof(read_buffer));
        if (status != 0) {
            fprintf(stderr, "Error: Data read failed with code %u\n", status);
            return 1;
        }

        uint16_t raw_flow = bytes_to_uint16(read_buffer);
        float flow_rate;

        // calculation for 0-250[Pa] range
        flow_rate = ((float)raw_flow - 1024.0) * 250.0 / 60000.0;

        printf("Flow Rate: %6.2f [Pa]\n", flow_rate);

        delay_ms(100); // Add a small delay between readings
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>
#include <time.h>
#include <errno.h>

// MPR121 I2C address
#define MPR121_ADDRESS 0x5A

// LED GPIO pin
#define LED_PIN 17

// Function to initialize the MPR121
int mpr121_init(int fd) {
    // Soft reset
    if (wiringPiI2CWriteReg8(fd, 0x80, 0x63) < 0) {
        perror("Error resetting MPR121");
        return -1;
    }
    delay(100);

    // Stop mode
    if (wiringPiI2CWriteReg8(fd, 0x5E, 0x00) < 0) {
        perror("Error setting MPR121 to stop mode");
        return -1;
    }

    // Set electrode sensitivity
    for (int i = 0x41; i <= 0x5A; i++) {
        if (wiringPiI2CWriteReg8(fd, i, 0x10) < 0) {
            perror("Error setting MPR121 sensitivity");
            return -1;
        }
    }

    // Configure baseline filtering
    if (wiringPiI2CWriteReg8(fd, 0x5B, 0x0A) < 0) {
        perror("Error configuring MPR121 baseline");
        return -1;
    }
    if (wiringPiI2CWriteReg8(fd, 0x5C, 0x05) < 0) {
        perror("Error configuring MPR121 baseline");
        return -1;
    }
    if (wiringPiI2CWriteReg8(fd, 0x5D, 0x01) < 0) {
        perror("Error configuring MPR121 baseline");
        return -1;
    }

    // Start operation
    if (wiringPiI2CWriteReg8(fd, 0x5E, 0x01 << 0) < 0) { // ELEPROX_EN = 1 for electrode mode
        perror("Error setting MPR121 to operation mode");
        return -1;
    }

    delay(1);

    if (wiringPiI2CWriteReg8(fd, 0x5E, 0x01 << 0) < 0) { // ELEPROX_EN = 1 for electrode mode
        perror("Error setting MPR121 to operation mode");
        return -1;
    }

    return 0;
}

// Function to read the touch status from the MPR121
int mpr121_read_touch_status(int fd) {
    int touch_status = wiringPiI2CReadReg16(fd, 0x00); //Read register 0x00 and 0x01
    if (touch_status < 0) {
        perror("Error reading touch status");
        return -1;
    }
    return touch_status;
}

// Function to control the LED
void led_control(int gpio_pin, int state) {
    digitalWrite(gpio_pin, state);
}

// Function to log touch events
int log_touch_event(const char *filename, int electrode_number) {
    FILE *fp = fopen(filename, "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return -1;
    }

    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char s[64];
    strftime(s, sizeof(s), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(fp, "%s: Electrode %d touched\n", s, electrode_number);

    if (fclose(fp) != 0) {
        perror("Error closing log file");
        return -1;
    }
    return 0;
}

int main() {
    // Initialize WiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi setup failed!\n");
        return 1;
    }

    // Initialize LED pin as output
    pinMode(LED_PIN, OUTPUT);

    // Open I2C device
    int fd = wiringPiI2CSetup(MPR121_ADDRESS);
    if (fd == -1) {
        fprintf(stderr, "I2C setup failed!\n");
        return 1;
    }

    // Initialize MPR121
    if (mpr121_init(fd) == -1) {
        fprintf(stderr, "MPR121 initialization failed!\n");
        return 1;
    }

    printf("MPR121 initialized. Ready for touch input.\n");

    // Main loop
    while (1) {
        int touch_status = mpr121_read_touch_status(fd);
        if (touch_status >= 0) {
            // Check each electrode for touch
            for (int i = 0; i < 12; i++) {
                if ((touch_status & (1 << i)) != 0) {
                    // Electrode i is touched
                    led_control(LED_PIN, 1); // Turn on LED
                    if(log_touch_event("touch_log.txt", i) != 0){
                        fprintf(stderr, "Logging failed for electrode %d!\n", i);
                    }
                    delay(50); // Debounce delay
                    led_control(LED_PIN, 0); // Turn off LED
                }
            }
        }
        delay(50);
    }

    return 0;
}

#include <stdio.h>
#include <pigpio.h>

#define LED_PIN 13
#define BUTTON_PIN 19

volatile int button_pressed = 0;

void button_callback(int gpio, int level, uint32_t tick)
{
    if (gpio == BUTTON_PIN && level == 0) // Button pressed (LOW signal)
    {
        button_pressed = 1;
    }
    else if (gpio == BUTTON_PIN && level == 1) // Button released (HIGH signal)
    {
        button_pressed = 0;
        gpioWrite(LED_PIN, 0); // Turn LED off immediately
    }
}

int main()
{
    if (gpioInitialise() < 0)
    {
        printf("pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(LED_PIN, PI_OUTPUT);
    gpioSetMode(BUTTON_PIN, PI_INPUT);
    gpioSetPullUpDown(BUTTON_PIN, PI_PUD_UP); // Enable pull-up resistor

    gpioSetAlertFunc(BUTTON_PIN, button_callback);

    while (1)
    {
        if (button_pressed)
        {
            gpioWrite(LED_PIN, 1);
            gpioDelay(100000); // 100ms
            gpioWrite(LED_PIN, 0);
            gpioDelay(100000); // 100ms
        }
        else
        {
            gpioDelay(10000); // Small delay to reduce CPU usage
        }
    }

    gpioTerminate();
    return 0;
}

