#include <stdio.h>
#include <wiringPi.h>
#include <unistd.h>

// Define the GPIO pins connected to the seven segments (a to g)
#define SEG_A 0
#define SEG_B 1
#define SEG_C 2
#define SEG_D 3
#define SEG_E 4
#define SEG_F 5
#define SEG_G 6

// Function to display a number on the seven-segment display
void display_number(int number) {
  switch (number) {
    case 0:
      digitalWrite(SEG_A, HIGH); digitalWrite(SEG_B, HIGH); digitalWrite(SEG_C, HIGH);
      digitalWrite(SEG_D, HIGH); digitalWrite(SEG_E, HIGH); digitalWrite(SEG_F, HIGH);
      digitalWrite(SEG_G, LOW);
      break;
    case 1:
      digitalWrite(SEG_A, LOW); digitalWrite(SEG_B, HIGH); digitalWrite(SEG_C, HIGH);
      digitalWrite(SEG_D, LOW); digitalWrite(SEG_E, LOW); digitalWrite(SEG_F, LOW);
      digitalWrite(SEG_G, LOW);
      break;
    case 2:
      digitalWrite(SEG_A, HIGH); digitalWrite(SEG_B, HIGH); digitalWrite(SEG_C, LOW);
      digitalWrite(SEG_D, HIGH); digitalWrite(SEG_E, HIGH); digitalWrite(SEG_F, LOW);
      digitalWrite(SEG_G, HIGH);
      break;
    case 3:
      digitalWrite(SEG_A, HIGH); digitalWrite(SEG_B, HIGH); digitalWrite(SEG_C, HIGH);
      digitalWrite(SEG_D, HIGH); digitalWrite(SEG_E, LOW); digitalWrite(SEG_F, LOW);
      digitalWrite(SEG_G, HIGH);
      break;
    case 4:
      digitalWrite(SEG_A, LOW); digitalWrite(SEG_B, HIGH); digitalWrite(SEG_C, HIGH);
      digitalWrite(SEG_D, LOW); digitalWrite(SEG_E, LOW); digitalWrite(SEG_F, HIGH);
      digitalWrite(SEG_G, HIGH);
      break;
    case 5:
      digitalWrite(SEG_A, HIGH); digitalWrite(SEG_B, LOW); digitalWrite(SEG_C, HIGH);
      digitalWrite(SEG_D, HIGH); digitalWrite(SEG_E, LOW); digitalWrite(SEG_F, HIGH);
      digitalWrite(SEG_G, HIGH);
      break;
    case 6:
      digitalWrite(SEG_A, HIGH); digitalWrite(SEG_B, LOW); digitalWrite(SEG_C, HIGH);
      digitalWrite(SEG_D, HIGH); digitalWrite(SEG_E, HIGH); digitalWrite(SEG_F, HIGH);
      digitalWrite(SEG_G, HIGH);
      break;
    case 7:
      digitalWrite(SEG_A, HIGH); digitalWrite(SEG_B, HIGH); digitalWrite(SEG_C, HIGH);
      digitalWrite(SEG_D, LOW); digitalWrite(SEG_E, LOW); digitalWrite(SEG_F, LOW);
      digitalWrite(SEG_G, LOW);
      break;
    case 8:
      digitalWrite(SEG_A, HIGH); digitalWrite(SEG_B, HIGH); digitalWrite(SEG_C, HIGH);
      digitalWrite(SEG_D, HIGH); digitalWrite(SEG_E, HIGH); digitalWrite(SEG_F, HIGH);
      digitalWrite(SEG_G, HIGH);
      break;
    case 9:
      digitalWrite(SEG_A, HIGH); digitalWrite(SEG_B, HIGH); digitalWrite(SEG_C, HIGH);
      digitalWrite(SEG_D, HIGH); digitalWrite(SEG_E, LOW); digitalWrite(SEG_F, HIGH);
      digitalWrite(SEG_G, HIGH);
      break;
    default:
      // If the number is invalid, turn off all segments
      digitalWrite(SEG_A, LOW); digitalWrite(SEG_B, LOW); digitalWrite(SEG_C, LOW);
      digitalWrite(SEG_D, LOW); digitalWrite(SEG_E, LOW); digitalWrite(SEG_F, LOW);
      digitalWrite(SEG_G, LOW);
  }
}

int main() {
  // Initialize WiringPi
  if (wiringPiSetup() == -1) {
    fprintf(stderr, "WiringPi initialization failed!\n");
    return 1;
  }

  // Set the GPIO pins as output
  pinMode(SEG_A, OUTPUT);
  pinMode(SEG_B, OUTPUT);
  pinMode(SEG_C, OUTPUT);
  pinMode(SEG_D, OUTPUT);
  pinMode(SEG_E, OUTPUT);
  pinMode(SEG_F, OUTPUT);
  pinMode(SEG_G, OUTPUT);

  // Display numbers from 9 to 0
  for (int i = 9; i >= 0; i--) {
    display_number(i);
    delay(1000); // Wait for 1 second
  }

  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <softPwm.h>
#include <errno.h>

// Define the GPIO pin connected to the LED
#define LED_PIN 1

// Define PWM range (0-100)
#define PWM_RANGE 100

// Define delay in milliseconds
#define DELAY_MS 20

int main(void) {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return 1; // Exit with error
    }

    // Create a software PWM channel on the LED pin
    if (softPwmCreate(LED_PIN, 0, PWM_RANGE) != 0) {
        fprintf(stderr, "SoftPWM creation failed for pin %d: %s\n", LED_PIN, strerror(errno));
        return 1; // Exit with error
    }

    // Main loop to create the breathing effect
    while (1) {
        // Fade in
        for (int dutyCycle = 0; dutyCycle <= PWM_RANGE; dutyCycle++) {
            softPwmWrite(LED_PIN, dutyCycle);
            delay(DELAY_MS);
            printf("PWM Duty Cycle = %d\n", dutyCycle);
        }

        // Fade out
        for (int dutyCycle = PWM_RANGE; dutyCycle >= 0; dutyCycle--) {
            softPwmWrite(LED_PIN, dutyCycle);
            delay(DELAY_MS);
            printf("PWM Duty Cycle = %d\n", dutyCycle);
        }
    }

    return 0; // Exit normally (this will likely never be reached in this example)
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Define GPIO pins
#define FLAME_SENSOR_PIN 17
#define BUZZER_PIN 18
#define LED_PIN 23

// Define constants
#define BUZZER_LED_DURATION_MS 2000
#define DEBOUNCE_DELAY_US 50000 // 50ms
#define LOG_FILE "fire_events.log"

// Global flag for graceful shutdown
volatile sig_atomic_t program_running = 1;

// Function prototypes
int setupGPIO(int pin, int mode);
int readSensor(int pin);
void activateBuzzer(int pin, int duration_ms);
void activateLED(int pin, int duration_ms);
void logEvent(const char* filename, const char* event);
void handleFlameDetected();
void signalHandler(int signal);

// Function to set up a GPIO pin as input or output
int setupGPIO(int pin, int mode) {
    int result = gpioSetMode(pin, mode);
    if (result != 0) {
        fprintf(stderr, "Error setting GPIO %d mode to %d: %d\n", pin, mode, result);
        return 1; // Indicate failure
    }
    return 0; // Indicate success
}

// Function to read the digital value from a GPIO pin
int readSensor(int pin) {
    return gpioRead(pin);
}

// Function to activate the buzzer for a specified duration
void activateBuzzer(int pin, int duration_ms) {
    gpioWrite(pin, 1); // Turn buzzer ON
    gpioDelay(duration_ms * 1000); // Delay for specified duration
    gpioWrite(pin, 0); // Turn buzzer OFF
}

// Function to activate the LED for a specified duration
void activateLED(int pin, int duration_ms) {
    gpioWrite(pin, 1); // Turn LED ON
    gpioDelay(duration_ms * 1000); // Delay for specified duration
    gpioWrite(pin, 0); // Turn LED OFF
}

// Function to log an event to a file with a timestamp
void logEvent(const char* filename, const char* event) {
    FILE *fp = fopen(filename, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file %s\n", filename);
        return;
    }

    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(fp, "%s: %s\n", timestamp, event);
    fclose(fp);
}

// Function to handle flame detection
void handleFlameDetected() {
    activateBuzzer(BUZZER_PIN, BUZZER_LED_DURATION_MS);
    activateLED(LED_PIN, BUZZER_LED_DURATION_MS);
    logEvent(LOG_FILE, "Flame detected!");
}

// Signal handler for graceful shutdown
void signalHandler(int signal) {
    program_running = 0;
    fprintf(stderr, "Caught signal %d, exiting gracefully...\n", signal);
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signalHandler);

    // Set up GPIO pins
    if (setupGPIO(FLAME_SENSOR_PIN, PI_INPUT) != 0 ||
        setupGPIO(BUZZER_PIN, PI_OUTPUT) != 0 ||
        setupGPIO(LED_PIN, PI_OUTPUT) != 0) {
        gpioTerminate();
        return 1;
    }

    printf("Flame sensor monitoring started. Press Ctrl+C to exit.\n");

    int last_state = 1; // Initialize to no flame detected (HIGH)

    // Main loop
    while (program_running) {
        int sensor_value = readSensor(FLAME_SENSOR_PIN);

        if (sensor_value == 0 && last_state == 1) { // Flame detected (LOW) and previous state was no flame
            handleFlameDetected();
            last_state = 0; // Update last state
            gpioDelay(DEBOUNCE_DELAY_US); // Debounce delay
        } else if (sensor_value == 1 && last_state == 0) {
            last_state = 1; // Update last state to no flame
            gpioDelay(DEBOUNCE_DELAY_US); // Debounce delay
        }

        gpioDelay(10000); // Check every 10ms (adjust as needed)
    }

    // Clean up and exit
    gpioTerminate();
    printf("Program terminated.\n");
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <errno.h>
#include <unistd.h>

#define GPIO17 "17"
#define GPIO18 "18"

static volatile int running = 1;

// Function to handle errors
void error_exit(const char *message) {
    perror(message);
    exit(EXIT_FAILURE);
}

// Function to write to a file
int write_to_file(const char *path, const char *value) {
    FILE *fp = fopen(path, "w");
    if (fp == NULL) {
        fprintf(stderr, "Error opening file %s: %s\n", path, strerror(errno));
        return -1;
    }
    if (fputs(value, fp) == EOF) {
        fprintf(stderr, "Error writing to file %s: %s\n", path, strerror(errno));
        fclose(fp);
        return -1;
    }
    fclose(fp);
    return 0;
}

// Function to read from a file
int read_from_file(const char *path, char *buffer, size_t buffer_size) {
    FILE *fp = fopen(path, "r");
    if (fp == NULL) {
        fprintf(stderr, "Error opening file %s: %s\n", path, strerror(errno));
        return -1;
    }
    if (fgets(buffer, buffer_size, fp) == NULL && ferror(fp)) {
        fprintf(stderr, "Error reading from file %s: %s\n", path, strerror(errno));
        fclose(fp);
        return -1;
    }
    fclose(fp);
    return 0;
}

// Function to export a GPIO
int export_gpio(const char *gpio) {
    char path[64];
    snprintf(path, sizeof(path), "/sys/class/gpio/export");
    return write_to_file(path, gpio);
}

// Function to unexport a GPIO
int unexport_gpio(const char *gpio) {
    char path[64];
    snprintf(path, sizeof(path), "/sys/class/gpio/unexport");
    return write_to_file(path, gpio);
}

// Function to set GPIO direction
int set_gpio_direction(const char *gpio, const char *direction) {
    char path[64];
    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%s/direction", gpio);
    return write_to_file(path, direction);
}

// Function to write GPIO value
int write_gpio_value(const char *gpio, const char *value) {
    char path[64];
    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%s/value", gpio);
    return write_to_file(path, value);
}

// Function to read GPIO value
int read_gpio_value(const char *gpio, char *value, size_t size) {
    char path[64];
    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%s/value", gpio);
    return read_from_file(path, value, size);
}

// Signal handler to gracefully exit
void signal_handler(int sig) {
    running = 0;
    printf("Caught signal %d, exiting...\n", sig);
}

// Function to check if the current time is within the specified range
int is_night_time() {
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    int hour = tm.tm_hour;
    return (hour >= 22 || hour < 6);
}

int main() {
    // Install signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Export GPIOs
    if (export_gpio(GPIO17) != 0) {
        fprintf(stderr, "Failed to export GPIO%s\n", GPIO17);
        return EXIT_FAILURE;
    }
    if (export_gpio(GPIO18) != 0) {
        fprintf(stderr, "Failed to export GPIO%s\n", GPIO18);
        unexport_gpio(GPIO17);
        return EXIT_FAILURE;
    }

    // Set GPIO directions
    if (set_gpio_direction(GPIO17, "in") != 0) {
        fprintf(stderr, "Failed to set GPIO%s direction to in\n", GPIO17);
        unexport_gpio(GPIO17);
        unexport_gpio(GPIO18);
        return EXIT_FAILURE;
    }
    if (set_gpio_direction(GPIO18, "out") != 0) {
        fprintf(stderr, "Failed to set GPIO%s direction to out\n", GPIO18);
        unexport_gpio(GPIO17);
        unexport_gpio(GPIO18);
        return EXIT_FAILURE;
    }

    printf("Motion detection started. Press Ctrl+C to exit.\n");

    while (running) {
        char value[2];
        if (read_gpio_value(GPIO17, value, sizeof(value)) == 0) {
            if (value[0] == '1') {
                printf("Motion detected!\n");
                if (is_night_time()) {
                    printf("Activating buzzer...\n");
                    if (write_gpio_value(GPIO18, "1") == 0) {
                        sleep(5);
                        if (write_gpio_value(GPIO18, "0") == 0) {
                            printf("Buzzer deactivated.\n");
                        } else {
                            fprintf(stderr, "Failed to deactivate buzzer (GPIO%s)\n", GPIO18);
                        }
                    } else {
                        fprintf(stderr, "Failed to activate buzzer (GPIO%s)\n", GPIO18);
                    }
                } else {
                    printf("Ignoring motion, not night time.\n");
                }
            }
        } else {
            fprintf(stderr, "Failed to read GPIO%s value\n", GPIO17);
        }
        sleep(1); // Check every second
    }

    // Unexport GPIOs on exit
    printf("Unexporting GPIOs...\n");
    unexport_gpio(GPIO17);
    unexport_gpio(GPIO18);

    printf("Exiting.\n");
    return EXIT_SUCCESS;
}

