#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>
#include <signal.h>
#include <unistd.h>
#include <math.h>

// BMP280 I2C address
#define BMP280_I2C_ADDR 0x76

// BMP280 register addresses
#define BMP280_REG_CALIB_00 0x88
#define BMP280_REG_ID 0xD0
#define BMP280_REG_CTRL_MEAS 0xF4
#define BMP280_REG_CONFIG 0xF5
#define BMP280_REG_PRESS_MSB 0xF7
#define BMP280_REG_TEMP_MSB 0xFA

// Relay GPIO pin (WiringPi pin number)
#define RELAY_PIN 17

// Pressure thresholds (hPa)
#define PRESSURE_LOW_THRESHOLD 990.0
#define PRESSURE_HIGH_THRESHOLD 995.0

// Global variables
static int i2c_fd;
static short dig_T1; // unsigned short
static short dig_T2;
static short dig_T3;
static unsigned short dig_P1;
static short dig_P2;
static short dig_P3;
static short dig_P4;
static short dig_P5;
static short dig_P6;
static short dig_P7;
static short dig_P8;
static short dig_P9;
static volatile int running = 1;

// Function prototypes
int read_register(int reg);
int write_register(int reg, int value);
int read_calibration_data();
void configure_sensor();
void read_raw_data(long* raw_temperature, long* raw_pressure);
double compensate_temperature(long raw_temperature);
double compensate_pressure(long raw_pressure, double t);
void control_relay(int state);
void log_data(double pressure, double temperature);
void signal_handler(int signal);

// Error handling and retry mechanism
int read_register_with_retry(int reg, int retries);
int write_register_with_retry(int reg, int value, int retries);


int read_register_with_retry(int reg, int retries) {
    int result = -1;
    for (int i = 0; i < retries; ++i) {
        result = wiringPiI2CReadReg8(i2c_fd, reg);
        if (result >= 0) {
            return result;
        }
        fprintf(stderr, "Error reading register 0x%X (attempt %d): %d\n", reg, i + 1, result);
        delay(10); // Short delay before retry
    }
    return -1; // Indicate failure after all retries
}

int write_register_with_retry(int reg, int value, int retries) {
    int result = -1;  //Initialize to -1 to indicate failure
    for (int i = 0; i < retries; ++i) {
        result = wiringPiI2CWriteReg8(i2c_fd, reg, value);
        if (result == 0) {
            return 0; // Success
        }
        fprintf(stderr, "Error writing to register 0x%X (attempt %d): %d\n", reg, i + 1, result);
        delay(10); // Short delay before retry
    }
    return -1; // Indicate failure after all retries
}


int main() {
    // Initialize WiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi initialization failed!\n");
        return 1;
    }

    // Initialize I2C
    i2c_fd = wiringPiI2CSetup(BMP280_I2C_ADDR);
    if (i2c_fd == -1) {
        fprintf(stderr, "I2C initialization failed!\n");
        return 1;
    }

    // Verify sensor ID
    int sensor_id = read_register_with_retry(BMP280_REG_ID, 3);
    if (sensor_id != 0x60) {
        fprintf(stderr, "Incorrect sensor ID: 0x%X\n", sensor_id);
        return 1;
    }

    // Read calibration data
    if (read_calibration_data() != 0) {
        fprintf(stderr, "Failed to read calibration data!\n");
        return 1;
    }

    // Configure the sensor
    configure_sensor();

    // Set relay pin as output
    pinMode(RELAY_PIN, OUTPUT);

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    double pressure, temperature;
    long raw_temperature, raw_pressure;

    // Main loop
    while (running) {
        // Read raw data
        read_raw_data(&raw_temperature, &raw_pressure);

        // Compensate temperature
        temperature = compensate_temperature(raw_temperature);

        // Compensate pressure
        pressure = compensate_pressure(raw_pressure, temperature);

        // Log data
        log_data(pressure, temperature);

        // Control relay based on pressure threshold
        if (pressure < PRESSURE_LOW_THRESHOLD) {
            control_relay(HIGH); // Activate relay
        } else if (pressure > PRESSURE_HIGH_THRESHOLD) {
            control_relay(LOW);  // Deactivate relay
        }

        delay(1000); // 1-second interval
    }

    return 0;
}

int read_register(int reg) {
    return wiringPiI2CReadReg8(i2c_fd, reg);
}

int write_register(int reg, int value) {
    return wiringPiI2CWriteReg8(i2c_fd, reg, value);
}

int read_calibration_data() {
    dig_T1 = (read_register_with_retry(BMP280_REG_CALIB_00, 3) | (read_register_with_retry(BMP280_REG_CALIB_00 + 1, 3) << 8));
    dig_T2 = (read_register_with_retry(BMP280_REG_CALIB_00 + 2, 3) | (read_register_with_retry(BMP280_REG_CALIB_00 + 3, 3) << 8));
    dig_T3 = (read_register_with_retry(BMP280_REG_CALIB_00 + 4, 3) | (read_register_with_retry(BMP280_REG_CALIB_00 + 5, 3) << 8));
    dig_P1 = (read_register_with_retry(BMP280_REG_CALIB_00 + 6, 3) | (read_register_with_retry(BMP280_REG_CALIB_00 + 7, 3) << 8));
    dig_P2 = (read_register_with_retry(BMP280_REG_CALIB_00 + 8, 3) | (read_register_with_retry(BMP280_REG_CALIB_00 + 9, 3) << 8));
    dig_P3 = (read_register_with_retry(BMP280_REG_CALIB_00 + 10, 3) | (read_register_with_retry(BMP280_REG_CALIB_00 + 11, 3) << 8));
    dig_P4 = (read_register_with_retry(BMP280_REG_CALIB_00 + 12, 3) | (read_register_with_retry(BMP280_REG_CALIB_00 + 13, 3) << 8));
    dig_P5 = (read_register_with_retry(BMP280_REG_CALIB_00 + 14, 3) | (read_register_with_retry(BMP280_REG_CALIB_00 + 15, 3) << 8));
    dig_P6 = (read_register_with_retry(BMP280_REG_CALIB_00 + 16, 3) | (read_register_with_retry(BMP280_REG_CALIB_00 + 17, 3) << 8));
    dig_P7 = (read_register_with_retry(BMP280_REG_CALIB_00 + 18, 3) | (read_register_with_retry(BMP280_REG_CALIB_00 + 19, 3) << 8));
    dig_P8 = (read_register_with_retry(BMP280_REG_CALIB_00 + 20, 3) | (read_register_with_retry(BMP280_REG_CALIB_00 + 21, 3) << 8));
    dig_P9 = (read_register_with_retry(BMP280_REG_CALIB_00 + 22, 3) | (read_register_with_retry(BMP280_REG_CALIB_00 + 23, 3) << 8));

    return 0;
}

void configure_sensor() {
    // Forced mode, oversampling x16 for pressure and temperature, filter coefficient of 4
    write_register_with_retry(BMP280_REG_CONFIG, 0x20, 3); // t_sb = 0.5ms, filter = 4
    write_register_with_retry(BMP280_REG_CTRL_MEAS, 0x2F, 3); // Oversampling x16, forced mode
}

void read_raw_data(long* raw_temperature, long* raw_pressure) {
    // Trigger a measurement by setting the sensor to forced mode
    write_register_with_retry(BMP280_REG_CTRL_MEAS, 0x2F, 3); // Oversampling x16, forced mode
    delay(100); // Wait for measurement to complete (adjust as needed)

    long msb, lsb, xlsb;

    msb = read_register_with_retry(BMP280_REG_PRESS_MSB, 3);
    lsb = read_register_with_retry(BMP280_REG_PRESS_MSB + 1, 3);
    xlsb = read_register_with_retry(BMP280_REG_PRESS_MSB + 2, 3);
    *raw_pressure = ((long)msb << 12) | ((long)lsb << 4) | ((long)xlsb >> 4);

    msb = read_register_with_retry(BMP280_REG_TEMP_MSB, 3);
    lsb = read_register_with_retry(BMP280_REG_TEMP_MSB + 1, 3);
    xlsb = read_register_with_retry(BMP280_REG_TEMP_MSB + 2, 3);
    *raw_temperature = ((long)msb << 12) | ((long)lsb << 4) | ((long)xlsb >> 4);
}


double compensate_temperature(long raw_temperature) {
    double var1, var2, T;
    double T_fine;

    var1 = (((double)raw_temperature) / 16384.0 - ((double)dig_T1) / 1024.0) * ((double)dig_T2);
    var2 = ((((double)raw_temperature) / 131072.0 - ((double)dig_T1) / 8192.0) * (((double)raw_temperature) / 131072.0 - ((double)dig_T1) / 8192.0)) * ((double)dig_T3);
    T_fine = (var1 + var2);
    T = (var1 + var2) / 5120.0;
    return T;
}

double compensate_pressure(long raw_pressure, double t) {
    double var1, var2, p;
    double T_fine;

    // Reuse T_fine from temperature compensation
    var1 = ((double)t) / 2.0 - 64000.0;
    var2 = var1 * var1 * ((double)dig_P6) / 32768.0;
    var2 = var2 + var1 * ((double)dig_P5) * 2.0;
    var2 = (var2 / 4.0) + (((double)dig_P4) * 65536.0);
    var1 = (((double)dig_P3) * var1 * var1 / 524288.0 + ((double)dig_P2) * var1) / 524288.0;
    var1 = (1.0 + var1 / 32768.0) * ((double)dig_P1);

    if (var1 == 0)
    {
        return 0; // avoid exception caused by division by zero
    }

    p = 1048576.0 - (double)raw_pressure;
    p = (p - (var2 / 4096.0)) * 6250.0 / var1;
    var1 = ((double)dig_P9) * p * p / 2147483648.0;
    var2 = p * ((double)dig_P8) / 32768.0;
    p = p + (var1 + var2 + ((double)dig_P7)) / 16.0;

    return p / 100.0; // in hPa
}

void control_relay(int state) {
    digitalWrite(RELAY_PIN, state);
}

void log_data(double pressure, double temperature) {
    printf("Pressure: %.2f hPa, Temperature: %.2f C\n", pressure, temperature);
}

void signal_handler(int signal) {
    running = 0;
    control_relay(LOW); // Deactivate relay on exit
    printf("Exiting...\n");
    exit(0);
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <stdint.h>
#include <string.h>
#include <errno.h>
#include <wiringPi.h>
#include <wiringPiSPI.h>
#include <time.h>

#define SPI_CHANNEL 0
#define NUM_ITERATIONS 100
#define MAX_TRANSFER_SIZE (1024 * 1024)
#define MIN_SPEED_MHZ 1
#define MAX_SPEED_MHZ 32

// Function prototypes
int spi_setup(int speed_hz);
void spi_transfer_test(int spi_fd, int speed_mhz, int transfer_size);

int main(void) {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return EXIT_FAILURE;
    }

    for (int speed_mhz = MIN_SPEED_MHZ; speed_mhz <= MAX_SPEED_MHZ; speed_mhz *= 2) {
        printf("+-------+--------+----------+----------+-----------+------------+\n");
        printf("|   MHz |   Size | mS/Trans |      TpS |    Mb/Sec | Latency mS |\n");
        printf("+-------+--------+----------+----------+-----------+------------+\n");

        int spi_fd = spi_setup(speed_mhz * 1000000); // Convert MHz to Hz
        if (spi_fd == -1) {
            continue; // Skip to the next speed if setup fails
        }

        for (int transfer_size = 1; transfer_size <= MAX_TRANSFER_SIZE; transfer_size *= 2) {
            spi_transfer_test(spi_fd, speed_mhz, transfer_size);
        }

        close(spi_fd);
        printf("+-------+--------+----------+----------+-----------+------------+\n");
        printf("\n");
    }

    return EXIT_SUCCESS;
}

// Initializes the SPI interface with the given speed.
int spi_setup(int speed_hz) {
    int spi_fd = wiringPiSPISetup(SPI_CHANNEL, speed_hz);
    if (spi_fd < 0) {
        fprintf(stderr, "Failed to open SPI bus at %d Hz: %s\n", speed_hz, strerror(errno));
        return -1; // Indicate failure
    }
    return spi_fd;
}

// Performs SPI transfer tests and prints the results.
void spi_transfer_test(int spi_fd, int speed_mhz, int transfer_size) {
    unsigned char *tx_buffer = malloc(transfer_size);
    if (tx_buffer == NULL) {
        fprintf(stderr, "Failed to allocate TX buffer of size %d: %s\n", transfer_size, strerror(errno));
        return; // Exit if allocation fails
    }

    unsigned char *rx_buffer = malloc(transfer_size);
     if (rx_buffer == NULL) {
        fprintf(stderr, "Failed to allocate RX buffer of size %d: %s\n", transfer_size, strerror(errno));
        free(tx_buffer);
        return; // Exit if allocation fails
    }

    // Initialize transmit buffer (optional: fill with some pattern)
    for (int i = 0; i < transfer_size; ++i) {
        tx_buffer[i] = (unsigned char)(i % 256); // Example pattern
    }

    struct timespec start_time, end_time;
    double total_time = 0.0;
    int spi_fail = 0;

    printf("| %5d | %6d ", speed_mhz, transfer_size);

    for (int i = 0; i < NUM_ITERATIONS; ++i) {
        clock_gettime(CLOCK_MONOTONIC, &start_time);
        int result = wiringPiSPIDataRW(SPI_CHANNEL, tx_buffer, transfer_size);
        clock_gettime(CLOCK_MONOTONIC, &end_time);

        if (result == -1) {
            fprintf(stderr, "SPI transfer failed: %s\n", strerror(errno));
            spi_fail = 1;
            break;
        }

        total_time += (end_time.tv_sec - start_time.tv_sec) + (end_time.tv_nsec - start_time.tv_nsec) / 1000000000.0;
    }

    if (spi_fail) {
        free(tx_buffer);
        free(rx_buffer);
        return;
    }

    double time_per_transaction = total_time / (double)NUM_ITERATIONS;
    double data_speed = ((double)transfer_size * 8.0) / (1024.0 * 1024.0) / time_per_transaction;
    double perfect_time_per_transaction = ((double)transfer_size * 8.0) / ((double)speed_mhz * 1000000.0);
    double latency = (time_per_transaction - perfect_time_per_transaction) * 1000.0;

    printf("| %8.3f ", time_per_transaction * 1000.0);
    printf("| %8.1f ", 1.0 / time_per_transaction);
    printf("| %9.5f ", data_speed);
    printf("|   %8.5f |\n", latency);

    free(tx_buffer);
    free(rx_buffer);
}

#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>

// Define GPIO pins for the seven-segment display
#define SEG_A 4
#define SEG_B 17
#define SEG_C 22
#define SEG_D 23
#define SEG_E 24
#define SEG_F 25
#define SEG_G 26

// Define GPIO pin for the button
#define BUTTON_PIN 27

// Function to display a digit on the seven-segment display
void displayDigit(int digit) {
    gpioWrite(SEG_A, 0); // Default off
    gpioWrite(SEG_B, 0);
    gpioWrite(SEG_C, 0);
    gpioWrite(SEG_D, 0);
    gpioWrite(SEG_E, 0);
    gpioWrite(SEG_F, 0);
    gpioWrite(SEG_G, 0);

    switch (digit) {
        case 4:
            gpioWrite(SEG_B, 1);
            gpioWrite(SEG_C, 1);
            gpioWrite(SEG_F, 1);
            gpioWrite(SEG_G, 1);
            break;
        case 7:
            gpioWrite(SEG_A, 1);
            gpioWrite(SEG_B, 1);
            gpioWrite(SEG_C, 1);
            break;
        default:
            // Handle invalid digit (optional)
            break;
    }
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pins as outputs for the seven-segment display
    gpioSetMode(SEG_A, PI_OUTPUT);
    gpioSetMode(SEG_B, PI_OUTPUT);
    gpioSetMode(SEG_C, PI_OUTPUT);
    gpioSetMode(SEG_D, PI_OUTPUT);
    gpioSetMode(SEG_E, PI_OUTPUT);
    gpioSetMode(SEG_F, PI_OUTPUT);
    gpioSetMode(SEG_G, PI_OUTPUT);

    // Set GPIO pin as input for the button with pull-up resistor
    gpioSetMode(BUTTON_PIN, PI_INPUT);
    gpioSetPullUpDown(BUTTON_PIN, PI_PUD_UP);

    int currentDigit = 4;
    int buttonState = 1; // Initialize to released state (pull-up resistor)
    int previousButtonState = 1;

    while (1) {
        buttonState = gpioRead(BUTTON_PIN);

        if (buttonState == 0 && previousButtonState == 1) { // Button pressed
            if (currentDigit == 4) {
                currentDigit = 7;
            } else {
                currentDigit = 4;
            }
            displayDigit(currentDigit);
        }

        previousButtonState = buttonState;
        gpioDelay(50); // Debounce delay
    }

    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>
#include <time.h>
#include <string.h>

// Constants
#define TCS34725_ADDR 0x29
#define LED_PIN 17

// TCS34725 Registers
#define TCS34725_ENABLE 0x80
#define TCS34725_ENABLE_PON 0x01
#define TCS34725_ENABLE_AEN 0x02
#define TCS34725_ID 0x12
#define TCS34725_CDATA 0x14
#define TCS34725_RDATA 0x16
#define TCS34725_GDATA 0x18
#define TCS34725_BDATA 0x1A

// Ripeness Stages
enum Ripeness {
    GREEN,
    YELLOW,
    RED
};

// Function Prototypes
int initTCS34725();
int readTCS34725(int *red, int *green, int *blue, int *clear);
enum Ripeness classifyRipeness(int red, int green, int blue, int clear);
void controlLED(enum Ripeness ripeness);
void logData(int red, int green, int blue, int clear, enum Ripeness ripeness);
char* timestamp();

// Global variables (minimal use)
int fd;
FILE *logFile;

int main() {
    // Initialize WiringPi with GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi initialization failed!\n");
        return 1;
    }

    // Initialize the TCS34725 sensor
    fd = initTCS34725();
    if (fd == -1) {
        fprintf(stderr, "TCS34725 initialization failed!\n");
        return 1;
    }

    // Configure LED pin as output
    pinMode(LED_PIN, OUTPUT);

    // Open the log file
    logFile = fopen("ripeness_log.txt", "a");
    if (logFile == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        return 1;
    }

    int red, green, blue, clear;
    enum Ripeness ripeness;

    while (1) {
        // Read sensor data
        if (readTCS34725(&red, &green, &blue, &clear) == 0) {
            // Classify ripeness
            ripeness = classifyRipeness(red, green, blue, clear);

            // Output ripeness to console
            switch (ripeness) {
                case GREEN:
                    printf("Ripeness: GREEN\n");
                    break;
                case YELLOW:
                    printf("Ripeness: YELLOW\n");
                    break;
                case RED:
                    printf("Ripeness: RED\n");
                    break;
                default:
                    printf("Ripeness: UNKNOWN\n");
                    break;
            }

            // Control LED
            controlLED(ripeness);

            // Log data
            logData(red, green, blue, clear, ripeness);
        } else {
            fprintf(stderr, "Error reading sensor data!\n");
            fprintf(logFile, "%s Error reading sensor data!\n", timestamp());
        }

        delay(1000); // Wait for 1 second
    }

    // Close the log file (this will never be reached in the infinite loop)
    fclose(logFile);

    return 0;
}

// Initialize the TCS34725 sensor
int initTCS34725() {
    int fd = wiringPiI2CSetup(TCS34725_ADDR);
    if (fd == -1) {
        fprintf(stderr, "Error initializing I2C communication!\n");
        return -1;
    }

    // Check the ID register
    int id = wiringPiI2CReadReg8(fd, TCS34725_ID);
    if (id != 0x44) {
        fprintf(stderr, "Error: Invalid sensor ID (0x%X)\n", id);
        return -1;
    }

    // Enable power and RGBC
    wiringPiI2CWriteReg8(fd, TCS34725_ENABLE, TCS34725_ENABLE_PON | TCS34725_ENABLE_AEN);

    printf("TCS34725 initialized successfully!\n");
    return fd;
}

// Read color data from the TCS34725 sensor
int readTCS34725(int *red, int *green, int *blue, int *clear) {
    *clear = wiringPiI2CReadReg16(fd, TCS34725_CDATA);
    *red   = wiringPiI2CReadReg16(fd, TCS34725_RDATA);
    *green = wiringPiI2CReadReg16(fd, TCS34725_GDATA);
    *blue  = wiringPiI2CReadReg16(fd, TCS34725_BDATA);

    // Handle potential I2C errors (negative return values)
    if (*clear < 0 || *red < 0 || *green < 0 || *blue < 0) {
        fprintf(stderr, "Error reading sensor data from I2C!\n");
        return -1; // Indicate an error
    }

    return 0; // Indicate success
}

// Classify ripeness based on RGB values
enum Ripeness classifyRipeness(int red, int green, int blue, int clear) {
    // Normalize RGB values
    float red_norm   = (float)red   / clear;
    float green_norm = (float)green / clear;
    float blue_norm  = (float)blue  / clear;

    if (green_norm > red_norm && green_norm > blue_norm) {
        return GREEN;
    } else if (red_norm > green_norm && red_norm > blue_norm && (float)red / green < 2.0) { // Added ratio check
        return YELLOW;
    } else if (red_norm > green_norm && red_norm > blue_norm) {
        return RED;
    } else {
        return GREEN; // Default to green if no condition is met
    }
}

// Control the LED based on ripeness
void controlLED(enum Ripeness ripeness) {
    if (ripeness == RED) {
        digitalWrite(LED_PIN, HIGH); // Turn LED on
    } else {
        digitalWrite(LED_PIN, LOW);  // Turn LED off
    }
}

// Log data to file
void logData(int red, int green, int blue, int clear, enum Ripeness ripeness) {
    char *currentTime = timestamp();
    fprintf(logFile, "%s R: %d, G: %d, B: %d, C: %d, Ripeness: ", currentTime, red, green, blue, clear);
    switch (ripeness) {
        case GREEN:
            fprintf(logFile, "GREEN\n");
            break;
        case YELLOW:
            fprintf(logFile, "YELLOW\n");
            break;
        case RED:
            fprintf(logFile, "RED\n");
            break;
        default:
            fprintf(logFile, "UNKNOWN\n");
            break;
    }
    fflush(logFile); // Ensure data is written to the file immediately
    free(currentTime); // Free the allocated memory for the timestamp
}

// Get current timestamp
char* timestamp() {
    time_t rawtime;
    struct tm *timeinfo;
    time(&rawtime);
    timeinfo = localtime(&rawtime);

    char *timestamp_str = (char*)malloc(25 * sizeof(char)); // Allocate memory for timestamp string
    if (timestamp_str == NULL) {
        perror("Failed to allocate memory for timestamp");
        return NULL; // Or handle the error as appropriate
    }

    strftime(timestamp_str, 25, "%Y-%m-%d %H:%M:%S", timeinfo);
    return timestamp_str;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>

// Define the GPIO pins
#define PIR_SENSOR_PIN 4
#define BUZZER_PIN 18

// Function to check if motion is detected
int isMotionDetected() {
    // Read the state of the PIR sensor pin
    int sensorValue = gpioRead(PIR_SENSOR_PIN);
    // Return 1 if motion is detected (HIGH), 0 otherwise
    return sensorValue;
}

// Function to activate the buzzer for 2 seconds
void activateBuzzer(int buzzerPin) {
    // Activate the buzzer by setting the GPIO HIGH
    if (gpioWrite(buzzerPin, 1) != 0) {
        fprintf(stderr, "Error: Failed to activate buzzer.\n");
        exit(EXIT_FAILURE);
    }

    // Wait for 2 seconds (2000000 microseconds)
    gpioDelay(2000000);

    // Deactivate the buzzer by setting the GPIO LOW
    if (gpioWrite(buzzerPin, 0) != 0) {
        fprintf(stderr, "Error: Failed to deactivate buzzer.\n");
        exit(EXIT_FAILURE);
    }
}

int main() {
    // Initialize the pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed.\n");
        exit(EXIT_FAILURE);
    }

    // Set GPIO 4 as an input (PIR sensor)
    if (gpioSetMode(PIR_SENSOR_PIN, PI_INPUT) != 0) {
        fprintf(stderr, "Error: Failed to set GPIO %d as input.\n", PIR_SENSOR_PIN);
        gpioTerminate();
        exit(EXIT_FAILURE);
    }

    // Set GPIO 18 as an output (buzzer)
    if (gpioSetMode(BUZZER_PIN, PI_OUTPUT) != 0) {
        fprintf(stderr, "Error: Failed to set GPIO %d as output.\n", BUZZER_PIN);
        gpioTerminate();
        exit(EXIT_FAILURE);
    }

    printf("Motion detection alert system started. Press Ctrl+C to exit.\n");

    // Main loop
    while (1) {
        // Check for motion
        if (isMotionDetected()) {
            printf("Motion detected! Activating buzzer.\n");
            // Activate the buzzer
            activateBuzzer(BUZZER_PIN);
            printf("Buzzer deactivated.\n");
        }

        // Small delay to avoid busy-waiting (adjust as needed)
        gpioDelay(100000); // 0.1 seconds
    }

    // Clean up before exiting
    gpioTerminate();

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>
#include <softPwm.h>
#include <signal.h>
#include <errno.h>

// TCS34725 I2C address
#define TCS34725_ADDRESS 0x29

// TCS34725 Registers
#define TCS34725_ENABLE 0x80
#define TCS34725_ATIME 0x81
#define TCS34725_CDATA 0x90
#define TCS34725_RDATA 0x92
#define TCS34725_GDATA 0x94
#define TCS34725_BDATA 0x96
#define TCS34725_AGAIN 0x8F

// RGB LED GPIO pins
#define RED_PIN 17
#define GREEN_PIN 18
#define BLUE_PIN 27

int i2c_fd;

// Function to read a register from the TCS34725
int tcs34725_read_register(int fd, unsigned char reg) {
    int result = wiringPiI2CReadReg8(fd, reg);
    if (result == -1) {
        fprintf(stderr, "Error reading register 0x%02x: %s\n", reg, strerror(errno));
        return -1;
    }
    return result;
}

// Function to write a register to the TCS34725
int tcs34725_write_register(int fd, unsigned char reg, unsigned char value) {
    int result = wiringPiI2CWriteReg8(fd, reg, value);
    if (result == -1) {
        fprintf(stderr, "Error writing register 0x%02x with value 0x%02x: %s\n", reg, value, strerror(errno));
        return -1;
    }
    return 0; // Return 0 on success
}

// Function to initialize the TCS34725 sensor
int tcs34725_init(int fd) {
    // Enable power and ADC
    if (tcs34725_write_register(fd, TCS34725_ENABLE, 0x03) == -1) {
        return -1;
    }

    // Set integration time
    if (tcs34725_write_register(fd, TCS34725_ATIME, 0xD5) == -1) {
        return -1;
    }

    // Set gain
    if (tcs34725_write_register(fd, TCS34725_AGAIN, 0x00) == -1) {
        return -1;
    }

    return 0;
}

// Function to read the clear, red, green, and blue values from the sensor
int tcs34725_read_crgb(int fd, unsigned int *clear, unsigned int *red, unsigned int *green, unsigned int *blue) {
    int c_low, c_high, r_low, r_high, g_low, g_high, b_low, b_high;

    c_low = tcs34725_read_register(fd, TCS34725_CDATA);
    c_high = tcs34725_read_register(fd, TCS34725_CDATA + 1);
    r_low = tcs34725_read_register(fd, TCS34725_RDATA);
    r_high = tcs34725_read_register(fd, TCS34725_RDATA + 1);
    g_low = tcs34725_read_register(fd, TCS34725_GDATA);
    g_high = tcs34725_read_register(fd, TCS34725_GDATA + 1);
    b_low = tcs34725_read_register(fd, TCS34725_BDATA);
    b_high = tcs34725_read_register(fd, TCS34725_BDATA + 1);

    if (c_low == -1 || c_high == -1 || r_low == -1 || r_high == -1 || g_low == -1 || g_high == -1 || b_low == -1 || b_high == -1) {
        return -1;
    }

    *clear = (unsigned int)(c_low | (c_high << 8));
    *red = (unsigned int)(r_low | (r_high << 8));
    *green = (unsigned int)(g_low | (g_high << 8));
    *blue = (unsigned int)(b_low | (b_high << 8));

    return 0;
}

// Function to set the RGB LED color using PWM
void led_set_color(int red_pin, int green_pin, int blue_pin, unsigned int red_val, unsigned int green_val, unsigned int blue_val) {
    // Map the 16-bit color values (0-65535) to PWM duty cycle (0-100)
    int red_duty = (int)(((float)red_val / 65535.0) * 100.0);
    int green_duty = (int)(((float)green_val / 65535.0) * 100.0);
    int blue_duty = (int)(((float)blue_val / 65535.0) * 100.0);

    softPwmWrite(red_pin, red_duty);
    softPwmWrite(green_pin, green_duty);
    softPwmWrite(blue_pin, blue_duty);
}

// Cleanup handler to turn off the LED and close I2C on program exit
void cleanup_handler(int signum) {
    printf("Cleaning up and exiting...\n");
    softPwmWrite(RED_PIN, 0);
    softPwmWrite(GREEN_PIN, 0);
    softPwmWrite(BLUE_PIN, 0);
    close(i2c_fd);
    exit(0);
}

int main() {
    unsigned int clear, red, green, blue;

    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
        return 1;
    }

    // Initialize I2C
    i2c_fd = wiringPiI2CSetup(TCS34725_ADDRESS);
    if (i2c_fd == -1) {
        fprintf(stderr, "Error initializing I2C: %s\n", strerror(errno));
        return 1;
    }

    // Initialize TCS34725 sensor
    if (tcs34725_init(i2c_fd) == -1) {
        fprintf(stderr, "Error initializing TCS34725 sensor.\n");
        return 1;
    }

    // Set up PWM for RGB LED pins
    softPwmCreate(RED_PIN, 0, 100);
    softPwmCreate(GREEN_PIN, 0, 100);
    softPwmCreate(BLUE_PIN, 0, 100);

    // Register the cleanup handler
    signal(SIGINT, cleanup_handler);

    // Main loop
    while (1) {
        // Read CRGB values from the sensor
        if (tcs34725_read_crgb(i2c_fd, &clear, &red, &green, &blue) == -1) {
            fprintf(stderr, "Error reading CRGB values.\n");
        } else {
            // Print the CRGB values
            printf("C: %5u, R: %5u, G: %5u, B: %5u\n", clear, red, green, blue);

            // Set the RGB LED color
            led_set_color(RED_PIN, GREEN_PIN, BLUE_PIN, red, green, blue);
        }

        // Delay
        delay(100);
    }

    return 0;
}

