#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <math.h>

// ADS1115 I2C address (default)
#define ADS1115_ADDRESS 0x48

// ADS1115 register addresses
#define ADS1115_REG_CONFIG 0x01
#define ADS1115_REG_CONVERT 0x00

// ADS1115 configuration register settings
#define ADS1115_CONFIG_OS_SINGLE 0x8000  // Start single-conversion
#define ADS1115_CONFIG_MUX_SINGLE_0 0x4000 // AIN0 single-ended
#define ADS1115_CONFIG_PGA_4_096V 0x0200   // +/-4.096V range = Gain 2
#define ADS1115_CONFIG_MODE_SINGLE 0x0100  // Single-shot mode
#define ADS1115_CONFIG_DR_128SPS 0x0060    // 128 SPS
#define ADS1115_CONFIG_COMP_QUE_DISABLE 0x0003 // Disable comparator

int i2c_fd;

// Function to initialize I2C
int i2c_init(int address) {
    int fd = open("/dev/i2c-1", O_RDWR);
    if (fd < 0) {
        perror("Error opening I2C device");
        return -1;
    }

    if (ioctl(fd, I2C_SLAVE, address) < 0) {
        perror("Error setting I2C slave address");
        close(fd);
        return -1;
    }

    return fd;
}

// Function to write a 16-bit value to an I2C register
int i2c_write_register(int fd, uint8_t reg, uint16_t value) {
    uint8_t buf[3];
    buf[0] = reg;
    buf[1] = (value >> 8) & 0xFF; // MSB
    buf[2] = value & 0xFF;        // LSB

    if (write(fd, buf, 3) != 3) {
        perror("Error writing to I2C register");
        return -1;
    }
    return 0;
}

// Function to read a 16-bit value from an I2C register
int i2c_read_register(int fd, uint8_t reg, uint16_t *value) {
    uint8_t buf[1];
    buf[0] = reg;

    if (write(fd, buf, 1) != 1) {
        perror("Error writing to I2C register (for read)");
        return -1;
    }

    uint8_t read_buf[2];
    if (read(fd, read_buf, 2) != 2) {
        perror("Error reading from I2C register");
        return -1;
    }

    *value = (read_buf[0] << 8) | read_buf[1];
    return 0;
}

int main() {
    float voltage;
    uint16_t config;
    uint16_t conversion;

    i2c_fd = i2c_init(ADS1115_ADDRESS);
    if (i2c_fd < 0) {
        return 1;
    }

    // Configure ADS1115 for single-ended AIN0, +/-4.096V, single-shot mode, 128 SPS
    config = ADS1115_CONFIG_OS_SINGLE | ADS1115_CONFIG_MUX_SINGLE_0 | ADS1115_CONFIG_PGA_4_096V | ADS1115_CONFIG_MODE_SINGLE | ADS1115_CONFIG_DR_128SPS | ADS1115_CONFIG_COMP_QUE_DISABLE;

    while (1) {
        // Start a single conversion
        if (i2c_write_register(i2c_fd, ADS1115_REG_CONFIG, config) < 0) {
            close(i2c_fd);
            return 1;
        }

        // Wait for conversion to complete (at least 8ms for 128 SPS)
        usleep(10000); // 10ms

        // Read the conversion result
        if (i2c_read_register(i2c_fd, ADS1115_REG_CONVERT, &conversion) < 0) {
            close(i2c_fd);
            return 1;
        }

        // Calculate voltage (assuming +/-4.096V range)
        voltage = (float)conversion * 4.096 / 32768.0;

        printf("AIN0 Voltage: %.4f V\n", voltage);

        // Wait before next measurement
        usleep(500000); // 0.5 seconds
    }

    close(i2c_fd);
    return 0;
}

#include <pigpio.h>
#include <stdio.h>
#include <time.h>
#define ALPHA 0.3
int read_adc(int spi, int ch) {
    char tx[3] = {1, (0x80 | (ch << 4)), 0}, rx[3];
    spiXfer(spi, tx, rx, 3);
    return ((rx[1] & 3) << 8) | rx[2];
}
int main() {
    if (gpioInitialise() < 0) return 1;
    int spi = spiOpen(0, 1000000, 0);
    FILE* f = fopen("lpf_adc_log.csv", "w");
    fprintf(f, "Time,Filtered\n");
    double y = 0;
    while (1) {
        int x = read_adc(spi, 0);
        y = ALPHA * x + (1 - ALPHA) * y;
        time_t t = time(NULL);
        fprintf(f, "%ld,%.2f\n", t, y);
        fflush(f);
        gpioDelay(200000);
    }
    fclose(f);
    spiClose(spi);
    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <pigpio.h>

#define LED_PIN 19
#define BUTTON_PIN 26

int main() {
    if (gpioInitialise() < 0) {
        printf("pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(LED_PIN, PI_OUTPUT);
    gpioSetMode(BUTTON_PIN, PI_INPUT);
    gpioSetPullUpDown(BUTTON_PIN, PI_PUD_UP); // Enable pull-up resistor

    int brightness = 0; // Initial brightness
    int button_state = 1; // Assume button is initially not pressed (pulled up)

    while (1) {
        int current_button_state = gpioRead(BUTTON_PIN);

        if (current_button_state == 0 && button_state == 1) { // Button pressed (transition from high to low)
            brightness += 50; // Increase brightness
            if (brightness > 255) {
                brightness = 0; // Reset to minimum if brightness exceeds maximum
            }
            gpioPWM(LED_PIN, brightness); // Set new brightness
            printf("Brightness: %d\n", brightness);

            // Debounce the button
            gpioDelay(200); // Wait 200ms
        }
        button_state = current_button_state; // Update button state

        gpioDelay(10); // Small delay to avoid busy-waiting
    }

    gpioTerminate();
    return 0;
}

