// MPR121 Registers
#define MPR121_TOUCHSTATUS_L 0x00
#define MPR121_TOUCHSTATUS_H 0x01
#define MPR121_ELECTRODE_CONFIG 0x5E
#define MPR121_RESET 0x80

// Electrode thresholds
#define TOUCH_THRESHOLD 40
#define RELEASE_THRESHOLD 20

int i2c_fd;

// Function to open I2C device
int i2c_open(char *device) {
    int fd = open(device, O_RDWR);
    if (fd < 0) {
        perror("Error opening I2C device");
        return -1;
    }
    return fd;
}

// Function to write a byte to an I2C register
int i2c_write_byte(int fd, unsigned char reg, unsigned char value) {
    unsigned char buf[2];
    buf[0] = reg;
    buf[1] = value;
    if (write(fd, buf, 2) != 2) {
        perror("Error writing to I2C device");
        return -1;
    }
    return 0;
}

// Function to read a byte from an I2C register
int i2c_read_byte(int fd, unsigned char reg) {
    unsigned char buf[1];
    buf[0] = reg;
    if (write(fd, buf, 1) != 1) {
        perror("Error writing register address for read");
        return -1;
    }
    if (read(fd, buf, 1) != 1) {
        perror("Error reading from I2C device");
        return -1;
    }
    return buf[0];
}

// Function to initialize the MPR121
int mpr121_init(int fd) {
    // Reset MPR121
    if (i2c_write_byte(fd, MPR121_RESET, 0x63) < 0) return -1;
    usleep(1000); // Wait for reset

    // Configure touch and release thresholds for all electrodes
    for (int i = 0; i < 12; i++) {
        if (i2c_write_byte(fd, 0x41 + (i * 2), TOUCH_THRESHOLD) < 0) return -1; // Touch Threshold
        if (i2c_write_byte(fd, 0x42 + (i * 2), RELEASE_THRESHOLD) < 0) return -1; // Release Threshold
    }

    // Configure Electrode Enable register to enable all electrodes
    if (i2c_write_byte(fd, MPR121_ELECTRODE_CONFIG, 0x3F) < 0) return -1; // Enable electrodes 0-5
    if (i2c_write_byte(fd, 0x5D, 0x00) < 0) return -1; // Enable electrodes 6-11

    // Enter Electrode Enable mode
    if (i2c_write_byte(fd, MPR121_ELECTRODE_CONFIG, 0x90) < 0) return -1; // Enable Proximity Detection
    usleep(5000); //5ms delay
    if (i2c_write_byte(fd, MPR121_ELECTRODE_CONFIG, 0x10) < 0) return -1; // Enable Electrode mode
    return 0;
}

// Function to read the MPR121 touch status
int mpr121_read_touch_status(int fd) {
    int touch_status_l = i2c_read_byte(fd, MPR121_TOUCHSTATUS_L);
    int touch_status_h = i2c_read_byte(fd, MPR121_TOUCHSTATUS_H);

    if (touch_status_l < 0 || touch_status_h < 0) return -1;

    return (touch_status_h << 8) | touch_status_l;
}

// Function to export a GPIO pin
int gpio_export(int gpio) {
    char buffer[3];
    int fd = open("/sys/class/gpio/export", O_WRONLY);
    if (fd < 0) {
        perror("Error opening /sys/class/gpio/export");
        return -1;
    }
    int len = snprintf(buffer, sizeof(buffer), "%d", gpio);
    if (write(fd, buffer, len) != len) {
        perror("Error writing to /sys/class/gpio/export");
        close(fd);
        return -1;
    }
    close(fd);
    return 0;
}

// Function to set the GPIO direction
int gpio_set_direction(int gpio, char *direction) {
    char path[64];
    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/direction", gpio);
    int fd = open(path, O_WRONLY);
    if (fd < 0) {
        perror("Error opening GPIO direction file");
        return -1;
    }
    if (write(fd, direction, strlen(direction)) != strlen(direction)) {
        perror("Error writing to GPIO direction file");
        close(fd);
        return -1;
    }
    close(fd);
    return 0;
}

// Function to set the GPIO value
int gpio_set_value(int gpio, int value) {
    char path[64];
    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", gpio);
    int fd = open(path, O_WRONLY);
    if (fd < 0) {
        perror("Error opening GPIO value file");
        return -1;
    }
    char val_str[2];
    snprintf(val_str, sizeof(val_str), "%d", value);
    if (write(fd, val_str, 1) != 1) {
        perror("Error writing to GPIO value file");
        close(fd);
        return -1;
    }
    close(fd);
    return 0;
}

// Function to unexport a GPIO pin
int gpio_unexport(int gpio) {
    char buffer[3];
    int fd = open("/sys/class/gpio/unexport", O_WRONLY);
    if (fd < 0) {
        perror("Error opening /sys/class/gpio/unexport");
        return -1;
    }
    int len = snprintf(buffer, sizeof(buffer), "%d", gpio);
    if (write(fd, buffer, len) != len) {
        perror("Error writing to /sys/class/gpio/unexport");
        close(fd);
        return -1;
    }
    close(fd);
    return 0;
}

// Buzzer control functions
int buzzer_on() {
    return gpio_set_value(GPIO_PIN, 1);
}

int buzzer_off() {
    return gpio_set_value(GPIO_PIN, 0);
}

// Logging function
void log_touch(int electrode) {
    FILE *fp = fopen("touch_log.txt", "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return;
    }
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(fp, "%d-%02d-%02d %02d:%02d:%02d: Electrode %d touched\n", tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, electrode);
    fclose(fp);
}

void cleanup() {
    buzzer_off();
    gpio_unexport(GPIO_PIN);
    close(i2c_fd);
    printf("Cleanup complete. Exiting.\n");
}

int main() {
    const char *i2c_device = "/dev/i2c-1";
    int touch_status;

    // Register cleanup function
    atexit(cleanup);

    // Open I2C device
    i2c_fd = i2c_open(i2c_device);
    if (i2c_fd < 0) {
        return 1;
    }

    // Set I2C slave address
    if (ioctl(i2c_fd, I2C_SLAVE, MPR121_ADDR) < 0) {
        perror("Error setting I2C slave address");
        close(i2c_fd);
        return 1;
    }

    // Initialize MPR121
    if (mpr121_init(i2c_fd) < 0) {
        fprintf(stderr, "MPR121 initialization failed.\n");
        close(i2c_fd);
        return 1;
    }

    // Export GPIO pin for buzzer
    if (gpio_export(GPIO_PIN) < 0) {
        close(i2c_fd);
        return 1;
    }

    // Set GPIO direction to output
    if (gpio_set_direction(GPIO_PIN, "out") < 0) {
        gpio_unexport(GPIO_PIN);
        close(i2c_fd);
        return 1;
    }

    printf("MPR121 and Buzzer initialized. Ready to detect touch.\n");

    while (1) {
        // Read touch status
        touch_status = mpr121_read_touch_status(i2c_fd);
        if (touch_status < 0) {
            fprintf(stderr, "Error reading touch status.\n");
            break;
        }

        // Check for touch on any electrode
        if (touch_status > 0) {
            // Activate buzzer
            buzzer_on();

            // Log the touch event
            for (int i = 0; i < 12; i++) {
                if (touch_status & (1 << i)) {
                    log_touch(i);
                }
            }

            // Delay to prevent multiple triggers
            usleep(100000); // 100ms

            // Deactivate buzzer
            buzzer_off();
        }

        usleep(50000); // Short delay
    }

    return 0;
}

#include <stdio.h>
