// Define GPIO pins
#define IR_SENSOR_PIN 17
#define RELAY_PIN 18

// Define distance threshold (adjust based on your sensor readings)
#define DISTANCE_THRESHOLD 500  // Example value.  Calibrate this.

// Define debounce delay (in milliseconds)
#define DEBOUNCE_DELAY 500

// Global variables
FILE *log_file = NULL;
volatile sig_atomic_t program_running = 1;

// Function prototypes
int initialize();
int read_ir_sensor();
void activate_relay();
void log_event();
void cleanup(int signal);

// Signal handler for Ctrl+C
void cleanup(int signal) {
    if (signal == SIGINT) {
        fprintf(stderr, "\nCaught signal SIGINT, exiting gracefully.\n");
        program_running = 0;

        // Cleanup GPIO pins
        pinMode(RELAY_PIN, INPUT); // Set relay pin to INPUT to avoid leaving it activated
        pinMode(IR_SENSOR_PIN, INPUT);

        // Close the log file
        if (log_file != NULL) {
            fclose(log_file);
            log_file = NULL;
        }

        wiringPiSetup(); // Reinitialize to ensure wiringPi is set up
        digitalWrite(RELAY_PIN, LOW); // Ensure relay is off

        exit(0);
    }
}

int main() {
    // Set up signal handling for Ctrl+C
    signal(SIGINT, cleanup);

    // Initialize the program
    if (initialize() != 0) {
        fprintf(stderr, "Initialization failed. Exiting.\n");
        return 1;
    }

    // Main loop
    while (program_running) {
        int distance = read_ir_sensor();

        if (distance < DISTANCE_THRESHOLD) {
            activate_relay();
            log_event();
            delay(DEBOUNCE_DELAY); // Debounce
        }

        delay(100); // Small delay to prevent busy-waiting
    }

    return 0;
}

// Initializes wiringPi and the log file.
