    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPi initialization failed: %s\n", strerror(errno));
        return -1;
    }

    // Set pin modes
    pinMode(IR_SENSOR_PIN, INPUT); // IR sensor is an analog input, but we're reading it digitally for simplicity
    pinMode(RELAY_PIN, OUTPUT);
    digitalWrite(RELAY_PIN, LOW); // Ensure relay is initially off

    // Open the log file
    log_file = fopen("door_log.txt", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Failed to open log file: %s\n", strerror(errno));
        return -1;
    }

    return 0;
}

