    // In a real application, you would use an ADC to read the analog voltage.
    // Since wiringPi doesn't directly provide an analogRead() function,
    // this example uses a placeholder.  A real implementation would
    // involve setting up an ADC (e.g., using an MCP3008 chip) and reading
    // the value from it. For now, we'll simulate a reading.
    // Note: the return value is an integer representing a distance-related value.

    // Simulate reading from the IR sensor (replace with actual ADC reading)
    int sensorValue = analogRead(IR_SENSOR_PIN); // Replace with ADC read
    return sensorValue;
}

// Activates the relay for 2 seconds.
void activate_relay() {
    digitalWrite(RELAY_PIN, HIGH); // Activate the relay
    delay(2000);                   // Wait for 2 seconds
    digitalWrite(RELAY_PIN, LOW);  // Deactivate the relay
}

// Logs the door opening event to the log file.
void log_event() {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

