#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pigpio.h>

// Define GPIO pins
#define SOUND_SENSOR_PIN 4
#define LED_PIN 27

// Define sampling parameters
#define SAMPLE_PERIOD_US 10000 // 10 milliseconds
#define NUM_SAMPLES 500       // 5 seconds * 100 samples/second

// Define sound level threshold
#define SOUND_THRESHOLD 2000

// Global variables
int samples[NUM_SAMPLES];
int sample_index = 0;
int running = 1;

// Function prototypes
int read_sound_sensor();
double calculate_average(int *samples, int num_samples);
void control_led(int state);
void signal_handler(int signal);

// Function to read the sound sensor
int read_sound_sensor() {
    int value = gpioRead(SOUND_SENSOR_PIN);
    if (value < 0) {
        fprintf(stderr, "Error reading sound sensor: %d\n", value);
        return -1; // Indicate error
    }
    return (value == 0) ? 1 : 0; // Active low: 0 indicates sound detected
}

// Function to calculate the average of an array of integers
double calculate_average(int *samples, int num_samples) {
    double sum = 0;
    for (int i = 0; i < num_samples; i++) {
        sum += samples[i];
    }
    return sum / num_samples;
}

// Function to control the LED
void control_led(int state) {
    gpioWrite(LED_PIN, state);
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, exiting gracefully.\n", signal);
    running = 0;
    control_led(0); // Turn off LED
    gpioTerminate(); // Terminate pigpio
    exit(0);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(SOUND_SENSOR_PIN, PI_INPUT);
    gpioSetMode(LED_PIN, PI_OUTPUT);

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Sound level monitoring started. Press Ctrl+C to exit.\n");

    // Main loop
    while (running) {
        // Read sound sensor
        int sound_level = read_sound_sensor();
        if (sound_level == -1) { // Error reading sensor
            gpioDelay(SAMPLE_PERIOD_US); // Wait before retrying
            continue; // Skip to the next iteration
        }

        // Store the sound level in the circular buffer
        samples[sample_index] = sound_level;
        sample_index = (sample_index + 1) % NUM_SAMPLES;

        // Calculate the average sound level
        double average_level = calculate_average(samples, NUM_SAMPLES);

        // Check if the average exceeds the threshold
        if (average_level > SOUND_THRESHOLD) {
            printf("Sound detected! Average level: %.2f\n", average_level);
            control_led(1); // Turn on LED
            gpioDelay(1000000); // Wait for 1 second
            control_led(0); // Turn off LED
        }

        // Wait for the next sample
        gpioDelay(SAMPLE_PERIOD_US);
    }

    // Cleanup (should not be reached if signal handler works correctly)
    control_led(0); // Turn off LED
    gpioTerminate(); // Terminate pigpio

    return 0;
}

#include <pigpio.h>
#include <stdio.h>
#define INA1 17  // BCM GPIO 17
#define INA2 27  // BCM GPIO 27
#define ENA  22  // BCM GPIO 22

void setup() {
    if (gpioInitialise() < 0) return;
    gpioSetMode(INA1, PI_OUTPUT);
    gpioSetMode(INA2, PI_OUTPUT);
    gpioSetMode(ENA, PI_OUTPUT);
}

void forward() {
    gpioWrite(INA1, 1);
    gpioWrite(INA2, 0);
    gpioPWM(ENA, 100);
}

void stopMotor() {
    gpioWrite(INA1, 0);
    gpioWrite(INA2, 0);
    gpioPWM(ENA, 0);
}

int main() {
    setup();
    while (1) {
        forward();
        gpioDelay(1000000);
        stopMotor();
        gpioDelay(2000000);
    }
    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <unistd.h>
#include <fcntl.h>
#include <signal.h>
#include <time.h>

#define GPIO17 17  // TTP223 sensor input
#define GPIO18 18  // Fan relay output

// Function prototypes
int gpio_export(int gpio);
int gpio_unexport(int gpio);
int gpio_set_direction(int gpio, const char *direction);
int gpio_read_value(int gpio);
int gpio_write_value(int gpio, int value);
int read_touch_sensor();
int control_fan(int state);
int log_event(int touch_state, int fan_state);
void signal_handler(int signal);

// Global variable to track program termination for signal handling
volatile sig_atomic_t program_running = 1;

int main() {
    // Install signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Export GPIO pins
    if (gpio_export(GPIO17) == -1 || gpio_export(GPIO18) == -1) {
        fprintf(stderr, "Failed to export GPIO pins. Exiting.\n");
        return 1;
    }

    // Set GPIO17 as input
    if (gpio_set_direction(GPIO17, "in") == -1) {
        fprintf(stderr, "Failed to set GPIO17 as input. Exiting.\n");
        gpio_unexport(GPIO17);
        gpio_unexport(GPIO18);
        return 1;
    }

    // Set GPIO18 as output
    if (gpio_set_direction(GPIO18, "out") == -1) {
        fprintf(stderr, "Failed to set GPIO18 as output. Exiting.\n");
        gpio_unexport(GPIO17);
        gpio_unexport(GPIO18);
        return 1;
    }

    printf("Smart Greenhouse Fan Control started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        int touch_state = read_touch_sensor();
        int fan_state;

        if (touch_state == 1) {
            fan_state = control_fan(1);
        } else {
            fan_state = control_fan(0);
        }

        log_event(touch_state, fan_state);

        // Delay to prevent excessive CPU usage
        struct timespec delay;
        delay.tv_sec = 0;
        delay.tv_nsec = 50 * 1000 * 1000; // 50ms
        nanosleep(&delay, NULL);
    }

    // Clean up GPIO pins before exiting
    gpio_unexport(GPIO17);
    gpio_unexport(GPIO18);

    printf("Smart Greenhouse Fan Control stopped.\n");

    return 0;
}

// Function to export a GPIO pin
int gpio_export(int gpio) {
    char buffer[64];
    int len;
    int fd;

    fd = open("/sys/class/gpio/export", O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "gpio_export: Failed to open export for writing: %s\n", strerror(errno));
        return -1;
    }

    len = snprintf(buffer, sizeof(buffer), "%d", gpio);
    if (write(fd, buffer, len) < 0) {
        fprintf(stderr, "gpio_export: Failed to write to export: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to unexport a GPIO pin
int gpio_unexport(int gpio) {
    char buffer[64];
    int len;
    int fd;

    fd = open("/sys/class/gpio/unexport", O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "gpio_unexport: Failed to open unexport for writing: %s\n", strerror(errno));
        return -1;
    }

    len = snprintf(buffer, sizeof(buffer), "%d", gpio);
    if (write(fd, buffer, len) < 0) {
        fprintf(stderr, "gpio_unexport: Failed to write to unexport: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to set the direction of a GPIO pin (in or out)
int gpio_set_direction(int gpio, const char *direction) {
    char path[64];
    int fd;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/direction", gpio);
    fd = open(path, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "gpio_set_direction: Failed to open direction for writing: %s\n", strerror(errno));
        return -1;
    }

    if (write(fd, direction, strlen(direction)) < 0) {
        fprintf(stderr, "gpio_set_direction: Failed to write to direction: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to read the value of a GPIO pin
int gpio_read_value(int gpio) {
    char path[64];
    char value_str[3];
    int fd;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", gpio);
    fd = open(path, O_RDONLY);
    if (fd < 0) {
        fprintf(stderr, "gpio_read_value: Failed to open value for reading: %s\n", strerror(errno));
        return -1;
    }

    if (read(fd, value_str, 3) < 0) {
        fprintf(stderr, "gpio_read_value: Failed to read value: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return atoi(value_str);
}

// Function to write a value to a GPIO pin
int gpio_write_value(int gpio, int value) {
    char path[64];
    char value_str[3];
    int fd;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", gpio);
    fd = open(path, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "gpio_write_value: Failed to open value for writing: %s\n", strerror(errno));
        return -1;
    }

    snprintf(value_str, sizeof(value_str), "%d", value);
    if (write(fd, value_str, strlen(value_str)) < 0) {
        fprintf(stderr, "gpio_write_value: Failed to write value: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to read the touch sensor value with debouncing
int read_touch_sensor() {
    int i;
    int readings[5]; // Take 5 readings
    int sum = 0;

    for (i = 0; i < 5; i++) {
        readings[i] = gpio_read_value(GPIO17);
        if (readings[i] == -1) {
            fprintf(stderr, "Error reading touch sensor value.\n");
            return 0; // Or handle the error as appropriate
        }
        struct timespec delay;
        delay.tv_sec = 0;
        delay.tv_nsec = 2 * 1000 * 1000; // 2ms delay
        nanosleep(&delay, NULL);
    }

    for (i = 0; i < 5; i++) {
        sum += readings[i];
    }

    // Consider it a touch if all or most readings are high
    return (sum >= 3) ? 1 : 0;
}

// Function to control the fan
int control_fan(int state) {
    if (gpio_write_value(GPIO18, state) == -1) {
        fprintf(stderr, "Failed to control fan.  Attempted state: %d\n", state);
        return -1;
    }
    return state; // Return the state to confirm the intended action
}

// Function to log events to a file
int log_event(int touch_state, int fan_state) {
    FILE *fp;
    time_t rawtime;
    struct tm *timeinfo;
    char filename[] = "touch_log.txt";
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fp = fopen(filename, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        return -1;
    }

    fprintf(fp, "%s, Touch: %d, Fan: %d\n", timestamp, touch_state, fan_state);

    fclose(fp);
    return 0;
}

// Signal handler to catch Ctrl+C and exit gracefully
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("Ctrl+C pressed. Exiting...\n");
        program_running = 0;
    }
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/spi/spidev.h>
#include <errno.h>
#include <string.h>

#define SPI_DEV "/dev/spidev0.0"
#define SPI_MODE SPI_MODE_0
#define SPI_BITS_PER_WORD 8
#define SPI_SPEED 1000000 // 1 MHz

int spi_fd;

int spi_setup()
{
    spi_fd = open(SPI_DEV, O_RDWR);
    if (spi_fd < 0) {
        perror("Error opening SPI device");
        return -1;
    }

    uint8_t mode = SPI_MODE;
    if (ioctl(spi_fd, SPI_IOC_WR_MODE, &mode) == -1) {
        perror("Error setting SPI mode");
        close(spi_fd);
        return -1;
    }

    uint8_t bits = SPI_BITS_PER_WORD;
    if (ioctl(spi_fd, SPI_IOC_WR_BITS_PER_WORD, &bits) == -1) {
        perror("Error setting bits per word");
        close(spi_fd);
        return -1;
    }

    uint32_t speed = SPI_SPEED;
    if (ioctl(spi_fd, SPI_IOC_WR_MAX_SPEED_HZ, &speed) == -1) {
        perror("Error setting max speed");
        close(spi_fd);
        return -1;
    }

    return 0;
}

int spi_transfer(unsigned char *data, int len)
{
    struct spi_ioc_transfer tr = {
        .tx_buf = (unsigned long)data,
        .rx_buf = (unsigned long)data,
        .len = len,
        .delay_usecs = 0,
        .speed_hz = SPI_SPEED,
        .bits_per_word = SPI_BITS_PER_WORD,
    };

    if (ioctl(spi_fd, SPI_IOC_MESSAGE(1), &tr) < 1) {
        perror("Error sending SPI message");
        return -1;
    }
    return 0;
}

int read_mcp3008(int channel)
{
    unsigned char tx_buf[3];
    unsigned char rx_buf[3];

    // Construct SPI message for MCP3008
    tx_buf[0] = 0x01; // Start bit
    tx_buf[1] = (0x08 | channel) << 4; // Single-ended mode, channel selection
    tx_buf[2] = 0x00; // Dummy byte

    if (spi_transfer(tx_buf, 3) < 0) {
        fprintf(stderr, "SPI transfer failed\n");
        return -1;
    }

    // Extract ADC value from response
    int adc_value = ((rx_buf[1] & 0x03) << 8) + rx_buf[2];
    return adc_value;
}

