#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <curl/curl.h>
#include <wiringPi.h>

// Configuration
#define GPIO_PIN 18
#define API_ENDPOINT "http://example.com/api/temperature"
#define LOG_FILE "heating_log.txt"
#define CURRENT_TEMPERATURE 20.0 // Constant current temperature
#define KP 1.0                   // Proportional gain
#define PWM_RANGE 100
#define API_RETRY_DELAY 60        // Seconds
#define LOOP_DELAY 10           // Seconds

// Global variables
static volatile int keep_running = 1;
static FILE *log_file = NULL;

// Structure to hold the API response data
typedef struct {
  char *data;
  size_t size;
} ApiResponse;

// Function prototypes
size_t write_callback(char *ptr, size_t size, size_t nmemb, void *userdata);
double fetch_temperature(void);
int control_heating_element(double target_temperature);
int log_data(double target_temperature, double duty_cycle);
void signal_handler(int sig);

// Callback function to handle the API response
size_t write_callback(char *ptr, size_t size, size_t nmemb, void *userdata) {
  ApiResponse *api_response = (ApiResponse *)userdata;
  size_t new_size = api_response->size + size * nmemb;

  api_response->data = realloc(api_response->data, new_size + 1);
  if (api_response->data == NULL) {
    fprintf(stderr, "realloc() failed\n");
    return 0;
  }
  memcpy(api_response->data + api_response->size, ptr, size * nmemb);
  api_response->data[new_size] = '\0';
  api_response->size = new_size;

  return size * nmemb;
}

// Function to fetch the temperature from the REST API
double fetch_temperature(void) {
  CURL *curl;
  CURLcode res;
  double temperature = -1000.0; // Initialize with an invalid value
  ApiResponse api_response = {NULL, 0};

  curl_global_init(CURL_GLOBAL_DEFAULT);
  curl = curl_easy_init();
  if (curl) {
    curl_easy_setopt(curl, CURLOPT_URL, API_ENDPOINT);
    curl_easy_setopt(curl, CURLOPT_WRITEFUNCTION, write_callback);
    curl_easy_setopt(curl, CURLOPT_WRITEDATA, &api_response);

    res = curl_easy_perform(curl);
    if (res != CURLE_OK) {
      fprintf(stderr, "curl_easy_perform() failed: %s\n", curl_easy_strerror(res));
      log_data(temperature, -1); // Log the error
      curl_easy_cleanup(curl);
      curl_global_cleanup();
      if (api_response.data) free(api_response.data);
      return -1000.0;
    }

    // Convert the response to a double
    temperature = strtod(api_response.data, NULL);

    curl_easy_cleanup(curl);
  }
  curl_global_cleanup();
  if (api_response.data) free(api_response.data);

  return temperature;
}

// Function to control the heating element using PWM
int control_heating_element(double target_temperature) {
  double error = target_temperature - CURRENT_TEMPERATURE;
  double duty_cycle = KP * error;

  // Clamp the duty cycle between 0 and 100
  if (duty_cycle < 0) {
    duty_cycle = 0;
  } else if (duty_cycle > PWM_RANGE) {
    duty_cycle = PWM_RANGE;
  }

  // Set the PWM duty cycle
  pwmWrite(GPIO_PIN, (int)duty_cycle);

  return (int)duty_cycle;
}

// Function to log data to a file
int log_data(double target_temperature, double duty_cycle) {
  time_t rawtime;
  struct tm *timeinfo;
  char timestamp[80];

  time(&rawtime);
  timeinfo = localtime(&rawtime);

  strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

  if (log_file != NULL) {
    fprintf(log_file, "%s, Target Temperature: %.2f, Current Temperature: %.2f, Duty Cycle: %.2f\n",
            timestamp, target_temperature, CURRENT_TEMPERATURE, duty_cycle);
    fflush(log_file); // Ensure data is written to the file immediately
    return 0;
  } else {
    fprintf(stderr, "Error: Log file is not open.\n");
    return -1;
  }
}

// Signal handler for graceful shutdown
void signal_handler(int sig) {
  fprintf(stdout, "\nCaught signal %d, exiting gracefully.\n", sig);
  keep_running = 0;
  if (log_file != NULL) {
    fclose(log_file);
  }
  exit(0);
}

int main(void) {
  int pwm_value;
  double target_temperature;

  // Set up signal handling
  signal(SIGINT, signal_handler);

  // Initialize wiringPi
  if (wiringPiSetupGpio() == -1) {
    fprintf(stderr, "Error initializing wiringPi.\n");
    return 1;
  }

  // Open the log file
  log_file = fopen(LOG_FILE, "a");
  if (log_file == NULL) {
    fprintf(stderr, "Error opening log file.\n");
    return 1;
  }

  // Configure GPIO18 as PWM output
  pinMode(GPIO_PIN, PWM_OUTPUT);
  pwmSetMode(PWM_MODE_MS);
  pwmSetRange(PWM_RANGE);
  pwmSetClock(192); // Adjust clock for desired PWM frequency

  fprintf(stdout, "Threat Detection Node Started.\n");

  // Main loop
  while (keep_running) {
    // Fetch the target temperature from the API
    target_temperature = fetch_temperature();

    if (target_temperature > -999.0) {
      // Control the heating element
      pwm_value = control_heating_element(target_temperature);

      // Log the data
      log_data(target_temperature, pwm_value);
    } else {
      fprintf(stderr, "Error fetching temperature, retrying in %d seconds.\n", API_RETRY_DELAY);
      log_data(target_temperature, -1.0); // Log error
      delay(API_RETRY_DELAY * 1000);       // Wait before retrying
      continue;
    }

    // Wait before the next iteration
    delay(LOOP_DELAY * 1000);
  }

  // Close the log file and exit
  fclose(log_file);
  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <wiringPiI2C.h>
#include <wiringPi.h>
#include <time.h>
#include <signal.h>
#include <errno.h>
#include <string.h>

// Constants
#define I2C_ADDR 0x1A
#define GPIO_PIN 17
#define TILT_THRESHOLD 45

// Function pointer type for logging
typedef void (*LogFunction)(const char* message);

// Global I2C file descriptor (avoid global mutable state as much as possible)
static int i2c_fd = -1;
static volatile sig_atomic_t program_running = 1;

// Function to handle signals
void signal_handler(int signal) {
    program_running = 0;
    printf("Caught signal %d, exiting gracefully.\n", signal);
}

// Function to initialize I2C
bool initialize_i2c(int* fd, LogFunction log_function) {
    *fd = wiringPiI2CSetup(I2C_ADDR);
    if (*fd == -1) {
        log_function("Failed to initialize I2C. Check your wiring and I2C configuration.\n");
        return false;
    }
    return true;
}

// Function to read sensor data
bool read_sensor_data(int fd, int* x_angle, int* y_angle, LogFunction log_function) {
    int x, y;
    x = wiringPiI2CReadReg8(fd, 0x00);
    y = wiringPiI2CReadReg8(fd, 0x01);

    if (x < 0 || y < 0) {
        log_function("Error reading sensor data.\n");
        return false;
    }

    *x_angle = (int8_t)x; // Treat as signed 8-bit integer
    *y_angle = (int8_t)y; // Treat as signed 8-bit integer
    return true;
}

// Function to check for excessive tilt
bool is_excessive_tilt(int x_angle, int y_angle) {
    return (abs(x_angle) > TILT_THRESHOLD || abs(y_angle) > TILT_THRESHOLD);
}

// Function to control GPIO pin
void control_gpio(int pin, int state) {
    digitalWrite(pin, state);
}

// Function to log data to file
void log_to_file(const char* message) {
    FILE* fp = fopen("tilt_log.txt", "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return;
    }

    time_t t = time(NULL);
    struct tm* tm = localtime(&t);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(fp, "%s: %s", timestamp, message);
    fclose(fp);
}

int main() {
    // Install signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return 1;
    }

    // Set GPIO pin to output mode
    pinMode(GPIO_PIN, OUTPUT);
    digitalWrite(GPIO_PIN, LOW); // Ensure it's off initially

    // Initialize I2C
    if (!initialize_i2c(&i2c_fd, log_to_file)) {
        return 1;
    }

    printf("Tilt sensor data logging started. Press Ctrl+C to exit.\n");

    while (program_running) {
        int x_angle, y_angle;

        if (read_sensor_data(i2c_fd, &x_angle, &y_angle, log_to_file)) {
            char log_message[128];
            snprintf(log_message, sizeof(log_message), "X: %d, Y: %d\n", x_angle, y_angle);
            log_to_file(log_message);

            if (is_excessive_tilt(x_angle, y_angle)) {
                control_gpio(GPIO_PIN, HIGH);
                delay(500); // 500ms
                control_gpio(GPIO_PIN, LOW);
            }
        } else {
            log_to_file("Failed to read sensor data.\n");
        }

        delay(100); // Sample every 100ms
    }

    // Cleanup: Ensure GPIO is low on exit
    digitalWrite(GPIO_PIN, LOW);

    if (i2c_fd != -1) {
        // No specific I2C close function in wiringPi.  The fd is just an integer.
    }

    printf("Exiting.\n");
    return 0;
}

