    fd = wiringPiI2CSetup(I2C_ADDR);
    if (fd == -1)
    {
        fprintf(stderr, "wiringPiI2CSetup failed\n");
        return 1;
    }

    // Initialize the VL53L1X sensor
    if (!initSensor())
    {
        fprintf(stderr, "Sensor initialization failed\n");
        return 1;
    }

    // Configure servo pin as software PWM output
    softPwmCreate(SERVO_PIN, 0, 200); // Range 0-200 for 50Hz (20ms period)

    // Main loop
    while (1)
    {
        int distance = readDistance();

        if (distance < 0) {
            handleError("Error reading distance");
            delay(100);
            continue;
        }

        if (distance < DISTANCE_THRESHOLD)
        {
            openGate();
            delay(CLOSE_DELAY);
            closeGate();
        }

        delay(100); // Delay for stability
    }

    return 0;
}

// Initialize the VL53L1X sensor
int initSensor()
{
    // Check sensor ID (example)
    int sensor_id = wiringPiI2CReadReg16(fd, VL53L1X_IDENTIFICATION_MODEL_ID);
    if (sensor_id == -1) {
        handleError("Error reading sensor ID");
        return 0;
    }

    //Basic configuration (replace with your sensor's initialization sequence)
    wiringPiI2CWriteReg16(fd, 0x02d8, 0x0001); // Example register write
    wiringPiI2CWriteReg16(fd, 0x02de, 0x0001); // Example register write
    wiringPiI2CWriteReg16(fd, 0x00e8, 0x0001); // Example register write
    wiringPiI2CWriteReg16(fd, 0x0004, 0xC000); // Example register write
    wiringPiI2CWriteReg16(fd, 0x0006, 0x0080); // Example register write
    wiringPiI2CWriteReg16(fd, 0x02cc, 0x0008); // Example register write
    wiringPiI2CWriteReg16(fd, 0x010c, 0x0000); // Example register write
    wiringPiI2CWriteReg16(fd, 0x010e, 0x0000); // Example register write
    wiringPiI2CWriteReg16(fd, 0x0014, 0x0024); // Example register write

    return 1; // Return 1 if initialization is successful
}

// Read distance from the VL53L1X sensor
int readDistance()
{
    int range = wiringPiI2CReadReg16(fd, VL53L1X_RESULT_FINAL_CROSSTALK_CORRECTED_RANGE_MM_SD0);

    if (range < 0) {
        return -1; // Indicate error
    }

    return range;
}

