#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <signal.h>
#include <time.h>
#include <pigpio.h>

// Define GPIO pin for the water pump relay
#define PUMP_GPIO 17

// Define moisture threshold (ADC value)
#define MOISTURE_THRESHOLD 600

// File to log irrigation events
#define LOG_FILE "irrigation_log.txt"

// SPI channel
#define SPI_CHANNEL 0

// SPI speed
#define SPI_SPEED 50000

// File pointer for the log file
FILE *log_file = NULL;

// Function prototypes
int read_mcp3008(int channel);
void check_moisture(int gpio, int level, uint32_t tick);
void signal_handler(int signal);

// Function to read analog values from MCP3008 ADC via SPI
int read_mcp3008(int channel) {
    int handle, i;
    unsigned char spi_tx_buf[3];
    unsigned char spi_rx_buf[3];

    // Construct SPI message for single-ended read
    spi_tx_buf[0] = 0x01; // Start bit
    spi_tx_buf[1] = ((channel & 0x07) << 4) | 0x80; // Single-ended, channel select
    spi_tx_buf[2] = 0x00;

    // Open SPI channel
    handle = spiOpen(SPI_CHANNEL, SPI_SPEED, 0); // CE0, 50kHz, mode 0
    if (handle < 0) {
        fprintf(stderr, "Error: spiOpen failed (%d)\n", handle);
        return -1;
    }

    // Transfer SPI data
    if (spiXfer(handle, spi_tx_buf, spi_rx_buf, 3) != 3) {
        fprintf(stderr, "Error: spiXfer failed\n");
        spiClose(handle);
        return -1;
    }

    // Close SPI channel
    spiClose(handle);

    // Extract ADC value (10 bits)
    int adc_value = ((spi_rx_buf[1] & 0x03) << 8) + spi_rx_buf[2];

    return adc_value;
}

// Callback function to check soil moisture and control the pump
void check_moisture(int gpio, int level, uint32_t tick) {
    int moisture_value = read_mcp3008(0);
    time_t rawtime;
    struct tm *timeinfo;
    time(&rawtime);
    timeinfo = localtime(&rawtime);

    if (moisture_value > MOISTURE_THRESHOLD) {
        // Activate the pump
        gpioWrite(PUMP_GPIO, 1);
        fprintf(log_file, "%s ADC: %d, Pump ACTIVATED\n", asctime(timeinfo), moisture_value);
        fflush(log_file);
    } else {
        // Deactivate the pump
        gpioWrite(PUMP_GPIO, 0);
        fprintf(log_file, "%s ADC: %d, Pump DEACTIVATED\n", asctime(timeinfo), moisture_value);
        fflush(log_file);
    }
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    time_t rawtime;
    struct tm *timeinfo;
    time(&rawtime);
    timeinfo = localtime(&rawtime);
    fprintf(log_file, "%s Program terminated by signal %d\n", asctime(timeinfo), signal);
    fflush(log_file);

    printf("Signal received, shutting down...\n");
    gpioWrite(PUMP_GPIO, 0); // Deactivate the pump
    if (log_file != NULL) {
        fclose(log_file);
    }
    gpioTerminate(); // Terminate pigpio
    exit(0);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Configure GPIO 17 as output for the pump relay
    gpioSetMode(PUMP_GPIO, PI_OUTPUT);

    // Open the log file
    log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error: Could not open log file\n");
        gpioTerminate();
        return 1;
    }

    // Set up signal handling for Ctrl+C
    signal(SIGINT, signal_handler);

    // Set up a timer to call the check_moisture function every 5 seconds (5000 ms)
    gpioSetTimerFunc(0, 5000, check_moisture);

    printf("Smart Irrigation System running...\nPress Ctrl+C to exit.\n");

    // Keep the program running
    while (1) {
        gpioDelay(1000); // Sleep for 1 second
    }

    return 0;
}

