// VEML6075 I2C address
#define VEML6075_ADDR 0x38

// LCD I2C address (replace with your LCD's address)
#define LCD_ADDR 0x27

// GPIO pin for LED
#define LED_PIN 17

// VEML6075 Registers
#define VEML6075_CONF 0x00
#define VEML6075_UVA_DATA 0x07
#define VEML6075_UVB_DATA 0x09

// UVA Index Threshold
#define UVA_THRESHOLD 7

// Global variables for I2C handles
int veml6075_handle;
int lcd_handle;

// Function prototypes
int veml6075_read_data(int handle, int *uva, int *uvb);
void calculate_indices(int uva, int uvb, float *uva_index, float *uvb_index);
int lcd_init(int handle);
int lcd_write_string(int handle, const char *str);
int lcd_clear(int handle);
void display_data(int handle, float uva_index, float uvb_index);
void cleanup(int sig);

// Signal handler for graceful shutdown
void cleanup(int sig) {
    printf("Cleaning up and exiting.\n");
    gpioWrite(LED_PIN, 0); // Turn off LED
    if (veml6075_handle >= 0) {
        i2cClose(veml6075_handle);
    }
    if (lcd_handle >= 0) {
        i2cClose(lcd_handle);
    }
    gpioTerminate();
    exit(0);
}

// Function to read data from VEML6075
int veml6075_read_data(int handle, int *uva, int *uvb) {
    char buf[2];
    int result;

    // Read UVA data
    result = i2cReadI2CBlockData(handle, VEML6075_UVA_DATA, buf, 2);
    if (result != 2) {
        fprintf(stderr, "Error reading UVA data: %d\n", result);
        return -1;
    }
    *uva = (buf[1] << 8) | buf[0];

    // Read UVB data
    result = i2cReadI2CBlockData(handle, VEML6075_UVB_DATA, buf, 2);
    if (result != 2) {
