#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <signal.h>
#include <pigpio.h>

// Constants
#define RAIN_SENSOR_PIN 4  // GPIO pin connected to the rain sensor
#define MOTOR_PIN_1 23      // GPIO pin for motor control (H-bridge input 1)
#define MOTOR_PIN_2 24      // GPIO pin for motor control (H-bridge input 2)
#define MAX_LOG_ENTRIES 10 // Size of the circular buffer

// Global Variables
volatile sig_atomic_t program_running = 1; // Flag to control program execution
int RAIN_THRESHOLD = 0;                     // Calibrated rain threshold

// Data Structures
typedef enum {
    OPEN,
    CLOSED,
    STOPPED
} MotorState;

typedef struct {
    time_t timestamp;
    int rawSensorValue;
    int calibratedSensorValue;
    int calibratedThreshold;
    MotorState motorState;
} LogEntry;

LogEntry circularBuffer[MAX_LOG_ENTRIES];
int bufferIndex = 0;

// Function Prototypes
int readRainSensor();
int calibrateThreshold();
int controlMotor(MotorState state);
void addToCircularBuffer(int rawValue, int calibratedValue, MotorState state);
void printCircularBuffer();
void handleShutdown(int signal);

// Function Implementations

// Reads the rain sensor value using capacitor discharge time
int readRainSensor() {
    int dischargeTime = 0;
    gpioSetMode(RAIN_SENSOR_PIN, PI_OUTPUT);
    gpioWrite(RAIN_SENSOR_PIN, 1); // Charge the capacitor
    gpioDelay(1);                   // Wait for charging
    gpioSetMode(RAIN_SENSOR_PIN, PI_INPUT);

    uint32_t startTick = gpioTick();
    while (gpioRead(RAIN_SENSOR_PIN) == 1 && dischargeTime < 5000) {
        dischargeTime = gpioTick() - startTick;
    }

    return dischargeTime;
}

// Calibrates the rain threshold by prompting the user for input
int calibrateThreshold() {
    int threshold;
    printf("Enter the rain threshold value: ");
    if (scanf("%d", &threshold) != 1) {
        fprintf(stderr, "Error: Invalid input. Please enter an integer.\n");
        return 1; // Indicate error
    }
    RAIN_THRESHOLD = threshold;
    printf("Rain threshold set to: %d\n", RAIN_THRESHOLD);
    return 0; // Indicate success
}

// Controls the motor based on the desired state
int controlMotor(MotorState state) {
    int result1, result2;
    switch (state) {
        case OPEN:
            result1 = gpioWrite(MOTOR_PIN_1, 0);
            result2 = gpioWrite(MOTOR_PIN_2, 1);
            break;
        case CLOSED:
            result1 = gpioWrite(MOTOR_PIN_1, 1);
            result2 = gpioWrite(MOTOR_PIN_2, 0);
            break;
        case STOPPED:
        default:
            result1 = gpioWrite(MOTOR_PIN_1, 0);
            result2 = gpioWrite(MOTOR_PIN_2, 0);
            break;
    }

    if (result1 < 0 || result2 < 0) {
        fprintf(stderr, "Error: Failed to control motor. pigpio error code: %d, %d\n", result1, result2);
        return 1; // Indicate error
    }
    return 0; // Indicate success
}

// Adds a log entry to the circular buffer
void addToCircularBuffer(int rawValue, int calibratedValue, MotorState state) {
    time_t now = time(NULL);
    circularBuffer[bufferIndex].timestamp = now;
    circularBuffer[bufferIndex].rawSensorValue = rawValue;
    circularBuffer[bufferIndex].calibratedSensorValue = calibratedValue;
    circularBuffer[bufferIndex].calibratedThreshold = RAIN_THRESHOLD;
    circularBuffer[bufferIndex].motorState = state;

    bufferIndex = (bufferIndex + 1) % MAX_LOG_ENTRIES;
}

// Prints the contents of the circular buffer
void printCircularBuffer() {
    printf("\n--- Log Entries ---\n");
    for (int i = 0; i < MAX_LOG_ENTRIES; i++) {
        int index = (bufferIndex + i) % MAX_LOG_ENTRIES; // Correct order
        struct tm *timeinfo = localtime(&circularBuffer[index].timestamp);
        char timestamp[80];
        strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

        char motorStateStr[10];
        switch (circularBuffer[index].motorState) {
            case OPEN: strcpy(motorStateStr, "OPEN"); break;
            case CLOSED: strcpy(motorStateStr, "CLOSED"); break;
            case STOPPED: strcpy(motorStateStr, "STOPPED"); break;
            default: strcpy(motorStateStr, "UNKNOWN"); break;
        }

        printf("Timestamp: %s, Raw: %d, Calibrated: %d, Threshold: %d, Motor: %s\n",
               timestamp, circularBuffer[index].rawSensorValue, circularBuffer[index].calibratedSensorValue,
               circularBuffer[index].calibratedThreshold, motorStateStr);
    }
    printf("--------------------\n");
}

// Handles program shutdown (e.g., on Ctrl+C)
void handleShutdown(int signal) {
    printf("\nShutting down...\n");
    program_running = 0;
    controlMotor(STOPPED); // Stop the motor
    gpioTerminate();       // Terminate pigpio
    exit(0);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Configure GPIO pins
    gpioSetMode(MOTOR_PIN_1, PI_OUTPUT);
    gpioSetMode(MOTOR_PIN_2, PI_OUTPUT);

    // Calibrate the rain threshold
    if (calibrateThreshold() != 0) {
        gpioTerminate();
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, handleShutdown);

    printf("Program running. Press Ctrl+C to exit.\n");

    while (program_running) {
        // Read the rain sensor value
        int rawSensorValue = readRainSensor();
        int calibratedSensorValue = 5000 - rawSensorValue; // Invert and scale (example)

        // Determine motor state based on rain sensor value and threshold
        MotorState motorState = STOPPED; // Default state
        if (calibratedSensorValue > RAIN_THRESHOLD) {
            motorState = CLOSED;
        } else {
            motorState = OPEN; // Or STOPPED, depending on desired behavior
        }

        // Control the motor
        if (controlMotor(motorState) != 0) {
            handleShutdown(0);
        }

        // Add data to the circular buffer
        addToCircularBuffer(rawSensorValue, calibratedSensorValue, motorState);

        // Print the circular buffer (for debugging/logging)
        printCircularBuffer();

        // Wait before the next iteration
        gpioDelay(2000); // Wait 2 seconds
    }

    return 0;
}

