    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Initialize pigpio and GPIO pins
    if (initialize_gpio() != 0) {
        fprintf(stderr, "Failed to initialize GPIO. Exiting.\n");
        return 1;
    }

    printf("Flame detection system started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        // Read flame sensor
        int flame_detected = read_flame_sensor();

        // Check if flame is detected
        if (flame_detected == FLAME_DETECTED) {
            printf("Flame detected!\n");

            // Activate buzzer and LED
            activate_buzzer(1);
            activate_led(1);

            // Log flame detection event
            log_flame_detection();

            // Wait for a short period to avoid repeated detections
            gpioDelay(1000); // 1 second

            // Deactivate buzzer and LED
            activate_buzzer(0);
            activate_led(0);
        }

        // Short delay to avoid busy-waiting
        gpioDelay(100);
    }

    // Cleanup GPIO before exiting
    cleanup_gpio();

