#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <time.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/spi/spidev.h>
#include <errno.h>
#include <string.h>

#define SPI_BUS 0
#define SPI_CE 0
#define SPI_DEVICE "/dev/spidev0.0"

// MCP3008 Definitions
#define MCP3008_SINGLE_ENDED(channel) (0x08 | ((channel & 0x07) << 4))

// Function to initialize the SPI bus
int spi_init(int bus, int ce, int speed, int mode)
{
    int fd;
    char spi_device[20];

    snprintf(spi_device, sizeof(spi_device), "/dev/spidev%d.%d", bus, ce);
    fd = open(spi_device, O_RDWR);
    if (fd < 0)
    {
        perror("Error opening SPI device");
        return -1;
    }

    // Set SPI mode
    if (ioctl(fd, SPI_IOC_WR_MODE, &mode) < 0)
    {
        perror("Error setting SPI mode");
        close(fd);
        return -1;
    }

    // Set SPI speed
    if (ioctl(fd, SPI_IOC_WR_MAX_SPEED_HZ, &speed) < 0)
    {
        perror("Error setting SPI speed");
        close(fd);
        return -1;
    }

    return fd;
}

// Function to read from MCP3008 ADC
int read_mcp3008(int fd, int channel)
{
    uint8_t tx_buf[3];
    uint8_t rx_buf[3];
    struct spi_ioc_transfer tr;

    // Construct SPI message to send to MCP3008
    tx_buf[0] = 0x01;                          // Start bit
    tx_buf[1] = MCP3008_SINGLE_ENDED(channel); // Single-ended channel
    tx_buf[2] = 0x00;                          // Dummy byte

    memset(&tr, 0, sizeof(tr));
    tr.tx_buf = (unsigned long)tx_buf;
    tr.rx_buf = (unsigned long)rx_buf;
    tr.len = 3;
    tr.delay_usecs = 0;
    tr.speed_hz = 1000000; // SPI clock speed
    tr.bits_per_word = 8;

    if (ioctl(fd, SPI_IOC_MESSAGE(1), &tr) < 0)
    {
        perror("Error sending SPI message");
        return -1;
    }

    // Extract the ADC value from the response
    int adc_value = ((rx_buf[1] & 0x03) << 8) | rx_buf[2];

    return adc_value;
}

int main()
{
    int spi_fd;
    int adc_value;
    double sum = 0.0;
    int count = 0;
    time_t start_time, current_time;

    // Initialize SPI
    spi_fd = spi_init(SPI_BUS, SPI_CE, 1000000, 0);
    if (spi_fd < 0)
    {
        fprintf(stderr, "SPI Initialization failed\n");
        return 1;
    }

    time(&start_time);

    while (1)
    {
        // Read ADC value (channel 0)
        adc_value = read_mcp3008(spi_fd, 0);
        if (adc_value < 0)
        {
            fprintf(stderr, "ADC read failed\n");
            close(spi_fd);
            return 1;
        }

        sum += adc_value;
        count++;

        time(&current_time);
        if (difftime(current_time, start_time) >= 5.0)
        {
            // Calculate and print the average
            double average = sum / count;
            printf("Average ADC Value: %.2f\n", average);

            // Reset variables for the next 5-second interval
            sum = 0.0;
            count = 0;
            time(&start_time);
        }

        usleep(100000); //delay 100ms
    }

    close(spi_fd);
    return 0;
}

