    int export_fd, unexport_fd, direction_fd;

    // Signal handling
    if (signal(SIGINT, signal_handler) == SIG_ERR) {
        perror("signal");
        return 1;
    }

    // Parse command-line argument for threshold
    if (argc > 1) {
        threshold = atoi(argv[1]);
        if (threshold <= 0) {
            fprintf(stderr, "Invalid threshold value. Using default threshold of 1.\n");
            threshold = 1;
        }
    }

    // Export GPIO
    export_fd = open(export_path, O_WRONLY);
    if (export_fd == -1) {
        perror("main: open export");
        return 1;
    }
    if (write(export_fd, gpio_num, strlen(gpio_num)) == -1) {
        perror("main: write export");
        close(export_fd);
        return 1;
    }
    close(export_fd);
    sleep(1); // Give the system time to create the GPIO directory

    // Set GPIO direction to input
    direction_fd = open(direction_path, O_WRONLY);
    if (direction_fd == -1) {
        perror("main: open direction");
        goto unexport;
    }
    if (write(direction_fd, "in", 2) == -1) {
        perror("main: write direction");
        close(direction_fd);
        goto unexport;
    }
    close(direction_fd);

    // Construct GPIO value path
    snprintf(gpio_path, sizeof(gpio_path), "/sys/class/gpio/gpio17/value");

    // Main loop
    while (!terminate) {
        vibration_value = read_vibration_sensor(gpio_path);
        if (vibration_value == -1) {
            fprintf(stderr, "Error reading vibration sensor, exiting...\n");
            break;
        }

        if (vibration_value >= threshold) {
            log_event(log_file, "Vibration detected!");
        }

        usleep(100000); // 100ms delay
    }

    // Unexport GPIO
unexport:
    unexport_fd = open(unexport_path, O_WRONLY);
    if (unexport_fd == -1) {
        perror("main: open unexport");
        return 1;
    }
    if (write(unexport_fd, gpio_num, strlen(gpio_num)) == -1) {
        perror("main: write unexport");
        close(unexport_fd);
        return 1;
    }
    close(unexport_fd);

    return 0;
}

