// Function to initialize GPIO and pigpio library
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1; // Indicate failure
    }

    // Set GPIO pins as outputs
    gpioSetMode(MOTOR_1_GPIO, PI_OUTPUT);
    gpioSetMode(MOTOR_2_GPIO, PI_OUTPUT);

    // Ensure motors are initially off
    gpioPWM(MOTOR_1_GPIO, 0);
    gpioPWM(MOTOR_2_GPIO, 0);

    return 0; // Indicate success
}

// Function to generate a vibration pattern on a motor
void vibrate_motor(int gpio_pin, int intensity, int duration_ms) {
    if (gpio_pin != MOTOR_1_GPIO && gpio_pin != MOTOR_2_GPIO) {
        fprintf(stderr, "Invalid GPIO pin: %d\n", gpio_pin);
        return;
    }

    if (intensity < 0 || intensity > 255) {
        fprintf(stderr, "Invalid intensity: %d. Must be between 0 and 255\n", intensity);
        return;
    }

    gpioPWM(gpio_pin, intensity);
    gpioDelay(duration_ms * 1000); // Convert ms to microseconds
    gpioPWM(gpio_pin, 0); // Turn off motor after duration
}

// Function to simulate proximity data (replace with actual sensor data)
int simulate_proximity_data() {
    // In a real application, this would read data from a proximity sensor
    // For simulation, we'll generate a random value
    return rand() % 1000; // Simulate values between 0 and 999
}

// Function to handle proximity data and trigger vibration
void handle_proximity(int proximity_value) {
    if (proximity_value > PROXIMITY_THRESHOLD) {
        printf("Proximity detected (value: %d). Triggering vibration pattern.\n", proximity_value);

        // Trigger a distinct vibration pattern on motor 1
        vibrate_motor(MOTOR_1_GPIO, 150, 200); // Medium intensity, short duration
        gpioDelay(100 * 1000); // Short pause
        vibrate_motor(MOTOR_1_GPIO, 200, 100); // High intensity, very short duration

        // Trigger a different vibration pattern on motor 2
        vibrate_motor(MOTOR_2_GPIO, 100, 500); // Low intensity, longer duration

    } else {
        // No proximity detected
        printf("No proximity detected (value: %d).\n", proximity_value);
    }
}

