#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <wiringPiSPI.h>
#include <time.h>
#include <string.h>

#define FAN_PIN 18          // GPIO18 (physical pin 12)
#define SPI_CHANNEL 0       // SPI channel 0
#define SPI_SPEED 1000000   // 1 MHz
#define TARGET_TEMP 55.0    // Target temperature in Celsius
#define KP 2.0              // Proportional gain constant
#define LOG_FILE "/var/log/fan_control.log"

// Function to read temperature from MAX31855 via SPI
float readTemperature() {
    unsigned char data[4];
    int raw;
    float temperature;

    if (wiringPiSPIDataRW(SPI_CHANNEL, data, 4) == -1) {
        logData(-200.0, -1); // Log error temperature
        fprintf(stderr, "SPI read failed\n");
        return -1.0;
    }

    // Check for fault conditions (bits 2-0)
    if (data[3] & 0x07) {
        FILE *fp = fopen(LOG_FILE, "a");
        if (fp != NULL) {
            time_t t = time(NULL);
            struct tm tm = *localtime(&t);
            fprintf(fp, "%d-%02d-%02d %02d:%02d:%02d - MAX31855 Fault: %02X %02X %02X %02X\n", tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, data[0], data[1], data[2], data[3]);
            fclose(fp);
        } else {
            fprintf(stderr, "Error opening log file for fault logging!\n");
        }

        return -1.0;
    }

    // Extract thermocouple temperature (bits 31-18)
    raw = ((data[0] << 8) | data[1]) >> 2;
    temperature = raw * 0.25;

    return temperature;
}

// Function to set the fan speed using PWM
void setFanSpeed(int dutyCycle) {
    // Clamp duty cycle between 0 and 100
    if (dutyCycle < 0) dutyCycle = 0;
    if (dutyCycle > 100) dutyCycle = 100;

    pwmWrite(FAN_PIN, dutyCycle);
}

// Function to calculate the duty cycle using proportional control
int calculateDutyCycle(float currentTemperature, float targetTemperature) {
    float error = targetTemperature - currentTemperature;
    float dutyCycle = KP * error;
    return (int)dutyCycle;
}

// Function to log temperature and duty cycle to a file
void logData(float temperature, int dutyCycle) {
    FILE *fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(fp, "%d-%02d-%02d %02d:%02d:%02d - Temperature: %.2f°C, Duty Cycle: %d\n", tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, temperature, dutyCycle);
    fclose(fp);
}

int main() {
    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "wiringPiSetupGpio failed\n");
        return 1;
    }

    // Initialize PWM on GPIO18
    pinMode(FAN_PIN, PWM_OUTPUT);
    pwmSetMode(PWM_MODE_MS);
    pwmSetRange(100);
    pwmSetClock(192); // Set PWM frequency to approximately 50Hz (19.2MHz / 192 / 100)

    // Initialize SPI
    if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) == -1) {
        fprintf(stderr, "wiringPiSPISetup failed\n");
        return 1;
    }

    float currentTemperature;
    int dutyCycle;

    // Main loop
    while (1) {
        currentTemperature = readTemperature();

        if (currentTemperature == -1.0) {
            // Error reading temperature, continue to the next iteration
            delay(1000);
            continue;
        }

        dutyCycle = calculateDutyCycle(currentTemperature, TARGET_TEMP);
        setFanSpeed(dutyCycle);
        logData(currentTemperature, dutyCycle);

        delay(1000); // Sleep for 1 second
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>

// Constants
#define THERMAL_ZONE_PATH "/sys/class/thermal/thermal_zone0/temp"
#define PWM_PATH "/sys/class/pwm/pwmchip0/pwm0"
#define PWM_PERIOD_FILE "period"
#define PWM_DUTY_CYCLE_FILE "duty_cycle"
#define PWM_ENABLE_FILE "enable"
#define LOG_FILE "/var/log/fan_control.log"
#define PWM_PERIOD_NS 1000000 // 1 ms

// Function prototypes
int read_cpu_temp(const char* thermal_zone_path);
int write_pwm_period(const char* pwm_path, int period_ns);
int write_pwm_duty_cycle(const char* pwm_path, int duty_cycle_ns);
int enable_pwm(const char* pwm_path, int enable);
int map_temp_to_duty_cycle(int temperature);
void log_message(const char* message);
void signal_handler(int signal);

// Global variable for program termination
volatile sig_atomic_t program_running = 1;

int main() {
    // Signal handling setup
    signal(SIGINT, signal_handler);

    // Initialize PWM
    if (write_pwm_period(PWM_PATH, PWM_PERIOD_NS) != 0) {
        log_message("Failed to set PWM period. Exiting.");
        return 1;
    }
    if (enable_pwm(PWM_PATH, 1) != 0) {
        log_message("Failed to enable PWM. Exiting.");
        return 1;
    }

    // Main loop
    while (program_running) {
        // Read CPU temperature
        int temperature = read_cpu_temp(THERMAL_ZONE_PATH);
        if (temperature == -1) {
            log_message("Failed to read CPU temperature.");
        } else {
            // Map temperature to duty cycle
            int duty_cycle = map_temp_to_duty_cycle(temperature);

            // Set PWM duty cycle
            if (write_pwm_duty_cycle(PWM_PATH, duty_cycle) != 0) {
                log_message("Failed to set PWM duty cycle.");
            } else {
                // Log action
                char message[100];
                snprintf(message, sizeof(message), "Temperature: %d m°C, Duty Cycle: %d ns", temperature, duty_cycle);
                log_message(message);
            }
        }

        // Sleep for 5 seconds
        sleep(5);
    }

    // Shutdown fan
    log_message("Shutting down fan...");
    write_pwm_duty_cycle(PWM_PATH, 0);
    enable_pwm(PWM_PATH, 0);

    log_message("Fan control program terminated.");
    return 0;
}

// Function to read CPU temperature from sysfs
int read_cpu_temp(const char* thermal_zone_path) {
    FILE* fp;
    char temp_str[10];
    int temperature;

    fp = fopen(thermal_zone_path, "r");
    if (fp == NULL) {
        log_message("Error opening thermal zone file.");
        return -1;
    }

    if (fgets(temp_str, sizeof(temp_str), fp) == NULL) {
        log_message("Error reading thermal zone file.");
        fclose(fp);
        return -1;
    }

    fclose(fp);

    temperature = atoi(temp_str);
    return temperature;
}

// Function to write PWM period to sysfs
int write_pwm_period(const char* pwm_path, int period_ns) {
    char path[100];
    snprintf(path, sizeof(path), "%s/%s", pwm_path, PWM_PERIOD_FILE);
    FILE* fp;

    fp = fopen(path, "w");
    if (fp == NULL) {
        log_message("Error opening PWM period file.");
        return -1;
    }

    fprintf(fp, "%d", period_ns);
    fclose(fp);
    return 0;
}

// Function to write PWM duty cycle to sysfs
int write_pwm_duty_cycle(const char* pwm_path, int duty_cycle_ns) {
    char path[100];
    snprintf(path, sizeof(path), "%s/%s", pwm_path, PWM_DUTY_CYCLE_FILE);
    FILE* fp;

    fp = fopen(path, "w");
    if (fp == NULL) {
        log_message("Error opening PWM duty cycle file.");
        return -1;
    }

    fprintf(fp, "%d", duty_cycle_ns);
    fclose(fp);
    return 0;
}

// Function to enable/disable PWM output
int enable_pwm(const char* pwm_path, int enable) {
    char path[100];
    snprintf(path, sizeof(path), "%s/%s", pwm_path, PWM_ENABLE_FILE);
    FILE* fp;

    fp = fopen(path, "w");
    if (fp == NULL) {
        log_message("Error opening PWM enable file.");
        return -1;
    }

    fprintf(fp, "%d", enable);
    fclose(fp);
    return 0;
}

// Function to map temperature to duty cycle
int map_temp_to_duty_cycle(int temperature) {
    if (temperature < 50000) {
        return 0; // Fan off
    } else if (temperature < 60000) {
        return 500000; // 50% speed
    } else if (temperature < 70000) {
        return 750000; // 75% speed
    } else {
        return 1000000; // 100% speed
    }
}

// Function to log messages to file
void log_message(const char* message) {
    FILE* fp;
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[20];

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return;
    }

    fprintf(fp, "[%s] %s\n", timestamp, message);
    fclose(fp);
}

// Signal handler function
void signal_handler(int signal) {
    if (signal == SIGINT) {
        log_message("Received SIGINT. Shutting down...");
        program_running = 0;
    }
}

