#define ADC_DEVICE_PATH "/dev/iio_device0"
#define ADC_CHANNEL_PATH "/sys/bus/iio/devices/iio:device0/in_voltage0_raw"
#define ADC_SCALE_PATH "/sys/bus/iio/devices/iio:device0/in_voltage0_scale"


int read_adc_value(int *value)
{
    int fd;
    char buf[16];
    int ret;
    float scale;

    // Read scale
    fd = open(ADC_SCALE_PATH, O_RDONLY);
    if (fd < 0) {
        perror("Failed to open ADC scale attribute");
        return -1;
    }
    ret = read(fd, buf, sizeof(buf));
    if (ret < 0) {
        perror("Failed to read ADC scale attribute");
        close(fd);
        return -1;
    }
    close(fd);
    scale = atof(buf);

    // Read raw value
    fd = open(ADC_CHANNEL_PATH, O_RDONLY);
    if (fd < 0) {
        perror("Failed to open ADC raw value attribute");
        return -1;
    }

    ret = read(fd, buf, sizeof(buf));
    if (ret < 0) {
        perror("Failed to read ADC raw value attribute");
        close(fd);
        return -1;
    }

    close(fd);
    *value = atoi(buf);

    return 0;
}


int main()
{
    int adc_value;
    long sum = 0;
    int count = 0;
    time_t start_time, current_time;
    double elapsed_time;

    time(&start_time);

    while (1) {
        if (read_adc_value(&adc_value) == 0) {
            sum += adc_value;
            count++;
        } else {
            fprintf(stderr, "Error reading ADC value\n");
        }

        usleep(100000); // 10 times per second

        time(&current_time);
        elapsed_time = difftime(current_time, start_time);

        if (elapsed_time >= 1.0) {
            if (count > 0) {
                double average = (double)sum / count;
                printf("Time: %.0f, Moving Average: %.2f\n", elapsed_time, average);
            }

            sum = 0;
            count = 0;
            time(&start_time);
        }
    }

    return 0;
}

#include <stdio.h>
