#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <signal.h>
#include <unistd.h>
#include <math.h>

// Define GPIO pins
#define LEFT_TRIGGER_PIN 2
#define LEFT_ECHO_PIN 3
#define RIGHT_TRIGGER_PIN 4
#define RIGHT_ECHO_PIN 5
#define LEFT_SPEAKER_PIN 18
#define RIGHT_SPEAKER_PIN 19

// Constants
#define SPEED_OF_SOUND 34300.0 // cm/s
#define MIN_FREQUENCY 200.0   // Hz
#define MAX_FREQUENCY 2000.0  // Hz
#define SCALE_FACTOR 50.0
#define TRIGGER_PULSE_WIDTH 10 // us

// Global variables for signal handling
volatile sig_atomic_t terminate = 0;

// Structure to hold echo start and end times
typedef struct {
    unsigned int start_time;
    unsigned int end_time;
} EchoTimes;

EchoTimes leftEchoTimes = {0, 0};
EchoTimes rightEchoTimes = {0, 0};

// Signal handler function
void signalHandler(int signum) {
    if (signum == SIGINT) {
        fprintf(stderr, "\nCaught SIGINT, exiting gracefully...\n");
        terminate = 1;
    }
}

// Callback function for left echo pin rising edge
void leftEchoRising(int gpio, int level, unsigned int tick) {
    (void)level; // unused
    (void)gpio;  // unused
    leftEchoTimes.start_time = tick;
}

// Callback function for left echo pin falling edge
void leftEchoFalling(int gpio, int level, unsigned int tick) {
    (void)level; // unused
    (void)gpio;  // unused
    leftEchoTimes.end_time = tick;
}

// Callback function for right echo pin rising edge
void rightEchoRising(int gpio, int level, unsigned int tick) {
    (void)level; // unused
    (void)gpio;  // unused
    rightEchoTimes.start_time = tick;
}

// Callback function for right echo pin falling edge
void rightEchoFalling(int gpio, int level, unsigned int tick) {
    (void)level; // unused
    (void)gpio;  // unused
    rightEchoTimes.end_time = tick;
}

// Function to get distance from ultrasonic sensor
float getDistance(int triggerPin, int echoPin, EchoTimes *echoTimes) {
    unsigned int startTime, endTime, pulseWidth;
    float distance;

    echoTimes->start_time = 0;
    echoTimes->end_time = 0;

    // Trigger the sensor
    gpioTrigger(triggerPin, TRIGGER_PULSE_WIDTH, 1);

    // Wait for echo
    int timeout_us = 100000; // 100ms timeout
    int elapsed_us = 0;
    startTime = gpioTick();
    while (echoTimes->start_time == 0 && elapsed_us < timeout_us) {
        gpioDelay(10); // Check every 10us
        endTime = gpioTick();
        elapsed_us = endTime - startTime;
    }

    if (echoTimes->start_time == 0) {
        fprintf(stderr, "Timeout waiting for rising edge on pin %d\n", echoPin);
        return -1.0;
    }

    elapsed_us = 0;
    startTime = gpioTick();
    while (echoTimes->end_time == 0 && elapsed_us < timeout_us) {
        gpioDelay(10); // Check every 10us
        endTime = gpioTick();
        elapsed_us = endTime - startTime;
    }

    if (echoTimes->end_time == 0) {
        fprintf(stderr, "Timeout waiting for falling edge on pin %d\n", echoPin);
        return -1.0;
    }

    // Calculate pulse width in microseconds
    pulseWidth = echoTimes->end_time - echoTimes->start_time;

    // Calculate distance in centimeters
    distance = ((float)pulseWidth / 1000000.0) * SPEED_OF_SOUND / 2.0;

    return distance;
}

// Function to set PWM frequency
void setFrequency(int gpioPin, float frequency) {
    if (frequency < MIN_FREQUENCY) {
        frequency = MIN_FREQUENCY;
    } else if (frequency > MAX_FREQUENCY) {
        frequency = MAX_FREQUENCY;
    }

    int dutyCycle = (int)(128.0 * (frequency - MIN_FREQUENCY) / (MAX_FREQUENCY - MIN_FREQUENCY) + 127.0); // Map frequency to duty cycle (0-255)
    if (dutyCycle < 0) dutyCycle = 0;
    if (dutyCycle > 255) dutyCycle = 255;

    gpioPWM(gpioPin, dutyCycle);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Register signal handler
    signal(SIGINT, signalHandler);

    // Set GPIO modes
    gpioSetMode(LEFT_TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(LEFT_ECHO_PIN, PI_INPUT);
    gpioSetMode(RIGHT_TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(RIGHT_ECHO_PIN, PI_INPUT);
    gpioSetMode(LEFT_SPEAKER_PIN, PI_OUTPUT);
    gpioSetMode(RIGHT_SPEAKER_PIN, PI_OUTPUT);

    // Set PWM frequency (initial value)
    gpioSetPWMfrequency(LEFT_SPEAKER_PIN, 400);  // Example frequency
    gpioSetPWMfrequency(RIGHT_SPEAKER_PIN, 400); // Example frequency
    gpioSetPWMrange(LEFT_SPEAKER_PIN, 255);
    gpioSetPWMrange(RIGHT_SPEAKER_PIN, 255);

    // Register callback functions for echo pins
    gpioSetAlertFuncEx(LEFT_ECHO_PIN, leftEchoRising, NULL);
    gpioSetAlertFuncEx(LEFT_ECHO_PIN, leftEchoFalling, NULL);
    gpioSetAlertFuncEx(RIGHT_ECHO_PIN, rightEchoRising, NULL);
    gpioSetAlertFuncEx(RIGHT_ECHO_PIN, rightEchoFalling, NULL);

    fprintf(stderr, "Theremin program started. Press Ctrl+C to exit.\n");

    // Main loop
    while (!terminate) {
        // Read distances from ultrasonic sensors
        float leftDistance = getDistance(LEFT_TRIGGER_PIN, LEFT_ECHO_PIN, &leftEchoTimes);
        float rightDistance = getDistance(RIGHT_TRIGGER_PIN, RIGHT_ECHO_PIN, &rightEchoTimes);

        // Handle errors
        if (leftDistance < 0) {
            fprintf(stderr, "Error reading left sensor, skipping...\n");
        } else {
            // Calculate frequency based on distance (example mapping)
            float leftFrequency = MIN_FREQUENCY + (MAX_FREQUENCY - MIN_FREQUENCY) * (1 - exp(-leftDistance / SCALE_FACTOR));
            setFrequency(LEFT_SPEAKER_PIN, leftFrequency);
        }

        if (rightDistance < 0) {
            fprintf(stderr, "Error reading right sensor, skipping...\n");
        } else {
            // Calculate frequency based on distance (example mapping)
            float rightFrequency = MIN_FREQUENCY + (MAX_FREQUENCY - MIN_FREQUENCY) * (1 - exp(-rightDistance / SCALE_FACTOR));
            setFrequency(RIGHT_SPEAKER_PIN, rightFrequency);
        }

        // Small delay
        gpioDelay(50000); // 50ms
    }

    // Stop PWM output
    gpioPWM(LEFT_SPEAKER_PIN, 0);
    gpioPWM(RIGHT_SPEAKER_PIN, 0);

    // Terminate pigpio
    gpioTerminate();

    fprintf(stderr, "Program terminated.\n");
    return 0;
}

