    exit(0);
}

// Function to export a GPIO pin
int gpio_export(int pin) {
    char export_path[64];
    snprintf(export_path, sizeof(export_path), GPIO_PATH "/export");

    FILE *fp = fopen(export_path, "w");
    if (fp == NULL) {
        fprintf(stderr, "Error opening %s: %s\n", export_path, strerror(errno));
        return -1;
    }

    fprintf(fp, "%d", pin);
    fclose(fp);

    return 0;
}

// Function to unexport a GPIO pin
int gpio_unexport(int pin) {
    char unexport_path[64];
    snprintf(unexport_path, sizeof(unexport_path), GPIO_PATH "/unexport");

    FILE *fp = fopen(unexport_path, "w");
    if (fp == NULL) {
        fprintf(stderr, "Error opening %s: %s\n", unexport_path, strerror(errno));
        return -1;
    }

    fprintf(fp, "%d", pin);
    fclose(fp);

    return 0;
}

// Function to set the direction of a GPIO pin (in or out)
int gpio_set_direction(int pin, char *direction) {
    char direction_path[64];
    snprintf(direction_path, sizeof(direction_path), GPIO_PATH "/gpio%d/direction", pin);

    FILE *fp = fopen(direction_path, "w");
    if (fp == NULL) {
        fprintf(stderr, "Error opening %s: %s\n", direction_path, strerror(errno));
        return -1;
    }

    fprintf(fp, "%s", direction);
    fclose(fp);

    return 0;
}

// Function to set the value of a GPIO pin (0 or 1)
int gpio_set_value(int pin, int value) {
    char value_path[64];
    snprintf(value_path, sizeof(value_path), GPIO_PATH "/gpio%d/value", pin);

    FILE *fp = fopen(value_path, "w");
    if (fp == NULL) {
        fprintf(stderr, "Error opening %s: %s\n", value_path, strerror(errno));
        return -1;
    }

    fprintf(fp, "%d", value);
    fclose(fp);

    return 0;
}

// Function to calculate the CPU load percentage
float calculate_cpu_load() {
    FILE *fp;
    unsigned long long user, nice, system, idle, iowait, irq, softirq, steal, guest, guest_nice;
    unsigned long long total_cpu_time, idle_time;
    static unsigned long long prev_total_cpu_time = 0, prev_idle_time = 0;

    fp = fopen("/proc/stat", "r");
    if (fp == NULL) {
        fprintf(stderr, "Error opening /proc/stat: %s\n", strerror(errno));
        return -1.0;
    }

    fscanf(fp, "cpu  %llu %llu %llu %llu %llu %llu %llu %llu %llu %llu",
           &user, &nice, &system, &idle, &iowait, &irq, &softirq, &steal, &guest, &guest_nice);
    fclose(fp);

    total_cpu_time = user + nice + system + idle + iowait + irq + softirq + steal + guest + guest_nice;
    idle_time = idle + iowait;

    float cpu_load = 1.0 - (float)(idle_time - prev_idle_time) / (total_cpu_time - prev_total_cpu_time);

    prev_total_cpu_time = total_cpu_time;
    prev_idle_time = idle_time;

    return cpu_load * 100.0;
}

// Function to map CPU load percentage to RGB color values
void map_load_to_color(float cpu_load, int *red, int *green, int *blue) {
    if (cpu_load <= 33.0) {
        // Blue to Green
        *red = 0;
        *green = (int)(cpu_load / 33.0 * 255.0);
        *blue = 255 - (int)(cpu_load / 33.0 * 255.0);
    } else if (cpu_load <= 66.0) {
        // Green to Yellow
        *red = (int)((cpu_load - 33.0) / 33.0 * 255.0);
        *green = 255;
        *blue = 0;
    } else {
        // Yellow to Red
        *red = 255;
        *green = 255 - (int)((cpu_load - 66.0) / 34.0 * 255.0);
        *blue = 0;
    }
}

int main() {
    // Install signal handler for Ctrl+C
    signal(SIGINT, cleanup_handler);

    // Export GPIO pins
    if (gpio_export(RED_PIN) != 0 ||
        gpio_export(GREEN_PIN) != 0 ||
        gpio_export(BLUE_PIN) != 0) {
        fprintf(stderr, "Failed to export GPIO pins. Exiting.\n");
        return 1;
    }

    // Set GPIO direction to output
    if (gpio_set_direction(RED_PIN, "out") != 0 ||
        gpio_set_direction(GREEN_PIN, "out") != 0 ||
        gpio_set_direction(BLUE_PIN, "out") != 0) {
        fprintf(stderr, "Failed to set GPIO direction. Exiting.\n");
        gpio_unexport(RED_PIN);
        gpio_unexport(GREEN_PIN);
        gpio_unexport(BLUE_PIN);
        return 1;
    }

    struct timespec sleep_time;
    sleep_time.tv_sec = 0;
    sleep_time.tv_nsec = 500000000; // 0.5 seconds

    while (program_running) {
        float cpu_load = calculate_cpu_load();

        if (cpu_load < 0.0) {
            fprintf(stderr, "Failed to calculate CPU load. Retrying.\n");
            nanosleep(&sleep_time, NULL);
            continue;
        }

        int red, green, blue;
        map_load_to_color(cpu_load, &red, &green, &blue);

        // Set GPIO values (0 or 1, adjust for common anode/cathode if needed)
        gpio_set_value(RED_PIN, red > 127 ? 1 : 0); // Example for common cathode
        gpio_set_value(GREEN_PIN, green > 127 ? 1 : 0);
        gpio_set_value(BLUE_PIN, blue > 127 ? 1 : 0);

        printf("CPU Load: %.2f%%, RGB: (%d, %d, %d)\n", cpu_load, red, green, blue);

        nanosleep(&sleep_time, NULL);
    }

    // Unexport GPIO pins before exiting
    gpio_unexport(RED_PIN);
    gpio_unexport(GREEN_PIN);
    gpio_unexport(BLUE_PIN);

    return 0;
}

