// Define constants for dot and dash durations in milliseconds
#define DOT_DURATION 100
#define DASH_DURATION (DOT_DURATION * 3)

// Define constants for inter-element, inter-character, and inter-word spaces
#define INTER_ELEMENT_SPACE DOT_DURATION
#define INTER_CHARACTER_SPACE (DOT_DURATION * 3)
#define INTER_WORD_SPACE (DOT_DURATION * 7)

// Define the GPIO pin connected to the LED
