// Define the I2C address of the BH1750 sensor
#define BH1750_I2C_ADDR 0x23

// Define the GPIO pin for the LED
#define LED_PIN 18

// Global variable to track if the program should exit
volatile sig_atomic_t program_running = 1;

// Signal handler for Ctrl+C (SIGINT)
void signal_handler(int signal) {
    (void)signal; // Suppress unused parameter warning
    program_running = 0;
    printf("\nExiting gracefully...\n");
}

// Function to read illuminance data from the BH1750 sensor
float read_bh1750(int fd) {
    // Send command 0x10 for high-resolution mode
    int raw_value = wiringPiI2CReadReg16(fd, 0x10);

    if (raw_value == -1) {
        fprintf(stderr, "Error reading data from BH1750!\n");
        return -1.0f; // Indicate an error with a negative value
    }

    // Byte swap the raw value (BH1750 returns MSB first)
    uint16_t swapped_value = (raw_value >> 8) | (raw_value << 8);

    // Convert the raw value to lux
    float lux = (float)swapped_value / 1.2f;  //BH1750 datasheet says to divide by 1.2
    return lux;
}

// Function to process the illuminance data
bool process_illuminance(float lux) {
    // Return true if illuminance is below 50 lux, false otherwise
    return (lux < 50.0f);
}

// Function to control the LED
void control_led(int gpio_pin, int state) {
    digitalWrite(gpio_pin, state);
}

int main() {
    // Set up signal handling for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize wiringPi with GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi!\n");
        return EXIT_FAILURE;
    }

    // Set the LED pin as output
    pinMode(LED_PIN, OUTPUT);

    // Open the I2C device
    int fd = wiringPiI2CSetup(BH1750_I2C_ADDR);
    if (fd == -1) {
        fprintf(stderr, "Error opening I2C device!\n");
        return EXIT_FAILURE;
    }

    printf("BH1750 Light Sensor and LED Control\n");

    // Main loop
    while (program_running) {
        // Read illuminance data
        float lux = read_bh1750(fd);

        if (lux >= 0) { // Check for read error
            // Process the data
            bool turn_on_led = process_illuminance(lux);

            // Control the LED
            control_led(LED_PIN, turn_on_led);

            // Print the illuminance value
            printf("Illuminance: %.2f lux, LED: %s\n", lux, turn_on_led ? "ON" : "OFF");
        } else {
            fprintf(stderr, "Error reading illuminance. Skipping LED control.\n");
        }

        // Wait for 1 second
        delay(1000);
    }

    // Ensure LED is turned off before exiting
    control_led(LED_PIN, LOW);

    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>
#include <stdint.h>

// Define GPIO pins
#define TRIGGER_PIN 17
#define ECHO_PIN 18
#define BUZZER_PIN 27

// Define distance threshold (in cm)
#define DISTANCE_THRESHOLD 20.0f

// Define speed of sound (cm/µs)
#define SPEED_OF_SOUND 0.0343f

// Global variable to store the pulse width
volatile uint32_t pulse_width = 0;
volatile uint32_t start_tick = 0;

// Function prototypes
void echo_callback(int gpio, int level, uint32_t tick);
float calculate_distance(uint32_t pulse_width);
void buzzer_on(void);
void buzzer_off(void);
void check_distance_and_buzz(float distance);
void trigger_pulse(void);
void signal_handler(int signal);

// Signal handler function
void signal_handler(int signal)
{
    if (signal == SIGINT)
    {
        printf("Ctrl+C detected. Exiting gracefully.\n");
        gpioTerminate(); // Release pigpio resources
        exit(0);         // Exit the program
    }
}

// Interrupt handler for echo pin
void echo_callback(int gpio, int level, uint32_t tick)
{
    if (level == 1) // Rising edge
    {
        start_tick = tick;
    }
    else if (level == 0) // Falling edge
    {
        if (start_tick != 0)
        {
            pulse_width = tick - start_tick;
            start_tick = 0; // Reset start_tick for the next measurement
        }
    }
}

// Function to calculate distance in centimeters
float calculate_distance(uint32_t pulse_width)
{
    return (pulse_width * SPEED_OF_SOUND) / 2.0f;
}

// Function to turn the buzzer on
void buzzer_on(void)
{
    gpioWrite(BUZZER_PIN, 1); // Set BUZZER_PIN high
}

// Function to turn the buzzer off
void buzzer_off(void)
{
    gpioWrite(BUZZER_PIN, 0); // Set BUZZER_PIN low
}

// Function to check distance and activate buzzer
void check_distance_and_buzz(float distance)
{
    if (distance < DISTANCE_THRESHOLD)
    {
        buzzer_on(); // Turn buzzer on if distance is below threshold
    }
    else
    {
        buzzer_off(); // Turn buzzer off if distance is above threshold
    }
}

// Function to generate a 10µs trigger pulse
void trigger_pulse(void)
{
    gpioWrite(TRIGGER_PIN, 1); // Set TRIGGER_PIN high
    gpioDelay(10);             // Wait for 10µs
    gpioWrite(TRIGGER_PIN, 0); // Set TRIGGER_PIN low
}

int main(void)
{
    // Initialize pigpio library
    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "pigpio initialisation failed\n");
        exit(EXIT_FAILURE);
    }

    // Configure GPIO pins
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT); // Trigger pin as output
    gpioSetMode(ECHO_PIN, PI_INPUT);   // Echo pin as input
    gpioSetMode(BUZZER_PIN, PI_OUTPUT); // Buzzer pin as output

    // Register interrupt handler for echo pin
    gpioSetAlertFuncEx(ECHO_PIN, echo_callback, NULL);

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Ultrasonic sensor with buzzer started. Press Ctrl+C to exit.\n");

    // Main loop
    while (1)
    {
        trigger_pulse();                // Generate trigger pulse
        gpioDelay(200);                  // Wait for a short period (adjust as needed)

        // Calculate distance
        float distance = calculate_distance(pulse_width);
        printf("Distance: %.2f cm\n", distance);

        // Check distance and activate buzzer
        check_distance_and_buzz(distance);

        sleep(1); // Wait for 1 second
    }

    return 0;
}

