#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <pthread.h>
#include <errno.h>
#include <string.h>
#include <unistd.h>
#include <wiringPi.h>

// Constants
#define BUTTON_GPIO_PIN 17          // BCM GPIO pin for the button
#define DEBOUNCE_DELAY_MS 100       // Debounce delay in milliseconds
#define INTERRUPT_PRIORITY 50       // Priority of the interrupt thread (1-99, higher is more important)

// Global variables
static volatile uint32_t interrupt_count = 0; // Counter for interrupts
static pthread_mutex_t interrupt_mutex = PTHREAD_MUTEX_INITIALIZER; // Mutex for interrupt counter
static volatile uint32_t last_interrupt_time = 0; // Last interrupt time

// Function prototypes
void* interrupt_handler_thread(void* arg);
int initialize_gpio(int pin);


// Interrupt handler thread function
void* interrupt_handler_thread(void* arg) {
    (void)arg; // Suppress unused parameter warning

    if (piHiPri(INTERRUPT_PRIORITY) != 0) {
        fprintf(stderr, "Error: Failed to set thread priority: %s\n", strerror(errno));
        pthread_exit(NULL);
    }

    while (true) {
        if (waitForInterrupt(BUTTON_GPIO_PIN, -1) < 0) {
            fprintf(stderr, "Error: waitForInterrupt failed: %s\n", strerror(errno));
            delay(100); // Prevent busy-waiting on error
            continue;
        }

        uint32_t current_time = millis();
        if (current_time - last_interrupt_time > DEBOUNCE_DELAY_MS) {
            // Debounced interrupt
            pthread_mutex_lock(&interrupt_mutex);
            interrupt_count++;
            pthread_mutex_unlock(&interrupt_mutex);
            last_interrupt_time = current_time;

            // Wait for button release (optional, but prevents multiple counts from a single press)
            while (digitalRead(BUTTON_GPIO_PIN) == LOW) {
                delay(1); // Small delay to avoid busy-waiting
            }
        }
    }
    return NULL;
}

// Initialize GPIO pin for interrupt
int initialize_gpio(int pin) {
    if (wiringPiSetupSys() == -1) {
        fprintf(stderr, "Error: wiringPiSetup failed: %s\n", strerror(errno));
        return -1;
    }

    pinMode(pin, INPUT);
    pullUpDnControl(pin, PUD_UP); // Enable pull-up resistor

    // Export GPIO pin for edge detection (using system calls for broader compatibility)
    char command[64];
    snprintf(command, sizeof(command), "gpio edge %d falling", pin);
    if (system(command) != 0) {
        fprintf(stderr, "Error: Failed to set edge detection for GPIO %d\n", pin);
        return -1;
    }

    return 0;
}

int main() {
    pthread_t interrupt_thread;
    int return_code = EXIT_FAILURE;
    uint32_t previous_count = 0;

    // Initialize GPIO
    if (initialize_gpio(BUTTON_GPIO_PIN) != 0) {
        fprintf(stderr, "GPIO initialization failed. Exiting.\n");
        return EXIT_FAILURE;
    }

    // Create interrupt handler thread
    if (pthread_create(&interrupt_thread, NULL, interrupt_handler_thread, NULL) != 0) {
        fprintf(stderr, "Error: Failed to create interrupt thread: %s\n", strerror(errno));
        return EXIT_FAILURE;
    }

    printf("Interrupt counter started. Press button on GPIO %d to increment counter.\n", BUTTON_GPIO_PIN);

    // Main loop to print the interrupt count
    while (true) {
        delay(1000);
        pthread_mutex_lock(&interrupt_mutex);
        uint32_t current_count = interrupt_count;
        pthread_mutex_unlock(&interrupt_mutex);

        if (current_count != previous_count) {
            printf("Interrupt count: %u\n", current_count);
            previous_count = current_count;
        }
    }

    // Cleanup (This part is unreachable in this example but good practice)
    pthread_cancel(interrupt_thread);
    pthread_join(interrupt_thread, NULL);
    pthread_mutex_destroy(&interrupt_mutex);

    return return_code;
}

#include <stdio.h>
