// Minimum and maximum PWM frequencies
#define MIN_FREQUENCY 50.0
#define MAX_FREQUENCY 200.0

// Minimum and maximum CPU temperatures for frequency mapping
#define MIN_TEMP 40.0
#define MAX_TEMP 80.0

// Global variable to track whether the program should exit
volatile sig_atomic_t program_running = 1;

// Signal handler for SIGINT (Ctrl+C)
void signal_handler(int sig) {
    if (sig == SIGINT) {
        program_running = 0;
        printf("\nCaught SIGINT, exiting gracefully...\n");
    }
}

// Function to read the CPU temperature from the thermal zone file
int read_cpu_temperature() {
    FILE *fp;
    int temperature_millidegrees;

    fp = fopen(TEMP_FILE, "r");
    if (fp == NULL) {
        fprintf(stderr, "Error opening temperature file: %s\n", strerror(errno));
        return -1;
    }

    if (fscanf(fp, "%d", &temperature_millidegrees) != 1) {
        fprintf(stderr, "Error reading temperature from file\n");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return temperature_millidegrees / 1000; // Convert to degrees Celsius
}

// Function to export a GPIO pin
int gpio_export(int pin) {
    char buffer[3];
    int fd;

    fd = open("/sys/class/gpio/export", O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Error opening /sys/class/gpio/export: %s\n", strerror(errno));
        return -1;
    }

    int len = snprintf(buffer, sizeof(buffer), "%d", pin);
    if (write(fd, buffer, len) != len) {
        fprintf(stderr, "Error writing to /sys/class/gpio/export: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to unexport a GPIO pin
int gpio_unexport(int pin) {
    char buffer[3];
    int fd;

    fd = open("/sys/class/gpio/unexport", O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Error opening /sys/class/gpio/unexport: %s\n", strerror(errno));
        return -1;
    }

    int len = snprintf(buffer, sizeof(buffer), "%d", pin);
    if (write(fd, buffer, len) != len) {
        fprintf(stderr, "Error writing to /sys/class/gpio/unexport: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to set the direction of a GPIO pin (in or out)
int gpio_set_direction(int pin, char *direction) {
    char path[64];
    int fd;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/direction", pin);
    fd = open(path, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Error opening %s: %s\n", path, strerror(errno));
        return -1;
    }

    if (write(fd, direction, strlen(direction)) != strlen(direction)) {
        fprintf(stderr, "Error writing to %s: %s\n", path, strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to write a value to a GPIO pin (0 or 1)
int gpio_write(int pin, int value) {
    char path[64];
    int fd;
    char val_str[2];

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", pin);
    fd = open(path, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Error opening %s: %s\n", path, strerror(errno));
        return -1;
    }

    snprintf(val_str, sizeof(val_str), "%d", value);
    if (write(fd, val_str, 1) != 1) {
        fprintf(stderr, "Error writing to %s: %s\n", path, strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to simulate PWM by toggling the GPIO pin
void set_pwm_frequency(int pin, float frequency) {
    if (frequency < MIN_FREQUENCY) {
        frequency = MIN_FREQUENCY;
    } else if (frequency > MAX_FREQUENCY) {
        frequency = MAX_FREQUENCY;
    }

    // Calculate the period and half-period (on/off time)
    float period = 1.0 / frequency;
    float half_period = period / 2.0;

    // Convert half-period to microseconds
    int delay_us = (int)(half_period * 1000000);

    // Toggle the GPIO pin
    gpio_write(pin, 1); // ON
    usleep(delay_us);
    gpio_write(pin, 0); // OFF
    usleep(delay_us);
}

// Function to control motor 1
void control_motor1(float frequency) {
    set_pwm_frequency(MOTOR1_PIN, frequency);
}

// Function to control motor 2
void control_motor2(float frequency) {
    set_pwm_frequency(MOTOR2_PIN, frequency);
}

int main() {
    int temperature;
    float frequency1, frequency2;

    // Install signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Export the GPIO pins
    if (gpio_export(MOTOR1_PIN) < 0) return 1;
    if (gpio_export(MOTOR2_PIN) < 0) {
        gpio_unexport(MOTOR1_PIN);
        return 1;
    }

    // Set the GPIO pin direction to output
    if (gpio_set_direction(MOTOR1_PIN, "out") < 0) {
        gpio_unexport(MOTOR1_PIN);
        gpio_unexport(MOTOR2_PIN);
        return 1;
    }
    if (gpio_set_direction(MOTOR2_PIN, "out") < 0) {
        gpio_unexport(MOTOR1_PIN);
        gpio_unexport(MOTOR2_PIN);
        return 1;
    }

    printf("Starting motor control loop...\n");

    while (program_running) {
        // Read the CPU temperature
        temperature = read_cpu_temperature();
        if (temperature < 0) {
            fprintf(stderr, "Error reading CPU temperature, using default values.\n");
            temperature = (int)((MIN_TEMP + MAX_TEMP) / 2.0); // Use a default temperature
        }

        // Map the temperature to a PWM frequency
        frequency1 = MIN_FREQUENCY + (temperature - MIN_TEMP) * (MAX_FREQUENCY - MIN_FREQUENCY) / (MAX_TEMP - MIN_TEMP);
        frequency2 = MIN_FREQUENCY + (temperature - MIN_TEMP) * (MAX_FREQUENCY - MIN_FREQUENCY) / (MAX_TEMP - MIN_TEMP);

        // Control the motors
        control_motor1(frequency1);
        control_motor2(frequency2);

        // Wait 5 seconds
        sleep(5);
    }

    // Unexport the GPIO pins before exiting
    gpio_unexport(MOTOR1_PIN);
    gpio_unexport(MOTOR2_PIN);

    printf("Exiting.\n");
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <time.h>
#include <signal.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>

// TCS34725 Registers
#define TCS34725_ADDRESS          (0x29)
#define TCS34725_COMMAND_BIT      (0x80)
#define TCS34725_ENABLE           (0x00)
#define TCS34725_ENABLE_PON       (0x01)
#define TCS34725_ENABLE_AEN       (0x02)
#define TCS34725_ID               (0x12)
#define TCS34725_ATIME            (0x01)
#define TCS34725_CONTROL          (0x0F)
#define TCS34725_CDATA            (0x14)
#define TCS34725_RDATA            (0x16)
#define TCS34725_GDATA            (0x18)
#define TCS34725_BDATA            (0x1A)

// Calibration Constants
#define RED_CALIBRATION   (1.0)
#define GREEN_CALIBRATION (1.0)
#define BLUE_CALIBRATION  (1.0)

// GPIO Pin for Control
#define GPIO_PIN            (20)

// Global Variables
int fd;
FILE *log_file;
volatile sig_atomic_t program_running = 1;

// Function Prototypes
int tcs34725_init();
void tcs34725_read_raw_data(uint16_t *r, uint16_t *g, uint16_t *b, uint16_t *c);
void tcs34725_calibrate_data(uint16_t raw_r, uint16_t raw_g, uint16_t raw_b, uint16_t *calibrated_r, uint16_t *calibrated_g, uint16_t *calibrated_b);
void log_data(uint16_t r, uint16_t g, uint16_t b);
void control_gpio(uint16_t r, uint16_t g, uint16_t b);
void cleanup_handler(int signum);


/**
 * @brief Initializes the TCS34725 color sensor.
 * @return 0 on success, -1 on failure.
 */
int tcs34725_init() {
    // Initialize I2C
    fd = wiringPiI2CSetup(TCS34725_ADDRESS);
    if (fd == -1) {
        fprintf(stderr, "Error: Failed to initialize I2C communication.\n");
        return -1;
    }

    // Check sensor ID
    int sensor_id = wiringPiI2CReadReg8(fd, TCS34725_COMMAND_BIT | TCS34725_ID);
    if (sensor_id != 0x44) {
        fprintf(stderr, "Error: Invalid sensor ID: 0x%02X\n", sensor_id);
        return -1;
    }

    // Enable power and ALS
    wiringPiI2CWriteReg8(fd, TCS34725_COMMAND_BIT | TCS34725_ENABLE, TCS34725_ENABLE_PON | TCS34725_ENABLE_AEN);

    // Set integration time (ATIME) - 2.4ms
    wiringPiI2CWriteReg8(fd, TCS34725_COMMAND_BIT | TCS34725_ATIME, 0xFF);

    // Set gain (AGAIN) - 4x
    wiringPiI2CWriteReg8(fd, TCS34725_COMMAND_BIT | TCS34725_CONTROL, 0x01);

    return 0;
}

/**
 * @brief Reads raw RGBC data from the TCS34725 sensor.
 * @param r Pointer to store the raw red value.
 * @param g Pointer to store the raw green value.
 * @param b Pointer to store the raw blue value.
 * @param c Pointer to store the raw clear value.
 */
void tcs34725_read_raw_data(uint16_t *r, uint16_t *g, uint16_t *b, uint16_t *c) {
    *c = wiringPiI2CReadReg16(fd, TCS34725_COMMAND_BIT | TCS34725_CDATA);
    *r = wiringPiI2CReadReg16(fd, TCS34725_COMMAND_BIT | TCS34725_RDATA);
    *g = wiringPiI2CReadReg16(fd, TCS34725_COMMAND_BIT | TCS34725_GDATA);
    *b = wiringPiI2CReadReg16(fd, TCS34725_COMMAND_BIT | TCS34725_BDATA);
}

/**
 * @brief Calibrates the raw RGBC data using predefined calibration constants.
 * @param raw_r Raw red value.
 * @param raw_g Raw green value.
 * @param raw_b Raw blue value.
 * @param calibrated_r Pointer to store the calibrated red value.
 * @param calibrated_g Pointer to store the calibrated green value.
 * @param calibrated_b Pointer to store the calibrated blue value.
 */
void tcs34725_calibrate_data(uint16_t raw_r, uint16_t raw_g, uint16_t raw_b, uint16_t *calibrated_r, uint16_t *calibrated_g, uint16_t *calibrated_b) {
    *calibrated_r = (uint16_t)(raw_r * RED_CALIBRATION);
    *calibrated_g = (uint16_t)(raw_g * GREEN_CALIBRATION);
    *calibrated_b = (uint16_t)(raw_b * BLUE_CALIBRATION);
}

/**
 * @brief Logs the calibrated RGBC data to a file.
 * @param r Calibrated red value.
 * @param g Calibrated green value.
 * @param b Calibrated blue value.
 */
void log_data(uint16_t r, uint16_t g, uint16_t b) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(log_file, "%s,%u,%u,%u\n", timestamp, r, g, b);
    fflush(log_file); // Ensure data is written immediately
}

/**
 * @brief Controls a GPIO pin based on the calibrated RGB values.
 *        If red > (green + blue), activate the GPIO pin.
 * @param r Calibrated red value.
 * @param g Calibrated green value.
 * @param b Calibrated blue value.
 */
void control_gpio(uint16_t r, uint16_t g, uint16_t b) {
    if (r > (g + b)) {
        digitalWrite(GPIO_PIN, HIGH); // Activate GPIO
    } else {
        digitalWrite(GPIO_PIN, LOW);  // Deactivate GPIO
    }
}

/**
 * @brief Signal handler for Ctrl+C (SIGINT).
 *        Disables the sensor, closes the log file, and sets GPIO to LOW.
 * @param signum Signal number.
 */
void cleanup_handler(int signum) {
    printf("\nCaught signal %d, cleaning up...\n", signum);
    program_running = 0;

    // Disable sensor (optional, but good practice)
    wiringPiI2CWriteReg8(fd, TCS34725_COMMAND_BIT | TCS34725_ENABLE, 0x00);

    // Close log file
    if (log_file != NULL) {
        fclose(log_file);
    }

    // Set GPIO to LOW
    digitalWrite(GPIO_PIN, LOW);

    exit(0);
}

int main() {
    // Initialize WiringPi with GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error: Failed to initialize WiringPi GPIO.\n");
        return 1;
    }

    // Set GPIO pin as output
    pinMode(GPIO_PIN, OUTPUT);

    // Initialize the TCS34725 sensor
    if (tcs34725_init() == -1) {
        fprintf(stderr, "Error: Failed to initialize TCS34725 sensor.\n");
        return 1;
    }

    // Open log file
    log_file = fopen("color_data.log", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error: Failed to open log file.\n");
        return 1;
    }

    // Register signal handler
    signal(SIGINT, cleanup_handler);

    printf("Color data logging started. Press Ctrl+C to exit.\n");

    uint16_t raw_red, raw_green, raw_blue, raw_clear;
    uint16_t calibrated_red, calibrated_green, calibrated_blue;

    while (program_running) {
        // Read raw data
        tcs34725_read_raw_data(&raw_red, &raw_green, &raw_blue, &raw_clear);

        // Calibrate data
        tcs34725_calibrate_data(raw_red, raw_green, raw_blue, &calibrated_red, &calibrated_green, &calibrated_blue);

        // Log data
        log_data(calibrated_red, calibrated_green, calibrated_blue);

        // Control GPIO
        control_gpio(calibrated_red, calibrated_green, calibrated_blue);

        delay(500); // Wait 500 milliseconds
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <gpiod.h>
#include <time.h>
#include <string.h>
#include <signal.h>
#include <unistd.h>

// Define the GPIO pins
#define BUZZER_PIN 18
#define SOUND_SENSOR_PIN 23

// Define the sound threshold
#define SOUND_THRESHOLD 1 // Since KY-038 provides digital output

// Define the GPIO chip name
#define GPIOCHIP "gpiochip0"

// Global variables for GPIO lines and chip (required for signal handler)
struct gpiod_line *buzzer_line = NULL;
struct gpiod_line *sound_sensor_line = NULL;
struct gpiod_chip *chip = NULL;

// Function to log alarm events to a file
void log_alarm(const char *message) {
    FILE *fp = fopen("/var/log/alarm.log", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file: /var/log/alarm.log\n");
        perror("fopen");
        return;
    }

    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char s[64];
    strftime(s, sizeof(s), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(fp, "%s - %s\n", s, message);

    if (fclose(fp) != 0) {
        fprintf(stderr, "Error closing log file.\n");
        perror("fclose");
    }
}

// Function to read the sound sensor value
int read_sound_sensor(struct gpiod_line *line) {
    int value = gpiod_line_get_value(line);
    if (value < 0) {
        fprintf(stderr, "Error reading sound sensor value.\n");
        perror("gpiod_line_get_value");
        return -1;
    }
    return value;
}

// Function to control the buzzer
void control_buzzer(struct gpiod_line *line, int state) {
    int ret = gpiod_line_set_value(line, state);
    if (ret < 0) {
        fprintf(stderr, "Error setting buzzer state.\n");
        perror("gpiod_line_set_value");
    }
}

// Signal handler for graceful shutdown
void signal_handler(int sig) {
    printf("Caught signal %d, releasing resources...\n", sig);

    if (buzzer_line) {
        gpiod_line_release(buzzer_line);
    }
    if (sound_sensor_line) {
        gpiod_line_release(sound_sensor_line);
    }
    if (chip) {
        gpiod_chip_close(chip);
    }

    printf("Resources released, exiting.\n");
    exit(0);
}

int main() {
    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Open the GPIO chip
    chip = gpiod_chip_open_by_name(GPIOCHIP);
    if (!chip) {
        fprintf(stderr, "Error opening GPIO chip '%s'.\n", GPIOCHIP);
        perror("gpiod_chip_open_by_name");
        return 1;
    }

    // Get the line for the buzzer
    buzzer_line = gpiod_chip_get_line(chip, BUZZER_PIN);
    if (!buzzer_line) {
        fprintf(stderr, "Error getting line for buzzer (GPIO%d).\n", BUZZER_PIN);
        perror("gpiod_chip_get_line");
        gpiod_chip_close(chip);
        return 1;
    }

    // Get the line for the sound sensor
    sound_sensor_line = gpiod_chip_get_line(chip, SOUND_SENSOR_PIN);
    if (!sound_sensor_line) {
        fprintf(stderr, "Error getting line for sound sensor (GPIO%d).\n", SOUND_SENSOR_PIN);
        perror("gpiod_chip_get_line");
        gpiod_line_release(buzzer_line);
        gpiod_chip_close(chip);
        return 1;
    }

    // Request the buzzer line for output
    if (gpiod_line_request_output(buzzer_line, "alarm", 0) < 0) {
        fprintf(stderr, "Error requesting buzzer line for output.\n");
        perror("gpiod_line_request_output");
        gpiod_line_release(sound_sensor_line);
        gpiod_line_release(buzzer_line);
        gpiod_chip_close(chip);
        return 1;
    }

    // Request the sound sensor line for input
    if (gpiod_line_request_input(sound_sensor_line, "sound_sensor") < 0) {
        fprintf(stderr, "Error requesting sound sensor line for input.\n");
        perror("gpiod_line_request_input");
        gpiod_line_release(buzzer_line);
        gpiod_chip_close(chip);
        return 1;
    }

    printf("Alarm system initialized. Press Ctrl+C to exit.\n");

    // Main loop
    while (1) {
        int sound_level = read_sound_sensor(sound_sensor_line);
        if (sound_level < 0) {
            log_alarm("Error reading sound sensor, exiting.");
            break;
        }

        if (sound_level > 0) { //Digital signal
            control_buzzer(buzzer_line, 1);
            log_alarm("Sound threshold exceeded!");
            sleep(1);
            control_buzzer(buzzer_line, 0);
        }

        usleep(100000); // Check every 100ms
    }

    // Release resources before exiting (in case the loop breaks)
    gpiod_line_release(buzzer_line);
    gpiod_line_release(sound_sensor_line);
    gpiod_chip_close(chip);

    return 0;
}

#include <stdio.h>
