#define BUTTON_PIN 3  // WiringPi pin 3 (BCM GPIO 22)
#define PWM_LED_PIN 1  // WiringPi pin 1 (BCM GPIO 18) - PWM capable
#define REGULAR_LED_PIN 0 // WiringPi pin 0 (BCM GPIO 17)

int main(void) {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi setup failed!\n");
        return 1;
    }

    pinMode(BUTTON_PIN, INPUT);
pinMode(REGULAR_LED_PIN, OUTPUT);
    softPwmCreate(PWM_LED_PIN, 0, 100); // Initialize PWM on PWM_LED_PIN, range 0-100

    int pwm_value = 0;
    int button_state = 0;
    int last_button_state = 0;
    int led_state = 0; // 0 for off, 1 for on

    while (1) {
        button_state = digitalRead(BUTTON_PIN);

        if (button_state == HIGH && last_button_state == LOW) {
            // Button pressed (rising edge)
            if (pwm_value == 0) {
                pwm_value = 100; // Set PWM to bright
            } else {
                pwm_value = 0; // Set PWM to dim
            }
            softPwmWrite(PWM_LED_PIN, pwm_value);
            delay(50); // Debounce delay
        }

        last_button_state = button_state;

       // Toggle the regular LED every 100ms
        if (led_state == 0) {
            digitalWrite(REGULAR_LED_PIN, HIGH);
            led_state = 1;
        } else {
            digitalWrite(REGULAR_LED_PIN, LOW);
            led_state = 0;
        }
        delay(100);
    }

    return 0;
}

