#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Define GPIO pins for relays
#define RELAY1_PIN 17
#define RELAY2_PIN 18
#define RELAY3_PIN 22
#define RELAY4_PIN 23

// Define I2C address for BH1750 sensor
#define BH1750_ADDR 0x23

// Define BH1750 measurement command (Continuous H-resolution Mode)
#define BH1750_CONTINUOUS_HIGH_RES_MODE 0x10

// Global variable for I2C handle
int i2c_handle;

// Global variable for logging file pointer
FILE *log_file;

// Function prototypes
void cleanup(int signal);
double calculate_lux(uint16_t raw_data);
void set_relay_state(int relay_pin, int state);
void adjust_brightness(double lux);
int initialize_i2c();
void log_data(double lux, int relay1_state, int relay2_state, int relay3_state, int relay4_state);

// Function to handle signals (e.g., Ctrl+C)
void cleanup(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);

    // Turn off all relays
    set_relay_state(RELAY1_PIN, 0);
    set_relay_state(RELAY2_PIN, 0);
    set_relay_state(RELAY3_PIN, 0);
    set_relay_state(RELAY4_PIN, 0);

    // Close I2C connection
    if (i2c_handle >= 0) {
        i2cClose(i2c_handle);
    }

    // Close log file
    if (log_file != NULL) {
        fclose(log_file);
    }

    // Stop pigpio
    gpioTerminate();

    exit(0);
}

// Function to calculate lux value from raw sensor data (pure function)
double calculate_lux(uint16_t raw_data) {
    return (double)raw_data / 1.2; // BH1750 datasheet conversion
}

// Function to set the state of a relay (0 = off, 1 = on)
void set_relay_state(int relay_pin, int state) {
    gpioWrite(relay_pin, state);
}

// Function to adjust brightness based on lux value
void adjust_brightness(double lux) {
    int relay1_state = 0, relay2_state = 0, relay3_state = 0, relay4_state = 0;

    if (lux <= 100) {
        // All relays on
        relay1_state = 1;
        relay2_state = 1;
        relay3_state = 1;
        relay4_state = 1;
    } else if (lux <= 200) {
        // 3 relays on
        relay1_state = 1;
        relay2_state = 1;
        relay3_state = 1;
    } else if (lux <= 300) {
        // 2 relays on
        relay1_state = 1;
        relay2_state = 1;
    } else if (lux <= 400) {
        // 1 relay on
        relay1_state = 1;
    } else {
        // All relays off
        // Already initialized to 0, no action needed
    }

    set_relay_state(RELAY1_PIN, relay1_state);
    set_relay_state(RELAY2_PIN, relay2_state);
    set_relay_state(RELAY3_PIN, relay3_state);
    set_relay_state(RELAY4_PIN, relay4_state);

    log_data(lux, relay1_state, relay2_state, relay3_state, relay4_state);
}

// Function to initialize I2C communication
int initialize_i2c() {
    i2c_handle = i2cOpen(1, BH1750_ADDR, 0); // Bus 1, address 0x23, no flags
    if (i2c_handle < 0) {
        fprintf(log_file, "%s", "Error opening I2C channel\n");
        fflush(log_file);
        return -1; // Indicate failure
    }

    // Send measurement command
    if (i2cWriteByteData(i2c_handle, 0x00, BH1750_CONTINUOUS_HIGH_RES_MODE) < 0) {
        fprintf(log_file, "%s", "Error writing to I2C channel\n");
        fflush(log_file);
        i2cClose(i2c_handle);
        return -1; // Indicate failure
    }

    return 0; // Indicate success
}

// Function to log data to a file
void log_data(double lux, int relay1_state, int relay2_state, int relay3_state, int relay4_state) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(log_file, "%s - Lux: %.2f, Relays: %d %d %d %d\n", timestamp, lux, relay1_state, relay2_state, relay3_state, relay4_state);
    fflush(log_file); // Ensure data is written to the file immediately
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pins to output mode
    gpioSetMode(RELAY1_PIN, PI_OUTPUT);
    gpioSetMode(RELAY2_PIN, PI_OUTPUT);
    gpioSetMode(RELAY3_PIN, PI_OUTPUT);
    gpioSetMode(RELAY4_PIN, PI_OUTPUT);

    // Open log file
    log_file = fopen("lighting_log.txt", "a");
    if (log_file == NULL) {
        perror("Error opening log file");
        gpioTerminate();
        return 1;
    }

    // Initialize I2C
    if (initialize_i2c() != 0) {
        fprintf(stderr, "I2C initialization failed\n");
        fclose(log_file);
        gpioTerminate();
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, cleanup);
    signal(SIGTERM, cleanup);

    uint16_t raw_data;
    double lux;

    while (1) {
        // Read data from BH1750 sensor
        raw_data = i2cReadWordData(i2c_handle, 0x00); // Dummy register address
        if (raw_data >= 0) {
            // Byte order is swapped, so reverse it.
            raw_data = (raw_data >> 8) | (raw_data << 8);

            // Calculate lux value
            lux = calculate_lux(raw_data);

            // Adjust brightness based on lux value
            adjust_brightness(lux);
        } else {
            fprintf(log_file, "%s", "Error reading from I2C channel\n");
            fflush(log_file);
        }

        // Wait for 2 seconds
        gpioDelay(2000000); // 2 seconds
    }

    return 0; // This line will never be reached due to the infinite loop, but it's good practice to include it.
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>
#include <errno.h>
#include <string.h>

// BMP280 Registers
#define BMP280_ADDR_76 0x76
#define BMP280_ADDR_77 0x77
#define BMP280_CALIB_START 0x88
#define BMP280_CALIB_END 0xA1
#define BMP280_TEMP_MSB 0xFA
#define BMP280_PRESS_MSB 0xF7
#define BMP280_CTRL_MEAS 0xF4
#define BMP280_CONFIG 0xF5

// BMP280 Oversampling settings
#define BMP280_OSRS_T_1 0x20
#define BMP280_OSRS_P_1 0x04
#define BMP280_MODE_NORMAL 0x03

// Calibration data structure
typedef struct {
    uint16_t dig_T1;
    int16_t dig_T2;
    int16_t dig_T3;
    uint16_t dig_P1;
    int16_t dig_P2;
    int16_t dig_P3;
    int16_t dig_P4;
    int16_t dig_P5;
    int16_t dig_P6;
    int16_t dig_P7;
    int16_t dig_P8;
    int16_t dig_P9;
} bmp280_calib_data;

// Global variables
int bmp280_fd;
bmp280_calib_data calib;
int ledPin = 12; // WiringPi pin 12, corresponds to GPIO 18

// Function prototypes
int bmp280_init(int address);
int bmp280_read_calibration_data(int fd, bmp280_calib_data *calib);
int bmp280_read_raw_data(int fd, int32_t *temperature, int32_t *pressure);
double bmp280_compensate_temperature(int32_t adc_T, bmp280_calib_data calib);
double bmp280_compensate_pressure(int32_t adc_P, bmp280_calib_data calib, double t_fine);
void control_led(int state);
int read_bytes(int fd, uint8_t reg, uint8_t *data, int len);

// Function to read multiple bytes from BMP280 registers
int read_bytes(int fd, uint8_t reg, uint8_t *data, int len) {
    for (int i = 0; i < len; i++) {
        data[i] = wiringPiI2CReadReg8(fd, reg + i);
        if (data[i] < 0) {
            fprintf(stderr, "Error reading register 0x%X: %s\n", reg + i, strerror(errno));
            return -1;
        }
    }
    return 0;
}

// Function to initialize the BMP280 sensor
int bmp280_init(int address) {
    bmp280_fd = wiringPiI2CSetup(address);
    if (bmp280_fd < 0) {
        fprintf(stderr, "Error initializing I2C communication: %s\n", strerror(errno));
        return -1;
    }

    // Set oversampling and mode
    int config = (BMP280_OSRS_T_1 << 5) | (BMP280_OSRS_P_1 << 2) | BMP280_MODE_NORMAL;
    if (wiringPiI2CWriteReg8(bmp280_fd, BMP280_CTRL_MEAS, config) < 0) {
        fprintf(stderr, "Error writing to CTRL_MEAS register: %s\n", strerror(errno));
        return -1;
    }

    return 0;
}

// Function to read calibration data from the sensor
int bmp280_read_calibration_data(int fd, bmp280_calib_data *calib) {
    uint8_t data[BMP280_CALIB_END - BMP280_CALIB_START + 1];

    if (read_bytes(fd, BMP280_CALIB_START, data, sizeof(data)) < 0) {
        return -1;
    }

    calib->dig_T1 = (uint16_t)(data[1] << 8 | data[0]);
    calib->dig_T2 = (int16_t)(data[3] << 8 | data[2]);
    calib->dig_T3 = (int16_t)(data[5] << 8 | data[4]);
    calib->dig_P1 = (uint16_t)(data[7] << 8 | data[6]);
    calib->dig_P2 = (int16_t)(data[9] << 8 | data[8]);
    calib->dig_P3 = (int16_t)(data[11] << 8 | data[10]);
    calib->dig_P4 = (int16_t)(data[13] << 8 | data[12]);
    calib->dig_P5 = (int16_t)(data[15] << 8 | data[14]);
    calib->dig_P6 = (int16_t)(data[17] << 8 | data[16]);
    calib->dig_P7 = (int16_t)(data[19] << 8 | data[18]);
    calib->dig_P8 = (int16_t)(data[21] << 8 | data[20]);
    calib->dig_P9 = (int16_t)(data[23] << 8 | data[22]);

    return 0;
}

// Function to read raw temperature and pressure data
int bmp280_read_raw_data(int fd, int32_t *temperature, int32_t *pressure) {
    uint8_t data[6];

    if (read_bytes(fd, BMP280_PRESS_MSB, data, sizeof(data)) < 0) {
        return -1;
    }

    *pressure = (int32_t)((((uint32_t)data[0]) << 12) | (((uint32_t)data[1]) << 4) | ((uint32_t)data[2] >> 4));
    *temperature = (int32_t)((((uint32_t)data[3]) << 12) | (((uint32_t)data[4]) << 4) | ((uint32_t)data[5] >> 4));

    return 0;
}

// Function to compensate temperature
double bmp280_compensate_temperature(int32_t adc_T, bmp280_calib_data calib) {
    double var1, var2, T;
    double T_fine;

    var1 = (((double)adc_T) / 16384.0 - ((double)calib.dig_T1) / 1024.0) * ((double)calib.dig_T2);
    var2 = ((((double)adc_T) / 131072.0 - ((double)calib.dig_T1) / 8192.0) * (((double)adc_T) / 131072.0 - ((double)calib.dig_T1) / 8192.0)) * ((double)calib.dig_T3);
    T_fine = (double)(var1 + var2);
    T = (T_fine / 5120.0);
    return T;
}

// Function to compensate pressure
double bmp280_compensate_pressure(int32_t adc_P, bmp280_calib_data calib, double t_fine) {
    double var1, var2, p;

    var1 = ((double)t_fine / 2.0) - 64000.0;
    var2 = var1 * var1 * ((double)calib.dig_P6) / 32768.0;
    var2 = var2 + var1 * ((double)calib.dig_P5) * 2.0;
    var2 = (var2 / 4.0) + (((double)calib.dig_P4) * 65536.0);
    var1 = (((double)calib.dig_P3) * var1 * var1 / 524288.0 + ((double)calib.dig_P2) * var1) / 524288.0;
    var1 = (1.0 + var1 / 32768.0) * ((double)calib.dig_P1);

    if (var1 == 0)
    {
        return 0;
    }

    p = 1048576.0 - (double)adc_P;
    p = (p - (var2 / 4096.0)) * 6250.0 / var1;
    var1 = ((double)calib.dig_P9) * p * p / 2147483648.0;
    var2 = p * ((double)calib.dig_P8) / 32768.0;
    p = p + (var1 + var2 + ((double)calib.dig_P7)) / 16.0;

    return p/100.0; // Return in hPa
}

// Function to control the LED
void control_led(int state) {
    digitalWrite(ledPin, state);
}

int main(int argc, char *argv[]) {
    int i2c_address;
    double pressure_threshold;

    if (argc != 3) {
        fprintf(stderr, "Usage: %s <i2c_address> <pressure_threshold_hPa>\n", argv[0]);
        return 1;
    }

    // Parse command-line arguments
    if (strcmp(argv[1], "0x76") == 0) {
        i2c_address = BMP280_ADDR_76;
    } else if (strcmp(argv[1], "0x77") == 0) {
        i2c_address = BMP280_ADDR_77;
    } else {
        fprintf(stderr, "Invalid I2C address. Use 0x76 or 0x77.\n");
        return 1;
    }

    pressure_threshold = atof(argv[2]);

    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error initializing WiringPi: %s\n", strerror(errno));
        return 1;
    }

    pinMode(ledPin, OUTPUT);

    if (bmp280_init(i2c_address) == -1) {
        return 1;
    }

    if (bmp280_read_calibration_data(bmp280_fd, &calib) == -1) {
        return 1;
    }

    int32_t raw_temperature, raw_pressure;
    double temperature, pressure;

    while (1) {
        if (bmp280_read_raw_data(bmp280_fd, &raw_temperature, &raw_pressure) == -1) {
            fprintf(stderr, "Error reading raw data. Retrying in 1 second.\n");
            delay(1000);
            continue;
        }

        temperature = bmp280_compensate_temperature(raw_temperature, calib);
        double t_fine = temperature * 5120.0;
        pressure = bmp280_compensate_pressure(raw_pressure, calib, t_fine);

        printf("Temperature: %.2f °C, Pressure: %.2f hPa\n", temperature, pressure);

        if (pressure < pressure_threshold) {
            printf("Pressure below threshold (%.2f hPa). Triggering LED.\n", pressure_threshold);
            control_led(HIGH);
            delay(500);
            control_led(LOW);
        }

        delay(1000); // Sample every 1 second
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <sys/time.h>
#include <signal.h>
#include <sys/file.h>
#include <string.h>

#define PIR_GPIO 17
#define BUZZER_GPIO 22
#define LOG_FILE "motion_log.txt"

volatile sig_atomic_t terminate = 0;

// Function to format the timestamp
int format_timestamp(char *buffer, size_t buffer_size, struct timeval tv) {
    struct tm tm_info;
    time_t rawtime = tv.tv_sec;

    if (localtime_r(&rawtime, &tm_info) == NULL) {
        fprintf(stderr, "Error: localtime_r failed\n");
        return -1;
    }

    if (strftime(buffer, buffer_size, "%Y-%m-%d %H:%M:%S", &tm_info) == 0) {
        fprintf(stderr, "Error: strftime failed\n");
        return -1;
    }

    snprintf(buffer + strlen(buffer), buffer_size - strlen(buffer), ".%06d", (int)tv.tv_usec);
    return 0;
}

// Function to trigger the buzzer
void trigger_buzzer(int gpio_pin, int duration_ms) {
    if (gpioWrite(gpio_pin, 1) != 0) {
        fprintf(stderr, "Error: Failed to activate buzzer.\n");
        return;
    }
    gpioDelay(duration_ms * 1000); // pigpioDelay takes microseconds
    if (gpioWrite(gpio_pin, 0) != 0) {
        fprintf(stderr, "Error: Failed to deactivate buzzer.\n");
    }
}

// Function to log motion event with timestamp
void log_motion_event() {
    struct timeval tv;
    char timestamp[30];
    FILE *fp;

    if (gettimeofday(&tv, NULL) != 0) {
        fprintf(stderr, "Error: gettimeofday failed\n");
        return;
    }

    if (format_timestamp(timestamp, sizeof(timestamp), tv) != 0) {
        fprintf(stderr, "Error: Failed to format timestamp\n");
        return;
    }

    fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error: Failed to open log file\n");
        return;
    }

    int fd = fileno(fp);
    if (flock(fd, LOCK_EX) != 0) {
        fprintf(stderr, "Error: Failed to acquire lock on log file\n");
        fclose(fp);
        return;
    }

    fprintf(fp, "%s Motion detected!\n", timestamp);

    if (flock(fd, LOCK_UN) != 0) {
        fprintf(stderr, "Error: Failed to release lock on log file\n");
    }

    if (fclose(fp) != 0) {
        fprintf(stderr, "Error: Failed to close log file\n");
    }
}

// Callback function for motion detection
void motion_detected_callback(int gpio, int level, uint32_t tick) {
    (void)level; // unused
    (void)tick;  // unused

    if (gpio == PIR_GPIO) {
        log_motion_event();
        trigger_buzzer(BUZZER_GPIO, 500);
    }
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    (void)signal; // unused
    terminate = 1;
    printf("Received signal, terminating...\n");
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    if (gpioSetMode(PIR_GPIO, PI_INPUT) != 0) {
        fprintf(stderr, "Error: Failed to set GPIO %d to input mode\n", PIR_GPIO);
        gpioTerminate();
        return 1;
    }
    if (gpioSetMode(BUZZER_GPIO, PI_OUTPUT) != 0) {
        fprintf(stderr, "Error: Failed to set GPIO %d to output mode\n", BUZZER_GPIO);
        gpioTerminate();
        return 1;
    }

    // Ensure buzzer is off at startup
    gpioWrite(BUZZER_GPIO, 0);

    // Set up interrupt callback
    if (gpioSetAlertFuncEx(PIR_GPIO, motion_detected_callback, NULL) != 0) {
        fprintf(stderr, "Error: Failed to set alert function for GPIO %d\n", PIR_GPIO);
        gpioTerminate();
        return 1;
    }

    // Set up signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    printf("Motion detection service started. Press Ctrl+C to exit.\n");

    // Main loop
    while (!terminate) {
        gpioDelay(100000); // Check every 0.1 seconds
    }

    // Cleanup
    printf("Terminating pigpio...\n");
    gpioWrite(BUZZER_GPIO, 0); // Ensure buzzer is off
    gpioTerminate();

    printf("Exiting.\n");
    return 0;
}

#include <stdio.h>
#include <wiringPi.h>

#define BUTTON_PIN 18 // GPIO 12 in BCM, pin 18 in WiringPi
#define DATA_PIN 24   // Example: GPIO 18 (WiringPi pin 1)
#define CLOCK_PIN 25  // Example: GPIO 22 (WiringPi pin 3)
#define LATCH_PIN 23  // Example: GPIO 27 (WiringPi pin 2)

void setup_pins() {
    wiringPiSetupGpio(); // Use BCM numbering
    pinMode(BUTTON_PIN, INPUT);
    pullUpDnControl(BUTTON_PIN, PUD_UP);
    pinMode(DATA_PIN, OUTPUT);
    pinMode(CLOCK_PIN, OUTPUT);
    pinMode(LATCH_PIN, OUTPUT);
}

void shiftOut(int dataPin, int clockPin, unsigned char data) {
    for (int i = 0; i < 8; i++) {
        digitalWrite(dataPin, (data >> i) & 1);
        digitalWrite(clockPin, HIGH);
        digitalWrite(clockPin, LOW);
    }
}

void displayRow(int row) {
    unsigned char rowData = 1 << row; // Create a bitmask for the row
    digitalWrite(LATCH_PIN, LOW);
    shiftOut(DATA_PIN, CLOCK_PIN, rowData);
    digitalWrite(LATCH_PIN, HIGH);
}

int main() {
    setup_pins();
    int currentRow = 0;

    while (1) {
        if (digitalRead(BUTTON_PIN) == LOW) {
            delay(100); // Debounce
            if (digitalRead(BUTTON_PIN) == LOW) {
                displayRow(currentRow);
                printf("Row %d displayed\n", currentRow);
                currentRow = (currentRow + 1) % 8;

                while (digitalRead(BUTTON_PIN) == LOW) {
                    delay(10);
                }
            }
        } else {
            displayRow(-1); // Turn off all rows
            delay(10);
        }
    }

    return 0;
}

#include <pigpio.h>
#include <stdio.h>
#define RELAY_PIN 26  // BCM GPIO 26
int main() {
    if (gpioInitialise() < 0) return 1;
    gpioSetMode(RELAY_PIN, PI_OUTPUT);
    while (1) {
        gpioWrite(RELAY_PIN, 1);
        printf("Relay ON for 10 minutes\n");
        gpioSleep(PI_TIME_RELATIVE, 600, 0);
        gpioWrite(RELAY_PIN, 0);
        printf("Relay OFF for 5 minutes\n");
        gpioSleep(PI_TIME_RELATIVE, 300, 0);
    }
    gpioTerminate();
    return 0;
}

#include <pigpio.h>
#include <stdio.h>
#define INA1 17  // BCM GPIO 17
#define INA2 27  // BCM GPIO 27
#define ENA  22  // BCM GPIO 22

void setup() {
    if (gpioInitialise() < 0) return;
    gpioSetMode(INA1, PI_OUTPUT);
    gpioSetMode(INA2, PI_OUTPUT);
    gpioSetMode(ENA, PI_OUTPUT);
}

void runConveyor() {
    gpioWrite(INA1, 1);
    gpioWrite(INA2, 0);
    gpioPWM(ENA, 100);
    gpioDelay(10000000);
    gpioWrite(INA1, 0);
    gpioWrite(INA2, 0);
    gpioPWM(ENA, 0);
    gpioDelay(5000000);
}

int main() {
    setup();
    while (1) {
        runConveyor();
    }
    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <unistd.h>
#include <errno.h>
#include <signal.h>

// Define GPIO pins
#define BUZZER_GPIO 17
#define SWITCH_GPIO 4

// Define sysfs paths
#define GPIO_EXPORT_PATH "/sys/class/gpio/export"
#define GPIO_UNEXPORT_PATH "/sys/class/gpio/unexport"
#define BUZZER_GPIO_PATH "/sys/class/gpio/gpio17"
#define SWITCH_GPIO_PATH "/sys/class/gpio/gpio4"
#define BUZZER_DIRECTION_PATH "/sys/class/gpio/gpio17/direction"
#define SWITCH_DIRECTION_PATH "/sys/class/gpio/gpio4/direction"
#define BUZZER_VALUE_PATH "/sys/class/gpio/gpio17/value"
#define SWITCH_VALUE_PATH "/sys/class/gpio/gpio4/value"

// Define frequencies and durations
#define FREQ_LOW 440
#define FREQ_HIGH 880
#define DURATION_MS 500

// Define debounce delay
#define DEBOUNCE_DELAY_US 50000 // 50ms

// Log file path
#define LOG_FILE "siren_log.txt"

// Global variable to track program state for signal handling
volatile sig_atomic_t program_running = 1;

// Function prototypes
int export_gpio(int gpio);
int unexport_gpio(int gpio);
int set_gpio_direction(int gpio, const char* direction);
int write_gpio_value(int gpio, int value);
int read_gpio_value(int gpio);
void play_frequency(int frequency, int duration_ms);
void stop_sound();
void log_event(const char* event_message);
void signal_handler(int signum);

// Signal handler to gracefully unexport GPIO pins
void signal_handler(int signum) {
    if (signum == SIGINT) {
        printf("Caught signal SIGINT, exiting gracefully.\n");
        log_event("Program interrupted by user (Ctrl+C).");
        stop_sound(); // Ensure the buzzer is off
        unexport_gpio(BUZZER_GPIO);
        unexport_gpio(SWITCH_GPIO);
        program_running = 0;
        exit(EXIT_SUCCESS);
    }
}

// Exports a GPIO pin using sysfs
int export_gpio(int gpio) {
    FILE* export_file = fopen(GPIO_EXPORT_PATH, "w");
    if (export_file == NULL) {
        fprintf(stderr, "Error opening %s: %s\n", GPIO_EXPORT_PATH, strerror(errno));
        return -1;
    }

    fprintf(export_file, "%d", gpio);
    fclose(export_file);
    return 0;
}

// Unexports a GPIO pin using sysfs
int unexport_gpio(int gpio) {
    FILE* unexport_file = fopen(GPIO_UNEXPORT_PATH, "w");
    if (unexport_file == NULL) {
        fprintf(stderr, "Error opening %s: %s\n", GPIO_UNEXPORT_PATH, strerror(errno));
        return -1;
    }

    fprintf(unexport_file, "%d", gpio);
    fclose(unexport_file);
    return 0;
}

// Sets the direction of a GPIO pin (input or output)
int set_gpio_direction(int gpio, const char* direction) {
    char direction_path[100];
    sprintf(direction_path, (gpio == BUZZER_GPIO) ? BUZZER_DIRECTION_PATH : SWITCH_DIRECTION_PATH);

    FILE* direction_file = fopen(direction_path, "w");
    if (direction_file == NULL) {
        fprintf(stderr, "Error opening %s: %s\n", direction_path, strerror(errno));
        return -1;
    }

    fprintf(direction_file, "%s", direction);
    fclose(direction_file);
    return 0;
}

// Writes a value to a GPIO pin (0 or 1)
int write_gpio_value(int gpio, int value) {
    char value_path[100];
    sprintf(value_path, BUZZER_VALUE_PATH);

    FILE* value_file = fopen(value_path, "w");
    if (value_file == NULL) {
        fprintf(stderr, "Error opening %s: %s\n", value_path, strerror(errno));
        return -1;
    }

    fprintf(value_file, "%d", value);
    fclose(value_file);
    return 0;
}

// Reads a value from a GPIO pin
int read_gpio_value(int gpio) {
    char value_path[100];
    sprintf(value_path, SWITCH_VALUE_PATH);

    FILE* value_file = fopen(value_path, "r");
    if (value_file == NULL) {
        fprintf(stderr, "Error opening %s: %s\n", value_path, strerror(errno));
        return -1;
    }

    int value;
    if (fscanf(value_file, "%d", &value) != 1) {
        fprintf(stderr, "Error reading value from %s\n", value_path);
        fclose(value_file);
        return -1;
    }

    fclose(value_file);
    return value;
}

// Plays a frequency on the buzzer for a given duration
void play_frequency(int frequency, int duration_ms) {
    if (frequency <= 0 || duration_ms <= 0) {
        fprintf(stderr, "Invalid frequency or duration.\n");
        return;
    }

    // Calculate the period of the frequency in microseconds
    long period_us = 1000000 / frequency;

    // Calculate the half-period in microseconds
    long half_period_us = period_us / 2;

    // Calculate the number of cycles to play for the given duration
    int num_cycles = (duration_ms * 1000) / period_us;

    for (int i = 0; i < num_cycles; ++i) {
        if (write_gpio_value(BUZZER_GPIO, 1) != 0) return; // Error writing to GPIO
        usleep(half_period_us);
        if (write_gpio_value(BUZZER_GPIO, 0) != 0) return; // Error writing to GPIO
        usleep(half_period_us);
    }
}

// Stops the sound on the buzzer
void stop_sound() {
    write_gpio_value(BUZZER_GPIO, 0);
}

// Logs an event to the log file
void log_event(const char* event_message) {
    FILE* log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening %s: %s\n", LOG_FILE, strerror(errno));
        return;
    }

    time_t t = time(NULL);
    struct tm* tm = localtime(&t);
    char timestamp[100];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(log_file, "[%s] %s\n", timestamp, event_message);
    fclose(log_file);
}

int main() {
    // Install signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Export GPIO pins
    if (export_gpio(BUZZER_GPIO) != 0) {
        fprintf(stderr, "Error exporting GPIO %d\n", BUZZER_GPIO);
        exit(EXIT_FAILURE);
    }
    if (export_gpio(SWITCH_GPIO) != 0) {
        fprintf(stderr, "Error exporting GPIO %d\n", SWITCH_GPIO);
        unexport_gpio(BUZZER_GPIO);
        exit(EXIT_FAILURE);
    }

    // Set GPIO directions
    if (set_gpio_direction(BUZZER_GPIO, "out") != 0) {
        fprintf(stderr, "Error setting direction for GPIO %d\n", BUZZER_GPIO);
        unexport_gpio(BUZZER_GPIO);
        unexport_gpio(SWITCH_GPIO);
        exit(EXIT_FAILURE);
    }
    if (set_gpio_direction(SWITCH_GPIO, "in") != 0) {
        fprintf(stderr, "Error setting direction for GPIO %d\n", SWITCH_GPIO);
        unexport_gpio(BUZZER_GPIO);
        unexport_gpio(SWITCH_GPIO);
        exit(EXIT_FAILURE);
    }

    log_event("Siren program started.");

    int switch_state = 0;
    int last_switch_state = 0;

    while (program_running) {
        int current_switch_state = read_gpio_value(SWITCH_GPIO);
        if (current_switch_state < 0) {
            fprintf(stderr, "Error reading switch state, exiting.\n");
            break;
        }

        if (current_switch_state != last_switch_state) {
            usleep(DEBOUNCE_DELAY_US); // Debounce
            current_switch_state = read_gpio_value(SWITCH_GPIO);
            if (current_switch_state < 0) {
                fprintf(stderr, "Error reading switch state after debounce, exiting.\n");
                break;
            }

            if (current_switch_state != last_switch_state) {
                switch_state = current_switch_state;
                last_switch_state = current_switch_state;

                if (switch_state == 1) {
                    log_event("Switch pressed, activating siren.");
                    while (switch_state == 1 && program_running) {
                        play_frequency(FREQ_LOW, DURATION_MS);
                        play_frequency(FREQ_HIGH, DURATION_MS);
                        switch_state = read_gpio_value(SWITCH_GPIO);
                        if (switch_state < 0) {
                            fprintf(stderr, "Error reading switch state during siren, exiting.\n");
                            break;
                        }
                    }
                    stop_sound();
                    log_event("Switch released, deactivating siren.");
                }
            }
        }

        usleep(50000); // Check every 50ms
    }

    stop_sound();
    unexport_gpio(BUZZER_GPIO);
    unexport_gpio(SWITCH_GPIO);
    log_event("Siren program stopped.");

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <pigpio.h>

// Constants
#define TTP229_I2C_ADDR 0x5A // Example I2C address for TTP229
#define LED_GPIO 17
#define POLLING_INTERVAL_MS 50
#define ALERT_DURATION_MS 500

// Global Variables
int i2c_handle;
FILE *log_file;
volatile sig_atomic_t program_running = 1; // Flag to control the main loop

// Function Prototypes
void signal_handler(int signal);
int init_gpio(void);
int init_i2c(void);
int init_logging(void);
void cleanup(void);
void log_touch_event(int touch_status);

// Signal Handler for Ctrl+C
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("Ctrl+C detected. Exiting gracefully...\n");
        program_running = 0; // Set the flag to exit the main loop
    }
}

// Initialize GPIO
int init_gpio(void) {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }

    gpioSetMode(LED_GPIO, PI_OUTPUT);
    gpioWrite(LED_GPIO, 0); // Initially turn the LED off
    return 0;
}

// Initialize I2C
int init_i2c(void) {
    i2c_handle = i2cOpen(1, TTP229_I2C_ADDR, 0); // I2C bus 1
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %d\n", i2c_handle);
        return -1;
    }
    return 0;
}

// Initialize Logging
int init_logging(void) {
    log_file = fopen("touch_events.log", "a");
    if (log_file == NULL) {
        perror("Failed to open log file");
        return -1;
    }
    return 0;
}

// Cleanup Resources
void cleanup(void) {
    printf("Cleaning up resources...\n");

    // Close I2C connection
    if (i2c_handle >= 0) {
        i2cClose(i2c_handle);
    }

    // Close log file
    if (log_file != NULL) {
        fclose(log_file);
    }

    // Turn off LED
    gpioWrite(LED_GPIO, 0);

    // Terminate pigpio
    gpioTerminate();
}

// Log Touch Event
void log_touch_event(int touch_status) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(log_file, "%s, %d\n", timestamp, touch_status);
    fflush(log_file); // Ensure data is written to the file immediately
}

int main(void) {
    // Install signal handler
    signal(SIGINT, signal_handler);

    // Initialize
    if (init_gpio() != 0) {
        return 1;
    }
    if (init_i2c() != 0) {
        cleanup();
        return 1;
    }
    if (init_logging() != 0) {
        cleanup();
        return 1;
    }

    printf("Touch sensor monitoring started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        int data;

        // Read data from the sensor
        data = i2cReadByteData(i2c_handle, 0x00); // Assuming register 0x00 holds touch data
        if (data < 0) {
            fprintf(stderr, "I2C read failed: %d\n", data);
            log_touch_event( -1); //Log I2C failure
        } else {
            // Process touch data (example: check if any bit is set)
            int touch_detected = (data > 0) ? 1 : 0; // Simplistic touch detection

            if (touch_detected) {
                printf("Touch detected!\n");
                gpioWrite(LED_GPIO, 1); // Turn on LED
                gpioDelay(ALERT_DURATION_MS); // Keep LED on for 500ms
                gpioWrite(LED_GPIO, 0); // Turn off LED
            }

            log_touch_event(touch_detected);
        }

        gpioDelay(POLLING_INTERVAL_MS); // Wait before next poll
    }

    // Cleanup and exit
    cleanup();
    printf("Exiting.\n");
    return 0;
}

#include <stdio.h>
