#define SAMPLE_DELAY 200  // ms
#define WINDOW_DURATION 10000  // ms
int read_adc(int ch) {
    unsigned char buf[3] = {1, (0x80 | (ch << 4)), 0};
    wiringPiSPIDataRW(0, buf, 3);
    return ((buf[1] & 3) << 8) | buf[2];
}
int main() {
    wiringPiSetup();
    wiringPiSPISetup(0, 1000000);
    FILE* f = fopen("minmax_log.csv", "w");
    fprintf(f, "Time,Min,Max\n");
    while (1) {
        int min = 1023, max = 0;
        int elapsed = 0;
        while (elapsed < WINDOW_DURATION) {
            int val = read_adc(0);
            if (val < min) min = val;
            if (val > max) max = val;
            delay(SAMPLE_DELAY);
            elapsed += SAMPLE_DELAY;
        }
        time_t t = time(NULL);
        fprintf(f, "%ld,%d,%d\n", t, min, max);
        fflush(f);
    }
    fclose(f);
    return 0;
}

