// Define the GPIO pins for the relays
#define IRRIGATION_PIN 4
#define VENTILATION_PIN 17
#define HEATING_PIN 27
#define LIGHTING_PIN 22

// Structure to represent the Relay Controller
typedef struct {
    int irrigation_pin;
    int ventilation_pin;
    int heating_pin;
    int lighting_pin;
} RelayController;

// Function to initialize the Relay Controller
int relay_controller_init(RelayController *controller) {
    controller->irrigation_pin = IRRIGATION_PIN;
    controller->ventilation_pin = VENTILATION_PIN;
    controller->heating_pin = HEATING_PIN;
    controller->lighting_pin = LIGHTING_PIN;

    // Set the GPIO pins as outputs
    gpioSetMode(controller->irrigation_pin, PI_OUTPUT);
    gpioSetMode(controller->ventilation_pin, PI_OUTPUT);
    gpioSetMode(controller->heating_pin, PI_OUTPUT);
    gpioSetMode(controller->lighting_pin, PI_OUTPUT);

    return 0; // Indicate success
}

// Function to set the state of a relay (ON or OFF)
void set_relay_state(int pin, int state) {
    gpioWrite(pin, state); // 1 for ON, 0 for OFF
}

// Function to cleanup the Relay Controller (reset pins to input)
void relay_controller_cleanup(RelayController *controller) {
    gpioSetMode(controller->irrigation_pin, PI_INPUT); // Reset to input
    gpioSetMode(controller->ventilation_pin, PI_INPUT);
    gpioSetMode(controller->heating_pin, PI_INPUT);
    gpioSetMode(controller->lighting_pin, PI_INPUT);
}

int main() {
    // Initialize the pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Indicate failure
    }

    // Create a RelayController instance
    RelayController greenhouse_controller;

    // Initialize the Relay Controller
    if (relay_controller_init(&greenhouse_controller) != 0) {
        fprintf(stderr, "Relay controller initialisation failed\n");
        gpioTerminate();
        return 1; // Indicate failure
    }

    // Main loop to simulate the smart greenhouse system
    while (1) {
        // Simulate irrigation
        printf("Activating Irrigation...\n");
        set_relay_state(greenhouse_controller.irrigation_pin, 1); // Turn ON irrigation
        time_sleep(5);
        set_relay_state(greenhouse_controller.irrigation_pin, 0); // Turn OFF irrigation
        printf("Irrigation Deactivated.\n");

        // Simulate ventilation
        printf("Activating Ventilation...\n");
        set_relay_state(greenhouse_controller.ventilation_pin, 1); // Turn ON ventilation
        time_sleep(5);
        set_relay_state(greenhouse_controller.ventilation_pin, 0); // Turn OFF ventilation
        printf("Ventilation Deactivated.\n");

        // Simulate heating
        printf("Activating Heating...\n");
        set_relay_state(greenhouse_controller.heating_pin, 1); // Turn ON heating
        time_sleep(5);
        set_relay_state(greenhouse_controller.heating_pin, 0); // Turn OFF heating
        printf("Heating Deactivated.\n");

        // Simulate lighting
        printf("Activating Lighting...\n");
        set_relay_state(greenhouse_controller.lighting_pin, 1); // Turn ON lighting
        time_sleep(5);
        set_relay_state(greenhouse_controller.lighting_pin, 0); // Turn OFF lighting
        printf("Lighting Deactivated.\n");
    }

    // Cleanup and exit (this part will likely never be reached in this infinite loop)
    relay_controller_cleanup(&greenhouse_controller);
    gpioTerminate();

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <wiringPiI2C.h>
#include <wiringPi.h>

// SSD1306 OLED Display I2C Address
#define SSD1306_I2C_ADDR 0x3C

// SSD1306 OLED Display Dimensions
#define SSD1306_WIDTH 128
#define SSD1306_HEIGHT 64

// I2C File Descriptor
int fd;

// Function to write a command to the SSD1306
void ssd1306_command(uint8_t command) {
  uint8_t control_byte = 0x00; // Command control byte
  wiringPiI2CWriteReg8(fd, control_byte, command);
}

// Function to initialize the SSD1306 OLED display
void ssd1306_init() {
  // Initialization sequence (typical for 128x64)
  ssd1306_command(0xAE);  // Display off
  ssd1306_command(0xD5);  // Set display clock divide ratio/oscillator frequency
  ssd1306_command(0x80);  // --ratio
  ssd1306_command(0xA8);  // Set multiplex ratio
  ssd1306_command(0x3F);  // --ratio
  ssd1306_command(0xD3);  // Set display offset
  ssd1306_command(0x00);  // --offset
  ssd1306_command(0x40);  // Set start line address
  ssd1306_command(0x8D);  // Charge pump setting
  ssd1306_command(0x14);  // --enable
  ssd1306_command(0x20);  // Set memory addressing mode
  ssd1306_command(0x00);  // --horizontal
  ssd1306_command(0xA1);  // Set segment re-map   (A0 or A1)
  ssd1306_command(0xC8);  // Set COM output scan direction   (C0 or C8)
  ssd1306_command(0xDA);  // Set COM pins hardware configuration
  ssd1306_command(0x12);  // --pins
  ssd1306_command(0x81);  // Set contrast control register
  ssd1306_command(0xCF);  // --contrast
  ssd1306_command(0xD9);  // Set pre-charge period
  ssd1306_command(0xF1);  // --period
  ssd1306_command(0xDB);  // Set VCOM deselect level
  ssd1306_command(0x40);  // --level
  ssd1306_command(0xA4);  // Set entire display on/off
  ssd1306_command(0xA6);  // Set normal display
  ssd1306_command(0xAF);  // Display on
}

// Function to clear the SSD1306 OLED display
void ssd1306_clear() {
  int i, j;
  for (i = 0; i < SSD1306_HEIGHT / 8; i++) {
    ssd1306_command(0xB0 + i);  // Set page start address for page 0 to 7
    ssd1306_command(0x00);      // Set lower column address
    ssd1306_command(0x10);      // Set higher column address
    for (j = 0; j < SSD1306_WIDTH; j++) {
      wiringPiI2CWriteReg8(fd, 0x40, 0x00); // Write 0 to each pixel on the page
    }
  }
}

int main() {
  // Initialize WiringPi
  if (wiringPiSetup() == -1) {
    fprintf(stderr, "WiringPi initialization failed!\n");
    return 1;
  }

  // Open I2C device
  fd = wiringPiI2CSetup(SSD1306_I2C_ADDR);
  if (fd == -1) {
    fprintf(stderr, "Failed to init I2C communication.\n");
    return 1;
  }

  // Initialize the SSD1306 OLED display
  ssd1306_init();

  // Clear the display
  ssd1306_clear();

  printf("SSD1306 OLED display initialized and cleared!\n");

  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <unistd.h>

// Define the pins connected to the LED matrix (adjust as needed)
#define ROW_COUNT 8
#define COL_COUNT 8

const int rowPins[ROW_COUNT] = {0, 1, 2, 3, 4, 5, 6, 7};  // Example: WiringPi pins 0-7
const int colPins[COL_COUNT] = {8, 9, 10, 11, 12, 13, 14, 15}; // Example: WiringPi pins 8-15

void setupPins() {
  wiringPiSetup();
  for (int i = 0; i < ROW_COUNT; i++) {
    pinMode(rowPins[i], OUTPUT);
    digitalWrite(rowPins[i], LOW); // Initially turn off rows
  }
  for (int i = 0; i < COL_COUNT; i++) {
    pinMode(colPins[i], OUTPUT);
    digitalWrite(colPins[i], LOW); // Initially turn off columns
  }
}

void display(unsigned char matrix[ROW_COUNT]) {
  for (int row = 0; row < ROW_COUNT; row++) {
    digitalWrite(rowPins[row], HIGH);
    for (int col = 0; col < COL_COUNT; col++) {
      digitalWrite(colPins[col], (matrix[row] >> col) & 1);
    }
    delayMicroseconds(800); //Adjust scan rate
    digitalWrite(rowPins[row], LOW);
    for (int col = 0; col < COL_COUNT; col++) {
         digitalWrite(colPins[col], LOW); //Turn off the column pins quickly.
    }

  }
}

int main() {
  setupPins();

  unsigned char wave1[ROW_COUNT] = {0x01, 0x02, 0x04, 0x08, 0x10, 0x20, 0x40, 0x80};
  unsigned char wave2[ROW_COUNT] = {0x80, 0x40, 0x20, 0x10, 0x08, 0x04, 0x02, 0x01};

  while (1) {
    display(wave1);
    delay(5); // Wave speed
    unsigned char temp = wave1[0];
      for (int i = 0; i < ROW_COUNT - 1; i++) {
           wave1[i] = wave1[i+1];
      }
      wave1[ROW_COUNT - 1] = temp;

    display(wave2);
    delay(5); // Wave speed
       temp = wave2[0];
      for (int i = 0; i < ROW_COUNT - 1; i++) {
           wave2[i] = wave2[i+1];
      }
      wave2[ROW_COUNT - 1] = temp;

  }

  return 0;
}

#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
#include <errno.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <stdbool.h>
#include <time.h>
#include <math.h>

// Constants
#define D6F_I2C_ADDR 0x6C  // D6F-PH I2C address (7-bit)
#define I2C_DEVICE "/dev/i2c-1" // I2C device file

// Function Prototypes
int i2c_write_bytes(int file_descriptor, uint8_t device_address, uint16_t register_address, const uint8_t *data, uint8_t length);
int i2c_read_bytes(int file_descriptor, uint8_t device_address, uint8_t register_address, uint8_t *data, uint8_t length);
float convert_raw_to_flow(uint16_t raw_flow);
int open_i2c_device(const char *device);
void close_i2c_device(int file_descriptor);

// Helper Functions
void delay_ms(int milliseconds) {
    struct timespec ts;
    ts.tv_sec = milliseconds / 1000;
    ts.tv_nsec = (milliseconds % 1000) * 1000000;
    nanosleep(&ts, NULL);
}

/**
 * Opens the I2C device.
 * @param device The path to the I2C device (e.g., "/dev/i2c-1").
 * @return The file descriptor of the opened device, or -1 on error.
 */
int open_i2c_device(const char *device) {
    int file_descriptor = open(device, O_RDWR);
    if (file_descriptor < 0) {
        fprintf(stderr, "Error opening I2C device %s: %s\n", device, strerror(errno));
    }
    return file_descriptor;
}

/**
 * Closes the I2C device.
 * @param file_descriptor The file descriptor of the I2C device.
 */
void close_i2c_device(int file_descriptor) {
    if (file_descriptor >= 0) {
        close(file_descriptor);
    }
}

/**
 * Writes bytes to an I2C device register.
 * @param file_descriptor The file descriptor of the I2C device.
 * @param device_address The I2C address of the device.
 * @param register_address The 16-bit register address to write to.
 * @param data The data to write.
 * @param length The number of bytes to write.
 * @return 0 on success, -1 on error.
 */
int i2c_write_bytes(int file_descriptor, uint8_t device_address, uint16_t register_address, const uint8_t *data, uint8_t length) {
    if (length > 125) { // Limiting the maximum data length
        fprintf(stderr, "Error: Write length exceeds maximum allowed (125 bytes).\n");
        return -1;
    }

    uint8_t buffer[128]; // Buffer to hold register address and data
    buffer[0] = (register_address >> 8) & 0xFF; // MSB of register address
    buffer[1] = register_address & 0xFF;        // LSB of register address

    if (data != NULL && length > 0) {
        memcpy(buffer + 2, data, length);
    }

    int total_length = length + 2;

    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Error: Could not set I2C_SLAVE address: %s\n", strerror(errno));
        return -1;
    }

    ssize_t bytes_written = write(file_descriptor, buffer, total_length);
    if (bytes_written != total_length) {
        fprintf(stderr, "Error: I2C write failed: %s (Wrote %zd bytes, expected %d)\n", strerror(errno), bytes_written, total_length);
        return -1;
    }

    return 0;
}

/**
 * Reads bytes from an I2C device register.
 * @param file_descriptor The file descriptor of the I2C device.
 * @param device_address The I2C address of the device.
 * @param register_address The 8-bit register address to read from.
 * @param data The buffer to store the read data.
 * @param length The number of bytes to read.
 * @return 0 on success, -1 on error.
 */
int i2c_read_bytes(int file_descriptor, uint8_t device_address, uint8_t register_address, uint8_t *data, uint8_t length) {
    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Error: Could not set I2C_SLAVE address: %s\n", strerror(errno));
        return -1;
    }

    // Write the register address to read from
    ssize_t bytes_written = write(file_descriptor, &register_address, 1);
    if (bytes_written != 1) {
        fprintf(stderr, "Error: Failed to write register address: %s\n", strerror(errno));
        return -1;
    }

    // Read the data
    ssize_t bytes_read = read(file_descriptor, data, length);
    if (bytes_read != length) {
        fprintf(stderr, "Error: I2C read failed: %s (Read %zd bytes, expected %d)\n", strerror(errno), bytes_read, length);
        return -1;
    }

    return 0;
}

/**
 * Converts the raw flow sensor reading to a flow rate in L/min.
 * @param raw_flow The raw flow sensor reading (16-bit unsigned integer).
 * @return The flow rate in L/min.
 */
float convert_raw_to_flow(uint16_t raw_flow) {
    return ((float)raw_flow - 1024.0) * 10.0 / 60000.0;
}

int main() {
    int i2c_file_descriptor = open_i2c_device(I2C_DEVICE);
    if (i2c_file_descriptor < 0) {
        return EXIT_FAILURE;
    }

    // 1. Initialize sensor (0Bh, 00h)
    if (i2c_write_bytes(i2c_file_descriptor, D6F_I2C_ADDR, 0x0B00, NULL, 0) != 0) {
        fprintf(stderr, "Error: Failed to initialize sensor.\n");
        close_i2c_device(i2c_file_descriptor);
        return EXIT_FAILURE;
    }
    delay_ms(900);

    while (1) {
        // 2. Trigger getting data (00h, D0h, 40h, 18h, 06h)
        uint8_t trigger_data[] = {0x40, 0x18, 0x06};
        if (i2c_write_bytes(i2c_file_descriptor, D6F_I2C_ADDR, 0x00D0, trigger_data, sizeof(trigger_data)) != 0) {
            fprintf(stderr, "Error: Failed to trigger data acquisition.\n");
            close_i2c_device(i2c_file_descriptor);
            return EXIT_FAILURE;
        }

        delay_ms(50);

        // 3. Read data (00h, D0h, 51h, 2Ch) (07h)
        uint8_t read_command[] = {0x51, 0x2C};
        if (i2c_write_bytes(i2c_file_descriptor, D6F_I2C_ADDR, 0x00D0, read_command, sizeof(read_command)) != 0) {
            fprintf(stderr, "Error: Failed to send read command.\n");
            close_i2c_device(i2c_file_descriptor);
            return EXIT_FAILURE;
        }

        uint8_t flow_data[2];
        if (i2c_read_bytes(i2c_file_descriptor, D6F_I2C_ADDR, 0x07, flow_data, sizeof(flow_data)) != 0) {
            fprintf(stderr, "Error: Failed to read flow data.\n");
            close_i2c_device(i2c_file_descriptor);
            return EXIT_FAILURE;
        }

        uint16_t raw_flow = (flow_data[0] << 8) | flow_data[1]; // Combine bytes to form 16-bit value
        float flow_rate = convert_raw_to_flow(raw_flow);

        printf("Flow Rate: %6.2f [L/min]\n", flow_rate);

        delay_ms(1000); // Read every 1 second
    }

    close_i2c_device(i2c_file_descriptor);
    return EXIT_SUCCESS;
}

