int main() {
    int pi;
    FILE *log_file;
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];
    int pir_value;

    // Initialize pigpio
    pi = gpioInitialise();
    if (pi < 0) {
        fprintf(stderr, "pigpio initialisation failed: %d\n", pi);
        return 1; // Exit with an error code
    }

    // Open the log file
    log_file = fopen("motion_log.txt", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening motion_log.txt\n");
        gpioTerminate();
        return 1; // Exit with an error code
    }

    // Set GPIO modes
    gpioSetMode(PIR_GPIO, PI_INPUT);
    gpioSetMode(BUZZER_GPIO, PI_OUTPUT);

    printf("Motion detection system started. Press Ctrl+C to exit.\n");

    while (1) {
        // Read PIR sensor value
        pir_value = gpioRead(PIR_GPIO);

        // Validate the PIR sensor reading
        if (pir_value == 0 || pir_value == 1) {
            if (pir_value == 1) {
                // Motion detected
                time(&rawtime);
                timeinfo = localtime(&rawtime);
                strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

                // Log the event
                fprintf(log_file, "%s: Motion detected\n", timestamp);
                fflush(log_file); // Ensure the log is written immediately

                printf("%s: Motion detected\n", timestamp);

                // Activate the buzzer
                gpioWrite(BUZZER_GPIO, 1); // Turn on the buzzer
                gpioDelay(2000);           // Keep it on for 2 seconds
                gpioWrite(BUZZER_GPIO, 0); // Turn off the buzzer
            }
        } else {
          fprintf(stderr, "Invalid PIR sensor reading: %d\n", pir_value);
        }

        gpioDelay(50); // Delay to prevent excessive CPU usage
    }

    // Cleanup
    fclose(log_file);
    gpioTerminate();

    return 0;
}

#include <stdio.h>
