// Define the GPIO pins connected to the LEDs
#define LED_COUNT 8
const int ledPins[LED_COUNT] = {1, 4, 5, 6, 26, 27, 28, 29}; // WiringPi pin numbers

// Function to initialize the GPIO pins
int initializeGPIO() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return 1; // Indicate failure
    }

    // Set all LED pins to output mode
    for (int i = 0; i < LED_COUNT; i++) {
        pinMode(ledPins[i], OUTPUT);
        digitalWrite(ledPins[i], LOW); // Initialize all LEDs to OFF
    }
    return 0; // Indicate success
}

// Function to perform the chasing effect
void runChasingEffect(int delay_ms) {
    // Light up LEDs one by one
    for (int i = 0; i < LED_COUNT; i++) {
        digitalWrite(ledPins[i], HIGH);
        delay(delay_ms);
    }

    // Turn off LEDs one by one
    for (int i = 0; i < LED_COUNT; i++) {
        digitalWrite(ledPins[i], LOW);
        delay(delay_ms);
    }
}

int main() {
    // Initialize the wiringPi library and configure the GPIO pins
    if (initializeGPIO() != 0) {
        return 1; // Exit if initialization fails
    }

    // Main loop to run the chasing effect continuously
    while (1) {
        runChasingEffect(100); // Adjust the delay for speed
    }

    return 0;
}

