#define SSD1306_I2C_ADDR  0x3C
#define SSD1306_WIDTH     128
#define SSD1306_HEIGHT    64

int i2c_fd;
void ssd1306_sendCommand(unsigned char command) {
    unsigned char buffer[2] = {0x00, command};
    if (write(i2c_fd, buffer, 2) < 0) {
        perror("I2C Command Write Failed");
    }
}
void ssd1306_init() {
    ssd1306_sendCommand(0xAE);
    ssd1306_sendCommand(0xD5);
    ssd1306_sendCommand(0x80);
    ssd1306_sendCommand(0xA8);
    ssd1306_sendCommand(SSD1306_HEIGHT - 1);
    ssd1306_sendCommand(0xD3);
    ssd1306_sendCommand(0x00);
    ssd1306_sendCommand(0x40);
    ssd1306_sendCommand(0x8D);
    ssd1306_sendCommand(0x14);
    ssd1306_sendCommand(0xA1);
    ssd1306_sendCommand(0xC8);
    ssd1306_sendCommand(0xDA);
    ssd1306_sendCommand(0x12);
    ssd1306_sendCommand(0x81);
    ssd1306_sendCommand(0x7F);
    ssd1306_sendCommand(0xD9);
    ssd1306_sendCommand(0xF1);
    ssd1306_sendCommand(0xDB);
    ssd1306_sendCommand(0x40);
    ssd1306_sendCommand(0xA4);
    ssd1306_sendCommand(0xA6);
    ssd1306_sendCommand(0xAF);
}
void ssd1306_clearDisplay() {
    unsigned char buffer[1025] = {0x40};
    memset(buffer + 1, 0x00, 1024);
    write(i2c_fd, buffer, 1025);
}
void ssd1306_displayPixels() {
    unsigned char buffer[130] = {0x40};
    for (int i = 1; i < 129; i++) {
        buffer[i] = 0xFF;
    }
    write(i2c_fd, buffer, 130);
}
int main() {
    const char *i2c_device = "/dev/i2c-1";
    if ((i2c_fd = open(i2c_device, O_RDWR)) < 0) {
        perror("Failed to open I2C bus");
        return EXIT_FAILURE;
    }
    if (ioctl(i2c_fd, I2C_SLAVE, SSD1306_I2C_ADDR) < 0) {
        perror("Failed to communicate with SSD1306");
        return EXIT_FAILURE;
    }
    ssd1306_init();
    ssd1306_clearDisplay();
    ssd1306_displayPixels();
    sleep(5);
    close(i2c_fd);
    return EXIT_SUCCESS;
}

