    uint8_t buf[2];

    while (1) {
        buf[0] = PCF8591_CTRL_AIN1;
        if (bcm2835_i2c_write((char *)buf, 1) != BCM2835_I2C_OK) {
            fprintf(stderr, "I2C write error\n");
            bcm2835_i2c_end();
            bcm2835_close();
            return 1;
        }

