#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <wiringPi.h>
#include <time.h>

// Define GPIO pins using wiringPi numbering
#define PIR_PIN 17
#define LED_PIN 18

// Debounce time in milliseconds
#define DEBOUNCE_TIME 500

// Global variable to store the last interrupt time
static volatile unsigned long lastInterruptTime = 0;

// Function prototypes
int setupGPIO(void);
void motionDetectedISR(void);
void controlLED(int state);
void cleanupGPIO(int signal);

int main(void) {
    // Install signal handler for graceful exit
    signal(SIGINT, cleanupGPIO);

    // Initialize wiringPi and GPIO pins
    if (setupGPIO() != 0) {
        fprintf(stderr, "GPIO setup failed. Exiting.\n");
        return 1;
    }

    printf("Motion detection program started. Press Ctrl+C to exit.\n");

    // Main loop (program runs indefinitely until interrupted)
    while (1) {
        delay(100); // Small delay to prevent busy-waiting
    }

    return 0;
}

// Function to set up GPIO pins
int setupGPIO(void) {
    // Initialize wiringPi using GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "wiringPiSetupGpio failed. Check permissions and wiring.\n");
        return -1;
    }

    // Set PIR pin as input
    pinMode(PIR_PIN, INPUT);
    pullUpDnControl(PIR_PIN, PUD_DOWN); // Use a pull-down resistor

    // Set LED pin as output
    pinMode(LED_PIN, OUTPUT);
    digitalWrite(LED_PIN, LOW); // Initially turn the LED off

    // Register interrupt handler for motion detection
    if (wiringPiISR(PIR_PIN, INT_EDGE_RISING, motionDetectedISR) < 0) {
        fprintf(stderr, "Unable to register ISR. Exiting.\n");
        return -1;
    }

    return 0;
}

// Interrupt Service Routine (ISR) for motion detection
void motionDetectedISR(void) {
    unsigned long currentTime = millis();

    // Debounce the interrupt
    if (currentTime - lastInterruptTime > DEBOUNCE_TIME) {
        printf("Motion detected!\n");
        controlLED(HIGH); // Turn on the LED
        delay(5000);       // Keep the LED on for 5 seconds
        controlLED(LOW);  // Turn off the LED
        lastInterruptTime = currentTime;
    } else {
        printf("Debounced motion detection.\n");
    }
}

// Function to control the LED
void controlLED(int state) {
    digitalWrite(LED_PIN, state); // Set the LED pin to the specified state (HIGH or LOW)
}

// Function to clean up GPIO pins before exiting
void cleanupGPIO(int signal) {
    printf("Cleaning up GPIO and exiting.\n");
    digitalWrite(LED_PIN, LOW); // Ensure LED is off
    wiringPiSetupGpio(); // Reinitialize wiringPi to reset GPIO pins
    exit(0);
}

#include <stdio.h>
