#include <string.h>

// Configuration
#define I2C_BUS 1
#define VL53L1X_ADDR 0x29
#define GATE_PIN 18      // GPIO pin for gate actuator (relay)
#define GATE_SENSOR_PIN 23 // GPIO pin for gate sensor (limit switch)
#define DISTANCE_THRESHOLD 500 // Distance threshold in mm
#define LOG_FILE "parking_log.txt"

// Global variables
int i2c_handle;
volatile sig_atomic_t program_running = 1;

// Function prototypes
int initialize_sensor(int i2c_handle);
int read_distance(int i2c_handle);
int control_gate(int gate_pin, int state);
int check_gate_state(int gate_sensor_pin);
void log_event(const char* event_description);
void signal_handler(int signal);

// VL53L1X register addresses (example, adjust as needed for your sensor)
#define VL53L1X_REG_IDENTIFICATION_MODEL_ID 0x010F
#define VL53L1X_REG_SYSRANGE_START 0x00
#define VL53L1X_REG_RESULT_RANGE_STATUS 0x0014
#define VL53L1X_REG_RESULT_FINAL_CROSSTALK_CORRECTED_RANGE_MM_SD0 0x0050


int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        perror("pigpio initialisation failed");
        return 1;
    }

    // Register signal handlers for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Open I2C communication
    i2c_handle = i2cOpen(I2C_BUS, VL53L1X_ADDR, 0);
    if (i2c_handle < 0) {
        perror("Failed to open I2C bus");
        gpioTerminate();
        return 1;
    }

    // Initialize the VL53L1X sensor
    if (initialize_sensor(i2c_handle) != 0) {
        fprintf(stderr, "Sensor initialization failed.\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set GPIO modes for gate control and sensor
    gpioSetMode(GATE_PIN, PI_OUTPUT);
    gpioSetMode(GATE_SENSOR_PIN, PI_INPUT);

    printf("Smart Parking Gate Controller started.\n");

    while (program_running) {
        // Read distance from VL53L1X sensor
        int distance = read_distance(i2c_handle);
        if (distance < 0) {
            fprintf(stderr, "Error reading distance.\n");
            log_event("Error reading distance");
        } else {
            printf("Distance: %d mm\n", distance);

            // Check if an object is close enough to trigger the gate
            if (distance < DISTANCE_THRESHOLD) {
                printf("Object detected! Opening gate.\n");
                log_event("Object detected, opening gate");
                if (control_gate(GATE_PIN, 1) == 0) { // Open the gate
                    // Wait for the gate to open (or timeout)
                    gpioDelay(2000); // Simulate gate opening time
                    if (check_gate_state(GATE_SENSOR_PIN) == 1) {
                        log_event("Gate opened successfully");
                    } else {
                        log_event("Gate failed to open");
                    }
                    gpioDelay(5000); // Wait for vehicle to pass
                    printf("Closing gate.\n");
                    log_event("Closing gate");
                    if (control_gate(GATE_PIN, 0) == 0) { // Close the gate
                        gpioDelay(2000); // Simulate gate closing time
                        if (check_gate_state(GATE_SENSOR_PIN) == 0) {
                            log_event("Gate closed successfully");
                        } else {
                            log_event("Gate failed to close");
                        }
                    }
                } else {
                    log_event("Failed to control gate");
                }
            }
        }

        gpioDelay(100); // Delay between readings
    }

    // Cleanup
    printf("Exiting program.\n");
    i2cClose(i2c_handle);
    gpioTerminate();
    return 0;
}

// Initialize the VL53L1X sensor
int initialize_sensor(int i2c_handle) {
    // Basic initialization (replace with your sensor's initialization sequence)
    // This is a placeholder; consult your sensor's datasheet for the correct sequence.
    char model_id;
    if(i2cReadDevice(i2c_handle, &model_id, 1) != 1){
        perror("Failed to read model ID");
        return -1;
    }

    if (model_id == 0xEE) {
        printf("VL53L1X sensor found.\n");
    } else {
        fprintf(stderr, "VL53L1X sensor not found (Model ID: 0x%02X)\n", model_id);
        return -1;
    }

    //Example of writing a value to a register
    char init_data[2] = {VL53L1X_REG_SYSRANGE_START, 0x01};
    if (i2cWriteDevice(i2c_handle, init_data, 2) != 0) {
        perror("Failed to write to sensor");
        return -1;
    }

    return 0;
}

// Read distance from VL53L1X sensor
int read_distance(int i2c_handle) {
    // This is a simplified example; you'll need to adapt it to your sensor's
    // specific data format and register layout.
    char cmd[1] = {VL53L1X_REG_RESULT_FINAL_CROSSTALK_CORRECTED_RANGE_MM_SD0}; // Command to read distance
    char data[2];

    if (i2cWriteDevice(i2c_handle, cmd, 1) != 0) {
        perror("Failed to write to sensor");
        return -1;
    }

    if (i2cReadDevice(i2c_handle, data, 2) != 2) {
        perror("Failed to read distance");
        return -1;
    }

    // Combine the two bytes into a single distance value
    int distance = (data[0] << 8) | data[1];

    return distance;
}

// Control the gate actuator (relay)
int control_gate(int gate_pin, int state) {
    if (gpioWrite(gate_pin, state) != 0) {
        perror("Failed to control gate");
        return -1;
    }
    return 0;
}

// Check the gate state using the limit switch
int check_gate_state(int gate_sensor_pin) {
    return gpioRead(gate_sensor_pin);
}

// Log events to a file
void log_event(const char* event_description) {
    FILE* log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
        perror("Failed to open log file");
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(log_file, "[%d-%02d-%02d %02d:%02d:%02d] %s\n", tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, event_description);
    fclose(log_file);
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Signal received, exiting.\n");
    program_running = 0;
