#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <pigpio.h>
#include <jansson.h>
#include <unistd.h>

// Define GPIO pins for the two locks (BCM numbering)
#define LOCK1_GPIO 17
#define LOCK2_GPIO 27

// JSON configuration file name
#define CONFIG_FILE "lock_schedule.json"

// Global variables (minimize usage, but needed for signal handler)
static volatile int running = 1;

// Structure to represent a schedule entry
typedef struct {
    int start_time;
    int end_time;
    int lock_state;
} schedule_entry_t;

// Function prototypes
int time_to_minutes(const char *time_str);
int evaluate_schedule(int current_time, schedule_entry_t *schedule, int num_entries);
int set_lock_state(int lock_number, int state);
void signal_handler(int signal);
json_t* load_and_validate_config(const char* filename, schedule_entry_t **schedule, int *num_entries);

// Signal handler to ensure clean shutdown
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("Caught SIGINT, shutting down...\n");
        running = 0;
        // Unlock both doors on shutdown for safety
        set_lock_state(1, 0);
        set_lock_state(2, 0);
        gpioTerminate();
        exit(0);
    }
}

// Converts a time string in HH:MM format to minutes since midnight
int time_to_minutes(const char *time_str) {
    int hours, minutes;
    if (sscanf(time_str, "%d:%d", &hours, &minutes) != 2) {
        fprintf(stderr, "Error parsing time string: %s\n", time_str);
        return -1; // Indicate error
    }
    return hours * 60 + minutes;
}

// Evaluates the schedule and returns the appropriate lock state
int evaluate_schedule(int current_time, schedule_entry_t *schedule, int num_entries) {
    for (int i = 0; i < num_entries; i++) {
        if (schedule[i].start_time <= schedule[i].end_time) {
            // Normal case: start time is before end time
            if (current_time >= schedule[i].start_time && current_time < schedule[i].end_time) {
                return schedule[i].lock_state;
            }
        } else {
            // Wrap-around case: end time is before start time (e.g., overnight schedule)
            if (current_time >= schedule[i].start_time || current_time < schedule[i].end_time) {
                return schedule[i].lock_state;
            }
        }
    }

    // Default to locked state if no schedule entry matches
    return 1; // Locked
}

// Sets the state of a lock (1 or 2) using pigpio
int set_lock_state(int lock_number, int state) {
    int gpio_pin;

    if (lock_number == 1) {
        gpio_pin = LOCK1_GPIO;
    } else if (lock_number == 2) {
        gpio_pin = LOCK2_GPIO;
    } else {
        fprintf(stderr, "Invalid lock number: %d\n", lock_number);
        return -1; // Indicate error
    }

    // Assuming HIGH activates the relay and locks the door
    gpioWrite(gpio_pin, state ? 1 : 0); // Corrected logic
    printf("Lock %d set to %s\n", lock_number, state ? "LOCKED" : "UNLOCKED");
    return 0;
}

json_t* load_and_validate_config(const char* filename, schedule_entry_t **schedule, int *num_entries) {
    json_error_t error;
    json_t *root = json_load_file(filename, 0, &error);

    if (!root) {
        fprintf(stderr, "Error loading JSON file: %s\n", error.text);
        return NULL;
    }

    if (!json_is_array(root)) {
        fprintf(stderr, "Error: Root element is not an array\n");
        json_decref(root);
        return NULL;
    }

    *num_entries = json_array_size(root);
    *schedule = (schedule_entry_t*)malloc(sizeof(schedule_entry_t) * (*num_entries));
    if (*schedule == NULL) {
        fprintf(stderr, "Memory allocation error\n");
        json_decref(root);
        return NULL;
    }

    for (int i = 0; i < *num_entries; i++) {
        json_t *entry = json_array_get(root, i);
        if (!json_is_object(entry)) {
            fprintf(stderr, "Error: Array element %d is not an object\n", i);
            free(*schedule);
            json_decref(root);
            return NULL;
        }

        json_t *start_time_json = json_object_get(entry, "start_time");
        json_t *end_time_json = json_object_get(entry, "end_time");
        json_t *lock_state_json = json_object_get(entry, "lock_state");

        if (!json_is_string(start_time_json) || !json_is_string(end_time_json) || !json_is_boolean(lock_state_json)) {
            fprintf(stderr, "Error: Missing or invalid fields in array element %d\n", i);
            free(*schedule);
            json_decref(root);
            return NULL;
        }

        const char *start_time_str = json_string_value(start_time_json);
        const char *end_time_str = json_string_value(end_time_json);
        int lock_state = json_boolean_value(lock_state_json);

        (*schedule)[i].start_time = time_to_minutes(start_time_str);
        if ((*schedule)[i].start_time == -1) {
            fprintf(stderr, "Error parsing start_time in entry %d\n", i);
            free(*schedule);
            json_decref(root);
            return NULL;
        }

        (*schedule)[i].end_time = time_to_minutes(end_time_str);
        if ((*schedule)[i].end_time == -1) {
            fprintf(stderr, "Error parsing end_time in entry %d\n", i);
            free(*schedule);
            json_decref(root);
            return NULL;
        }

        (*schedule)[i].lock_state = lock_state;
    }

    return root; // Return the root JSON object for later cleanup
}

int main() {
    // Install signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pins as outputs
    gpioSetMode(LOCK1_GPIO, PI_OUTPUT);
    gpioSetMode(LOCK2_GPIO, PI_OUTPUT);

    // Load configuration from JSON file
    schedule_entry_t *schedule = NULL;
    int num_entries = 0;
    json_t *root = load_and_validate_config(CONFIG_FILE, &schedule, &num_entries);

    if (!root) {
        gpioTerminate();
        return 1;
    }

    // Main loop
    while (running) {
        // Get current time
        time_t now = time(NULL);
        struct tm *local_time = localtime(&now);
        int current_time = local_time->tm_hour * 60 + local_time->tm_min;

        // Evaluate schedule
        int lock1_state = evaluate_schedule(current_time, schedule, num_entries);
        int lock2_state = evaluate_schedule(current_time, schedule, num_entries);

        // Set lock states
        set_lock_state(1, lock1_state);
        set_lock_state(2, lock2_state);

        // Sleep for 10 seconds
        usleep(10000000); // 10 seconds
    }

    // Clean up
    free(schedule);
    json_decref(root);
    gpioTerminate();

