#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/spi/spidev.h>
#include <errno.h>

#define SPI_DEVICE "/dev/spidev0.0"
#define SPI_MODE SPI_MODE_0
#define SPI_BITS_PER_WORD 8
#define SPI_SPEED 1000000 // 1 MHz
#define MCP3008_CHANNEL 0

int spi_fd;

int spi_init()
{
    spi_fd = open(SPI_DEVICE, O_RDWR);
    if (spi_fd < 0) {
        perror("Error opening SPI device");
        return -1;
    }

    uint8_t mode = SPI_MODE;
    if (ioctl(spi_fd, SPI_IOC_WR_MODE, &mode) < 0) {
        perror("Error setting SPI mode");
        close(spi_fd);
        return -1;
    }

    uint8_t bits = SPI_BITS_PER_WORD;
    if (ioctl(spi_fd, SPI_IOC_WR_BITS_PER_WORD, &bits) < 0) {
        perror("Error setting SPI bits per word");
        close(spi_fd);
        return -1;
    }

    uint32_t speed = SPI_SPEED;
    if (ioctl(spi_fd, SPI_IOC_WR_MAX_SPEED_HZ, &speed) < 0) {
        perror("Error setting SPI speed");
        close(spi_fd);
        return -1;
    }

    return 0;
}

int read_mcp3008(int channel)
{
    uint8_t tx_buf[3];
    uint8_t rx_buf[3];
    struct spi_ioc_transfer transfer[1];

    tx_buf[0] = 0x01; // Start bit
    tx_buf[1] = ((0x08 | channel) << 4); // Single-ended mode, channel selection
    tx_buf[2] = 0x00; // Don't care

    transfer[0].tx_buf = (unsigned long)tx_buf;
    transfer[0].rx_buf = (unsigned long)rx_buf;
    transfer[0].len = 3;
    transfer[0].delay_usecs = 0;
    transfer[0].speed_hz = SPI_SPEED;
    transfer[0].bits_per_word = SPI_BITS_PER_WORD;
    transfer[0].cs_change = 0;

    if (ioctl(spi_fd, SPI_IOC_MESSAGE(1), transfer) < 0) {
        perror("Error sending SPI message");
        return -1;
    }

    // Extract the ADC value (10 bits)
    int adc_value = ((rx_buf[1] & 0x03) << 8) + rx_buf[2];
    return adc_value;
}

void sort(int arr[], int n)
{
    for (int i = 0; i < n-1; i++)
        for (int j = 0; j < n-i-1; j++)
            if (arr[j] > arr[j+1])
            {
                int temp = arr[j];
                arr[j] = arr[j+1];
                arr[j+1] = temp;
            }
}

int median_filter(int buffer[], int size)
{
    int temp_buffer[size];
    for (int i = 0; i < size; i++) {
        temp_buffer[i] = buffer[i];
    }

    sort(temp_buffer, size);
    return temp_buffer[size / 2];
}

int main()
{
    if (spi_init() < 0) {
        return 1;
    }

    int adc_buffer[5] = {0};
    int buffer_index = 0;

    while (1) {
        int adc_value = read_mcp3008(MCP3008_CHANNEL);
        if (adc_value < 0) {
            fprintf(stderr, "Error reading ADC value\n");
            continue;
        }

        adc_buffer[buffer_index] = adc_value;
        buffer_index = (buffer_index + 1) % 5;

        int filtered_value = median_filter(adc_buffer, 5);
        printf("Raw: %d, Filtered: %d\n", adc_value, filtered_value);
        usleep(100000); // 100ms
    }

    close(spi_fd);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <unistd.h>

// Define GPIO pins for segment control
#define SEG_A 5
#define SEG_B 1
#define SEG_C 22
#define SEG_D 24
#define SEG_E 25
#define SEG_F 4
#define SEG_G 21
#define SEG_DP 23 // Decimal Point (Not used in this example)

// Define GPIO pins for digit selection
#define DIGIT_1 7
#define DIGIT_2 0
#define DIGIT_3 2
#define DIGIT_4 3

// Delay between digit refreshes (in milliseconds)
#define REFRESH_DELAY_MS 2

// Lookup table for 7-segment display patterns (0-9)
const int segmentPatterns[10] = {
    0b00111111, // 0
    0b00000110, // 1
    0b01011011, // 2
    0b01001111, // 3
    0b01100110, // 4
    0b01101101, // 5
    0b01111101, // 6
    0b00000111, // 7
    0b01111111, // 8
    0b01101111  // 9
};

// Function to set the segment pins based on the pattern
void setSegments(int pattern) {
    digitalWrite(SEG_A, (pattern >> 6) & 1);
    digitalWrite(SEG_B, (pattern >> 5) & 1);
    digitalWrite(SEG_C, (pattern >> 4) & 1);
    digitalWrite(SEG_D, (pattern >> 3) & 1);
    digitalWrite(SEG_E, (pattern >> 2) & 1);
    digitalWrite(SEG_F, (pattern >> 1) & 1);
    digitalWrite(SEG_G, pattern & 1);
}

// Function to select a digit
void selectDigit(int digit) {
    digitalWrite(DIGIT_1, (digit == 1) ? LOW : HIGH);
    digitalWrite(DIGIT_2, (digit == 2) ? LOW : HIGH);
    digitalWrite(DIGIT_3, (digit == 3) ? LOW : HIGH);
    digitalWrite(DIGIT_4, (digit == 4) ? LOW : HIGH);
}

// Function to display a digit on a specific digit position
void displayDigit(int digit, int number) {
    selectDigit(digit);
    setSegments(segmentPatterns[number]);
    delay(REFRESH_DELAY_MS);
    setSegments(0x00); // Turn off segments to prevent ghosting
    selectDigit(0);  //Deselect all digits
}

int main() {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed, exiting...\n");
        return 1;
    }

    // Set segment pins as output
    int segmentPins[] = {SEG_A, SEG_B, SEG_C, SEG_D, SEG_E, SEG_F, SEG_G, SEG_DP};
    for (int i = 0; i < sizeof(segmentPins) / sizeof(segmentPins[0]); i++) {
        pinMode(segmentPins[i], OUTPUT);
    }

    // Set digit selection pins as output
    int digitPins[] = {DIGIT_1, DIGIT_2, DIGIT_3, DIGIT_4};
    for (int i = 0; i < sizeof(digitPins) / sizeof(digitPins[0]); i++) {
        pinMode(digitPins[i], OUTPUT);
        digitalWrite(digitPins[i], HIGH); // Initially disable all digits
    }

    // Main loop
    unsigned int counter = 0;
    while (1) {
        // Extract digits
        int digit1 = (counter / 1000) % 10; // Thousands
        int digit2 = (counter / 100) % 10;  // Hundreds
        int digit3 = (counter / 10) % 10;   // Tens
        int digit4 = counter % 10;            // Ones

        // Display digits using multiplexing
        displayDigit(1, digit1);
        displayDigit(2, digit2);
        displayDigit(3, digit3);
        displayDigit(4, digit4);

        // Increment counter every second
        delay(1000 - (4 * REFRESH_DELAY_MS)); // Adjust delay for refresh time

        counter = (counter + 1) % 10000; // Increment and wrap around at 9999
    }

    return 0;
}

