#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <math.h>
#include <signal.h>
#include <unistd.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>

// MPU6050 Registers
#define MPU6050_ADDR 0x68
#define PWR_MGMT_1 0x6B
#define ACCEL_XOUT_H 0x3B
#define ACCEL_YOUT_H 0x3D
#define ACCEL_ZOUT_H 0x3F
#define ACCEL_CONFIG 0x1C

// Accelerometer Sensitivity
#define ACCEL_SENSITIVITY 16384.0f // LSB/g for +/- 2g range

// GPIO Pin for LED
#define LED_PIN 17

// Threshold for acceleration magnitude (in g)
#define ACCEL_THRESHOLD 1.5f

// Global variable for I2C file descriptor
int fd;

// Function to initialize the MPU6050
int initMPU6050() {
  // Wake up the MPU6050 (disable sleep mode)
  if (wiringPiI2CWriteReg8(fd, PWR_MGMT_1, 0) < 0) {
    fprintf(stderr, "Error: Could not wake up MPU6050\n");
    return -1;
  }

  // Configure accelerometer for +/- 2g range
  if (wiringPiI2CWriteReg8(fd, ACCEL_CONFIG, 0) < 0) {
    fprintf(stderr, "Error: Could not configure accelerometer range\n");
    return -1;
  }

  return 0;
}

// Function to read raw accelerometer data
int readRawData(int16_t *x, int16_t *y, int16_t *z) {
  *x = (int16_t)((wiringPiI2CReadReg8(fd, ACCEL_XOUT_H) << 8) | wiringPiI2CReadReg8(fd, ACCEL_XOUT_H + 1));
  *y = (int16_t)((wiringPiI2CReadReg8(fd, ACCEL_YOUT_H) << 8) | wiringPiI2CReadReg8(fd, ACCEL_YOUT_H + 1));
  *z = (int16_t)((wiringPiI2CReadReg8(fd, ACCEL_ZOUT_H) << 8) | wiringPiI2CReadReg8(fd, ACCEL_ZOUT_H + 1));

  return 0;
}

// Function to convert raw data to g's
void convertToG(int16_t x, int16_t y, int16_t z, float *gx, float *gy, float *gz) {
  *gx = (float)x / ACCEL_SENSITIVITY;
  *gy = (float)y / ACCEL_SENSITIVITY;
  *gz = (float)z / ACCEL_SENSITIVITY;
}

// Function to calculate acceleration magnitude
float calculateMagnitude(float gx, float gy, float gz) {
  return sqrt(gx * gx + gy * gy + gz * gz);
}

// Signal handler for graceful shutdown
void signalHandler(int signum) {
  printf("Received signal %d, shutting down...\n", signum);
  digitalWrite(LED_PIN, LOW); // Turn off LED
  exit(0);
}

int main() {
  // Initialize WiringPi with GPIO numbering
  if (wiringPiSetupGpio() == -1) {
    fprintf(stderr, "Error: Could not initialize WiringPi\n");
    return 1;
  }

  // Initialize I2C
  fd = wiringPiI2CSetup(MPU6050_ADDR);
  if (fd == -1) {
    fprintf(stderr, "Error: Could not initialize I2C communication\n");
    return 1;
  }

  // Initialize MPU6050
  if (initMPU6050() == -1) {
    return 1;
  }

  // Set LED pin as output
  pinMode(LED_PIN, OUTPUT);
  digitalWrite(LED_PIN, LOW); // Initially turn off LED

  // Register signal handlers
  signal(SIGINT, signalHandler);
  signal(SIGTERM, signalHandler);

  int16_t rawX, rawY, rawZ;
  float gx, gy, gz, magnitude;

  printf("Starting acceleration monitoring...\n");

  while (1) {
    // Read raw accelerometer data
    if (readRawData(&rawX, &rawY, &rawZ) == -1) {
      fprintf(stderr, "Error: Could not read raw data\n");
    }

    // Convert raw data to g's
    convertToG(rawX, rawY, rawZ, &gx, &gy, &gz);

    // Calculate acceleration magnitude
    magnitude = calculateMagnitude(gx, gy, gz);

    // Log acceleration values
    printf("X: %.3f g, Y: %.3f g, Z: %.3f g, Magnitude: %.3f g\n", gx, gy, gz, magnitude);

    // Check if acceleration exceeds threshold
    if (magnitude > ACCEL_THRESHOLD) {
      digitalWrite(LED_PIN, HIGH); // Turn on LED
    } else {
      digitalWrite(LED_PIN, LOW);  // Turn off LED
    }

    delay(100); // 10 Hz sampling rate
  }

  return 0;
}

