#define SERVO_MAX_PULSE_WIDTH 2000 // Maximum pulse width (us)
#define SERVO_MID_PULSE_WIDTH 1500 // Neutral pulse width (us)

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(SERVO1_PIN, PI_OUTPUT);
    gpioSetMode(SERVO2_PIN, PI_OUTPUT);
    gpioSetMode(SERVO3_PIN, PI_OUTPUT);
    gpioSetMode(BUTTON_PIN, PI_INPUT);
