    while (1) {
        // Read button state
        int current_button_state = gpioRead(BUTTON_PIN);

        // Check for button press (falling edge)
        if (current_button_state == 0 && button_state == 1) {
            printf("Button pressed!\n");

            // Adjust servo positions
            gpioServo(SERVO1_PIN, SERVO_MIN_PULSE_WIDTH);
            gpioServo(SERVO2_PIN, SERVO_MID_PULSE_WIDTH);
