// Function to initialize the Raspberry Pi and PCF8591
int initialize()
{
    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error initializing WiringPi.\n");
        return -1;
    }

    // Initialize PCF8591
    pcf8591Setup(PCF8591_BASE, PCF8591_I2C_ADDR);

