void controlLedBrightness()
{
    int analogValue;
    int pwmValue;

    // Read analog value from PCF8591
    analogValue = analogRead(PCF8591_BASE + ANALOG_INPUT_PIN);

    // Map analog value (0-255) to PWM range (0-1023)
    pwmValue = analogValue * 4;  // Scale the value for PWM range

    // Write PWM value to LED pin
    pwmWrite(LED_PIN, pwmValue);

    printf("Analog Value: %d, PWM Value: %d\n", analogValue, pwmValue);

    delay(10); // Small delay
}

