} aqi_data_t;

// Structure for circular buffer
typedef struct {
    aqi_data_t data[CIRCULAR_BUFFER_SIZE];
    int head;
    int tail;
    int count;
} circular_buffer;

// Function Prototypes
int init_uart(const char *port, int baud);
int read_pms5003_data(float *pm1_0, float *pm2_5, float *pm10);
float calculate_aqi(float pm25_value);
