    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed!\n");
        return 1;
    }

    // Initialize UART
    serial_fd = init_uart(UART_PORT, BAUD_RATE);
