    }

    // Initialize Circular Buffer
    circular_buffer aqi_buffer;
    aqi_buffer.head = 0;
    aqi_buffer.tail = 0;
    aqi_buffer.count = 0;

    // Set up signal handler for graceful shutdown
    signal(SIGINT, sigint_handler);

    float pm1_0, pm2_5, pm10;
    float aqi_value;

    while (keep_running) {
        // Read data from PMS5003 sensor
        if (read_pms5003_data(&pm1_0, &pm2_5, &pm10) == 0) {
            // Calculate AQI
            aqi_value = calculate_aqi(pm2_5);

            // Enqueue data into circular buffer
            enqueue_data(&aqi_buffer, aqi_value);

            // Display AQI on OLED screen
            if(i2c_fd > 0) display_aqi(aqi_value);

