// Initialize UART
int init_uart(const char *port, int baud) {
    int fd = serialOpen(port, baud);
    if (fd == -1) {
        perror("serialOpen failed");
        return -1;
    }
    return fd;
}

// Read data from PMS5003 sensor
int read_pms5003_data(float *pm1_0, float *pm2_5, float *pm10) {
    unsigned char buffer[32];
    unsigned int i = 0, checksum = 0;

    // Wait for start bytes
    while (serialDataAvail(serial_fd) < 2) {
        delay(1);
    }

    if (serialGetchar(serial_fd) != 0x42 || serialGetchar(serial_fd) != 0x4d) {
        fprintf(stderr, "Invalid start bytes!\n");
        return -1;
    }

    buffer[0] = 0x42;
    buffer[1] = 0x4d;

    // Read the rest of the data
    while (i < 30) {
        while (serialDataAvail(serial_fd) < 1) {
            delay(1);
        }
        buffer[i+2] = serialGetchar(serial_fd);
        i++;
    }

    // Calculate checksum
    for (i = 0; i < 30; i++) {
        checksum += buffer[i+2];
    }

    unsigned int calculated_checksum = (buffer[30+2] << 8) | buffer[31+2];

    if (checksum != calculated_checksum) {
        fprintf(stderr, "Checksum mismatch!\n");
        return -1;
    }

    // Extract PM values
    *pm1_0 = (buffer[4] << 8) | buffer[5];
    *pm2_5 = (buffer[6] << 8) | buffer[7];
    *pm10 = (buffer[8] << 8) | buffer[9];

    return 0;
}

// Calculate AQI based on PM2.5 concentration (US EPA standard)
float calculate_aqi(float pm25_value) {
    float aqi;

    if (pm25_value <= 12.0) {
        aqi = (50.0 / 12.0) * pm25_value;
    } else if (pm25_value <= 35.4) {
        aqi = ((100.0 - 51.0) / (35.4 - 12.1)) * (pm25_value - 12.1) + 51.0;
    } else if (pm25_value <= 55.4) {
        aqi = ((150.0 - 101.0) / (55.4 - 35.5)) * (pm25_value - 35.5) + 101.0;
    } else if (pm25_value <= 150.4) {
        aqi = ((200.0 - 151.0) / (150.4 - 55.5)) * (pm25_value - 55.5) + 151.0;
    } else if (pm25_value <= 250.4) {
        aqi = ((300.0 - 201.0) / (250.4 - 150.5)) * (pm25_value - 150.5) + 201.0;
    } else if (pm25_value <= 350.4) {
        aqi = ((400.0 - 301.0) / (350.4 - 250.5)) * (pm25_value - 250.5) + 301.0;
    } else if (pm25_value <= 500.4) {
        aqi = ((500.0 - 401.0) / (500.4 - 350.5)) * (pm25_value - 350.5) + 401.0;
    } else {
        aqi = 500.0;
    }

    return aqi;
}

// Enqueue data into circular buffer
void enqueue_data(circular_buffer *buffer, float aqi_value) {
    buffer->data[buffer->head].timestamp = time(NULL);
    buffer->data[buffer->head].aqi_value = aqi_value;
    buffer->head = (buffer->head + 1) % CIRCULAR_BUFFER_SIZE;
    if (buffer->count == CIRCULAR_BUFFER_SIZE) {
        buffer->tail = (buffer->tail + 1) % CIRCULAR_BUFFER_SIZE;
    } else {
        buffer->count++;
    }
}

// Dequeue data from circular buffer
float dequeue_data(circular_buffer *buffer) {
    if (buffer->count == 0) {
        return -1.0; // Indicate empty buffer
    }
    float value = buffer->data[buffer->tail].aqi_value;
    buffer->tail = (buffer->tail + 1) % CIRCULAR_BUFFER_SIZE;
    buffer->count--;
    return value;
}

// Initialize I2C and OLED Display
int init_oled() {
    int fd = open("/dev/i2c-1", O_RDWR);
    if (fd < 0) {
        perror("Failed to open i2c device");
        return -1;
    }

    if (ioctl(fd, I2C_SLAVE, OLED_ADDRESS) < 0) {
        perror("Failed to acquire bus access and/or talk to slave");
        close(fd);
        return -1;
    }

    // Initialization sequence (basic, depends on the specific OLED)
    i2c_write_command(fd, 0xAE); // Display off
    i2c_write_command(fd, 0x00); // Set low column address
    i2c_write_command(fd, 0x10); // Set high column address
    i2c_write_command(fd, 0x40); // Set start line address
    i2c_write_command(fd, 0x81); // Set contrast control register
    i2c_write_command(fd, 0xCF); // Set SEG output current brightness
    i2c_write_command(fd, 0xA1); // Set segment re-map 0 to 127
    i2c_write_command(fd, 0xC8); // Set COM output scan direction
    i2c_write_command(fd, 0xA6); // Set normal display
    i2c_write_command(fd, 0xA8); // Set multiplex ratio(1 to 64)
    i2c_write_command(fd, 0x3F); // 1/64 duty
    i2c_write_command(fd, 0xD3); // Set display offset
    i2c_write_command(fd, 0x00); // Offset: 0
    i2c_write_command(fd, 0xD5); // Set divide ratio/oscillator frequency
    i2c_write_command(fd, 0x80); // Set divide ratio, Fosc
    i2c_write_command(fd, 0xD9); // Set pre-charge period
    i2c_write_command(fd, 0xF1); // Set pre-charge period
    i2c_write_command(fd, 0xDA); // Set com pins hardware configuration
    i2c_write_command(fd, 0x12);
    i2c_write_command(fd, 0xDB); // Set vcomh
    i2c_write_command(fd, 0x40);
    i2c_write_command(fd, 0x8D); // Charge pump enable/disable
    i2c_write_command(fd, 0x14); // Set(0x10) disable
    i2c_write_command(fd, 0xAF); // Display on

    return fd;
}

// Display AQI on OLED screen (crude implementation)
void display_aqi(float aqi_value) {
    if (i2c_fd < 0) return; //OLED not initialized
    char buffer[20];
    snprintf(buffer, sizeof(buffer), "AQI: %.1f", aqi_value);

    // Very basic pixel writing.  Needs improvement for readability.
    // A proper OLED library would be much better.
    // This is just a placeholder to show I2C communication.
    for (int i = 0; i < OLED_WIDTH; i++) {
        for (int j = 0; j < OLED_HEIGHT; j++) {
            //Crude text rendering, replace with a proper library
            if(j < 8 && i < strlen(buffer)*8) {
                if(buffer[i/8] & (1 << (i%8))) {
                    draw_pixel(i, j, 1);
                } else {
                    draw_pixel(i, j, 0);
                }
            } else {
                draw_pixel(i, j, 0);
            }
        }
    }

    if (aqi_value > AQI_THRESHOLD) {
        fprintf(stderr, "High AQI: %.1f!\n", aqi_value);
    }
}

// Clear OLED display (basic)
void clear_oled() {
    if (i2c_fd < 0) return; //OLED not initialized
    for (int i = 0; i < OLED_WIDTH; i++) {
        for (int j = 0; j < OLED_HEIGHT; j++) {
            draw_pixel(i, j, 0); // Black
        }
    }
}

// Signal handler for graceful shutdown
void sigint_handler(int sig) {
    keep_running = 0;
    fprintf(stderr, "Received SIGINT, shutting down...\n");
}

