#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <unistd.h>
#include <inttypes.h>
#include <errno.h>
#include <string.h>

// MPU6050 Register Addresses
#define MPU6050_ADDR 0x68        // I2C address of the MPU6050
#define MPU6050_REG_PWR_MGMT_1 0x6B // Power Management 1 register
#define MPU6050_REG_TEMP_OUT_H 0x41 // Temperature sensor output (high byte)
#define MPU6050_REG_ACCEL_XOUT_H 0x3B // Accelerometer X-axis output (high byte)
#define MPU6050_REG_GYRO_XOUT_H 0x43  // Gyroscope X-axis output (high byte)

// Helper macros for reading and combining high and low bytes
#define READ_HIGH_LOW(fd, high_reg, low_offset) ((int16_t)(((uint16_t)i2c_smbus_read_byte_data(fd, high_reg) << 8) | (uint16_t)i2c_smbus_read_byte_data(fd, (high_reg) + (low_offset))))

// Function to handle I2C errors
void i2c_error_handler(const char *message, int fd) {
    fprintf(stderr, "Error: %s (errno: %d, %s)\n", message, errno, strerror(errno));
    if (fd > 0) {
        close(fd);
    }
    exit(EXIT_FAILURE);
}

int main() {
    const char *i2c_device = "/dev/i2c-1"; // I2C device file
    int file_descriptor;                    // File descriptor for the I2C device

    // Open the I2C device
    if ((file_descriptor = open(i2c_device, O_RDWR)) < 0) {
        i2c_error_handler("Failed to open I2C device", 0);
    }

    // Specify the address of the slave device
    if (ioctl(file_descriptor, I2C_SLAVE, MPU6050_ADDR) < 0) {
        i2c_error_handler("Failed to acquire bus access and/or talk to slave", file_descriptor);
    }

    // Wake up the MPU6050 (clear sleep mode bit)
    if (i2c_smbus_write_byte_data(file_descriptor, MPU6050_REG_PWR_MGMT_1, 0) < 0) {
        i2c_error_handler("Failed to wake up MPU6050", file_descriptor);
    }

    // Main loop to read and print data
    while (1) {
        // Read temperature data
        int16_t temperature_raw = READ_HIGH_LOW(file_descriptor, MPU6050_REG_TEMP_OUT_H, 1);

        // Read accelerometer data
        int16_t accel_x = READ_HIGH_LOW(file_descriptor, MPU6050_REG_ACCEL_XOUT_H, 1);
        int16_t accel_y = READ_HIGH_LOW(file_descriptor, MPU6050_REG_ACCEL_XOUT_H + 2, 1);
        int16_t accel_z = READ_HIGH_LOW(file_descriptor, MPU6050_REG_ACCEL_XOUT_H + 4, 1);

        // Read gyroscope data
        int16_t gyro_x = READ_HIGH_LOW(file_descriptor, MPU6050_REG_GYRO_XOUT_H, 1);
        int16_t gyro_y = READ_HIGH_LOW(file_descriptor, MPU6050_REG_GYRO_XOUT_H + 2, 1);
        int16_t gyro_z = READ_HIGH_LOW(file_descriptor, MPU6050_REG_GYRO_XOUT_H + 4, 1);

        // Convert temperature to Celsius
        float temperature_celsius = (float)temperature_raw / 340.0f + 36.53f;

        // Print the data
        printf("Temperature: %.2f °C\n", temperature_celsius);
        printf("Accelerometer (X, Y, Z): %6d, %6d, %6d\n", accel_x, accel_y, accel_z);
        printf("Gyroscope (X, Y, Z):     %6d, %6d, %6d\n\n", gyro_x, gyro_y, gyro_z);

        sleep(1); // Delay for 1 second
    }

    close(file_descriptor); // Close the I2C device
    return 0;
}

