    }

    // Set the LED pin to PWM output mode
    pinMode(LED_PIN, PWM_OUTPUT);

    // Main loop for the breathing effect
    while (1) {
        // Fade in (0 to PWM_RANGE - 1)
        for (brightness = 0; brightness < PWM_RANGE; ++brightness) {
            pwmWrite(LED_PIN, brightness);
            //printf("Brightness: %d\n", brightness); // Optional: Print brightness value
            delay(DELAY_MS);
        }

        // Fade out (PWM_RANGE - 1 to 0)
        for (brightness = PWM_RANGE - 1; brightness >= 0; --brightness) {
            pwmWrite(LED_PIN, brightness);
            //printf("Brightness: %d\n", brightness); // Optional: Print brightness value
            delay(DELAY_MS);
        }
    }

    return 0;
}

#include <iostream>
#include <cmath>
#include <csignal>
#include <pigpio.h>
#include <unistd.h>

// Define MPU6050 registers
#define MPU6050_ADDR 0x68
#define PWR_MGMT_1 0x6B
#define ACCEL_XOUT_H 0x3B
#define ACCEL_YOUT_H 0x3D
#define ACCEL_ZOUT_H 0x3F

// Define LED GPIO pin
#define LED_PIN 17

// Define acceleration scale factor
#define ACCEL_SCALE 16384.0

// Global variables for signal handling
volatile sig_atomic_t program_running = 1;
int i2c_handle;

// Function prototypes
void signal_handler(int signal);

class LEDIndicator {
public:
    LEDIndicator(int pin) : pin_(pin) {
        gpioSetMode(pin_, PI_OUTPUT);
        turnOff(); // Initialize LED to off state
    }

    void turnOn() {
        gpioWrite(pin_, 1);
    }

    void turnOff() {
        gpioWrite(pin_, 0);
    }

private:
    int pin_;
};

class MPU6050Sensor {
public:
    MPU6050Sensor(int i2c_bus, int i2c_addr) : i2c_bus_(i2c_bus), i2c_addr_(i2c_addr), i2c_handle_(-1) {}

    bool initialize() {
        i2c_handle_ = i2cOpen(i2c_bus_, i2c_addr_, 0);
        if (i2c_handle_ < 0) {
            std::cerr << "Error opening I2C device: " << i2c_handle_ << std::endl;
            return false;
        }

        // Wake up the MPU6050 (disable sleep mode)
        int result = i2cWriteByteData(i2c_handle_, PWR_MGMT_1, 0);
        if (result < 0) {
            std::cerr << "Error writing to PWR_MGMT_1: " << result << std::endl;
            i2cClose(i2c_handle_);
            i2c_handle_ = -1;
            return false;
        }
        return true;
    }

    bool readData(float& x, float& y, float& z) {
        if (i2c_handle_ < 0) {
            std::cerr << "I2C not initialized" << std::endl;
            return false;
        }

        int16_t raw_x = i2cReadWordData(i2c_handle_, ACCEL_XOUT_H);
        int16_t raw_y = i2cReadWordData(i2c_handle_, ACCEL_YOUT_H);
        int16_t raw_z = i2cReadWordData(i2c_handle_, ACCEL_ZOUT_H);

        if (raw_x < 0 || raw_y < 0 || raw_z < 0) {
            std::cerr << "Error reading accelerometer data" << std::endl;
            return false;
        }

        x = static_cast<float>(raw_x) / ACCEL_SCALE;
        y = static_cast<float>(raw_y) / ACCEL_SCALE;
        z = static_cast<float>(raw_z) / ACCEL_SCALE;

        return true;
    }

    void close() {
        if (i2c_handle_ >= 0) {
            i2cClose(i2c_handle_);
            i2c_handle_ = -1;
        }
    }

private:
    int i2c_bus_;
    int i2c_addr_;
    int i2c_handle_;
};

void signal_handler(int signal) {
    std::cout << "Received signal " << signal << ". Shutting down..." << std::endl;
    program_running = 0;
}

int main() {
    if (gpioInitialise() < 0) {
        std::cerr << "pigpio initialisation failed" << std::endl;
        return 1;
    }

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    MPU6050Sensor sensor(1, MPU6050_ADDR); // I2C bus 1, MPU6050 address 0x68
    LEDIndicator led(LED_PIN);

    if (!sensor.initialize()) {
        std::cerr << "MPU6050 initialization failed" << std::endl;
        gpioTerminate();
        return 1;
    }

    float x, y, z;
    while (program_running) {
        if (sensor.readData(x, y, z)) {
            float magnitude = sqrt(x * x + y * y + z * z);
            std::cout << "Acceleration: X=" << x << "g, Y=" << y << "g, Z=" << z << "g, Magnitude=" << magnitude << "g" << std::endl;

            if (magnitude > 1.5) {
                led.turnOn();
            } else {
                led.turnOff();
            }
        } else {
            std::cerr << "Failed to read sensor data. Attempting re-initialization." << std::endl;
            sensor.close();
            if (!sensor.initialize()) {
                std::cerr << "MPU6050 re-initialization failed. Exiting." << std::endl;
                program_running = 0; // Exit loop if re-initialization fails
            }
        }

        gpioDelay(100); // Read data every 100ms
    }

    // Cleanup
    std::cout << "Cleaning up..." << std::endl;
    led.turnOff(); // Ensure LED is off before exiting
    sensor.close();  // Close I2C connection
    gpioTerminate(); // Terminate pigpio

    std::cout << "Program terminated." << std::endl;
    return 0;
}

