#include <time.h>
#include <string.h>
#include <signal.h>
#include <unistd.h>
#include <math.h>

// LSM303D I2C address
#define LSM303D_ADDR 0x1E

// LSM303D register addresses
#define OUT_X_L_M 0x08
#define OUT_X_H_M 0x09
#define OUT_Y_L_M 0x0A
#define OUT_Y_H_M 0x0B
#define OUT_Z_L_M 0x0C
#define OUT_Z_H_M 0x0D
#define CRA_REG_M 0x00
#define CRB_REG_M 0x01
#define MR_REG_M 0x02

// LED GPIO pin
#define LED_PIN 17

// Magnetic field threshold (in microteslas)
#define MAG_THRESHOLD 50.0

// Hard iron calibration values (replace with your calibrated values)
const int16_t X_OFFSET = 0;
const int16_t Y_OFFSET = 0;
const int16_t Z_OFFSET = 0;

// I2C handle
int i2c_handle;

// Flag to indicate program termination
volatile sig_atomic_t terminate = 0;

// Signal handler for graceful shutdown
void signal_handler(int sig) {
    fprintf(stderr, "\nCaught signal %d, terminating...", sig);
    terminate = 1;
}

// Structure to hold magnetometer data
typedef struct {
    int16_t x;
    int16_t y;
    int16_t z;
} magnetometer_data_t;

// Function to initialize the LSM303D magnetometer
int init_lsm303d() {
    // Configure CRA_REG_M (e.g., data rate)
    if (i2cWriteByteData(i2c_handle, CRA_REG_M, 0x14) < 0) { // 220 Hz
        fprintf(stderr, "Error writing to CRA_REG_M\n");
        return -1;
    }

    // Configure CRB_REG_M (e.g., gain)
    if (i2cWriteByteData(i2c_handle, CRB_REG_M, 0x20) < 0) { // Gain setting
        fprintf(stderr, "Error writing to CRB_REG_M\n");
        return -1;
    }

    // Configure MR_REG_M (continuous conversion mode)
    if (i2cWriteByteData(i2c_handle, MR_REG_M, 0x00) < 0) {
        fprintf(stderr, "Error writing to MR_REG_M\n");
        return -1;
    }

    return 0;
}

// Function to read magnetometer data
magnetometer_data_t read_magnetometer_data() {
    char buffer[6];
    magnetometer_data_t data;

    if (i2cReadI2CBlockData(i2c_handle, OUT_X_L_M, buffer, 6) != 6) {
        fprintf(stderr, "Error reading magnetometer data\n");
        data.x = 0;
        data.y = 0;
        data.z = 0;
        return data;
    }

    data.x = (int16_t)((buffer[1] << 8) | buffer[0]);
    data.y = (int16_t)((buffer[3] << 8) | buffer[2]);
    data.z = (int16_t)((buffer[5] << 8) | buffer[4]);

    return data;
}

// Function to calculate magnetic field magnitude
float calculate_magnitude(magnetometer_data_t data) {
    float x = (float)(data.x - X_OFFSET);
    float y = (float)(data.y - Y_OFFSET);
    float z = (float)(data.z - Z_OFFSET);

    return sqrt(x * x + y * y + z * z);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C connection
    i2c_handle = i2cOpen(1, LSM303D_ADDR, 0); // Bus 1, address 0x1E, no flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C connection: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Initialize LSM303D
    if (init_lsm303d() < 0) {
        fprintf(stderr, "Error initializing LSM303D\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set LED pin as output
    gpioSetMode(LED_PIN, PI_OUTPUT);

    // Install signal handler
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Main loop
    while (!terminate) {
        // Read magnetometer data
        magnetometer_data_t data = read_magnetometer_data();

        // Calculate magnetic field magnitude
        float magnitude = calculate_magnitude(data);

        // Check if magnitude exceeds threshold
        if (magnitude > MAG_THRESHOLD) {
            // Turn LED on
            gpioWrite(LED_PIN, 1);

            // Log message to console
            time_t now = time(NULL);
            struct tm *t = localtime(&now);
            char timestamp[64];
            strftime(timestamp, sizeof(timestamp) - 1, "%Y-%m-%d %H:%M:%S", t);
            printf("%s - Threshold exceeded: X=%d, Y=%d, Z=%d, Magnitude=%.2f\n", timestamp, data.x, data.y, data.z, magnitude);
        } else {
            // Turn LED off
            gpioWrite(LED_PIN, 0);

            // Log data to console
            time_t now = time(NULL);
            struct tm *t = localtime(&now);
            char timestamp[64];
            strftime(timestamp, sizeof(timestamp) - 1, "%Y-%m-%d %H:%M:%S", t);
            printf("%s - X=%d, Y=%d, Z=%d, Magnitude=%.2f\n", timestamp, data.x, data.y, data.z, magnitude);
        }

        // Delay
        time_sleep(0.1); // 100 milliseconds
    }

    // Cleanup
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

