#define FLAME_SENSOR_GPIO 17
#define BUZZER_GPIO 27
#define LED_GPIO 22

// Function to export a GPIO pin
int export_gpio(int gpio) {
    FILE *fp = fopen("/sys/class/gpio/export", "w");
    if (fp == NULL) {
        perror("Error opening /sys/class/gpio/export");
        return -1;
    }
    fprintf(fp, "%d", gpio);
    if (fclose(fp) != 0) {
        perror("Error closing /sys/class/gpio/export");
        return -1;
    }
    return 0;
}

// Function to unexport a GPIO pin
int unexport_gpio(int gpio) {
    FILE *fp = fopen("/sys/class/gpio/unexport", "w");
    if (fp == NULL) {
        perror("Error opening /sys/class/gpio/unexport");
        return -1;
    }
    fprintf(fp, "%d", gpio);
    if (fclose(fp) != 0) {
        perror("Error closing /sys/class/gpio/unexport");
        return -1;
    }
    return 0;
}

// Function to set GPIO direction (in or out)
int set_gpio_direction(int gpio, const char *direction) {
    char path[50];
    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/direction", gpio);
    FILE *fp = fopen(path, "w");
    if (fp == NULL) {
        perror("Error opening GPIO direction file");
        return -1;
    }
    fprintf(fp, "%s", direction);
    if (fclose(fp) != 0) {
        perror("Error closing GPIO direction file");
        return -1;
    }
    return 0;
}

// Function to read GPIO value
int read_gpio_value(int gpio) {
    char path[50];
    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", gpio);
    FILE *fp = fopen(path, "r");
    if (fp == NULL) {
        perror("Error opening GPIO value file");
        return -1; // Indicate error
    }
    int value;
    if (fscanf(fp, "%d", &value) != 1) {
        perror("Error reading GPIO value");
        fclose(fp);
        return -1; // Indicate error
    }
    if (fclose(fp) != 0) {
        perror("Error closing GPIO value file");
        return -1;
    }
    return value;
}

// Function to write GPIO value
int write_gpio_value(int gpio, int value) {
    char path[50];
    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", gpio);
    FILE *fp = fopen(path, "w");
    if (fp == NULL) {
        perror("Error opening GPIO value file");
        return -1;
    }
    fprintf(fp, "%d", value);
    if (fclose(fp) != 0) {
        perror("Error closing GPIO value file");
        return -1;
    }
    return 0;
}

// Function to get current timestamp
void get_timestamp(char *timestamp) {
    time_t rawtime;
    struct tm *timeinfo;
    time(&rawtime);
    timeinfo = localtime(&rawtime);
    strftime(timestamp, 20, "%Y-%m-%d %H:%M:%S", timeinfo);
}

// Function to initialize GPIO pins
int initialize_gpio(int flame_gpio, int buzzer_gpio, int led_gpio) {
    if (export_gpio(flame_gpio) != 0 ||
        export_gpio(buzzer_gpio) != 0 ||
        export_gpio(led_gpio) != 0) {
        return -1;
    }

    sleep(1); // Wait for the files to be created

    if (set_gpio_direction(flame_gpio, "in") != 0 ||
        set_gpio_direction(buzzer_gpio, "out") != 0 ||
        set_gpio_direction(led_gpio, "out") != 0) {
        return -1;
    }

    return 0;
}

// Function to cleanup GPIO pins
int cleanup_gpio(int flame_gpio, int buzzer_gpio, int led_gpio) {
    if (unexport_gpio(flame_gpio) != 0 ||
        unexport_gpio(buzzer_gpio) != 0 ||
        unexport_gpio(led_gpio) != 0) {
        return -1;
    }
    return 0;
}

int main() {
    if (initialize_gpio(FLAME_SENSOR_GPIO, BUZZER_GPIO, LED_GPIO) != 0) {
        fprintf(stderr, "GPIO initialization failed. Exiting.\n");
        return 1;
    }

    char timestamp[20];

    while (1) {
        int flame_detected = read_gpio_value(FLAME_SENSOR_GPIO);
        if (flame_detected == -1) {
            fprintf(stderr, "Error reading flame sensor value. Continuing.\n");
            sleep(1); // Avoid spamming errors
            continue;
        }

        if (flame_detected == 0) { // Assuming LOW signal indicates flame
            get_timestamp(timestamp);
            printf("%s: Flame detected!\n", timestamp);

            if (write_gpio_value(BUZZER_GPIO, 1) != 0) {
                fprintf(stderr, "Error activating buzzer.\n");
            }
            if (write_gpio_value(LED_GPIO, 1) != 0) {
                fprintf(stderr, "Error activating LED.\n");
            }
            sleep(5); // Keep buzzer and LED on for 5 seconds

            if (write_gpio_value(BUZZER_GPIO, 0) != 0) {
                fprintf(stderr, "Error deactivating buzzer.\n");
            }
            if (write_gpio_value(LED_GPIO, 0) != 0) {
                fprintf(stderr, "Error deactivating LED.\n");
            }
        }

        sleep(1); // Check every 1 second
    }

    // This part will never be reached in the current infinite loop
    // It's important to have a mechanism to break the loop and call cleanup_gpio in a real application

    return 0;
}

