// Sysfs paths
#define GPIO_EXPORT_PATH "/sys/class/gpio/export"
#define GPIO_UNEXPORT_PATH "/sys/class/gpio/unexport"
#define GPIO_DIR_PATH_FORMAT "/sys/class/gpio/gpio%d/direction"
#define GPIO_VALUE_PATH_FORMAT "/sys/class/gpio/gpio%d/value"
#define GPIO_EDGE_PATH_FORMAT "/sys/class/gpio/gpio%d/edge"

// Timer interval for RPM calculation (seconds)
#define RPM_TIMER_INTERVAL 1

// Stall detection timeout (seconds)
#define STALL_TIMEOUT 10

// Global variables
volatile sig_atomic_t program_running = 1;
volatile unsigned int rotation_count = 0;
timer_t stall_timer_id;
int led_state = 0; // 0: off, 1: on

// Function prototypes
int gpio_export(int gpio);
int gpio_unexport(int gpio);
int gpio_set_direction(int gpio, const char *direction);
int gpio_set_edge(int gpio, const char *edge);
