// Function to export a GPIO pin
int gpio_export(int gpio) {
  char buf[64];
  int fd = open(GPIO_EXPORT_PATH, O_WRONLY);
  if (fd < 0) {
    fprintf(stderr, "Error opening %s: %s\n", GPIO_EXPORT_PATH, strerror(errno));
    return -1;
  }
  int len = snprintf(buf, sizeof(buf), "%d", gpio);
  if (write(fd, buf, len) != len) {
    fprintf(stderr, "Error writing to %s: %s\n", GPIO_EXPORT_PATH, strerror(errno));
    close(fd);
    return -1;
  }
  close(fd);
  return 0;
}

// Function to unexport a GPIO pin
int gpio_unexport(int gpio) {
  char buf[64];
  int fd = open(GPIO_UNEXPORT_PATH, O_WRONLY);
  if (fd < 0) {
    fprintf(stderr, "Error opening %s: %s\n", GPIO_UNEXPORT_PATH, strerror(errno));
    return -1;
  }
  int len = snprintf(buf, sizeof(buf), "%d", gpio);
  if (write(fd, buf, len) != len) {
    fprintf(stderr, "Error writing to %s: %s\n", GPIO_UNEXPORT_PATH, strerror(errno));
    close(fd);
    return -1;
  }
  close(fd);
  return 0;
}

// Function to set the direction of a GPIO pin (in or out)
int gpio_set_direction(int gpio, const char *direction) {
  char path[128];
  snprintf(path, sizeof(path), GPIO_DIR_PATH_FORMAT, gpio);
  int fd = open(path, O_WRONLY);
  if (fd < 0) {
    fprintf(stderr, "Error opening %s: %s\n", path, strerror(errno));
    return -1;
  }
  if (write(fd, direction, strlen(direction)) != strlen(direction)) {
    fprintf(stderr, "Error writing to %s: %s\n", path, strerror(errno));
    close(fd);
    return -1;
  }
  close(fd);
  return 0;
}

// Function to set the edge trigger for a GPIO pin (rising, falling, both, none)
int gpio_set_edge(int gpio, const char *edge) {
  char path[128];
  snprintf(path, sizeof(path), GPIO_EDGE_PATH_FORMAT, gpio);
  int fd = open(path, O_WRONLY);
  if (fd < 0) {
    fprintf(stderr, "Error opening %s: %s\n", path, strerror(errno));
    return -1;
  }
  if (write(fd, edge, strlen(edge)) != strlen(edge)) {
    fprintf(stderr, "Error writing to %s: %s\n", path, strerror(errno));
    close(fd);
    return -1;
  }
  close(fd);
  return 0;
}

// Function to get the file descriptor for the GPIO value file
int gpio_get_value_fd(int gpio) {
  char path[128];
  snprintf(path, sizeof(path), GPIO_VALUE_PATH_FORMAT, gpio);
  int fd = open(path, O_RDONLY);
  if (fd < 0) {
    fprintf(stderr, "Error opening %s: %s\n", path, strerror(errno));
    return -1;
  }
  return fd;
}

// Function to calculate RPM and log it to the console
void calculate_rpm(int sig) {
  static unsigned int last_rotation_count = 0;
  unsigned int rpm = (rotation_count - last_rotation_count) * 60; // Rotations per second * 60 = RPM
  printf("RPM: %u\n", rpm);
  last_rotation_count = rotation_count;
}

// Stall detection timer callback function
void stall_detection(int sig) {
  // Toggle LED state
  led_state = !led_state;
  char value[2];
  snprintf(value, sizeof(value), "%d", led_state);

  char path[128];
  snprintf(path, sizeof(path), GPIO_VALUE_PATH_FORMAT, STALL_LED_GPIO);
  int fd = open(path, O_WRONLY);
  if (fd < 0) {
    fprintf(stderr, "Error opening %s: %s\n", path, strerror(errno));
    return;
  }
  if (write(fd, value, strlen(value)) != strlen(value)) {
    fprintf(stderr, "Error writing to %s: %s\n", path, strerror(errno));
  }
  close(fd);

  fprintf(stderr, "Stall detected! Toggling LED.\n");
}

// Signal handler for SIGINT and SIGTERM
void signal_handler(int sig) {
  program_running = 0;
  printf("Exiting gracefully...\n");
}

int main() {
  // Signal handling setup
  struct sigaction sa;
  sa.sa_handler = signal_handler;
sigemptyset(&sa.sa_mask);
sa.sa_flags = 0;
if (sigaction(SIGINT, &sa, NULL) == -1 || sigaction(SIGTERM, &sa, NULL) == -1) {
    fprintf(stderr, "Error setting signal handler: %s\n", strerror(errno));
    return 1;
}

  // GPIO setup
  if (gpio_export(ROTATION_SENSOR_GPIO) < 0) return 1;
  if (gpio_set_direction(ROTATION_SENSOR_GPIO, "in") < 0) {
    gpio_unexport(ROTATION_SENSOR_GPIO);
    return 1;
  }
  if (gpio_set_edge(ROTATION_SENSOR_GPIO, "rising") < 0) {
    gpio_unexport(ROTATION_SENSOR_GPIO);
    return 1;
  }

  if (gpio_export(STALL_LED_GPIO) < 0) {
      gpio_unexport(ROTATION_SENSOR_GPIO);
      return 1;
  }
  if (gpio_set_direction(STALL_LED_GPIO, "out") < 0) {
    gpio_unexport(ROTATION_SENSOR_GPIO);
    gpio_unexport(STALL_LED_GPIO);
    return 1;
  }

  int rotation_fd = gpio_get_value_fd(ROTATION_SENSOR_GPIO);
  if (rotation_fd < 0) {
    gpio_unexport(ROTATION_SENSOR_GPIO);
    gpio_unexport(STALL_LED_GPIO);
    return 1;
  }

  // Timer setup for RPM calculation
  struct sigevent sev;
  struct itimerspec its;

  memset(&sev, 0, sizeof(sev));
  sev.sigev_notify = SIGEV_SIGNAL;
  sev.sigev_signo = SIGALRM;
  sev.sigev_value.sival_int = 0; // Not used, but required
  if (timer_create(CLOCK_REALTIME, &sev, &stall_timer_id) == -1) {
      fprintf(stderr, "Error creating timer: %s\n", strerror(errno));
      close(rotation_fd);
      gpio_unexport(ROTATION_SENSOR_GPIO);
      gpio_unexport(STALL_LED_GPIO);
      return 1;
  }

  // Timer setup for stall detection
  timer_t rpm_timer_id;
  struct sigevent rpm_sev;
  memset(&rpm_sev, 0, sizeof(rpm_sev));
  rpm_sev.sigev_notify = SIGEV_SIGNAL;
  rpm_sev.sigev_signo = SIGUSR1;
  rpm_sev.sigev_value.sival_int = 0;
  if (timer_create(CLOCK_REALTIME, &rpm_sev, &rpm_timer_id) == -1) {
    fprintf(stderr, "Error creating RPM timer: %s\n", strerror(errno));
    close(rotation_fd);
    gpio_unexport(ROTATION_SENSOR_GPIO);
    gpio_unexport(STALL_LED_GPIO);
    timer_delete(stall_timer_id);
    return 1;
  }

  struct sigaction rpm_sa;
  rpm_sa.sa_handler = calculate_rpm;
sigemptyset(&rpm_sa.sa_mask);
rpm_sa.sa_flags = 0;
if (sigaction(SIGUSR1, &rpm_sa, NULL) == -1) {
    fprintf(stderr, "Error setting signal handler for RPM timer: %s\n", strerror(errno));
    close(rotation_fd);
    gpio_unexport(ROTATION_SENSOR_GPIO);
    gpio_unexport(STALL_LED_GPIO);
    timer_delete(stall_timer_id);
    timer_delete(rpm_timer_id);
    return 1;
}

  struct sigaction stall_sa;
  stall_sa.sa_handler = stall_detection;
sigemptyset(&stall_sa.sa_mask);
stall_sa.sa_flags = 0;
if (sigaction(SIGALRM, &stall_sa, NULL) == -1) {
    fprintf(stderr, "Error setting signal handler for stall timer: %s\n", strerror(errno));
    close(rotation_fd);
    gpio_unexport(ROTATION_SENSOR_GPIO);
    gpio_unexport(STALL_LED_GPIO);
    timer_delete(stall_timer_id);
    timer_delete(rpm_timer_id);
    return 1;
}

  its.it_value.tv_sec = RPM_TIMER_INTERVAL;
  its.it_value.tv_nsec = 0;
  its.it_interval.tv_sec = RPM_TIMER_INTERVAL;
  its.it_interval.tv_nsec = 0;

  if (timer_settime(rpm_timer_id, 0, &its, NULL) == -1) {
    fprintf(stderr, "Error setting RPM timer: %s\n", strerror(errno));
    close(rotation_fd);
    gpio_unexport(ROTATION_SENSOR_GPIO);
    gpio_unexport(STALL_LED_GPIO);
    timer_delete(stall_timer_id);
    timer_delete(rpm_timer_id);
    return 1;
  }

  // Poll setup
  struct pollfd pfd;
  pfd.fd = rotation_fd;
  pfd.events = POLLPRI; // Monitor for high-priority events (interrupts)

  // Initial stall timer setup
  its.it_value.tv_sec = STALL_TIMEOUT;
  its.it_value.tv_nsec = 0;
  its.it_interval.tv_sec = 0; // One-shot timer
  its.it_interval.tv_nsec = 0;

  if (timer_settime(stall_timer_id, 0, &its, NULL) == -1) {
    fprintf(stderr, "Error setting stall timer: %s\n", strerror(errno));
    close(rotation_fd);
    gpio_unexport(ROTATION_SENSOR_GPIO);
    gpio_unexport(STALL_LED_GPIO);
    timer_delete(stall_timer_id);
    timer_delete(rpm_timer_id);
    return 1;
  }

  // Main loop
  while (program_running) {
    // Read the current value to clear the interrupt.  This is necessary for sysfs GPIO interrupts.
    char value_buf[2];
    lseek(rotation_fd, 0, SEEK_SET); // Rewind to the beginning of the file
    if (read(rotation_fd, value_buf, 1) == -1) {
        fprintf(stderr, "Error reading GPIO value: %s\n", strerror(errno));
        break;
    }

    int ret = poll(&pfd, 1, -1); // Wait indefinitely for an interrupt
    if (ret < 0) {
      fprintf(stderr, "Error in poll: %s\n", strerror(errno));
      break;
    } else if (ret > 0) {
      if (pfd.revents & POLLPRI) {
        rotation_count++;

        // Reset stall timer
        its.it_value.tv_sec = STALL_TIMEOUT;
        its.it_value.tv_nsec = 0;
        its.it_interval.tv_sec = 0; // One-shot timer
        its.it_interval.tv_nsec = 0;
        if (timer_settime(stall_timer_id, 0, &its, NULL) == -1) {
          fprintf(stderr, "Error resetting stall timer: %s\n", strerror(errno));
          break;
        }
      }
    }
  }

  // Cleanup
  close(rotation_fd);
  gpio_unexport(ROTATION_SENSOR_GPIO);
  gpio_unexport(STALL_LED_GPIO);
  timer_delete(stall_timer_id);
  timer_delete(rpm_timer_id);
  return 0;
}

