    // Write the header if the file is new (optional)
    fseek(fp, 0, SEEK_END);
    long fsize = ftell(fp);
    if (fsize == 0) {
        fprintf(fp, "Timestamp,SensorValue\n");
    }
    rewind(fp);

    // Main loop to collect and log data
    while (1) {
        // Generate sensor data and timestamp
        sensor_value = generate_sensor_data();
        get_timestamp(timestamp);

        // Write data to the CSV file
        fprintf(fp, "%s,%.2f\n", timestamp, sensor_value);
        fflush(fp); // Ensure data is written to the file immediately

        // Wait for the specified sample period
        bcm2835_delay(SAMPLE_PERIOD_MS);
    }

    // Code will never reach here in normal operation (infinite loop)
    fclose(fp);
    bcm2835_close();

    return 0;
}

