        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(BUZZER_PIN, PI_OUTPUT);

    int delay_ms = 500; // Initial delay
    int min_delay = 50;  // Minimum delay

    while (1) {
        gpioWrite(BUZZER_PIN, 1); // Turn buzzer on
        gpioDelay(delay_ms);
        gpioWrite(BUZZER_PIN, 0); // Turn buzzer off
        gpioDelay(delay_ms);

        delay_ms = delay_ms * 0.9; // Reduce delay by 10% (increase speed)
