#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <fcntl.h>
#include <unistd.h>
#include <errno.h>
#include <time.h>

// Configuration
#define SER_PIN 17   // GPIO pin for Serial Data (SER)
#define SRCLK_PIN 27 // GPIO pin for Shift Register Clock (SRCLK)
#define RCLK_PIN 22  // GPIO pin for Register Clock (RCLK)
#define SCROLL_DELAY_NS 2000000 // Delay between shifts in nanoseconds (2ms)
#define PATTERN_FILE "patterns.txt"

// LED Matrix Dimensions
#define MATRIX_WIDTH 5
#define MATRIX_HEIGHT 7

// Message to display
#define MESSAGE "Hello Pico! "

// Function Prototypes
int gpio_export(int pin);
int gpio_unexport(int pin);
int gpio_set_direction(int pin, const char *direction);
int gpio_set_value(int pin, int value);
void shift_out(unsigned char data);
void latch_data();
void scroll_message();
void delay_ns(long ns);
int save_patterns(const unsigned char *patterns, int num_patterns, const char *filename);
int load_patterns(unsigned char **patterns, int *num_patterns, const char *filename);
void free_patterns(unsigned char *patterns[], int num_patterns);

// Character definitions (5x7) - Constant data
const unsigned char font[][5] = {
    {0x7E, 0x09, 0x09, 0x09, 0x7E}, // H
    {0x7F, 0x24, 0x24, 0x24, 0x18}, // E
    {0x7F, 0x08, 0x04, 0x02, 0x01}, // L
    {0x7F, 0x08, 0x04, 0x08, 0x7F}, // L
    {0x7F, 0x08, 0x14, 0x22, 0x41}, // O
    {0x00, 0x00, 0x00, 0x00, 0x00}, // Space
    {0x3E, 0x63, 0x73, 0x73, 0x3E}, // P
    {0x7F, 0x6B, 0x6B, 0x6B, 0x3A}, // I
    {0x3E, 0x63, 0x73, 0x63, 0x3E}, // C
    {0x7F, 0x60, 0x60, 0x60, 0x7F}, // O
    {0x00, 0x00, 0x00, 0x00, 0x00}  // Space
};

int main() {
    int i;

    // Export GPIO pins
    if (gpio_export(SER_PIN) || gpio_export(SRCLK_PIN) || gpio_export(RCLK_PIN)) {
        fprintf(stderr, "Error exporting GPIO pins. Exiting.\n");
        return 1;
    }

    // Set GPIO pin direction to output
    if (gpio_set_direction(SER_PIN, "out") ||
        gpio_set_direction(SRCLK_PIN, "out") ||
        gpio_set_direction(RCLK_PIN, "out")) {
        fprintf(stderr, "Error setting GPIO direction. Exiting.\n");
        gpio_unexport(SER_PIN);
        gpio_unexport(SRCLK_PIN);
        gpio_unexport(RCLK_PIN);
        return 1;
    }

    // Generate message patterns
    int message_len = strlen(MESSAGE);
    int num_patterns = message_len * MATRIX_WIDTH; // Total number of patterns
    unsigned char *patterns = (unsigned char *)malloc(num_patterns * sizeof(unsigned char));

    if (patterns == NULL) {
        fprintf(stderr, "Memory allocation failed.\n");
        gpio_unexport(SER_PIN);
        gpio_unexport(SRCLK_PIN);
        gpio_unexport(RCLK_PIN);
        return 1;
    }

    int pattern_index = 0;
    for (i = 0; i < message_len; i++) {
        char c = MESSAGE[i];
        int char_index;

        if (c >= 'A' && c <= 'Z') {
            char_index = c - 'A';
        } else if (c >= 'a' && c <= 'z') {
            char_index = c - 'a';
        } else if (c == ' ') {
            char_index = 5; // Space character
        } else {
            char_index = 11; // Default to space
        }

        for (int col = 0; col < MATRIX_WIDTH; col++) {
            patterns[pattern_index++] = font[char_index][col];
        }
    }

    // Save patterns to file
    if (save_patterns(patterns, num_patterns, PATTERN_FILE) != 0) {
        fprintf(stderr, "Error saving patterns to file.\n");
    }

    // Load patterns from file (demonstration)
    unsigned char *loaded_patterns = NULL;
    int loaded_num_patterns = 0;
    if (load_patterns(&loaded_patterns, &loaded_num_patterns, PATTERN_FILE) == 0) {
        printf("Successfully loaded %d patterns from file.\n", loaded_num_patterns);
    } else {
        fprintf(stderr, "Error loading patterns from file. Using generated patterns.\n");
        loaded_patterns = patterns;
        loaded_num_patterns = num_patterns;
    }


    // Main loop - scrolling the message
    while (1) {
        for (int k = 0; k < loaded_num_patterns; k++) {
            shift_out(loaded_patterns[k]);
            latch_data();
            delay_ns(SCROLL_DELAY_NS);
        }
    }

    // Cleanup (this part will likely never be reached in an infinite loop)
    if (loaded_patterns != patterns && loaded_patterns != NULL) {
        free(loaded_patterns);
    }
    free(patterns);
    gpio_unexport(SER_PIN);
    gpio_unexport(SRCLK_PIN);
    gpio_unexport(RCLK_PIN);

    return 0;
}

// Function to export a GPIO pin
int gpio_export(int pin) {
    char buffer[64];
    int fd;

    fd = open("/sys/class/gpio/export", O_WRONLY);
    if (fd < 0) {
        perror("gpio/export");
        return 1;
    }
    sprintf(buffer, "%d", pin);
    if (write(fd, buffer, strlen(buffer)) < 0) {
        perror("gpio/export");
        close(fd);
        return 1;
    }
    close(fd);
    return 0;
}

// Function to unexport a GPIO pin
int gpio_unexport(int pin) {
    char buffer[64];
    int fd;

    fd = open("/sys/class/gpio/unexport", O_WRONLY);
    if (fd < 0) {
        perror("gpio/unexport");
        return 1;
    }
    sprintf(buffer, "%d", pin);
    if (write(fd, buffer, strlen(buffer)) < 0) {
        perror("gpio/unexport");
        close(fd);
        return 1;
    }
    close(fd);
    return 0;
}

// Function to set the direction of a GPIO pin (in or out)
int gpio_set_direction(int pin, const char *direction) {
    char buffer[64];
    int fd;

    sprintf(buffer, "/sys/class/gpio/gpio%d/direction", pin);
    fd = open(buffer, O_WRONLY);
    if (fd < 0) {
        perror("gpio/direction");
        return 1;
    }
    if (write(fd, direction, strlen(direction)) < 0) {
        perror("gpio/direction");
        close(fd);
        return 1;
    }
    close(fd);
    return 0;
}

// Function to set the value of a GPIO pin (0 or 1)
int gpio_set_value(int pin, int value) {
    char buffer[64];
    int fd;

    sprintf(buffer, "/sys/class/gpio/gpio%d/value", pin);
    fd = open(buffer, O_WRONLY);
    if (fd < 0) {
        perror("gpio/value");
        return 1;
    }

    char val_str[2];
    sprintf(val_str, "%d", value);

    if (write(fd, val_str, strlen(val_str)) < 0) {
        perror("gpio/value");
        close(fd);
        return 1;
    }
    close(fd);
    return 0;
}

// Function to shift out a byte of data to the shift register
void shift_out(unsigned char data) {
    for (int i = 0; i < 8; i++) {
        // Set the SER pin based on the current bit
        gpio_set_value(SER_PIN, (data >> (7 - i)) & 0x01);

        // Pulse the SRCLK pin
        gpio_set_value(SRCLK_PIN, 1);
        gpio_set_value(SRCLK_PIN, 0);
    }
}

// Function to latch the data to the output registers
void latch_data() {
    gpio_set_value(RCLK_PIN, 1);
    gpio_set_value(RCLK_PIN, 0);
}

// Function to introduce a delay in nanoseconds
void delay_ns(long ns) {
    struct timespec req;
    req.tv_sec = 0;
    req.tv_nsec = ns;
    nanosleep(&req, NULL);
}

// Function to save LED patterns to a file
int save_patterns(const unsigned char *patterns, int num_patterns, const char *filename) {
    FILE *fp = fopen(filename, "w");
    if (fp == NULL) {
        perror("Error opening pattern file for writing");
        return -1;
    }

    for (int i = 0; i < num_patterns; i++) {
        fprintf(fp, "%u\n", patterns[i]);
    }

    fclose(fp);
    return 0;
}

// Function to load LED patterns from a file
int load_patterns(unsigned char **patterns, int *num_patterns, const char *filename) {
    FILE *fp = fopen(filename, "r");
    if (fp == NULL) {
        perror("Error opening pattern file for reading");
        return -1;
    }

    // Determine the number of patterns in the file
    int count = 0;
    char line[10]; // Assuming each line contains a number < 256
    while (fgets(line, sizeof(line), fp) != NULL) {
        count++;
    }

    // Allocate memory for the patterns
    *patterns = (unsigned char *)malloc(count * sizeof(unsigned char));
    if (*patterns == NULL) {
        fprintf(stderr, "Memory allocation failed.\n");
        fclose(fp);
        return -1;
    }

    // Reset file pointer to the beginning
    fseek(fp, 0, SEEK_SET);

    // Read the patterns from the file
    for (int i = 0; i < count; i++) {
        unsigned int value;
        if (fscanf(fp, "%u", &value) != 1) {
            fprintf(stderr, "Error reading pattern from file.\n");
            free(*patterns);
            *patterns = NULL;
            *num_patterns = 0;
            fclose(fp);
            return -1;
        }
        (*patterns)[i] = (unsigned char)value;
    }

    fclose(fp);
    *num_patterns = count;
    return 0;
}

// Function to free dynamically allocated pattern arrays
void free_patterns(unsigned char *patterns[], int num_patterns) {
    for (int i = 0; i < num_patterns; i++) {
        if (patterns[i] != NULL) {
            free(patterns[i]);
        }
    }
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <unistd.h>
#include <fcntl.h>
#include <termios.h>

#define SERIAL_PORT "/dev/ttyAMA0"
#define BAUD_RATE B115200

int main() {
    int serial_fd;
    struct termios serial_options;

    // Open the serial port
    serial_fd = open(SERIAL_PORT, O_RDWR | O_NOCTTY | O_NDELAY);
    if (serial_fd == -1) {
        fprintf(stderr, "Error opening serial port %s: %s\n", SERIAL_PORT, strerror(errno));
        return EXIT_FAILURE;
    }

    // Get the current serial port options
    if (tcgetattr(serial_fd, &serial_options) != 0) {
        fprintf(stderr, "Error getting serial port options: %s\n", strerror(errno));
        close(serial_fd);
        return EXIT_FAILURE;
    }

    // Set the baud rate
    cfsetispeed(&serial_options, BAUD_RATE);
    cfsetospeed(&serial_options, BAUD_RATE);

    // Configure the serial port
    serial_options.c_cflag &= ~PARENB; // No parity
    serial_options.c_cflag &= ~CSTOPB; // 1 stop bit
    serial_options.c_cflag &= ~CSIZE;  // Clear size bits
    serial_options.c_cflag |= CS8;   // 8 data bits
    serial_options.c_cflag &= ~CRTSCTS; // Disable hardware flow control
    serial_options.c_cflag |= CREAD | CLOCAL; // Enable read and ignore control lines

    serial_options.c_iflag &= ~(IXON | IXOFF | IXANY); // Disable software flow control
    serial_options.c_iflag &= ~(IGNBRK | BRKINT | PARMRK | ISTRIP | INLCR | IGNCR | ICRNL); //Disable special handling of received bytes

    serial_options.c_oflag &= ~OPOST; //Raw output

    serial_options.c_lflag &= ~ICANON; // Disable canonical mode
    serial_options.c_lflag &= ~ECHO;   // Disable echo
    serial_options.c_lflag &= ~ECHOE;  // Disable erasure
    serial_options.c_lflag &= ~ECHONL; // Disable new-line echo
    serial_options.c_lflag &= ~ISIG;   // Disable interpretation of INTR, QUIT and SUSP

    serial_options.c_cc[VMIN] = 0;  // Read at least 0 characters
    serial_options.c_cc[VTIME] = 10; // Wait for up to 1 second (10 deciseconds)

    // Apply the serial port options
    if (tcsetattr(serial_fd, TCSANOW, &serial_options) != 0) {
        fprintf(stderr, "Error setting serial port options: %s\n", strerror(errno));
        close(serial_fd);
        return EXIT_FAILURE;
    }

    // Main loop: read and print data
    unsigned char read_buffer[256];
    ssize_t bytes_read;

    while (1) {
        bytes_read = read(serial_fd, read_buffer, sizeof(read_buffer));
        if (bytes_read > 0) {
            // Print the received data
            for (ssize_t i = 0; i < bytes_read; ++i) {
                putchar(read_buffer[i]);
            }
            fflush(stdout); // Flush the output buffer
        } else if (bytes_read < 0) {
            fprintf(stderr, "Error reading from serial port: %s\n", strerror(errno));
            break; // Exit the loop on error
        } else {
            //No data received, sleep to avoid busy-waiting
            usleep(10000); // Sleep for 10ms
        }
    }

    // Close the serial port
    close(serial_fd);

    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <fcntl.h>
#include <unistd.h>
#include <poll.h>
#include <signal.h>
#include <time.h>
#include <errno.h>

#define GPIO_PIN 17
#define POLL_TIMEOUT 10 // milliseconds

volatile sig_atomic_t program_running = 1;
static int tilt_count = 0;

// Function to handle signals (e.g., Ctrl+C)
void signal_handler(int sig) {
    if (sig == SIGINT) {
        program_running = 0;
        fprintf(stderr, "\nCaught SIGINT, exiting gracefully.\n");
    }
}

// Function to generate a timestamp string
int generate_timestamp(char *timestamp, size_t timestamp_size) {
    time_t rawtime;
    struct tm *timeinfo;

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    if (timeinfo == NULL) {
        fprintf(stderr, "Error: localtime failed in generate_timestamp: %s\n", strerror(errno));
        return -1;
    }

    if (strftime(timestamp, timestamp_size, "%Y-%m-%d %H:%M:%S", timeinfo) == 0) {
        fprintf(stderr, "Error: strftime failed in generate_timestamp\n");
        return -1;
    }

    return 0;
}

// Function to log tilt events to a file
int log_tilt_event() {
    FILE *fp;
    char timestamp[20];

    if (generate_timestamp(timestamp, sizeof(timestamp)) != 0) {
        fprintf(stderr, "Error: Failed to generate timestamp in log_tilt_event\n");
        return -1;
    }

    fp = fopen("tilt_log.txt", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error: Failed to open tilt_log.txt for writing in log_tilt_event: %s\n", strerror(errno));
        return -1;
    }

    fprintf(fp, "%s Tilt Count: %d\n", timestamp, tilt_count);
    if (ferror(fp)) {
        fprintf(stderr, "Error: Failed to write to tilt_log.txt in log_tilt_event\n");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return 0;
}

// Function to initialize GPIO as input
int initialize_gpio() {
    int fd, ret;
    char buffer[64];

    // Export GPIO
    fd = open("/sys/class/gpio/export", O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Error: Failed to open GPIO export for writing in initialize_gpio: %s\n", strerror(errno));
        return -1;
    }
    snprintf(buffer, sizeof(buffer), "%d", GPIO_PIN);
    ret = write(fd, buffer, strlen(buffer));
    if (ret < 0) {
        fprintf(stderr, "Error: Failed to write GPIO pin to export in initialize_gpio: %s\n", strerror(errno));
        close(fd);
        return -1;
    }
    close(fd);

    // Set GPIO direction to input
    snprintf(buffer, sizeof(buffer), "/sys/class/gpio/gpio%d/direction", GPIO_PIN);
    fd = open(buffer, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Error: Failed to open GPIO direction for writing in initialize_gpio: %s\n", strerror(errno));
        return -1;
    }
    ret = write(fd, "in", 2);
    if (ret < 0) {
        fprintf(stderr, "Error: Failed to write 'in' to GPIO direction in initialize_gpio: %s\n", strerror(errno));
        close(fd);
        return -1;
    }
    close(fd);

    return 0;
}

// Function to unexport GPIO
int unexport_gpio() {
    int fd, ret;
    char buffer[64];

    fd = open("/sys/class/gpio/unexport", O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Error: Failed to open GPIO unexport for writing in unexport_gpio: %s\n", strerror(errno));
        return -1;
    }
    snprintf(buffer, sizeof(buffer), "%d", GPIO_PIN);
    ret = write(fd, buffer, strlen(buffer));
    if (ret < 0) {
        fprintf(stderr, "Error: Failed to write GPIO pin to unexport in unexport_gpio: %s\n", strerror(errno));
        close(fd);
        return -1;
    }
    close(fd);

    return 0;
}

int main() {
    int fd, ret;
    char buffer[64];
    struct pollfd pfd;

    // Install signal handler
    signal(SIGINT, signal_handler);

    // Initialize GPIO
    if (initialize_gpio() != 0) {
        fprintf(stderr, "Error: GPIO initialization failed.\n");
        return 1;
    }

    // Open GPIO value file for reading
    snprintf(buffer, sizeof(buffer), "/sys/class/gpio/gpio%d/value", GPIO_PIN);
    fd = open(buffer, O_RDONLY);
    if (fd < 0) {
        fprintf(stderr, "Error: Failed to open GPIO value file for reading: %s\n", strerror(errno));
        unexport_gpio();
        return 1;
    }

    pfd.fd = fd;
    pfd.events = POLLPRI; // Monitor for high-priority events (rising/falling edges)

    // Consume initial value
    ret = read(fd, buffer, sizeof(buffer));
    if (ret < 0) {
      fprintf(stderr, "Error: Initial read failed: %s\n", strerror(errno));
      close(fd);
      unexport_gpio();
      return 1;
    }

    // Main event loop
    printf("Tilt detection started. Press Ctrl+C to exit.\n");
    while (program_running) {
        // Poll for changes in GPIO value
        ret = poll(&pfd, 1, POLL_TIMEOUT);

        if (ret < 0) {
            fprintf(stderr, "Error: Poll failed: %s\n", strerror(errno));
            break;
        } else if (ret > 0) {
            // A rising edge (tilt event) is detected
            if (pfd.revents & POLLPRI) {
                // Increment tilt counter
                tilt_count++;

                // Log the event
                if (log_tilt_event() != 0) {
                    fprintf(stderr, "Error: Failed to log tilt event.\n");
                }

                // Consume the interrupt by reading the value file
                lseek(fd, 0, SEEK_SET); // Rewind to the beginning of the file
                ret = read(fd, buffer, sizeof(buffer));
                if (ret < 0) {
                  fprintf(stderr, "Error: Read after poll failed: %s\n", strerror(errno));
                  break;
                }
            }
        }
    }

    // Clean up
    close(fd);
    unexport_gpio();

    printf("Tilt detection stopped. Total tilt count: %d\n", tilt_count);
    return 0;
}

#include <stdio.h>
#include <wiringPi.h>
#include <softPwm.h>

#define BUTTON_PIN 27 // BCM GPIO 27
#define LED_PIN 18    // PWM capable pin, using WiringPi pin 1 (BCM GPIO 18)

int main(void) {
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi setup failed!\n");
        return 1;
    }

    pinMode(BUTTON_PIN, INPUT);
    pinMode(LED_PIN, OUTPUT);

    softPwmCreate(LED_PIN, 0, 100); // Initialize PWM on LED_PIN, range 0-100

    int brightness = 0;

    while (1) {
        if (digitalRead(BUTTON_PIN) == HIGH) { // Button Pressed
            if (brightness < 100) {
                brightness++;
                softPwmWrite(LED_PIN, brightness);
                delay(10); // Debounce and PWM update rate
            }
        } else { // Button Released
            if (brightness > 0) {
                brightness--;
                softPwmWrite(LED_PIN, brightness);
                delay(10); // Debounce and PWM update rate
            }
        }
    }

    return 0;
}

