#include <wiringPi.h>

#define SERVO_PIN 3
#define BUTTON_PIN 5

#define UNLOCKED_POSITION 2000 // Adjust these values based on your servo
#define LOCKED_POSITION 1000    // and door lock mechanism

int main(void) {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi setup failed!\n");
        return 1;
    }

    pinMode(SERVO_PIN, PWM_OUTPUT);
    pwmSetMode(PWM_MODE_MS);
    pwmSetRange(2000);
    pwmSetClock(192); // Adjust this value to fine-tune servo movement. Try 192 first.

    pinMode(BUTTON_PIN, INPUT);
    pullUpDnControl(BUTTON_PIN, PUD_UP); // Enable internal pull-up resistor

    printf("Door lock control. Press the button to unlock, release to lock.\n");

    while (1) {
        if (digitalRead(BUTTON_PIN) == LOW) { // Button is pressed (LOW due to pull-up)
            pwmWrite(SERVO_PIN, UNLOCKED_POSITION);
            delay(10);
        } else {
            pwmWrite(SERVO_PIN, LOCKED_POSITION);
            delay(10);
        }
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>
#include <math.h>

// BMP280 I2C address
#define BMP280_I2C_ADDR 0x76

// BMP280 registers
#define BMP280_REG_TEMP_MSB 0xFA
#define BMP280_REG_TEMP_LSB 0xFB
#define BMP280_REG_TEMP_XLSB 0xFC
#define BMP280_REG_PRESS_MSB 0xF7
#define BMP280_REG_PRESS_LSB 0xF8
#define BMP280_REG_PRESS_XLSB 0xF9
#define BMP280_REG_CTRL_MEAS 0xF4
#define BMP280_REG_CONFIG 0xF5

// Fan GPIO pin
#define FAN_GPIO 18

// Temperature threshold (in Celsius)
#define TEMPERATURE_THRESHOLD 30.0

// PWM frequency (in Hz)
#define PWM_FREQUENCY 1000

// Log file path
#define LOG_FILE "/var/log/temperature_monitor.log"

// Global variables
int i2c_handle;
FILE *log_file;
volatile sig_atomic_t terminate = 0;

// Function prototypes
double read_temperature();
void control_fan(double temperature);
void log_data(double temperature, int duty_cycle);
void signal_handler(int signal);
int bmp280_init();

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    fprintf(log_file, "%s","Signal caught, exiting...\n");
    terminate = 1;
}

// Initialize the BMP280 sensor
int bmp280_init() {
    // Set oversampling and mode (temperature only for simplicity)
    char ctrl_meas = 0b00100111; // Oversampling x1, Normal mode
    char config = 0b00000000;     // Filter off, no standby

    if (i2cWriteByteData(i2c_handle, BMP280_REG_CTRL_MEAS, ctrl_meas) != 0) {
        fprintf(log_file, "%s","Error writing to CTRL_MEAS register\n");
        return -1;
    }

    if (i2cWriteByteData(i2c_handle, BMP280_REG_CONFIG, config) != 0) {
        fprintf(log_file, "%s","Error writing to CONFIG register\n");
        return -1;
    }

    return 0;
}

// Read temperature from the BMP280 sensor
double read_temperature() {
    unsigned char data[3];
    int raw_temperature;
    double temperature;
    int retries = 5; // Number of retries
    int delay_ms = 10; // Initial delay in milliseconds

    while (retries > 0) {
        if (i2cReadI2CBlockData(i2c_handle, BMP280_REG_TEMP_MSB, (char *)data, 3) == 3) {
            raw_temperature = (data[0] << 12) | (data[1] << 4) | (data[2] >> 4);
            // Simplified conversion (calibration data is needed for accurate readings)
            temperature = (double)raw_temperature / 100.0; 
            return temperature;
        } else {
            fprintf(log_file, "%s","Error reading temperature data, retrying...\n");
            gpioDelay(delay_ms * 1000); // Delay in microseconds
            delay_ms *= 2; // Exponential backoff
            retries--;
        }
    }

    fprintf(log_file, "%s","Failed to read temperature after multiple retries\n");
    return -999.0; // Indicate error
}

// Control the fan speed based on temperature
void control_fan(double temperature) {
    int duty_cycle = 0;

    if (temperature > TEMPERATURE_THRESHOLD) {
        duty_cycle = (int)(((temperature - TEMPERATURE_THRESHOLD) / 10.0) * 100.0);
        if (duty_cycle > 100) {
            duty_cycle = 100;
        }
        if (duty_cycle < 0){
            duty_cycle = 0;
        }
    }

    gpioPWM(FAN_GPIO, duty_cycle);
}

// Log temperature and fan duty cycle to a file
void log_data(double temperature, int duty_cycle) {
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[30];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", t);

    fprintf(log_file, "%s, Temperature: %.2f °C, Fan Duty Cycle: %d%%\n", timestamp, temperature, duty_cycle);
    fflush(log_file); // Ensure data is written to disk immediately
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "%s","pigpio initialisation failed\n");
        return 1;
    }

    // Open log file
    log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        gpioTerminate();
        return 1;
    }

    // Open I2C bus
    i2c_handle = i2cOpen(1, BMP280_I2C_ADDR, 0); // Bus 1, address 0x76, no flags
    if (i2c_handle < 0) {
        fprintf(log_file, "%s","Error opening I2C bus\n");
        fclose(log_file);
        gpioTerminate();
        return 1;
    }

    // Initialize BMP280 sensor
    if (bmp280_init() != 0) {
        fprintf(log_file, "%s","BMP280 initialization failed\n");
        i2cClose(i2c_handle);
        fclose(log_file);
        gpioTerminate();
        return 1;
    }

    // Set FAN_GPIO as output and set PWM frequency
    gpioSetMode(FAN_GPIO, PI_OUTPUT);
    gpioSetPWMfrequency(FAN_GPIO, PWM_FREQUENCY);

    // Register signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    fprintf(log_file, "%s","Temperature monitoring started...\n");

    // Main loop
    while (!terminate) {
        double temperature = read_temperature();

        if (temperature != -999.0) {
            control_fan(temperature);
            int duty_cycle = gpioGetPWMdutycycle(FAN_GPIO);
            log_data(temperature, duty_cycle);
        }

        gpioDelay(5000000); // Wait 5 seconds (5000000 microseconds)
    }

    // Clean up
    gpioPWM(FAN_GPIO, 0); // Stop the fan
    i2cClose(i2c_handle);
    fclose(log_file);
    gpioTerminate();

    fprintf(stdout, "%s","Temperature monitoring stopped.\n");

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
