// Define musical notes (frequencies in Hz)
#define NOTE_DO   262
#define NOTE_RE   294
#define NOTE_MI   330
#define NOTE_FA   349
#define NOTE_SOL  392
#define NOTE_LA   440
#define NOTE_SI   494
#define NOTE_DO_H 523
#define NOTE_RE_H 587
#define NOTE_MI_H 659
#define NOTE_FA_H 698
#define NOTE_SOL_H 784
#define NOTE_LA_H 880
#define NOTE_SI_H 988

// Define the GPIO pin connected to the buzzer
#define BUZZER_PIN 1  // BCM GPIO 18, WiringPi pin 1

// Melody definition
const int melody[] = {
    NOTE_SOL, NOTE_SOL, NOTE_LA, NOTE_SOL, NOTE_DO_H, NOTE_SI,
    NOTE_SOL, NOTE_SOL, NOTE_LA, NOTE_SOL, NOTE_RE_H, NOTE_DO_H,
    NOTE_SOL, NOTE_SOL, NOTE_SOL_H, NOTE_MI_H, NOTE_DO_H, NOTE_SI, NOTE_LA,
    NOTE_FA_H, NOTE_FA_H, NOTE_MI_H, NOTE_DO_H, NOTE_RE_H, NOTE_DO_H
};

// Duration of each note (relative to a base duration)
const float durations[] = {
    0.5, 0.5, 1, 1, 1, 2,
    0.5, 0.5, 1, 1, 1, 2,
    0.5, 0.5, 1, 1, 1, 1, 1,
    0.5, 0.5, 1, 1, 1, 2
};

const int melody_length = sizeof(melody) / sizeof(melody[0]);

// Function to initialize the buzzer pin
int initialize_buzzer() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return -1;
    }

    pinMode(BUZZER_PIN, PWM_OUTPUT);
    pwmSetMode(PWM_MODE_MS);
    pwmSetClock(32); // Adjust for desired frequency range

    return 0;
}

// Function to play a tone on the buzzer
void play_tone(int frequency, int duration_ms) {
    if (frequency < 50 || frequency > 5000) { // Reasonable frequency range
        fprintf(stderr, "Invalid frequency: %d Hz.  Skipping tone.\n", frequency);
        return;
    }

    int range = 600000 / frequency; // Calculate PWM range
    pwmSetRange(range);
    pwmWrite(BUZZER_PIN, range / 2); // 50% duty cycle
    delay(duration_ms);
    pwmWrite(BUZZER_PIN, 0); // Stop the tone
}

int main() {
    if (initialize_buzzer() != 0) {
        fprintf(stderr, "Buzzer initialization failed. Exiting.\n");
        return 1;
    }

    printf("Playing melody...\n");

    while (1) {
        for (int i = 0; i < melody_length; ++i) {
            play_tone(melody[i], (int)(500 * durations[i]));
        }
        delay(2000); // Pause between repetitions
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pigpio.h>
#include <unistd.h>

// Define GPIO pins for HC-SR04
#define TRIGGER_PIN 17
#define ECHO_PIN 18

// Define GPIO pin for PWM audio output
#define PWM_PIN 12

// Define frequency range for audio output (Hz)
#define MIN_FREQUENCY 200
#define MAX_FREQUENCY 2000

// Define maximum measurable distance (cm)
#define MAX_DISTANCE 100

// Function prototypes
float getDistance();
int mapDistanceToFrequency(float distance);
void cleanup();
void die(char *message);
void signal_handler(int signal);

// Global variable for program termination
volatile sig_atomic_t program_running = 1;

// Error handling function
void die(char *message) {
    fprintf(stderr, "Error: %s\n", message);
    cleanup();
    exit(1);
}

// Cleanup function to release resources
void cleanup() {
    // Stop PWM signal
    gpioPWM(PWM_PIN, 0);

    // Release GPIO pins
    gpioSetMode(TRIGGER_PIN, PI_INPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);
    gpioSetMode(PWM_PIN, PI_INPUT);

    // Terminate pigpio library
    gpioTerminate();

    printf("Cleanup complete. Exiting.\n");
}

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    printf("Caught signal %d\n", signal);
    program_running = 0;
}

// Function to measure distance using HC-SR04
float getDistance() {
    long long start, end;
    float distance;

    // Trigger the sensor
    gpioWrite(TRIGGER_PIN, 1);
    gpioDelay(0.01); // 10us trigger pulse
    gpioWrite(TRIGGER_PIN, 0);

    // Measure the pulse width of the echo signal
    while (gpioRead(ECHO_PIN) == 0 && program_running) {
       start = gpioTick();
    }
    if (!program_running) return -1.0; // Exit if signal received

    while (gpioRead(ECHO_PIN) == 1 && program_running) {
        end = gpioTick();
    }
    if (!program_running) return -1.0; // Exit if signal received

    // Calculate the pulse width in microseconds
    float pulse_width = (float)(end - start) / 1000.0; // Convert ticks to milliseconds, then to microseconds

    // Calculate the distance in centimeters (speed of sound: 343 m/s)
    // distance = (pulse_width / 1000000.0) * 34300.0 / 2.0; // original formula
    distance = pulse_width * 0.0343 / 2.0; // Simplified formula

    // Handle potential errors in distance readings
    if (distance < 0 || distance > MAX_DISTANCE) {
        return -1.0; // Return -1 for invalid readings
    }

    return distance;
}

// Function to map distance to frequency
int mapDistanceToFrequency(float distance) {
    // Handle cases where the distance reading is invalid
    if (distance < 0) {
        return MIN_FREQUENCY; // Default to minimum frequency
    }

    // Linearly scale the distance to the desired frequency range
    float frequency = MIN_FREQUENCY + (distance / MAX_DISTANCE) * (MAX_FREQUENCY - MIN_FREQUENCY);

    // Ensure the frequency is within the valid range
    if (frequency < MIN_FREQUENCY) {
        return MIN_FREQUENCY;
    } else if (frequency > MAX_FREQUENCY) {
        return MAX_FREQUENCY;
    }

    return (int)frequency;
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        die("pigpio initialisation failed");
    }

    // Set GPIO pin modes
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);
    gpioSetMode(PWM_PIN, PI_OUTPUT);

    // Set PWM frequency
    gpioSetPWMfrequency(PWM_PIN, 1000); // Set PWM frequency to 1 kHz
    gpioSetPWMrange(PWM_PIN, 1000); // Set PWM range to 1000

    // Register cleanup function to be called on program termination
    atexit(cleanup);

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Wearable Theremin started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        // Read distance from HC-SR04 sensor
        float distance = getDistance();

        // Map distance to frequency
        int frequency = mapDistanceToFrequency(distance);

        // Set PWM frequency
        gpioSetPWMfrequency(PWM_PIN, frequency);

        // Generate PWM signal (duty cycle = 50%)
        gpioPWM(PWM_PIN, 500); // 50% duty cycle

        // Introduce a small delay
        gpioDelay(10); // 10ms delay
    }

    return 0;
}

