#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <errno.h>

// Define GPIO pins using WiringPi numbering
#define BUTTON_PIN  0  // GPIO 17 (WiringPi pin 0)
#define LED1_PIN    1  // GPIO 18 (WiringPi pin 1)
#define LED2_PIN    7  // GPIO 4  (WiringPi pin 7)

// Function prototypes
int initializeGPIO(void);
void buttonLedControl(void);

int main(void) {
    // Initialize WiringPi and GPIO pins
    if (initializeGPIO() != 0) {
        fprintf(stderr, "GPIO initialization failed. Exiting.\n");
        return 1;
    }

    printf("Raspberry Pi - Button & LED Control\n");

    // Main loop to monitor button and control LEDs
    buttonLedControl();

    return 0;
}

// Function to initialize GPIO pins
int initializeGPIO(void) {
    // Initialize WiringPi using WiringPi numbering
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return -1; // Indicate failure
    }

    // Set pin modes
    pinMode(BUTTON_PIN, INPUT);
    pinMode(LED1_PIN, OUTPUT);
    pinMode(LED2_PIN, OUTPUT);

    // Initial LED states
    digitalWrite(LED1_PIN, HIGH); // LED1 on
    digitalWrite(LED2_PIN, LOW);  // LED2 off

    return 0; // Indicate success
}

// Function to monitor button and control LEDs
void buttonLedControl(void) {
    while (1) {
        // Check if the button is pressed (HIGH)
        if (digitalRead(BUTTON_PIN) == HIGH) {
            // Button is pressed, swap LED states
            digitalWrite(LED1_PIN, LOW);
            digitalWrite(LED2_PIN, HIGH);

            // Debounce the button by waiting until it's released
            while (digitalRead(BUTTON_PIN) == HIGH) {
                delay(1); // Small delay to avoid busy-waiting
            }

            // Swap LED states back
            digitalWrite(LED1_PIN, HIGH);
            digitalWrite(LED2_PIN, LOW);
        }

        delay(1); // Small delay to reduce CPU usage
    }
}

#include <wiringPi.h>
#include <stdio.h>
#include <time.h>
#define BUZZER 18
#define BUTTON 23
#define FREQUENCY 1500

int main() {
    if (wiringPiSetupGpio() == -1) return 1;
    pinMode(BUZZER, PWM_OUTPUT);
    pinMode(BUTTON, INPUT);
    pullUpDnControl(BUTTON, PUD_UP);
    pwmSetMode(PWM_MODE_MS);
    pwmSetClock(32);
    pwmSetRange(600000 / FREQUENCY);

    int pressCount = 0;
    clock_t startTime = 0;

    while (1) {
        if (digitalRead(BUTTON) == 0) {
            if (pressCount == 0) {
                startTime = clock();
            }
            pressCount++;
            delay(300);
        }

        if (pressCount == 2) {
            clock_t endTime = clock();
            double elapsedTime = ((double)(endTime - startTime)) / CLOCKS_PER_SEC;
            if (elapsedTime < 1) {
                pwmWrite(BUZZER, 300);
                printf("Alarm ON\n");
                delay(2000);
                pwmWrite(BUZZER, 0);
            }
            pressCount = 0;
        }
    }
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <errno.h>

// Define GPIO pins for motor control
#define MOTOR_PIN_1   0  // GPIO pin connected to Motor Pin 1
#define MOTOR_PIN_2   2  // GPIO pin connected to Motor Pin 2
#define MOTOR_ENABLE  3  // GPIO pin connected to Motor Enable

// Function prototypes
int motor_init(void);
void motor_clockwise(void);
void motor_anticlockwise(void);
void motor_stop(void);
void safe_delay(unsigned int milliseconds);

int main(void) {
    // Initialize WiringPi and motor control pins
    if (motor_init() != 0) {
        fprintf(stderr, "Motor initialization failed. Exiting.\n");
        return EXIT_FAILURE; // Exit if initialization fails
    }

    printf("Motor control program started.\n");

    // Main loop to control motor direction and state
    while (1) {
        printf("Clockwise...\n");
        safe_delay(100); // Small delay for stability
        motor_clockwise();
        safe_delay(3000); // Run clockwise for 3 seconds

        printf("Stop...\n");
        safe_delay(100); // Small delay for stability
        motor_stop();
        safe_delay(3000); // Stop for 3 seconds

        printf("Anti-clockwise...\n");
        safe_delay(100); // Small delay for stability
        motor_anticlockwise();
        safe_delay(3000); // Run anti-clockwise for 3 seconds

        printf("Stop...\n");
        safe_delay(100); // Small delay for stability
        motor_stop();
        safe_delay(3000); // Stop for 3 seconds
    }

    return EXIT_SUCCESS; // Program should not reach here in normal execution
}

// Initializes WiringPi and configures motor control pins.
int motor_init(void) {
    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi setup failed: %s\n", strerror(errno));
        return -1; // Indicate failure
    }

    // Configure motor control pins as output
    pinMode(MOTOR_PIN_1, OUTPUT);
    pinMode(MOTOR_PIN_2, OUTPUT);
    pinMode(MOTOR_ENABLE, OUTPUT);

    // Ensure motor is initially stopped
    motor_stop();

    printf("Motor initialized successfully.\n");
    return 0; // Indicate success
}

// Sets the motor to rotate in the clockwise direction.
void motor_clockwise(void) {
    digitalWrite(MOTOR_ENABLE, HIGH); // Enable the motor
    digitalWrite(MOTOR_PIN_1, HIGH);  // Set Pin 1 High
    digitalWrite(MOTOR_PIN_2, LOW);   // Set Pin 2 Low
    printf("Motor rotating clockwise.\n");
}

// Sets the motor to rotate in the anti-clockwise direction.
void motor_anticlockwise(void) {
    digitalWrite(MOTOR_ENABLE, HIGH); // Enable the motor
    digitalWrite(MOTOR_PIN_1, LOW);   // Set Pin 1 Low
    digitalWrite(MOTOR_PIN_2, HIGH);  // Set Pin 2 High
    printf("Motor rotating anti-clockwise.\n");
}

// Stops the motor.
void motor_stop(void) {
    digitalWrite(MOTOR_ENABLE, LOW); // Disable the motor
    printf("Motor stopped.\n");
}

// A safer delay function using nanosleep to avoid blocking signals
void safe_delay(unsigned int milliseconds) {
    delay(milliseconds);
}

#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <string.h>
#include <signal.h>
#include <pigpio.h>

// Define GPIO pins
#define DT_PIN 2
#define SCK_PIN 3
#define LOCK_PIN 4

// Threshold weight in kg
#define WEIGHT_THRESHOLD 5.0

// Calibration weight in kg
#define CALIBRATION_WEIGHT 1.0

// Global variables
double scale_factor = 0.0; // Scale factor for converting raw data to kg

// Function prototypes
int read_hx711();
void calibrate_hx711(double known_weight);
double convert_to_kg(int raw_value);
int is_above_threshold(double weight);
void activate_lock();
void log_event(double weight);
void signal_handler(int signal);

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    fprintf(stderr, "\nCaught signal %d, cleaning up...\n", signal);
    gpioWrite(LOCK_PIN, 0); // Ensure lock is disengaged
    gpioTerminate();        // Terminate pigpio
    exit(0);
}

// Reads data from the HX711 load cell amplifier
int read_hx711() {
    int data = 0;
    int i;

    gpioSetMode(DT_PIN, PI_INPUT);
    gpioSetMode(SCK_PIN, PI_OUTPUT);

    // Wait for DT_PIN to go low
    int retry_count = 0;
    while (gpioRead(DT_PIN)) {
        gpioDelay(1); // Short delay
        retry_count++;
        if (retry_count > 1000) {
            fprintf(stderr, "Error: DT_PIN did not go low after 1000ms\n");
            return -1; // Indicate error
        }
    }

    // Read 24 bits of data
    for (i = 0; i < 24; i++) {
        gpioWrite(SCK_PIN, 1);
        gpioDelay(1); // Short delay
        data = data << 1;
        if (gpioRead(DT_PIN)) {
            data++;
        }
        gpioWrite(SCK_PIN, 0);
        gpioDelay(1); // Short delay
    }

    // Pulse SCK 25th time to set gain to 128
    gpioWrite(SCK_PIN, 1);
    gpioDelay(1); // Short delay
    gpioWrite(SCK_PIN, 0);
    gpioDelay(1); // Short delay

    // Convert 24 bit two's complement to 32 bit signed integer
    if (data & 0x800000) {
        data |= 0xFF000000;
    }

    return data;
}

// Calibrates the HX711 with a known weight
void calibrate_hx711(double known_weight) {
    int raw_value = 0;
    int sum = 0;
    int num_readings = 10; // Number of readings to average

    printf("Calibrating with a known weight of %.2f kg...\n", known_weight);

    // Take multiple readings and average them
    for (int i = 0; i < num_readings; i++) {
        int reading = read_hx711();
        if (reading == -1) {
            fprintf(stderr, "Error reading HX711 during calibration, attempt %d\n", i + 1);
            return; // Exit calibration if reading fails
        }
        sum += reading;
        gpioDelay(50); // Small delay between readings
    }
    raw_value = sum / num_readings;

    scale_factor = known_weight / (double)raw_value;

    printf("Calibration complete. Scale factor: %.6f\n", scale_factor);
}

// Converts the raw HX711 reading to weight in kilograms
double convert_to_kg(int raw_value) {
    return (double)raw_value * scale_factor;
}

// Checks if the weight is above the defined threshold
int is_above_threshold(double weight) {
    return (weight > WEIGHT_THRESHOLD) ? 1 : 0;
}

// Activates the solenoid lock for 3 seconds
void activate_lock() {
    printf("Activating lock...\n");
    gpioWrite(LOCK_PIN, 1); // Set lock pin HIGH
    gpioDelay(3000);          // Wait for 3 seconds
    gpioWrite(LOCK_PIN, 0); // Set lock pin LOW
    printf("Lock deactivated.\n");
}

// Logs the event to a file
void log_event(double weight) {
    FILE *fp;
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[64];

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    fp = fopen("lock_events.log", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        return;
    }

    fprintf(fp, "%s, %.2f kg\n", timestamp, weight);
    fclose(fp);

    printf("Event logged: %s, %.2f kg\n", timestamp, weight);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(LOCK_PIN, PI_OUTPUT);

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Calibrate the HX711
    calibrate_hx711(CALIBRATION_WEIGHT);

    // Main loop
    while (1) {
        int raw_value = read_hx711();
        if (raw_value == -1) {
            fprintf(stderr, "Error reading HX711, retrying...\n");
            gpioDelay(100); // Short delay before retrying
            continue;
        }

        double weight = convert_to_kg(raw_value);

        printf("Weight: %.2f kg\n", weight);

        if (is_above_threshold(weight)) {
            activate_lock();
            log_event(weight);
        }

        gpioDelay(100); // Short delay
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <errno.h>
#include <string.h>

#define I2C_BUS "/dev/i2c-1" // Adjust if using a different I2C bus
#define PCF8591_ADDR 0x48    // PCF8591 I2C address
#define AIN0 0x40            // Address for AIN0, no auto-increment

int main() {
  int file;
  int adc_value;
  char buffer[2];

  // Open I2C bus
  if ((file = open(I2C_BUS, O_RDWR)) < 0) {
    perror("Failed to open the I2C bus");
    fprintf(stderr, "Error number: %d\n", errno);
    fprintf(stderr, "Error message: %s\n", strerror(errno));
    exit(1);
  }

  // Specify the address of the slave device
  if (ioctl(file, I2C_SLAVE, PCF8591_ADDR) < 0) {
    perror("Failed to acquire bus access and/or talk to slave");
        fprintf(stderr, "Error number: %d\n", errno);
        fprintf(stderr, "Error message: %s\n", strerror(errno));
    exit(1);
  }

  printf("Reading from PCF8591 AIN0...\n");

  while (1) {
    // Send control byte to start ADC conversion on AIN0 (no auto-increment)
    buffer[0] = AIN0;
    if (write(file, buffer, 1) != 1) {
      perror("Failed to write to the I2C bus");
      fprintf(stderr, "Error number: %d\n", errno);
      fprintf(stderr, "Error message: %s\n", strerror(errno));
      close(file);
      exit(1);
    }

    // Read ADC value
    if (read(file, buffer, 1) != 1) {
      perror("Failed to read from the I2C bus");
        fprintf(stderr, "Error number: %d\n", errno);
        fprintf(stderr, "Error message: %s\n", strerror(errno));
      close(file);
      exit(1);
    }

    adc_value = (unsigned char)buffer[0]; // Convert char to unsigned int.
    printf("AIN0 Value: %d\n", adc_value);

    usleep(500000); // 0.5 second delay
  }

  close(file);
  return 0;
}

#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
#include <errno.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <stdbool.h>
#include <time.h>
#include <math.h>

// Define the I2C address of the D6F-PH sensor
#define D6F_ADDR 0x6C

// Define the I2C device file on Raspberry Pi
#define I2C_DEVICE "/dev/i2c-1"

// Function to convert a 16-bit integer to its high byte (uint8_t)
static inline uint8_t high_byte(int16_t value) {
    return (uint8_t)(value >> 8);
}

// Function to convert a 16-bit integer to its low byte (uint8_t)
static inline uint8_t low_byte(int16_t value) {
    return (uint8_t)(value & 0xFF);
}

// Function to convert two uint8_t values (big-endian) to a uint16_t
static inline uint16_t bytes_to_uint16(uint8_t high_byte, uint8_t low_byte) {
    return (uint16_t)(((uint32_t)high_byte << 8) | (uint32_t)low_byte);
}

// Function to perform a delay in milliseconds using nanosleep
void delay_ms(int milliseconds) {
    struct timespec ts;
    ts.tv_sec = milliseconds / 1000;
    ts.tv_nsec = (milliseconds % 1000) * 1000000;
    nanosleep(&ts, NULL);
}

// Function to write data to the I2C device using a 16-bit register address
int i2c_write(int file_descriptor, uint8_t device_address, uint16_t register_address, const uint8_t *data, uint8_t length) {
    uint8_t buffer[128]; // Buffer to hold the register address and data
    if (length > 125) {  // Maximum data length is 125 bytes (127 - 2 for reg address)
        fprintf(stderr, "Error: Data length exceeds maximum allowed (125 bytes).\n");
        return -1; // Indicate an error
    }

    buffer[0] = high_byte(register_address); // High byte of the register address
    buffer[1] = low_byte(register_address);  // Low byte of the register address

    if (data != NULL && length > 0) {
        memcpy(buffer + 2, data, length); // Copy the data to the buffer after the register address
    }

    // Set the I2C slave address for the device
    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Error: Could not set I2C device address. %s\n", strerror(errno));
        return -1; // Indicate an error
    }

    // Write the data to the I2C device
    ssize_t bytes_written = write(file_descriptor, buffer, length + 2); // Write reg addr + data
    if (bytes_written != (length + 2)) {
        fprintf(stderr, "Error: I2C write failed. Wrote %zd bytes, expected %d. %s\n", bytes_written, length + 2, strerror(errno));
        return -1; // Indicate an error
    }

    return 0; // Indicate success
}

// Function to read data from the I2C device using an 8-bit register address
int i2c_read(int file_descriptor, uint8_t device_address, uint8_t register_address, uint8_t *data, uint8_t length) {
    // Set the I2C slave address for the device
    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Error: Could not set I2C device address. %s\n", strerror(errno));
        return -1; // Indicate an error
    }

    // Write the register address to the I2C device
    if (write(file_descriptor, &register_address, 1) != 1) {
        fprintf(stderr, "Error: Could not write register address. %s\n", strerror(errno));
        return -1; // Indicate an error
    }

    // Read the data from the I2C device
    ssize_t bytes_read = read(file_descriptor, data, length);
    if (bytes_read != length) {
        fprintf(stderr, "Error: I2C read failed. Read %zd bytes, expected %d. %s\n", bytes_read, length, strerror(errno));
        return -1; // Indicate an error
    }

    return 0; // Indicate success
}

int main() {
    int file_descriptor; // File descriptor for the I2C device

    // Open the I2C device file
    file_descriptor = open(I2C_DEVICE, O_RDWR);
    if (file_descriptor < 0) {
        fprintf(stderr, "Error: Could not open I2C device. %s\n", strerror(errno));
        return 1; // Indicate an error
    }

    // 1. Initialize sensor (0Bh, 00h)
    if (i2c_write(file_descriptor, D6F_ADDR, 0x0B00, NULL, 0) != 0) {
        fprintf(stderr, "Error: Sensor initialization failed.\n");
        close(file_descriptor);
        return 1;
    }
    delay_ms(900);

    while (1) {
        // 2. Trigger getting data (00h, D0h, 40h, 18h, 06h)
        uint8_t trigger_data[] = {0x40, 0x18, 0x06};
        if (i2c_write(file_descriptor, D6F_ADDR, 0x00D0, trigger_data, sizeof(trigger_data)) != 0) {
            fprintf(stderr, "Error: Trigger write failed.\n");
            close(file_descriptor);
            return 1;
        }

        delay_ms(50); // wait 50ms

        // 3. Read data (00h, D0h, 51h, 2Ch) (07h)
        uint8_t read_command[] = {0x51, 0x2C};
        if (i2c_write(file_descriptor, D6F_ADDR, 0x00D0, read_command, sizeof(read_command)) != 0) {
            fprintf(stderr, "Error: Read command write failed.\n");
            close(file_descriptor);
            return 1;
        }

        uint8_t flow_data[2];
        if (i2c_read(file_descriptor, D6F_ADDR, 0x07, flow_data, sizeof(flow_data)) != 0) {
            fprintf(stderr, "Error: Flow data read failed.\n");
            close(file_descriptor);
            return 1;
        }

        uint16_t raw_flow = bytes_to_uint16(flow_data[0], flow_data[1]);
        float flow_rate;

        // 0-50[L/min] range
        flow_rate = ((float)raw_flow - 1024.0) * 50.0 / 60000.0;

        printf("Flow Rate: %6.2f [L/min]\n", flow_rate);

        delay_ms(100); // Add a small delay between readings
    }

    close(file_descriptor);
    return 0;
}

#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>

#define SERVO_PIN 18
#define BUTTON_PIN 25

// Define the sequence of servo angles (pulse widths in microseconds)
int servoAngles[] = {1000, 1500, 2000}; // Example angles
int numAngles = sizeof(servoAngles) / sizeof(servoAngles[0]);
int currentAngleIndex = 0;

int buttonPressed = 0;

void button_callback(int gpio, int level, uint32_t tick) {
    if (gpio == BUTTON_PIN && level == 0 && !buttonPressed) { // Button pressed (low level)
        buttonPressed = 1;

        // Move to the next servo angle
        currentAngleIndex = (currentAngleIndex + 1) % numAngles;
        gpioServo(SERVO_PIN, servoAngles[currentAngleIndex]);
        printf("Servo moved to position: %d us\n", servoAngles[currentAngleIndex]);
    }
    if(gpio == BUTTON_PIN && level == 1) {
      buttonPressed = 0; //reset when released
    }
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set the button pin as an input with a pull-up resistor
    gpioSetMode(BUTTON_PIN, PI_INPUT);
    gpioSetPullUpDown(BUTTON_PIN, PI_PUD_UP);

    // Set the servo pin as an output
    gpioSetMode(SERVO_PIN, PI_OUTPUT);

    // Initial servo position
    gpioServo(SERVO_PIN, servoAngles[currentAngleIndex]);
    printf("Servo initialized to position: %d us\n", servoAngles[currentAngleIndex]);

    // Set callback function for button press
    gpioSetAlertFunc(BUTTON_PIN, button_callback);

    // Keep the program running
    while (1) {
        sleep(1); // Reduce CPU usage
    }

    gpioTerminate();
    return 0;
}

#include <wiringPi.h>
#include <stdio.h>
#include <stdlib.h>
#include <errno.h>

// Define GPIO pins connected to the 74HC595
#define DATA_PIN   0   // Serial Data Input (SDI)
#define LATCH_PIN  1   // Register Clock (RCLK / STCP)
#define CLOCK_PIN  2   // Shift Register Clock (SRCLK / SHCP)

// Array representing the segment patterns for 0-9 and A-F
const unsigned char segmentCodes[16] = {
    0x3f, 0x06, 0x5b, 0x4f, 0x66, 0x6d, 0x7d, 0x07, 0x7f, 0x6f, 0x77, 0x7c, 0x39, 0x5e, 0x79, 0x71
};

// Function to initialize the WiringPi library and configure GPIO pins
int initialize(void) {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return -1; // Indicate failure
    }

    // Set the pin modes for the control pins
    pinMode(DATA_PIN, OUTPUT);
    pinMode(LATCH_PIN, OUTPUT);
    pinMode(CLOCK_PIN, OUTPUT);

    // Initialize pins to LOW
    digitalWrite(DATA_PIN, LOW);
    digitalWrite(LATCH_PIN, LOW);
    digitalWrite(CLOCK_PIN, LOW);

    return 0; // Indicate success
}

// Function to shift data to the 74HC595 shift register
void shiftOut(unsigned char data) {
    for (int i = 0; i < 8; i++) {
        // Determine if the most significant bit is a 1 or 0
        digitalWrite(DATA_PIN, (data & 0x80) ? HIGH : LOW);  // Check MSB
        data <<= 1; // Shift left to process the next bit

        // Clock the data into the shift register
        digitalWrite(CLOCK_PIN, HIGH);
        delayMicroseconds(1); // Small delay for stable clock
        digitalWrite(CLOCK_PIN, LOW);
    }
}

// Function to latch the data to the output of the 74HC595
void latchData(void) {
    digitalWrite(LATCH_PIN, HIGH);
    delayMicroseconds(1); // Small delay for stable latch
    digitalWrite(LATCH_PIN, LOW);
}

// Function to display a number (0-15) on the 7-segment display
void displayHexDigit(int digit) {
    if (digit < 0 || digit > 15) {
        fprintf(stderr, "Error: Invalid digit for 7-segment display: %d\n", digit);
        return; // Exit if the digit is out of range
    }

    shiftOut(segmentCodes[digit]); // Send segment code to shift register
    latchData();                    // Latch the data to the output

    printf("Displaying 0x%X on 7-segment display\n", digit);
}

int main(void) {
    // Initialize WiringPi and configure GPIO pins
    if (initialize() == -1) {
        return EXIT_FAILURE; // Exit if initialization failed
    }

    // Main loop to display numbers 0-15 on the 7-segment display
    while (1) {
        for (int i = 0; i < 16; i++) {
            displayHexDigit(i); // Display the current digit
            delay(500);           // Delay for 500ms
        }
    }

    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <unistd.h>

// Define constants
#define MCP3008_SPI_CHANNEL 0
#define GAS_SENSOR_CHANNEL 0 // MCP3008 channel connected to gas sensor
#define BUZZER_GPIO 17      // GPIO pin connected to the buzzer
#define THRESHOLD 500      // ADC value threshold (0-1023)
#define SPI_CE 8            // Chip Enable pin for SPI (CE0 is usually 8)

// Function to read data from MCP3008
int read_mcp3008(int channel)
{
    if (channel < 0 || channel > 7) return -1; // Invalid channel

    int spi_handle = spiOpen(MCP3008_SPI_CHANNEL, 100000, 0); // Open SPI channel (speed is 100kHz, mode is 0)
    if (spi_handle < 0) {
        fprintf(stderr, "Error: spiOpen failed (%d)\n", spi_handle);
        return -1;
    }

    unsigned char tx_buffer[3];
    unsigned char rx_buffer[3];

    tx_buffer[0] = 0x01; // Start bit
    tx_buffer[1] = (0x08 | channel) << 4; // Single-ended mode, channel select
    tx_buffer[2] = 0x00; // Dummy byte

    spiXfer(spi_handle, tx_buffer, rx_buffer, 3); // Transfer data

    int adc_value = ((rx_buffer[1] & 0x03) << 8) + rx_buffer[2]; // Extract ADC value

    spiClose(spi_handle); // Close SPI channel
    return adc_value;
}

int main()
{
    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(BUZZER_GPIO, PI_OUTPUT); // Set buzzer pin as output
    gpioWrite(BUZZER_GPIO, PI_LOW);         // Initially turn buzzer off

    printf("Monitoring gas sensor...\n");

    while (1)
    {
        int gas_value = read_mcp3008(GAS_SENSOR_CHANNEL);

        if (gas_value < 0)
        {
            fprintf(stderr, "Error reading gas sensor value\n");
            gpioTerminate();
            return 1;
        }

        printf("Gas sensor value: %d\n", gas_value);

        if (gas_value > THRESHOLD)
        {
            printf("Threshold exceeded! Activating buzzer.\n");
            gpioWrite(BUZZER_GPIO, PI_HIGH); // Turn buzzer on
            gpioDelay(1000);                 // Buzzer on for 1 second
            gpioWrite(BUZZER_GPIO, PI_LOW);  // Turn buzzer off
            gpioDelay(1000);                 // Buzzer off for 1 second
        }
        else
        {
            gpioWrite(BUZZER_GPIO, PI_LOW); // Ensure buzzer is off if below threshold
        }

        gpioDelay(500); // Check every 0.5 seconds
    }

    gpioTerminate(); // Terminate pigpio
    return 0;
}

#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <inttypes.h>

// Define the I2C bus and address
#define I2C_BUS 1
#define ADS1115_ADDRESS 0x48

// Define ADS1115 registers
#define ADS1115_REG_CONFIG 0x01
#define ADS1115_REG_CONVERT 0x00

// Function to write a register value
int write_register(int fd, uint8_t reg, uint16_t value) {
    uint8_t buffer[3];
    buffer[0] = reg;
    buffer[1] = (value >> 8) & 0xFF;
    buffer[2] = value & 0xFF;
    if (write(fd, buffer, 3) != 3) {
        perror("Failed to write to I2C device");
        return -1;
    }
    return 0;
}

// Function to read a register value
int read_register(int fd, uint8_t reg, uint16_t *value) {
    if (write(fd, &reg, 1) != 1) {
        perror("Failed to write to I2C device");
        return -1;
    }
    uint8_t buffer[2];
    if (read(fd, buffer, 2) != 2) {
        perror("Failed to read from I2C device");
        return -1;
    }
    *value = (buffer[0] << 8) | buffer[1];
    return 0;
}

// Function to read a single channel
int16_t read_channel(int fd, uint8_t channel) {
    uint16_t config = 0x8000; // Start single conversion
    config |= (channel << 12); // Set channel
    config |= 0x0080;          // +/- 4.096V range
    config |= 0x0100;          // 128 SPS
    config |= 0x0003;          // Disable comparator

    if (write_register(fd, ADS1115_REG_CONFIG, config) < 0) {
        fprintf(stderr, "Failed to write config register.\n");
        return -1;
    }

    // Wait for conversion to complete (at least 8ms for 128 SPS)
    usleep(10000); // 10 ms

    uint16_t value;
    if (read_register(fd, ADS1115_REG_CONVERT, &value) < 0) {
        fprintf(stderr, "Failed to read conversion register.\n");
        return -1;
    }
    return (int16_t)value;
}

int main() {
    int fd;
    char filename[20];

    // Open I2C bus
    snprintf(filename, 19, "/dev/i2c-%d", I2C_BUS);
    fd = open(filename, O_RDWR);
    if (fd < 0) {
        perror("Failed to open I2C bus");
        return 1;
    }

    // Specify slave address
    if (ioctl(fd, I2C_SLAVE, ADS1115_ADDRESS) < 0) {
        perror("Failed to acquire bus access and/or talk to slave");
        close(fd);
        return 1;
    }

    printf("ADS1115 Readings:\n");
    printf("-------------------\n");

    // Read all four channels
    for (int i = 0; i < 4; i++) {
        int16_t value = read_channel(fd, i);
        if (value != -1) {
            printf("Channel %d: %d\n", i, value);
        } else {
            fprintf(stderr, "Failed to read channel %d.\n", i);
        }
    }

    // Close the I2C device
    close(fd);

    return 0;
}

