    return 0;
}

// Initialize GPIO pins
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(TOUCH_SENSOR_GPIO, PI_INPUT);
    gpioSetMode(RELAY_GPIO, PI_OUTPUT);
    gpioWrite(RELAY_GPIO, 0); // Ensure relay is initially off

    return 0;
}

// Callback function for touch sensor events
void touch_event_callback(int gpio, int level, uint32_t tick) {
    if (gpio == TOUCH_SENSOR_GPIO && level == 1) { // Rising edge detected
        char *timestamp = get_timestamp();
        if (timestamp != NULL) {
            printf("Touch detected at: %s\n", timestamp);
            log_touch_event(timestamp);
            free(timestamp);
            trigger_relay_pulse(RELAY_GPIO, PULSE_DURATION);
        }
    }
}

// Trigger a pulse on the relay GPIO
void trigger_relay_pulse(int gpio, int duration) {
    gpioWrite(gpio, 1); // Turn relay on
    gpioDelay(duration); // Wait for the specified duration
    gpioWrite(gpio, 0); // Turn relay off
}

// Get current timestamp in YYYY-MM-DD HH:MM:SS format
char* get_timestamp() {
    time_t rawtime;
    struct tm *timeinfo;
    char *timestamp = (char*)malloc(20 * sizeof(char)); // Allocate memory for timestamp

    if (timestamp == NULL) {
        perror("Memory allocation error");
        return NULL; // Indicate failure
    }

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, 20, "%Y-%m-%d %H:%M:%S", timeinfo);

    return timestamp;
}

// Log touch event to file
int log_touch_event(const char *timestamp) {
    if (log_file != NULL) {
        fprintf(log_file, "%s: Touch detected\n", timestamp);
        fflush(log_file); // Ensure data is written to disk immediately
        return 0; // Indicate success
    } else {
        perror("Error writing to log file");
        return 1; // Indicate failure
    }
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("\nCaught signal %d, exiting gracefully.\n", signal);
    running = 0; // Stop the main loop

    // Release GPIO resources and close log file
    if (log_file != NULL) {
        fclose(log_file);
    }
    gpioTerminate();
    exit(0);
}

