#define MOTOR_PIN_2 18  // Example: GPIO18 for motor control
#define PWM_PIN 12      // Example: GPIO12 for PWM control

// Function to set motor direction
void setMotorDirection(int dir) {
    if (dir == 1) { // Forward
        gpioWrite(MOTOR_PIN_1, 1);
        gpioWrite(MOTOR_PIN_2, 0);
    } else if (dir == -1) { // Reverse
        gpioWrite(MOTOR_PIN_1, 0);
        gpioWrite(MOTOR_PIN_2, 1);
    } else { // Stop
        gpioWrite(MOTOR_PIN_1, 0);
        gpioWrite(MOTOR_PIN_2, 0);
    }
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pins as output
    gpioSetMode(MOTOR_PIN_1, PI_OUTPUT);
    gpioSetMode(MOTOR_PIN_2, PI_OUTPUT);
    gpioSetMode(PWM_PIN, PI_OUTPUT);

    // Set PWM range (adjust as needed)
    gpioSetPWMrange(PWM_PIN, 100); // Range 0-100
    gpioSetPWMfrequency(PWM_PIN, 1000); // 1kHz

    int i, dutyCycle;

    // Gradual increase in speed
    setMotorDirection(1); // Forward direction
    for (i = 0; i <= 100; i++) {
        dutyCycle = i;
        gpioPWM(PWM_PIN, dutyCycle);
        usleep(20000); // Sleep for 20ms
    }

    usleep(1000000); // run at full speed for 1 second

    // Gradual decrease in speed
    for (i = 100; i >= 0; i--) {
        dutyCycle = i;
        gpioPWM(PWM_PIN, dutyCycle);
        usleep(20000); // Sleep for 20ms
    }

    setMotorDirection(0); // Stop the motor

    gpioTerminate();
    return 0;
}

