// Define GPIO pins for HX711
#define HX711_DT 2
#define HX711_SCK 3

// Define LED control file
#define LED_FILE "/sys/class/leds/led0/brightness"

// Define calibration factor (obtained through calibration)
#define CALIBRATION_FACTOR 100.0 // Example value, needs to be calibrated

// Define threshold weight (in grams)
#define WEIGHT_THRESHOLD 50.0 // Example value

// Define number of readings to average
#define NUM_READINGS 10

// Global variables
FILE *log_file = NULL;
volatile sig_atomic_t terminate = 0;

// Function prototypes
int read_hx711(void);
double calculate_weight(int raw_value);
int log_weight(double weight);
int control_led(int on);
void signal_handler(int signal);

// Signal handler for graceful termination
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("Caught SIGINT, exiting gracefully.\n");
        terminate = 1;
    }
}

// Function to read raw value from HX711
int read_hx711(void) {
    int value = 0;
    int i;

    gpioSetMode(HX711_DT, PI_INPUT);
    gpioSetMode(HX711_SCK, PI_OUTPUT);

    // Wait for HX711 to be ready
    while (gpioRead(HX711_DT) == 1) {
        gpioDelay(1); // Small delay to prevent busy-waiting
    }

    for (i = 0; i < 24; i++) {
        gpioWrite(HX711_SCK, 1);
        gpioDelay(1); // Short clock pulse
        value = value << 1;
        if (gpioRead(HX711_DT)) {
            value++;
        }
        gpioWrite(HX711_SCK, 0);
        gpioDelay(1);
    }

    // 25th pulse for gain setting (Channel A, gain 128)
    gpioWrite(HX711_SCK, 1);
    gpioDelay(1);
    gpioWrite(HX711_SCK, 0);
    gpioDelay(1);

    // Two's complement conversion if necessary
    if (value & 0x800000) {
        value |= ~0xffffff;
    }

    return value;
}

// Function to calculate weight from raw value
double calculate_weight(int raw_value) {
    return (double)raw_value / CALIBRATION_FACTOR;
}

// Function to log weight to file
int log_weight(double weight) {
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    if (log_file == NULL) {
        fprintf(stderr, "Log file is not opened.\n");
        return 1; // Indicate error
    }
    fprintf(log_file, "%d-%02d-%02d %02d:%02d:%02d, %.2f\n",
            t->tm_year + 1900, t->tm_mon + 1, t->tm_mday,
            t->tm_hour, t->tm_min, t->tm_sec, weight);
    fflush(log_file); // Ensure data is written to disk
    return 0; // Indicate success
}

// Function to control LED
int control_led(int on) {
    FILE *led_file_ptr = fopen(LED_FILE, "w");
    if (led_file_ptr == NULL) {
        fprintf(stderr, "Error opening LED file.\n");
        return 1; // Indicate error
    }

    if (on) {
        fprintf(led_file_ptr, "1");
    } else {
        fprintf(led_file_ptr, "0");
    }

    fclose(led_file_ptr);
    return 0; // Indicate success
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Open log file
    log_file = fopen("weight_log.txt", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file.\n");
        gpioTerminate();
        return 1;
    }

    printf("Weight measurement started. Press Ctrl+C to exit.\n");

    while (!terminate) {
        int raw_sum = 0;
        for (int i = 0; i < NUM_READINGS; i++) {
            raw_sum += read_hx711();
        }
        double raw_average = (double)raw_sum / NUM_READINGS;
        double weight = calculate_weight(raw_average);

        printf("Weight: %.2f g\n", weight);

        if (log_weight(weight) != 0) {
            fprintf(stderr, "Error logging weight.\n");
        }

        if (weight > WEIGHT_THRESHOLD) {
            if (control_led(1) != 0) {
                fprintf(stderr, "Error turning LED on.\n");
            }
        } else {
            if (control_led(0) != 0) {
                fprintf(stderr, "Error turning LED off.\n");
            }
        }

        gpioDelay(500); // Wait 0.5 seconds
    }

    // Cleanup
    fclose(log_file);
    gpioTerminate();

    printf("Weight measurement stopped.\n");

    return 0;
}

