// MCP3008 SPI pins (wiringPi numbering)
#define SPI_CE 8  // Chip Enable (CS) - GPIO8
#define SPI_CLK 11 // Clock - GPIO11
#define SPI_MISO 9 // MISO - GPIO9
#define SPI_MOSI 10 // MOSI - GPIO10

// Water pump control pin
#define PUMP_PIN 17 // GPIO17

// Soil moisture threshold (raw ADC value)
#define MOISTURE_THRESHOLD 300

// Function prototypes
int read_mcp3008(int channel);
void control_pump(int pump_state);
void log_data(int adc_value, int pump_state);
void signal_handler(int signal);

// Global variable for pump state (0 = OFF, 1 = ON)
volatile int pump_state = 0;
volatile sig_atomic_t program_running = 1;

// Signal handler for graceful shutdown
void signal_handler(int signal)
{
    printf("\nCaught signal %d, cleaning up and exiting...\n", signal);
    program_running = 0;
    control_pump(0); // Turn off the pump
    exit(0);
}

// Function to read data from MCP3008 ADC
int read_mcp3008(int channel)
{
    unsigned char buffer[3];
    int adc_value = 0;

    if (channel < 0 || channel > 7)
    {
        fprintf(stderr, "Error: Invalid MCP3008 channel: %d\n", channel);
        return -1; // Indicate an error
    }

    digitalWrite(SPI_CE, LOW); // Select the MCP3008

    // Prepare the SPI message to send to MCP3008
    buffer[0] = 0x01;                                       // Start bit
    buffer[1] = ((channel & 0x07) << 4) | 0x80;             // Single-ended mode, channel select
    buffer[2] = 0x00;                                       // Don't care

    wiringPiSPIDataRW(0, buffer, 3); // Send and receive SPI data (Channel 0)

    adc_value = ((buffer[1] & 0x03) << 8) + buffer[2]; // Extract the ADC value

    digitalWrite(SPI_CE, HIGH); // Deselect the MCP3008

    return adc_value;
}

// Function to control the water pump
void control_pump(int pump_state_new)
{
    if (pump_state_new != pump_state)
    {
        digitalWrite(PUMP_PIN, pump_state_new); // Set the pump pin HIGH or LOW
        pump_state = pump_state_new;
    }
}

// Function to log data to the console
void log_data(int adc_value, int pump_state)
{
    printf("ADC Value: %d, Pump Status: %s\n", adc_value, pump_state ? "ON" : "OFF");
}

int main(void)
{
    // Set up signal handling for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1) // Use Broadcom GPIO numbering
    {
        fprintf(stderr, "Error: Unable to initialize wiringPi: %s\n", strerror(errno));
        return 1;
    }

    // Configure the pump pin as output
    pinMode(PUMP_PIN, OUTPUT);
    digitalWrite(PUMP_PIN, LOW); // Initially turn the pump off
    pump_state = 0;             // Ensure pump_state reflects initial off state

    // Configure SPI
    if (wiringPiSPISetup(0, 1000000) == -1) // Channel 0, 1MHz clock speed
    {
        fprintf(stderr, "Error: Unable to initialize SPI: %s\n", strerror(errno));
        return 1;
    }

    // Set Chip Enable pin as output
    pinMode(SPI_CE, OUTPUT);
    digitalWrite(SPI_CE, HIGH); // Deselect the MCP3008 initially

    printf("Soil Moisture Monitoring and Irrigation System\n");

    while (program_running)
    {
        int adc_value = read_mcp3008(0); // Read from channel 0

        if (adc_value == -1)
        {
            fprintf(stderr, "Error: Failed to read ADC value. Retrying in 5 seconds.\n");
        } else {
            // Determine pump state based on moisture level
            if (adc_value < MOISTURE_THRESHOLD)
            {
                control_pump(1); // Turn the pump ON
            } else {
                control_pump(0); // Turn the pump OFF
            }

            // Log the data
            log_data(adc_value, pump_state);
        }

        delay(5000); // Wait 5 seconds
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <wiringPi.h>

// Define GPIO pins
#define DATA_PIN  17  // Shift register data input (SER)
#define CLOCK_PIN 18  // Shift register clock input (SRCLK)
#define LATCH_PIN 27  // Shift register latch input (RCLK)
#define BUTTON_PIN 4   // Button input

// Seven-segment display patterns (common cathode)
const uint8_t numbers[] = {
    0x3F, // 0
    0x06, // 1
    0x5B, // 2
    0x4F, // 3
    0x66, // 4
    0x6D, // 5
    0x7D, // 6
    0x07, // 7
    0x7F, // 8
    0x6F  // 9
};

// Function to shift out data to the shift register
void shiftOut(uint8_t data) {
    for (int i = 0; i < 8; i++) {
        digitalWrite(DATA_PIN, (data >> (7 - i)) & 0x01);
        digitalWrite(CLOCK_PIN, HIGH);
        digitalWrite(CLOCK_PIN, LOW);
    }
}

int main() {
    // Initialize WiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi setup failed!\n");
        return 1;
    }

    // Set pin modes
    pinMode(DATA_PIN, OUTPUT);
    pinMode(CLOCK_PIN, OUTPUT);
    pinMode(LATCH_PIN, OUTPUT);
    pinMode(BUTTON_PIN, INPUT);
    pullUpDnControl(BUTTON_PIN, PUD_UP); // Enable internal pull-up resistor

    int currentNumber = 0;
    int buttonState = HIGH;  // Assume button is not pressed initially

    while (1) {
        // Check if the button is pressed (low active)
        if (digitalRead(BUTTON_PIN) == LOW) {
            // Debounce the button
            delay(50);  // Short delay for debouncing
            if (digitalRead(BUTTON_PIN) == LOW) {
                // Increment the number
                currentNumber++;
                if (currentNumber > 9) {
                    currentNumber = 0;
                }

                // Update the seven-segment display
                digitalWrite(LATCH_PIN, LOW);
                shiftOut(numbers[currentNumber]);
                digitalWrite(LATCH_PIN, HIGH);

                // Wait for button release
                while (digitalRead(BUTTON_PIN) == LOW) {
                    delay(10); // Small delay
                }
            }
        }

        delay(10); // Small delay to prevent busy-waiting
    }

    return 0;
}

