void initializeGPIO() {
  wiringPiSetup();

  // Set button pin as input
  pinMode(BUTTON_PIN, INPUT);
  pullUpDnControl(BUTTON_PIN, PUD_UP); // Use internal pull-up resistor

  // Set column pins as output
  for (int i = 0; i < 8; i++) {
    pinMode(columnPins[i], OUTPUT);
    digitalWrite(columnPins[i], LOW); // Initially off
  }

  // Set row pins as output
  for (int i = 0; i < 8; i++) {
    pinMode(rowPins[i], OUTPUT);
    digitalWrite(rowPins[i], HIGH); // Initially off (common anode)
  }
}

void turnOnLED(int row, int col) {
    digitalWrite(columnPins[col], HIGH);
    digitalWrite(rowPins[row], LOW);
    delay(5); // Keep LED on briefly
    digitalWrite(columnPins[col], LOW);
    digitalWrite(rowPins[row], HIGH);
}

