    if (digitalRead(BUTTON_PIN) == LOW) { // Button pressed (LOW due to pull-up)
      turnOnLED(0, 0); // Turn on LED at row 0, column 0
      delay(200); // Debounce delay
    }
  }

  return 0;
}

