    int result;

    // Read the two bytes from the sensor
    result = i2cReadDevice(i2c_handle, buf, 2);
    I2C_CHECK(result, "Failed to read from MAX44009");

    // Convert the data to lux (example conversion, adjust as needed)
    double lux = (double)((buf[0] << 4) | (buf[1] & 0x0F)) * 0.045; // Example conversion
    return lux;
}

double read_decibels(int spi_handle) {
    unsigned char spi_tx_buf[3];
    unsigned char spi_rx_buf[3];
    int result;

    // MCP3008 command to read from channel 0 (single-ended)
    spi_tx_buf[0] = 0x01;  // Start bit
    spi_tx_buf[1] = 0x80;  // Single-ended mode, channel 0
    spi_tx_buf[2] = 0x00;  // Don't care

    result = spiXfer(spi_handle, spi_tx_buf, spi_rx_buf, 3);
    SPI_CHECK(result, "Failed to read from MCP3008");

    // Extract the ADC value (10 bits)
    int adc_value = ((spi_rx_buf[1] & 0x03) << 8) + spi_rx_buf[2];

    // Convert ADC value to decibels (example conversion, adjust as needed)
    // Assuming 0-1023 maps to a certain dB range.  This is a placeholder.
    double decibels = (double)adc_value / 1023.0 * 80.0; // Example: 0-80 dB
    return decibels;
}


void log_data(double lux, double decibels) {
    json_t *root, *data;
    json_t *timestamp_json, *lux_json, *decibels_json;
    char *timestamp = get_timestamp();
    FILE *fp;

    root = json_object();

    timestamp_json = json_string(timestamp);
    lux_json = json_real(lux);
    decibels_json = json_real(decibels);

    json_object_set_new(root, "timestamp", timestamp_json);
    json_object_set_new(root, "lux", lux_json);
    json_object_set_new(root, "decibels", decibels_json);

    fp = fopen("environmental_log.json", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening environmental_log.json for writing\n");
        json_decref(root);
        free(timestamp);
        return;
    }

    json_dumpf(root, fp, JSON_INDENT(4));
    fprintf(fp, "\n"); // Add a newline after each JSON object

    fclose(fp);
    json_decref(root);
    free(timestamp);
}


char* get_timestamp() {
    time_t rawtime;
    struct tm *timeinfo;
    char *buffer = (char*)malloc(80 * sizeof(char)); // Allocate memory
    if (buffer == NULL) {
        fprintf(stderr, "Memory allocation error\n");
        return NULL; // Or handle the error in another appropriate way
    }

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(buffer, 80, "%Y-%m-%d %H:%M:%S", timeinfo);
    return buffer;
}


int main() {
    int i2c_handle, spi_handle;
    double lux, decibels;

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C
    i2c_handle = i2cOpen(1, MAX44009_ADDR, 0); // Bus 1, address 0x4A
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Open SPI
    spi_handle = spiOpen(MCP3008_CHANNEL, SPI_SPEED, 0); // Channel 0, 1MHz, no flags
    if (spi_handle < 0) {
        fprintf(stderr, "Failed to open SPI device: %d\n", spi_handle);
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Main loop
    while (1) {
