#define SERVO_PIN 18
#define BUTTON_INCREMENT_PIN 17 // Example pin for increment button
#define BUTTON_DECREMENT_PIN 27 // Example pin for decrement button
#define SERVO_MIN_PULSE_WIDTH 1000 // Minimum pulse width (us)
#define SERVO_MAX_PULSE_WIDTH 2000 // Maximum pulse width (us)
#define STEP_SIZE 50              // Step size for increment/decrement (us)

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(SERVO_PIN, PI_OUTPUT);
    gpioSetMode(BUTTON_INCREMENT_PIN, PI_INPUT);
    gpioSetMode(BUTTON_DECREMENT_PIN, PI_INPUT);
    gpioSetPullUpDown(BUTTON_INCREMENT_PIN, PI_PUD_UP); // Enable pull-up resistor
    gpioSetPullUpDown(BUTTON_DECREMENT_PIN, PI_PUD_UP);

    int pulse_width = (SERVO_MIN_PULSE_WIDTH + SERVO_MAX_PULSE_WIDTH) / 2; // Start at mid-point

    while (1) {
        // Increment
        if (gpioRead(BUTTON_INCREMENT_PIN) == 0) {
            pulse_width += STEP_SIZE;
            if (pulse_width > SERVO_MAX_PULSE_WIDTH) {
                pulse_width = SERVO_MAX_PULSE_WIDTH;
            }
            gpioServo(SERVO_PIN, pulse_width);
            usleep(200000); // Debounce delay
        }

        // Decrement
        if (gpioRead(BUTTON_DECREMENT_PIN) == 0) {
            pulse_width -= STEP_SIZE;
            if (pulse_width < SERVO_MIN_PULSE_WIDTH) {
                pulse_width = SERVO_MIN_PULSE_WIDTH;
            }
            gpioServo(SERVO_PIN, pulse_width);
            usleep(200000); // Debounce delay
        }

        gpioServo(SERVO_PIN, pulse_width); // Maintain current position
        usleep(10000); // Small delay to prevent CPU hogging
    }

    gpioTerminate();
    return 0;
}

