#define SPI_CHANNEL 0   // SPI channel for MCP3008 (CE0 or CE1)

// SPI parameters
#define SPI_SPEED 1000000 // SPI clock speed (1 MHz)
#define MCP3008_CHANNELS 8 // MCP3008 has 8 channels

// Function to read ADC value from MCP3008 via SPI
int read_adc(int channel)
{
    if (channel < 0 || channel >= MCP3008_CHANNELS) {
        fprintf(stderr, "Error: Invalid ADC channel %d\n", channel);
        return -1;
    }

    unsigned char buffer[3];
    buffer[0] = 0x01; // Start bit
    buffer[1] = ((channel & 0x07) << 4) | 0x80; // Single-ended mode, channel select
    buffer[2] = 0x00;

    digitalWrite(8, LOW); // Select SPI
    wiringPiSPIDataRW(SPI_CHANNEL, buffer, 3);
    digitalWrite(8, HIGH); // Deselect SPI

    int adc_value = ((buffer[1] & 0x03) << 8) + buffer[2];
    return adc_value;
}


