// Define the pins connected to the 74HC595
#define LATCH_PIN  0  // GPIO 17, WiringPi pin 0
#define CLOCK_PIN  1  // GPIO 18, WiringPi pin 1
#define DATA_PIN   2  // GPIO 27, WiringPi pin 2

// Define the segment patterns for digits 0-9 (common cathode)
const uint8_t digits[] = {
    0b00111111, // 0
    0b00000110, // 1
    0b01011011, // 2
    0b01001111, // 3
    0b01100110, // 4
    0b01101101, // 5
    0b01111101, // 6
    0b00000111, // 7
    0b01111111, // 8
    0b01101111  // 9
};

// Function to shift out a byte to the 74HC595
void shiftOut(uint8_t data) {
    for (int i = 0; i < 8; i++) {
        digitalWrite(DATA_PIN, (data >> i) & 1);
        digitalWrite(CLOCK_PIN, HIGH);
        digitalWrite(CLOCK_PIN, LOW);
    }
}

int main() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi setup failed!\n");
        return 1;
    }

    // Set the pins as output
    pinMode(LATCH_PIN, OUTPUT);
    pinMode(CLOCK_PIN, OUTPUT);
    pinMode(DATA_PIN, OUTPUT);

    while (1) {
        // Display the digit '8'
        digitalWrite(LATCH_PIN, LOW);
        shiftOut(digits[8]);
        digitalWrite(LATCH_PIN, HIGH);
        delay(500);

        // Turn off all segments (blank the display)
        digitalWrite(LATCH_PIN, LOW);
        shiftOut(0b00000000);
        digitalWrite(LATCH_PIN, HIGH);
        delay(500);
    }

    return 0;
}

