    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Main loop
    while (!terminate) {
        // Update pan angle
        pan_angle += 5 * pan_direction;
        if (pan_angle >= MAX_ANGLE) {
            pan_angle = MAX_ANGLE;
            pan_direction = -1;
        } else if (pan_angle <= MIN_ANGLE) {
            pan_angle = MIN_ANGLE;
            pan_direction = 1;
        }

        // Update tilt angle
        tilt_angle += 5 * tilt_direction;
        if (tilt_angle >= MAX_ANGLE) {
            tilt_angle = MAX_ANGLE;
            tilt_direction = -1;
        } else if (tilt_angle <= MIN_ANGLE) {
            tilt_angle = MIN_ANGLE;
            tilt_direction = 1;
        }

        // Set servo angles
        set_servo_angle(PAN_GPIO, pan_angle);
        set_servo_angle(TILT_GPIO, tilt_angle);

        // Delay for a short period
        time_sleep(0.1); // Adjust delay for desired speed
    }

    // Reset servo angles to 90 degrees before exiting
    set_servo_angle(PAN_GPIO, 90);
    set_servo_angle(TILT_GPIO, 90);

    // Terminate pigpio library
    gpioTerminate();

    return 0;
}

