// Define the GPIO pins connected to the LEDs of the bar graph
// Ensure these pins are available and not used by other processes
const int ledPins[10] = {0, 1, 2, 3, 4, 5, 6, 8, 9, 10};
const int numLeds = 10;

// Function to light up the LED bar graph in a specific pattern
void lightUpLeds(int pattern) {
    // Pattern 0: Odd LEDs, 1: Even LEDs, 2: All LEDs
    int start = 0;
    int step = 1;
    int count = numLeds;

    if (pattern == 0) { // Odd LEDs
        start = 0;
        step = 2;
        count = 5;
    } else if (pattern == 1) { // Even LEDs
        start = 1;
        step = 2;
        count = 5;
    } // Else pattern 2: All LEDs

    for (int i = 0; i < count; ++i) {
        int ledIndex = start + i * step;
        digitalWrite(ledPins[ledIndex], HIGH); // Turn LED on
        delay(300);                           // Wait for 300ms
        digitalWrite(ledPins[ledIndex], LOW);  // Turn LED off
    }
}

int main(void) {
    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return EXIT_FAILURE;
    }

    // Set LED pins as output and initialize to LOW (off)
    for (int i = 0; i < numLeds; ++i) {
        pinMode(ledPins[i], OUTPUT);
        digitalWrite(ledPins[i], LOW);
    }

    // Main loop to cycle through LED patterns
    while (1) {
        lightUpLeds(0); // Odd LEDs
        delay(300);
        lightUpLeds(1); // Even LEDs
        delay(300);
        lightUpLeds(2); // All LEDs
        delay(300);
    }

    return EXIT_SUCCESS;
}

