#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pigpio.h>

// Define GPIO pins
#define BUTTON_GPIO 17
#define ACT_LED_GPIO 47

// Define Morse code timing constants (in milliseconds)
#define DOT_LENGTH 250
#define DASH_LENGTH (3 * DOT_LENGTH)
#define INTER_ELEMENT_PAUSE DOT_LENGTH
#define INTER_CHARACTER_PAUSE (3 * DOT_LENGTH)
#define INTER_WORD_PAUSE (7 * DOT_LENGTH)

// Global variable to track program termination
volatile sig_atomic_t program_running = 1;

// Signal handler function
void signal_handler(int signal) {
    program_running = 0;
    fprintf(stderr, "\nCaught signal %d, terminating gracefully...\n", signal);
}

// Function to initialize the pigpio library
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Indicate failure
    }
    return 0; // Indicate success
}

// Function to configure GPIO pins
int configure_gpio_pins() {
    if (gpioSetMode(BUTTON_GPIO, PI_INPUT) != 0) {
        fprintf(stderr, "Failed to set GPIO %d as input\n", BUTTON_GPIO);
        return 1;
    }
    if (gpioSetPullUpDown(BUTTON_GPIO, PI_PUD_UP) != 0) { // Enable pull-up resistor
        fprintf(stderr, "Failed to set pull-up resistor on GPIO %d\n", BUTTON_GPIO);
        return 1;
    }
    if (gpioSetMode(ACT_LED_GPIO, PI_OUTPUT) != 0) {
        fprintf(stderr, "Failed to set GPIO %d as output\n", ACT_LED_GPIO);
        return 1;
    }
    return 0;
}

// Function to wait for a button press (active low)
void waitForButtonPress() {
    // Simple debouncing with a delay
    while (gpioRead(BUTTON_GPIO) == PI_HIGH && program_running) {
        gpioDelay(1); // Check every millisecond
    }
    gpioDelay(50); // Debounce delay
    while (gpioRead(BUTTON_GPIO) == PI_LOW && program_running) {
        gpioDelay(1); // Wait until button is released
    }
    gpioDelay(50); // Debounce delay
}

// Function to transmit a dot
void transmitDot() {
    gpioWrite(ACT_LED_GPIO, PI_HIGH);
    gpioDelay(DOT_LENGTH);
    gpioWrite(ACT_LED_GPIO, PI_LOW);
    gpioDelay(INTER_ELEMENT_PAUSE);
}

// Function to transmit a dash
void transmitDash() {
    gpioWrite(ACT_LED_GPIO, PI_HIGH);
    gpioDelay(DASH_LENGTH);
    gpioWrite(ACT_LED_GPIO, PI_LOW);
    gpioDelay(INTER_ELEMENT_PAUSE);
}

// Function to transmit the SOS morse code sequence
void transmitSOS() {
    // S (...)
    transmitDot();
    transmitDot();
    transmitDot();

    // O (--)
    transmitDash();
    transmitDash();
    transmitDash();

    // S (...)
    transmitDot();
    transmitDot();
    transmitDot();

    gpioDelay(INTER_WORD_PAUSE); // Pause between repetitions
}

int main() {
    // Register signal handlers for graceful termination
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize pigpio
    if (initialize_gpio() != 0) {
        return 1;
    }

    // Configure GPIO pins
    if (configure_gpio_pins() != 0) {
        gpioTerminate();
        return 1;
    }

    printf("Tamper detection system started. Press button to trigger SOS signal (Ctrl+C to exit).\n");

    // Main loop
    while (program_running) {
        waitForButtonPress(); // Wait for button press
        printf("Button pressed! Transmitting SOS...\n");
        while(gpioRead(BUTTON_GPIO) == PI_LOW && program_running){
            transmitSOS(); // Transmit SOS while button is pressed
        }
        printf("Button released!\n");
        gpioWrite(ACT_LED_GPIO, PI_LOW); // Ensure LED is off after transmission
    }

    // Cleanup and terminate pigpio
    gpioTerminate();
    printf("Tamper detection system terminated.\n");
    return 0;
}

