#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>
#include <time.h>

// Sensor Pin Definitions
#define TRIGGER_PIN 4
#define ECHO_PIN 17
#define SERVO_PIN 18

// Constants
#define SPEED_OF_SOUND 34300.0 // cm/s
#define MIN_DISTANCE 20.0      // cm
#define MAX_DISTANCE 200.0     // cm
#define MIN_PULSE_WIDTH 500    // us
#define MAX_PULSE_WIDTH 2500   // us

volatile sig_atomic_t terminate = 0;

void signal_handler(int sig) {
    terminate = 1;
    fprintf(stderr, "\nCaught signal %d, terminating gracefully...\n", sig);
}

float measureDistance() {
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);

    gpioTrigger(TRIGGER_PIN, 10, 1); // 10 us trigger pulse

    long long start_tick = gpioTick();
    long long end_tick = start_tick;

    // Wait for echo to go high (with timeout)
    int count = 0;
    while (gpioRead(ECHO_PIN) == 0 && count < 10000) {
        count++;
        gpioDelay(1); // Small delay to prevent busy-waiting
    }

    if (count >= 10000) {
        fprintf(stderr, "Error: Echo pulse start timeout\n");
        return -1.0;
    }

    start_tick = gpioTick();

    // Wait for echo to go low (with timeout)
    count = 0;
    while (gpioRead(ECHO_PIN) == 1 && count < 10000) {
        count++;
        gpioDelay(1); // Small delay to prevent busy-waiting
    }

    if (count >= 10000) {
        fprintf(stderr, "Error: Echo pulse end timeout\n");
        return -1.0;
    }

    end_tick = gpioTick();

    long long diff = end_tick - start_tick;

    // Calculate distance in cm
    float pulse_width = (float)diff / 1000000.0; // in seconds
    float distance = (pulse_width * SPEED_OF_SOUND) / 2.0;

    return distance;
}

void setServoAngle(float distance) {
    if (distance < MIN_DISTANCE) {
        distance = MIN_DISTANCE;
    } else if (distance > MAX_DISTANCE) {
        distance = MAX_DISTANCE;
    }

    // Map distance to pulse width
    float pulse_width = (distance - MIN_DISTANCE) / (MAX_DISTANCE - MIN_DISTANCE) * (MAX_PULSE_WIDTH - MIN_PULSE_WIDTH) + MIN_PULSE_WIDTH;

    gpioServo(SERVO_PIN, (int)pulse_width);
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    gpioSetMode(SERVO_PIN, PI_OUTPUT);

    printf("Parking Assist System running...\n");

    while (!terminate) {
        float distance = measureDistance();

        if (distance < 0) {
            fprintf(stderr, "Error: Distance measurement failed, retrying...\n");
            gpioDelay(100); // Wait before retrying
            continue;
        }

        setServoAngle(distance);
        printf("Distance: %.2f cm\n", distance);

        gpioDelay(50); // Delay to avoid overwhelming the system
    }

    // Clean up and terminate
    gpioServo(SERVO_PIN, 0); // Stop servo
    gpioTerminate();

    printf("Parking Assist System terminated.\n");
    return 0;
}

