// Define GPIO pins using wiringPi numbering
const int PIR_PIN = 0;   // GPIO 17 (wiringPi pin 0)
const int LED_PIN = 1;   // GPIO 18 (wiringPi pin 1)

// Debouncing delay in milliseconds
const int DEBOUNCE_DELAY = 200;

// Function to toggle the LED state
void toggleLed(void) {
    static volatile int ledState = 0; // Use static volatile to preserve state between calls and prevent optimization
    ledState = !ledState;
    digitalWrite(LED_PIN, ledState);
    delay(DEBOUNCE_DELAY); // Debounce
}

// Signal handler for Ctrl+C (SIGINT)
void signalHandler(int signum) {
    if (signum == SIGINT) {
        printf("\nExiting program...\n");
        digitalWrite(LED_PIN, LOW); // Turn off the LED
        wiringPiSetup(); // Reset all pins to default state
        exit(0);
    }
}

int main(void) {
    // Set up signal handler for Ctrl+C
    signal(SIGINT, signalHandler);

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error initializing wiringPi!\n");
        return 1;
    }

    // Configure PIR sensor pin as input with pull-down resistor
    pinMode(PIR_PIN, INPUT);
    pullUpDnControl(PIR_PIN, PUD_DOWN);

    // Configure LED pin as output
    pinMode(LED_PIN, OUTPUT);
    digitalWrite(LED_PIN, LOW); // Initialize LED to off state

    // Attach interrupt handler to PIR sensor pin
    if (wiringPiISR(PIR_PIN, INT_EDGE_RISING, toggleLed) < 0) {
        fprintf(stderr, "Error attaching interrupt!\n");
        return 1;
    }

    printf("Health Monitoring System running. Press Ctrl+C to exit.\n");

    // Main loop (do nothing, interrupt handler does the work)
    while (1) {
        delay(1000); // Sleep for 1 second
    }

    return 0;
}

