    int lastButtonState = HIGH;

    while (1) {
        buttonState = digitalRead(BUTTON_PIN);

        // Detect button press (transition from HIGH to LOW)
        if (buttonState == LOW && lastButtonState == HIGH) {
            // Toggle the digit
            if (currentDigit == 1) {
                currentDigit = 7;
            } else {
                currentDigit = 1;
            }
            displayDigit(currentDigit);
            delay(50); // Debounce delay
        }

