    int handle, raw_value, moisture_percentage = -1; // Initialize to -1 for error checking
    unsigned char spi_data[3];

    // MCP3008 configuration: Start bit (1), single-ended mode (1), channel 0 (000), don't care (0)
    spi_data[0] = 0x01; // Start bit
    spi_data[1] = 0x80; // Single-ended, channel 0
    spi_data[2] = 0x00; // Don't care

    handle = spiOpen(SPI_CHANNEL, 100000, 0); // Open SPI channel (CE0), 100kHz, mode 0
    if (handle < 0) {
        log_event("ERROR: Failed to open SPI channel", 0);
        return -1; // Indicate error
    }

    if (spiXfer(handle, spi_data, spi_data, 3) == 3) {
        raw_value = ((spi_data[1] & 0x03) << 8) + spi_data[2]; // Extract 10-bit ADC value

        // Simple linear conversion (adjust based on sensor calibration)
        moisture_percentage = 100 - (int)(((float)raw_value / 1023.0) * 100.0);
        if (moisture_percentage < 0) moisture_percentage = 0;
        if (moisture_percentage > 100) moisture_percentage = 100;

    } else {
        log_event("ERROR: SPI communication failed", 0);
        moisture_percentage = -1; // Indicate error
    }

    spiClose(handle);
    return moisture_percentage;
}

// Function to control the water pump
void control_pump(int state) {
    gpioWrite(PUMP_PIN, state); // HIGH to turn ON, LOW to turn OFF
}

// Function to log events to a file
void log_event(const char *event, int duration) {
    FILE *fp = fopen("watering_log.txt", "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(fp, "%d-%02d-%02d %02d:%02d:%02d - %s - Duration: %d seconds\n",
            tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, event, duration);
    fclose(fp);
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set pump pin as output
    gpioSetMode(PUMP_PIN, PI_OUTPUT);

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Smart Watering System started. Press Ctrl+C to exit.\n");

    while (program_running) {
        int moisture = read_soil_moisture();
        if (moisture == -1) {
            // SPI error, retry after a delay
            log_event("Retrying after SPI error", 0);
            sleep(SPI_RETRY_DELAY);
            continue; // Skip the rest of the loop and retry
        }

        printf("Soil Moisture: %d%%\n", moisture);

        if (moisture < MOISTURE_THRESHOLD) {
            printf("Moisture below threshold. Activating pump.\n");
            control_pump(1); // Turn pump ON
            log_event("Pump ACTIVATED", 0);
            time_t start_time = time(NULL);
            sleep(5); // Water for 5 seconds (adjust as needed)
            control_pump(0); // Turn pump OFF
            time_t end_time = time(NULL);
            int duration = (int)(end_time - start_time);
            log_event("Pump DEACTIVATED", duration);
        }

        sleep(60); // Check every 60 seconds (adjust as needed)
    }

    // Cleanup before exiting
    printf("Shutting down pump and terminating pigpio.\n");
    control_pump(0); // Ensure pump is OFF
    gpioTerminate();
    printf("Exiting.\n");
    return 0;
}

