#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>

// Define GPIO pins
#define TRIGGER_PIN 23
#define ECHO_PIN 24
#define SERVO_PIN 18

// Constants
#define SPEED_OF_SOUND 34300 // cm/s
#define MAX_DISTANCE 200     // cm
#define MIN_DISTANCE 20      // cm
#define MAX_ANGLE 180
#define MIN_ANGLE 0
#define TIMEOUT_US 30000      // Timeout for echo pulse in microseconds

// Global variables
static volatile int pulse_start = 0;
static volatile int pulse_end = 0;
static volatile int timeout_flag = 0;

// Function prototypes
float measure_distance();
int distance_to_angle(float distance);
int set_servo_angle(int angle);
void timeout_handler();
void signal_handler(int signal);

// Timeout handler function
void timeout_handler() {
    timeout_flag = 1;
}

// Interrupt handler for echo pin
void echo_callback(int gpio, int level, uint32_t tick) {
    if (level == 1) {
        pulse_start = tick;
        timeout_flag = 0; // Reset timeout flag on rising edge
        gpioSetTimerFuncEx(ECHO_PIN, TIMEOUT_US, timeout_handler, NULL); // Start timeout timer
    } else if (level == 0) {
        pulse_end = tick;
        gpioSetTimerFuncEx(ECHO_PIN, 0, NULL, NULL); // Disable timeout timer
    }
}

// Function to measure distance using HC-SR04
float measure_distance() {
    // Trigger the sensor
    gpioWrite(TRIGGER_PIN, 1);
    gpioDelay(10); // 10us trigger pulse
    gpioWrite(TRIGGER_PIN, 0);

    // Wait for the echo pulse
    pulse_start = 0;
    pulse_end = 0;
    timeout_flag = 0;

    // Wait until pulse_end has a value or timeout occurs
    while (pulse_end == 0 && timeout_flag == 0) {
        gpioDelay(1); // Small delay to prevent busy-waiting
    }

    if (timeout_flag == 1) {
        fprintf(stderr, "Error: HC-SR04 timeout\n");
        return -1.0; // Indicate error
    }

    // Calculate pulse duration
    int pulse_duration = pulse_end - pulse_start;
    if (pulse_duration <= 0) {
        fprintf(stderr, "Error: Invalid pulse duration\n");
        return -1.0; // Indicate error
    }

    // Calculate distance
    float distance = (pulse_duration * SPEED_OF_SOUND) / 2000000.0; // in cm

    return distance;
}

// Function to map distance to servo angle
int distance_to_angle(float distance) {
    int angle = 0;

    if (distance < 0.0) {
        return -1; // error
    }

    if (distance > MAX_DISTANCE) {
        angle = MIN_ANGLE; // Far away
    } else if (distance < MIN_DISTANCE) {
        angle = MAX_ANGLE; // Very close
    } else {
        // Linear mapping
        angle = (int)(((distance - MIN_DISTANCE) / (MAX_DISTANCE - MIN_DISTANCE)) * (MIN_ANGLE - MAX_ANGLE) + MAX_ANGLE);
    }

    // Ensure angle is within safe limits
    if (angle < MIN_ANGLE) {
        angle = MIN_ANGLE;
    } else if (angle > MAX_ANGLE) {
        angle = MAX_ANGLE;
    }

    return angle;
}

// Function to set servo angle
int set_servo_angle(int angle) {
    if (angle < MIN_ANGLE || angle > MAX_ANGLE) {
        fprintf(stderr, "Error: Servo angle out of range\n");
        return -1; // Indicate error
    }

    gpioServo(SERVO_PIN, angle * 1000 / 180 + 500); // Convert angle to pulse width (500-2500)
    return 0;
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, cleaning up...\n", signal);
    gpioServo(SERVO_PIN, 0); // Disable servo
    gpioTerminate();        // Terminate pigpio
    exit(0);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);
    gpioSetMode(SERVO_PIN, PI_OUTPUT);

    // Set pull-down resistor on echo pin
    gpioSetPullUpDown(ECHO_PIN, PI_PUD_DOWN);

    // Register interrupt handler for echo pin
    gpioSetAlertFunc(ECHO_PIN, echo_callback);

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Parking assist system started. Press Ctrl+C to exit.\n");

    // Main loop
    while (1) {
        float distance = measure_distance();

        if (distance > 0) {
            printf("Distance: %.2f cm\n", distance);
            int angle = distance_to_angle(distance);

            if (angle >= 0) {
                if (set_servo_angle(angle) == 0) {
                    printf("Servo angle: %d degrees\n", angle);
                } else {
                    fprintf(stderr, "Error: Failed to set servo angle\n");
                }
            } else {
                fprintf(stderr, "Error: Invalid angle conversion\n");
            }
        } else {
            fprintf(stderr, "Error: Failed to measure distance\n");
        }

        gpioDelay(200); // Delay between measurements
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <pigpio.h>
#include <unistd.h>
#include <string.h>
#include <fcntl.h>
#include <termios.h>

// MCP3008 definitions
#define SPI_CHANNEL 0
#define ADC_CHANNEL 0  // Single-ended channel 0

// Serial port definitions
#define SERIAL_PORT "/dev/ttyAMA0" // Or /dev/ttyS0 for newer Pis
#define BAUD_RATE B115200

int spi_handle;
int serial_fd;

// Function to initialize the serial port
int serial_init()
{
    serial_fd = open(SERIAL_PORT, O_RDWR | O_NOCTTY | O_NDELAY);
    if (serial_fd == -1) {
        perror("Error opening serial port");
        return -1;
    }

    struct termios tty;
    memset(&tty, 0, sizeof(tty));
    if (tcgetattr(serial_fd, &tty) != 0) {
        perror("Error getting serial attributes");
        close(serial_fd); // Close before exiting
        return -1;
    }

    cfsetospeed(&tty, BAUD_RATE);
    cfsetispeed(&tty, BAUD_RATE);

    tty.c_cflag |= (CLOCAL | CREAD);
    tty.c_cflag &= ~PARENB;
    tty.c_cflag &= ~CSTOPB;
    tty.c_cflag &= ~CSIZE;
    tty.c_cflag |= CS8;
    tty.c_lflag &= ~ICANON;      // disable canonical mode
    tty.c_lflag &= ~ECHO;         // disable echo
    tty.c_lflag &= ~ECHOE;        // disable erasure
    tty.c_lflag &= ~ECHONL;       // disable new-line echo
    tty.c_lflag &= ~ISIG;         // disable SIGINTR, SIGQUIT, SIGTSTP, and SIGTTIN signals
    tty.c_iflag &= ~(IXON | IXOFF | IXANY);
    tty.c_oflag &= ~OPOST;       // disable pre-processing

    tty.c_cc[VMIN] = 0;            // read doesn't block
    tty.c_cc[VTIME] = 5;           // 0.5 seconds read timeout

    if (tcsetattr(serial_fd, TCSANOW, &tty) != 0) {
        perror("Error setting serial attributes");
        close(serial_fd);
        return -1;
    }

    return 0;
}

// Function to read from MCP3008
int read_mcp3008(int channel)
{
    unsigned char tx_buffer[3];
    unsigned char rx_buffer[3];

    // Construct SPI message
    tx_buffer[0] = 0x01;                           // Start bit
    tx_buffer[1] = ((channel << 4) | 0x80);    // Single-ended mode, channel selection
    tx_buffer[2] = 0x00;                           // Don't care

    spiXfer(spi_handle, tx_buffer, rx_buffer, 3);

    // Extract ADC value (10 bits)
    int adc_value = ((rx_buffer[1] & 0x03) << 8) + rx_buffer[2];
    return adc_value;
}

int main()
{
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Initialize SPI
    spi_handle = spiOpen(SPI_CHANNEL, 1000000, 0); // Channel 0, 1MHz, mode 0
    if (spi_handle < 0) {
        fprintf(stderr, "SPI initialisation failed\n");
        gpioTerminate();
        return 1;
    }

    // Initialize Serial Port
    if (serial_init() < 0) {
        fprintf(stderr, "Serial port initialisation failed\n");
        spiClose(spi_handle);
        gpioTerminate();
        return 1;
    }

    while (1) {
        // Read ADC value
        int adc_value = read_mcp3008(ADC_CHANNEL);

        // Print to serial port
        char buffer[32];
        snprintf(buffer, sizeof(buffer), "%d\r\n", adc_value);
        write(serial_fd, buffer, strlen(buffer));

        // Wait 100ms
        gpioDelay(100);
    }

    // Cleanup (never reached in this example)
    close(serial_fd);
    spiClose(spi_handle);
    gpioTerminate();
    return 0;
}

