    // Initialize WiringPi using BCM GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "ERROR: Unable to initialize WiringPi: %s\n", strerror(errno));
        return 1; // Indicate failure
    }

