// MCP3008 Configuration
#define SPI_CHANNEL 0
#define MCP3008_CHANNELS 8

// Function to read from MCP3008 channel
int readMCP3008(int channel)
{
    if (channel < 0 || channel > 7)
    {
        printf("Invalid MCP3008 channel: %d\n", channel);
        return -1; // Indicate error
    }

    uint8_t buffer[3];
    buffer[0] = 0x01;                                       // Start bit
    buffer[1] = (0x08 | channel) << 4;                       // SGL/DIFF bit + Channel selection
    buffer[2] = 0x00;

    wiringPiSPIDataRW(SPI_CHANNEL, buffer, 3);

    int adcValue = ((buffer[1] & 0x03) << 8) + buffer[2]; // Extract value (10 bits)

    return adcValue;
}

int main(void)
{
    // Initialize wiringPi with SPI mode
    if (wiringPiSetup() == -1)
    {
        fprintf(stderr, "wiringPiSetup failed\n");
        return 1;
    }

    // Initialize SPI
    if (wiringPiSPISetup(SPI_CHANNEL, 1000000) == -1)
    {
        fprintf(stderr, "wiringPiSPISetup failed\n");
        return 1;
    }

    // Main loop
    while (1)
    {
        // Get current timestamp
        time_t rawtime;
        struct tm *timeinfo;
        char timestamp[80];

        time(&rawtime);
        timeinfo = localtime(&rawtime);

        strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

        // Read and print all channels
        printf("%s: ", timestamp);
        for (int i = 0; i < MCP3008_CHANNELS; i++)
        {
            int adcValue = readMCP3008(i);
            if(adcValue != -1) {
                printf("CH%d=%d ", i, adcValue);
            } else {
                printf("CH%d=Error ", i);
            }

        }
        printf("\n");

        delay(1000); // Sample every 1 second
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <wiringPi.h>
#include <math.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// LSM303AGR I2C address
#define LSM303AGR_ADDR 0x19

// LSM303AGR register addresses
#define LSM303AGR_CTRL_REG1_A 0x20
#define LSM303AGR_OUT_X_L_A 0x28
#define LSM303AGR_OUT_X_H_A 0x29
#define LSM303AGR_OUT_Y_L_A 0x2A
#define LSM303AGR_OUT_Y_H_A 0x2B
#define LSM303AGR_OUT_Z_L_A 0x2C
#define LSM303AGR_OUT_Z_H_A 0x2D

// GPIO pin for the buzzer
#define BUZZER_PIN 27

// Impact threshold (2g in m/s^2)
#define IMPACT_THRESHOLD 19.6

// Scale factor for accelerometer data (mg/LSB) at +/- 2g
#define ACCEL_SCALE_FACTOR 0.061 // mg/LSB

// I2C file descriptor
int i2c_fd = -1;

// File pointer for the log file
FILE *log_file = NULL;

// Signal handler flag
volatile sig_atomic_t terminate = 0;

// Function to handle signals (SIGINT, SIGTERM)
void signal_handler(int sig) {
    printf("Caught signal %d, cleaning up...\n", sig);
    terminate = 1;
}

// Function to write a byte to an I2C register
int i2c_write_reg(int fd, uint8_t reg, uint8_t value) {
    uint8_t buf[2];
    buf[0] = reg;
    buf[1] = value;
    if (write(fd, buf, 2) != 2) {
        perror("Failed to write to I2C device");
        return -1;
    }
    return 0;
}

// Function to read multiple bytes from an I2C register
int i2c_read_regs(int fd, uint8_t reg, uint8_t *buf, int len) {
    if (write(fd, &reg, 1) != 1) {
        perror("Failed to write to I2C device");
        return -1;
    }
    if (read(fd, buf, len) != len) {
        perror("Failed to read from I2C device");
        return -1;
    }
    return 0;
}

// Function to initialize the LSM303AGR accelerometer
int init_lsm303agr(int fd) {
    // Enable accelerometer, 100Hz ODR, high-resolution mode
    if (i2c_write_reg(fd, LSM303AGR_CTRL_REG1_A, 0x77) != 0) {
        fprintf(stderr, "Failed to initialize LSM303AGR\n");
        return -1;
    }
    delay(10); // Add a small delay after initialization
    return 0;
}

// Function to read acceleration data from the LSM303AGR
int read_acceleration(int fd, float *x, float *y, float *z) {
    uint8_t buf[6];

    // Read X, Y, and Z acceleration data
    if (i2c_read_regs(fd, LSM303AGR_OUT_X_L_A, buf, 6) != 0) {
        fprintf(stderr, "Failed to read acceleration data\n");
        return -1;
    }

    // Combine high and low bytes, and convert to mg
    int16_t x_raw = (int16_t)((buf[1] << 8) | buf[0]);
    int16_t y_raw = (int16_t)((buf[3] << 8) | buf[2]);
    int16_t z_raw = (int16_t)((buf[5] << 8) | buf[4]);

    *x = (float)x_raw * ACCEL_SCALE_FACTOR;
    *y = (float)y_raw * ACCEL_SCALE_FACTOR;
    *z = (float)z_raw * ACCEL_SCALE_FACTOR;

    return 0;
}

// Function to calculate the magnitude of the acceleration vector
float calculate_magnitude(float x, float y, float z) {
    return sqrt(x * x + y * y + z * z) * 9.81 / 1000.0; // Convert mg to m/s^2
}

// Function to trigger the buzzer
void trigger_buzzer(int pin) {
    digitalWrite(pin, HIGH);
    delay(500); // 0.5 seconds
    digitalWrite(pin, LOW);
}

// Function to log the impact event
int log_impact(FILE *fp) {
    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char s[64];

    if (strftime(s, sizeof(s), "%Y-%m-%d %H:%M:%S", tm) == 0) {
        fprintf(stderr, "Failed to format time\n");
        return -1;
    }

    fprintf(fp, "%s: Impact detected!\n", s);
    fflush(fp); // Flush the buffer to ensure immediate write
    return 0;
}

int main() {
    // Install signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Failed to initialize wiringPi\n");
        return 1;
    }

    // Set buzzer pin as output
    pinMode(BUZZER_PIN, OUTPUT);
    digitalWrite(BUZZER_PIN, LOW); // Ensure buzzer is initially off

    // Open I2C device
    i2c_fd = open("/dev/i2c-1", O_RDWR);
    if (i2c_fd < 0) {
        perror("Failed to open I2C device");
        return 1;
    }

    // Specify the address of the slave device
    if (ioctl(i2c_fd, I2C_SLAVE, LSM303AGR_ADDR) < 0) {
        perror("Failed to acquire bus access and/or talk to slave");
        close(i2c_fd);
        return 1;
    }

    // Initialize the LSM303AGR accelerometer
    if (init_lsm303agr(i2c_fd) != 0) {
        fprintf(stderr, "LSM303AGR initialization failed\n");
        close(i2c_fd);
        return 1;
    }

    // Open the log file
    log_file = fopen("impact_log.txt", "a");
    if (log_file == NULL) {
        perror("Failed to open log file");
        close(i2c_fd);
        return 1;
    }

    printf("Impact detection started. Press Ctrl+C to exit.\n");

    float x, y, z, magnitude;

    while (!terminate) {
        // Read acceleration data
        if (read_acceleration(i2c_fd, &x, &y, &z) == 0) {
            // Calculate the magnitude of the acceleration vector
            magnitude = calculate_magnitude(x, y, z);

            // Check for impact
            if (magnitude > IMPACT_THRESHOLD) {
                printf("Impact detected! Magnitude: %.2f m/s^2\n", magnitude);

                // Trigger the buzzer
                trigger_buzzer(BUZZER_PIN);

                // Log the impact event
                if (log_impact(log_file) != 0) {
                    fprintf(stderr, "Failed to log impact\n");
                }
            }
        } else {
            fprintf(stderr, "Failed to read acceleration data\n");
        }

        delay(100); // Delay to avoid overwhelming the I2C bus
    }

    // Cleanup
    printf("Cleaning up resources...\n");
    if (i2c_fd != -1) {
        close(i2c_fd);
    }
    if (log_file != NULL) {
        fclose(log_file);
    }
    digitalWrite(BUZZER_PIN, LOW); // Ensure buzzer is off

    printf("Exiting.\n");
    return 0;
}

