void control_fan(float lpg_ppm);
void log_data(int adc_value, float lpg_ppm);
void handle_error(const char *message);
void cleanup();

FILE *log_file = NULL;

int main()
{
    // Initialize wiringPi using GPIO numbering
    if (wiringPiSetupGpio() == -1)
    {
        fprintf(stderr, "wiringPiSetupGpio failed: %s\n", strerror(errno));
        return 1;
    }

    // Initialize SPI
    if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) == -1)
    {
        fprintf(stderr, "wiringPiSPISetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Configure the fan GPIO pin as output
    pinMode(FAN_GPIO, OUTPUT);

    // Open the log file in append mode
    log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL)
    {
        fprintf(stderr, "Failed to open log file: %s\n", strerror(errno));
        return 1;
    }

    // Log file header
    fprintf(log_file, "Timestamp,ADC Value,PPM\n");

    // Main loop
    while (1)
    {
        // Read the MQ-6 sensor value
        int adc_value = read_mq6_sensor();

        // Convert the ADC value to PPM
        float lpg_ppm = convert_adc_to_ppm(adc_value);

        // Control the ventilation fan
        control_fan(lpg_ppm);

        // Log the data if the LPG concentration exceeds the threshold
        if (lpg_ppm > THRESHOLD_PPM)
        {
            log_data(adc_value, lpg_ppm);
        }

        // Wait for 1 second
        delay(1000);
    }

    // Cleanup (this part will not be reached in the infinite loop)
    cleanup();

    return 0;
}

// Function to read the MQ-6 sensor value from the MCP3008 ADC
int read_mq6_sensor()
{
    unsigned char buffer[3];
    int adc_value;

    // Build the SPI request: start bit, single-ended mode, channel number (MQ6_CHANNEL), don't care bit
    buffer[0] = 0x01;                           // Start bit
    buffer[1] = (0x08 | (MQ6_CHANNEL << 4)) << 4; // Single-ended, channel 0
    buffer[2] = 0x00;                           // Don't care

    // Transfer the data via SPI
    wiringPiSPIDataRW(SPI_CHANNEL, buffer, 3);

    // Extract the ADC value from the response
    adc_value = ((buffer[1] & 0x03) << 8) + buffer[2];

    return adc_value;
}

// Function to convert the ADC value to PPM
float convert_adc_to_ppm(int adc_value)
{
    return (adc_value / 1023.0) * MAX_PPM;
}

// Function to control the ventilation fan
void control_fan(float lpg_ppm)
{
    if (lpg_ppm > THRESHOLD_PPM)
    {
        digitalWrite(FAN_GPIO, HIGH); // Turn the fan on
        printf("Fan ON (PPM: %.2f)\n", lpg_ppm);
    }
    else
    {
        digitalWrite(FAN_GPIO, LOW); // Turn the fan off
        printf("Fan OFF (PPM: %.2f)\n", lpg_ppm);
    }
}

// Function to log the data to a file
void log_data(int adc_value, float lpg_ppm)
{
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[26];
    strftime(timestamp, sizeof(timestamp) - 1, "%Y-%m-%d %H:%M:%S", t);

    if (log_file != NULL)
    {
        fprintf(log_file, "%s,%d,%.2f\n", timestamp, adc_value, lpg_ppm);
        fflush(log_file); // Flush the buffer to ensure data is written immediately
        printf("Logged: %s, ADC: %d, PPM: %.2f\n", timestamp, adc_value, lpg_ppm);
    }
    else
    {
        handle_error("Log file is not open.");
    }
}

// Function to handle errors
void handle_error(const char *message)
{
    fprintf(stderr, "Error: %s\n", message);

    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[26];
    strftime(timestamp, sizeof(timestamp) - 1, "%Y-%m-%d %H:%M:%S", t);

    if (log_file != NULL)
    {
        fprintf(log_file, "%s,ERROR,%s\n", timestamp, message);
        fflush(log_file);
    }

    cleanup(); // Attempt cleanup before exiting
    exit(1);   // Exit the program
}

// Function to perform cleanup tasks
void cleanup()
{
    if (log_file != NULL)
    {
        fclose(log_file);
    }
    digitalWrite(FAN_GPIO, LOW); // Ensure fan is off during cleanup
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>

// Define GPIO pins for RGB LED (common anode)
#define RED_PIN   17
#define GREEN_PIN 18
#define BLUE_PIN  27

// Define temperature file path
#define TEMP_FILE "/sys/class/thermal/thermal_zone0/temp"

// Default temperature in case of read error
#define DEFAULT_TEMP 40.0

// Structure to represent RGB color
typedef struct {
    int red;
    int green;
    int blue;
} RGBColor;

// Global variable to indicate program termination
volatile sig_atomic_t program_running = 1;

// Signal handler for SIGINT (Ctrl+C)
void signal_handler(int signal) {
    if (signal == SIGINT) {
        program_running = 0;
        printf("\nCaught SIGINT, exiting gracefully...\n");
    }
}

/**
 * @brief Reads the CPU temperature from the specified file.
 * @param file_path The path to the temperature file.
 * @return The temperature in Celsius, or DEFAULT_TEMP on error.
 */
double read_temperature(const char *file_path) {
    FILE *fp;
    char temp_str[10];
    int temp_raw;

    fp = fopen(file_path, "r");
    if (fp == NULL) {
        fprintf(stderr, "Error: Could not open temperature file %s\n", file_path);
        return DEFAULT_TEMP;
    }

    if (fgets(temp_str, sizeof(temp_str), fp) == NULL) {
        fprintf(stderr, "Error: Could not read temperature from file %s\n", file_path);
        fclose(fp);
        return DEFAULT_TEMP;
    }

    fclose(fp);

    temp_raw = atoi(temp_str);
    return (double)temp_raw / 1000.0; // Convert to Celsius
}

/**
 * @brief Maps a temperature value to an RGB color.
 * @param temperature The temperature in Celsius.
 * @return An RGBColor struct representing the color.
 */
RGBColor map_temperature_to_color(double temperature) {
    RGBColor color;

    // Define temperature ranges and corresponding colors
    // Example: 20-30: Blue -> Green, 30-40: Green -> Yellow, 40-50: Yellow -> Red
    if (temperature <= 20.0) {
        // Clamped to blue
        color.red = 0;
        color.green = 0;
        color.blue = 255;
    } else if (temperature > 20.0 && temperature <= 30.0) {
        // Blue to Green
        double fraction = (temperature - 20.0) / 10.0;
        color.red = 0;
        color.green = (int)(255 * fraction);
        color.blue = 255 - (int)(255 * fraction);
    } else if (temperature > 30.0 && temperature <= 40.0) {
        // Green to Yellow
        double fraction = (temperature - 30.0) / 10.0;
        color.red = (int)(255 * fraction);
        color.green = 255;
        color.blue = 0 + (int)(0 * fraction);
    } else if (temperature > 40.0 && temperature <= 50.0) {
        // Yellow to Red
        double fraction = (temperature - 40.0) / 10.0;
        color.red = 255;
        color.green = 255 - (int)(255 * fraction);
        color.blue = 0;
    } else {
        // Clamped to red
        color.red = 255;
        color.green = 0;
        color.blue = 0;
    }

    return color;
}

/**
 * @brief Sets the color of the RGB LED using PWM.
 * @param red The red component (0-255).
 * @param green The green component (0-255).
 * @param blue The blue component (0-255).
 */
void set_led_color(int red, int green, int blue) {
    // Common anode, so invert the PWM duty cycle
    gpioPWM(RED_PIN, 255 - red);
    gpioPWM(GREEN_PIN, 255 - green);
    gpioPWM(BLUE_PIN, 255 - blue);
}

int main() {
    // Install signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pins to output mode
    gpioSetMode(RED_PIN, PI_OUTPUT);
    gpioSetMode(GREEN_PIN, PI_OUTPUT);
    gpioSetMode(BLUE_PIN, PI_OUTPUT);

    printf("Mood lighting system started. Press Ctrl+C to exit.\n");

    while (program_running) {
        // Read CPU temperature
        double temperature = read_temperature(TEMP_FILE);
        printf("CPU Temperature: %.2f °C\n", temperature);

        // Map temperature to RGB color
        RGBColor color = map_temperature_to_color(temperature);
        printf("RGB Color: R=%d, G=%d, B=%d\n", color.red, color.green, color.blue);

        // Set LED color
        set_led_color(color.red, color.green, color.blue);

        // Sleep for 1 second
        sleep(1);
    }

    // Stop PWM and terminate pigpio
    gpioPWM(RED_PIN, 0);
    gpioPWM(GREEN_PIN, 0);
    gpioPWM(BLUE_PIN, 0);
    gpioTerminate();

    printf("Program terminated.\n");
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/spi/spidev.h>
#include <errno.h>
#include <string.h>
#include <time.h>

// SPI device definitions
#define SPI_DEVICE "/dev/spidev0.0"
#define SPI_MODE SPI_MODE_0
#define SPI_BITS_PER_WORD 8
#define SPI_SPEED 1000000 // 1 MHz

int spi_fd;

// Function to initialize SPI
int spi_init()
{
    spi_fd = open(SPI_DEVICE, O_RDWR);
    if (spi_fd < 0) {
        perror("Error opening SPI device");
        return -1;
    }

    // Set SPI mode
    uint8_t mode = SPI_MODE;
    if (ioctl(spi_fd, SPI_IOC_WR_MODE, &mode) == -1) {
        perror("Error setting SPI mode");
        close(spi_fd);
        return -1;
    }

    // Set bits per word
    uint8_t bits = SPI_BITS_PER_WORD;
    if (ioctl(spi_fd, SPI_IOC_WR_BITS_PER_WORD, &bits) == -1) {
        perror("Error setting bits per word");
        close(spi_fd);
        return -1;
    }

    // Set SPI speed
    uint32_t speed = SPI_SPEED;
    if (ioctl(spi_fd, SPI_IOC_WR_MAX_SPEED_HZ, &speed) == -1) {
        perror("Error setting SPI speed");
        close(spi_fd);
        return -1;
    }

    return 0;
}

// Function to read ADC value from MCP3008
int read_adc(int channel)
{
    uint8_t tx_buf[3];
    uint8_t rx_buf[3];
    struct spi_ioc_transfer transfer[1];

    // Construct SPI message
    tx_buf[0] = 0x01; // Start bit
    tx_buf[1] = (0x08 | (channel & 0x07)) << 4; // Single-ended mode, channel select
    tx_buf[2] = 0x00;

    transfer[0].tx_buf = (unsigned long)tx_buf;
    transfer[0].rx_buf = (unsigned long)rx_buf;
    transfer[0].len = 3;
    transfer[0].delay_usecs = 0;
    transfer[0].speed_hz = SPI_SPEED;
    transfer[0].bits_per_word = SPI_BITS_PER_WORD;
    transfer[0].cs_change = 0;

    // Transfer the SPI message
    if (ioctl(spi_fd, SPI_IOC_MESSAGE(1), transfer) < 1) {
        perror("Error during SPI transfer");
        return -1;
    }

    // Extract ADC value
    int adc_value = ((rx_buf[1] & 0x03) << 8) + rx_buf[2];
    return adc_value;
}

int main()
{
    // Initialize SPI
    if (spi_init() < 0) {
        fprintf(stderr, "SPI initialization failed. Exiting.\n");
        return 1;
    }

    // Main loop
    while (1) {
        // Read ADC channel 0
        int adc_value = read_adc(0);

        if (adc_value < 0) {
            fprintf(stderr, "Error reading ADC value.\n");
            close(spi_fd);
            return 1;
        }

        // Print ADC value to standard output (serial)
        printf("%d\n", adc_value);
        fflush(stdout); // Ensure immediate output

        // Delay for 10ms
        struct timespec delay;
        delay.tv_sec = 0;
        delay.tv_nsec = 10000000; // 10ms
        nanosleep(&delay, NULL);
    }

    // Close SPI device (should not be reached in this example)
    close(spi_fd);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <wiringPi.h>
#include <softPwm.h>
#include <errno.h>

// Define GPIO pins using BCM numbering
#define LED1_PIN 17  // BCM GPIO 17
#define LED2_PIN 27  // BCM GPIO 27
#define TILT_SENSOR_PIN 18 // BCM GPIO 18

// Constants for PWM range
#define PWM_RANGE 100

// Function prototypes
int initialize_gpio(void);
void handle_tilt_sensor(int *led1_brightness, int *led2_brightness);

int main(void) {
    int led1_brightness = 50; // Initial brightness for LED1
    int led2_brightness = 50; // Initial brightness for LED2
    int tilt_state;

    // Initialize wiringPi and softPwm
    if (initialize_gpio() != 0) {
        fprintf(stderr, "GPIO initialization failed. Exiting.\n");
        return EXIT_FAILURE;
    }

    printf("Ball Tilt Sensor with LED Control\n");
    printf("Press Ctrl+C to exit.\n");

    // Main loop
    while (1) {
        handle_tilt_sensor(&led1_brightness, &led2_brightness);
        delay(50); // Delay for stability
    }

    return EXIT_SUCCESS;
}

// Initializes wiringPi and configures GPIO pins.
int initialize_gpio(void) {
    if (wiringPiSetupGpio() == -1) { // Use BCM GPIO numbering
        fprintf(stderr, "wiringPiSetupGpio failed: %s\n", strerror(errno));
        return -1;
    }

    // Configure LED pins as PWM outputs
    if (softPwmCreate(LED1_PIN, 0, PWM_RANGE) != 0) {
        fprintf(stderr, "softPwmCreate for LED1 failed: %s\n", strerror(errno));
        return -1;
    }
    if (softPwmCreate(LED2_PIN, 0, PWM_RANGE) != 0) {
        fprintf(stderr, "softPwmCreate for LED2 failed: %s\n", strerror(errno));
        return -1;
    }

    // Configure tilt sensor pin as input with pull-up resistor
    pinMode(TILT_SENSOR_PIN, INPUT);
    pullUpDnControl(TILT_SENSOR_PIN, PUD_UP); // Enable pull-up resistor

    return 0;
}

// Handles the tilt sensor input and adjusts LED brightness accordingly.
void handle_tilt_sensor(int *led1_brightness, int *led2_brightness) {
    int tilt_state = digitalRead(TILT_SENSOR_PIN);

    if (tilt_state == HIGH) { // Sensor is upright (pulled HIGH by resistor)
        (*led1_brightness)++;
        (*led2_brightness)--;
    } else { // Sensor is tilted (pulled LOW by the sensor)
        (*led1_brightness)--;
        (*led2_brightness)++;
    }

    // Clamp brightness values to the PWM range
    if (*led1_brightness > PWM_RANGE) {
        *led1_brightness = PWM_RANGE;
    }
    if (*led1_brightness < 0) {
        *led1_brightness = 0;
    }
    if (*led2_brightness > PWM_RANGE) {
        *led2_brightness = PWM_RANGE;
    }
    if (*led2_brightness < 0) {
        *led2_brightness = 0;
    }

    // Update PWM outputs
    softPwmWrite(LED1_PIN, *led1_brightness);
    softPwmWrite(LED2_PIN, *led2_brightness);
}

#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>
#define SSD1306_I2C_ADDR  0x3C
int i2c_fd;
void ssd1306_sendCommand(unsigned char command) {
    char buffer[2] = {0x00, command};
    i2cWriteDevice(i2c_fd, buffer, 2);
}
void ssd1306_init() {
    ssd1306_sendCommand(0xAE);
    ssd1306_sendCommand(0xAF);
}
void ssd1306_clearDisplay() {
    char buffer[1025] = {0x40};
    memset(buffer + 1, 0x00, 1024);
    i2cWriteDevice(i2c_fd, buffer, 1025);
}
void ssd1306_displayBatteryLevel(int level) {
    char buffer[130] = {0x40};
    char text[10];
    snprintf(text, sizeof(text), "Battery: %d%%", level);
    for (int i = 0; i < 10; i++) {
        buffer[(i * 6) + 1] = text[i];
    }
    i2cWriteDevice(i2c_fd, buffer, 130);
}
int main() {
    if (gpioInitialise() < 0) {
        printf("Failed to initialize!\n");
        return -1;
    }
    i2c_fd = i2cOpen(1, SSD1306_I2C_ADDR, 0);
    if (i2c_fd < 0) {
        printf("Failed to open I2C connection!\n");
        return -1;
    }
    ssd1306_init();
    for (int level = 0; level <= 100; level += 10) {
        ssd1306_clearDisplay();
        ssd1306_displayBatteryLevel(level);
        sleep(1);
    }
    i2cClose(i2c_fd);
    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <wiringPiI2C.h>
#include <wiringPi.h>
#include <errno.h>

// TCS34725 I2C address
#define TCS34725_ADDRESS 0x29

// TCS34725 Registers
#define TCS34725_ENABLE 0x80
#define TCS34725_ID 0x12
#define TCS34725_CDATAL 0x14
#define TCS34725_CDATAH 0x15
#define TCS34725_RDATAL 0x16
#define TCS34725_RDATAH 0x17
#define TCS34725_GDATAL 0x18
#define TCS34725_GDATAH 0x19
#define TCS34725_BDATAL 0x1A
#define TCS34725_BDATAH 0x1B

// Constants
#define PON 0x01
#define AEN 0x02
#define EPSILON 0.0001

// Function prototypes
int tcs34725_init(int fd);
int tcs34725_read_raw_data(int fd, unsigned int *r, unsigned int *g, unsigned int *b, unsigned int *c);
void tcs34725_calibrate(unsigned int r, unsigned int g, unsigned int b, unsigned int c, float *r_calibrated, float *g_calibrated, float *b_calibrated);
void detect_dominant_color(float r, float g, float b, char *dominant_color);
int write_data_to_json(float r, float g, float b, unsigned int c, const char *dominant_color, const char *filename);

int main()
{
    int fd;
    unsigned int r, g, b, c;
    float r_calibrated, g_calibrated, b_calibrated;
    char dominant_color[20];

    // Initialize wiringPi
    if (wiringPiSetup() == -1)
    {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Initialize I2C
    fd = wiringPiI2CSetup(TCS34725_ADDRESS);
    if (fd == -1)
    {
        fprintf(stderr, "wiringPiI2CSetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Initialize TCS34725 sensor
    if (tcs34725_init(fd) != 0)
    {
        fprintf(stderr, "TCS34725 initialization failed.\n");
        return 1;
    }

    printf("TCS34725 sensor initialized successfully.\n");

    // Main loop
    while (1)
    {
        // Read raw data
        if (tcs34725_read_raw_data(fd, &r, &g, &b, &c) != 0)
        {
            fprintf(stderr, "Error reading raw data.\n");
            continue; // Continue to the next iteration
        }

        // Calibrate data
        tcs34725_calibrate(r, g, b, c, &r_calibrated, &g_calibrated, &b_calibrated);

        // Detect dominant color
        detect_dominant_color(r_calibrated, g_calibrated, b_calibrated, dominant_color);

        // Write data to JSON file
        if (write_data_to_json(r_calibrated, g_calibrated, b_calibrated, c, dominant_color, "color_data.json") != 0)
        {
            fprintf(stderr, "Error writing data to JSON file.\n");
        }

        printf("Red: %.3f, Green: %.3f, Blue: %.3f, Clear: %u, Dominant Color: %s\n",
               r_calibrated, g_calibrated, b_calibrated, c, dominant_color);

        delay(100); // Delay for 100ms
    }

    return 0;
}

// Initialize TCS34725 sensor
int tcs34725_init(int fd)
{
    // Check sensor ID
    int id = wiringPiI2CReadReg8(fd, TCS34725_ID);
    if (id != 0x44)
    {
        fprintf(stderr, "Error: Invalid sensor ID (0x%02X)\n", id);
        return -1;
    }

    // Enable power and RGBCEN
    if (wiringPiI2CWriteReg8(fd, TCS34725_ENABLE, PON | AEN) == -1)
    {
        fprintf(stderr, "Error writing to ENABLE register: %s\n", strerror(errno));
        return -1;
    }

    return 0;
}

// Read raw RGBC data from TCS34725 sensor
int tcs34725_read_raw_data(int fd, unsigned int *r, unsigned int *g, unsigned int *b, unsigned int *c)
{
    *c = wiringPiI2CReadReg8(fd, TCS34725_CDATAL);
    *c |= (wiringPiI2CReadReg8(fd, TCS34725_CDATAH) << 8);

    *r = wiringPiI2CReadReg8(fd, TCS34725_RDATAL);
    *r |= (wiringPiI2CReadReg8(fd, TCS34725_RDATAH) << 8);

    *g = wiringPiI2CReadReg8(fd, TCS34725_GDATAL);
    *g |= (wiringPiI2CReadReg8(fd, TCS34725_GDATAH) << 8);

    *b = wiringPiI2CReadReg8(fd, TCS34725_BDATAL);
    *b |= (wiringPiI2CReadReg8(fd, TCS34725_BDATAH) << 8);

    return 0;
}

// Calibrate raw RGBC values
void tcs34725_calibrate(unsigned int r, unsigned int g, unsigned int b, unsigned int c, float *r_calibrated, float *g_calibrated, float *b_calibrated)
{
    float clear_float = (float)c;

    *r_calibrated = (float)r / (clear_float + EPSILON);
    *g_calibrated = (float)g / (clear_float + EPSILON);
    *b_calibrated = (float)b / (clear_float + EPSILON);

    // Clip values to [0.0, 1.0]
    if (*r_calibrated > 1.0) *r_calibrated = 1.0;
    if (*g_calibrated > 1.0) *g_calibrated = 1.0;
    if (*b_calibrated > 1.0) *b_calibrated = 1.0;
    if (*r_calibrated < 0.0) *r_calibrated = 0.0;
    if (*g_calibrated < 0.0) *g_calibrated = 0.0;
    if (*b_calibrated < 0.0) *b_calibrated = 0.0;
}

// Detect dominant color
void detect_dominant_color(float r, float g, float b, char *dominant_color)
{
    if (r > g && r > b)
    {
        strcpy(dominant_color, "Red");
    }
    else if (g > r && g > b)
    {
        strcpy(dominant_color, "Green");
    }
    else if (b > r && b > g)
    {
        strcpy(dominant_color, "Blue");
    }
    else
    {
        strcpy(dominant_color, "Unknown");
    }
}

// Write data to JSON file
int write_data_to_json(float r, float g, float b, unsigned int c, const char *dominant_color, const char *filename)
{
    FILE *fp = fopen(filename, "w");
    if (fp == NULL)
    {
        fprintf(stderr, "Error opening file: %s\n", strerror(errno));
        return -1;
    }

    fprintf(fp, "{\"red\": %.3f, \"green\": %.3f, \"blue\": %.3f, \"clear\": %u, \"dominant_color\": \"%s\"}\n",
            r, g, b, c, dominant_color);

    fclose(fp);
    return 0;
}

#include <wiringPi.h>
#include <stdio.h>
#define BUZZER 18 // BCM GPIO 18
#define BUTTON_ON 20 // BCM GPIO 20
#define BUTTON_OFF 21 // BCM GPIO 21

int main() {
    wiringPiSetupGpio();
    pinMode(BUZZER, OUTPUT);
    pinMode(BUTTON_ON, INPUT);
    pinMode(BUTTON_OFF, INPUT);
    pullUpDnControl(BUTTON_ON, PUD_UP);
    pullUpDnControl(BUTTON_OFF, PUD_UP);

    while (1) {
        if (digitalRead(BUTTON_ON) == 0) {
            digitalWrite(BUZZER, HIGH);
            printf("Buzzer ON\n");
        }
        if (digitalRead(BUTTON_OFF) == 0) {
            digitalWrite(BUZZER, LOW);
            printf("Buzzer OFF\n");
        }
        delay(100);
    }
    return 0;
}

