#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <wiringPi.h>
#include <unistd.h>
#include <time.h>

// Define GPIO pins using wiringPi numbering
#define PIR_PIN 17  // GPIO 17, wiringPi pin number
#define LED_PIN 18  // GPIO 18, wiringPi pin number

// Debounce time in milliseconds
#define DEBOUNCE_TIME 200

// Global variable to store the last interrupt time
static volatile unsigned long lastInterruptTime = 0;

// Function prototypes
int initializeGPIO();
void motionDetectedISR();
void toggleLED();
bool debounce();

int main()
{
    // Initialize wiringPi and GPIO pins
    if (initializeGPIO() != 0) {
        fprintf(stderr, "GPIO initialization failed. Exiting.\n");
        return 1;
    }

    printf("Motion detection program started. Press Ctrl+C to exit.\n");

    // Main loop to keep the program running
    while (1) {
        // Program does nothing in the main loop, interrupt driven
        delay(100); // Reduce CPU usage
    }

    return 0;
}

// Function to initialize GPIO pins using wiringPi
int initializeGPIO()
{
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPi initialization failed.\n");
        return -1;
    }

    // Set PIR pin as input
    pinMode(PIR_PIN, INPUT);

    // Set LED pin as output
    pinMode(LED_PIN, OUTPUT);

    // Initialize LED to off state
    digitalWrite(LED_PIN, LOW);

    // Set up interrupt on PIR pin, triggered on rising edge
    if (wiringPiISR(PIR_PIN, INT_EDGE_RISING, &motionDetectedISR) < 0) {
        fprintf(stderr, "Unable to setup ISR.\n");
        return -1;
    }

    return 0;
}

// Interrupt service routine (ISR) for motion detection
void motionDetectedISR()
{
    // Debounce the interrupt
    if (debounce()) {
        // Motion detected, toggle the LED
        toggleLED();
        printf("Motion detected!\n");
    }
}

// Function to toggle the LED state
void toggleLED()
{
    static bool ledState = false; // Keep track of the LED state

    ledState = !ledState; // Toggle the LED state
    digitalWrite(LED_PIN, ledState ? HIGH : LOW); // Set the LED pin to the new state
}

// Function to implement debouncing
bool debounce()
{
    unsigned long currentTime = millis(); // Get current time in milliseconds

    // Check if the time since the last interrupt is greater than the debounce time
    if (currentTime - lastInterruptTime > DEBOUNCE_TIME) {
        lastInterruptTime = currentTime; // Update the last interrupt time
        return true; // Valid interrupt
    }

    return false; // Ignore the interrupt
}

#include <stdio.h>
#include <wiringPi.h>
