// Define motor control pins (adjust these according to your wiring)
#define MOTOR1_PWM 18 // PWM pin for motor 1 (GPIO 18)
#define MOTOR1_IN1 23 // Input 1 for motor 1 (GPIO 23)
#define MOTOR1_IN2 24 // Input 2 for motor 1 (GPIO 24)

#define MOTOR2_PWM 12 // PWM pin for motor 2 (GPIO 12)
#define MOTOR2_IN1 16 // Input 1 for motor 2 (GPIO 16)
#define MOTOR2_IN2 20 // Input 2 for motor 2 (GPIO 20)


void motor_forward(int pwm_pin, int in1_pin, int in2_pin, int speed) {
    digitalWrite(in1_pin, HIGH);
    digitalWrite(in2_pin, LOW);
    softPwmWrite(pwm_pin, speed); // Adjust speed from 0-100
}

void motor_stop(int pwm_pin, int in1_pin, int in2_pin) {
    digitalWrite(in1_pin, LOW);
    digitalWrite(in2_pin, LOW);
    softPwmWrite(pwm_pin, 0);
}

int main() {
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi setup failed!\n");
        return 1;
    }

    // Setup motor control pins
    pinMode(MOTOR1_IN1, OUTPUT);
    pinMode(MOTOR1_IN2, OUTPUT);
    pinMode(MOTOR2_IN1, OUTPUT);
    pinMode(MOTOR2_IN2, OUTPUT);

    softPwmCreate(MOTOR1_PWM, 0, 100); // PWM range: 0-100
    softPwmCreate(MOTOR2_PWM, 0, 100);

    while (1) {
        // Move forward for 10 seconds
        printf("Motors moving forward...\n");
