        motor_forward(MOTOR2_PWM, MOTOR2_IN1, MOTOR2_IN2, 50);
        delay(10000); // 10 seconds

        // Stop for 5 seconds
        printf("Motors stopped...\n");
        motor_stop(MOTOR1_PWM, MOTOR1_IN1, MOTOR1_IN2);
        motor_stop(MOTOR2_PWM, MOTOR2_IN1, MOTOR2_IN2);
        delay(5000); // 5 seconds
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <time.h>
#include <signal.h>
#include <wiringPi.h>

// Define GPIO pins for RGB LED (Common Anode)
#define RED_PIN   17
#define GREEN_PIN 18
#define BLUE_PIN  19

// Define PWM range (0-1023 for wiringPi)
#define PWM_RANGE 1024

// Function prototypes
typedef struct {
    int red;
    int green;
    int blue;
} Color;

Color generateRandomColor();
void setLedColor(int red, int green, int blue);
void fadeToColor(Color targetColor);
void cleanupAndExit(int signal);

// Global variables for current color
Color currentColor = {0, 0, 0};

int main(int argc, char *argv[]) {
    // Initialize wiringPi using GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi. Please check permissions and wiring.\n");
        return 1; // Exit with error
    }

    // Seed the random number generator
    srand(time(NULL));

    // Set GPIO pins to PWM output mode
    pinMode(RED_PIN, PWM_OUTPUT);
    pinMode(GREEN_PIN, PWM_OUTPUT);
    pinMode(BLUE_PIN, PWM_OUTPUT);

    // Set PWM range
    pwmSetRange(PWM_RANGE);

    // Initialize signal handler for Ctrl+C
    signal(SIGINT, cleanupAndExit);

    // Main loop: Generate random colors and fade to them
    while (1) {
        Color targetColor = generateRandomColor();
        fadeToColor(targetColor);
        delay(5000); // Wait 5 seconds
    }

    return 0; // Should never reach here
}

// Function to generate a random RGB color
Color generateRandomColor() {
    Color color;
    color.red = rand() % PWM_RANGE;
    color.green = rand() % PWM_RANGE;
    color.blue = rand() % PWM_RANGE;
    return color;
}

// Function to set the RGB LED color using PWM
void setLedColor(int red, int green, int blue) {
    pwmWrite(RED_PIN, red);
    pwmWrite(GREEN_PIN, green);
    pwmWrite(BLUE_PIN, blue);
}

// Function to smoothly fade to a target color
void fadeToColor(Color targetColor) {
    int redDiff   = targetColor.red   - currentColor.red;
    int greenDiff = targetColor.green - currentColor.green;
    int blueDiff  = targetColor.blue  - currentColor.blue;

    int steps = 100; // Number of steps for fading

    float redStep   = (float)redDiff   / steps;
    float greenStep = (float)greenDiff / steps;
    float blueStep  = (float)blueDiff  / steps;

    for (int i = 0; i < steps; i++) {
        currentColor.red   += redStep;
        currentColor.green += greenStep;
        currentColor.blue  += blueStep;

        setLedColor(currentColor.red, currentColor.green, currentColor.blue);
        delay(10); // Delay for smooth fading
    }

    // Ensure the final color is exactly the target color
    setLedColor(targetColor.red, targetColor.green, targetColor.blue);
    currentColor = targetColor;
}

// Signal handler for Ctrl+C (SIGINT)
void cleanupAndExit(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);

    // Reset PWM outputs to 0 (turn off LED)
    pwmWrite(RED_PIN, 0);
    pwmWrite(GREEN_PIN, 0);
    pwmWrite(BLUE_PIN, 0);

    // Set GPIO pins back to input mode (safer)
    pinMode(RED_PIN, INPUT);
    pinMode(GREEN_PIN, INPUT);
    pinMode(BLUE_PIN, INPUT);

    exit(0); // Exit program
}

#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <stdint.h>
#include <stdbool.h>
#include <signal.h>
#include <errno.h>
#include <string.h>
#include <time.h>

#define I2C_BUS "/dev/i2c-1"
#define BH1750_ADDR 0x23
#define CONTINUOUS_HIGH_RES_MODE 0x10
#define GPIO_PIN 17
#define CIRCULAR_BUFFER_SIZE 60

// Circular buffer structure
typedef struct {
    float buffer[CIRCULAR_BUFFER_SIZE];
    int head;
    int tail;
    int count;
} CircularBuffer;

// Global variables
static int i2c_fd = -1;
static volatile sig_atomic_t keep_running = 1;

// Function prototypes
int init_i2c(void);
int init_gpio(void);
void cleanup_gpio(void);
float read_bh1750(int fd);
float raw_to_lux(uint16_t raw_value);
bool add_to_circular_buffer(CircularBuffer *cb, float value);
float calculate_average_lux(const CircularBuffer *cb);
float calculate_blink_rate(float average_lux);
void blink_led(float frequency);
void signal_handler(int signal);
void unexport_gpio(void);


// Initialize I2C communication
int init_i2c(void) {
    i2c_fd = open(I2C_BUS, O_RDWR);
    if (i2c_fd < 0) {
        perror("Error opening I2C bus");
        return -1;
    }

    if (ioctl(i2c_fd, I2C_SLAVE, BH1750_ADDR) < 0) {
        perror("Error setting I2C slave address");
        close(i2c_fd);
        return -1;
    }

    // Set continuous high-resolution mode
    char config_data[1] = {CONTINUOUS_HIGH_RES_MODE};
    if (write(i2c_fd, config_data, 1) != 1) {
        perror("Error setting BH1750 mode");
        close(i2c_fd);
        return -1;
    }

    return 0;
}

// Initialize GPIO
int init_gpio(void) {
    int fd;
    char buf[64];

    // Export GPIO
    fd = open("/sys/class/gpio/export", O_WRONLY);
    if (fd < 0) {
        perror("Error opening /sys/class/gpio/export");
        return -1;
    }
    snprintf(buf, sizeof(buf), "%d", GPIO_PIN);
    if (write(fd, buf, strlen(buf)) < 0) {
        perror("Error writing to /sys/class/gpio/export");
        close(fd);
        return -1;
    }
    close(fd);

    // Set GPIO direction to output
    snprintf(buf, sizeof(buf), "/sys/class/gpio/gpio%d/direction", GPIO_PIN);
    fd = open(buf, O_WRONLY);
    if (fd < 0) {
        perror("Error opening GPIO direction file");
        return -1;
    }
    if (write(fd, "out", 3) < 0) {
        perror("Error writing to GPIO direction file");
        close(fd);
        return -1;
    }
    close(fd);

    return 0;
}

// Cleanup GPIO
void cleanup_gpio(void) {
    unexport_gpio();
}

void unexport_gpio(void) {
    int fd;
    char buf[64];

    snprintf(buf, sizeof(buf), "%d", GPIO_PIN);
    fd = open("/sys/class/gpio/unexport", O_WRONLY);
    if (fd < 0) {
        perror("Error opening /sys/class/gpio/unexport");
        return;
    }
    if (write(fd, buf, strlen(buf)) < 0) {
        perror("Error writing to /sys/class/gpio/unexport");
    }
    close(fd);
}

// Read raw value from BH1750 sensor
float read_bh1750(int fd) {
    uint8_t buffer[2];
    if (read(fd, buffer, 2) != 2) {
        perror("Error reading from BH1750");
        return -1.0f; // Indicate error
    }

    uint16_t raw_value = (buffer[0] << 8) | buffer[1];
    return (float)raw_value;
}

// Convert raw value to lux
float raw_to_lux(uint16_t raw_value) {
    return (float)raw_value / 1.2f; // BH1750 lux calculation
}

// Add data to circular buffer
bool add_to_circular_buffer(CircularBuffer *cb, float value) {
    if (cb == NULL) return false;

    cb->buffer[cb->head] = value;
    cb->head = (cb->head + 1) % CIRCULAR_BUFFER_SIZE;

    if (cb->count < CIRCULAR_BUFFER_SIZE) {
        cb->count++;
    } else {
        cb->tail = (cb->tail + 1) % CIRCULAR_BUFFER_SIZE;
    }
    return true;
}

// Calculate average lux value from circular buffer
float calculate_average_lux(const CircularBuffer *cb) {
    if (cb == NULL || cb->count == 0) return 0.0f;

    float sum = 0.0f;
    for (int i = 0; i < cb->count; i++) {
        sum += cb->buffer[(cb->tail + i) % CIRCULAR_BUFFER_SIZE];
    }
    return sum / cb->count;
}

// Calculate LED blink rate based on average lux
float calculate_blink_rate(float average_lux) {
    // Scale lux value to blink rate (0.5 Hz to 5 Hz)
    // Assuming a reasonable lux range, adjust as needed
    float min_lux = 0.0f;
    float max_lux = 1000.0f; // Example max lux value
    float min_rate = 0.5f;
    float max_rate = 5.0f;

    if (average_lux < min_lux) return min_rate;
    if (average_lux > max_lux) return max_rate;

    return min_rate + (average_lux - min_lux) * (max_rate - min_rate) / (max_lux - min_lux);
}

// Blink LED with specified frequency
void blink_led(float frequency) {
    int fd;
    char buf[64];
    struct timespec on_time, off_time;

    // Calculate on and off times based on frequency
    long period_ns = (long)(1000000000.0 / (2.0 * frequency)); // Half period in nanoseconds
    on_time.tv_sec = 0;
    on_time.tv_nsec = period_ns;
    off_time.tv_sec = 0;
    off_time.tv_nsec = period_ns;

    snprintf(buf, sizeof(buf), "/sys/class/gpio/gpio%d/value", GPIO_PIN);
    fd = open(buf, O_WRONLY);
    if (fd < 0) {
        perror("Error opening GPIO value file");
        return;
    }

    // Turn LED on
    if (write(fd, "1", 1) < 0) {
        perror("Error writing to GPIO value file");
    }
    close(fd);
    nanosleep(&on_time, NULL);

    fd = open(buf, O_WRONLY);
    if (fd < 0) {
        perror("Error opening GPIO value file");
        return;
    }

    // Turn LED off
    if (write(fd, "0", 1) < 0) {
        perror("Error writing to GPIO value file");
    }
    close(fd);
    nanosleep(&off_time, NULL);
}

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("Ctrl+C pressed, exiting...\n");
        keep_running = 0;
    }
}

int main(void) {
    CircularBuffer lux_buffer = {{0.0f}, 0, 0, 0};
    float lux_value, average_lux, blink_rate;

    // Register signal handler
    signal(SIGINT, signal_handler);

    // Initialize I2C and GPIO
    if (init_i2c() != 0) {
        fprintf(stderr, "I2C initialization failed. Exiting.\n");
        return 1;
    }
    if (init_gpio() != 0) {
        fprintf(stderr, "GPIO initialization failed. Exiting.\n");
        close(i2c_fd);
        return 1;
    }

    printf("Ambient light sensor and LED control program started.\nPress Ctrl+C to exit.\n");

    while (keep_running) {
        // Read lux value from sensor
        lux_value = read_bh1750(i2c_fd);
        if (lux_value < 0.0f) {
            fprintf(stderr, "Error reading lux value. Retrying.\n");
            sleep(1); // Wait before retrying
            continue;
        }
        lux_value = raw_to_lux((uint16_t)lux_value);

        // Add lux value to circular buffer
        add_to_circular_buffer(&lux_buffer, lux_value);

        // Calculate average lux value
        average_lux = calculate_average_lux(&lux_buffer);

        // Calculate LED blink rate
        blink_rate = calculate_blink_rate(average_lux);

        // Blink LED
        blink_led(blink_rate);

    }

    // Cleanup and exit
    cleanup_gpio();
    close(i2c_fd);
    printf("Program exited.\n");
    return 0;
}

#include <wiringPi.h>
#include <stdio.h>
#define DELAY_TIME 200

int y[8] = {17, 18, 27, 22, 23, 24, 25, 4}; // BCM Y-direction pins
int x[8] = {5, 6, 13, 19, 26, 16, 20, 21}; // BCM X-direction pins

void setup() {
    wiringPiSetupGpio();
    for (int i = 0; i < 8; i++) {
        pinMode(y[i], OUTPUT);
        pinMode(x[i], OUTPUT);
    }
}

void clearMatrix() {
    for (int i = 0; i < 8; i++) {
        digitalWrite(y[i], LOW);
        digitalWrite(x[i], HIGH);
    }
}

void diagonalWave() {
    for (int step = 0; step < 8; step++) {
        clearMatrix();
        for (int i = 0; i <= step; i++) {
            digitalWrite(y[i], HIGH);
            digitalWrite(x[step - i], LOW);
        }
        delay(DELAY_TIME);
    }
}

int main() {
    setup();
    while (1) {
        diagonalWave();
    }
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <signal.h>
#include <errno.h>

// Define GPIO pins for the two motors
#define MOTOR1_GPIO 17
#define MOTOR2_GPIO 27

// Global variable to indicate program termination
volatile sig_atomic_t program_running = 1;

// Signal handler for SIGINT (Ctrl+C)
void signal_handler(int signum) {
    if (signum == SIGINT) {
        program_running = 0;
        printf("\nCaught SIGINT, exiting gracefully...\n");
    }
}

// Function to export a GPIO pin
int gpio_export(int pin) {
    char buffer[64];
    int len;
    FILE *fp;

    fp = fopen("/sys/class/gpio/export", "w");
    if (fp == NULL) {
        perror("Failed to open /sys/class/gpio/export for writing");
        return -1;
    }
    len = snprintf(buffer, sizeof(buffer), "%d", pin);
    if (fwrite(buffer, 1, len, fp) != len) {
        perror("Failed to write to /sys/class/gpio/export");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return 0;
}

// Function to unexport a GPIO pin
int gpio_unexport(int pin) {
    char buffer[64];
    int len;
    FILE *fp;

    fp = fopen("/sys/class/gpio/unexport", "w");
    if (fp == NULL) {
        perror("Failed to open /sys/class/gpio/unexport for writing");
        return -1;
    }

    len = snprintf(buffer, sizeof(buffer), "%d", pin);
    if (fwrite(buffer, 1, len, fp) != len) {
        perror("Failed to write to /sys/class/gpio/unexport");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return 0;
}

// Function to set the direction of a GPIO pin (in or out)
int gpio_direction(int pin, char *direction) {
    char path[64];
    FILE *fp;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/direction", pin);
    fp = fopen(path, "w");
    if (fp == NULL) {
        perror("Failed to open GPIO direction file for writing");
        return -1;
    }

    if (fprintf(fp, "%s", direction) < 0) {
        perror("Failed to write to GPIO direction file");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return 0;
}

// Function to write a value (0 or 1) to a GPIO pin
int gpio_write(int pin, int value) {
    char path[64];
    FILE *fp;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", pin);
    fp = fopen(path, "w");
    if (fp == NULL) {
        perror("Failed to open GPIO value file for writing");
        return -1;
    }

    if (fprintf(fp, "%d", value) < 0) {
        perror("Failed to write to GPIO value file");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return 0;
}

// Function to control a single motor for a specified duration
int motor_pulse(int pin, int duration_ms) {
    if (gpio_write(pin, 1) != 0) { // Turn motor on
        fprintf(stderr, "Error turning motor %d on\n", pin);
        return -1;
    }
    usleep(duration_ms * 1000); // Wait for the specified duration
    if (gpio_write(pin, 0) != 0) { // Turn motor off
        fprintf(stderr, "Error turning motor %d off\n", pin);
        return -1;
    }
    return 0;
}

int main() {
    // Register the signal handler for SIGINT
    if (signal(SIGINT, signal_handler) == SIG_ERR) {
        perror("Failed to register signal handler");
        return 1;
    }

    // Export the GPIO pins
    if (gpio_export(MOTOR1_GPIO) != 0) return 1;
    if (gpio_export(MOTOR2_GPIO) != 0) {
        gpio_unexport(MOTOR1_GPIO); // Clean up if the second export fails
        return 1;
    }

    // Set the GPIO pin directions to output
    if (gpio_direction(MOTOR1_GPIO, "out") != 0) {
        gpio_unexport(MOTOR1_GPIO);
        gpio_unexport(MOTOR2_GPIO);
        return 1;
    }
    if (gpio_direction(MOTOR2_GPIO, "out") != 0) {
        gpio_unexport(MOTOR1_GPIO);
        gpio_unexport(MOTOR2_GPIO);
        return 1;
    }

    // Main loop to pulse the motors sequentially
    while (program_running) {
        if (motor_pulse(MOTOR1_GPIO, 200) != 0) {
            break; // Exit loop on error
        }
        if (motor_pulse(MOTOR2_GPIO, 300) != 0) {
            break; // Exit loop on error
        }
    }

    // Unexport the GPIO pins before exiting
    gpio_unexport(MOTOR1_GPIO);
    gpio_unexport(MOTOR2_GPIO);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>

// TCS34725 Registers
#define TCS34725_ADDRESS         (0x29)
#define TCS34725_ENABLE          (0x80)
#define TCS34725_ENABLE_PON      (0x01)
#define TCS34725_ENABLE_AEN      (0x02)
#define TCS34725_ENABLE_AIEN     (0x10)
#define TCS34725_ID              (0x12)
#define TCS34725_CDATAL          (0x14)
#define TCS34725_CDATAH          (0x15)
#define TCS34725_RDATAL          (0x16)
#define TCS34725_RDATAH          (0x17)
#define TCS34725_GDATAL          (0x18)
#define TCS34725_GDATAH          (0x19)
#define TCS34725_BDATAL          (0x1A)
#define TCS34725_BDATAH          (0x1B)
#define TCS34725_ATIME            (0x81)
#define TCS34725_AGAIN            (0x8F)

// GPIO Pins for LEDs
#define RED_LED_PIN   (17)
#define GREEN_LED_PIN (18)
#define BLUE_LED_PIN  (27)

int i2c_handle;
volatile sig_atomic_t program_running = 1;

void signal_handler(int signum) {
    if (signum == SIGINT) {
        program_running = 0;
        printf("Ctrl+C detected. Exiting gracefully.\n");
        // Turn off all LEDs
        gpioWrite(RED_LED_PIN, 0);
        gpioWrite(GREEN_LED_PIN, 0);
        gpioWrite(BLUE_LED_PIN, 0);
        // Close I2C bus
        i2cClose(i2c_handle);
        // Terminate pigpio
        gpioTerminate();
        exit(0);
    }
}

int main() {
    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set LED pins as outputs
    gpioSetMode(RED_LED_PIN, PI_OUTPUT);
    gpioSetMode(GREEN_LED_PIN, PI_OUTPUT);
    gpioSetMode(BLUE_LED_PIN, PI_OUTPUT);

    // Initialize I2C bus
    i2c_handle = i2cOpen(1, TCS34725_ADDRESS, 0); // Bus 1, address 0x29, no flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C bus: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Verify sensor ID
    int sensor_id = i2cReadByteData(i2c_handle, TCS34725_ID);
    if (sensor_id < 0) {
        fprintf(stderr, "Error reading sensor ID: %d\n", sensor_id);
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }
    if (sensor_id != 0x44 && sensor_id != 0x10) {
        fprintf(stderr, "Incorrect sensor ID: 0x%02X\n", sensor_id);
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Configure TCS34725
    if (i2cWriteByteData(i2c_handle, TCS34725_ATIME, 0xD5) < 0) { //Integration time
      fprintf(stderr, "Error writing ATIME\n");
      i2cClose(i2c_handle);
      gpioTerminate();
      return 1;
    }

    if (i2cWriteByteData(i2c_handle, TCS34725_AGAIN, 0x00) < 0) { //Gain
      fprintf(stderr, "Error writing AGAIN\n");
      i2cClose(i2c_handle);
      gpioTerminate();
      return 1;
    }

    if (i2cWriteByteData(i2c_handle, TCS34725_ENABLE, TCS34725_ENABLE_PON | TCS34725_ENABLE_AEN) < 0) {
        fprintf(stderr, "Error enabling sensor\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    while (program_running) {
        // Read RGBA values
        uint8_t clear_low = i2cReadByteData(i2c_handle, TCS34725_CDATAL);
        uint8_t clear_high = i2cReadByteData(i2c_handle, TCS34725_CDATAH);
        uint8_t red_low = i2cReadByteData(i2c_handle, TCS34725_RDATAL);
        uint8_t red_high = i2cReadByteData(i2c_handle, TCS34725_RDATAH);
        uint8_t green_low = i2cReadByteData(i2c_handle, TCS34725_GDATAL);
        uint8_t green_high = i2cReadByteData(i2c_handle, TCS34725_GDATAH);
        uint8_t blue_low = i2cReadByteData(i2c_handle, TCS34725_BDATAL);
        uint8_t blue_high = i2cReadByteData(i2c_handle, TCS34725_BDATAH);

        if (clear_low < 0 || clear_high < 0 || red_low < 0 || red_high < 0 ||
            green_low < 0 || green_high < 0 || blue_low < 0 || blue_high < 0) {
            fprintf(stderr, "Error reading color data\n");
            break; // Exit loop on read error
        }

        uint16_t clear = (clear_high << 8) | clear_low;
        uint16_t red = (red_high << 8) | red_low;
        uint16_t green = (green_high << 8) | green_low;
        uint16_t blue = (blue_high << 8) | blue_low;

        // Determine dominant color
        if (red > green && red > blue && red > 100) {
            gpioWrite(RED_LED_PIN, 1);
            gpioWrite(GREEN_LED_PIN, 0);
            gpioWrite(BLUE_LED_PIN, 0);
            printf("Dominant color: Red\n");
        } else if (green > red && green > blue && green > 100) {
            gpioWrite(RED_LED_PIN, 0);
            gpioWrite(GREEN_LED_PIN, 1);
            gpioWrite(BLUE_LED_PIN, 0);
            printf("Dominant color: Green\n");
        } else if (blue > red && blue > green && blue > 100) {
            gpioWrite(RED_LED_PIN, 0);
            gpioWrite(GREEN_LED_PIN, 0);
            gpioWrite(BLUE_LED_PIN, 1);
            printf("Dominant color: Blue\n");
        } else {
            gpioWrite(RED_LED_PIN, 0);
            gpioWrite(GREEN_LED_PIN, 0);
            gpioWrite(BLUE_LED_PIN, 0);
            printf("Dominant color: Unknown\n");
        }

        time_sleep(0.5); // 500ms delay
    }

    // Cleanup (only reached if loop breaks due to error, not Ctrl+C)
    gpioWrite(RED_LED_PIN, 0);
    gpioWrite(GREEN_LED_PIN, 0);
    gpioWrite(BLUE_LED_PIN, 0);
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

