#define ECHO_PIN    24

// Constants
#define SPEED_OF_SOUND 34300.0 // Speed of sound in cm/s
#define ALARM_THRESHOLD 30.0   // Distance threshold for alarm in cm

// Global variables
static volatile int pulse_start = 0;
static volatile int pulse_end = 0;
static volatile int distance = 0;

// Signal handler for graceful shutdown
void signal_handler(int signal)
{
    printf("\nCaught signal %d, cleaning up...\n", signal);
    gpioServo(SERVO_PIN, 1500); // Set servo to a safe position (90 degrees)
    gpioTerminate();           // Terminate pigpio
    exit(0);                   // Exit the program
}

// Callback function for echo pin
void echo_callback(int gpio, int level, uint32_t tick)
{
    if (level == 1) {
        pulse_start = tick;
    } else if (level == 0) {
        pulse_end = tick;

        // Calculate pulse duration
        int pulse_duration = pulse_end - pulse_start;

        // Basic sanity check for duration
        if (pulse_duration < 0 || pulse_duration > 50000) {
            fprintf(stderr, "Error: Invalid pulse duration: %d\n", pulse_duration);
            return;
        }

        // Calculate distance in centimeters
        distance = (pulse_duration * SPEED_OF_SOUND) / 20000.0; // Dividing by 1000000.0 to convert to seconds and multiplying by speed of sound in cm/s
    }
}

// Function to trigger the ultrasonic sensor
void trigger_sensor()
{
    gpioWrite(TRIGGER_PIN, 1);
    gpioDelay(10); // 10us trigger pulse
    gpioWrite(TRIGGER_PIN, 0);
}

int main()
{
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(SERVO_PIN, PI_OUTPUT);
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);

    // Set pull-down resistor on echo pin (recommended for HC-SR04)
    gpioSetPullUpDown(ECHO_PIN, PI_PUD_DOWN);

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Set up callback function for echo pin
    gpioSetAlertFuncEx(ECHO_PIN, echo_callback, NULL);

    // Main loop: Sweep servo and measure distance
    for (int angle = 0; angle <= 180; angle += 10) {
        // Set servo position
        gpioServo(SERVO_PIN, 500 + (angle * 2000 / 180)); // Convert angle to pulse width (500-2500)
        gpioDelay(500); // Wait for servo to move

        // Trigger ultrasonic sensor
        trigger_sensor();
        gpioDelay(50); // Allow time for echo

        // Display distance reading
        printf("Angle: %d, Distance: %d cm\n", angle, distance);

        // Alarm simulation
        if (distance < ALARM_THRESHOLD) {
            printf("WARNING: Object within %.0fcm!\n", ALARM_THRESHOLD);
        }
    }

    // Clean up and exit
    gpioServo(SERVO_PIN, 1500); // Set servo to a safe position (90 degrees)
    gpioTerminate();           // Terminate pigpio
    return 0;
}

#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
#include <errno.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <stdbool.h>
#include <time.h>

// Constants for the D6T sensor
#define D6T_I2C_ADDR 0x0A  // I2C 7-bit address
#define D6T_COMMAND 0x4C // Command to read temperature data
#define NUM_PIXELS 64      // Number of pixels (8x8)
#define NUM_READ_BYTES ((NUM_PIXELS + 1) * 2 + 1) // Number of bytes to read
#define I2C_DEVICE_PATH "/dev/i2c-1" // I2C device path

// Global variables
uint8_t read_buffer[NUM_READ_BYTES]; // Buffer to store raw data from the sensor
double ambient_temperature;        // Ambient temperature
double pixel_temperatures[NUM_PIXELS]; // Array to store pixel temperatures

// Function prototypes
int i2c_read_data(int file_descriptor, uint8_t device_address, uint8_t command, uint8_t *data, int length);
bool check_pec(uint8_t *data, int length);
int16_t convert_bytes_to_int16(uint8_t *buffer, int index);
void initialize_sensor(int file_descriptor);

// Helper function for delays
void delay_ms(int milliseconds) {
    struct timespec ts;
    ts.tv_sec = milliseconds / 1000;
    ts.tv_nsec = (milliseconds % 1000) * 1000000;
    nanosleep(&ts, NULL);
}

// Function to read data from the I2C device
int i2c_read_data(int file_descriptor, uint8_t device_address, uint8_t command, uint8_t *data, int length) {
    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        perror("Failed to acquire bus access and/or talk to slave.\n");
        return -1;
    }

    if (write(file_descriptor, &command, 1) != 1) {
        perror("Failed to write to the i2c bus.\n");
        return -1;
    }

    int bytes_read = read(file_descriptor, data, length);
    if (bytes_read != length) {
        fprintf(stderr, "Failed to read complete data from I2C. Expected %d, got %d\n", length, bytes_read);
        return -1;
    }

    return 0;
}

// Function to calculate CRC8 checksum (PEC)
uint8_t calculate_crc(uint8_t data) {
    uint8_t crc = data;
    for (int i = 0; i < 8; i++) {
        if (crc & 0x80) {
            crc = (crc << 1) ^ 0x07;
        } else {
            crc <<= 1;
        }
    }
    return crc;
}

// Function to check PEC (Packet Error Check)
bool check_pec(uint8_t *data, int length) {
    uint8_t crc = calculate_crc((D6T_I2C_ADDR << 1) | 1); // I2C read address
    for (int i = 0; i < length; i++) {
        crc = calculate_crc(data[i] ^ crc);
    }

    return (crc == data[length]);
}

// Function to convert two bytes to a signed 16-bit integer (little-endian)
int16_t convert_bytes_to_int16(uint8_t *buffer, int index) {
    return (int16_t)((buffer[index]) | (buffer[index + 1] << 8));
}

void initialize_sensor(int file_descriptor) {
    uint8_t dat1[] = {0x02, 0x00, 0x01, 0xee};
    if (i2c_read_data(file_descriptor, D6T_I2C_ADDR, dat1[0], dat1+1, sizeof(dat1)-1) !=0) {
        fprintf(stderr, "Failed to write initialization data 1\n");
    }
    uint8_t dat2[] = {0x05, 0x90, 0x3a, 0xb8};
    if (i2c_read_data(file_descriptor, D6T_I2C_ADDR, dat2[0], dat2+1, sizeof(dat2)-1) !=0) {
        fprintf(stderr, "Failed to write initialization data 2\n");
    }
    uint8_t dat3[] = {0x03, 0x00, 0x03, 0x8b};
    if (i2c_read_data(file_descriptor, D6T_I2C_ADDR, dat3[0], dat3+1, sizeof(dat3)-1) !=0) {
        fprintf(stderr, "Failed to write initialization data 3\n");
    }
    uint8_t dat4[] = {0x03, 0x00, 0x07, 0x97};
        if (i2c_read_data(file_descriptor, D6T_I2C_ADDR, dat4[0], dat4+1, sizeof(dat4)-1) !=0) {
        fprintf(stderr, "Failed to write initialization data 4\n");
    }
    uint8_t dat5[] = {0x02, 0x00, 0x00, 0xe9};
    if (i2c_read_data(file_descriptor, D6T_I2C_ADDR, dat5[0], dat5+1, sizeof(dat5)-1) !=0) {
        fprintf(stderr, "Failed to write initialization data 5\n");
    }
    delay_ms(500);
}

int main() {
    int file_descriptor;

    // Open the I2C device
    file_descriptor = open(I2C_DEVICE_PATH, O_RDWR);
    if (file_descriptor < 0) {
        perror("Failed to open the I2C bus\n");
        return 1;
    }

    // Initialize the sensor
    initialize_sensor(file_descriptor);
    delay_ms(500);

    while (1) {
        // Read data from the sensor
        if (i2c_read_data(file_descriptor, D6T_I2C_ADDR, D6T_COMMAND, read_buffer, NUM_READ_BYTES) != 0) {
            fprintf(stderr, "Failed to read temperature data\n");
            close(file_descriptor);
            return 1; // Exit on error
        }

        // Verify PEC
        if (!check_pec(read_buffer, NUM_READ_BYTES - 1)) {
            fprintf(stderr, "PEC check failed. Data may be corrupted.\n");
        }

        // Extract ambient temperature
        ambient_temperature = (double)convert_bytes_to_int16(read_buffer, 0) / 10.0;

        // Extract pixel temperatures
        for (int i = 0; i < NUM_PIXELS; i++) {
            pixel_temperatures[i] = (double)convert_bytes_to_int16(read_buffer, 2 + (2 * i)) / 5.0;
        }

        // Print the results
        printf("Ambient Temperature: %.1f °C\n", ambient_temperature);
        printf("Pixel Temperatures: ");
        for (int i = 0; i < NUM_PIXELS; i++) {
            printf("%.1f ", pixel_temperatures[i]);
        }
        printf("°C\n");

        // Delay before the next reading
        delay_ms(250);
    }

    // Close the I2C device (this will never be reached in the current loop)
    close(file_descriptor);
    return 0;
}

#include <pigpio.h>
#include <stdio.h>
#define M1_INA1 5
#define M1_INA2 6
#define M1_ENA  13
#define M2_INA1 19
#define M2_INA2 26
#define M2_ENA  16

void setup() {
    if (gpioInitialise() < 0) return;
    gpioSetMode(M1_INA1, PI_OUTPUT);
    gpioSetMode(M1_INA2, PI_OUTPUT);
    gpioSetMode(M1_ENA, PI_OUTPUT);
    gpioSetMode(M2_INA1, PI_OUTPUT);
    gpioSetMode(M2_INA2, PI_OUTPUT);
    gpioSetMode(M2_ENA, PI_OUTPUT);
}

void startConveyor() {
    gpioWrite(M1_INA1, 1);
    gpioWrite(M1_INA2, 0);
    gpioWrite(M2_INA1, 1);
    gpioWrite(M2_INA2, 0);
    gpioPWM(M1_ENA, 100);
    gpioPWM(M2_ENA, 100);
}

void stopConveyor() {
    gpioWrite(M1_INA1, 0);
    gpioWrite(M1_INA2, 0);
    gpioWrite(M2_INA1, 0);
    gpioWrite(M2_INA2, 0);
    gpioPWM(M1_ENA, 0);
    gpioPWM(M2_ENA, 0);
}

int main() {
    setup();
    while (1) {
        startConveyor();
        gpioDelay(10000000);
        stopConveyor();
        gpioDelay(5000000);
    }
    gpioTerminate();
    return 0;
}

