    gpioSetMode(BUTTON_GPIO, PI_INPUT);
    gpioSetPullUpDown(BUTTON_GPIO, PI_PUD_UP); // Enable pull-up resistor

    int last_state = 1; // Assume button is released initially (pulled up)

    while (1) {
        int current_state = gpioRead(BUTTON_GPIO);

        if (current_state == 0 && last_state == 1) { // Button pressed (LOW)
            printf("Button Pressed\n");
