#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <errno.h>
#include <pigpio.h>

// TCS34725 Registers
#define TCS34725_ADDRESS          (0x29)
#define TCS34725_COMMAND_BIT      (0x80)
#define TCS34725_ENABLE           (0x00)
#define TCS34725_ATIME            (0x01)
#define TCS34725_WTIME            (0x03)
#define TCS34725_AILTL            (0x04)
#define TCS34725_AILTH            (0x05)
#define TCS34725_AIHTL            (0x06)
#define TCS34725_AIHTH            (0x07)
#define TCS34725_ID               (0x12)
#define TCS34725_STATUS           (0x13)
#define TCS34725_CDATA            (0x14)
#define TCS34725_RDATA            (0x16)
#define TCS34725_GDATA            (0x18)
#define TCS34725_BDATA            (0x1A)
#define TCS34725_PDATA            (0x1C)
#define TCS34725_CONTROL          (0x0F)

#define TCS34725_ENABLE_PON       (0x01)
#define TCS34725_ENABLE_AEN       (0x02)
#define TCS34725_ENABLE_AIEN      (0x10)

// RGB LED Pins
#define RED_PIN   (17)
#define GREEN_PIN (18)
#define BLUE_PIN  (27)

// I2C Retry Settings
#define I2C_RETRIES (3)
#define I2C_DELAY_MS (10)

// Global Variables
static int i2c_handle;
static FILE *log_file;
static volatile sig_atomic_t terminate = 0;

// Function Prototypes
int tcs34725_init(int handle);
int tcs34725_read_data(int handle, uint16_t *r, uint16_t *g, uint16_t *b, uint16_t *c);
void set_rgb_led(int r, int g, int b);
const char* determine_dominant_color(uint16_t r, uint16_t g, uint16_t b, uint16_t c);
void log_color_data(const char *color);
void signal_handler(int signal);

// Helper function to write to I2C with retries
int i2c_write_register(int handle, uint8_t reg, uint8_t value) {
    int i, result;
    for (i = 0; i < I2C_RETRIES; ++i) {
        result = i2cWriteByteData(handle, TCS34725_COMMAND_BIT | reg, value);
        if (result == 0) return 0; // Success
        gpioDelay(I2C_DELAY_MS * 1000); // Delay in microseconds
    }
    fprintf(stderr, "I2C Write Error: %s\n", strerror(errno));
    return -1;
}

// Helper function to read from I2C with retries
int i2c_read_register(int handle, uint8_t reg, uint8_t *value) {
    int i, result;
    for (i = 0; i < I2C_RETRIES; ++i) {
        result = i2cReadByteData(handle, TCS34725_COMMAND_BIT | reg);
        if (result >= 0) {
            *value = (uint8_t)result;
            return 0; // Success
        }
        gpioDelay(I2C_DELAY_MS * 1000); // Delay in microseconds
    }
    fprintf(stderr, "I2C Read Error: %s\n", strerror(errno));
    return -1;
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C connection
    i2c_handle = i2cOpen(1, TCS34725_ADDRESS, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %s\n", strerror(errno));
        gpioTerminate();
        return 1;
    }

    // Initialize TCS34725
    if (tcs34725_init(i2c_handle) != 0) {
        fprintf(stderr, "TCS34725 initialization failed\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Open log file
    log_file = fopen("color_log.txt", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Failed to open log file\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set RGB LED pins as output
    gpioSetMode(RED_PIN, PI_OUTPUT);
    gpioSetMode(GREEN_PIN, PI_OUTPUT);
    gpioSetMode(BLUE_PIN, PI_OUTPUT);

    // Set signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    uint16_t r, g, b, c;
    const char *dominant_color;

    while (!terminate) {
        // Read color data
        if (tcs34725_read_data(i2c_handle, &r, &g, &b, &c) == 0) {
            // Determine dominant color
            dominant_color = determine_dominant_color(r, g, b, c);

            // Log color data
            log_color_data(dominant_color);

            // Control RGB LED (Common Anode)
            if (strcmp(dominant_color, "Red") == 0) {
                set_rgb_led(0, 255, 255); // Red
            } else if (strcmp(dominant_color, "Green") == 0) {
                set_rgb_led(255, 0, 255); // Green
            } else if (strcmp(dominant_color, "Blue") == 0) {
                set_rgb_led(255, 255, 0); // Blue
            } else {
                set_rgb_led(255, 255, 255); // Clear/White
            }
        } else {
            fprintf(stderr, "Failed to read color data\n");
        }

        gpioDelay(500000); // 500ms delay
    }

    // Cleanup
    set_rgb_led(255, 255, 255); // Turn off LED
    fclose(log_file);
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

int tcs34725_init(int handle) {
    uint8_t id;

    // Check ID register
    if (i2c_read_register(handle, TCS34725_ID, &id) != 0 || id != 0x44) {
        fprintf(stderr, "TCS34725 not found\n");
        return -1;
    }

    // Enable power and ALS
    if (i2c_write_register(handle, TCS34725_ENABLE, TCS34725_ENABLE_PON | TCS34725_ENABLE_AEN) != 0) return -1;

    // Set integration time (ATIME = 101ms)
    if (i2c_write_register(handle, TCS34725_ATIME, 0xDB) != 0) return -1; // 256 - 101 = 155 = 0x9B. But 0xDB is used for correct timing

    // Set gain (AGAIN = 60x)
    if (i2c_write_register(handle, TCS34725_CONTROL, 0x05) != 0) return -1; //Gain 60x

    return 0;
}

int tcs34725_read_data(int handle, uint16_t *r, uint16_t *g, uint16_t *b, uint16_t *c) {
    uint8_t cData[8]; // Array to store all 8 bytes of color data
    int i, result;

    // Read all color data registers at once using block transfer
    for (i = 0; i < I2C_RETRIES; ++i) {
        result = i2cReadI2CBlockData(handle, TCS34725_COMMAND_BIT | TCS34725_CDATA, (char *)cData, 8);
        if (result == 8) break; // Success
        gpioDelay(I2C_DELAY_MS * 1000);
    }

    if (result != 8) {
        fprintf(stderr, "I2C Block Read Error: %s\n", strerror(errno));
        return -1;
    }

    *c = (uint16_t)cData[1] << 8 | cData[0];
    *r = (uint16_t)cData[3] << 8 | cData[2];
    *g = (uint16_t)cData[5] << 8 | cData[4];
    *b = (uint16_t)cData[7] << 8 | cData[6];

    return 0;
}

void set_rgb_led(int r, int g, int b) {
    gpioWrite(RED_PIN, r > 127 ? 0 : 1);
    gpioWrite(GREEN_PIN, g > 127 ? 0 : 1);
    gpioWrite(BLUE_PIN, b > 127 ? 0 : 1);
}

const char* determine_dominant_color(uint16_t r, uint16_t g, uint16_t b, uint16_t c) {
    if (r > g && r > b && r > c) return "Red";
    if (g > r && g > b && g > c) return "Green";
    if (b > r && b > g && b > c) return "Blue";
    return "Clear";
}

void log_color_data(const char *color) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[30];
    struct timespec spec;

    clock_gettime(CLOCK_REALTIME, &spec);
    rawtime = spec.tv_sec;
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);
    fprintf(log_file, "%s.%03ld: Dominant Color: %s\n", timestamp, spec.tv_nsec / 1000000, color);
    fflush(log_file);
}

void signal_handler(int signal) {
    fprintf(stderr, "Caught signal %d, terminating...\n", signal);
    terminate = 1;
}

#include <stdio.h>
#include <wiringPi.h>
#include <stdint.h>
