// Seven-segment display patterns for digits 0-9 (common cathode)
const uint8_t segments[] = {
  0b00111111, // 0
  0b00000110, // 1
  0b01011011, // 2
  0b01001111, // 3
  0b01100110, // 4
  0b01101101, // 5
  01111101,   //6
  0b00000111, // 7
  0b01111111, // 8
  0b01101111  // 9
};

// Function to send data to 74HC595
void shiftOut(uint8_t dataPin, uint8_t clockPin, uint8_t data) {
  for (int i = 0; i < 8; i++) {
    digitalWrite(dataPin, (data >> (7 - i)) & 0x01); // Send bit
    digitalWrite(clockPin, HIGH);      // Clock high
    digitalWrite(clockPin, LOW);       // Clock low
  }
}

int main() {
  wiringPiSetupGpio(); // Use GPIO numbering

  // Set pins as output
  pinMode(LATCH_PIN, OUTPUT);
  pinMode(CLOCK_PIN, OUTPUT);
  pinMode(DATA_PIN, OUTPUT);

  int number_to_display = 5;
  uint8_t segment_value = segments[number_to_display];

  while (1) {
    // Display the number
    digitalWrite(LATCH_PIN, LOW);
    shiftOut(DATA_PIN, CLOCK_PIN, segment_value);
    digitalWrite(LATCH_PIN, HIGH);
    delay(500); // Wait 0.5 second

    // Turn off the display
    digitalWrite(LATCH_PIN, LOW);
    shiftOut(DATA_PIN, CLOCK_PIN, 0x00); // Send all zeros
    digitalWrite(LATCH_PIN, HIGH);
    delay(500); // Wait 0.5 second
  }

  return 0;
}

#include <stdio.h>
