// GPIO pins
#define BUZZER_GPIO 17
#define BUTTON_GPIO 18

// Sysfs paths
#define GPIO_EXPORT_PATH "/sys/class/gpio/export"
#define GPIO_UNEXPORT_PATH "/sys/class/gpio/unexport"
#define GPIO_DIR_PATH_FORMAT "/sys/class/gpio/gpio%d/direction"
#define GPIO_VALUE_PATH_FORMAT "/sys/class/gpio/gpio%d/value"
#define GPIO_EDGE_PATH_FORMAT "/sys/class/gpio/gpio%d/edge"

// Arpeggio notes (C4, D4, E4, F4, G4)
const int arpeggio_frequencies[] = {262, 294, 330, 349, 392};
const int arpeggio_size = sizeof(arpeggio_frequencies) / sizeof(arpeggio_frequencies[0]);

// Melody notes and durations
const int melody_frequencies[] = {440, 494, 523, 494, 440, 392, 440, 494};
const int melody_durations[] = {250, 250, 500, 250, 250, 500, 250, 750};
const int melody_size = sizeof(melody_frequencies) / sizeof(melody_frequencies[0]);

// Flag to indicate program termination
volatile sig_atomic_t program_running = 1;

// Function to handle signals (e.g., SIGINT)
void signal_handler(int sig) {
    program_running = 0;
    printf("\nCaught signal %d, exiting gracefully.\n", sig);
}

// Function to export a GPIO pin
int export_gpio(int gpio) {
    int fd;
    char buf[3];

    fd = open(GPIO_EXPORT_PATH, O_WRONLY);
    if (fd < 0) {
        perror("Failed to open GPIO export file");
        return -1;
    }

    int len = snprintf(buf, sizeof(buf), "%d", gpio);
    if (write(fd, buf, len) != len) {
        perror("Failed to write GPIO number to export file");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to unexport a GPIO pin
int unexport_gpio(int gpio) {
    int fd;
    char buf[3];

    fd = open(GPIO_UNEXPORT_PATH, O_WRONLY);
    if (fd < 0) {
        perror("Failed to open GPIO unexport file");
        return -1;
    }

    int len = snprintf(buf, sizeof(buf), "%d", gpio);
    if (write(fd, buf, len) != len) {
        perror("Failed to write GPIO number to unexport file");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to set the direction of a GPIO pin (in or out)
int set_gpio_direction(int gpio, const char *direction) {
    char path[64];
    int fd;

    snprintf(path, sizeof(path), GPIO_DIR_PATH_FORMAT, gpio);
    fd = open(path, O_WRONLY);
    if (fd < 0) {
        perror("Failed to open GPIO direction file");
        return -1;
    }

    if (write(fd, direction, strlen(direction)) != strlen(direction)) {
        perror("Failed to write direction to GPIO direction file");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to set the value of a GPIO pin (0 or 1)
int set_gpio_value(int gpio, int value) {
    char path[64];
    int fd;
    char buf[2];

    snprintf(path, sizeof(path), GPIO_VALUE_PATH_FORMAT, gpio);
    fd = open(path, O_WRONLY);
    if (fd < 0) {
        perror("Failed to open GPIO value file");
        return -1;
    }

    int len = snprintf(buf, sizeof(buf), "%d", value);
    if (write(fd, buf, len) != len) {
        perror("Failed to write value to GPIO value file");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to set the edge detection for a GPIO pin (rising, falling, both, none)
int set_gpio_edge(int gpio, const char *edge) {
    char path[64];
    int fd;

    snprintf(path, sizeof(path), GPIO_EDGE_PATH_FORMAT, gpio);
    fd = open(path, O_WRONLY);
    if (fd < 0) {
