        return -1;
    }

    if (write(fd, edge, strlen(edge)) != strlen(edge)) {
        perror("Failed to write edge to GPIO edge file");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function for precise delay in milliseconds using nanosleep
void delay_ms(int milliseconds) {
    struct timespec req;
    req.tv_sec = 0;
    req.tv_nsec = milliseconds * 1000000L;
    while (nanosleep(&req, &req) == -1) {
        continue; // Handle interrupt by continuing
    }
}

// Function to play a single note with a given frequency and duration
void play_note(int frequency, int duration_ms) {
    float period_ms = 1000.0 / frequency;  // Period in milliseconds
    int half_period_us = (int)(period_ms * 500); // Half period in microseconds

    int num_cycles = duration_ms * frequency / 1000; // Number of cycles to play

    for (int i = 0; i < num_cycles; i++) {
        if (set_gpio_value(BUZZER_GPIO, 1) < 0) {
            fprintf(stderr, "Error setting GPIO value high\n");
            return;
        }
        usleep(half_period_us);

        if (set_gpio_value(BUZZER_GPIO, 0) < 0) {
            fprintf(stderr, "Error setting GPIO value low\n");
            return;
        }
        usleep(half_period_us);
    }
}

// Function to play the arpeggio
void play_arpeggio(int duration_ms) {
    for (int i = 0; i < arpeggio_size; i++) {
        play_note(arpeggio_frequencies[i], duration_ms);
    }
}

// Function to play the melody
void play_melody() {
    for (int i = 0; i < melody_size; i++) {
        play_note(melody_frequencies[i], melody_durations[i]);
    }
}

int main() {
    int button_fd;
    char button_value_path[64];
    struct pollfd pfd;

    // Register signal handler
    signal(SIGINT, signal_handler);

    // Export GPIO pins
    if (export_gpio(BUZZER_GPIO) < 0) return 1;
    if (export_gpio(BUTTON_GPIO) < 0) {
        unexport_gpio(BUZZER_GPIO);
        return 1;
    }

    // Set GPIO directions
    if (set_gpio_direction(BUZZER_GPIO, "out") < 0) {
        unexport_gpio(BUZZER_GPIO);
        unexport_gpio(BUTTON_GPIO);
        return 1;
    }
    if (set_gpio_direction(BUTTON_GPIO, "in") < 0) {
        unexport_gpio(BUZZER_GPIO);
        unexport_gpio(BUTTON_GPIO);
        return 1;
    }

    // Set edge detection for the button (falling edge)
    if (set_gpio_edge(BUTTON_GPIO, "falling") < 0) {
        unexport_gpio(BUZZER_GPIO);
        unexport_gpio(BUTTON_GPIO);
        return 1;
    }

    // Open the button value file for polling
    snprintf(button_value_path, sizeof(button_value_path), GPIO_VALUE_PATH_FORMAT, BUTTON_GPIO);
    button_fd = open(button_value_path, O_RDONLY);
    if (button_fd < 0) {
        perror("Failed to open button value file for polling");
        unexport_gpio(BUZZER_GPIO);
        unexport_gpio(BUTTON_GPIO);
        return 1;
    }

    pfd.fd = button_fd;
    pfd.events = POLLPRI; // Check for high-priority events (edge interrupt)

    // Play the initial arpeggio
    play_arpeggio(200); // Play each note for 200ms

    printf("Monitoring button press...\n");

    // Main loop to monitor button presses
    while (program_running) {
        // Poll for button press
        int ret = poll(&pfd, 1, -1); // Wait indefinitely

        if (ret < 0) {
            perror("Poll failed");
            break;
        }

        if (ret > 0) {
            if (pfd.revents & POLLPRI) {
                // Button pressed (falling edge detected)
                printf("Button pressed! Playing melody.\n");
                play_melody();

                // Consume the interrupt by reading from the value file
                char buf[2];
                lseek(button_fd, 0, SEEK_SET); // Rewind to the beginning of the file
                read(button_fd, buf, 1);
            }
        }
    }

    // Clean up GPIOs before exiting
    close(button_fd);
    unexport_gpio(BUZZER_GPIO);
    unexport_gpio(BUTTON_GPIO);

    printf("Program finished.\n");
    return 0;
}

