// Function to log an alarm event to a file
int log_alarm(const char *filename) {
    FILE *fp;
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fp = fopen(filename, "a");
    if (fp == NULL) {
        fprintf(stderr, "log_alarm: Failed to open log file: %s\n", strerror(errno));
        return -1;
    }

    fprintf(fp, "%s - Alarm triggered!\n", timestamp);
    fclose(fp);
    return 0;
}

// Function to debounce the sound sensor reading
int debounce(int pin, int duration_ms) {
    int start_time, current_time;
    struct timeval tv;

    gettimeofday(&tv, NULL);
    start_time = (tv.tv_sec) * 1000 + (tv.tv_usec) / 1000;

    while (1) {
        if (gpio_read(pin) == LOW) {
            return LOW; // Return LOW immediately if signal drops
        }

        gettimeofday(&tv, NULL);
        current_time = (tv.tv_sec) * 1000 + (tv.tv_usec) / 1000;

        if (current_time - start_time >= duration_ms) {
            return HIGH; // Return HIGH if signal remains HIGH for the duration
        }
        usleep(1000); // Check every 1 ms
    }
}

int main() {
    // Install signal handler
    signal(SIGINT, signal_handler);

    // Export GPIO pins
    if (gpio_export(SOUND_SENSOR_PIN) < 0) return 1;
    if (gpio_export(BUZZER_PIN) < 0) {
        gpio_unexport(SOUND_SENSOR_PIN);
        return 1;
    }

    // Set GPIO pin directions
    if (gpio_set_direction(SOUND_SENSOR_PIN, "in") < 0) {
        gpio_unexport(SOUND_SENSOR_PIN);
        gpio_unexport(BUZZER_PIN);
        return 1;
    }
    if (gpio_set_direction(BUZZER_PIN, "out") < 0) {
        gpio_unexport(SOUND_SENSOR_PIN);
        gpio_unexport(BUZZER_PIN);
        return 1;
    }

    printf("Sound sensor monitoring started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        // Read sound sensor value
        int sound_level = gpio_read(SOUND_SENSOR_PIN);

        // Check if sound exceeds threshold (HIGH)
        if (sound_level == HIGH) {
            // Debounce the reading
            if (debounce(SOUND_SENSOR_PIN, 50) == HIGH) {
                printf("Sound detected! Triggering buzzer.\n");

                // Activate buzzer
                if (gpio_write(BUZZER_PIN, HIGH) < 0) {
                    fprintf(stderr, "Failed to activate buzzer.\n");
                } else {
                    // Log alarm event
                    if (log_alarm(ALARM_LOG_FILE) < 0) {
                        fprintf(stderr, "Failed to log alarm event.\n");
                    }

                    // Wait for 500ms
                    usleep(500000); // 500ms

                    // Deactivate buzzer
                    if (gpio_write(BUZZER_PIN, LOW) < 0) {
                        fprintf(stderr, "Failed to deactivate buzzer.\n");
                    }
                }
            }
        }
        usleep(10000); // Check every 10ms
    }

    // Unexport GPIO pins
    gpio_unexport(SOUND_SENSOR_PIN);
    gpio_unexport(BUZZER_PIN);

    printf("Program exited.\n");
    return 0;
}

