#define ADC_CHANNEL_1_CMD 0x42 // Replace with actual command for channel 1

int main(void) {
    int adc_fd; // File descriptor for the I2C device
    int switch_state;
    int adc_value;

    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi initialization failed!\n");
        return 1;
    }

    // Initialize the I2C device
    adc_fd = wiringPiI2CSetup(ADC_I2C_ADDR);
    if (adc_fd == -1) {
        fprintf(stderr, "Failed to initialize I2C communication!\n");
        return 1;
    }

    // Set the GPIO pin as input
    pinMode(SWITCH_GPIO_PIN, INPUT);
    pullUpDnControl(SWITCH_GPIO_PIN, PUD_UP); // Enable pull-up resistor

    printf("ADC Channel Selection using GPIO Switch\n");

    while (1) {
        // Read the state of the switch
        switch_state = digitalRead(SWITCH_GPIO_PIN);

        // Select the ADC channel based on the switch state
        if (switch_state == LOW) { // Active Low Switch. Can be switched if required
            wiringPiI2CWrite(adc_fd, ADC_CHANNEL_0_CMD);
            usleep(10000); // Wait for conversion (10ms)
            adc_value = wiringPiI2CReadReg16(adc_fd, 0);
            printf("Channel 0: %d\n", adc_value >> 4); //Shift as the ADC value is only 12 bits
        } else {
            wiringPiI2CWrite(adc_fd, ADC_CHANNEL_1_CMD);
            usleep(10000); // Wait for conversion (10ms)
            adc_value = wiringPiI2CReadReg16(adc_fd, 0);
            printf("Channel 1: %d\n", adc_value >> 4); //Shift as the ADC value is only 12 bits
        }

        delay(250); // Delay for 250ms
    }

    return 0;
}

