        // Read raw data
        if (read_raw_data(i2c_fd, &raw_x, &raw_y, &raw_z) == 0) {
            // Calibrate data
            calibrate_data(raw_x, raw_y, raw_z, &calibrated_x, &calibrated_y, &calibrated_z);

            // Write to file
            write_to_file(calibrated_x, calibrated_y, calibrated_z);

            // Metal detection
            metal_detection(calibrated_x, calibrated_y, calibrated_z);
        } else {
            fprintf(stderr, "Error reading magnetometer data. Retrying...\n");
        }

        // Delay for approximately 10Hz
        delay(100);
    }

    // Close file and reset PWM (this part will likely not be reached in the infinite loop)
    fclose(fp);
    pwmWrite(PWM_PIN, 0);

    return 0;
}

// Initialize I2C connection
int initialize_i2c(void) {
    int fd;
    int result;

    fd = wiringPiI2CSetup(HMC5883L_ADDR);
    if (fd < 0) {
        fprintf(stderr, "Unable to open I2C device: %s\n", strerror(errno));
        return -1;
    }

    // Set continuous measurement mode
    int retries = 3;
    while (retries > 0) {
        result = wiringPiI2CWriteReg8(fd, HMC5883L_CONFIG_A, 0x70); // 8-average, 15 Hz, normal measurement
        if (result == 0) break; // Success
        fprintf(stderr, "Error writing to HMC5883L_CONFIG_A: %s. Retrying...\n", strerror(errno));
        delay(I2C_RETRY_DELAY_MS);
        retries--;
    }
    if (retries == 0) return -1; // Failed after multiple retries

    retries = 3;
    while (retries > 0) {
        result = wiringPiI2CWriteReg8(fd, HMC5883L_MODE, 0x00); // Continuous measurement mode
        if (result == 0) break; // Success
        fprintf(stderr, "Error writing to HMC5883L_MODE: %s. Retrying...\n", strerror(errno));
        delay(I2C_RETRY_DELAY_MS);
        retries--;
    }
    if (retries == 0) return -1; // Failed after multiple retries

    return fd;
}

// Read raw magnetometer data
int read_raw_data(int fd, int16_t *x, int16_t *y, int16_t *z) {
    int x_msb, x_lsb, y_msb, y_lsb, z_msb, z_lsb;
    int retries = 3;

    while (retries > 0) {
        x_msb = wiringPiI2CReadReg8(fd, HMC5883L_DATA_X_MSB);
        if (x_msb >= 0) break; // Success
        fprintf(stderr, "Error reading HMC5883L_DATA_X_MSB: %s. Retrying...\n", strerror(errno));
        delay(I2C_RETRY_DELAY_MS);
        retries--;
    }
    if (retries == 0) return -1; // Failed after multiple retries

    retries = 3;
    while (retries > 0) {
        x_lsb = wiringPiI2CReadReg8(fd, HMC5883L_DATA_X_LSB);
        if (x_lsb >= 0) break; // Success
        fprintf(stderr, "Error reading HMC5883L_DATA_X_LSB: %s. Retrying...\n", strerror(errno));
        delay(I2C_RETRY_DELAY_MS);
        retries--;
    }
    if (retries == 0) return -1; // Failed after multiple retries

    retries = 3;
    while (retries > 0) {
        z_msb = wiringPiI2CReadReg8(fd, HMC5883L_DATA_Z_MSB);
        if (z_msb >= 0) break; // Success
        fprintf(stderr, "Error reading HMC5883L_DATA_Z_MSB: %s. Retrying...\n", strerror(errno));
        delay(I2C_RETRY_DELAY_MS);
        retries--;
    }
    if (retries == 0) return -1; // Failed after multiple retries

    retries = 3;
    while (retries > 0) {
        z_lsb = wiringPiI2CReadReg8(fd, HMC5883L_DATA_Z_LSB);
        if (z_lsb >= 0) break; // Success
        fprintf(stderr, "Error reading HMC5883L_DATA_Z_LSB: %s. Retrying...\n", strerror(errno));
        delay(I2C_RETRY_DELAY_MS);
        retries--;
    }
    if (retries == 0) return -1; // Failed after multiple retries

    retries = 3;
    while (retries > 0) {
        y_msb = wiringPiI2CReadReg8(fd, HMC5883L_DATA_Y_MSB);
        if (y_msb >= 0) break; // Success
        fprintf(stderr, "Error reading HMC5883L_DATA_Y_MSB: %s. Retrying...\n", strerror(errno));
        delay(I2C_RETRY_DELAY_MS);
        retries--;
    }
    if (retries == 0) return -1; // Failed after multiple retries

    retries = 3;
    while (retries > 0) {
        y_lsb = wiringPiI2CReadReg8(fd, HMC5883L_DATA_Y_LSB);
        if (y_lsb >= 0) break; // Success
        fprintf(stderr, "Error reading HMC5883L_DATA_Y_LSB: %s. Retrying...\n", strerror(errno));
        delay(I2C_RETRY_DELAY_MS);
        retries--;
    }
    if (retries == 0) return -1; // Failed after multiple retries

    *x = (int16_t)(x_msb << 8 | x_lsb);
    *y = (int16_t)(y_msb << 8 | y_lsb);
    *z = (int16_t)(z_msb << 8 | z_lsb);

    return 0;
}

// Calibrate magnetometer data
void calibrate_data(int16_t raw_x, int16_t raw_y, int16_t raw_z, float *calibrated_x, float *calibrated_y, float *calibrated_z) {
    *calibrated_x = (float)(raw_x - X_OFFSET) * X_SCALE;
    *calibrated_y = (float)(raw_y - Y_OFFSET) * Y_SCALE;
    *calibrated_z = (float)(raw_z - Z_OFFSET) * Z_SCALE;
}

// Write calibrated data to file
void write_to_file(float x, float y, float z) {
    fprintf(fp, "%f,%f,%f\n", x, y, z);
    fflush(fp); // Ensure data is written immediately
}

// Metal detection using PWM output
void metal_detection(float x, float y, float z) {
    float magnitude = sqrt(x * x + y * y + z * z);
    int pwm_value = 0;

    if (magnitude > METAL_THRESHOLD) {
        // Calculate PWM duty cycle based on magnitude above threshold
        pwm_value = (int)(((magnitude - METAL_THRESHOLD) / METAL_THRESHOLD) * PWM_RANGE);
        if (pwm_value > PWM_RANGE) {
            pwm_value = PWM_RANGE;
        }
        pwmWrite(PWM_PIN, pwm_value);
    } else {
        pwmWrite(PWM_PIN, 0);
    }
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <time.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>

// BMP180 I2C address
#define BMP180_ADDR 0x77

// BMP180 registers
#define BMP180_REG_CONTROL 0xF4
#define BMP180_REG_MSB 0xF6
#define BMP180_REG_LSB 0xF7
#define BMP180_REG_XLSB 0xF8

// Calibration data registers
#define BMP180_REG_AC1 0xAA
#define BMP180_REG_AC2 0xAC
#define BMP180_REG_AC3 0xAE
#define BMP180_REG_AC4 0xB0
#define BMP180_REG_AC5 0xB2
#define BMP180_REG_AC6 0xB4
#define BMP180_REG_B1 0xB6
#define BMP180_REG_B2 0xB8
#define BMP180_REG_MB 0xBA
#define BMP180_REG_MC 0xBC
#define BMP180_REG_MD 0xBE

// Oversampling setting (0, 1, 2, or 3)
#define BMP180_OSS 0

// Global variables
static volatile bool isLogging = false;
static int bmp180_fd;

// Calibration data
static int16_t ac1, ac2, ac3, b1, b2, mb, mc, md;
static uint16_t ac4, ac5, ac6;

// Function prototypes
int16_t read_int16(int fd, uint8_t reg);
uint16_t read_uint16(int fd, uint8_t reg);
int32_t read_uncompensated_temperature(int fd);
int32_t read_uncompensated_pressure(int fd, uint8_t oss);
float calculate_temperature(int32_t ut, int16_t ac5, int16_t ac6, int16_t mc, int16_t md);
float calculate_pressure(int32_t up, int32_t ut, int16_t ac1, int16_t ac2, int16_t ac3, uint16_t ac4, uint16_t ac5, uint16_t ac6, int16_t b1, int16_t b2, int16_t mb, int16_t mc, int16_t md, uint8_t oss);
bool initialize_bmp180(int fd);
void loggingToggle(void);

int main(void) {
    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed!\n");
        return 1;
    }

    // Initialize I2C
    bmp180_fd = wiringPiI2CSetup(BMP180_ADDR);
    if (bmp180_fd == -1) {
        fprintf(stderr, "I2C initialization failed!\n");
        return 1;
    }

    // Initialize BMP180
    if (!initialize_bmp180(bmp180_fd)) {
        fprintf(stderr, "BMP180 initialization failed!\n");
        return 1;
    }

    // Configure GPIO25 as input with pull-up resistor
    pinMode(25, INPUT);
    pullUpDnControl(25, PUD_UP);

    // Attach interrupt to GPIO25 (falling edge)
    if (wiringPiISR(25, INT_EDGE_FALLING, loggingToggle) < 0) {
        fprintf(stderr, "Unable to setup ISR!\n");
        return 1;
    }

    printf("Data logging is initially OFF.  Toggle with falling edge on GPIO25.\n");

    // Main loop
    while (1) {
        if (isLogging) {
            // Read temperature and pressure
            int32_t ut = read_uncompensated_temperature(bmp180_fd);
            int32_t up = read_uncompensated_pressure(bmp180_fd, BMP180_OSS);

            // Calculate compensated temperature and pressure
            float temperature = calculate_temperature(ut, ac5, ac6, mc, md);
            float pressure = calculate_pressure(up, ut, ac1, ac2, ac3, ac4, ac5, ac6, b1, b2, mb, mc, md, BMP180_OSS);

            // Get current timestamp
            time_t rawtime;
            struct tm *timeinfo;
            time(&rawtime);
            timeinfo = localtime(&rawtime);
            char timestamp[20]; // Enough space for "YYYY-MM-DD HH:MM:SS"
            strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

            // Format data as CSV string
            char csv_string[100];
            snprintf(csv_string, sizeof(csv_string), "%s,%.2f\n", timestamp, pressure);

            // Open file for appending
            FILE *fp = fopen("pressure_log.txt", "a");
            if (fp == NULL) {
                fprintf(stderr, "Error opening file!\n");
            } else {
                // Write data to file
                if (fprintf(fp, "%s", csv_string) < 0) {
                    fprintf(stderr, "Error writing to file!\n");
                }

                // Close file
                fclose(fp);
            }
        }

        delay(1000); // Log data every second
    }

    return 0;
}

// Interrupt handler to toggle logging
void loggingToggle(void) {
    isLogging = !isLogging;
    printf("Data logging is now %s.\n", isLogging ? "ON" : "OFF");
}

// Function to read a signed 16-bit integer from I2C
int16_t read_int16(int fd, uint8_t reg) {
    int16_t msb = wiringPiI2CReadReg8(fd, reg);
    int16_t lsb = wiringPiI2CReadReg8(fd, reg + 1);

    if (msb == -1 || lsb == -1) {
        fprintf(stderr, "I2C read error!\n");
        return 0; // Or some other error value
    }
    return (msb << 8) | lsb;
}

// Function to read an unsigned 16-bit integer from I2C
uint16_t read_uint16(int fd, uint8_t reg) {
    uint16_t msb = wiringPiI2CReadReg8(fd, reg);
    uint16_t lsb = wiringPiI2CReadReg8(fd, reg + 1);

    if (msb == -1 || lsb == -1) {
        fprintf(stderr, "I2C read error!\n");
        return 0; // Or some other error value
    }

    return (msb << 8) | lsb;
}

// Function to read the uncompensated temperature from the BMP180
int32_t read_uncompensated_temperature(int fd) {
    wiringPiI2CWriteReg8(fd, BMP180_REG_CONTROL, 0x2E);
    delay(5); // Wait 4.5ms
    return read_int16(fd, BMP180_REG_MSB);
}

// Function to read the uncompensated pressure from the BMP180
int32_t read_uncompensated_pressure(int fd, uint8_t oss) {
    wiringPiI2CWriteReg8(fd, BMP180_REG_CONTROL, 0x34 + (oss << 6));
    delay(2 + (3 << oss)); // Wait time depends on OSS

    int32_t msb = wiringPiI2CReadReg8(fd, BMP180_REG_MSB);
    int32_t lsb = wiringPiI2CReadReg8(fd, BMP180_REG_LSB);
    int32_t xlsb = wiringPiI2CReadReg8(fd, BMP180_REG_XLSB);

    if (msb == -1 || lsb == -1 || xlsb == -1) {
        fprintf(stderr, "I2C read error!\n");
        return 0; // Or some other error value
    }

    return ((msb << 16) + (lsb << 8) + xlsb) >> (8 - oss);
}

// Function to calculate the compensated temperature (degrees Celsius)
float calculate_temperature(int32_t ut, int16_t ac5, int16_t ac6, int16_t mc, int16_t md) {
    int32_t x1 = ((ut - (int32_t)ac6) * (int32_t)ac5) >> 15;
    int32_t x2 = ((int32_t)mc << 11) / (x1 + md);
    int32_t b5 = x1 + x2;
    float temperature = (float)(b5 + 8) / 16.0;
    return temperature;
}

// Function to calculate the compensated pressure (Pascals)
float calculate_pressure(int32_t up, int32_t ut, int16_t ac1, int16_t ac2, int16_t ac3, uint16_t ac4, uint16_t ac5, uint16_t ac6, int16_t b1, int16_t b2, int16_t mb, int16_t mc, int16_t md, uint8_t oss) {
    int32_t x1 = ((ut - (int32_t)ac6) * (int32_t)ac5) >> 15;
    int32_t x2 = ((int32_t)mc << 11) / (x1 + md);
    int32_t b5 = x1 + x2;

    int32_t b6 = b5 - 4000;
    x1 = (b2 * (b6 * b6) >> 12) >> 11;
    x2 = (ac2 * b6) >> 11;
    int32_t x3 = x1 + x2;
    int32_t b3 = (((((int32_t)ac1) * 4 + x3) << oss) + 2) >> 2;

    x1 = (ac3 * b6) >> 13;
    x2 = (b1 * ((b6 * b6) >> 12)) >> 16;
    x3 = ((x1 + x2) + 2) >> 2;
    uint32_t b4 = (uint32_t)ac4 * (uint32_t)(x3 + 32768) >> 15;

    uint32_t b7 = ((uint32_t)up - b3) * (uint32_t)(50000 >> oss);
    int32_t p;
    if (b7 < 0x80000000) {
        p = (b7 * 2) / b4;
    } else {
        p = (b7 / b4) * 2;
    }

    x1 = (p >> 8) * (p >> 8);
    x1 = (x1 * 3038) >> 16;
    x2 = (-7357 * p) >> 16;
    p = p + ((x1 + x2 + 3791) >> 4);

    return (float)p;
}

// Function to initialize the BMP180 and read calibration data
bool initialize_bmp180(int fd) {
    // Read calibration data
    ac1 = read_int16(fd, BMP180_REG_AC1);
    ac2 = read_int16(fd, BMP180_REG_AC2);
    ac3 = read_int16(fd, BMP180_REG_AC3);
    ac4 = read_uint16(fd, BMP180_REG_AC4);
    ac5 = read_uint16(fd, BMP180_REG_AC5);
    ac6 = read_uint16(fd, BMP180_REG_AC6);
    b1 = read_int16(fd, BMP180_REG_B1);
    b2 = read_int16(fd, BMP180_REG_B2);
    mb = read_int16(fd, BMP180_REG_MB);
    mc = read_int16(fd, BMP180_REG_MC);
    md = read_int16(fd, BMP180_REG_MD);

    // Check for invalid calibration data (very basic check)
    if (ac1 == 0 || ac2 == 0 || ac3 == 0 || ac4 == 0 || ac5 == 0 || ac6 == 0) {
        fprintf(stderr, "Invalid calibration data!\n");
        return false;
    }

    return true;
}

