#include <linux/i2c-dev.h>
#include <unistd.h>

// PCF8591 I2C Address
#define PCF8591_ADDR 0x48

int main() {
    int file;
    int i;

    // Open I2C device file
    if ((file = open("/dev/i2c-1", O_RDWR)) < 0) {
        perror("Failed to open the i2c bus");
        exit(1);
    }

    // Specify the address of the slave device
    if (ioctl(file, I2C_SLAVE, PCF8591_ADDR) < 0) {
        perror("Failed to acquire bus access and/or talk to slave.");
        exit(1);
    }

    // Sweep the DAC output from 0 to 255
    for (i = 0; i <= 255; i++) {
        // Write the DAC value to the PCF8591
        if (write(file, &i, 1) != 1) {
            perror("Failed to write to the i2c bus.");
            close(file);
            exit(1);
        }

        printf("DAC Output: %d\n", i);

        // Delay for a short time (adjust as needed)
        usleep(10000); // 10ms
    }

    // Close the I2C device file
    close(file);

    return 0;
}

