#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>

// Define GPIO pins
#define DT 17
#define SCK 18
#define Buzzer 22

// Calibration constants (must be determined experimentally)
float zero_offset = 0.0; // Initial zero offset, calibrate this value.
float scaling_factor = 1.0; // Scaling factor, calibrate this value.
float weight_threshold = 100.0; // Weight threshold in grams

// Function to read from HX711
long readHX711() {
    long value = 0;
    int i;

    gpioSetMode(DT, PI_INPUT); // Ensure DT is input
    gpioSetMode(SCK, PI_OUTPUT); // Ensure SCK is output

    // Wait for DT to go low (HX711 ready)
    int timeout = 0;
    while (gpioRead(DT) == 1 && timeout < 1000) {
        gpioDelay(1); // Wait 1 us
        timeout++;
    }

    if (timeout >= 1000) {
        fprintf(stderr, "Error: HX711 not ready (DT high)\n");
        return -1; // Indicate error
    }

    for (i = 0; i < 24; i++) {
        gpioWrite(SCK, 1);
        gpioDelay(1); // Short delay
        value = value << 1; // Shift left by 1 bit
        if (gpioRead(DT) == 1) {
            value++;
        }
        gpioWrite(SCK, 0);
        gpioDelay(1); // Short delay
    }

    // 25th pulse to set gain to 128
    gpioWrite(SCK, 1);
    gpioDelay(1);
    gpioWrite(SCK, 0);
    gpioDelay(1);

    // Sign extend if negative
    if (value & 0x800000) {
        value |= 0xFF000000;
    }

    return value;
}

// Function to calibrate HX711
void calibrateHX711() {
    long sum = 0;
    int num_readings = 10;
    int i;

    printf("Calibrating... Please ensure no weight is on the load cell.\n");
    gpioDelay(2000000); // Wait 2 seconds

    for (i = 0; i < num_readings; i++) {
        long reading = readHX711();
        if (reading == -1) {
            fprintf(stderr, "Error during calibration reading. Aborting calibration.\n");
            return; // Exit calibration if there's an error
        }
        sum += reading;
        gpioDelay(100000); // Short delay between readings
    }

    zero_offset = (float)sum / num_readings;
    printf("Calibration complete. Zero offset: %.2f\n", zero_offset);
}

// Function to calculate weight
float calculateWeight(long raw_value) {
    return (raw_value - zero_offset) / scaling_factor;
}

// Function to check weight threshold
int checkThreshold(float weight) {
    return (weight > weight_threshold) ? 1 : 0;
}

// Function to control buzzer
void controlBuzzer(int activate) {
    gpioWrite(Buzzer, activate);
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(Buzzer, PI_OUTPUT);

    calibrateHX711();

    printf("Reading weight...\n");

    while (1) {
        long raw_value = readHX711();
        if (raw_value != -1) {
            float weight = calculateWeight(raw_value);
            printf("Weight: %.2f grams\n", weight);

            int threshold_exceeded = checkThreshold(weight);
            controlBuzzer(threshold_exceeded);
        } else {
            fprintf(stderr, "Error reading HX711 value.\n");
        }

        gpioDelay(100000); // 100ms delay
    }

    gpioTerminate();
    return 0;
}

