#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <time.h>
#include <pigpio.h>

// Define GPIO pins for the vibration motors
#define MOTOR1_GPIO 17 // GPIO 17 for the first motor (1-minute load)
#define MOTOR2_GPIO 27 // GPIO 27 for the second motor (5-minute load)

// Global variable to indicate program termination
volatile sig_atomic_t program_running = 1;

// Function to initialize GPIO using pigpio
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1; // Indicate failure
    }
    gpioSetMode(MOTOR1_GPIO, PI_OUTPUT);
    gpioSetMode(MOTOR2_GPIO, PI_OUTPUT);
    return 0; // Indicate success
}

// Function to set the PWM duty cycle for a motor
int set_motor_intensity(int gpio_pin, int duty_cycle) {
    if (duty_cycle < 0 || duty_cycle > 255) {
        fprintf(stderr, "Invalid duty cycle value: %d. Must be between 0 and 255.\n", duty_cycle);
        return -1; // Indicate failure
    }
    gpioPWM(gpio_pin, duty_cycle);
    return 0; // Indicate success
}

// Function to retrieve the CPU load average
double get_cpu_load() {
    double loadavg[3];
    if (getloadavg(loadavg, 3) < 0) {
        perror("getloadavg failed");
        return -1.0; // Indicate failure
    }
    return loadavg[0]; // Return the 1-minute load average
}

// Signal handler for Ctrl+C (SIGINT)
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("Ctrl+C detected. Cleaning up and exiting.\n");
        program_running = 0; // Set the flag to exit the main loop
    }
}

int main() {
    // Register the signal handler for SIGINT
    signal(SIGINT, signal_handler);

    // Initialize GPIO
    if (initialize_gpio() != 0) {
        return 1; // Exit if GPIO initialization fails
    }

    // Main loop
    while (program_running) {
        // Get the CPU load average
        double load_1min = get_cpu_load();
        double load_5min;
        double loadavg[3];
        getloadavg(loadavg,3);
        load_5min = loadavg[1];

        if (load_1min < 0) {
            fprintf(stderr, "Failed to retrieve CPU load average. Setting motors to 0.\n");
            set_motor_intensity(MOTOR1_GPIO, 0);
            set_motor_intensity(MOTOR2_GPIO, 0);
        } else {
            // Map the CPU load average to a PWM duty cycle (0-255)
            int duty_cycle_1min = (int)(load_1min * 50); // Adjust scaling factor as needed
            int duty_cycle_5min = (int)(load_5min * 50); // Adjust scaling factor as needed

            if (duty_cycle_1min > 255) duty_cycle_1min = 255;
            if (duty_cycle_5min > 255) duty_cycle_5min = 255;
            if (duty_cycle_1min < 0) duty_cycle_1min = 0;
            if (duty_cycle_5min < 0) duty_cycle_5min = 0;

            // Set the motor intensities
            if (set_motor_intensity(MOTOR1_GPIO, duty_cycle_1min) != 0) {
                fprintf(stderr, "Failed to set motor 1 intensity.\n");
            }
            if (set_motor_intensity(MOTOR2_GPIO, duty_cycle_5min) != 0) {
                fprintf(stderr, "Failed to set motor 2 intensity.\n");
            }
        }

        // Wait for 0.5 seconds
        struct timespec sleep_time;
        sleep_time.tv_sec = 0;
        sleep_time.tv_nsec = 500000000; // 0.5 seconds
        nanosleep(&sleep_time, NULL);
    }

    // Cleanup GPIO before exiting
    gpioTerminate();
    printf("Program terminated.\n");
    return 0;
}

