#include <pigpio.h>
#include <stdio.h>
#define INA1 17  // BCM GPIO 17
#define INA2 27  // BCM GPIO 27
#define ENA  22  // BCM GPIO 22
#define BUTTON 4  // BCM GPIO 4

void setup() {
    if (gpioInitialise() < 0) return;
    gpioSetMode(INA1, PI_OUTPUT);
    gpioSetMode(INA2, PI_OUTPUT);
    gpioSetMode(ENA, PI_OUTPUT);
    gpioSetMode(BUTTON, PI_INPUT);
    gpioSetPullUpDown(BUTTON, PI_PUD_UP);
}

void openBlinds() {
    gpioWrite(INA1, 1);
    gpioWrite(INA2, 0);
    gpioPWM(ENA, 80);
    gpioDelay(5000000);
    gpioWrite(INA1, 0);
    gpioWrite(INA2, 0);
    gpioPWM(ENA, 0);
}

void closeBlinds() {
    gpioWrite(INA1, 0);
    gpioWrite(INA2, 1);
    gpioPWM(ENA, 80);
    gpioDelay(5000000);
    gpioWrite(INA1, 0);
    gpioWrite(INA2, 0);
    gpioPWM(ENA, 0);
}

int main() {
    setup();
    int state = 0;
    while (1) {
        if (gpioRead(BUTTON) == 0) {
            state = !state;
            if (state) openBlinds(); else closeBlinds();
            gpioDelay(300000);
        }
    }
    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <fcntl.h>
#include <linux/spi/spidev.h>
#include <sys/ioctl.h>
#include <stdint.h>

int read_adc(int fd, int ch) {
    uint8_t tx[] = {1, (0x80 | (ch << 4)), 0};
    uint8_t rx[3];
    struct spi_ioc_transfer tr = {
        .tx_buf = (unsigned long)tx,
        .rx_buf = (unsigned long)rx,
        .len = 3,
        .speed_hz = 1000000,
        .bits_per_word = 8
    };
    ioctl(fd, SPI_IOC_MESSAGE(1), &tr);
    return ((rx[1] & 0x03) << 8) | rx[2];
}

int main() {
    int fd = open("/dev/spidev0.0", O_RDWR);
    while (1) {
        for (int i = 0; i < 4; i++) printf("%d ", read_adc(fd, i));
        printf("\n"); fflush(stdout);
        usleep(200000);
    }
    return 0;
}

#include <stdio.h>
