#include <sys/ioctl.h>

int try_address(int file, int addr) {
    if (ioctl(file, I2C_SLAVE, addr) < 0) return 0;
    return (write(file, "", 0) >= 0);
}

int main() {
    const char* device = "/dev/i2c-1";
    int file = open(device, O_RDWR);
    if (file < 0) {
        perror("I2C open failed");
        return 1;
    }

    int found_ads1115 = 0, found_pcf8591 = 0;
    for (int addr = 0x03; addr <= 0x77; addr++) {
        if (try_address(file, addr)) {
            if (addr == 0x48) found_ads1115 = 1;
            if (addr == 0x48 || addr == 0x4F) found_pcf8591 = 1;
            printf("Device found at 0x%02X\n", addr);
        }
    }

    if (found_ads1115) printf("ADS1115 detected!\n");
    if (found_pcf8591) printf("PCF8591 detected!\n");

    close(file);
    return 0;
}

#include <stdio.h>
