// Define GPIO pins
#define BUZZER_PIN 17
#define PIR_SENSOR_PIN 18

// Debounce time in milliseconds
#define DEBOUNCE_TIME 500

// Buzzer duration in seconds
#define BUZZER_DURATION 3

// Alarm state file name
#define ALARM_STATE_FILE "alarm_state.txt"

// Global variable to track the last detection time
static volatile unsigned long last_detection_time = 0;

// Function to initialize GPIO pins
int initializeGPIO() {
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "GPIO initialization failed!\n");
        return -1;
    }

    // Set BUZZER_PIN as output
    pinMode(BUZZER_PIN, OUTPUT);
    digitalWrite(BUZZER_PIN, LOW); // Ensure buzzer is initially off

    // Set PIR_SENSOR_PIN as input
    pinMode(PIR_SENSOR_PIN, INPUT);

    return 0;
}

// Function to read the PIR sensor value
int readPIRSensor() {
    return digitalRead(PIR_SENSOR_PIN);
}

// Function to activate the buzzer
void activateBuzzer() {
    digitalWrite(BUZZER_PIN, HIGH);
    printf("Buzzer activated!\n");
    sleep(BUZZER_DURATION);
    digitalWrite(BUZZER_PIN, LOW);
    printf("Buzzer deactivated!\n");
}

// Function to check the alarm state from the file
int checkAlarmState() {
    FILE *fp = fopen(ALARM_STATE_FILE, "r");
    if (fp == NULL) {
        // File doesn't exist, assume alarm is enabled
        return 1;
    }

    char state;
    if (fread(&state, 1, 1, fp) != 1) {
        fclose(fp);
        return 1; // Error reading file, assume alarm is enabled
    }

    fclose(fp);

    return (state != '0'); // Return 1 if alarm is enabled, 0 if disabled
}

// Signal handler for Ctrl+C
void signalHandler(int signum) {
    printf("Interrupt signal (%d) received.\n", signum);
    digitalWrite(BUZZER_PIN, LOW); // Ensure buzzer is off
    exit(0);
}

int main() {
    // Register signal handler
    signal(SIGINT, signalHandler);

    // Initialize GPIO
    if (initializeGPIO() == -1) {
        return 1;
    }

    printf("Burglar alarm system started. Press Ctrl+C to exit.\n");

    while (1) {
        // Read PIR sensor value
        int pir_value = readPIRSensor();

        // Check for motion detection
        if (pir_value == HIGH) {
            // Debounce the sensor
            unsigned long current_time = millis();
            if (current_time - last_detection_time > DEBOUNCE_TIME) {
                // Check alarm state
                if (checkAlarmState()) {
                    // Activate buzzer
                    activateBuzzer();
                } else {
                    printf("Alarm is disabled. Motion detected but buzzer not activated.\n");
                }
                last_detection_time = current_time;
            }
        }

        // Small delay to avoid busy-waiting
        delay(100);
    }

    return 0;
}

