#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>

// Define constants
#define SPI_CHANNEL 0
#define SPI_SPEED 50000
#define ALERT_GPIO 17
#define MOISTURE_BUFFER_SIZE 10

// Global variables
int spi_handle;
volatile int running = 1;

// Circular buffer for moisture readings
float moisture_buffer[MOISTURE_BUFFER_SIZE];
int buffer_index = 0;

// Function prototypes
int read_mcp3008(int channel);
float convert_adc_to_moisture(int adc_value);
void add_to_buffer(float moisture);
float calculate_average_moisture();
int check_moisture_threshold(float average_moisture, float threshold);
void trigger_alert(int alert_state);
void signal_handler(int signal);

// Function to read from MCP3008 ADC
int read_mcp3008(int channel) {
    char tx_buffer[3];
    char rx_buffer[3];

    tx_buffer[0] = 0x01;
    tx_buffer[1] = (0x08 + channel) << 4;
    tx_buffer[2] = 0x00;

    spiXfer(spi_handle, tx_buffer, rx_buffer, 3);

    int adc_value = ((rx_buffer[1] & 0x03) << 8) + rx_buffer[2];
    return adc_value;
}

// Function to convert ADC reading to moisture percentage
float convert_adc_to_moisture(int adc_value) {
    // Simple linear conversion (0-1023 to 0-100%)
    // Consider calibration for better accuracy
    return (float)adc_value / 1023.0 * 100.0;
}

// Function to add a new reading to the circular buffer
void add_to_buffer(float moisture) {
    moisture_buffer[buffer_index] = moisture;
    buffer_index = (buffer_index + 1) % MOISTURE_BUFFER_SIZE;
}

// Function to calculate the average moisture level from the buffer
float calculate_average_moisture() {
    float sum = 0.0;
    for (int i = 0; i < MOISTURE_BUFFER_SIZE; i++) {
        sum += moisture_buffer[i];
    }
    return sum / MOISTURE_BUFFER_SIZE;
}

// Function to check if the average moisture level is below the threshold
int check_moisture_threshold(float average_moisture, float threshold) {
    return (average_moisture < threshold) ? 1 : 0;
}

// Function to trigger the alert (turn LED on/off)
void trigger_alert(int alert_state) {
    gpioWrite(ALERT_GPIO, alert_state);
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, cleaning up...\n", signal);
    running = 0;
    gpioWrite(ALERT_GPIO, 0); // Turn off LED
    spiClose(spi_handle);
    gpioTerminate();
    exit(0);
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        printf("pigpio initialisation failed\n");
        return 1;
    }

    // Configure alert GPIO as output
    gpioSetMode(ALERT_GPIO, PI_OUTPUT);

    // Open SPI channel
    spi_handle = spiOpen(SPI_CHANNEL, SPI_SPEED, 0);
    if (spi_handle < 0) {
        printf("SPI open failed\n");
        gpioTerminate();
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize moisture buffer with zeros
    for (int i = 0; i < MOISTURE_BUFFER_SIZE; i++) {
        moisture_buffer[i] = 0.0;
    }

    float moisture_threshold = 30.0; // Set moisture threshold

    // Main loop
    while (running) {
        // Read analog value from VH400 sensor (MCP3008 channel 0)
        int adc_value = read_mcp3008(0);

        // Convert ADC reading to moisture level
        float moisture_level = convert_adc_to_moisture(adc_value);

        // Add moisture level to circular buffer
        add_to_buffer(moisture_level);

        // Calculate average moisture level
        float average_moisture = calculate_average_moisture();

        // Check if moisture level is below threshold
        int alert_state = check_moisture_threshold(average_moisture, moisture_threshold);

        // Trigger alert if necessary
        trigger_alert(alert_state);

        // Get current timestamp
        time_t now = time(NULL);
        struct tm *tstruct = localtime(&now);
        char buf[80];
        strftime(buf, sizeof(buf), "%Y-%m-%d.%X", tstruct);

        // Log moisture level to console
        printf("%s - Moisture level: %.2f%%, Average: %.2f%%, Alert: %s\n", buf, moisture_level, average_moisture, alert_state ? "ON" : "OFF");

        // Delay for 1 second
        gpioDelay(1000); // Delay in milliseconds
    }

    return 0;
}

