#define SPI_SPEED 1000000 // 1 MHz

// MCP3008 channel to read (0-7)
#define MCP3008_CHANNEL 0

// Bar graph width
#define BAR_WIDTH 40

// Function to read MCP3008 ADC value
int read_mcp3008(int channel)
{
    if (channel < 0 || channel > 7) {
        fprintf(stderr, "Error: Invalid MCP3008 channel: %d\n", channel);
        return -1; // Indicate error
    }

    unsigned char spi_data[3];
    spi_data[0] = 0x01; // Start bit
    spi_data[1] = ((channel | 0x08) << 4); // Single-ended mode, channel select
    spi_data[2] = 0x00; // Don't care

    wiringPiSPIDataRW(SPI_CHANNEL, spi_data, 3);

    int adc_value = ((spi_data[1] & 0x03) << 8) + spi_data[2];
    return adc_value;
}

