#define BMP180_REG_CAL_B2 0xB8
#define BMP180_REG_CAL_MB 0xBA
#define BMP180_REG_CAL_MC 0xBC
#define BMP180_REG_CAL_MD 0xBE

// Commands
#define BMP180_CMD_TEMP 0x2E
#define BMP180_CMD_PRESSURE0 0x34 // Oss = 0
#define BMP180_CMD_PRESSURE1 0x74 // Oss = 1
#define BMP180_CMD_PRESSURE2 0xB4 // Oss = 2
#define BMP180_CMD_PRESSURE3 0xF4 // Oss = 3

//OLED defines (SSD1306)
#define OLED_SPI_CHANNEL 0
#define OLED_SPI_SPEED 8000000

#define OLED_WIDTH 128
