// Global variables
static int bmp180_fd;
static int oled_fd = -1;
static int lock_fd = -1;
volatile sig_atomic_t program_running = 1;

// Calibration data
static int16_t ac1, ac2, ac3, b1, b2, mb, mc, md;
static uint16_t ac4, ac5, ac6;

// Lock file path
const char *lock_file = "/tmp/bmp180.lock";

// Function prototypes
int init_bmp180();
