void format_data(float temperature, float pressure, char *temp_str, char *pressure_str);
void signal_handler(int signal);
bool acquire_lock();
void release_lock();

// Function to acquire a file lock
bool acquire_lock() {
    lock_fd = open(lock_file, O_RDWR | O_CREAT, 0666);
    if (lock_fd < 0) {
        perror("Error opening lock file");
        return false;
    }

    if (flock(lock_fd, LOCK_EX | LOCK_NB) == -1) {
        if (errno == EWOULDBLOCK) {
            fprintf(stderr, "I2C bus is busy, another process is using it.\n");
        } else {
            perror("Error acquiring lock");
        }
        close(lock_fd);
        lock_fd = -1;
        return false;
    }

    return true;
}

// Function to release the file lock
void release_lock() {
    if (lock_fd != -1) {
        if (flock(lock_fd, LOCK_UN) == -1) {
            perror("Error releasing lock");
        }
        close(lock_fd);
        lock_fd = -1;
    }
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    program_running = 0;
    printf("Caught signal %d, exiting gracefully.\n", signal);

    // Release resources
    if (bmp180_fd != -1) {
        release_lock();
        close(bmp180_fd);
    }
    if (oled_fd != -1) {
      oled_clear();
    }
    wiringPiSPIDataRW(OLED_SPI_CHANNEL, (unsigned char*)"\xAE", 1); //display off

    wiringPiSPIClose(OLED_SPI_CHANNEL);

    exit(0);
}

// Initialize the BMP180 sensor
int init_bmp180() {
    bmp180_fd = wiringPiI2CSetup(BMP180_ADDR);
    if (bmp180_fd == -1) {
        perror("Failed to initialize BMP180");
        return -1;
    }
    return 0;
}

// Initialize the OLED display
int init_oled() {

    wiringPiSPISetup(OLED_SPI_CHANNEL, OLED_SPI_SPEED);
    if (oled_fd < 0) {
        fprintf(stderr, "wiringPiSPISetup failed\n");
        return -1;
    }

    // Reset the OLED display
    pinMode(OLED_RESET_PIN, OUTPUT);
digitalWrite(OLED_RESET_PIN, HIGH);
delay(100);
digitalWrite(OLED_RESET_PIN, LOW);
delay(100);
digitalWrite(OLED_RESET_PIN, HIGH);
delay(100);

    // Initialization sequence for SSD1306
    oled_command(0xAE); // Display off
    oled_command(0xD5); // Set display clock divide ratio/oscillator frequency
    oled_command(0x80); // Default setting for display clock divide ratio/oscillator frequency
    oled_command(0xA8); // Set multiplex ratio
    oled_command(0x3F); // 64 rows
    oled_command(0xD3); // Set display offset
    oled_command(0x00); // No offset
    oled_command(0x40); // Set start line address
    oled_command(0x8D); // Charge pump setting
    oled_command(0x14); // Enable charge pump
    oled_command(0x20); // Set memory addressing mode
    oled_command(0x00); // Horizontal addressing mode
    oled_command(0xA1); // Set segment re-map
    oled_command(0xC8); // Set COM output scan direction
    oled_command(0xDA); // Set COM pins hardware configuration
    oled_command(0x12); // Alternative COM pin configuration
    oled_command(0x81); // Set contrast control
    oled_command(0xCF); // Set contrast to maximum
    oled_command(0xD9); // Set pre-charge period
    oled_command(0xF1); // Phase 1 and 2 period setting
    oled_command(0xDB); // Set VCOM deselect level
    oled_command(0x40); // VCOM deselect level setting
    oled_command(0xA4); // Entire display ON/OFF
    oled_command(0xA6); // Set normal display
    oled_command(0xAF); // Display on

    oled_clear();

    return 0;
}

// Send a command to the OLED display
void oled_command(uint8_t command) {
    unsigned char buf[2];
    buf[0] = 0x80; //Co = 1, D/C = 0
    buf[1] = command;
    wiringPiSPIDataRW(OLED_SPI_CHANNEL, buf, 2);
}

// Send data to the OLED display
void oled_data(uint8_t data) {
    unsigned char buf[2];
    buf[0] = 0xC0; //Co = 1, D/C = 1
    buf[1] = data;
    wiringPiSPIDataRW(OLED_SPI_CHANNEL, buf, 2);
}

void oled_set_position(int x, int y) {
    oled_command(0xB0 + y);                       //set page address
    oled_command(0x00 + (x & 0x0F));              //set column lower address
    oled_command(0x10 + ((x >> 4) & 0x0F));         //set column higher address
}

// Write a string to the OLED display at the specified position
