// Read calibration data from the BMP180 EEPROM
void read_calibration_data() {
    if (!acquire_lock()) return;
    ac1 = wiringPiI2CReadReg16(bmp180_fd, BMP180_REG_CAL_AC1);
    ac2 = wiringPiI2CReadReg16(bmp180_fd, BMP180_REG_CAL_AC2);
    ac3 = wiringPiI2CReadReg16(bmp180_fd, BMP180_REG_CAL_AC3);
    ac4 = wiringPiI2CReadReg16(bmp180_fd, BMP180_REG_CAL_AC4);
    ac5 = wiringPiI2CReadReg16(bmp180_fd, BMP180_REG_CAL_AC5);
    ac6 = wiringPiI2CReadReg16(bmp180_fd, BMP180_REG_CAL_AC6);
    b1 = wiringPiI2CReadReg16(bmp180_fd, BMP180_REG_CAL_B1);
    b2 = wiringPiI2CReadReg16(bmp180_fd, BMP180_REG_CAL_B2);
    mb = wiringPiI2CReadReg16(bmp180_fd, BMP180_REG_CAL_MB);
    mc = wiringPiI2CReadReg16(bmp180_fd, BMP180_REG_CAL_MC);
    md = wiringPiI2CReadReg16(bmp180_fd, BMP180_REG_CAL_MD);
    release_lock();

    // Byte swap (BMP180 returns big-endian)
    ac1 = __builtin_bswap16(ac1);
    ac2 = __builtin_bswap16(ac2);
    ac3 = __builtin_bswap16(ac3);
    ac4 = __builtin_bswap16(ac4);
    ac5 = __builtin_bswap16(ac5);
    ac6 = __builtin_bswap16(ac6);
    b1 = __builtin_bswap16(b1);
    b2 = __builtin_bswap16(b2);
    mb = __builtin_bswap16(mb);
    mc = __builtin_bswap16(mc);
    md = __builtin_bswap16(md);

}

// Read the uncompensated temperature value from the BMP180
int32_t read_raw_temperature() {
    int32_t ut = 0;

    if (!acquire_lock()) return -1;
    wiringPiI2CWriteReg8(bmp180_fd, BMP180_REG_CONTROL, BMP180_CMD_TEMP);
delay(5);
    ut = wiringPiI2CReadReg16(bmp180_fd, BMP180_REG_MSB);
    release_lock();

    return __builtin_bswap16(ut);
}

// Read the uncompensated pressure value from the BMP180
int32_t read_raw_pressure(uint8_t oss) {
    int32_t up = 0;

    if (!acquire_lock()) return -1;
    uint8_t cmd = BMP180_CMD_PRESSURE0;
    switch (oss) {
        case 0: cmd = BMP180_CMD_PRESSURE0; break;
        case 1: cmd = BMP180_CMD_PRESSURE1; break;
        case 2: cmd = BMP180_CMD_PRESSURE2; break;
        case 3: cmd = BMP180_CMD_PRESSURE3; break;
    }

    wiringPiI2CWriteReg8(bmp180_fd, BMP180_REG_CONTROL, cmd);
delay(2 + (3 << oss)); // Delay depends on OSS
    int msb = wiringPiI2CReadReg8(bmp180_fd, BMP180_REG_MSB);
    int lsb = wiringPiI2CReadReg8(bmp180_fd, BMP180_REG_LSB);
    int xlsb = wiringPiI2CReadReg8(bmp180_fd, BMP180_REG_XLSB);
    release_lock();

    up = ((int32_t)msb << 16 | (int32_t)lsb << 8 | (int32_t)xlsb) >> (8 - oss);

    return up;
}

// Calculate the true temperature based on calibration data and uncompensated value
float calculate_temperature(int32_t ut) {
    int32_t x1 = (((int32_t)ut - (int32_t)ac6) * (int32_t)ac5) >> 15;
    int32_t x2 = ((int32_t)mc << 11) / (x1 + md);
    int32_t b5 = x1 + x2;
    float temperature = ((b5 + 8) >> 4) / 10.0f; // Temperature in degrees Celsius
    return temperature;
}

// Calculate the true pressure based on calibration data, uncompensated value, and temperature
float calculate_pressure(int32_t up, int8_t oss, int32_t ut) {
    int32_t x1 = (((int32_t)ut - (int32_t)ac6) * (int32_t)ac5) >> 15;
    int32_t x2 = ((int32_t)mc << 11) / (x1 + md);
    int32_t b5 = x1 + x2;

    int32_t b6 = b5 - 4000;
    x1 = (b2 * (b6 * b6) >> 12) >> 11;
    x2 = (ac2 * b6) >> 11;
    int32_t x3 = x1 + x2;
    int32_t b3 = (((((int32_t)ac1) * 4 + x3) << oss) + 2) >> 2;

    x1 = (ac3 * b6) >> 13;
    x2 = (b1 * ((b6 * b6) >> 12)) >> 16;
    x3 = ((x1 + x2) + 2) >> 2;
    uint32_t b4 = (uint32_t)ac4 * (uint32_t)(x3 + 32768) >> 15;
    uint32_t b7 = ((uint32_t)up - b3) * (50000 >> oss);

    int32_t p = 0;
    if (b7 < 0x80000000) {
        p = (b7 * 2) / b4;
    } else {
        p = (b7 / b4) * 2;
    }

    x1 = (p >> 8) * (p >> 8);
    x1 = (x1 * 3038) >> 16;
    x2 = (-7357 * p) >> 16;
    p = p + ((x1 + x2 + 3791) >> 4);

    float pressure = p / 100.0f; // Pressure in hPa
    return pressure;
}

// Format temperature and pressure values as strings
void format_data(float temperature, float pressure, char *temp_str, char *pressure_str) {
    sprintf(temp_str, "Temp: %.2f C", temperature);
    sprintf(pressure_str, "Pressure: %.2f hPa", pressure);
}

int main() {
    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Failed to initialize WiringPi\n");
        return 1;
    }

    // Initialize BMP180
    if (init_bmp180() == -1) {
        fprintf(stderr, "Failed to initialize BMP180\n");
        return 1;
    }

    // Initialize OLED display
    if (init_oled() == -1) {
        fprintf(stderr, "Failed to initialize OLED\n");
        return 1;
    }

    // Read calibration data
    read_calibration_data();

    // Set up signal handling for SIGINT
    signal(SIGINT, signal_handler);

    printf("Monitoring system started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        // Read raw temperature and pressure values
        int32_t ut = read_raw_temperature();
        int32_t up = read_raw_pressure(3); // Use OSS = 3 for highest resolution

        if (ut != -1 && up != -1) {
            // Calculate true temperature and pressure
            float temperature = calculate_temperature(ut);
            float pressure = calculate_pressure(up, 3, ut);

            // Format data as strings
            char temp_str[32];
            char pressure_str[32];
            format_data(temperature, pressure, temp_str, pressure_str);

            // Display data on OLED
            oled_clear();
            oled_write_string(0, 0, temp_str);
            oled_write_string(0, 1, pressure_str);

            printf("%s\n", temp_str);
            printf("%s\n", pressure_str);
        } else {
            fprintf(stderr, "Failed to read temperature or pressure\n");
        }

        delay(5000); // Update every 5 seconds
    }

    return 0;
}

