#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <unistd.h>

// Define MCP3008 and LED pins
#define SPI_CHANNEL 0 // SPI channel (CE0)
#define CS_PIN 8      // Chip Select Pin (GPIO 8)

#define LED1_PIN 17
#define LED2_PIN 27
#define LED3_PIN 22
#define LED4_PIN 10

// Function to read from MCP3008 ADC
int read_mcp3008(int channel)
{
    if (channel < 0 || channel > 7) return -1; // Invalid channel

    int spi_handle = spiOpen(SPI_CHANNEL, 100000, 0); // Open SPI channel with 100kHz and mode 0
    if (spi_handle < 0)
    {
        fprintf(stderr, "Error opening SPI channel: %d\n", spi_handle);
        return -1;
    }

    unsigned char tx_buffer[3];
    unsigned char rx_buffer[3];

    // Construct the SPI message to send to the MCP3008
    tx_buffer[0] = 0x01;                  // Start bit
    tx_buffer[1] = ((0x08 | channel) << 4); // Single-ended mode, channel number
    tx_buffer[2] = 0x00;                  // Don't care bit

    // Send the message and receive the result
    spiXfer(spi_handle, tx_buffer, rx_buffer, 3);

    // Extract the ADC value from the received bytes
    int adc_value = ((rx_buffer[1] & 0x03) << 8) + rx_buffer[2];

    spiClose(spi_handle);
    return adc_value;
}

int main()
{
    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set LED pins as output
    gpioSetMode(LED1_PIN, PI_OUTPUT);
    gpioSetMode(LED2_PIN, PI_OUTPUT);
    gpioSetMode(LED3_PIN, PI_OUTPUT);
    gpioSetMode(LED4_PIN, PI_OUTPUT);

    while (1)
    {
        // Read ADC values from all channels
        for (int channel = 0; channel < 8; channel++)
        {
            int adc_value = read_mcp3008(channel);
            if (adc_value < 0)
            {
                fprintf(stderr, "Error reading from channel %d\n", channel);
                continue; // Skip to the next channel
            }

            printf("Channel %d: ADC Value = %d\n", channel, adc_value);

            //Example thresholds (adjust as needed)
            if (channel == 0)
            {
                if (adc_value > 200)
                {
                    gpioWrite(LED1_PIN, 1); // Turn on LED1
                }
                else
                {
                    gpioWrite(LED1_PIN, 0); // Turn off LED1
                }
            }
            if (channel == 1)
            {
                if (adc_value > 400)
                {
                    gpioWrite(LED2_PIN, 1); // Turn on LED2
                }
                else
                {
                    gpioWrite(LED2_PIN, 0); // Turn off LED2
                }
            }
            if (channel == 2)
            {
                if (adc_value > 600)
                {
                    gpioWrite(LED3_PIN, 1); // Turn on LED3
                }
                else
                {
                    gpioWrite(LED3_PIN, 0); // Turn off LED3
                }
            }
            if (channel == 3)
            {
                if (adc_value > 800)
                {
                    gpioWrite(LED4_PIN, 1); // Turn on LED4
                }
                else
                {
                    gpioWrite(LED4_PIN, 0); // Turn off LED4
                }
            }
        }

        usleep(500000); // Wait 0.5 seconds
    }

    gpioTerminate();
    return 0;
}

