#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <time.h>
#include <pigpio.h>

// Define GPIO pins
#define TRIGGER_PIN 23
#define ECHO_PIN 24
#define SERVO_PIN 18

// Define constants
#define SPEED_OF_SOUND 34300 // cm/s
#define MIN_DISTANCE 2.0    // cm
#define MAX_DISTANCE 200.0  // cm
#define MIN_ANGLE 0
#define MAX_ANGLE 180
#define MIN_PULSE_WIDTH 500
#define MAX_PULSE_WIDTH 2500
#define ERROR_VALUE -1.0

// Global variables
FILE *log_file = NULL;

// Function prototypes
float read_distance();
int set_servo_angle(int angle);
int log_data(float distance, int angle);
void signal_handler(int signal);

// Signal handler function
void signal_handler(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);

    // Set servo to a safe position (90 degrees)
    set_servo_angle(90);

    // Close the log file if it's open
    if (log_file != NULL) {
        fclose(log_file);
        printf("Log file closed.\n");
    }

    // Terminate pigpio
    gpioTerminate();
    printf("pigpio terminated.\n");

    exit(0);
}

// Function to read distance from HC-SR04 sensor
float read_distance() {
    // Trigger the sensor
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioWrite(TRIGGER_PIN, 0);
    gpioDelay(2); // 2us
    gpioWrite(TRIGGER_PIN, 1);
    gpioDelay(10); // 10us
    gpioWrite(TRIGGER_PIN, 0);

    // Measure the echo pulse width
    gpioSetMode(ECHO_PIN, PI_INPUT);
    int start_tick = gpioTick();
    while (gpioRead(ECHO_PIN) == 0 && (gpioTick() - start_tick) < 50000) {}; // Wait for echo start, with timeout
    int start = gpioTick();
    while (gpioRead(ECHO_PIN) == 1 && (gpioTick() - start_tick) < 50000) {}; // Wait for echo end, with timeout
    int end = gpioTick();

    // Calculate the pulse width in microseconds
    int pulse_width = end - start;

    // Error handling: check for invalid pulse widths
    if (pulse_width <= 0) {
        fprintf(stderr, "Error: Invalid pulse width (%d). Timeout or sensor error.\n", pulse_width);
        return ERROR_VALUE;
    }

    // Calculate the distance in centimeters
    float distance = (pulse_width * SPEED_OF_SOUND) / 2000000.0;

    return distance;
}

// Function to control the SG90 servo
int set_servo_angle(int angle) {
    // Input validation
    if (angle < MIN_ANGLE || angle > MAX_ANGLE) {
        fprintf(stderr, "Error: Invalid angle (%d). Angle must be between %d and %d.\n", angle, MIN_ANGLE, MAX_ANGLE);
        return -1;
    }

    // Map the angle to a PWM pulse width (500us - 2500us)
    int pulse_width = (int)(((float)(angle - MIN_ANGLE) / (MAX_ANGLE - MIN_ANGLE)) * (MAX_PULSE_WIDTH - MIN_PULSE_WIDTH) + MIN_PULSE_WIDTH);

    // Set the servo pulse width
    gpioServo(SERVO_PIN, pulse_width);

    return 0;
}

// Function to log data to a file
int log_data(float distance, int angle) {
    // Get the current time
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    // Open the log file in append mode
    if (log_file == NULL) {
        log_file = fopen("parking_data.log", "a");
        if (log_file == NULL) {
            fprintf(stderr, "Error: Could not open log file.\n");
            return -1;
        }
    }

    // Write the data to the log file
    fprintf(log_file, "%s,%.2f,%d\n", timestamp, distance, angle);
    fflush(log_file); // Ensure data is written immediately

    return 0;
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed.\n");
        return 1;
    }

    // Set signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Set GPIO modes
    gpioSetMode(SERVO_PIN, PI_OUTPUT);

    printf("Parking control system started. Press Ctrl+C to exit.\n");

    // Main loop
    while (1) {
        // Read the distance from the HC-SR04 sensor
        float distance = read_distance();

        // Validate the distance reading
        if (distance == ERROR_VALUE) {
            fprintf(stderr, "Error: Invalid distance reading, skipping.\n");
            gpioDelay(100);
            continue;
        }
        if (distance < MIN_DISTANCE || distance > MAX_DISTANCE) {
            fprintf(stderr, "Distance out of range (%.2f cm), skipping.\n", distance);
            gpioDelay(100);
            continue;
        }

        // Map the distance to a servo angle
        int angle = (int)(((distance - MIN_DISTANCE) / (MAX_DISTANCE - MIN_DISTANCE)) * (MAX_ANGLE - MIN_ANGLE));

        // Set the servo angle
        if (set_servo_angle(angle) != 0) {
            fprintf(stderr, "Error: Failed to set servo angle.\n");
        }

        // Log the data
        if (log_data(distance, angle) != 0) {
            fprintf(stderr, "Error: Failed to log data.\n");
        }

        // Delay
        gpioDelay(100); // 100ms
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <signal.h>
#include <unistd.h>
#include <wiringPi.h>

// Define GPIO pins connected to the shift register and digit selection
#define SHIFT_DATA_PIN   5  // SDI (Serial Data In)
#define SHIFT_CLOCK_PIN  1  // SRCLK (Shift Register Clock)
#define LATCH_CLOCK_PIN  4  // RCLK (Register Clock/Latch)

// Define GPIO pins for digit selection (common cathode pins)
const int digitSelectPins[] = {12, 3, 2, 0};
const int numDigits = sizeof(digitSelectPins) / sizeof(digitSelectPins[0]);

// Define segment patterns for digits 0-9 (common cathode configuration)
const uint8_t digitPatterns[] = {
    0xC0, // 0
    0xF9, // 1
    0xA4, // 2
    0xB0, // 3
    0x99, // 4
    0x92, // 5
    0x82, // 6
    0xF8, // 7
    0x80, // 8
    0x90  // 9
};

// Global variable for the counter
volatile unsigned int counter = 0;

// Function prototypes
void displayDigit(int digit, int value);
void shiftOut(uint8_t data);
void clearDisplay(void);
void timerHandler(int signal);
void initialize(void);

// Interrupt handler for the timer signal
void timerHandler(int signal) {
    if (signal == SIGALRM) {
        counter++;
        printf("Counter: %d\n", counter);
        alarm(1); // Schedule the next alarm in 1 second
    }
}

// Function to shift out data to the 74HC595 shift register
void shiftOut(uint8_t data) {
    for (int i = 0; i < 8; i++) {
        // Set the data pin based on the current bit
        digitalWrite(SHIFT_DATA_PIN, (data >> i) & 0x01);

        // Clock the data into the shift register
        digitalWrite(SHIFT_CLOCK_PIN, HIGH);
        delayMicroseconds(1); // Small delay for stable clocking
        digitalWrite(SHIFT_CLOCK_PIN, LOW);
    }

    // Latch the data to the output register
    digitalWrite(LATCH_CLOCK_PIN, HIGH);
    delayMicroseconds(1); // Small delay for stable latching
    digitalWrite(LATCH_CLOCK_PIN, LOW);
}

// Function to clear the display (turn off all segments)
void clearDisplay(void) {
    // Shift out all 1s to turn off all segments (common cathode)
    shiftOut(0xFF);
}

// Function to display a digit on a specific digit position
void displayDigit(int digit, int value) {
    if (digit < 0 || digit >= numDigits) {
        fprintf(stderr, "Error: Invalid digit position: %d\n", digit);
        return;
    }

    if (value < 0 || value > 9) {
        fprintf(stderr, "Error: Invalid digit value: %d\n", value);
        return;
    }

    // Clear the display before displaying the new digit
    clearDisplay();

    // Select the digit by setting the corresponding pin HIGH
    digitalWrite(digitSelectPins[digit], HIGH);

    // Shift out the digit pattern
    shiftOut(digitPatterns[value]);

    // Deselect the digit by setting the corresponding pin LOW
    digitalWrite(digitSelectPins[digit], LOW);
}


// Main loop
int main(void) {
    // Initialize WiringPi and GPIO pins
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error: Unable to initialize WiringPi.\n");
        return 1; // Exit with an error code
    }

    initialize();

    // Set up the timer signal handler
    signal(SIGALRM, timerHandler);
    alarm(1); // Set the initial alarm

    // Main loop to display the counter value
    while (1) {
        // Extract the digits from the counter value
        int digit0 = counter % 10;
        int digit1 = (counter / 10) % 10;
        int digit2 = (counter / 100) % 10;
        int digit3 = (counter / 1000) % 10;

        // Display the digits on the 7-segment display
        displayDigit(0, digit3);
        delay(2); // Small delay for multiplexing
        displayDigit(1, digit2);
        delay(2);
        displayDigit(2, digit1);
        delay(2);
        displayDigit(3, digit0);
        delay(2);
    }

    return 0; // Exit normally (though the loop never ends)
}

void initialize(void) {
    // Set pin modes
    pinMode(SHIFT_DATA_PIN, OUTPUT);
    pinMode(SHIFT_CLOCK_PIN, OUTPUT);
    pinMode(LATCH_CLOCK_PIN, OUTPUT);

    for (int i = 0; i < numDigits; i++) {
        pinMode(digitSelectPins[i], OUTPUT);
        digitalWrite(digitSelectPins[i], LOW); //Initialize to LOW (Common cathode)
    }
}

