#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pigpio.h>

// Define the GPIO pin connected to the buzzer
#define BUZZER_GPIO 16

// Volatile flag to signal program termination
volatile sig_atomic_t terminate_flag = 0;

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("\nCtrl+C detected. Exiting gracefully...\n");
        terminate_flag = 1;
    }
}

// Function to initialize the GPIO library and set the buzzer pin
int initialize_buzzer() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "ERROR: pigpio initialisation failed\n");
        return -1; // Indicate failure
    }

    gpioSetMode(BUZZER_GPIO, PI_OUTPUT);
    gpioWrite(BUZZER_GPIO, PI_LOW); // Ensure buzzer is initially off
    return 0; // Indicate success
}

// Function to cleanup GPIO resources
void cleanup_buzzer() {
    gpioWrite(BUZZER_GPIO, PI_LOW); // Ensure buzzer is off before exiting
    gpioSetMode(BUZZER_GPIO, PI_INPUT); // Set back to input to avoid issues
    gpioTerminate();
}

int main() {
    // Register the signal handler for Ctrl+C
    if (signal(SIGINT, signal_handler) == SIG_ERR) {
        perror("ERROR: Could not register signal handler");
        return 1;
    }

    // Initialize the buzzer
    if (initialize_buzzer() != 0) {
        return 1; // Exit if initialization fails
    }

    printf("Buzzer control program. Press Ctrl+C to exit.\n");

    // Main loop: Toggle the buzzer every 2 seconds until Ctrl+C is pressed
    while (!terminate_flag) {
        gpioWrite(BUZZER_GPIO, PI_HIGH); // Turn buzzer on
        gpioDelay(2000000);             // Delay for 2 seconds (2000000 microseconds)

        gpioWrite(BUZZER_GPIO, PI_LOW);  // Turn buzzer off
        gpioDelay(2000000);             // Delay for 2 seconds
    }

    // Cleanup and exit
    cleanup_buzzer();
    return 0;
}

