// Function to read the rain sensor value
int readRainSensor() {
    int sensorValue = gpioRead(RAIN_SENSOR_PIN);
    if (sensorValue < 0) {
        fprintf(stderr, "Error reading rain sensor\n");
        return -1; // Indicate failure
    }
    return sensorValue;
}

// Function to close the window
void closeWindow() {
    gpioWrite(WINDOW_CLOSE_PIN, 1); // Set HIGH to close
    sleep(5);                       // Simulate closing for 5 seconds
    gpioWrite(WINDOW_CLOSE_PIN, 0); // Set LOW after closing
    gpioWrite(WINDOW_OPEN_PIN, 0);  // Ensure open pin is LOW
}

// Function to log events to a file
