#include <wiringPi.h>
#include <errno.h>

// Define GPIO pins using WiringPi numbering
#define BUTTON_UP_PIN   37  // Button to control the buzzer
#define BUTTON_DOWN_PIN 33  // Button to control the vibration module
#define BUZZER_PIN      12  // Buzzer output pin
#define VIBRATION_PIN   13  // Vibration module output pin

// Function prototypes
int initialize_gpio(void);
void control_outputs(void);

int main()
{
    // Initialize WiringPi and GPIO pins
    if (initialize_gpio() != 0) {
        fprintf(stderr, "GPIO initialization failed. Exiting.\n");
        return 1; // Exit with an error code
    }

    printf("\nRaspberry Pi Vibration and Buzzer Control\n");
    printf("Press BUTTON UP to activate the buzzer, BUTTON DOWN to activate the vibration module.\n");
    printf("Press CTRL+C to exit.\n");

    // Main control loop
    while (1) {
        control_outputs();
    }

    return 0;
}

// Function to initialize GPIO pins
int initialize_gpio(void)
{
    // Initialize WiringPi using physical pin numbering
    if (wiringPiSetupPhys() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return -1; // Indicate initialization failure
    }

    // Set pin modes
    pinMode(BUTTON_UP_PIN, INPUT);        // Button UP as input
    pinMode(BUTTON_DOWN_PIN, INPUT);      // Button DOWN as input
    pinMode(BUZZER_PIN, OUTPUT);          // Buzzer as output
    pinMode(VIBRATION_PIN, OUTPUT);       // Vibration module as output

    // Initial state: Turn off buzzer and vibration module
    digitalWrite(BUZZER_PIN, LOW);
    digitalWrite(VIBRATION_PIN, LOW);

    return 0; // Indicate success
}

// Function to control the buzzer and vibration module based on button presses
void control_outputs(void)
{
    // Check if BUTTON UP is pressed (active low)
    if (digitalRead(BUTTON_UP_PIN) == LOW) {
        digitalWrite(BUZZER_PIN, HIGH); // Activate buzzer
    } else {
        digitalWrite(BUZZER_PIN, LOW);  // Deactivate buzzer
    }

    // Check if BUTTON DOWN is pressed (active low)
    if (digitalRead(BUTTON_DOWN_PIN) == LOW) {
        digitalWrite(VIBRATION_PIN, HIGH); // Activate vibration module
    } else {
        digitalWrite(VIBRATION_PIN, LOW);  // Deactivate vibration module
    }
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <time.h>
#include <string.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <wiringPi.h>
#include <wiringPiSPI.h>

// MCP3008 configuration
#define SPI_CHANNEL 0
#define SPI_SPEED 1000000 // 1MHz

// PCF8591 configuration
#define PCF8591_ADDRESS 0x48 // Default address

// File path for the CSV log
#define LOG_FILE "data.csv"

// Function to read from MCP3008 channel
int read_mcp3008(int channel)
{
    unsigned char buffer[3];
    buffer[0] = 0x01;                  // Start bit
    buffer[1] = (0x08 | channel) << 4; // SGL/DIFF=1, D2=D1=D0=channel
    buffer[2] = 0x00;

    wiringPiSPIDataRW(SPI_CHANNEL, buffer, 3);

    int adc_value = ((buffer[1] & 0x03) << 8) + buffer[2];
    return adc_value;
}

// Function to read from PCF8591 AIN0
int read_pcf8591()
{
    int file;
    if ((file = open("/dev/i2c-1", O_RDWR)) < 0) {
        perror("Failed to open the i2c bus");
        return -1;
    }

    if (ioctl(file, I2C_SLAVE, PCF8591_ADDRESS) < 0) {
        perror("Failed to acquire bus access and/or talk to slave.\n");
        return -1;
    }

    // Send a dummy byte to initiate the conversion
    unsigned char write_buffer[1] = {0x40}; // Control byte: Enable AOUT, single-ended inputs.
    if (write(file, write_buffer, 1) != 1) {
        perror("Failed to write to the i2c bus");
        close(file);
        return -1;
    }

    // Read the result
    unsigned char read_buffer[1];
    if (read(file, read_buffer, 1) != 1) {
        perror("Failed to read from the i2c bus");
        close(file);
        return -1;
    }

    close(file);
    return read_buffer[0];
}

int main()
{
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed\n");
        return 1;
    }

    if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) == -1) {
        fprintf(stderr, "wiringPiSPISetup failed\n");
        return 1;
    }

    FILE *fp = fopen(LOG_FILE, "a"); // Open in append mode
    if (fp == NULL) {
        perror("Failed to open log file");
        return 1;
    }

    // Write header if the file is newly created (optional)
    fseek(fp, 0, SEEK_END);
    long fsize = ftell(fp);
    if (fsize == 0) {
        fprintf(fp, "Timestamp,MCP3008,PCF8591\n");
    }
    rewind(fp);

    while (1) {
        // Get current timestamp
        time_t rawtime;
        struct tm *timeinfo;
        time(&rawtime);
        timeinfo = localtime(&rawtime);
        char timestamp[80];
        strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

        // Read from MCP3008
        int mcp3008_value = read_mcp3008(0);

        // Read from PCF8591
        int pcf8591_value = read_pcf8591();

        if (pcf8591_value == -1) {
            fprintf(stderr, "Error reading PCF8591 value\n");
        } else {
            // Log data to CSV file
            fprintf(fp, "%s,%d,%d\n", timestamp, mcp3008_value, pcf8591_value);
            fflush(fp); // Ensure data is written immediately

            printf("%s, MCP3008: %d, PCF8591: %d\n", timestamp, mcp3008_value, pcf8591_value);
        }

        delay(1000); // Wait for 1 second
    }

    fclose(fp); // This will never be reached in this example due to the infinite loop.

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <unistd.h>
#include <errno.h>
#include <signal.h>

// Define GPIO pins
const int gpios[] = {17, 18, 27, 22};
const int num_gpios = sizeof(gpios) / sizeof(gpios[0]);

// Define constants for success and failure
#define SUCCESS 0
#define FAILURE -1

// Global flag to handle program termination
volatile sig_atomic_t terminate = 0;

// Signal handler function
void signal_handler(int sig) {
    terminate = 1;
    printf("\nCaught signal %d, cleaning up and exiting...\n", sig);
}

// Function to export a GPIO pin
int gpio_export(int gpio) {
    char buffer[64];
    int len;
    FILE *fp = NULL;

    fp = fopen("/sys/class/gpio/export", "w");
    if (fp == NULL) {
        perror("Failed to open /sys/class/gpio/export for writing");
        return FAILURE;
    }

    len = snprintf(buffer, sizeof(buffer), "%d", gpio);
    if (fwrite(buffer, 1, len, fp) != len) {
        perror("Failed to write GPIO number to /sys/class/gpio/export");
        fclose(fp);
        return FAILURE;
    }

    fclose(fp);
    return SUCCESS;
}

// Function to unexport a GPIO pin
int gpio_unexport(int gpio) {
    char buffer[64];
    int len;
    FILE *fp = NULL;

    fp = fopen("/sys/class/gpio/unexport", "w");
    if (fp == NULL) {
        perror("Failed to open /sys/class/gpio/unexport for writing");
        return FAILURE;
    }

    len = snprintf(buffer, sizeof(buffer), "%d", gpio);
    if (fwrite(buffer, 1, len, fp) != len) {
        perror("Failed to write GPIO number to /sys/class/gpio/unexport");
        fclose(fp);
        return FAILURE;
    }

    fclose(fp);
    return SUCCESS;
}

// Function to set the direction of a GPIO pin (in or out)
int gpio_set_direction(int gpio, char *direction) {
    char path[128];
    FILE *fp = NULL;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/direction", gpio);
    fp = fopen(path, "w");
    if (fp == NULL) {
        perror("Failed to open GPIO direction file for writing");
        return FAILURE;
    }

    if (fwrite(direction, 1, strlen(direction), fp) != strlen(direction)) {
        perror("Failed to write direction to GPIO direction file");
        fclose(fp);
        return FAILURE;
    }

    fclose(fp);
    return SUCCESS;
}

// Function to write a value to a GPIO pin (0 or 1)
int gpio_write(int gpio, int value) {
    char path[128];
    FILE *fp = NULL;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", gpio);
    fp = fopen(path, "w");
    if (fp == NULL) {
        perror("Failed to open GPIO value file for writing");
        return FAILURE;
    }

    if (fprintf(fp, "%d", value) < 0) {
        perror("Failed to write value to GPIO value file");
        fclose(fp);
        return FAILURE;
    }

    fclose(fp);
    return SUCCESS;
}

// Function to log an event to a file with timestamp
int log_event(int gpio) {
    FILE *fp = NULL;
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fp = fopen("relay_log.txt", "a");
    if (fp == NULL) {
        perror("Failed to open relay_log.txt for writing");
        return FAILURE;
    }

    fprintf(fp, "%s: Relay on GPIO %d activated\n", timestamp, gpio);
    fclose(fp);
    return SUCCESS;
}

// Function to execute the relay sequence
int relay_sequence() {
    for (int i = 0; i < num_gpios && !terminate; i++) {
        int gpio = gpios[i];

        printf("Activating relay on GPIO %d\n", gpio);
        if (gpio_write(gpio, 1) == FAILURE) {
            fprintf(stderr, "Error activating relay on GPIO %d\n", gpio);
            return FAILURE;
        }
        if (log_event(gpio) == FAILURE) {
            fprintf(stderr, "Error logging event for GPIO %d\n", gpio);
            return FAILURE;
        }

        usleep(2000000); // 2 seconds

        printf("Deactivating relay on GPIO %d\n", gpio);
        if (gpio_write(gpio, 0) == FAILURE) {
            fprintf(stderr, "Error deactivating relay on GPIO %d\n", gpio);
            return FAILURE;
        }

        usleep(1000000); // 1 second delay
    }
    return SUCCESS;
}

int main() {
    // Install signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Export and set direction for each GPIO
    for (int i = 0; i < num_gpios; i++) {
        if (gpio_export(gpios[i]) == FAILURE) {
            fprintf(stderr, "Failed to export GPIO %d, exiting\n", gpios[i]);
            //Unexport any GPIOs that were exported before exiting
            for (int j = 0; j < i; j++){
                gpio_unexport(gpios[j]);
            }
            return EXIT_FAILURE;
        }
        if (gpio_set_direction(gpios[i], "out") == FAILURE) {
            fprintf(stderr, "Failed to set direction for GPIO %d, exiting\n", gpios[i]);
            gpio_unexport(gpios[i]);
            //Unexport any GPIOs that were exported before exiting
            for (int j = 0; j < i; j++){
                gpio_unexport(gpios[j]);
            }
            return EXIT_FAILURE;
        }
        if (gpio_write(gpios[i], 0) == FAILURE) {
            fprintf(stderr, "Failed to set initial value for GPIO %d, exiting\n", gpios[i]);
            gpio_unexport(gpios[i]);
             //Unexport any GPIOs that were exported before exiting
            for (int j = 0; j < i; j++){
                gpio_unexport(gpios[j]);
            }
            return EXIT_FAILURE;
        }
    }

    // Run the relay sequence
    if (relay_sequence() == FAILURE) {
        fprintf(stderr, "Relay sequence failed\n");
    }

    // Clean up: Unexport GPIOs
    for (int i = 0; i < num_gpios; i++) {
        if (gpio_unexport(gpios[i]) == FAILURE) {
            fprintf(stderr, "Failed to unexport GPIO %d\n", gpios[i]);
        }
    }

    printf("Program finished\n");
    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <bcm2835.h>
#include <unistd.h>
#include <stdlib.h>
#include <stdint.h>

// MCP4725 I2C address (default)
#define MCP4725_ADDR 0x62

// Function to set the DAC value
int set_dac_value(uint16_t value) {
    // Construct the I2C message: configuration byte + 12-bit data
    char data[3];
    data[0] = 0x40; // Write DAC register (no EEPROM write)
    data[1] = (value >> 4) & 0xFF;   // Upper 8 bits
    data[2] = (value << 4) & 0xF0;  // Lower 4 bits

    if (!bcm2835_i2c_begin()) {
        fprintf(stderr, "Failed to begin I2C\n");
        return -1;
    }

    bcm2835_i2c_setSlaveAddress(MCP4725_ADDR);
    bcm2835_i2c_set_baudrate(100000); // 100kHz

    int ret = bcm2835_i2c_write(data, 3);

    bcm2835_i2c_end();

    if (ret != 0) {
        fprintf(stderr, "I2C write error: %d\n", ret);
        return -1; // Indicate error
    }

    return 0; // Indicate success
}

int main(int argc, char **argv) {
    if (!bcm2835_init()) {
        fprintf(stderr, "bcm2835_init failed. Are you running as root?\n");
        return 1;
    }

    uint16_t dac_value = 0; // Initial DAC value
    if (argc > 1) {
        dac_value = atoi(argv[1]);
        if (dac_value > 4095) {
            fprintf(stderr, "DAC value must be between 0 and 4095\n");
            bcm2835_close();
            return 1;
        }
    }

    if (set_dac_value(dac_value) != 0) {
        fprintf(stderr, "Failed to set DAC value.\n");
        bcm2835_close();
        return 1;
    }

    printf("DAC value set to: %d\n", dac_value);

    bcm2835_close();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/spi/spidev.h>
#include <errno.h>
#include <string.h>

// SPI device settings
#define SPI_DEVICE "/dev/spidev0.0" // Change to spidev0.1 if using CE1
#define SPI_MODE SPI_MODE_0
#define SPI_BITS_PER_WORD 8
#define SPI_SPEED 1000000  // 1 MHz

int spi_fd;

// Function to initialize SPI
int spi_init()
{
    spi_fd = open(SPI_DEVICE, O_RDWR);
    if (spi_fd < 0) {
        perror("Error opening SPI device");
        return -1;
    }

    // Set SPI mode
    if (ioctl(spi_fd, SPI_IOC_WR_MODE, SPI_MODE) == -1) {
        perror("Error setting SPI mode");
        close(spi_fd);
        return -1;
    }

    // Set bits per word
    if (ioctl(spi_fd, SPI_IOC_WR_BITS_PER_WORD, SPI_BITS_PER_WORD) == -1) {
        perror("Error setting bits per word");
        close(spi_fd);
        return -1;
    }

    // Set SPI speed
    if (ioctl(spi_fd, SPI_IOC_WR_MAX_SPEED_HZ, SPI_SPEED) == -1) {
        perror("Error setting SPI speed");
        close(spi_fd);
        return -1;
    }

    return 0;
}

// Function to read data from MCP3008
int read_mcp3008(int channel)
{
    uint8_t tx_buf[3];
    uint8_t rx_buf[3];
    struct spi_ioc_transfer tr;

    // Construct the SPI message
    tx_buf[0] = 0x01; // Start bit
    tx_buf[1] = (0x08 | (channel & 0x07)) << 4; // SGL/DIFF, D2, D1, D0
    tx_buf[2] = 0x00; // Don't care

    memset(&tr, 0, sizeof(tr));
    tr.tx_buf = (unsigned long)tx_buf;
    tr.rx_buf = (unsigned long)rx_buf;
    tr.len = 3;
    tr.delay_usecs = 0;
    tr.speed_hz = SPI_SPEED;
    tr.bits_per_word = SPI_BITS_PER_WORD;

    if (ioctl(spi_fd, SPI_IOC_MESSAGE(1), &tr) < 1) {
        perror("Error sending SPI message");
        return -1;
    }

    // Extract the ADC value from the response
    return ((rx_buf[1] & 0x03) << 8) | rx_buf[2];
}

int main()
{
    if (spi_init() == -1) {
        fprintf(stderr, "SPI initialization failed. Exiting.\n");
        return 1;
    }

    printf("SPI initialized successfully.\n");

    // Read from channel 0
    int adc_value = read_mcp3008(0);
    if (adc_value == -1) {
        fprintf(stderr, "Failed to read from MCP3008.\n");
        close(spi_fd);
        return 1;
    }

    printf("Raw ADC value from channel 0: %d\n", adc_value);

    // Convert ADC value to voltage (assuming Vref = 3.3V)
    float voltage = (float)adc_value * (3.3 / 1024.0);
    printf("Voltage from channel 0: %.2f V\n", voltage);

    close(spi_fd);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pigpio.h>

// Define GPIO pins
#define TOUCH_SENSOR_GPIO 4
#define RELAY_GPIO 17

// Define debounce duration in milliseconds
#define DEBOUNCE_DURATION_MS 50

// Global variable to store the relay state (0 = OFF, 1 = ON)
static volatile int relayState = 0;

// Signal handler for graceful termination
void signalHandler(int signal)
{
    printf("\nCaught signal %d, cleaning up...\n", signal);
    // Turn off the relay before exiting
    controlRelay(RELAY_GPIO, 0);
    gpioTerminate();
    exit(0);
}

// Function to initialize the pigpio library
int initializeGPIO()
{
    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Indicate failure
    }
    return 0; // Indicate success
}

// Function to configure GPIO pins
int configureGPIO()
{
    // Configure touch sensor GPIO as input with pull-down resistor
    if (gpioSetMode(TOUCH_SENSOR_GPIO, PI_INPUT) != 0)
    {
        fprintf(stderr, "Failed to set GPIO %d as input\n", TOUCH_SENSOR_GPIO);
        return 1;
    }
    gpioSetPullUpDown(TOUCH_SENSOR_GPIO, PI_PUD_DOWN);

    // Configure relay GPIO as output
    if (gpioSetMode(RELAY_GPIO, PI_OUTPUT) != 0)
    {
        fprintf(stderr, "Failed to set GPIO %d as output\n", RELAY_GPIO);
        return 1;
    }

    return 0;
}

// Function to read the touch sensor state
int readTouchSensor(int gpio)
{
    return gpioRead(gpio);
}

// Function to debounce the touch sensor input
int debounce(int gpio, int duration_ms)
{
    int stable = 1;
    int startTick = gpioTick();
    while (gpioTick() - startTick < duration_ms * 1000)
    {
        if (gpioRead(gpio) == 0)
        {
            stable = 0;
            break;
        }
        gpioDelay(1000); // Wait 1ms
    }
    return stable;
}

// Function to control the relay
void controlRelay(int gpio, int state)
{
    if (gpioWrite(gpio, state) != 0)
    {
        fprintf(stderr, "Failed to write state %d to GPIO %d\n", state, gpio);
    }
    relayState = state; // Update global relay state
    printf("Relay set to %s\n", state ? "ON" : "OFF");
}

int main()
{
    // Install signal handler for Ctrl+C
    signal(SIGINT, signalHandler);

    // Initialize pigpio
    if (initializeGPIO() != 0)
    {
        return 1; // Exit if initialization fails
    }

    // Configure GPIO pins
    if (configureGPIO() != 0)
    {
        gpioTerminate();
        return 1; // Exit if configuration fails
    }

    // Main loop
    while (1)
    {
        // Read touch sensor
        if (readTouchSensor(TOUCH_SENSOR_GPIO))
        {
            // Debounce the touch sensor input
            if (debounce(TOUCH_SENSOR_GPIO, DEBOUNCE_DURATION_MS))
            {
                // Toggle the relay state
                controlRelay(RELAY_GPIO, !relayState);

                // Wait for a short period to avoid multiple toggles
                gpioDelay(500000); // Wait 500ms
            }
        }
        gpioDelay(10000); // Check every 10ms
    }

    // This point will not be reached unless there is an error or the program is terminated by a signal.
    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>

// Define GPIO pins
#define PIR_PIN 4
#define BUZZER_PIN 18

// Structure for the PIR sensor
typedef struct {
    int pin;
    int (*init)(int);
    int (*detectMotion)(int);
} PIRSensor;

// Structure for the Buzzer
typedef struct {
    int pin;
    int (*init)(int);
    int (*activate)(int);
    int (*deactivate)(int);
} Buzzer;

// Global flag to handle program termination
volatile sig_atomic_t program_running = 1;

// Signal handler for Ctrl+C
void sigint_handler(int signal) {
    program_running = 0;
    printf("\nCaught signal %d, exiting gracefully.\n", signal);
}

// PIR Sensor Initialization function
int pirInit(int pin) {
    if (gpioSetMode(pin, PI_INPUT) != 0) {
        fprintf(stderr, "Error setting PIR pin %d to input mode.\n", pin);
        return -1;
    }
    gpioSetPullUpDown(pin, PI_PUD_DOWN); // Use pull-down resistor
    return 0;
}

// PIR Motion Detection function
int pirDetectMotion(int pin) {
    return gpioRead(pin);
}

// Buzzer Initialization function
int buzzerInit(int pin) {
    if (gpioSetMode(pin, PI_OUTPUT) != 0) {
        fprintf(stderr, "Error setting Buzzer pin %d to output mode.\n", pin);
        return -1;
    }
    return 0;
}

// Buzzer Activation function
int buzzerActivate(int pin) {
    gpioWrite(pin, 1); // HIGH to activate the buzzer
    return 0;
}

// Buzzer Deactivation function
int buzzerDeactivate(int pin) {
    gpioWrite(pin, 0); // LOW to deactivate the buzzer
    return 0;
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Initialize signal handler
    signal(SIGINT, sigint_handler);

    // Create PIR sensor object
    PIRSensor pir = {PIR_PIN, pirInit, pirDetectMotion};

    // Create Buzzer object
    Buzzer buzzer = {BUZZER_PIN, buzzerInit, buzzerActivate, buzzerDeactivate};

    // Initialize PIR sensor
    if (pir.init(pir.pin) != 0) {
        gpioTerminate();
        return 1;
    }

    // Initialize Buzzer
    if (buzzer.init(buzzer.pin) != 0) {
        gpioTerminate();
        return 1;
    }

    // Open log file
    FILE *log_file = fopen("motion_log.txt", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        gpioTerminate();
        return 1;
    }

    printf("Motion detection started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        // Detect motion
        if (pir.detectMotion(pir.pin) == 1) {
            // Activate buzzer
            buzzer.activate(buzzer.pin);
            printf("Motion detected! Buzzer activated.\n");

            // Get current timestamp
            time_t rawtime;
            struct tm *timeinfo;
            char timestamp[20];
            time(&rawtime);
            timeinfo = localtime(&rawtime);
            strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

            // Log event to file
            fprintf(log_file, "%s: Motion detected\n", timestamp);
            fflush(log_file); // Ensure data is written to file immediately

            // Wait for a short duration to avoid repeated triggers
            gpioDelay(2000); // Wait 2 seconds

            // Deactivate buzzer
            buzzer.deactivate(buzzer.pin);
            printf("Buzzer deactivated.\n");
        } else {
            gpioDelay(100); // Check every 100ms
        }
    }

    // Close log file
    fclose(log_file);

    // Clean up and terminate pigpio
    gpioTerminate();
    printf("Program terminated. GPIO resources released.\n");
    return 0;
}

