// Function to convert voltage to distance (cm) using a simple approximation
// Based on the GP2Y0A21YK0F datasheet
float voltage_to_distance(float voltage) {
    // This is a very basic approximation.  A lookup table or polynomial
    // would provide better accuracy for a real application.
    if (voltage < 0.4) return 80; // Max range
    if (voltage > 2.7) return 10; // Min range
    return 27.0 / (voltage - 0.3); // Simplified approximation
}

