        return 1;
    }

    // Set GPIO pin as output for PWM
    gpioSetMode(IR_SENSOR_GPIO, PI_OUTPUT);

    // Set PWM frequency and duty cycle
    gpioSetPWMfrequency(IR_SENSOR_GPIO, PWM_FREQUENCY);
    gpioPWM(IR_SENSOR_GPIO, PWM_DUTY_CYCLE * 255 / 100); // pigpio uses 0-255 for duty cycle

    // Open the log file
    log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        gpioTerminate();
        return 1;
    }

