#include <errno.h>

#define GPIO_FAN 18
#define TEMPERATURE_FILE "/sys/class/thermal/thermal_zone0/temp"
#define LOG_FILE "fan_log.txt"
#define PWM_FREQUENCY 20000 // 20kHz

// Global variables for PID controller (static to retain state)
static float previous_error = 0.0;
static float integral = 0.0;

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("\nCaught signal %d, shutting down gracefully...\n", signal);
    gpioWrite(GPIO_FAN, 0); // Turn off the fan
    gpioTerminate();        // Terminate pigpio
    exit(0);
}

// Function to read CPU temperature from file
float read_temperature() {
    FILE *fp;
    int temperature_millidegrees;
    float temperature_degrees;

    fp = fopen(TEMPERATURE_FILE, "r");
    if (fp == NULL) {
        fprintf(stderr, "Error opening temperature file: %s\n", strerror(errno));
        return -1.0; // Indicate error
    }

    if (fscanf(fp, "%d", &temperature_millidegrees) != 1) {
        fprintf(stderr, "Error reading temperature from file: %s\n", strerror(errno));
        fclose(fp);
        return -1.0; // Indicate error
    }

    fclose(fp);
    temperature_degrees = (float)temperature_millidegrees / 1000.0;
    return temperature_degrees;
}

// Function to set PWM duty cycle on the specified GPIO
int set_pwm_dutycycle(int gpio, float dutycycle) {
    if (dutycycle < 0.0 || dutycycle > 100.0) {
        fprintf(stderr, "Error: Duty cycle out of range (0.0 - 100.0)\n");
        return -1; // Indicate error
    }

    int pwm_range = gpioGetPWMrange(gpio);
    if (pwm_range == PI_BAD_GPIO) {
        fprintf(stderr, "Error: Invalid GPIO for PWM: %d\n", gpio);
        return -1; // Indicate error
    }

    int pwm_value = (int)((dutycycle / 100.0) * pwm_range);
    gpioPWM(gpio, pwm_value);
    return 0;
}

// Function to implement PID control algorithm
float pid_control(float current_temperature, float setpoint, float Kp, float Ki, float Kd) {
    float error = setpoint - current_temperature;
    float derivative = error - previous_error;

    integral += error;

    float output = Kp * error + Ki * integral + Kd * derivative;

    previous_error = error;

    // Clamp the output to the range of 0-100
    if (output < 0.0) {
        output = 0.0;
    } else if (output > 100.0) {
        output = 100.0;
    }

    return output;
}

// Function to log temperature and duty cycle to file
int log_data(float temperature, float dutycycle, FILE *logfile) {
    if (fprintf(logfile, "%.2f,%.2f\n", temperature, dutycycle) < 0) {
        fprintf(stderr, "Error writing to log file: %s\n", strerror(errno));
        return -1; // Indicate error
    }
    return 0;
}

int main() {
    // PID controller parameters
    float setpoint = 55.0; // Target temperature in degrees Celsius
    float Kp = 2.0;         // Proportional gain
    float Ki = 0.1;         // Integral gain
    float Kd = 0.5;         // Derivative gain

    float temperature, dutycycle;
    FILE *logfile;

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO18 as PWM output
    gpioSetMode(GPIO_FAN, PI_OUTPUT);
    gpioSetPWMfrequency(GPIO_FAN, PWM_FREQUENCY);
    gpioSetPWMrange(GPIO_FAN, 1000); // Set PWM range (adjust as needed)

    // Open log file
    logfile = fopen(LOG_FILE, "a");
    if (logfile == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        gpioTerminate();
        return 1;
    }

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    printf("PID-controlled cooling system started. Press Ctrl+C to exit.\n");

    // Main loop
    while (1) {
        // Read temperature
        temperature = read_temperature();
        if (temperature < 0.0) {
            fprintf(stderr, "Error reading temperature, using previous value.\n");
            // Consider a default or previous valid temperature here to avoid runaway fan.
        } else {
            // Calculate PWM duty cycle using PID control
            dutycycle = pid_control(temperature, setpoint, Kp, Ki, Kd);

            // Set PWM duty cycle
            if (set_pwm_dutycycle(GPIO_FAN, dutycycle) != 0) {
                fprintf(stderr, "Error setting PWM duty cycle\n");
            }

            // Log data
            if (log_data(temperature, dutycycle, logfile) != 0) {
                fprintf(stderr, "Error logging data\n");
            }

            fflush(logfile); // Flush the log file to ensure data is written

            printf("Temperature: %.2f C, Duty Cycle: %.2f %%\n", temperature, dutycycle);
        }

        // Wait for 1 second
        sleep(1);
    }

    // This point will not be reached unless there's an error or the loop is exited manually.
    fclose(logfile);
    gpioTerminate();
    return 0;
}

