#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <wiringPi.h>

// Constants
#define HALL_SENSOR_PIN 17
#define MOTOR_SHUTDOWN_PIN 27
#define DEFAULT_POLE_PAIRS 7
#define DEFAULT_CRITICAL_RPM 10000
#define DEBOUNCE_DELAY_US 1000 // 1 millisecond
#define BUFFER_SIZE 100
#define LOG_FILE "motor_data.log"

// Calibration parameters for A1324 (example values)
#define HALL_SENSOR_SLOPE 0.001  // Gauss per digital unit
#define HALL_SENSOR_OFFSET 0.0   // Gauss offset

// Structure to store timestamped data
typedef struct {
    time_t timestamp;
    float magnetic_field;
    float rpm;
} SensorData;

// Global variables (minimize usage)
static volatile int running = 1;
static FILE *log_file = NULL;

// Circular buffer
SensorData circular_buffer[BUFFER_SIZE];
int buffer_head = 0;
int buffer_size = 0; // Current number of elements in buffer

// Function prototypes
int initialize_gpio();
int read_sensor();
float calculate_rpm(unsigned long time_interval_us, int pole_pairs);
float calibrate_field_strength(int digital_reading);
void add_to_buffer(float magnetic_field, float rpm);
void shutdown_motor();
void signal_handler(int signal);
void log_data();

// Function to initialize GPIO using wiringPi
int initialize_gpio() {
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error: Unable to initialize wiringPi (GPIO mode).\n");
        return 1;
    }

    pinMode(HALL_SENSOR_PIN, INPUT);
    pinMode(MOTOR_SHUTDOWN_PIN, OUTPUT);
    digitalWrite(MOTOR_SHUTDOWN_PIN, HIGH); // Initialize to HIGH (motor enabled)

    return 0;
}

// Function to read the Hall effect sensor with debouncing
int read_sensor() {
    int current_state = digitalRead(HALL_SENSOR_PIN);
    int last_state = current_state;
    unsigned long last_change_time = micros();

    while (digitalRead(HALL_SENSOR_PIN) == last_state) {
        if (micros() - last_change_time > DEBOUNCE_DELAY_US) {
            return current_state;
        }
    }

    return !current_state; // Return the new state
}

// Function to calculate RPM from time interval
float calculate_rpm(unsigned long time_interval_us, int pole_pairs) {
    if (time_interval_us == 0) {
        return 0.0; // Avoid division by zero
    }
    float frequency = 1000000.0 / time_interval_us; // Frequency in Hz
    return (frequency * 60.0) / pole_pairs;
}

// Function to calibrate magnetic field strength
float calibrate_field_strength(int digital_reading) {
    return (digital_reading * HALL_SENSOR_SLOPE) + HALL_SENSOR_OFFSET;
}

// Function to add data to the circular buffer
void add_to_buffer(float magnetic_field, float rpm) {
    circular_buffer[buffer_head].timestamp = time(NULL);
    circular_buffer[buffer_head].magnetic_field = magnetic_field;
    circular_buffer[buffer_head].rpm = rpm;

    buffer_head = (buffer_head + 1) % BUFFER_SIZE;
    if (buffer_size < BUFFER_SIZE) {
        buffer_size++;
    }
}

// Function to shutdown the motor
void shutdown_motor() {
    printf("Shutting down motor...\n");
    digitalWrite(MOTOR_SHUTDOWN_PIN, LOW);
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    running = 0;
    shutdown_motor();

    if (log_file != NULL) {
        fclose(log_file);
    }

    printf("Program terminated gracefully.\n");
    exit(0);
}

// Function to log data to a file
void log_data() {
    if (log_file == NULL) {
        log_file = fopen(LOG_FILE, "a");
        if (log_file == NULL) {
            fprintf(stderr, "Error: Unable to open log file.\n");
            return;
        }
    }

    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", t);

    fprintf(log_file, "%s, %.6f, %.2f\n", timestamp, circular_buffer[buffer_head == 0 ? BUFFER_SIZE - 1 : buffer_head - 1].magnetic_field, circular_buffer[buffer_head == 0 ? BUFFER_SIZE - 1 : buffer_head - 1].rpm);
    fflush(log_file); // Ensure data is written to disk immediately
}

int main(int argc, char *argv[]) {
    int pole_pairs = DEFAULT_POLE_PAIRS;
    int critical_rpm = DEFAULT_CRITICAL_RPM;

    // Parse command-line arguments
    if (argc > 1) {
        critical_rpm = atoi(argv[1]);
    }
    if (argc > 2) {
        pole_pairs = atoi(argv[2]);
    }

    // Initialize GPIO
    if (initialize_gpio() != 0) {
        return 1;
    }

    // Set up signal handler
    signal(SIGINT, signal_handler);

    printf("BLDC Motor Monitoring Program\n");
    printf("Critical RPM: %d\n", critical_rpm);
    printf("Pole Pairs: %d\n", pole_pairs);

    int last_state = digitalRead(HALL_SENSOR_PIN);
    unsigned long last_rising_edge_time = micros();

    while (running) {
        int current_state = read_sensor();

        if (current_state != last_state && current_state == 1) { // Rising edge
            unsigned long current_time = micros();
            unsigned long time_interval = current_time - last_rising_edge_time;
            float rpm = calculate_rpm(time_interval, pole_pairs);
            float magnetic_field = calibrate_field_strength(current_state); // Or read analog value if available

            add_to_buffer(magnetic_field, rpm);

            if (rpm > critical_rpm) {
                fprintf(stderr, "Error: RPM exceeded critical threshold (%d). Shutting down motor.\n", critical_rpm);
                shutdown_motor();
                running = 0; // Stop the loop after shutdown
            }

            last_rising_edge_time = current_time;
        }

        last_state = current_state;
        delay(1); // Small delay to reduce CPU usage

        // Log data every second
        static time_t last_log_time = 0;
        time_t current_time = time(NULL);
        if (current_time - last_log_time >= 1) {
            log_data();
            last_log_time = current_time;
        }
    }

    return 0;
}

#include <pigpio.h>
