#include <unistd.h>
#define DAC_ADDR 0x60
int main() {
    if (gpioInitialise() < 0) return 1;
    int i2c = i2cOpen(1, DAC_ADDR, 0);
    while (1) {
        for (int i = 0; i < 360; i += 10) {
            double rad = i * M_PI / 180.0;
            int val = (int)(2048 + 2047 * sin(rad));
            char buf[3];
            buf[0] = 0x40;
            buf[1] = (val >> 4) & 0xFF;
            buf[2] = (val << 4) & 0xFF;
            i2cWriteDevice(i2c, buf, 3);
            gpioDelay(5000);
        }
    }
    i2cClose(i2c);
    gpioTerminate();
    return 0;
}

