    }

    gpioServo(SERVO_PIN, 0); // Stop signal
    gpioTerminate();

    return 0;
}

#include <pigpio.h>
#include <stdio.h>
int read_adc(int spi, int ch) {
    char tx[3] = {1, (0x80 | (ch << 4)), 0}, rx[3];
    spiXfer(spi, tx, rx, 3);
    return ((rx[1] & 3) << 8) | rx[2];
}
int main() {
    if (gpioInitialise() < 0) return 1;
    int spi = spiOpen(0, 1000000, 0);
    while (1) {
        int val = read_adc(spi, 0);
        printf("%d\n", val);
        fflush(stdout);
        gpioDelay(100000);
    }
    spiClose(spi);
    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <fcntl.h>
#include <time.h>
#include <sys/mman.h>
#include <sys/stat.h>
#include <sys/types.h>
#include <unistd.h>
#include <errno.h>
#include <string.h>

// Hardware Definitions
#define CLK_BASE  0x20101000
#define GPIO_BASE 0x20200000
#define PWM_BASE  0x2020C000

#define CLK_LEN   0xA8
#define GPIO_LEN  0xB4
#define PWM_LEN   0x28

// PWM Registers
#define PWM_CTL      0
#define PWM_STA      1
#define PWM_RNG1     4
#define PWM_FIFO     6

// PWM Control Bits
#define PWM_CTL_CLRF1 (1 << 6)
#define PWM_CTL_USEF1 (1 << 5)
#define PWM_CTL_MODE1 (1 << 1)
#define PWM_CTL_PWEN1 (1 << 0)

#define PWM_STA_EMPT1 (1 << 1)

// Clock Defines
#define CLK_PASSWD  (0x5A << 24)

#define CLK_CTL_MASH(x) ((x) << 9)
#define CLK_CTL_BUSY    (1 << 7)
#define CLK_CTL_KILL    (1 << 5)
#define CLK_CTL_ENAB    (1 << 4)
#define CLK_CTL_SRC(x) ((x) << 0)

#define CLK_CTL_SRC_PLLD 6  /* 500.0 MHz */

#define CLK_DIV_DIVI(x) ((x) << 12)
#define CLK_DIV_DIVF(x) ((x) << 0)

#define CLK_PWMCTL 40
#define CLK_PWMDIV 41

#define MAX_BITS 224

// PWM Clock Configuration Structure
typedef struct {
    unsigned divider;
    unsigned bits;
} pwm_clock_config_t;

// Predefined base nanosecond values
static const unsigned base_nanos[] = {4, 8, 10, 20, 40, 80, 100, 200, 250, 500, 1000};
static const size_t num_base_nanos = sizeof(base_nanos) / sizeof(base_nanos[0]);

// Global Variables for Memory Mapped Registers
static volatile uint32_t *clk_registers = MAP_FAILED;
static volatile uint32_t *gpio_registers = MAP_FAILED;
static volatile uint32_t *pwm_registers = MAP_FAILED;

// Function Prototypes
static int map_peripheral_memory(unsigned base, unsigned len, volatile uint32_t **addr);
static void unmap_peripheral_memory(volatile uint32_t **addr, unsigned len);
static void precise_nanosleep(unsigned nanos);
static int gpio_set_mode(unsigned gpio, unsigned mode);
static int gpio_get_mode(unsigned gpio);
static int initialize_pwm(unsigned divider);
static int send_pulse(unsigned bits);
static pwm_clock_config_t calculate_pwm_config(unsigned target_nanos);
static void cleanup();

// Error Handling Macro
#define CHECK_MAP(addr, name) \
    if (addr == MAP_FAILED) { \
        fprintf(stderr, "Error: Could not map %s registers. %s\n", name, strerror(errno)); \
        cleanup(); \
        return EXIT_FAILURE; \
    }

// Function to perform a precise nanosleep
static void precise_nanosleep(unsigned nanos) {
    struct timespec ts;
    ts.tv_sec = 0;
    ts.tv_nsec = nanos;
    if (nanosleep(&ts, NULL) != 0) {
        perror("nanosleep");
    }
}

// Function to set the GPIO mode
static int gpio_set_mode(unsigned gpio, unsigned mode) {
    if (gpio > 53) {
        fprintf(stderr, "Error: Invalid GPIO pin %u\n", gpio);
        return -1; // Indicate error
    }
    unsigned reg = gpio / 10;
    unsigned shift = (gpio % 10) * 3;
    gpio_registers[reg] = (gpio_registers[reg] & ~(7 << shift)) | (mode << shift);
    return 0;
}

// Function to get the GPIO mode
static int gpio_get_mode(unsigned gpio) {
    if (gpio > 53) {
        fprintf(stderr, "Error: Invalid GPIO pin %u\n", gpio);
        return -1; // Indicate error
    }
    unsigned reg = gpio / 10;
    unsigned shift = (gpio % 10) * 3;
    return (gpio_registers[reg] >> shift) & 7;
}

// Function to initialize the PWM module
static int initialize_pwm(unsigned divider) {
    // Reset PWM clock
    clk_registers[CLK_PWMCTL] = CLK_PASSWD | CLK_CTL_KILL;
    precise_nanosleep(10000);

    // Set PWM clock source as 500 MHz PLLD
    clk_registers[CLK_PWMCTL] = CLK_PASSWD | CLK_CTL_SRC(CLK_CTL_SRC_PLLD);
    precise_nanosleep(10000);

    // Set PWM clock divider
    clk_registers[CLK_PWMDIV] = CLK_PASSWD | CLK_DIV_DIVI(divider) | CLK_DIV_DIVF(0);
    precise_nanosleep(10000);

    // Enable PWM clock
    clk_registers[CLK_PWMCTL] = CLK_PASSWD | CLK_CTL_ENAB | CLK_CTL_SRC(CLK_CTL_SRC_PLLD);
    precise_nanosleep(100000);

    // Reset PWM
    pwm_registers[PWM_CTL] = 0;

    // Clear PWM status bits
    pwm_registers[PWM_STA] = -1;
    precise_nanosleep(10000);

    return 0;
}

// Function to send a pulse via PWM
static int send_pulse(unsigned bits) {
    if (bits == 0) {
        bits = 1;
    } else if (bits > MAX_BITS) {
        bits = MAX_BITS;
    }

    // Clear PWM FIFO
    pwm_registers[PWM_CTL] = PWM_CTL_CLRF1;
    precise_nanosleep(10000);

    // Fill FIFO with data
    unsigned i;
    uint32_t word;
    while (bits >= 32) {
        pwm_registers[PWM_FIFO] = -1; // All bits set
        bits -= 32;
    }

    if (bits > 0) {
        word = 0;
        for (i = 0; i < bits; ++i) {
            word |= (1 << (31 - i)); // Set the most significant bits
        }
        pwm_registers[PWM_FIFO] = word;
    }

    pwm_registers[PWM_FIFO] = 0; // Trailing zero

    // Enable PWM for serialised data from FIFO
    pwm_registers[PWM_CTL] = PWM_CTL_USEF1 | PWM_CTL_MODE1 | PWM_CTL_PWEN1;

    return 0;
}

// Function to calculate PWM clock configuration
static pwm_clock_config_t calculate_pwm_config(unsigned target_nanos) {
    pwm_clock_config_t config;
    unsigned best_error = -1; // Initialize with a large value
    unsigned best_base = 0;
    unsigned best_bits = 0;

    for (size_t i = 0; i < num_base_nanos; ++i) {
        unsigned bits = target_nanos / base_nanos[i];
        if (bits > MAX_BITS) {
            bits = MAX_BITS;
        }

        unsigned error = target_nanos - (bits * base_nanos[i]);

        if (error < best_error) {
            best_error = error;
            best_base = base_nanos[i];
            best_bits = bits;
        }
    }

    config.divider = best_base / 2;
    config.bits = best_bits;

    return config;
}

// Function to map peripheral memory
static int map_peripheral_memory(unsigned base, unsigned len, volatile uint32_t **addr) {
    int fd = open("/dev/mem", O_RDWR | O_SYNC);
    if (fd < 0) {
        fprintf(stderr, "Error: Could not open /dev/mem.  Did you forget sudo? %s\n", strerror(errno));
        return -1;
    }

    *addr = (uint32_t *)mmap(0, len, PROT_READ | PROT_WRITE | PROT_EXEC, MAP_SHARED | MAP_LOCKED, fd, base);
    close(fd);

    if (*addr == MAP_FAILED) {
        return -1;
    }
    return 0;
}

// Function to unmap peripheral memory
static void unmap_peripheral_memory(volatile uint32_t **addr, unsigned len) {
    if (*addr != MAP_FAILED) {
        if (munmap((void *)*addr, len) != 0) {
            perror("munmap");
        }
        *addr = MAP_FAILED; // Ensure the pointer is reset
    }
}

// Cleanup function to unmap memory before exiting
static void cleanup() {
    unmap_peripheral_memory(&gpio_registers, GPIO_LEN);
    unmap_peripheral_memory(&pwm_registers, PWM_LEN);
    unmap_peripheral_memory(&clk_registers, CLK_LEN);
}

int main(int argc, char *argv[]) {
    unsigned nanos = 1000;  // Default pulse width
    unsigned pulses = 100;  // Default number of pulses
    unsigned gap = 5000;    // Default gap between pulses
    unsigned gpio_pin = 18; // Default GPIO pin for PWM
    int original_gpio_mode;

    // Parse command-line arguments
    if (argc > 1) nanos = atoi(argv[1]);
    if (argc > 2) pulses = atoi(argv[2]);
    if (argc > 3) gap = atoi(argv[3]);
    if (argc > 4) gpio_pin = atoi(argv[4]);

    // Validate input parameters
    if (nanos < 4) nanos = 4;
    else if (nanos > 224000) nanos = 224000;

    if (pulses < 1) pulses = 1;
    if (gap < 0) gap = 0;

    // Map peripheral memory
    if (map_peripheral_memory(GPIO_BASE, GPIO_LEN, &gpio_registers) != 0) {
        return EXIT_FAILURE;
    }
    CHECK_MAP(gpio_registers, "GPIO");

    if (map_peripheral_memory(PWM_BASE, PWM_LEN, &pwm_registers) != 0) {
        cleanup();
        return EXIT_FAILURE;
    }
    CHECK_MAP(pwm_registers, "PWM");

    if (map_peripheral_memory(CLK_BASE, CLK_LEN, &clk_registers) != 0) {
        cleanup();
        return EXIT_FAILURE;
    }
    CHECK_MAP(clk_registers, "Clock");

    // Calculate PWM configuration
    pwm_clock_config_t pwm_config = calculate_pwm_config(nanos);

    // Print configuration information
    printf("%d pulses of %d nanos with gap of %d nanos (div=%d bits=%d) on GPIO %u\n",
           pulses, pwm_config.divider * 2 * pwm_config.bits, gap, pwm_config.divider, pwm_config.bits, gpio_pin);

    // Save original GPIO mode
    original_gpio_mode = gpio_get_mode(gpio_pin);
    if (original_gpio_mode < 0) {
        cleanup();
        return EXIT_FAILURE;
    }

    // Set GPIO to ALT5 (PWM1)
    if (gpio_set_mode(gpio_pin, 2) != 0) {
        cleanup();
        return EXIT_FAILURE;
    }

    // Initialize PWM
    if (initialize_pwm(pwm_config.divider) != 0) {
        cleanup();
        return EXIT_FAILURE;
    }

    // Generate pulses
    for (unsigned i = 0; i < pulses; ++i) {
        if (send_pulse(pwm_config.bits) != 0) {
            cleanup();
            return EXIT_FAILURE;
        }
        precise_nanosleep(nanos + gap);
    }

    // Restore original GPIO mode
    if (gpio_set_mode(gpio_pin, original_gpio_mode) != 0) {
        cleanup();
        return EXIT_FAILURE;
    }

    // Cleanup and exit
    cleanup();
    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pigpio.h>
#include <unistd.h>

// Define GPIO pins
#define FLAME_SENSOR_PIN 17
#define BUZZER_PIN 18
#define LED_PIN 23

// Function prototypes
int initialize_gpio();
int read_flame_sensor();
void activate_alarm();
void deactivate_alarm();
void cleanup_gpio();

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    printf("Caught signal %d, cleaning up...\n", signal);
    cleanup_gpio();
    exit(0);
}

// Initializes the pigpio library and sets GPIO modes
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        perror("pigpio initialisation failed");
        return -1;
    }

    gpioSetMode(FLAME_SENSOR_PIN, PI_INPUT);
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);
    gpioSetMode(LED_PIN, PI_OUTPUT);

    return 0;
}

// Reads the digital value from the flame sensor
int read_flame_sensor() {
    return gpioRead(FLAME_SENSOR_PIN);
}

// Activates the alarm (buzzer and LED)
void activate_alarm() {
    gpioWrite(BUZZER_PIN, 1); // HIGH
    gpioWrite(LED_PIN, 1);    // HIGH
    printf("Flame detected! Activating alarm.\n");
}

// Deactivates the alarm (buzzer and LED)
void deactivate_alarm() {
    gpioWrite(BUZZER_PIN, 0); // LOW
    gpioWrite(LED_PIN, 0);    // LOW
    printf("No flame detected. Deactivating alarm.\n");
}

// Cleans up the pigpio library and resets GPIO pins
void cleanup_gpio() {
    gpioWrite(BUZZER_PIN, 0); // LOW
    gpioWrite(LED_PIN, 0);    // LOW
    gpioTerminate();
}

int main() {
    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize GPIO
    if (initialize_gpio() != 0) {
        return 1;
    }

    printf("Flame sensor monitoring started. Press Ctrl+C to exit.\n");

    // Main loop
    while (1) {
        int flame_detected = (read_flame_sensor() == 0); // LOW signal indicates flame

        if (flame_detected) {
            activate_alarm();
        } else {
            deactivate_alarm();
        }

        gpioDelay(100000); // Delay for 0.1 seconds (100 milliseconds)
    }

    return 0; // This line will never be reached due to the infinite loop
}

#include <stdio.h>
#include <wiringPi.h>
#include <softPwm.h>
#include <unistd.h>

#define SERVO_PIN 4 // GPIO 4 (WiringPi pin number)
#define SERVO_MIN 100 // Minimum pulse width (adjust according to your servo)
#define SERVO_MAX 200 // Maximum pulse width (adjust according to your servo)

int main(void) {
  if (wiringPiSetup() == -1) {
    fprintf(stderr, "WiringPi setup failed!\n");
    return 1;
  }

  softPwmCreate(SERVO_PIN, 0, 200); // Initialize PWM on the servo pin, range 0-200

  int position = SERVO_MIN;
  int direction = 1; // 1 for increasing, -1 for decreasing
  int delay_ms = 20;  // Initial delay in milliseconds
  float speed_factor = 1.0; // Speed multiplier

  while (1) {
    softPwmWrite(SERVO_PIN, position);
    usleep(delay_ms * 1000 * speed_factor); // Convert ms to microseconds

    if (direction == 1) {
      position++;
      if (position >= SERVO_MAX) {
        direction = -1;
        delay_ms = 20;  // Reset the speed when changing direction
        speed_factor = 1.0; // Reset the speed when changing direction
      }
    } else {
      position--;
      if (position <= SERVO_MIN) {
        direction = 1;
        delay_ms = 20;  // Reset the speed when changing direction
        speed_factor = 1.0; // Reset the speed when changing direction
      }
    }

    // Gradually increase the speed by decreasing the delay or increasing a speed factor.
    // Choose only one of the methods below. Decreasing delay is generally more reliable with usleep
    if (delay_ms > 1) {
         delay_ms -= 1; // Decrease delay
    } else {
         speed_factor += 0.01; // Increase speed factor
    }


  }

  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <signal.h>
#include <fcntl.h>
#include <unistd.h>
#include <time.h>
#include <stdbool.h>

// Configuration
#define FLAME_SENSOR_GPIO 17
#define BUZZER_GPIO 18
#define LED_GPIO 27
#define DEBOUNCE_SAMPLES 5
#define DEBOUNCE_DELAY_MS 10
#define LOG_FILE "flame_detection.log"

// Global flag to signal program termination
volatile sig_atomic_t terminate = 0;

// Function Prototypes
int gpio_export(int gpio);
int gpio_unexport(int gpio);
int gpio_set_direction(int gpio, const char *direction);
int gpio_read(int gpio);
int gpio_write(int gpio, int value);
int read_flame_sensor(int gpio);
int activate_buzzer(int gpio);
int deactivate_buzzer(int gpio);
int activate_led(int gpio);
int deactivate_led(int gpio);
void signal_handler(int sig);
int debounce_flame_sensor(int gpio, int samples, int delay_ms);
void log_event(const char *message);

// GPIO Utility Functions
int gpio_export(int gpio) {
    char buffer[64];
    int fd;

    fd = open("/sys/class/gpio/export", O_WRONLY);
    if (fd < 0) {
        perror("gpio/export");
        return -1;
    }
    snprintf(buffer, sizeof(buffer), "%d", gpio);
    if (write(fd, buffer, strlen(buffer)) < 0) {
        perror("gpio/export");
        close(fd);
        return -1;
    }
    close(fd);
    return 0;
}

int gpio_unexport(int gpio) {
    char buffer[64];
    int fd;

    fd = open("/sys/class/gpio/unexport", O_WRONLY);
    if (fd < 0) {
        perror("gpio/unexport");
        return -1;
    }
    snprintf(buffer, sizeof(buffer), "%d", gpio);
    if (write(fd, buffer, strlen(buffer)) < 0) {
        perror("gpio/unexport");
        close(fd);
        return -1;
    }
    close(fd);
    return 0;
}

int gpio_set_direction(int gpio, const char *direction) {
    char path[64];
    int fd;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/direction", gpio);
    fd = open(path, O_WRONLY);
    if (fd < 0) {
        perror("gpio/direction");
        return -1;
    }
    if (write(fd, direction, strlen(direction)) < 0) {
        perror("gpio/direction");
        close(fd);
        return -1;
    }
    close(fd);
    return 0;
}

int gpio_read(int gpio) {
    char path[64];
    char value_str[3];
    int fd;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", gpio);
    fd = open(path, O_RDONLY);
    if (fd < 0) {
        perror("gpio/value");
        return -1;
    }
    if (read(fd, value_str, 3) < 0) {
        perror("gpio/value");
        close(fd);
        return -1;
    }
    close(fd);
    return atoi(value_str);
}

int gpio_write(int gpio, int value) {
    char path[64];
    char value_str[3];
    int fd;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", gpio);
    fd = open(path, O_WRONLY);
    if (fd < 0) {
        perror("gpio/value");
        return -1;
    }

    snprintf(value_str, sizeof(value_str), "%d", value);
    if (write(fd, value_str, strlen(value_str)) < 0) {
        perror("gpio/value");
        close(fd);
        return -1;
    }
    close(fd);
    return 0;
}

// Flame Sensor Monitoring
int read_flame_sensor(int gpio) {
    int value = gpio_read(gpio);
    if (value < 0) {
        fprintf(stderr, "Error reading flame sensor value\n");
        return -1; // Indicate error
    }
    return value;
}

int debounce_flame_sensor(int gpio, int samples, int delay_ms) {
    int readings[samples];
    int high_count = 0;
    int low_count = 0;
    struct timespec ts;
    ts.tv_sec = 0;
    ts.tv_nsec = delay_ms * 1000000; // Convert milliseconds to nanoseconds

    for (int i = 0; i < samples; i++) {
        readings[i] = read_flame_sensor(gpio);
        if (readings[i] == -1) return -1; // Propagate error
        if (readings[i] == 1) {
            high_count++;
        } else {
            low_count++;
        }
        nanosleep(&ts, NULL);
    }

    return (low_count > high_count) ? 0 : 1; // Return the most frequent value
}

// Actuator Control
int activate_buzzer(int gpio) {
    return gpio_write(gpio, 1);
}

int deactivate_buzzer(int gpio) {
    return gpio_write(gpio, 0);
}

int activate_led(int gpio) {
    return gpio_write(gpio, 1);
}

int deactivate_led(int gpio) {
    return gpio_write(gpio, 0);
}

// Signal Handler
void signal_handler(int sig) {
    if (sig == SIGINT || sig == SIGTERM) {
        terminate = 1;
        printf("Received signal %d, exiting gracefully...\n", sig);
    }
}

// Logging Function
void log_event(const char *message) {
    FILE *fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(fp, "[%d-%02d-%02d %02d:%02d:%02d] %s\n", tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, message);

    fclose(fp);
}

int main() {
    // Signal Handling Setup
    struct sigaction sa;
    sa.sa_handler = signal_handler;
sigemptyset(&sa.sa_mask);
    sa.sa_flags = 0;
    if (sigaction(SIGINT, &sa, NULL) == -1 || sigaction(SIGTERM, &sa, NULL) == -1) {
        perror("sigaction");
        exit(EXIT_FAILURE);
    }

    // GPIO Initialization
    if (gpio_export(FLAME_SENSOR_GPIO) < 0 ||
        gpio_export(BUZZER_GPIO) < 0 ||
        gpio_export(LED_GPIO) < 0) {
        fprintf(stderr, "Failed to export GPIOs\n");
        goto cleanup;
    }

    if (gpio_set_direction(FLAME_SENSOR_GPIO, "in") < 0 ||
        gpio_set_direction(BUZZER_GPIO, "out") < 0 ||
        gpio_set_direction(LED_GPIO, "out") < 0) {
        fprintf(stderr, "Failed to set GPIO directions\n");
        goto cleanup;
    }

    // Main Loop
    while (!terminate) {
        int flame_detected = debounce_flame_sensor(FLAME_SENSOR_GPIO, DEBOUNCE_SAMPLES, DEBOUNCE_DELAY_MS);
        if (flame_detected < 0) {
            fprintf(stderr, "Error reading flame sensor, exiting\n");
            goto cleanup;
        }

        if (flame_detected == 0) { // Active-low: 0 indicates flame detected
            printf("Flame detected!\n");
            log_event("Flame detected!");
            if (activate_buzzer(BUZZER_GPIO) < 0 || activate_led(LED_GPIO) < 0) {
                fprintf(stderr, "Error activating buzzer or LED\n");
                goto cleanup;
            }
            sleep(2); // Keep buzzer and LED on for 2 seconds
            if (deactivate_buzzer(BUZZER_GPIO) < 0 || deactivate_led(LED_GPIO) < 0) {
                fprintf(stderr, "Error deactivating buzzer or LED\n");
                goto cleanup;
            }
        }

        struct timespec sleep_time;
        sleep_time.tv_sec = 0;
        sleep_time.tv_nsec = 100 * 1000 * 1000; // 100 milliseconds
        nanosleep(&sleep_time, NULL);
    }

cleanup:
    // Cleanup
    gpio_unexport(FLAME_SENSOR_GPIO);
    gpio_unexport(BUZZER_GPIO);
    gpio_unexport(LED_GPIO);

    return 0;
}

