float pressure_threshold = 100000.0;
FILE *log_file;

// Structure to hold the response from the API
typedef struct {
    char *memory;
    size_t size;
} MemoryStruct;

// Callback function for libcurl to write the response to memory
static size_t WriteMemoryCallback(void *contents, size_t size, size_t nmemb, void *userp) {
    size_t realsize = size * nmemb;
    MemoryStruct *mem = (MemoryStruct *)userp;

    char *ptr = realloc(mem->memory, mem->size + realsize + 1);
    if (ptr == NULL) {
        fprintf(stderr, "Not enough memory (realloc returned NULL)\n");
        return 0;
    }

    mem->memory = ptr;
    memcpy(&(mem->memory[mem->size]), contents, realsize);
    mem->size += realsize;
    mem->memory[mem->size] = 0;

    return realsize;
}

// Signal handler for graceful shutdown
void signal_handler(int sig) {
    fprintf(log_file, "%s: Received signal %d, terminating...\n", __TIME__, sig);
    terminate = 1;
}

// Function to fetch temperature and pressure thresholds from a REST API
int fetch_thresholds() {
    CURL *curl;
    CURLcode res;
    MemoryStruct chunk;

    chunk.memory = malloc(1);
    chunk.size = 0;

    curl_global_init(CURL_GLOBAL_DEFAULT);
    curl = curl_easy_init();
    if (curl) {
        curl_easy_setopt(curl, CURLOPT_URL, "http://your-api-endpoint/thresholds"); // Replace with your API endpoint
        curl_easy_setopt(curl, CURLOPT_WRITEFUNCTION, WriteMemoryCallback);
        curl_easy_setopt(curl, CURLOPT_WRITEDATA, (void *)&chunk);

        res = curl_easy_perform(curl);
        if (res != CURLE_OK) {
            fprintf(stderr, "%s: curl_easy_perform() failed: %s\n", __TIME__, curl_easy_strerror(res));
            curl_easy_cleanup(curl);
            free(chunk.memory);
            curl_global_cleanup();
            return -1;
        }

        curl_easy_cleanup(curl);

        // Simple JSON parsing (replace with a proper JSON library like jansson for production)
        char *temp_start = strstr(chunk.memory, "\"temperature\":");
        char *pressure_start = strstr(chunk.memory, "\"pressure\":");

        if (temp_start && pressure_start) {
            temperature_threshold = strtof(temp_start + strlen("\"temperature\":"), NULL);
            pressure_threshold = strtof(pressure_start + strlen("\"pressure\":"), NULL);
            fprintf(log_file, "%s: Fetched thresholds - Temperature: %.2f, Pressure: %.2f\n", __TIME__, temperature_threshold, pressure_threshold);
        } else {
            fprintf(stderr, "%s: Failed to parse JSON response: %s\n", __TIME__, chunk.memory);
            free(chunk.memory);
            curl_global_cleanup();
            return -1;
        }

        free(chunk.memory);
    } else {
        fprintf(stderr, "%s: curl_easy_init() failed\n", __TIME__);
        curl_global_cleanup();
        return -1;
    }
    curl_global_cleanup();
    return 0;
}

// Function to read temperature and pressure data from the BMP180 sensor
int read_bmp180(float *temperature, float *pressure) {
    uint8_t write_data[2];
    uint8_t read_data[3];
    int16_t ut, up;
    long x1, x2, b5, b6, x3, b3, p;
    unsigned long b4, b7;

    // Calibration data (replace with actual values from your sensor)
    int16_t ac1 = 408;
    int16_t ac2 = -72;
    int16_t ac3 = -14383;
    uint16_t ac4 = 32741;
    uint16_t ac5 = 32757;
    uint16_t ac6 = 23153;
    int16_t b1 = 6190;
    int16_t b2 = 4;
    int16_t mb = -32768;
    int16_t mc = -8711;
    int16_t md = 2868;

    // Read uncompensated temperature
    write_data[0] = BMP180_REG_CONTROL;
    write_data[1] = BMP180_COMMAND_TEMP;
    bcm2835_i2c_write(write_data, 2);
    bcm2835_delay(5);

    write_data[0] = BMP180_REG_TEMP_DATA;
    bcm2835_i2c_write(write_data, 1);
    bcm2835_i2c_read(read_data, 2);

    ut = (read_data[0] << 8) | read_data[1];

    // Read uncompensated pressure
    write_data[0] = BMP180_REG_CONTROL;
    write_data[1] = BMP180_COMMAND_PRESSURE3; //oss=3
    bcm2835_i2c_write(write_data, 2);
    bcm2835_delay(27);

    write_data[0] = BMP180_REG_PRESSURE_DATA;
    bcm2835_i2c_write(write_data, 1);
    bcm2835_i2c_read(read_data, 3);

    up = (read_data[0] << 16 | read_data[1] << 8 | read_data[2]) >> (8 - 3); //oss=3

    // Calculate temperature (simplified from datasheet)
    x1 = ((long)ut - ac6) * ac5 >> 15;
    x2 = ((long)mc << 11) / (x1 + md);
    b5 = x1 + x2;
    *temperature = (b5 + 8) >> 4;
    *temperature /= 10.0;

    // Calculate pressure (simplified from datasheet)
    b6 = b5 - 4000;
    x1 = (b2 * (b6 * b6 >> 12)) >> 11;
    x2 = ac2 * b6 >> 11;
    x3 = x1 + x2;
    b3 = (((long)ac1 * 4 + x3) + 2) >> 2;
    x1 = ac3 * b6 >> 13;
    x2 = (b1 * (b6 * b6 >> 12)) >> 16;
    x3 = ((x1 + x2) + 2) >> 2;
    b4 = (ac4 * (unsigned long)(x3 + 32768)) >> 15;
    b7 = ((unsigned long)up - b3) * (50000 >> 3);
    if (b7 < 0x80000000)
    {
        p = (b7 * 2) / b4;
    }
    else
    {
        p = (b7 / b4) * 2;
    }
    x1 = (p >> 8) * (p >> 8);
    x1 = (x1 * 3038) >> 16;
    x2 = (-7357 * p) >> 16;
    *pressure = p + ((x1 + x2 + 3791) >> 4);

    return 0;
}

// Function to control the relay
void control_relay(int state) {
    if (state) {
        bcm2835_gpio_write(RELAY_PIN, HIGH); // Turn relay ON
        fprintf(log_file, "%s: Relay ON\n", __TIME__);
    } else {
        bcm2835_gpio_write(RELAY_PIN, LOW);  // Turn relay OFF
        fprintf(log_file, "%s: Relay OFF\n", __TIME__);
    }
}

int main(int argc, char **argv) {
    time_t rawtime;
    struct tm * timeinfo;
    char timestamp[80];

    // Initialize BCM2835 library
    if (!bcm2835_init()) {
        fprintf(stderr, "%s: bcm2835_init failed. Are you running as root?\n", __TIME__);
        return 1;
    }

    // Open log file
    log_file = fopen("/var/log/threshold_updates.log", "a");
    if (log_file == NULL) {
        fprintf(stderr, "%s: Error opening log file!\n", __TIME__);
        bcm2835_close();
        return 1;
    }

    // Set up signal handler
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Configure relay pin as output
    bcm2835_gpio_fsel(RELAY_PIN, BCM2835_GPIO_FSEL_OUTP);

    // Initialize I2C
    bcm2835_i2c_begin();
    bcm2835_i2c_setSlaveAddress(BMP180_ADDR);
    bcm2835_i2c_setClockDivider(BCM2835_I2C_CLOCK_DIVIDER_626); // 100kHz

    fprintf(log_file, "%s: Home Automation System started\n", __TIME__);

    float temperature, pressure;

    while (!terminate) {
        time (&rawtime);
        timeinfo = localtime (&rawtime);

        strftime(timestamp,sizeof(timestamp),"%Y-%m-%d %H:%M:%S",timeinfo);
        // Fetch thresholds from API
        if (fetch_thresholds() != 0) {
            fprintf(stderr, "%s: Failed to fetch thresholds, using default values\n", __TIME__);
        }

        // Read sensor data
        if (read_bmp180(&temperature, &pressure) == 0) {
            fprintf(log_file, "%s: Temperature: %.2f C, Pressure: %.2f Pa\n", __TIME__, temperature, pressure);

            // Control relay based on thresholds
            if (temperature > temperature_threshold || pressure > pressure_threshold) {
                control_relay(1);
            } else {
                control_relay(0);
            }
        } else {
            fprintf(stderr, "%s: Failed to read BMP180 sensor data\n", __TIME__);
        }

        // Delay before next iteration
        bcm2835_delay(5000); // 5 seconds
    }

    // Cleanup before exiting
    control_relay(0);
    fclose(log_file);
    bcm2835_i2c_end();
    bcm2835_close();

    fprintf(stdout, "%s: Home Automation System terminated\n", __TIME__);
    return 0;
}

