#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <time.h>
#include <signal.h>
#include <pigpio.h>

// Define constants
#define HEATER_GPIO 17
#define PWM_FREQUENCY 10  // Hz
#define LOG_FILENAME "heater_log.csv"
#define SPI_CHANNEL 0     // SPI CE0
#define SPI_SPEED 500000  // SPI clock speed (Hz)
#define SPI_FLAGS 0       // SPI flags (e.g., SPI_MODE_0)

// Global variables (target temperature, PID gains)
double target_temperature = 50.0; // Target temperature in Celsius
double Kp = 1.0;                   // Proportional gain
double Ki = 0.1;                   // Integral gain
double Kd = 0.01;                  // Derivative gain

// Global variables for PID controller
double integral = 0.0;
double previous_error = 0.0;

// Global variable for SPI handle
int spi_handle;

// Global variable for log file
FILE *log_file = NULL;

// Function prototypes
double read_thermocouple_temp();
double calculate_pid(double current_temperature);
void set_heater_pwm(double duty_cycle);
void log_data(double temperature, double duty_cycle);
void cleanup();
void signal_handler(int signal);

// Function to read temperature from MAX31855 via SPI
double read_thermocouple_temp() {
    unsigned char rx_buffer[4];
    int result;
    double temperature = -1000.0; // Initialize to an invalid value

    result = spiRead(spi_handle, (char *)rx_buffer, 4);

    if (result != 4) {
        fprintf(stderr, "Error: SPI read failed! Result = %d\n", result);
        if (log_file != NULL) {
            fprintf(log_file, "Error: SPI read failed! Result = %d\n", result);
            fflush(log_file);
        }
        return temperature; // Return invalid temperature on failure
    }

    // Extract temperature data from the buffer
    int32_t raw_data = (rx_buffer[0] << 24) | (rx_buffer[1] << 16) | (rx_buffer[2] << 8) | rx_buffer[3];

    // Check for fault bits (bit 2 is fault bit)
    if (raw_data & 0x00000004) {
        fprintf(stderr, "Error: MAX31855 fault detected!\n");
        if (log_file != NULL) {
            fprintf(log_file, "Error: MAX31855 fault detected!\n");
            fflush(log_file);
        }
        return temperature; // Return invalid temperature on fault
    }

    // Extract thermocouple temperature (bits 31:18, signed)
    temperature = ((raw_data >> 18) & 0x3FFF) * 0.25;

    return temperature;
}

// Function to calculate PID output
double calculate_pid(double current_temperature) {
    double error = target_temperature - current_temperature;
    integral += error;
    double derivative = error - previous_error;
    double output = (Kp * error) + (Ki * integral) + (Kd * derivative);
    previous_error = error;

    // Clamp the output to [0, 100]
    if (output < 0) output = 0;
    if (output > 100) output = 100;

    return output;
}

// Function to control the heater via PWM
void set_heater_pwm(double duty_cycle) {
    int pulse_width = (int)(duty_cycle * 10000); // pigpio uses range 0-10000 for PWM
    gpioPWM(HEATER_GPIO, pulse_width / 100);    // Set the PWM duty cycle
}

// Function to log data to a file
void log_data(double temperature, double duty_cycle) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(log_file, "%s, %.2f, %.2f\n", timestamp, temperature, duty_cycle);
    fflush(log_file); // Ensure data is written to disk immediately
}

// Cleanup function to release resources
void cleanup() {
    printf("Cleaning up...\n");
    gpioWrite(HEATER_GPIO, 0); // Turn off the heater
    gpioPWM(HEATER_GPIO, 0); // Ensure PWM is off
    if (spi_handle >= 0) {
        spiClose(spi_handle);
    }
    if (log_file != NULL) {
        fclose(log_file);
    }
    gpioTerminate();
    exit(0);
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d\n", signal);
    cleanup();
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Set the heater GPIO as output
    gpioSetMode(HEATER_GPIO, PI_OUTPUT);

    // Set PWM frequency
    gpioSetPWMfrequency(HEATER_GPIO, PWM_FREQUENCY);
    gpioSetPWMrange(HEATER_GPIO, 100);

    // Open SPI channel
    spi_handle = spiOpen(SPI_CHANNEL, SPI_SPEED, SPI_FLAGS);
    if (spi_handle < 0) {
        fprintf(stderr, "Error: SPI open failed\n");
        gpioTerminate();
        return 1;
    }

    // Open the log file
    log_file = fopen(LOG_FILENAME, "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error: Could not open log file\n");
        spiClose(spi_handle);
        gpioTerminate();
        return 1;
    }

    // Write header to log file
    fprintf(log_file, "Timestamp, Temperature (C), Duty Cycle (%%)\n");

    // Register signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Main loop
    while (1) {
        double temperature = read_thermocouple_temp();
        if (temperature > -999.0) {
            double duty_cycle = calculate_pid(temperature);
            set_heater_pwm(duty_cycle);
            log_data(temperature, duty_cycle);
            printf("Temperature: %.2f C, Duty Cycle: %.2f %%\n", temperature, duty_cycle);
        } else {
            fprintf(stderr, "Error: Invalid temperature reading\n");
            if (log_file != NULL) {
                fprintf(log_file, "Error: Invalid temperature reading\n");
                fflush(log_file);
            }
        }

        gpioDelay(1000); // Wait 1 second
    }

    return 0; // This will never be reached due to the infinite loop and signal handler
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>
#include <errno.h>
#include <fcntl.h>
#include <poll.h>
#include <pthread.h>
#include <stdatomic.h>

#define GPIO17 17
#define GPIO27 27
#define RPM_THRESHOLD 3000

// Global variables (minimize usage)
static volatile atomic_int revolutions = 0;
static volatile sig_atomic_t running = 1;
static volatile atomic_int current_rpm = 0;
static volatile atomic_int led_state = 0; // 0: off, 1: on

// Mutex for protecting shared resources
pthread_mutex_t rpm_mutex = PTHREAD_MUTEX_INITIALIZER;

// Function prototypes
int gpio_export(int gpio);
int gpio_unexport(int gpio);
int gpio_set_direction(int gpio, const char *direction);
int gpio_set_edge(int gpio, const char *edge);
int gpio_read_value(int gpio);
int gpio_write_value(int gpio, int value);
void *overspeed_warning_thread(void *arg);
void signal_handler(int sig);
double calculate_rpm(int revolutions);

// Helper function to write to sysfs file
int write_sysfs(const char *path, const char *value)
{
    int fd;
    if ((fd = open(path, O_WRONLY)) < 0) {
        fprintf(stderr, "Error opening %s: %s\n", path, strerror(errno));
        return -1;
    }
    if (write(fd, value, strlen(value)) < 0) {
        fprintf(stderr, "Error writing to %s: %s\n", path, strerror(errno));
        close(fd);
        return -1;
    }
    close(fd);
    return 0;
}

// GPIO export function
int gpio_export(int gpio)
{
    char buffer[3];
    snprintf(buffer, sizeof(buffer), "%d", gpio);
    char export_path[64];
    snprintf(export_path, sizeof(export_path), "/sys/class/gpio/export");

    // Check if GPIO is already exported
    char gpio_path[64];
    snprintf(gpio_path, sizeof(gpio_path), "/sys/class/gpio/gpio%d", gpio);
    if (access(gpio_path, F_OK) == 0) {
        // GPIO is already exported, return success
        return 0;
    }

    return write_sysfs(export_path, buffer);
}

// GPIO unexport function
int gpio_unexport(int gpio)
{
    char buffer[3];
    snprintf(buffer, sizeof(buffer), "%d", gpio);
    char unexport_path[64];
    snprintf(unexport_path, sizeof(unexport_path), "/sys/class/gpio/unexport");
    return write_sysfs(unexport_path, buffer);
}

// GPIO set direction function
int gpio_set_direction(int gpio, const char *direction)
{
    char path[64];
    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/direction", gpio);
    return write_sysfs(path, direction);
}

// GPIO set edge trigger function
int gpio_set_edge(int gpio, const char *edge)
{
    char path[64];
    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/edge", gpio);
    return write_sysfs(path, edge);
}

// GPIO read value function
int gpio_read_value(int gpio)
{
    char path[64];
    char value_str[3];
    int fd;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", gpio);
    if ((fd = open(path, O_RDONLY)) < 0) {
        fprintf(stderr, "Error opening %s: %s\n", path, strerror(errno));
        return -1;
    }
    if (read(fd, value_str, 3) < 0) {
        fprintf(stderr, "Error reading from %s: %s\n", path, strerror(errno));
        close(fd);
        return -1;
    }
    close(fd);
    return atoi(value_str);
}

// GPIO write value function
int gpio_write_value(int gpio, int value)
{
    char path[64];
    char value_str[3];

    snprintf(value_str, sizeof(value_str), "%d", value);
    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", gpio);
    return write_sysfs(path, value_str);
}

// Signal handler function
void signal_handler(int sig)
{
    running = 0;
    printf("Caught signal %d, exiting...\n", sig);
}

// RPM calculation function
double calculate_rpm(int revolutions)
{
    // Assumes revolutions are counted over 1 second
    return (double)revolutions * 60.0;
}

// Overspeed warning thread function
void *overspeed_warning_thread(void *arg)
{
    while (running) {
        if (atomic_load(&current_rpm) > RPM_THRESHOLD) {
            // Toggle LED state
            atomic_store(&led_state, !atomic_load(&led_state));
            gpio_write_value(GPIO27, atomic_load(&led_state));
            struct timespec sleep_time = {0, 500000000}; // 0.5 seconds
            nanosleep(&sleep_time, NULL);
        } else {
            // Ensure LED is off if RPM is below threshold
            gpio_write_value(GPIO27, 0);
            atomic_store(&led_state, 0);
            usleep(100000); // Check every 0.1 seconds
        }
    }
    // Ensure LED is turned off before exiting
    gpio_write_value(GPIO27, 0);
    atomic_store(&led_state, 0);
    return NULL;
}

int main()
{
    // Signal handling setup
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // GPIO initialization
    if (gpio_export(GPIO17) < 0) return 1;
    if (gpio_set_direction(GPIO17, "in") < 0) {
        gpio_unexport(GPIO17);
        return 1;
    }
    if (gpio_set_edge(GPIO17, "rising") < 0) {
        gpio_unexport(GPIO17);
        return 1;
    }

    if (gpio_export(GPIO27) < 0) {
        gpio_unexport(GPIO17);
        return 1;
    }
    if (gpio_set_direction(GPIO27, "out") < 0) {
        gpio_unexport(GPIO17);
        gpio_unexport(GPIO27);
        return 1;
    }

    // Overspeed warning thread
    pthread_t overspeed_thread;
    if (pthread_create(&overspeed_thread, NULL, overspeed_warning_thread, NULL) != 0) {
        fprintf(stderr, "Error creating overspeed thread: %s\n", strerror(errno));
        gpio_unexport(GPIO17);
        gpio_unexport(GPIO27);
        return 1;
    }

    // Main loop
    struct pollfd pfd;
    pfd.fd = open("/sys/class/gpio/gpio17/value", O_RDONLY);
    if (pfd.fd < 0) {
        fprintf(stderr, "Error opening /sys/class/gpio/gpio17/value: %s\n", strerror(errno));
        running = 0; // Signal threads to exit
    }
    pfd.events = POLLPRI;  // Monitor for high-priority events (interrupts)

    int prev_revolutions = 0;
    struct timespec start_time, current_time;
    clock_gettime(CLOCK_MONOTONIC, &start_time);

    while (running) {
        // Poll for interrupt
        int ret = poll(&pfd, 1, 1000); // 1-second timeout
        if (ret < 0) {
            fprintf(stderr, "Error polling: %s\n", strerror(errno));
            running = 0;
            break;
        } else if (ret == 0) {
            // Timeout, no interrupt received
        } else {
            // Interrupt received, increment revolution counter
            if (pfd.revents & POLLPRI) {
                // Consume the interrupt by reading the value file
                char buffer[2];
                lseek(pfd.fd, 0, SEEK_SET); // Rewind the file pointer
                read(pfd.fd, buffer, 2);    // Read the value (0 or 1)
                atomic_fetch_add(&revolutions, 1);
            }
        }

        // Calculate and log RPM every second
        clock_gettime(CLOCK_MONOTONIC, &current_time);
        double elapsed_time = (current_time.tv_sec - start_time.tv_sec) +
                              (current_time.tv_nsec - start_time.tv_nsec) / 1e9;

        if (elapsed_time >= 1.0) {
            int current_revolutions = atomic_load(&revolutions);
            int revolutions_in_interval = current_revolutions - prev_revolutions;
            double rpm = calculate_rpm(revolutions_in_interval);

            pthread_mutex_lock(&rpm_mutex);
            atomic_store(&current_rpm, (int)rpm);
            pthread_mutex_unlock(&rpm_mutex);

            time_t rawtime;
            struct tm *timeinfo;
            time(&rawtime);
            timeinfo = localtime(&rawtime);
            char timestamp[20];
            strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

            printf("%s RPM: %.2f\n", timestamp, rpm);

            prev_revolutions = current_revolutions;
            start_time = current_time;
        }
    }

    // Cleanup
    close(pfd.fd);
    pthread_join(overspeed_thread, NULL);
    gpio_unexport(GPIO17);
    gpio_unexport(GPIO27);
    pthread_mutex_destroy(&rpm_mutex);

    return 0;
}

#include <stdio.h>
