// Define GPIO pins
#define HALL_SENSOR_GPIO 17
#define LED_GPIO 27

// Define RPM threshold for overspeed alarm
#define OVERSPEED_THRESHOLD 120

// Global variables
volatile int rotations = 0;
pthread_t overspeed_thread;
bool overspeed_active = false;

// Mutex to protect rotations variable
pthread_mutex_t rotations_mutex = PTHREAD_MUTEX_INITIALIZER;

// Function prototypes
int gpio_export(int gpio);
int gpio_unexport(int gpio);
int gpio_direction(int gpio, const char *direction);
int gpio_edge(int gpio, const char *edge);
int gpio_read(int gpio);
void *overspeed_alarm(void *arg);
