// Function to export a GPIO pin
int gpio_export(int gpio) {
    char buffer[64];
    int len;
    int fd;

    len = snprintf(buffer, sizeof(buffer), "/sys/class/gpio/export");
    fd = open(buffer, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "gpio_export: Failed to open export file: %s\n", strerror(errno));
        return -1;
    }

    len = snprintf(buffer, sizeof(buffer), "%d", gpio);
    if (write(fd, buffer, len) < 0) {
        fprintf(stderr, "gpio_export: Failed to write GPIO number: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to unexport a GPIO pin
int gpio_unexport(int gpio) {
    char buffer[64];
    int len;
    int fd;

    len = snprintf(buffer, sizeof(buffer), "/sys/class/gpio/unexport");
    fd = open(buffer, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "gpio_unexport: Failed to open unexport file: %s\n", strerror(errno));
        return -1;
    }

    len = snprintf(buffer, sizeof(buffer), "%d", gpio);
    if (write(fd, buffer, len) < 0) {
        fprintf(stderr, "gpio_unexport: Failed to write GPIO number: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to set the direction of a GPIO pin
int gpio_direction(int gpio, const char *direction) {
    char buffer[64];
    int fd;

    snprintf(buffer, sizeof(buffer), "/sys/class/gpio/gpio%d/direction", gpio);
    if (access(buffer, F_OK) == -1) {
        fprintf(stderr, "gpio_direction: GPIO %d not exported\n", gpio);
        return -1;
    }

    fd = open(buffer, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "gpio_direction: Failed to open direction file: %s\n", strerror(errno));
        return -1;
    }

    if (write(fd, direction, strlen(direction)) < 0) {
        fprintf(stderr, "gpio_direction: Failed to write direction: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to set the interrupt edge trigger for a GPIO pin
int gpio_edge(int gpio, const char *edge) {
    char buffer[64];
    int fd;

    snprintf(buffer, sizeof(buffer), "/sys/class/gpio/gpio%d/edge", gpio);
    if (access(buffer, F_OK) == -1) {
        fprintf(stderr, "gpio_edge: GPIO %d not exported\n", gpio);
        return -1;
    }

    fd = open(buffer, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "gpio_edge: Failed to open edge file: %s\n", strerror(errno));
        return -1;
    }

    if (write(fd, edge, strlen(edge)) < 0) {
        fprintf(stderr, "gpio_edge: Failed to write edge: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to read the value of a GPIO pin
int gpio_read(int gpio) {
    char buffer[64];
    char value_str[3];
    int fd;

    snprintf(buffer, sizeof(buffer), "/sys/class/gpio/gpio%d/value", gpio);
    if (access(buffer, F_OK) == -1) {
        fprintf(stderr, "gpio_read: GPIO %d not exported\n", gpio);
        return -1;
    }

    fd = open(buffer, O_RDONLY);
    if (fd < 0) {
        fprintf(stderr, "gpio_read: Failed to open value file: %s\n", strerror(errno));
        return -1;
    }

    if (read(fd, value_str, 3) < 0) {
        fprintf(stderr, "gpio_read: Failed to read value: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return atoi(value_str);
}

// Thread function for the overspeed alarm
void *overspeed_alarm(void *arg) {
    (void)arg; // Suppress unused parameter warning
    struct timespec sleep_time;
    sleep_time.tv_sec = 0;
    sleep_time.tv_nsec = 500000000; // 0.5 seconds

    while (1) {
        // Toggle the LED
        int current_value = gpio_read(LED_GPIO);
        if (current_value < 0) {
            fprintf(stderr, "overspeed_alarm: Error reading LED GPIO value\n");
            pthread_exit(NULL);
        }
        int new_value = (current_value == 0) ? 1 : 0;
        char value_str[2];
        snprintf(value_str, sizeof(value_str), "%d", new_value);
        char buffer[64];
        snprintf(buffer, sizeof(buffer), "/sys/class/gpio/gpio%d/value", LED_GPIO);
        int fd = open(buffer, O_WRONLY);
        if (fd < 0) {
            fprintf(stderr, "overspeed_alarm: Failed to open LED value file: %s\n", strerror(errno));
            pthread_exit(NULL);
        }
        if (write(fd, value_str, strlen(value_str)) < 0) {
            fprintf(stderr, "overspeed_alarm: Failed to write LED value: %s\n", strerror(errno));
            close(fd);
            pthread_exit(NULL);
        }
        close(fd);

        if (nanosleep(&sleep_time, NULL) != 0) {
            if (errno == EINTR) {
                // Interrupted by signal, exit thread
                pthread_exit(NULL);
            } else {
                fprintf(stderr, "overspeed_alarm: nanosleep failed: %s\n", strerror(errno));
                pthread_exit(NULL);
            }
        }
        pthread_testcancel(); // Check for cancellation requests
    }
    return NULL;
}

// Signal handler function
void signal_handler(int signal) {
    printf("Caught signal %d, cleaning up...\n", signal);

    // Unexport GPIO pins
    gpio_unexport(HALL_SENSOR_GPIO);
    gpio_unexport(LED_GPIO);

    // Cancel overspeed alarm thread if it's running
    if (overspeed_active) {
        pthread_cancel(overspeed_thread);
        pthread_join(overspeed_thread, NULL);
    }

    pthread_mutex_destroy(&rotations_mutex);

    exit(0);
}

// Interrupt handler (ISR) - counts rising edges
void interrupt_handler(int gpio) {
    (void)gpio; // Suppress unused parameter warning
    pthread_mutex_lock(&rotations_mutex);
    rotations++;
    pthread_mutex_unlock(&rotations_mutex);
}

int main() {
    // Install signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Export GPIO pins
    if (gpio_export(HALL_SENSOR_GPIO) < 0) {
        fprintf(stderr, "Failed to export HALL_SENSOR_GPIO\n");
        return 1;
    }
    if (gpio_export(LED_GPIO) < 0) {
        fprintf(stderr, "Failed to export LED_GPIO\n");
        gpio_unexport(HALL_SENSOR_GPIO);
        return 1;
    }

    // Set GPIO directions
    if (gpio_direction(HALL_SENSOR_GPIO, "in") < 0) {
        fprintf(stderr, "Failed to set HALL_SENSOR_GPIO direction\n");
        gpio_unexport(HALL_SENSOR_GPIO);
        gpio_unexport(LED_GPIO);
        return 1;
    }
    if (gpio_direction(LED_GPIO, "out") < 0) {
        fprintf(stderr, "Failed to set LED_GPIO direction\n");
        gpio_unexport(HALL_SENSOR_GPIO);
        gpio_unexport(LED_GPIO);
        return 1;
    }

    // Set interrupt edge trigger
    if (gpio_edge(HALL_SENSOR_GPIO, "rising") < 0) {
        fprintf(stderr, "Failed to set HALL_SENSOR_GPIO edge trigger\n");
        gpio_unexport(HALL_SENSOR_GPIO);
        gpio_unexport(LED_GPIO);
        return 1;
    }

    // Initialize variables
    int rpm = 0;
    time_t current_time;
    struct tm *time_info;
    char time_string[64];

    // Main loop
    while (1) {
        sleep(1);

        // Calculate RPM
        pthread_mutex_lock(&rotations_mutex);
        rpm = rotations * 60; // Assuming one pulse per rotation
        rotations = 0;
        pthread_mutex_unlock(&rotations_mutex);

        // Get current time
        time(&current_time);
        time_info = localtime(&current_time);
        strftime(time_string, sizeof(time_string), "%Y-%m-%d %H:%M:%S", time_info);

        // Print RPM with timestamp
        printf("[%s] RPM: %d\n", time_string, rpm);

        // Overspeed alarm logic
        if (rpm > OVERSPEED_THRESHOLD && !overspeed_active) {
            // Create overspeed alarm thread
            if (pthread_create(&overspeed_thread, NULL, overspeed_alarm, NULL) != 0) {
                fprintf(stderr, "Failed to create overspeed alarm thread: %s\n", strerror(errno));
            } else {
                overspeed_active = true;
                pthread_detach(overspeed_thread);
            }
        } else if (rpm <= OVERSPEED_THRESHOLD && overspeed_active) {
            // Cancel overspeed alarm thread
            pthread_cancel(overspeed_thread);
            pthread_join(overspeed_thread, NULL);
            overspeed_active = false;
        }

        // Read the GPIO value and call the interrupt handler
        int hall_value = gpio_read(HALL_SENSOR_GPIO);
        if (hall_value < 0) {
            fprintf(stderr, "Error reading HALL_SENSOR_GPIO value\n");
        } else if (hall_value == 1) { // Simulate interrupt on rising edge
            interrupt_handler(HALL_SENSOR_GPIO);
        }
    }

    return 0;
}

#include <stdio.h>
