// Define GPIO pins
#define FLAME_SENSOR_GPIO 17
#define BUZZER_GPIO 18
#define LED_GPIO 27

// Global variables for graceful exit
volatile sig_atomic_t program_running = 1;

// Function to handle SIGINT signal (Ctrl+C)
void signal_handler(int signal) {
    program_running = 0;
    printf("\nExiting gracefully...\n");
}

// Function to log flame detection events to a file
void log_flame_detection() {
    FILE *fp = fopen("flame_log.txt", "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    fprintf(fp, "%s: Flame detected!\n", timestamp);
    fclose(fp);
}

// Callback function for flame detection
void flame_detected_callback(int gpio, int level, uint32_t tick) {
    if (level == 0) { // Flame detected (LOW signal)
        printf("Flame detected!\n");
        log_flame_detection();

        // Activate buzzer and LED
        gpioWrite(BUZZER_GPIO, 1); // Turn on buzzer
        gpioWrite(LED_GPIO, 1);    // Turn on LED
        gpioDelay(2000);            // Wait for 2 seconds
        gpioWrite(BUZZER_GPIO, 0); // Turn off buzzer
        gpioWrite(LED_GPIO, 0);    // Turn off LED
    }
}

int main() {
    // Register signal handler for graceful exit
    signal(SIGINT, signal_handler);

    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Configure GPIO pins
    gpioSetMode(FLAME_SENSOR_GPIO, PI_INPUT);
    gpioSetPullUpDown(FLAME_SENSOR_GPIO, PI_PUD_UP); // Enable pull-up resistor
    gpioSetMode(BUZZER_GPIO, PI_OUTPUT);
    gpioSetMode(LED_GPIO, PI_OUTPUT);

    // Set initial state for buzzer and LED
    gpioWrite(BUZZER_GPIO, 0);
    gpioWrite(LED_GPIO, 0);

    // Set callback function for flame sensor
    if (gpioSetAlertFuncEx(FLAME_SENSOR_GPIO, flame_detected_callback, NULL) != 0) {
        fprintf(stderr, "Failed to set alert function\n");
        gpioTerminate();
        return 1;
    }

    printf("Flame detection system running. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        gpioDelay(100); // Small delay to reduce CPU usage
    }

    // Cleanup and exit
    gpioTerminate();
    return 0;
}

#include <iostream>
#include <pigpio.h>
#include <unistd.h>
#include <stdexcept>

class DoorStrikeController {
private:
    const int motionSensorPin = 17; // GPIO pin for the PIR motion sensor
    const int relayPin = 27;       // GPIO pin for the relay controlling the door strike

public:
    // Constructor: Initializes the pigpio library and configures GPIO pins
    DoorStrikeController() {
        if (gpioInitialise() < 0) {
            std::cerr << "pigpio initialisation failed" << std::endl;
            throw std::runtime_error("pigpio initialisation failed");
        }

        // Set motion sensor pin as input with pull-down resistor
        gpioSetMode(motionSensorPin, PI_INPUT);
        gpioSetPullUpDown(motionSensorPin, PI_PUD_DOWN);

        // Set relay pin as output and initially low (deactivated)
        gpioSetMode(relayPin, PI_OUTPUT);
        gpioWrite(relayPin, 0); // Ensure relay is initially off
    }

    // Destructor: Releases GPIO resources
    ~DoorStrikeController() {
        gpioTerminate();
    }

    // Detects motion and triggers the door strike
    void detectMotion() {
        while (true) {
            // Read the motion sensor pin
            int motionDetected = gpioRead(motionSensorPin);

            if (motionDetected == 1) {
                std::cout << "Motion detected!" << std::endl;
                unlockDoorStrike();
                // Debounce: Wait for a short period to avoid multiple triggers from a single motion event
                gpioDelay(2000000); // Wait 2 seconds
            }
            gpioDelay(100000); // Check every 0.1 seconds
        }
    }

    // Activates the relay to unlock the door strike for a short duration
    void unlockDoorStrike() {
        try {
            std::cout << "Activating door strike..." << std::endl;
            gpioWrite(relayPin, 1); // Activate the relay (HIGH)
            gpioDelay(500000);      // Wait for 0.5 seconds (500 milliseconds)
            gpioWrite(relayPin, 0); // Deactivate the relay (LOW)
            std::cout << "Door strike deactivated." << std::endl;
        } catch (const std::exception& e) {
            std::cerr << "Error activating door strike: " << e.what() << std::endl;
        }
    }
};

int main() {
    try {
        DoorStrikeController doorStrikeController;
        doorStrikeController.detectMotion(); // Start motion detection loop
    } catch (const std::exception& e) {
        std::cerr << "Program terminated due to an error: " << e.what() << std::endl;
        return 1; // Indicate an error occurred
    }

    return 0; // Indicate successful execution
}

#include <stdio.h>
