// Define LED sysfs paths
#define RED_LED_PATH   "/sys/class/leds/led0:red/brightness"
#define GREEN_LED_PATH "/sys/class/leds/led0:green/brightness"
#define BLUE_LED_PATH  "/sys/class/leds/led0:blue/brightness"

// Global flag for signal handling
volatile sig_atomic_t program_running = 1;

// Signal handler function
void signal_handler(int signum) {
    if (signum == SIGINT) {
        program_running = 0;
        fprintf(stderr, "\nCaught SIGINT, exiting gracefully...\n");
    }
}

// Function to read BPM from file
int read_bpm(const char *filename) {
    FILE *fp = fopen(filename, "r");
    if (fp == NULL) {
        perror("Error opening heart_rate.txt");
        return -1;
    }

    int bpm;
    if (fscanf(fp, "%d", &bpm) != 1) {
        fprintf(stderr, "Error reading BPM from file or invalid format.\n");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return bpm;
}

// Function to calculate delay in seconds for half a pulse cycle
double calculate_delay(int bpm) {
    if (bpm <= 0) {
        return 1.0; // Default delay for invalid BPM
    }
    return 60.0 / (double)bpm / 2.0;
}

// Function to set LED color
int set_led_color(int red, int green, int blue) {
    FILE *fp;

    // Set red
    fp = fopen(RED_LED_PATH, "w");
    if (fp == NULL) {
        perror("Error opening red LED brightness file");
        return -1;
    }
    fprintf(fp, "%d", red);
    fclose(fp);

    // Set green
    fp = fopen(GREEN_LED_PATH, "w");
    if (fp == NULL) {
        perror("Error opening green LED brightness file");
        return -1;
    }
    fprintf(fp, "%d", green);
    fclose(fp);

    // Set blue
    fp = fopen(BLUE_LED_PATH, "w");
    if (fp == NULL) {
        perror("Error opening blue LED brightness file");
        return -1;
    }
    fprintf(fp, "%d", blue);
    fclose(fp);

    return 0;
}

int main() {
    // Register signal handler for SIGINT
    if (signal(SIGINT, signal_handler) == SIG_ERR) {
        perror("Error setting signal handler");
        return 1;
    }

    struct timespec sleep_time;
    sleep_time.tv_sec = 0;

    while (program_running) {
        int bpm = read_bpm("heart_rate.txt");
        if (bpm == -1) {
            fprintf(stderr, "Error reading BPM, using default delay.\n");
            sleep_time.tv_nsec = 500000000L; // 0.5 seconds
        } else {
            double delay = calculate_delay(bpm);
            sleep_time.tv_nsec = (long)(delay * 1000000000.0); // Convert seconds to nanoseconds
        }

        // Turn LED red
        if (set_led_color(255, 0, 0) != 0) {
            fprintf(stderr, "Error setting LED color to red.\n");
        }

        nanosleep(&sleep_time, NULL);

        // Turn LED off
        if (set_led_color(0, 0, 0) != 0) {
            fprintf(stderr, "Error turning LED off.\n");
        }

        nanosleep(&sleep_time, NULL);
    }

    // Ensure LED is turned off before exiting
    set_led_color(0, 0, 0);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <unistd.h>

// Define the GPIO pins connected to the segments (a-g)
const int segments[7] = {4, 17, 27, 22, 5, 6, 13}; // Example pins, adjust according to your wiring

// Define the GPIO pins connected to the digit selection (D1-D4)
const int digits[4] = {19, 26, 20, 21}; // Example pins, adjust according to your wiring

// Segment patterns for digits 0-9
const int digitPatterns[10] = {
    0b00111111, // 0
    0b00000110, // 1
    0b01011011, // 2
    0b01001111, // 3
    0b01100110, // 4
    0b01101101, // 5
    0b01111101, // 6
    0b00000111, // 7
    0b01111111, // 8
    0b01101111  // 9
};

void displayDigit(int digit, int position) {
    // Disable all digits
    for (int i = 0; i < 4; i++) {
        digitalWrite(digits[i], LOW);
    }

    // Set the segment pattern for the digit
    for (int i = 0; i < 7; i++) {
        if ((digitPatterns[digit] >> i) & 1) {
            digitalWrite(segments[i], HIGH);
        } else {
            digitalWrite(segments[i], LOW);
        }
    }

    // Enable the selected digit
    digitalWrite(digits[position], HIGH);
    delay(2); // Small delay to allow the digit to be displayed

    // Disable all digits again (for multiplexing effect)
     for (int i = 0; i < 4; i++) {
        digitalWrite(digits[i], LOW);
    }
}

int main() {
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi setup failed!\n");
        return 1;
    }

    // Set pin modes
    for (int i = 0; i < 7; i++) {
        pinMode(segments[i], OUTPUT);
    }
    for (int i = 0; i < 4; i++) {
        pinMode(digits[i], OUTPUT);
    }

    int countdown = 9999;

    while (countdown >= 0) {
        int thousands = countdown / 1000;
        int hundreds = (countdown % 1000) / 100;
        int tens = (countdown % 100) / 10;
        int ones = countdown % 10;

        // Display each digit using multiplexing
        displayDigit(thousands, 0);
        displayDigit(hundreds, 1);
        displayDigit(tens, 2);
        displayDigit(ones, 3);

        countdown--;
        sleep(1); // Wait for 1 second
    }

    printf("Countdown finished!\n");
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
