// Define the number of rows and columns in the LED matrix
#define MATRIX_SIZE 8

// Define the GPIO pins connected to the rows (Y-direction) of the LED matrix
const int rowPins[MATRIX_SIZE] = {2, 7, 21, 0, 25, 22, 24, 23};

// Define the GPIO pins connected to the columns (X-direction) of the LED matrix
const int colPins[MATRIX_SIZE] = {5, 27, 28, 1, 29, 4, 6, 26};

// Function to initialize the GPIO pins
int initializeGPIO()
{
    // Initialize wiringPi library
    if (wiringPiSetup() == -1)
    {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return 1; // Indicate failure
    }

    // Set all row and column pins to output mode
    for (int i = 0; i < MATRIX_SIZE; i++)
    {
        pinMode(rowPins[i], OUTPUT);
        pinMode(colPins[i], OUTPUT);
    }
    return 0; // Indicate success
}

// Function to clear the LED matrix (turn off all LEDs)
void clearMatrix()
{
    for (int i = 0; i < MATRIX_SIZE; i++)
    {
        digitalWrite(colPins[i], HIGH); // Set all columns HIGH (LEDs off)
    }
}

// Function to display a pattern on the LED matrix
void displayPattern()
{
    // First, turn off all columns
    for (int j = 0; j < MATRIX_SIZE; j++)
    {
        digitalWrite(colPins[j], HIGH);
    }

    // Then, light up each row sequentially
    for (int i = 0; i < MATRIX_SIZE; i++)
    {
        digitalWrite(rowPins[i], HIGH);
        delay(200);
        digitalWrite(rowPins[i], LOW);
        delay(200);
    }
}

int main()
{
    // Initialize GPIO pins
    if (initializeGPIO() != 0)
    {
        fprintf(stderr, "GPIO initialization failed. Exiting.\n");
        return 1; // Exit if initialization fails
    }

    // Main loop to continuously display the pattern
    while (1)
    {
        displayPattern();
    }

    return 0;
}

