// Data structure for storing sensor data
typedef struct {
    int raw_adc_value;
    float moisture_percentage;
} SensorData;

// Circular buffer structure
typedef struct {
    SensorData buffer[BUFFER_SIZE];
    int head;
    int tail;
    int count;
} CircularBuffer;

// Global variables (try to minimize)
