// Function to calculate moisture percentage
float calculate_moisture_percentage(int adc_value) {
    float percentage = 100.0 - ((float)(adc_value - WET_ADC_VALUE) / (DRY_ADC_VALUE - WET_ADC_VALUE)) * 100.0;
    if (percentage < 0.0) percentage = 0.0;
    if (percentage > 100.0) percentage = 100.0;
    return percentage;
}

// Function to write data to the circular buffer
void write_to_buffer(CircularBuffer *cb, SensorData data) {
    cb->buffer[cb->head] = data;
    cb->head = (cb->head + 1) % BUFFER_SIZE;
    if (cb->count == BUFFER_SIZE) {
        cb->tail = (cb->tail + 1) % BUFFER_SIZE;
    } else {
        cb->count++;
    }
}

// Function to read data from the circular buffer
SensorData read_from_buffer(CircularBuffer *cb, int index) {
    if (index < 0 || index >= cb->count) {
        fprintf(stderr, "Error: Index out of bounds\n");
        SensorData dummy = {0, 0.0};
        return dummy; // Return a dummy value
    }
    int actual_index = (cb->tail + index) % BUFFER_SIZE;
    return cb->buffer[actual_index];
}

// Function to print the contents of the circular buffer
void print_buffer(CircularBuffer *cb) {
    printf("Circular Buffer Contents:\n");
    for (int i = 0; i < cb->count; i++) {
        SensorData data = read_from_buffer(cb, i);
        printf("Index %d: ADC = %d, Moisture = %.2f%%\n", i, data.raw_adc_value, data.moisture_percentage);
    }
}

// Signal handler for graceful termination
void signal_handler(int signal) {
    printf("Received signal %d, cleaning up...\n", signal);
    running = 0;
}

// Function to initialize the pigpio library and GPIO pins
int initialize() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Indicate error
    }

    gpioSetMode(GPIO_LED, PI_OUTPUT);
    // GPIO_ADC is an input, but we don't directly read it here (ADC handles it).

    return 0; // Indicate success
}

// Function to cleanup resources before exiting
void cleanup() {
    gpioWrite(GPIO_LED, 0); // Turn off the LED
    gpioTerminate();        // Terminate the pigpio library
}

int main() {
    // Initialize signal handling
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize pigpio
    if (initialize()) {
        return 1;
    }

    // Initialize circular buffer
    CircularBuffer moisture_data_buffer;
    init_circular_buffer(&moisture_data_buffer);

    // Main loop
    while (running) {
        // Read ADC value
        int adc_value = read_adc_value();
        if (adc_value < 0) {
            fprintf(stderr, "Error reading ADC value\n");
            continue; // Skip to the next iteration
        }

        // Calculate moisture percentage
        float moisture_percentage = calculate_moisture_percentage(adc_value);

        // Create sensor data
        SensorData data = {adc_value, moisture_percentage};

        // Write data to the circular buffer
        write_to_buffer(&moisture_data_buffer, data);

        // Check moisture threshold and control LED
        if (moisture_percentage < MOISTURE_THRESHOLD) {
            gpioWrite(GPIO_LED, 1); // Turn on LED
        } else {
            gpioWrite(GPIO_LED, 0); // Turn off LED
        }

        // Print buffer contents (for debugging)
        print_buffer(&moisture_data_buffer);

        // Delay for the sample interval
        gpioDelay(SAMPLE_INTERVAL_MS);
    }

    // Cleanup resources
    cleanup();

    return 0;
}

