#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>

// Constants
const int PIR_GPIO = 17;
const int BUZZER_GPIO = 18;
const int DEBOUNCE_MS = 200;
const int BUZZER_DURATION_MS = 1000;
const int GPIO_INIT_ERROR = 1;
const int INTERRUPT_INIT_ERROR = 2;

// Global variables
static volatile uint32_t last_trigger_time = 0;
static volatile int running = 1;

// Function prototypes
int gpio_init();
void pir_interrupt_handler(int gpio, int level, uint32_t tick);
void buzzer_on();
void buzzer_off();
void buzzer_pulse();
void error_handler(int error_code, const char *message);
void signal_handler(int signal);

// GPIO Initialization
int gpio_init() {
    if (gpioInitialise() < 0) {
        return GPIO_INIT_ERROR;
    }

    gpioSetMode(PIR_GPIO, PI_INPUT);
    gpioSetMode(BUZZER_GPIO, PI_OUTPUT);

    return 0; // Success
}

// Interrupt Handling
void pir_interrupt_handler(int gpio, int level, uint32_t tick) {
    uint32_t now = tick;

    if (now - last_trigger_time > DEBOUNCE_MS * 1000) { // Debounce
        buzzer_pulse();
        last_trigger_time = now;
    }
}

// Buzzer Control
void buzzer_on() {
    gpioWrite(BUZZER_GPIO, 1); // HIGH
}

void buzzer_off() {
    gpioWrite(BUZZER_GPIO, 0); // LOW
}

void buzzer_pulse() {
    buzzer_on();
    gpioDelay(BUZZER_DURATION_MS); // Wait for 1 second
    buzzer_off();
}

// Error Handling
void error_handler(int error_code, const char *message) {
    fprintf(stderr, "Error: %s (code %d)\n", message, error_code);
    gpioTerminate();
    exit(error_code);
}

// Signal Handler
void signal_handler(int signal) {
    printf("Caught signal %d, cleaning up...\n", signal);
    running = 0;
    gpioTerminate();
    exit(0);
}

int main() {
    // Initialize GPIO
    int init_result = gpio_init();
    if (init_result != 0) {
        error_handler(GPIO_INIT_ERROR, "GPIO initialization failed");
    }

    // Register interrupt handler
    if (gpioSetAlertFuncEx(PIR_GPIO, EITHER_EDGE, pir_interrupt_handler) != 0) {
        error_handler(INTERRUPT_INIT_ERROR, "Interrupt handler registration failed");
    }

    // Set up signal handling for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    printf("PIR sensor monitoring started. Press Ctrl+C to exit.\n");

    // Main loop
    while (running) {
        sleep(1); // Wait for interrupts
    }

    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>

// GPIO pins
#define FLAME_SENSOR_PIN 17
#define BUZZER_PIN 27

// Sysfs paths
#define GPIO_EXPORT_PATH "/sys/class/gpio/export"
#define GPIO_UNEXPORT_PATH "/sys/class/gpio/unexport"
#define GPIO_DIRECTION_PATH_FORMAT "/sys/class/gpio/gpio%d/direction"
#define GPIO_VALUE_PATH_FORMAT "/sys/class/gpio/gpio%d/value"

// Log file path
#define LOG_FILE_PATH "fire_log.txt"

// Function prototypes
int gpio_export(int pin);
int gpio_unexport(int pin);
int gpio_set_direction(int pin, const char *direction);
int gpio_get_value(int pin);
int gpio_set_value(int pin, int value);
char *get_timestamp();
int log_event(const char *timestamp);
int read_flame_sensor();
int activate_buzzer();
void cleanup(int signum);
void main_loop();

// Signal handler for cleanup
void cleanup(int signum) {
    printf("\nCleaning up and exiting...\n");
    gpio_set_value(BUZZER_PIN, 0); // Ensure buzzer is off
    gpio_unexport(FLAME_SENSOR_PIN);
    gpio_unexport(BUZZER_PIN);
    exit(signum);
}

// Exports a GPIO pin
int gpio_export(int pin) {
    FILE *fp = fopen(GPIO_EXPORT_PATH, "w");
    if (!fp) {
        fprintf(stderr, "Error: Could not open GPIO export file.\n");
        return -1;
    }
    fprintf(fp, "%d", pin);
    fclose(fp);
    return 0;
}

// Unexports a GPIO pin
int gpio_unexport(int pin) {
    FILE *fp = fopen(GPIO_UNEXPORT_PATH, "w");
    if (!fp) {
        fprintf(stderr, "Error: Could not open GPIO unexport file.\n");
        return -1;
    }
    fprintf(fp, "%d", pin);
    fclose(fp);
    return 0;
}

// Sets the direction of a GPIO pin (in or out)
int gpio_set_direction(int pin, const char *direction) {
    char path[64];
    snprintf(path, sizeof(path), GPIO_DIRECTION_PATH_FORMAT, pin);
    FILE *fp = fopen(path, "w");
    if (!fp) {
        fprintf(stderr, "Error: Could not open GPIO direction file for pin %d.\n", pin);
        return -1;
    }
    fprintf(fp, "%s", direction);
    fclose(fp);
    return 0;
}

// Reads the value of a GPIO pin
int gpio_get_value(int pin) {
    char path[64];
    snprintf(path, sizeof(path), GPIO_VALUE_PATH_FORMAT, pin);
    FILE *fp = fopen(path, "r");
    if (!fp) {
        fprintf(stderr, "Error: Could not open GPIO value file for pin %d.\n", pin);
        return -1;
    }
    int value;
    fscanf(fp, "%d", &value);
    fclose(fp);
    return value;
}

// Sets the value of a GPIO pin
int gpio_set_value(int pin, int value) {
    char path[64];
    snprintf(path, sizeof(path), GPIO_VALUE_PATH_FORMAT, pin);
    FILE *fp = fopen(path, "w");
    if (!fp) {
        fprintf(stderr, "Error: Could not open GPIO value file for pin %d.\n", pin);
        return -1;
    }
    fprintf(fp, "%d", value);
    fclose(fp);
    return 0;
}

// Gets the current timestamp in YYYY-MM-DD HH:MM:SS format
char *get_timestamp() {
    time_t rawtime;
    struct tm *timeinfo;
    time(&rawtime);
    timeinfo = localtime(&rawtime);
    static char timestamp[20]; // Static to keep the memory valid after function returns
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);
    return timestamp;
}

// Logs a flame detection event to the log file
int log_event(const char *timestamp) {
    FILE *fp = fopen(LOG_FILE_PATH, "a");
    if (!fp) {
        fprintf(stderr, "Error: Could not open log file for writing.\n");
        return -1;
    }
    fprintf(fp, "%s - Flame detected!\n", timestamp);
    fclose(fp);
    return 0;
}

// Reads the flame sensor value
int read_flame_sensor() {
    return gpio_get_value(FLAME_SENSOR_PIN);
}

// Activates the buzzer for 1 second
int activate_buzzer() {
    if (gpio_set_value(BUZZER_PIN, 1) != 0) {
        fprintf(stderr, "Error: Could not activate buzzer.\n");
        return -1;
    }
    sleep(1);
    if (gpio_set_value(BUZZER_PIN, 0) != 0) {
        fprintf(stderr, "Error: Could not deactivate buzzer.\n");
        return -1;
    }
    return 0;
}

// Main loop of the program
void main_loop() {
    while (1) {
        int flame_detected = (read_flame_sensor() == 0); // LOW = Flame detected

        if (flame_detected) {
            char *timestamp = get_timestamp();
            printf("%s - Flame detected!\n", timestamp);
            log_event(timestamp);
            activate_buzzer();
        }

        sleep(1); // Check every 1 second
    }
}

int main() {
    // Set up signal handler for Ctrl+C
    signal(SIGINT, cleanup);

    // Export GPIO pins
    if (gpio_export(FLAME_SENSOR_PIN) != 0) return 1;
    if (gpio_export(BUZZER_PIN) != 0) return 1;

    // Set GPIO directions
    if (gpio_set_direction(FLAME_SENSOR_PIN, "in") != 0) return 1;
    if (gpio_set_direction(BUZZER_PIN, "out") != 0) return 1;

    // Initialize buzzer to off
    if (gpio_set_value(BUZZER_PIN, 0) != 0) return 1;

    printf("Flame sensor monitoring started. Press Ctrl+C to exit.\n");

    main_loop();

    return 0; // This should never be reached due to the infinite loop
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <signal.h>
#include <unistd.h>

// Define GPIO pins
#define SERVO_PIN 17
#define TRIGGER_PIN 23
#define ECHO_PIN 24

// Constants
#define SPEED_OF_SOUND 34300.0 // Speed of sound in cm/s
#define OBJECT_DETECTED_THRESHOLD 20.0 // Distance threshold in cm
#define SERVO_NEUTRAL_POSITION 1500 // Neutral position for servo (microseconds)
#define SERVO_MIN_PULSE_WIDTH 1000  // Minimum pulse width for servo (microseconds)
#define SERVO_MAX_PULSE_WIDTH 2000  // Maximum pulse width for servo (microseconds)

// Global variables
volatile sig_atomic_t program_running = 1;

// Function prototypes
int initializeGPIO();
void sweepServo();
float getDistance();
int isObjectDetected(float distance);
void signal_handler(int signal);

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("\nCtrl+C pressed. Exiting gracefully...\n");
        gpioServo(SERVO_PIN, SERVO_NEUTRAL_POSITION); // Stop the servo
        gpioTerminate(); // Terminate pigpio
        program_running = 0;
        exit(0); // Exit the program
    }
}

// Initialize GPIO pins
int initializeGPIO() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Error
    }

    gpioSetMode(SERVO_PIN, PI_OUTPUT); // Set servo pin as output
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT); // Set trigger pin as output
    gpioSetMode(ECHO_PIN, PI_INPUT); // Set echo pin as input

    return 0; // Success
}

// Sweep the servo motor from 0 to 180 degrees
void sweepServo() {
    for (int angle = 0; angle <= 180 && program_running; angle++) {
        // Calculate pulse width for the given angle (SG90 servo)
        int pulse_width = SERVO_MIN_PULSE_WIDTH + (int)(((float)angle / 180.0) * (SERVO_MAX_PULSE_WIDTH - SERVO_MIN_PULSE_WIDTH));

        if (gpioServo(SERVO_PIN, pulse_width) != 0) {
            fprintf(stderr, "Error setting servo angle\n");
            gpioTerminate(); // Terminate pigpio
            exit(1); // Exit the program
        }

        float distance = getDistance(); // Get distance reading
        printf("Angle: %d degrees, Distance: %.2f cm\n", angle, distance);

        if (isObjectDetected(distance)) {
            printf("Object detected within %.2f cm! Halting sweep.\n", OBJECT_DETECTED_THRESHOLD);
            gpioServo(SERVO_PIN, SERVO_NEUTRAL_POSITION); // Stop the servo
            break; // Exit the loop
        }

        gpioDelay(20000); // Delay 20ms (adjust as needed)
    }
}

// Get distance reading from the ultrasonic sensor
float getDistance() {
    gpioWrite(TRIGGER_PIN, 0); // Ensure trigger is low
    gpioDelay(2); // Wait 2us
    gpioWrite(TRIGGER_PIN, 1); // Send a 10us pulse
    gpioDelay(10); 
    gpioWrite(TRIGGER_PIN, 0);

    uint32_t start = gpioTick(); // Record start time
    uint32_t end = gpioTick();   // Record end time

    // Wait for echo to go high (with timeout)
    int timeout = 100000; // Timeout after 100ms (adjust as needed)
    while (gpioRead(ECHO_PIN) == 0 && timeout > 0) {
        timeout--;
        gpioDelay(1); // Small delay to prevent busy-waiting
    }
    if (timeout <= 0) return 999.0; // Return a large value if timeout

    start = gpioTick();

    // Wait for echo to go low (with timeout)
    timeout = 100000;
    while (gpioRead(ECHO_PIN) == 1 && timeout > 0) {
        timeout--;
        gpioDelay(1);
    }
    if (timeout <= 0) return 999.0; // Return a large value if timeout

    end = gpioTick();

    uint32_t diff = end - start; // Calculate pulse duration

    float distance = (diff / 2.0) * (SPEED_OF_SOUND / 1000000.0); // Calculate distance in cm
    return distance;
}

// Check if an object is detected within the threshold
int isObjectDetected(float distance) {
    return (distance < OBJECT_DETECTED_THRESHOLD);
}

int main() {
    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize GPIO
    if (initializeGPIO() != 0) {
        return 1; // Exit if initialization fails
    }

    printf("Parking Assist System for Smart Agriculture\n");

    // Sweep the servo and measure distances
    sweepServo();

    // Clean up and exit
    gpioServo(SERVO_PIN, SERVO_NEUTRAL_POSITION); // Stop the servo
    gpioTerminate(); // Terminate pigpio

    return 0;
}

