#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <unistd.h>
#include <inttypes.h>
#include <errno.h>
#include <string.h>

// MPU6050 Register Addresses
#define MPU6050_ADDR 0x68        // MPU6050 default I2C address
#define MPU6050_REG_PWR_MGMT_1 0x6B // Power Management 1 register
#define MPU6050_REG_TEMP_OUT_H 0x41 // Temperature sensor MSB register
#define MPU6050_REG_ACCEL_XOUT_H 0x3B // Accel X MSB register
#define MPU6050_REG_GYRO_XOUT_H 0x43  // Gyro X MSB register

// Helper function to read a 16-bit value from two 8-bit registers
static int16_t read_word_2c(int file, uint8_t reg)
{
    int16_t high, low, value;
    high = i2c_smbus_read_byte_data(file, reg);          // Read high byte
    low = i2c_smbus_read_byte_data(file, reg + 1);      // Read low byte
    value = (high << 8) | low;
    return value;
}

int main()
{
    const char *i2c_device = "/dev/i2c-1"; // I2C device file
    int file;

    // Open I2C device
    if ((file = open(i2c_device, O_RDWR)) < 0) {
        fprintf(stderr, "Error: Could not open file %s: %s\n", i2c_device, strerror(errno));
        return 1;
    }

    // Specify the address of the slave device
    if (ioctl(file, I2C_SLAVE, MPU6050_ADDR) < 0) {
        fprintf(stderr, "Error: Could not set I2C slave address: %s\n", strerror(errno));
        close(file);
        return 1;
    }

    // Wake up the MPU6050 (clear sleep mode bit)
    if (i2c_smbus_write_byte_data(file, MPU6050_REG_PWR_MGMT_1, 0) < 0) {
        fprintf(stderr, "Error: Could not wake up MPU6050: %s\n", strerror(errno));
        close(file);
        return 1;
    }

    // Main loop to read and print data
    while (1) {
        // Read temperature
        int16_t temperature = read_word_2c(file, MPU6050_REG_TEMP_OUT_H);
        float temperature_celsius = (float)temperature / 340.0f + 36.53f;

        // Read accelerometer values
        int16_t accel_x = read_word_2c(file, MPU6050_REG_ACCEL_XOUT_H);
        int16_t accel_y = read_word_2c(file, MPU6050_REG_ACCEL_XOUT_H + 2);
        int16_t accel_z = read_word_2c(file, MPU6050_REG_ACCEL_XOUT_H + 4);

        // Read gyroscope values
        int16_t gyro_x = read_word_2c(file, MPU6050_REG_GYRO_XOUT_H);
        int16_t gyro_y = read_word_2c(file, MPU6050_REG_GYRO_XOUT_H + 2);
        int16_t gyro_z = read_word_2c(file, MPU6050_REG_GYRO_XOUT_H + 4);

        // Print the data
        printf("Temperature: %.2f °C\n", temperature_celsius);
        printf("Accelerometer: X = %d, Y = %d, Z = %d\n", accel_x, accel_y, accel_z);
        printf("Gyroscope: X = %d, Y = %d, Z = %d\n\n", gyro_x, gyro_y, gyro_z);

        sleep(1); // Wait for 1 second
    }

    close(file);
    return 0;
}

#include <pigpio.h>
#include <stdio.h>
#include <unistd.h>

// Define GPIO pins for segments (A, B, C, D, E, F, G)
#define SEG_A 4
#define SEG_B 17
#define SEG_C 27
#define SEG_D 22
#define SEG_E 5
#define SEG_F 6
#define SEG_G 13

// Define delay in milliseconds
#define DELAY_MS 500

// Function to display a digit on the seven-segment display
void displayDigit(int digit) {
    // Define segment patterns for digits 0-9 (common anode configuration)
    unsigned char segments[10] = {
        0b00111111, // 0: A+B+C+D+E+F
        0b00000110, // 1: B+C
        0b01011011, // 2: A+B+D+E+G
        0b01001111, // 3: A+B+C+D+G
        0b01100110, // 4: B+C+F+G
        0b01101101, // 5: A+C+D+F+G
        0b01111101, // 6: A+C+D+E+F+G
        0b00000111, // 7: A+B+C
        0b01111111, // 8: A+B+C+D+E+F+G
        0b01101111  // 9: A+B+C+F+G
    };

    // Get the segment pattern for the digit
    unsigned char pattern = segments[digit];

    // Set GPIO pins according to the segment pattern
    gpioWrite(SEG_A, !(pattern & 0x40)); // A
    gpioWrite(SEG_B, !(pattern & 0x20)); // B
    gpioWrite(SEG_C, !(pattern & 0x10)); // C
    gpioWrite(SEG_D, !(pattern & 0x08)); // D
    gpioWrite(SEG_E, !(pattern & 0x04)); // E
    gpioWrite(SEG_F, !(pattern & 0x02)); // F
    gpioWrite(SEG_G, !(pattern & 0x01)); // G
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pins as outputs
    gpioSetMode(SEG_A, PI_OUTPUT);
    gpioSetMode(SEG_B, PI_OUTPUT);
    gpioSetMode(SEG_C, PI_OUTPUT);
    gpioSetMode(SEG_D, PI_OUTPUT);
    gpioSetMode(SEG_E, PI_OUTPUT);
    gpioSetMode(SEG_F, PI_OUTPUT);
    gpioSetMode(SEG_G, PI_OUTPUT);

    // Flash digits 0-9
    for (int i = 0; i < 10; i++) {
        displayDigit(i);
        gpioDelay(DELAY_MS * 1000); // Delay in microseconds
    }

    // Clear the display (optional)
    displayDigit(-1); // Or set all pins low

    // Terminate pigpio
    gpioTerminate();

    return 0;
}

