}

int main() {
    int pwm_value;

    // Set up signal handling for SIGINT (Ctrl+C)
    signal(SIGINT, signal_handler);

    // Initialize wiringPi with GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "wiringPiSetupGpio failed: %s\n", strerror(errno));
        return 1;
    }

    // Disable the default LED trigger
    if (set_led_trigger_none() != 0) {
        fprintf(stderr, "Failed to set LED trigger to 'none'. Exiting.\n");
        return 1;
    }

    // Create a soft PWM controller on the OK_LED_PIN
    if (softPwmCreate(OK_LED_PIN, 0, PWM_RANGE) != 0) {
        fprintf(stderr, "softPwmCreate failed for pin %d. Exiting.\n", OK_LED_PIN);
        return 1;
    }

    printf("OK LED pulsation started. Press Ctrl+C to exit.\n");

    // Main loop to pulsate the LED
    while (program_running) {
        // Fade in
        for (pwm_value = 0; pwm_value <= PWM_RANGE; ++pwm_value) {
            softPwmWrite(OK_LED_PIN, pwm_value);
            delay(10);
        }

        delay(50);

        // Fade out
        for (pwm_value = PWM_RANGE; pwm_value >= 0; --pwm_value) {
            softPwmWrite(OK_LED_PIN, pwm_value);
            delay(10);
        }

        delay(10);
    }

    // Clean up: set LED to off and exit
    softPwmWrite(OK_LED_PIN, 0);

    return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <fcntl.h>
#include <linux/spi/spidev.h>
#include <sys/ioctl.h>
#include <stdint.h>

int read_adc(int fd, int ch) {
    uint8_t tx[] = {0x01, (0x80 | (ch << 4)), 0x00};
    uint8_t rx[3];
    struct spi_ioc_transfer tr = {
        .tx_buf = (unsigned long)tx,
        .rx_buf = (unsigned long)rx,
        .len = 3,
        .speed_hz = 1000000,
        .bits_per_word = 8
    };
    ioctl(fd, SPI_IOC_MESSAGE(1), &tr);
    return ((rx[1] & 0x03) << 8) | rx[2];
}

int main() {
    FILE *f = fopen("adc_4ch_log.csv", "w");
    fprintf(f, "CH0,CH1,CH2,CH3\n");
    int fd = open("/dev/spidev0.0", O_RDWR);
    while (1) {
        for (int i = 0; i < 4; i++) fprintf(f, "%d%s", read_adc(fd, i), i < 3 ? "," : "\n");
        fflush(f);
        sleep(1);
    }
    fclose(f);
    return 0;
}

