#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>

// Define the GPIO pins connected to the 74HC595
#define SER 17  // Serial data input
#define RCLK 27 // Register clock (latch)
#define SRCLK 22 // Shift register clock

// Seven-segment display patterns (common cathode)
const unsigned char segment_digits[] = {
    0b00111111, // 0
    0b00000110, // 1
    0b01011011, // 2
    0b01001111, // 3
    0b01100110, // 4
    0b01101101, // 5
    0b01111101, // 6
    0b00000111, // 7
    0b01111111, // 8
    0b01101111  // 9
};

// Function to shift out data to the 74HC595
void shift_out(unsigned char data) {
    for (int i = 0; i < 8; i++) {
        // Set the data bit
        gpioWrite(SER, (data >> (7 - i)) & 0x01);
        // Clock the shift register
        gpioWrite(SRCLK, 1);
        gpioWrite(SRCLK, 0);
    }
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set the GPIO pins as outputs
    gpioSetMode(SER, PI_OUTPUT);
    gpioSetMode(RCLK, PI_OUTPUT);
    gpioSetMode(SRCLK, PI_OUTPUT);

    // Initialize the pins to low
    gpioWrite(SER, 0);
    gpioWrite(RCLK, 0);
    gpioWrite(SRCLK, 0);

    // Main loop to count from 0 to 9
    for (int i = 0; i < 10; i++) {
        shift_out(segment_digits[i]);
        // Latch the data to the output
        gpioWrite(RCLK, 1);
        gpioWrite(RCLK, 0);

        sleep(1);
    }

    gpioTerminate();
    return 0;
}

