#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <stdint.h>
#include <pigpio.h>

// Define GPIO pins for lamp actuators
#define LAMP1_GPIO 4
#define LAMP2_GPIO 17
#define LAMP3_GPIO 27
#define LAMP4_GPIO 22

// Define I2C address for BH1750 sensor
#define BH1750_ADDR 0x23

// Define PWM frequency
#define PWM_FREQUENCY 200

// Global variables for graceful shutdown
static int i2c_handle = -1;
static volatile sig_atomic_t terminate = 0;

// Function prototypes
int read_light_level(int i2c_handle);
void set_lamp_intensity(int gpio, int intensity);
int map_light_to_intensity(int light_level);
void signal_handler(int signal);

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    fprintf(stderr, "\nCaught signal %d, terminating gracefully...\n", signal);
    terminate = 1;
}

// Function to read light level from BH1750 sensor
int read_light_level(int i2c_handle) {
    uint8_t data[2];
    int light_level;
    int result;

    // Send command for continuous high-resolution mode
    if (i2cWriteByte(i2c_handle, 0x10) < 0) { // 0x10 is the continuous high resolution mode command
        fprintf(stderr, "Error: Failed to set BH1750 to continuous high-resolution mode\n");
        return -1; // Indicate error
    }

    // Wait for measurement (at least 180ms)
    gpioDelay(200); 

    // Read 2 bytes of data
    result = i2cReadDevice(i2c_handle, (char *)data, 2);
    if (result != 2) {
        fprintf(stderr, "Error: Failed to read data from BH1750 (result = %d)\n", result);
        return -1; // Indicate error
    }

    // Combine the bytes to get the light level
    light_level = (data[0] << 8) | data[1];

    return light_level;
}

// Function to set lamp intensity using PWM
void set_lamp_intensity(int gpio, int intensity) {
    if (gpioPWM(gpio, intensity) != 0) {
        fprintf(stderr, "Error: Failed to set PWM for GPIO %d\n", gpio);
    }
}

// Function to map light level to lamp intensity (PWM duty cycle)
int map_light_to_intensity(int light_level) {
    // Adjust these values based on your specific needs and sensor range
    const int max_light_level = 1000; // Example maximum light level

    if (light_level < 0) light_level = 0; // Ensure light level is not negative
    if (light_level > max_light_level) light_level = max_light_level; // Cap at max

    // Map light level to intensity (0-255)
    return (int)(((float)(max_light_level - light_level) / max_light_level) * 255.0); // Inverse mapping: lower light -> higher intensity
}

int main() {
    // Register signal handlers for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes for lamp actuators as outputs
    gpioSetMode(LAMP1_GPIO, PI_OUTPUT);
    gpioSetMode(LAMP2_GPIO, PI_OUTPUT);
    gpioSetMode(LAMP3_GPIO, PI_OUTPUT);
    gpioSetMode(LAMP4_GPIO, PI_OUTPUT);

    // Set PWM frequency for all lamp GPIOs
    gpioSetPWMfrequency(LAMP1_GPIO, PWM_FREQUENCY);
    gpioSetPWMfrequency(LAMP2_GPIO, PWM_FREQUENCY);
    gpioSetPWMfrequency(LAMP3_GPIO, PWM_FREQUENCY);
    gpioSetPWMfrequency(LAMP4_GPIO, PWM_FREQUENCY);

    // Open I2C device
    i2c_handle = i2cOpen(1, BH1750_ADDR, 0); // Bus 1, address 0x23, no flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Error: Failed to open I2C device (handle = %d)\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    fprintf(stderr, "Smart Lighting System started. Press Ctrl+C to exit.\n");

    // Main loop
    while (!terminate) {
        int light_level = read_light_level(i2c_handle);
        if (light_level >= 0) {
            int intensity1 = map_light_to_intensity(light_level);
            int intensity2 = map_light_to_intensity(light_level);
            int intensity3 = map_light_to_intensity(light_level);
            int intensity4 = map_light_to_intensity(light_level);

            set_lamp_intensity(LAMP1_GPIO, intensity1);
            set_lamp_intensity(LAMP2_GPIO, intensity2);
            set_lamp_intensity(LAMP3_GPIO, intensity3);
            set_lamp_intensity(LAMP4_GPIO, intensity4);

            // Print light level and intensities (for debugging)
            printf("Light Level: %d, Intensities: %d %d %d %d\n", light_level, intensity1, intensity2, intensity3, intensity4);
        } else {
            fprintf(stderr, "Error: Failed to read light level, retrying...\n");
        }

        gpioDelay(500); // Delay for 0.5 seconds
    }

    // Turn off all lamps during shutdown
    gpioWrite(LAMP1_GPIO, 0);
    gpioWrite(LAMP2_GPIO, 0);
    gpioWrite(LAMP3_GPIO, 0);
    gpioWrite(LAMP4_GPIO, 0);

    // Close I2C device
    i2cClose(i2c_handle);

    // Terminate pigpio library
    gpioTerminate();

    fprintf(stderr, "Smart Lighting System terminated.\n");

    return 0;
}

#include <stdio.h>
