#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pigpio.h>

// Constants
#define TRIGGER_PIN 23
#define ECHO_PIN 24
#define SERVO_PIN 17
#define MAX_DISTANCE 200.0  // Maximum distance to measure (cm)
#define SOUND_SPEED 34300.0 // Speed of sound in cm/s
#define TIMEOUT_US 200000     // Timeout for echo pulse (200ms)
#define RETRY_COUNT 3         // Number of retries for sensor reading

// Function prototypes
float measureDistance();
int setServoAngle(float distance);
void signal_handler(int signal);

// Global variable for graceful shutdown
volatile sig_atomic_t program_running = 1;

// Signal handler function
void signal_handler(int signal)
{
    if (signal == SIGINT)
    {
        printf("Ctrl+C pressed. Exiting gracefully.\n");
        program_running = 0;
        // Set servo to a safe position (90 degrees)
        setServoAngle(100.0); // Assuming 100cm is a safe distance
        gpioDelay(200);      // Allow servo to move
        gpioTerminate();       // Terminate pigpio
        exit(0);
    }
}

// Function to measure distance using HC-SR04 sensor
float measureDistance()
{
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);

    // Trigger the sensor
    gpioWrite(TRIGGER_PIN, 1);
    gpioDelay(10); // 10us trigger pulse
    gpioWrite(TRIGGER_PIN, 0);

    // Measure echo pulse width
    uint32_t start_tick = 0, end_tick = 0;

    // Wait for echo to start
    int count = 0;
    while (gpioRead(ECHO_PIN) == 0 && count < TIMEOUT_US)
    {
        if (count == 0) start_tick = gpioTick();
        count++;
        gpioDelay(1); // Check every 1us
    }

    if (count >= TIMEOUT_US) {
      fprintf(stderr, "Error: Echo start timeout\n");
      return -1.0;
    }

    // Wait for echo to end
    count = 0;
    while (gpioRead(ECHO_PIN) == 1 && count < TIMEOUT_US)
    {
        count++;
        gpioDelay(1); // Check every 1us
    }

    if (count >= TIMEOUT_US) {
      fprintf(stderr, "Error: Echo end timeout\n");
      return -1.0;
    }

    end_tick = gpioTick();

    // Calculate pulse width in microseconds
    uint32_t pulse_width = end_tick - start_tick;

    // Calculate distance in centimeters
    float distance = (float)pulse_width * SOUND_SPEED / 20000.0;

    return distance;
}

// Function to set servo angle based on distance
int setServoAngle(float distance)
{
    // Ensure distance is within valid range
    if (distance < 0.0) distance = 0.0;
    if (distance > MAX_DISTANCE) distance = MAX_DISTANCE;

    // Map distance to angle (0cm = 0 degrees, 200cm = 180 degrees)
    float angle = (distance / MAX_DISTANCE) * 180.0;

    // Calculate pulse width (500us = 0 degrees, 2500us = 180 degrees)
    int pulsewidth = (int)(angle * (2000.0 / 180.0) + 500.0);

    // Set servo pulse width
    int result = gpioServo(SERVO_PIN, pulsewidth);

    if (result != 0)
    {
        fprintf(stderr, "Error: Failed to set servo angle. pigpio error code: %d\n", result);
        return result; // Return error code
    }

    return 0; // Return success
}

int main()
{
    // Initialize pigpio library
    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Set signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Set GPIO mode for servo pin
    gpioSetMode(SERVO_PIN, PI_OUTPUT);

    printf("Parking Assist System started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running)
    {
        float distance = -1.0;
        int retry = 0;

        // Retry distance measurement if it fails
        while (distance < 0.0 && retry < RETRY_COUNT)
        {
            distance = measureDistance();
            if (distance < 0.0) {
                fprintf(stderr, "Warning: Distance measurement failed. Retrying (%d/%d)\n", retry + 1, RETRY_COUNT);
                gpioDelay(100); // Wait before retrying
            }
            retry++;
        }

        if (distance >= 0.0)
        {
            printf("Distance: %.2f cm\n", distance);
            int servo_result = setServoAngle(distance);
            if (servo_result != 0) {
              fprintf(stderr, "Warning: Servo control failed, but continuing.\n");
            }
        }
        else
        {
            fprintf(stderr, "Error: Distance measurement failed after multiple retries.\n");
        }

        gpioDelay(500); // Delay to avoid overwhelming sensor and servo
    }

    // This part will only be reached if program_running is set to 0 (e.g., by the signal handler)
    printf("Exiting...\n");

    // Reset servo to a safe position (90 degrees) before exiting
    setServoAngle(100.0); // Assuming 100cm is a safe distance
    gpioDelay(200);      // Allow servo to move

    gpioTerminate(); // Terminate pigpio

    return 0;
}

