#define ADS_ADDR 0x48
#define CONFIG_REG 0x01
#define CONVERSION_REG 0x00
#define REF_VOLTAGE 4.096
int read_ads_channel(int fd, int ch) {
    int mux = 0x4000 | (ch << 12); // single-ended AINx
    int config = 0xC083 | mux;     // OS=1, PGA=±4.096V, CONT=0
    wiringPiI2CWriteReg16(fd, CONFIG_REG, (config >> 8) | ((config & 0xFF) << 8));
    usleep(9000);
    int raw = wiringPiI2CReadReg16(fd, CONVERSION_REG);
    return (raw << 8 & 0xFF00) | (raw >> 8 & 0x00FF);
}
int main() {
    int fd = wiringPiI2CSetup(ADS_ADDR);
    while (1) {
        printf("============================\n");
        for (int i = 0; i < 4; i++) {
            int val = read_ads_channel(fd, i);
            double v = val * REF_VOLTAGE / 32768.0;
            printf("Channel %d: %6.3f V\n", i, v);
        }
        printf("============================\n\n");
        sleep(1);
    }
    return 0;
}

