#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <signal.h>
#include <pthread.h>
#include <unistd.h>

// Define GPIO pins
#define TRIGGER_PIN 23
#define ECHO_PIN 24

// Mutex for protecting pulse width
pthread_mutex_t pulse_mutex;

// Global variable to store pulse width
volatile long pulse_width = 0;

// Signal handler for graceful termination
void signal_handler(int signal) {
    printf("\nExiting program...\n");
    gpioTerminate();
    exit(0);
}

// Function to trigger the ultrasonic sensor
void triggerSensor() {
    gpioWrite(TRIGGER_PIN, 1); // Send a HIGH pulse
    gpioDelay(10);            // for 10 microseconds
    gpioWrite(TRIGGER_PIN, 0); // Send a LOW pulse
}

// Function to calculate distance in centimeters
double calculateDistance(long pulseWidth) {
    // Speed of sound in air is approximately 0.0343 cm/us
    // Divide by 2 because the sound travels to the object and back
    return pulseWidth * 0.0343 / 2.0;
}

// Interrupt handler for echo pin
void echo_callback(int gpio, int level, uint32_t tick) {
    static uint32_t start_tick = 0;

    if (level == 1) {
        // Rising edge: record start time
        start_tick = tick;
    } else if (level == 0) {
        // Falling edge: calculate pulse width
        uint32_t end_tick = tick;
        long width = end_tick - start_tick;

        pthread_mutex_lock(&pulse_mutex);
        pulse_width = width;
        pthread_mutex_unlock(&pulse_mutex);
    }
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize mutex
    if (pthread_mutex_init(&pulse_mutex, NULL) != 0) {
        fprintf(stderr, "Mutex initialization failed\n");
        gpioTerminate();
        return 1;
    }

    // Set GPIO modes
    if (gpioSetMode(TRIGGER_PIN, PI_OUTPUT) != 0) {
        fprintf(stderr, "Failed to set trigger pin as output\n");
        gpioTerminate();
        pthread_mutex_destroy(&pulse_mutex);
        return 1;
    }
    if (gpioSetMode(ECHO_PIN, PI_INPUT) != 0) {
        fprintf(stderr, "Failed to set echo pin as input\n");
        gpioTerminate();
        pthread_mutex_destroy(&pulse_mutex);
        return 1;
    }

    // Register interrupt handler for echo pin
    if (gpioSetAlertFuncEx(ECHO_PIN, echo_callback, NULL) != 0) {
        fprintf(stderr, "Failed to set alert function\n");
        gpioTerminate();
        pthread_mutex_destroy(&pulse_mutex);
        return 1;
    }

    printf("Ultrasonic distance measurement started. Press Ctrl+C to exit.\n");

    while (1) {
        // Trigger the sensor
        triggerSensor();

        // Wait for the pulse width to be updated by the interrupt handler
        gpioDelay(100); // Small delay to allow interrupt to fire

        // Acquire the mutex before reading the pulse width
        pthread_mutex_lock(&pulse_mutex);
        long width = pulse_width;
        pthread_mutex_unlock(&pulse_mutex);

        // Calculate the distance
        double distance = calculateDistance(width);

        // Print the distance
        printf("Distance: %.2f cm\n", distance);

        // Delay before next measurement (100ms)
        gpioDelay(100000);
    }

    // Cleanup (never reached in normal execution due to the while loop)
    gpioTerminate();
    pthread_mutex_destroy(&pulse_mutex);
    return 0;
}

#include <stdio.h>
#include <wiringPi.h>

// Define the GPIO pins for the motor driver
#define MOTOR_A_IN1 17 // GPIO 17 (Physical Pin 11)
#define MOTOR_A_IN2 18 // GPIO 18 (Physical Pin 12)
#define MOTOR_B_IN3 22 // GPIO 22 (Physical Pin 15)
#define MOTOR_B_IN4 23 // GPIO 23 (Physical Pin 16)

// Define the GPIO pin for the button
#define BUTTON_PIN 4 // GPIO 4 (Physical Pin 7)

// Function to move the motor forward
void moveMotorForward(int in1, int in2) {
  digitalWrite(in1, HIGH);
  digitalWrite(in2, LOW);
}

// Function to stop the motor
void stopMotor(int in1, int in2) {
  digitalWrite(in1, LOW);
  digitalWrite(in2, LOW);
}

int main() {
  // Initialize wiringPi using the BCM GPIO numbering scheme
  if (wiringPiSetupGpio() == -1) {
    fprintf(stderr, "WiringPi initialization failed!\n");
    return 1;
  }

  // Set the motor control pins as output
  pinMode(MOTOR_A_IN1, OUTPUT);
  pinMode(MOTOR_A_IN2, OUTPUT);
  pinMode(MOTOR_B_IN3, OUTPUT);
  pinMode(MOTOR_B_IN4, OUTPUT);

  // Set the button pin as input with pull-up resistor
  pinMode(BUTTON_PIN, INPUT);
  pullUpDnControl(BUTTON_PIN, PUD_UP); // Enable pull-up resistor

  printf("Motor control program started. Press the button to move motors forward.\n");

  while (1) {
    // Read the button state
    int buttonState = digitalRead(BUTTON_PIN);

    // If the button is pressed (LOW because of pull-up)
    if (buttonState == LOW) {
      // Move both motors forward
      moveMotorForward(MOTOR_A_IN1, MOTOR_A_IN2);
      moveMotorForward(MOTOR_B_IN3, MOTOR_B_IN4);
      printf("Motors moving forward.\n");
      delay(10); // Small delay to avoid excessive CPU usage
    } else {
      // Stop both motors
      stopMotor(MOTOR_A_IN1, MOTOR_A_IN2);
      stopMotor(MOTOR_B_IN3, MOTOR_B_IN4);
      printf("Motors stopped.\n");
      delay(10); // Small delay to avoid excessive CPU usage
    }
  }

  return 0;
}

