#include <stdio.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <linux/i2c-dev.h>
#include <sys/ioctl.h>

#define I2C_BUS "/dev/i2c-1"
#define ADS1115_ADDR 0x48
#define CONFIG_REG 0x01
#define CONVERSION_REG 0x00
#define REF_VOLTAGE 4.096

int main() {
    int fd = open(I2C_BUS, O_RDWR);
    if (fd < 0) return 1;
    ioctl(fd, I2C_SLAVE, ADS1115_ADDR);

    // Configure single-ended AIN0, 4.096V range, single-shot mode
    uint8_t config[3] = {
        CONFIG_REG,
        0xC2, // OS=1, MUX=100 (AIN0), PGA=001 (±4.096V), MODE=1
        0x83  // DR=100 (128 SPS), COMP=disabled
    };
    write(fd, config, 3);
    usleep(9000); // Wait for conversion (~8ms)

    uint8_t reg = CONVERSION_REG;
    write(fd, &reg, 1);
    uint8_t data[2];
    read(fd, data, 2);

    int16_t raw = (data[0] << 8) | data[1];
    double voltage = (raw * REF_VOLTAGE) / 32768.0;
    printf("AIN0 Voltage: %.3f V\n", voltage);

    close(fd);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
