#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pigpio.h>

// Motor 1 GPIO pins
#define MOTOR1_FORWARD 12
#define MOTOR1_BACKWARD 13

// Motor 2 GPIO pins
#define MOTOR2_FORWARD 18
#define MOTOR2_BACKWARD 19

// PWM frequency (Hz)
#define PWM_FREQUENCY 500

// Minimum and maximum PWM duty cycle (microseconds)
#define MIN_DUTY_CYCLE 1000
#define MAX_DUTY_CYCLE 2000

// Function prototypes
void set_motor_angle(int motor_number, int angle);
void signal_handler(int signal);

// Global variables
volatile sig_atomic_t terminate = 0;

int main(int argc, char *argv[]) {
    int angle1, angle2;

    // Install signal handler
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Check command-line arguments
    if (argc != 3) {
        fprintf(stderr, "Usage: %s <angle1> <angle2>\n", argv[0]);
        return 1;
    }

    // Convert command-line arguments to integers
    angle1 = atoi(argv[1]);
    angle2 = atoi(argv[2]);

    // Validate angles
    if (angle1 < 0 || angle1 > 180 || angle2 < 0 || angle2 > 180) {
        fprintf(stderr, "Error: Angles must be between 0 and 180 degrees\n");
        return 1;
    }

    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pins to output mode
    gpioSetMode(MOTOR1_FORWARD, PI_OUTPUT);
    gpioSetMode(MOTOR1_BACKWARD, PI_OUTPUT);
    gpioSetMode(MOTOR2_FORWARD, PI_OUTPUT);
    gpioSetMode(MOTOR2_BACKWARD, PI_OUTPUT);

    // Set PWM frequency
    gpioSetPWMfrequency(MOTOR1_FORWARD, PWM_FREQUENCY);
    gpioSetPWMfrequency(MOTOR1_BACKWARD, PWM_FREQUENCY);
    gpioSetPWMfrequency(MOTOR2_FORWARD, PWM_FREQUENCY);
    gpioSetPWMfrequency(MOTOR2_BACKWARD, PWM_FREQUENCY);

    // Set PWM range
    gpioSetPWMrange(MOTOR1_FORWARD, 1000000); // Range is microseconds
    gpioSetPWMrange(MOTOR1_BACKWARD, 1000000);
    gpioSetPWMrange(MOTOR2_FORWARD, 1000000);
    gpioSetPWMrange(MOTOR2_BACKWARD, 1000000);

    // Set angles for motors
    set_motor_angle(1, angle1);
    set_motor_angle(2, angle2);

    // Keep the program running until a signal is received
    while (!terminate) {
        gpioDelay(100); // Delay for 100ms
    }

    // Clean up and exit
    gpioTerminate();
    return 0;
}

// Function to set the motor angle
void set_motor_angle(int motor_number, int angle) {
    int gpio_forward, gpio_backward;
    float duty_cycle;

    // Select GPIO pins based on motor number
    if (motor_number == 1) {
        gpio_forward = MOTOR1_FORWARD;
        gpio_backward = MOTOR1_BACKWARD;
    } else if (motor_number == 2) {
        gpio_forward = MOTOR2_FORWARD;
        gpio_backward = MOTOR2_BACKWARD;
    } else {
        fprintf(stderr, "Error: Invalid motor number\n");
        return;
    }

    // Calculate PWM duty cycle using linear interpolation
    duty_cycle = MIN_DUTY_CYCLE + (float)angle / 180.0 * (MAX_DUTY_CYCLE - MIN_DUTY_CYCLE);

    // Control motor direction based on angle
    if (angle == 0) {
        // Stop the motor
        gpioWrite(gpio_forward, 0);
        gpioWrite(gpio_backward, 0);
        gpioPWM(gpio_forward, 0); // Stop PWM
        gpioPWM(gpio_backward, 0);
    } else if (angle > 0 && angle <= 90) {
        // Move forward
        gpioWrite(gpio_backward, 0);
        gpioWrite(gpio_forward, 1);
        gpioPWM(gpio_forward, duty_cycle);
    } else {
        // Move backward
        gpioWrite(gpio_forward, 0);
        gpioWrite(gpio_backward, 1);
        gpioPWM(gpio_backward, duty_cycle);
    }
}

// Signal handler function
void signal_handler(int signal) {
    printf("Signal received, stopping motors and exiting...\n");

    // Stop motors
    set_motor_angle(1, 0);
    set_motor_angle(2, 0);

    // Set GPIOs to low to fully stop the motor
    gpioWrite(MOTOR1_FORWARD, 0);
    gpioWrite(MOTOR1_BACKWARD, 0);
    gpioWrite(MOTOR2_FORWARD, 0);
    gpioWrite(MOTOR2_BACKWARD, 0);

    // Terminate pigpio library
    gpioTerminate();

    // Set terminate flag to exit the main loop
    terminate = 1;

    exit(0);
}

