#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <unistd.h>

// Define a structure to hold rotary encoder data
typedef struct {
    int gpioA;
    int gpioB;
    void (*callback)(int);
    int levelA;
    int levelB;
    int lastGpio;
} RotaryEncoder;

// Forward declaration of the interrupt handler
static void rotaryInterruptHandler(int gpio, int level, uint32_t tick, void *user);

// Global variable to store the current position
static volatile int currentPosition = 0;

// Callback function to handle rotary encoder changes
void updatePosition(int direction)
{
    currentPosition += direction;
    printf("Position: %d\n", currentPosition);
}

// Initialize the rotary encoder
RotaryEncoder *rotaryEncoderSetup(int gpioA, int gpioB, void (*callback)(int))
{
    RotaryEncoder *encoder = malloc(sizeof(RotaryEncoder));
    if (encoder == NULL) {
        perror("Failed to allocate memory for rotary encoder");
        return NULL;
    }

    encoder->gpioA = gpioA;
    encoder->gpioB = gpioB;
    encoder->callback = callback;
    encoder->levelA = 0;
    encoder->levelB = 0;
    encoder->lastGpio = -1;

    // Set GPIO modes and pull-ups
    if (gpioSetMode(gpioA, PI_INPUT) != 0) {
        fprintf(stderr, "Failed to set GPIO %d mode\n", gpioA);
        free(encoder);
        return NULL;
    }
    if (gpioSetMode(gpioB, PI_INPUT) != 0) {
        fprintf(stderr, "Failed to set GPIO %d mode\n", gpioB);
        free(encoder);
        return NULL;
    }

    if (gpioSetPullUpDown(gpioA, PI_PUD_UP) != 0) {
        fprintf(stderr, "Failed to set GPIO %d pull-up\n", gpioA);
        free(encoder);
        return NULL;
    }
    if (gpioSetPullUpDown(gpioB, PI_PUD_UP) != 0) {
        fprintf(stderr, "Failed to set GPIO %d pull-up\n", gpioB);
        free(encoder);
        return NULL;
    }

    // Set interrupt handlers
    if (gpioSetAlertFuncEx(gpioA, rotaryInterruptHandler, encoder) != 0) {
        fprintf(stderr, "Failed to set interrupt handler for GPIO %d\n", gpioA);
        free(encoder);
        return NULL;
    }
    if (gpioSetAlertFuncEx(gpioB, rotaryInterruptHandler, encoder) != 0) {
        fprintf(stderr, "Failed to set interrupt handler for GPIO %d\n", gpioB);
        free(encoder);
        return NULL;
    }

    return encoder;
}

// Interrupt handler for rotary encoder changes
static void rotaryInterruptHandler(int gpio, int level, uint32_t tick, void *user)
{
    RotaryEncoder *encoder = (RotaryEncoder *)user;

    if (gpio == encoder->gpioA) {
        encoder->levelA = level;
    } else {
        encoder->levelB = level;
    }

    if (gpio != encoder->lastGpio) {
        encoder->lastGpio = gpio;

        if ((gpio == encoder->gpioA) && (level == 1)) {
            if (encoder->levelB) {
                encoder->callback(1); // Clockwise
            }
        } else if ((gpio == encoder->gpioB) && (level == 1)) {
            if (encoder->levelA) {
                encoder->callback(-1); // Counter-clockwise
            }
        }
    }
}

// Clean up and release resources
void rotaryEncoderCleanup(RotaryEncoder *encoder)
{
    if (encoder) {
        gpioSetAlertFunc(encoder->gpioA, NULL);
        gpioSetAlertFunc(encoder->gpioB, NULL);
        free(encoder);
    }
}

int main()
{
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Setup the rotary encoder
    RotaryEncoder *encoder = rotaryEncoderSetup(7, 8, updatePosition);
    if (encoder == NULL) {
        gpioTerminate();
        return 1;
    }

    // Keep the program running for a while
    sleep(300);

    // Cleanup
    rotaryEncoderCleanup(encoder);
    gpioTerminate();

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>

// Constants
#define I2C_BUS 1
#define LM75B_ADDR 0x48
#define TEMP_REG 0x00
#define FAN_GPIO 18
#define PWM_FREQUENCY 100 // Hz
#define LOG_BUFFER_SIZE 100

// Temperature thresholds (Celsius)
#define TEMP_LOW 40.0
#define TEMP_MED 50.0
#define TEMP_HIGH 60.0

// PWM duty cycle values (0-255)
#define FAN_OFF 0
#define FAN_LOW 85
#define FAN_MED 170
#define FAN_HIGH 255

// Data structure for log entries
struct logEntry {
    float temperature;
    int fanSpeed;
    time_t timestamp;
};

// Circular buffer for logging
struct logEntry logBuffer[LOG_BUFFER_SIZE];
int logIndex = 0;

// Global variable for I2C handle
int i2cHandle = -1;

// Function prototypes
float readTemperature();
int getFanSpeed(float temperature);
void setFanSpeed(int dutyCycle);
void addLogEntry(float temperature, int fanSpeed);
void signalHandler(int signal);

// Function to read temperature from LM75B sensor
float readTemperature() {
    int retries = 0;
    while (retries < 3) {
        char buf[2];
        int bytesRead = i2cReadI2CBlockData(i2cHandle, TEMP_REG, buf, 2);
        if (bytesRead == 2) {
            // Convert raw data to temperature (MSB first)
            int16_t rawTemp = (buf[0] << 8) | buf[1];
            // Shift right by 5 bits to get the signed integer value
            rawTemp = rawTemp >> 5;
            // Convert to Celsius (0.125 degrees per LSB)
            float temperature = rawTemp * 0.125;
            return temperature;
        } else {
            fprintf(stderr, "%s I2C read failed (attempt %d): %d\n", __func__, retries + 1, bytesRead);
            retries++;
            gpioDelay(1000); // Wait 1ms before retrying
        }
    }
    fprintf(stderr, "%s I2C read failed after multiple retries.\n", __func__);
    return -273.15; // Return absolute zero on failure
}

// Function to determine fan speed based on temperature
int getFanSpeed(float temperature) {
    if (temperature < TEMP_LOW) {
        return FAN_OFF;
    } else if (temperature < TEMP_MED) {
        return FAN_LOW;
    } else if (temperature < TEMP_HIGH) {
        return FAN_MED;
    } else {
        return FAN_HIGH;
    }
}

// Function to set fan speed using PWM
void setFanSpeed(int dutyCycle) {
    gpioPWM(FAN_GPIO, dutyCycle);
}

// Function to add a log entry to the circular buffer
void addLogEntry(float temperature, int fanSpeed) {
    time_t now = time(NULL);
    logBuffer[logIndex].temperature = temperature;
    logBuffer[logIndex].fanSpeed = fanSpeed;
    logBuffer[logIndex].timestamp = now;
    logIndex = (logIndex + 1) % LOG_BUFFER_SIZE;
}

// Signal handler for graceful shutdown
void signalHandler(int signal) {
    fprintf(stderr, "\nCaught signal %d, exiting gracefully...\n", signal);
    setFanSpeed(FAN_OFF); // Stop the fan
    if (i2cHandle >= 0) {
        i2cClose(i2cHandle);
    }
    gpioTerminate();
    exit(0);
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Register signal handler for Ctrl+C and SIGTERM
    signal(SIGINT, signalHandler);
    signal(SIGTERM, signalHandler);

    // Initialize I2C communication
    i2cHandle = i2cOpen(I2C_BUS, LM75B_ADDR, 0);
    if (i2cHandle < 0) {
        fprintf(stderr, "I2C open failed: %d\n", i2cHandle);
        gpioTerminate();
        return 1;
    }

    // Configure GPIO18 as PWM output
    gpioSetMode(FAN_GPIO, PI_OUTPUT);
    gpioSetPWMfrequency(FAN_GPIO, PWM_FREQUENCY);
    gpioSetPWMrange(FAN_GPIO, 255); // Set PWM range to 0-255

    // Main loop
    while (1) {
        // Read temperature from sensor
        float temperature = readTemperature();

        // Get fan speed based on temperature
        int fanSpeed = getFanSpeed(temperature);

        // Set fan speed
        setFanSpeed(fanSpeed);

        // Add log entry
        addLogEntry(temperature, fanSpeed);

        // Print current status
        time_t now = time(NULL);
        struct tm *timeinfo = localtime(&now);
        char timestamp[20];
        strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);
        printf("%s - Temperature: %.2f°C, Fan Speed: %d\n", timestamp, temperature, fanSpeed);

        // Sleep for 1 second
        sleep(1);
    }

    return 0; // This line will never be reached due to the infinite loop, but it's good practice to include it.
}

