#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>
#include <linux/spi/spidev.h>
#include <sys/ioctl.h>
#include <stdint.h>
#define SPI_DEV "/dev/spidev0.0"
#define REF_VOLTAGE 3.3

int read_adc(int fd, int channel) {
    uint8_t tx[] = {0x01, (0x80 | (channel << 4)), 0x00};
    uint8_t rx[3] = {0};
    struct spi_ioc_transfer tr = {
        .tx_buf = (unsigned long)tx,
        .rx_buf = (unsigned long)rx,
        .len = 3,
        .speed_hz = 1000000,
        .bits_per_word = 8,
    };
    if (ioctl(fd, SPI_IOC_MESSAGE(1), &tr) < 0) return -1;
    return ((rx[1] & 0x03) << 8) | rx[2];
}

int main() {
    int fd = open(SPI_DEV, O_RDWR);
    if (fd < 0) {
        perror("SPI device open failed");
        return 1;
    }

    int value = read_adc(fd, 0);
    if (value >= 0) {
        double voltage = (value / 1023.0) * REF_VOLTAGE;
        printf("MCP3008 detected. Channel 0 Voltage: %.2f V\n", voltage);
    } else {
        printf("Failed to read from MCP3008.\n");
    }
    close(fd);
    return 0;
}

