    pinMode(BUTTON_PIN_1, INPUT);
    pinMode(BUTTON_PIN_2, INPUT);
    pinMode(BUTTON_PIN_3, INPUT);
    pinMode(BUTTON_PIN_4, INPUT);

    pullUpDnControl(BUTTON_PIN_1, PUD_UP); // Enable pull-up resistors
    pullUpDnControl(BUTTON_PIN_2, PUD_UP); // Enable pull-up resistors
    pullUpDnControl(BUTTON_PIN_3, PUD_UP); // Enable pull-up resistors
    pullUpDnControl(BUTTON_PIN_4, PUD_UP); // Enable pull-up resistors

    while (1)
    {
        if (digitalRead(BUTTON_PIN_1) == LOW)
        {
            softPwmWrite(SERVO_PIN_1, SERVO_POS_1);
