#define SERVO_PIN 18
#define INC_BUTTON 23
#define DEC_BUTTON 24

int main() {
    if (gpioInitialise() < 0) {
        printf("pigpio initialization failed!\n");
        return 1;
    }
    gpioSetMode(SERVO_PIN, PI_OUTPUT);
    gpioSetMode(INC_BUTTON, PI_INPUT);
    gpioSetMode(DEC_BUTTON, PI_INPUT);
    gpioSetPullUpDown(INC_BUTTON, PI_PUD_UP);
    gpioSetPullUpDown(DEC_BUTTON, PI_PUD_UP);

    int position = 1500; // Neutral position

    while (1) {
        if (gpioRead(INC_BUTTON) == 0 && position < 2000) {
            position += 10;
            gpioServo(SERVO_PIN, position);
            printf("Moving to %d\n", position);
            gpioDelay(200000); // Debounce delay
        }
        if (gpioRead(DEC_BUTTON) == 0 && position > 1000) {
            position -= 10;
            gpioServo(SERVO_PIN, position);
            printf("Moving to %d\n", position);
            gpioDelay(200000); // Debounce delay
        }
    }
    gpioTerminate();
    return 0;
