#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <math.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>

// LSM303D I2C address
#define LSM303D_ADDR 0x1D

// LSM303D registers
#define OUT_X_L_A 0x28
#define OUT_X_H_A 0x29
#define OUT_Y_L_A 0x2A
#define OUT_Y_H_A 0x2B
#define OUT_Z_L_A 0x2C
#define OUT_Z_H_A 0x2D
#define CTRL1 0x20

// GPIO pin for LED
#define LED_PIN 17

// Acceleration threshold (2g in m/s^2)
#define ACCEL_THRESHOLD (2.0 * 9.81)

// Circular buffer size
#define BUFFER_SIZE 64

// Structure to hold acceleration data
typedef struct {
    int16_t x;
    int16_t y;
    int16_t z;
} accelData_t;

// Circular buffer
accelData_t accelBuffer[BUFFER_SIZE];
int bufferIndex = 0;

// I2C file descriptor
int fd;

// Function to initialize the LSM303D accelerometer
int initLSM303D() {
    // Enable accelerometer (100Hz, normal mode)
    if (wiringPiI2CWriteReg8(fd, CTRL1, 0x67) < 0) {
        fprintf(stderr, "Error writing to CTRL1 register\n");
        return -1;
    }
    return 0;
}

// Function to read acceleration data from the LSM303D
int readAccelData(accelData_t *data) {
    int16_t x, y, z;
    uint8_t xL, xH, yL, yH, zL, zH;

    xL = wiringPiI2CReadReg8(fd, OUT_X_L_A);
    xH = wiringPiI2CReadReg8(fd, OUT_X_H_A);
    yL = wiringPiI2CReadReg8(fd, OUT_Y_L_A);
    yH = wiringPiI2CReadReg8(fd, OUT_Y_H_A);
    zL = wiringPiI2CReadReg8(fd, OUT_Z_L_A);
    zH = wiringPiI2CReadReg8(fd, OUT_Z_H_A);

    if (xL == -1 || xH == -1 || yL == -1 || yH == -1 || zL == -1 || zH == -1) {
        fprintf(stderr, "Error reading acceleration data\n");
        return -1;
    }

    x = (int16_t)((xH << 8) | xL);
    y = (int16_t)((yH << 8) | yL);
    z = (int16_t)((zH << 8) | zL);

    data->x = x;
    data->y = y;
    data->z = z;

    return 0;
}

// Function to calculate the magnitude of acceleration
float calculateAccelerationMagnitude(accelData_t data) {
    float x = (float)data.x;
    float y = (float)data.y;
    float z = (float)data.z;

    // Scale raw values.  The scaling factor depends on the full-scale
    // range configured in the accelerometer. Here we assume +/- 2g range
    // which is common and implies a scaling factor of ~0.061 mg/LSB
    // For simplicity, we assume 1 unit = 1 mg = 0.00981 m/s^2
    float x_scaled = x * 0.00981;
    float y_scaled = y * 0.00981;
    float z_scaled = z * 0.00981;

    return sqrt(x_scaled * x_scaled + y_scaled * y_scaled + z_scaled * z_scaled);
}

// Function to update the circular buffer
void updateCircularBuffer(accelData_t data) {
    accelBuffer[bufferIndex] = data;
    bufferIndex = (bufferIndex + 1) % BUFFER_SIZE;
}

// Function to control the LED
void controlLED(int state) {
    digitalWrite(LED_PIN, state);
}

int main() {
    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi\n");
        return 1;
    }

    // Initialize I2C
    fd = wiringPiI2CSetup(LSM303D_ADDR);
    if (fd == -1) {
        fprintf(stderr, "Error initializing I2C communication\n");
        return 1;
    }

    // Initialize LSM303D
    if (initLSM303D() == -1) {
        fprintf(stderr, "Error initializing LSM303D accelerometer\n");
        return 1;
    }

    // Set LED pin as output
    pinMode(LED_PIN, OUTPUT);

    accelData_t accelData;
    float magnitude;

    while (1) {
        // Read acceleration data
        if (readAccelData(&accelData) == -1) {
            fprintf(stderr, "Error reading acceleration data. Retrying...\n");
            delay(100);
            continue;
        }

        // Calculate acceleration magnitude
        magnitude = calculateAccelerationMagnitude(accelData);

        // Update circular buffer
        updateCircularBuffer(accelData);

        // Check if acceleration exceeds threshold
        if (magnitude > ACCEL_THRESHOLD) {
            printf("Acceleration threshold exceeded! Magnitude: %.2f m/s^2\n", magnitude);
            controlLED(HIGH); // Turn LED on
            delay(500);       // Wait 500ms
            controlLED(LOW);  // Turn LED off
        }

        delay(50); // Sample at 20Hz
    }

    return 0;
}

#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>

// Define GPIO pins
#define TRIGGER_PIN 23
#define ECHO_PIN 24
#define SERVO_PIN 18

// Define constants
#define SPEED_OF_SOUND 34300.0  // cm/s
#define MIN_DISTANCE 20.0      // cm
#define MAX_DISTANCE 200.0     // cm
#define MIN_ANGLE 0            // degrees
#define MAX_ANGLE 180          // degrees

// Function to get distance from HC-SR04 sensor
float get_distance() {
    gpioTrigger(TRIGGER_PIN, 10, 1);
    int start_tick = gpioTick();
    int pulse_width = 0;

    while (gpioRead(ECHO_PIN) == 0 && (gpioTick() - start_tick) < 50000) {}
    start_tick = gpioTick();

    while (gpioRead(ECHO_PIN) == 1 && (gpioTick() - start_tick) < 50000) {}
    pulse_width = gpioTick() - start_tick;

    if (pulse_width >= 50000 || pulse_width <= 0) {
        fprintf(stderr, "Error: Invalid pulse width: %d\n", pulse_width);
        return -1.0;
    }

    float time_in_seconds = (float)pulse_width / 1000000.0;
    float distance = time_in_seconds * SPEED_OF_SOUND / 2.0;

    return distance;
}

// Function to set servo angle
int set_servo_angle(int angle) {
    if (angle < MIN_ANGLE || angle > MAX_ANGLE) {
        fprintf(stderr, "Error: Angle out of range: %d\n", angle);
        return -1;
    }

    int pulse_width = 500 + (angle * 2000 / 180); // Map angle to pulse width (SG90 specific)
    gpioServo(SERVO_PIN, pulse_width);
    return 0;
}

// Function to map distance to servo angle
int map_distance_to_angle(float distance) {
    if (distance < MIN_DISTANCE) {
        return MIN_ANGLE;
    } else if (distance > MAX_DISTANCE) {
        return MAX_ANGLE;
    } else {
        return (int)((distance - MIN_DISTANCE) / (MAX_DISTANCE - MIN_DISTANCE) * (MAX_ANGLE - MIN_ANGLE));
    }
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);
    gpioSetMode(SERVO_PIN, PI_OUTPUT);

    // Main loop
    while (1) {
        float distance = get_distance();

        if (distance > 0) {
            int angle = map_distance_to_angle(distance);
            if (set_servo_angle(angle) != 0) {
                fprintf(stderr, "Error: Failed to set servo angle\n");
            }
        } else {
            fprintf(stderr, "Error: Failed to read distance\n");
        }

        gpioDelay(100); // Delay for 100 milliseconds
    }

    // Terminate pigpio library
    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <time.h>
#include <sys/time.h>
#include <fcntl.h>
#include <errno.h>
#include <string.h>

#include "pigpio.h"

// Define the size of the gpioReport_t structure
#define REPORT_SIZE (sizeof(gpioReport_t))

// Define states for SCL and SDA lines
#define SCL_FALLING 0
#define SCL_RISING  1
#define SCL_STEADY  2

#define SDA_FALLING 0
#define SDA_RISING  4
#define SDA_STEADY  8

// Function to get a timestamp for logging
static char *get_timestamp()
{
    static char timestamp_str[32];
    struct timeval current_time;
    struct tm *time_info;

    gettimeofday(&current_time, NULL);
    time_info = localtime(&current_time.tv_sec);

    strftime(timestamp_str, sizeof(timestamp_str), "%Y-%m-%d %H:%M:%S", time_info);
    return timestamp_str;
}

// Function to parse I2C data based on SCL and SDA transitions
void parse_i2c_data(int scl_level, int sda_level)
{
    static int in_data = 0;      // Flag to indicate if we are currently receiving data
    static int current_byte = 0;  // The current byte being assembled
    static int bit_count = 0;     // The number of bits received for the current byte
    static int old_scl_level = 1; // Previous SCL level (initially high)
    static int old_sda_level = 1; // Previous SDA level (initially high)

    int scl_transition, sda_transition;

    // Determine SCL transition
    if (scl_level != old_scl_level)
    {
        old_scl_level = scl_level;
        scl_transition = (scl_level) ? SCL_RISING : SCL_FALLING;
    } else {
        scl_transition = SCL_STEADY;
    }

    // Determine SDA transition
    if (sda_level != old_sda_level)
    {
        old_sda_level = sda_level;
        sda_transition = (sda_level) ? SDA_RISING : SDA_FALLING;
    } else {
        sda_transition = SDA_STEADY;
    }

    // Process I2C state changes
    switch (scl_transition + sda_transition)
    {
        case SCL_RISING + SDA_RISING:
        case SCL_RISING + SDA_FALLING:
        case SCL_RISING + SDA_STEADY:
            // SCL rising edge
            if (in_data)
            {
                if (bit_count++ < 8)
                {
                    current_byte <<= 1;
                    current_byte |= sda_level; // Sample SDA on SCL rising edge
                }
                else
                {
                    // Byte complete
                    printf("%02X", current_byte);
                    printf((sda_level) ? "-" : "+"); // Indicate ACK/NACK
                    bit_count = 0;
                    current_byte = 0;
                }
            }
            break;

        case SCL_FALLING + SDA_RISING:
        case SCL_FALLING + SDA_FALLING:
        case SCL_FALLING + SDA_STEADY:
            // SCL falling edge (do nothing)
            break;

        case SCL_STEADY + SDA_RISING:
            // SDA rising edge
            if (scl_level)
            {
                // Stop condition
                in_data = 0;
                current_byte = 0;
                bit_count = 0;
                printf("]\n"); // Stop
                fflush(stdout);
            }
            break;

        case SCL_STEADY + SDA_FALLING:
            // SDA falling edge
            if (scl_level)
            {
                // Start condition
                in_data = 1;
                current_byte = 0;
                bit_count = 0;
                printf("[ %s: ", get_timestamp()); // Start
            }
            break;

        case SCL_STEADY + SDA_STEADY:
            // No change (do nothing)
            break;
    }
}

int main(int argc, char *argv[])
{
    int scl_gpio, sda_gpio;
    int scl_level, sda_level;
    int read_result;
    uint32_t level_mask, scl_mask, sda_mask;
    gpioReport_t report;
    uint32_t previous_level = 0; // Store the previous level to detect changes

    // Check command line arguments
    if (argc != 3)
    {
        fprintf(stderr, "Usage: %s <SCL_GPIO> <SDA_GPIO>\n", argv[0]);
        return EXIT_FAILURE;
    }

    // Parse GPIO numbers from arguments
    scl_gpio = atoi(argv[1]);
    sda_gpio = atoi(argv[2]);

    // Create bit masks for SCL and SDA
    scl_mask = (1 << scl_gpio);
    sda_mask = (1 << sda_gpio);
    level_mask = scl_mask | sda_mask;

    // Initialize SCL and SDA levels to high (default state)
    scl_level = 1;
    sda_level = 1;

    // Main loop to read pigpio reports from stdin
    while ((read_result = read(STDIN_FILENO, &report, REPORT_SIZE)) == REPORT_SIZE)
    {
        // Mask out irrelevant bits from the report level
        report.level &= level_mask;

        // Check if the level has changed since the last report
        if (report.level != previous_level)
        {
            // Update SCL and SDA levels based on the report
            scl_level = (report.level & scl_mask) ? 1 : 0;
            sda_level = (report.level & sda_mask) ? 1 : 0;

            // Parse the I2C data based on the current SCL and SDA levels
            parse_i2c_data(scl_level, sda_level);

            // Update the previous level
            previous_level = report.level;
        }
    }

    // Handle read errors
    if (read_result < 0)
    {
        perror("Error reading from stdin");
        return EXIT_FAILURE;
    }

    // Handle partial read (should not normally happen)
    if (read_result > 0)
    {
        fprintf(stderr, "Partial read from stdin (%d bytes)\n", read_result);
        return EXIT_FAILURE;
    }

    return EXIT_SUCCESS;
}

