#define MOTION_SENSOR_PIN 4
#define RELAY_PIN 17
#define TIMEOUT_SECONDS 60
#define LOG_FILE_NAME "lighting_log.txt"

// Global variables (minimize usage)
static volatile int running = 1;
static FILE *log_file = NULL;
static pthread_t timer_thread;

// Mutex for thread safety
static pthread_mutex_t log_mutex = PTHREAD_MUTEX_INITIALIZER;

// Function prototypes
void *timer_function(void *arg);
void log_event(const char *event_type);
void signal_handler(int signal);

// Structure to pass arguments to the timer thread
typedef struct {
    int relay_pin;
} timer_args_t;

// Timer function to turn off the relay after a timeout
void *timer_function(void *arg) {
    timer_args_t *args = (timer_args_t *)arg;
    sleep(TIMEOUT_SECONDS);

    if (running) {
        gpioWrite(args->relay_pin, 0); // Turn off relay
        log_event("Timeout: Relay OFF");
    }

    pthread_exit(NULL);
}

// Function to log events with timestamps
void log_event(const char *event_type) {
    pthread_mutex_lock(&log_mutex);
    if (log_file != NULL) {
        time_t rawtime;
        struct tm *timeinfo;
        char timestamp[30];
        struct timespec now;

        clock_gettime(CLOCK_REALTIME, &now);
        rawtime = now.tv_sec;
        timeinfo = localtime(&rawtime);

        strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);
        fprintf(log_file, "%s.%03ld: %s\n", timestamp, now.tv_nsec / 1000000, event_type);
        fflush(log_file);
    }
    pthread_mutex_unlock(&log_mutex);
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    running = 0;
    printf("Caught signal %d, exiting gracefully.\n", signal);

    // Turn off the relay
    gpioWrite(RELAY_PIN, 0);

    // Cancel the timer thread if it's running
    pthread_cancel(timer_thread);

    // Close the log file
    if (log_file != NULL) {
        fclose(log_file);
    }

    // Terminate pigpio
    gpioTerminate();

    exit(0);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(MOTION_SENSOR_PIN, PI_INPUT);
    gpioSetMode(RELAY_PIN, PI_OUTPUT);

    // Initialize log file
    log_file = fopen(LOG_FILE_NAME, "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        gpioTerminate();
        return 1;
    }

    // Register signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    log_event("System started");

    // Main loop
    while (running) {
        if (gpioRead(MOTION_SENSOR_PIN) == 1) {
            // Motion detected
            gpioWrite(RELAY_PIN, 1); // Turn on relay
            log_event("Motion detected: Relay ON");

            // Create and start the timer thread
            timer_args_t timer_args;
            timer_args.relay_pin = RELAY_PIN;

            if (pthread_create(&timer_thread, NULL, timer_function, &timer_args) != 0) {
                fprintf(stderr, "Error creating timer thread!\n");
                signal_handler(SIGTERM); // Simulate termination
            }

            // Detach the timer thread so it cleans up after itself
            pthread_detach(timer_thread);

            // Wait for motion to stop (debounce)
            while (gpioRead(MOTION_SENSOR_PIN) == 1 && running) {
                gpioDelay(100000); // 100ms delay
            }
        }
        gpioDelay(100000); // 100ms delay
    }

    // Cleanup (should not reach here under normal circumstances due to signal handler)
    gpioWrite(RELAY_PIN, 0);
    fclose(log_file);
    gpioTerminate();

    return 0;
}

#include <wiringPi.h>
#include <stdio.h>
#define DELAY_TIME 500

int y[8] = {17, 18, 27, 22, 23, 24, 25, 4}; // BCM Y-direction pins
int x[8] = {5, 6, 13, 19, 26, 16, 20, 21}; // BCM X-direction pins

void setup() {
    wiringPiSetupGpio();
    for (int i = 0; i < 8; i++) {
        pinMode(y[i], OUTPUT);
        pinMode(x[i], OUTPUT);
    }
}

void clearMatrix() {
    for (int i = 0; i < 8; i++) {
        digitalWrite(y[i], LOW);
        digitalWrite(x[i], HIGH);
    }
}

void displayPlus() {
    clearMatrix();
    for (int i = 0; i < 8; i++) {
        digitalWrite(y[3], HIGH);
        digitalWrite(y[4], HIGH);
        digitalWrite(x[i], LOW);
    }
    for (int i = 0; i < 8; i++) {
        digitalWrite(x[3], LOW);
        digitalWrite(x[4], LOW);
        digitalWrite(y[i], HIGH);
    }
    delay(DELAY_TIME);
    clearMatrix();
    delay(DELAY_TIME);
}

int main() {
    setup();
    while (1) {
        displayPlus();
    }
    return 0;
}

#include <stdio.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>

#define PCF8591_ADDR 0x48
#define MOTOR_PIN 1  // WiringPi pin number for the motor control (e.g., GPIO18)

int main(void) {
    int pcf8591_fd, analog_value;
    float voltage, duty_cycle;

    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed!\n");
        return 1;
    }

    pcf8591_fd = wiringPiI2CSetup(PCF8591_ADDR);
    if (pcf8591_fd == -1) {
        fprintf(stderr, "PCF8591 setup failed!\n");
        return 1;
    }

    pinMode(MOTOR_PIN, PWM_OUTPUT);

    while (1) {
        // Read analog value from PCF8591 channel 0
        wiringPiI2CReadReg8(pcf8591_fd, 0x40); //Dummy read, see datasheet
        analog_value = wiringPiI2CReadReg8(pcf8591_fd, 0x40);  //Channel 0

        // Convert analog value to voltage (assuming 0-3.3V range)
        voltage = (float)analog_value / 255.0 * 3.3;

        // Map voltage to PWM duty cycle (0-100%)
        duty_cycle = voltage / 3.3 * 100.0;

        // Set PWM duty cycle (wiringPi PWM range is 0-1024)
        pwmWrite(MOTOR_PIN, (int)(duty_cycle * 10.24));

        printf("Analog Value: %d, Voltage: %.2f V, Duty Cycle: %.2f %%\n", analog_value, voltage, duty_cycle);

        delay(100); // Adjust delay as needed
    }

    return 0;
}

#include <stdio.h>
#include <wiringPi.h>
#include <signal.h>
#include <stdlib.h>

#define RELAY_PIN 1 // WiringPi pin 1 corresponds to BCM GPIO 18
#define BUTTON_PIN 4  // WiringPi pin 4 corresponds to BCM GPIO 23

volatile int relay_state = 0; // 0: OFF, 1: ON
volatile int button_pressed = 0;

void button_isr(void) {
  button_pressed = 1; // Flag that the button has been pressed
}

void cleanup(int signal) {
  printf("Cleaning up and exiting.\n");
  digitalWrite(RELAY_PIN, LOW); // Turn off relay on exit
  exit(0);
}

int main(void) {
  if (wiringPiSetup() == -1) {
    fprintf(stderr, "WiringPi setup failed!\n");
    return 1;
  }

  pinMode(RELAY_PIN, OUTPUT);
  pinMode(BUTTON_PIN, INPUT);
  pullUpDnControl(BUTTON_PIN, PUD_UP); // Enable internal pull-up resistor

  wiringPiISR(BUTTON_PIN, INT_EDGE_FALLING, &button_isr); // Interrupt on falling edge

  signal(SIGINT, cleanup); // Handle Ctrl+C

  printf("Relay control using button. Press Ctrl+C to exit.\n");

  while (1) {
    if (button_pressed) {
      button_pressed = 0; // Reset the flag
      delay(50); // Debounce delay
      if (digitalRead(BUTTON_PIN) == LOW) {
          relay_state = !relay_state;  // Toggle relay state
          digitalWrite(RELAY_PIN, relay_state ? HIGH : LOW);
          printf("Relay is now %s\n", relay_state ? "ON" : "OFF");
      }
    }
    delay(10); // Small delay to prevent busy-waiting
  }

  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <signal.h>
#include <pigpio.h>

#define GPIO_MOTOR_1 17
#define GPIO_MOTOR_2 27
#define SINE_TABLE_SIZE 256

// Global variables for graceful shutdown
volatile sig_atomic_t program_running = 1;
float *sine_table = NULL;

// Signal handler for Ctrl+C
void signal_handler(int signum) {
    if (signum == SIGINT) {
        program_running = 0;
        fprintf(stderr, "\nCtrl+C pressed. Exiting gracefully.\n");
    }
}

// Initializes the pigpio library
int initialize_pigpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }
    return 0;
}

// Sets the PWM frequency of the specified GPIO pin
void set_pwm_frequency(int gpio, float frequency) {
    gpioSetPWMfrequency(gpio, (int)frequency);
}

// Sets the GPIO pin mode
void set_gpio_mode(int gpio, int mode) {
    gpioSetMode(gpio, mode);
}

// Generates the sine wave lookup table
float* generate_sine_table(int size) {
    float *table = (float*)malloc(sizeof(float) * size);
    if (table == NULL) {
        fprintf(stderr, "Memory allocation failed for sine table\n");
        return NULL;
    }
    for (int i = 0; i < size; i++) {
        table[i] = sinf(2.0 * M_PI * i / size);
    }
    return table;
}

// Controls the motors based on the sine wave table
void control_motors(float sine_table[], int index, float base_frequency, float frequency_range) {
    float motor1_frequency = base_frequency + (sine_table[index] * frequency_range);
    float motor2_frequency = base_frequency - (sine_table[index] * frequency_range);

    set_pwm_frequency(GPIO_MOTOR_1, motor1_frequency);
    set_pwm_frequency(GPIO_MOTOR_2, motor2_frequency);
}

// Cleans up resources and terminates the pigpio library
void cleanup(float *sine_table) {
    gpioTerminate();
    if (sine_table != NULL) {
        free(sine_table);
    }
}

int main() {
    // Set up signal handling for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize pigpio
    if (initialize_pigpio() != 0) {
        return 1;
    }

    // Set GPIO modes
    set_gpio_mode(GPIO_MOTOR_1, PI_OUTPUT);
    set_gpio_mode(GPIO_MOTOR_2, PI_OUTPUT);

    // Define motor control parameters
    float base_frequency = 100.0f;
    float frequency_range = 50.0f;
    int index = 0;

    // Generate the sine wave table
    sine_table = generate_sine_table(SINE_TABLE_SIZE);
    if (sine_table == NULL) {
        gpioTerminate();
        return 1;
    }

    // Main loop
    while (program_running) {
        // Control the motors
        control_motors(sine_table, index, base_frequency, frequency_range);

        // Increment the index and wrap around
        index = (index + 1) % SINE_TABLE_SIZE;

        // Delay for a short period
        gpioDelay(10000); // 10 milliseconds
    }

    // Clean up resources before exiting
    cleanup(sine_table);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <time.h>
#include <string.h>

// Define the GPIO pins for the sound sensor and relay module (using wiringPi numbering)
#define SOUND_SENSOR_PIN 17
#define RELAY_PIN 18

// Define the sound threshold (adjust this value based on your environment)
#define SOUND_THRESHOLD 0 // KY-038 outputs 0 when sound is detected

// Function to read the sound sensor
int readSoundSensor(int pin) {
    int value = digitalRead(pin);
    // Basic error handling: return -1 if the read fails (though digitalRead rarely fails).
    if (value != 0 && value != 1) {
        fprintf(stderr, "Error: Invalid sensor reading\n");
        return -1; // Indicate an error
    }
    return value;
}

// Function to activate the relay (turn on the siren)
void activateRelay(int pin) {
    digitalWrite(pin, HIGH); // Activate the relay
    printf("Relay activated (Siren ON)\n");
}

// Function to deactivate the relay (turn off the siren)
void deactivateRelay(int pin) {
    digitalWrite(pin, LOW);  // Deactivate the relay
    printf("Relay deactivated (Siren OFF)\n");
}

// Function to log an event to the alarm_log.txt file
void logEvent(const char* filename) {
    FILE* fp = fopen(filename, "a"); // Open the file in append mode
    if (fp == NULL) {
        fprintf(stderr, "Error: Could not open log file %s\n", filename);
        perror("fopen");
        return; // Exit if file opening failed
    }

    time_t t = time(NULL);
    struct tm* tm = localtime(&t);
    char s[64];
    strftime(s, sizeof(s), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(fp, "%s - Sound detected! Alarm triggered.\n", s);
    fclose(fp);
    printf("Event logged to %s\n", filename);
}

int main() {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error: Failed to initialize wiringPi\n");
        return 1; // Exit if wiringPi initialization failed
    }

    // Set the pin modes
    pinMode(SOUND_SENSOR_PIN, INPUT);
    pinMode(RELAY_PIN, OUTPUT);

    printf("Sound sensor monitoring started...\n");

    // Main loop
    while (1) {
        int soundLevel = readSoundSensor(SOUND_SENSOR_PIN);

        if (soundLevel == 0) { // Sound detected (KY-038 outputs LOW when sound is detected)
            printf("Sound detected!\n");
            activateRelay(RELAY_PIN);
            logEvent("alarm_log.txt");
            delay(5000); // Keep the siren on for 5 seconds
            deactivateRelay(RELAY_PIN);
        } else if (soundLevel == -1) {
            fprintf(stderr, "Error reading sound sensor. Skipping this cycle.\n");
        }

        delay(100); // Small delay to prevent busy-waiting
    }

    // The program will run indefinitely until manually stopped.
    // Add a cleanup section if needed (e.g., deactivating the relay).

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <unistd.h>

// Define GPIO pins
#define TRIGGER_PIN 4
#define ECHO_PIN 18
#define LED_PIN 17

// Define distance threshold (in cm)
#define DISTANCE_THRESHOLD 20.0

// Function prototypes
int gpio_export(int pin);
int gpio_unexport(int pin);
int gpio_set_direction(int pin, char *direction);
int gpio_set_value(int pin, int value);
int gpio_get_value(int pin);
void trigger_pulse();
float get_distance();
void log_data(float distance);
void control_led(float distance);
void cleanup();

FILE *log_file;

// Helper function to write to sysfs file
int write_to_file(const char *path, const char *value) {
    FILE *fp = fopen(path, "w");
    if (fp == NULL) {
        perror("Error opening file");
        return -1;
    }
    fprintf(fp, "%s", value);
    fclose(fp);
    return 0;
}

// Helper function to read from sysfs file
int read_from_file(const char *path, char *value, int max_len) {
    FILE *fp = fopen(path, "r");
    if (fp == NULL) {
        perror("Error opening file");
        return -1;
    }
    if (fgets(value, max_len, fp) == NULL) {
        fclose(fp);
        return -1;
    }
    fclose(fp);
    return 0;
}

// Exports the given GPIO pin
int gpio_export(int pin) {
    char pin_str[3];
    sprintf(pin_str, "%d", pin);
    return write_to_file("/sys/class/gpio/export", pin_str);
}

// Unexports the given GPIO pin
int gpio_unexport(int pin) {
    char pin_str[3];
    sprintf(pin_str, "%d", pin);
    return write_to_file("/sys/class/gpio/unexport", pin_str);
}

// Sets the direction (input or output) of the given GPIO pin
int gpio_set_direction(int pin, char *direction) {
    char path[50];
    sprintf(path, "/sys/class/gpio/gpio%d/direction", pin);
    return write_to_file(path, direction);
}

// Sets the value (0 or 1) of the given GPIO pin
int gpio_set_value(int pin, int value) {
    char path[50];
    sprintf(path, "/sys/class/gpio/gpio%d/value", pin);
    char value_str[2];
    sprintf(value_str, "%d", value);
    return write_to_file(path, value_str);
}

// Reads the value of the given GPIO pin
int gpio_get_value(int pin) {
    char path[50];
    sprintf(path, "/sys/class/gpio/gpio%d/value", pin);
    char value_str[2];
    if (read_from_file(path, value_str, 2) != 0) {
        return -1; // Error reading value
    }
    return atoi(value_str);
}

// Sends a 10us trigger pulse to the HC-SR04 trigger pin
void trigger_pulse() {
    gpio_set_value(TRIGGER_PIN, 1);
    usleep(10); // 10 microseconds
    gpio_set_value(TRIGGER_PIN, 0);
}

// Measures the time taken for the ultrasonic pulse to return and calculates the distance in centimeters
float get_distance() {
    struct timespec start, end;
    long long start_ns, end_ns, elapsed_ns;

    // Trigger the sensor
    trigger_pulse();

    // Wait for the echo pin to go high (start of pulse)
    clock_gettime(CLOCK_MONOTONIC, &start);
    start_ns = start.tv_sec * 1000000000LL + start.tv_nsec;
    while (gpio_get_value(ECHO_PIN) == 0) {
        clock_gettime(CLOCK_MONOTONIC, &end);
        end_ns = end.tv_sec * 1000000000LL + end.tv_nsec;
        elapsed_ns = end_ns - start_ns;
        if (elapsed_ns > 1000000000LL) { // 1 second timeout
            fprintf(log_file, "Error: Timeout waiting for ECHO high.\n");
            fflush(log_file);
            return -1.0;
        }
    }

    // Measure the time the echo pin is high (pulse width)
    clock_gettime(CLOCK_MONOTONIC, &start);
    start_ns = start.tv_sec * 1000000000LL + start.tv_nsec;
    while (gpio_get_value(ECHO_PIN) == 1) {
        clock_gettime(CLOCK_MONOTONIC, &end);
        end_ns = end.tv_sec * 1000000000LL + end.tv_nsec;
        elapsed_ns = end_ns - start_ns;
        if (elapsed_ns > 1000000000LL) { // 1 second timeout
            fprintf(log_file, "Error: Timeout waiting for ECHO low.\n");
            fflush(log_file);
            return -1.0;
        }
    }
    clock_gettime(CLOCK_MONOTONIC, &end);
    end_ns = end.tv_sec * 1000000000LL + end.tv_nsec;
    elapsed_ns = end_ns - start_ns;

    // Calculate the distance (speed of sound in air is approximately 343 m/s)
    // Distance = (Time * Speed of Sound) / 2
    // Distance in cm = (Time in seconds * 34300 cm/s) / 2
    float time_sec = (float)elapsed_ns / 1000000000.0;
    float distance = (time_sec * 34300.0) / 2.0;

    return distance;
}

// Logs the distance reading and timestamp to "parking_log.txt"
void log_data(float distance) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    if (distance >= 0) {
        fprintf(log_file, "%s, Distance: %.2f cm\n", timestamp, distance);
    } else {
        fprintf(log_file, "%s, Error: Failed to read distance.\n", timestamp);
    }
    fflush(log_file);
}

// Controls the red LED on GPIO17 based on the distance
void control_led(float distance) {
    if (distance >= 0 && distance < DISTANCE_THRESHOLD) {
        gpio_set_value(LED_PIN, 1); // Turn on LED
    } else {
        gpio_set_value(LED_PIN, 0); // Turn off LED
    }
}

// Cleanup function to unexport the GPIO pins
void cleanup() {
    gpio_unexport(TRIGGER_PIN);
    gpio_unexport(ECHO_PIN);
    gpio_unexport(LED_PIN);
    if (log_file != NULL) {
        fclose(log_file);
    }
}

int main() {
    // Open the log file
    log_file = fopen("parking_log.txt", "a");
    if (log_file == NULL) {
        perror("Error opening parking_log.txt");
        return 1;
    }

    // Export GPIO pins
    if (gpio_export(TRIGGER_PIN) || gpio_export(ECHO_PIN) || gpio_export(LED_PIN)) {
        fprintf(log_file, "Error: Failed to export GPIO pin.\n");
        fflush(log_file);
        cleanup();
        return 1;
    }

    // Set GPIO directions
    if (gpio_set_direction(TRIGGER_PIN, "out") || gpio_set_direction(ECHO_PIN, "in") || gpio_set_direction(LED_PIN, "out")) {
        fprintf(log_file, "Error: Failed to set GPIO direction.\n");
        fflush(log_file);
        cleanup();
        return 1;
    }

    // Initialize trigger pin to low
    gpio_set_value(TRIGGER_PIN, 0);
    gpio_set_value(LED_PIN, 0);

    // Main loop
    while (1) {
        float distance = get_distance();
        log_data(distance);
        control_led(distance);
        usleep(100000); // 100ms
    }

    // Cleanup (this will never be reached in the infinite loop)
    cleanup();

    return 0;
}

