#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <errno.h>

// Define GPIO pins connected to ULN2003 driver (BCM numbering)
#define IN1_PIN 22
#define IN2_PIN 27
#define IN3_PIN 17
#define IN4_PIN 4

// Define motor control constants
#define STEPS_PER_REVOLUTION 512  // Number of steps for one full rotation
#define DELAY_MS 3                // Delay between steps (adjust for speed)
#define ROTATION_DELAY_MS 3000      // Delay between rotations

// Function to set the motor step sequence
void set_step(int step) {
    switch (step) {
        case 0:
            digitalWrite(IN1_PIN, LOW);
            digitalWrite(IN2_PIN, LOW);
            digitalWrite(IN3_PIN, LOW);
            digitalWrite(IN4_PIN, HIGH);
            break;
        case 1:
            digitalWrite(IN1_PIN, LOW);
            digitalWrite(IN2_PIN, LOW);
            digitalWrite(IN3_PIN, HIGH);
            digitalWrite(IN4_PIN, LOW);
            break;
        case 2:
            digitalWrite(IN1_PIN, LOW);
            digitalWrite(IN2_PIN, HIGH);
            digitalWrite(IN3_PIN, LOW);
            digitalWrite(IN4_PIN, LOW);
            break;
        case 3:
            digitalWrite(IN1_PIN, HIGH);
            digitalWrite(IN2_PIN, LOW);
            digitalWrite(IN3_PIN, LOW);
            digitalWrite(IN4_PIN, LOW);
            break;
        default:
            fprintf(stderr, "Error: Invalid step value: %d\n", step);
            break;
    }
}

// Function to rotate the motor clockwise
void rotate_clockwise(int steps) {
    for (int i = 0; i < steps; i++) {
        set_step(i % 4);
        delay(DELAY_MS);
    }
}

// Function to rotate the motor counter-clockwise
void rotate_counter_clockwise(int steps) {
    for (int i = 0; i < steps; i++) {
        set_step(3 - (i % 4));
        delay(DELAY_MS);
    }
}

int main() {
    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
        return 1;
    }

    // Set pin modes
    pinMode(IN1_PIN, OUTPUT);
    pinMode(IN2_PIN, OUTPUT);
    pinMode(IN3_PIN, OUTPUT);
    pinMode(IN4_PIN, OUTPUT);

    // Main loop
    while (1) {
        // Rotate counter-clockwise
        printf("Rotating counter-clockwise...\n");
        rotate_counter_clockwise(STEPS_PER_REVOLUTION);

        // Stop for a while
        digitalWrite(IN1_PIN, LOW);
        digitalWrite(IN2_PIN, LOW);
        digitalWrite(IN3_PIN, LOW);
        digitalWrite(IN4_PIN, LOW);
        delay(ROTATION_DELAY_MS);

        // Rotate clockwise
        printf("Rotating clockwise...\n");
        rotate_clockwise(STEPS_PER_REVOLUTION);

        // Stop for a while
        digitalWrite(IN1_PIN, LOW);
        digitalWrite(IN2_PIN, LOW);
        digitalWrite(IN3_PIN, LOW);
        digitalWrite(IN4_PIN, LOW);
        delay(ROTATION_DELAY_MS);
    }

    return 0;
}

#include <stdio.h>
#include <pigpio.h>

#define IN1 22  // GPIO 22 (BCM)
#define IN2 27  // GPIO 27 (BCM)
#define IN3 17  // GPIO 17 (BCM)
#define IN4 4   // GPIO 4  (BCM)

// Full-Step Sequence
int fullStep[4][4] = {
    {1, 0, 0, 0},  // Step 1
    {0, 1, 0, 0},  // Step 2
    {0, 0, 1, 0},  // Step 3
    {0, 0, 0, 1}   // Step 4
};

// Function to set motor step
void setStep(int step) {
    gpioWrite(IN1, fullStep[step][0]);
    gpioWrite(IN2, fullStep[step][1]);
    gpioWrite(IN3, fullStep[step][2]);
    gpioWrite(IN4, fullStep[step][3]);
}

// Function to rotate stepper motor
void rotate(int steps, int delayTime, int direction) {
    for (int i = 0; i < steps; i++) {
        int stepIndex = direction ? i % 4 : (3 - i % 4); // Forward or Reverse
        setStep(stepIndex);
        gpioDelay(delayTime * 1000); // Delay in microseconds
    }
    setStep(0); // Stop motor
}

int main() {
    if (gpioInitialise() < 0) {
        printf("pigpio initialization failed!\n");
        return 1;
    }

    gpioSetMode(IN1, PI_OUTPUT);
    gpioSetMode(IN2, PI_OUTPUT);
    gpioSetMode(IN3, PI_OUTPUT);
    gpioSetMode(IN4, PI_OUTPUT);

    while (1) {
        printf("Rotating Counterclockwise...\n");
        rotate(512, 3, 1);
        gpioSleep(PI_TIME_RELATIVE, 3, 0);

        printf("Rotating Clockwise...\n");
        rotate(512, 3, 0);
        gpioSleep(PI_TIME_RELATIVE, 3, 0);
    }

    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
