#include <errno.h>
#include <wiringPi.h>

#define FAN_GPIO 18
#define TEMP_FILE "/sys/class/thermal/thermal_zone0/temp"
#define LOG_FILE "fan_log.txt"

FILE *log_file_ptr = NULL;

// Function to read the CPU temperature from the thermal zone file.
int read_temperature() {
    FILE *fp;
    int temperature_milliC = -1; // Initialize to -1 to indicate error

    fp = fopen(TEMP_FILE, "r");
    if (fp == NULL) {
        fprintf(stderr, "Error opening temperature file: %s\n", strerror(errno));
        return -1;
    }

    if (fscanf(fp, "%d", &temperature_milliC) != 1) {
        fprintf(stderr, "Error reading temperature from file: %s\n", strerror(errno));
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return temperature_milliC;
}

// Function to calculate the fan speed based on the CPU temperature.
int calculate_fan_speed(float temperature) {
    int fan_speed = 0;

    if (temperature < 45.0) {
        fan_speed = 0;
    } else if (temperature < 60.0) {
        fan_speed = (int)((temperature - 45.0) / (60.0 - 45.0) * 50.0);
    } else if (temperature < 75.0) {
        fan_speed = (int)((temperature - 60.0) / (75.0 - 60.0) * 30.0 + 50.0);
    } else {
        fan_speed = 100;
    }

    return fan_speed;
}

// Function to set the fan speed using PWM.
void set_fan_speed(int speed) {
    pwmWrite(FAN_GPIO, speed);
}

// Function to log the CPU temperature and fan speed to a file.
void log_data(float temperature, int fan_speed) {
    if (log_file_ptr == NULL) {
        fprintf(stderr, "Log file not initialized.\n");
        return;
    }

    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char s[64];
    strftime(s, sizeof(s), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(log_file_ptr, "%s - Temperature: %.2f°C, Fan Speed: %d%%\n", s, temperature, fan_speed);
    fflush(log_file_ptr); // Ensure data is written immediately
}

// Signal handler for graceful shutdown.
void signal_handler(int signal) {
    printf("Caught signal %d, shutting down...\n", signal);
    set_fan_speed(0);

    if (log_file_ptr != NULL) {
        time_t t = time(NULL);
        struct tm *tm = localtime(&t);
        char s[64];
        strftime(s, sizeof(s), "%Y-%m-%d %H:%M:%S", tm);
        fprintf(log_file_ptr, "%s - Program terminated.\n", s);
        fclose(log_file_ptr);
    }

    wiringPiSetupGpio(); //Reinitialize to ensure GPIO is in a safe state
    pinMode(FAN_GPIO, OUTPUT); //Set GPIO to output
digitalWrite(FAN_GPIO, LOW); //Turn off the fan

    exit(0);
}

int main() {
    int temperature_milliC, fan_speed;
    float temperature;

    // Initialize WiringPi using GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return 1;
    }

    // Configure GPIO18 as PWM output
    pinMode(FAN_GPIO, PWM_OUTPUT);
    pwmSetMode(PWM_MODE_MS);
    pwmSetRange(100);
    pwmSetClock(192); // Adjust for ~50Hz PWM frequency

    // Open the log file
    log_file_ptr = fopen(LOG_FILE, "a");
    if (log_file_ptr == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        return 1;
    }

    // Register the signal handler for SIGINT
    signal(SIGINT, signal_handler);

    printf("Cooling fan management program started. Press Ctrl+C to exit.\n");

    while (1) {
        // Read the CPU temperature
        temperature_milliC = read_temperature();
        if (temperature_milliC == -1) {
            fprintf(stderr, "Failed to read temperature. Continuing...\n");
            log_data(-1.0, -1); //Log error state
        } else {
          temperature = (float)temperature_milliC / 1000.0;

            // Calculate the fan speed
            fan_speed = calculate_fan_speed(temperature);

            // Set the fan speed
            set_fan_speed(fan_speed);

            // Log the data
            log_data(temperature, fan_speed);
        }

        // Sleep for 5 seconds
        delay(5000);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <signal.h>
#include <unistd.h>
#include <time.h>

#define FAN_GPIO 18
#define ALERT_GPIO 23
#define TEMP_FILE "/sys/class/thermal/thermal_zone0/temp"
#define BUFFER_SIZE 60
#define ALERT_THRESHOLD 75.0
#define ALERT_RESET 70.0
#define ALERT_TIME 30

// Circular buffer structure
typedef struct {
    float cpu_temp[BUFFER_SIZE];
    int fan_speed[BUFFER_SIZE];
    int head;
    int count;
} CircularBuffer;

CircularBuffer buffer;

// Function prototypes
float read_cpu_temp();
void control_fan(float cpu_temp);
void add_to_buffer(float cpu_temp, int fan_speed);
void print_buffer(); // For debugging, can be removed
void signal_handler(int signal);

// Global variables for alert mechanism
int alert_active = 0;
int alert_counter = 0;

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Configure GPIO18 as PWM output
    gpioSetMode(FAN_GPIO, PI_OUTPUT);
    gpioSetPWMrange(FAN_GPIO, 1000);

    // Configure GPIO23 as output for alert
    gpioSetMode(ALERT_GPIO, PI_OUTPUT);
    gpioWrite(ALERT_GPIO, 0);

    // Initialize circular buffer
    buffer.head = 0;
    buffer.count = 0;

    // Set up signal handlers for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Main loop
    while (1) {
        float cpu_temp = read_cpu_temp();
        if (cpu_temp < -200.0) {
            fprintf(stderr, "Error reading CPU temperature, exiting\n");
            break;
        }

        control_fan(cpu_temp);

        // Add data to circular buffer
        int fan_speed = gpioGetPWMdutycycle(FAN_GPIO);
        add_to_buffer(cpu_temp, fan_speed);

        // Check for temperature alert condition
        if (cpu_temp > ALERT_THRESHOLD) {
            alert_counter++;
            if (alert_counter >= ALERT_TIME && !alert_active) {
                gpioWrite(ALERT_GPIO, 1); // Activate alert
                alert_active = 1;
                printf("Temperature alert activated!\n");
            }
        } else {
            alert_counter = 0;
            if (alert_active && cpu_temp < ALERT_RESET) {
                gpioWrite(ALERT_GPIO, 0); // Deactivate alert
                alert_active = 0;
                printf("Temperature alert deactivated.\n");
            }
        }

        // Sleep for 1 second
        time_sleep(1.0);
    }

    // Clean up and exit
    gpioPWM(FAN_GPIO, 0); // Stop fan
    gpioWrite(ALERT_GPIO, 0);
    gpioTerminate();
    return 0;
}

// Function to read CPU temperature from file
float read_cpu_temp() {
    FILE *fp;
    int temp_milli;
    float temp_celsius = -999.0; // Initialize to an invalid value

    fp = fopen(TEMP_FILE, "r");
    if (fp == NULL) {
        fprintf(stderr, "Failed to open temperature file\n");
        return -500.0; // Indicate error with a very low temperature
    }

    if (fscanf(fp, "%d", &temp_milli) == 1) {
        temp_celsius = (float)temp_milli / 1000.0;
    } else {
        fprintf(stderr, "Failed to read temperature from file\n");
        temp_celsius = -300.0;
    }

    fclose(fp);
    return temp_celsius;
}

// Function to control fan speed based on CPU temperature
void control_fan(float cpu_temp) {
    int fan_speed;

    if (cpu_temp < 45.0) {
        fan_speed = 0;
    } else if (cpu_temp < 65.0) {
        fan_speed = (int)((cpu_temp - 45.0) / (65.0 - 45.0) * 1000.0);
    } else {
        fan_speed = 1000;
    }

    gpioPWM(FAN_GPIO, fan_speed);
}

// Function to add data to the circular buffer
void add_to_buffer(float cpu_temp, int fan_speed) {
    buffer.cpu_temp[buffer.head] = cpu_temp;
    buffer.fan_speed[buffer.head] = fan_speed;
    buffer.head = (buffer.head + 1) % BUFFER_SIZE;
    if (buffer.count < BUFFER_SIZE) {
        buffer.count++;
    }
}

// Function to print the contents of the circular buffer (for debugging)
void print_buffer() {
    int i;
    int index;

    printf("Circular Buffer Contents:\n");
    for (i = 0; i < buffer.count; i++) {
        index = (buffer.head - buffer.count + i + BUFFER_SIZE) % BUFFER_SIZE;
        printf("Index: %d, CPU Temp: %.2f, Fan Speed: %d\n", index, buffer.cpu_temp[index], buffer.fan_speed[index]);
    }
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, cleaning up and exiting...\n", signal);
    gpioPWM(FAN_GPIO, 0); // Stop fan
    gpioWrite(ALERT_GPIO, 0); // Ensure alert is off
    gpioTerminate();
    exit(0);
}

#include <stdio.h>
