#include <wiringPiI2C.h>

// Define constants
#define SHT31_ADDRESS 0x44
#define HUMIDITY_THRESHOLD 60.0
#define RELAY_GPIO 17

// Function prototypes
int initialize_i2c();
float read_humidity(int fd);
void control_relay(float humidity);
void log_data(float humidity);

int i2c_fd;

int main()
{
    // Initialize wiringPi and I2C
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi initialization failed!\n");
        return 1;
    }

    i2c_fd = initialize_i2c();
    if (i2c_fd == -1) {
        fprintf(stderr, "I2C initialization failed!\n");
        return 1;
    }

    // Configure relay GPIO as output
    pinMode(RELAY_GPIO, OUTPUT);

    // Main loop
    while (1) {
        float humidity = read_humidity(i2c_fd);

        if (humidity != -1.0) {
            control_relay(humidity);
            log_data(humidity);
        } else {
            // Log the error
            FILE *fp = fopen("dehumidifier_log.txt", "a");
            if (fp != NULL) {
                time_t t = time(NULL);
                struct tm tm = *localtime(&t);
                char timestamp[64];
                strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);
                fprintf(fp, "%s - ERROR: Failed to read humidity.\n", timestamp);
                fclose(fp);
            }
        }

        delay(60000); // Sleep for 60 seconds
    }

    return 0;
}

// Initialize I2C communication with the SHT31 sensor
int initialize_i2c()
{
    int fd = wiringPiI2CSetup(SHT31_ADDRESS);
    if (fd == -1) {
        FILE *fp = fopen("dehumidifier_log.txt", "a");
        if (fp != NULL) {
            time_t t = time(NULL);
            struct tm tm = *localtime(&t);
            char timestamp[64];
            strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);
            fprintf(fp, "%s - ERROR: I2C initialization failed.\n", timestamp);
            fclose(fp);
        }
        return -1;
    }
    return fd;
}

// Read humidity data from the SHT31 sensor
float read_humidity(int fd)
{
    // Send the single-shot measurement command (clock stretching disabled)
    wiringPiI2CWrite(fd, 0x2400); // High repeatability
    delay(20); // Wait for measurement (datasheet specifies typical 15ms, using 20ms to be safe)

    // Read the 6 bytes of data (Temp MSB, Temp LSB, Temp CRC, Hum MSB, Hum LSB, Hum CRC)
    int data[6];
    data[0] = wiringPiI2CReadReg8(fd, 0x00); // Dummy read to trigger the read sequence
    data[0] = wiringPiI2CReadReg8(fd, 0x00); // Temp MSB
    data[1] = wiringPiI2CReadReg8(fd, 0x00); // Temp LSB
    data[2] = wiringPiI2CReadReg8(fd, 0x00); // Temp CRC
    data[3] = wiringPiI2CReadReg8(fd, 0x00); // Hum MSB
    data[4] = wiringPiI2CReadReg8(fd, 0x00); // Hum LSB
    data[5] = wiringPiI2CReadReg8(fd, 0x00); // Hum CRC

    if (data[0] == -1 || data[1] == -1 || data[3] == -1 || data[4] == -1) {
        FILE *fp = fopen("dehumidifier_log.txt", "a");
        if (fp != NULL) {
            time_t t = time(NULL);
            struct tm tm = *localtime(&t);
            char timestamp[64];
            strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);
            fprintf(fp, "%s - ERROR: I2C read failed.\n", timestamp);
            fclose(fp);
        }
        return -1.0;
    }

    // Convert the raw humidity data to a percentage
    float humidity = (float)(((data[3] * 256.0) + data[4]) / 65535.0) * 100.0;

    return humidity;
}

// Control the relay based on the humidity level
void control_relay(float humidity)
{
    if (humidity > HUMIDITY_THRESHOLD) {
        digitalWrite(RELAY_GPIO, HIGH); // Activate relay
        printf("Humidity above threshold. Activating dehumidifier.\n");
    } else {
        digitalWrite(RELAY_GPIO, LOW);  // Deactivate relay
        printf("Humidity below threshold. Deactivating dehumidifier.\n");
    }
}

// Log the humidity data to a file
void log_data(float humidity)
{
    FILE *fp = fopen("dehumidifier_log.txt", "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    fprintf(fp, "%s - Humidity: %.2f%%\n", timestamp, humidity);
    fclose(fp);
}

