    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return -1; // Indicate failure
    }

    pinMode(BUTTON_PIN, INPUT);  // Set the button pin as input
    pinMode(BUZZER_PIN, OUTPUT); // Set the buzzer pin as output

    // Enable pull-up resistor on the button pin (optional, but recommended)
    pullUpDnControl(BUTTON_PIN, PUD_UP);

    return 0; // Indicate success
}

int main() {
    // Initialize GPIO
    if (initialize_gpio() == -1) {
        return 1; // Exit if initialization fails
    }

    int button_state; // Variable to store the button state

    printf("Active Buzzer Control Program\n");

    while (1) {
        // Read the button state
        button_state = digitalRead(BUTTON_PIN);

        // Print the button state for debugging (optional)
        printf("Button state: %d\n", button_state);

        // Check if the button is pressed (low signal indicates pressed due to pull-up resistor)
        if (button_state == LOW) {
            digitalWrite(BUZZER_PIN, HIGH); // Activate the buzzer
            printf("Buzzer ON\n");
        } else {
            digitalWrite(BUZZER_PIN, LOW);  // Deactivate the buzzer
            printf("Buzzer OFF\n");
        }

        delay(50); // Debounce and reduce CPU usage
    }

    return 0; // Program should not normally reach here
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>

// Constants for GPIO pins
#define SERVO_PIN 4
#define PWM_PIN 17
#define OUTPUT_PIN 18
#define INPUT_PIN 23
#define MIRROR_PIN 24

// Constants for PWM and Servo values
#define SERVO_MID_PULSE_WIDTH 1500  // microseconds
#define PWM_DUTYCYCLE 192           // out of 255 (75%)

// Constants for timing
#define SLEEP_DURATION 0.5          // seconds
#define RUN_DURATION 60.0           // seconds

int main(int argc, char *argv[]) {
    double startTime;

    // Initialize the pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "ERROR: pigpio initialisation failed\n");
        return 1; // Exit with an error code
    }

    // Set GPIO modes
    if (gpioSetMode(SERVO_PIN, PI_OUTPUT) != 0) {
        fprintf(stderr, "ERROR: Failed to set mode for SERVO_PIN\n");
        gpioTerminate();
        return 1;
    }
    if (gpioSetMode(PWM_PIN, PI_OUTPUT) != 0) {
        fprintf(stderr, "ERROR: Failed to set mode for PWM_PIN\n");
        gpioTerminate();
        return 1;
    }
    if (gpioSetMode(OUTPUT_PIN, PI_OUTPUT) != 0) {
        fprintf(stderr, "ERROR: Failed to set mode for OUTPUT_PIN\n");
        gpioTerminate();
        return 1;
    }
    if (gpioSetMode(INPUT_PIN, PI_INPUT) != 0) {
        fprintf(stderr, "ERROR: Failed to set mode for INPUT_PIN\n");
        gpioTerminate();
        return 1;
    }
    if (gpioSetMode(MIRROR_PIN, PI_OUTPUT) != 0) {
        fprintf(stderr, "ERROR: Failed to set mode for MIRROR_PIN\n");
        gpioTerminate();
        return 1;
    }

    // Start 1500 us servo pulses on SERVO_PIN
    if (gpioServo(SERVO_PIN, SERVO_MID_PULSE_WIDTH) != 0) {
        fprintf(stderr, "ERROR: Failed to set servo pulse width\n");
        gpioTerminate();
        return 1;
    }

    // Start PWM on PWM_PIN
    if (gpioPWM(PWM_PIN, PWM_DUTYCYCLE) != 0) {
        fprintf(stderr, "ERROR: Failed to set PWM duty cycle\n");
        gpioTerminate();
        return 1;
    }

    startTime = time_time();

    // Main loop: Toggle OUTPUT_PIN and mirror INPUT_PIN to MIRROR_PIN
    while ((time_time() - startTime) < RUN_DURATION) {
        // Set OUTPUT_PIN high
        if (gpioWrite(OUTPUT_PIN, 1) != 0) {
            fprintf(stderr, "ERROR: Failed to write to OUTPUT_PIN\n");
            gpioTerminate();
            return 1;
        }

        // Sleep for SLEEP_DURATION seconds
        time_sleep(SLEEP_DURATION);

        // Set OUTPUT_PIN low
        if (gpioWrite(OUTPUT_PIN, 0) != 0) {
            fprintf(stderr, "ERROR: Failed to write to OUTPUT_PIN\n");
            gpioTerminate();
            return 1;
        }

        // Sleep for SLEEP_DURATION seconds
        time_sleep(SLEEP_DURATION);

        // Mirror INPUT_PIN to MIRROR_PIN
        int input_value = gpioRead(INPUT_PIN);
        if (input_value >= 0) {
            if (gpioWrite(MIRROR_PIN, input_value) != 0) {
                fprintf(stderr, "ERROR: Failed to write to MIRROR_PIN\n");
                gpioTerminate();
                return 1;
            }
        } else {
            fprintf(stderr, "ERROR: Failed to read from INPUT_PIN\n");
            gpioTerminate();
            return 1;
        }
    }

    // Clean up and terminate the pigpio library
    gpioTerminate();

    return 0; // Exit successfully
}

#include <stdio.h>
#include <wiringPi.h>
#include <stdint.h>

// Define WiringPi pins connected to the 74HC595
#define LATCH_PIN  0  // GPIO 17
#define CLOCK_PIN  1  // GPIO 18
#define DATA_PIN   2  // GPIO 27

// Seven segment display patterns (common cathode)
const uint8_t segments[] = {
    0b00111111, // 0
    0b00000110, // 1
    0b01011011, // 2
    0b01001111, // 3
    0b01100110, // 4
    0b01101101, // 5
    0b01111101, // 6
    0b00000111, // 7
    0b01111111, // 8
    0b01101111  // 9
};

void shiftOut(uint8_t dataPin, uint8_t clockPin, uint8_t dataOut) {
    for (int i = 0; i < 8; i++) {
        digitalWrite(dataPin, (dataOut >> (7 - i)) & 0x01);
        digitalWrite(clockPin, HIGH);
        digitalWrite(clockPin, LOW);
    }
}

void display(int number) {
    shiftOut(DATA_PIN, CLOCK_PIN, segments[number]);
    digitalWrite(LATCH_PIN, HIGH);
    digitalWrite(LATCH_PIN, LOW);
}

int main(void) {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi setup failed!\n");
        return 1;
    }

    pinMode(LATCH_PIN, OUTPUT);
    pinMode(CLOCK_PIN, OUTPUT);
    pinMode(DATA_PIN, OUTPUT);

    while (1) {
        for (int i = 0; i < 10; i++) {
            display(i);
            delay(1000); // Display each number for 1 second
        }
    }

    return 0;
}

