#define IR_RECEIVE_PIN 24 // BCM GPIO 24 (WiringPi pin number will vary based on setup)
#define LED_PIN 25        // BCM GPIO 25 (WiringPi pin number will vary based on setup)

// Timing constants (in microseconds)
#define PULSE_9MS   9000  // 9ms pulse
#define PULSE_4_5MS 4500  // 4.5ms pulse
#define PULSE_0_56MS 560  // 0.56ms pulse
#define PULSE_1_69MS 1690 // 1.69ms pulse

// Timeout value (in milliseconds) - adjust as needed
#define TIMEOUT_MS 50

// Function prototypes
int read_ir_data(unsigned char data[4]);

int main()
{
    // Initialize wiringPi using BCM GPIO numbering
    if (wiringPiSetupGpio() < 0) {
        fprintf(stderr, "WiringPi initialization failed!\n");
        return 1;
    }

    // Set IR receive pin as input with pull-up resistor
    pinMode(IR_RECEIVE_PIN, INPUT);
    pullUpDnControl(IR_RECEIVE_PIN, PUD_UP);

    // Set LED pin as output
    pinMode(LED_PIN, OUTPUT);

    printf("Infrared Remote Control Decoder\n");

    unsigned char received_data[4];

    while (1) {
        // Attempt to read IR data
        if (read_ir_data(received_data) == 0) {
            // Verify checksum
            if ((received_data[0] + received_data[1] == 0xFF) && (received_data[2] + received_data[3] == 0xFF)) {
                printf("Received key: 0x%02X\n", received_data[2]);

                // Control LED based on received key (example)
                if (received_data[2] == 0x46) {
                    digitalWrite(LED_PIN, HIGH); // Turn LED on
                } else if (received_data[2] == 0x40) {
                    digitalWrite(LED_PIN, LOW);  // Turn LED off
                }
            } else {
                fprintf(stderr, "Checksum error!\n");
            }
        } else {
            // No data received or error occurred
            //fprintf(stderr, "No data received or error occurred.\n"); //Commented out to reduce console spam
        }

        // Small delay to prevent excessive CPU usage
        usleep(10000); // 10ms
    }

    return 0;
}

// Function to read IR data
int read_ir_data(unsigned char data[4]) {
    unsigned int count = 0;
    unsigned char i, idx, bit_index;

    // Wait for the start signal (low pulse)
    while (digitalRead(IR_RECEIVE_PIN) == HIGH) {
        usleep(100); // Wait a short time
        count++;
        if (count > 1000) return -1; // Timeout if no signal detected
    }

    count = 0;
    while (digitalRead(IR_RECEIVE_PIN) == LOW) {
        usleep(60); //delayMicroseconds(60);
        count++;
        if (count > 200) return -1; // Timeout
    }

    count = 0;
    while (digitalRead(IR_RECEIVE_PIN) == HIGH) {
        usleep(60); //delayMicroseconds(60);
        count++;
        if (count > 80) return -1; // Timeout
    }

    // Read the 32 bits of data
    idx = 0;
    bit_index = 0;
    data[0] = 0;
    data[1] = 0;
    data[2] = 0;
    data[3] = 0;

    for (i = 0; i < 32; i++) {
        count = 0;
        while (digitalRead(IR_RECEIVE_PIN) == LOW) {
            usleep(60); //delayMicroseconds(60);
            count++;
            if (count > 15) return -1; // Timeout
        }

        count = 0;
        while (digitalRead(IR_RECEIVE_PIN) == HIGH) {
            usleep(60); //delayMicroseconds(60);
            count++;
            if (count > 40) return -1; // Timeout
        }

        // Determine if the bit is a 0 or a 1 based on the pulse length
        if (count > 25) {
            data[idx] |= (1 << bit_index);
        }

        // Increment bit and byte indices
        bit_index++;
        if (bit_index == 8) {
            bit_index = 0;
            idx++;
        }
    }

    return 0; // Success
}

