#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <unistd.h>
#include <fcntl.h>
#include <signal.h>
#include <time.h>
#include <stdbool.h>

// GPIO pins
#define RAIN_SENSOR_GPIO 17
#define MOTOR_IN1_GPIO 22
#define MOTOR_IN2_GPIO 27

// Sysfs paths
#define GPIO_EXPORT_PATH "/sys/class/gpio/export"
#define GPIO_UNEXPORT_PATH "/sys/class/gpio/unexport"
#define GPIO_DIR_PATH_BASE "/sys/class/gpio/gpio%d/direction"
#define GPIO_VALUE_PATH_BASE "/sys/class/gpio/gpio%d/value"

// Debounce time (ms)
#define DEBOUNCE_TIME_MS 100

// Motor close duration (ms)
#define MOTOR_CLOSE_DURATION_MS 5000

// Log file path
#define LOG_FILE_PATH "rain_events.log"

// Global flag for program termination
volatile sig_atomic_t terminate = 0;

// Signal handler for SIGINT (Ctrl+C)
void signal_handler(int sig) {
    terminate = 1;
    printf("\nCaught signal %d, terminating...\n", sig);
}

// Function to export a GPIO
int gpio_export(int gpio) {
    char buf[64];
    int len;
    int fd;

    fd = open(GPIO_EXPORT_PATH, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Error opening %s: %s\n", GPIO_EXPORT_PATH, strerror(errno));
        return -1;
    }

    len = snprintf(buf, sizeof(buf), "%d", gpio);
    if (write(fd, buf, len) != len) {
        fprintf(stderr, "Error writing to %s: %s\n", GPIO_EXPORT_PATH, strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to unexport a GPIO
int gpio_unexport(int gpio) {
    char buf[64];
    int len;
    int fd;

    fd = open(GPIO_UNEXPORT_PATH, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Error opening %s: %s\n", GPIO_UNEXPORT_PATH, strerror(errno));
        return -1;
    }

    len = snprintf(buf, sizeof(buf), "%d", gpio);
    if (write(fd, buf, len) != len) {
        fprintf(stderr, "Error writing to %s: %s\n", GPIO_UNEXPORT_PATH, strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to set the direction of a GPIO (in or out)
int gpio_set_direction(int gpio, const char *direction) {
    char path[128];
    int fd;

    snprintf(path, sizeof(path), GPIO_DIR_PATH_BASE, gpio);
    fd = open(path, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Error opening %s: %s\n", path, strerror(errno));
        return -1;
    }

    if (write(fd, direction, strlen(direction)) != (ssize_t)strlen(direction)) {
        fprintf(stderr, "Error writing to %s: %s\n", path, strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to read the value of a GPIO
int gpio_read(int gpio) {
    char path[128];
    char value_str[3];
    int fd;

    snprintf(path, sizeof(path), GPIO_VALUE_PATH_BASE, gpio);
    fd = open(path, O_RDONLY);
    if (fd < 0) {
        fprintf(stderr, "Error opening %s: %s\n", path, strerror(errno));
        return -1;
    }

    if (read(fd, value_str, 3) < 0) {
        fprintf(stderr, "Error reading from %s: %s\n", path, strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return atoi(value_str);
}

// Function to write a value to a GPIO
int gpio_write(int gpio, int value) {
    char path[128];
    char value_str[3];
    int fd;

    snprintf(path, sizeof(path), GPIO_VALUE_PATH_BASE, gpio);
    fd = open(path, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Error opening %s: %s\n", path, strerror(errno));
        return -1;
    }

    snprintf(value_str, sizeof(value_str), "%d", value);
    if (write(fd, value_str, strlen(value_str)) != (ssize_t)strlen(value_str)) {
        fprintf(stderr, "Error writing to %s: %s\n", path, strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to close the window motor
int motor_close(int duration_ms) {
    if (gpio_write(MOTOR_IN1_GPIO, 1) < 0) {
        fprintf(stderr, "Error setting MOTOR_IN1_GPIO HIGH\n");
        return -1;
    }
    if (gpio_write(MOTOR_IN2_GPIO, 0) < 0) {
        fprintf(stderr, "Error setting MOTOR_IN2_GPIO LOW\n");
        gpio_write(MOTOR_IN1_GPIO, 0); // Attempt to stop motor if IN2 fails
        return -1;
    }

    struct timespec ts;
    ts.tv_sec = duration_ms / 1000;
    ts.tv_nsec = (duration_ms % 1000) * 1000000;
    nanosleep(&ts, NULL);

    if (gpio_write(MOTOR_IN1_GPIO, 0) < 0) {
        fprintf(stderr, "Error setting MOTOR_IN1_GPIO LOW\n");
        return -1;
    }
    if (gpio_write(MOTOR_IN2_GPIO, 0) < 0) {
        fprintf(stderr, "Error setting MOTOR_IN2_GPIO LOW\n");
        return -1;
    }

    return 0;
}

// Function to log an event to a file
int log_event(const char *event_type) {
    FILE *fp;
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    fp = fopen(LOG_FILE_PATH, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening %s: %s\n", LOG_FILE_PATH, strerror(errno));
        return -1;
    }

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);
    fprintf(fp, "%s: %s\n", timestamp, event_type);

    if (fclose(fp) != 0) {
        fprintf(stderr, "Error closing %s: %s\n", LOG_FILE_PATH, strerror(errno));
        return -1;
    }

    return 0;
}

int main() {
    // Install signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Export GPIOs
    if (gpio_export(RAIN_SENSOR_GPIO) < 0) return 1;
    if (gpio_export(MOTOR_IN1_GPIO) < 0) {
        gpio_unexport(RAIN_SENSOR_GPIO);
        return 1;
    }
    if (gpio_export(MOTOR_IN2_GPIO) < 0) {
        gpio_unexport(RAIN_SENSOR_GPIO);
        gpio_unexport(MOTOR_IN1_GPIO);
        return 1;
    }

    // Set GPIO directions
    if (gpio_set_direction(RAIN_SENSOR_GPIO, "in") < 0) {
        gpio_unexport(RAIN_SENSOR_GPIO);
        gpio_unexport(MOTOR_IN1_GPIO);
        gpio_unexport(MOTOR_IN2_GPIO);
        return 1;
    }
    if (gpio_set_direction(MOTOR_IN1_GPIO, "out") < 0) {
        gpio_unexport(RAIN_SENSOR_GPIO);
        gpio_unexport(MOTOR_IN1_GPIO);
        gpio_unexport(MOTOR_IN2_GPIO);
        return 1;
    }
    if (gpio_set_direction(MOTOR_IN2_GPIO, "out") < 0) {
        gpio_unexport(RAIN_SENSOR_GPIO);
        gpio_unexport(MOTOR_IN1_GPIO);
        gpio_unexport(MOTOR_IN2_GPIO);
        return 1;
    }

    printf("Rain sensor monitoring started. Press Ctrl+C to exit.\n");

    bool rain_detected = false;
    struct timespec debounce_ts;
    debounce_ts.tv_sec = 0;
    debounce_ts.tv_nsec = DEBOUNCE_TIME_MS * 1000000;

    while (!terminate) {
        int rain_sensor_value = gpio_read(RAIN_SENSOR_GPIO);
        if (rain_sensor_value < 0) {
            fprintf(stderr, "Error reading rain sensor value\n");
            break;
        }

        if (rain_sensor_value == 0 && !rain_detected) {
            // Debounce
            nanosleep(&debounce_ts, NULL);
            if (gpio_read(RAIN_SENSOR_GPIO) == 0) { // Re-check after debounce
                printf("Rain detected!\n");
                log_event("Rain detected");

                if (motor_close(MOTOR_CLOSE_DURATION_MS) < 0) {
                    fprintf(stderr, "Error closing motor\n");
                } else {
                    printf("Window closed.\n");
                    log_event("Window closed");
                }
                rain_detected = true; // Set flag to avoid re-triggering
            }
        } else if (rain_sensor_value == 1 && rain_detected) {
            rain_detected = false; // Reset flag when rain stops
        }

        usleep(50000); // Check every 50ms
    }

    // Unexport GPIOs before exiting
    gpio_unexport(RAIN_SENSOR_GPIO);
    gpio_unexport(MOTOR_IN1_GPIO);
    gpio_unexport(MOTOR_IN2_GPIO);

    printf("Program terminated.\n");
    return 0;
}

