#define LOCK_1_GPIO 17
#define LOCK_2_GPIO 27
#define PIR_SENSOR_GPIO 22

#define UNLOCK 1
#define LOCK 0

#define UNLOCK_DURATION_MS 5000 // 5 seconds
#define DEBOUNCE_DELAY_MS 50

// Function to read keypad input from stdin
int read_keypad_input(int *input)
{
    char buffer[5]; // Buffer to hold 4 digits + null terminator
    printf("Enter 4-digit PIN code: ");
    if (fgets(buffer, sizeof(buffer), stdin) != NULL) // Use fgets to prevent buffer overflows
    {
        // Remove trailing newline if present
        size_t len = strlen(buffer);
        if (len > 0 && buffer[len - 1] == '\n') {
            buffer[len - 1] = '\0';
        }

        if (strlen(buffer) == 4) // Check for correct length
        {
            for (int i = 0; i < 4; i++)
            {
                if (buffer[i] < '0' || buffer[i] > '9') // Check for non-numeric characters
                {
                    fprintf(stderr, "Error: Invalid input. Please enter only numeric digits.\n");
                    return -1; // Error code for invalid input
                }
            }
            *input = atoi(buffer); // Convert string to integer
            return 0;            // Success
        }
        else
        {
            fprintf(stderr, "Error: Invalid input length. Please enter a 4-digit PIN.\n");
            return -1; // Error code for incorrect length
        }
    }
    else
    {
        fprintf(stderr, "Error reading input.\n");
        return -1; // Error reading input
    }
}

// Function to read PIR sensor state with debouncing
int read_pir_sensor()
{
    int pir_state = digitalRead(PIR_SENSOR_GPIO);
    int last_state = pir_state;

    while (digitalRead(PIR_SENSOR_GPIO) == last_state) {
        delay(1); // Small delay to avoid busy-waiting
    }
    delay(DEBOUNCE_DELAY_MS); // Debounce delay
    return digitalRead(PIR_SENSOR_GPIO);  // Return the debounced PIR sensor state
}

// Function to authenticate the user
int authenticate(int lock_number, int keypad_input, int pir_state)
{
    int correct_pin;
    if (lock_number == 1)
    {
        correct_pin = 1234;
    }
    else if (lock_number == 2)
    {
        correct_pin = 5678;
    }
    else
    {
        fprintf(stderr, "Error: Invalid lock number.\n");
        return 0; // Authentication failed due to invalid lock number
    }

    if (keypad_input == correct_pin && pir_state == 1)
    {
        return 1; // Authentication successful
    }
    else
    {
        return 0; // Authentication failed
    }
}

// Function to control the door lock
void control_door_lock(int lock_gpio, int action)
{
    digitalWrite(lock_gpio, action); // Set the GPIO pin to unlock/lock
    if (action == UNLOCK)
    {
        printf("Door unlocking...\n");
        delay(UNLOCK_DURATION_MS); // Keep unlocked for specified duration
        digitalWrite(lock_gpio, LOCK);  // Lock the door after the duration
        printf("Door locking...\n");
    }
}

// Function to log access attempts
void log_access_attempt(int lock_number, int success)
{
    FILE *log_file = fopen("/var/log/door_access.log", "a");
    if (log_file == NULL)
    {
        fprintf(stderr, "Error opening log file!\n");
        return; // Exit if log file cannot be opened
    }

    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(log_file, "%s - Lock %d: %s\n", timestamp, lock_number, success ? "Access Granted" : "Access Denied");

    if (fclose(log_file) != 0)
    {
        fprintf(stderr, "Error closing log file!\n");
    }
}

int main()
{
    if (wiringPiSetupGpio() == -1)
    {
        fprintf(stderr, "Error initializing wiringPi!\n");
        return 1; // Exit if wiringPi initialization fails
    }

    pinMode(LOCK_1_GPIO, OUTPUT);
