            continue;
        }
        while (getchar() != '\n'); // Clear the input buffer

        if (read_keypad_input(&keypad_input) == 0)
        {
            int pir_state = read_pir_sensor();
            int authentication_result = authenticate(lock_number, keypad_input, pir_state);

            if (authentication_result == 1)
            {
                printf("Authentication successful!\n");
                if (lock_number == 1)
                {
                    control_door_lock(LOCK_1_GPIO, UNLOCK);
                }
                else
                {
                    control_door_lock(LOCK_2_GPIO, UNLOCK);
                }
                log_access_attempt(lock_number, 1); // Log successful access
            }
            else
            {
                printf("Authentication failed.\n");
                log_access_attempt(lock_number, 0); // Log failed access
            }
        }
    }

