#include <softPwm.h>

#define INA1 0  // BCM GPIO 17
#define INA2 2  // BCM GPIO 27
#define ENA  3  // BCM GPIO 22

void setup() {
    wiringPiSetup();
    pinMode(INA1, OUTPUT);
    pinMode(INA2, OUTPUT);
    softPwmCreate(ENA, 0, 100);
}

void forward(int duration) {
    digitalWrite(INA1, HIGH);
    digitalWrite(INA2, LOW);
    softPwmWrite(ENA, 80);
    delay(duration);
    digitalWrite(INA1, LOW);
    digitalWrite(INA2, LOW);
    softPwmWrite(ENA, 0);
}

void reverse(int duration) {
    digitalWrite(INA1, LOW);
    digitalWrite(INA2, HIGH);
    softPwmWrite(ENA, 80);
    delay(duration);
    digitalWrite(INA1, LOW);
    digitalWrite(INA2, LOW);
    softPwmWrite(ENA, 0);
}

int main() {
    setup();
    while (1) {
        forward(3000);
        delay(2000);
        reverse(3000);
        delay(2000);
    }
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>

// Define GPIO pins for RGB LED
#define RED_PIN   17
#define GREEN_PIN 18
#define BLUE_PIN  27

// Define PWM range (0-255 for common anode)
#define PWM_RANGE 255

// Structure to represent an RGB color
typedef struct {
    int red;
    int green;
    int blue;
} Color;

// Global flag to signal program termination
volatile sig_atomic_t terminate = 0;

// Signal handler for graceful termination
void signal_handler(int signal) {
    terminate = 1;
    fprintf(stderr, "\nCaught signal %d, exiting gracefully...\n", signal);
}

// Function to initialize pigpio
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Indicate failure
    }
    return 0; // Indicate success
}

// Function to set GPIO pin as output
void set_pin_output(int pin) {
    gpioSetMode(pin, PI_OUTPUT);
}

// Function to generate a random color
Color generate_random_color() {
    Color color;
    color.red = rand() % (PWM_RANGE + 1);
    color.green = rand() % (PWM_RANGE + 1);
    color.blue = rand() % (PWM_RANGE + 1);
    return color;
}

// Function to set the RGB LED color using PWM
void set_led_color(int red, int green, int blue) {
    gpioPWM(RED_PIN, PWM_RANGE - red);   // Invert for common anode
    gpioPWM(GREEN_PIN, PWM_RANGE - green); // Invert for common anode
    gpioPWM(BLUE_PIN, PWM_RANGE - blue);  // Invert for common anode
}

// Function to linearly interpolate between two colors
Color interpolate_color(Color start_color, Color end_color, float fraction) {
    Color interpolated_color;
    interpolated_color.red = start_color.red + (end_color.red - start_color.red) * fraction;
    interpolated_color.green = start_color.green + (end_color.green - start_color.green) * fraction;
    interpolated_color.blue = start_color.blue + (end_color.blue - start_color.blue) * fraction;
    return interpolated_color;
}

int main() {
    // Seed the random number generator
    srand(time(NULL));

    // Register signal handler for graceful termination
    signal(SIGINT, signal_handler);

    // Initialize pigpio
    if (initialize_gpio() != 0) {
        return 1; // Exit if initialization fails
    }

    // Set GPIO pins as output
    set_pin_output(RED_PIN);
    set_pin_output(GREEN_PIN);
    set_pin_output(BLUE_PIN);

    // Initial color
    Color current_color = generate_random_color();
    Color target_color = generate_random_color();

    // Main loop
    while (!terminate) {
        // Generate a new target color every 5 seconds
        target_color = generate_random_color();

        // Smooth transition over 5 seconds
        for (int i = 0; i <= 100; ++i) {
            if (terminate) break; // Check for termination signal

            float fraction = (float)i / 100.0f;
            Color interpolated_color = interpolate_color(current_color, target_color, fraction);
            set_led_color(interpolated_color.red, interpolated_color.green, interpolated_color.blue);
            gpioDelay(50000); // Delay for 50ms (100 steps * 50ms = 5 seconds)
        }

        current_color = target_color;
    }

    // Turn off the LED before exiting
    set_led_color(0, 0, 0);

    // Terminate pigpio
    gpioTerminate();

    return 0;
}

#include <time.h>
#include <stdio.h>
#include <stdlib.h>
#include <bcm2835.h>
#include <unistd.h>

// Define the GPIO pin for the LED
#define LED_PIN RPI_GPIO_P1_11 // GPIO 17

// Function to simulate ADC reading (0-1023)
int simulate_adc_reading() {
    // Generate a pseudo-random number between 0 and 1023
    return rand() % 1024;
}

// Function to map ADC reading to delay value (in milliseconds)
int map_adc_to_delay(int adc_value) {
    // Map ADC value (0-1023) to delay (10-1000 ms) inversely
    // Higher ADC -> Smaller delay -> Faster blink
    return 1000 - (adc_value * 990 / 1023); // Map 0-1023 to 1000-10
}

int main(int argc, char **argv) {
    // Initialize bcm2835 library
    if (!bcm2835_init()) {
        fprintf(stderr, "bcm2835_init failed. Are you running as root?\n");
        return 1;
    }

    // Set the LED pin as output
    bcm2835_gpio_fsel(LED_PIN, BCM2835_GPIO_FSEL_OUTP);

    // Seed the random number generator
    srand(time(NULL));

    while (1) {
        // Simulate ADC reading
        int adc_value = simulate_adc_reading();

        // Map ADC reading to delay value
        int delay_ms = map_adc_to_delay(adc_value);

        // Turn LED on
        bcm2835_gpio_write(LED_PIN, HIGH);
        bcm2835_delay(delay_ms);

        // Turn LED off
        bcm2835_gpio_write(LED_PIN, LOW);
        bcm2835_delay(delay_ms);
    }

    // Close bcm2835 library (this will never be reached in this example)
    bcm2835_close();
    return 0;
}

