#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>

// Define GPIO pins for segment control (a-g)
#define SEG_A 4
#define SEG_B 17
#define SEG_C 27
#define SEG_D 22
#define SEG_E 5
#define SEG_F 6
#define SEG_G 13

// Define GPIO pins for digit selection (digit1-digit4)
#define DIGIT1 19
#define DIGIT2 26
#define DIGIT3 16
#define DIGIT4 20

// Array representing the segment patterns for digits 0-9
const int segments[10] = {
    0b00111111, // 0
    0b00000110, // 1
    0b01011011, // 2
    0b01001111, // 3
    0b01100110, // 4
    0b01101101, // 5
    0b01111101, // 6
    0b00000111, // 7
    0b01111111, // 8
    0b01101111  // 9
};

// Function to display a digit on a specific digit
void displayDigit(int digit, int position) {
    // Clear all digits
    gpioWrite(DIGIT1, 1);
    gpioWrite(DIGIT2, 1);
    gpioWrite(DIGIT3, 1);
    gpioWrite(DIGIT4, 1);

    // Set segment pins based on the digit
    int segmentPattern = segments[digit];
    gpioWrite(SEG_A, (segmentPattern >> 6) & 1);
    gpioWrite(SEG_B, (segmentPattern >> 5) & 1);
    gpioWrite(SEG_C, (segmentPattern >> 4) & 1);
    gpioWrite(SEG_D, (segmentPattern >> 3) & 1);
    gpioWrite(SEG_E, (segmentPattern >> 2) & 1);
    gpioWrite(SEG_F, (segmentPattern >> 1) & 1);
    gpioWrite(SEG_G, segmentPattern & 1);

    // Enable the selected digit
    switch (position) {
        case 1:
            gpioWrite(DIGIT1, 0);
            break;
        case 2:
            gpioWrite(DIGIT2, 0);
            break;
        case 3:
            gpioWrite(DIGIT3, 0);
            break;
        case 4:
            gpioWrite(DIGIT4, 0);
            break;
    }
    usleep(1000); // Short delay to allow the digit to be displayed
}

int main() {
    if (gpioInitialise() < 0) {
        printf("pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pins as outputs
    gpioSetMode(SEG_A, PI_OUTPUT);
    gpioSetMode(SEG_B, PI_OUTPUT);
    gpioSetMode(SEG_C, PI_OUTPUT);
    gpioSetMode(SEG_D, PI_OUTPUT);
    gpioSetMode(SEG_E, PI_OUTPUT);
    gpioSetMode(SEG_F, PI_OUTPUT);
    gpioSetMode(SEG_G, PI_OUTPUT);
    gpioSetMode(DIGIT1, PI_OUTPUT);
    gpioSetMode(DIGIT2, PI_OUTPUT);
    gpioSetMode(DIGIT3, PI_OUTPUT);
    gpioSetMode(DIGIT4, PI_OUTPUT);

    int seconds = 0;
    while (1) {
        // Calculate digits for the display
        int digit1 = (seconds / 1000) % 10;
        int digit2 = (seconds / 100) % 10;
        int digit3 = (seconds / 10) % 10;
        int digit4 = seconds % 10;

        // Display digits rapidly to create the illusion of a stable display
        displayDigit(digit1, 1);
        displayDigit(digit2, 2);
        displayDigit(digit3, 3);
        displayDigit(digit4, 4);

        sleep(1);
        seconds++;
    }

    gpioTerminate();
    return 0;
}

