int read_adc(int ch) {
    unsigned char buf[3] = {1, (0x80 | (ch << 4)), 0};
    wiringPiSPIDataRW(0, buf, 3);
    return ((buf[1] & 3) << 8) | buf[2];
}
int main() {
    wiringPiSetup();
    wiringPiSPISetup(0, 1000000);
    FILE* f = fopen("adc_log.csv", "w");
    fprintf(f, "Time,ADC_Value\n");
    while (1) {
        int val = read_adc(0);
        time_t t = time(NULL);
        fprintf(f, "%ld,%d\n", t, val);
        fflush(f);
        delay(500);
    }
    fclose(f);
    return 0;
}

