}

// Function to actuate a solenoid
void actuate_solenoid(int pin, int duration_ms) {
    digitalWrite(pin, HIGH); // Turn solenoid on
    delay(duration_ms);       // Wait for specified duration
    deactuate_solenoid(pin);  // Turn solenoid off
}

// Function to deactuate a solenoid
void deactuate_solenoid(int pin) {
    digitalWrite(pin, LOW); // Turn solenoid off
}

// Sorting actions
void sort_item_left() {
    printf("Sorting item left.\n");
    actuate_solenoid(SOLENOID_LEFT_PIN, DEFAULT_ACTUATION_MS);
}

void sort_item_right() {
    printf("Sorting item right.\n");
    actuate_solenoid(SOLENOID_RIGHT_PIN, DEFAULT_ACTUATION_MS);
}

void no_sort() {
    printf("No sorting action.\n");
    // Do nothing
}

// Signal handler for graceful exit
void signal_handler(int signal) {
    program_running = 0; // Set flag to exit loop
    printf("Caught signal %d, exiting gracefully.\n", signal);
}

// Cleanup function to reset GPIO pins
void cleanup_gpio(int pin) {
    digitalWrite(pin, LOW); // Ensure solenoid is off
    pinMode(pin, INPUT);    // Set pin to input mode (safer state)
}

int main() {
    // Register signal handler for Ctrl+C (SIGINT)
    signal(SIGINT, signal_handler);

    // Initialize GPIO pins
    if (initialize_gpio(SOLENOID_LEFT_PIN) != 0 || initialize_gpio(SOLENOID_RIGHT_PIN) != 0) {
        return 1; // Exit if initialization fails
    }

    printf("Pneumatic Sorting System Control.\n");
    printf("Press 'l' to sort left, 'r' to sort right, 'n' for no sort. Press Ctrl+C to exit.\n");

    // Main program loop
    while (program_running) {
        fd_set readfds;
        struct timeval timeout;
        int result;

        // Set up file descriptor set for select()
        FD_ZERO(&readfds);
        FD_SET(STDIN_FILENO, &readfds);

        // Set timeout for 1 second
        timeout.tv_sec = 1;
        timeout.tv_usec = 0;

        // Wait for input or timeout
        result = select(STDIN_FILENO + 1, &readfds, NULL, NULL, &timeout);

        if (result == -1) {
            perror("select()");
            break; // Exit loop on error
        } else if (result == 0) {
            // Timeout: No input received
            no_sort();
        } else {
            // Input received
            char input = getchar();
            switch (input) {
                case 'l':
                    sort_item_left();
                    break;
                case 'r':
                    sort_item_right();
                    break;
                case 'n':
                    no_sort();
                    break;
                default:
                    printf("Invalid input. Please enter 'l', 'r', or 'n'.\n");
                    break;
            }
            // Consume any remaining characters in the input buffer
            while (getchar() != '\n');
        }
    }

    // Cleanup GPIO pins before exiting
    cleanup_gpio(SOLENOID_LEFT_PIN);
    cleanup_gpio(SOLENOID_RIGHT_PIN);

    printf("Program exiting.\n");
    return 0;
}

#include <stdio.h>
#include <wiringPi.h>
#include <softPwm.h>
#include <stdlib.h>

#define NUM_SERVOS 8

// Servo pins connected to GPIO 0-7 (WiringPi pin numbers)
int servoPins[NUM_SERVOS] = {0, 1, 2, 3, 4, 5, 6, 7};

// Function to initialize servos
void initializeServos() {
    for (int i = 0; i < NUM_SERVOS; i++) {
        pinMode(servoPins[i], OUTPUT);
        softPwmCreate(servoPins[i], 0, 200); // Range 0-200 for 20ms period (50Hz)
    }
}

// Function to set servo position (duty cycle)
void setServoPosition(int servoPin, int position) {
    softPwmWrite(servoPin, position);
}

int main() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi setup failed!\n");
        return 1;
    }

    initializeServos();

    int position = 15; // Initial position (adjust based on your servo)
    int increment = 1;  // Increment value

    while (1) {
        // Move all servos in sync
        for (int i = 0; i < NUM_SERVOS; i++) {
            setServoPosition(servoPins[i], position);
        }

        // Update position
        position += increment;

        // Reverse direction at limits
        if (position >= 24) {
            increment = -1;
        } else if (position <= 6) {
            increment = 1;
        }

        delay(20); // Delay for smooth movement
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <signal.h>
#include <time.h>
#include <pigpio.h>

// Define GPIO pins for RGB LED
#define RED_PIN   17
#define GREEN_PIN 22
#define BLUE_PIN  27

// Define PWM frequency (Hz)
#define PWM_FREQUENCY 200

// Define fade duration (milliseconds)
#define FADE_DURATION_MS 2000

// Define the number of colors in the palette
#define PALETTE_SIZE 5

// Structure to represent an RGB color
typedef struct {
    int red;
    int green;
    int blue;
} RGBColor;

// Global variables
RGBColor colorPalette[PALETTE_SIZE];
int running = 1; // Flag to control the main loop

// Function prototypes
int hexToRgb(const char *hexCode, RGBColor *rgb);
char* rgbToHex(RGBColor rgb, char *hexCode);
int readColorPalette(const char *filename, RGBColor *palette);
RGBColor getRandomColor(const RGBColor *palette, int size);
void setLedColor(int red, int green, int blue);
void fadeToColor(RGBColor startColor, RGBColor endColor, int durationMs);
void cleanup_handler(int signo);

// Function to convert a hexadecimal color code to RGB values
int hexToRgb(const char *hexCode, RGBColor *rgb) {
    if (hexCode[0] != '#' || strlen(hexCode) != 7) {
        fprintf(stderr, "Error: Invalid hex code format. Expected #RRGGBB\n");
        return 1; // Indicate an error
    }

    long number = strtol(hexCode + 1, NULL, 16);
    rgb->red   = (number >> 16) & 0xFF;
    rgb->green = (number >> 8) & 0xFF;
    rgb->blue  = number & 0xFF;

    return 0; // Indicate success
}

// Function to convert RGB values to a hexadecimal color code
char* rgbToHex(RGBColor rgb, char *hexCode) {
    sprintf(hexCode, "#%02X%02X%02X", rgb.red, rgb.green, rgb.blue);
    return hexCode;
}

// Function to read the color palette from a file
int readColorPalette(const char *filename, RGBColor *palette) {
    FILE *fp = fopen(filename, "r");
    if (fp == NULL) {
        fprintf(stderr, "Error: Could not open palette file '%s'. Using default palette.\n", filename);
        // Default color palette (Red, Green, Blue, Yellow, Magenta)
        hexToRgb("#FF0000", &palette[0]);
        hexToRgb("#00FF00", &palette[1]);
        hexToRgb("#0000FF", &palette[2]);
        hexToRgb("#FFFF00", &palette[3]);
        hexToRgb("#FF00FF", &palette[4]);
        return 1; // Indicate default palette used
    }

    char line[8]; // Buffer to store each line (7 characters + null terminator)
    for (int i = 0; i < PALETTE_SIZE; i++) {
        if (fgets(line, sizeof(line), fp) != NULL) {
            // Remove trailing newline character, if present
            size_t len = strlen(line);
            if (len > 0 && line[len - 1] == '\n') {
                line[len - 1] = '\0';
            }

            if (hexToRgb(line, &palette[i]) != 0) {
                fprintf(stderr, "Error: Invalid hex code in palette file at line %d. Using default color.\n", i + 1);
                // Assign a default color if the hex code is invalid
                palette[i].red = 255;
                palette[i].green = 255;
                palette[i].blue = 255;
            }
        } else {
            fprintf(stderr, "Error: Not enough colors in palette file. Using default colors for remaining entries.\n");
            // Fill remaining colors with default values (white)
            for (int j = i; j < PALETTE_SIZE; j++) {
                palette[j].red = 255;
                palette[j].green = 255;
                palette[j].blue = 255;
            }
            break; // Exit the loop
        }
    }

    fclose(fp);
    return 0; // Indicate success
}

// Function to select a random color from the palette
RGBColor getRandomColor(const RGBColor *palette, int size) {
    int randomIndex = rand() % size;
    return palette[randomIndex];
}

// Function to set the PWM duty cycle for each color channel
void setLedColor(int red, int green, int blue) {
    gpioPWM(RED_PIN, red);
    gpioPWM(GREEN_PIN, green);
    gpioPWM(BLUE_PIN, blue);
}

// Function to smoothly fade between two RGB colors
void fadeToColor(RGBColor startColor, RGBColor endColor, int durationMs) {
    int steps = 100; // Number of steps in the fade
    float redDiff   = (float)(endColor.red   - startColor.red)   / steps;
    float greenDiff = (float)(endColor.green - startColor.green) / steps;
    float blueDiff  = (float)(endColor.blue  - startColor.blue)  / steps;

    for (int i = 0; i <= steps; i++) {
        int red   = startColor.red   + (int)(redDiff   * i);
        int green = startColor.green + (int)(greenDiff * i);
        int blue  = startColor.blue  + (int)(blueDiff  * i);

        setLedColor(red, green, blue);
        gpioDelay(durationMs / steps * 1000); // Convert ms to microseconds
    }
}

// Signal handler for graceful shutdown
void cleanup_handler(int signo) {
    printf("\nCaught signal %d, cleaning up...\n", signo);
    running = 0; // Stop the main loop

    // Stop PWM on all pins
    gpioPWM(RED_PIN, 0);
    gpioPWM(GREEN_PIN, 0);
    gpioPWM(BLUE_PIN, 0);

    gpioTerminate(); // Terminate the pigpio library
    exit(0); // Exit the program
}

int main() {
    // Initialize the pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1; // Exit with an error code
    }

    // Set GPIO pins as outputs
    gpioSetMode(RED_PIN, PI_OUTPUT);
    gpioSetMode(GREEN_PIN, PI_OUTPUT);
    gpioSetMode(BLUE_PIN, PI_OUTPUT);

    // Set PWM frequency
    gpioSetPWMfrequency(RED_PIN, PWM_FREQUENCY);
    gpioSetPWMfrequency(GREEN_PIN, PWM_FREQUENCY);
    gpioSetPWMfrequency(BLUE_PIN, PWM_FREQUENCY);

    // Initialize random number generator
    srand(time(NULL));

    // Read the color palette from the file
    if (readColorPalette("palette.txt", colorPalette) != 0) {
        printf("Using default color palette.\n");
    }

    // Set up signal handling for Ctrl+C
    signal(SIGINT, cleanup_handler);

    // Initial color (black)
    RGBColor currentColor = {0, 0, 0};
    setLedColor(0, 0, 0);

    // Main loop
    while (running) {
        // Select a random color from the palette
        RGBColor nextColor = getRandomColor(colorPalette, PALETTE_SIZE);

        // Fade to the new color
        fadeToColor(currentColor, nextColor, FADE_DURATION_MS);

        // Update the current color
        currentColor = nextColor;
    }

    return 0;
}

#include <stdio.h>
