// Define relay pins
#define RELAY1_PIN 17
#define RELAY2_PIN 18
#define RELAY3_PIN 27
#define RELAY4_PIN 22

// Log file path
#define LOG_FILE "/var/log/lighting.log"

// Function prototypes
void relay_control(int pin, int state);
void log_event(int pin, int state);
void signal_handler(int signal);

// Global flag to control the main loop
volatile sig_atomic_t program_running = 1;

int main(void) {
    // Seed the random number generator
    srand(time(NULL));

    // Initialize wiringPi using GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi. Please check permissions and wiring.\n");
        return 1;
    }

    // Set relay pins as output
    pinMode(RELAY1_PIN, OUTPUT);
    pinMode(RELAY2_PIN, OUTPUT);
    pinMode(RELAY3_PIN, OUTPUT);
    pinMode(RELAY4_PIN, OUTPUT);

    // Register signal handler for SIGINT (Ctrl+C)
    signal(SIGINT, signal_handler);

    printf("Smart Lighting System started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        // Control each relay with a random on/off cycle
        int relay1_state = rand() % 2; // 0 or 1
        int relay2_state = rand() % 2; // 0 or 1
        int relay3_state = rand() % 2; // 0 or 1
        int relay4_state = rand() % 2; // 0 or 1

        relay_control(RELAY1_PIN, relay1_state);
        log_event(RELAY1_PIN, relay1_state);

        relay_control(RELAY2_PIN, relay2_state);
        log_event(RELAY2_PIN, relay2_state);

        relay_control(RELAY3_PIN, relay3_state);
        log_event(RELAY3_PIN, relay3_state);

        relay_control(RELAY4_PIN, relay4_state);
        log_event(RELAY4_PIN, relay4_state);

