    relay_control(RELAY4_PIN, 0); // Turn off

    return 0;
}

// Function to control a relay
void relay_control(int pin, int state) {
    digitalWrite(pin, state);
}

// Function to log relay state changes to a file
void log_event(int pin, int state) {
    FILE *fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file %s\n", LOG_FILE);
        return;
    }

    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(fp, "%s - Relay %d: %s\n", timestamp, pin, state ? "ON" : "OFF");
    fclose(fp);
}

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("Ctrl+C pressed. Exiting gracefully...\n");
        program_running = 0;
    }
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <signal.h>
#include <string.h>
#include <time.h>

// Define GPIO pins
#define RAIN_SENSOR_PIN 18
#define RELAY_PIN 24

// Global variables
static volatile int running = 1;
FILE *log_file = NULL;

// Function to handle signals (Ctrl+C, termination)
void signal_handler(int signal)
{
    printf("\nCaught signal %d, cleaning up and exiting...\n", signal);
    running = 0;
}

// Function to get current timestamp in ISO 8601 format
void get_timestamp(char *timestamp)
{
    time_t rawtime;
    struct tm *timeinfo;
    time(&rawtime);
    timeinfo = localtime(&rawtime);
    strftime(timestamp, 30, "%Y-%m-%dT%H:%M:%SZ", timeinfo);
}

// Function to log events to file
void log_event(const char *event)
{
    char timestamp[30];
    get_timestamp(timestamp);

    if (log_file != NULL)
    {
        fprintf(log_file, "%s: %s\n", timestamp, event);
        fflush(log_file); // Ensure immediate write to file
    }
    else
    {
        fprintf(stderr, "Error: Log file not opened.\n");
    }
}

int main(int argc, char *argv[])
{
    int rain_threshold;
    int rain_detected;

    // Check command-line arguments
    if (argc != 2)
    {
        fprintf(stderr, "Usage: %s <rain_threshold (0 or 1)>\n", argv[0]);
        return 1;
    }

    rain_threshold = atoi(argv[1]);
    if (rain_threshold != 0 && rain_threshold != 1)
    {
        fprintf(stderr, "Error: Rain threshold must be 0 or 1.\n");
        return 1;
    }

    // Initialize pigpio library
    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    if (gpioSetMode(RELAY_PIN, PI_OUTPUT) != 0)
    {
        fprintf(stderr, "Error: Failed to set GPIO%d as output\n", RELAY_PIN);
        gpioTerminate();
        return 1;
    }

    if (gpioSetMode(RAIN_SENSOR_PIN, PI_INPUT) != 0)
    {
        fprintf(stderr, "Error: Failed to set GPIO%d as input\n", RAIN_SENSOR_PIN);
        gpioTerminate();
        return 1;
    }

    // Open log file
    log_file = fopen("rain_events.log", "a");
    if (log_file == NULL)
    {
        fprintf(stderr, "Error: Failed to open log file\n");
        gpioTerminate();
        return 1;
    }

    // Register signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    printf("Rain sensor monitoring started. Threshold: %d\n", rain_threshold);

    // Main loop
    while (running)
    {
        rain_detected = gpioRead(RAIN_SENSOR_PIN);
        if (rain_detected == rain_threshold)
        {
            // Rain detected, close the vent (activate relay)
            if (gpioWrite(RELAY_PIN, 1) != 0)
            {
                fprintf(stderr, "Error: Failed to write to GPIO%d\n", RELAY_PIN);
                running = 0; // Stop the loop on error
            }
            else
            {
                log_event("Vent closed (rain detected)");
                printf("Rain detected! Vent closed.\n");
            }
        }
        else
        {
            // No rain, open the vent (deactivate relay)
            if (gpioWrite(RELAY_PIN, 0) != 0)
            {
                fprintf(stderr, "Error: Failed to write to GPIO%d\n", RELAY_PIN);
                running = 0; // Stop the loop on error
            }
            else
            {
                log_event("Vent opened (no rain)");
                printf("No rain. Vent opened.\n");
            }
        }

        gpioDelay(500); // Check every 500ms
    }

    // Cleanup
    printf("Cleaning up GPIO and exiting...\n");
    gpioWrite(RELAY_PIN, 0); // Ensure relay is off before exiting
    fclose(log_file);
    gpioTerminate();

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>
#include <bcm2835.h>

// Define GPIO pins
#define SOUND_SENSOR_PIN RPI_GPIO_P1_16 // GPIO 23
#define LED_PIN RPI_GPIO_P1_18        // GPIO 24

// Define sound threshold
#define SOUND_THRESHOLD LOW

// Define LED on time (milliseconds)
#define LED_ON_TIME 500

// Global file pointer for logging
FILE *log_file = NULL;

// Function prototypes
int init_gpio();
int read_sound_sensor();
void control_led(int state);
void log_event();
void cleanup(int signal);

int main(int argc, char **argv) {
    // Initialize the bcm2835 library
    if (!bcm2835_init()) {
        fprintf(stderr, "bcm2835_init failed. Are you running as root?\n");
        return 1;
    }

    // Initialize GPIO pins
    if (init_gpio() != 0) {
        fprintf(stderr, "GPIO initialization failed.\n");
        bcm2835_close();
        return 1;
    }

    // Open log file
    log_file = fopen("audio_events.log", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        bcm2835_close();
        return 1;
    }

    // Set up signal handling for Ctrl+C
    signal(SIGINT, cleanup);

    printf("Audio-reactive LED control started. Press Ctrl+C to exit.\n");

    // Main loop
    while (1) {
        // Read sound sensor value
        int sound_level = read_sound_sensor();

        // Check if sound level exceeds threshold
        if (sound_level == SOUND_THRESHOLD) {
            // Turn on LED
            control_led(HIGH);

            // Log the event
            log_event();

            // Wait for a short time
            bcm2835_delay(LED_ON_TIME);

            // Turn off LED
            control_led(LOW);
        }

        // Small delay to avoid busy-waiting
        bcm2835_delay(10);
    }

    return 0;
}

// Initialize GPIO pins
int init_gpio() {
    // Configure sound sensor pin as input with pull-up resistor
    bcm2835_gpio_fsel(SOUND_SENSOR_PIN, BCM2835_GPIO_FSEL_INPT);
    bcm2835_gpio_set_pud(SOUND_SENSOR_PIN, BCM2835_GPIO_PUD_UP);

    // Configure LED pin as output
    bcm2835_gpio_fsel(LED_PIN, BCM2835_GPIO_FSEL_OUTP);

    return 0;
}

// Read sound sensor value
int read_sound_sensor() {
    return bcm2835_gpio_lev(SOUND_SENSOR_PIN);
}

// Control LED state
void control_led(int state) {
    bcm2835_gpio_write(LED_PIN, state);
}

// Log event to file
void log_event() {
    time_t now = time(NULL);
    char *timestamp = ctime(&now);
    // Remove trailing newline from ctime()
    timestamp[strcspn(timestamp, "\n")] = 0;
    fprintf(log_file, "[%s] Sound detected!\n", timestamp);
    fflush(log_file); // Ensure data is written to disk immediately
}

// Cleanup function to close log file and de-initialize bcm2835 library
void cleanup(int signal) {
    printf("\nCleaning up and exiting...\n");

    if (log_file != NULL) {
        fclose(log_file);
    }

    bcm2835_close();
    exit(0);
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>

// Define GPIO pins for data, latch, and clock
#define DATA_PIN   16
#define LATCH_PIN  5
#define CLOCK_PIN  6

// Define the number of LEDs in the display (assuming 8 for simplicity)
#define NUM_LEDS   8

// Global flag to handle program termination via signal
volatile sig_atomic_t program_running = 1;

// Function prototypes
void signal_handler(int signal);
int initialize_gpio(void);
void clear_leds(void);
int set_led_pattern(const char *pattern);
void cleanup_gpio(void);


// Signal handler for graceful exit
void signal_handler(int signal) {
    if (signal == SIGINT) {
        program_running = 0;
        printf("\nSIGINT received.  Exiting gracefully.\n");
    }
}

// Initializes the pigpio library and sets pin modes.
int initialize_gpio(void) {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "ERROR: pigpio initialisation failed\n");
        return -1; // Indicate failure
    }

    gpioSetMode(DATA_PIN, PI_OUTPUT);
    gpioSetMode(LATCH_PIN, PI_OUTPUT);
    gpioSetMode(CLOCK_PIN, PI_OUTPUT);

    return 0; // Indicate success
}

// Clears all LEDs by setting all data bits to 0.
void clear_leds(void) {
    gpioWrite(LATCH_PIN, PI_LOW); // Begin data transmission

    for (int i = 0; i < NUM_LEDS; ++i) {
        gpioWrite(DATA_PIN, PI_LOW); // Send a '0' bit
        gpioWrite(CLOCK_PIN, PI_HIGH); // Clock the bit in
        gpioDelay(1); // Small delay for reliable clocking
        gpioWrite(CLOCK_PIN, PI_LOW);
    }

    gpioWrite(LATCH_PIN, PI_HIGH); // Latch the data to the LEDs
}

// Sets the LED pattern based on an 8-character string of '0's and '1's.
// Returns 0 on success, -1 on error.
int set_led_pattern(const char *pattern) {
    if (pattern == NULL) {
        fprintf(stderr, "ERROR: Null pattern passed to set_led_pattern\n");
        return -1;
    }

    gpioWrite(LATCH_PIN, PI_LOW);

    for (int i = 0; i < NUM_LEDS; ++i) {
        if (pattern[i] != '0' && pattern[i] != '1') {
            fprintf(stderr, "ERROR: Invalid character in pattern at position %d: '%c'\n", i, pattern[i]);
            gpioWrite(LATCH_PIN, PI_HIGH);
            return -1;
        }

        gpioWrite(DATA_PIN, pattern[i] - '0');
        gpioWrite(CLOCK_PIN, PI_HIGH);
        gpioDelay(1); // Small delay for reliable clocking
        gpioWrite(CLOCK_PIN, PI_LOW);
    }

    gpioWrite(LATCH_PIN, PI_HIGH);
    return 0;
}

// Resets GPIO pins to input mode and terminates the pigpio library.
void cleanup_gpio(void) {
    gpioWrite(LATCH_PIN, PI_INPUT);
    gpioWrite(DATA_PIN, PI_INPUT);
    gpioWrite(CLOCK_PIN, PI_INPUT);

    gpioTerminate();
}

int main() {
    // Register the signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize GPIO
    if (initialize_gpio() != 0) {
        return 1; // Exit if initialization fails
    }

    printf("LED Multiplexing Demo. Press CTRL-C to exit.\n");

    while (program_running) {
        // Clear LEDs
        clear_leds();
        gpioDelay(1000); // 1 second delay

        // Display pattern '11111111'
        if (set_led_pattern("11111111") != 0) {
            break; // Exit loop on error
        }
        gpioDelay(1000);

        // Cycle through some patterns
        for (int i = 0; i < 10 && program_running; ++i) {
            if (set_led_pattern("10101010") != 0) {
                program_running = 0;
                break;
            }
            gpioDelay(500);
            if (set_led_pattern("01010101") != 0) {
                program_running = 0;
                break;
            }
            gpioDelay(500);
        }
    }

    // Cleanup and exit
    cleanup_gpio();

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <errno.h>

// Define constants
#define PWM_DUTY_CYCLE_PATH "/sys/class/pwm/pwmchip0/pwm0/duty_cycle" // Verify this path on your Raspberry Pi 5
#define TEMPERATURE_PATH "/sys/class/thermal/thermal_zone0/temp"
#define TARGET_TEMPERATURE 50 // Target temperature in degrees Celsius
#define MAX_DUTY_CYCLE 1000000
#define MIN_DUTY_CYCLE 0

// PID Gains
#define Kp 10000.0  // Proportional gain
#define Ki 100.0   // Integral gain
#define Kd 1000.0   // Derivative gain

// Global variable for graceful shutdown
volatile sig_atomic_t program_running = 1;

// Signal handler for graceful shutdown
void signal_handler(int sig) {
    (void)sig; //Suppress unused parameter warning
    program_running = 0;
    printf("\nCaught signal, shutting down gracefully...\n");
}

// Function to read CPU temperature from sysfs
int read_temperature() {
    FILE *fp;
    long temp_milli;

    fp = fopen(TEMPERATURE_PATH, "r");
    if (fp == NULL) {
        perror("Error opening temperature file");
        return -1;
    }

    if (fscanf(fp, "%ld", &temp_milli) != 1) {
        perror("Error reading temperature");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return (int)(temp_milli / 1000); // Convert to degrees Celsius
}

// Function to set PWM duty cycle via sysfs
int set_pwm_duty_cycle(const char *path, long duty_cycle) {
    FILE *fp;

    if (duty_cycle < MIN_DUTY_CYCLE || duty_cycle > MAX_DUTY_CYCLE) {
        fprintf(stderr, "Error: Duty cycle out of range (%ld)\n", duty_cycle);
        return -1;
    }

    fp = fopen(path, "w");
    if (fp == NULL) {
        perror("Error opening duty cycle file");
        return -1;
    }

    if (fprintf(fp, "%ld", duty_cycle) < 0) {
        perror("Error writing duty cycle");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return 0;
}

// PID controller functions

// Proportional term calculation
double calculate_proportional(double error) {
    return Kp * error;
}

// Integral term calculation
double calculate_integral(double error) {
    static double integral = 0;
    integral += error;
    return Ki * integral;
}

// Derivative term calculation
double calculate_derivative(double error) {
    static double previous_error = 0;
    double derivative = error - previous_error;
    previous_error = error;
    return Kd * derivative;
}

// PID control function
long pid_control(double current_temperature, double target_temperature) {
    double error = target_temperature - current_temperature;

    double proportional = calculate_proportional(error);
    double integral = calculate_integral(error);
    double derivative = calculate_derivative(error);

    double output = proportional + integral + derivative;

    // Limit the output duty cycle
    if (output > MAX_DUTY_CYCLE) {
        output = MAX_DUTY_CYCLE;
    } else if (output < MIN_DUTY_CYCLE) {
        output = MIN_DUTY_CYCLE;
    }

    return (long)output;
}

int main() {
    struct timespec sleep_time;
    sleep_time.tv_sec = 1;  // 1 second
    sleep_time.tv_nsec = 0;

    // Set up signal handler for graceful shutdown
    if (signal(SIGINT, signal_handler) == SIG_ERR) {
        perror("Error setting up signal handler");
        return 1;
    }

    while (program_running) {
        int temperature = read_temperature();
        if (temperature < 0) {
            fprintf(stderr, "Error reading temperature, skipping iteration\n");
            nanosleep(&sleep_time, NULL);
            continue;
        }

        long duty_cycle = pid_control((double)temperature, (double)TARGET_TEMPERATURE);

        if (set_pwm_duty_cycle(PWM_DUTY_CYCLE_PATH, duty_cycle) != 0) {
            fprintf(stderr, "Error setting duty cycle, skipping iteration\n");
        }

        printf("Temperature: %d°C, Duty Cycle: %ld\n", temperature, duty_cycle);

        nanosleep(&sleep_time, NULL);
    }

    // Ensure fan is turned off on exit
    if (set_pwm_duty_cycle(PWM_DUTY_CYCLE_PATH, 0) != 0) {
        fprintf(stderr, "Error turning off fan during shutdown\n");
    }

    return 0;
}

