#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <signal.h>
#include <errno.h>
#include <unistd.h>

// Configuration Macros
#define VL53L1X_I2C_ADDRESS 0x29
#define SERVO_GPIO 18
#define GATE_OPEN_DELAY_SECONDS 5
#define DISTANCE_THRESHOLD_MM 100 // 10cm
#define SERVO_OPEN_PULSEWIDTH 1500 // Adjust these values based on your servo
#define SERVO_CLOSED_PULSEWIDTH 1000 // Adjust these values based on your servo
#define MOVING_AVERAGE_WINDOW 5

// Global Variables (Minimize use, but needed for signal handler)
static int i2c_handle = -1;
static volatile sig_atomic_t terminate = 0;

// Structure for sensor configuration
typedef struct {
    int i2c_address;
} sensor_config_t;

// Structure for actuator configuration
typedef struct {
    int gpio_pin;
    int open_pulsewidth;
    int closed_pulsewidth;
} actuator_config_t;

// Function Prototypes
int initialize_sensor(sensor_config_t *config);
int read_distance(int *distance);
int initialize_actuator(actuator_config_t *config);
int set_servo_pulsewidth(int pulsewidth);
int set_servo_open(actuator_config_t *config);
int set_servo_closed(actuator_config_t *config);
int control_gate(sensor_config_t *sensor_config, actuator_config_t *actuator_config);
void signal_handler(int signal);
int shutdown(void);
float moving_average(float new_value);

// Static variable for moving average
static float moving_average_values[MOVING_AVERAGE_WINDOW];
static int moving_average_index = 0;
static int moving_average_count = 0;

int main()
{
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed: %s\n", strerror(errno));
        return 1;
    }

    // Sensor and Actuator Configurations
    sensor_config_t sensor_config = {VL53L1X_I2C_ADDRESS};
    actuator_config_t actuator_config = {SERVO_GPIO, SERVO_OPEN_PULSEWIDTH, SERVO_CLOSED_PULSEWIDTH};

    // Initialize Sensor and Actuator
    if (initialize_sensor(&sensor_config) != 0) {
        fprintf(stderr, "Sensor initialization failed.\n");
        shutdown();
        return 1;
    }
    if (initialize_actuator(&actuator_config) != 0) {
        fprintf(stderr, "Actuator initialization failed.\n");
        shutdown();
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Main control loop
    while (!terminate) {
        if (control_gate(&sensor_config, &actuator_config) != 0) {
            fprintf(stderr, "Gate control failed.\n");
            break;
        }
        gpioDelay(100); // Delay for 100ms
    }

    // Shutdown
    shutdown();
    return 0;
}

// Initializes the VL53L1X sensor
int initialize_sensor(sensor_config_t *config)
{
    i2c_handle = i2cOpen(1, config->i2c_address, 0); // Bus 1, address, flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %s\n", strerror(errno));
        return 1;
    }
    return 0;
}

// Reads the distance from the VL53L1X sensor
int read_distance(int *distance)
{
    // VL53L1X register address for distance reading (example, might need adjustment)
    char reg_address = 0x89; // Example register, check datasheet
    char buffer[2]; // 2 bytes for the distance

    if (i2cWriteDevice(i2c_handle, &reg_address, 1) != 0) {
        fprintf(stderr, "Failed to write register address: %s\n", strerror(errno));
        return 1;
    }

    if (i2cReadDevice(i2c_handle, buffer, 2) != 2) {
        fprintf(stderr, "Failed to read distance data: %s\n", strerror(errno));
        return 1;
    }

    // Combine the two bytes to form the distance
    *distance = (buffer[0] << 8) | buffer[1];
    return 0;
}

// Initializes the servo motor
int initialize_actuator(actuator_config_t *config)
{
    gpioSetMode(config->gpio_pin, PI_OUTPUT);
    gpioSetPWMfrequency(config->gpio_pin, 50); // 50 Hz is typical for servos
    gpioSetPWMrange(config->gpio_pin, 20000); // 20000 us = 20 ms
    return 0;
}

// Sets the servo pulsewidth
int set_servo_pulsewidth(int pulsewidth)
{
    gpioPWM(SERVO_GPIO, pulsewidth); // Send PWM signal
    return 0;
}

// Sets the servo to the open position
int set_servo_open(actuator_config_t *config)
{
    return set_servo_pulsewidth(config->open_pulsewidth);
}

// Sets the servo to the closed position
int set_servo_closed(actuator_config_t *config)
{
    return set_servo_pulsewidth(config->closed_pulsewidth);
}

// Controls the gate based on distance readings
int control_gate(sensor_config_t *sensor_config, actuator_config_t *actuator_config)
{
    int distance;
    if (read_distance(&distance) != 0) {
        fprintf(stderr, "Failed to read distance.\n");
        return 1;
    }

    // Apply moving average filter
    float filtered_distance = moving_average((float)distance);

    if (filtered_distance < DISTANCE_THRESHOLD_MM) {
        printf("Distance below threshold (%.2f mm). Opening gate.\n", filtered_distance);
        if (set_servo_open(actuator_config) != 0) {
            fprintf(stderr, "Failed to open gate.\n");
            return 1;
        }
        sleep(GATE_OPEN_DELAY_SECONDS);
        printf("Closing gate.\n");
        if (set_servo_closed(actuator_config) != 0) {
            fprintf(stderr, "Failed to close gate.\n");
            return 1;
        }
    } else {
        printf("Distance: %.2f mm\n", filtered_distance);
    }
    return 0;
}

// Signal handler for Ctrl+C
void signal_handler(int signal)
{
    fprintf(stderr, "Ctrl+C pressed, terminating...\n");
    terminate = 1;
}

// Shutdown function to release resources
int shutdown(void)
{
    printf("Shutting down...\n");
    if (i2c_handle >= 0) {
        i2cClose(i2c_handle);
    }
    gpioTerminate();
    return 0;
}

// Simple moving average filter
float moving_average(float new_value) {
    moving_average_values[moving_average_index] = new_value;
    moving_average_index = (moving_average_index + 1) % MOVING_AVERAGE_WINDOW;

    if (moving_average_count < MOVING_AVERAGE_WINDOW) {
        moving_average_count++;
    }

    float sum = 0.0f;
    for (int i = 0; i < moving_average_count; i++) {
        sum += moving_average_values[i];
    }

    return sum / moving_average_count;
}

#include <stdio.h>
#include <pigpio.h>

#define IN1 22  // GPIO 22 (BCM)
#define IN2 27  // GPIO 27 (BCM)
#define IN3 17  // GPIO 17 (BCM)
#define IN4 4   // GPIO 4  (BCM)

// Corrected Half-Step Sequence
int halfStep[8][4] = {
    {1, 0, 0, 0},  // Step 1 (Coil A)
    {1, 1, 0, 0},  // Step 2 (Coil A & B)
    {0, 1, 0, 0},  // Step 3 (Coil B)
    {0, 1, 1, 0},  // Step 4 (Coil B & C)
    {0, 0, 1, 0},  // Step 5 (Coil C)
    {0, 0, 1, 1},  // Step 6 (Coil C & D)
    {0, 0, 0, 1},  // Step 7 (Coil D)
    {1, 0, 0, 1}   // Step 8 (Coil D & A) ✅ FIXED
};

// Function to set motor step
void setStep(int step) {
    gpioWrite(IN1, halfStep[step][0]);
    gpioWrite(IN2, halfStep[step][1]);
    gpioWrite(IN3, halfStep[step][2]);
    gpioWrite(IN4, halfStep[step][3]);
}

// Function to rotate stepper motor
void rotate(int steps, int delayTime, int direction) {
    for (int i = 0; i < steps; i++) {
        int stepIndex = direction ? i % 8 : (7 - i % 8); // Forward or Reverse
        setStep(stepIndex);
        gpioDelay(delayTime * 1000); // Delay in microseconds (1ms = 1000µs)
    }
    setStep(0); // Stop motor
}

int main() {
    if (gpioInitialise() < 0) {
        printf("pigpio initialization failed!\n");
        return 1;
    }

    gpioSetMode(IN1, PI_OUTPUT);
    gpioSetMode(IN2, PI_OUTPUT);
    gpioSetMode(IN3, PI_OUTPUT);
    gpioSetMode(IN4, PI_OUTPUT);

    while (1) {
        printf("Rotating Counterclockwise...\n");
        rotate(512, 3, 1);  // 512 steps, 3ms delay, Forward
        gpioSleep(PI_TIME_RELATIVE, 3, 0); // Stop for 3 seconds

        printf("Rotating Clockwise...\n");
        rotate(512, 3, 0);  // 512 steps, 3ms delay, Reverse
        gpioSleep(PI_TIME_RELATIVE, 3, 0); // Stop for 3 seconds
    }

    gpioTerminate();
    return 0;
}

