#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <time.h>
#include <errno.h>
#include <string.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>

// BMP280 I2C address
#define BMP280_I2C_ADDR 0x76

// BMP280 register addresses
#define BMP280_REG_TEMP_MSB 0xFA
#define BMP280_REG_TEMP_LSB 0xFB
#define BMP280_REG_TEMP_XLSB 0xFC
#define BMP280_REG_PRESS_MSB 0xF7
#define BMP280_REG_PRESS_LSB 0xF8
#define BMP280_REG_PRESS_XLSB 0xF9
#define BMP280_REG_CTRL_MEAS 0xF4
#define BMP280_REG_CONFIG 0xF5

// LED GPIO pin (WiringPi pin number)
#define LED_PIN 17

// Circular buffer size
#define CIRCULAR_BUFFER_SIZE 20

// Function prototypes
int bmp280_init(int fd);
int bmp280_read_data(int fd, int32_t *temperature, int32_t *pressure);
double bmp280_compensate_T_double(int32_t adc_T, double dig_T1, double dig_T2, double dig_T3);
double bmp280_compensate_P_double(int32_t adc_P, double dig_P1, double dig_P2, double dig_P3, double dig_P4, double dig_P5, double dig_P6, double dig_P7, double dig_P8, double dig_P9, double t_fine);
void led_on(int pin);
void led_off(int pin);
double calculate_average_pressure(double buffer[], int size, int current_index);

// Global variables
double circular_buffer[CIRCULAR_BUFFER_SIZE];
int buffer_index = 0;

// Calibration data
double dig_T1, dig_T2, dig_T3;
double dig_P1, dig_P2, dig_P3, dig_P4, dig_P5, dig_P6, dig_P7, dig_P8, dig_P9;

int main(void) {
    int fd;
    int32_t temperature_raw, pressure_raw;
    double temperature, pressure;
    double average_pressure;
    int i;

    // Initialize WiringPi using GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing WiringPi: %s\n", strerror(errno));
        return 1;
    }

    // Initialize I2C
    fd = wiringPiI2CSetup(BMP280_I2C_ADDR);
    if (fd == -1) {
        fprintf(stderr, "Error initializing I2C: %s\n", strerror(errno));
        return 1;
    }

    // Initialize BMP280 sensor
    if (bmp280_init(fd) != 0) {
        fprintf(stderr, "Error initializing BMP280 sensor.\n");
        return 1;
    }

    // Set LED pin as output
    pinMode(LED_PIN, OUTPUT);

    // Initialize circular buffer with zeros
    for (i = 0; i < CIRCULAR_BUFFER_SIZE; i++) {
        circular_buffer[i] = 0.0;
    }

    printf("Starting pressure and temperature monitoring...\n");

    while (1) {
        // Read temperature and pressure data
        if (bmp280_read_data(fd, &temperature_raw, &pressure_raw) == 0) {
            // Compensate temperature and pressure
            temperature = bmp280_compensate_T_double(temperature_raw, dig_T1, dig_T2, dig_T3);
            pressure = bmp280_compensate_P_double(pressure_raw, dig_P1, dig_P2, dig_P3, dig_P4, dig_P5, dig_P6, dig_P7, dig_P8, dig_P9, temperature);

            printf("Temperature: %.2f °C, Pressure: %.2f Pa\n", temperature / 100.0, pressure / 100.0);

            // Add pressure reading to circular buffer
            circular_buffer[buffer_index] = pressure;
            buffer_index = (buffer_index + 1) % CIRCULAR_BUFFER_SIZE;

            // Calculate average pressure from last 10 readings
            average_pressure = calculate_average_pressure(circular_buffer, CIRCULAR_BUFFER_SIZE, buffer_index);

            // Check for pressure deviation
            if (fabs(pressure - average_pressure) > 500.0) {
                printf("Pressure deviation detected!\n");
                led_on(LED_PIN);
                delay(500);
                led_off(LED_PIN);
            }
        } else {
            fprintf(stderr, "Error reading sensor data. Retrying in 100ms...\n");
            delay(100);
            continue; // Retry reading
        }

        delay(1000); // Read every 1 second
    }

    return 0;
}

// Function to initialize the BMP280 sensor
int bmp280_init(int fd) {
    uint8_t config = 0; // Normal mode, T = 1x, P = 1x

    // Write control register to set mode and oversampling
    wiringPiI2CWriteReg8(fd, BMP280_REG_CTRL_MEAS, 0b00110111); //osrs_t = x1, osrs_p = x1, normal mode
    wiringPiI2CWriteReg8(fd, BMP280_REG_CONFIG, 0b01010000); //t_sb = 100ms

    // Read calibration data
    dig_T1 = (wiringPiI2CReadReg8(fd, 0x88) | wiringPiI2CReadReg8(fd, 0x89) << 8);
    dig_T2 = (int16_t)(wiringPiI2CReadReg8(fd, 0x8A) | wiringPiI2CReadReg8(fd, 0x8B) << 8);
    dig_T3 = (int16_t)(wiringPiI2CReadReg8(fd, 0x8C) | wiringPiI2CReadReg8(fd, 0x8D) << 8);

    dig_P1 = (wiringPiI2CReadReg8(fd, 0x8E) | wiringPiI2CReadReg8(fd, 0x8F) << 8);
    dig_P2 = (int16_t)(wiringPiI2CReadReg8(fd, 0x90) | wiringPiI2CReadReg8(fd, 0x91) << 8);
    dig_P3 = (int16_t)(wiringPiI2CReadReg8(fd, 0x92) | wiringPiI2CReadReg8(fd, 0x93) << 8);
    dig_P4 = (int16_t)(wiringPiI2CReadReg8(fd, 0x94) | wiringPiI2CReadReg8(fd, 0x95) << 8);
    dig_P5 = (int16_t)(wiringPiI2CReadReg8(fd, 0x96) | wiringPiI2CReadReg8(fd, 0x97) << 8);
    dig_P6 = (int16_t)(wiringPiI2CReadReg8(fd, 0x98) | wiringPiI2CReadReg8(fd, 0x99) << 8);
    dig_P7 = (int16_t)(wiringPiI2CReadReg8(fd, 0x9A) | wiringPiI2CReadReg8(fd, 0x9B) << 8);
    dig_P8 = (int16_t)(wiringPiI2CReadReg8(fd, 0x9C) | wiringPiI2CReadReg8(fd, 0x9D) << 8);
    dig_P9 = (int16_t)(wiringPiI2CReadReg8(fd, 0x9E) | wiringPiI2CReadReg8(fd, 0x9F) << 8);

    return 0;
}

// Function to read temperature and pressure data from the BMP280 sensor
int bmp280_read_data(int fd, int32_t *temperature, int32_t *pressure) {
    int32_t temp_msb, temp_lsb, temp_xlsb;
    int32_t press_msb, press_lsb, press_xlsb;

    // Read temperature data
    temp_msb = wiringPiI2CReadReg8(fd, BMP280_REG_TEMP_MSB);
    temp_lsb = wiringPiI2CReadReg8(fd, BMP280_REG_TEMP_LSB);
    temp_xlsb = wiringPiI2CReadReg8(fd, BMP280_REG_TEMP_XLSB);

    // Read pressure data
    press_msb = wiringPiI2CReadReg8(fd, BMP280_REG_PRESS_MSB);
    press_lsb = wiringPiI2CReadReg8(fd, BMP280_REG_PRESS_LSB);
    press_xlsb = wiringPiI2CReadReg8(fd, BMP280_REG_PRESS_XLSB);

    if (temp_msb == -1 || temp_lsb == -1 || temp_xlsb == -1 ||
        press_msb == -1 || press_lsb == -1 || press_xlsb == -1) {
        fprintf(stderr, "Error reading I2C register: %s\n", strerror(errno));
        return -1; // Indicate error
    }

    *temperature = (temp_msb << 12) | (temp_lsb << 4) | (temp_xlsb >> 4);
    *pressure = (press_msb << 12) | (press_lsb << 4) | (press_xlsb >> 4);

    return 0; // Indicate success
}

// Function to compensate temperature (taken from BMP280 datasheet)
double bmp280_compensate_T_double(int32_t adc_T, double dig_T1, double dig_T2, double dig_T3) {
    double var1, var2, T;
    var1 = (((double)adc_T) / 16384.0 - ((double)dig_T1) / 1024.0) * ((double)dig_T2);
    var2 = ((((double)adc_T) / 131072.0 - ((double)dig_T1) / 8192.0) * (((double)adc_T)/ 131072.0 - ((double)dig_T1)/ 8192.0)) * ((double)dig_T3);
    double t_fine = (var1 + var2);
    T = (t_fine / 5.0 + 32.0)*100; //convert to celcius and multiply by 100
    return T;
}

// Function to compensate pressure (taken from BMP280 datasheet)
double bmp280_compensate_P_double(int32_t adc_P, double dig_P1, double dig_P2, double dig_P3, double dig_P4, double dig_P5, double dig_P6, double dig_P7, double dig_P8, double dig_P9, double t_fine) {
    double var1, var2, p;
    var1 = ((double)t_fine / 2.0) - 64000.0;
    var2 = var1 * var1 * ((double)dig_P6) / 32768.0;
    var2 = var2 + var1 * ((double)dig_P5) * 2.0;
    var2 = (var2 / 4.0) + (((double)dig_P4) * 65536.0);
    var1 = (((double)dig_P3) * var1 * var1 / 524288.0 + ((double)dig_P2) * var1) / 524288.0;
    var1 = (1.0 + var1 / 32768.0) * ((double)dig_P1);
    if (var1 == 0.0)
    {
        return 0; // avoid exception caused by division by zero
    }
    p = 1048576.0 - (double)adc_P;
    p = (p - (var2 / 4096.0)) * 6250.0 / var1;
    var1 = ((double)dig_P9) * p * p / 2147483648.0;
    var2 = p * ((double)dig_P8) / 32768.0;
    p = p + (var1 + var2 + ((double)dig_P7)) / 16.0;
    return p;
}

// Function to turn the LED on
void led_on(int pin) {
    digitalWrite(pin, HIGH);
}

// Function to turn the LED off
void led_off(int pin) {
    digitalWrite(pin, LOW);
}

// Function to calculate the average pressure from the last 10 readings in the buffer
double calculate_average_pressure(double buffer[], int size, int current_index) {
    double sum = 0.0;
    int count = 0;
    int i;
    int start_index = (current_index - 10 + size) % size; // Start from 10 readings back

    for (i = 0; i < 10; i++) {
        int index = (start_index + i) % size;
        if (buffer[index] != 0.0) { // Only include valid readings
            sum += buffer[index];
            count++;
        }
    }

    if (count > 0) {
        return sum / count;
    } else {
        return 0.0; // Return 0 if no valid readings
    }
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <softPwm.h>
#include <errno.h>

// Define the GPIO pins connected to the RGB LED
#define RED_PIN   0
#define GREEN_PIN 1
#define BLUE_PIN  2

// Define the PWM range (0-100)
#define PWM_RANGE 100

// Function prototypes
int initialize_leds(void);
int set_led_color(int red_intensity, int green_intensity, int blue_intensity);

/**
 * @brief Initializes the RGB LED pins using softPwm.
 *
 * @return 0 on success, -1 on failure.
 */
int initialize_leds(void) {
    if (softPwmCreate(RED_PIN, 0, PWM_RANGE) != 0) {
        fprintf(stderr, "Error creating softPwm for RED_PIN: %s\n", strerror(errno));
        return -1;
    }
    if (softPwmCreate(GREEN_PIN, 0, PWM_RANGE) != 0) {
        fprintf(stderr, "Error creating softPwm for GREEN_PIN: %s\n", strerror(errno));
        return -1;
    }
    if (softPwmCreate(BLUE_PIN, 0, PWM_RANGE) != 0) {
        fprintf(stderr, "Error creating softPwm for BLUE_PIN: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

/**
 * @brief Sets the color of the RGB LED.
 *
 * @param red_intensity   Intensity of the red component (0-100).
 * @param green_intensity Intensity of the green component (0-100).
 * @param blue_intensity  Intensity of the blue component (0-100).
 * @return 0 on success, -1 on failure (if intensity is out of range).
 */
int set_led_color(int red_intensity, int green_intensity, int blue_intensity) {
    if (red_intensity < 0 || red_intensity > PWM_RANGE ||
        green_intensity < 0 || green_intensity > PWM_RANGE ||
        blue_intensity < 0 || blue_intensity > PWM_RANGE) {
        fprintf(stderr, "Error: Color intensity values must be between 0 and %d\n", PWM_RANGE);
        return -1;
    }

    softPwmWrite(RED_PIN, red_intensity);
    softPwmWrite(GREEN_PIN, green_intensity);
    softPwmWrite(BLUE_PIN, blue_intensity);
    return 0;
}

int main(void) {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Initialize the RGB LED pins
    if (initialize_leds() != 0) {
        fprintf(stderr, "RGB LED initialization failed.\n");
        return 1;
    }

    // Main loop: cycle through different colors
    while (1) {
        printf("Red\n");
        if (set_led_color(100, 0, 0) != 0) return 1; // Red
        delay(500);

        printf("Green\n");
        if (set_led_color(0, 100, 0) != 0) return 1; // Green
        delay(500);

        printf("Blue\n");
        if (set_led_color(0, 0, 100) != 0) return 1;   // Blue
        delay(500);

        printf("Yellow\n");
        if (set_led_color(100, 100, 0) != 0) return 1; // Yellow
        delay(500);

        printf("Purple\n");
        if (set_led_color(100, 0, 100) != 0) return 1; // Purple
        delay(500);

        printf("Cyan\n");
        if (set_led_color(60, 100, 24) != 0) return 1;  // Cyan
        delay(500);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <time.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/spi/spidev.h>
#include <string.h>
#include <errno.h>

// Configuration
#define SPI_DEVICE "/dev/spidev0.0" // Change if your SPI device is different
#define SPI_MODE SPI_MODE_0
#define SPI_BITS_PER_WORD 8
#define SPI_SPEED 1000000       // 1 MHz
#define ANALOG_CHANNEL 0         // Assuming single-ended channel 0
#define LOG_FILE "sensor_log.txt"
#define WINDOW_SIZE 10           // Seconds

// Function to read from the SPI ADC
int read_adc(int spi_fd, int channel)
{
    uint8_t tx_buf[3];
    uint8_t rx_buf[3];
    struct spi_ioc_transfer transfer = {
        .tx_buf = (unsigned long)tx_buf,
        .rx_buf = (unsigned long)rx_buf,
        .len = 3,
        .speed_hz = SPI_SPEED,
        .bits_per_word = SPI_BITS_PER_WORD,
    };

    // Construct the transmit buffer.  Assuming MCP3008 or similar.
    tx_buf[0] = 0x01;                            // Start bit
    tx_buf[1] = (0x08 | (channel << 4)) << 4;    // Single-ended channel selection
    tx_buf[2] = 0x00;                            // Don't care

    if (ioctl(spi_fd, SPI_IOC_MESSAGE(1), &transfer) < 0) {
        perror("SPI transfer failed");
        return -1;
    }

    // Extract the ADC value from the receive buffer
    int adc_value = ((rx_buf[1] & 0x03) << 8) + rx_buf[2];
    return adc_value;
}

int main()
{
    int spi_fd, log_fd;
    time_t start_time, current_time;
    int adc_value;
    int min_value, max_value;
    char timestamp[30];
    struct tm *timeinfo;

    // Open the SPI device
    spi_fd = open(SPI_DEVICE, O_RDWR);
    if (spi_fd < 0) {
        perror("Failed to open SPI device");
        return 1;
    }

    // Configure SPI mode
    uint8_t mode = SPI_MODE;
    if (ioctl(spi_fd, SPI_IOC_WR_MODE, &mode) < 0) {
        perror("Failed to set SPI mode");
        close(spi_fd);
        return 1;
    }

    // Configure SPI bits per word
    uint8_t bits = SPI_BITS_PER_WORD;
    if (ioctl(spi_fd, SPI_IOC_WR_BITS_PER_WORD, &bits) < 0) {
        perror("Failed to set SPI bits per word");
        close(spi_fd);
        return 1;
    }

    // Configure SPI speed
    uint32_t speed = SPI_SPEED;
    if (ioctl(spi_fd, SPI_IOC_WR_MAX_SPEED_HZ, &speed) < 0) {
        perror("Failed to set SPI speed");
        close(spi_fd);
        return 1;
    }

    // Open the log file
    log_fd = open(LOG_FILE, O_WRONLY | O_CREAT | O_APPEND, 0644);
    if (log_fd < 0) {
        perror("Failed to open log file");
        close(spi_fd);
        return 1;
    }

    time(&start_time);
    min_value = 1024; // Initialize to maximum possible ADC value
    max_value = 0;

    while (1) {
        adc_value = read_adc(spi_fd, ANALOG_CHANNEL);
        if (adc_value < 0) {
            fprintf(stderr, "Error reading ADC, continuing...");
            continue; // Continue to next iteration
        }

        if (adc_value < min_value) {
            min_value = adc_value;
        }
        if (adc_value > max_value) {
            max_value = adc_value;
        }

        time(&current_time);
        if (difftime(current_time, start_time) >= WINDOW_SIZE) {
            // Get timestamp
            timeinfo = localtime(&start_time);
            strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

            // Log min/max values
            char log_message[100];
            snprintf(log_message, sizeof(log_message), "%s, Min: %d, Max: %d\n", timestamp, min_value, max_value);
            if (write(log_fd, log_message, strlen(log_message)) < 0) {
                perror("Failed to write to log file");
            }

            // Reset min/max values and start time
            min_value = 1024;
            max_value = 0;
            time(&start_time);
        }

        usleep(100000); // 100ms delay
    }

    // Cleanup (this will never be reached in the current loop)
    close(spi_fd);
    close(log_fd);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <stdint.h>
#include <string.h>
#include <fcntl.h>
#include <sys/mman.h>
#include <sys/stat.h>
#include <sys/types.h>
#include <errno.h>

// Base addresses for peripherals (adjust for different Raspberry Pi models)
static volatile uint32_t peripheralBase = 0xFE000000; // Default for Pi 4/5
static int isRaspberryPi2711 = 0;

// Register offsets
#define GPIO_OFFSET  0x00200000
#define SYST_OFFSET  0x00003000
#define BSCS_OFFSET  0x00214000

// Register lengths
#define GPIO_LENGTH  0xF4
#define SYST_LENGTH  0x1C
#define BSCS_LENGTH  0x40

// GPIO register offsets
#define GPFSEL0 0  // GPIO Function Select 0
#define GPSET0  7  // GPIO Pin Output Set 0
#define GPCLR0  10 // GPIO Pin Output Clear 0
#define GPLEV0  13 // GPIO Pin Level 0
#define GPPUD   37 // GPIO Pin Pull-up/down Enable
#define GPPUDCLK0 38 // GPIO Pin Pull-up/down Clock Enable 0

// BCM2711 Pull-up/down register offsets
#define GPPUPPDN0 57

// SYST register offsets
#define SYST_CS  0  // System Timer Control/Status
#define SYST_CLO 1  // System Timer Counter Lower 32 bits
#define SYST_CHI 2  // System Timer Counter Upper 32 bits

// Pointers to memory mapped registers
static volatile uint32_t *gpioRegisters = MAP_FAILED;
static volatile uint32_t *systRegisters = MAP_FAILED;
static volatile uint32_t *bscsRegisters = MAP_FAILED;

// Helper macros
#define GPIO_BANK(gpio) ((gpio) >> 5)
#define GPIO_BIT(gpio)  (1 << ((gpio) & 0x1F))

// GPIO modes
enum {
    GPIO_MODE_INPUT  = 0,
    GPIO_MODE_OUTPUT = 1,
    GPIO_MODE_ALT0   = 4,
    GPIO_MODE_ALT1   = 5,
    GPIO_MODE_ALT2   = 6,
    GPIO_MODE_ALT3   = 7,
    GPIO_MODE_ALT4   = 3,
    GPIO_MODE_ALT5   = 2
};

// Pull-up/down resistor options
enum {
    GPIO_PULL_OFF  = 0,
    GPIO_PULL_DOWN = 1,
    GPIO_PULL_UP   = 2
};

// Function to set the GPIO pin mode (input, output, alt function)
int gpioSetMode(unsigned int gpio, unsigned int mode) {
    if (gpio > 53 || mode > 7) {
        fprintf(stderr, "gpioSetMode: Invalid GPIO %u or mode %u\n", gpio, mode);
        return -1; // Indicate error
    }

    int registerIndex = gpio / 10;
    int shift = (gpio % 10) * 3;
    uint32_t mask = 0x7 << shift;
    uint32_t value = mode << shift;

    gpioRegisters[registerIndex] = (gpioRegisters[registerIndex] & ~mask) | value;
    return 0; // Indicate success
}

// Function to get the GPIO pin mode
int gpioGetMode(unsigned int gpio) {
    if (gpio > 53) {
        fprintf(stderr, "gpioGetMode: Invalid GPIO %u\n", gpio);
        return -1; //Indicate error
    }

    int registerIndex = gpio / 10;
    int shift = (gpio % 10) * 3;
    return (gpioRegisters[registerIndex] >> shift) & 0x7;
}

// Function to set the GPIO pin pull-up/down resistor
int gpioSetPullUpDown(unsigned int gpio, unsigned int pud) {
    if (gpio > 53 || pud > 2) {
        fprintf(stderr, "gpioSetPullUpDown: Invalid GPIO %u or pud %u\n", gpio, pud);
        return -1; // Indicate error
    }

    if (isRaspberryPi2711) {
        // BCM2711 uses different registers for pull-up/down control
        uint32_t pull = 0;
        switch (pud) {
            case GPIO_PULL_OFF:  pull = 0; break;
            case GPIO_PULL_UP:   pull = 1; break;
            case GPIO_PULL_DOWN: pull = 2; break;
            default: return -1;
        }

        int shift = (gpio & 0xf) << 1;
        uint32_t bits = gpioRegisters[GPPUPPDN0 + (gpio >> 4)];
        bits &= ~(3 << shift);
        bits |= (pull << shift);
        gpioRegisters[GPPUPPDN0 + (gpio >> 4)] = bits;
    } else {
        // Older Raspberry Pi models
        gpioRegisters[GPPUD] = pud;
        usleep(20); // Wait for 20 microseconds
        gpioRegisters[GPPUDCLK0 + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
        usleep(20); // Wait for 20 microseconds
        gpioRegisters[GPPUD] = 0;
        gpioRegisters[GPPUDCLK0 + GPIO_BANK(gpio)] = 0;
    }
    return 0; // Indicate success
}

// Function to read the level of a GPIO pin
int gpioRead(unsigned int gpio) {
    if (gpio > 53) {
        fprintf(stderr, "gpioRead: Invalid GPIO %u\n", gpio);
        return -1; // Indicate error
    }

    return (gpioRegisters[GPLEV0 + GPIO_BANK(gpio)] & GPIO_BIT(gpio)) ? 1 : 0;
}

// Function to write a value to a GPIO pin
int gpioWrite(unsigned int gpio, unsigned int level) {
    if (gpio > 53 || level > 1) {
        fprintf(stderr, "gpioWrite: Invalid GPIO %u or level %u\n", gpio, level);
        return -1; // Indicate error
    }

    if (level == 0) {
        gpioRegisters[GPCLR0 + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
    } else {
        gpioRegisters[GPSET0 + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
    }
    return 0; // Indicate success
}

// Function to trigger a GPIO pin with a pulse
int gpioTrigger(unsigned int gpio, unsigned int pulseLengthUs, unsigned int level) {
    if (gpio > 53 || level > 1) {
        fprintf(stderr, "gpioTrigger: Invalid GPIO %u or level %u\n", gpio, level);
        return -1; // Indicate error
    }

    if (level == 0) {
        gpioRegisters[GPCLR0 + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
    } else {
        gpioRegisters[GPSET0 + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
    }

    usleep(pulseLengthUs);

    if (level == 0) {
        gpioRegisters[GPSET0 + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
    } else {
        gpioRegisters[GPCLR0 + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
    }
    return 0; // Indicate success
}

// Function to read the system timer (microseconds since boot)
uint32_t gpioTick(void) {
    return systRegisters[SYST_CLO];
}

// Function to map physical memory into virtual memory
static uint32_t *mapPeripheral(int fileDescriptor, uint32_t physicalAddress, uint32_t length) {
    uint32_t *virtualAddress = (uint32_t *)mmap(NULL, length, PROT_READ | PROT_WRITE, MAP_SHARED, fileDescriptor, physicalAddress);
    if (virtualAddress == MAP_FAILED) {
        fprintf(stderr, "Memory mapping failed at address 0x%X with length 0x%X: %s\n", physicalAddress, length, strerror(errno));
        return MAP_FAILED;
    }
    return virtualAddress;
}

// Function to initialize the GPIO library
int gpioInitialise(void) {
    int fileDescriptor = open("/dev/mem", O_RDWR | O_SYNC);
    if (fileDescriptor < 0) {
        fprintf(stderr, "Failed to open /dev/mem: %s\n", strerror(errno));
        fprintf(stderr, "This program requires root privileges.  Try using sudo.\n");
        return -1;
    }

    // Determine Raspberry Pi hardware revision and peripheral base address
    FILE *cpuinfo = fopen("/proc/cpuinfo", "r");
    if (cpuinfo != NULL) {
        char line[256];
        while (fgets(line, sizeof(line), cpuinfo)) {
            if (strstr(line, "Revision")) {
                unsigned int revision;
                if (sscanf(line, "Revision\t: %x", &revision) == 1) {
                    // Basic check for Pi 4/5 (more robust checks might be needed)
                    if ((revision & 0x10) == 0x10) {
                        peripheralBase = 0xFE000000; // Confirmed for Pi4/5
                    } else {
                        peripheralBase = 0x3F000000; // Older Pis
                    }
                    break;
                }
            }
        }
        fclose(cpuinfo);
    } else {
        perror("Failed to open /proc/cpuinfo");
        close(fileDescriptor);
        return -1;
    }

    // Map the GPIO, System Timer, and BSC registers into memory
    gpioRegisters = mapPeripheral(fileDescriptor, peripheralBase + GPIO_OFFSET, GPIO_LENGTH);
    systRegisters = mapPeripheral(fileDescriptor, peripheralBase + SYST_OFFSET, SYST_LENGTH);
    bscsRegisters = mapPeripheral(fileDescriptor, peripheralBase + BSCS_OFFSET, BSCS_LENGTH);

    close(fileDescriptor);

    // Check if any of the memory mappings failed
    if (gpioRegisters == MAP_FAILED || systRegisters == MAP_FAILED || bscsRegisters == MAP_FAILED) {
        fprintf(stderr, "One or more memory mappings failed.\n");
        //Unmap any successfully mapped memory
        if (gpioRegisters != MAP_FAILED) munmap((void*)gpioRegisters, GPIO_LENGTH);
        if (systRegisters != MAP_FAILED) munmap((void*)systRegisters, SYST_LENGTH);
        if (bscsRegisters != MAP_FAILED) munmap((void*)bscsRegisters, BSCS_LENGTH);

        return -1;
    }

    return 0;
}

// Function to de-initialize the GPIO library and unmap memory
void gpioTerminate(void) {
    if (gpioRegisters != MAP_FAILED) {
        if (munmap((void*)gpioRegisters, GPIO_LENGTH) != 0) {
            perror("Failed to unmap GPIO memory");
        }
        gpioRegisters = MAP_FAILED; // Set to MAP_FAILED to prevent further access
    }
    if (systRegisters != MAP_FAILED) {
        if (munmap((void*)systRegisters, SYST_LENGTH) != 0) {
            perror("Failed to unmap System Timer memory");
        }
        systRegisters = MAP_FAILED;
    }
    if (bscsRegisters != MAP_FAILED) {
        if (munmap((void*)bscsRegisters, BSCS_LENGTH) != 0) {
            perror("Failed to unmap BSC memory");
        }
        bscsRegisters = MAP_FAILED;
    }
}

int main(int argc, char *argv[]) {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "GPIO initialization failed.\n");
        return 1;
    }

    // Example usage: Read and print the state of GPIO pins 0-53
    for (int i = 0; i < 54; i++) {
        int mode = gpioGetMode(i);
        int level = gpioRead(i);
        if (mode == -1 || level == -1) {
            fprintf(stderr, "Error reading GPIO %d, skipping.\n", i);
            continue;
        }
        printf("GPIO %d: Mode = %d, Level = %d, Tick = %u\n", i, mode, level, gpioTick());
    }

    // Example usage: Print the values of the first 16 BSC registers
    for (int i = 0; i < 16; i++) {
        printf("BSC Register %d: Value = 0x%08X\n", i, bscsRegisters[i]);
    }

    gpioTerminate(); // Unmap memory before exiting
    return 0;
}

#include <pigpio.h>
