// Callback function for echo pin
void echo_callback(int gpio, int level, uint32_t tick) {
    if (gpio == ECHO_PIN) {
        if (level == 1) { // Rising edge
            echo_start_time = tick;
            echo_received = 0; // Reset flag for new reading
        } else if (level == 0) { // Falling edge
            echo_end_time = tick;
            echo_received = 1; // Set flag to indicate echo received
        } else {
            fprintf(stderr, "Error: Invalid level in echo_callback\n");
        }
    }
}

// Function to get distance from ultrasonic sensor
float getDistance() {
    echo_start_time = 0;
    echo_end_time = 0;
    echo_received = 0;

    // Trigger the sensor
    gpioWrite(TRIGGER_PIN, 1);
    gpioDelay(10); // 10 us trigger pulse
    gpioWrite(TRIGGER_PIN, 0);

    // Measure echo pulse width
    time_t start_time = time(NULL);
    while (!echo_received) {
        if (time(NULL) - start_time > 1) { // 1 second timeout
            fprintf(stderr, "Error: Timeout waiting for echo\n");
            return -1.0; // Indicate error
        }
        gpioDelay(10);
    }

    if (echo_start_time == 0 || echo_end_time == 0) {
        fprintf(stderr, "Error: Missing echo start or end time\n");
        return -1.0;
    }

    uint32_t pulse_width = echo_end_time - echo_start_time;
    float distance = (float)pulse_width * SPEED_OF_SOUND / 2000000.0; // Convert us to s and divide by 2

    return distance;
}

// Function to map distance to frequency
unsigned int mapDistanceToFrequency(float distance) {
    unsigned int frequency;

    // Clamp distance to the defined range
    if (distance < MIN_DISTANCE) {
        distance = MIN_DISTANCE;
    } else if (distance > MAX_DISTANCE) {
        distance = MAX_DISTANCE;
    }

    // Linear mapping
    frequency = (unsigned int)((MAX_FREQUENCY - MIN_FREQUENCY) * (1.0 - (distance - MIN_DISTANCE) / (MAX_DISTANCE - MIN_DISTANCE)) + MIN_FREQUENCY);

    return frequency;
}

// Function to set buzzer frequency
void setBuzzerFrequency(unsigned int frequency) {
    gpioPWM(BUZZER_PIN, 128); // 50% duty cycle
    gpioSetPWMfrequency(BUZZER_PIN, frequency);
}

// Cleanup function
void cleanup() {
    gpioTerminate();
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1; // Exit with error code
    }
    atexit(cleanup);

    // Configure GPIO pins
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);

    // Set PWM range and frequency (optional, can be adjusted)
    gpioSetPWMrange(BUZZER_PIN, 200); // Adjust range for finer control
    gpioSetPWMfrequency(BUZZER_PIN, 500); // Initial frequency

    // Set up alert function for echo pin
    if (gpioSetAlertFuncEx(ECHO_PIN, echo_callback, NULL) != 0) {
      fprintf(stderr, "Error setting alert function for ECHO_PIN\n");
      return 1;
    }

    // Main loop
    while (1) {
        // Get distance from ultrasonic sensor
        float distance = getDistance();

        // Check for errors
        if (distance < 0) {
            fprintf(stderr, "Error: Failed to read distance\n");
            gpioDelay(50000); //50ms delay
            continue; // Skip to the next iteration
        }

        // Map distance to frequency
        unsigned int frequency = mapDistanceToFrequency(distance);

        // Set buzzer frequency
        setBuzzerFrequency(frequency);

        // Delay
        gpioDelay(50000); // 50 ms
    }

    return 0;
}

