#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Define GPIO pins
#define FAN_PIN 18
#define SPI_CLK 21
#define SPI_CS 20
#define SPI_DO 19

// Define PWM frequency
#define PWM_FREQUENCY 100

// Define temperature thresholds and duty cycles
#define TEMP_LOW 40.0
#define TEMP_MED 60.0
#define DUTY_LOW 0
#define DUTY_MED 50
#define DUTY_HIGH 100

// Define error value
#define ERROR_TEMP -273.15

// Define SPI channel
#define SPI_CHANNEL 0

// Define SPI flags (adjust as needed, e.g., SPI_MODE_0)
#define SPI_FLAGS 0 //SPI_MODE_0

// Global variables for SPI handle and log file
int spi_handle = -1;
FILE *log_file = NULL;

// Function prototypes
unsigned int spi_read_max31855();
float process_temperature_data(unsigned int raw_data);
void control_fan_speed(float temperature);
void log_data(float temperature, int fan_speed);
void signal_handler(int signal);

// Function to read data from MAX31855 via SPI
unsigned int spi_read_max31855() {
    char rx_buffer[4];
    int status;

    status = spiRead(spi_handle, rx_buffer, 4);
    if (status != 4) {
        fprintf(stderr, "SPI read error: %d\n", status);
        log_data(ERROR_TEMP, -1); // Log the error
        return 0xFFFFFFFF; // Return an error value
    }

    unsigned int raw_data = (rx_buffer[0] << 24) | (rx_buffer[1] << 16) | (rx_buffer[2] << 8) | rx_buffer[3];
    return raw_data;
}

// Function to process raw temperature data and convert to Celsius
float process_temperature_data(unsigned int raw_data) {
    // Check for fault bits
    if (raw_data & 0x00000007) {
        fprintf(stderr, "MAX31855 Fault: %X\n", raw_data & 0x00000007);
        log_data(ERROR_TEMP, -1);
        return ERROR_TEMP;
    }

    // Check for thermocouple not connected
    if (raw_data & 0x00010000) {
        fprintf(stderr, "Thermocouple not connected\n");
        log_data(ERROR_TEMP, -1);
        return ERROR_TEMP;
    }

    // Extract temperature data (bits 18-31, signed 14-bit value)
    int16_t temp_raw = (raw_data >> 18) & 0x3FFF; // Extract the temp bits

    // Sign extend if negative
    if (temp_raw & 0x2000) {
        temp_raw |= 0xC000; // Sign extend to 16 bits
    }

    float temperature = (float)temp_raw / 4.0; // Each LSB is 0.25 degrees C

    return temperature;
}

// Function to control fan speed based on temperature
void control_fan_speed(float temperature) {
    int duty_cycle;

    if (temperature < TEMP_LOW) {
        duty_cycle = DUTY_LOW;
    } else if (temperature < TEMP_MED) {
        duty_cycle = DUTY_MED;
    } else {
        duty_cycle = DUTY_HIGH;
    }

    gpioPWM(FAN_PIN, duty_cycle); // Set the PWM duty cycle
}

// Function to log data to a file
void log_data(float temperature, int fan_speed) {
    if (log_file == NULL) {
        fprintf(stderr, "Log file not initialized.\n");
        return;
    }

    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    if (temperature == ERROR_TEMP){
        fprintf(log_file, "%d-%02d-%02d %02d:%02d:%02d, Error: Check thermocouple or SPI communication, Fan Speed: %d%%\n",
            t->tm_year + 1900, t->tm_mon + 1, t->tm_mday, t->tm_hour, t->tm_min, t->tm_sec, fan_speed);
    } else {
    fprintf(log_file, "%d-%02d-%02d %02d:%02d:%02d, Temperature: %.2f°C, Fan Speed: %d%%\n",
            t->tm_year + 1900, t->tm_mon + 1, t->tm_mday, t->tm_hour, t->tm_min, t->tm_sec, temperature, fan_speed);
    }
    fflush(log_file); // Ensure data is written to disk
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, shutting down...\n", signal);
    if (spi_handle >= 0) {
        spiClose(spi_handle);
    }
    gpioPWM(FAN_PIN, 0); // Stop the fan
    if (log_file != NULL) {
        fclose(log_file);
    }
    gpioTerminate();
    exit(0);
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open SPI channel
    spi_handle = spiOpen(SPI_CHANNEL, 1000000, SPI_FLAGS); // Adjust baud rate as needed
    if (spi_handle < 0) {
        fprintf(stderr, "SPI open failed\n");
        gpioTerminate();
        return 1;
    }

    // Set PWM frequency for the fan pin
    gpioSetPWMfrequency(FAN_PIN, PWM_FREQUENCY);
    gpioSetPWMrange(FAN_PIN, 100); // Set PWM range to 100 for percentage control

    // Open log file
    log_file = fopen("cooling_log.txt", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        spiClose(spi_handle);
        gpioTerminate();
        return 1;
    }

    // Register signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Main loop
    while (1) {
        // Read temperature data
        unsigned int raw_data = spi_read_max31855();
        float temperature = process_temperature_data(raw_data);

        // Control fan speed
        control_fan_speed(temperature);

        // Log data
        log_data(temperature, gpioGetPWMdutycycle(FAN_PIN));

        // Delay for 1 second
        time_sleep(1.0);
    }

    return 0;
}

#include <pigpio.h>
