#include <stdio.h>
#include <wiringPi.h>
#include <softPwm.h>

#define BUZZER_PIN 1 // WiringPi GPIO 1, BCM GPIO 18

// Frequencies for Do, Re, Mi (approximate)
#define DO 262
#define RE 294
#define MI 330

// Function to play a tone
void playTone(int frequency, int duration) {
  if (frequency == 0) {
    softPwmWrite(BUZZER_PIN, 0); // Turn off buzzer for silence
    delay(duration);
  } else {
    int period = 1000000 / frequency; // Period in microseconds
    int halfPeriod = period / 2;

    for (long i = 0; i < duration * 1000L; i += period) {
      softPwmWrite(BUZZER_PIN, 50);  // High
      delayMicroseconds(halfPeriod);
      softPwmWrite(BUZZER_PIN, 0);   // Low
      delayMicroseconds(halfPeriod);
    }
  }
}

int main(void) {
  wiringPiSetup();

  // Initialize softPwm on the buzzer pin
  softPwmCreate(BUZZER_PIN, 0, 100); // Range 0-100

  // Do Re Mi
  playTone(DO, 500);
  delay(100);
  playTone(RE, 500);
  delay(100);
  playTone(MI, 500);
  delay(100);

  //cleanup
  softPwmWrite(BUZZER_PIN,0);

  return 0;
}

#include <pigpio.h>
