// Define GPIO pins for each segment (a-g) of the seven-segment display
#define SEG_A 4
#define SEG_B 17
#define SEG_C 27
#define SEG_D 22
#define SEG_E 5
#define SEG_F 6
#define SEG_G 13

// Function to display a number on the seven-segment display
void display_number(int number) {
    // Turn off all segments initially
    gpioWrite(SEG_A, 0);
    gpioWrite(SEG_B, 0);
    gpioWrite(SEG_C, 0);
    gpioWrite(SEG_D, 0);
    gpioWrite(SEG_E, 0);
    gpioWrite(SEG_F, 0);
    gpioWrite(SEG_G, 0);

    switch (number) {
        case 0:
            gpioWrite(SEG_A, 1);
            gpioWrite(SEG_B, 1);
            gpioWrite(SEG_C, 1);
            gpioWrite(SEG_D, 1);
            gpioWrite(SEG_E, 1);
            gpioWrite(SEG_F, 1);
            break;
        case 1:
            gpioWrite(SEG_B, 1);
            gpioWrite(SEG_C, 1);
            break;
        case 2:
            gpioWrite(SEG_A, 1);
            gpioWrite(SEG_B, 1);
            gpioWrite(SEG_D, 1);
            gpioWrite(SEG_E, 1);
            gpioWrite(SEG_G, 1);
            break;
        case 3:
            gpioWrite(SEG_A, 1);
            gpioWrite(SEG_B, 1);
            gpioWrite(SEG_C, 1);
            gpioWrite(SEG_D, 1);
            gpioWrite(SEG_G, 1);
            break;
        case 4:
