#include <wiringPi.h>

// Constants for GPIO pins
#define OUTPUT_PIN 0  // WiringPi pin 0 (GPIO17)
#define INPUT_PIN 1   // WiringPi pin 1 (GPIO18)

// Global variables
static volatile unsigned int interrupt_count = 0; // Counter for interrupts
static volatile sig_atomic_t program_running = 1; // Flag to control the main loop

// Function prototypes
void interrupt_handler(void);
void signal_handler(int signal);

// Interrupt handler function
void interrupt_handler(void) {
    // This function is called when a falling edge is detected on the input pin.
    digitalWrite(OUTPUT_PIN, HIGH); // Set output pin HIGH
    interrupt_count++;                 // Increment interrupt counter
    digitalWrite(OUTPUT_PIN, LOW);  // Set output pin LOW
}

// Signal handler function (for graceful shutdown)
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("\nCaught SIGINT, exiting gracefully.\n");
        program_running = 0; // Set the flag to exit the main loop
    }
}

int main(void) {
    unsigned int current_count = 0;
    unsigned int last_count = 0;
    unsigned int count_delta = 0;

    // Initialize WiringPi
    if (wiringPiSetup() < 0) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return 1;
    }

    // Set GPIO pin modes
    pinMode(OUTPUT_PIN, OUTPUT);
    pinMode(INPUT_PIN, INPUT);
    pullUpDnControl(INPUT_PIN, PUD_UP); // Enable pull-up resistor on the input pin

    // Register the interrupt handler
    if (wiringPiISR(INPUT_PIN, INT_EDGE_FALLING, &interrupt_handler) < 0) {
        fprintf(stderr, "Interrupt setup failed: %s\n", strerror(errno));
        return 1;
    }

    // Set up signal handling for Ctrl+C (SIGINT)
    signal(SIGINT, signal_handler);

    printf("Interrupt-driven GPIO toggling started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        printf("Waiting for interrupts...\n");
        delay(1000); // Wait for 1 second

        current_count = interrupt_count;
        count_delta = current_count - last_count;

        printf("Interrupt count: %u, Interrupts/second: %u\n", current_count, count_delta);

        last_count = current_count;
    }

    printf("Program terminated.\n");
    return 0;
}

