#include <bcm2835.h>
#include <pigpio.h>

// Define MPU6050 I2C address
#define MPU6050_ADDR 0x68

// Define MPU6050 register addresses
#define MPU6050_ACCEL_XOUT_H 0x3B
#define MPU6050_PWR_MGMT_1 0x6B

// Define LED GPIO pin
#define LED_PIN 17

// Define timer interval (in milliseconds)
#define TIMER_INTERVAL 10

// Define acceleration threshold (in g)
#define ACCEL_THRESHOLD 1.5

// Define LED activation duration (in milliseconds)
#define LED_DURATION 250

// Global variables for signal handling
volatile sig_atomic_t terminate = 0;

// Function prototypes
int init_i2c();
int init_gpio();
int read_accel_data(float *x, float *y, float *z);
float calculate_magnitude(float x, float y, float z);
void alert_callback(int gpio, int level, uint32_t tick, void *user);
void signal_handler(int signal);
void cleanup();

int i2c_read_data(uint8_t reg, uint8_t *data, uint8_t len);
int i2c_write_data(uint8_t reg, uint8_t value);

int main(int argc, char **argv)
{
    // Register signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize bcm2835 library
    if (!bcm2835_init()) {
        fprintf(stderr, "bcm2835_init failed. Are you running as root?\n");
        return 1;
    }

    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        bcm2835_close();
        return 1;
    }

    // Initialize I2C
    if (init_i2c() != 0) {
        fprintf(stderr, "I2C initialization failed\n");
        gpioTerminate();
        bcm2835_close();
        return 1;
    }

    // Initialize GPIO
    if (init_gpio() != 0) {
        fprintf(stderr, "GPIO initialization failed\n");
        bcm2835_i2c_end();
        gpioTerminate();
        bcm2835_close();
        return 1;
    }

    // Register the alert callback function
    if (gpioSetAlertFuncEx(LED_PIN, alert_callback, NULL) != 0) {
        fprintf(stderr, "Failed to set alert function\n");
        bcm2835_i2c_end();
        gpioTerminate();
        bcm2835_close();
        return 1;
    }

    // Main loop (sleep until a signal is received)
    while (!terminate) {
        gpioDelay(100); // Sleep for 100ms to avoid busy-waiting
    }

    // Cleanup and exit
    cleanup();

    return 0;
}

// Initialize I2C communication
int init_i2c()
{
    bcm2835_i2c_begin();
    bcm2835_i2c_setClockDivider(BCM2835_I2C_CLOCK_DIVIDER_626); // 100kHz
    bcm2835_i2c_setSlaveAddress(MPU6050_ADDR);

    // Wake up the MPU6050 (clear sleep mode bit)
    if (i2c_write_data(MPU6050_PWR_MGMT_1, 0) != 0) {
        fprintf(stderr, "Failed to wake up MPU6050\n");
        return -1;
    }

    return 0;
}

// Initialize GPIO pin for LED control
int init_gpio()
{
    gpioSetMode(LED_PIN, PI_OUTPUT);
    gpioWrite(LED_PIN, PI_OFF); // Turn off LED initially
    return 0;
}

// Read accelerometer data from MPU6050
int read_accel_data(float *x, float *y, float *z)
{
    uint8_t raw_data[6];
    int16_t accel_x, accel_y, accel_z;
    int retries = 3; // Number of retries

    while (retries > 0) {
        if (i2c_read_data(MPU6050_ACCEL_XOUT_H, raw_data, 6) == 0) {
            // Combine high and low bytes
            accel_x = (raw_data[0] << 8) | raw_data[1];
            accel_y = (raw_data[2] << 8) | raw_data[3];
            accel_z = (raw_data[4] << 8) | raw_data[5];

            // Convert to g-force units (assuming +/- 2g sensitivity)
            *x = (float)accel_x / 16384.0f;
            *y = (float)accel_y / 16384.0f;
            *z = (float)accel_z / 16384.0f;

            return 0; // Success
        } else {
            perror("I2C read error");
            bcm2835_delay(100); // Wait before retrying
            retries--;
        }
    }

    fprintf(stderr, "Failed to read accelerometer data after multiple retries\n");
    return -1; // Failure
}

// Calculate the magnitude of the acceleration vector
float calculate_magnitude(float x, float y, float z)
{
    return sqrt(x * x + y * y + z * z);
}

// Alert callback function (triggered by pigpio timer)
void alert_callback(int gpio, int level, uint32_t tick, void *user)
{
    float x, y, z, magnitude;

    // Read accelerometer data
    if (read_accel_data(&x, &y, &z) == 0) {
        // Calculate acceleration magnitude
        magnitude = calculate_magnitude(x, y, z);

        // Check if acceleration exceeds threshold
        if (magnitude > ACCEL_THRESHOLD) {
            // Activate LED
            gpioWrite(LED_PIN, PI_ON);
            gpioDelay(LED_DURATION);
            gpioWrite(LED_PIN, PI_OFF);
        }
    }
}

// Signal handler function
void signal_handler(int signal)
{
    printf("Received signal %d, terminating...\n", signal);
    terminate = 1;
}

// Cleanup function
void cleanup()
{
    // Disable the alert function
    gpioSetAlertFuncEx(LED_PIN, NULL, NULL);

    // Turn off the LED
    gpioWrite(LED_PIN, PI_OFF);

    // Close I2C connection
    bcm2835_i2c_end();

    // Close bcm2835 library
    bcm2835_close();

    // Terminate pigpio library
    gpioTerminate();

    printf("Cleanup complete. Exiting.\n");
}

// Helper function to read data over I2C
int i2c_read_data(uint8_t reg, uint8_t *data, uint8_t len)
{
    char reg_addr = (char)reg;

    bcm2835_i2c_write(&reg_addr, 1); // Write the register address
    int result = bcm2835_i2c_read((char *)data, len); // Read the data

    if (result != BCM2835_I2C_REASON_OK) {
        fprintf(stderr, "I2C read failed: %d\n", result);
        return -1;
    }

    return 0;
}

// Helper function to write data over I2C
int i2c_write_data(uint8_t reg, uint8_t value)
{
    char data[2];
    data[0] = (char)reg;
    data[1] = (char)value;

    int result = bcm2835_i2c_write(data, 2);

    if (result != BCM2835_I2C_REASON_OK) {
        fprintf(stderr, "I2C write failed: %d\n", result);
        return -1;
    }

    return 0;
}

