// Constants
#define I2C_DEVICE "/dev/i2c-1"
#define SHT31_ADDRESS 0x44
#define MEASURE_COMMAND 0x2400
#define GPIO_CHIP "gpiochip0"
#define GPIO_PIN 17
#define HUMIDITY_THRESHOLD_HIGH 60.0
#define HUMIDITY_THRESHOLD_LOW 55.0
#define SLEEP_DURATION 60 // seconds
