// Global variables
static int running = 1;
static int log_fd = -1; // File descriptor for the log file
static struct gpiod_chip *gpio_chip = NULL;
static struct gpiod_line *gpio_line = NULL;

// CRC-8-ATM checksum function
unsigned char crc8(const unsigned char *data, int len) {
    unsigned char crc = 0xFF;
    for (int i = 0; i < len; i++) {
        crc ^= data[i];
        for (int j = 0; j < 8; j++) {
            if (crc & 0x80) {
                crc = (crc << 1) ^ 0x31;
            } else {
                crc <<= 1;
            }
        }
    }
    return crc;
}

// Function to read humidity from SHT31 sensor
float read_sht31_humidity() {
    int fd;
    unsigned char buffer[6];
    unsigned short raw_humidity;
    float humidity;

    // Open I2C device
    fd = open(I2C_DEVICE, O_RDWR);
    if (fd < 0) {
        perror("Error opening I2C device");
        return -1.0;
    }

    // Set I2C slave address
    if (ioctl(fd, I2C_SLAVE, SHT31_ADDRESS) < 0) {
        perror("Error setting I2C slave address");
        close(fd);
        return -1.0;
    }

    // Send measurement command
    unsigned char command[2];
    command[0] = (MEASURE_COMMAND >> 8) & 0xFF;
    command[1] = MEASURE_COMMAND & 0xFF;
    if (write(fd, command, 2) != 2) {
        perror("Error writing to I2C device");
        close(fd);
        return -1.0;
    }

    // Wait for measurement to complete (at least 10 ms)
    struct timespec delay;
    delay.tv_sec = 0;
    delay.tv_nsec = 10000000; // 10 ms
    nanosleep(&delay, NULL);

    // Read 6 bytes from sensor
    if (read(fd, buffer, 6) != 6) {
        perror("Error reading from I2C device");
        close(fd);
        return -1.0;
    }

    close(fd);

    // Validate humidity checksum
    if (crc8(buffer + 2, 1) != buffer[3]) {
        fprintf(stderr, "Humidity checksum error\n");
        return -1.0;
    }

    // Convert raw humidity to percentage
    raw_humidity = (buffer[2] << 8) | buffer[3];
    humidity = -6.0 + 125.0 * (raw_humidity / 65535.0);

    return humidity;
}

// Function to turn on the dehumidifier
int dehumidifier_on() {
    int ret = 0;
    // Open GPIO chip
    gpio_chip = gpiod_chip_open_by_name(GPIO_CHIP);
    if (!gpio_chip) {
        perror("Error opening GPIO chip");
        return -1;
    }

    // Get GPIO line
    gpio_line = gpiod_chip_get_line(gpio_chip, GPIO_PIN);
    if (!gpio_line) {
        perror("Error getting GPIO line");
        gpiod_chip_close(gpio_chip);
        return -1;
    }

    // Request GPIO line for output
    ret = gpiod_line_request_output(gpio_line, "dehumidifier", 1); // Initial value HIGH
    if (ret < 0) {
        perror("Error requesting GPIO line for output");
        gpiod_chip_close(gpio_chip);
        gpiod_line_release(gpio_line);
        return -1;
    }

    // Set GPIO line value to HIGH (turn on relay)
    ret = gpiod_line_set_value(gpio_line, 1);
    if (ret < 0) {
        perror("Error setting GPIO line value");
        gpiod_line_release(gpio_line);
        gpiod_chip_close(gpio_chip);
        return -1;
    }

    return 0;
}

// Function to turn off the dehumidifier
int dehumidifier_off() {
    int ret = 0;
    // Open GPIO chip
    gpio_chip = gpiod_chip_open_by_name(GPIO_CHIP);
    if (!gpio_chip) {
        perror("Error opening GPIO chip");
        return -1;
    }

    // Get GPIO line
    gpio_line = gpiod_chip_get_line(gpio_chip, GPIO_PIN);
    if (!gpio_line) {
        perror("Error getting GPIO line");
        gpiod_chip_close(gpio_chip);
        return -1;
    }

    // Request GPIO line for output
    ret = gpiod_line_request_output(gpio_line, "dehumidifier", 0); // Initial value LOW
    if (ret < 0) {
        perror("Error requesting GPIO line for output");
        gpiod_chip_close(gpio_chip);
        gpiod_line_release(gpio_line);
        return -1;
    }

    // Set GPIO line value to LOW (turn off relay)
    ret = gpiod_line_set_value(gpio_line, 0);
    if (ret < 0) {
        perror("Error setting GPIO line value");
        gpiod_line_release(gpio_line);
        gpiod_chip_close(gpio_chip);
        return -1;
    }
    return 0;
}

// Function to log data to file
void log_data(float humidity, int dehumidifier_state) {
    time_t now;
    struct tm *timeinfo;
    char timestamp[20];

    // Get current time
    time(&now);
    timeinfo = localtime(&now);
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    // Open log file for appending
    if (log_fd == -1) {
        log_fd = open(LOG_FILE, O_WRONLY | O_APPEND | O_CREAT, 0644);
        if (log_fd == -1) {
            perror("Error opening log file");
            return;
        }
    }

    // Write log entry
    char log_entry[256];
    snprintf(log_entry, sizeof(log_entry), "%s - Humidity: %.2f%%, Dehumidifier: %s\n",
             timestamp, humidity, dehumidifier_state ? "ON" : "OFF");
    if (write(log_fd, log_entry, strlen(log_entry)) == -1) {
        perror("Error writing to log file");
    }

    fsync(log_fd); // Ensure data is written to disk
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Received signal %d, shutting down...\n", signal);
    running = 0;

    // Turn off dehumidifier
    if (gpio_line != NULL && gpio_chip != NULL) {
        dehumidifier_off();
        gpiod_line_release(gpio_line);
        gpiod_chip_close(gpio_chip);
    }

    // Close log file
    if (log_fd != -1) {
        close(log_fd);
    }

    exit(0);
}

