#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <signal.h>
#include <unistd.h>

// Constants
#define I2C_BUS 1
#define I2C_ADDRESS 0x20
#define PUMP_GPIO 17
#define MOISTURE_THRESHOLD 30
#define PUMP_RUNTIME_LIMIT_MS 10000 // 10 seconds
#define SENSOR_READ_DELAY_MS 5000   // 5 seconds
#define MOISTURE_ERROR_VALUE -1

// Global variables (volatile for signal handling)
volatile int running = 1;
int i2c_handle;

// Function prototypes
int readSoilMoisture();
int processSoilMoisture(int rawValue);
void controlPump(int moisturePercentage);
void signalHandler(int signal);

// Signal handler for graceful shutdown
void signalHandler(int signal) {
    if (signal == SIGINT) {
        fprintf(stderr, "\nCaught SIGINT, shutting down gracefully...\n");
        running = 0;

        // Turn off the pump
        gpioWrite(PUMP_GPIO, 0);

        // Close the I2C interface
        i2cClose(i2c_handle);

        // Terminate the pigpio library
        gpioTerminate();

        exit(0);
    }
}

// Reads the soil moisture value from the sensor
int readSoilMoisture() {
    int rawValue;

    rawValue = i2cReadWordData(i2c_handle, 0); // Assuming register 0 holds the moisture value

    if (rawValue < 0) {
        fprintf(stderr, "Error reading soil moisture: %d\n", rawValue);
        return MOISTURE_ERROR_VALUE; // Indicate an error
    }

    return rawValue;
}

// Converts the raw sensor value to a percentage
int processSoilMoisture(int rawValue) {
    if (rawValue == MOISTURE_ERROR_VALUE) {
        return -1; // Propagate the error
    }

    // Assuming rawValue ranges from 0 (dry) to 1000 (saturated)
    double percentage = 100.0 - ((double)rawValue / 1000.0) * 100.0; // Inverted scale

    // Bounds checking
    if (percentage < 0.0) {
        percentage = 0.0;
    } else if (percentage > 100.0) {
        percentage = 100.0;
    }

    return (int)percentage;
}

// Controls the water pump based on the moisture percentage
void controlPump(int moisturePercentage) {
    if (moisturePercentage < 0) {
        fprintf(stderr, "Invalid moisture percentage, pump control skipped.\n");
        return; // Don't activate the pump with invalid data
    }

    if (moisturePercentage < MOISTURE_THRESHOLD) {
        fprintf(stderr, "Moisture level below threshold (%d%%), activating pump.\n", moisturePercentage);
        gpioWrite(PUMP_GPIO, 1); // Turn pump ON
        gpioDelay(PUMP_RUNTIME_LIMIT_MS);
        gpioWrite(PUMP_GPIO, 0); // Turn pump OFF after runtime limit
        fprintf(stderr, "Pump deactivated after runtime limit.\n");
    } else {
        gpioWrite(PUMP_GPIO, 0); // Ensure pump is OFF
    }
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Configure GPIO17 as output (pump control)
    gpioSetMode(PUMP_GPIO, PI_OUTPUT);
    gpioWrite(PUMP_GPIO, 0); // Initially OFF

    // Initialize I2C interface
    i2c_handle = i2cOpen(I2C_BUS, I2C_ADDRESS, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signalHandler);

    fprintf(stderr, "Soil moisture monitoring and pump control started. Press Ctrl+C to exit.\n");

    // Main loop
    while (running) {
        int rawMoisture = readSoilMoisture();
        int moisturePercentage = processSoilMoisture(rawMoisture);

        if (moisturePercentage >= 0) {
            fprintf(stderr, "Moisture level: %d%%\n", moisturePercentage);
            controlPump(moisturePercentage);
        } else {
            fprintf(stderr, "Error: Could not read moisture level. Skipping pump control.\n");
        }

        gpioDelay(SENSOR_READ_DELAY_MS);
    }

    // Cleanup (should not reach here if signal handler works)
    gpioWrite(PUMP_GPIO, 0);
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

