// Define the ADC file (replace with your actual ADC interface)
#define ADC_FILE "/sys/bus/iio/devices/iio:device0/in_voltage0_raw"
#define LOG_FILE "sensor_log.txt"
#define SAMPLE_RATE 100 // samples per second
#define WINDOW_SIZE 10 // seconds

// Function to read from the ADC
int read_adc()
{
    int fd;
    char buf[10];
    int ret;
    int val;

    fd = open(ADC_FILE, O_RDONLY);
    if (fd < 0)
    {
        perror("Failed to open ADC file");
        return -1;
    }

    ret = read(fd, buf, sizeof(buf));
    if (ret < 0)
    {
        perror("Failed to read ADC value");
        close(fd);
        return -1;
    }
    buf[ret] = 0; // Null-terminate the string

    val = atoi(buf);
    close(fd);
    return val;
}

int main()
{
    FILE *fp;
    time_t start_time, current_time;
    int adc_value;
    int min_value = 1024; // Assuming 10-bit ADC, initialize with max value
    int max_value = 0;
    int sample_count = 0;
    struct timeval tv;

    fp = fopen(LOG_FILE, "a"); // Open log file in append mode
    if (fp == NULL)
    {
        perror("Failed to open log file");
        return 1;
    }

    time(&start_time);
    printf("Logging started.  Logging to %s\n", LOG_FILE);

    while (1)
    {
        adc_value = read_adc();
        if (adc_value == -1)
        {
            fprintf(stderr, "Error reading ADC. Retrying...\n");
            usleep(10000); // Wait 10ms before retrying
            continue; // Retry the loop
        }

        if (adc_value < min_value)
        {
            min_value = adc_value;
        }
        if (adc_value > max_value)
        {
            max_value = adc_value;
        }

        sample_count++;

        time(&current_time);
        if (difftime(current_time, start_time) >= WINDOW_SIZE)
        {
            gettimeofday(&tv, NULL);
            fprintf(fp, "%ld.%06ld, min=%d, max=%d\n", (long)tv.tv_sec, (long)tv.tv_usec, min_value, max_value);
            fflush(fp); // Ensure data is written to file
            printf("%ld.%06ld, min=%d, max=%d\n", (long)tv.tv_sec, (long)tv.tv_usec, min_value, max_value);

            // Reset for the next window
            min_value = 1024;
            max_value = 0;
            start_time = current_time;
            sample_count = 0;
        }

        usleep(1000000 / SAMPLE_RATE); // Delay to achieve desired sampling rate
    }

    fclose(fp);
    return 0;
}

