#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <wiringPi.h>
#include <pcf8591.h>

// Constants
#define LED_PIN         1       // GPIO pin for the on-board LED
#define PCF8591_BASE    120     // Base address for the PCF8591 chip
#define PCF8591_ADDRESS 0x48    // I2C address of the PCF8591 chip
#define NUM_ANALOG_PINS 4       // Number of analog input pins on PCF8591
#define VREF            3.3     // Reference voltage of the ADC (in volts)
#define ADC_MAX_VALUE   255.0   // Maximum ADC value (2^8 - 1)

// Function prototypes
int initialize();
float readVoltage(int pin);
void cleanup();

int main(void) {
    // Initialize WiringPi and PCF8591
    if (initialize() != 0) {
        fprintf(stderr, "Initialization failed. Exiting.\n");
        return 1;
    }

    printf("Raspberry Pi - Quick2Wire Voltmeter\n");

    // Main loop: read and display voltages continuously
    while (1) {
        // Read and print voltages from each analog pin
        for (int pin = 0; pin < NUM_ANALOG_PINS; ++pin) {
            float voltage = readVoltage(pin);
            printf("  %5.2f", voltage);
        }
        printf("\r"); // Carriage return to overwrite the previous line
        fflush(stdout); // Flush output buffer to ensure immediate display

        // Toggle the LED and delay for a short period
        digitalWrite(LED_PIN, !digitalRead(LED_PIN));
        delay(100); // Reduced delay for better responsiveness
    }

    // Code will never reach here in normal operation due to the infinite loop
    cleanup(); //Cleanup resources before exiting
    return 0;
}

// Initializes WiringPi and PCF8591
int initialize() {
    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed.\n");
        return -1;
    }

    // Set LED pin as output
    pinMode(LED_PIN, OUTPUT);

    // Initialize PCF8591
    pcf8591Setup(PCF8591_BASE, PCF8591_ADDRESS);

    return 0;
}

// Reads the voltage from the specified analog pin
float readVoltage(int pin) {
    // Read the analog value from the PCF8591
    int analogValue = analogRead(PCF8591_BASE + pin);

    // Convert the analog value to voltage
    float voltage = (float)analogValue * VREF / ADC_MAX_VALUE;

    return voltage;
}

// Cleanup resources
void cleanup() {
    // Set LED pin to low (off)
    digitalWrite(LED_PIN, LOW);
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>

#define BMP180_ADDR 0x77
#define BMP180_REG_CONTROL 0xF4
#define BMP180_REG_MSB 0xF6
#define BMP180_REG_LSB 0xF7
#define BMP180_REG_XLSB 0xF8

#define BMP180_CAL_AC1 0xAA
#define BMP180_CAL_AC2 0xAC
#define BMP180_CAL_AC3 0xAE
#define BMP180_CAL_AC4 0xB0
#define BMP180_CAL_AC5 0xB2
#define BMP180_CAL_AC6 0xB4
#define BMP180_CAL_B1  0xB6
#define BMP180_CAL_B2  0xB8
#define BMP180_CAL_MB  0xBA
#define BMP180_CAL_MC  0xBC
#define BMP180_CAL_MD  0xBE


#define GPIO_BUTTON 17

static volatile int logging_enabled = 0;
static int i2c_handle;
static int terminate_flag = 0;

// Calibration data
static int16_t ac1, ac2, ac3, b1, b2, mb, mc, md;
static uint16_t ac4, ac5, ac6;

// Function to read a 16-bit value from the BMP180
static int16_t read_int16(int i2c_handle, uint8_t reg)
{
    char buf[2];
    if (i2cReadI2CBlockData(i2c_handle, reg, buf, 2) != 2) {
        fprintf(stderr, "Error reading 16-bit value from register 0x%02X\n", reg);
        return 0;
    }
    return (int16_t)((buf[0] << 8) | buf[1]);
}

// Function to read a uint16_t value from the BMP180
static uint16_t read_uint16(int i2c_handle, uint8_t reg)
{
    char buf[2];
    if (i2cReadI2CBlockData(i2c_handle, reg, buf, 2) != 2) {
        fprintf(stderr, "Error reading uint16_t value from register 0x%02X\n", reg);
        return 0;
    }
    return (uint16_t)((buf[0] << 8) | buf[1]);
}

// Function to read calibration data from BMP180
static int read_calibration_data(int i2c_handle) {
    ac1 = read_int16(i2c_handle, BMP180_CAL_AC1);
    ac2 = read_int16(i2c_handle, BMP180_CAL_AC2);
    ac3 = read_int16(i2c_handle, BMP180_CAL_AC3);
    ac4 = read_uint16(i2c_handle, BMP180_CAL_AC4);
    ac5 = read_uint16(i2c_handle, BMP180_CAL_AC5);
    ac6 = read_uint16(i2c_handle, BMP180_CAL_AC6);
    b1  = read_int16(i2c_handle, BMP180_CAL_B1);
    b2  = read_int16(i2c_handle, BMP180_CAL_B2);
    mb  = read_int16(i2c_handle, BMP180_CAL_MB);
    mc  = read_int16(i2c_handle, BMP180_CAL_MC);
    md  = read_int16(i2c_handle, BMP180_CAL_MD);

    if (ac1 == 0 || ac2 == 0 || ac3 == 0 || ac4 == 0 || ac5 == 0 || ac6 == 0 ||
        b1 == 0  || b2 == 0  || mb == 0  || mc == 0  || md == 0) {
        fprintf(stderr, "Error: Invalid calibration data. Check sensor connection.\n");
        return -1;
    }
    return 0;
}

// Function to read pressure from BMP180
float read_bmp180_pressure(int i2c_handle) {
    char buf[1];
    char data[3];
    int ut, up;
    long x1, x2, x3, b3, b5, b6, p;
    unsigned long b4, b7;

    // Request temperature reading
    buf[0] = 0x2E; // Temperature measurement command
    if (i2cWriteI2CBlockData(i2c_handle, BMP180_REG_CONTROL, buf, 1) != 1) {
        fprintf(stderr, "Error writing to control register for temperature reading\n");
        return -1.0;
    }
    time_sleep(0.005); // Wait 4.5ms

    // Read temperature
    if (i2cReadI2CBlockData(i2c_handle, BMP180_REG_MSB, data, 2) != 2) {
        fprintf(stderr, "Error reading temperature data\n");
        return -1.0;
    }
    ut = (data[0] << 8) | data[1];

    // Request pressure reading (oss = 0)
    buf[0] = 0x34; // Pressure measurement command (oss=0)
    if (i2cWriteI2CBlockData(i2c_handle, BMP180_REG_CONTROL, buf, 1) != 1) {
        fprintf(stderr, "Error writing to control register for pressure reading\n");
        return -1.0;
    }
    time_sleep(0.005); // Wait 4.5ms

    // Read pressure
    if (i2cReadI2CBlockData(i2c_handle, BMP180_REG_MSB, data, 2) != 2) {
        fprintf(stderr, "Error reading pressure data\n");
        return -1.0;
    }
    up = (data[0] << 8) | data[1];

    // Calculate pressure (see BMP180 datasheet)
    x1 = ((long)ut - (long)ac6) * ((long)ac5) / pow(2, 15);
    x2 = ((long)mc * pow(2, 11)) / (x1 + md);
    b5 = x1 + x2;
    b6 = b5 - 4000;
    x1 = (b2 * (b6 * b6 / pow(2, 12))) / pow(2, 11);
    x2 = ac2 * b6 / pow(2, 11);
    x3 = x1 + x2;
    b3 = (((ac1 * 4 + x3) << 0) + 2) / 4;  // oss = 0
    x1 = ac3 * b6 / pow(2, 13);
    x2 = (b1 * (b6 * b6 / pow(2, 12))) / pow(2, 16);
    x3 = ((x1 + x2) + 2) / 4;
    b4 = ac4 * (unsigned long)(x3 + 32768) / pow(2, 15);
    b7 = ((unsigned long)up - b3) * (50000 >> 0); // oss = 0
    if (b7 < 0x80000000)
    {
        p = (b7 * 2) / b4;
    }
    else
    {
        p = (b7 / b4) * 2;
    }
    x1 = (p / pow(2, 8)) * (p / pow(2, 8));
    x1 = (x1 * 3038) / pow(2, 16);
    x2 = (-7357 * p) / pow(2, 16);
    p = p + (x1 + x2 + 3791) / pow(2, 4);

    return (float)p;
}

// Function to write pressure data to a file
int write_pressure_to_file(const char *filename, time_t timestamp, float pressure) {
    FILE *fp = fopen(filename, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening file %s for writing\n", filename);
        return -1;
    }

    fprintf(fp, "%ld,%.2f\n", timestamp, pressure);

    if (fclose(fp) != 0) {
        fprintf(stderr, "Error closing file %s\n", filename);
        return -1;
    }

    return 0;
}

// Interrupt handler for button press
void button_interrupt_handler(int gpio, int level, uint32_t tick) {
    if (gpio == GPIO_BUTTON && level == 0) { // Falling edge
        logging_enabled = !logging_enabled;
        printf("Logging toggled to %s\n", logging_enabled ? "ON" : "OFF");
    }
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, exiting gracefully...\n", signal);
    terminate_flag = 1;

    // Disable interrupt
    gpioSetAlertFuncEx(GPIO_BUTTON, NULL, NULL);

    // Close I2C handle
    i2cClose(i2c_handle);

    // Terminate pigpio
    gpioTerminate();

    exit(0);
}

int main() {
