    gpioSetMode(GPIO_BUTTON, PI_INPUT);
    gpioSetPullUpDown(GPIO_BUTTON, PI_PUD_UP);

    // Register interrupt handler
    gpioSetAlertFuncEx(GPIO_BUTTON, button_interrupt_handler, NULL);

