#include <errno.h>

// BMP280 I2C address
#define BMP280_ADDR 0x76

// BMP280 register addresses
#define BMP280_REG_TEMP_MSB 0xFA
#define BMP280_REG_TEMP_LSB 0xFB
#define BMP280_REG_TEMP_XLSB 0xFC
#define BMP280_REG_CTRL_MEAS 0xF4
#define BMP280_REG_CONFIG 0xF5

// GPIO pin for PWM fan control
#define FAN_GPIO 18

// PWM frequency (Hz)
#define PWM_FREQUENCY 1000

// Log file name
#define LOG_FILE "cooling_log.txt"

// I2C handle
int i2c_handle;

// File pointer for log file
FILE *log_file;

// Flag to indicate program should terminate
volatile sig_atomic_t terminate = 0;

// Signal handler for graceful shutdown
void signal_handler(int sig)
{
    fprintf(stderr, "\nCaught signal %d, terminating...\n", sig);
    terminate = 1;
}

// Function to read temperature from BMP280
float read_temperature()
{
    unsigned char buffer[3];
    int raw_temp;
    float temperature;

    // Set BMP280 to forced mode for temperature measurement
    if (i2cWriteByteData(i2c_handle, BMP280_REG_CTRL_MEAS, 0x2E) < 0) {
        fprintf(stderr, "Error writing to BMP280_REG_CTRL_MEAS: %s\n", strerror(errno));
        return -273.15; // Return absolute zero on error
    }

    // Small delay to allow measurement to complete (datasheet recommends > 2ms)
    gpioDelay(5000); // 5ms

    // Read raw temperature data
    if (i2cReadI2CBlockData(i2c_handle, BMP280_REG_TEMP_MSB, (char *)buffer, 3) != 3) {
        fprintf(stderr, "Error reading temperature data from BMP280: %s\n", strerror(errno));
        return -273.15; // Return absolute zero on error
    }

    // Combine raw temperature data
    raw_temp = (buffer[0] << 12) | (buffer[1] << 4) | (buffer[2] >> 4);

    // Dummy conversion (replace with actual BMP280 conversion formula)
    temperature = (float)raw_temp / 100.0; // Example conversion

    return temperature;
}

// Function to control fan speed based on temperature
void control_fan_speed(float temperature)
{
    int duty_cycle;

    // Map temperature to duty cycle (0-100%)
    if (temperature < 25.0) {
        duty_cycle = 0;
    } else if (temperature > 40.0) {
        duty_cycle = 1000000; // Full speed
    } else {
        duty_cycle = (int)(((temperature - 25.0) / (40.0 - 25.0)) * 1000000.0);
    }

    // Set PWM duty cycle
    gpioPWM(FAN_GPIO, duty_cycle);
}

int main()
{
    float temperature;
    int fan_speed;
    time_t now;
    struct tm *timeinfo;
    char timestamp[20];

    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Configure GPIO18 as PWM output
    gpioSetMode(FAN_GPIO, PI_OUTPUT);
    gpioSetPWMfrequency(FAN_GPIO, PWM_FREQUENCY);
    gpioSetPWMrange(FAN_GPIO, 1000000); // Set range to 1,000,000 for easier duty cycle calculation

    // Initialize I2C interface
    i2c_handle = i2cOpen(1, BMP280_ADDR, 0); // Bus 1, address 0x76, no flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C: %s\n", strerror(errno));
        gpioTerminate();
        return 1;
    }

    // Open log file
    log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Main loop
    while (!terminate) {
        // Read temperature
        temperature = read_temperature();

        // Control fan speed
        control_fan_speed(temperature);

        // Get current timestamp
        time(&now);
        timeinfo = localtime(&now);
        strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

        // Calculate fan speed (0-100%)
        fan_speed = gpioGetPWMdutycycle(FAN_GPIO) / 10000;

        // Log temperature and fan speed
        if (fprintf(log_file, "%s,%.2f,%d\n", timestamp, temperature, fan_speed) < 0) {
            fprintf(stderr, "Error writing to log file: %s\n", strerror(errno));
        }
        fflush(log_file); // Flush the buffer to ensure data is written to disk

        // Sleep for 5 seconds
        gpioDelay(5000000); // 5 seconds in microseconds
    }

    // Cleanup
    i2cClose(i2c_handle);
    gpioWrite(FAN_GPIO, 0); // Turn off fan
    fclose(log_file);
    gpioTerminate();

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Define GPIO pins
#define SENSOR_PIN 4
#define RELAY_PIN 17

// Define activation duration (seconds)
#define ACTIVATION_DURATION 2

// Define debounce count
#define DEBOUNCE_COUNT 5

// Global flag for graceful shutdown
volatile sig_atomic_t program_running = 1;

// File pointer for the log file
FILE *log_file = NULL;

// Function prototypes
int read_distance();
void activate_relay();
void deactivate_relay();
void log_activation();
void signal_handler(int signal);

// Function to read the distance sensor
int read_distance() {
    int count = 0;
    for (int i = 0; i < DEBOUNCE_COUNT; i++) {
        if (gpioRead(SENSOR_PIN) == 1) {
            count++;
        }
        gpioDelay(1); // Short delay for debouncing
    }
    return (count == DEBOUNCE_COUNT) ? 1 : 0; // Object within range
}

// Function to activate the relay
void activate_relay() {
    gpioWrite(RELAY_PIN, 1); // Set GPIO HIGH to activate relay
}

// Function to deactivate the relay
void deactivate_relay() {
    gpioWrite(RELAY_PIN, 0); // Set GPIO LOW to deactivate relay
}

// Function to log the activation event
void log_activation() {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    log_file = fopen("door_log.txt", "a");
    if (log_file == NULL) {
        perror("Error opening log file");
        return;
    }

    fprintf(log_file, "%s: Door activated\n", timestamp);
    fclose(log_file);
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    program_running = 0;
    printf("\nCaught signal %d, exiting gracefully...\n", signal);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        perror("pigpio initialisation failed");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(SENSOR_PIN, PI_INPUT);
    gpioSetMode(RELAY_PIN, PI_OUTPUT);

    // Set pull-down resistor for the sensor pin (adjust as needed)
    gpioSetPullUpDown(SENSOR_PIN, PI_PUD_DOWN);

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Contactless Door Opener running...\nPress Ctrl+C to exit.\n");

    while (program_running) {
        // Read distance sensor
        if (read_distance()) {
            // Activate relay
            activate_relay();

            // Log activation
            log_activation();

            printf("Door activated!\n");

            // Wait for activation duration
            gpioDelay(ACTIVATION_DURATION * 1000); // Convert seconds to milliseconds

            // Deactivate relay
            deactivate_relay();

            printf("Door deactivated!\n");
        }

        // Wait a short period
        gpioDelay(100); // 100ms delay
    }

    // Clean up before exiting
    deactivate_relay(); // Ensure relay is off
    gpioTerminate();   // Terminate pigpio

    printf("Program terminated.\n");
    return 0;
}

#include <stdio.h>
#include <wiringPi.h>
#include <stdint.h>

// Define WiringPi pin numbers for the LED matrix and button
#define ROW1 0
#define ROW2 1
#define ROW3 2
#define ROW4 3
#define ROW5 4
#define ROW6 5
#define ROW7 6
#define ROW8 7

#define COL1 8
#define COL2 9
#define COL3 10
#define COL4 11
#define COL5 12
#define COL6 13
#define COL7 14
#define COL8 15

#define BUTTON_PIN 16

// Define LED matrix dimensions
#define ROWS 8
#define COLS 8

// Function to initialize the LED matrix pins
void initMatrixPins() {
    int rowPins[] = {ROW1, ROW2, ROW3, ROW4, ROW5, ROW6, ROW7, ROW8};
    int colPins[] = {COL1, COL2, COL3, COL4, COL5, COL6, COL7, COL8};

    for (int i = 0; i < ROWS; i++) {
        pinMode(rowPins[i], OUTPUT);
        digitalWrite(rowPins[i], LOW);
    }

    for (int i = 0; i < COLS; i++) {
        pinMode(colPins[i], OUTPUT);
        digitalWrite(colPins[i], LOW);
    }
}

// Function to light up a specific LED on the matrix
void lightUpLED(int row, int col) {
    int rowPins[] = {ROW1, ROW2, ROW3, ROW4, ROW5, ROW6, ROW7, ROW8};
    int colPins[] = {COL1, COL2, COL3, COL4, COL5, COL6, COL7, COL8};

    digitalWrite(rowPins[row], HIGH); // Enable the row
    digitalWrite(colPins[col], HIGH); // Enable the column
    delay(5); // Keep the LED on for a short period
    digitalWrite(rowPins[row], LOW);  // Disable the row
    digitalWrite(colPins[col], LOW);  // Disable the column
}

int main() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi setup failed!\n");
        return 1;
    }

    // Initialize the button pin
    pinMode(BUTTON_PIN, INPUT);
    pullUpDnControl(BUTTON_PIN, PUD_UP); // Enable pull-up resistor

    // Initialize the LED matrix pins
    initMatrixPins();

    printf("Press the button to light up an LED on the matrix!\n");

    while (1) {
        if (digitalRead(BUTTON_PIN) == LOW) { // Button is pressed
            printf("Button Pressed!\n");
            lightUpLED(0, 0); // Light up the LED at row 0, column 0
            delay(200); // Debounce delay
        }
        delay(10); // Small delay to prevent busy-waiting
    }

    return 0;
}

#include <stdio.h>
#include <time.h>
#include <unistd.h>
#include <fcntl.h>
#include <linux/spi/spidev.h>
#include <sys/ioctl.h>
#include <stdint.h>

#define SPI_DEV "/dev/spidev0.0"

int read_adc(int fd, int ch) {
    uint8_t tx[] = {1, (0x80 | (ch << 4)), 0};
    uint8_t rx[3];
    struct spi_ioc_transfer tr = {.tx_buf=(unsigned long)tx, .rx_buf=(unsigned long)rx, .len=3, .speed_hz=1000000, .bits_per_word=8};
    ioctl(fd, SPI_IOC_MESSAGE(1), &tr);
    return ((rx[1] & 0x03) << 8) | rx[2];
}

int main() {
    FILE *log = fopen("ch1_10min_log.txt", "w");
    int fd = open(SPI_DEV, O_RDWR);
    time_t start = time(NULL);
    while (difftime(time(NULL), start) < 600) {
        int val = read_adc(fd, 1);
        time_t now = time(NULL);
        fprintf(log, "%ld %d\n", now, val);
        fflush(log);
        sleep(1);
    }
    fclose(log);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <unistd.h>
#include <signal.h>
#include <time.h>
#include <sys/time.h>
#include <bcm2835.h>
#include <errno.h>
#include <fcntl.h>
#include <linux/i2c-dev.h>
#include <sys/ioctl.h>

// Define ADS1115 I2C address and registers
#define ADS1115_ADDRESS 0x48
#define ADS1115_CONFIG_REG 0x01
#define ADS1115_CONVERSION_REG 0x00
#define ADS1115_LO_THRESH_REG 0x02
#define ADS1115_HI_THRESH_REG 0x03

// Define GPIO pin for ALERT signal (adjust as needed)
#define ALERT_PIN RPI_GPIO_P1_11 // GPIO17 (physical pin 11)

// Define Full Scale Range (FSR) for +/- 4.096V
#define FSR 4.096

// Conversion factor from raw ADC reading to voltage
#define VOLTAGE_CONVERSION_FACTOR (FSR / 32767.0)

// Global flag to indicate interrupt occurrence
volatile sig_atomic_t alert_triggered = 0;

int i2c_fd;

// Signal handler for the ALERT pin interrupt
void alert_handler(int signum) {
    alert_triggered = 1;
}

// Function to read a 16-bit value from the ADS1115
int16_t read_ads1115(uint8_t reg) {
    uint8_t buf[2];
    buf[0] = reg;
    if (write(i2c_fd, buf, 1) != 1) {
        perror("Failed to write to I2C device");
        return -1;
    }
    if (read(i2c_fd, buf, 2) != 2) {
        perror("Failed to read from I2C device");
        return -1;
    }
    return (int16_t)((buf[0] << 8) | buf[1]);
}

// Function to write a 16-bit value to the ADS1115
bool write_ads1115(uint8_t reg, uint16_t value) {
    uint8_t buf[3];
    buf[0] = reg;
    buf[1] = (value >> 8) & 0xFF;
    buf[2] = value & 0xFF;
    if (write(i2c_fd, buf, 3) != 3) {
        perror("Failed to write to I2C device");
        return false;
    }
    return true;
}

int main(int argc, char **argv) {
    // Initialize bcm2835 library
    if (!bcm2835_init()) {
        fprintf(stderr, "bcm2835_init failed. Are you running as root?\n");
        return 1;
    }

    // Open I2C device
    i2c_fd = open("/dev/i2c-1", O_RDWR);
    if (i2c_fd < 0) {
        perror("Failed to open I2C device");
        bcm2835_close();
        return 1;
    }

    // Specify the address of the slave device
    if (ioctl(i2c_fd, I2C_SLAVE, ADS1115_ADDRESS) < 0) {
        perror("Failed to acquire bus access and/or talk to slave");
        close(i2c_fd);
        bcm2835_close();
        return 1;
    }

    // Configure ADS1115 (Single-ended input A0, +/-4.096V, Continuous conversion, DR=128SPS, ALERT active low, Comparator mode)
    uint16_t config = 0x4083; //0b0100000010000011
    if (!write_ads1115(ADS1115_CONFIG_REG, config)) {
        fprintf(stderr, "Failed to configure ADS1115\n");
        close(i2c_fd);
        bcm2835_close();
        return 1;
    }

    // Set High Threshold to trigger alert. Adjust value for testing.
    uint16_t high_threshold = 10000;  // Example value: 10000
    if (!write_ads1115(ADS1115_HI_THRESH_REG, high_threshold)) {
        fprintf(stderr, "Failed to write high threshold\n");
        close(i2c_fd);
        bcm2835_close();
        return 1;
    }

    // Set Low Threshold.  This is important for comparator mode to work
    uint16_t low_threshold = 0; // Example value: 0
    if (!write_ads1115(ADS1115_LO_THRESH_REG, low_threshold)) {
        fprintf(stderr, "Failed to write low threshold\n");
        close(i2c_fd);
        bcm2835_close();
        return 1;
    }


    // Configure ALERT pin as input with pull-up resistor
    bcm2835_gpio_fsel(ALERT_PIN, BCM2835_GPIO_FSEL_INPT);
    bcm2835_gpio_set_pud(ALERT_PIN, BCM2835_GPIO_PUD_UP);

    // Set up signal handling for falling edge detection
    signal(SIGIO, alert_handler);
    fcntl(i2c_fd, F_SETOWN, getpid());
    int flags = fcntl(i2c_fd, F_GETFL);
    fcntl(i2c_fd, F_SETFL, flags | O_ASYNC);

    // Main loop
    while (1) {
        // Check if the ALERT pin triggered an interrupt
        if (alert_triggered) {
            // Read the conversion result
            int16_t raw_value = read_ads1115(ADS1115_CONVERSION_REG);
            if (raw_value != -1) {
                float voltage = raw_value * VOLTAGE_CONVERSION_FACTOR;
                printf("Alert Triggered! Voltage: %.4f V\n", voltage);
            } else {
                fprintf(stderr, "Failed to read conversion result\n");
            }

            // Reset the interrupt flag
            alert_triggered = 0;
        }

        // Small delay to prevent busy-waiting
        usleep(100000); // 100ms
    }

    // Cleanup (this part is never reached in this example but included for completeness)
    close(i2c_fd);
    bcm2835_close();
    return 0;
}

