#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <wiringPiSPI.h>
#include <time.h>
#include <signal.h>
#include <errno.h>

// Define constants
#define FAN_PIN 18          // GPIO18 for PWM
#define MCP3008_CHANNEL 0 // MCP3008 channel for TMP36
#define SPI_CHANNEL 0       // SPI channel (CE0)
#define SPI_SPEED 1000000   // SPI clock speed (1 MHz)
#define PWM_RANGE 100       // PWM range
#define TEMP_OFFSET 0.5     // TMP36 offset (0.5V)
#define VCC 3.3             // Supply voltage
#define ADC_RESOLUTION 1024 // ADC resolution (10 bits)

// Global variables
FILE *log_file = NULL;

// Function prototypes
int read_mcp3008(int channel);
float read_temperature();
void set_fan_speed(int pwm_duty);
void log_data(float temperature, int pwm_duty);
void signal_handler(int signal);

int main()
{
    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1)
    {
        fprintf(stderr, "wiringPiSetupGpio failed: %s\n", strerror(errno));
        return 1;
    }

    // Initialize SPI
    if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) == -1)
    {
        fprintf(stderr, "wiringPiSPISetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Configure PWM on GPIO18
    pinMode(FAN_PIN, PWM_OUTPUT);
    pwmSetMode(PWM_MODE_MS); // Set PWM mode to mark:space
    pwmSetRange(PWM_RANGE);  // Set PWM range
    pwmSetClock(192);      // Set PWM clock divisor (adjust for ~25kHz)

    // Open log file
    log_file = fopen("fan_log.txt", "a");
    if (log_file == NULL)
    {
        fprintf(stderr, "Failed to open log file: %s\n", strerror(errno));
        return 1;
    }

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Main loop
    while (1)
    {
        // Read temperature
        float temperature = read_temperature();

        // Calculate PWM duty cycle (proportional control)
        int pwm_duty = 0;
        if (temperature > 20.0 && temperature <= 40.0)
        {
            pwm_duty = (int)((temperature - 20.0) * (100.0 / 20.0));
        }
        else if (temperature > 40.0)
        {
            pwm_duty = 100;
        }
        else
        {
            pwm_duty = 0;
        }

        // Set fan speed
        set_fan_speed(pwm_duty);

        // Log data
        log_data(temperature, pwm_duty);

        // Wait for 1 second
        delay(1000);
    }

    return 0;
}

// Function to read data from MCP3008 ADC
int read_mcp3008(int channel)
{
    unsigned char buffer[3];
    buffer[0] = 0x01;                           // Start bit
    buffer[1] = ((channel & 0x07) << 4) | 0x80; // Single-ended mode
    buffer[2] = 0x00;                           // Dummy byte

    if (wiringPiSPIDataRW(SPI_CHANNEL, buffer, 3) == -1)
    {
        fprintf(log_file, "%ld Failed to read from SPI: %s\n", time(NULL), strerror(errno));
        fflush(log_file);
        return -1; // Indicate error
    }

    int adc_value = ((buffer[1] & 0x03) << 8) + buffer[2];
    return adc_value;
}

// Function to read temperature from TMP36 sensor
float read_temperature()
{
    int adc_value = read_mcp3008(MCP3008_CHANNEL);

    if (adc_value == -1)
    {
        return -273.15; // Return absolute zero on SPI read error
    }

    float voltage = (float)adc_value * VCC / ADC_RESOLUTION;
    float temperature = (voltage - TEMP_OFFSET) * 100.0;
    return temperature;
}

// Function to set fan speed using PWM
void set_fan_speed(int pwm_duty)
{
    if (pwm_duty < 0) pwm_duty = 0;
    if (pwm_duty > 100) pwm_duty = 100;
    pwmWrite(FAN_PIN, pwm_duty);
}

// Function to log data to file
void log_data(float temperature, int pwm_duty)
{
    time_t rawtime;
    struct tm *timeinfo;
    time(&rawtime);
    timeinfo = localtime(&rawtime);

    char timestamp[80];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    if (log_file != NULL)
    {
        fprintf(log_file, "%s, Temperature: %.2f C, PWM Duty: %d\n", timestamp, temperature, pwm_duty);
        fflush(log_file);
    } else {
      fprintf(stderr, "Log file is NULL. Cannot log data.\n");
    }
}

// Signal handler for Ctrl+C
void signal_handler(int signal)
{
    printf("Caught signal %d, exiting gracefully...\n", signal);

    // Stop the fan
    set_fan_speed(0);

    // Close the log file
    if (log_file != NULL)
    {
        fclose(log_file);
    }

    exit(0);
}

