#include <stdio.h>
#include <wiringPi.h>
#include <unistd.h>

#define BUZZER_PIN 5
#define BUTTON_PIN 9

#define DEBOUNCE_DELAY 50 // milliseconds
#define DOUBLE_PRESS_DELAY 300 // milliseconds

int buttonState = 0; // Initially OFF
int lastButtonState = LOW;
unsigned long lastDebounceTime = 0;
unsigned long lastPressTime = 0;
int pressCount = 0;

void handleButtonPress() {
  int reading = digitalRead(BUTTON_PIN);

  if (reading != lastButtonState) {
    lastDebounceTime = millis();
  }

  if ((millis() - lastDebounceTime) > DEBOUNCE_DELAY) {
    if (reading != buttonState) {
      buttonState = reading;

      if (buttonState == HIGH) {
        pressCount++;
        unsigned long currentTime = millis();

        if (pressCount == 1) {
            lastPressTime = currentTime;
        } else if (pressCount == 2 && (currentTime - lastPressTime) <= DOUBLE_PRESS_DELAY) {
          // Double press detected
          printf("Double press detected!\n");
          if (digitalRead(BUZZER_PIN) == LOW) {
            digitalWrite(BUZZER_PIN, HIGH); // Turn buzzer ON
            printf("Buzzer ON\n");
          } else {
            digitalWrite(BUZZER_PIN, LOW); // Turn buzzer OFF
            printf("Buzzer OFF\n");
          }
          pressCount = 0; // Reset press count
        } else {
            pressCount = 0;
        }
      }
    }
  }

  lastButtonState = reading;
}

int main() {
  if (wiringPiSetup() == -1) {
    fprintf(stderr, "WiringPi setup failed!\n");
    return 1;
  }

  pinMode(BUZZER_PIN, OUTPUT);
  pinMode(BUTTON_PIN, INPUT);
  pullUpDnControl(BUTTON_PIN, PUD_DOWN); // Use internal pull-down resistor
  digitalWrite(BUZZER_PIN, LOW); // Ensure buzzer is initially off

  printf("Waiting for double press...\n");

  while (1) {
    handleButtonPress();
    delay(1); // Small delay to prevent busy-waiting
  }

  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <fcntl.h>
#include <unistd.h>
#include <time.h>
#include <signal.h>
#include <errno.h>

// Define GPIO pins
#define RAIN_SENSOR_PIN 18
#define MOTOR_DIR1_PIN 23
#define MOTOR_DIR2_PIN 24
#define MOTOR_ENABLE_PIN 25

// Define rain threshold
#define RAIN_THRESHOLD 500

// Define the duration of the analog read emulation in milliseconds
#define ANALOG_READ_DURATION_MS 10

// Global flag to indicate program termination
volatile sig_atomic_t program_running = 1;

// Function prototypes
int gpio_export(int pin);
int gpio_unexport(int pin);
int gpio_set_direction(int pin, const char* direction);
int gpio_write(int pin, int value);
int read_rain_sensor(int pin);
void close_window(int dir1_pin, int dir2_pin, int enable_pin);
void log_event(const char* event);
void signal_handler(int signum);

int main() {
    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Export GPIO pins
    if (gpio_export(RAIN_SENSOR_PIN) == -1 ||
        gpio_export(MOTOR_DIR1_PIN) == -1 ||
        gpio_export(MOTOR_DIR2_PIN) == -1 ||
        gpio_export(MOTOR_ENABLE_PIN) == -1) {
        fprintf(stderr, "Failed to export GPIO pins. Check permissions and pin availability.\n");
        return 1;
    }

    // Set GPIO directions
    if (gpio_set_direction(RAIN_SENSOR_PIN, "in") == -1 ||
        gpio_set_direction(MOTOR_DIR1_PIN, "out") == -1 ||
        gpio_set_direction(MOTOR_DIR2_PIN, "out") == -1 ||
        gpio_set_direction(MOTOR_ENABLE_PIN, "out") == -1) {
        fprintf(stderr, "Failed to set GPIO directions.\n");
        // Attempt to unexport before exiting
        gpio_unexport(RAIN_SENSOR_PIN);
        gpio_unexport(MOTOR_DIR1_PIN);
        gpio_unexport(MOTOR_DIR2_PIN);
        gpio_unexport(MOTOR_ENABLE_PIN);
        return 1;
    }

    log_event("Program started.");

    // Main loop
    while (program_running) {
        int sensor_value = read_rain_sensor(RAIN_SENSOR_PIN);
        char log_message[100];
        snprintf(log_message, sizeof(log_message), "Rain sensor value: %d", sensor_value);
        log_event(log_message);

        if (sensor_value > RAIN_THRESHOLD) {
            log_event("Rain detected! Closing window.");
            close_window(MOTOR_DIR1_PIN, MOTOR_DIR2_PIN, MOTOR_ENABLE_PIN);
            log_event("Window closed.");
        }

        // Wait for a short interval before reading the sensor again
        sleep(1); // Check every 1 second
    }

    // Unexport GPIO pins before exiting
    gpio_unexport(RAIN_SENSOR_PIN);
    gpio_unexport(MOTOR_DIR1_PIN);
    gpio_unexport(MOTOR_DIR2_PIN);
    gpio_unexport(MOTOR_ENABLE_PIN);

    log_event("Program terminated.");

    return 0;
}

int gpio_export(int pin) {
    char buffer[64];
    int fd;

    fd = open("/sys/class/gpio/export", O_WRONLY);
    if (fd < 0) {
        perror("gpio/export");
        return -1;
    }
    snprintf(buffer, sizeof(buffer), "%d", pin);
    if (write(fd, buffer, strlen(buffer)) < 0) {
        if (errno == EBUSY) {
          close(fd);
          return 0; // Already exported, not an error
        }
        perror("gpio/export");
        close(fd);
        return -1;
    }
    close(fd);
    return 0;
}

int gpio_unexport(int pin) {
    char buffer[64];
    int fd;

    fd = open("/sys/class/gpio/unexport", O_WRONLY);
    if (fd < 0) {
        perror("gpio/unexport");
        return -1;
    }
    snprintf(buffer, sizeof(buffer), "%d", pin);
    if (write(fd, buffer, strlen(buffer)) < 0) {
        perror("gpio/unexport");
        close(fd);
        return -1;
    }
    close(fd);
    return 0;
}

int gpio_set_direction(int pin, const char* direction) {
    char path[64];
    int fd;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/direction", pin);
    fd = open(path, O_WRONLY);
    if (fd < 0) {
        perror("gpio/direction");
        return -1;
    }
    if (write(fd, direction, strlen(direction)) < 0) {
        perror("gpio/direction");
        close(fd);
        return -1;
    }
    close(fd);
    return 0;
}

int gpio_write(int pin, int value) {
    char path[64];
    int fd;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", pin);
    fd = open(path, O_WRONLY);
    if (fd < 0) {
        perror("gpio/value");
        return -1;
    }
    if (write(fd, value ? "1" : "0", 1) < 0) {
        perror("gpio/value");
        close(fd);
        return -1;
    }
    close(fd);
    return 0;
}

int read_rain_sensor(int pin) {
    char path[64];
    int fd;
    int count = 0;
    struct timespec ts;
    ts.tv_sec = 0;
    ts.tv_nsec = 100000L; // 0.1 ms

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", pin);

    // Emulate analog read by counting HIGH states for a short duration
    for (int i = 0; i < ANALOG_READ_DURATION_MS * 10; ++i) { // 10ms * 10 reads/ms = 100 reads
        fd = open(path, O_RDONLY);
        if (fd < 0) {
            perror("gpio/value (read)");
            //Handle the error, perhaps return a default value or log it.
            return 0; // Or some other appropriate error value
        }

        char value[2];
        ssize_t bytes_read = read(fd, value, 1);
        close(fd);

        if (bytes_read > 0) {
            if (value[0] == '1') {
                count++;
            }
        } else if (bytes_read < 0 && errno != EINTR) { // Check for errors other than interruption
            perror("gpio/value (read) - error during read");
            return 0; // Or some other appropriate error value
        }

        nanosleep(&ts, NULL); // Wait a short time
    }

    return count;
}

void close_window(int dir1_pin, int dir2_pin, int enable_pin) {
    // Set direction pins to close the window
    if (gpio_write(dir1_pin, 1) == -1) {
        log_event("Error setting motor direction 1");
        return;
    }
    if (gpio_write(dir2_pin, 0) == -1) {
        log_event("Error setting motor direction 2");
        return;
    }

    // Enable the motor
    if (gpio_write(enable_pin, 1) == -1) {
        log_event("Error enabling motor");
        return;
    }

    // Wait for 5 seconds to fully close the window
    sleep(5);

    // Disable the motor
    if (gpio_write(enable_pin, 0) == -1) {
        log_event("Error disabling motor");
    }
}

void log_event(const char* event) {
    FILE* fp;
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[64];

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    fp = fopen("window_log.txt", "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return;
    }

    fprintf(fp, "[%s] %s\n", timestamp, event);
    fclose(fp);
}

void signal_handler(int signum) {
    if (signum == SIGINT || signum == SIGTERM) {
        log_event("Signal received, exiting...");
        program_running = 0;
    }
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <string.h>
#include <errno.h>
#include <time.h>
#include <gpiod.h>
#include <math.h>

// Constants
#define MAX_SENSORS 32
#define DS18B20_SKIP_ROM 0xCC
#define DS18B20_CONVERT_T 0x44
#define DS18B20_READ_SCRATCHPAD 0xBE
#define RETRY_MAX 3

// Data structure for sensor information
typedef struct {
    int pin;
    bool valid;
    unsigned char resolution;
    double temperature;
} sensor_data_t;

// Global variables
struct gpiod_chip *gpiochip = NULL;
sensor_data_t sensors[MAX_SENSORS];
int num_sensors = 0;

// Function prototypes
bool init_gpio(void);
bool add_sensor(int pin);
int reset_sensors(void);
void write_byte(unsigned char value);
void read_byte(unsigned int *datatable);
void extract_scratchpad(unsigned int bitmask, unsigned char *scratchpad, unsigned int *bitdatatable);
unsigned char calc_crc(unsigned char *data, unsigned char byteSize);
int read_temperatures(unsigned int *bitdatatable);
void delay_microseconds(int delay_us);

int main(int argc, char **argv) {
    int loop;
    unsigned long acq_delay;
    unsigned char highest_resolution = 9;

    if (argc == 1) {
        fprintf(stderr, "Usage: %s GPIO1 GPIO2 ... GPIO%d\n", argv[0], MAX_SENSORS);
        return EXIT_FAILURE;
    }

    // Initialize GPIO
    if (!init_gpio()) {
        fprintf(stderr, "Failed to initialize GPIO.\n");
        return EXIT_FAILURE;
    }

    // Add sensors from command line arguments
    for (loop = 1; loop < argc && num_sensors < MAX_SENSORS; loop++) {
        int pin = atoi(argv[loop]);
        if (add_sensor(pin)) {
            sensors[num_sensors].pin = pin;
            num_sensors++;
        } else {
            fprintf(stderr, "Failed to add sensor on GPIO %d.\n", pin);
        }
    }

    if (num_sensors == 0) {
        fprintf(stderr, "No valid sensors added. Exiting.\n");
        gpiod_chip_close(gpiochip);
        return EXIT_FAILURE;
    }

    // Determine highest resolution among sensors
    unsigned int bitdatatable[72];
    read_temperatures(bitdatatable);
    for (loop = 0; loop < num_sensors; loop++) {
        if (sensors[loop].valid && sensors[loop].resolution > highest_resolution) {
            highest_resolution = sensors[loop].resolution;
        }
    }

    // Set acquisition delay based on highest resolution
    switch (highest_resolution) {
        case 9:
            acq_delay = 94000;
            break;
        case 10:
            acq_delay = 188000;
            break;
        case 11:
            acq_delay = 375000;
            break;
        default:
            acq_delay = 750000;
    }

    printf("Highest resolution: %d bits. Acquisition delay: %ld ms.\n", highest_resolution, acq_delay / 1000);
    printf("Press Enter to start. Ctrl-C to exit.\n");
    getchar();

    // Main loop
    struct timespec start_time, acq_start_time, end_time;
    do {
        clock_gettime(CLOCK_MONOTONIC, &acq_start_time);

        // Reset and start temperature conversion
        if (reset_sensors() != 0) {
          fprintf(stderr, "Reset Failed, trying again.\n");
          continue;
        }

        write_byte(DS18B20_SKIP_ROM);
        write_byte(DS18B20_CONVERT_T);

        // Wait for conversion
        delay_microseconds(acq_delay);

        // Read temperatures
        read_temperatures(bitdatatable);

        clock_gettime(CLOCK_MONOTONIC, &end_time);

        printf("====\nAcquisition time: %.3f sec\n", (end_time.tv_sec - acq_start_time.tv_sec) + (end_time.tv_nsec - acq_start_time.tv_nsec) / 1e9);

        // Print results
        for (loop = 0; loop < num_sensors; loop++) {
            printf("GPIO %d: ", sensors[loop].pin);
            if (sensors[loop].valid) {
                printf("%02d bits  Temperature: %6.2f +/- %4.2f Celsius\n",
                       sensors[loop].resolution, sensors[loop].temperature,
                       0.0625 * (double)(1 << (12 - sensors[loop].resolution)));
            } else {
                printf("Invalid data\n");
            }
        }
        fflush(stdout);

    } while (1);

    // Clean up
    gpiod_chip_close(gpiochip);
    return 0;
}

bool init_gpio(void) {
    gpiochip = gpiod_chip_open_by_name("gpiochip4");
    if (!gpiochip) {
        gpiochip = gpiod_chip_open_by_name("gpiochip0");
        if (!gpiochip) {
            perror("gpiod_chip_open_by_name");
            return false;
        }
    }
    return true;
}

bool add_sensor(int pin) {
    struct gpiod_line *line = gpiod_chip_get_line(gpiochip, pin);
    if (!line) {
        perror("gpiod_chip_get_line");
        return false;
    }
    gpiod_line_release(line);
    return true;
}

int reset_sensors(void) {
    struct gpiod_line *line;
    int i, ret;

    // Set all sensor pins to output and high
    for (i = 0; i < num_sensors; i++) {
        line = gpiod_chip_get_line(gpiochip, sensors[i].pin);
        if (!line) {
            perror("gpiod_chip_get_line");
            return -1;
        }
        ret = gpiod_line_request_output(line, "reset", 1);
        if (ret < 0) {
            perror("gpiod_line_request_output");
            gpiod_line_release(line);
            return -1;
        }
        gpiod_line_release(line);
    }

    delay_microseconds(10);

    // Drive all sensor pins low simultaneously
    for (i = 0; i < num_sensors; i++) {
        line = gpiod_chip_get_line(gpiochip, sensors[i].pin);
        if (!line) {
            perror("gpiod_chip_get_line");
            return -1;
        }
        ret = gpiod_line_request_output(line, "reset", 0);
        if (ret < 0) {
            perror("gpiod_line_request_output");
            gpiod_line_release(line);
            return -1;
        }
        gpiod_line_release(line);
    }
    usleep(480);

    // Release the bus
    for (i = 0; i < num_sensors; i++) {
        line = gpiod_chip_get_line(gpiochip, sensors[i].pin);
        if (!line) {
            perror("gpiod_chip_get_line");
            return -1;
        }
        ret = gpiod_line_request_input(line, "reset");
        if (ret < 0) {
            perror("gpiod_line_request_input");
            gpiod_line_release(line);
            return -1;
        }
        gpiod_line_release(line);
    }
    delay_microseconds(60);

    // Sample for presence pulse (not really used, but good practice)
    int presence[MAX_SENSORS];
    for (i = 0; i < num_sensors; i++) {
        line = gpiod_chip_get_line(gpiochip, sensors[i].pin);
        if (!line) {
            perror("gpiod_chip_get_line");
            return -1;
        }
        ret = gpiod_line_get_value(line);
        if (ret < 0) {
            perror("gpiod_line_get_value");
            gpiod_line_release(line);
            return -1;
        }
        presence[i] = ret;
        gpiod_line_release(line);
    }

    delay_microseconds(420);

    // Check for any errors during reset
    for (i = 0; i < num_sensors; i++) {
        if (presence[i] == 1) {
            return -1; // Indicate error
        }
    }
    return 0; // Indicate success
}

void write_byte(unsigned char value) {
    struct gpiod_line *line;
    int i, bit;

    for (bit = 0; bit < 8; bit++) {
        for (i = 0; i < num_sensors; i++) {
            line = gpiod_chip_get_line(gpiochip, sensors[i].pin);
            if (!line) {
                perror("gpiod_chip_get_line");
                return;
            }
            gpiod_line_request_output(line, "write", 0);
            gpiod_line_release(line);
        }

        if ((value & (1 << bit)) != 0) {
            delay_microseconds(1);
            for (i = 0; i < num_sensors; i++) {
                line = gpiod_chip_get_line(gpiochip, sensors[i].pin);
                if (!line) {
                    perror("gpiod_chip_get_line");
                    return;
                }
                gpiod_line_request_output(line, "write", 1);
                gpiod_line_release(line);
            }
            usleep(60);
        } else {
            delay_microseconds(60);
            for (i = 0; i < num_sensors; i++) {
                line = gpiod_chip_get_line(gpiochip, sensors[i].pin);
                if (!line) {
                    perror("gpiod_chip_get_line");
                    return;
                }
                gpiod_line_request_output(line, "write", 1);
                gpiod_line_release(line);
            }
            usleep(1);
        }
        delay_microseconds(60);
    }
    usleep(100);
}

void read_byte(unsigned int *datatable) {
    struct gpiod_line *line;
    int i, bit, ret;

    for (bit = 0; bit < 8; bit++) {
        for (i = 0; i < num_sensors; i++) {
            line = gpiod_chip_get_line(gpiochip, sensors[i].pin);
            if (!line) {
                perror("gpiod_chip_get_line");
                return;
            }
            gpiod_line_request_output(line, "read", 0);
            gpiod_line_release(line);
        }

        delay_microseconds(1);

        for (i = 0; i < num_sensors; i++) {
            line = gpiod_chip_get_line(gpiochip, sensors[i].pin);
            if (!line) {
                perror("gpiod_chip_get_line");
                return;
            }
            gpiod_line_request_input(line, "read");
            gpiod_line_release(line);
        }

        delay_microseconds(2);

        for (i = 0; i < num_sensors; i++) {
            line = gpiod_chip_get_line(gpiochip, sensors[i].pin);
            if (!line) {
                perror("gpiod_chip_get_line");
                return;
            }
            ret = gpiod_line_get_value(line);
            if (ret < 0) {
                perror("gpiod_line_get_value");
                return;
            }
            if (ret) {
                datatable[bit * num_sensors + i] = 1;
            } else {
                datatable[bit * num_sensors + i] = 0;
            }
        }

        delay_microseconds(60);
    }
}

void extract_scratchpad(unsigned int bitmask, unsigned char *scratchpad, unsigned int *bitdatatable) {
    int loop, loopr;
    unsigned char mask;

    for (loopr = 0; loopr < 9; loopr++) {
        mask = 1;
        scratchpad[loopr] = 0;
        for (loop = 0; loop < 8; loop++) {
            if ((bitdatatable[loopr * 8 * num_sensors + loop * num_sensors] & bitmask) != 0) {
                scratchpad[loopr] |= mask;
            }
            mask <<= 1;
        }
    }
}

unsigned char calc_crc(unsigned char *data, unsigned char byteSize) {
    unsigned char shift_register = 0;
    unsigned char loop, loop2;
    char dataByte;

    for (loop = 0; loop < byteSize; loop++) {
        dataByte = data[loop];
        for (loop2 = 0; loop2 < 8; loop2++) {
            if ((shift_register ^ dataByte) & 1) {
                shift_register >>= 1;
                shift_register ^= 0x8C;
            } else {
                shift_register >>= 1;
            }
            dataByte >>= 1;
        }
    }
    return shift_register;
}

int read_temperatures(unsigned int *bitdatatable) {
    int loop, retryloop;
    unsigned char scratchpad[9];
    unsigned char crc_byte;
    union {
        short SHORT;
        unsigned char CHAR[2];
    } int_temp;

    // Initialize sensors' valid flag to false
    for (loop = 0; loop < num_sensors; loop++) {
        sensors[loop].valid = false;
    }

    // Retry reading multiple times for reliability
    for (retryloop = 0; retryloop < RETRY_MAX; retryloop++) {
        // Reset data table
        memset(bitdatatable, 0, 72 * num_sensors * sizeof(unsigned int));

        // Reset the sensors
        if (reset_sensors() != 0) {
            fprintf(stderr, "Reset failed during temperature read, retrying.\n");
            continue;
        }

        // Send commands to read scratchpad
        write_byte(DS18B20_SKIP_ROM);
        write_byte(DS18B20_READ_SCRATCHPAD);

        // Read scratchpad data
        for (loop = 0; loop < 72; loop += 8) {
            read_byte(&bitdatatable[loop * num_sensors]);
        }

        // Extract data and validate CRC for each sensor
        for (loop = 0; loop < num_sensors; loop++) {
            extract_scratchpad(1 << loop, scratchpad, bitdatatable);
            crc_byte = calc_crc(scratchpad, 8);

            if (crc_byte == scratchpad[8]) {
                // Check resolution
                if ((scratchpad[4] & 0x9F) == 0x1F) {
                    sensors[loop].valid = true;
                    switch (scratchpad[4]) {
                        case 0x1F:
                            sensors[loop].resolution = 9;
                            break;
                        case 0x3F:
                            sensors[loop].resolution = 10;
                            break;
                        case 0x5F:
                            sensors[loop].resolution = 11;
                            break;
                        default:
                            sensors[loop].resolution = 12;
                            break;
                    }

                    // Read temperature
                    int_temp.CHAR[0] = scratchpad[0];
                    int_temp.CHAR[1] = scratchpad[1];
                    sensors[loop].temperature = 0.0625 * (double)int_temp.SHORT;
                }
            }
        }

        // Check if all sensors have valid data
        bool all_valid = true;
        for (loop = 0; loop < num_sensors; loop++) {
            if (!sensors[loop].valid) {
                all_valid = false;
                break;
            }
        }

        if (all_valid) {
            return 1; // Success
        }
    }

    return 0; // Failure
}

void delay_microseconds(int delay_us) {
    struct timespec ts;
    ts.tv_sec = 0;
    ts.tv_nsec = delay_us * 1000;
    nanosleep(&ts, NULL);
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <unistd.h>
#include <fcntl.h>
#include <time.h>
#include <inttypes.h>

// Define GPIO pins
#define TRIGGER_PIN 17
#define ECHO_PIN 18
#define BUZZER_PIN 27

// Define constants
#define SPEED_OF_SOUND 34300.0 // Speed of sound in cm/s
#define DISTANCE_THRESHOLD 20.0  // Distance threshold in cm
#define BUZZER_DURATION_MS 100   // Buzzer duration in milliseconds
#define ECHO_TIMEOUT_US 500000    // 0.5 seconds timeout for echo

// Helper function to write to a file
int write_to_file(const char *path, const char *value) {
  int fd = open(path, O_WRONLY);
  if (fd < 0) {
    perror("open");
    fprintf(stderr, "Error opening %s: %s\n", path, strerror(errno));
    return -1;
  }
  if (write(fd, value, strlen(value)) < 0) {
    perror("write");
    close(fd);
    return -1;
  }
  close(fd);
  return 0;
}

// Helper function to read from a file
int read_from_file(const char *path, char *buffer, size_t buffer_size) {
  int fd = open(path, O_RDONLY);
  if (fd < 0) {
    perror("open");
    fprintf(stderr, "Error opening %s: %s\n", path, strerror(errno));
    return -1;
  }
  ssize_t count = read(fd, buffer, buffer_size - 1);
  if (count < 0) {
    perror("read");
    close(fd);
    return -1;
  }
  buffer[count] = '\0';
  close(fd);
  return 0;
}

// Function to export a GPIO pin
int gpio_export(int pin) {
  char buffer[3];
  snprintf(buffer, sizeof(buffer), "%d", pin);
  return write_to_file("/sys/class/gpio/export", buffer);
}

// Function to unexport a GPIO pin
int gpio_unexport(int pin) {
  char buffer[3];
  snprintf(buffer, sizeof(buffer), "%d", pin);
  return write_to_file("/sys/class/gpio/unexport", buffer);
}

// Function to set the direction of a GPIO pin (in or out)
int gpio_set_direction(int pin, const char *direction) {
  char path[64];
  snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/direction", pin);
  return write_to_file(path, direction);
}

// Function to write a value to a GPIO pin (0 or 1)
int gpio_write(int pin, int value) {
  char path[64];
  char buffer[2];
  snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", pin);
  snprintf(buffer, sizeof(buffer), "%d", value);
  return write_to_file(path, buffer);
}

// Function to read the value of a GPIO pin
int gpio_read(int pin) {
  char path[64];
  char buffer[3];
  snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", pin);
  if (read_from_file(path, buffer, sizeof(buffer)) < 0) {
    return -1; // Error reading the value
  }
  return atoi(buffer);
}

// Function to adjust the speed of sound based on temperature (in Celsius)
float adjust_speed_of_sound(float temperature) {
  return 331.45 + (0.62 * temperature); // Speed of sound in m/s
}

// Function to measure the pulse duration on the echo pin
long measure_pulse_duration() {
  struct timespec start, end;
  int timeout = ECHO_TIMEOUT_US; // Timeout in microseconds

  // Wait for the echo pin to go high
  while (gpio_read(ECHO_PIN) == 0) {
    clock_gettime(CLOCK_MONOTONIC, &start);
    if (timeout-- < 0) {
      fprintf(stderr, "Error: Echo pulse timeout waiting for HIGH.\n");
      return -1; // Timeout
    }
    usleep(1); // Small delay to avoid busy-waiting
  }

  clock_gettime(CLOCK_MONOTONIC, &start);

  // Wait for the echo pin to go low
  timeout = ECHO_TIMEOUT_US;
  while (gpio_read(ECHO_PIN) == 1) {
    clock_gettime(CLOCK_MONOTONIC, &end);
    if (timeout-- < 0) {
      fprintf(stderr, "Error: Echo pulse timeout waiting for LOW.\n");
      return -1; // Timeout
    }
    usleep(1); // Small delay to avoid busy-waiting
  }

  clock_gettime(CLOCK_MONOTONIC, &end);

  // Calculate the pulse duration in nanoseconds
  long start_ns = start.tv_sec * 1000000000L + start.tv_nsec;
  long end_ns = end.tv_sec * 1000000000L + end.tv_nsec;
  long pulse_duration = end_ns - start_ns;

  return pulse_duration;
}

// Function to calculate the distance in centimeters
float calculate_distance(long pulse_duration) {
  if (pulse_duration < 0) {
    return -1.0; // Indicate an error
  }

  float time_in_seconds = (float)pulse_duration / 1000000000.0;
  float distance = (time_in_seconds * SPEED_OF_SOUND) / 2.0;
  return distance;
}

// Function to activate the buzzer for a specified duration
int buzzer_on(int pin, int duration_ms) {
  if (gpio_write(pin, 1) < 0) {
    return -1;
  }
  usleep(duration_ms * 1000); // Convert milliseconds to microseconds
  return 0;
}

// Function to deactivate the buzzer
int buzzer_off(int pin) {
  return gpio_write(pin, 0);
}

int main() {
  // Export GPIO pins
  if (gpio_export(TRIGGER_PIN) < 0 ||
      gpio_export(ECHO_PIN) < 0 ||
      gpio_export(BUZZER_PIN) < 0) {
    fprintf(stderr, "Failed to export GPIO pins.\n");
    return 1;
  }

  // Set GPIO directions
  if (gpio_set_direction(TRIGGER_PIN, "out") < 0 ||
      gpio_set_direction(ECHO_PIN, "in") < 0 ||
      gpio_set_direction(BUZZER_PIN, "out") < 0) {
    fprintf(stderr, "Failed to set GPIO directions.\n");
    goto cleanup;
  }

  // Main loop
  while (1) {
    // Trigger the ultrasonic sensor
    gpio_write(TRIGGER_PIN, 0); // Ensure low
    usleep(2);                   // 2 us
    gpio_write(TRIGGER_PIN, 1);
    usleep(10); // 10 us trigger pulse
    gpio_write(TRIGGER_PIN, 0);

    // Measure the echo pulse duration
    long pulse_duration = measure_pulse_duration();
    if (pulse_duration < 0) {
      fprintf(stderr, "Error: Failed to measure pulse duration.\n");
      continue; // Retry measurement
    }

    // Calculate the distance
    float distance = calculate_distance(pulse_duration);

    if (distance < 0) {
      fprintf(stderr, "Error: Invalid pulse duration.\n");
      continue; // Retry measurement
    }

    // Print the distance
    printf("Distance: %.2f cm\n", distance);

    // Activate the buzzer if the distance is less than the threshold
    if (distance < DISTANCE_THRESHOLD) {
      printf("Distance is less than %.2f cm. Activating buzzer.\n", DISTANCE_THRESHOLD);
      if (buzzer_on(BUZZER_PIN, BUZZER_DURATION_MS) < 0) {
        fprintf(stderr, "Failed to activate buzzer.\n");
      }
      buzzer_off(BUZZER_PIN);
    }

    sleep(1); // Wait for 1 second before the next measurement
  }

cleanup:
  // Unexport GPIO pins
  gpio_unexport(TRIGGER_PIN);
  gpio_unexport(ECHO_PIN);
  gpio_unexport(BUZZER_PIN);

  return 1;
}

#include <stdio.h>
