#define LED_PIN 13
#define BUTTON_PIN 19

void button_callback(int gpio, int level, uint32_t tick)
{
  if (gpio == BUTTON_PIN)
  {
    if (level == 0) // Button pressed (LOW)
    {
      gpioWrite(LED_PIN, 0); // Turn LED off
    }
    else if (level == 1) // Button released (HIGH)
    {
      gpioWrite(LED_PIN, 1); // Turn LED on
    }
  }
}

