  gpioSetPullUpDown(BUTTON_PIN, PI_PUD_UP); // Use internal pull-up resistor

  gpioWrite(LED_PIN, 1); // Initially turn LED on

  gpioSetAlertFunc(BUTTON_PIN, button_callback); // Set callback for button

  printf("Press CTRL+C to exit\n");

  while (1)
  {
    // Keep the program running
    gpioDelay(100); // Avoid busy-waiting
  }

  gpioTerminate();
  return 0;
}

#include <stdio.h>
#include <wiringPi.h>

// Define the Raspberry Pi pins connected to the LED matrix columns and rows.
// Adjust these pins based on your wiring.
#define ROW_1 0
#define ROW_2 1
#define ROW_3 2
#define ROW_4 3
#define ROW_5 4
#define ROW_6 5
#define ROW_7 6
#define ROW_8 7

#define COL_1 8
#define COL_2 9
#define COL_3 10
#define COL_4 11
#define COL_5 12
#define COL_6 13
#define COL_7 14
#define COL_8 15

// Define the LED pattern to display.  1 = LED ON, 0 = LED OFF.
// Each byte represents a row.
unsigned char led_pattern[8] = {
  0b00111100, // Row 1
  0b00100100, // Row 2
  0b00100100, // Row 3
  0b00000000, // Row 4
  0b00000000, // Row 5
  0b00100100, // Row 6
  0b00100100, // Row 7
  0b00111100  // Row 8
};

// Function to display a single row.
void display_row(int row_num, unsigned char row_data) {
  // Set the row pin HIGH to enable the row.
  switch (row_num) {
    case 0: digitalWrite(ROW_1, HIGH); break;
    case 1: digitalWrite(ROW_2, HIGH); break;
    case 2: digitalWrite(ROW_3, HIGH); break;
    case 3: digitalWrite(ROW_4, HIGH); break;
    case 4: digitalWrite(ROW_5, HIGH); break;
    case 5: digitalWrite(ROW_6, HIGH); break;
    case 6: digitalWrite(ROW_7, HIGH); break;
    case 7: digitalWrite(ROW_8, HIGH); break;
    default: return; // Invalid row number.
  }

  // Set the column pins based on the row data.
  digitalWrite(COL_1, (row_data >> 0) & 0x01);  // Rightmost bit is column 1
  digitalWrite(COL_2, (row_data >> 1) & 0x01);
  digitalWrite(COL_3, (row_data >> 2) & 0x01);
  digitalWrite(COL_4, (row_data >> 3) & 0x01);
  digitalWrite(COL_5, (row_data >> 4) & 0x01);
  digitalWrite(COL_6, (row_data >> 5) & 0x01);
  digitalWrite(COL_7, (row_data >> 6) & 0x01);
  digitalWrite(COL_8, (row_data >> 7) & 0x01);  // Leftmost bit is column 8

  // Delay for a short time to illuminate the LEDs.
  delayMicroseconds(500); // Adjust delay for brightness.

  // Disable the row pin.
  switch (row_num) {
    case 0: digitalWrite(ROW_1, LOW); break;
    case 1: digitalWrite(ROW_2, LOW); break;
    case 2: digitalWrite(ROW_3, LOW); break;
    case 3: digitalWrite(ROW_4, LOW); break;
    case 4: digitalWrite(ROW_5, LOW); break;
    case 5: digitalWrite(ROW_6, LOW); break;
    case 6: digitalWrite(ROW_7, LOW); break;
    case 7: digitalWrite(ROW_8, LOW); break;
    default: return; // Invalid row number.
  }

}

int main() {
  // Initialize WiringPi.
  if (wiringPiSetup() == -1) {
    fprintf(stderr, "WiringPi initialization failed!\n");
    return 1;
  }

  // Set the row and column pins as output.
  pinMode(ROW_1, OUTPUT);
  pinMode(ROW_2, OUTPUT);
  pinMode(ROW_3, OUTPUT);
  pinMode(ROW_4, OUTPUT);
  pinMode(ROW_5, OUTPUT);
  pinMode(ROW_6, OUTPUT);
  pinMode(ROW_7, OUTPUT);
  pinMode(ROW_8, OUTPUT);

  pinMode(COL_1, OUTPUT);
  pinMode(COL_2, OUTPUT);
  pinMode(COL_3, OUTPUT);
  pinMode(COL_4, OUTPUT);
  pinMode(COL_5, OUTPUT);
  pinMode(COL_6, OUTPUT);
  pinMode(COL_7, OUTPUT);
  pinMode(COL_8, OUTPUT);

  // Display the static pattern in a loop.
  while (1) {
    for (int i = 0; i < 8; i++) {
      display_row(i, led_pattern[i]);
    }
  }

  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <unistd.h>
#include <signal.h>
#include <time.h>

// Define GPIO pins
#define TRIGGER_PIN 17
#define ECHO_PIN 18
#define BUZZER_PIN 27

// Constants
#define SPEED_OF_SOUND 34300.0 // Speed of sound in cm/s
#define TIMEOUT_US 500000       // 0.5 seconds timeout in microseconds
#define BUZZER_THRESHOLD 30.0   // Distance threshold for buzzer activation in cm
#define BUZZER_DELAY_MS 200      // Buzzer activation delay in milliseconds

// Global variables
FILE *log_file;
volatile sig_atomic_t program_running = 1;

// Function prototypes
int initialize_pigpio();
void trigger_hc_sr04();
long long measure_echo_pulse();
double calculate_distance(long long pulse_duration);
void activate_buzzer(double distance);
void log_message(const char *message);
void signal_handler(int signal);

// pigpio Initialization
int initialize_pigpio() {
    if (gpioInitialise() < 0) {
        log_message("pigpio initialisation failed");
        return -1;
    }
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);
    return 0;
}

// HC-SR04 Trigger
void trigger_hc_sr04() {
    gpioWrite(TRIGGER_PIN, 1);
    gpioDelay(10); // 10 us trigger pulse
    gpioWrite(TRIGGER_PIN, 0);
}

// Echo Pulse Measurement
long long measure_echo_pulse() {
    long long start_tick, end_tick, pulse_duration;

    // Wait for the echo pin to go high
    int count = 0;
    while (gpioRead(ECHO_PIN) == 0) {
        start_tick = gpioTick();
        if (count++ > TIMEOUT_US) {
            log_message("Echo pulse timeout (waiting for HIGH)");
            return -1;
        }
        usleep(1); // Small delay to prevent busy-waiting
    }

    // Measure the pulse duration
    count = 0;
    while (gpioRead(ECHO_PIN) == 1) {
        end_tick = gpioTick();
        if (count++ > TIMEOUT_US) {
            log_message("Echo pulse timeout (waiting for LOW)");
            return -1;
        }
        usleep(1); // Small delay to prevent busy-waiting
    }

    pulse_duration = end_tick - start_tick;
    return pulse_duration;
}

// Distance Calculation
double calculate_distance(long long pulse_duration) {
    if (pulse_duration < 0) return -1.0; // Indicate error
    return (double)pulse_duration * SPEED_OF_SOUND / 2000000.0; // Divide by 2 for one-way distance
}

// Buzzer Activation
void activate_buzzer(double distance) {
    if (distance >= 0 && distance < BUZZER_THRESHOLD) {
        gpioWrite(BUZZER_PIN, 1); // Activate buzzer
        log_message("Buzzer activated");
        gpioDelay(BUZZER_DELAY_MS);
        gpioWrite(BUZZER_PIN, 0); // Deactivate buzzer
    }
}

// Logging
void log_message(const char *message) {
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    fprintf(log_file, "[%d-%02d-%02d %02d:%02d:%02d] %s\n",
            t->tm_year + 1900, t->tm_mon + 1, t->tm_mday, t->tm_hour, t->tm_min, t->tm_sec, message);
    fflush(log_file);
}

// Signal Handler
void signal_handler(int signal) {
    program_running = 0;
    log_message("Signal received, exiting...");
}

int main() {
    // Open log file
    log_file = fopen("sensor_log.txt", "a");
    if (log_file == NULL) {
        perror("Error opening log file");
        return 1;
    }

    // Signal handling
    signal(SIGINT, signal_handler);

    // Initialize pigpio
    if (initialize_pigpio() != 0) {
        fclose(log_file);
        return 1;
    }

    log_message("Parking sensor started");

    // Main loop
    while (program_running) {
        trigger_hc_sr04();
        long long pulse_duration = measure_echo_pulse();
        if (pulse_duration >= 0) {
            double distance = calculate_distance(pulse_duration);
            if (distance >= 0) {
                printf("Distance: %.2f cm\n", distance);
                activate_buzzer(distance);
            } else {
                log_message("Error calculating distance");
            }
        } else {
            log_message("Error measuring echo pulse");
        }
        gpioDelay(50); // Delay between readings
    }

    // Cleanup
    gpioWrite(BUZZER_PIN, 0); // Ensure buzzer is off
    gpioTerminate();
    fclose(log_file);
    log_message("Parking sensor stopped");
    return 0;
}

