#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>

#define SERVO1 12
#define SERVO2 13
#define SERVO3 18

// Define minimum and maximum pulse widths (microseconds)
#define MIN_PULSE_WIDTH 1000
#define MAX_PULSE_WIDTH 2000

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(SERVO1, PI_OUTPUT);
    gpioSetMode(SERVO2, PI_OUTPUT);
    gpioSetMode(SERVO3, PI_OUTPUT);

    int i;
    while (1) {
        // Sweep from min to max
        for (i = MIN_PULSE_WIDTH; i <= MAX_PULSE_WIDTH; i += 10) {
            gpioServo(SERVO1, i);
            gpioServo(SERVO2, i);
            gpioServo(SERVO3, i);
            usleep(20000); // Short delay to allow movement (20ms)
        }

        // Sweep from max to min
        for (i = MAX_PULSE_WIDTH; i >= MIN_PULSE_WIDTH; i -= 10) {
            gpioServo(SERVO1, i);
            gpioServo(SERVO2, i);
            gpioServo(SERVO3, i);
            usleep(20000); // Short delay to allow movement (20ms)
        }
    }

    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <unistd.h>
#include <fcntl.h>
#include <signal.h>
#include <time.h>

// Define GPIO pins
#define SOUND_SENSOR_PIN 4
#define LED_PIN 17

// Define constants
#define ALARM_DURATION_SEC 5
#define FLASH_PERIOD_USEC 500000 // 0.5 seconds

// Global flag to signal program termination
volatile sig_atomic_t terminate = 0;

// Signal handler for SIGINT (Ctrl+C)
void signal_handler(int sig)
{
    (void)sig; // Suppress unused parameter warning
    terminate = 1;
    fprintf(stderr, "\nCaught signal, exiting gracefully...\n");
}

// Function to export a GPIO pin
int gpio_export(int pin)
{
    char buffer[3];
    int fd;

    fd = open("/sys/class/gpio/export", O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Error opening /sys/class/gpio/export: %s\n", strerror(errno));
        return -1;
    }

    int len = snprintf(buffer, sizeof(buffer), "%d", pin);
    if (write(fd, buffer, len) != len) {
        fprintf(stderr, "Error writing to /sys/class/gpio/export: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to unexport a GPIO pin
int gpio_unexport(int pin)
{
    char buffer[3];
    int fd;

    fd = open("/sys/class/gpio/unexport", O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Error opening /sys/class/gpio/unexport: %s\n", strerror(errno));
        return -1;
    }

    int len = snprintf(buffer, sizeof(buffer), "%d", pin);
    if (write(fd, buffer, len) != len) {
        fprintf(stderr, "Error writing to /sys/class/gpio/unexport: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to set the direction of a GPIO pin (input or output)
int gpio_set_direction(int pin, char *direction)
{
    char path[64];
    int fd;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/direction", pin);
    fd = open(path, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Error opening %s: %s\n", path, strerror(errno));
        return -1;
    }

    if (write(fd, direction, strlen(direction)) != (ssize_t)strlen(direction)) {
        fprintf(stderr, "Error writing to %s: %s\n", path, strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to write a value (0 or 1) to a GPIO pin
int gpio_write(int pin, int value)
{
    char path[64];
    int fd;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", pin);
    fd = open(path, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Error opening %s: %s\n", path, strerror(errno));
        return -1;
    }

    if (value != 0 && value != 1) {
        fprintf(stderr, "Error: Invalid GPIO value (must be 0 or 1)\n");
        close(fd);
        return -1;
    }

    char val_str[2];
    snprintf(val_str, sizeof(val_str), "%d", value);
    if (write(fd, val_str, 1) != 1) {
        fprintf(stderr, "Error writing to %s: %s\n", path, strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to read the value (0 or 1) from a GPIO pin
int gpio_read(int pin)
{
    char path[64];
    int fd;
    char value_str[3];

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", pin);
    fd = open(path, O_RDONLY);
    if (fd < 0) {
        fprintf(stderr, "Error opening %s: %s\n", path, strerror(errno));
        return -1;
    }

    if (read(fd, value_str, 3) < 0) {
        fprintf(stderr, "Error reading from %s: %s\n", path, strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return atoi(value_str);
}

// Function to log the alarm event with timestamp
int log_alarm(void)
{
    FILE *fp;
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[64];

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    fp = fopen("alarm_log.txt", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening alarm_log.txt: %s\n", strerror(errno));
        return -1;
    }

    fprintf(fp, "%s: Alarm triggered\n", timestamp);
    fclose(fp);
    return 0;
}

int main()
{
    // Install signal handler
    signal(SIGINT, signal_handler);

    // Export GPIO pins
    if (gpio_export(SOUND_SENSOR_PIN) < 0 || gpio_export(LED_PIN) < 0) {
        fprintf(stderr, "Error exporting GPIO pins, exiting...\n");
        goto cleanup;
    }

    // Set GPIO directions
    if (gpio_set_direction(SOUND_SENSOR_PIN, "in") < 0 || gpio_set_direction(LED_PIN, "out") < 0) {
        fprintf(stderr, "Error setting GPIO directions, exiting...\n");
        goto cleanup;
    }

    fprintf(stderr, "Monitoring sound sensor...\n");

    // Main loop
    while (!terminate) {
        int sensor_value = gpio_read(SOUND_SENSOR_PIN);
        if (sensor_value < 0) {
            fprintf(stderr, "Error reading sound sensor value, exiting...\n");
            goto cleanup;
        }

        // Check if sound threshold is exceeded (sensor output is low)
        if (sensor_value == 0) {
            fprintf(stderr, "Sound detected! Triggering alarm...\n");

            // Log the alarm event
            if (log_alarm() < 0) {
                fprintf(stderr, "Error logging alarm event\n");
            }

            // Flash the LED for ALARM_DURATION_SEC seconds
            for (int i = 0; i < ALARM_DURATION_SEC * 2; i++) {
                if (gpio_write(LED_PIN, 1) < 0) {
                    fprintf(stderr, "Error writing to LED pin, exiting...\n");
                    goto cleanup;
                }
                usleep(FLASH_PERIOD_USEC);
                if (gpio_write(LED_PIN, 0) < 0) {
                    fprintf(stderr, "Error writing to LED pin, exiting...\n");
                    goto cleanup;
                }
                usleep(FLASH_PERIOD_USEC);

                if (terminate) break; // Check for termination signal during alarm
            }
        }

        usleep(100000); // Check every 0.1 seconds
    }

cleanup:
    // Unexport GPIO pins
    gpio_unexport(SOUND_SENSOR_PIN);
    gpio_unexport(LED_PIN);

    fprintf(stderr, "Exiting program.\n");
    return 0;
}

#include <stdio.h>
