// Define the GPIO pin connected to the relay (using WiringPi numbering)
#define RELAY_PIN 1

// Define the on and off durations in milliseconds
#define ON_DURATION_MS 5000
#define OFF_DURATION_MS 1000

int main(void) {
    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return EXIT_FAILURE;
    }

    // Set the relay pin as an output
    pinMode(RELAY_PIN, OUTPUT);

    // Main loop to control the relay
    while (1) {
        // Turn the relay on (HIGH)
        digitalWrite(RELAY_PIN, HIGH);
        printf("Relay turned ON\n");
        fflush(stdout); // Ensure the output is printed immediately

        // Wait for the specified duration
        delay(ON_DURATION_MS);

        // Turn the relay off (LOW)
        digitalWrite(RELAY_PIN, LOW);
        printf("Relay turned OFF\n");
        fflush(stdout); // Ensure the output is printed immediately

        // Wait for the specified duration
        delay(OFF_DURATION_MS);
    }

    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Define constants
#define VALVE_PIN 1  // wiringPi pin 1 (GPIO18)
#define I2C_ADDRESS 0x13
#define MOISTURE_REGISTER 0x00
#define DEFAULT_MOISTURE 500
#define MIN_MOISTURE 0
#define MAX_MOISTURE 1000
#define PWM_RANGE 100

// Global variables
int i2c_fd;
FILE *log_file;
volatile sig_atomic_t program_running = 1; // Flag to control the main loop

// Function prototypes
int read_moisture_sensor();
int calculate_pwm_duty_cycle(int moisture_level);
void set_valve_position(int duty_cycle);
void log_data(time_t timestamp, int moisture_level, int valve_position);
void signal_handler(int signal);

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("Received SIGINT. Shutting down gracefully.\n");
        program_running = 0; // Stop the main loop
        set_valve_position(0); // Close the valve
        if (log_file != NULL) {
            fclose(log_file); // Close the log file
        }
        exit(0); // Exit the program
    }
}

// Function to read moisture data from the VH400 sensor
int read_moisture_sensor() {
    int moisture_level;

    moisture_level = wiringPiI2CReadReg16(i2c_fd, MOISTURE_REGISTER);
    if (moisture_level < 0) {
        fprintf(stderr, "Error reading moisture sensor data!\n");
        log_data(time(NULL), -1, -1); // Log the error
        return DEFAULT_MOISTURE; // Return a default value
    }

    // Validate the sensor data
    if (moisture_level < MIN_MOISTURE || moisture_level > MAX_MOISTURE) {
        fprintf(stderr, "Invalid moisture level: %d. Using default value.\n", moisture_level);
        log_data(time(NULL), moisture_level, -1); // Log the error
        return DEFAULT_MOISTURE;
    }

    return moisture_level;
}

// Function to calculate the PWM duty cycle based on the moisture level
int calculate_pwm_duty_cycle(int moisture_level) {
    // Proportional control algorithm
    // Map the moisture level (0-1000) to the duty cycle (0-100)
    // Lower moisture level -> Higher duty cycle
    int duty_cycle = 100 - (moisture_level * 100 / 1000); // Invert and scale

    // Ensure the duty cycle is within the valid range
    if (duty_cycle < 0) {
        duty_cycle = 0;
    } else if (duty_cycle > 100) {
        duty_cycle = 100;
    }

    return duty_cycle;
}

// Function to set the PWM duty cycle on GPIO18
void set_valve_position(int duty_cycle) {
    pwmWrite(VALVE_PIN, duty_cycle);
}

// Function to log data to a file
void log_data(time_t timestamp, int moisture_level, int valve_position) {
    char timestamp_str[30];
    struct tm *timeinfo;

    timeinfo = localtime(&timestamp);
    strftime(timestamp_str, sizeof(timestamp_str), "%Y-%m-%d %H:%M:%S", timeinfo);

    if (log_file != NULL) {
        fprintf(log_file, "%s, Moisture: %d, Valve Position: %d\n", timestamp_str, moisture_level, valve_position);
        fflush(log_file); // Ensure data is written to the file immediately
    } else {
        fprintf(stderr, "Error: Log file is not open!\n");
    }
}

int main() {
    int moisture_level, duty_cycle;
    time_t current_time;

    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "wiringPiSetupGpio failed!\n");
        return 1;
    }

    // Configure GPIO18 as PWM output
    pwmSetMode(PWM_MODE_MS);
    pwmSetRange(PWM_RANGE);
    pwmSetClock(192); // Adjust for ~50Hz PWM frequency.  Clock frequency = 19.2 MHz / divisor.  19.2MHz / 192 / 100 = 1000 Hz. Actual frequency depends on the divisor.

    // Initialize I2C communication
    i2c_fd = wiringPiI2CSetup(I2C_ADDRESS);
    if (i2c_fd == -1) {
        fprintf(stderr, "wiringPiI2CSetup failed!\n");
        return 1;
    }

    // Open the log file in append mode
    log_file = fopen("irrigation_log.txt", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        return 1;
    }

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Main loop
    while (program_running) {
        // Read moisture sensor data
        moisture_level = read_moisture_sensor();

        // Calculate PWM duty cycle
        duty_cycle = calculate_pwm_duty_cycle(moisture_level);

        // Set valve position
        set_valve_position(duty_cycle);

        // Log data
        current_time = time(NULL);
        log_data(current_time, moisture_level, duty_cycle);

        // Delay for 5 seconds
        delay(5000);
    }

    // Close the valve and log file before exiting
    set_valve_position(0);
    fclose(log_file);

    return 0;
}

#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>
#include <linux/spi/spidev.h>
#include <sys/ioctl.h>
#include <stdint.h>

void print_binary(int value) {
    for (int i = 9; i >= 0; i--) {
        printf("%d", (value >> i) & 1);
    }
    printf("\n");
}

int main() {
    const char* spi_dev = "/dev/spidev0.0";
    int fd = open(spi_dev, O_RDWR);
    if (fd < 0) {
        perror("SPI open failed");
        return 1;
    }

    uint8_t tx[3] = {0x01, 0x80, 0x00};
    uint8_t rx[3] = {0};
    struct spi_ioc_transfer tr = {
        .tx_buf = (unsigned long)tx,
        .rx_buf = (unsigned long)rx,
        .len = 3,
        .speed_hz = 1000000,
        .bits_per_word = 8,
    };
    ioctl(fd, SPI_IOC_MESSAGE(1), &tr);
    int value = ((rx[1] & 0x03) << 8) | rx[2];
    printf("Binary output from channel 0: ");
    print_binary(value);
    close(fd);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <time.h>
#include <signal.h>
#include <errno.h>

// Define GPIO pins
#define TRIGGER_PIN 4
#define ECHO_PIN 5
#define RELAY_PIN 17
#define DOOR_SENSOR_PIN 27

// Define constants
#define MAX_DISTANCE 10.0  // Maximum distance for object detection (cm)
#define TIMEOUT 30000       // Timeout for ultrasonic sensor (microseconds)

// Global variable for log file pointer (needed for signal handler)
FILE *logFile = NULL;

// Function prototypes
float measureDistance();
int isObjectDetected(float distance);
void setRelayState(int state);
int getDoorState();
void logEvent(int doorState);
void signalHandler(int signum);

// Function to measure distance using HC-SR04 ultrasonic sensor
float measureDistance() {
    digitalWrite(TRIGGER_PIN, LOW);
    delayMicroseconds(2);
    digitalWrite(TRIGGER_PIN, HIGH);
    delayMicroseconds(10);
    digitalWrite(TRIGGER_PIN, LOW);

    long startTime = micros();
    long travelTime;

    // Wait for echo to start or timeout
    while (digitalRead(ECHO_PIN) == LOW) {
        if (micros() - startTime > TIMEOUT) {
            fprintf(stderr, "Timeout waiting for ECHO start.\n");
            return -1.0; // Indicate timeout error
        }
    }

    startTime = micros();

    // Wait for echo to end or timeout
    while (digitalRead(ECHO_PIN) == HIGH) {
        if (micros() - startTime > TIMEOUT) {
            fprintf(stderr, "Timeout waiting for ECHO end.\n");
            return -1.0; // Indicate timeout error
        }
    }

    travelTime = micros() - startTime;

    // Calculate distance in centimeters
    float distance = travelTime / 58.0; // Speed of sound adjustment
    return distance;
}

// Function to check if an object is detected within the maximum distance
int isObjectDetected(float distance) {
    return (distance >= 0.0 && distance <= MAX_DISTANCE) ? 1 : 0; //Added distance >= 0.0 check
}

// Function to set the state of the relay (HIGH for activate, LOW for deactivate)
void setRelayState(int state) {
    digitalWrite(RELAY_PIN, state);
}

// Function to get the state of the door sensor (1 for open, 0 for closed)
int getDoorState() {
    return digitalRead(DOOR_SENSOR_PIN);
}

// Function to log door open/close events with timestamps
void logEvent(int doorState) {
    if (logFile == NULL) {
        fprintf(stderr, "Error: Log file is not open.\n");
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(logFile, "%d-%02d-%02d %02d:%02d:%02d - Door: %s\n",
            tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec,
            doorState == 1 ? "Open" : "Closed");
    fflush(logFile); // Ensure the log is written immediately
}

// Signal handler for graceful shutdown
void signalHandler(int signum) {
    printf("Interrupt signal (%d) received.\n", signum);
    setRelayState(LOW); // Close the door

    if (logFile != NULL) {
        fclose(logFile);
    }

    wiringPiSetupGpio(); // Reinitialize wiringPi to safely set pins to input mode
    pinMode(RELAY_PIN, INPUT); // Set relay pin to input
    pinMode(TRIGGER_PIN, INPUT); // Set trigger pin to input
    pinMode(ECHO_PIN, INPUT); // Set echo pin to input
    pinMode(DOOR_SENSOR_PIN, INPUT); // Set door sensor pin to input

    exit(signum);
}

int main() {
    // Initialize wiringPi using GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
        return 1;
    }

    // Set GPIO pin modes
    pinMode(TRIGGER_PIN, OUTPUT);
    pinMode(ECHO_PIN, INPUT);
    pinMode(RELAY_PIN, OUTPUT);
    pinMode(DOOR_SENSOR_PIN, INPUT);
    pullUpDnControl(DOOR_SENSOR_PIN, PUD_UP); // Enable pull-up resistor on the door sensor

    // Open the log file
    logFile = fopen("door_events.log", "a");
    if (logFile == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        return 1;
    }

    // Register signal handler for Ctrl+C
    signal(SIGINT, signalHandler);

    printf("Automated Door System started. Press Ctrl+C to exit.\n");

    // Main loop
    while (1) {
        float distance = measureDistance();
        if (distance < 0.0) {
            fprintf(stderr, "Error measuring distance. Retrying...\n");
        } else {
            int objectDetected = isObjectDetected(distance);

            if (objectDetected) {
                setRelayState(HIGH); // Open the door
            } else {
                setRelayState(LOW); // Close the door
            }

            int doorState = getDoorState();
            logEvent(doorState);
        }

        delay(100); // Delay to avoid excessive CPU usage
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <wiringPi.h>
#include <time.h>
#include <errno.h>
#include <string.h>

// Constants for test parameters
#define FAST_COUNT 10000000
#define SLOW_COUNT  1000000
#define PASSES        5

// Function to measure the execution time
double time_diff(struct timespec start, struct timespec end)
{
    return (end.tv_sec - start.tv_sec) + (end.tv_nsec - start.tv_nsec) / 1e9;
}

// Function to perform the speed test for a given pin and iteration count
int speedTest(int gpioPin, int maxCount, const char *testName)
{
    int count, i;
    double totalTime = 0.0;
    struct timespec startTime, endTime;

    printf("\n%s: (%8d iterations)\n", testName, maxCount);

    for (i = 0; i < PASSES; ++i)
    {
        if (clock_gettime(CLOCK_MONOTONIC, &startTime) == -1) {
            fprintf(stderr, "Error getting start time: %s\n", strerror(errno));
            return 1; // Indicate failure
        }

        for (count = 0; count < maxCount; ++count)
        {
            digitalWrite(gpioPin, HIGH); // Set the pin high
            digitalWrite(gpioPin, LOW);  // Set the pin low
        }

        if (clock_gettime(CLOCK_MONOTONIC, &endTime) == -1) {
            fprintf(stderr, "Error getting end time: %s\n", strerror(errno));
            return 1; // Indicate failure
        }

        double elapsedTime = time_diff(startTime, endTime);
        printf(" %9.6f", elapsedTime);
        fflush(stdout);
        totalTime += elapsedTime;
    }

    double avgTime = totalTime / PASSES;
    printf(". Avg: %9.6fs", avgTime);
    int perSec = (int)((double)maxCount / avgTime);
    printf(": %9d/sec\n", perSec);

    return 0; // Indicate success
}

int main(void)
{
    printf("Raspberry Pi wiringPi GPIO speed test program\n");
    printf("=============================================\n");

    int result;

    // Native wiringPi method
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed, exiting.\n");
        return 1;
    }
    pinMode(0, OUTPUT);
    result = speedTest(0, FAST_COUNT, "Native wiringPi method");
    if (result != 0) return result;

    // Native GPIO method
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "wiringPiSetupGpio failed, exiting.\n");
        return 1;
    }
    pinMode(17, OUTPUT);
    result = speedTest(17, FAST_COUNT, "Native GPIO method");
    if (result != 0) return result;

    // Physical pin GPIO method
    if (wiringPiSetupPhys() == -1) {
        fprintf(stderr, "wiringPiSetupPhys failed, exiting.\n");
        return 1;
    }
    pinMode(11, OUTPUT);
    result = speedTest(11, FAST_COUNT, "Physical pin GPIO method");
    if (result != 0) return result;

    // /sys/class/gpio method
    if (wiringPiSetupSys() == -1) {
        fprintf(stderr, "wiringPiSetupSys failed, exiting.\n");
        return 1;
    }
    result = speedTest(17, SLOW_COUNT, "/sys/class/gpio method");
    if (result != 0) return result;

    // character device ABI method
    if (wiringPiSetupGpioDevice(WPI_PIN_BCM) == -1) {
        fprintf(stderr, "wiringPiSetupGpioDevice failed, exiting.\n");
        return 1;
    }
    pinMode(17, OUTPUT);
    result = speedTest(17, SLOW_COUNT, "Character device ABI method");
    if (result != 0) return result;

    return 0;
}

