#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <signal.h>
#include <unistd.h>
#include <wiringPi.h>
#include <wiringPiSPI.h>

// Constants
#define SPI_CHANNEL 0
#define SPI_SPEED 1000000 // 1MHz
#define MCP3008_CHANNEL 0
#define NUM_LEDS 10

// Error value for MCP3008 reading
#define MCP3008_ERROR -1

// Global flag for signal handling
volatile sig_atomic_t program_running = 1;

// Signal handler function
void signal_handler(int sig)
{
    (void)sig; // Suppress unused parameter warning
    program_running = 0;
    fprintf(stderr, "\nCaught signal, exiting gracefully...\n");
}

// Function to read LDR value from MCP3008
int read_ldr(int channel)
{
    unsigned char buffer[3];
    buffer[0] = 0x01;                                   // Start bit
    buffer[1] = (0x08 | channel) << 4;                   // SGL/DIFF=1, D2=D1=D0=0
    buffer[2] = 0x00;

    if (wiringPiSPIDataRW(SPI_CHANNEL, buffer, 3) == -1)
    {
        fprintf(stderr, "Error: SPI read failed\n");
        return MCP3008_ERROR;
    }

    int adc_value = ((buffer[1] & 0x03) << 8) + buffer[2];
    return adc_value;
}

// Function to map LDR value to brightness (0-255)
unsigned char map_ldr_to_brightness(int ldr_value)
{
    // Linear mapping from 0-1023 to 0-255
    if (ldr_value < 0) return 0; //handle error case
    if (ldr_value > 1023) return 255; //cap value
    return (unsigned char)(ldr_value / 4); // Divide by 4 to scale 1024 to 256
}

// Function to send APA102 frame
void send_apa102_frame(unsigned char red, unsigned char green, unsigned char blue, unsigned char brightness)
{
    unsigned char buffer[4];

    // Start frame (0x00, 0x00, 0x00, 0x00)
    buffer[0] = 0x00;
    buffer[1] = 0x00;
    buffer[2] = 0x00;
    buffer[3] = 0x00;
    wiringPiSPIDataRW(SPI_CHANNEL, buffer, 4);

    // LED data frame (0b11100000 | brightness, blue, green, red)
    buffer[0] = 0xE0 | brightness; // Global brightness
    buffer[1] = blue;
    buffer[2] = green;
    buffer[3] = red;

    for (int i = 0; i < NUM_LEDS; i++) {
        wiringPiSPIDataRW(SPI_CHANNEL, buffer, 4);
    }

    // End frame (NUM_LEDS / 2 bytes of 0xFF)
    for (int i = 0; i < (NUM_LEDS + 15) / 16; i++) {
        buffer[0] = 0xFF;
        buffer[1] = 0xFF;
        buffer[2] = 0xFF;
        buffer[3] = 0xFF;
        wiringPiSPIDataRW(SPI_CHANNEL, buffer, 4);
    }
}

// Cleanup function
void cleanup()
{
    // Reset SPI (not strictly necessary, but good practice)
    // wiringPiSPIClose(SPI_CHANNEL); // Function doesn't exist
    fprintf(stderr, "Cleanup complete.\n");
}

int main()
{
    // Set up signal handling
    signal(SIGINT, signal_handler);

    // Initialize wiringPi
    if (wiringPiSetup() == -1)
    {
        fprintf(stderr, "Error: wiringPiSetup failed\n");
        return 1;
    }

    // Initialize SPI
    if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) == -1)
    {
        fprintf(stderr, "Error: wiringPiSPISetup failed\n");
        return 1;
    }

    fprintf(stderr, "Program started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running)
    {
        // Read LDR value
        int ldr_value = read_ldr(MCP3008_CHANNEL);
        if (ldr_value == MCP3008_ERROR)
        {
            fprintf(stderr, "Error reading LDR, exiting.\n");
            break;
        }

        // Map LDR value to brightness
        unsigned char brightness = map_ldr_to_brightness(ldr_value);

        // Send APA102 frame (red, green, blue, brightness)
        send_apa102_frame(brightness, 0, brightness, brightness); // Red color with variable brightness

        // Delay
        delay(50); // Adjust as needed
    }

    // Cleanup and exit
    cleanup();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <time.h>
#include <signal.h>
#include <string.h>

#define TILT_PIN 2  // wiringPi pin 2 (physical pin 13)
#define LED_PIN 3   // wiringPi pin 3 (physical pin 15)

volatile sig_atomic_t program_running = 1;
FILE *log_file = NULL;

void cleanup_and_exit(int signal) {
    program_running = 0;
    if (log_file != NULL) {
        fclose(log_file);
    }
    digitalWrite(LED_PIN, LOW); // Turn off LED on exit
    wiringPiSetup(); // Reinitialize to ensure pins are in a known state
    pinMode(LED_PIN, OUTPUT);
    digitalWrite(LED_PIN, LOW);
    printf("\nExiting gracefully.\n");
    exit(0);
}

char* get_timestamp() {
    time_t rawtime;
    struct tm *timeinfo;
    static char timestamp[20]; //YYYY-MM-DD HH:MM:SS\0

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);
    return timestamp;
}

void log_tilt_event() {
    char* timestamp = get_timestamp();
    fprintf(log_file, "%s: Tilt detected\n", timestamp);
    fflush(log_file); // Ensure immediate write to file
}

void toggle_led() {
    static int led_state = LOW;
    led_state = (led_state == LOW) ? HIGH : LOW;
    digitalWrite(LED_PIN, led_state);
}

void tilt_interrupt_handler() {
    // Debounce
    delay(50); // 50ms debounce delay

    // Verify the tilt is still present after the delay
    if (digitalRead(TILT_PIN) == HIGH) {
        log_tilt_event();
        toggle_led();
    }
}

int main() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed. Exiting.\n");
        return 1;
    }

    // Open log file
    log_file = fopen("tilt_log.txt", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file. Exiting.\n");
        return 1;
    }

    // Set up pins
    pinMode(TILT_PIN, INPUT);
    pinMode(LED_PIN, OUTPUT);
    digitalWrite(LED_PIN, LOW); // Initialize LED to off

    // Set up interrupt
    if (wiringPiISR(TILT_PIN, INT_EDGE_RISING, &tilt_interrupt_handler) < 0) {
        fprintf(stderr, "Unable to setup ISR. Exiting.\n");
        return 1;
    }

    // Set up signal handler for graceful shutdown
    signal(SIGINT, cleanup_and_exit);

    printf("Tilt detection program running. Press Ctrl+C to exit.\n");

    while (program_running) {
        delay(100); // Keep the program running
    }

    return 0;
}

#include <stdio.h>
