#include <wiringPi.h>

// Define constants
#define FAN_PIN 1         // WiringPi pin 1 (GPIO18)
#define TEMP_FILE "/sys/class/thermal/thermal_zone0/temp"
#define LOG_FILE "fan_log.txt"
#define POLLING_INTERVAL 5 // Seconds

// Global variables
FILE *log_fp = NULL;
volatile sig_atomic_t program_running = 1;

// Function prototypes
float read_cpu_temp();
int calculate_fan_speed(float temp);
void log_data(float temp, int fan_speed);
void cleanup_handler(int signum);
