int open_log_file();

// Signal handler for graceful shutdown
void cleanup_handler(int signum) {
    program_running = 0;
    printf("\nCaught signal %d, cleaning up...\n", signum);

    // Stop the fan
    pwmWrite(FAN_PIN, 0);

    // Close the log file if it's open
    if (log_fp != NULL) {
        fclose(log_fp);
        printf("Log file closed.\n");
    }

    // Reset GPIO pin to input mode (safer)
    pinMode(FAN_PIN, INPUT);

    wiringPiSetup(); // Reinitialize wiringPi to reset the pin

    exit(0);
}

// Initialize wiringPi and PWM
int init_wiringpi() {
    if (wiringPiSetupGpio() == -1) { // Use GPIO numbering
        fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
        return -1;
    }

    pinMode(FAN_PIN, PWM_OUTPUT);
    pwmSetMode(PWM_MODE_MS);        // Set PWM mode to mark:space
    pwmSetRange(1024);              // Set PWM range (resolution)
    pwmSetClock(192);               // Set PWM clock (adjust as needed)

    return 0;
}

// Open the log file
int open_log_file() {
    log_fp = fopen(LOG_FILE, "a");
    if (log_fp == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

// Read CPU temperature from file
float read_cpu_temp() {
    FILE *fp;
    char temp_str[10];
    float temp_celsius;

    fp = fopen(TEMP_FILE, "r");
    if (fp == NULL) {
        fprintf(stderr, "Error opening temperature file: %s\n", strerror(errno));
        return -1.0; // Indicate error with -1.0
    }

    if (fread(temp_str, 1, sizeof(temp_str) - 1, fp) <= 0) {
        fprintf(stderr, "Error reading temperature file: %s\n", strerror(errno));
        fclose(fp);
        return -1.0; // Indicate error
    }

    fclose(fp);
    temp_str[sizeof(temp_str) - 1] = '\0'; // Ensure null termination
    temp_celsius = atoi(temp_str) / 1000.0;  // Convert to degrees Celsius

    return temp_celsius;
}

// Calculate fan speed based on temperature
int calculate_fan_speed(float temp) {
    int fan_speed;

    if (temp < 40.0) {
        fan_speed = 0;
    } else if (temp < 60.0) {
        fan_speed = (int)((temp - 40.0) / (60.0 - 40.0) * 1023);
    } else {
        fan_speed = 1023;
    }

    return fan_speed;
}

// Log data to file
void log_data(float temp, int fan_speed) {
    if (log_fp == NULL) {
        fprintf(stderr, "Log file not open. Skipping log entry.\n");
        return;
    }

    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char timestamp[64];

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(log_fp, "%s - CPU Temperature: %.2f°C, Fan Speed: %d\n", timestamp, temp, fan_speed);
    fflush(log_fp); // Ensure data is written to disk immediately
}

int main() {
    float cpu_temp;
    int fan_speed;

    // Set up signal handler for Ctrl+C
    signal(SIGINT, cleanup_handler);

    // Initialize wiringPi
    if (init_wiringpi() == -1) {
        return 1;
    }

    // Open log file
    if (open_log_file() == -1) {
        fprintf(stderr, "Logging to file disabled.\n");
    }

    printf("Fan control started. Press Ctrl+C to exit.\n");

    while (program_running) {
        // Read CPU temperature
        cpu_temp = read_cpu_temp();

        if (cpu_temp < 0) {
            fprintf(stderr, "Error reading CPU temperature. Skipping fan control.\n");
        } else {
            // Calculate fan speed
            fan_speed = calculate_fan_speed(cpu_temp);

            // Set fan speed
            pwmWrite(FAN_PIN, fan_speed);

            // Log data
            log_data(cpu_temp, fan_speed);
        }

        // Wait for the next polling interval
        delay(POLLING_INTERVAL * 1000); // delay() is in milliseconds
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pigpio.h>
#include <unistd.h>

// Define GPIO pins for LEDs
#define RED_LED_PIN   16
#define YELLOW_LED_PIN 19
#define GREEN_LED_PIN  26

// Define traffic light timings (in seconds)
#define GREEN_DURATION  3
#define YELLOW_DURATION 1
#define RED_DURATION    3

// Global flag to signal program termination
volatile sig_atomic_t program_running = 1;

// Signal handler for Ctrl+C (SIGINT)
void signal_handler(int signal) {
    (void)signal; // Suppress unused parameter warning
    program_running = 0;
    printf("\nExiting gracefully...\n");
}

// Function to initialize GPIO pins
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }

    gpioSetMode(RED_LED_PIN, PI_OUTPUT);
    gpioSetMode(YELLOW_LED_PIN, PI_OUTPUT);
    gpioSetMode(GREEN_LED_PIN, PI_OUTPUT);

    return 0;
}

// Function to cleanup GPIO pins
void cleanup_gpio() {
    gpioWrite(RED_LED_PIN, PI_LOW);
    gpioWrite(YELLOW_LED_PIN, PI_LOW);
    gpioWrite(GREEN_LED_PIN, PI_LOW);

    gpioSetMode(RED_LED_PIN, PI_INPUT); // Set back to input
    gpioSetMode(YELLOW_LED_PIN, PI_INPUT);
    gpioSetMode(GREEN_LED_PIN, PI_INPUT);

    gpioTerminate();
}

// Function to run the traffic light sequence
void run_traffic_light() {
    // Green light
    gpioWrite(GREEN_LED_PIN, PI_HIGH);
    printf("Green light ON for %d seconds\n", GREEN_DURATION);
    sleep(GREEN_DURATION);
    gpioWrite(GREEN_LED_PIN, PI_LOW);

    // Yellow light (blinking)
    for (int i = 0; i < 3 && program_running; ++i) {
        gpioWrite(YELLOW_LED_PIN, PI_HIGH);
        printf("Yellow light ON (blink %d)\n", i + 1);
        sleep(YELLOW_DURATION);
        gpioWrite(YELLOW_LED_PIN, PI_LOW);
        if (i < 2 && program_running) {
            sleep(YELLOW_DURATION);
        }
    }

    // Red light
    gpioWrite(RED_LED_PIN, PI_HIGH);
    printf("Red light ON for %d seconds\n", RED_DURATION);
    sleep(RED_DURATION);
    gpioWrite(RED_LED_PIN, PI_LOW);
}

int main() {
    // Install signal handler
    signal(SIGINT, signal_handler);

    // Initialize GPIO
    if (initialize_gpio() != 0) {
        return EXIT_FAILURE;
    }

    printf("Traffic light simulation started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        run_traffic_light();
    }

    // Cleanup GPIO before exiting
    cleanup_gpio();

    return EXIT_SUCCESS;
}

