#define BACKWARD_PIN1 27 // IN3 on L293D
#define BACKWARD_PIN2 22 // IN4 on L293D

#define ENABLE_PIN 23    // EN pin, enable the motor. Connect to PWM or High

void motor_forward() {
    gpioWrite(FORWARD_PIN1, 1);
    gpioWrite(FORWARD_PIN2, 0);
    gpioWrite(BACKWARD_PIN1, 0);
    gpioWrite(BACKWARD_PIN2, 0);
    printf("Motor Forward\n");
}

void motor_backward() {
    gpioWrite(FORWARD_PIN1, 0);
    gpioWrite(FORWARD_PIN2, 0);
    gpioWrite(BACKWARD_PIN1, 1);
    gpioWrite(BACKWARD_PIN2, 0);
    printf("Motor Backward\n");
}

void motor_stop() {
    gpioWrite(FORWARD_PIN1, 0);
    gpioWrite(FORWARD_PIN2, 0);
    gpioWrite(BACKWARD_PIN1, 0);
    gpioWrite(BACKWARD_PIN2, 0);
    printf("Motor Stop\n");
}

