#include <signal.h>
#include <errno.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>

// MPR121 I2C Address
#define MPR121_ADDRESS 0x5A

// GPIO pin for LED (wiringPi numbering)
#define LED_PIN 1

// Debounce delay in milliseconds
#define DEBOUNCE_DELAY 200

// Watering cycle duration in seconds
#define WATERING_DURATION 5

// Circular buffer size
#define BUFFER_SIZE 10

// Structure to store touch event data
typedef struct {
    time_t timestamp;
    int electrode;
} TouchEvent;

// Global variables
int i2c_fd;
TouchEvent touch_buffer[BUFFER_SIZE];
int buffer_index = 0;
volatile sig_atomic_t program_running = 1;

// Function prototypes
int mpr121_init(int fd);
int mpr121_read_touch_status(int fd);
void log_touch_event(int electrode);
void display_touch_events();
void watering_cycle();
void cleanup(int signal);

// Signal handler for graceful exit
void cleanup(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);
    program_running = 0;
    digitalWrite(LED_PIN, LOW); // Turn off LED
    exit(0);
}

int main() {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Initialize I2C
    i2c_fd = wiringPiI2CSetup(MPR121_ADDRESS);
    if (i2c_fd == -1) {
        fprintf(stderr, "wiringPiI2CSetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Initialize MPR121
    if (mpr121_init(i2c_fd) != 0) {
        fprintf(stderr, "MPR121 initialization failed\n");
        return 1;
    }

    // Set LED pin as output
    pinMode(LED_PIN, OUTPUT);
    digitalWrite(LED_PIN, LOW); // Initially off

    // Set up signal handler for Ctrl+C
    signal(SIGINT, cleanup);

    printf("Smart Garden Irrigation Trigger Simulation\n");
    printf("Press Ctrl+C to exit\n");

    while (program_running) {
        int touch_status = mpr121_read_touch_status(i2c_fd);
        if (touch_status > 0) {
            // Find the first touched electrode
            for (int i = 0; i < 12; i++) {
                if (touch_status & (1 << i)) {
                    log_touch_event(i);
                    display_touch_events();
                    watering_cycle();
                    delay(DEBOUNCE_DELAY); // Debounce
                    break; // Only trigger once per read
                }
            }
        }
        delay(50); // Check every 50ms
    }

    return 0;
}

// Initialize the MPR121
int mpr121_init(int fd) {
    // Stop mode
    if (wiringPiI2CWriteReg8(fd, 0x80, 0x63) < 0) return -1;
    delay(1);

    // Electrode configuration
    if (wiringPiI2CWriteReg8(fd, 0x5E, 0b11010000) < 0) return -1; // Default value

    // Touch and release thresholds for electrode 0-11
    for (int i = 0; i < 12; i++) {
        if (wiringPiI2CWriteReg8(fd, 0x41 + 2 * i, 40) < 0) return -1; // Touch threshold
        if (wiringPiI2CWriteReg8(fd, 0x42 + 2 * i, 20) < 0) return -1; // Release threshold
    }

    // Debounce configuration
    if (wiringPiI2CWriteReg8(fd, 0x5B, 0x06) < 0) return -1; // Touch debounce = 6, Release debounce = 6

    // Filter configuration
    if (wiringPiI2CWriteReg8(fd, 0x5D, 0x04) < 0) return -1; // Filter configuration

    // Start mode
    if (wiringPiI2CWriteReg8(fd, 0x80, 0x10) < 0) return -1; // Enable all electrodes
    delay(1);

    return 0;
}

// Read the touch status from the MPR121
int mpr121_read_touch_status(int fd) {
    int touch_status = wiringPiI2CReadReg8(fd, 0x00);
    if (touch_status < 0) {
        fprintf(stderr, "Error reading touch status: %s\n", strerror(errno));
        return 0; // Return 0 on error, indicating no touch
    }
    int touch_status_high = wiringPiI2CReadReg8(fd, 0x01);
    if (touch_status_high < 0) {
        fprintf(stderr, "Error reading touch status (high byte): %s\n", strerror(errno));
        return 0;
    }
    return (touch_status_high << 8) | touch_status;
}

// Log a touch event to the circular buffer
void log_touch_event(int electrode) {
    time(&touch_buffer[buffer_index].timestamp);
    touch_buffer[buffer_index].electrode = electrode;
    buffer_index = (buffer_index + 1) % BUFFER_SIZE;
}

// Display the contents of the circular buffer
void display_touch_events() {
    printf("\n--- Touch Event Log ---\n");
    for (int i = 0; i < BUFFER_SIZE; i++) {
        int index = (buffer_index + i) % BUFFER_SIZE;
        if (touch_buffer[index].timestamp != 0) {
            char timestamp_str[30];
            ctime_r(&touch_buffer[index].timestamp, timestamp_str);
            timestamp_str[strlen(timestamp_str) - 1] = '\0'; // Remove trailing newline
            printf("[%s] Electrode: %d\n", timestamp_str, touch_buffer[index].electrode);
        } else {
            printf("[Empty]\n");
        }
    }
    printf("-----------------------\n");
}

// Simulate a watering cycle by toggling the LED
void watering_cycle() {
    printf("Starting watering cycle...\n");
    digitalWrite(LED_PIN, HIGH); // Turn on LED
    delay(WATERING_DURATION * 1000); // Wait for watering duration
    digitalWrite(LED_PIN, LOW);  // Turn off LED
    printf("Watering cycle complete.\n");
}

