#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
#include <errno.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <stdbool.h>
#include <time.h>

// Constants
#define D6F_I2C_ADDR 0x6C  // D6F-PH I2C address (7-bit)
#define I2C_DEVICE "/dev/i2c-1" // I2C device file

// Function Prototypes
uint32_t i2c_write_bytes(int file_descriptor, uint8_t dev_addr, uint8_t* data, uint16_t length);
uint32_t i2c_read_bytes(int file_descriptor, uint8_t dev_addr, uint8_t reg_addr, uint8_t* data, uint16_t length);
uint16_t bytes_to_uint16(uint8_t* buffer);
void safe_delay_ms(int milliseconds);

int main() {
    int i2c_file_descriptor;
    uint8_t init_command[] = {0x0B, 0x00};
    uint8_t trigger_command[] = {0x00, 0xD0, 0x40, 0x18, 0x06};
    uint8_t read_command[] = {0x00, 0xD0, 0x51, 0x2C};
    uint8_t flow_data[2];
    uint16_t raw_flow_data;
    float flow_rate;
    uint32_t status;

    // Open I2C device
    i2c_file_descriptor = open(I2C_DEVICE, O_RDWR);
    if (i2c_file_descriptor < 0) {
        fprintf(stderr, "Error opening I2C device: %s\n", strerror(errno));
        return 1;
    }

    // Initialize sensor (0Bh, 00h)
    status = i2c_write_bytes(i2c_file_descriptor, D6F_I2C_ADDR, init_command, 2);
    if(status != 0){
        fprintf(stderr, "Error initializing sensor\n");
        close(i2c_file_descriptor);
        return 1;
    }
    safe_delay_ms(900); // Initial delay after initialization

    while (1) {
        // Trigger data acquisition (00h, D0h, 40h, 18h, 06h)
        status = i2c_write_bytes(i2c_file_descriptor, D6F_I2C_ADDR, trigger_command, 5);
        if(status != 0){
            fprintf(stderr, "Error triggering data acquisition\n");
            break;
        }

        safe_delay_ms(50); // Wait for conversion

        // Send read command (00h, D0h, 51h, 2Ch)
        status = i2c_write_bytes(i2c_file_descriptor, D6F_I2C_ADDR, read_command, 4);
        if(status != 0){
            fprintf(stderr, "Error sending read command\n");
            break;
        }

        // Read flow data (07h)
        status = i2c_read_bytes(i2c_file_descriptor, D6F_I2C_ADDR, 0x07, flow_data, 2);
        if(status != 0){
            fprintf(stderr, "Error reading flow data\n");
            break;
        }

        // Convert received bytes to unsigned 16-bit integer
        raw_flow_data = bytes_to_uint16(flow_data);

        // Calculate flow rate (0-20 L/min range)
        flow_rate = ((float)raw_flow_data - 1024.0) * 20.0 / 60000.0;

        printf("Flow Rate: %6.2f [L/min]\n", flow_rate);

        safe_delay_ms(1000); // Delay between readings
    }

    // Close I2C device
    close(i2c_file_descriptor);

    return 0;
}

// Function to write bytes to I2C device
uint32_t i2c_write_bytes(int file_descriptor, uint8_t dev_addr, uint8_t* data, uint16_t length) {
    if (file_descriptor < 0) return 1;

    if (ioctl(file_descriptor, I2C_SLAVE, dev_addr) < 0) {
        fprintf(stderr, "Error acquiring bus access or addressing slave: %s\n", strerror(errno));
        return 2;
    }

    ssize_t bytes_written = write(file_descriptor, data, length);
    if (bytes_written != length) {
        fprintf(stderr, "Error writing to I2C device: %s (Wrote %zd/%d bytes)\n", strerror(errno), bytes_written, length);
        return 3;
    }

    return 0; // Success
}

// Function to read bytes from I2C device
uint32_t i2c_read_bytes(int file_descriptor, uint8_t dev_addr, uint8_t reg_addr, uint8_t* data, uint16_t length) {
    if (file_descriptor < 0) return 1;

    if (ioctl(file_descriptor, I2C_SLAVE, dev_addr) < 0) {
        fprintf(stderr, "Error acquiring bus access or addressing slave: %s\n", strerror(errno));
        return 2;
    }

    // Write the register address to be read from
    ssize_t bytes_written = write(file_descriptor, &reg_addr, 1);
    if (bytes_written != 1) {
        fprintf(stderr, "Error writing register address: %s\n", strerror(errno));
        return 3;
    }

    // Read the data
    ssize_t bytes_read = read(file_descriptor, data, length);
    if (bytes_read != length) {
        fprintf(stderr, "Error reading from I2C device: %s (Read %zd/%d bytes)\n", strerror(errno), bytes_read, length);
        return 4;
    }

    return 0; // Success
}

// Function to convert two bytes to a 16-bit unsigned integer (Big Endian)
uint16_t bytes_to_uint16(uint8_t* buffer) {
    return (uint16_t)((((uint16_t)buffer[0]) << 8) | ((uint16_t)buffer[1]));
}

// Safe delay function using nanosleep
void safe_delay_ms(int milliseconds) {
    struct timespec req, rem;
    req.tv_sec = milliseconds / 1000;
    req.tv_nsec = (milliseconds % 1000) * 1000000L;
    while (nanosleep(&req, &rem) == -1) {
        if (errno == EINTR) {
            req = rem; // Resume interrupted sleep
        } else {
            perror("nanosleep");
            break; // Exit if nanosleep fails for other reasons
        }
    }
}

