#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pigpio.h>

// Define GPIO pins
#define IR_RECEIVER_GPIO 17
#define SERVO_GPIO 18

// NEC IR protocol timings (in microseconds)
#define NEC_HDR_MARK 9000
#define NEC_HDR_SPACE 4500
#define NEC_BIT_MARK 562
#define NEC_ONE_SPACE 1688
#define NEC_ZERO_SPACE 562
#define NEC_RPT_SPACE 2250

// Tolerance for timing comparisons
#define TOLERANCE 200

// Servo PWM frequency (Hz)
#define SERVO_FREQUENCY 50

// Servo PWM range (microseconds)
#define SERVO_MIN_PULSE_WIDTH 1000 // 1ms
#define SERVO_MAX_PULSE_WIDTH 2000 // 2ms

// Global variables
volatile int ir_code[34]; // Array to store raw IR code timings
volatile int ir_code_index = 0;
volatile int last_tick = 0;
volatile int nec_decode_complete = 0;

// Function prototypes
int initialize_gpio();
void ir_callback(int gpio, int level, uint32_t tick);
int decode_nec();
void control_servo(int command);
void cleanup(int signal);

// Signal handler for graceful shutdown
void cleanup(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);
    gpioTerminate();
    exit(0);
}

// Initialize pigpio library and GPIO pins
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        printf("pigpio initialisation failed\n");
        return -1;
    }

    gpioSetMode(IR_RECEIVER_GPIO, PI_INPUT);
    gpioSetMode(SERVO_GPIO, PI_OUTPUT);

    // Set PWM frequency for the servo
    gpioSetPWMfrequency(SERVO_GPIO, SERVO_FREQUENCY);

    // Set PWM range (optional, but good practice)
    gpioSetPWMrange(SERVO_GPIO, 1000000); // Range in microseconds

    // Register interrupt callback function
    gpioSetAlertFuncEx(IR_RECEIVER_GPIO, ir_callback, NULL);

    return 0;
}

// Interrupt callback function for IR receiver
void ir_callback(int gpio, int level, uint32_t tick) {
    int diff = tick - last_tick;

    if (diff > 10000) {
        // Reset index if long pause detected (start of new transmission)
        ir_code_index = 0;
    }

    if (ir_code_index < 34) {
        ir_code[ir_code_index++] = diff;
    }

    last_tick = tick;

    if (ir_code_index == 34) {
        nec_decode_complete = 1;
    }
}

// Decode NEC IR protocol
int decode_nec() {
    int address, command, inv_command;

    // Validate header
    if (ir_code[0] < NEC_HDR_MARK - TOLERANCE || ir_code[0] > NEC_HDR_MARK + TOLERANCE ||
        ir_code[1] < NEC_HDR_SPACE - TOLERANCE || ir_code[1] > NEC_HDR_SPACE + TOLERANCE) {
        printf("Error: Invalid NEC header\n");
        return -1;
    }

    // Decode address
    address = 0;
    for (int i = 2; i < 10; i++) {
        address <<= 1;
        if (ir_code[2 * i] < NEC_BIT_MARK - TOLERANCE || ir_code[2 * i] > NEC_BIT_MARK + TOLERANCE) {
            printf("Error: Invalid bit mark at index %d\n", 2 * i);
            return -1;
        }
        if (ir_code[2 * i + 1] > NEC_ONE_SPACE - TOLERANCE) {
            address |= 1;
        }
    }

    // Decode command
    command = 0;
    for (int i = 10; i < 18; i++) {
        command <<= 1;
        if (ir_code[2 * i] < NEC_BIT_MARK - TOLERANCE || ir_code[2 * i] > NEC_BIT_MARK + TOLERANCE) {
            printf("Error: Invalid bit mark at index %d\n", 2 * i);
            return -1;
        }
        if (ir_code[2 * i + 1] > NEC_ONE_SPACE - TOLERANCE) {
            command |= 1;
        }
    }

    // Decode inverted command
    inv_command = 0;
    for (int i = 18; i < 26; i++) {
        inv_command <<= 1;
        if (ir_code[2 * i] < NEC_BIT_MARK - TOLERANCE || ir_code[2 * i] > NEC_BIT_MARK + TOLERANCE) {
            printf("Error: Invalid bit mark at index %d\n", 2 * i);
            return -1;
        }
        if (ir_code[2 * i + 1] > NEC_ONE_SPACE - TOLERANCE) {
            inv_command |= 1;
        }
    }

    // Validate command and inverted command
    if ((command ^ inv_command) != 0xFF) {
        printf("Error: Command and inverted command mismatch\n");
        return -1;
    }

    printf("Decoded NEC: Address = 0x%X, Command = 0x%X\n", address, command);
    return command;
}

// Control servo motor
void control_servo(int command) {
    int pulse_width;

    switch (command) {
        case 0x01: // Command 0x01: 0 degrees
            pulse_width = SERVO_MIN_PULSE_WIDTH;
            break;
        case 0x02: // Command 0x02: 90 degrees
            pulse_width = (SERVO_MIN_PULSE_WIDTH + SERVO_MAX_PULSE_WIDTH) / 2;
            break;
        case 0x03: // Command 0x03: 180 degrees
            pulse_width = SERVO_MAX_PULSE_WIDTH;
            break;
        default:
            printf("Error: Unknown command 0x%X\n", command);
            return;
    }

    gpioPWM(SERVO_GPIO, pulse_width);
    printf("Servo set to pulse width %d us\n", pulse_width);
}

int main() {
    // Install signal handlers
    signal(SIGINT, cleanup);
    signal(SIGTERM, cleanup);

    // Initialize GPIO
    if (initialize_gpio() != 0) {
        return 1;
    }

    printf("NEC IR Remote Controlled Servo Application\n");

    while (1) {
        if (nec_decode_complete) {
            int command = decode_nec();
            if (command > 0) {
                control_servo(command);
            }
            ir_code_index = 0; // Reset index for next code
            nec_decode_complete = 0;
        }
        gpioDelay(100); // Delay to reduce CPU usage
    }

    return 0;
}

