// Define GPIO pin numbers for the 7-segment display segments
#define SEG_A 6
#define SEG_B 25
#define SEG_C 24
#define SEG_D 22
#define SEG_E 17
#define SEG_F 23
#define SEG_G 27
#define SEG_DP 5 // Decimal Point

// Define the segment patterns for displaying digits 0-9
const int digit_patterns[10][8] = {
    {SEG_A, SEG_B, SEG_C, SEG_D, SEG_E, SEG_F, -1, -1},       // 0
    {SEG_B, SEG_C, -1, -1, -1, -1, -1, -1},                  // 1
    {SEG_A, SEG_B, SEG_D, SEG_E, SEG_G, -1, -1, -1},       // 2
    {SEG_A, SEG_B, SEG_C, SEG_D, SEG_G, -1, -1, -1},       // 3
    {SEG_B, SEG_C, SEG_F, SEG_G, -1, -1, -1, -1},             // 4
    {SEG_A, SEG_C, SEG_D, SEG_F, SEG_G, -1, -1, -1},       // 5
    {SEG_A, SEG_C, SEG_D, SEG_E, SEG_F, SEG_G, -1, -1},    // 6
    {SEG_A, SEG_B, SEG_C, -1, -1, -1, -1, -1},              // 7
    {SEG_A, SEG_B, SEG_C, SEG_D, SEG_E, SEG_F, SEG_G, -1}, // 8
    {SEG_A, SEG_B, SEG_C, SEG_F, SEG_G, -1, -1, -1}        // 9
};

// Array of all segment pins for easy iteration
const int all_segments[] = {SEG_A, SEG_B, SEG_C, SEG_D, SEG_E, SEG_F, SEG_G, SEG_DP};

// Global flag to handle program termination via signal
volatile sig_atomic_t program_running = 1;

// Signal handler for SIGINT (Ctrl+C)
void signal_handler(int signal) {
    program_running = 0;
    printf("\nExiting program...\n");
}

// Function to set the state of a GPIO pin (safer wrapper)
int set_gpio_output(int pin, int value) {
    if (gpioWrite(pin, value) != 0) {
        fprintf(stderr, "Error: Failed to write value %d to GPIO %d\n", value, pin);
        return -1; // Indicate failure
    }
    return 0; // Indicate success
}

// Function to display a digit on the 7-segment display
int display_digit(int digit) {
    if (digit < 0 || digit > 9) {
        fprintf(stderr, "Error: Invalid digit: %d. Must be between 0 and 9.\n", digit);
        return -1; // Indicate failure
    }

    // Turn off all segments first
    for (size_t i = 0; i < sizeof(all_segments) / sizeof(all_segments[0]); ++i) {
        if (set_gpio_output(all_segments[i], PI_LOW) != 0) return -1; // Exit if error
    }

    // Turn on the required segments for the digit
    for (int i = 0; i < 8; ++i) {
        int segment_pin = digit_patterns[digit][i];
        if (segment_pin != -1) { // -1 indicates end of segment list for this digit
            if (set_gpio_output(segment_pin, PI_HIGH) != 0) return -1; // Exit if error
        }
    }
    return 0; // Indicate success
}

int main() {
    // Initialize the pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Register the signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Set all segment pins as output
    for (size_t i = 0; i < sizeof(all_segments) / sizeof(all_segments[0]); ++i) {
        gpioSetMode(all_segments[i], PI_OUTPUT);
    }

    printf("7-Segment Display Demo. Press Ctrl+C to exit.\n");

    // Main loop to display digits 0-9 repeatedly
    while (program_running) {
        for (int digit = 0; digit < 10; ++digit) {
            if (display_digit(digit) != 0) {
                fprintf(stderr, "Error displaying digit %d. Exiting.\n", digit);
                program_running = 0; // Stop the loop if there's an error
                break;
            }
            sleep(1); // Display each digit for 1 second
        }
    }

    // Cleanup: Set all segments to LOW and terminate pigpio
    for (size_t i = 0; i < sizeof(all_segments) / sizeof(all_segments[0]); ++i) {
        gpioWrite(all_segments[i], PI_LOW);
        gpioSetMode(all_segments[i], PI_INPUT); // Reset to input mode
    }

    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <string.h>
#include <signal.h>
#include <unistd.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>

// TCS34725 I2C address
#define TCS34725_ADDRESS 0x29

// TCS34725 registers
#define TCS34725_COMMAND_BIT 0x80
#define TCS34725_ENABLE 0x00
#define TCS34725_ATIME 0x01
#define TCS34725_WTIME 0x03
#define TCS34725_AILTL 0x04
#define TCS34725_AILTH 0x05
#define TCS34725_AIHTL 0x06
#define TCS34725_AIHTH 0x07
#define TCS34725_ID 0x12
#define TCS34725_STATUS 0x13
#define TCS34725_CDATA 0x14
#define TCS34725_RDATA 0x16
#define TCS34725_GDATA 0x18
#define TCS34725_BDATA 0x1A
#define TCS34725_PDATA 0x1C

// Enable register values
#define TCS34725_ENABLE_AIEN 0x10  // ALS interrupt enable
#define TCS34725_ENABLE_WEN 0x08   // Wait enable
#define TCS34725_ENABLE_AEN 0x02   // ALS enable
#define TCS34725_ENABLE_PON 0x01   // Power on

// GPIO pin for LED
#define LED_PIN 17

// Global variable for I2C file descriptor
int fd;

// Signal handler for Ctrl+C
void signalHandler(int signum) {
    printf("Caught signal %d, cleaning up...\n", signum);
    digitalWrite(LED_PIN, LOW); // Turn off LED
    if (fd != -1) {
        close(fd); // Close I2C connection (not strictly needed with wiringPi but good practice)
    }
    wiringPiSetupGpio();
    pinMode(LED_PIN, OUTPUT);
    digitalWrite(LED_PIN, LOW);
    exit(signum);
}

// Function to initialize the TCS34725 sensor
int initializeTCS34725() {
    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi initialization failed!\n");
        return -1;
    }

    // Setup I2C communication
    fd = wiringPiI2CSetup(TCS34725_ADDRESS);
    if (fd == -1) {
        fprintf(stderr, "I2C initialization failed!\n");
        return -1;
    }

    // Enable the sensor
    wiringPiI2CWriteReg8(fd, TCS34725_ENABLE, TCS34725_ENABLE_PON);
    delay(3); // Wait for power-on
    wiringPiI2CWriteReg8(fd, TCS34725_ENABLE, TCS34725_ENABLE_PON | TCS34725_ENABLE_AEN);

    return 0;
}

// Function to read a 16-bit value from a TCS34725 register
int readTCS34725Register(int reg) {
    int value = wiringPiI2CReadReg16(fd, reg);
    if (value == -1) {
        fprintf(stderr, "Error reading register 0x%02X\n", reg);
        return -1;
    }
    return value;
}

// Function to read the raw color data (Red, Green, Blue, Clear)
int readRawColorData(unsigned int *red, unsigned int *green, unsigned int *blue, unsigned int *clear) {
    int r = readTCS34725Register(TCS34725_RDATA);
    int g = readTCS34725Register(TCS34725_GDATA);
    int b = readTCS34725Register(TCS34725_BDATA);
    int c = readTCS34725Register(TCS34725_CDATA);

    if (r == -1 || g == -1 || b == -1 || c == -1) {
        return -1;
    }

    *red = (unsigned int)r;
    *green = (unsigned int)g;
    *blue = (unsigned int)b;
    *clear = (unsigned int)c;

    return 0;
}

// Function to normalize the RGB data against the clear channel
void normalizeRGB(unsigned int red, unsigned int green, unsigned int blue, unsigned int clear, float *normalized_r, float *normalized_g, float *normalized_b) {
    if (clear == 0) {
        *normalized_r = 0.0;
        *normalized_g = 0.0;
        *normalized_b = 0.0;
    } else {
        *normalized_r = (float)red / (float)clear;
        *normalized_g = (float)green / (float)clear;
        *normalized_b = (float)blue / (float)clear;
    }
}

// Function to identify the dominant color
const char* identifyDominantColor(float normalized_r, float normalized_g, float normalized_b) {
    if (normalized_r > normalized_g && normalized_r > normalized_b) {
        return "Red";
    } else if (normalized_g > normalized_r && normalized_g > normalized_b) {
        return "Green";
    } else if (normalized_b > normalized_r && normalized_b > normalized_g) {
        return "Blue";
    } else {
        return "Unknown";
    }
}

// Function to check if the color is within the defined red range
int isRed(unsigned int red, unsigned int green, unsigned int blue) {
    return (red > 150 && green < 80 && blue < 80);
}

int main() {
    // Set up signal handler for Ctrl+C
    signal(SIGINT, signalHandler);

    // Initialize the sensor
    if (initializeTCS34725() == -1) {
        fprintf(stderr, "TCS34725 initialization failed! Exiting.\n");
        return 1;
    }

    // Configure LED pin as output
    pinMode(LED_PIN, OUTPUT);

    printf("TCS34725 color sensor application running...\n");

    // Main loop
    while (1) {
        unsigned int red, green, blue, clear;
        float normalized_r, normalized_g, normalized_b;

        // Read raw color data
        if (readRawColorData(&red, &green, &blue, &clear) == -1) {
            fprintf(stderr, "Error reading color data. Retrying...\n");
            delay(1000); // Wait before retrying
            continue;
        }

        // Normalize RGB values
        normalizeRGB(red, green, blue, clear, &normalized_r, &normalized_g, &normalized_b);

        // Identify the dominant color
        const char* dominantColor = identifyDominantColor(normalized_r, normalized_g, normalized_b);

        // Check if the color is red
        int redDetected = isRed(red, green, blue);

        // Control the LED
        if (redDetected) {
            digitalWrite(LED_PIN, HIGH); // Turn on LED
        } else {
            digitalWrite(LED_PIN, LOW);  // Turn off LED
        }

        // Display the results
        printf("Raw: R=%u, G=%u, B=%u, C=%u\n", red, green, blue, clear);
        printf("Normalized: R=%.2f, G=%.2f, B=%.2f\n", normalized_r, normalized_g, normalized_b);
        printf("Dominant Color: %s\n", dominantColor);
        printf("Red Detected: %s\n", redDetected ? "Yes" : "No");
        printf("-----------------------------------\n");

        delay(500); // Delay for 500ms
    }

    return 0;
}

