#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <math.h>

#define I2C_BUS "/dev/i2c-1"  // Adjust if needed (e.g., /dev/i2c-0)
#define ADS1115_ADDR 0x48      // Default address.  Check your hardware!

#define ADS1115_REG_CONFIG 0x01
#define ADS1115_REG_LO_THRESH 0x02
#define ADS1115_REG_HI_THRESH 0x03

// Configuration register settings (adjust as needed)
#define CONFIG_OS_SINGLE      0x8000 // Start a single conversion
#define CONFIG_PGA_4_096V   0x0040 // +/- 4.096V range
#define CONFIG_MODE_SINGLE  0x0100 // Single-shot mode
#define CONFIG_DR_128SPS     0x0080 // 128 SPS
#define CONFIG_COMP_MODE_WINDOW 0x0002 // Window comparator mode
#define CONFIG_COMP_POL_ACTIVE_HIGH 0x0008 // Comparator polarity active high
#define CONFIG_COMP_LAT_NON_LATCHING 0x0004 // Non-latching comparator
#define CONFIG_COMP_QUE_1 0x0001  // Assert ALERT/RDY after one conversion

int i2c_fd;

// Function to write data to a register
int write_register(int reg, uint16_t value) {
    uint8_t buf[3];
    buf[0] = reg;
    buf[1] = (value >> 8) & 0xFF; // MSB
    buf[2] = value & 0xFF;      // LSB
    if (write(i2c_fd, buf, 3) != 3) {
        perror("Failed to write to I2C");
        return -1;
    }
    return 0;
}

int main() {
    int i;
    uint16_t low_threshold, high_threshold;
    float v_low = 1.0;  // 1.0V
    float v_high = 2.5; // 2.5V
    float v_fsr = 4.096; // Full scale range set to +/- 4.096V (PGA_4_096V)

    // Open I2C bus
    if ((i2c_fd = open(I2C_BUS, O_RDWR)) < 0) {
        perror("Failed to open I2C bus");
        return 1;
    }

    // Specify the address of the slave device
    if (ioctl(i2c_fd, I2C_SLAVE, ADS1115_ADDR) < 0) {
        perror("Failed to acquire bus access and/or talk to slave");
        close(i2c_fd);
        return 1;
    }

    // Calculate threshold register values.
    low_threshold = (uint16_t)((v_low / v_fsr) * 32767); // Offset binary conversion
    high_threshold = (uint16_t)((v_high / v_fsr) * 32767);

    // Write the high and low threshold values
    if (write_register(ADS1115_REG_LO_THRESH, low_threshold) < 0) {
        close(i2c_fd);
        return 1;
    }
    if (write_register(ADS1115_REG_HI_THRESH, high_threshold) < 0) {
        close(i2c_fd);
        return 1;
    }

    // Configure the ADS1115 for window comparator mode
    uint16_t config = CONFIG_OS_SINGLE | CONFIG_PGA_4_096V | CONFIG_MODE_SINGLE | CONFIG_DR_128SPS |
                      CONFIG_COMP_MODE_WINDOW | CONFIG_COMP_POL_ACTIVE_HIGH | CONFIG_COMP_LAT_NON_LATCHING | CONFIG_COMP_QUE_1;

    if (write_register(ADS1115_REG_CONFIG, config) < 0) {
        close(i2c_fd);
        return 1;
    }

    printf("ADS1115 configured for window comparator mode.  Waiting for ALERT/RDY pin to trigger (between %.2fV and %.2fV). Check the ALERT/RDY pin. \n", v_low, v_high);
    printf("Make sure you have external pull-up resistor connected to ALERT/RDY pin.\n");

    // Wait indefinitely.  In a real application, you'd monitor the ALERT/RDY pin.
    while(1) {
        sleep(1); // Sleep for a second to avoid busy-waiting.
    }


    close(i2c_fd);
    return 0;
}

