};

// Function pointer type for display functions (example)
typedef void (*DisplayFunction)(int, int);

// Function to initialize the UART port
int init_uart(const char *port) {
    int fd = open(port, O_RDWR | O_NOCTTY);
    if (fd < 0) {
        perror("Error opening UART port");
        return -1;
    }

    struct termios tty;
    if (tcgetattr(fd, &tty) != 0) {
        perror("Error getting UART attributes");
        close(fd);
        return -1;
    }

    tty.c_cflag = BAUD_RATE | CS8 | CLOCAL | CREAD;  // 9600 baud, 8 data bits, no parity, 1 stop bit
    tty.c_iflag = IGNPAR;
    tty.c_oflag = 0;
    tty.c_lflag = 0; // Non-canonical mode

    tty.c_cc[VMIN] = 1;  // Read at least 1 character
    tty.c_cc[VTIME] = 5; // 0.5 seconds read timeout

    if (tcsetattr(fd, TCSANOW, &tty) != 0) {
        perror("Error setting UART attributes");
        close(fd);
        return -1;
    }

    return fd;
}

// Function to read data from the PMS5003 sensor via UART
int read_pms5003_data(int fd, unsigned char *buffer, int length) {
    ssize_t bytes_read = read(fd, buffer, length);
    if (bytes_read < 0) {
        perror("Error reading from UART");
        return -1;
    } else if (bytes_read != length) {
        fprintf(stderr, "Timeout or incomplete data. Read %zd bytes, expected %d.\n", bytes_read, length);
        return -1;
    }

    // Check start bytes
    if (buffer[0] != 0x42 || buffer[1] != 0x4D) {
        fprintf(stderr, "Invalid PMS5003 data frame start bytes: 0x%02X 0x%02X\n", buffer[0], buffer[1]);
        return -1;
    }

    return 0;
}

// Function to parse PMS5003 data and calculate AQI
int parse_pms5003_data(const unsigned char *buffer, int *pm1_0, int *pm2_5, int *pm10, int *aqi) {
    // Calculate checksum
    unsigned short checksum = 0;
    for (int i = 0; i < PMS5003_FRAME_LENGTH - 2; i++) {
        checksum += buffer[i];
    }
    unsigned short received_checksum = (buffer[PMS5003_FRAME_LENGTH - 2] << 8) | buffer[PMS5003_FRAME_LENGTH - 1];

    if (checksum != received_checksum) {
        fprintf(stderr, "Checksum mismatch: calculated 0x%04X, received 0x%04X\n", checksum, received_checksum);
        return -1;
    }

    *pm1_0 = (buffer[4] << 8) | buffer[5];
    *pm2_5 = (buffer[6] << 8) | buffer[7];
    *pm10 = (buffer[8] << 8) | buffer[9];

    // Simplified AQI calculation based on PM2.5 (linear scaling)
    // This is a placeholder; a real AQI calculation is more complex.
    *aqi = *pm2_5; // Directly assign PM2.5 as AQI for simplicity
    if (*aqi > 500) *aqi = 500; // Clamp AQI

    return 0;
}

