}

// Function to clear the OLED screen
void clear_oled(int fd) {
    unsigned char buffer[OLED_WIDTH];
    memset(buffer, 0x00, OLED_WIDTH);
    for (int i = 0; i < OLED_HEIGHT / 8; i++) {
        unsigned char command[2] = {0x40, 0x00}; // 0x40 for data
        if (write(fd, command, 1) != 1) continue;
        for(int j = 0; j < OLED_WIDTH; j++) buffer[j] = 0x00;
        write(fd, buffer, OLED_WIDTH);
    }
}

// Function to display a character on the OLED screen
void display_char(int fd, int x, int y, char c) {
    if (c < ' ' || c > 'z') c = ' '; // Handle out-of-range characters
    int font_index = c - ' ';
    if (font_index < 0 || font_index >= sizeof(font) / sizeof(font[0])) font_index = 0;

    for (int i = 0; i < 8; i++) {
        unsigned char data[2] = {0x40, font[font_index][i]}; // 0x40 for data
        ioctl(fd, I2C_SLAVE, OLED_ADDR);
        //Set column and page
        unsigned char col_cmd[3] = {0x00, 0x21, (unsigned char)x};
        write(fd, col_cmd, 3);
        unsigned char page_cmd[3] = {0x00, 0x22, (unsigned char)y};
        write(fd, page_cmd, 3);
        if (write(fd, data, 2) != 2) {
            perror("Error writing character data to OLED");
            return; // Or handle error differently
        }
        x++;
    }
}

// Function to display a string on the OLED screen
void display_string(int fd, int x, int y, const char *str) {
    while (*str) {
        display_char(fd, x, y, *str);
        x += 8; // Move to the next character position
        str++;
    }
}

// Function to display the AQI value on the OLED screen
void display_aqi_on_oled(int fd, int aqi) {
    char aqi_str[20];
    sprintf(aqi_str, "AQI: %d", aqi);

    clear_oled(fd);
    display_string(fd, 0, 0, aqi_str);
}

int main() {
    int uart_fd, i2c_fd;
    unsigned char pms5003_data[PMS5003_FRAME_LENGTH];
    int pm1_0, pm2_5, pm10, aqi;

    // Initialize UART
    uart_fd = init_uart(UART_PORT);
    if (uart_fd < 0) {
        fprintf(stderr, "UART initialization failed. Exiting.\n");
        return 1;
    }
    printf("UART initialized successfully.\n");

    // Initialize I2C
    i2c_fd = open(I2C_BUS, O_RDWR);
    if (i2c_fd < 0) {
        perror("Error opening I2C bus");
        close(uart_fd);
        return 1;
    }

    if (ioctl(i2c_fd, I2C_SLAVE, OLED_ADDR) < 0) {
        perror("Error setting I2C slave address");
        close(uart_fd);
        close(i2c_fd);
        return 1;
    }

    if (init_oled(i2c_fd) < 0) {
        fprintf(stderr, "OLED initialization failed. Exiting.\n");
        close(uart_fd);
        close(i2c_fd);
        return 1;
    }
    printf("OLED initialized successfully.\n");

    // Main loop
    while (1) {
        // Read data from PMS5003
        if (read_pms5003_data(uart_fd, pms5003_data, PMS5003_FRAME_LENGTH) == 0) {
            // Parse data and calculate AQI
            if (parse_pms5003_data(pms5003_data, &pm1_0, &pm2_5, &pm10, &aqi) == 0) {
                // Display AQI on OLED
                display_aqi_on_oled(i2c_fd, aqi);
                printf("PM1.0: %d, PM2.5: %d, PM10: %d, AQI: %d\n", pm1_0, pm2_5, pm10, aqi);
            } else {
                fprintf(stderr, "Error parsing PMS5003 data.\n");
            }
        } else {
            fprintf(stderr, "Error reading PMS5003 data.\n");
        }

        sleep(1); // Wait 1 second
    }

    // Close UART and I2C (never reached in this example, but good practice)
    close(uart_fd);
    close(i2c_fd);

    return 0;
}

#include <stdio.h>
