#include <signal.h>

#define TILT_GPIO 17
#define LOG_FILE "tilt_events.log"
#define DEBOUNCE_MS 50

FILE *log_fp = NULL;

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("\nCaught signal %d, exiting gracefully...\n", signal);
    if (log_fp != NULL) {
        fclose(log_fp);
    }
    gpioTerminate();
    exit(0);
}

// Reads the state of the tilt switch
int read_tilt_state() {
    int state = gpioRead(TILT_GPIO);
    if (state < 0) {
        fprintf(stderr, "Error reading GPIO %d: %d\n", TILT_GPIO, state);
        return -1; // Indicate an error
    }
    return state;
}

// Logs the tilt event to the file
int log_tilt_event(int state) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    if (log_fp == NULL) {
        log_fp = fopen(LOG_FILE, "a");
        if (log_fp == NULL) {
            fprintf(stderr, "Error opening log file %s\n", LOG_FILE);
            return -1;
        }
    }

    fprintf(log_fp, "%s,State:%d\n", timestamp, state);
    fflush(log_fp); // Ensure data is written immediately

    return 0;
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO 17 as input
    if (gpioSetMode(TILT_GPIO, PI_INPUT) != 0) {
        fprintf(stderr, "Failed to set GPIO %d as input\n", TILT_GPIO);
        gpioTerminate();
        return 1;
    }

    // Install signal handler
    signal(SIGINT, signal_handler);

    int current_state = -1; // Initialize to an invalid state
    int previous_state = -1;

    printf("Tilt switch event logger started. Press Ctrl+C to exit.\n");

    // Main loop
    while (1) {
        current_state = read_tilt_state();

        if (current_state < 0) {
            // Error reading GPIO, but continue operation
            gpioDelay(DEBOUNCE_MS * 2); // Wait longer in case of errors
            continue;
        }

        if (current_state != previous_state) {
            if (log_tilt_event(current_state) != 0) {
                fprintf(stderr, "Error logging tilt event\n");
            }
            previous_state = current_state;
        }

        gpioDelay(DEBOUNCE_MS); // Debounce delay
    }

    return 0; // This line will never be reached due to the infinite loop
}

