#define SSD1306_I2C_ADDR  0x3C
#define SSD1306_WIDTH     128
#define SSD1306_HEIGHT    64
int i2c_fd;
void ssd1306_sendCommand(unsigned char command) {
    unsigned char buffer[2] = {0x00, command};
    write(i2c_fd, buffer, 2);
}
void ssd1306_init() {
    ssd1306_sendCommand(0xAE);
    ssd1306_sendCommand(0xAF);
}
void ssd1306_clearDisplay() {
    unsigned char buffer[1025] = {0x40};
    memset(buffer + 1, 0x00, 1024);
    write(i2c_fd, buffer, 1025);
}
void ssd1306_displayCenteredText(const char *text) {
    unsigned char buffer[130] = {0x40};
    int len = strlen(text);
    if (len > 16) len = 16;
    int startPos = (SSD1306_WIDTH / 6 - len) / 2;
    for (int i = 0; i < len; i++) {
        buffer[(startPos * 6) + (i * 6) + 1] = text[i];
    }
    write(i2c_fd, buffer, 130);
}
