}

#include <stdio.h>
#include <unistd.h>
#include <fcntl.h>
#include <linux/spi/spidev.h>
#include <sys/ioctl.h>
#include <stdint.h>
#include <time.h>

#define SPI_DEV "/dev/spidev0.0"

int read_adc(int fd, int ch) {
    uint8_t tx[3] = {0x01, (0x80 | (ch << 4)), 0x00};
    uint8_t rx[3];
    struct spi_ioc_transfer tr = {
        .tx_buf = (unsigned long)tx,
        .rx_buf = (unsigned long)rx,
        .len = 3,
        .speed_hz = 1000000,
        .bits_per_word = 8
    };
    ioctl(fd, SPI_IOC_MESSAGE(1), &tr);
    return ((rx[1] & 0x03) << 8) | rx[2];
}

int main() {
    FILE* log = fopen("pot_readings.txt", "a");
    int fd = open(SPI_DEV, O_RDWR);
    while (1) {
        int val = read_adc(fd, 0);
        time_t t = time(NULL);
        struct tm* tm_info = localtime(&t);
        char buffer[32];
        strftime(buffer, 32, "%Y-%m-%d %H:%M:%S", tm_info);
        fprintf(log, "%s - CH0: %d\n", buffer, val);
        fflush(log);
        usleep(1000000);
    }
    fclose(log);
    return 0;
}

