// Define GPIO pins for motor control and rain sensor
#define MOTOR_A_FORWARD 17
#define MOTOR_A_BACKWARD 18
#define MOTOR_B_FORWARD 27
#define MOTOR_B_BACKWARD 22
#define RAIN_SENSOR 23

// Define constants for timing
#define MOTOR_DURATION 5000 // 5 seconds
#define RAIN_DEBOUNCE_TIME 1000 // 1 second
#define OPEN_WINDOW_DELAY 1800000 // 30 minutes (in milliseconds)

// Global variable to track rain state
volatile int rainDetected = 0;

// Function prototypes
void closeWindow();
void openWindow();
void stopMotor();
void signalHandler(int signal);

// Function to close the window
void closeWindow() {
    printf("Closing window...\n");
    digitalWrite(MOTOR_A_FORWARD, HIGH);
    digitalWrite(MOTOR_A_BACKWARD, LOW);
    digitalWrite(MOTOR_B_FORWARD, LOW);
    digitalWrite(MOTOR_B_BACKWARD, LOW);
    delay(MOTOR_DURATION);
    stopMotor();
    printf("Window closed.\n");
}

// Function to open the window
void openWindow() {
    printf("Opening window...\n");
    digitalWrite(MOTOR_A_FORWARD, LOW);
    digitalWrite(MOTOR_A_BACKWARD, HIGH);
    digitalWrite(MOTOR_B_FORWARD, LOW);
    digitalWrite(MOTOR_B_BACKWARD, LOW);
    delay(MOTOR_DURATION);
    stopMotor();
    printf("Window opened.\n");
}

// Function to stop the motor
void stopMotor() {
    digitalWrite(MOTOR_A_FORWARD, LOW);
    digitalWrite(MOTOR_A_BACKWARD, LOW);
    digitalWrite(MOTOR_B_FORWARD, LOW);
    digitalWrite(MOTOR_B_BACKWARD, LOW);
}

// Signal handler for clean shutdown
void signalHandler(int signal) {
    printf("Caught signal %d, cleaning up...\n", signal);
    stopMotor();
    exit(0);
}

int main() {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed, exiting...\n");
        return 1;
    }

    // Set GPIO pins as output or input
    pinMode(MOTOR_A_FORWARD, OUTPUT);
    pinMode(MOTOR_A_BACKWARD, OUTPUT);
    pinMode(MOTOR_B_FORWARD, OUTPUT);
    pinMode(MOTOR_B_BACKWARD, OUTPUT);
    pinMode(RAIN_SENSOR, INPUT);

    // Register signal handler for Ctrl+C
    signal(SIGINT, signalHandler);

    printf("Home Automation System started. Press Ctrl+C to exit.\n");

    // Main loop
    int rainDebounceCounter = 0;
    unsigned long lastRainEnd = 0;

    while (1) {
        // Read rain sensor
        int rainValue = digitalRead(RAIN_SENSOR);

        // Debounce rain sensor
        if (rainValue == LOW) {
            rainDebounceCounter++;
            if (rainDebounceCounter >= (RAIN_DEBOUNCE_TIME / 100)) { // Check for 1 second of consistent rain
                if (!rainDetected) {
                    printf("Rain detected!\n");
                    closeWindow();
                    rainDetected = 1;
                }
            }
        } else {
            rainDebounceCounter = 0;
            if (rainDetected) {
                lastRainEnd = millis(); // Record the time when rain stopped
                rainDetected = 0;
                printf("Rain stopped.\n");
            }
        }

        // Open window after delay if no rain is detected
        if (!rainDetected && lastRainEnd > 0 && (millis() - lastRainEnd) >= OPEN_WINDOW_DELAY) {
            openWindow();
            lastRainEnd = 0; // Reset lastRainEnd after opening the window
        }

        delay(100); // Poll every 100 milliseconds
    }

    return 0;
}

