#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <errno.h>
#include <string.h>

#define I2C_BUS "/dev/i2c-1"
#define ADS1115_ADDR 0x48  // Default I2C address of the ADS1115
#define CONFIG_REG 0x01      // Configuration register
#define CONVERSION_REG 0x00  // Conversion register

int main() {
    int file;
    int adapter_nr = 1; // I2C bus number (usually 1 on Raspberry Pi)
    char filename[20];
    int16_t adc_value;

    snprintf(filename, 19, "/dev/i2c-%d", adapter_nr);
    file = open(filename, O_RDWR);
    if (file < 0) {
        perror("Failed to open I2C bus");
        return 1;
    }

    if (ioctl(file, I2C_SLAVE, ADS1115_ADDR) < 0) {
        perror("Failed to acquire bus access and/or talk to slave.");
        close(file);
        return 1;
    }

    // Configure ADS1115 for single-shot mode, +/- 4.096V range, continuous conversion disable, single-ended input A0.
    uint8_t config[3];
    config[0] = (CONFIG_REG) & 0xFF;
    config[1] = 0x83; // MSB: 1000 0011  Start single conversion, AIN0, +/-4.096V, single shot
    config[2] = 0x83; // LSB: 1000 0011  128 SPS, disable comparator

    if (write(file, config, 3) != 3) {
        perror("Failed to write to the I2C bus");
        close(file);
        return 1;
    }

    usleep(20000); // Wait for conversion (at least 125us for 8 SPS)

    // Read conversion register
    uint8_t read_buffer[2];
    uint8_t write_buffer[1] = {CONVERSION_REG};

    if (write(file, write_buffer, 1) != 1) {
        perror("Failed to write to the I2C bus (conversion register)");
        close(file);
        return 1;
    }
    if (read(file, read_buffer, 2) != 2) {
        perror("Failed to read from the I2C bus");
        close(file);
        return 1;
    }

    adc_value = (read_buffer[0] << 8) | read_buffer[1];

    printf("ADC Value: %d\n", adc_value);

    close(file);
    return 0;
}

