    gpioWrite(IN3, c);
    gpioWrite(IN4, d);
}
void rotate_half_step(int steps, int direction) {
    for (int i = 0; i < steps; i++) {
        if (direction) {
            set_step(1, 0, 0, 0);
            time_sleep(0.003);
            set_step(1, 1, 0, 0);
            time_sleep(0.003);
            set_step(0, 1, 0, 0);
            time_sleep(0.003);
            set_step(0, 1, 1, 0);
            time_sleep(0.003);
            set_step(0, 0, 1, 0);
            time_sleep(0.003);
            set_step(0, 0, 1, 1);
            time_sleep(0.003);
            set_step(0, 0, 0, 1);
            time_sleep(0.003);
            set_step(1, 0, 0, 1);
            time_sleep(0.003);
        } else {
            set_step(1, 0, 0, 1);
            time_sleep(0.003);
            set_step(0, 0, 0, 1);
            time_sleep(0.003);
            set_step(0, 0, 1, 1);
            time_sleep(0.003);
            set_step(0, 0, 1, 0);
            time_sleep(0.003);
            set_step(0, 1, 1, 0);
            time_sleep(0.003);
            set_step(0, 1, 0, 0);
            time_sleep(0.003);
            set_step(1, 1, 0, 0);
            time_sleep(0.003);
            set_step(1, 0, 0, 0);
            time_sleep(0.003);
        }
    }
}
