// Define GPIO pins for the traffic lights
#define RED_PIN   1  // BCM GPIO 18
#define YELLOW_PIN 4 // BCM GPIO 24
#define GREEN_PIN 5  // BCM GPIO 23

// Define constants for timing (in milliseconds)
#define RED_DURATION    5000
#define YELLOW_DURATION 500
#define GREEN_DURATION  5000

// Function to initialize GPIO pins
int initializeGPIO() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed!\n");
        return 1; // Indicate failure
    }

    pinMode(RED_PIN, OUTPUT);
    pinMode(YELLOW_PIN, OUTPUT);
    pinMode(GREEN_PIN, OUTPUT);

    // Initially turn off all LEDs
    digitalWrite(RED_PIN, LOW);
    digitalWrite(YELLOW_PIN, LOW);
    digitalWrite(GREEN_PIN, LOW);

    return 0; // Indicate success
}

// Function to simulate the yellow light blinking
void blinkYellowLight(int numBlinks) {
    for (int i = 0; i < numBlinks; i++) {
        digitalWrite(YELLOW_PIN, HIGH);
        delay(YELLOW_DURATION);
        digitalWrite(YELLOW_PIN, LOW);
        delay(YELLOW_DURATION);
    }
}

// Function to run the traffic light sequence
int runTrafficLight() {
    // Red light
    digitalWrite(RED_PIN, HIGH);
    printf("Red light ON for %d ms\n", RED_DURATION);
    delay(RED_DURATION);
    digitalWrite(RED_PIN, LOW);

    // Yellow light (blinking)
    printf("Yellow light blinking\n");
    blinkYellowLight(3);

    // Green light
    digitalWrite(GREEN_PIN, HIGH);
    printf("Green light ON for %d ms\n", GREEN_DURATION);
    delay(GREEN_DURATION);
    digitalWrite(GREEN_PIN, LOW);

    return 0;
}

int main() {
    // Initialize WiringPi and GPIO pins
    if (initializeGPIO() != 0) {
        return 1; // Exit if initialization fails
    }

    printf("Traffic light simulation started!\n");

    // Main loop to run the traffic light sequence continuously
    while (1) {
        if (runTrafficLight() != 0) {
            fprintf(stderr, "Error in traffic light sequence!\n");
        }
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <time.h>
#include <signal.h>
#include <gpiod.h>

// Constants
#define FAN_GPIO_PIN 18 // GPIO pin connected to the fan
#define TEMPERATURE_FILE "/sys/class/thermal/thermal_zone0/temp"
#define LOG_FILE "fan_log.txt"
#define SETPOINT_TEMPERATURE 50.0 // Desired CPU temperature in degrees Celsius
#define KP 1.0   // Proportional gain
#define KI 0.1   // Integral gain
#define KD 0.01  // Derivative gain
#define MAX_DUTY_CYCLE 100.0
#define MIN_DUTY_CYCLE 0.0
#define INTEGRAL_WINDUP_LIMIT 10.0

// Global variables
static struct gpiod_chip *chip;
static struct gpiod_line *line;
static volatile sig_atomic_t program_running = 1;
static double integral = 0.0;

// Function prototypes
double read_cpu_temperature();
double calculate_pid(double current_temperature, double setpoint_temperature, double previous_error);
int set_fan_speed(double duty_cycle);
int log_data(double temperature, double duty_cycle);
void signal_handler(int signal);
int cleanup();

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("Caught SIGINT, exiting gracefully.\n");
        program_running = 0;
    }
}

// Function to read CPU temperature from file
double read_cpu_temperature() {
    FILE *fp;
    char buffer[10];
    double temperature = 0.0;

    fp = fopen(TEMPERATURE_FILE, "r");
    if (fp == NULL) {
        perror("Error opening temperature file");
        log_data(-1, -1); // Log error
        return -1.0; // Indicate error
    }

    if (fread(buffer, 1, sizeof(buffer), fp) <= 0) {
        perror("Error reading temperature file");
        fclose(fp);
        log_data(-1, -1); // Log error
        return -1.0; // Indicate error
    }

    fclose(fp);

    // Convert temperature from millidegrees Celsius to degrees Celsius
    temperature = atoi(buffer) / 1000.0;

    return temperature;
}

// Function to calculate PID output
double calculate_pid(double current_temperature, double setpoint_temperature, double previous_error) {
    double error = setpoint_temperature - current_temperature;
    double derivative = error - previous_error;

    integral += error;

    // Integral windup prevention
    if (integral > INTEGRAL_WINDUP_LIMIT) {
        integral = INTEGRAL_WINDUP_LIMIT;
    } else if (integral < -INTEGRAL_WINDUP_LIMIT) {
        integral = -INTEGRAL_WINDUP_LIMIT;
    }

    double pid_output = (KP * error) + (KI * integral) + (KD * derivative);

    return pid_output;
}

// Function to set fan speed using libgpiod
int set_fan_speed(double duty_cycle) {
    int value;

    // Ensure duty cycle is within valid range
    if (duty_cycle < MIN_DUTY_CYCLE) {
        duty_cycle = MIN_DUTY_CYCLE;
    } else if (duty_cycle > MAX_DUTY_CYCLE) {
        duty_cycle = MAX_DUTY_CYCLE;
    }

    //Convert duty cycle (0-100) to GPIO value (0 or 1) using PWM approximation.
    //A more accurate PWM implementation would involve timers and interrupts.
    if (duty_cycle > 0) {
        value = 1;
    } else {
        value = 0;
    }

    if (gpiod_line_set_value(line, value) < 0) {
        perror("Error setting fan speed");
        log_data(-1, -1); // Log error
        return -1;
    }

    return 0;
}

// Function to log data to file
int log_data(double temperature, double duty_cycle) {
    FILE *fp;
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);

    fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return -1;
    }

    fprintf(fp, "[%d-%02d-%02d %02d:%02d:%02d] Temperature: %.2f C, Fan Duty Cycle: %.2f\n",
            tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec,
            temperature, duty_cycle);

    fclose(fp);
    return 0;
}

// Cleanup function to release resources
int cleanup() {
    if (line) {
        gpiod_line_release(line);
    }
    if (chip) {
        gpiod_chip_close(chip);
    }
    return 0;
}

int main() {
    double temperature, pid_output, previous_error = 0.0;

    // Register signal handler for Ctrl+C
    if (signal(SIGINT, signal_handler) == SIG_ERR) {
        perror("Error registering signal handler");
        return 1;
    }

    // Initialize libgpiod
    chip = gpiod_chip_open_by_name("gpiochip0");
    if (!chip) {
        perror("Error opening GPIO chip");
        return 1;
    }

    line = gpiod_chip_get_line(chip, FAN_GPIO_PIN);
    if (!line) {
        perror("Error getting GPIO line");
        gpiod_chip_close(chip);
        return 1;
    }

    if (gpiod_line_request_output(line, "fan_control", 0) < 0) {
        perror("Error requesting GPIO line for output");
        gpiod_chip_close(chip);
        return 1;
    }

    printf("Fan control program started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        // Read CPU temperature
        temperature = read_cpu_temperature();
        if (temperature < 0) {
            fprintf(stderr, "Error reading temperature, using previous reading.\n");
        } else {
            // Calculate PID output
            pid_output = calculate_pid(temperature, SETPOINT_TEMPERATURE, previous_error);
            previous_error = SETPOINT_TEMPERATURE - temperature;

            // Set fan speed
            if (set_fan_speed(pid_output) != 0) {
                fprintf(stderr, "Error setting fan speed.\n");
            }

            // Log data
            if (log_data(temperature, pid_output) != 0) {
                fprintf(stderr, "Error logging data.\n");
            }
        }

        // Wait for 1 second
        sleep(1);
    }

    // Shutdown sequence
    printf("Shutting down...\n");
    set_fan_speed(0.0); // Stop the fan
    cleanup();             // Release GPIO line and chip
    printf("Fan control program stopped.\n");

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <unistd.h>

// Define motor control pins (GPIO numbers)
const int MOTOR_PINS[] = {1, 4, 5, 6};
const int NUM_PINS = sizeof(MOTOR_PINS) / sizeof(MOTOR_PINS[0]);

// Motor parameters
const int STEPS_PER_REVOLUTION = 2048; // Adjust based on your motor
const int DEFAULT_RPM = 15;             // Default rotations per minute

// Function prototypes
void initialize_gpio();
void set_motor_speed(int rpm);
void rotate_motor(char direction);
void cleanup_gpio();

// Global variable for step delay (microseconds)
unsigned int step_delay_us;

int main() {
    // Initialize wiringPi and GPIO pins
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPi setup failed!\n");
        return EXIT_FAILURE;
    }

    initialize_gpio();
    set_motor_speed(DEFAULT_RPM);

    char direction;

    while (1) {
        printf("Select motor direction (a=anticlockwise, c=clockwise, q=quit): ");
        fflush(stdout); // Ensure prompt is displayed
        if (scanf(" %c", &direction) != 1) {
            fprintf(stderr, "Error reading input. Exiting.\n");
            break;
        }

        if (direction == 'c' || direction == 'a') {
            printf("Motor running %s\n", (direction == 'c') ? "clockwise" : "anti-clockwise");
            while (1) {
                rotate_motor(direction);
            }
        } else if (direction == 'q') {
            printf("Exiting program.\n");
            break;
        } else {
            printf("Invalid input. Please try again!\n");
        }

        // Consume any remaining characters in the input buffer
        while (getchar() != '\n');
    }

    cleanup_gpio();
    return EXIT_SUCCESS;
}

void initialize_gpio() {
    for (int i = 0; i < NUM_PINS; i++) {
        pinMode(MOTOR_PINS[i], OUTPUT);
    }
}

void set_motor_speed(int rpm) {
    if (rpm <= 0) {
        fprintf(stderr, "Invalid RPM value. Using default RPM.\n");
        rpm = DEFAULT_RPM;
    }
    step_delay_us = 60000000 / ((unsigned int)rpm * STEPS_PER_REVOLUTION); // Calculate delay in microseconds
    printf("Step delay: %u us\n", step_delay_us);
}

void rotate_motor(char direction) {
    // Stepping sequence (full step drive)
    static const int step_sequence[] = {0b1001, 0b0011, 0b0110, 0b1100}; // Example sequence
    const int num_steps = sizeof(step_sequence) / sizeof(step_sequence[0]);
    static int current_step = 0;

    if (direction == 'c') {
        current_step = (current_step + 1) % num_steps; // Clockwise
    } else {
        current_step = (current_step - 1 + num_steps) % num_steps; // Anti-clockwise
    }

    int step_pattern = step_sequence[current_step];

    for (int i = 0; i < NUM_PINS; i++) {
        digitalWrite(MOTOR_PINS[i], (step_pattern >> (NUM_PINS - 1 - i)) & 1);
    }
    delayMicroseconds(step_delay_us);
}

void cleanup_gpio() {
    // Optionally, turn off all motor pins during cleanup
    for (int i = 0; i < NUM_PINS; i++) {
        digitalWrite(MOTOR_PINS[i], LOW);
    }
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <time.h>
#include <signal.h>
#include <wiringPi.h>
#include <errno.h>

// Define SPI parameters
#define SPI_CHANNEL 0
#define SPI_SPEED 1000000 // 1 MHz

// Define MCP3008 channel connected to MQ-3
#define MQ3_CHANNEL 0

// Define LED GPIO pin
#define LED_PIN 18

// Define BAC threshold for LED blinking
#define BAC_THRESHOLD 0.08f

// Define data logging file
#define LOG_FILE "alcohol_levels.dat"

// Global variables
static volatile int keepRunning = 1;
static FILE *logFile = NULL;

// Function prototypes
int initWiringPi();
int initSPI();
int readMCP3008(int channel);
float calculateBAC(int adcValue);
int logData(float bac);
void controlLED(float bac);
void signalHandler(int signal);

// Function to initialize wiringPi
int initWiringPi() {
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return 1;
    }
    return 0;
}

// Function to initialize SPI
int initSPI() {
    if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) == -1) {
        fprintf(stderr, "SPI initialization failed: %s\n", strerror(errno));
        return 1;
    }
    return 0;
}

// Function to read data from MCP3008 ADC
int readMCP3008(int channel) {
    unsigned char buffer[3];
    buffer[0] = 0x01; // Start bit
    buffer[1] = (0x08 | (channel << 4)); // Single-ended mode, channel selection
    buffer[2] = 0x00;

    wiringPiSPIDataRW(SPI_CHANNEL, buffer, 3);

    int adcValue = ((buffer[1] & 0x03) << 8) + buffer[2];
    return adcValue;
}

// Function to calculate BAC (simplified model)
float calculateBAC(int adcValue) {
    // This is a placeholder and needs proper calibration with the MQ-3 sensor
    // and appropriate BAC calculation formula.
    // The following is a linear approximation.  Proper calibration is REQUIRED.
    float voltage = (float)adcValue / 1023.0f * 3.3f; // Assuming 3.3V reference
    float bac = (voltage - 0.5f) * 0.1f; // Example linear mapping.  Needs calibration.

    if (bac < 0.0f) bac = 0.0f; // Ensure BAC is not negative
    return bac;
}

// Function to log data to file
int logData(float bac) {
    time_t now = time(NULL);
    if (fwrite(&now, sizeof(time_t), 1, logFile) != 1) {
        fprintf(stderr, "Error writing timestamp to log file: %s\n", strerror(errno));
        return 1;
    }
    if (fwrite(&bac, sizeof(float), 1, logFile) != 1) {
        fprintf(stderr, "Error writing BAC to log file: %s\n", strerror(errno));
        return 1;
    }
    fflush(logFile); // Ensure data is written to disk
    return 0;
}

// Function to control the LED based on BAC level
void controlLED(float bac) {
    if (bac > BAC_THRESHOLD) {
        // Blink rapidly (10 Hz)
        digitalWrite(LED_PIN, HIGH);
        delay(50); // 50ms HIGH, 50ms LOW = 10Hz
        digitalWrite(LED_PIN, LOW);
        delay(50);
    } else {
        digitalWrite(LED_PIN, LOW); // Ensure LED is off when below threshold
    }
}

// Signal handler for graceful shutdown
void signalHandler(int signal) {
    keepRunning = 0;
    printf("Caught signal %d, exiting gracefully.\n", signal);
    digitalWrite(LED_PIN, LOW); // Turn off LED
    if (logFile != NULL) {
        fclose(logFile);
    }
    exit(0);
}

int main() {
    // Register signal handler
    signal(SIGINT, signalHandler);

    // Initialize wiringPi
    if (initWiringPi() != 0) {
        return 1;
    }

    // Initialize SPI
    if (initSPI() != 0) {
        return 1;
    }

    // Set LED pin as output
    pinMode(LED_PIN, OUTPUT);

    // Open log file in binary write mode
    logFile = fopen(LOG_FILE, "wb");
    if (logFile == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        return 1;
    }

    printf("MQ-3 Alcohol Sensor Interface\n");
    printf("Logging data to %s\n", LOG_FILE);
    printf("Press Ctrl+C to exit.\n");

    while (keepRunning) {
        // Read ADC value from MQ-3 channel
        int adcValue = readMCP3008(MQ3_CHANNEL);

        // Calculate BAC level
        float bac = calculateBAC(adcValue);

        // Log data
        if (logData(bac) != 0) {
            fprintf(stderr, "Error logging data.\n");
        }

        // Control LED
        controlLED(bac);

        // Print BAC level to console
        printf("BAC: %.4f%%\n", bac);

        // Delay for a short period
        delay(100); // 100ms delay
    }

    // Close log file and turn off LED before exiting (should not reach here due to signal handler)
    fclose(logFile);
    digitalWrite(LED_PIN, LOW);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <signal.h>
#include <unistd.h>
#include <string.h>
#include <time.h>

#define FAN_GPIO 18
#define TARGET_TEMP 55.0
#define SENSOR_FILE_PATH "/sys/bus/w1/devices/28-xxxxxxxxxxxx/w1_slave" // Replace with your sensor's address

// PID Gains
#define Kp 1.0
#define Ki 0.1
#define Kd 0.01

// Global variables (try to minimize)
static volatile int running = 1;
static double integral = 0.0;
static double previous_error = 0.0;

// Function prototypes
double read_temperature();
int set_fan_speed(int duty_cycle);
double calculate_pid(double current_temperature);
void log_data(double temperature, int duty_cycle, const char *message);
void signal_handler(int signal);

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(FAN_GPIO, PI_OUTPUT);
    gpioSetPWMfrequency(FAN_GPIO, 25000); // Set PWM frequency to 25 kHz
    gpioPWM(FAN_GPIO, 0); // Initialize fan to off

    signal(SIGINT, signal_handler);  // Handle Ctrl+C
    signal(SIGTERM, signal_handler); // Handle termination signal

    log_data(0.0, 0, "Cooling system started");

    while (running) {
        double temperature = read_temperature();
        if (temperature < -270.0) { // Error reading temperature
            sleep(5);
            continue;
        }

        double pid_output = calculate_pid(temperature);
        int duty_cycle = (int)pid_output;
        if (duty_cycle < 0) duty_cycle = 0;
        if (duty_cycle > 255) duty_cycle = 255;

        if (set_fan_speed(duty_cycle) != 0) {
            log_data(temperature, duty_cycle, "Error setting fan speed");
        }

        log_data(temperature, duty_cycle, NULL); // Log data without error message
        sleep(5);
    }

    gpioPWM(FAN_GPIO, 0); // Turn off fan on exit
    gpioTerminate();       // Terminate pigpio
    log_data(0.0, 0, "Cooling system stopped");

    return 0;
}

double read_temperature() {
    FILE *fp;
    char buffer[256];
    double temperature = -273.0; // Initialize to absolute zero (error value)
    char *token;

    fp = fopen(SENSOR_FILE_PATH, "r");
    if (fp == NULL) {
        perror("Error opening sensor file");
        log_data(0.0, 0, "Error opening sensor file");
        return temperature; // Return error value
    }

    // Read the file line by line
    while (fgets(buffer, sizeof(buffer), fp) != NULL) {
        if (strstr(buffer, "t=")) {
            token = strtok(buffer, "t=");
            token = strtok(NULL, "t=");
            if (token != NULL) {
                temperature = atof(token) / 1000.0;
                break; // Exit loop after finding the temperature
            }
        }
    }

    fclose(fp);
    return temperature;
}

int set_fan_speed(int duty_cycle) {
    if (gpioPWM(FAN_GPIO, duty_cycle) != 0) {
        fprintf(stderr, "Error setting fan speed to %d\n", duty_cycle);
        return 1;
    }
    return 0;
}

double calculate_pid(double current_temperature) {
    double error = TARGET_TEMP - current_temperature;

    integral += error * 5; // Integrate over 5 second interval
    double derivative = (error - previous_error) / 5; // Differentiate over 5 second interval

    double output = Kp * error + Ki * integral + Kd * derivative;

    previous_error = error;
    return output;
}

void log_data(double temperature, int duty_cycle, const char *message) {
    FILE *fp;
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);

    fp = fopen("cooling_log.txt", "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return;
    }

    fprintf(fp, "[%04d-%02d-%02d %02d:%02d:%02d] Temp: %.2f°C, Duty Cycle: %d",
            tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, temperature, duty_cycle);

    if (message != NULL) {
        fprintf(fp, ", Message: %s", message);
    }
    fprintf(fp, "\n");

    fclose(fp);
}

void signal_handler(int signal) {
    running = 0;
    printf("Caught signal %d, exiting...\n", signal);
    log_data(0.0, 0, "Cooling system shutting down due to signal");
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <time.h>
#include <signal.h>

// Define GPIO numbers
#define FLAME_SENSOR_GPIO 4
#define BUZZER_GPIO 17

// PWM parameters
#define PWM_PERIOD_NS 100000  // 100us period

// Threshold for flame intensity to activate the buzzer
#define INTENSITY_THRESHOLD 75

// Function prototypes
int init_gpio(int gpio);
int set_gpio_value(int gpio, int value);
int get_duty_cycle();
int calculate_intensity(int duty_cycle);
void control_buzzer(int intensity);
void cleanup_gpio(int gpio);
void signal_handler(int signum);

// Global flag to control the main loop
volatile sig_atomic_t program_running = 1;

// Signal handler to catch SIGINT (Ctrl+C)
void signal_handler(int signum) {
    program_running = 0;
    printf("Caught signal %d, exiting gracefully...\n", signum);
    // Disable the buzzer before exiting
    set_gpio_value(BUZZER_GPIO, 0);
    cleanup_gpio(FLAME_SENSOR_GPIO);
    cleanup_gpio(BUZZER_GPIO);
    exit(0);
}

// Initializes a GPIO for output using sysfs
int init_gpio(int gpio) {
    FILE *fp;
    char buffer[50];

    // Export the GPIO
    snprintf(buffer, sizeof(buffer), "/sys/class/gpio/export");
    fp = fopen(buffer, "w");
    if (fp == NULL) {
        fprintf(stderr, "Error: Could not open /sys/class/gpio/export for writing\n");
        return -1;
    }
    fprintf(fp, "%d", gpio);
    fclose(fp);
    usleep(100000); // Wait for the GPIO to be exported (100ms)

    // Set the GPIO direction to output
    snprintf(buffer, sizeof(buffer), "/sys/class/gpio/gpio%d/direction", gpio);
    fp = fopen(buffer, "w");
    if (fp == NULL) {
        fprintf(stderr, "Error: Could not open /sys/class/gpio/gpio%d/direction for writing\n", gpio);
        return -1;
    }
    fprintf(fp, "out");
    fclose(fp);

    return 0;
}

// Sets the value of a GPIO using sysfs
int set_gpio_value(int gpio, int value) {
    FILE *fp;
    char buffer[50];

    snprintf(buffer, sizeof(buffer), "/sys/class/gpio/gpio%d/value", gpio);
    fp = fopen(buffer, "w");
    if (fp == NULL) {
        fprintf(stderr, "Error: Could not open /sys/class/gpio/gpio%d/value for writing\n", gpio);
        return -1;
    }
    fprintf(fp, "%d", value);
    fclose(fp);

    return 0;
}

// Cleans up a GPIO by unexporting it
void cleanup_gpio(int gpio) {
    FILE *fp;
    char buffer[50];

    snprintf(buffer, sizeof(buffer), "/sys/class/gpio/unexport");
    fp = fopen(buffer, "w");
    if (fp == NULL) {
        fprintf(stderr, "Error: Could not open /sys/class/gpio/unexport for writing\n");
        return;
    }
    fprintf(fp, "%d", gpio);
    fclose(fp);
}

// Measures the duty cycle of the emulated PWM signal on GPIO4
int get_duty_cycle() {
    struct timespec on_time, off_time;
    int high_count = 0; // Count the number of loops the GPIO is high
    int total_count = 100; // Number of PWM cycles to measure

    // PWM emulation parameters
    int on_ns = 0; //Variable for duty cycle calculation

    //Emulate analog input using PWM on GPIO4
    for (int i = 0; i < total_count; i++) {
        // Simulate analog voltage by varying the duty cycle
        // Higher duty cycle = higher voltage = more flame
        on_ns = (i * PWM_PERIOD_NS) / total_count; // Vary on-time based on loop iteration

        // Set GPIO high
        if (set_gpio_value(FLAME_SENSOR_GPIO, 1) != 0) {
            fprintf(stderr, "Error setting GPIO high\n");
            return -1; // Indicate error
        }

        on_time.tv_sec = 0;
        on_time.tv_nsec = on_ns; //On Time
        nanosleep(&on_time, NULL);

        // Set GPIO low
        if (set_gpio_value(FLAME_SENSOR_GPIO, 0) != 0) {
            fprintf(stderr, "Error setting GPIO low\n");
            return -1; // Indicate error
        }

        off_time.tv_sec = 0;
        off_time.tv_nsec = PWM_PERIOD_NS - on_ns; // Off Time
        nanosleep(&off_time, NULL);

        high_count++; //increment high count to represent the duty cycle.
    }

    return (high_count * 100) / total_count; // Return the average duty cycle percentage
}

// Calculates flame intensity as a percentage based on the duty cycle
int calculate_intensity(int duty_cycle) {
    // Assume a linear relationship between duty cycle and flame intensity
    return duty_cycle; // For simplicity, duty cycle percentage equals intensity percentage
}

// Controls the buzzer based on flame intensity
void control_buzzer(int intensity) {
    if (intensity > INTENSITY_THRESHOLD) {
        // Activate the buzzer
        if (set_gpio_value(BUZZER_GPIO, 1) != 0) {
            fprintf(stderr, "Error activating buzzer\n");
        }
    } else {
        // Deactivate the buzzer
        if (set_gpio_value(BUZZER_GPIO, 0) != 0) {
            fprintf(stderr, "Error deactivating buzzer\n");
        }
    }
}

int main() {
    int duty_cycle, intensity;

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize GPIOs
    if (init_gpio(FLAME_SENSOR_GPIO) != 0) {
        fprintf(stderr, "Failed to initialize flame sensor GPIO\n");
        return 1;
    }
    if (init_gpio(BUZZER_GPIO) != 0) {
        fprintf(stderr, "Failed to initialize buzzer GPIO\n");
        cleanup_gpio(FLAME_SENSOR_GPIO);
        return 1;
    }

    printf("Flame sensor program started. Press Ctrl+C to exit.\n");

    while (program_running) {
        // Read the duty cycle (representing analog voltage)
        duty_cycle = get_duty_cycle();
        if (duty_cycle == -1) {
            fprintf(stderr, "Error reading duty cycle, retrying...\n");
            usleep(100000); // Wait before retrying
            continue;
        }

        // Calculate flame intensity
        intensity = calculate_intensity(duty_cycle);

        // Control the buzzer
        control_buzzer(intensity);

        printf("Flame Intensity: %d%%\n", intensity);

        usleep(500000); // Delay for 0.5 seconds
    }

    // Cleanup GPIOs before exiting
    cleanup_gpio(FLAME_SENSOR_GPIO);
    cleanup_gpio(BUZZER_GPIO);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <string.h>

#define GPIO_PIN 17
#define MAX_PULSES 64

// NEC timings (in microseconds)
#define NEC_HDR_MARK  9000
#define NEC_HDR_SPACE 4500
#define NEC_BIT_MARK  562
#define NEC_ONE_SPACE 1687
#define NEC_ZERO_SPACE 562
#define NEC_RPT_SPACE 2250

// Tolerance for timing comparison (in microseconds)
#define TOLERANCE 200

static volatile int pulses[MAX_PULSES];
static volatile int pulse_count = 0;
static volatile int nec_state = 0; // 0: idle, 1: receiving
static volatile unsigned int nec_address = 0;
static volatile unsigned int nec_command = 0;
static volatile int nec_repeat = 0;

static void cleanup(int signum);
static int init_gpio(void);
static void nec_decode(int gpio, int level, uint32_t tick);
static int decode_nec_signal(void);
static char* format_output(unsigned int address, unsigned int command, int repeat);
static char* get_timestamp(void);

int main(void) {
    signal(SIGINT, cleanup);

    if (init_gpio() != 0) {
        fprintf(stderr, "Failed to initialize GPIO. Exiting.\n");
        return 1;
    }

    printf("NEC IR Remote Decoder running on GPIO %d. Press Ctrl+C to exit.\n", GPIO_PIN);

    while (1) {
        // Main loop - decoding happens in the interrupt handler
        gpioDelay(1000); // Check every second
    }

    return 0;
}

static int init_gpio(void) {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(GPIO_PIN, PI_INPUT);
    gpioSetAlertFunc(GPIO_PIN, nec_decode);
    return 0;
}

static void nec_decode(int gpio, int level, uint32_t tick) {
    static uint32_t last_tick = 0;
    uint32_t duration;

    duration = tick - last_tick;
    last_tick = tick;

    if (pulse_count >= MAX_PULSES) {
        pulse_count = 0; // Reset if buffer overflows
        nec_state = 0;    // Reset state
        fprintf(stderr, "Pulse buffer overflow!\n");
        return;
    }

    pulses[pulse_count++] = duration;

    if (level == 0) { // Falling edge marks the end of a pulse
        if (pulse_count == 1) {
            nec_state = 1; // Start of a new transmission
        } else {
            // Attempt to decode when a space is detected after a mark
            if (decode_nec_signal() == 0) { // Successful decode
                char* output_string = format_output(nec_address, nec_command, nec_repeat);
                printf("%s\n", output_string);
                free(output_string); // Free allocated memory
            }
            pulse_count = 0;
            nec_state = 0;
        }
    }
}

static int decode_nec_signal(void) {
    if (pulse_count < 32) {
        // Not enough pulses for a complete NEC transmission
        return -1;
    }

    // Check for NEC header
    if ((pulses[0] > NEC_HDR_MARK - TOLERANCE) && (pulses[0] < NEC_HDR_MARK + TOLERANCE) &&
        (pulses[1] > NEC_HDR_SPACE - TOLERANCE) && (pulses[1] < NEC_HDR_SPACE + TOLERANCE)) {
        // Valid NEC header
        nec_address = 0;
        nec_command = 0;
        nec_repeat = 0;

        // Decode address and command
        for (int i = 2; i < 34; i += 2) {
            if ((pulses[i] > NEC_BIT_MARK - TOLERANCE) && (pulses[i] < NEC_BIT_MARK + TOLERANCE)) {
                if ((pulses[i + 1] > NEC_ONE_SPACE - TOLERANCE) && (pulses[i + 1] < NEC_ONE_SPACE + TOLERANCE)) {
                    // Bit 1
                    if (i < 18) {
                        nec_address = (nec_address << 1) | 1;
                    } else {
                        nec_command = (nec_command << 1) | 1;
                    }
                } else if ((pulses[i + 1] > NEC_ZERO_SPACE - TOLERANCE) && (pulses[i + 1] < NEC_ZERO_SPACE + TOLERANCE)) {
                    // Bit 0
                    if (i < 18) {
                        nec_address = (nec_address << 1) | 0;
                    } else {
                        nec_command = (nec_command << 1) | 0;
                    }
                } else {
                    fprintf(stderr, "Invalid bit space at pulse %d\n", i + 1);
                    return -1; // Invalid space
                }
            } else {
                fprintf(stderr, "Invalid bit mark at pulse %d\n", i);
                return -1; // Invalid mark
            }
        }

        // Verify checksum (address + command == ~command_inverse)
        unsigned char address_byte = (unsigned char)(nec_address & 0xFF);
        unsigned char command_byte = (unsigned char)(nec_command & 0xFF);
        unsigned char command_inverse = (unsigned char)((nec_command >> 8) & 0xFF);

        if ((address_byte + command_byte) != (0xFF - command_inverse)) {
            fprintf(stderr, "Checksum verification failed\n");
            return -1;
        }

        return 0; // Successful decode

    } else if ((pulses[0] > NEC_HDR_MARK - TOLERANCE) && (pulses[0] < NEC_HDR_MARK + TOLERANCE) &&
               (pulses[1] > NEC_RPT_SPACE - TOLERANCE) && (pulses[1] < NEC_RPT_SPACE + TOLERANCE) &&
               (pulses[2] > NEC_BIT_MARK - TOLERANCE) && (pulses[2] < NEC_BIT_MARK + TOLERANCE)) {
        // NEC repeat code
        nec_repeat = 1;
        return 0;
    } else {
        fprintf(stderr, "Invalid NEC header\n");
        return -1; // Invalid header
    }
}

static char* format_output(unsigned int address, unsigned int command, int repeat) {
    char* timestamp = get_timestamp();
    char* output_string = (char*)malloc(100 * sizeof(char)); // Allocate memory
    if (output_string == NULL) {
        fprintf(stderr, "Memory allocation failed!\n");
        return NULL; // Handle memory allocation failure
    }

    if (repeat) {
        snprintf(output_string, 100, "%s NEC Repeat", timestamp);
    } else {
        snprintf(output_string, 100, "%s Address: 0x%02X, Command: 0x%02X", timestamp, address, command);
    }

    free(timestamp);
    return output_string;
}

static char* get_timestamp(void) {
    time_t rawtime;
    struct tm* timeinfo;
    char* timestamp = (char*)malloc(20 * sizeof(char)); // Allocate memory for timestamp

    if (timestamp == NULL) {
        fprintf(stderr, "Memory allocation failed!\n");
        return NULL; // Handle memory allocation failure
    }

    time(&rawtime);
    timeinfo = localtime(&rawtime);
    strftime(timestamp, 20, "%Y-%m-%d %H:%M:%S", timeinfo);

    return timestamp;
}

static void cleanup(int signum) {
    printf("\nCleaning up and exiting...\n");
    gpioTerminate();
    exit(0);
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <time.h>
#include <pigpio.h>
#include <pthread.h>
#include <unistd.h>

// Define servo motor GPIO pins
#define PAN_SERVO_PIN 17
#define TILT_SERVO_PIN 18

// Define servo pulsewidth limits (microseconds)
#define SERVO_MIN_PULSEWIDTH 500
#define SERVO_MAX_PULSEWIDTH 2500

// Define servo angle limits (degrees)
#define SERVO_MIN_ANGLE 0
#define SERVO_MAX_ANGLE 180

// Define object detection probability (0-100)
#define OBJECT_DETECTION_PROBABILITY 20

// Structure to represent a servo motor
typedef struct {
    int pin;
    int pulsewidth;
    int angle;
} Servo;

// Mutex to protect servo data
pthread_mutex_t servo_mutex;

// Servo motor instances
Servo pan_servo = {PAN_SERVO_PIN, 1500, 90};
Servo tilt_servo = {TILT_SERVO_PIN, 1500, 90};

// Flag to indicate program termination
volatile sig_atomic_t terminate = 0;

// Function prototypes
int initialize_gpio();
void terminate_gpio();
int set_servo_angle(Servo *servo, int angle);
int angle_to_pulsewidth(int angle);
int handle_object_detection(Servo *pan_servo, Servo *tilt_servo);
void *servo_control_thread(void *arg);
void signal_handler(int signal);

// Function to initialize the pigpio library
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Indicate failure
    }
    return 0; // Indicate success
}

// Function to terminate the pigpio library
void terminate_gpio() {
    gpioTerminate();
    fprintf(stdout, "pigpio terminated successfully\n");
}

// Function to set the servo angle
int set_servo_angle(Servo *servo, int angle) {
    if (angle < SERVO_MIN_ANGLE || angle > SERVO_MAX_ANGLE) {
        fprintf(stderr, "Error: Angle %d is out of range (%d-%d)\n", angle, SERVO_MIN_ANGLE, SERVO_MAX_ANGLE);
        return 1; // Indicate failure
    }

    int pulsewidth = angle_to_pulsewidth(angle);

    // Lock the mutex before accessing shared resources
    if (pthread_mutex_lock(&servo_mutex) != 0) {
        fprintf(stderr, "Error: Failed to lock mutex\n");
        return 1;
    }

    int result = gpioServo(servo->pin, pulsewidth);
    if (result != 0) {
        fprintf(stderr, "Error: Failed to set servo pulsewidth (pin %d, pulsewidth %d, result %d)\n", servo->pin, pulsewidth, result);
        // Unlock the mutex even if there's an error
        if (pthread_mutex_unlock(&servo_mutex) != 0) {
            fprintf(stderr, "Error: Failed to unlock mutex\n");
        }
        return 1; // Indicate failure
    }

    servo->pulsewidth = pulsewidth;
    servo->angle = angle;

    // Unlock the mutex after accessing shared resources
    if (pthread_mutex_unlock(&servo_mutex) != 0) {
        fprintf(stderr, "Error: Failed to unlock mutex\n");
        return 1;
    }

    return 0; // Indicate success
}

// Function to map an angle to a pulsewidth
int angle_to_pulsewidth(int angle) {
    return (int)(((float)(angle - SERVO_MIN_ANGLE) / (SERVO_MAX_ANGLE - SERVO_MIN_ANGLE)) * (SERVO_MAX_PULSEWIDTH - SERVO_MIN_PULSEWIDTH) + SERVO_MIN_PULSEWIDTH);
}

// Function to handle simulated object detection
int handle_object_detection(Servo *pan_servo, Servo *tilt_servo) {
    // Generate a pseudo-random number to simulate object detection
    int random_number = rand() % 100;

    // Check if an object is detected based on the probability
    if (random_number < OBJECT_DETECTION_PROBABILITY) {
        // Generate random pan and tilt adjustments
        int pan_adjustment = (rand() % 60) - 30; // Range: -30 to +30 degrees
        int tilt_adjustment = (rand() % 40) - 20; // Range: -20 to +20 degrees

        // Calculate new pan and tilt angles
        int new_pan_angle = pan_servo->angle + pan_adjustment;
        int new_tilt_angle = tilt_servo->angle + tilt_adjustment;

        // Ensure angles are within the valid range
        if (new_pan_angle < SERVO_MIN_ANGLE) new_pan_angle = SERVO_MIN_ANGLE;
        if (new_pan_angle > SERVO_MAX_ANGLE) new_pan_angle = SERVO_MAX_ANGLE;
        if (new_tilt_angle < SERVO_MIN_ANGLE) new_tilt_angle = SERVO_MIN_ANGLE;
        if (new_tilt_angle > SERVO_MAX_ANGLE) new_tilt_angle = SERVO_MAX_ANGLE;

        // Set the new servo angles
        if (set_servo_angle(pan_servo, new_pan_angle) != 0) {
            fprintf(stderr, "Error: Failed to set pan servo angle\n");
            return 1;
        }
        if (set_servo_angle(tilt_servo, new_tilt_angle) != 0) {
            fprintf(stderr, "Error: Failed to set tilt servo angle\n");
            return 1;
        }

        printf("Object detected!  Pan: %d, Tilt: %d\n", new_pan_angle, new_tilt_angle);
    }
    return 0;
}

// Servo control thread function
void *servo_control_thread(void *arg) {
    (void)arg; // Suppress unused parameter warning

    while (!terminate) {
        // Simulate object detection and adjust servo positions
        if (handle_object_detection(&pan_servo, &tilt_servo) != 0) {
            fprintf(stderr, "Error: Failed to handle object detection\n");
        }

        // Sleep for a short duration
        usleep(200000); // 200 ms
    }

    pthread_exit(NULL);
    return NULL;
}

// Signal handler function
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("Ctrl+C detected. Terminating program...\n");
        terminate = 1;
    }
}

int main() {
    // Seed the random number generator
    srand(time(NULL));

    // Initialize the pigpio library
    if (initialize_gpio() != 0) {
        return 1; // Exit if initialization fails
    }

    // Initialize mutex
    if (pthread_mutex_init(&servo_mutex, NULL) != 0) {
        fprintf(stderr, "Error: Failed to initialize mutex\n");
        terminate_gpio();
        return 1;
    }

    // Set initial servo positions
    if (set_servo_angle(&pan_servo, 90) != 0) {
        fprintf(stderr, "Error: Failed to set initial pan servo angle\n");
        terminate_gpio();
        pthread_mutex_destroy(&servo_mutex);
        return 1;
    }
    if (set_servo_angle(&tilt_servo, 90) != 0) {
        fprintf(stderr, "Error: Failed to set initial tilt servo angle\n");
        terminate_gpio();
        pthread_mutex_destroy(&servo_mutex);
        return 1;
    }

    // Set up signal handling for Ctrl+C
    signal(SIGINT, signal_handler);

    // Create servo control thread
    pthread_t servo_thread;
    if (pthread_create(&servo_thread, NULL, servo_control_thread, NULL) != 0) {
        fprintf(stderr, "Error: Failed to create servo control thread\n");
        terminate_gpio();
        pthread_mutex_destroy(&servo_mutex);
        return 1;
    }

    // Main loop (wait for termination signal)
    while (!terminate) {
        sleep(1); // Sleep for 1 second
    }

    // Wait for servo control thread to finish
    if (pthread_join(servo_thread, NULL) != 0) {
        fprintf(stderr, "Error: Failed to join servo control thread\n");
    }

    // Destroy mutex
    if (pthread_mutex_destroy(&servo_mutex) != 0) {
        fprintf(stderr, "Error: Failed to destroy mutex\n");
    }

    // Terminate the pigpio library
    terminate_gpio();

    return 0;
}

