#include <pigpio.h>
#include <stdio.h>
#include <time.h>
#define SAMPLE_INTERVAL 200000  // µs
#define TOTAL_DURATION 10000000  // µs (10s)
int read_adc(int spi, int ch) {
    char tx[3] = {1, (0x80 | (ch << 4)), 0}, rx[3];
    spiXfer(spi, tx, rx, 3);
    return ((rx[1] & 3) << 8) | rx[2];
}
int main() {
    if (gpioInitialise() < 0) return 1;
    int spi = spiOpen(0, 1000000, 0);
    FILE* f = fopen("window_stats.csv", "w");
    fprintf(f, "Time,Min,Max\n");
    while (1) {
        int min = 1023, max = 0;
        uint32_t elapsed = 0;
        while (elapsed < TOTAL_DURATION) {
            int val = read_adc(spi, 0);
            if (val < min) min = val;
            if (val > max) max = val;
            gpioDelay(SAMPLE_INTERVAL);
            elapsed += SAMPLE_INTERVAL;
        }
        time_t t = time(NULL);
        fprintf(f, "%ld,%d,%d\n", t, min, max);
        fflush(f);
    }
    fclose(f);
    spiClose(spi);
    gpioTerminate();
    return 0;
}

