int main(void) {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(LED_PIN, PI_OUTPUT);
    gpioSetMode(BUTTON_PIN, PI_INPUT);
    gpioSetPullUpDown(BUTTON_PIN, PI_PUD_UP); // Internal pull-up resistor

    int led_state = 0; // 0: off, 1: on
    int button_pressed = 0;
    int last_button_state = 1; // Assume button is released initially (pulled up)

    while (1) {
        int current_button_state = gpioRead(BUTTON_PIN);

        if (current_button_state == 0 && last_button_state == 1) { // Button pressed
            button_pressed = 1;
        } else if (current_button_state == 1 && last_button_state == 0 && button_pressed == 1) { // Button released after press
            led_state = !led_state; // Toggle LED state
            gpioWrite(LED_PIN, led_state);
            button_pressed = 0;
        }

        last_button_state = current_button_state;
        gpioDelay(5); // Debounce delay
    }

    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pigpio.h>

// Define GPIO pins
#define TRIGGER_PIN 17
#define ECHO_PIN 18
#define BUZZER_PIN 27

// Constants
#define SPEED_OF_SOUND 0.0343 // cm/us
#define DISTANCE_THRESHOLD 20  // cm

// Global variables (volatile because they are accessed in interrupt handlers)
volatile static uint32_t start_tick = 0;
volatile static uint32_t end_tick = 0;
volatile static int echo_active = 0;

// Function prototypes
int initialize_gpio();
void cleanup_gpio();
float calculate_distance(uint32_t pulse_width);
void control_buzzer(float distance);
void echo_callback(int gpio, int level, uint32_t tick);
void trigger_sensor();
void signal_handler(int signal);

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);
    cleanup_gpio();
    exit(0);
}

// Initialize GPIO pins and pigpio library
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Indicate failure
    }

    // Set GPIO modes
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);

    // Disable alerts on TRIGGER_PIN to avoid spurious interrupts
    gpioSetAlertFunc(TRIGGER_PIN, NULL);

    // Set up interrupt callback for ECHO_PIN
    gpioSetAlertFuncEx(ECHO_PIN, echo_callback, NULL); // Using Ex version for tick data

    return 0; // Indicate success
}

// Clean up GPIO pins and terminate pigpio library
void cleanup_gpio() {
    gpioWrite(BUZZER_PIN, 0); // Ensure buzzer is off
    gpioTerminate();
}

// Calculate distance from pulse width
float calculate_distance(uint32_t pulse_width) {
    return (float)pulse_width * SPEED_OF_SOUND / 2.0;
}

// Control the buzzer based on distance
void control_buzzer(float distance) {
    if (distance < DISTANCE_THRESHOLD) {
        gpioWrite(BUZZER_PIN, 1); // Activate buzzer
    } else {
        gpioWrite(BUZZER_PIN, 0); // Deactivate buzzer
    }
}

// Interrupt callback function for ECHO pin
void echo_callback(int gpio, int level, uint32_t tick) {
    if (level == 1) {
        // Rising edge
        start_tick = tick;
        echo_active = 1;
    } else if (level == 0 && echo_active) {
        // Falling edge
        end_tick = tick;
        uint32_t pulse_width = end_tick - start_tick;

        // Calculate distance
        float distance = calculate_distance(pulse_width);

        // Control buzzer
        control_buzzer(distance);

        echo_active = 0; // Reset flag
    }
}

// Trigger the ultrasonic sensor
void trigger_sensor() {
    gpioWrite(TRIGGER_PIN, 1);
    gpioDelay(10); // 10us trigger pulse
    gpioWrite(TRIGGER_PIN, 0);
}

int main() {
    // Set up signal handling for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize GPIO and pigpio
    if (initialize_gpio() != 0) {
        return 1; // Exit if initialization fails
    }

    printf("HC-SR04 distance sensor with buzzer\n");

    // Main loop
    while (1) {
        trigger_sensor();
        gpioDelay(50); // Delay between measurements
    }

    return 0; // This line should never be reached due to the infinite loop
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <errno.h>
#include <string.h>
#include <unistd.h>
#include <signal.h>

#include <wiringPi.h>
#include <softPwm.h>

// Constants
#define PWM_RANGE       100
#define NUM_LEDS        8
#define DELAY_MS        10

// Pin mapping (BCM numbering)
const int led_gpio_pins[NUM_LEDS] = {17, 18, 27, 22, 23, 24, 25, 4};

// Global variables
volatile sig_atomic_t program_running = 1;

// Function prototypes
void cleanup(int signal);
int initialize_leds(void);
void chasing_lights(void);

// Signal handler for clean exit
void cleanup(int signal)
{
    (void)signal; // Suppress unused parameter warning
    printf("\nCleaning up and exiting...\n");
    program_running = 0;

    // Disable PWM and set pins to input to avoid leaving LEDs on
    for (int i = 0; i < NUM_LEDS; ++i)
    {
        softPwmStop(led_gpio_pins[i]);
        pinMode(led_gpio_pins[i], INPUT); // Set as input to avoid leaving them on
    }

    wiringPiSetup();

    exit(0);
}

// Initialize LEDs with software PWM
int initialize_leds(void)
{
    int pin;
    for (int i = 0; i < NUM_LEDS; ++i)
    {
        pin = led_gpio_pins[i];
        if (softPwmCreate(pin, 0, PWM_RANGE) != 0)
        {
            fprintf(stderr, "Error creating PWM on pin %d: %s\n", pin, strerror(errno));
            return -1;
        }
        printf("LED %d initialized on GPIO %d\n", i, pin);
    }
    return 0;
}

// Chasing lights effect
void chasing_lights(void)
{
    int values[NUM_LEDS] = {0, 25, 50, 75, 100, 75, 50, 25};
    int i, j, temp;

    while (program_running)
    {
        for (i = 0; i < NUM_LEDS; ++i)
        {
            softPwmWrite(led_gpio_pins[i], values[i]);
        }

        delay(50);

        // Rotate the values array for the chasing effect
        temp = values[0];
        for (j = 0; j < NUM_LEDS - 1; ++j)
        {
            values[j] = values[j + 1];
        }
        values[NUM_LEDS - 1] = temp;
    }
}

int main(void)
{
    // Setup signal handler for Ctrl+C
    signal(SIGINT, cleanup);

