#include <stdio.h>
#include <pigpio.h>
#include <signal.h>
#include <unistd.h>

// Define GPIO pins
#define TRIGGER_PIN 23
#define ECHO_PIN 24
#define BUZZER_PIN 18

// Define distance and frequency ranges
#define MIN_DISTANCE 20.0  // cm
#define MAX_DISTANCE 100.0 // cm
#define MIN_FREQUENCY 200.0 // Hz
#define MAX_FREQUENCY 2000.0 // Hz

// Define constants
#define SOUND_SPEED 34300.0 // cm/s

// Global variable for graceful shutdown
volatile sig_atomic_t terminate = 0;

// Signal handler function
void signal_handler(int sig)
{
    fprintf(stderr, "\nCaught signal %d, terminating gracefully...\n", sig);
    terminate = 1;
}

// Function to read distance from the ultrasonic sensor
float getDistance()
{
    // Trigger the sensor
    gpioWrite(TRIGGER_PIN, 1);
    gpioDelay(10); // 10us trigger pulse
    gpioWrite(TRIGGER_PIN, 0);

    // Measure echo pulse width
    uint32_t start_tick = gpioTick();
    uint32_t end_tick = start_tick;
    int timeout_count = 0;

    // Wait for echo to go high
    while (gpioRead(ECHO_PIN) == 0) {
        if (timeout_count++ > 50000) return -1.0; // Timeout after 50ms
        gpioDelay(1); // Small delay to avoid busy-waiting
    }

    start_tick = gpioTick();

    // Wait for echo to go low
    timeout_count = 0;
    while (gpioRead(ECHO_PIN) == 1) {
        if (timeout_count++ > 50000) return -1.0; // Timeout after 50ms
        gpioDelay(1); // Small delay to avoid busy-waiting
    }

    end_tick = gpioTick();

    // Calculate pulse width in microseconds
    uint32_t pulse_width = end_tick - start_tick;

    // Calculate distance in centimeters
    float distance = (pulse_width / 2.0) * (SOUND_SPEED / 1000000.0);

    return distance;
}

// Function to calculate frequency based on distance
float calculateFrequency(float distance)
{
    // Ensure distance is within the defined range
    if (distance < MIN_DISTANCE)
        distance = MIN_DISTANCE;
    else if (distance > MAX_DISTANCE)
        distance = MAX_DISTANCE;

    // Map distance to frequency linearly
    float frequency = MIN_FREQUENCY + (distance - MIN_DISTANCE) * (MAX_FREQUENCY - MIN_FREQUENCY) / (MAX_DISTANCE - MIN_DISTANCE);

    return frequency;
}

int main()
{
    // Initialize pigpio library
    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Configure GPIO pins
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);

    // Set PWM frequency (initial value)
    gpioSetPWMfrequency(BUZZER_PIN, 400); // Initial frequency

    // Set PWM range (maximum duty cycle value)
    gpioSetPWMrange(BUZZER_PIN, 200); // Adjust as needed

    // Set PWM duty cycle (50% initially)
    gpioPWM(BUZZER_PIN, 100);

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    fprintf(stderr, "Theremin started. Press Ctrl+C to exit.\n");

    // Main loop
    while (!terminate)
    {
        // Read distance from the ultrasonic sensor
        float distance = getDistance();

        if (distance < 0)
        {
            fprintf(stderr, "Sensor failure or timeout\n");
        }
        else
        {
            // Calculate the corresponding frequency
            float frequency = calculateFrequency(distance);

            // Update the PWM signal output to the piezo buzzer
            gpioSetPWMfrequency(BUZZER_PIN, (int)frequency); // Set frequency
        }

        // Small delay to avoid overwhelming the CPU
        gpioDelay(50); // 50ms delay
    }

    // Stop PWM signal
    gpioPWM(BUZZER_PIN, 0);

    // Terminate pigpio library
    gpioTerminate();

    fprintf(stderr, "Theremin terminated.\n");

    return 0;
}

