#include <stdio.h>
#include <pigpio.h>
#include <signal.h>
#include <time.h>
#include <math.h>

// Define GPIO pins for servos
#define PAN_SERVO_GPIO 17
#define TILT_SERVO_GPIO 18

// Define sweep parameters
#define SWEEP_DURATION 5000 // milliseconds (5 seconds)
#define TILT_MIN_ANGLE 45
#define TILT_MAX_ANGLE 135

// Global variables for servo angles
volatile int pan_angle = 0;
volatile int tilt_angle = 90; // Initial tilt angle

// Global variables for sweep direction
volatile int pan_direction = 1; // 1 for increasing, -1 for decreasing
volatile int tilt_direction = 1;

// File pointer for logging
FILE *log_file = NULL;

// Function to set servo angle using pigpio
void set_servo_angle(int gpio, int angle) {
    // Ensure angle is within valid range (0-180)
    if (angle < 0) angle = 0;
    if (angle > 180) angle = 180;

    // Map angle (0-180) to pulse width (500-2500)
    int pulse_width = (int)(500 + ((float)angle / 180.0) * 2000);

    gpioServo(gpio, pulse_width);
    gpioDelay(10); // Small delay to prevent excessive CPU usage
}

// Callback function for timer-based event
void sweep_callback(int gpio, int level, uint32_t tick) {
    // Update pan angle
    pan_angle += pan_direction;
    if (pan_angle >= 180) {
        pan_angle = 180;
        pan_direction = -1; // Reverse direction
    } else if (pan_angle <= 0) {
        pan_angle = 0;
        pan_direction = 1; // Reverse direction
    }

    // Update tilt angle (sinusoidal motion)
    float tilt_rad = ((float)tick / SWEEP_DURATION) * 2 * M_PI;
    tilt_angle = TILT_MIN_ANGLE + (TILT_MAX_ANGLE - TILT_MIN_ANGLE) * (0.5 + 0.5 * sin(tilt_rad));

    // Set servo angles
    set_servo_angle(PAN_SERVO_GPIO, pan_angle);
    set_servo_angle(TILT_SERVO_GPIO, tilt_angle);

    // Log servo angles and timestamp
    time_t current_time = time(NULL);
    struct tm *tm_info = localtime(&current_time);
    char time_string[26];
    strftime(time_string, 26, "%Y-%m-%d %H:%M:%S", tm_info);

    if (log_file != NULL) {
        fprintf(log_file, "%s\t%d\t%d\n", time_string, pan_angle, tilt_angle);
        fflush(log_file); // Flush the buffer to ensure data is written to file
    } else {
        fprintf(stderr, "Error: Log file is not open.\n");
    }
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("\nCaught signal %d, exiting gracefully.\n", signal);

    // Stop servos
    gpioServo(PAN_SERVO_GPIO, 0);
    gpioServo(TILT_SERVO_GPIO, 0);

    // Close log file
    if (log_file != NULL) {
        fclose(log_file);
        printf("Log file closed.\n");
    }

    // Terminate pigpio library
    gpioTerminate();
    printf("pigpio terminated.\n");

    exit(0);
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes for servo control
    gpioSetMode(PAN_SERVO_GPIO, PI_OUTPUT);
    gpioSetMode(TILT_SERVO_GPIO, PI_OUTPUT);

    // Open log file in append mode
    log_file = fopen("radar_log.txt", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        gpioTerminate();
        return 1;
    }
    fprintf(log_file, "Timestamp\tPan Angle\tTilt Angle\n");
    fflush(log_file);

    // Set up signal handling for Ctrl+C
    signal(SIGINT, signal_handler);

    // Set up timer-based event for sweep motion
    gpioSetTimerFuncEx(0, 10, sweep_callback, 0); // Timer 0, every 10 ms

    printf("Radar simulation started. Press Ctrl+C to exit.\n");

    // Keep the program running
    while (1) {
        gpioDelay(1000); // Sleep for 1 second
    }

    return 0;
}

#include <stdio.h>
