// Define GPIO pins and threshold
#define SOUND_SENSOR_PIN 17
#define BUZZER_PIN 18
#define SOUND_THRESHOLD 0  // Experimentally determined threshold (0 or 1)

// Function prototypes
int readSoundSensor();
void controlBuzzer(int state);
void logAlarm();
void cleanup(int signal);

// Global variable for signal handling
volatile sig_atomic_t program_running = 1;

int main() {
    // Setup signal handler for Ctrl+C
    signal(SIGINT, cleanup);

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed, exiting...\n");
        return 1;
    }

    // Set GPIO pins to correct modes
    pinMode(SOUND_SENSOR_PIN, INPUT);
    pinMode(BUZZER_PIN, OUTPUT);

    printf("Sound monitoring started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        int soundLevel = readSoundSensor();

        if (soundLevel == -1) {
            fprintf(stderr, "Error reading sound sensor.\n");
        } else if (soundLevel > SOUND_THRESHOLD) {
            printf("Sound detected!\n");
            controlBuzzer(1); // Activate buzzer
            logAlarm();         // Log the alarm
            delay(500);         // Buzzer duration
            controlBuzzer(0); // Deactivate buzzer
        }

        delay(100); // Check every 100ms
    }

    return 0;
}

// Function to read the sound sensor
int readSoundSensor() {
    int soundLevel = digitalRead(SOUND_SENSOR_PIN);
    return soundLevel;
}

// Function to control the buzzer
void controlBuzzer(int state) {
    digitalWrite(BUZZER_PIN, state);
}

// Function to log alarm events
void logAlarm() {
    FILE *fp = fopen("alarm_log.txt", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        return;
    }

    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(fp, "%s - Sound alarm triggered\n", timestamp);
    fclose(fp);
}

// Function to handle Ctrl+C signal and cleanup GPIO pins
void cleanup(int signal) {
    printf("Cleaning up and exiting...\n");
    program_running = 0;
    controlBuzzer(0); // Ensure buzzer is off
    digitalWrite(BUZZER_PIN, LOW); //Set to LOW to avoid floating pin state
    exit(0);
}

