// Define ioctl command (replace with your actual ioctl command)
#define IOCTL_ACTIVATE_SENSOR  _IOW('k', 1, int)
#define IOCTL_DEACTIVATE_SENSOR _IOW('k', 2, int)

// Device file path
#define DEVICE_PATH "/dev/sa_driver_dev"

int main() {
    int file_descriptor;
    int user_input;
    int return_val;

    // Open the device file
    file_descriptor = open(DEVICE_PATH, O_RDWR);
    if (file_descriptor < 0) {
        perror("Failed to open device");
        return EXIT_FAILURE;
    }

    // Main loop
    while (1) {
        printf("\nSensor Control:\n");
        printf("1. Activate Sensor\n");
        printf("2. Deactivate Sensor\n");
        printf("3. Exit\n");
        printf("Enter your choice: ");

        // Read user input
        if (scanf("%d", &user_input) != 1) {
            fprintf(stderr, "Invalid input. Please enter a number.\n");
            while (getchar() != '\n'); // Clear input buffer
            continue;
        }

        // Process user input
        switch (user_input) {
            case 1:
                // Activate sensor using ioctl
                return_val = ioctl(file_descriptor, IOCTL_ACTIVATE_SENSOR, NULL);
                if (return_val == -1) {
                    perror("Failed to activate sensor");
                } else {
                    printf("Sensor activated successfully.\n");
                }
                break;

            case 2:
                // Deactivate sensor using ioctl
                return_val = ioctl(file_descriptor, IOCTL_DEACTIVATE_SENSOR, NULL);
                if (return_val == -1) {
                    perror("Failed to deactivate sensor");
                } else {
                    printf("Sensor deactivated successfully.\n");
                }
                break;

            case 3:
                // Exit the application
                close(file_descriptor);
                printf("Exiting application.\n");
                return EXIT_SUCCESS;

            default:
                printf("Invalid choice. Please try again.\n");
                break;
        }
    }

    // Close the device file (should not reach here in normal execution)
    close(file_descriptor);
    return EXIT_SUCCESS;
}

#include <pigpio.h>
#include <stdio.h>
#define LED_PIN 17
#define CONTROL_PIN 22
int read_adc(int spi, int ch) {
    char tx[3] = {1, (0x80 | (ch << 4)), 0}, rx[3];
    spiXfer(spi, tx, rx, 3);
    return ((rx[1] & 3) << 8) | rx[2];
}
int main() {
    if (gpioInitialise() < 0) return 1;
    gpioSetMode(LED_PIN, PI_OUTPUT);
    gpioSetMode(CONTROL_PIN, PI_INPUT);
    int spi = spiOpen(0, 1000000, 0);
    while (1) {
        if (gpioRead(CONTROL_PIN) == 1) {
            int val = read_adc(spi, 0);
            gpioWrite(LED_PIN, val > 500 ? 1 : 0);
        } else {
            gpioWrite(LED_PIN, 0);
        }
        gpioDelay(200000);
    }
    spiClose(spi);
    gpioTerminate();
    return 0;
}

