#include <pigpio.h>
#include <stdio.h>
#define N 10
int read_adc(int spi, int ch) {
    char tx[3] = {1, (0x80 | (ch << 4)), 0}, rx[3];
    spiXfer(spi, tx, rx, 3);
    return ((rx[1] & 3) << 8) | rx[2];
}
int main() {
    if (gpioInitialise() < 0) return 1;
    int spi = spiOpen(0, 1000000, 0);
    int buffer[N] = {0}, sum = 0, index = 0;
    while (1) {
        int val = read_adc(spi, 0);
        sum -= buffer[index];
        buffer[index] = val;
        sum += val;
        index = (index + 1) % N;
        if (index == 0) printf("Moving Avg: %d\n", sum / N);
        gpioDelay(100000);
    }
    spiClose(spi);
    gpioTerminate();
    return 0;
}

