#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <unistd.h>
#include <errno.h>
#include <wiringPi.h>
#include <mcp23017.h>

// Constants
#define Q2W_BASE_PIN 100         // Base pin number for the MCP23017
#define MCP23017_I2C_ADDR 0x20   // I2C address of the MCP23017
#define NUM_OUTPUT_PINS 10       // Number of output pins used for the binary counter
#define INPUT_PIN_ONBOARD 0      // Onboard GPIO pin for input (e.g., button)
#define INPUT_PIN_MCP23017 (Q2W_BASE_PIN + 15) // MCP23017 pin for input

// Function prototypes
bool setup_gpio();
void binary_counter();

int main(void) {
    if (!setup_gpio()) {
        fprintf(stderr, "GPIO setup failed. Exiting.\n");
        return EXIT_FAILURE;
    }

    printf("Raspberry Pi - quite2Wire MCP23017 Binary Counter\n");

    binary_counter();

    return EXIT_SUCCESS;
}

bool setup_gpio() {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return false;
    }

    // Setup MCP23017
    int result = mcp23017Setup(Q2W_BASE_PIN, MCP23017_I2C_ADDR);
    if (result == -1) {
        fprintf(stderr, "mcp23017Setup failed: %s\n", strerror(errno));
        return false;
    }

    // On-board button Input:
    pinMode(INPUT_PIN_ONBOARD, INPUT);

    // First NUM_OUTPUT_PINS pins on q2w board as outputs:
    for (int i = 0; i < NUM_OUTPUT_PINS; ++i) {
        pinMode(Q2W_BASE_PIN + i, OUTPUT);
    }

    // Last pin as an input with the internal pull-up enabled
    pinMode(INPUT_PIN_MCP23017, INPUT);
    pullUpDnControl(INPUT_PIN_MCP23017, PUD_UP);

    return true;
}

void binary_counter() {
    // Loop, outputting a binary number
    while (true) {
        for (int i = 0; i < 1024; ++i) {
            // Output the binary representation of 'i' to the MCP23017 pins
            for (int bit = 0; bit < NUM_OUTPUT_PINS; ++bit) {
                digitalWrite(Q2W_BASE_PIN + bit, (i >> bit) & 1);
            }

            // Delay based on input pins
            while (digitalRead(INPUT_PIN_ONBOARD) == HIGH) { // While pushed
                delay(1); // Short delay while onboard button is pressed
            }

            if (digitalRead(INPUT_PIN_MCP23017) == HIGH) { // Not Pushed
                delay(100); // Longer delay if MCP23017 button is not pressed
            }
        }
    }
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <time.h>
#include <signal.h>
#include <string.h>
#include <errno.h>

// Compile-time definitions
#define SENSOR_PIN 4
#define LED_PIN 5
#define LOG_FILE "vibration_log.txt"

volatile sig_atomic_t program_running = 1;

// Function prototypes
int readVibrationSensor(void);
void controlLED(int state);
void logEvent(void);
void vibrationDetected(void);
void cleanup(int signal);

// Sensor monitoring function
int readVibrationSensor(void) {
    int state = digitalRead(SENSOR_PIN);
    delay(5); // Debounce
    return (state == LOW) ? 1 : 0; // Vibration detected if signal is LOW
}

// LED control function
void controlLED(int state) {
    digitalWrite(LED_PIN, state);
}

// Logging function
void logEvent(void) {
    FILE *fp = NULL;
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return;
    }

    fprintf(fp, "Vibration detected at: %s\n", timestamp);

    if (fclose(fp) != 0) {
        perror("Error closing log file");
    }
}

// Interrupt handling function
void vibrationDetected(void) {
    controlLED(HIGH); // Turn LED on
    logEvent();       // Log the event
    delay(1000);      // Keep LED on for 1 second
    controlLED(LOW);  // Turn LED off
}

// Cleanup function for graceful shutdown
void cleanup(int signal) {
    printf("Cleaning up and exiting...\n");
    program_running = 0; // Stop the main loop if it's running.
    pinMode(SENSOR_PIN, INPUT); // Set sensor pin to input
    pinMode(LED_PIN, INPUT);    // Set LED pin to input

    // Close the log file if it's open (although it should be closed already)
    FILE *fp = fopen(LOG_FILE, "a"); // Open in append mode to check if it exists
    if (fp != NULL) {
        if (fclose(fp) != 0) {
            perror("Error closing log file during cleanup");
        }
    }

    wiringPiSetup();
    digitalWrite(LED_PIN, LOW);
    pinMode(LED_PIN, INPUT);
    exit(0);
}

int main(void) {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Set GPIO modes
    pinMode(SENSOR_PIN, INPUT);
    pinMode(LED_PIN, OUTPUT);

    // Set up interrupt on GPIO 4 (WiringPi pin number)
    if (wiringPiISR(SENSOR_PIN, INT_EDGE_FALLING, vibrationDetected) < 0) {
        fprintf(stderr, "Unable to setup ISR: %s\n", strerror(errno));
        return 1;
    }

    // Set up signal handling for Ctrl+C
    signal(SIGINT, cleanup);

    printf("Vibration monitoring started. Press Ctrl+C to exit.\n");

    // Main loop (optional, as the interrupt handles everything)
    while (program_running) {
        delay(100);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>
#include <unistd.h>

// TCS34725 I2C address
#define TCS34725_ADDRESS 0x29

// TCS34725 registers
#define TCS34725_ENABLE 0x00
#define TCS34725_ATIME 0x01
#define TCS34725_CONTROL 0x0F
#define TCS34725_ID 0x12
#define TCS34725_CDATA 0x14
#define TCS34725_RDATA 0x16
#define TCS34725_GDATA 0x18
#define TCS34725_BDATA 0x1A

// GPIO pin for LED
#define LED_PIN 17

// Red value threshold
#define RED_THRESHOLD 200

// Function to initialize the I2C bus and check sensor ID
int init_i2c(int *fd) {
    *fd = wiringPiI2CSetup(TCS34725_ADDRESS);
    if (*fd == -1) {
        fprintf(stderr, "Error: Unable to initialize I2C bus.\n");
        return -1;
    }

    int id = wiringPiI2CReadReg8(*fd, TCS34725_ID);
    if (id != 0x44) {
        fprintf(stderr, "Error: Invalid sensor ID: 0x%02X\n", id);
        return -1;
    }

    printf("TCS34725 sensor found with ID: 0x%02X\n", id);
    return 0;
}

// Function to configure the TCS34725 sensor
int config_sensor(int fd) {
    // Enable power and ADC
    if (wiringPiI2CWriteReg8(fd, TCS34725_ENABLE, 0x03) == -1) {
        fprintf(stderr, "Error: Unable to write to enable register.\n");
        return -1;
    }

    // Set integration time
    if (wiringPiI2CWriteReg8(fd, TCS34725_ATIME, 0xEB) == -1) {
        fprintf(stderr, "Error: Unable to write to integration time register.\n");
        return -1;
    }

    // Set gain
    if (wiringPiI2CWriteReg8(fd, TCS34725_CONTROL, 0x01) == -1) {
        fprintf(stderr, "Error: Unable to write to gain register.\n");
        return -1;
    }

    return 0;
}

// Function to read a 16-bit value from the sensor
int read_16bit_value(int fd, int reg, uint16_t *value) {
    int low = wiringPiI2CReadReg8(fd, reg);
    if (low == -1) {
        fprintf(stderr, "Error: Unable to read low byte from register 0x%02X.\n", reg);
        return -1;
    }

    int high = wiringPiI2CReadReg8(fd, reg + 1);
    if (high == -1) {
        fprintf(stderr, "Error: Unable to read high byte from register 0x%02X.\n", reg + 1);
        return -1;
    }

    *value = (high << 8) | low;
    return 0;
}

// Function to read color data from the sensor
int read_color_data(int fd, uint16_t *clear, uint16_t *red, uint16_t *green, uint16_t *blue) {
    if (read_16bit_value(fd, TCS34725_CDATA, clear) == -1) return -1;
    if (read_16bit_value(fd, TCS34725_RDATA, red) == -1) return -1;
    if (read_16bit_value(fd, TCS34725_GDATA, green) == -1) return -1;
    if (read_16bit_value(fd, TCS34725_BDATA, blue) == -1) return -1;
    return 0;
}

// Function to normalize RGB values based on clear value
void normalize_rgb(uint16_t clear, uint16_t red, uint16_t green, uint16_t blue, float *r_norm, float *g_norm, float *b_norm) {
    float clear_f = (float)clear;
    *r_norm = (float)red / clear_f;
    *g_norm = (float)green / clear_f;
    *b_norm = (float)blue / clear_f;
}

// Function to check if red value exceeds threshold
int is_red_above_threshold(uint16_t red) {
    return red > RED_THRESHOLD;
}

// Function to blink the LED
void blink_led(int pin) {
    digitalWrite(pin, HIGH);
    delay(50);
    digitalWrite(pin, LOW);
    delay(50);
}

int main() {
    int fd; // I2C file descriptor

    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error: Unable to initialize wiringPi.\n");
        return 1;
    }

    // Initialize I2C
    if (init_i2c(&fd) == -1) {
        return 1;
    }

    // Configure sensor
    if (config_sensor(fd) == -1) {
        return 1;
    }

    // Set LED pin as output
    pinMode(LED_PIN, OUTPUT);

    // Main loop
    while (1) {
        uint16_t clear, red, green, blue;

        // Read color data
        if (read_color_data(fd, &clear, &red, &green, &blue) == -1) {
            fprintf(stderr, "Error reading color data. Retrying...");
            delay(100); // Add a small delay before retrying
            continue;      // Skip the rest of the loop and retry reading
        }

        // Normalize RGB values
        float r_norm, g_norm, b_norm;
        normalize_rgb(clear, red, green, blue, &r_norm, &g_norm, &b_norm);

        // Print color data
        printf("Clear: %5d, Red: %5d, Green: %5d, Blue: %5d, R_norm: %.2f, G_norm: %.2f, B_norm: %.2f\n", clear, red, green, blue, r_norm, g_norm, b_norm);

        // Check if red value exceeds threshold and blink LED
        if (is_red_above_threshold(red)) {
            blink_led(LED_PIN);
        }

        delay(100);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <wiringPi.h>

// Define NES button mappings (same as piNes.h, but included here for self-containment and clarity)
#define NES_A      1
#define NES_B      2
#define NES_SELECT 4
#define NES_START  8
#define NES_UP     16
#define NES_DOWN   32
#define NES_LEFT   64
#define NES_RIGHT  128

// GPIO pins connected to the NES controller (adjust as needed)
#define NES_DATA_PIN  2  // Data pin
#define NES_LATCH_PIN 1  // Latch pin
#define NES_CLOCK_PIN 0  // Clock pin

// Function prototypes
int setupNesController(int dataPin, int latchPin, int clockPin);
unsigned int readNesController();

// Error handling macro
#define FATAL_ERROR(msg) do { \
    fprintf(stderr, "Error: %s (%s:%d)\n", msg, __FILE__, __LINE__); \
    exit(EXIT_FAILURE); \
} while (0)

int main() {
    int controllerHandle;
    unsigned int buttonState;

    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        FATAL_ERROR("WiringPi initialization failed");
    }

    // Setup the NES controller
    controllerHandle = setupNesController(NES_DATA_PIN, NES_LATCH_PIN, NES_CLOCK_PIN);
    if (controllerHandle == -1) {
        FATAL_ERROR("NES controller setup failed");
    }

    // Main loop: read controller input and print button states
    while (1) {
        buttonState = readNesController();

        printf("Buttons: ");
        printf((buttonState & NES_UP)     ? "UP "     : "-- ");
        printf((buttonState & NES_DOWN)   ? "DOWN "   : "-- ");
        printf((buttonState & NES_LEFT)   ? "LEFT "   : "-- ");
        printf((buttonState & NES_RIGHT)  ? "RIGHT "  : "-- ");
        printf((buttonState & NES_SELECT) ? "SELECT " : "-- ");
        printf((buttonState & NES_START)  ? "START "  : "-- ");
        printf((buttonState & NES_A)      ? "A "      : "-- ");
        printf((buttonState & NES_B)      ? "B "      : "-- ");
        printf("\n");

        delay(50); // Small delay to avoid flooding the console
    }

    return 0;
}


// Function to set up the NES controller pins
int setupNesController(int dataPin, int latchPin, int clockPin) {
    // Set pin modes
    pinMode(dataPin, INPUT);
    pinMode(latchPin, OUTPUT);
    pinMode(clockPin, OUTPUT);

    // Initial state for clock and latch pins
    digitalWrite(latchPin, LOW);
    digitalWrite(clockPin, LOW);

    return 0; // Return 0 to indicate success
}


// Function to read the NES controller state
unsigned int readNesController() {
    unsigned int buttonData = 0;

    // Strobe the latch pin to load the button states
    digitalWrite(NES_LATCH_PIN, HIGH);
    delayMicroseconds(12); // Minimum 12us pulse
    digitalWrite(NES_LATCH_PIN, LOW);

    // Read the button states by clocking the data pin
    for (int i = 0; i < 8; i++) {
        digitalWrite(NES_CLOCK_PIN, HIGH);
        delayMicroseconds(6); // Minimum 6us pulse
        if (digitalRead(NES_DATA_PIN) == LOW) { // Active low
            buttonData |= (1 << i);
        }
        digitalWrite(NES_CLOCK_PIN, LOW);
        delayMicroseconds(6); // Minimum 6us pulse
    }

    return buttonData;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>

// Define the GPIO pin for the buzzer
#define BUZZER_PIN 22

// Define some notes (frequencies in Hz)
#define NOTE_C4 262
#define NOTE_D4 294
#define NOTE_E4 330
#define NOTE_F4 349
#define NOTE_G4 392
#define NOTE_A4 440
#define NOTE_B4 494
#define NOTE_C5 523

// Structure to hold a note and its duration
typedef struct {
    int frequency;
    int duration_ms;
} Note;

// Function to play a note
void playNote(int frequency, int duration_ms) {
    if (frequency == 0) { // Rest
        gpioWrite(BUZZER_PIN, 0);
        gpioDelay(duration_ms * 1000); // Convert ms to microseconds
    } else {
        int period_us = 1000000 / frequency; // Period in microseconds
        int half_period_us = period_us / 2;
        long start_time = gpioTick();
        while (gpioTick() - start_time < duration_ms * 1000) {
            gpioWrite(BUZZER_PIN, 1);
            gpioDelay(half_period_us);
            gpioWrite(BUZZER_PIN, 0);
            gpioDelay(half_period_us);
        }
    }
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(BUZZER_PIN, PI_OUTPUT);

    // Seed the random number generator
    srand(time(NULL));

    // Define an array of notes for the melody
    Note melody[] = {
        {NOTE_C4, 250},
        {NOTE_D4, 250},
        {NOTE_E4, 250},
        {NOTE_F4, 250},
        {NOTE_G4, 250},
        {NOTE_A4, 250},
        {NOTE_B4, 250},
        {NOTE_C5, 500}
    };

    int melody_length = sizeof(melody) / sizeof(melody[0]);

    // Play a random melody several times
    for (int i = 0; i < 5; ++i) {
        // Generate a random index to start the melody
        int start_index = rand() % melody_length;

        // Play the melody from the random start index
        for (int j = 0; j < melody_length; ++j) {
            int index = (start_index + j) % melody_length;
            playNote(melody[index].frequency, melody[index].duration_ms);
        }
        gpioDelay(500000); // Delay between melodies (0.5 seconds)
    }

    gpioTerminate();
    return 0;
}

