// Helper function to get current timestamp with microseconds
void get_timestamp(char *timestamp)
{
    struct timeval tv;
    struct tm *tm_info;

    gettimeofday(&tv, NULL);
    tm_info = localtime(&tv.tv_sec);

    strftime(timestamp, 26, "%Y-%m-%d %H:%M:%S", tm_info);
    sprintf(timestamp + strlen(timestamp), ".%06ld", (long int)tv.tv_usec);
}

// GPIO utility functions
int gpio_export(int pin) {
    char buffer[64];
    int len;
    FILE *fp;

    len = snprintf(buffer, sizeof(buffer), "/sys/class/gpio/export");
    fp = fopen(buffer, "w");
    if (fp == NULL) {
        perror("Failed to open export file");
        return -1;
    }
    len = snprintf(buffer, sizeof(buffer), "%d", pin);
    if (fwrite(buffer, 1, len, fp) != len) {
        perror("Failed to write to export file");
        fclose(fp);
        return -1;
    }
    fclose(fp);
    return 0;
}

