// Motor control functions
void motor_forward(int motor) {
    if (motor == 0) { // Motor A
        gpio_write(MOTOR_A_IN1, 1);
        gpio_write(MOTOR_A_IN2, 0);
        log_motor_command("Motor A Forward");
    } else if (motor == 1) { // Motor B
        gpio_write(MOTOR_B_IN3, 1);
        gpio_write(MOTOR_B_IN4, 0);
        log_motor_command("Motor B Forward");
    }
}

void motor_backward(int motor) {
    if (motor == 0) { // Motor A
        gpio_write(MOTOR_A_IN1, 0);
        gpio_write(MOTOR_A_IN2, 1);
        log_motor_command("Motor A Backward");
    } else if (motor == 1) { // Motor B
        gpio_write(MOTOR_B_IN3, 0);
        gpio_write(MOTOR_B_IN4, 1);
        log_motor_command("Motor B Backward");
    }
}

void motor_stop(int motor) {
    if (motor == 0) { // Motor A
        gpio_write(MOTOR_A_IN1, 0);
        gpio_write(MOTOR_A_IN2, 0);
        log_motor_command("Motor A Stop");
    } else if (motor == 1) { // Motor B
        gpio_write(MOTOR_B_IN3, 0);
        gpio_write(MOTOR_B_IN4, 0);
        log_motor_command("Motor B Stop");
    }
}

// Collision detection function
int check_collision() {
    int left_sensor_value = gpio_read(LEFT_SENSOR);
    int right_sensor_value = gpio_read(RIGHT_SENSOR);

    if (left_sensor_value == -1 || right_sensor_value == -1) {
        fprintf(stderr, "Error reading sensor values.\n");
        return 0; // Assume no collision if sensor read fails.
    }

    return (left_sensor_value == 1 || right_sensor_value == 1);
}

