#include <stdio.h>
#include <pigpio.h>

#define LED_CONSTANT 21
#define LED_PWM 13
#define BUTTON 20

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(LED_CONSTANT, PI_OUTPUT);
    gpioSetMode(LED_PWM, PI_OUTPUT);
    gpioSetMode(BUTTON, PI_INPUT);
    gpioSetPullUpDown(BUTTON, PI_PUD_UP); // Enable pull-up resistor

    gpioWrite(LED_CONSTANT, 1); // Turn on the constant LED

    int button_state = 1; // Initialize to released state
    int pwm_value = 0;
    int increment = 5;   // PWM increment/decrement step
    int pulsing = 0;     // Flag to indicate pulsing is active

    while (1) {
        int current_button_state = gpioRead(BUTTON);

        if (current_button_state == 0 && button_state == 1) {
            // Button pressed
            pulsing = 1; // Start pulsing
            button_state = 0;  //debounce
        } else if (current_button_state == 1 && button_state == 0) {
            // Button released. Debounce.
            button_state = 1;
        }

        if (pulsing) {
            gpioPWM(LED_PWM, pwm_value);
            pwm_value += increment;

            if (pwm_value >= 255) {
                pwm_value = 255;
                increment = -5;
            } else if (pwm_value <= 0) {
                pwm_value = 0;
                increment = 5;
                pulsing = 0; // Stop pulsing after one cycle
                gpioPWM(LED_PWM, 0); // Turn off LED after pulse
            }
            gpioDelay(20);
        }
        else {
            gpioPWM(LED_PWM, 0); // Ensure LED_PWM is off when not pulsing
            gpioDelay(10);  //Reduce CPU usage
        }
    }

    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/spi/spidev.h>
#include <errno.h>

// Define GPIO pins for servo motors
#define HORIZONTAL_SERVO_PIN 17
#define VERTICAL_SERVO_PIN 18

// Define SPI settings
#define SPI_DEVICE "/dev/spidev0.0"
#define SPI_MODE SPI_MODE_0
#define SPI_BITS_PER_WORD 8
#define SPI_SPEED 1000000 // 1 MHz

// Servo limits (SG90)
#define SERVO_MIN_PULSE_WIDTH 500
#define SERVO_MAX_PULSE_WIDTH 2500

// MCP3008 ADC resolution
#define ADC_MAX_VALUE 1023

// Global variables (volatile for signal handling)
volatile sig_atomic_t program_running = 1;
int spi_fd;

// Function prototypes
int pigpio_init_safe();
int mcp3008_read_channel(int channel);
int calculate_servo_angle(int adc_value);
int set_servo_pulse_width(int gpio, int pulse_width);
void handle_signal(int signal);
int spi_setup();

// Function to initialize pigpio safely
int pigpio_init_safe() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }
    return 0;
}

// Function to read data from MCP3008 ADC
int mcp3008_read_channel(int channel) {
    unsigned char tx_buf[3];
    unsigned char rx_buf[3];

    // Construct SPI message
    tx_buf[0] = 0x01; // Start bit
    tx_buf[1] = ((channel & 0x07) << 4) | 0x80; // Single-ended mode, channel selection
    tx_buf[2] = 0x00;

    struct spi_ioc_transfer transfer = {
        .tx_buf = (unsigned long)tx_buf,
        .rx_buf = (unsigned long)rx_buf,
        .len = 3,
        .speed_hz = SPI_SPEED,
        .bits_per_word = SPI_BITS_PER_WORD,
    };

    if (ioctl(spi_fd, SPI_IOC_MESSAGE(1), &transfer) < 0) {
        perror("SPI transaction failed");
        return -1;
    }

    // Extract ADC value
    int adc_value = ((rx_buf[1] & 0x03) << 8) + rx_buf[2];
    return adc_value;
}

// Function to calculate servo angle from ADC value
int calculate_servo_angle(int adc_value) {
    // Scale ADC value (0-1023) to servo pulse width (SERVO_MIN_PULSE_WIDTH - SERVO_MAX_PULSE_WIDTH)
    // This assumes a linear relationship. Adjust the scaling and offset as needed
    int pulse_width = SERVO_MIN_PULSE_WIDTH + (int)(((float)adc_value / ADC_MAX_VALUE) * (SERVO_MAX_PULSE_WIDTH - SERVO_MIN_PULSE_WIDTH));
    return pulse_width;
}

// Function to set servo pulse width
int set_servo_pulse_width(int gpio, int pulse_width) {
    if (pulse_width < SERVO_MIN_PULSE_WIDTH || pulse_width > SERVO_MAX_PULSE_WIDTH) {
        fprintf(stderr, "Pulse width out of range: %d\n", pulse_width);
        return -1;
    }
    gpioServo(gpio, pulse_width);
    return 0;
}

// Signal handler for graceful shutdown
void handle_signal(int signal) {
    printf("Caught signal %d, stopping servos and cleaning up...\n", signal);
    program_running = 0;
    gpioServo(HORIZONTAL_SERVO_PIN, 0); // Stop horizontal servo
    gpioServo(VERTICAL_SERVO_PIN, 0);   // Stop vertical servo
    gpioTerminate();                   // Terminate pigpio
    close(spi_fd);
    exit(0);
}

// Function to set up SPI communication
int spi_setup() {
    spi_fd = open(SPI_DEVICE, O_RDWR);
    if (spi_fd < 0) {
        perror("Failed to open SPI device");
        return -1;
    }

    unsigned char mode = SPI_MODE;
    if (ioctl(spi_fd, SPI_IOC_WR_MODE, &mode) < 0) {
        perror("Failed to set SPI mode");
        close(spi_fd);
        return -1;
    }

    unsigned char bits = SPI_BITS_PER_WORD;
    if (ioctl(spi_fd, SPI_IOC_WR_BITS_PER_WORD, &bits) < 0) {
        perror("Failed to set SPI bits per word");
        close(spi_fd);
        return -1;
    }

    unsigned int speed = SPI_SPEED;
    if (ioctl(spi_fd, SPI_IOC_WR_MAX_SPEED_HZ, &speed) < 0) {
        perror("Failed to set SPI speed");
        close(spi_fd);
        return -1;
    }

    return 0;
}

int main() {
    // Initialize pigpio
    if (pigpio_init_safe() != 0) {
        return 1;
    }

    // Initialize SPI
    if (spi_setup() != 0) {
        gpioTerminate();
        return 1;
    }

    // Set signal handlers for graceful shutdown
    signal(SIGINT, handle_signal);
    signal(SIGTERM, handle_signal);

    // Main loop
    while (program_running) {
        // Read light sensor values from MCP3008
        int horizontal_adc_value = mcp3008_read_channel(0);
        int vertical_adc_value = mcp3008_read_channel(1);

        if (horizontal_adc_value < 0 || vertical_adc_value < 0) {
            fprintf(stderr, "Error reading ADC values\n");
            continue; // Skip to the next iteration
        }

        // Calculate servo angles
        int horizontal_pulse_width = calculate_servo_angle(horizontal_adc_value);
        int vertical_pulse_width = calculate_servo_angle(vertical_adc_value);

        // Set servo positions
        if (set_servo_pulse_width(HORIZONTAL_SERVO_PIN, horizontal_pulse_width) != 0) {
            fprintf(stderr, "Error setting horizontal servo pulse width\n");
        }
        if (set_servo_pulse_width(VERTICAL_SERVO_PIN, vertical_pulse_width) != 0) {
            fprintf(stderr, "Error setting vertical servo pulse width\n");
        }

        // Small delay
        gpioDelay(20); // 20ms
    }

    return 0;
}

