#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <pigpio.h>

// Define constants
#define RELAY_GPIO 17
#define MPR121_I2C_ADDR 0x5A
#define TOUCH_STATUS_REG 0x00

// Function to initialize the MPR121
int initMPR121(int i2c_handle) {
    // Soft reset
    if (i2cWriteByteData(i2c_handle, 0x80, 0x63) < 0) {
        fprintf(stderr, "Error: MPR121 soft reset failed\n");
        return -1;
    }
    gpioDelay(100000); // 100ms delay

    // Configuration (example - adjust as needed)
    if (i2cWriteByteData(i2c_handle, 0x5E, 0x0C) < 0) { // Electrode Filter Control
        fprintf(stderr, "Error: Failed to write to Electrode Filter Control register\n");
        return -1;
    }

    if (i2cWriteByteData(i2c_handle, 0x5D, 0x24) < 0) { // Debounce Configuration
        fprintf(stderr, "Error: Failed to write to Debounce Configuration register\n");
        return -1;
    }

    // Enable all electrodes
    if (i2cWriteByteData(i2c_handle, 0x5B, 0x01) < 0) { // Enable electrodes
        fprintf(stderr, "Error: Failed to write to Electrode Configuration register\n");
        return -1;
    }

    if (i2cWriteByteData(i2c_handle, 0x5C, 0x01) < 0) { // Enable electrodes
        fprintf(stderr, "Error: Failed to write to Electrode Configuration register\n");
        return -1;
    }

    if (i2cWriteByteData(i2c_handle, 0x2B, 0x0A) < 0) {
        fprintf(stderr, "Error: Failed to write to USL register\n");
        return -1;
    }

    if (i2cWriteByteData(i2c_handle, 0x2C, 0x05) < 0) {
        fprintf(stderr, "Error: Failed to write to LSL register\n");
        return -1;
    }

    if (i2cWriteByteData(i2c_handle, 0x2D, 0x0F) < 0) {
        fprintf(stderr, "Error: Failed to write to Target register\n");
        return -1;
    }

    // Enable MPR121
    if (i2cWriteByteData(i2c_handle, 0x5E, 0x8C) < 0) { // Enable electrodes
        fprintf(stderr, "Error: Failed to write to Electrode Configuration register\n");
        return -1;
    }

    return 0;
}

// Function to read the touch status from MPR121
int readTouchStatus(int i2c_handle) {
    int status = i2cReadByteData(i2c_handle, TOUCH_STATUS_REG);
    if (status < 0) {
        fprintf(stderr, "Error: Failed to read touch status: %d\n", status);
        return -1;
    }
    return status;
}

// Function to toggle the relay state
void toggleRelay(int current_state) {
    int new_state = (current_state == 0) ? 1 : 0;
    gpioWrite(RELAY_GPIO, new_state);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Set relay GPIO as output
    gpioSetMode(RELAY_GPIO, PI_OUTPUT);
    gpioWrite(RELAY_GPIO, 0); // Initialize relay to OFF state

    // Open I2C bus
    int i2c_handle = i2cOpen(1, MPR121_I2C_ADDR, 0); // Bus 1, address 0x5A, no flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Error: Could not open I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Initialize MPR121
    if (initMPR121(i2c_handle) != 0) {
        fprintf(stderr, "Error: MPR121 initialization failed\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    int relay_state = 0; // 0 = OFF, 1 = ON
    int last_touch_status = 0; // Store the last touch status to detect changes

    printf("Touch sensor relay control started. Press Ctrl+C to exit.\n");

    while (1) {
        // Read touch status
        int touch_status = readTouchStatus(i2c_handle);
        if (touch_status < 0) {
            fprintf(stderr, "Error reading touch status. Exiting.\n");
            break;
        }

        // Check if any electrode is touched and if the touch status has changed
        if ((touch_status != 0) && (touch_status != last_touch_status)) {
            toggleRelay(relay_state);
            relay_state = (relay_state == 0) ? 1 : 0; // Update relay state
            printf("Relay toggled to state: %d\n", relay_state);
        }

        last_touch_status = touch_status; // Update last touch status
        gpioDelay(100000); // 100ms delay
    }

    // Cleanup
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

