// Microsecond delay function (using clock_gettime for higher precision)
void delay_microseconds(int delay_us)
{
    long int start_time, time_difference;
    struct timespec gettime_now;

    clock_gettime(CLOCK_REALTIME, &gettime_now);
    start_time = gettime_now.tv_nsec;

    while (1)
    {
        clock_gettime(CLOCK_REALTIME, &gettime_now);
        time_difference = gettime_now.tv_nsec - start_time;
        if (time_difference < 0) {
            time_difference += 1000000000; // Roll over every 1 second
        }
        if (time_difference > (delay_us * 1000)) {
            break;
        }
    }
}

// Reset the DS18B20 (return 0 if device is present, -1 otherwise)
int ds18b20_reset()
{
    GPIO_INP(ds_pin);
    delay_microseconds(10);

    GPIO_OUT(ds_pin);
    GPIO_CLR = 1 << ds_pin; // Drive low
    delay_microseconds(480);

    GPIO_INP(ds_pin);
    delay_microseconds(60);

    int presence_detect = GPIO_READ(ds_pin) == 0;
    delay_microseconds(420);

    return presence_detect ? 0 : -1;
}

// Write a byte to the DS18B20
void ds18b20_write_byte(unsigned char value)
{
    for (int i = 0; i < 8; ++i)
    {
        GPIO_OUT(ds_pin);
        GPIO_CLR = 1 << ds_pin; // Drive low

        if ((value & (1 << i)) != 0)
        {
            delay_microseconds(1);
            GPIO_INP(ds_pin); // Release the line
            delay_microseconds(60);
        }
        else
        {
            delay_microseconds(60);
            GPIO_INP(ds_pin); // Release the line
            delay_microseconds(1);
        }

        delay_microseconds(60);
    }
}

// Read a byte from the DS18B20
unsigned char ds18b20_read_byte()
{
    unsigned char data = 0;

    for (int i = 0; i < 8; ++i)
    {
        GPIO_OUT(ds_pin);
        GPIO_CLR = 1 << ds_pin; // Drive low
        delay_microseconds(1);

        GPIO_INP(ds_pin); // Release the line
        delay_microseconds(2);

        if (GPIO_READ(ds_pin) != 0)
        {
            data |= (1 << i);
        }

        delay_microseconds(60);
    }

    return data;
}

// Read the scratchpad from the DS18B20
int ds18b20_read_scratchpad()
{
    ds18b20_write_byte(DS18B20_READ_SCRATCHPAD);
    for (int i = 0; i < 9; ++i)
    {
        scratchpad[i] = ds18b20_read_byte();
    }
    return 0; // No error handling here, should be added
}

// Calculate the CRC of the data
unsigned char ds18b20_calculate_crc(unsigned char *data, unsigned char byte_size)
{
    unsigned char shift_register = 0;
    unsigned char loop, loop2;
    char data_byte;

    for (loop = 0; loop < byte_size; loop++)
    {
        data_byte = *(data + loop);
        for (loop2 = 0; loop2 < 8; loop2++)
        {
            if ((shift_register ^ data_byte) & 1)
            {
                shift_register = shift_register >> 1;
                shift_register ^= 0x8C;
            }
            else
            {
                shift_register = shift_register >> 1;
            }
            data_byte = data_byte >> 1;
        }
    }
    return shift_register;
}

// Select a specific sensor
void ds18b20_select_sensor(unsigned long long id)
{
    ds18b20_write_byte(DS18B20_MATCH_ROM);
    for (int i = 0; i < 64; ++i)
    {
        ds18b20_write_byte((id >> i) & 0x01);
    }
}

// Read temperature from a specific sensor
int ds18b20_read_sensor(unsigned long long id)
{
    for (int retry_count = 0; retry_count < 10; ++retry_count)
    {
        if (ds18b20_reset() != 0) continue;

        // Start a conversion
        ds18b20_select_sensor(id);
        if (ds18b20_read_scratchpad() != 0) continue;

        // OK Check sum Check;
        unsigned char crc_byte = ds18b20_calculate_crc(scratchpad, 8);
        if (crc_byte != scratchpad[8]) continue;

        // Check Resolution
        resolution = 0;
        switch (scratchpad[4])
        {
        case 0x1f: resolution = 9; break;
        case 0x3f: resolution = 10; break;
        case 0x5f: resolution = 11; break;
        case 0x7f: resolution = 12; break;
        }

        if (resolution == 0) continue;

        // Read Temperature
        short temp_raw = (scratchpad[1] << 8) | scratchpad[0];
        temperature = 0.0625 * (double)temp_raw;

        printf("%016llX : %02d bits Temperature: %6.2f +/- %4.2f Celsius\n",
               id, resolution, temperature, 0.0625 * (double)(1 << (12 - resolution)));
        return 0; // Success
    }
    return -1; // Failure
}

// Start temperature conversion on all sensors
int ds18b20_global_start_conversion()
{
    for (int retry = 0; retry < 10; ++retry)
    {
        if (ds18b20_reset() != 0)
        {
            delay_microseconds(10000);
        }
        else
        {
            ds18b20_write_byte(DS18B20_SKIP_ROM);
            ds18b20_write_byte(DS18B20_CONVERT_T);
            delay_microseconds(arg_wait_time * 1000); // Wait for conversion
            return 0; // Success
        }
    }
    return -1; // Failure
}

