#define H_T_OUT_H 0x29

// Function prototypes
int init_i2c(const char *device_path, int device_address);
int read_hts221_byte(int file_descriptor, uint8_t register_address);
int write_hts221_byte(int file_descriptor, uint8_t register_address, uint8_t data);
void trigger_measurement(int file_descriptor);
double calculate_temperature(int file_descriptor);
double calculate_humidity(int file_descriptor);

// Error handling macro
#define CHECK_ERROR(condition, message) \
    if (condition) {                     \
        fprintf(stderr, "Error: %s\n", message); \
        return EXIT_FAILURE;             \
    }

int main() {
    int i2c_file_descriptor;
    double temperature_celsius, humidity_percent;

    // Initialize I2C communication
    i2c_file_descriptor = init_i2c(I2C_DEVICE_PATH, HTS221_ADDRESS);
    if (i2c_file_descriptor == -1) {
        fprintf(stderr, "Failed to initialize I2C communication.\n");
        return EXIT_FAILURE;
    }

    // Verify the sensor
    if (read_hts221_byte(i2c_file_descriptor, WHO_AM_I_REG) != 0xBC) {
        fprintf(stderr, "HTS221 sensor not detected.\n");
        close(i2c_file_descriptor);
        return EXIT_FAILURE;
    }

    // Trigger a measurement
    trigger_measurement(i2c_file_descriptor);

    // Read temperature and humidity
    temperature_celsius = calculate_temperature(i2c_file_descriptor);
    humidity_percent = calculate_humidity(i2c_file_descriptor);

    // Print the results
    printf("Temperature: %.2f °C\n", temperature_celsius);
    printf("Humidity: %.2f %%\n", humidity_percent);

    // Close the I2C device
    close(i2c_file_descriptor);

    return EXIT_SUCCESS;
}

/**
 * @brief Initializes I2C communication with the specified device.
 *
 * @param device_path The path to the I2C device (e.g., "/dev/i2c-1").
 * @param device_address The I2C address of the device.
 * @return The file descriptor of the I2C device, or -1 on error.
 */
int init_i2c(const char *device_path, int device_address) {
    int file_descriptor = open(device_path, O_RDWR);
    if (file_descriptor < 0) {
        fprintf(stderr, "Failed to open I2C device %s: %s\n", device_path, strerror(errno));
        return -1;
    }

    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Failed to set I2C slave address 0x%X: %s\n", device_address, strerror(errno));
        close(file_descriptor);
        return -1;
    }

    return file_descriptor;
}

/**
 * @brief Reads a byte from the specified register of the HTS221 sensor.
 *
 * @param file_descriptor The file descriptor of the I2C device.
 * @param register_address The address of the register to read from.
 * @return The byte read from the register, or -1 on error.
 */
int read_hts221_byte(int file_descriptor, uint8_t register_address) {
    int result = i2c_smbus_read_byte_data(file_descriptor, register_address);
    if (result < 0) {
        fprintf(stderr, "Failed to read byte from register 0x%X: %s\n", register_address, strerror(errno));
        return -1;
    }
    return result;
}

/**
 * @brief Writes a byte to the specified register of the HTS221 sensor.
 *
 * @param file_descriptor The file descriptor of the I2C device.
 * @param register_address The address of the register to write to.
 * @param data The byte to write to the register.
 * @return 0 on success, or -1 on error.
 */
int write_hts221_byte(int file_descriptor, uint8_t register_address, uint8_t data) {
    int result = i2c_smbus_write_byte_data(file_descriptor, register_address, data);
    if (result < 0) {
        fprintf(stderr, "Failed to write byte 0x%X to register 0x%X: %s\n", data, register_address, strerror(errno));
        return -1;
    }
    return 0;
}

/**
 * @brief Triggers a single measurement of temperature and humidity.
 *
 * @param file_descriptor The file descriptor of the I2C device.
 */
void trigger_measurement(int file_descriptor) {
    // Power down the device (clean start)
    if (write_hts221_byte(file_descriptor, CTRL_REG1, 0x00) == -1) {
        fprintf(stderr, "Failed to power down device.\n");
        exit(EXIT_FAILURE);
    }

    // Turn on the humidity sensor analog front end in single shot mode
    if (write_hts221_byte(file_descriptor, CTRL_REG1, 0x84) == -1) {
        fprintf(stderr, "Failed to configure CTRL_REG1.\n");
        exit(EXIT_FAILURE);
    }

    // Run one-shot measurement (temperature and humidity)
    if (write_hts221_byte(file_descriptor, CTRL_REG2, 0x01) == -1) {
        fprintf(stderr, "Failed to trigger one-shot measurement.\n");
        exit(EXIT_FAILURE);
    }

    // Wait until the measurement is completed (max 25ms)
    uint8_t status;
    do {
        usleep(25000); // 25 milliseconds
        status = read_hts221_byte(file_descriptor, CTRL_REG2);
        if (status == -1) {
            fprintf(stderr, "Failed to read CTRL_REG2 status.\n");
            exit(EXIT_FAILURE);
        }
    } while (status != 0);
}

/**
 * @brief Calculates the temperature in degrees Celsius from the sensor data.
 *
 * @param file_descriptor The file descriptor of the I2C device.
 * @return The temperature in degrees Celsius.
 */
double calculate_temperature(int file_descriptor) {
    // Read calibration data
    int16_t T0_OUT = (read_hts221_byte(file_descriptor, T0_OUT_H) << 8) | read_hts221_byte(file_descriptor, T0_OUT_L);
    int16_t T1_OUT = (read_hts221_byte(file_descriptor, T1_OUT_H) << 8) | read_hts221_byte(file_descriptor, T1_OUT_L);
    uint16_t T0_DegC_x8 = ((read_hts221_byte(file_descriptor, T1_T0_MSB) & 3) << 8) | read_hts221_byte(file_descriptor, T0_degC_x8);
    uint16_t T1_DegC_x8 = (((read_hts221_byte(file_descriptor, T1_T0_MSB) & 12) >> 2) << 8) | read_hts221_byte(file_descriptor, T1_degC_x8);

    // Calculate calibration values
    double T0_DegC = T0_DegC_x8 / 8.0;
    double T1_DegC = T1_DegC_x8 / 8.0;

    // Solve the linear equation 'y = mx + c' to give the calibration straight line graph for temperature
    double t_gradient_m = (T1_DegC - T0_DegC) / (T1_OUT - T0_OUT);
    double t_intercept_c = T1_DegC - (t_gradient_m * T1_OUT);

    // Read the ambient temperature measurement
    int16_t T_OUT = (read_hts221_byte(file_descriptor, TEMP_OUT_H) << 8) | read_hts221_byte(file_descriptor, TEMP_OUT_L);

    // Calculate ambient temperature
    return (t_gradient_m * T_OUT) + t_intercept_c;
}

/**
 * @brief Calculates the relative humidity in percent from the sensor data.
 *
 * @param file_descriptor The file descriptor of the I2C device.
 * @return The relative humidity in percent.
 */
double calculate_humidity(int file_descriptor) {
    // Read calibration data
    int16_t H0_T0_OUT = (read_hts221_byte(file_descriptor, H0_T0_OUT_H) << 8) | read_hts221_byte(file_descriptor, H0_T0_OUT_L);
    int16_t H1_T0_OUT = (read_hts221_byte(file_descriptor, H1_T0_OUT_H) << 8) | read_hts221_byte(file_descriptor, H1_T0_OUT_L);
    double H0_rH = read_hts221_byte(file_descriptor, H0_rH_x2) / 2.0;
    double H1_rH = read_hts221_byte(file_descriptor, H1_rH_x2) / 2.0;

    // Solve the linear equation 'y = mx + c' to give the calibration straight line graph for humidity
    double h_gradient_m = (H1_rH - H0_rH) / (H1_T0_OUT - H0_T0_OUT);
    double h_intercept_c = H1_rH - (h_gradient_m * H1_T0_OUT);

    // Read the ambient humidity measurement
    int16_t H_T_OUT = (read_hts221_byte(file_descriptor, H_T_OUT_H) << 8) | read_hts221_byte(file_descriptor, H_T_OUT_L);

    // Calculate ambient humidity
    double humidity = (h_gradient_m * H_T_OUT) + h_intercept_c;

    // Clamp the humidity value to be within the valid range of 0-100%
    if (humidity < 0.0) {
        humidity = 0.0;
    } else if (humidity > 100.0) {
        humidity = 100.0;
    }

    return humidity;
}

