// Define GPIO pins for servo motors
#define PAN_SERVO_PIN 17
#define TILT_SERVO_PIN 18

// Define the file to save servo positions
#define SERVO_POSITIONS_FILE "servo_positions.txt"

// Global variables to store servo angles
int pan_angle = 90;
int tilt_angle = 90;

// Function prototypes
void signal_handler(int signal);
int kbhit(void);
void save_servo_positions(void);
void load_servo_positions(void);

// Terminal settings for non-blocking input
struct termios orig_termios;

void reset_terminal_mode()
{
    tcsetattr(0, TCSANOW, &orig_termios);
}

void set_conio_terminal_mode()
{
    struct termios new_termios;

    /* take two copies - one for now, one for restoring at exit */
    tcgetattr(0, &orig_termios);
    memcpy(&new_termios, &orig_termios, sizeof(new_termios));

    /* register cleanup handler, and catch signals */
    atexit(reset_terminal_mode);
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    /* disable buffered i/o, and local echo */
    new_termios.c_lflag &= ~(ICANON | ECHO);
    new_termios.c_cc[VMIN] = 1;
    new_termios.c_cc[VTIME] = 0;

    /* set the new terminal mode */
    tcsetattr(0, TCSANOW, &new_termios);
}

// Signal handler for clean shutdown
void signal_handler(int signal) {
    fprintf(stderr, "\nCaught signal %d, cleaning up...\n", signal);
    save_servo_positions();
    gpioTerminate();
    reset_terminal_mode();
    exit(0);
}

// Non-blocking keyboard hit function using select()
int kbhit(void) {
    struct timeval tv = {0L, 0L};
    fd_set fds;
    FD_ZERO(&fds);
    FD_SET(0, &fds);
    return select(1, &fds, NULL, NULL, &tv);
}

// Function to save servo positions to file
void save_servo_positions(void) {
    FILE *fp = fopen(SERVO_POSITIONS_FILE, "w");
    if (fp == NULL) {
        fprintf(stderr, "Error opening file %s for writing: %s\n", SERVO_POSITIONS_FILE, strerror(errno));
        return;
    }
    fprintf(fp, "%d,%d\n", pan_angle, tilt_angle);
    fclose(fp);
    printf("Servo positions saved to %s\n", SERVO_POSITIONS_FILE);
}

// Function to load servo positions from file
void load_servo_positions(void) {
    FILE *fp = fopen(SERVO_POSITIONS_FILE, "r");
    if (fp == NULL) {
        fprintf(stderr, "Warning: Could not open file %s for reading. Using default positions.\n", SERVO_POSITIONS_FILE);
        return;
    }
    if (fscanf(fp, "%d,%d", &pan_angle, &tilt_angle) != 2) {
        fprintf(stderr, "Warning: Could not read servo positions from %s. Using default positions.\n", SERVO_POSITIONS_FILE);
        pan_angle = 90;
        tilt_angle = 90;
    }
    fclose(fp);
    printf("Servo positions loaded from %s: Pan=%d, Tilt=%d\n", SERVO_POSITIONS_FILE, pan_angle, tilt_angle);
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pins as outputs
    gpioSetMode(PAN_SERVO_PIN, PI_OUTPUT);
    gpioSetMode(TILT_SERVO_PIN, PI_OUTPUT);

    // Load servo positions from file
    load_servo_positions();

    // Set initial servo positions
    gpioServo(PAN_SERVO_PIN, pan_angle * 1000 / 180 + 1000); // Convert angle to pulse width (1000-2000 us)
    gpioServo(TILT_SERVO_PIN, tilt_angle * 1000 / 180 + 1000);

    set_conio_terminal_mode();

    printf("Pan-Tilt Camera Control\n");
    printf("Use 'l', 'r', 'u', 'd' to move the camera. Press Ctrl+C to exit.\n");

    // Main loop
    while (1) {
        if (kbhit()) {
            char input = getchar();

            switch (input) {
                case 'l': // Move left
                    pan_angle -= 2;
                    if (pan_angle < 0) pan_angle = 0;
                    break;
                case 'r': // Move right
                    pan_angle += 2;
                    if (pan_angle > 180) pan_angle = 180;
                    break;
                case 'u': // Move up
                    tilt_angle -= 2;
                    if (tilt_angle < 0) tilt_angle = 0;
                    break;
                case 'd': // Move down
                    tilt_angle += 2;
                    if (tilt_angle > 180) tilt_angle = 180;
                    break;
                default:
                    fprintf(stderr, "Invalid input: %c\n", input);
                    continue; // Skip the rest of the loop
            }

            // Set new servo positions
            gpioServo(PAN_SERVO_PIN, pan_angle * 1000 / 180 + 1000); // Convert angle to pulse width (1000-2000 us)
            gpioServo(TILT_SERVO_PIN, tilt_angle * 1000 / 180 + 1000);

            // Small delay for smooth movement
            usleep(20000); // 20 ms
        }
        usleep(1000); // Check for input every 1 ms
    }

    return 0;
}

