    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>

#define SSD1306_I2C_ADDR  0x3C
#define SSD1306_WIDTH     128
#define SSD1306_HEIGHT    64

int i2c_fd;

void ssd1306_sendCommand(unsigned char command) {
    wiringPiI2CWriteReg8(i2c_fd, 0x00, command);
}

void ssd1306_init() {
    ssd1306_sendCommand(0xAE);
    ssd1306_sendCommand(0xD5);
    ssd1306_sendCommand(0x80);
    ssd1306_sendCommand(0xA8);
    ssd1306_sendCommand(SSD1306_HEIGHT - 1);
    ssd1306_sendCommand(0xD3);
    ssd1306_sendCommand(0x00);
    ssd1306_sendCommand(0x40);
    ssd1306_sendCommand(0x8D);
    ssd1306_sendCommand(0x14);
    ssd1306_sendCommand(0xA1);
    ssd1306_sendCommand(0xC8);
    ssd1306_sendCommand(0xDA);
    ssd1306_sendCommand(0x12);
    ssd1306_sendCommand(0x81);
    ssd1306_sendCommand(0x7F);
    ssd1306_sendCommand(0xD9);
    ssd1306_sendCommand(0xF1);
    ssd1306_sendCommand(0xDB);
    ssd1306_sendCommand(0x40);
    ssd1306_sendCommand(0xA4);
    ssd1306_sendCommand(0xA6);
    ssd1306_sendCommand(0xAF);
}

void ssd1306_clearDisplay() {
    for (int page = 0; page < 8; page++) {
        ssd1306_sendCommand(0xB0 + page);
        ssd1306_sendCommand(0x00);
        ssd1306_sendCommand(0x10);
        for (int col = 0; col < SSD1306_WIDTH; col++) {
            wiringPiI2CWriteReg8(i2c_fd, 0x40, 0x00);
        }
    }
}

int main(void) {
    if (wiringPiSetup() == -1) {
        printf("WiringPi Initialization Failed!\n");
        return -1;
    }

    i2c_fd = wiringPiI2CSetup(SSD1306_I2C_ADDR);
    if (i2c_fd < 0) {
        printf("Failed to connect to I2C device.\n");
        return -1;
    }

    ssd1306_init();
    ssd1306_clearDisplay();
    sleep(5);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pigpio.h>
#include <unistd.h>

// Define GPIO pins
#define PIR_GPIO 17
#define BUZZER_GPIO 18

// Global variable to track program termination
volatile sig_atomic_t terminate = 0;

// Function prototypes
int gpio_init(int pir_gpio, int buzzer_gpio);
int register_interrupt(int pir_gpio, void (*callback)(int, int, uint32_t));
void buzzer_on(int buzzer_gpio, int duration_ms);
void pir_callback(int gpio, int level, uint32_t tick);
void cleanup(int pir_gpio, int buzzer_gpio);
void signal_handler(int signum);

// GPIO Initialization
int gpio_init(int pir_gpio, int buzzer_gpio) {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Indicate failure
    }

    gpioSetMode(pir_gpio, PI_INPUT);
    gpioSetPullUpDown(pir_gpio, PI_PUD_DOWN); // Use pull-down resistor
    gpioSetMode(buzzer_gpio, PI_OUTPUT);
    gpioWrite(buzzer_gpio, 0); // Ensure buzzer is off initially

    return 0; // Indicate success
}

// Interrupt Registration
int register_interrupt(int pir_gpio, void (*callback)(int, int, uint32_t)) {
    if (gpioSetAlertFuncEx(pir_gpio, callback, NULL) != 0) {
        fprintf(stderr, "Failed to register interrupt for GPIO %d\n", pir_gpio);
        return 1; // Indicate failure
    }
    return 0; // Indicate success
}

// Buzzer Control
void buzzer_on(int buzzer_gpio, int duration_ms) {
    gpioWrite(buzzer_gpio, 1); // Turn buzzer on
    gpioDelay(duration_ms * 1000); // Delay for specified duration (microseconds)
    gpioWrite(buzzer_gpio, 0); // Turn buzzer off
}

// Callback Function for PIR sensor
void pir_callback(int gpio, int level, uint32_t tick) {
    if (gpio == PIR_GPIO && level == 1) {
        printf("Motion detected!\n");
        buzzer_on(BUZZER_GPIO, 500); // Activate buzzer for 500ms
    }
}

// Cleanup function
void cleanup(int pir_gpio, int buzzer_gpio) {
    printf("Cleaning up and exiting...\n");
    gpioWrite(buzzer_gpio, 0); // Ensure buzzer is off
    gpioTerminate(); // Terminate pigpio
    exit(0);
}

// Signal handler function
void signal_handler(int signum) {
    if (signum == SIGINT || signum == SIGTERM) {
        printf("Received signal %d, terminating...\n", signum);
        terminate = 1;
        cleanup(PIR_GPIO, BUZZER_GPIO);
    }
}

int main() {
    // Register signal handlers for Ctrl+C and termination signals
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize GPIO pins
    if (gpio_init(PIR_GPIO, BUZZER_GPIO) != 0) {
        fprintf(stderr, "GPIO initialization failed. Exiting.\n");
        return 1;
    }

    // Register interrupt handler for PIR sensor
    if (register_interrupt(PIR_GPIO, pir_callback) != 0) {
        fprintf(stderr, "Interrupt registration failed. Exiting.\n");
        cleanup(PIR_GPIO, BUZZER_GPIO);
        return 1;
    }

    printf("PIR sensor monitoring started. Press Ctrl+C to exit.\n");

    // Keep the program running until a signal is received
    while (!terminate) {
        sleep(1); // Sleep for 1 second to reduce CPU usage
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <time.h>
#include <string.h>
#include <errno.h>
#include <unistd.h>
#include <pigpio.h>

// Define GPIO pins
#define SOUND_SENSOR_PIN 17
#define BUZZER_PIN 18

// Define sound threshold (adjust based on sensor sensitivity)
#define SOUND_THRESHOLD 0 // Digital sensor, so threshold is either 0 or 1. 0 means sound detected.

// Define alarm duration (in seconds)
#define ALARM_DURATION 2

// Define log file path
#define LOG_FILE "alarm_log.txt"

// Global flag to indicate program termination
volatile sig_atomic_t program_running = 1;

// Function prototypes
int initialize_gpio();
int read_sound_sensor();
void activate_alarm();
int log_alarm_event();
void cleanup_gpio();
void signal_handler(int signal);

int main() {
    // Install signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize pigpio library and GPIO pins
    if (initialize_gpio() != 0) {
        fprintf(stderr, "Error: GPIO initialization failed. Exiting.\n");
        return 1;
    }

    printf("Sound sensor monitoring started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        // Read sound sensor value
        int sensor_value = read_sound_sensor();

        // Check if sound level exceeds threshold
        if (sensor_value == SOUND_THRESHOLD) {
            printf("Sound detected! Activating alarm.\n");

            // Activate alarm
            activate_alarm();

            // Log alarm event
            if (log_alarm_event() != 0) {
                fprintf(stderr, "Error: Failed to log alarm event.\n");
            }
        }

        // Delay for a short period (non-blocking)
        gpioDelay(100); // 100 ms
    }

    printf("Sound sensor monitoring stopped.\n");

    // Cleanup GPIO and terminate pigpio library
    cleanup_gpio();

    return 0;
}

// Initializes the pigpio library and configures GPIO pins
int initialize_gpio() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed: %s\n", strerror(errno));
        return -1;
    }

    // Configure sound sensor pin as input
    gpioSetMode(SOUND_SENSOR_PIN, PI_INPUT);

    // Configure buzzer pin as output
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);

    // Ensure buzzer is initially off
    if (gpioWrite(BUZZER_PIN, 1) != 0) {
         fprintf(stderr, "Error: Failed to set buzzer pin to LOW: %s\n", strerror(errno));
         cleanup_gpio();
         return -1;
    }

    return 0;
}

// Reads the digital value from the sound sensor
int read_sound_sensor() {
    int value = gpioRead(SOUND_SENSOR_PIN);
    if (value < 0) {
        fprintf(stderr, "Error reading sensor value: %s. Retrying...\n", strerror(errno));
        gpioDelay(10); // Small delay before retry
        return read_sound_sensor(); // Recursive retry
    }
    return value;
}

// Activates the buzzer for a specified duration
void activate_alarm() {
    if (gpioWrite(BUZZER_PIN, 0) != 0) {
        fprintf(stderr, "Error: Failed to set buzzer pin to HIGH: %s\n", strerror(errno));
        return; // Consider a more robust error handling mechanism
    }
    gpioDelay(ALARM_DURATION * 1000); // Delay for alarm duration (in milliseconds)
    if (gpioWrite(BUZZER_PIN, 1) != 0) {
        fprintf(stderr, "Error: Failed to set buzzer pin to LOW: %s\n", strerror(errno));
    }
}

