#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <time.h>
#include <signal.h>
#include <wiringPi.h>
#include <errno.h>

// MCP3008 defines
#define SPI_CHANNEL 0
#define SPI_SPEED 1000000 // 1MHz
#define ADC_CHANNEL 0 // MCP3008 Channel 0

// GPIO defines
#define LED_PIN 0 // WiringPi pin 0, physical pin 11, GPIO17

// Alcohol level threshold (adjust based on sensor calibration)
#define ALCOHOL_THRESHOLD 500

// Circular buffer size
#define BUFFER_SIZE 100

// Error value for ADC reading
#define ADC_ERROR_VALUE -1

// Global variables (try to minimize)
static volatile int keepRunning = 1;

// Circular buffer structure
typedef struct {
    int buffer[BUFFER_SIZE];
    int head;
    int count;
} CircularBuffer;

// Function prototypes
int spiSetup();
int readMcp3008(int channel);
float processSensorData(int adcValue);
void controlLed(int state);
void initializeBuffer(CircularBuffer *cb);
void addToBuffer(CircularBuffer *cb, int value);
float calculateAverage(CircularBuffer *cb);
void signalHandler(int signal);

// SPI setup function
int spiSetup() {
    if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) < 0) {
        fprintf(stderr, "SPI setup failed: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

// Function to read from MCP3008 ADC
int readMcp3008(int channel) {
    unsigned char buffer[3];
    int adcValue = ADC_ERROR_VALUE;
    int retries = 3;

    buffer[0] = 0x01; // Start bit
    buffer[1] = ((channel & 0x07) << 4) | 0x80; // Single-ended mode, channel select
    buffer[2] = 0x00;

    while (retries > 0) {
        if (wiringPiSPIDataRW(SPI_CHANNEL, buffer, 3) == -1) {
            fprintf(stderr, "SPI data read failed: %s\n", strerror(errno));
            retries--;
            delay(10); // Wait before retrying
        } else {
            adcValue = ((buffer[1] & 0x03) << 8) + buffer[2];
            break; // Exit loop on success
        }
    }

    if (adcValue == ADC_ERROR_VALUE) {
        fprintf(stderr, "Failed to read ADC after multiple retries.\n");
    }

    return adcValue;
}

// Function to process sensor data (convert ADC value to PPM - parts per million)
float processSensorData(int adcValue) {
    // Assuming MCP3008 is powered by 3.3V
    // Voltage = (ADC Value / 1023) * 3.3V
    // PPM is directly proportional to the voltage.  A real application would require calibration.
    float voltage = ((float)adcValue / 1023.0) * 3.3;
    float ppm = voltage * 1000; // Example conversion for demonstration.
    return ppm;
}

// Function to control the LED
void controlLed(int state) {
    digitalWrite(LED_PIN, state);
}

// Function to initialize the circular buffer
void initializeBuffer(CircularBuffer *cb) {
    memset(cb->buffer, 0, sizeof(cb->buffer));
    cb->head = 0;
    cb->count = 0;
}

// Function to add a value to the circular buffer
void addToBuffer(CircularBuffer *cb, int value) {
    cb->buffer[cb->head] = value;
    cb->head = (cb->head + 1) % BUFFER_SIZE;
    if (cb->count < BUFFER_SIZE) {
        cb->count++;
    }
}

// Function to calculate the average of the circular buffer
float calculateAverage(CircularBuffer *cb) {
    if (cb->count == 0) {
        return 0.0;
    }
    int sum = 0;
    for (int i = 0; i < cb->count; i++) {
        sum += cb->buffer[i];
    }
    return (float)sum / cb->count;
}

// Signal handler for Ctrl+C
void signalHandler(int signal) {
    keepRunning = 0;
    printf("Exiting gracefully...\n");
    controlLed(LOW); // Turn off LED on exit
    exit(0);
}

int main() {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi setup failed: %s\n", strerror(errno));
        return 1;
    }

    // Initialize SPI
    if (spiSetup() == -1) {
        return 1;
    }

    // Set LED pin as output
    pinMode(LED_PIN, OUTPUT);

    // Initialize circular buffer
    CircularBuffer alcoholReadings;
    initializeBuffer(&alcoholReadings);

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signalHandler);

    time_t rawtime;
    struct tm * timeinfo;
    char timestamp[80];

    printf("Alcohol sensor monitoring started. Press Ctrl+C to exit.\n");

    while (keepRunning) {
        // Read ADC value
        int adcValue = readMcp3008(ADC_CHANNEL);

        if (adcValue != ADC_ERROR_VALUE) {
            // Process sensor data
            float alcoholLevel = processSensorData(adcValue);

            // Add reading to circular buffer
            addToBuffer(&alcoholReadings, adcValue);

            // Calculate average alcohol level
            float averageAlcoholLevel = calculateAverage(&alcoholReadings);

            // Check if alcohol level exceeds threshold
            if (averageAlcoholLevel > ALCOHOL_THRESHOLD) {
                // Activate LED for 1 second
                controlLed(HIGH);
                delay(1000);
                controlLed(LOW);
            }

             // Get current timestamp
            time(&rawtime);
            timeinfo = localtime(&rawtime);
            strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

            // Log timestamp and alcohol level
            printf("[%s] Alcohol Level (PPM): %.2f\n", timestamp, alcoholLevel);
        } else {
            fprintf(stderr, "Error reading alcohol sensor data.\n");
        }

        delay(1000); // Read every 1 second
    }

    return 0;
}

