#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>

#define LED_PIN 5
#define BUTTON_PIN 6
#define PWM_PIN 12

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(LED_PIN, PI_OUTPUT);
    gpioSetMode(BUTTON_PIN, PI_INPUT);
    gpioSetMode(PWM_PIN, PI_OUTPUT);
    gpioSetPullUpDown(BUTTON_PIN, PI_PUD_UP); // Enable pull-up resistor

    int button_state = 1; // Initialize to released state
    int led_state = 0;
    int pwm_value = 0;
    int fade_direction = 1; // 1 for increasing, -1 for decreasing

    while (1) {
        int current_button_state = gpioRead(BUTTON_PIN);

        if (current_button_state == 0) { // Button is pressed
            if (button_state == 1) { // Only toggle LED once per press
                led_state = !led_state;
                gpioWrite(LED_PIN, led_state);
                button_state = 0; // Update button state to pressed
            }

            // PWM fade in/out while button is held
            gpioPWM(PWM_PIN, pwm_value);
            pwm_value += fade_direction;

            if (pwm_value > 255) {
                pwm_value = 255;
                fade_direction = -1;
            } else if (pwm_value < 0) {
                pwm_value = 0;
                fade_direction = 1;
            }
        } else {
            button_state = 1; // Reset button state when released
        }

        gpioDelay(10); // Small delay for debounce and smooth fading
    }

    gpioTerminate();
    return 0;
}

#include <stdio.h>
