#define MOTION_SENSOR_PIN 17
#define LED_PIN 18

volatile sig_atomic_t program_running = 1;
volatile int led_state = 0; // 0: off, 1: on

void signal_handler(int sig);
int setupGPIO();
void motionDetected();
void controlLED(int state);

void signal_handler(int sig) {
    if (sig == SIGINT) {
        fprintf(stderr, "\nCaught SIGINT, exiting gracefully.\n");
        program_running = 0;
    }
}

int setupGPIO() {
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
        return -1;
    }

    pinMode(MOTION_SENSOR_PIN, INPUT);
    pinMode(LED_PIN, OUTPUT);

    // Initialize LED to off
    controlLED(0);

    return 0;
}

void controlLED(int state) {
    digitalWrite(LED_PIN, state);
    led_state = state;
}

void motionDetected() {
    // Debounce the interrupt by checking if the LED was toggled recently.
    controlLED(1 - led_state); // Toggle LED state
}

int main() {
    // Set up signal handler for Ctrl+C
    if (signal(SIGINT, signal_handler) == SIG_ERR) {
        perror("Error setting up signal handler");
        return 1;
    }

    // Initialize GPIO
    if (setupGPIO() == -1) {
        fprintf(stderr, "GPIO setup failed. Exiting.\n");
        return 1;
    }

    // Set up interrupt on motion sensor pin
    if (wiringPiISR(MOTION_SENSOR_PIN, INT_EDGE_RISING, motionDetected) < 0) {
        fprintf(stderr, "Unable to setup ISR: %s\n", strerror(errno));
        return 1;
    }

    fprintf(stderr, "Motion detection program started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        delay(100); // Short delay to avoid CPU hogging
    }

    // Cleanup before exiting
    wiringPiISR(MOTION_SENSOR_PIN, INT_EDGE_RISING, NULL); // Disable interrupt
    controlLED(0); // Turn off LED

    return 0;
}

