#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>

#define I2C_BUS 1
#define LM75B_ADDR 0x48
#define FAN_GPIO 18

typedef struct {
    int i2c_handle;
} TemperatureController;

TemperatureController controller;

// Function prototypes
double readTemperature();
void controlFan(double temperature);
void logFanActivation();
void cleanup(int signal);

// Global variables for temperature thresholds
const double FAN_ON_THRESHOLD = 45.0;
const double FAN_OFF_THRESHOLD = 40.0;

// Flag to indicate if the fan is currently active
int fan_active = 0;

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C connection
    controller.i2c_handle = i2cOpen(I2C_BUS, LM75B_ADDR, 0);
    if (controller.i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %d\n", controller.i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set GPIO18 as output for fan control
    gpioSetMode(FAN_GPIO, PI_OUTPUT);

    // Register signal handler for graceful termination
    signal(SIGINT, cleanup);

    // Main loop
    while (1) {
        double temperature = readTemperature();
        if (temperature > -273.0) { // Valid temperature reading
            printf("Temperature: %.2f °C\n", temperature);
            controlFan(temperature);
        } else {
            fprintf(stderr, "Failed to read temperature\n");
        }

        gpioDelay(1000000); // 1 second delay
    }

    return 0;
}

double readTemperature() {
    int raw_temp = i2cReadWordData(controller.i2c_handle, 0); // Read temperature register
    if (raw_temp < 0) {
        fprintf(stderr, "I2C read failed: %d\n", raw_temp);
        return -273.15; // Return absolute zero on failure
    }

    // LM75B returns temperature in format MSB: sign, 7 bits integer, 8 bits fraction
    // LSB: always 0
    // Divide by 256.0 to get temperature in Celsius
    raw_temp = ((raw_temp >> 8) & 0xFF) | ((raw_temp & 0xFF) << 8); // Byte swap
    short signed_temp = (short)raw_temp; // Cast to signed short to handle negative temperatures
    double temperature = (double)signed_temp / 256.0;

    return temperature;
}

void controlFan(double temperature) {
    if (temperature > FAN_ON_THRESHOLD && !fan_active) {
        gpioWrite(FAN_GPIO, 1); // Turn fan ON
        fan_active = 1;
        printf("Turning fan ON\n");
        logFanActivation();
    } else if (temperature < FAN_OFF_THRESHOLD && fan_active) {
        gpioWrite(FAN_GPIO, 0); // Turn fan OFF
        fan_active = 0;
        printf("Turning fan OFF\n");
    }
}

void logFanActivation() {
    FILE *fp = fopen("fan_log.txt", "a");
    if (fp == NULL) {
        fprintf(stderr, "Failed to open log file\n");
        return;
    }

    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char s[64];
    strftime(s, sizeof(s), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(fp, "%s: Fan activated\n", s);
    fclose(fp);
}

void cleanup(int signal) {
    printf("Cleaning up and exiting...\n");
    gpioWrite(FAN_GPIO, 0); // Turn fan OFF
    i2cClose(controller.i2c_handle);
    gpioTerminate();
    exit(0);
}

