#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>

// Define GPIO pins for the seven segments (a to g)
#define SEG_A 4
#define SEG_B 17
#define SEG_C 27
#define SEG_D 22
#define SEG_E 5
#define SEG_F 6
#define SEG_G 13

// Define the pin connected to decimal point
#define SEG_DP 19

// Function to display a digit on the seven-segment display
void displayDigit(int digit) {
    // Define the segment patterns for each digit (0-9)
    // Each bit represents a segment (a-g), 1 for on, 0 for off
    unsigned char segments[] = {
        0x3F, // 0: a,b,c,d,e,f
        0x06, // 1: b,c
        0x5B, // 2: a,b,d,e,g
        0x4F, // 3: a,b,c,d,g
        0x66, // 4: b,c,f,g
        0x6D, // 5: a,c,d,f,g
        0x7D, // 6: a,c,d,e,f,g
        0x07, // 7: a,b,c
        0x7F, // 8: a,b,c,d,e,f,g
        0x6F  // 9: a,b,c,d,f,g
    };

    unsigned char pattern = segments[digit];

    // Set the GPIO pins based on the segment pattern
    gpioWrite(SEG_A, (pattern >> 0) & 1);
    gpioWrite(SEG_B, (pattern >> 1) & 1);
    gpioWrite(SEG_C, (pattern >> 2) & 1);
    gpioWrite(SEG_D, (pattern >> 3) & 1);
    gpioWrite(SEG_E, (pattern >> 4) & 1);
    gpioWrite(SEG_F, (pattern >> 5) & 1);
    gpioWrite(SEG_G, (pattern >> 6) & 1);

    //Turn off decimal point
    gpioWrite(SEG_DP, 0);
}

int main() {
    if (gpioInitialise() < 0) {
        printf("pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pins as outputs
    gpioSetMode(SEG_A, PI_OUTPUT);
    gpioSetMode(SEG_B, PI_OUTPUT);
    gpioSetMode(SEG_C, PI_OUTPUT);
    gpioSetMode(SEG_D, PI_OUTPUT);
    gpioSetMode(SEG_E, PI_OUTPUT);
    gpioSetMode(SEG_F, PI_OUTPUT);
    gpioSetMode(SEG_G, PI_OUTPUT);
    gpioSetMode(SEG_DP, PI_OUTPUT);

    // Display numbers 0 to 9 with a delay
    for (int i = 0; i <= 9; i++) {
        displayDigit(i);
        printf("Displaying: %d\n", i);
        sleep(1); // Wait for 1 second
    }

    gpioTerminate();
    return 0;
}

