#define VL53L1X_REG_IDENTIFICATION_MODEL_ID  0x00c0
#define VL53L1X_REG_SYSTEM_START              0x0000
#define VL53L1X_REG_RESULT_RANGE_STATUS       0x0014
#define VL53L1X_REG_RESULT_FINAL_CROSSTALK_CORRECTED_RANGE_MM_SD0 0x0050

// Configuration parameters (example, adapt based on datasheet and desired mode)
#define VL53L1X_DEFAULT_SIGNAL_RATE_LIMIT 0x00
#define VL53L1X_DEFAULT_PRE_RANGE_CONFIG_VCSEL_PERIOD 0x0F
#define VL53L1X_DEFAULT_FINAL_RANGE_CONFIG_VCSEL_PERIOD 0x14


// Function to initialize the VL53L1X sensor
int vl53l1x_init(int fd) {
    // Check sensor ID (example)
    int sensor_id = wiringPiI2CReadReg8(fd, VL53L1X_REG_IDENTIFICATION_MODEL_ID);
    if (sensor_id < 0) {
        perror("I2C read error (sensor ID)");
        return -1;
    }
    if (sensor_id != 0xE1) { //Expected Sensor ID
        fprintf(stderr, "Error: Incorrect sensor ID: 0x%x\n", sensor_id);
        return -1;
    }

    // Example initialization sequence (adapt based on datasheet)
    if (wiringPiI2CWriteReg8(fd, 0x88, 0x00) < 0) {
        perror("I2C write error (init 1)");
        return -1;
    }

     if (wiringPiI2CWriteReg8(fd, 0x80, 0x01) < 0) {
        perror("I2C write error (init 2)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0xFF, 0x01) < 0) {
        perror("I2C write error (init 3)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0x00, 0x00) < 0) {
        perror("I2C write error (init 4)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0x91, 0x00) < 0) {
        perror("I2C write error (init 5)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0xFF, 0x00) < 0) {
        perror("I2C write error (init 6)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0x80, 0x00) < 0) {
        perror("I2C write error (init 7)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0x8F, 0x00) < 0) {
        perror("I2C write error (init 8)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0xFF, 0x01) < 0) {
        perror("I2C write error (init 9)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0x00, 0x01) < 0) {
        perror("I2C write error (init 10)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0xFF, 0x00) < 0) {
        perror("I2C write error (init 11)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0x80, 0x01) < 0) {
        perror("I2C write error (init 12)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0x94, 0x69) < 0) {
        perror("I2C write error (init 13)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0x83, 0x00) < 0) {
        perror("I2C write error (init 14)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0x88, 0x00) < 0) {
        perror("I2C write error (init 15)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0xFF, 0x01) < 0) {
        perror("I2C write error (init 16)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0x00, 0x01) < 0) {
        perror("I2C write error (init 17)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0xFF, 0x00) < 0) {
        perror("I2C write error (init 18)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0x80, 0x01) < 0) {
        perror("I2C write error (init 19)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0x41, 0x00) < 0) {
        perror("I2C write error (init 20)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0x00, 0x00) < 0) {
        perror("I2C write error (init 21)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0xFF, 0x00) < 0) {
        perror("I2C write error (init 22)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0x80, 0x00) < 0) {
        perror("I2C write error (init 23)");
        return -1;
    }

    if (wiringPiI2CWriteReg8(fd, 0x8F, 0x00) < 0) {
        perror("I2C write error (init 24)");
        return -1;
    }

    // Start continuous ranging
    if (wiringPiI2CWriteReg8(fd, VL53L1X_REG_SYSTEM_START, 0x01) < 0) {
        perror("I2C write error (start ranging)");
        return -1;
    }

    return 0;
}

// Function to read distance from the VL53L1X sensor
int read_distance(int fd) {
    int range = 0;

    // Read the range in mm
    range = wiringPiI2CReadReg16(fd, VL53L1X_REG_RESULT_FINAL_CROSSTALK_CORRECTED_RANGE_MM_SD0);
    if (range < 0) {
        perror("I2C read error (range)");
        return -1;
    }

    return range;
}

// Function to control the LED
void control_led(int gpio_pin, int state) {
    digitalWrite(gpio_pin, state);
}

int main() {
    int fd; // I2C file descriptor
    int distance;

    // Initialize wiringPi with GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi setup failed: %s\n", strerror(errno));
        return 1;
    }

    // Set LED pin as output
    pinMode(LED_PIN, OUTPUT);

    // Initialize I2C
    fd = wiringPiI2CSetup(VL53L1X_ADDR);
    if (fd == -1) {
        fprintf(stderr, "I2C setup failed: %s\n", strerror(errno));
        return 1;
    }

    // Initialize VL53L1X sensor
    if (vl53l1x_init(fd) == -1) {
        fprintf(stderr, "VL53L1X initialization failed.\n");
        return 1;
    }

    // Main loop
    while (1) {
        distance = read_distance(fd);

        if (distance >= 0) {
            printf("Distance: %d mm\n", distance);

            if (distance < 200) {
                control_led(LED_PIN, HIGH); // Turn on LED
            } else {
                control_led(LED_PIN, LOW);  // Turn off LED
            }
        } else {
            fprintf(stderr, "Error reading distance. Re-initializing...\n");
            // Attempt to re-initialize I2C and sensor
            close(fd);
            fd = wiringPiI2CSetup(VL53L1X_ADDR);
            if (fd == -1) {
                fprintf(stderr, "I2C setup failed during re-initialization: %s\n", strerror(errno));
                delay(1000); // Wait before retrying I2C setup
                continue;    // Skip the rest of the loop and retry I2C setup
            }
            if (vl53l1x_init(fd) == -1) {
                fprintf(stderr, "VL53L1X initialization failed during re-initialization.\n");
            }
        }

        delay(100); // Delay between readings
    }

    return 0;
}

