// Constants
#define ARDUINO_ADDRESS 0x04
#define TEMP_REQUEST_CODE 1

// Function Prototypes
char* get_current_time();
int read_temperature(int file_descriptor);

int main()
{
    int file_descriptor;
    int result;
    float temperature;

    printf("Content-Type: text/html\n\n");
    printf("<html><body>\n");
    printf("<h1>I2C Temperature Reader</h1>\n");

    printf("<p>Connecting to I2C device at address 0x%02X...</p>\n", ARDUINO_ADDRESS);

    // Initialize I2C communication
    file_descriptor = wiringPiI2CSetup(ARDUINO_ADDRESS);
    if (file_descriptor < 0) {
        fprintf(stderr, "<p>Error: Failed to initialize I2C communication. Error code: %d (%s)</p>\n", errno, strerror(errno));
        printf("<p>I2C Initialization Failed!</p>\n");
        printf("</body></html>\n");
        return EXIT_FAILURE;
    } else {
        printf("<p>I2C connection established successfully!</p>\n");
    }

    // Request temperature data from Arduino
    printf("<p>Requesting temperature data...</p>\n");
    result = wiringPiI2CWrite(file_descriptor, TEMP_REQUEST_CODE);
    if (result < 0) {
        fprintf(stderr, "<p>Error: Failed to write to I2C device. Error code: %d (%s)</p>\n", errno, strerror(errno));
        printf("<p>I2C Write Failed!</p>\n");
        printf("</body></html>\n");
        return EXIT_FAILURE;
    } else {
        printf("<p>Temperature request sent successfully (Request Code: %d).</p>\n", TEMP_REQUEST_CODE);
    }

    // Delay to allow Arduino to process the request
    usleep(10000); // 10 milliseconds

    // Read temperature from Arduino
    temperature = read_temperature(file_descriptor);
    if (temperature == -1000.0) {
        printf("</body></html>\n");
        return EXIT_FAILURE;
    }

    // Display temperature data
    printf("<p>Temperature: %.2f &deg;C</p>\n", temperature);
    printf("<p>Timestamp: %s</p>\n", get_current_time());

    printf("<p>Closing I2C connection...</p>\n");
    printf("</body></html>\n");

    return EXIT_SUCCESS;
}

// Function to read temperature from I2C device
int read_temperature(int file_descriptor)
{
    int raw_value;
    float temperature;

    raw_value = wiringPiI2CRead(file_descriptor);
    if (raw_value < 0) {
        fprintf(stderr, "<p>Error: Failed to read from I2C device. Error code: %d (%s)</p>\n", errno, strerror(errno));
        printf("<p>I2C Read Failed!</p>\n");
        return -1000.0; // Indicate failure
    }

    temperature = (float)raw_value / 100.0;
    printf("<p>Raw Value from I2C: %d</p>\n", raw_value);

    return temperature;
}

// Function to get the current timestamp
char* get_current_time()
{
    time_t current_time;
    char* c_time_string;

    current_time = time(NULL);
    if (current_time == ((time_t)-1)) {
        fprintf(stderr, "<p>Error: Failed to get current time.</p>\n");
        return ""; // Return empty string in case of error
    }

    c_time_string = ctime(&current_time);
    if (c_time_string == NULL) {
        fprintf(stderr, "<p>Error: Failed to convert time to string.</p>\n");
        return ""; // Return empty string in case of error
    }

    return c_time_string;
}

