#define SSD1306_I2C_ADDR  0x3C
#define BUTTON_PIN 0  // BCM GPIO 17
int i2c_fd;
void ssd1306_sendCommand(unsigned char command) {
    unsigned char buffer[2] = {0x00, command};
    write(i2c_fd, buffer, 2);
}
void ssd1306_init() {
    ssd1306_sendCommand(0xAE);
    ssd1306_sendCommand(0xA6);
    ssd1306_sendCommand(0xAF);
}
void toggle_display_mode(int *mode) {
    *mode = !(*mode);
    ssd1306_sendCommand(*mode ? 0xA7 : 0xA6);
}
int main() {
    if ((i2c_fd = open("/dev/i2c-1", O_RDWR)) < 0) {
        perror("Failed to open I2C bus");
        return EXIT_FAILURE;
    }
    if (ioctl(i2c_fd, I2C_SLAVE, SSD1306_I2C_ADDR) < 0) {
        perror("Failed to communicate with SSD1306");
        return EXIT_FAILURE;
    }
    wiringPiSetup();
    pinMode(BUTTON_PIN, INPUT);
    pullUpDnControl(BUTTON_PIN, PUD_UP);
    ssd1306_init();
    int mode = 0;
    while (1) {
        if (digitalRead(BUTTON_PIN) == 0) {
            toggle_display_mode(&mode);
            printf("Display mode: %s\n", mode ? "Inverted" : "Normal");
            sleep(1);
        }
    }
    close(i2c_fd);
    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>

#define TILT_PIN 17
#define LEFT_PIN 18
#define RIGHT_PIN 19

void tilt_callback(int gpio, int level, uint32_t tick, void *user);

int main() {
    FILE *log_file;
    int pigpio_init_status;

    // Initialize pigpio
    pigpio_init_status = gpioInitialise();
    if (pigpio_init_status < 0) {
        fprintf(stderr, "pigpio initialisation failed: %d\n", pigpio_init_status);
        return 1;
    }

    // Configure GPIO 17 as input with pull-up resistor
    gpioSetMode(TILT_PIN, PI_INPUT);
    gpioSetPullUpDown(TILT_PIN, PI_PUD_UP);

    // Configure GPIO 18 and 19 as inputs
    gpioSetMode(LEFT_PIN, PI_INPUT);
    gpioSetMode(RIGHT_PIN, PI_INPUT);

    // Open the log file for appending
    log_file = fopen("tilt_events.log", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        gpioTerminate();
        return 1;
    }

    // Set the callback function for GPIO 17
    gpioSetAlertFuncEx(TILT_PIN, tilt_callback, log_file);

    printf("Tilt detection started. Press Ctrl+C to exit.\n");

    // Keep the program running indefinitely
    while (1) {
        gpioDelay(1000); // Check every second
    }

    // Cleanup (this part will not be reached in normal execution)
    fclose(log_file);
    gpioTerminate();
    return 0;
}

void tilt_callback(int gpio, int level, uint32_t tick, void *user) {
    FILE *log_file = (FILE *)user;
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];
    int left_state, right_state;
    char *direction;

    // Get the current timestamp
    time(&rawtime);
    timeinfo = localtime(&rawtime);
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    // Determine the tilt direction based on GPIO 18 and 19
    left_state = gpioRead(LEFT_PIN);
    right_state = gpioRead(RIGHT_PIN);

    if (left_state && !right_state) {
        direction = "Left";
    } else if (!left_state && right_state) {
        direction = "Right";
    } else {
        direction = "Center";
    }

    // Log the timestamp and tilt direction to the file
    fprintf(log_file, "%s,%s\n", timestamp, direction);
    fflush(log_file); // Ensure data is written to disk immediately

    printf("Tilt detected: Timestamp=%s, Direction=%s\n", timestamp, direction);
}

