#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>
#include <time.h>
#include <math.h>
#include <signal.h>
#include <stdlib.h>

// Motor GPIO pins
#define MOTOR1_UP 23   // Elevation Up
#define MOTOR1_DOWN 24 // Elevation Down
#define MOTOR2_LEFT 17 // Azimuth Left
#define MOTOR2_RIGHT 18 // Azimuth Right

// Tolerance for angle comparison
#define ANGLE_TOLERANCE 2.0

// Proportional gain for elevation adjustment
#define KP 0.5

// Log file path
#define LOG_FILE "motor_log.txt"

// Define motor directions
typedef enum {
    STOP = 0,
    UP,
    DOWN,
    LEFT,
    RIGHT
} MotorDirection;

// Global variables
FILE *logFile = NULL;
volatile sig_atomic_t programRunning = 1;
float currentElevation = 0.0;

// Function prototypes
void cleanup();
void signalHandler(int signal);
float calculateSolarElevation();
void setMotorDirection(int motor, MotorDirection direction);
void adjustElevation(float targetAngle);
void logMotorActivity(int motor, MotorDirection direction, float targetAngle, float currentAngle);

// Signal handler for graceful shutdown
void signalHandler(int signal) {
    programRunning = 0;
    printf("\nCaught signal %d, exiting gracefully...\n", signal);
}

// Cleanup function to reset GPIO pins and terminate pigpio
void cleanup() {
    printf("Cleaning up resources...\n");
    gpioWrite(MOTOR1_UP, 0);
    gpioWrite(MOTOR1_DOWN, 0);
    gpioWrite(MOTOR2_LEFT, 0);
    gpioWrite(MOTOR2_RIGHT, 0);

    if (logFile != NULL) {
        fclose(logFile);
        logFile = NULL;
    }

    gpioTerminate();
    printf("Cleanup complete.\n");
}

// Function to calculate a simulated solar elevation angle
float calculateSolarElevation() {
    time_t now = time(NULL);
    struct tm *localTime = localtime(&now);

    // Simulate a sinusoidal solar elevation angle based on the time of day
    double hour = localTime->tm_hour + localTime->tm_min / 60.0;
    float elevation = 45.0 * sin(M_PI * (hour - 6) / 12.0) + 45.0; // Max elevation at noon

    // Clamp the elevation angle between 0 and 90 degrees
    if (elevation < 0.0) elevation = 0.0;
    if (elevation > 90.0) elevation = 90.0;

    return elevation;
}

// Function to set the direction of a motor
void setMotorDirection(int motor, MotorDirection direction) {
    int upPin, downPin, leftPin, rightPin;

    if (motor == 1) {
        upPin = MOTOR1_UP;
        downPin = MOTOR1_DOWN;
    } else if (motor == 2) {
        leftPin = MOTOR2_LEFT;
        rightPin = MOTOR2_RIGHT;
    } else {
        fprintf(stderr, "Error: Invalid motor number: %d\n", motor);
        if (logFile != NULL) {
            fprintf(logFile, "Error: Invalid motor number: %d\n", motor);
        }
        return;
    }

    switch (direction) {
        case UP:
            gpioWrite(MOTOR1_UP, 1);
            gpioWrite(MOTOR1_DOWN, 0);
            break;
        case DOWN:
            gpioWrite(MOTOR1_UP, 0);
            gpioWrite(MOTOR1_DOWN, 1);
            break;
        case LEFT:
            gpioWrite(MOTOR2_LEFT, 1);
            gpioWrite(MOTOR2_RIGHT, 0);
            break;
        case RIGHT:
            gpioWrite(MOTOR2_LEFT, 0);
            gpioWrite(MOTOR2_RIGHT, 1);
            break;
        case STOP:
            if (motor == 1) {
                gpioWrite(MOTOR1_UP, 0);
                gpioWrite(MOTOR1_DOWN, 0);
            } else {
                gpioWrite(MOTOR2_LEFT, 0);
                gpioWrite(MOTOR2_RIGHT, 0);
            }
            break;
        default:
            fprintf(stderr, "Error: Invalid motor direction: %d\n", direction);
            if (logFile != NULL) {
                fprintf(logFile, "Error: Invalid motor direction: %d\n", direction);
            }
            return;
    }
}

// Function to adjust the elevation of the solar panel
void adjustElevation(float targetAngle) {
    float error = targetAngle - currentElevation;

    while (programRunning && fabs(error) > ANGLE_TOLERANCE) {
        MotorDirection direction;

        if (error > 0) {
            direction = UP;
        } else {
            direction = DOWN;
        }

        setMotorDirection(1, direction);
        logMotorActivity(1, direction, targetAngle, currentElevation);

        // Proportional control: adjust sleep time based on error
        int sleepTime = (int)(fabs(error) * KP * 10000); // microseconds
        usleep(sleepTime);

        setMotorDirection(1, STOP);
        logMotorActivity(1, STOP, targetAngle, currentElevation);

        // Update current elevation (crude simulation)
        if (direction == UP) {
            currentElevation += 0.5; // Increment based on sleep time
            if (currentElevation > 90.0) currentElevation = 90.0;
        } else {
            currentElevation -= 0.5;
            if (currentElevation < 0.0) currentElevation = 0.0;
        }

        error = targetAngle - currentElevation;
    }
    setMotorDirection(1, STOP);
    logMotorActivity(1, STOP, targetAngle, currentElevation);

    printf("Elevation adjusted to target angle: %.2f (Current: %.2f)\n", targetAngle, currentElevation);
}

// Function to log motor activity to a file
void logMotorActivity(int motor, MotorDirection direction, float targetAngle, float currentAngle) {
    if (logFile == NULL) return;

    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[26];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", t);

    fprintf(logFile, "%s, Motor: %d, Direction: %d, Target Angle: %.2f, Current Angle: %.2f\n",
            timestamp, motor, direction, targetAngle, currentAngle);
    fflush(logFile); // Ensure data is written to the file immediately
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pins as outputs
    gpioSetMode(MOTOR1_UP, PI_OUTPUT);
    gpioSetMode(MOTOR1_DOWN, PI_OUTPUT);
    gpioSetMode(MOTOR2_LEFT, PI_OUTPUT);
    gpioSetMode(MOTOR2_RIGHT, PI_OUTPUT);

    // Initialize log file
    logFile = fopen(LOG_FILE, "a");
    if (logFile == NULL) {
        perror("Error opening log file");
        gpioTerminate();
        return 1;
    }

    // Register signal handler for Ctrl+C
    signal(SIGINT, signalHandler);

    printf("Solar panel tracking simulation started. Press Ctrl+C to exit.\n");

    while (programRunning) {
        float targetAngle = calculateSolarElevation();
        printf("Target Elevation Angle: %.2f\n", targetAngle);
        adjustElevation(targetAngle);
        sleep(60); // Adjust every minute
    }

    cleanup();
    return 0;
}

#include <pigpio.h>
#include <stdio.h>
#define SWITCH 23
int read_adc(int spi, int ch) {
    char tx[3] = {1, (0x80 | (ch << 4)), 0}, rx[3];
    spiXfer(spi, tx, rx, 3);
    return ((rx[1] & 3) << 8) | rx[2];
}
int main() {
    if (gpioInitialise() < 0) return 1;
    gpioSetMode(SWITCH, PI_INPUT);
    gpioSetPullUpDown(SWITCH, PI_PUD_UP);
    int spi = spiOpen(0, 1000000, 0);
    while (1) {
        int channel = gpioRead(SWITCH) == 0 ? 1 : 0;
        int value = read_adc(spi, channel);
        printf("ADC CH%d: %d\n", channel, value);
        gpioDelay(200000);
    }
    spiClose(spi);
    gpioTerminate();
    return 0;
}

#include <bcm2835.h>
#include <stdio.h>
#define MCP4725_ADDR 0x60
int main() {
    if (!bcm2835_init()) {
        fprintf(stderr, "bcm2835 init failed\n");
        return 1;
    }
    if (!bcm2835_i2c_begin()) {
        fprintf(stderr, "I2C begin failed\n");
        bcm2835_close();
        return 1;
    }
    bcm2835_i2c_setSlaveAddress(MCP4725_ADDR);
    char buf[3] = {0x40, 0x80, 0x00};
    if (bcm2835_i2c_write(buf, 3) != BCM2835_I2C_REASON_OK) {
        fprintf(stderr, "Failed to write to MCP4725\n");
    } else {
        printf("DAC set to mid-scale.\n");
    }
    bcm2835_i2c_end();
    bcm2835_close();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <inttypes.h>

#define ADS1115_ADDRESS 0x48
#define ADS1115_CONFIG_REG 0x01
#define ADS1115_CONVERSION_REG 0x00

// Gain settings
#define ADS1115_GAIN_6_144V 0x0000

// Single conversion mode
#define ADS1115_MODE_SINGLE 0x0100

// Sample rate (128 SPS)
#define ADS1115_RATE_128SPS 0x0080

// Comparator mode
#define ADS1115_COMP_MODE_TRADITIONAL 0x0000

// Comparator polarity
#define ADS1115_COMP_POL_ACTIVE_LOW 0x0000

// Comparator latch enabled
#define ADS1115_COMP_LAT_NON_LATCHING 0x0000

// Comparator queue disabled
#define ADS1115_COMP_QUE_DISABLE 0x0003

int i2c_fd;

int ads1115_read_channel(int channel)
{
    uint16_t config;

    // Determine the mux value based on the channel
    uint16_t mux;
    switch (channel)
    {
    case 0:
        mux = 0x4000;
        break;
    case 1:
        mux = 0x5000;
        break;
    case 2:
        mux = 0x6000;
        break;
    case 3:
        mux = 0x7000;
        break;
    default:
        fprintf(stderr, "Invalid channel: %d\n", channel);
        return -1;
    }

    // Build the configuration register value
    config = ADS1115_GAIN_6_144V | ADS1115_MODE_SINGLE | ADS1115_RATE_128SPS |
             ADS1115_COMP_MODE_TRADITIONAL | ADS1115_COMP_POL_ACTIVE_LOW |
             ADS1115_COMP_LAT_NON_LATCHING | ADS1115_COMP_QUE_DISABLE | mux;

    // Write the configuration register
    uint8_t write_buf[3];
    write_buf[0] = ADS1115_CONFIG_REG;
    write_buf[1] = (config >> 8) & 0xFF;
    write_buf[2] = config & 0xFF;

    if (write(i2c_fd, write_buf, 3) != 3)
    {
        perror("Failed to write config register");
        return -1;
    }

    // Wait for conversion to complete (at least 8ms for 128 SPS)
    usleep(10000); // Wait 10ms

    // Read the conversion register
    uint8_t read_buf[2];
    write_buf[0] = ADS1115_CONVERSION_REG;

    if (write(i2c_fd, write_buf, 1) != 1)
    {
        perror("Failed to write conversion register address");
        return -1;
    }

    if (read(i2c_fd, read_buf, 2) != 2)
    {
        perror("Failed to read conversion register");
        return -1;
    }

    // Combine the bytes and return the value
    int16_t value = (read_buf[0] << 8) | read_buf[1];

    return value;
}

int main()
{
    // Initialize I2C
    i2c_fd = open("/dev/i2c-1", O_RDWR);
    if (i2c_fd < 0)
    {
        perror("Failed to open I2C bus");
        return 1;
    }

    if (ioctl(i2c_fd, I2C_SLAVE, ADS1115_ADDRESS) < 0)
    {
        perror("Failed to acquire bus access and/or talk to slave");
        close(i2c_fd);
        return 1;
    }

    printf("ADS1115 Channel Readings:\n");
    while (1)
    {
        for (int i = 0; i < 4; i++)
        {
            int reading = ads1115_read_channel(i);
            if (reading == -1)
            {
                fprintf(stderr, "Error reading channel %d\n", i);
            } else {
                printf("Channel %d: %d\n", i, reading);
            }
        }
        printf("\n");
        sleep(1); // Read every second
    }

    close(i2c_fd);
    return 0;
}

#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>

#define IN1 17 // GPIO pin connected to IN1 of L293D
#define IN2 18 // GPIO pin connected to IN2 of L293D

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(IN1, PI_OUTPUT);
    gpioSetMode(IN2, PI_OUTPUT);

    while (1) {
        // Move motor forward briefly
        gpioWrite(IN1, 1);
        gpioWrite(IN2, 0);
        usleep(500000); // 0.5 seconds

        // Stop the motor
        gpioWrite(IN1, 0);
        gpioWrite(IN2, 0);
        sleep(3);       // Wait for 3 seconds
    }

    gpioTerminate();
    return 0;
}

#include <bcm2835.h>
#include <stdio.h>
#include <unistd.h>
#include <time.h>
#define ADS_ADDR 0x48
#define CONFIG_REG 0x01
#define CONVERSION_REG 0x00
#define REF_VOLTAGE 4.096
void write_config_ch0() {
    char config[3] = {CONFIG_REG, 0xC2, 0x83};
    bcm2835_i2c_write(config, 3);
}
int read_conversion() {
    char data[2];
    bcm2835_i2c_read(data, 2);
    return (data[0] << 8) | data[1];
}
int main() {
    if (!bcm2835_init()) return 1;
    bcm2835_i2c_begin();
    bcm2835_i2c_setSlaveAddress(ADS_ADDR);
    FILE* f = fopen("ads1115_ch0_bcm_log.csv", "w");
    fprintf(f, "Time,Voltage\n");
    while (1) {
        write_config_ch0();
        bcm2835_delayMicroseconds(9000);
        int raw = read_conversion();
        double voltage = raw * REF_VOLTAGE / 32768.0;
        fprintf(f, "%ld,%.4f\n", time(NULL), voltage);
        fflush(f);
        sleep(1);
    }
    fclose(f);
    bcm2835_i2c_end();
    bcm2835_close();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <unistd.h>
#include <signal.h>
#include <errno.h>

// GPIO pins
#define FLAME_SENSOR_PIN 4
#define BUZZER_PIN 17
#define LED_PIN 27

// File paths for sysfs GPIO control
#define GPIO_EXPORT_PATH "/sys/class/gpio/export"
#define GPIO_UNEXPORT_PATH "/sys/class/gpio/unexport"
#define GPIO_DIRECTION_PATH_FORMAT "/sys/class/gpio/gpio%d/direction"
#define GPIO_VALUE_PATH_FORMAT "/sys/class/gpio/gpio%d/value"

// Log file path
#define LOG_FILE_PATH "fire_log.txt"

// Polling interval (milliseconds)
#define POLLING_INTERVAL_MS 500

// Buzzer and LED duration (milliseconds)
#define ALERT_DURATION_MS 2000

// Global flag to indicate program termination
volatile sig_atomic_t program_running = 1;

// Function prototypes
int gpio_export(int pin);
int gpio_unexport(int pin);
int gpio_set_direction(int pin, const char *direction);
int gpio_write(int pin, int value);
int gpio_read(int pin);
int read_flame_sensor();
void activate_buzzer(int duration_ms);
void activate_led(int duration_ms);
void log_event();
void cleanup();
void signal_handler(int signum);

// Signal handler for Ctrl+C
void signal_handler(int signum) {
    if (signum == SIGINT) {
        printf("Received SIGINT. Cleaning up and exiting.\n");
        program_running = 0;
    }
}

// Exports a GPIO pin using sysfs
int gpio_export(int pin) {
    FILE *fp;
    char buf[3];
    int len;

    fp = fopen(GPIO_EXPORT_PATH, "w");
    if (fp == NULL) {
        perror("Failed to open GPIO export file");
        return -1;
    }

    len = snprintf(buf, sizeof(buf), "%d", pin);
    if (fwrite(buf, 1, len, fp) != len) {
        perror("Failed to write to GPIO export file");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return 0;
}

// Unexports a GPIO pin using sysfs
int gpio_unexport(int pin) {
    FILE *fp;
    char buf[3];
    int len;

    fp = fopen(GPIO_UNEXPORT_PATH, "w");
    if (fp == NULL) {
        perror("Failed to open GPIO unexport file");
        return -1;
    }

    len = snprintf(buf, sizeof(buf), "%d", pin);
    if (fwrite(buf, 1, len, fp) != len) {
        perror("Failed to write to GPIO unexport file");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return 0;
}

// Sets the direction of a GPIO pin (input or output)
int gpio_set_direction(int pin, const char *direction) {
    FILE *fp;
    char path[64];

    snprintf(path, sizeof(path), GPIO_DIRECTION_PATH_FORMAT, pin);

    fp = fopen(path, "w");
    if (fp == NULL) {
        perror("Failed to open GPIO direction file");
        return -1;
    }

    if (fputs(direction, fp) == EOF) {
        perror("Failed to write to GPIO direction file");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return 0;
}

// Writes a value (0 or 1) to a GPIO pin
int gpio_write(int pin, int value) {
    FILE *fp;
    char path[64];

    snprintf(path, sizeof(path), GPIO_VALUE_PATH_FORMAT, pin);

    fp = fopen(path, "w");
    if (fp == NULL) {
        perror("Failed to open GPIO value file");
        return -1;
    }

    if (fprintf(fp, "%d", value) < 0) {
        perror("Failed to write to GPIO value file");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return 0;
}

// Reads the value of a GPIO pin
int gpio_read(int pin) {
    FILE *fp;
    char path[64];
    int value;

    snprintf(path, sizeof(path), GPIO_VALUE_PATH_FORMAT, pin);

    fp = fopen(path, "r");
    if (fp == NULL) {
        perror("Failed to open GPIO value file");
        return -1;
    }

    if (fscanf(fp, "%d", &value) != 1) {
        perror("Failed to read from GPIO value file");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return value;
}

// Reads the flame sensor value and returns 1 if a flame is detected, 0 otherwise
int read_flame_sensor() {
    int value = gpio_read(FLAME_SENSOR_PIN);
    if (value < 0) {
        fprintf(stderr, "Error reading flame sensor value.\n");
        return 0; // Return 0 on error to avoid infinite loops
    }
    return (value == 0); // Assuming 0 means flame detected (active low)
}

// Activates the buzzer for a specified duration
void activate_buzzer(int duration_ms) {
    if (gpio_write(BUZZER_PIN, 1) != 0) {
        fprintf(stderr, "Error activating buzzer.\n");
        return;
    }
    usleep(duration_ms * 1000); // Convert milliseconds to microseconds
    if (gpio_write(BUZZER_PIN, 0) != 0) {
        fprintf(stderr, "Error deactivating buzzer.\n");
    }
}

// Activates the LED for a specified duration
void activate_led(int duration_ms) {
    if (gpio_write(LED_PIN, 1) != 0) {
        fprintf(stderr, "Error activating LED.\n");
        return;
    }
    usleep(duration_ms * 1000); // Convert milliseconds to microseconds
    if (gpio_write(LED_PIN, 0) != 0) {
        fprintf(stderr, "Error deactivating LED.\n");
    }
}

// Logs the current timestamp to the log file
void log_event() {
    FILE *fp;
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fp = fopen(LOG_FILE_PATH, "a");
    if (fp == NULL) {
        perror("Failed to open log file");
        return;
    }

    fprintf(fp, "%s: Flame detected!\n", timestamp);
    fclose(fp);
}

// Cleans up GPIO pins by unexporting them
void cleanup() {
    gpio_unexport(FLAME_SENSOR_PIN);
    gpio_unexport(BUZZER_PIN);
    gpio_unexport(LED_PIN);
}

int main() {
    // Install signal handler
    if (signal(SIGINT, signal_handler) == SIG_ERR) {
        perror("Failed to install signal handler");
        return 1;
    }

    // Export GPIO pins
    if (gpio_export(FLAME_SENSOR_PIN) != 0 ||
        gpio_export(BUZZER_PIN) != 0 ||
        gpio_export(LED_PIN) != 0) {
        cleanup();
        return 1;
    }

    // Set GPIO directions
    if (gpio_set_direction(FLAME_SENSOR_PIN, "in") != 0 ||
        gpio_set_direction(BUZZER_PIN, "out") != 0 ||
        gpio_set_direction(LED_PIN, "out") != 0) {
        cleanup();
        return 1;
    }

    // Main loop
    while (program_running) {
        if (read_flame_sensor()) {
            printf("Flame detected!\n");
            log_event();
            activate_buzzer(ALERT_DURATION_MS);
            activate_led(ALERT_DURATION_MS);
        }
        usleep(POLLING_INTERVAL_MS * 1000); // Convert milliseconds to microseconds
    }

    // Cleanup and exit
    cleanup();
    printf("Program exiting.\n");
    return 0;
}

#include <stdio.h>
