#include <stdio.h>
#include <wiringPi.h>
#include <softPwm.h>

// Define the pins connected to the 74HC595 shift register
#define LATCH_PIN  1  // WiringPi pin 1 (BCM GPIO 18)
#define CLOCK_PIN  4  // WiringPi pin 4 (BCM GPIO 23)
#define DATA_PIN   5  // WiringPi pin 5 (BCM GPIO 24)

// Define the button pin
#define BUTTON_PIN 7  // WiringPi pin 7 (BCM GPIO 4)

// Seven-segment display patterns (common anode)
const unsigned char digits[] = {
    0xC0, // 0
    0xF9, // 1
    0xA4, // 2
    0xB0, // 3
    0x99, // 4
    0x92, // 5
    0x82, // 6
    0xF8, // 7
    0x80, // 8
    0x90  // 9
};

// Function to shift data to the 74HC595
void shiftData(unsigned char data) {
    for (int i = 0; i < 8; i++) {
        digitalWrite(DATA_PIN, (data >> (7 - i)) & 0x01);
        digitalWrite(CLOCK_PIN, HIGH);
        delayMicroseconds(1); // Short delay for clock pulse
        digitalWrite(CLOCK_PIN, LOW);
        delayMicroseconds(1); // Short delay for clock pulse
    }
}

// Function to display a number on the seven-segment display
void displayNum(int num) {
    shiftData(digits[num % 10]); // Display the number
    digitalWrite(LATCH_PIN, HIGH); // Latch the data to the output
    delayMicroseconds(1);         // Short delay for latch
    digitalWrite(LATCH_PIN, LOW);  // Disable latch
}

int main() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi setup failed!\n");
        return 1;
    }

    // Set pin modes
    pinMode(LATCH_PIN, OUTPUT);
    pinMode(CLOCK_PIN, OUTPUT);
    pinMode(DATA_PIN, OUTPUT);
    pinMode(BUTTON_PIN, INPUT);
    pullUpDnControl(BUTTON_PIN, PUD_UP); // Enable pull-up resistor

    int count = 0;
    int buttonState = HIGH; // Initialize button state to HIGH (not pressed)
    int lastButtonState = HIGH;

    while (1) {
        buttonState = digitalRead(BUTTON_PIN);

        // Check if the button is pressed (falling edge)
        if (buttonState == LOW && lastButtonState == HIGH) {
            count++;
            if (count > 9) {
                count = 0;
            }
            displayNum(count);
            delay(200); // Debounce delay
        }

        lastButtonState = buttonState;
        delay(10); // Short delay
    }

    return 0;
}

#include <stdio.h>
