#define GPIO4 4   // A0 (Analog Output - PWM Simulation)
#define GPIO5 5   // D0 (Digital Output)
#define GPIO6 6   // Ground (Unused in code, but good practice to define)

#define PWM_PERIOD 1000 // PWM period in microseconds

// Function to write to a file
int write_to_file(const char *path, const char *value) {
    FILE *fp = fopen(path, "w");
    if (fp == NULL) {
        fprintf(stderr, "Error opening file: %s\n", path);
        return -1;
    }
    if (fprintf(fp, "%s", value) < 0) {
        fprintf(stderr, "Error writing to file: %s\n", path);
        fclose(fp);
        return -1;
    }
    fclose(fp);
    return 0;
}

// Function to read from a file
int read_from_file(const char *path, char *buffer, size_t buffer_size) {
    FILE *fp = fopen(path, "r");
    if (fp == NULL) {
        fprintf(stderr, "Error opening file: %s\n", path);
        return -1;
    }
    if (fgets(buffer, buffer_size, fp) == NULL && !feof(fp)) {
        fprintf(stderr, "Error reading from file: %s\n", path);
        fclose(fp);
        return -1;
    }
    fclose(fp);
    return 0;
}

// Function to export a GPIO pin
int gpio_export(int gpio) {
    char buffer[3];
    snprintf(buffer, sizeof(buffer), "%d", gpio);
    return write_to_file("/sys/class/gpio/export", buffer);
}

// Function to unexport a GPIO pin
int gpio_unexport(int gpio) {
    char buffer[3];
    snprintf(buffer, sizeof(buffer), "%d", gpio);
    return write_to_file("/sys/class/gpio/unexport", buffer);
}

// Function to set GPIO direction (in or out)
int gpio_direction(int gpio, const char *direction) {
    char path[64];
    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/direction", gpio);
    return write_to_file(path, direction);
}

// Function to write a value to a GPIO pin
int gpio_write(int gpio, int value) {
    char path[64];
    char buffer[2];
    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", gpio);
    snprintf(buffer, sizeof(buffer), "%d", value);
    return write_to_file(path, buffer);
}

// Function to read a value from a GPIO pin
int gpio_read(int gpio, int *value) {
    char path[64];
    char buffer[3];
    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", gpio);
    if (read_from_file(path, buffer, sizeof(buffer)) != 0) {
        return -1;
    }
    *value = atoi(buffer);
    return 0;
}

// Function to simulate ADC reading using PWM on GPIO4
int simulate_adc_pwm(int gpio, int duty_cycle) {
    // duty_cycle is a percentage (0-100)
    if (duty_cycle < 0 || duty_cycle > 100) {
        fprintf(stderr, "Invalid duty cycle: %d\n", duty_cycle);
        return -1;
    }

    for (int i = 0; i < PWM_PERIOD; ++i) {
        if (i < (duty_cycle * PWM_PERIOD) / 100) {
            if (gpio_write(gpio, 1) != 0) return -1; // GPIO High
        } else {
            if (gpio_write(gpio, 0) != 0) return -1; // GPIO Low
        }
        usleep(1); // Small delay for PWM effect
    }
    return 0;
}

// Function to get timestamp as a string
char* get_timestamp() {
    time_t rawtime;
    struct tm *timeinfo;
    time(&rawtime);
    timeinfo = localtime(&rawtime);

    char *timestamp = (char*)malloc(25 * sizeof(char)); // Allocate memory for timestamp
    if (timestamp == NULL) {
        fprintf(stderr, "Memory allocation failed for timestamp\n");
        return NULL;
    }

    strftime(timestamp, 25, "%Y-%m-%d %H:%M:%S", timeinfo);
    return timestamp;
}

// Function to log data to JSON file
int log_to_json(int adc_value, int flame_detected) {
    FILE *fp = fopen("fire_log.json", "a+");
    if (fp == NULL) {
        fprintf(stderr, "Error opening fire_log.json\n");
        return -1;
    }

    // Get timestamp
    char *timestamp = get_timestamp();
    if (timestamp == NULL) {
        fclose(fp);
        return -1;
    }

    // Check if the file is empty. If so, add the opening bracket for the JSON array.
    fseek(fp, 0, SEEK_END);
    long file_size = ftell(fp);
    if (file_size == 0) {
        fprintf(fp, "[");
    } else {
        // If the file is not empty, go back one character and check if it's a closing bracket.
        fseek(fp, -1, SEEK_END);
        int last_char = fgetc(fp);
        if (last_char == ']') {
            // If it's a closing bracket, truncate the file to remove it and add a comma.
            ftruncate(fileno(fp), file_size - 1);
            fprintf(fp, ",");
        } else {
            //If not closing bracket, add a comma to seperate data
            fprintf(fp, ",");
        }
    }

    fprintf(fp, "{\"timestamp\": \"%s\", \"adc_value\": %d, \"flame_detected\": %d}", timestamp, adc_value, flame_detected);

    fprintf(fp, "]");

    fclose(fp);
    free(timestamp); // Free the allocated memory
    return 0;
}

int main() {
    // Export GPIO pins
    if (gpio_export(GPIO4) != 0 || gpio_export(GPIO5) != 0) {
        fprintf(stderr, "Failed to export GPIO pins\n");
        return 1;
    }

    // Set GPIO4 as output (PWM simulation) and GPIO5 as input (digital read)
    if (gpio_direction(GPIO4, "out") != 0 || gpio_direction(GPIO5, "in") != 0) {
        fprintf(stderr, "Failed to set GPIO direction\n");
        gpio_unexport(GPIO4);
        gpio_unexport(GPIO5);
        return 1;
    }

    int flame_detected;
    // Main loop
    for (int i = 0; i <= 100; i+=10) //Simulate different analog values by varying PWM duty cycle
    {
        // Simulate ADC reading with PWM
        if (simulate_adc_pwm(GPIO4, i) != 0) {
            fprintf(stderr, "PWM simulation failed\n");
            gpio_unexport(GPIO4);
            gpio_unexport(GPIO5);
            return 1;
        }

        // Read digital output from flame sensor
        if (gpio_read(GPIO5, &flame_detected) != 0) {
            fprintf(stderr, "Failed to read GPIO5\n");
            gpio_unexport(GPIO4);
            gpio_unexport(GPIO5);
            return 1;
        }

        // Log data to JSON file
        if (log_to_json(i, flame_detected) != 0) {
            fprintf(stderr, "Failed to log data to JSON\n");
            gpio_unexport(GPIO4);
            gpio_unexport(GPIO5);
            return 1;
        }

        printf("ADC Value: %d, Flame Detected: %d\n", i, flame_detected);
        sleep(1); // Wait for 1 second
    }

    // Unexport GPIO pins
    if (gpio_unexport(GPIO4) != 0 || gpio_unexport(GPIO5) != 0) {
        fprintf(stderr, "Failed to unexport GPIO pins\n");
        return 1;
    }

    return 0;
}

