#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <signal.h>
#include <unistd.h>
#include <wiringPi.h>
#include <wiringPiSPI.h>

// Define SPI channel and speed
#define SPI_CHANNEL 0
#define SPI_SPEED 1000000  // 1 MHz

// Define GPIO pin for PWM fan control
#define FAN_PIN 18

// Function prototypes
float readTemperature();
void setFanSpeed(int speed);
void handleFault(uint32_t data);
void signalHandler(int signum);

// Global variable to control program execution
volatile sig_atomic_t programRunning = 1;

int main()
{
    // Initialize wiringPi using GPIO numbering
    if (wiringPiSetupGpio() == -1)
    {
        fprintf(stderr, "wiringPiSetupGpio failed!\n");
        return 1;
    }

    // Initialize SPI
    if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) == -1)
    {
        fprintf(stderr, "wiringPiSPISetup failed!\n");
        return 1;
    }

    // Configure FAN_PIN as PWM output
    pinMode(FAN_PIN, PWM_OUTPUT);
    pwmSetMode(PWM_MODE_MS); // Set PWM mode to mark:space
    pwmSetRange(100);       // Set PWM range to 100 for percentage control
    pwmWrite(FAN_PIN, 0);   // Initialize fan speed to 0%

    // Set up signal handlers for graceful shutdown
    signal(SIGINT, signalHandler);
    signal(SIGTERM, signalHandler);

    printf("Temperature Monitoring and Fan Control\n");
    printf("Press Ctrl+C to exit\n");

    while (programRunning)
    {
        float temperature = readTemperature();
        int fanSpeed = 0;

        // Determine fan speed based on temperature
        if (temperature < 40.0)
        {
            fanSpeed = 0;
        } else if (temperature < 50.0)
        {
            fanSpeed = 30;
        } else if (temperature < 60.0)
        {
            fanSpeed = 60;
        } else
        {
            fanSpeed = 100;
        }

        setFanSpeed(fanSpeed);

        printf("Temperature: %.2f°C, Fan Speed: %d%%\n", temperature, fanSpeed);

        delay(1000); // Wait 1 second
    }

    // Clean up and exit
    setFanSpeed(0); // Stop the fan
    printf("Exiting program\n");
    return 0;
}

// Function to read temperature from MAX31855
float readTemperature()
{
    unsigned char data[4];
    int i;

    // Read 4 bytes from SPI
    wiringPiSPIDataRW(SPI_CHANNEL, data, 4);

    // Convert data to 32-bit integer
    uint32_t raw = (data[0] << 24) | (data[1] << 16) | (data[2] << 8) | data[3];

    // Check for fault conditions
    if (raw & 0x00000007) // Check the three fault bits
    {
        handleFault(raw);
        return -273.15; // Return absolute zero on fault.
    }

    // Extract temperature data (remove fault and sign bits)
    int16_t thermocouple_data = (raw >> 18) & 0x3FFF; // Extract 14-bit thermocouple data

    // Convert to temperature in Celsius
    float temperature = thermocouple_data * 0.25;

    return temperature;
}

// Function to set fan speed using PWM
void setFanSpeed(int speed)
{
    if (speed < 0) speed = 0;
    if (speed > 100) speed = 100;

    pwmWrite(FAN_PIN, speed);
}

// Function to handle fault conditions
void handleFault(uint32_t data)
{
    if (data & 0x00000001)
    {
        fprintf(stderr, "MAX31855 Fault: Open Circuit\n");
    } else if (data & 0x00000002)
    {
        fprintf(stderr, "MAX31855 Fault: Short to GND\n");
    } else if (data & 0x00000004)
    {
        fprintf(stderr, "MAX31855 Fault: Short to VCC\n");
    } else {
      fprintf(stderr, "Unknown MAX31855 Fault\n");
    }
}

// Signal handler to catch Ctrl+C and terminate gracefully
void signalHandler(int signum)
{
    programRunning = 0;
    printf("Caught signal %d, exiting...\n", signum);
}

