// GPIO setup function
int setup_gpio(int gpio, const char *direction) {
    char gpio_str[3]; // Enough to hold GPIO number (e.g., 99) and null terminator.
    sprintf(gpio_str, "%d", gpio);

    // Export GPIO
    if (write_to_file(GPIO_EXPORT_PATH, gpio_str) != 0) {
        fprintf(stderr, "Error exporting GPIO %d\n", gpio);
        return -1;
    }
    // Wait for the directory to be created.  This is crucial.
    char dir_path[128]; //Increased buffer size
    snprintf(dir_path, sizeof(dir_path), GPIO_DIR_PATH_FORMAT, gpio);
    int attempts = 0;
    while (access(dir_path, F_OK) == -1 && attempts < 10) {
        usleep(10000); // Wait 10ms
        attempts++;
    }
    if (attempts == 10) {
        fprintf(stderr, "Timeout waiting for GPIO directory to be created for GPIO %d\n", gpio);
        return -1;
    }

    // Set GPIO direction
    char direction_path[128]; //Increased buffer size
    snprintf(direction_path, sizeof(direction_path), GPIO_DIR_PATH_FORMAT, gpio);
    if (write_to_file(direction_path, direction) != 0) {
        fprintf(stderr, "Error setting direction for GPIO %d\n", gpio);
        return -1;
    }

    return 0;
}

// Rain sensor reading function with debouncing
int read_rain_sensor() {
    int low_count = 0;
    char value_str[2];
    char value_path[64];
    snprintf(value_path, sizeof(value_path), GPIO_VALUE_PATH_FORMAT, RAIN_SENSOR_GPIO);

    for (int i = 0; i < DEBOUNCE_READINGS; i++) {
        if (read_from_file(value_path, value_str, sizeof(value_str)) != 0) {
            fprintf(stderr, "Error reading rain sensor value\n");
            return -1; // Indicate error
        }

        if (value_str[0] == '0') {
            low_count++;
        }
        usleep(DEBOUNCE_DELAY_MS * 1000); // Delay in microseconds
    }

    return (low_count == DEBOUNCE_READINGS) ? 0 : 1; // 0 for rain, 1 for no rain
}

// Motor control functions
void motor_forward() {
    char in1_path[64];
    char in2_path[64];
    snprintf(in1_path, sizeof(in1_path), GPIO_VALUE_PATH_FORMAT, MOTOR_IN1_GPIO);
    snprintf(in2_path, sizeof(in2_path), GPIO_VALUE_PATH_FORMAT, MOTOR_IN2_GPIO);

    if (write_to_file(in1_path, "1") != 0 || write_to_file(in2_path, "0") != 0) {
        log_action("ERROR: Failed to start motor forward.");
    } else {
        log_action("Motor started forward");
    }
}

void motor_backward() {
    char in1_path[64];
    char in2_path[64];
    snprintf(in1_path, sizeof(in1_path), GPIO_VALUE_PATH_FORMAT, MOTOR_IN1_GPIO);
    snprintf(in2_path, sizeof(in2_path), GPIO_VALUE_PATH_FORMAT, MOTOR_IN2_GPIO);

    if (write_to_file(in1_path, "0") != 0 || write_to_file(in2_path, "1") != 0) {
        log_action("ERROR: Failed to start motor backward.");
    } else {
        log_action("Motor started backward");
    }
}

void motor_stop() {
    char in1_path[64];
    char in2_path[64];
    snprintf(in1_path, sizeof(in1_path), GPIO_VALUE_PATH_FORMAT, MOTOR_IN1_GPIO);
    snprintf(in2_path, sizeof(in2_path), GPIO_VALUE_PATH_FORMAT, MOTOR_IN2_GPIO);

    if (write_to_file(in1_path, "0") != 0 || write_to_file(in2_path, "0") != 0) {
        log_action("ERROR: Failed to stop motor.");
    } else {
        log_action("Motor stopped");
    }
}

// Window control functions
void close_window() {
    log_action("Closing window");
    motor_forward();
    sleep(MOTOR_TIMEOUT_SEC);
    motor_stop();
    log_action("Window close timeout");
}

void open_window() {
    log_action("Opening window");
    motor_backward();
    sleep(MOTOR_TIMEOUT_SEC);
    motor_stop();
    log_action("Window open timeout");
}

// Logging function
void log_action(const char *action) {
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[32];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", t);

    if (log_file != NULL) {
        fprintf(log_file, "%s: %s\n", timestamp, action);
        fflush(log_file); // Ensure immediate write
    } else {
        fprintf(stderr, "ERROR: Log file not initialized!\n");
    }
}

// Cleanup function
void cleanup() {
    motor_stop();

    char gpio_str[3];

    sprintf(gpio_str, "%d", RAIN_SENSOR_GPIO);
    write_to_file(GPIO_UNEXPORT_PATH, gpio_str);

    sprintf(gpio_str, "%d", MOTOR_IN1_GPIO);
    write_to_file(GPIO_UNEXPORT_PATH, gpio_str);

    sprintf(gpio_str, "%d", MOTOR_IN2_GPIO);
    write_to_file(GPIO_UNEXPORT_PATH, gpio_str);

    if (log_file != NULL) {
        fclose(log_file);
    }
    printf("Cleanup complete. Exiting.\n");
}

// Signal handler
void signal_handler(int signum) {
    if (signum == SIGINT) {
        printf("Caught SIGINT, exiting...\n");
        program_running = 0;
        cleanup(); // Call cleanup before exiting.
        exit(0);
    }
}

int main() {
    // Set up signal handling
    signal(SIGINT, signal_handler);

    // Initialize log file
    log_file = fopen(LOG_FILE_PATH, "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        return 1;
    }

    // Setup GPIO pins
    if (setup_gpio(RAIN_SENSOR_GPIO, "in") != 0) {
        log_action("ERROR: Failed to setup rain sensor GPIO");
        cleanup();
        return 1;
    }
    if (setup_gpio(MOTOR_IN1_GPIO, "out") != 0) {
        log_action("ERROR: Failed to setup motor IN1 GPIO");
        cleanup();
        return 1;
    }
    if (setup_gpio(MOTOR_IN2_GPIO, "out") != 0) {
        log_action("ERROR: Failed to setup motor IN2 GPIO");
        cleanup();
        return 1;
    }

    log_action("Program started");

    // Main loop
    while (program_running) {
        int rain_detected = read_rain_sensor();
        if (rain_detected == 0) {
            log_action("Rain detected");
            close_window();
        } else if (rain_detected > 0) {
           // printf("No rain detected\n");
           //open_window();
        } else {
            log_action("ERROR: Failed to read rain sensor");
        }
        sleep(5); // Check every 5 seconds
    }

    cleanup();
    return 0;
}

