int init_sds011(void)
{
    int fd;
    struct termios tty;

    // Open the serial port
    fd = open(SDS011_PORT, O_RDWR | O_NOCTTY | O_SYNC);
    if (fd < 0) {
        perror("Error opening serial port");
        return -1;
    }

    // Configure the serial port
    if (tcgetattr(fd, &tty) != 0) {
        perror("Error getting serial port attributes");
        close(fd);
        return -1;
    }

    tty.c_cflag = B9600 | CS8 | CLOCAL | CREAD;  // 9600 baud, 8-bit data, ignore modem control lines, enable receiver
    tty.c_iflag = IGNPAR;                         // Ignore parity errors
    tty.c_oflag = 0;                              // Raw output
    tty.c_lflag = 0;                              // Non-canonical mode

    tty.c_cc[VMIN] = 1;   // Read at least 1 character
    tty.c_cc[VTIME] = 5;  // Wait for 0.5 seconds

    if (tcsetattr(fd, TCSANOW, &tty) != 0) {
        perror("Error setting serial port attributes");
        close(fd);
        return -1;
    }

    // Set global file descriptor (bad practice, but quick and dirty for this example)
    return 0;
}

int read_sds011(float *pm25, float *pm10)
{
    int fd;
    unsigned char buffer[10];
    ssize_t bytes_read;

    // Open the serial port
    fd = open(SDS011_PORT, O_RDWR | O_NOCTTY | O_SYNC);
    if (fd < 0) {
        perror("Error opening serial port");
        return -1;
    }

    // Read data from the serial port
    bytes_read = read(fd, buffer, 10);
    close(fd);

    if (bytes_read != 10) {
        fprintf(stderr, "Error reading from serial port: %zd bytes read\n", bytes_read);
        return -1;
    }

    // Parse the data
    if (parse_sds011_data(buffer, pm25, pm10) != 0) {
        fprintf(stderr, "Error parsing SDS011 data.\n");
        return -1;
    }

    return 0;
}

int parse_sds011_data(unsigned char *data, float *pm25, float *pm10)
{
    if (data[0] != 0xAA || data[9] != 0xAB || data[1] != 0xC0) {
        fprintf(stderr, "Invalid SDS011 data frame.\n");
        return -1;
    }

    // Calculate checksum
    unsigned char checksum = 0;
    for (int i = 2; i < 8; i++) {
        checksum += data[i];
    }

    if (checksum != data[8]) {
        fprintf(stderr, "SDS011 checksum error.\n");
        return -1;
    }

    // Extract PM2.5 and PM10 values
    *pm25 = (float)((data[3] * 256) + data[2]) / 10.0;
    *pm10 = (float)((data[5] * 256) + data[4]) / 10.0;

    return 0;
}

int init_dht22(void)
{
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }

    gpioSetMode(DHT22_GPIO, PI_INPUT);
    return 0;
}

int read_dht22(float *temperature, float *humidity)
{
    int data[5] = {0, 0, 0, 0, 0};
    int laststate = PI_HIGH;
    int j = 0;

    gpioSetMode(DHT22_GPIO, PI_OUTPUT);
    gpioWrite(DHT22_GPIO, PI_LOW);
delay(1); // Reduced delay to 1 ms
    gpioWrite(DHT22_GPIO, PI_HIGH);
delayMicroseconds(30); // Reduced delay to 30 us
    gpioSetMode(DHT22_GPIO, PI_INPUT);

    // Read data
    for (int i = 0; i < 85; i++) {
        int count = 0;
        while (gpioRead(DHT22_GPIO) == laststate) {
            count++;
            delayMicroseconds(1);
            if (count > 255) {
                return -1; // Timeout
            }
        }
        laststate = gpioRead(DHT22_GPIO);

        if (i < 3) continue; // Skip the first 3 transitions

        if ((i % 2) == 0) {
            data[j / 8] <<= 1;
            if (count > 25) // Increased threshold to 25 us
                data[j / 8] |= 1;
            j++;
        }
    }

    if (j < 40) {
        return -1; // Not enough data transmitted
    }

    // Check validity
    if (data[4] != ((data[0] + data[1] + data[2] + data[3]) & 0xFF)) {
        return -1; // Checksum failure
    }

    // Convert data
    *humidity = (float)(((data[0] << 8) + data[1]) / 10.0);
    *temperature = (float)((((data[2] & 0x7F) << 8) + data[3]) / 10.0);
    if (data[2] & 0x80) {
        *temperature *= -1;
    }

    return 0;
}

int init_oled(void)
{
    wiringPiSetup();
    oled_fd = wiringPiI2CSetup(OLED_ADDRESS);
    if (oled_fd == -1) {
        fprintf(stderr, "Error initializing I2C communication.\n");
        return -1;
    }

    // Initialization sequence for SSD1306 (example, adjust for your OLED)
    oled_command(0xAE); // Display off
    oled_command(0xD5); // Set display clock divide ratio/oscillator frequency
    oled_command(0x80); // --ratio
    oled_command(0xA8); // Set multiplex ratio
    oled_command(0x3F); // --ratio
    oled_command(0xD3); // Set display offset
    oled_command(0x00); // --offset
    oled_command(0x40); // Set start line address
    oled_command(0x8D); // Set charge pump enable/disable
    oled_command(0x14); // --enable
    oled_command(0x20); // Set memory addressing mode
    oled_command(0x00); // --mode
    oled_command(0xA1); // Set segment re-map
    oled_command(0xC8); // Set COM output scan direction
    oled_command(0xDA); // Set COM pins hardware configuration
    oled_command(0x12); // --configuration
    oled_command(0x81); // Set contrast control
    oled_command(0xCF); // --contrast
    oled_command(0xD9); // Set pre-charge period
    oled_command(0xF1); // --period
    oled_command(0xDB); // Set VCOM deselect level
    oled_command(0x40); // --level
    oled_command(0xA4); // Set entire display on/off
    oled_command(0xA6); // Set normal/inverse display
    oled_command(0xAF); // Display on

    return 0;
}

void display_data_on_oled(float pm25, float pm10, float temperature, float humidity)
{
    char buffer[20];

    // Clear the display (optional, depends on your needs)
    for (int i = 0; i < 8; i++) {
        oled_set_cursor(i, 0);
        for (int j = 0; j < 21; j++) {
            oled_data(0x00); // Write blank data
        }
    }

    // Display PM2.5
    oled_print(0, 0, "PM2.5: ");
    if (pm25 >= 0) {
        sprintf(buffer, "%.1f ug/m3", pm25);
        oled_print(0, 8, buffer);
    } else {
        oled_print(0, 8, "N/A");
    }

    // Display PM10
    oled_print(1, 0, "PM10:  ");
    if (pm10 >= 0) {
        sprintf(buffer, "%.1f ug/m3", pm10);
        oled_print(1, 8, buffer);
    } else {
        oled_print(1, 8, "N/A");
    }

    // Display Temperature
    oled_print(2, 0, "Temp:  ");
    if (temperature > -99) {
        sprintf(buffer, "%.1f C", temperature);
        oled_print(2, 8, buffer);
    } else {
        oled_print(2, 8, "N/A");
    }

    // Display Humidity
    oled_print(3, 0, "Hum:   ");
    if (humidity >= 0) {
        sprintf(buffer, "%.1f %%", humidity);
        oled_print(3, 8, buffer);
    } else {
        oled_print(3, 8, "N/A");
    }
}

void oled_command(unsigned char command)
{
    wiringPiI2CWriteReg8(oled_fd, 0x00, command);
}

void oled_data(unsigned char data)
{
    wiringPiI2CWriteReg8(oled_fd, 0x40, data);
}

void oled_set_cursor(unsigned char row, unsigned char col)
{
    oled_command(0xB0 + row);                           // Set page address
    oled_command(0x00 + (col & 0x0F));                // Set lower column address
    oled_command(0x10 + ((col >> 4) & 0x0F));         // Set higher column address
}

void oled_print(unsigned char row, unsigned char col, char *text)
{
    int i, len;
    len = strlen(text);
    for (i = 0; i < len; i++) {
        oled_set_cursor(row, col + i);
        unsigned char character = text[i];
        if (character >= ' ' && character <= '~') {
            for (int j = 0; j < 5; j++) {
                oled_data(font[character - ' '][j]);
            }
            oled_data(0x00); // Add space between characters
        }
        else {
            for (int j = 0; j < 5; j++) {
                oled_data(0x00); // Print space if character not found
            }
            oled_data(0x00); // Add space between characters
        }
    }
}

void cleanup(int signal)
{
    printf("Cleaning up and exiting...\n");
    program_running = 0;
    gpioTerminate(); // Terminate pigpio
    exit(0);
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>

// Define GPIO pins for keypad rows and columns
#define ROW1 2
#define ROW2 3
#define ROW3 4
#define ROW4 5

#define COL1 8
#define COL2 9
#define COL3 10
#define COL4 11

// Define GPIO pin for buzzer
#define BUZZER_PIN 17

// Debounce delay in milliseconds
#define DEBOUNCE_DELAY 20

// Flag to indicate program termination
volatile sig_atomic_t terminate = 0;

// Signal handler for Ctrl+C
void signal_handler(int sig) {
    terminate = 1;
    fprintf(stderr, "\nCaught signal %d, terminating...\n", sig);
}

// Function to scan the keypad and return the pressed key (0-15) or -1 if no key is pressed
int scanKeypad() {
    // Set column pins as outputs and row pins as inputs
    gpioSetMode(COL1, PI_OUTPUT);
    gpioSetMode(COL2, PI_OUTPUT);
    gpioSetMode(COL3, PI_OUTPUT);
    gpioSetMode(COL4, PI_OUTPUT);

    gpioSetMode(ROW1, PI_INPUT);
    gpioSetMode(ROW2, PI_INPUT);
    gpioSetMode(ROW3, PI_INPUT);
    gpioSetMode(ROW4, PI_INPUT);

    gpioSetPullUpDown(ROW1, PI_PUD_UP);
    gpioSetPullUpDown(ROW2, PI_PUD_UP);
    gpioSetPullUpDown(ROW3, PI_PUD_UP);
    gpioSetPullUpDown(ROW4, PI_PUD_UP);

    // Scan each column
    for (int col = 0; col < 4; col++) {
        // Set the current column low
        gpioWrite(COL1 + col, 0);

        // Read the rows
        for (int row = 0; row < 4; row++) {
            if (gpioRead(ROW1 + row) == 0) {
                // Key pressed
                int key = row * 4 + col;

                // Debounce
                gpioDelay(DEBOUNCE_DELAY * 1000); // Convert ms to us

                // Verify key is still pressed
                if (gpioRead(ROW1 + row) == 0) {
                    // Reset the column
                    gpioWrite(COL1 + col, 1);
                    return key;
                }
            }
        }

        // Reset the column
        gpioWrite(COL1 + col, 1);
    }

    // No key pressed
    return -1;
}

// Function to map the key press value (0-15) to a frequency in Hz (C Major scale)
double mapKeyPressToFrequency(int key) {
    // C Major scale frequencies (approximate)
    double frequencies[] = {261.63, 293.66, 329.63, 349.23, 392.00, 440.00, 493.88, 523.25, 587.33, 659.25, 698.46, 783.99, 880.00, 987.77, 1046.50, 0.0}; // Add a 0 frequency for silence

    if (key >= 0 && key < 16) {
        return frequencies[key];
    } else {
        fprintf(stderr, "Invalid key press: %d\n", key);
        return 0.0; // Return 0 for invalid key presses (silence)
    }
}

// Function to play a note on the buzzer using PWM
void playNote(double frequency) {
    if (frequency > 0.0) {
        // Set PWM frequency
        int status = gpioSetPWMfrequency(BUZZER_PIN, (int)frequency);
        if (status != 0) {
            fprintf(stderr, "Error setting PWM frequency: %d\n", status);
            return;
        }

        // Set duty cycle (50%)
        gpioPWM(BUZZER_PIN, 128); // 128 for 50% duty cycle (0-255)
    } else {
        // Stop PWM to silence the buzzer
        gpioPWM(BUZZER_PIN, 0);
    }
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set buzzer pin as output
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);

    // Set PWM range (0-255)
    gpioSetPWMrange(BUZZER_PIN, 255);

    // Set PWM dutycycle to 0 initially
    gpioPWM(BUZZER_PIN, 0);

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Interactive Musical Instrument\n");
    printf("Press Ctrl+C to exit\n");

    while (!terminate) {
        // Scan the keypad
        int key = scanKeypad();

        if (key != -1) {
            // Map the key press to a frequency
            double frequency = mapKeyPressToFrequency(key);

            // Play the note
            playNote(frequency);

            // Wait a short time to avoid repeated notes
            gpioDelay(100 * 1000); // 100ms
        } else {
            // No key pressed, silence the buzzer
            playNote(0.0);
            gpioDelay(10 * 1000); // Small delay to avoid busy-waiting
        }
    }

    // Stop the buzzer
    playNote(0.0);

    // Terminate pigpio
    gpioTerminate();

    printf("Program terminated\n");
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>
#include <errno.h>

#define VALVE_GPIO 12
#define TEMP_FILE "/sys/class/thermal/thermal_zone0/temp"
#define DEFAULT_TEMP 25.0
#define PWM_FREQUENCY 1000  // Adjust as needed for the valve
#define MIN_TEMP 30.0
#define MAX_TEMP 70.0
#define MIN_PWM 0
#define MAX_PWM 255
#define LOG_FILE "valve_control.log"

static volatile int running = 1;
FILE *log_file;

// Function to read CPU temperature from file
float read_cpu_temp() {
    FILE *fp;
    int temp_raw;
    float temp_celsius;

    fp = fopen(TEMP_FILE, "r");
    if (fp == NULL) {
        fprintf(stderr, "Error opening temperature file: %s\n", strerror(errno));
        return DEFAULT_TEMP; // Return a default temperature
    }

    if (fscanf(fp, "%d", &temp_raw) != 1) {
        fprintf(stderr, "Error reading temperature from file\n");
        fclose(fp);
        return DEFAULT_TEMP;
    }

    fclose(fp);
    temp_celsius = (float)temp_raw / 1000.0;
    return temp_celsius;
}

// Function to set the valve opening using PWM
void set_valve_opening(int pwm_value) {
    if (pwm_value < 0 || pwm_value > MAX_PWM) {
        fprintf(stderr, "Invalid PWM value: %d. Clamping to 0-%d\n", pwm_value, MAX_PWM);
        if (pwm_value < 0) pwm_value = 0;
        if (pwm_value > MAX_PWM) pwm_value = MAX_PWM;
    }

    gpioPWM(VALVE_GPIO, pwm_value);
    fprintf(log_file, "PWM set to: %d\n", pwm_value);
    fflush(log_file);
}

// Function to map temperature to PWM value
int map_temperature_to_pwm(float temperature) {
    float pwm_float;

    if (temperature <= MIN_TEMP) {
        return MIN_PWM;
    } else if (temperature >= MAX_TEMP) {
        return MAX_PWM;
    }

    pwm_float = (temperature - MIN_TEMP) / (MAX_TEMP - MIN_TEMP) * (MAX_PWM - MIN_PWM) + MIN_PWM;
    return (int)pwm_float;
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    fprintf(log_file, "Received signal %d, shutting down...\n", signal);
    fflush(log_file);
    running = 0;
}

int main() {
    float temperature;
    int pwm_value;

    // Open log file
    log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        return 1;
    }

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(log_file, "pigpio initialisation failed\n");
        fprintf(stderr, "pigpio initialisation failed\n");
        fclose(log_file);
        return 1;
    }

    // Set GPIO mode for PWM output
    gpioSetMode(VALVE_GPIO, PI_OUTPUT);
    gpioSetPWMfrequency(VALVE_GPIO, PWM_FREQUENCY);
    gpioSetPWMrange(VALVE_GPIO, MAX_PWM); // Set PWM range to 0-255

    // Register signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    fprintf(log_file, "Valve control program started\n");
    fflush(log_file);

    while (running) {
        // Read CPU temperature
        temperature = read_cpu_temp();
        fprintf(log_file, "Temperature: %.2f C\n", temperature);
        fflush(log_file);

        // Map temperature to PWM value
        pwm_value = map_temperature_to_pwm(temperature);

        // Set valve opening
        set_valve_opening(pwm_value);

        // Wait for a short period
        sleep(1);
    }

    // Close valve before exiting
    set_valve_opening(MIN_PWM);

    // Terminate pigpio
    gpioTerminate();

    fprintf(log_file, "Valve control program stopped\n");
    fclose(log_file);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <signal.h>
#include <wiringPi.h>

#define RAIN_SENSOR_PIN 23
#define MOTOR_CONTROL_PIN 18

FILE *logFile;

// Function to log messages with timestamps
void logMessage(const char *message) {
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", t);
    fprintf(logFile, "[%s] %s\n", timestamp, message);
    fflush(logFile); // Ensure the log is written immediately
}

// Function to read the rain sensor value
int readRainSensor() {
    int retries = 3;
    while (retries > 0) {
        int value = digitalRead(RAIN_SENSOR_PIN);
        if (value != -1) { // digitalRead returns -1 on error
            return value;
        } else {
            retries--;
            delay(100); // Short delay before retrying
        }
    }

    // Log sensor read failure
    logMessage("Error: Failed to read rain sensor after multiple retries.");
    return -1; // Indicate sensor read failure
}

// Function to close the window
void closeWindow() {
    logMessage("Closing window...");
    digitalWrite(MOTOR_CONTROL_PIN, HIGH); // Activate motor to close window
    delay(5000); // Simulate closing for 5 seconds
    digitalWrite(MOTOR_CONTROL_PIN, LOW);  // Deactivate motor
    logMessage("Window closed.");
}

// Signal handler for graceful exit
void signalHandler(int signum) {
    if (signum == SIGINT) {
        logMessage("Received SIGINT. Closing log file and exiting.");
        if (logFile != NULL) {
            fclose(logFile);
        }
        exit(0);
    }
}

int main() {
    // Open the log file in append mode
    logFile = fopen("window_control.log", "a");
    if (logFile == NULL) {
        perror("Error opening log file");
        return 1;
    }

    // Initialize wiringPi using GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        logMessage("Error: Failed to initialize wiringPi.");
        fclose(logFile);
        return 1;
    }

    // Configure the rain sensor pin as input
    pinMode(RAIN_SENSOR_PIN, INPUT);

    // Configure the motor control pin as output
    pinMode(MOTOR_CONTROL_PIN, OUTPUT);
    digitalWrite(MOTOR_CONTROL_PIN, LOW); // Ensure motor is initially off

    // Set up signal handling for Ctrl+C
    signal(SIGINT, signalHandler);

    logMessage("Window control program started.");

    int failsafeCount = 0;
    while (1) {
        int sensorValue = readRainSensor();

        if (sensorValue == 0) {
            // Rain detected
            logMessage("Rain detected.");
            closeWindow();
            failsafeCount = 0; // Reset failsafe counter
        } else if (sensorValue == -1) {
            // Sensor read failure
            failsafeCount++;
            logMessage("Sensor read failure. Failsafe count: " + failsafeCount); // Concatenate int to string
            char message[100];
            snprintf(message, sizeof(message), "Sensor read failure. Failsafe count: %d", failsafeCount);
            logMessage(message);

            if (failsafeCount >= 3) {
                logMessage("Failsafe triggered: Sensor malfunction.");
                closeWindow();
                failsafeCount = 0; // Reset failsafe counter after failsafe
            }
        } else {
            // No rain detected
            failsafeCount = 0; // Reset failsafe counter
        }

        delay(10000); // Check every 10 seconds
    }

    // The program should never reach here due to the infinite loop, but it's good practice
    fclose(logFile);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
