#define RELAY_PIN 18 // BCM GPIO 18

void turn_on_pump() {
    printf("Turning pump ON\n");
    digitalWrite(RELAY_PIN, HIGH); // Assuming HIGH activates the relay
}

void turn_off_pump() {
    printf("Turning pump OFF\n");
    digitalWrite(RELAY_PIN, LOW); // Assuming LOW deactivates the relay
}

int main() {
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi setup failed!\n");
        return 1;
    }

    pinMode(RELAY_PIN, OUTPUT);
    turn_off_pump(); // Initialize with the pump OFF

    while (1) {
        time_t now = time(NULL);
        struct tm *currentTime = localtime(&now);

        // Calculate the minutes past the last 4-hour interval
        int minutes_past_interval = (currentTime->tm_hour % 4) * 60 + currentTime->tm_min;

        if (minutes_past_interval == 0) {
            turn_on_pump();
            sleep(30 * 60); // Run for 30 minutes (30 * 60 seconds)
            turn_off_pump();
        }

        sleep(60); // Check every minute
    }

    return 0;
}

