#define MIN_PULSE 12  // Minimum PWM value for 0 degree
#define MAX_PULSE 25  // Maximum PWM value for 180 degree

int main(void) {
  if (wiringPiSetup() == -1) {
    fprintf(stderr, "WiringPi setup failed!\n");
    return 1;
  }

  softPwmCreate(SERVO_PIN, 0, PWM_RANGE);

  while (1) {
    // Move to maximum position
    for (int i = MIN_PULSE; i <= MAX_PULSE; i++) {
      softPwmWrite(SERVO_PIN, i);
      delay(10); // Adjust delay for smooth movement
    }
    delay(1000); // Wait at max position

    // Move to minimum position
    for (int i = MAX_PULSE; i >= MIN_PULSE; i--) {
      softPwmWrite(SERVO_PIN, i);
      delay(10); // Adjust delay for smooth movement
    }
    delay(1000); // Wait at min position
  }

  return 0;
}

