void close_gate() {
    if (gate_open) {
        for (int pulse_width = OPEN_PULSE_WIDTH; pulse_width >= CLOSE_PULSE_WIDTH; pulse_width -= SERVO_SMOOTH_STEP) {
            set_servo_pulse_width(pulse_width);
            gpioDelay(5);
        }
        log_event("Gate Closed");
        gate_open = false;
    }
}

void control_gate(int distance) {
    if (distance < DISTANCE_THRESHOLD_OPEN && !gate_open) {
        open_gate();
    } else if (distance > DISTANCE_THRESHOLD_CLOSE && gate_open) {
        close_gate();
    }
}

void log_event(const char *event) {
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(log_file, "%d-%02d-%02d %02d:%02d:%02d: %s\n", tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, event);
    fflush(log_file); // Ensure immediate write to file
}

void signal_handler(int signal) {
    fprintf(log_file, "Caught signal %d, exiting gracefully.\n", signal);
    i2cClose(i2c_handle);
    gpioTerminate();
    fclose(log_file);
    exit(0);
}

