// Define GPIO pins
const int MOTION_SENSOR_PIN = 17;
const int RELAY_PIN = 27;

// Global flag to signal program termination
volatile sig_atomic_t program_running = 1;

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    std::cout << "\nCaught signal " << signal << ", exiting gracefully..." << std::endl;
    program_running = 0;
}

// MotionSensor class
class MotionSensor {
public:
    MotionSensor(int pin) : sensor_pin(pin) {
        // Initialize pigpio library
        if (gpioInitialise() < 0) {
            std::cerr << "pigpio initialisation failed" << std::endl;
            exit(1); // Exit if initialization fails
        }

        // Set GPIO pin as input
        gpioSetMode(sensor_pin, PI_INPUT);
        std::cout << "Motion sensor initialized on GPIO " << sensor_pin << std::endl;
    }

    ~MotionSensor() {
        // No need to terminate pigpio here, it's done in main.
    }

    bool isMotionDetected() {
        // Read the sensor's state
        int sensorValue = gpioRead(sensor_pin);
        return (sensorValue == 1); // Assuming HIGH (1) indicates motion
    }

private:
    int sensor_pin;
};

// DoorStrike class
class DoorStrike {
public:
    DoorStrike(int pin) : relay_pin(pin) {
        // Set GPIO pin as output
        gpioSetMode(relay_pin, PI_OUTPUT);
        gpioWrite(relay_pin, 0); // Ensure relay is initially off
        std::cout << "Door strike initialized on GPIO " << relay_pin << std::endl;
    }

    ~DoorStrike() {
        // Ensure relay is off when the object is destroyed.
        gpioWrite(relay_pin, 0);
    }

    void unlock() {
        std::cout << "Unlocking door..." << std::endl;
        gpioWrite(relay_pin, 1); // Activate relay (unlock)
        gpioDelay(2000);          // Wait for 2 seconds
        gpioWrite(relay_pin, 0); // Deactivate relay (lock)
        std::cout << "Door locked." << std::endl;
    }

private:
    int relay_pin;
};

int main() {
    // Set up signal handling for Ctrl+C
    signal(SIGINT, signal_handler);

    // Instantiate MotionSensor and DoorStrike objects
    MotionSensor motionSensor(MOTION_SENSOR_PIN);
    DoorStrike doorStrike(RELAY_PIN);

    // Main loop
    while (program_running) {
        if (motionSensor.isMotionDetected()) {
            std::cout << "Motion detected!" << std::endl;
            doorStrike.unlock();
            gpioDelay(5000); // Delay after unlocking to prevent immediate re-trigger
        }
        gpioDelay(500); // Delay to prevent excessive CPU usage
    }

    // Clean up and exit
    gpioTerminate();
    std::cout << "Program terminated gracefully." << std::endl;
    return 0;
}

