    wiringPiI2CWriteReg16(fd, CONFIG_REG, (config >> 8) | ((config & 0xFF) << 8));
    usleep(9000);
    int val = wiringPiI2CReadReg16(fd, CONVERSION_REG);
    return ((val << 8) & 0xFF00) | ((val >> 8) & 0x00FF);
}
