        if (ch < 0 || ch > 3) {
            printf("Invalid channel.\n");
            continue;
        }
        int val = read_ads_channel(fd, ch);
        double v = val * REF_VOLTAGE / 32768.0;
        printf("CH%d: %.4f V\n", ch, v);
    }
    return 0;
}

