#define BUZZER_PIN 18 // BCM GPIO 18
#define BUTTON_PIN 22 // BCM GPIO 22

// Define musical notes and durations
#define NOTE_C4  262
#define NOTE_D4  294
#define NOTE_E4  330
#define NOTE_F4  349
#define NOTE_G4  392
#define NOTE_A4  440
#define NOTE_B4  494
#define NOTE_C5  523

#define QUARTER_NOTE 500 // milliseconds
#define HALF_NOTE    1000
#define EIGHTH_NOTE 250

// Function to play a tone
void playTone(int frequency, int duration) {
  if (frequency == 0) {
    delay(duration);
  } else {
    int period = 1000000 / frequency; // Period in microseconds
    int pulse = period / 2;             // Pulse width (50% duty cycle)
    long startTime = millis();           // Record start time

    while (millis() - startTime < duration) {
      digitalWrite(BUZZER_PIN, HIGH);
      delayMicroseconds(pulse);
      digitalWrite(BUZZER_PIN, LOW);
      delayMicroseconds(pulse);
    }
  }
}

int main() {
  wiringPiSetupGpio(); // Use BCM GPIO numbering

  pinMode(BUZZER_PIN, OUTPUT);
  pinMode(BUTTON_PIN, INPUT);
  pullUpDnControl(BUTTON_PIN, PUD_UP); // Enable pull-up resistor

  printf("Press button to play melody...\n");

  while (1) {
    if (digitalRead(BUTTON_PIN) == LOW) { // Button is pressed (active low)
      printf("Playing melody...\n");

      // Play a simple melody
      playTone(NOTE_C4, QUARTER_NOTE);
      playTone(NOTE_D4, QUARTER_NOTE);
      playTone(NOTE_E4, QUARTER_NOTE);
      playTone(NOTE_F4, QUARTER_NOTE);
      playTone(NOTE_G4, QUARTER_NOTE);
      playTone(0, QUARTER_NOTE); // Rest
      playTone(NOTE_G4, QUARTER_NOTE);
      playTone(NOTE_F4, QUARTER_NOTE);
      playTone(NOTE_E4, QUARTER_NOTE);
      playTone(NOTE_D4, QUARTER_NOTE);
      playTone(NOTE_C4, QUARTER_NOTE);

      printf("Melody finished.\n");
      delay(200); // Small delay to avoid multiple triggers

    } else {
      digitalWrite(BUZZER_PIN, LOW); // Ensure buzzer is off when button isn't pressed.
      delay(10); // Small delay to reduce CPU usage
    }
  }

  return 0;
}

