#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <wiringPi.h>
#include <wiringPiSPI.h>
#include <signal.h>
#include <time.h>
#include <errno.h>
#include <string.h>

// Define constants
#define SPI_CHANNEL 0
#define SPI_SPEED 500000 // 500kHz
#define HEATER_GPIO 17
#define PWM_RANGE 1000
#define DEFAULT_SETPOINT 25.0
#define SETPOINT_FILE "/etc/heater_setpoint"
#define LOG_FILE "heater_log.txt"

// MAX31865 Registers
#define MAX31865_CONFIG_REG 0x00
#define MAX31865_RTD_MSB_REG 0x01
#define MAX31865_RTD_LSB_REG 0x02
#define MAX31865_FAULT_REG 0x03

// RTD Nominal Resistance and Reference Resistor
#define RREF 430.0
#define RNOMINAL 100.0

// PI Controller Gains
#define KP 100.0
#define KI 0.1

// Global variables (minimize usage)
volatile sig_atomic_t program_running = 1;

// Function prototypes
float read_temperature();
float read_setpoint();
void set_pwm(int duty_cycle);
float run_pi_controller(float setpoint, float current_temperature, float *integral, float dt);
void log_data(float temperature, int duty_cycle);
void signal_handler(int signal);
int spi_transfer(uint8_t address, uint8_t *data, int len);

// Signal handler to ensure graceful shutdown
void signal_handler(int signal) {
    printf("\nCaught signal %d, shutting down...\n", signal);
    program_running = 0;
    set_pwm(0); // Turn off heater
}

// SPI transfer function
int spi_transfer(uint8_t address, uint8_t *data, int len) {
    uint8_t buf[len + 1];
    buf[0] = address;
    for (int i = 0; i < len; i++) {
        buf[i + 1] = data[i];
    }

    wiringPiSPIDataRW(SPI_CHANNEL, buf, len + 1);

    for (int i = 0; i < len; i++) {
        data[i] = buf[i + 1];
    }
    return 0; // Simplifed: Add proper error handling for production code
}

// Function to read temperature from MAX31865
float read_temperature() {
    uint8_t config_write[] = {0xC0}; // Enable VBIAS, auto conversion, 50/60 Hz filter
    uint8_t rtd_data[2] = {0, 0};
    float rtd_resistance, temperature;

    // Write configuration register
    if (spi_transfer(MAX31865_CONFIG_REG | 0x80, config_write, 1) != 0) {
        fprintf(stderr, "Error writing to config register\n");
        return -273.15; // Return absolute zero on error
    }

    // Read RTD MSB and LSB registers
    if (spi_transfer(MAX31865_RTD_MSB_REG, rtd_data, 2) != 0) {
        fprintf(stderr, "Error reading RTD registers\n");
        return -273.15;
    }

    // Combine RTD data
    uint16_t rtd_raw = (rtd_data[0] << 8) | rtd_data[1];
    rtd_raw = rtd_raw >> 1; // Remove fault bit

    // Convert RTD reading to resistance (refer to MAX31865 datasheet)
    rtd_resistance = ((float)rtd_raw / 32768.0) * RREF;

    // Convert resistance to temperature (using simplified linear approximation)
    temperature = (rtd_resistance - RNOMINAL) / (RNOMINAL * 0.00385); // Linear approximation for PT100

    return temperature;
}

// Function to read setpoint from file
float read_setpoint() {
    FILE *fp = fopen(SETPOINT_FILE, "r");
    if (fp == NULL) {
        fprintf(stderr, "Error opening setpoint file: %s, using default setpoint %.2f\n", strerror(errno), DEFAULT_SETPOINT);
        return DEFAULT_SETPOINT;
    }

    float setpoint;
    if (fscanf(fp, "%f", &setpoint) != 1) {
        fprintf(stderr, "Error reading setpoint from file, using default setpoint %.2f\n", DEFAULT_SETPOINT);
        fclose(fp);
        return DEFAULT_SETPOINT;
    }

    fclose(fp);
    return setpoint;
}

// Function to set PWM duty cycle
void set_pwm(int duty_cycle) {
    if (duty_cycle < 0) duty_cycle = 0;
    if (duty_cycle > PWM_RANGE) duty_cycle = PWM_RANGE;
    pwmWrite(HEATER_GPIO, duty_cycle);
}

// Function to run PI controller
float run_pi_controller(float setpoint, float current_temperature, float *integral, float dt) {
    float error = setpoint - current_temperature;
    *integral += error * dt;

    // Limit integral term to prevent windup
    float integral_limit = 100.0; // Adjust as needed
    if (*integral > integral_limit) *integral = integral_limit;
    if (*integral < -integral_limit) *integral = -integral_limit;

    float output = KP * error + KI * (*integral);

    // Scale output to PWM range (0-1000)
    return output;
}

// Function to log data to file
void log_data(float temperature, int duty_cycle) {
    FILE *fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(fp, "%d-%02d-%02d %02d:%02d:%02d, Temperature: %.2f, Duty Cycle: %d\n",
            tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec,
            temperature, duty_cycle);

    fclose(fp);
}

int main() {
    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
        return 1;
    }

    // Initialize SPI
    if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) == -1) {
        fprintf(stderr, "Error initializing SPI: %s\n", strerror(errno));
        return 1;
    }

    // Configure heater GPIO as PWM output
    pinMode(HEATER_GPIO, PWM_OUTPUT);
    pwmSetMode(PWM_MODE_MS);
    pwmSetRange(PWM_RANGE);
    pwmSetClock(192); // Adjust clock for desired PWM frequency (e.g., 50Hz)

    // Read setpoint from file
    float setpoint = read_setpoint();
    printf("Setpoint: %.2f\n", setpoint);

    // Initialize PI controller
    float integral = 0.0;
    float dt = 5.0; // Time interval between controller updates (seconds)

    // Set up signal handler
    signal(SIGINT, signal_handler);

    // Main loop
    while (program_running) {
        // Read temperature
        float current_temperature = read_temperature();
        if (current_temperature < -200) {
            fprintf(stderr, "Error reading temperature, skipping control loop\n");
            delay(5000);
            continue;
        }

        // Run PI controller
        float output = run_pi_controller(setpoint, current_temperature, &integral, dt);

        // Set PWM duty cycle
        int duty_cycle = (int)output;
        set_pwm(duty_cycle);

        // Log data
        log_data(current_temperature, duty_cycle);

        // Print current state to console
        printf("Temperature: %.2f, Duty Cycle: %d\n", current_temperature, duty_cycle);

        // Wait for next iteration
        delay(5000); // 5 seconds
    }

    return 0;
}

