// Function to display a digit on the seven-segment display
void displayDigit(int digit) {
  switch (digit) {
    case 2:
      digitalWrite(SEG_A, HIGH); // a
      digitalWrite(SEG_B, HIGH); // b
      digitalWrite(SEG_C, LOW);  // c
      digitalWrite(SEG_D, HIGH); // d
      digitalWrite(SEG_E, HIGH); // e
      digitalWrite(SEG_F, LOW);  // f
      digitalWrite(SEG_G, HIGH); // g
      break;
    case 8:
      digitalWrite(SEG_A, HIGH); // a
      digitalWrite(SEG_B, HIGH); // b
      digitalWrite(SEG_C, HIGH); // c
      digitalWrite(SEG_D, HIGH); // d
      digitalWrite(SEG_E, HIGH); // e
      digitalWrite(SEG_F, HIGH); // f
      digitalWrite(SEG_G, HIGH); // g
      break;
    default:
      // Turn off all segments if the digit is invalid
      digitalWrite(SEG_A, LOW);
      digitalWrite(SEG_B, LOW);
      digitalWrite(SEG_C, LOW);
      digitalWrite(SEG_D, LOW);
      digitalWrite(SEG_E, LOW);
      digitalWrite(SEG_F, LOW);
      digitalWrite(SEG_G, LOW);
      break;
  }
}

int main() {
  if (wiringPiSetup() == -1) {
    fprintf(stderr, "WiringPi setup failed!\n");
    return 1;
  }

  // Set the segment pins as output
  pinMode(SEG_A, OUTPUT);
  pinMode(SEG_B, OUTPUT);
  pinMode(SEG_C, OUTPUT);
  pinMode(SEG_D, OUTPUT);
  pinMode(SEG_E, OUTPUT);
  pinMode(SEG_F, OUTPUT);
  pinMode(SEG_G, OUTPUT);

  // Set the button pin as input with pull-up resistor
  pinMode(BUTTON_PIN, INPUT);
  pullUpDnControl(BUTTON_PIN, PUD_UP);

  int currentDigit = 2;
  int buttonState = 0; // Variable to store the previous button state

  while (1) {
    // Read the button state
    int newButtonState = digitalRead(BUTTON_PIN);

    // Check if the button is pressed (falling edge)
    if (newButtonState == LOW && buttonState == HIGH) {
      // Toggle the digit
      if (currentDigit == 2) {
        currentDigit = 8;
      } else {
        currentDigit = 2;
      }
      // Debounce delay
      delay(200); // Debounce delay to prevent multiple toggles
    }

    // Update the button state
    buttonState = newButtonState;

    // Display the current digit
    displayDigit(currentDigit);

    delay(50); // Small delay for responsiveness
  }

  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Configuration
#define SPI_CHANNEL 0  // CE0
#define SPI_BAUD 500000
#define FAN_GPIO 18
#define PWM_FREQUENCY 1000 // Hz
#define PWM_RANGE 255
#define LOG_BUFFER_SIZE 100

// Temperature thresholds (Celsius)
#define TEMP_LOW 40
#define TEMP_MEDIUM 50
#define TEMP_HIGH 60

// Global variables (minimize usage)
static volatile int running = 1;
int spi_handle;

// Structure for log entries
typedef struct {
    time_t timestamp;
    char message[128];
} LogEntry;

// Circular buffer structure
typedef struct {
    LogEntry buffer[LOG_BUFFER_SIZE];
    int head;
    int tail;
    int count;
} CircularBuffer;

CircularBuffer log_buffer;

// Function prototypes
void initialize_gpio();
int initialize_spi();
void cleanup();
double read_temperature();
int control_fan(double temperature);
void add_log_entry(const char *message);
void print_log_buffer();
void signal_handler(int signal);
void init_circular_buffer(CircularBuffer *cb);
int is_circular_buffer_full(CircularBuffer *cb);
int is_circular_buffer_empty(CircularBuffer *cb);
int add_to_circular_buffer(CircularBuffer *cb, LogEntry data);
int remove_from_circular_buffer(CircularBuffer *cb, LogEntry *data);

// Initialize circular buffer
void init_circular_buffer(CircularBuffer *cb) {
    cb->head = 0;
    cb->tail = 0;
    cb->count = 0;
}

// Check if the circular buffer is full
int is_circular_buffer_full(CircularBuffer *cb) {
    return cb->count == LOG_BUFFER_SIZE;
}

// Check if the circular buffer is empty
int is_circular_buffer_empty(CircularBuffer *cb) {
    return cb->count == 0;
}

// Add data to the circular buffer
int add_to_circular_buffer(CircularBuffer *cb, LogEntry data) {
    if (is_circular_buffer_full(cb)) {
        // Buffer is full, overwrite the oldest entry
        cb->tail = (cb->tail + 1) % LOG_BUFFER_SIZE;
    }

    cb->buffer[cb->head] = data;
    cb->head = (cb->head + 1) % LOG_BUFFER_SIZE;

    if (cb->count < LOG_BUFFER_SIZE) {
        cb->count++;
    }

    return 0; // Success
}

// Remove data from the circular buffer
int remove_from_circular_buffer(CircularBuffer *cb, LogEntry *data) {
    if (is_circular_buffer_empty(cb)) {
        return -1; // Buffer is empty
    }

    *data = cb->buffer[cb->tail];
    cb->tail = (cb->tail + 1) % LOG_BUFFER_SIZE;
    cb->count--;

    return 0; // Success
}


int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Initialize GPIO and SPI
    initialize_gpio();
    if (initialize_spi() != 0) {
        cleanup();
        return 1;
    }

    // Initialize circular buffer
    init_circular_buffer(&log_buffer);

    // Set up signal handling
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Main loop
    while (running) {
        double temperature = read_temperature();
        if (temperature != -999.0) { // Valid temperature reading
            control_fan(temperature);
            char log_message[128];
            snprintf(log_message, sizeof(log_message), "Temperature: %.2f C", temperature);
            add_log_entry(log_message);
        } else {
            add_log_entry("Error reading temperature");
        }

        gpioDelay(1000); // Wait 1 second
    }

    // Cleanup and exit
    cleanup();
    printf("Program terminated gracefully.\n");
    return 0;
}

// Initialize GPIO
void initialize_gpio() {
    gpioSetMode(FAN_GPIO, PI_OUTPUT);
    gpioSetPWMfrequency(FAN_GPIO, PWM_FREQUENCY);
    gpioSetPWMrange(FAN_GPIO, PWM_RANGE);
    gpioPWM(FAN_GPIO, 0); // Initially turn off the fan
    printf("GPIO initialized.\n");
}

// Initialize SPI
int initialize_spi() {
    spi_handle = spiOpen(SPI_CHANNEL, SPI_BAUD, 0); // Mode 0
    if (spi_handle < 0) {
        fprintf(stderr, "SPI open failed: %d\n", spi_handle);
        return 1;
    }
    printf("SPI initialized.\n");
    return 0;
}

// Cleanup resources
void cleanup() {
    printf("Cleaning up...\n");
    gpioPWM(FAN_GPIO, 0); // Turn off fan
    if(spi_handle >= 0) {
      spiClose(spi_handle);
    }
    gpioTerminate();
    printf("Cleanup complete.\n");
}

// Read temperature from MAX31855
double read_temperature() {
    unsigned char raw_data[4];
    int status;

    status = spiRead(spi_handle, (char *)raw_data, 4);
    if (status < 0) {
        fprintf(stderr, "SPI read failed: %d\n", status);
        return -999.0;
    }

    // Check for fault conditions
    if (raw_data[3] & 0x04) {
        add_log_entry("Thermocouple open circuit");
        return -999.0;
    }
    if (raw_data[3] & 0x02) {
        add_log_entry("Thermocouple shorted to VCC");
        return -999.0;
    }
    if (raw_data[3] & 0x01) {
        add_log_entry("Thermocouple shorted to GND");
        return -999.0;
    }

    // Extract temperature data
    int16_t thermocouple_data = ((raw_data[0] << 8) | raw_data[1]) >> 2;

    // Convert to Celsius
    double temperature = thermocouple_data * 0.25;

    return temperature;
}

// Control fan speed based on temperature
int control_fan(double temperature) {
    int duty_cycle = 0;

    if (temperature < TEMP_LOW) {
        duty_cycle = 0; // Fan off
    } else if (temperature < TEMP_MEDIUM) {
        duty_cycle = PWM_RANGE * 0.5; // Fan at 50%
    } else if (temperature < TEMP_HIGH) {
        duty_cycle = PWM_RANGE * 0.75; // Fan at 75%
    } else {
        duty_cycle = PWM_RANGE; // Fan at 100%
    }

    gpioPWM(FAN_GPIO, duty_cycle);
    return 0;
}

// Add a log entry to the circular buffer
void add_log_entry(const char *message) {
    LogEntry entry;
    time(&entry.timestamp);
    strncpy(entry.message, message, sizeof(entry.message) - 1);
    entry.message[sizeof(entry.message) - 1] = '\0'; // Ensure null termination
    add_to_circular_buffer(&log_buffer, entry);

    // Optional: Print the log entry to the console
    time_t now = time(NULL);
    struct tm *tstruct = localtime(&now);
    char buf[80];
    strftime(buf, sizeof(buf), "%Y-%m-%d.%X", tstruct);
    printf("[%s] %s\n", buf, message);
}

// Print the contents of the log buffer (for debugging)
void print_log_buffer() {
    LogEntry entry;
    int original_tail = log_buffer.tail;
    int original_count = log_buffer.count;

    printf("Log Buffer Contents:\n");
    for (int i = 0; i < original_count; ++i) {
        if (remove_from_circular_buffer(&log_buffer, &entry) == 0) {
            time_t now = entry.timestamp;
            struct tm *tstruct = localtime(&now);
            char buf[80];
            strftime(buf, sizeof(buf), "%Y-%m-%d.%X", tstruct);
            printf("  [%s] %s\n", buf, entry.message);
        } else {
            printf("  Error retrieving log entry\n");
            break;
        }
    }

    // Restore the original state of the circular buffer
    log_buffer.tail = original_tail;
    log_buffer.count = original_count;
}

// Signal handler to catch Ctrl+C and terminate gracefully
void signal_handler(int signal) {
    printf("Signal caught (%d).  Exiting...\n", signal);
    running = 0;
}

#include <stdio.h>
#include <pigpio.h>
#include <signal.h>
#include <stdlib.h>

// Define GPIO pins
#define TRIGGER_PIN 23
#define ECHO_PIN 24
#define SERVO_PIN 18

// Constants
#define SPEED_OF_SOUND 34300.0 // Speed of sound in cm/s
#define MIN_DISTANCE 20.0      // Minimum distance (cm)
#define MAX_DISTANCE 200.0     // Maximum distance (cm)
#define TIMEOUT_US 50000        // Timeout in microseconds (50ms)

// Global variable for graceful exit
volatile int running = 1;

// Signal handler for Ctrl+C
void signalHandler(int signum) {
    (void)signum; // Suppress unused parameter warning
    running = 0;
    fprintf(stderr, "\nExiting gracefully...\n");
}

// Function to trigger the ultrasonic sensor
void triggerSensor() {
    gpioWrite(TRIGGER_PIN, 1);
    gpioDelay(10); // 10us pulse
    gpioWrite(TRIGGER_PIN, 0);
}

// Function to measure distance in centimeters
float getDistance() {
    long long startTick, endTick;

    gpioSetMode(ECHO_PIN, PI_INPUT);
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);

    // Wait for echo pin to go high (or timeout)
    int count = 0;
    while (gpioRead(ECHO_PIN) == 0) {
        startTick = gpioTick();
        if (count++ > TIMEOUT_US) {
            fprintf(stderr, "Error: Timeout waiting for echo start\n");
            return -1.0;
        }
        gpioDelay(1); // Small delay to avoid busy-waiting
    }
    startTick = gpioTick();

    // Wait for echo pin to go low (or timeout)
    count = 0;
    while (gpioRead(ECHO_PIN) == 1) {
        endTick = gpioTick();
        if (count++ > TIMEOUT_US) {
            fprintf(stderr, "Error: Timeout waiting for echo end\n");
            return -1.0;
        }
        gpioDelay(1); // Small delay to avoid busy-waiting
    }
    endTick = gpioTick();

    // Calculate pulse duration in microseconds
    float pulseDuration = (float)(endTick - startTick) / 1000000.0;

    // Calculate distance in centimeters
    float distance = (pulseDuration * SPEED_OF_SOUND) / 2.0;

    return distance;
}

// Function to set the servo angle
void setServoAngle(int angle) {
    if (angle >= 0 && angle <= 180) {
        // Map angle (0-180) to pulse width (500-2500 us).  Empirical values may differ.
        int pulseWidth = (int)(500 + (angle / 180.0) * 2000);
        gpioServo(SERVO_PIN, pulseWidth);
    } else {
        fprintf(stderr, "Error: Invalid servo angle: %d\n", angle);
    }
}

// Function to map distance to servo angle
int mapDistanceToAngle(float distance) {
    if (distance < MIN_DISTANCE) {
        return 0; // Clamp to 0 degrees
    } else if (distance > MAX_DISTANCE) {
        return 180; // Clamp to 180 degrees
    } else {
        // Linear mapping from 20cm-200cm to 0-180 degrees
        return (int)(((distance - MIN_DISTANCE) / (MAX_DISTANCE - MIN_DISTANCE)) * 180.0);
    }
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Set signal handler for Ctrl+C
    signal(SIGINT, signalHandler);

    // Set servo pin as output
    gpioSetMode(SERVO_PIN, PI_OUTPUT);

    // Main loop
    while (running) {
        // Trigger the sensor
        triggerSensor();

        // Get the distance
        float distance = getDistance();

        // Handle errors
        if (distance < 0) {
            fprintf(stderr, "Error: Distance measurement failed\n");
        } else {
            // Map distance to servo angle
            int angle = mapDistanceToAngle(distance);

            // Set the servo angle
            setServoAngle(angle);

            // Print distance and angle (for debugging)
            printf("Distance: %.2f cm, Angle: %d degrees\n", distance, angle);
        }

        // Delay before next measurement
        gpioDelay(100); // 100ms delay
    }

    // Stop servo
    gpioServo(SERVO_PIN, 0); // Stop servo movement

    // Terminate pigpio library
    gpioTerminate();

    return 0;
}

