#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <time.h>
#include <unistd.h>
#include <math.h>
// Assuming using a MCP3008 ADC connected via SPI
#include <wiringPi.h>
#include <wiringPiSPI.h>

// Define MCP3008 configuration
#define SPI_CHANNEL 0
#define SPI_SPEED 1000000 // 1 MHz

// Define ADC channel to read (0-7 for MCP3008)
#define ADC_CHANNEL 0

// Low-pass filter parameters
#define ALPHA 0.1 // Smoothing factor (0 < ALPHA < 1)

// Function to read ADC value from MCP3008
int read_mcp3008(int channel)
{
    unsigned char buffer[3];
    buffer[0] = 0x01; // Start bit
    buffer[1] = ((channel & 0x07) << 4) | 0x80; // Single-ended mode, channel select
    buffer[2] = 0x00;

    wiringPiSPIDataRW(SPI_CHANNEL, buffer, 3);

    int adc_value = ((buffer[1] & 0x03) << 8) + buffer[2];

    return adc_value;
}

int main()
{
    // Initialize wiringPi and SPI
    if (wiringPiSetup() == -1)
    {
        fprintf(stderr, "wiringPiSetup failed\n");
        return 1;
    }

    if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) == -1)
    {
        fprintf(stderr, "wiringPiSPISetup failed\n");
        return 1;
    }

    float filtered_value = 0.0; // Initialize filtered value
    float raw_value;

    while (1)
    {
        // Read raw ADC value
        int adc_value = read_mcp3008(ADC_CHANNEL);
        raw_value = (float)adc_value;

        // Apply low-pass filter
        filtered_value = ALPHA * raw_value + (1 - ALPHA) * filtered_value;

        // Print raw and filtered values
        printf("Raw: %d, Filtered: %.2f\n", adc_value, filtered_value);

        // Delay for a short period
        delay(100); // 100 ms delay
    }

    return 0;
}

