#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <signal.h>
#include <unistd.h>
#include <errno.h>
#include <wiringPi.h>

#define FAN_PIN 18
#define TEMP_FILE "/sys/class/thermal/thermal_zone0/temp"
#define PWM_RANGE 100
#define SLEEP_MS 5000

volatile sig_atomic_t program_running = 1;

// Function to read CPU temperature from file
int readTemperature() {
    FILE *fp;
    char temp_str[10];
    int temperature;

    fp = fopen(TEMP_FILE, "r");
    if (fp == NULL) {
        fprintf(stderr, "Error: Failed to open temperature file (%s): %s\n", TEMP_FILE, strerror(errno));
        return -1; // Indicate error
    }

    if (fgets(temp_str, sizeof(temp_str), fp) == NULL) {
        fprintf(stderr, "Error: Failed to read temperature from file: %s\n", strerror(errno));
        fclose(fp);
        return -1; // Indicate error
    }

    fclose(fp);

    temperature = atoi(temp_str);
    if (temperature == 0 && temp_str[0] != '0') {
        fprintf(stderr, "Error: Invalid temperature value: %s\n", temp_str);
        return -1; // Indicate error
    }

    return temperature;
}

// Function to set fan speed using PWM
void setFanSpeed(int pwmValue) {
    if (pwmValue < 0 || pwmValue > PWM_RANGE) {
        fprintf(stderr, "Error: Invalid PWM value: %d.  Must be between 0 and %d\n", pwmValue, PWM_RANGE);
        return;
    }
    pwmWrite(FAN_PIN, pwmValue);
}

// Function to map temperature to PWM value
int mapTemperatureToPWM(int temperature) {
    int pwmValue;

    if (temperature < 40000) { // Below 40°C
        pwmValue = 0;
    } else if (temperature < 60000) { // 40°C - 60°C
        pwmValue = (int)(((float)(temperature - 40000) / 20000.0) * 50.0);
    } else if (temperature < 80000) { // 60°C - 80°C
        pwmValue = (int)(((float)(temperature - 60000) / 20000.0) * 50.0 + 50.0);
    } else { // Above 80°C
        pwmValue = PWM_RANGE;
    }

    return pwmValue;
}

// Signal handler for graceful shutdown
void signalHandler(int signal) {
    printf("Caught signal %d, exiting gracefully...\n", signal);
    program_running = 0;
    setFanSpeed(0); // Turn off the fan
    exit(0);
}

int main() {
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error: Failed to initialize wiringPi: %s\n", strerror(errno));
        return 1;
    }

    pinMode(FAN_PIN, PWM_OUTPUT);
    pwmSetRange(PWM_RANGE);

    signal(SIGINT, signalHandler);
    signal(SIGTERM, signalHandler);

    printf("CPU Temperature Controlled Fan Started. Press Ctrl+C to exit.\n");

    while (program_running) {
        int temperature = readTemperature();
        if (temperature == -1) {
            fprintf(stderr, "Error: Failed to read temperature.  Retrying in %d ms.\n", SLEEP_MS);
        } else {
            int pwmValue = mapTemperatureToPWM(temperature);
            setFanSpeed(pwmValue);
            printf("Temperature: %d m°C, PWM: %d\n", temperature, pwmValue);
        }

        delay(SLEEP_MS);
    }

    return 0;
}

