void lcd_send_nibble(uint8_t nibble, int rs);

// Initialize LCD
int lcd_init() {
  // Initialize wiringPi I2C
  if ((i2c_fd = wiringPiI2CSetup(LCD_ADDR)) < 0) {
    fprintf(stderr, "Error: Failed to initialize I2C communication.\n");
    return -1;
  }

  // Initialization sequence
  lcd_send_command(0x33); // Initialize
  usleep(5000);           // Wait 5ms
  lcd_send_command(0x32); // Initialize
  usleep(5000);           // Wait 5ms
  lcd_send_command(0x28); // 4-bit mode, 2 lines, 5x8 font
  usleep(5000);           // Wait 5ms
  lcd_send_command(LCD_DISPLAYCONTROL | LCD_DISPLAYON); // Display on, cursor off, blink off
  usleep(5000);           // Wait 5ms
  lcd_clear();              // Clear display
  usleep(5000);           // Wait 5ms
  lcd_send_command(LCD_ENTRYMODESET | LCD_ENTRYLEFT);   // Set entry mode
  usleep(5000);           // Wait 5ms
  lcd_backlight(1); //Turn on backlight

  return 0;
}

// Send command to LCD
void lcd_send_command(uint8_t command) {
  lcd_send_nibble(command >> 4, 0);  // Send upper nibble
  lcd_send_nibble(command & 0x0F, 0); // Send lower nibble
}

// Send data to LCD
void lcd_send_data(uint8_t data) {
  lcd_send_nibble(data >> 4, 1);  // Send upper nibble
  lcd_send_nibble(data & 0x0F, 1); // Send lower nibble
}

// Send a nibble to the LCD
void lcd_send_nibble(uint8_t nibble, int rs) {
  uint8_t data = (nibble << 4) | (rs << 0) | LCD_BACKLIGHT_ON | 0x04; // E=1, RS = rs
  wiringPiI2CWrite(i2c_fd, data);
  usleep(1); // Enable pulse width >= 300ns
  data &= ~0x04; // E=0
  wiringPiI2CWrite(i2c_fd, data);
  usleep(100);
}

// Write a character to the LCD
void lcd_write_char(char character) {
  lcd_send_data(character);
}

// Write a string to the LCD
void lcd_write_string(const char *string) {
  for (int i = 0; string[i] != '\0'; i++) {
    lcd_write_char(string[i]);
  }
}

// Set the cursor position
void lcd_set_cursor(uint8_t row, uint8_t col) {
  uint8_t address;
  if (row == 0) {
    address = 0x00 + col;
  } else {
    address = 0x40 + col;
  }
  lcd_send_command(LCD_SETDDRAMADDR | address);
}

// Clear the LCD display
void lcd_clear() {
  lcd_send_command(LCD_CLEARDISPLAY);
  usleep(2000); // Wait for clear command to complete
}

// Control the LCD backlight
void lcd_backlight(int on) {
    uint8_t backlight_bit = on ? LCD_BACKLIGHT_ON : LCD_BACKLIGHT_OFF;
    uint8_t data = backlight_bit; // Only control the backlight bit

    // Send any nibble with the updated backlight status
    lcd_send_nibble(0, 0); //RS = 0

}

int main() {
  // Initialize the LCD
  if (lcd_init() < 0) {
    fprintf(stderr, "LCD initialization failed.\n");
    return 1;
  }

  // Write a greeting message
  lcd_set_cursor(0, 0);
  lcd_write_string("Hello, RPi!");

  lcd_set_cursor(1, 0);
  lcd_write_string("LCD 1602 Test");

  sleep(5);
  lcd_clear();
  lcd_set_cursor(0,0);
  lcd_write_string("Backlight Off");
  lcd_backlight(0);
  sleep(5);
  lcd_backlight(1);
  lcd_clear();
  lcd_write_string("Backlight On");
  sleep(2);

  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Define GPIO pins
#define TRIG_PIN 4
#define ECHO_PIN 17
#define SERVO_PIN 18

// Define constants
#define SPEED_OF_SOUND 34300.0 // cm/s
#define PROXIMITY_THRESHOLD 20.0 // cm
#define SERVO_MIN_PULSE_WIDTH 500 // us
#define SERVO_MAX_PULSE_WIDTH 2500 // us
#define SERVO_SWEEP_DELAY 20 // ms

// Global variables
FILE *log_file = NULL;
int running = 1;

// Function prototypes
int init_gpio();
void trigger_sensor();
float measure_distance();
void set_servo_angle(int angle);
void log_proximity(float distance, int angle);
void cleanup();
void signal_handler(int signum);

int main() {
    int angle;

    // Initialize pigpio
    if (init_gpio() != 0) {
        return 1;
    }

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Main loop: Sweep servo and measure distance
    while (running) {
        for (angle = 0; angle <= 180; angle++) {
            set_servo_angle(angle);
            gpioDelay(SERVO_SWEEP_DELAY * 1000); // Convert ms to us

            float distance = measure_distance();
            if (distance < 0) {
                fprintf(stderr, "Error: Invalid distance measurement.\n");
            } else {
                printf("Angle: %d, Distance: %.2f cm\n", angle, distance);

                if (distance < PROXIMITY_THRESHOLD) {
                    log_proximity(distance, angle);
                }
            }
        }
    }

    // Cleanup resources before exiting
    cleanup();

    return 0;
}

// Initializes pigpio
int init_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(TRIG_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);
    gpioSetMode(SERVO_PIN, PI_OUTPUT);

    return 0;
}

// Triggers the HC-SR04 sensor
void trigger_sensor() {
    gpioWrite(TRIG_PIN, 1);
    gpioDelay(10); // Keep high for 10us
    gpioWrite(TRIG_PIN, 0);
}

// Measures the distance using the HC-SR04 sensor
float measure_distance() {
    long start_tick, end_tick, diff_tick;

    trigger_sensor();

    // Wait for echo to go high (with timeout)
    int count = 0;
    while (gpioRead(ECHO_PIN) == 0 && count < 10000) { // Timeout after 10ms
        count++;
        gpioDelay(1); // Check every 1us
    }

    if (count >= 10000) {
        fprintf(stderr, "Error: Echo pulse start timeout.\n");
        return -1.0; // Indicate error
    }

    start_tick = gpioTick();

    // Wait for echo to go low (with timeout)
    count = 0;
    while (gpioRead(ECHO_PIN) == 1 && count < 30000) { // Timeout after 30ms
        count++;
        gpioDelay(1); // Check every 1us
    }

    if (count >= 30000) {
        fprintf(stderr, "Error: Echo pulse end timeout.\n");
        return -1.0; // Indicate error
    }

    end_tick = gpioTick();

    diff_tick = end_tick - start_tick;

    // Calculate distance in centimeters
    float distance = (diff_tick / 1000000.0) * SPEED_OF_SOUND / 2.0;
    return distance;
}

// Sets the servo angle
void set_servo_angle(int angle) {
    // Calculate pulse width based on angle (0-180 degrees)
    int pulse_width = SERVO_MIN_PULSE_WIDTH + (int)((float)(angle) / 180.0 * (SERVO_MAX_PULSE_WIDTH - SERVO_MIN_PULSE_WIDTH));
    gpioServo(SERVO_PIN, pulse_width);
}

// Logs proximity events to the file
void log_proximity(float distance, int angle) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    // Get current timestamp
    time(&rawtime);
    timeinfo = localtime(&rawtime);
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    // Open log file for appending
    log_file = fopen("aircraft_proximity_log.txt", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        return;
    }

    // Write log entry
    fprintf(log_file, "%s - Angle: %d, Distance: %.2f cm\n", timestamp, angle, distance);

    // Close log file
    fclose(log_file);
    log_file = NULL; // Reset to NULL after closing
}

// Cleans up resources
void cleanup() {
    printf("Cleaning up...\n");
    gpioServo(SERVO_PIN, 0); // Stop servo
    gpioTerminate(); // Terminate pigpio
    if (log_file != NULL) {
        fclose(log_file);
    }
}

// Signal handler for graceful shutdown
void signal_handler(int signum) {
    printf("Received signal %d, shutting down...\n", signum);
    running = 0;
}

