#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <wiringPi.h>
#include <errno.h>

// Define GPIO pins for solenoids
#define SOLENOID_1_PIN 17
#define SOLENOID_2_PIN 18

// Frequency range for solenoids (Hz)
#define MIN_FREQUENCY 20.0
#define MAX_FREQUENCY 400.0

// PWM range (duty cycle 0-100)
#define PWM_RANGE 100

// Global variables to store solenoid frequencies
float solenoid1Frequency = 0.0;
float solenoid2Frequency = 0.0;

// Function prototypes
int setSolenoidFrequency(int solenoidPin, float frequency);
void cleanup_handler(int signal);

// Function to set the frequency of a solenoid using PWM
int setSolenoidFrequency(int solenoidPin, float frequency) {
    // Validate frequency range
    if (frequency < MIN_FREQUENCY || frequency > MAX_FREQUENCY) {
        fprintf(stderr, "Error: Frequency %.2f Hz is out of range (%f - %f Hz)\n", frequency, MIN_FREQUENCY, MAX_FREQUENCY);
        pwmWrite(solenoidPin, 0); // Disable PWM if frequency is out of range
        return -1; // Return error code
    }

    // Calculate PWM duty cycle (50% for simplicity)
    int dutyCycle = 50; // 50% duty cycle

    // Set PWM output
    pwmWrite(solenoidPin, dutyCycle);

    return 0; // Return success code
}

// Signal handler for graceful shutdown
void cleanup_handler(int signal) {
    printf("Cleaning up and exiting...\n");

    // Disable PWM on both solenoids
    pwmWrite(SOLENOID_1_PIN, 0);
    pwmWrite(SOLENOID_2_PIN, 0);

    exit(0);
}

int main(int argc, char *argv[]) {
    // Initialize wiringPi using GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
        return 1;
    }

    // Configure PWM mode to Mark:Space
    pwmSetMode(PWM_MODE_MS);

    // Set PWM range
    pwmSetRange(PWM_RANGE);

    // Set GPIO pins as PWM outputs
    pinMode(SOLENOID_1_PIN, PWM_OUTPUT);
    pinMode(SOLENOID_2_PIN, PWM_OUTPUT);

    // Handle command-line arguments for frequencies
    if (argc == 3) {
        solenoid1Frequency = atof(argv[1]);
        solenoid2Frequency = atof(argv[2]);
    } else {
        fprintf(stderr, "Usage: %s <solenoid1_frequency> <solenoid2_frequency>\n", argv[0]);
        fprintf(stderr, "Using default frequencies: Solenoid 1 = 100Hz, Solenoid 2 = 200Hz\n");
        solenoid1Frequency = 100.0;
        solenoid2Frequency = 200.0;
    }

    // Install signal handler for Ctrl+C
    signal(SIGINT, cleanup_handler);

    printf("Solenoid 1 Frequency: %.2f Hz (GPIO %d)\n", solenoid1Frequency, SOLENOID_1_PIN);
    printf("Solenoid 2 Frequency: %.2f Hz (GPIO %d)\n", solenoid2Frequency, SOLENOID_2_PIN);
    printf("Press Ctrl+C to exit.\n");

    // Main loop to continuously update PWM output
    while (1) {
        if (setSolenoidFrequency(SOLENOID_1_PIN, solenoid1Frequency) != 0) {
            fprintf(stderr, "Error setting frequency for solenoid 1.\n");
        }
        if (setSolenoidFrequency(SOLENOID_2_PIN, solenoid2Frequency) != 0) {
            fprintf(stderr, "Error setting frequency for solenoid 2.\n");
        }

        delay(10); // Small delay to prevent CPU hogging
    }

    return 0;
}

#include <stdio.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <linux/i2c-dev.h>
#include <sys/ioctl.h>

#define I2C_BUS "/dev/i2c-1"
#define ADS1115_ADDR 0x48
#define CONFIG_REG 0x01
#define CONVERSION_REG 0x00
#define REF_VOLTAGE 4.096

int read_channel(int fd, int mux) {
    uint8_t config[3] = {CONFIG_REG, (0x40 | (mux << 4)), 0x83};
    write(fd, config, 3);
    usleep(9000);
    uint8_t reg = CONVERSION_REG;
    write(fd, &reg, 1);
    uint8_t data[2];
    read(fd, data, 2);
    int16_t raw = (data[0] << 8) | data[1];
    return raw;
}

int main() {
    int fd = open(I2C_BUS, O_RDWR);
    if (fd < 0) return 1;
    ioctl(fd, I2C_SLAVE, ADS1115_ADDR);

    for (int mux = 4; mux <= 7; mux++) {
        int val = read_channel(fd, mux);
        double v = (val * REF_VOLTAGE) / 32768.0;
        printf("AIN%d: %.3f V\n", mux - 4, v);
    }
    close(fd);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <signal.h>
#include <unistd.h>

// Define GPIO pins
#define SOUND_SENSOR_GPIO 17
#define BUZZER_GPIO 18

// Define sysfs paths
#define GPIO_EXPORT_PATH "/sys/class/gpio/export"
#define GPIO_UNEXPORT_PATH "/sys/class/gpio/unexport"
#define GPIO_DIR_PATH_FORMAT "/sys/class/gpio/gpio%d/direction"
#define GPIO_VALUE_PATH_FORMAT "/sys/class/gpio/gpio%d/value"

// Define sound threshold (adjust as needed)
#define SOUND_THRESHOLD 0 // Digital input, so 0 or 1

// Define buzzer activation duration (in seconds)
#define BUZZER_DURATION 1

// Define debouncing delay (in milliseconds)
#define DEBOUNCE_DELAY 100

// Global variable to track program termination
volatile sig_atomic_t program_running = 1;

// Function prototypes
int export_gpio(int gpio);
int unexport_gpio(int gpio);
int set_gpio_direction(int gpio, const char *direction);
int read_gpio_value(int gpio);
int write_gpio_value(int gpio, int value);
void signal_handler(int signal);

// Signal handler to gracefully unexport GPIO pins on program termination
void signal_handler(int signal) {
    printf("\nCaught signal %d, exiting gracefully.\n", signal);
    program_running = 0;
    unexport_gpio(SOUND_SENSOR_GPIO);
    unexport_gpio(BUZZER_GPIO);
    exit(0);
}

// Function to export a GPIO pin
int export_gpio(int gpio) {
    FILE *fp = fopen(GPIO_EXPORT_PATH, "w");
    if (fp == NULL) {
        perror("Error opening GPIO export file");
        return -1;
    }
    fprintf(fp, "%d", gpio);
    fclose(fp);
    return 0;
}

// Function to unexport a GPIO pin
int unexport_gpio(int gpio) {
    FILE *fp = fopen(GPIO_UNEXPORT_PATH, "w");
    if (fp == NULL) {
        perror("Error opening GPIO unexport file");
        return -1;
    }
    fprintf(fp, "%d", gpio);
    fclose(fp);
    return 0;
}

// Function to set the direction of a GPIO pin (in or out)
int set_gpio_direction(int gpio, const char *direction) {
    char path[64];
    snprintf(path, sizeof(path), GPIO_DIR_PATH_FORMAT, gpio);
    FILE *fp = fopen(path, "w");
    if (fp == NULL) {
        perror("Error opening GPIO direction file");
        return -1;
    }
    fprintf(fp, "%s", direction);
    fclose(fp);
    return 0;
}

// Function to read the value of a GPIO pin
int read_gpio_value(int gpio) {
    char path[64];
    snprintf(path, sizeof(path), GPIO_VALUE_PATH_FORMAT, gpio);
    FILE *fp = fopen(path, "r");
    if (fp == NULL) {
        perror("Error opening GPIO value file");
        return -1;
    }
    int value;
    fscanf(fp, "%d", &value);
    fclose(fp);
    return value;
}

// Function to write a value to a GPIO pin
int write_gpio_value(int gpio, int value) {
    char path[64];
    snprintf(path, sizeof(path), GPIO_VALUE_PATH_FORMAT, gpio);
    FILE *fp = fopen(path, "w");
    if (fp == NULL) {
        perror("Error opening GPIO value file");
        return -1;
    }
    fprintf(fp, "%d", value);
    fclose(fp);
    return 0;
}

int main() {
    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Export GPIO pins
    if (export_gpio(SOUND_SENSOR_GPIO) != 0) {
        fprintf(stderr, "Failed to export SOUND_SENSOR_GPIO %d\n", SOUND_SENSOR_GPIO);
        return 1;
    }
    if (export_gpio(BUZZER_GPIO) != 0) {
        fprintf(stderr, "Failed to export BUZZER_GPIO %d\n", BUZZER_GPIO);
        unexport_gpio(SOUND_SENSOR_GPIO);
        return 1;
    }

    // Set GPIO direction
    if (set_gpio_direction(SOUND_SENSOR_GPIO, "in") != 0) {
        fprintf(stderr, "Failed to set SOUND_SENSOR_GPIO direction\n");
        unexport_gpio(SOUND_SENSOR_GPIO);
        unexport_gpio(BUZZER_GPIO);
        return 1;
    }
    if (set_gpio_direction(BUZZER_GPIO, "out") != 0) {
        fprintf(stderr, "Failed to set BUZZER_GPIO direction\n");
        unexport_gpio(SOUND_SENSOR_GPIO);
        unexport_gpio(BUZZER_GPIO);
        return 1;
    }

    printf("Sound-activated alarm system started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        // Read sound sensor value
        int sound_level = read_gpio_value(SOUND_SENSOR_GPIO);
        if (sound_level < 0) {
            fprintf(stderr, "Failed to read sound sensor value\n");
            break;
        }

        // Check if sound exceeds threshold
        if (sound_level > SOUND_THRESHOLD) { // Assuming active low, adjust if needed
            printf("Sound detected! Activating buzzer.\n");

            // Activate buzzer
            if (write_gpio_value(BUZZER_GPIO, 1) != 0) {
                fprintf(stderr, "Failed to activate buzzer\n");
                break;
            }

            // Wait for buzzer duration
            sleep(BUZZER_DURATION);

            // Deactivate buzzer
            if (write_gpio_value(BUZZER_GPIO, 0) != 0) {
                fprintf(stderr, "Failed to deactivate buzzer\n");
                break;
            }

            // Debouncing delay
            usleep(DEBOUNCE_DELAY * 1000); // Convert milliseconds to microseconds
        }

        // Small delay to avoid busy-waiting
        usleep(10000); // 10ms
    }

    // Unexport GPIO pins before exiting
    unexport_gpio(SOUND_SENSOR_GPIO);
    unexport_gpio(BUZZER_GPIO);

    printf("Program finished.\n");
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Constants
#define SHT31_ADDR 0x44
#define RELAY_GPIO 18
#define HUMIDITY_THRESHOLD_HIGH 60.0
#define HUMIDITY_THRESHOLD_LOW 55.0
#define LOG_FILE "/var/log/dehumidifier.log"

// Global variables
int i2c_handle;
volatile sig_atomic_t terminate = 0;

// Function prototypes
double read_humidity();
int activate_relay();
int deactivate_relay();
int log_event(const char *message);
void signal_handler(int signal);

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    if (signal == SIGINT) {
        terminate = 1;
        printf("Received SIGINT. Shutting down gracefully...\n");
    }
}

// Function to read humidity from SHT31 sensor
double read_humidity() {
    unsigned char cmd[2] = {0x24, 0x00}; // High repeatability measurement
    unsigned char buffer[6];
    int result;

    result = i2cWriteDevice(i2c_handle, (char *)cmd, 2);
    if (result != 0) {
        log_event("Error writing to I2C device");
        return -1.0;
    }

    gpioDelay(20); // Wait for measurement (at least 15ms)

    result = i2cReadDevice(i2c_handle, (char *)buffer, 6);
    if (result != 6) {
        log_event("Error reading from I2C device");
        return -1.0;
    }

    // Convert the data
    int temperature = (buffer[0] * 256 + buffer[1]);
    int humidity = (buffer[3] * 256 + buffer[4]);

    double temperature_celsius = -45 + (175 * (double)temperature / 65535.0);
    double relative_humidity = 100 * (double)humidity / 65535.0;

    return relative_humidity;
}

// Function to activate the relay
int activate_relay() {
    gpioWrite(RELAY_GPIO, 1); // Set GPIO HIGH
    gpioDelay(1000); // 1-second delay
    return 0;
}

// Function to deactivate the relay
int deactivate_relay() {
    gpioWrite(RELAY_GPIO, 0); // Set GPIO LOW
    gpioDelay(1000); // 1-second delay
    return 0;
}

// Function to log events to a file
int log_event(const char *message) {
    FILE *fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return -1;
    }

    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(fp, "%s: %s\n", timestamp, message);
    fclose(fp);
    return 0;
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set relay GPIO as output
    gpioSetMode(RELAY_GPIO, PI_OUTPUT);

    // Open I2C bus
    i2c_handle = i2cOpen(1, SHT31_ADDR, 0); // Bus 1, address 0x44, no flags
    if (i2c_handle < 0) {
        log_event("Error opening I2C bus");
        gpioTerminate();
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    int relay_state = 0; // 0 = off, 1 = on

    while (!terminate) {
        double humidity = read_humidity();

        if (humidity < 0) {
            log_event("Error reading humidity");
            gpioDelay(5000); // Wait 5 seconds before retrying
            continue;
        }

        char log_message[128];
        snprintf(log_message, sizeof(log_message), "Humidity: %.2f%%", humidity);
        log_event(log_message);

        if (humidity > HUMIDITY_THRESHOLD_HIGH && relay_state == 0) {
            if (activate_relay() == 0) {
                log_event("Dehumidifier activated");
                relay_state = 1;
            } else {
                log_event("Error activating dehumidifier");
            }
        } else if (humidity < HUMIDITY_THRESHOLD_LOW && relay_state == 1) {
            if (deactivate_relay() == 0) {
                log_event("Dehumidifier deactivated");
                relay_state = 0;
            } else {
                log_event("Error deactivating dehumidifier");
            }
        }

        gpioDelay(5000); // Check every 5 seconds
    }

    // Cleanup before exiting
    printf("Cleaning up...\n");
    if (relay_state == 1) {
        deactivate_relay(); // Ensure relay is off on exit
    }
    i2cClose(i2c_handle);
    gpioTerminate();

    printf("Exiting.\n");
    return 0;
}

#include <stdio.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <linux/i2c-dev.h>
#include <sys/ioctl.h>

#define I2C_BUS "/dev/i2c-1"
#define ADS1115_ADDR 0x48
#define CONFIG_REG 0x01
#define CONVERSION_REG 0x00

int read_register(int fd, uint8_t reg) {
    write(fd, &reg, 1);
    uint8_t buf[2];
    read(fd, buf, 2);
    return (buf[0] << 8) | buf[1];
}

int main() {
    int fd = open(I2C_BUS, O_RDWR);
    if (fd < 0) return 1;
    ioctl(fd, I2C_SLAVE, ADS1115_ADDR);

    int config = read_register(fd, CONFIG_REG);
    int conv = read_register(fd, CONVERSION_REG);

    printf("ADS1115 Config Reg: 0x%04X\n", config);
    printf("ADS1115 Conversion Reg: 0x%04X (%d)\n", conv, conv);

    close(fd);
    return 0;
}

