#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <fcntl.h>
#include <unistd.h>
#include <signal.h>
#include <errno.h>
#include <time.h>

// GPIO pins
#define PIR_SENSOR_PIN 4
#define RELAY_PIN 17
#define DOOR_SENSOR_PIN 18

// Sysfs paths
#define GPIO_EXPORT_PATH "/sys/class/gpio/export"
#define GPIO_UNEXPORT_PATH "/sys/class/gpio/unexport"
#define GPIO_DIRECTION_PATH_FORMAT "/sys/class/gpio/gpio%d/direction"
#define GPIO_VALUE_PATH_FORMAT "/sys/class/gpio/gpio%d/value"

// Function pointer types for GPIO operations
typedef int (*gpio_operation_t)(int pin, const char* value);

// Global variables for signal handling
volatile sig_atomic_t program_running = 1;

// Log file path
const char* LOG_FILE = "remote_diagnostics.log";

// Function prototypes
int gpio_export(int pin, const char* value);
int gpio_unexport(int pin, const char* value);
int gpio_direction(int pin, const char* direction);
int gpio_write(int pin, const char* value);
int gpio_read(int pin, char* value);
void log_event(const char* message);
void signal_handler(int signal);

// Function to export a GPIO pin
int gpio_export(int pin, const char* value) {
    int fd, len, ret;
    char buf[64];

    fd = open(GPIO_EXPORT_PATH, O_WRONLY);
    if (fd < 0) {
        perror("gpio_export: open(/sys/class/gpio/export)");
        return -1;
    }

    len = snprintf(buf, sizeof(buf), "%d", pin);
    ret = write(fd, buf, len);
    if (ret < 0) {
        perror("gpio_export: write()");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to unexport a GPIO pin
int gpio_unexport(int pin, const char* value) {
    int fd, len, ret;
    char buf[64];

    fd = open(GPIO_UNEXPORT_PATH, O_WRONLY);
    if (fd < 0) {
        perror("gpio_unexport: open(/sys/class/gpio/unexport)");
        return -1;
    }

    len = snprintf(buf, sizeof(buf), "%d", pin);
    ret = write(fd, buf, len);
    if (ret < 0) {
        perror("gpio_unexport: write()");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to set the direction of a GPIO pin
int gpio_direction(int pin, const char* direction) {
    int fd, ret;
    char path[128];

    snprintf(path, sizeof(path), GPIO_DIRECTION_PATH_FORMAT, pin);
    fd = open(path, O_WRONLY);
    if (fd < 0) {
        perror("gpio_direction: open(/sys/class/gpio/gpio[pin]/direction)");
        return -1;
    }

    ret = write(fd, direction, strlen(direction));
    if (ret < 0) {
        perror("gpio_direction: write()");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to write a value to a GPIO pin
int gpio_write(int pin, const char* value) {
    int fd, ret;
    char path[128];

    snprintf(path, sizeof(path), GPIO_VALUE_PATH_FORMAT, pin);
    fd = open(path, O_WRONLY);
    if (fd < 0) {
        perror("gpio_write: open(/sys/class/gpio/gpio[pin]/value)");
        return -1;
    }

    ret = write(fd, value, 1); // Write only one character
    if (ret < 0) {
        perror("gpio_write: write()");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to read a value from a GPIO pin
int gpio_read(int pin, char* value) {
    int fd, ret;
    char path[128];

    snprintf(path, sizeof(path), GPIO_VALUE_PATH_FORMAT, pin);
    fd = open(path, O_RDONLY);
    if (fd < 0) {
        perror("gpio_read: open(/sys/class/gpio/gpio[pin]/value)");
        return -1;
    }

    ret = read(fd, value, 1); // Read only one character
    if (ret < 0) {
        perror("gpio_read: read()");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to log an event with a timestamp
void log_event(const char* message) {
    FILE* fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        perror("log_event: fopen");
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%dT%H:%M:%S%z", &tm);

    fprintf(fp, "%s: %s\n", timestamp, message);
    fclose(fp);
}

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("\nCtrl+C pressed. Exiting gracefully.\n");
        program_running = 0;
    }
}

int main() {
    // Install signal handler
    signal(SIGINT, signal_handler);

    // Function pointers for GPIO operations
    gpio_operation_t export_func = gpio_export;
    gpio_operation_t unexport_func = gpio_unexport;
    gpio_operation_t direction_func = gpio_direction;
    gpio_operation_t write_func = gpio_write;
    gpio_operation_t read_func = gpio_read;

    // Export GPIO pins
    if (export_func(PIR_SENSOR_PIN, "") < 0) return 1;
    if (export_func(RELAY_PIN, "") < 0) return 1;
    if (export_func(DOOR_SENSOR_PIN, "") < 0) return 1;

    // Set GPIO directions
    if (direction_func(PIR_SENSOR_PIN, "in") < 0) return 1;
    if (direction_func(RELAY_PIN, "out") < 0) return 1;
    if (direction_func(DOOR_SENSOR_PIN, "in") < 0) return 1;

    // Main loop
    while (program_running) {
        char pir_value[2];
        if (read_func(PIR_SENSOR_PIN, pir_value) < 0) {
            log_event("Error reading PIR sensor value.");
            continue;
        }

        if (pir_value[0] == '1') {
            log_event("Motion detected!");

            // Activate relay (unlock door)
            if (write_func(RELAY_PIN, "1") < 0) {
                log_event("Error activating relay.");
            } else {
                log_event("Relay activated (door unlocked).");
            }

            sleep(5); // Simulate door unlock duration

            // Deactivate relay
            if (write_func(RELAY_PIN, "0") < 0) {
                log_event("Error deactivating relay.");
            } else {
                log_event("Relay deactivated (door locked).");
            }

            // Check door sensor
            char door_value[2];
            if (read_func(DOOR_SENSOR_PIN, door_value) < 0) {
                log_event("Error reading door sensor value.");
            } else {
                if (door_value[0] == '1') {
                    log_event("Door opened.");
                } else {
                    log_event("Door remained closed after motion.");
                }
            }
        }

        sleep(1); // Check every 1 second
    }

    // Unexport GPIO pins on exit
    if (unexport_func(PIR_SENSOR_PIN, "") < 0) {
        perror("Failed to unexport PIR sensor pin");
    }
    if (unexport_func(RELAY_PIN, "") < 0) {
        perror("Failed to unexport relay pin");
    }
    if (unexport_func(DOOR_SENSOR_PIN, "") < 0) {
        perror("Failed to unexport door sensor pin");
    }

    return 0;
}

