#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <fcntl.h>
#include <unistd.h>
#include <signal.h>
#include <pthread.h>
#include <time.h>
#include <pigpio.h>

// GPIO pins
#define HALL_SENSOR_GPIO 17
#define RELAY_GPIO 27

// Sysfs paths
#define GPIO_EXPORT_PATH "/sys/class/gpio/export"
#define GPIO_UNEXPORT_PATH "/sys/class/gpio/unexport"
#define GPIO_DIRECTION_PATH_BASE "/sys/class/gpio/gpio%d/direction"
#define GPIO_VALUE_PATH_BASE "/sys/class/gpio/gpio%d/value"

// Mutex for protecting the rotation counter
pthread_mutex_t rotation_mutex;

// Global rotation counter
volatile int rotation_count = 0;

// Flag to indicate program termination
volatile sig_atomic_t program_running = 1;

// Function to write to a sysfs file
int write_sysfs(const char *path, const char *value)
{
    int fd = open(path, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Error opening %s: %s\n", path, strerror(errno));
        return -1;
    }
    if (write(fd, value, strlen(value)) < 0) {
        fprintf(stderr, "Error writing to %s: %s\n", path, strerror(errno));
        close(fd);
        return -1;
    }
    close(fd);
    return 0;
}

// Function to read from a sysfs file
int read_sysfs(const char *path, char *value, size_t size)
{
    int fd = open(path, O_RDONLY);
    if (fd < 0) {
        fprintf(stderr, "Error opening %s: %s\n", path, strerror(errno));
        return -1;
    }
    ssize_t count = read(fd, value, size - 1);
    if (count < 0) {
        fprintf(stderr, "Error reading from %s: %s\n", path, strerror(errno));
        close(fd);
        return -1;
    }
    value[count] = '\0';
    close(fd);
    return 0;
}

// Function to configure a GPIO pin
int configure_gpio(int gpio, const char *direction)
{
    char gpio_str[3];
    sprintf(gpio_str, "%d", gpio);

    // Export GPIO
    if (write_sysfs(GPIO_EXPORT_PATH, gpio_str) < 0) {
        fprintf(stderr, "Failed to export GPIO %d\n", gpio);
        return -1;
    }
    usleep(100000); // Wait for the file to be created

    // Set direction
    char direction_path[64];
    sprintf(direction_path, GPIO_DIRECTION_PATH_BASE, gpio);
    if (write_sysfs(direction_path, direction) < 0) {
        fprintf(stderr, "Failed to set direction for GPIO %d\n", gpio);
        return -1;
    }

    return 0;
}

// Function to set GPIO output
int set_gpio_output(int gpio, int value)
{
    char value_path[64];
    sprintf(value_path, GPIO_VALUE_PATH_BASE, gpio);
    char value_str[2];
    sprintf(value_str, "%d", value);
    if (write_sysfs(value_path, value_str) < 0) {
        fprintf(stderr, "Failed to set output for GPIO %d\n", gpio);
        return -1;
    }
    return 0;
}

// Interrupt handler
void rotation_interrupt_handler(int gpio, int level, uint32_t tick, void *userdata)
{
    if (gpio == HALL_SENSOR_GPIO) {
        pthread_mutex_lock(&rotation_mutex);
        rotation_count++;
        pthread_mutex_unlock(&rotation_mutex);
    }
}

// Signal handler for Ctrl+C
void signal_handler(int signal)
{
    program_running = 0;
    printf("Caught signal %d, exiting gracefully...\n", signal);
}

// Function to unexport a GPIO pin
int unexport_gpio(int gpio)
{
    char gpio_str[3];
    sprintf(gpio_str, "%d", gpio);

    if (write_sysfs(GPIO_UNEXPORT_PATH, gpio_str) < 0) {
        fprintf(stderr, "Failed to unexport GPIO %d\n", gpio);
        return -1;
    }

    return 0;
}

int main()
{
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Configure GPIOs
    if (configure_gpio(HALL_SENSOR_GPIO, "in") < 0) {
        gpioTerminate();
        return 1;
    }
    if (configure_gpio(RELAY_GPIO, "out") < 0) {
        gpioTerminate();
        return 1;
    }

    // Initialize mutex
    if (pthread_mutex_init(&rotation_mutex, NULL) != 0) {
        fprintf(stderr, "Mutex initialization failed\n");
        unexport_gpio(HALL_SENSOR_GPIO);
        unexport_gpio(RELAY_GPIO);
        gpioTerminate();
        return 1;
    }

    // Register interrupt handler
    if (gpioSetAlertFuncEx(HALL_SENSOR_GPIO, rotation_interrupt_handler, NULL) != 0) {
        fprintf(stderr, "Failed to register interrupt handler\n");
        pthread_mutex_destroy(&rotation_mutex);
        unexport_gpio(HALL_SENSOR_GPIO);
        unexport_gpio(RELAY_GPIO);
        gpioTerminate();
        return 1;
    }

    // Set signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    struct timespec start_time, current_time;
    clock_gettime(CLOCK_MONOTONIC, &start_time);
    int previous_count = 0;

    while (program_running) {
        sleep(1);

        clock_gettime(CLOCK_MONOTONIC, &current_time);
        double elapsed_time = (current_time.tv_sec - start_time.tv_sec) + (current_time.tv_nsec - start_time.tv_nsec) / 1e9;

        pthread_mutex_lock(&rotation_mutex);
        int current_count = rotation_count;
        pthread_mutex_unlock(&rotation_mutex);

        int rotations_per_second = current_count - previous_count;
        double rpm = rotations_per_second * 60.0;

        printf("RPM: %.2f\n", rpm);

        // Relay control
        if (rpm > 60.0) {
            set_gpio_output(RELAY_GPIO, 1);
        } else {
            set_gpio_output(RELAY_GPIO, 0);
        }

        previous_count = current_count;
        start_time = current_time;
    }

    // Cleanup
    gpioSetAlertFuncEx(HALL_SENSOR_GPIO, NULL, NULL); // Disable interrupt handler
    pthread_mutex_destroy(&rotation_mutex);
    unexport_gpio(HALL_SENSOR_GPIO);
    unexport_gpio(RELAY_GPIO);
    gpioTerminate();

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <stdint.h>

// Define GPIO pins connected to the 74HC595
#define DATA_PIN   17  // BCM GPIO 17
#define LATCH_PIN  22  // BCM GPIO 22
#define CLOCK_PIN  27  // BCM GPIO 27

// Define 7-segment display patterns for digits 0-9 (common cathode)
const uint8_t digitPatterns[] = {
    0x3F, // 0
    0x06, // 1
    0x5B, // 2
    0x4F, // 3
    0x66, // 4
    0x6D, // 5
    0x7D, // 6
    0x07, // 7
    0x7F, // 8
    0x6F  // 9
};

// Function to shift out data to the 74HC595
void shiftData(uint8_t data) {
    for (int i = 0; i < 8; i++) {
        // Set data pin based on the current bit
        digitalWrite(DATA_PIN, (data >> (7 - i)) & 0x01);

        // Clock the data in
        digitalWrite(CLOCK_PIN, HIGH);
        delayMicroseconds(1); // Small delay for reliable clocking
        digitalWrite(CLOCK_PIN, LOW);
    }
}

// Function to display a digit on the 7-segment display
void displayDigit(int digit) {
    if (digit < 0 || digit > 9) {
        fprintf(stderr, "Error: Invalid digit. Must be between 0 and 9.\n");
        return; // Exit if digit is out of range
    }

    // Latch low to start data transfer
    digitalWrite(LATCH_PIN, LOW);

    // Shift out the digit pattern
    shiftData(digitPatterns[digit]);

    // Latch high to display the data
    digitalWrite(LATCH_PIN, HIGH);
}

int main() {
    // Initialize WiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing WiringPi.\n");
        return 1; // Exit if WiringPi initialization fails
    }

    // Set pin modes
    pinMode(DATA_PIN, OUTPUT);
    pinMode(LATCH_PIN, OUTPUT);
    pinMode(CLOCK_PIN, OUTPUT);

    // Main loop
    while (1) {
        for (int i = 0; i < 10; i++) {
            displayDigit(i);
            delay(1000); // Display each digit for 1 second
        }
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>
#include <time.h>
#include <signal.h>

// Define constants
#define TMP102_I2C_ADDR 0x48
#define TMP102_TEMP_REG 0x00
#define GPIO_PIN 18
#define ERROR_VALUE -999.0

int i2c_fd;

// Function to read temperature from TMP102 sensor
float readTemperature() {
    int raw_value;
    float temperature;

    raw_value = wiringPiI2CReadReg16(i2c_fd, TMP102_TEMP_REG);
    if (raw_value == -1) {
        perror("Failed to read temperature from TMP102");
        return ERROR_VALUE;
    }

    // Convert raw value to Celsius
    temperature = (float)((raw_value >> 4) * 0.0625);

    return temperature;
}

// Function to control fan speed based on temperature
void controlFan(float temperature) {
    int duty_cycle = 0;

    if (temperature < 25.0) {
        duty_cycle = 0; // 0% duty cycle
    } else if (temperature >= 25.0 && temperature < 30.0) {
        duty_cycle = 25; // 25% duty cycle
    } else if (temperature >= 30.0 && temperature < 35.0) {
        duty_cycle = 50; // 50% duty cycle
    } else {
        duty_cycle = 100; // 100% duty cycle
    }

    pwmWrite(GPIO_PIN, duty_cycle);
    printf("Fan duty cycle: %d\n", duty_cycle);
}

// Signal handler for graceful shutdown
void signalHandler(int signum) {
    printf("Received signal %d, shutting down...\n", signum);
    pwmWrite(GPIO_PIN, 0); // Stop the fan
    exit(signum);
}

int main() {
    // Initialize wiringPi with GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Failed to initialize wiringPi\n");
        return 1;
    }

    // Initialize I2C communication
    i2c_fd = wiringPiI2CSetup(TMP102_I2C_ADDR);
    if (i2c_fd == -1) {
        fprintf(stderr, "Failed to initialize I2C communication\n");
        return 1;
    }

    // Configure PWM on GPIO 18
    pinMode(GPIO_PIN, PWM_OUTPUT);
    pwmSetMode(PWM_MODE_MS);
    pwmSetRange(100); // Range from 0 to 100 for duty cycle percentage
    pwmWrite(GPIO_PIN, 0); // Initially, turn off the fan

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signalHandler);

    // Main loop
    while (1) {
        // Read temperature
        float temperature = readTemperature();

        if (temperature == ERROR_VALUE) {
            fprintf(stderr, "Error reading temperature, skipping fan control.\n");
        } else {
            // Get current time
            time_t now = time(NULL);
            struct tm *t = localtime(&now);
            char timestamp[26];
            strftime(timestamp, sizeof(timestamp)-1, "%Y-%m-%d %H:%M:%S", t);

            // Log temperature with timestamp
            printf("[%s] Temperature: %.2f °C\n", timestamp, temperature);

            // Control fan speed
            controlFan(temperature);
        }

        // Wait for 5 seconds
        delay(5000);
    }

    return 0;
}

#include <pigpio.h>
#include <stdio.h>
#include <time.h>
#define ADS_ADDR 0x48
#define CONFIG_REG 0x01
#define LO_THRESH 0x02
#define HI_THRESH 0x03
#define CONV_REG 0x00
#define ALERT_PIN 23
void ads_setup_thresholds(int fd) {
    char config[3] = {CONFIG_REG, 0xC3, 0xF3};
    char lo[3] = {LO_THRESH, 0x80, 0x00};
    char hi[3] = {HI_THRESH, 0x40, 0x00};
    i2cWriteDevice(fd, lo, 3);
    i2cWriteDevice(fd, hi, 3);
    i2cWriteDevice(fd, config, 3);
}
int read_ads(int fd) {
    char buf[2];
    i2cReadI2CBlockData(fd, CONV_REG, buf, 2);
    return (buf[0] << 8) | buf[1];
}
int main() {
    if (gpioInitialise() < 0) return 1;
    gpioSetMode(ALERT_PIN, PI_INPUT);
    gpioSetPullUpDown(ALERT_PIN, PI_PUD_UP);
    int fd = i2cOpen(1, ADS_ADDR, 0);
    ads_setup_thresholds(fd);
    FILE* f = fopen("alert_log.csv", "w");
    fprintf(f, "Time,ADC\n");
    while (1) {
        if (gpioRead(ALERT_PIN) == 0) {
            int val = read_ads(fd);
            fprintf(f, "%ld,%d\n", time(NULL), val);
            fflush(f);
            gpioDelay(500000);
        } else {
            gpioDelay(100000);
        }
    }
    fclose(f);
    i2cClose(fd);
    gpioTerminate();
    return 0;
}

#include <stdio.h>
