// Define constants
#define SPI_CHANNEL 0
#define SPI_SPEED 500000 // 500kHz
#define MCP3008_CHANNEL 0
#define HEATER_PIN 17
#define TARGET_TEMPERATURE 30.0
#define TEMPERATURE_READ_INTERVAL 5 // seconds

// Global variables
FILE *log_file;
volatile sig_atomic_t program_running = 1;

// Function prototypes
float read_temperature();
int control_heater(float current_temperature, float target_temperature);
int log_data(float temperature, int duty_cycle);
void signal_handler(int signal);

// Function to read temperature from TMP36 via MCP3008
float read_temperature() {
    unsigned char buffer[3];
    int adc_value;
    float voltage, temperature;

    // MCP3008 Command: Start bit (1), Single-ended mode (1), Channel selection (3 bits), followed by 3 don't care bits (000)
    buffer[0] = 0x01; // Start bit
    buffer[1] = (0x08 | MCP3008_CHANNEL) << 4; // Single-ended, channel
    buffer[2] = 0x00; // Don't care

    wiringPiSPIDataRW(SPI_CHANNEL, buffer, 3);

    // Extract ADC value (10 bits) from the response.
    adc_value = ((buffer[1] & 0x03) << 8) + buffer[2];

    // Convert ADC value to voltage (assuming Vref = 3.3V)
    voltage = ((float)adc_value / 1023.0) * 3.3;

    // Convert voltage to temperature (Celsius) using TMP36 formula
    temperature = (voltage - 0.5) / 0.01;

    return temperature;
}

// Function to control the heater using PWM
int control_heater(float current_temperature, float target_temperature) {
    int duty_cycle;
    float error = target_temperature - current_temperature;

    // Proportional control algorithm
    duty_cycle = (int)(error * 10); // Adjust the gain (10) as needed

    // Limit the duty cycle to 0-100
    if (duty_cycle < 0) {
        duty_cycle = 0;
    } else if (duty_cycle > 100) {
        duty_cycle = 100;
    }

    softPwmWrite(HEATER_PIN, duty_cycle);
    return duty_cycle;
}

// Function to log data to file
int log_data(float temperature, int duty_cycle) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    if (log_file != NULL) {
        fprintf(log_file, "%s, Temperature: %.2f C, Duty Cycle: %d\n", timestamp, temperature, duty_cycle);
        fflush(log_file); // Ensure data is written to disk immediately
        return 0; // Success
    } else {
        perror("Error writing to log file");
        return -1; // Failure
    }
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("\nCaught signal %d, exiting gracefully.\n", signal);
    program_running = 0;
    softPwmWrite(HEATER_PIN, 0); // Turn off the heater
    if (log_file != NULL) {
        fclose(log_file);
    }
    exit(0);
}

int main() {
    float temperature;
    int duty_cycle;

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed\n");
        return 1;
    }

    // Initialize SPI
    if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) == -1) {
        fprintf(stderr, "wiringPiSPISetup failed\n");
        return 1;
    }

    // Initialize soft PWM for heater control
    softPwmCreate(HEATER_PIN, 0, 100); // Pin, initial value, range

    // Open log file
    log_file = fopen("heater_log.txt", "a");
    if (log_file == NULL) {
        perror("Error opening log file");
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Main loop
    while (program_running) {
        // Read temperature
        temperature = read_temperature();

        // Control heater
        duty_cycle = control_heater(temperature, TARGET_TEMPERATURE);

        // Log data
        if (log_data(temperature, duty_cycle) != 0) {
            fprintf(stderr, "Error logging data\n");
        }

        printf("Temperature: %.2f C, Duty Cycle: %d\n", temperature, duty_cycle);

        // Wait for the next reading
        delay(TEMPERATURE_READ_INTERVAL * 1000); // Convert seconds to milliseconds
    }

    // Cleanup (should not reach here if signal handler works correctly)
    softPwmWrite(HEATER_PIN, 0); // Turn off the heater
    fclose(log_file);

    return 0;
}

