// Write callback function for libcurl
size_t write_callback(char *contents, size_t size, size_t nmemb, void *userp) {
    size_t real_size = size * nmemb;
    char **response_string = (char **)userp;

    *response_string = realloc(*response_string, strlen(*response_string) + real_size + 1);
    if (*response_string == NULL) {
        fprintf(stderr, "Error: Failed to allocate memory in write_callback\n");
        return 0;
    }
    strncat(*response_string, contents, real_size);
    return real_size;
}

// Function to fetch thresholds from the API endpoint
Thresholds fetch_thresholds(const char *url) {
    CURL *curl;
    CURLcode res;
    Thresholds thresholds = {0.0, 0.0};
    char *response_string = strdup(""); // Initialize with an empty string

    curl_global_init(CURL_GLOBAL_DEFAULT);
    curl = curl_easy_init();
    if (curl) {
        curl_easy_setopt(curl, CURLOPT_URL, url);
        curl_easy_setopt(curl, CURLOPT_WRITEFUNCTION, write_callback);
        curl_easy_setopt(curl, CURLOPT_WRITEDATA, &response_string);
        curl_easy_setopt(curl, CURLOPT_USERAGENT, USER_AGENT);
        curl_easy_setopt(curl, CURLOPT_TIMEOUT, 10L); // Set timeout to 10 seconds

        res = curl_easy_perform(curl);
        if (res != CURLE_OK) {
            fprintf(stderr, "Error: curl_easy_perform() failed: %s\n", curl_easy_strerror(res));
        } else {
            thresholds = parse_json(response_string);
        }

        curl_easy_cleanup(curl);
    } else {
        fprintf(stderr, "Error: Failed to initialize libcurl\n");
    }
    curl_global_cleanup();
    free(response_string);
    return thresholds;
}

// Function to parse JSON response
Thresholds parse_json(const char *json_string) {
    Thresholds thresholds = {0.0, 0.0};
    cJSON *json = cJSON_Parse(json_string);

    if (json == NULL) {
        const char *error_ptr = cJSON_GetErrorPtr();
        if (error_ptr != NULL) {
            fprintf(stderr, "Error: JSON parse error: %s\n", error_ptr);
        }
        return thresholds; // Return default values on error
    }

    cJSON *temperature = cJSON_GetObjectItemCaseSensitive(json, "temperature");
    if (cJSON_IsNumber(temperature)) {
        thresholds.temperature = (float)temperature->valuedouble;
    } else {
        fprintf(stderr, "Warning: Temperature not found or invalid in JSON\n");
    }

    cJSON *humidity = cJSON_GetObjectItemCaseSensitive(json, "humidity");
    if (cJSON_IsNumber(humidity)) {
        thresholds.humidity = (float)humidity->valuedouble;
    } else {
        fprintf(stderr, "Warning: Humidity not found or invalid in JSON\n");
    }

    cJSON_Delete(json);
    return thresholds;
}

