int main(int argc, char *argv[]) {
    int opt;

    // Parse command-line arguments
    while ((opt = getopt(argc, argv, "u:")) != -1) {
        switch (opt) {
            case 'u':
                api_url = optarg;
                break;
            default:
                fprintf(stderr, "Usage: %s [-u api_url]\n", argv[0]);
                return 1;
        }
    }

    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error: Failed to initialize wiringPi\n");
        return 1;
    }

    // Set GPIO pin modes
    pinMode(FAN_PIN, OUTPUT);

    // Main loop
    while (1) {
        // Fetch thresholds from the API
        Thresholds thresholds = fetch_thresholds(api_url);

        // Read DHT22 sensor data
        DHT22Data dht22_data = read_dht22();

        if (dht22_data.temperature != -999.0 && dht22_data.humidity != -999.0) {
            printf("Temperature: %.2f°C, Humidity: %.2f%%\n", dht22_data.temperature, dht22_data.humidity);

            // Control the fan based on the temperature threshold
            if (dht22_data.temperature > thresholds.temperature) {
                control_fan(HIGH); // Turn the fan on
            } else {
                control_fan(LOW);  // Turn the fan off
            }
        } else {
            fprintf(stderr, "Error: Could not read DHT22 data, skipping fan control.\n");
        }

        // Delay before the next iteration
        delay(LOOP_DELAY_MS);
    }

    return 0;
}

