#include <wiringPiSPI.h>

// Constants
#define WIND_SPEED_PIN 17
#define SPI_CHANNEL 0
#define I2C_ADDRESS 0x27 // Example I2C address for LCD
#define PULSES_PER_ROTATION 1.0 // Assuming 1 pulse per rotation
#define CALIBRATION_FACTOR 2.4 // km/h per rotation
#define CONVERSION_FACTOR 0.277778 // km/h to m/s
#define NUM_DIRECTIONS 8

// Global variables
volatile int pulseCount = 0;
int lcdHandle;

// Lookup table for wind direction (example values, adjust based on your wind vane)
int voltageToDirectionMap[NUM_DIRECTIONS] = {50, 150, 250, 350, 450, 550, 650, 750}; // Analog value boundaries
char *directionNames[NUM_DIRECTIONS] = {"N", "NE", "E", "SE", "S", "SW", "W", "NW"};

// Function prototypes
void pulseCounter();
float calculateWindSpeed(int pulseCount, float calibrationFactor);
int readWindDirection();
char *mapVoltageToDirection(int analogValue, int *voltageToDirectionMap, int mapSize);
int lcdInit(int i2cAddress);
void lcdPrint(int i2cAddress, int row, int col, char *text);
void clearLcd(int i2cAddress);
void signalHandler(int signal);

// Interrupt routine for wind speed sensor
void pulseCounter()
{
    static unsigned long lastInterruptTime = 0;
    unsigned long interruptTime = millis();

    // Debounce the signal (adjust the delay as needed)
    if (interruptTime - lastInterruptTime > 5) // 5ms debounce
    {
        pulseCount++;
        lastInterruptTime = interruptTime;
    }
}

// Function to calculate wind speed in m/s
float calculateWindSpeed(int pulseCount, float calibrationFactor)
{
    float speedKmh = (float)pulseCount / PULSES_PER_ROTATION * calibrationFactor;
    return speedKmh * CONVERSION_FACTOR;
}

// Function to read wind direction from MCP3008 ADC
int readWindDirection()
{
    unsigned char buffer[3];
    buffer[0] = 0x01;                  // Start bit
    buffer[1] = 0x80;                  // SGL/DIFF=1, D2=D1=D0=0 (Channel 0)
    buffer[2] = 0x00;

    wiringPiSPIDataRW(SPI_CHANNEL, buffer, 3);

    int adcValue = ((buffer[1] & 0x03) << 8) + buffer[2];
    return adcValue;
}

// Function to map voltage to wind direction
char *mapVoltageToDirection(int analogValue, int *voltageToDirectionMap, int mapSize)
{
    for (int i = 0; i < mapSize; i++)
    {
        if (analogValue < voltageToDirectionMap[i])
        {
            return directionNames[i];
        }
    }
    return directionNames[mapSize - 1]; // Default to last direction
}

// Function to initialize the LCD
int lcdInit(int i2cAddress)
{
    lcdHandle = wiringPiI2CSetup(i2cAddress);
    if (lcdHandle == -1)
    {
        fprintf(stderr, "Error initializing I2C LCD: %s\n", strerror(errno));
        return -1;
    }

    // Initialize LCD (specific commands for your LCD model)
    wiringPiI2CWriteReg8(lcdHandle, 0x00, 0x38); // Function set: 8-bit, 2 lines
    wiringPiI2CWriteReg8(lcdHandle, 0x00, 0x0C); // Display control: Display on, cursor off, blink off
    wiringPiI2CWriteReg8(lcdHandle, 0x00, 0x06); // Entry mode set: Increment cursor, no shift
    wiringPiI2CWriteReg8(lcdHandle, 0x00, 0x01); // Clear display
    delay(2);                                     // Wait for clear display to complete

    return 0;
}

// Function to print text on the LCD
void lcdPrint(int i2cAddress, int row, int col, char *text)
{
    int address;
    if (row == 0)
        address = 0x80 + col; // First row
    else
        address = 0xC0 + col; // Second row

    wiringPiI2CWriteReg8(lcdHandle, 0x00, address);

    for (int i = 0; text[i] != 0; i++)
    {
        wiringPiI2CWriteReg8(lcdHandle, 0x00, 0x40); // RS = 1 for data
        wiringPiI2CWriteReg8(lcdHandle, 0x40, text[i]);
    }
}

// Function to clear the LCD
void clearLcd(int i2cAddress)
{
    wiringPiI2CWriteReg8(lcdHandle, 0x00, 0x01); // Clear display command
    delay(2);
}

// Signal handler for graceful shutdown
void signalHandler(int signal)
{
    printf("Caught signal %d, cleaning up...\n", signal);
    clearLcd(I2C_ADDRESS);
    exit(0);
}

int main()
{
    // Initialize WiringPi
    if (wiringPiSetupGpio() == -1)
    {
        fprintf(stderr, "Error initializing WiringPi: %s\n", strerror(errno));
        return 1;
    }

    // Initialize SPI
    if (wiringPiSPISetup(SPI_CHANNEL, 1000000) == -1)
    {
        fprintf(stderr, "Error initializing SPI: %s\n", strerror(errno));
        return 1;
    }

    // Initialize I2C LCD
    if (lcdInit(I2C_ADDRESS) == -1)
    {
        return 1;
    }

    // Set up interrupt for wind speed sensor
    pinMode(WIND_SPEED_PIN, INPUT);
    pullUpDnControl(WIND_SPEED_PIN, PUD_UP);
    if (wiringPiISR(WIND_SPEED_PIN, INT_EDGE_RISING, &pulseCounter) < 0)
    {
        fprintf(stderr, "Unable to setup ISR: %s\n", strerror(errno));
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signalHandler);

    // Main loop
    while (1)
    {
        // Read wind speed
        int currentPulseCount = pulseCount;
        pulseCount = 0; // Reset pulse count for the next second
        float windSpeed = calculateWindSpeed(currentPulseCount, CALIBRATION_FACTOR);

        // Read wind direction
        int windDirectionValue = readWindDirection();
        char *windDirection = mapVoltageToDirection(windDirectionValue, voltageToDirectionMap, NUM_DIRECTIONS);

        // Format data for display
        char speedString[20];
        sprintf(speedString, "Speed: %.2f m/s", windSpeed);
        char directionString[20];
        sprintf(directionString, "Dir: %s", windDirection);

        // Display data on LCD
        lcdPrint(I2C_ADDRESS, 0, 0, speedString);
        lcdPrint(I2C_ADDRESS, 1, 0, directionString);

        delay(1000); // Update every 1 second
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <unistd.h>
#include <time.h>

// Define GPIO pins connected to the ultrasonic sensor
#define TRIGGER_PIN 23 // GPIO pin for triggering the sensor
#define ECHO_PIN 24    // GPIO pin for receiving the echo

// Constants for distance calculation
#define SOUND_SPEED_CM_US 0.0343 // Speed of sound in cm/us
#define SOUND_SPEED_INCH_US 0.0135 // Speed of sound in inch/us

// Function prototypes
float measure_distance_cm();
float measure_distance_inch();
void setup_gpio();

int main()
{
    // Initialize WiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi initialization failed!\n");
        return 1;
    }

    setup_gpio();

    printf("Ultrasonic Distance Sensor Demo\n");

    while (1) {
        float distance_cm = measure_distance_cm();
        float distance_inch = measure_distance_inch();

        if (distance_cm > 0) {
            printf("Distance: %.2f cm / %.2f inch\n", distance_cm, distance_inch);
        } else {
            fprintf(stderr, "Error: Could not read distance. Check sensor connection.\n");
        }

        delay(1000); // Delay for 1 second
    }

    return 0;
}

void setup_gpio()
{
    // Set GPIO pin modes
    pinMode(TRIGGER_PIN, OUTPUT);
    pinMode(ECHO_PIN, INPUT);

    // Ensure trigger pin is low initially
    digitalWrite(TRIGGER_PIN, LOW);
    delay(500); // Allow sensor to settle
}

float measure_distance_cm()
{
    // Trigger the sensor
    digitalWrite(TRIGGER_PIN, HIGH);
    delayMicroseconds(10);
    digitalWrite(TRIGGER_PIN, LOW);

    // Measure echo pulse duration
    struct timespec start, end;
    long long start_time, end_time, pulse_duration;

    // Wait for echo to start (with timeout)
    int timeout = 1000; // 1ms timeout
    while (digitalRead(ECHO_PIN) == LOW && timeout > 0) {
        timeout--;
        delayMicroseconds(1); // Wait 1 us
    }

    if (timeout <= 0) {
        fprintf(stderr, "Error: Echo start timeout.\n");
        return -1.0; // Indicate error
    }

    clock_gettime(CLOCK_MONOTONIC_RAW, &start);

    // Wait for echo to end (with timeout)
    timeout = 10000; // 10ms timeout
    while (digitalRead(ECHO_PIN) == HIGH && timeout > 0) {
        timeout--;
        delayMicroseconds(1); // Wait 1 us
    }

    if (timeout <= 0) {
        fprintf(stderr, "Error: Echo end timeout.\n");
        return -1.0; // Indicate error
    }

    clock_gettime(CLOCK_MONOTONIC_RAW, &end);

    start_time = start.tv_sec * 1000000000LL + start.tv_nsec;
    end_time = end.tv_sec * 1000000000LL + end.tv_nsec;
    pulse_duration = end_time - start_time;

    // Calculate distance in centimeters
    return (float)pulse_duration * SOUND_SPEED_CM_US / 2000.0;
}

float measure_distance_inch()
{
    // Reuse cm measurement and convert
    float distance_cm = measure_distance_cm();
    if (distance_cm > 0) {
        return distance_cm / 2.54; // Convert cm to inches
    } else {
        return -1.0; // Propagate error
    }
}

