// Function to read temperature from MAX31855 via SPI
int read_temperature(int spi_channel, float *temperature) {
    unsigned char data[4];
    int result = wiringPiSPIDataRW(spi_channel, data, 4);
    if (result == -1) {
        fprintf(stderr, "SPI read failed.\n");
        return -1;
    }

    // Check for fault bits (bit 0)
    if (data[3] & 0x01) {
        fprintf(stderr, "MAX31855 fault detected: %x %x %x %x\n", data[0], data[1], data[2], data[3]);
        return -1; // Indicate an error
    }

    // Extract the thermocouple temperature (bits 31:18).  Shift right by 18 bits.
    int16_t raw_temp = ((data[0] << 8) | data[1]) >> 2; // Shift right by 2 to get rid of fault bits

    *temperature = (float)raw_temp * 0.25; // Each LSB is 0.25 degrees C

    return 0; // Success
}

// Function to perform temperature conversion and error handling
float process_temperature(float raw_temperature) {
    if (raw_temperature < 0.0 || raw_temperature > 100.0) {
        fprintf(stderr, "Temperature out of range: %.2f°C\n", raw_temperature);
        return -1.0; // Indicate an error
    }
    return raw_temperature;
}

// Function to calculate PID output
int calculate_pid(float setpoint, float current_temperature, float kp, float ki, float kd, float *previous_error, float *integral, float *derivative) {
    float error = setpoint - current_temperature;
    float proportional = kp * error;

    *integral += error * 0.1; // Integrate error over time (dt = 0.1s)
    // Integral windup prevention
    if (*integral > 100) *integral = 100;
    if (*integral < -100) *integral = -100;

    *derivative = (error - *previous_error) / 0.1; // Differentiate error over time (dt = 0.1s)

    float output = proportional + ki * (*integral) + kd * (*derivative);

    *previous_error = error;

    // Clamp output to 0-1000 (PWM range)
    if (output < 0) output = 0;
    if (output > 1000) output = 1000;

    return (int)output;
}

// Function to control the heater via PWM
void set_heater_pwm(int pin, int duty_cycle) {
    pwmWrite(pin, duty_cycle);
}

// Function to log temperature and duty cycle to a file
void log_data(float temperature, int duty_cycle) {
    FILE *fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file.\n");
        return;
    }

    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char s[64];
    strftime(s, sizeof(s), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(fp, "%s, Temperature: %.2f°C, Duty Cycle: %d\n", s, temperature, duty_cycle);
    fclose(fp);
}

int main() {
    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed.\n");
        return 1;
    }

    // Initialize SPI
    if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) == -1) {
        fprintf(stderr, "SPI initialization failed.\n");
        return 1;
    }

    // Configure heater pin as PWM output
    pinMode(HEATER_PIN, PWM_OUTPUT);
    pwmSetMode(PWM_MODE_MS); // Use mark:space PWM mode
    pwmSetRange(1000);       // Set PWM range to 0-1000
    pwmWrite(HEATER_PIN, 0);  // Initialize heater to off

    // Initialize PID variables
    float previous_error = 0.0;
    float integral = 0.0;
    float derivative = 0.0;
    float current_temperature;
    int duty_cycle;

    // Install signal handler
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Main loop
    while (program_running) {
        // Read temperature from MAX31855
        if (read_temperature(SPI_CHANNEL, &current_temperature) == 0) {
            // Process temperature
            float processed_temperature = process_temperature(current_temperature);

            if (processed_temperature != -1.0) {
                // Calculate PID output
                duty_cycle = calculate_pid(SETPOINT, processed_temperature, Kp, Ki, Kd, &previous_error, &integral, &derivative);

                // Set heater PWM
                set_heater_pwm(HEATER_PIN, duty_cycle);

                // Log data every second
                time_t now = time(NULL);
                static time_t last_log_time = 0;
                if (now - last_log_time >= 1) {
                    log_data(processed_temperature, duty_cycle);
                    last_log_time = now;
                }
            } else {
                // Temperature processing error, turn off heater
                pwmWrite(HEATER_PIN, 0);
                duty_cycle = 0;
            }
        } else {
            // SPI read error, turn off heater
            pwmWrite(HEATER_PIN, 0);
            duty_cycle = 0;
        }

        // Delay for 100ms
        delay(100);
    }

    // Cleanup and exit
    pwmWrite(HEATER_PIN, 0); // Turn off heater
    return 0;
}

