#include <stdio.h>
#include <bcm2835.h>
#include <unistd.h>

// MCP3008 Definitions
#define MCP3008_MOSI   RPI_GPIO_P1_19  // SPI0 MOSI on pin 19
#define MCP3008_MISO   RPI_GPIO_P1_21  // SPI0 MISO on pin 21
#define MCP3008_CLK    RPI_GPIO_P1_23  // SPI0 Clock on pin 23
#define MCP3008_CS     RPI_GPIO_P1_24  // SPI0 Chip Select on pin 24

int read_mcp3008(int channel)
{
    unsigned char cmdout[3];
    unsigned char data[3];
    int adc_value;

    // Build SPI command to read the specified channel
    cmdout[0] = 0x01; // Start bit
    cmdout[1] = ((channel & 0x07) << 4) | 0x80; // Single-ended mode, channel selection
    cmdout[2] = 0x00; // Don't care

    bcm2835_gpio_write(MCP3008_CS, LOW);
    bcm2835_spi_transfernb(cmdout, data, 3);
    bcm2835_gpio_write(MCP3008_CS, HIGH);

    // Extract the ADC value from the received data
    adc_value = ((data[1] & 0x03) << 8) | data[2];

    return adc_value;
}

int main(int argc, char **argv)
{
    if (!bcm2835_init()) {
        fprintf(stderr, "bcm2835_init failed. Are you running as root?\n");
        return 1;
    }

    // Configure GPIO pins for SPI communication
    bcm2835_gpio_fsel(MCP3008_MOSI, BCM2835_GPIO_FSEL_OUTP);
    bcm2835_gpio_fsel(MCP3008_MISO, BCM2835_GPIO_FSEL_INPT);
    bcm2835_gpio_fsel(MCP3008_CLK, BCM2835_GPIO_FSEL_OUTP);
    bcm2835_gpio_fsel(MCP3008_CS, BCM2835_GPIO_FSEL_OUTP);
    bcm2835_gpio_write(MCP3008_CS, HIGH);

    // SPI configuration
    bcm2835_spi_begin();
    bcm2835_spi_setBitOrder(BCM2835_SPI_BIT_ORDER_MSBFIRST);
    bcm2835_spi_setDataMode(BCM2835_SPI_MODE0);
    bcm2835_spi_setClockDivider(BCM2835_SPI_CLOCK_DIVIDER_64); // Adjust as needed
    bcm2835_spi_chipSelect(BCM2835_SPI_CS0);
    bcm2835_spi_setChipSelectPolarity(BCM2835_SPI_CS0, LOW);

    while (1) {
        int adc_value = read_mcp3008(0); // Read channel 0
        printf("%d\n", adc_value);
        fflush(stdout); // Important for real-time plotting
        usleep(50000); // Adjust delay as needed (50ms)
    }

    bcm2835_spi_end();
    bcm2835_close();

    return 0;
}

