#define SSD1306_I2C_ADDR  0x3C
#define SSD1306_WIDTH     128
#define SSD1306_HEIGHT    64
int i2c_fd;
void ssd1306_sendCommand(unsigned char command) {
    unsigned char buffer[2] = {0x00, command};
    write(i2c_fd, buffer, 2);
}
void ssd1306_init() {
    ssd1306_sendCommand(0xAE);
    ssd1306_sendCommand(0xAF);
}
void ssd1306_clearDisplay() {
    unsigned char buffer[1025] = {0x40};
    memset(buffer + 1, 0x00, 1024);
    write(i2c_fd, buffer, 1025);
}
void ssd1306_displayMultilineText() {
    unsigned char buffer[130] = {0x40};
    const char *text[] = {"LINE 1", "LINE 2", "LINE 3"};
    for (int line = 0; line < 3; line++) {
        int len = strlen(text[line]);
        if (len > 16) len = 16;
        for (int i = 0; i < len; i++) {
            buffer[(i * 6) + 1] = text[line][i];
        }
        write(i2c_fd, buffer, 130);
        sleep(2);
    }
}
int main() {
    if ((i2c_fd = open("/dev/i2c-1", O_RDWR)) < 0) {
        perror("Failed to open I2C bus");
        return EXIT_FAILURE;
    }
    if (ioctl(i2c_fd, I2C_SLAVE, SSD1306_I2C_ADDR) < 0) {
        perror("Failed to communicate with SSD1306");
        return EXIT_FAILURE;
    }
    ssd1306_init();
    ssd1306_clearDisplay();
    ssd1306_displayMultilineText();
    sleep(5);
    close(i2c_fd);
    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <wiringPiI2C.h>
#include <wiringPi.h>

// SSD1306 I2C address
#define OLED_ADDRESS 0x3C

// Screen dimensions
#define OLED_WIDTH 128
#define OLED_HEIGHT 64

// I2C file descriptor
int fd;

// Function to write a command to the OLED
void oled_command(unsigned char command) {
  unsigned char buf[2];
  buf[0] = 0x00; // Control byte: 0x00 for command
  buf[1] = command;
  write(fd, buf, 2);
}

// Function to write data to the OLED
void oled_data(unsigned char data) {
  unsigned char buf[2];
  buf[0] = 0x40; // Control byte: 0x40 for data
  buf[1] = data;
  write(fd, buf, 2);
}

// Function to initialize the OLED display
void oled_init() {
  oled_command(0xAE); // Display off
  oled_command(0xD5); // Set display clock divide ratio/oscillator frequency
  oled_command(0x80); // Default setting for display clock divide ratio/oscillator frequency
  oled_command(0xA8); // Set multiplex ratio (height-1)
  oled_command(0x3F); // 63
  oled_command(0xD3); // Set display offset
  oled_command(0x00); // 0
  oled_command(0x40); // Set display start line
  oled_command(0x8D); // Charge pump setting
  oled_command(0x14); // Enable charge pump
  oled_command(0x20); // Memory addressing mode
  oled_command(0x00); // Horizontal addressing mode
  oled_command(0xA1); // Set segment remap (A0/A1)
  oled_command(0xC8); // Set COM output scan direction
  oled_command(0xDA); // Set COM pins hardware configuration
  oled_command(0x12); // Alternative COM pin configuration
  oled_command(0x81); // Set contrast control register
  oled_command(0xCF); // Set contrast
  oled_command(0xD9); // Set pre-charge period
  oled_command(0xF1); // Set pre-charge period
  oled_command(0xDB); // Set VCOM deselect level
  oled_command(0x40); // Set VCOM deselect level
  oled_command(0xA4); // Entire display ON/OFF
  oled_command(0xA6); // Set normal display
  oled_command(0xAF); // Display on
}

// Function to clear the OLED display
void oled_clear() {
  for (int i = 0; i < (OLED_WIDTH * OLED_HEIGHT / 8); i++) {
    oled_data(0x00);
  }
}

// Function to draw a rectangle
void oled_draw_rectangle(int x1, int y1, int x2, int y2, unsigned char color) {
  // Simplified rectangle drawing. It actually fills entire bytes.
  for (int x = x1; x <= x2; x++) {
    for (int y = y1; y <= y2; y++) {
      // Calculate the byte and bit within that byte.
      int byte_index = x + (y / 8) * OLED_WIDTH;
      int bit_index = y % 8;

      // Access OLED memory directly via I2C.
      unsigned char buf[3];
      buf[0] = 0x40; // Data control byte

      // Send column and row addresses to set the drawing position
      oled_command(0x21); // Column address
      oled_command(x);
      oled_command(127);
      oled_command(0x22); //Page address
      oled_command(y / 8); 
      oled_command(7);   


      // Create a byte to write, with the proper bit set or cleared
        unsigned char data_to_write = (color) ? (1 << bit_index) : 0x00;

      // Update the memory with the new data
      buf[1] = data_to_write;
      write(fd, buf, 2);

    }
  }
}

int main() {
  if (wiringPiSetup() == -1) {
    fprintf(stderr, "WiringPi setup failed!\n");
    return 1;
  }

  // Initialize I2C
  fd = wiringPiI2CSetup(OLED_ADDRESS);
  if (fd == -1) {
    fprintf(stderr, "I2C setup failed!\n");
    return 1;
  }

  // Initialize the OLED display
  oled_init();

  // Clear the display
  oled_clear();

  // Draw a rectangle
  oled_draw_rectangle(20, 10, 100, 50, 1); // Draw from (20, 10) to (100, 50) with color 1 (white)

  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <errno.h>
#include <signal.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>

// MPR121 I2C address (default)
#define MPR121_I2C_ADDRESS 0x5A

// MPR121 Registers
#define MPR121_TOUCHSTATUS_REGISTER 0x00
#define MPR121_FILTERTH_REGISTER 0x24
#define MPR121_BASELINECONFIG_REGISTER 0x2B
#define MPR121_TOUCHTH_REGISTER 0x41
#define MPR121_RELEASETH_REGISTER 0x42
#define MPR121_ECR_REGISTER 0x5E

// File descriptor for I2C communication
int fd;

// File pointer for the log file
FILE *log_file;

// Function prototypes
int initialize_mpr121();
int read_touch_status(unsigned int *touch_status);
int process_access(unsigned int touch_status);
int log_access(unsigned int touch_status, int access_result);
void handle_error(const char *message);
void signal_handler(int signum);

int main()
{
    // Initialize WiringPi
    if (wiringPiSetup() == -1)
    {
        handle_error("Failed to initialize WiringPi.");
        return 1;
    }

    // Initialize I2C communication
    fd = wiringPiI2CSetup(MPR121_I2C_ADDRESS);
    if (fd < 0)
    {
        handle_error("Failed to initialize I2C communication.");
        return 1;
    }

    // Initialize the MPR121
    if (initialize_mpr121() != 0)
    {
        handle_error("Failed to initialize MPR121.");
        return 1;
    }

    // Open the log file
    log_file = fopen("access_log.txt", "a");
    if (log_file == NULL)
    {
        handle_error("Failed to open access_log.txt.");
        return 1;
    }

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Main loop
    unsigned int touch_status;
    while (1)
    {
        // Read touch status from the MPR121
        if (read_touch_status(&touch_status) == 0)
        {
            // Process access based on touch status
            process_access(touch_status);
        }

        delay(100); // Delay for 100ms
    }

    return 0;
}

// Initializes the MPR121 capacitive touch sensor
int initialize_mpr121()
{
    // Stop mode
    wiringPiI2CWriteReg8(fd, MPR121_ECR_REGISTER, 0x00);
    delay(1);

    // Configure Electrode Filter
    wiringPiI2CWriteReg8(fd, MPR121_FILTERTH_REGISTER, 0x10); // Default value
    delay(1);

    // Configure Baseline Filtering
    wiringPiI2CWriteReg8(fd, MPR121_BASELINECONFIG_REGISTER, 0x05); // Default value
    delay(1);

    // Set touch and release thresholds for all 12 electrodes
    for (int i = 0; i < 12; i++)
    {
        wiringPiI2CWriteReg8(fd, MPR121_TOUCHTH_REGISTER + 2 * i, 0x30); // Touch threshold
        wiringPiI2CWriteReg8(fd, MPR121_RELEASETH_REGISTER + 2 * i, 0x10); // Release threshold
        delay(1);
    }

    // Enable all electrodes
    wiringPiI2CWriteReg8(fd, MPR121_ECR_REGISTER, 0xBF); // Enable all electrodes, auto-config
    delay(1);

    return 0;
}

// Reads the touch status from the MPR121
int read_touch_status(unsigned int *touch_status)
{
    int touch_value = wiringPiI2CReadReg16(fd, MPR121_TOUCHSTATUS_REGISTER);
    if (touch_value < 0)
    {
        handle_error("Failed to read touch status.");
        return -1;
    }

    *touch_status = (unsigned int)touch_value & 0x0FFF; // Mask out irrelevant bits
    return 0;
}

// Processes the access control logic based on the touch status
int process_access(unsigned int touch_status)
{
    int access_result;

    // Define the correct touch combination (electrodes 0 and 1)
    unsigned int correct_combination = (1 << 0) | (1 << 1);

    // Check if the correct combination is touched
    if ((touch_status & correct_combination) == correct_combination)
    {
        // Grant access
        printf("Access Granted!\n");
        access_result = 1; // Granted
    } else {
        // Deny access
        printf("Access Denied!\n");
        access_result = 0; // Denied
    }

    // Log the access attempt
    log_access(touch_status, access_result);

    return access_result;
}

// Logs the access attempt to the log file
int log_access(unsigned int touch_status, int access_result)
{
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];
    char electrode_numbers[50] = "";
    int electrode_count = 0;

    // Get current time
    time(&rawtime);
    timeinfo = localtime(&rawtime);
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    // Determine which electrodes were touched
    for (int i = 0; i < 12; i++)
    {
        if (touch_status & (1 << i))
        {
            if (electrode_count > 0)
            {
                strcat(electrode_numbers, ", ");
            }
            char electrode_str[5];
            sprintf(electrode_str, "%d", i);
            strcat(electrode_numbers, electrode_str);
            electrode_count++;
        }
    }

    // Determine access result string
    const char *access_string = (access_result == 1) ? "Granted" : "Denied";

    // Create the log entry
    fprintf(log_file, "%s - Touch: [%s] - Access: %s\n", timestamp, electrode_numbers, access_string);
    fflush(log_file); // Flush the buffer to ensure the log is written immediately

    return 0;
}

// Handles errors by printing to stderr and logging to the log file
void handle_error(const char *message)
{
    fprintf(stderr, "Error: %s %s\n", message, strerror(errno));
    if (log_file != NULL)
    {
        time_t rawtime;
        struct tm *timeinfo;
        char timestamp[20];

        time(&rawtime);
        timeinfo = localtime(&rawtime);
        strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

        fprintf(log_file, "%s - ERROR: %s %s\n", timestamp, message, strerror(errno));
        fflush(log_file);
    }
    perror(message); // Print system error message
}

// Signal handler for graceful shutdown (e.g., Ctrl+C)
void signal_handler(int signum)
{
    if (signum == SIGINT)
    {
        printf("Received SIGINT. Shutting down gracefully...\n");

        // Close the log file
        if (log_file != NULL)
        {
            fclose(log_file);
        }

        // Reset MPR121 to stop mode
        wiringPiI2CWriteReg8(fd, MPR121_ECR_REGISTER, 0x00);

        exit(0);
    }
}

#include <pigpio.h>
#include <stdio.h>
#define BUZZER 17
int read_mcp3008(int spi, int ch) {
    char tx[3] = {1, (0x80 | (ch << 4)), 0}, rx[3];
    spiXfer(spi, tx, rx, 3);
    return ((rx[1] & 3) << 8) | rx[2];
}
int main() {
    if (gpioInitialise() < 0) return 1;
    gpioSetMode(BUZZER, PI_OUTPUT);
    int spi = spiOpen(0, 1000000, 0);
    int threshold = 512;
    while (1) {
        int val = read_mcp3008(spi, 1);
        gpioWrite(BUZZER, val > threshold);
        gpioDelay(200000);
    }
    spiClose(spi);
    gpioTerminate();
    return 0;
}

