    pcf8591Setup(PCF8591_BASE, PCF8591_I2C_ADDRESS);

    printf("PCF8591 ADC/DAC Example\n");

    while (1) {
        // Read analog value from ADC channel A0
        adc_value = analogRead(ADC_CHANNEL_A0);

        // Check for errors during analogRead
        if (adc_value == -1) {
            fprintf(stderr, "Error reading ADC channel A0\n");
        } else {
            // Print the ADC value
            printf("ADC Channel A0: %d\n", adc_value);

            // Write the ADC value to the DAC (channel 0)
            analogWrite(PCF8591_BASE, adc_value);

            // Print the DAC output value (which should be the same as ADC input)
            printf("DAC Output: %d\n", adc_value);
        }

        // Delay for a short period
