#include <wiringPi.h>
#include <wiringPiSPI.h>
#include <stdio.h>
#include <time.h>
#define BUTTON_PIN 2
int read_adc(int ch) {
    unsigned char buf[3] = {1, (0x80 | (ch << 4)), 0};
    wiringPiSPIDataRW(0, buf, 3);
    return ((buf[1] & 3) << 8) | buf[2];
}
int main() {
    wiringPiSetup();
    wiringPiSPISetup(0, 1000000);
    pinMode(BUTTON_PIN, INPUT);
    pullUpDnControl(BUTTON_PIN, PUD_UP);

    FILE* f = fopen("toggle_log.csv", "w");
    fprintf(f, "Time,ADC_Value\n");

    int logging = 0;
    int last_state = 1;

    while (1) {
        int btn_state = digitalRead(BUTTON_PIN);
        if (btn_state == 0 && last_state == 1) {
            logging = !logging;
            printf(logging ? "[Logging started]\n" : "[Logging stopped]\n");
            delay(300); // debounce delay
        }
        last_state = btn_state;

        if (logging) {
            int val = read_adc(0);
            fprintf(f, "%ld,%d\n", time(NULL), val);
            fflush(f);
        }
        delay(200);
    }
    fclose(f);
    return 0;
}

