#define WATER_SENSOR_CHANNEL PCF8591_BASE + 0 // A0
#define BUZZER_GPIO_PIN 18 // BCM GPIO 18
#define WATER_LEVEL_THRESHOLD 30
#define READ_DELAY_MS 100

// Function prototypes
int initialize();
void read_water_level_and_alert();

int main()
{
    if (initialize() != 0) {
        fprintf(stderr, "Initialization failed. Exiting.\n");
        return 1;
    }

    printf("Water level monitoring started. Press Ctrl+C to exit.\n");

    while (1) {
        read_water_level_and_alert();
        delay(READ_DELAY_MS);
    }

