    pcf8591Setup(PCF8591_BASE, PCF8591_ADDRESS);

    // Buzzer pin setup
    pinMode(BUZZER_GPIO_PIN, OUTPUT);
    digitalWrite(BUZZER_GPIO_PIN, LOW); // Ensure buzzer is initially off

    return 0; // Success
}

void read_water_level_and_alert()
{
    int sensor_value = analogRead(WATER_SENSOR_CHANNEL);

    printf("Water sensor value: %d\n", sensor_value);

    if (sensor_value > WATER_LEVEL_THRESHOLD) {
        printf("Water level too high! Activating buzzer.\n");
        digitalWrite(BUZZER_GPIO_PIN, HIGH); // Turn buzzer on
    } else {
        digitalWrite(BUZZER_GPIO_PIN, LOW);  // Turn buzzer off
    }
}

#include <wiringPi.h>
#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#define BUZZER 18
#define BUTTON 24
#define NOTES {262, 294, 330, 349, 392, 440, 494, 523}

void playTone(int freq, int duration) {
    pwmSetRange(600000 / freq);
    pwmWrite(BUZZER, 300);
    delay(duration);
    pwmWrite(BUZZER, 0);
    delay(50);
}

int main() {
    if (wiringPiSetupGpio() == -1) return 1;
    pinMode(BUZZER, PWM_OUTPUT);
    pinMode(BUTTON, INPUT);
    pullUpDnControl(BUTTON, PUD_UP);
    pwmSetMode(PWM_MODE_MS);
    pwmSetClock(32);
    srand(time(0));

    int notes[] = NOTES;
    while (1) {
        if (digitalRead(BUTTON) == 0) {
            for (int i = 0; i < 5; i++) {
                int randNote = notes[rand() % 8];
                playTone(randNote, 300);
            }
        } else {
            pwmWrite(BUZZER, 0);
        }
        delay(100);
    }
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <unistd.h>

// Define the data and clock pins connected to the LED matrix driver
#define DATA_PIN  0  // WiringPi pin 0 (GPIO 17)
#define CLOCK_PIN 1  // WiringPi pin 1 (GPIO 18)
#define LATCH_PIN 2  // WiringPi pin 2 (GPIO 27)

// Number of rows and columns in the LED matrix
#define NUM_ROWS 8
#define NUM_COLS 8

// Function to shift out data to the LED matrix driver
void shiftOut(unsigned char dataPin, unsigned char clockPin, unsigned char data) {
    for (int i = 0; i < 8; i++) {
        digitalWrite(clockPin, LOW);
        digitalWrite(dataPin, (data >> (7 - i)) & 0x01);
        digitalWrite(clockPin, HIGH);
    }
}

// Function to display a single row on the LED matrix
void displayRow(unsigned char rowData[]) {
    // Send the row data to the shift registers
    for (int i = 0; i < NUM_ROWS; i++) {
        shiftOut(DATA_PIN, CLOCK_PIN, rowData[NUM_ROWS - 1 - i]);
    }

    // Latch the data to display it on the LED matrix
    digitalWrite(LATCH_PIN, LOW);
    digitalWrite(LATCH_PIN, HIGH);
    digitalWrite(LATCH_PIN, LOW);
}

int main() {
    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed!\n");
        return 1;
    }

    // Set the data, clock, and latch pins as outputs
    pinMode(DATA_PIN, OUTPUT);
    pinMode(CLOCK_PIN, OUTPUT);
    pinMode(LATCH_PIN, OUTPUT);

    // Create a row of data to scroll
    unsigned char rowData[NUM_ROWS];
    for (int i = 0; i < NUM_ROWS; i++) {
        rowData[i] = 0x00; // Initialize all rows to off (grounded cathode)
    }

    // Start with a single LED lit
    rowData[0] = 0x80; // Set the first row to a single lit LED

    // Main loop to scroll the light
    while (1) {
        // Display the current row
        displayRow(rowData);

        // Shift the row data to the right
        unsigned char temp = rowData[0];
        for (int i = 0; i < NUM_ROWS - 1; i++) {
            rowData[i] = rowData[i+1];
        }
        rowData[NUM_ROWS - 1] = temp;

        // Delay for a short time
        usleep(100000); // Delay for 100 milliseconds
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <time.h>
#include <pigpio.h>
#include <string.h>

// Constants
#define I2C_BUS 1
#define LM75_ADDR 0x48
#define FAN_GPIO 18
#define PWM_FREQUENCY 1000
#define TEMP_READ_INTERVAL 5 // seconds
#define MIN_TEMP 25.0
#define MAX_TEMP 40.0

// Global variables
int i2c_handle;
volatile sig_atomic_t terminate = 0;

// Function prototypes
double read_temperature();
void control_fan(double temperature);
void log_error(const char *message);
void signal_handler(int signal);

// Signal handler for graceful termination
void signal_handler(int signal) {
    terminate = 1;
}

// Reads temperature from LM75 sensor
double read_temperature() {
    char buf[2];
    int raw_temp;
    double temperature;

    int result = i2cReadDevice(i2c_handle, buf, 2);
    if (result != 2) {
        log_error("Failed to read temperature from LM75");
        return -100.0; // Indicate error
    }

    raw_temp = (buf[0] << 8) | buf[1];
    raw_temp = raw_temp >> 5; // Shift to get the temp value.

    // Handle the sign bit (MSB of the 11-bit value)
    if (raw_temp & (1 << 10)) {
        // Negative temperature
        raw_temp &= 0x3FF; // Clear the sign bit for calculation
        temperature = - (double)(~(raw_temp - 1) & 0x3FF) * 0.125; // Two's complement
    } else {
        // Positive temperature
        temperature = (double)raw_temp * 0.125;
    }

    return temperature;
}

// Controls fan speed based on temperature
void control_fan(double temperature) {
    int duty_cycle;

    if (temperature < MIN_TEMP) {
        duty_cycle = 0;
    } else if (temperature > MAX_TEMP) {
        duty_cycle = 1000000; // 100% duty cycle
    } else {
        duty_cycle = (int)(((temperature - MIN_TEMP) / (MAX_TEMP - MIN_TEMP)) * 1000000.0);
    }

    gpioPWM(FAN_GPIO, duty_cycle);
    printf("Temperature: %.2f°C, Fan Duty Cycle: %d\n", temperature, duty_cycle);
}

// Logs errors to error.log with timestamp
void log_error(const char *message) {
    FILE *fp = fopen("error.log", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening error.log file!\n");
        return;
    }

    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(fp, "[%s] Error: %s\n", timestamp, message);
    fclose(fp);
    fprintf(stderr, "[%s] Error: %s\n", timestamp, message);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO 18 as output for PWM
    gpioSetMode(FAN_GPIO, PI_OUTPUT);

    // Set PWM frequency
    gpioSetPWMfrequency(FAN_GPIO, PWM_FREQUENCY);

    // Set PWM range (0-1000000 for 0-100%)
    gpioSetPWMrange(FAN_GPIO, 1000000);

    // Open I2C device
    i2c_handle = i2cOpen(I2C_BUS, LM75_ADDR, 0);
    if (i2c_handle < 0) {
        log_error("Failed to open I2C device");
        gpioTerminate();
        return 1;
    }

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Temperature-controlled fan started. Press Ctrl+C to exit.\n");

    // Main loop
    while (!terminate) {
        double temperature = read_temperature();
        if (temperature != -100.0) {
            control_fan(temperature);
        }
        sleep(TEMP_READ_INTERVAL);
    }

    // Cleanup
    printf("Cleaning up and exiting...\n");
    gpioPWM(FAN_GPIO, 0); // Turn off fan
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pigpio.h>

// Define GPIO pins for pan and tilt servos
#define PAN_GPIO 17
#define TILT_GPIO 18

// Define angle limits
#define MIN_ANGLE 0
#define MAX_ANGLE 180
#define NEUTRAL_ANGLE 90

// Function prototypes
int set_servo_angle(int gpio, int angle);
int get_user_input(int *pan_angle, int *tilt_angle);
void error_handler(const char *message);
void cleanup(int signum);

// Global variables (only for signal handling)
volatile sig_atomic_t running = 1;

// Signal handler for graceful exit
void cleanup(int signum) {
    running = 0;
    printf("\nCleaning up and exiting...\n");
    // Set servos to neutral position
    set_servo_angle(PAN_GPIO, NEUTRAL_ANGLE);
    set_servo_angle(TILT_GPIO, NEUTRAL_ANGLE);

    // Stop pigpio daemon
    gpioTerminate();
    exit(0);
}

// Function to set the servo angle
int set_servo_angle(int gpio, int angle) {
    if (angle < MIN_ANGLE || angle > MAX_ANGLE) {
        fprintf(stderr, "Error: Angle out of range (%d). Must be between %d and %d.\n", angle, MIN_ANGLE, MAX_ANGLE);
        return -1; // Indicate failure
    }

    // Convert angle to pulse width (500-2500 us)
    int pulse_width = 500 + (int)((float)(angle) / 180.0 * 2000.0);

    // Set the servo pulse width
    gpioPWM(gpio, pulse_width); // Use PWM instead of servo function

    return 0; // Indicate success
}

// Function to get user input and update angles
int get_user_input(int *pan_angle, int *tilt_angle) {
    char input;
    printf("Enter command (w: up, s: down, a: left, d: right, q: quit): ");
    scanf(" %c", &input); // Note the space before %c to consume any leftover newline

    switch (input) {
        case 'w': // Up (increment tilt)
            *tilt_angle += 5;
            if (*tilt_angle > MAX_ANGLE) *tilt_angle = MAX_ANGLE;
            break;
        case 's': // Down (decrement tilt)
            *tilt_angle -= 5;
            if (*tilt_angle < MIN_ANGLE) *tilt_angle = MIN_ANGLE;
            break;
        case 'a': // Left (decrement pan)
            *pan_angle -= 5;
            if (*pan_angle < MIN_ANGLE) *pan_angle = MIN_ANGLE;
            break;
        case 'd': // Right (increment pan)
            *pan_angle += 5;
            if (*pan_angle > MAX_ANGLE) *pan_angle = MAX_ANGLE;
            break;
        case 'q': // Quit
            running = 0;
            break;
        default:
            printf("Invalid command.\n");
            return -1;
    }
    return 0;
}

// Function to handle errors
void error_handler(const char *message) {
    fprintf(stderr, "Error: %s\n", message);
    // Optionally, perform cleanup here if the error is critical
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        error_handler("pigpio initialisation failed");
        return 1;
    }

    // Set GPIO modes to PWM output
    gpioSetMode(PAN_GPIO, PI_OUTPUT);
    gpioSetMode(TILT_GPIO, PI_OUTPUT);

    // Initialize servo angles to neutral position
    int pan_angle = NEUTRAL_ANGLE;
    int tilt_angle = NEUTRAL_ANGLE;

    // Set initial servo angles
    if (set_servo_angle(PAN_GPIO, pan_angle) != 0) {
        error_handler("Failed to set initial pan angle");
        gpioTerminate();
        return 1;
    }
    if (set_servo_angle(TILT_GPIO, tilt_angle) != 0) {
        error_handler("Failed to set initial tilt angle");
        gpioTerminate();
        return 1;
    }

    // Install signal handler for Ctrl+C
    signal(SIGINT, cleanup);

    // Main control loop
    while (running) {
        if (get_user_input(&pan_angle, &tilt_angle) == 0) {
            if (set_servo_angle(PAN_GPIO, pan_angle) != 0) {
                error_handler("Failed to set pan angle");
            }
            if (set_servo_angle(TILT_GPIO, tilt_angle) != 0) {
                error_handler("Failed to set tilt angle");
            }
        }
        gpioDelay(100); // Small delay to prevent excessive CPU usage
    }

    // Cleanup and exit (should also be called by signal handler)
    cleanup(0);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <signal.h>
#include <time.h>
#include <math.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>

// MPU6050 I2C address
#define MPU6050_ADDR 0x68

// MPU6050 registers
#define MPU6050_PWR_MGMT_1 0x6B
#define MPU6050_ACCEL_XOUT_H 0x3B
#define MPU6050_ACCEL_YOUT_H 0x3D
#define MPU6050_ACCEL_ZOUT_H 0x3F

// Servo motor GPIO pin
#define SERVO_PIN 17

// Servo PWM values (adjust based on your servo)
#define SERVO_MIN_PWM 50
#define SERVO_MAX_PWM 250
#define SERVO_NEUTRAL_ANGLE 90

//Tilt threshold
#define TILT_THRESHOLD 15.0f

// Global variables
static int i2c_fd;
static FILE *log_file;
static volatile sig_atomic_t keep_running = 1;

// Calibration offsets
static float accel_x_offset = 0.0f;
static float accel_y_offset = 0.0f;
static float accel_z_offset = 0.0f;

// Function prototypes
void signal_handler(int sig);
int init_i2c(int address);
int init_gpio(int pin);
int init_mpu6050(int fd);
void calibrate_mpu6050(int fd);
void read_accelerometer_data(int fd, int16_t *accel_x, int16_t *accel_y, int16_t *accel_z);
float calculate_roll(int16_t accel_x, int16_t accel_y, int16_t accel_z);
float calculate_pitch(int16_t accel_x, int16_t accel_y, int16_t accel_z);
void adjust_servo(int angle);
void log_data(float roll, float pitch);

// Signal handler for graceful shutdown
void signal_handler(int sig) {
    if (sig == SIGINT) {
        printf("Caught SIGINT, exiting gracefully.\n");
        keep_running = 0;
        adjust_servo(SERVO_NEUTRAL_ANGLE); // Set servo to neutral position
        if (log_file != NULL) {
            fclose(log_file);
        }
        exit(0);
    }
}

// Initialize I2C communication
int init_i2c(int address) {
    int fd = wiringPiI2CSetup(address);
    if (fd == -1) {
        perror("Failed to initialize I2C communication");
        return -1;
    }
    return fd;
}

// Initialize GPIO pin for servo motor
int init_gpio(int pin) {
    wiringPiSetup();
    pinMode(pin, PWM_OUTPUT);
    pwmSetMode(PWM_MODE_MS); // Optional: Set PWM mode
    pwmSetRange(1000); // Adjust range as needed
    pwmSetClock(192); // Adjust clock divider as needed
    return 0;
}

// Initialize MPU6050
int init_mpu6050(int fd) {
    // Wake up the MPU6050 (clear sleep mode bit)
    if (wiringPiI2CWriteReg8(fd, MPU6050_PWR_MGMT_1, 0) == -1) {
        fprintf(stderr, "Error: Could not wake up MPU6050\n");
        return -1;
    }
    delay(100); // Allow time for the MPU6050 to wake up
    return 0;
}

// Calibrate MPU6050
void calibrate_mpu6050(int fd) {
    const int num_samples = 1000;
    int16_t accel_x, accel_y, accel_z;
    float x_sum = 0.0f, y_sum = 0.0f, z_sum = 0.0f;

    printf("Calibrating MPU6050...\n");
    for (int i = 0; i < num_samples; ++i) {
        read_accelerometer_data(fd, &accel_x, &accel_y, &accel_z);
        x_sum += accel_x;
        y_sum += accel_y;
        z_sum += accel_z;
        delay(2); // Short delay between samples
    }

    accel_x_offset = x_sum / num_samples;
    accel_y_offset = y_sum / num_samples;
    accel_z_offset = z_sum / num_samples - 16384.0f; // Assuming 1g = 16384

    printf("Calibration complete. Offsets: X=%.2f, Y=%.2f, Z=%.2f\n", accel_x_offset, accel_y_offset, accel_z_offset);
}

// Read raw accelerometer data from MPU6050
void read_accelerometer_data(int fd, int16_t *accel_x, int16_t *accel_y, int16_t *accel_z) {
    *accel_x = (int16_t)((wiringPiI2CReadReg8(fd, MPU6050_ACCEL_XOUT_H) << 8) | wiringPiI2CReadReg8(fd, MPU6050_ACCEL_XOUT_H + 1));
    *accel_y = (int16_t)((wiringPiI2CReadReg8(fd, MPU6050_ACCEL_YOUT_H) << 8) | wiringPiI2CReadReg8(fd, MPU6050_ACCEL_YOUT_H + 1));
    *accel_z = (int16_t)((wiringPiI2CReadReg8(fd, MPU6050_ACCEL_ZOUT_H) << 8) | wiringPiI2CReadReg8(fd, MPU6050_ACCEL_ZOUT_H + 1));
}

// Calculate roll angle in degrees
float calculate_roll(int16_t accel_x, int16_t accel_y, int16_t accel_z) {
    float x = (float)accel_x - accel_x_offset;
    float y = (float)accel_y - accel_y_offset;
    float z = (float)accel_z - accel_z_offset;
    return atan2f(y, sqrtf(x * x + z * z)) * 180.0f / M_PI;
}

// Calculate pitch angle in degrees
float calculate_pitch(int16_t accel_x, int16_t accel_y, int16_t accel_z) {
    float x = (float)accel_x - accel_x_offset;
    float y = (float)accel_y - accel_y_offset;
    float z = (float)accel_z - accel_z_offset;
    return atan2f(-x, sqrtf(y * y + z * z)) * 180.0f / M_PI;
}

// Adjust servo motor angle
void adjust_servo(int angle) {
    if (angle < 0) angle = 0;
    if (angle > 180) angle = 180;

    // Map angle (0-180) to PWM value (SERVO_MIN_PWM - SERVO_MAX_PWM)
    int pwm_value = SERVO_MIN_PWM + (int)((float)(angle) / 180.0f * (SERVO_MAX_PWM - SERVO_MIN_PWM));
    pwmWrite(SERVO_PIN, pwm_value);
    printf("Servo angle: %d, PWM: %d\n", angle, pwm_value);
}

// Log data to file
void log_data(float roll, float pitch) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(log_file, "%s Roll: %.2f, Pitch: %.2f\n", timestamp, roll, pitch);
    fflush(log_file); // Ensure data is written to file immediately
}

int main() {
    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize I2C
    i2c_fd = init_i2c(MPU6050_ADDR);
    if (i2c_fd == -1) {
        return 1;
    }

    // Initialize GPIO for servo motor
    if (init_gpio(SERVO_PIN) != 0) {
        fprintf(stderr, "Failed to initialize GPIO for servo motor.\n");
        return 1;
    }

    // Initialize MPU6050
    if (init_mpu6050(i2c_fd) != 0) {
        return 1;
    }

    // Calibrate MPU6050
    calibrate_mpu6050(i2c_fd);

    // Open log file
    log_file = fopen("solar_log.txt", "a");
    if (log_file == NULL) {
        perror("Failed to open log file");
        return 1;
    }

    int16_t accel_x, accel_y, accel_z;
    float roll, pitch;

    printf("Starting solar panel tilt monitoring...\n");

    while (keep_running) {
        // Read accelerometer data
        read_accelerometer_data(i2c_fd, &accel_x, &accel_y, &accel_z);

        // Calculate roll and pitch angles
        roll = calculate_roll(accel_x, accel_y, accel_z);
        pitch = calculate_pitch(accel_x, accel_y, accel_z);

        // Log data
        log_data(roll, pitch);

        // Adjust servo motor if tilt exceeds threshold
        if (fabs(roll) > TILT_THRESHOLD || fabs(pitch) > TILT_THRESHOLD) {
            // Basic adjustment logic: Try to bring angles closer to zero.
            int servo_angle = SERVO_NEUTRAL_ANGLE - (int)(roll * 2); //Adjust multiplier as needed.
            adjust_servo(servo_angle);
        }

        delay(100); // Delay for 100ms
    }

    // Close log file and cleanup
    fclose(log_file);
    return 0;
}

#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
#include <errno.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <stdbool.h>
#include <time.h>
#include <math.h>

// Constants
#define D6F_PH_I2C_ADDR 0x6C  // D6F-PH I2C address (7-bit)
#define I2C_DEV_PATH "/dev/i2c-1" // I2C device path

// Function Prototypes
int i2c_write(int file_descriptor, uint8_t device_address, uint8_t *data, uint16_t length);
int i2c_read(int file_descriptor, uint8_t device_address, uint8_t register_address, uint8_t *data, uint16_t length);
float read_differential_pressure(int file_descriptor);

// Helper Functions
uint16_t bytes_to_uint16(uint8_t *buffer);
void delay_ms(int milliseconds);

int main() {
    int i2c_file_descriptor;

    // Open I2C device
    if ((i2c_file_descriptor = open(I2C_DEV_PATH, O_RDWR)) < 0) {
        fprintf(stderr, "Error: Could not open I2C device %s: %s\n", I2C_DEV_PATH, strerror(errno));
        return EXIT_FAILURE;
    }

    // Initialize sensor (0Bh, 00h)
    uint8_t init_data[] = {0x0B, 0x00};
    if (i2c_write(i2c_file_descriptor, D6F_PH_I2C_ADDR, init_data, 2) != 0) {
        fprintf(stderr, "Error: Failed to initialize sensor.\n");
        close(i2c_file_descriptor);
        return EXIT_FAILURE;
    }
    delay_ms(900);

    // Main loop
    while (1) {
        float pressure = read_differential_pressure(i2c_file_descriptor);
        if (isnan(pressure)){
            fprintf(stderr, "Error reading pressure. Retrying...\n");
            delay_ms(100);
            continue;
        }
        printf("Differential Pressure: %6.2f [Pa]\n", pressure);
        delay_ms(100); // Sample every 100ms
    }

    close(i2c_file_descriptor);
    return EXIT_SUCCESS;
}

// I2C Write Function
int i2c_write(int file_descriptor, uint8_t device_address, uint8_t *data, uint16_t length) {
    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Error: Could not set I2C slave address: %s\n", strerror(errno));
        return -1;
    }

    ssize_t bytes_written = write(file_descriptor, data, length);
    if (bytes_written != length) {
        fprintf(stderr, "Error: I2C write failed: %s (Wrote %zd/%d bytes)\n", strerror(errno), bytes_written, length);
        return -1;
    }

    return 0; // Success
}

// I2C Read Function
int i2c_read(int file_descriptor, uint8_t device_address, uint8_t register_address, uint8_t *data, uint16_t length) {
    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Error: Could not set I2C slave address: %s\n", strerror(errno));
        return -1;
    }

    // Write register address
    ssize_t bytes_written = write(file_descriptor, &register_address, 1);
    if (bytes_written != 1) {
        fprintf(stderr, "Error: Failed to write register address: %s\n", strerror(errno));
        return -1;
    }

    // Read data
    ssize_t bytes_read = read(file_descriptor, data, length);
    if (bytes_read != length) {
        fprintf(stderr, "Error: I2C read failed: %s (Read %zd/%d bytes)\n", strerror(errno), bytes_read, length);
        return -1;
    }

    return 0; // Success
}

// Function to Read Differential Pressure
float read_differential_pressure(int file_descriptor) {
    // Trigger data acquisition (0x00D0, 0x40, 0x18, 0x06)
    uint8_t trigger_data[] = {0x00, 0xD0, 0x40, 0x18, 0x06};
    if (i2c_write(file_descriptor, D6F_PH_I2C_ADDR, trigger_data + 2, 3) != 0) {
        fprintf(stderr, "Error: Failed to trigger data acquisition.\n");
        return NAN;
    }
    delay_ms(50);

    // Read data (0x00D0, 0x51, 0x2C) and register 0x07
    uint8_t read_command[] = {0x00, 0xD0, 0x51, 0x2C};
    uint8_t read_data[2];
    if (i2c_write(file_descriptor, D6F_PH_I2C_ADDR, read_command + 2, 2) != 0) {
        fprintf(stderr, "Error: Failed to send read command.\n");
        return NAN;
    }

    if (i2c_read(file_descriptor, D6F_PH_I2C_ADDR, 0x07, read_data, 2) != 0) {
        fprintf(stderr, "Error: Failed to read pressure data.\n");
        return NAN;
    }

    uint16_t raw_pressure = bytes_to_uint16(read_data);
    float flow_rate = ((float)raw_pressure - 1024.0) * 100.0 / 60000.0 - 50.0;
    return flow_rate;
}

// Helper Function: Convert 2 bytes to unsigned 16-bit integer (Big Endian)
uint16_t bytes_to_uint16(uint8_t *buffer) {
    return (uint16_t)((((uint16_t)buffer[0]) << 8) | ((uint16_t)buffer[1]));
}

// Helper Function: Delay for specified milliseconds
void delay_ms(int milliseconds) {
    struct timespec ts;
    ts.tv_sec = milliseconds / 1000;
    ts.tv_nsec = (milliseconds % 1000) * 1000000;
    nanosleep(&ts, NULL);
}

#include <signal.h>
#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <unistd.h>

// Define the dimensions of the LED matrix
#define MATRIX_SIZE 8

// Define GPIO pins for columns (anodes, sink current)
const int column_pins[MATRIX_SIZE] = {17, 7, 1, 23, 16, 18, 27, 14};

// Define GPIO pins for rows (cathodes, source current)
const int row_pins[MATRIX_SIZE] = {24, 22, 20, 15, 25, 21, 8, 12};

// Global flag to handle program termination via signal
volatile sig_atomic_t program_running = 1;

// Function prototypes
void cleanup_gpio();
void signal_handler(int signal);
int initialize_gpio();
void clear_matrix();
void display_pattern();

// Signal handler to gracefully terminate the program
void signal_handler(int signal) {
    if (signal == SIGINT) {
        program_running = 0;
        printf("\nCaught SIGINT.  Exiting gracefully.\n");
    }
}

// Initializes the GPIO library and sets pin modes
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "ERROR: pigpio initialisation failed\n");
        return -1; // Indicate failure
    }

    // Set column pins as outputs (sinking current, active low)
    for (int i = 0; i < MATRIX_SIZE; ++i) {
        if (gpioSetMode(column_pins[i], PI_OUTPUT) != 0) {
            fprintf(stderr, "ERROR: Failed to set column pin %d as output\n", column_pins[i]);
            cleanup_gpio();
            return -1;
        }
        gpioWrite(column_pins[i], PI_HIGH); // Initially off
    }

    // Set row pins as outputs (sourcing current, active high)
    for (int i = 0; i < MATRIX_SIZE; ++i) {
        if (gpioSetMode(row_pins[i], PI_OUTPUT) != 0) {
            fprintf(stderr, "ERROR: Failed to set row pin %d as output\n", row_pins[i]);
            cleanup_gpio();
            return -1;
        }
        gpioWrite(row_pins[i], PI_LOW); // Initially off
    }

    return 0; // Indicate success
}

// Clears the LED matrix (turns all LEDs off)
void clear_matrix() {
    for (int i = 0; i < MATRIX_SIZE; ++i) {
        gpioWrite(row_pins[i], PI_LOW);
        gpioWrite(column_pins[i], PI_HIGH);
    }
}

// Displays a simple pattern on the LED matrix
void display_pattern() {
    // Example pattern: Light up LEDs diagonally
    for (int i = 0; i < MATRIX_SIZE; ++i) {
        gpioWrite(row_pins[i], PI_HIGH);
        gpioWrite(column_pins[i], PI_LOW);
        usleep(1000); // 1 millisecond delay
        gpioWrite(row_pins[i], PI_LOW);
        gpioWrite(column_pins[i], PI_HIGH);
    }

     int x = 0;
        for (int i = 7; i >= 0; i--) {
            gpioWrite(row_pins[i], PI_HIGH);
            gpioWrite(column_pins[x], PI_LOW);
            usleep(1000); // Sleep for 1 ms
            gpioWrite(row_pins[i], PI_LOW);
            gpioWrite(column_pins[x], PI_HIGH);
            x++;
        }
}

// Releases GPIO resources and terminates the pigpio library
void cleanup_gpio() {
    // Set all pins to INPUT to avoid short circuits
    for (int i = 0; i < MATRIX_SIZE; ++i) {
        gpioSetMode(row_pins[i], PI_INPUT);
        gpioSetMode(column_pins[i], PI_INPUT);
    }
    gpioTerminate();
}

int main() {
    // Register the signal handler for SIGINT (Ctrl+C)
    signal(SIGINT, signal_handler);

    // Initialize the GPIO library and pins
    if (initialize_gpio() != 0) {
        fprintf(stderr, "Failed to initialize GPIO. Exiting.\n");
        return 1;
    }

    printf("LED Matrix Control - Press Ctrl+C to exit.\n");

    // Main loop: display the pattern repeatedly until a signal is received
    while (program_running) {
        display_pattern();
    }

    // Clean up GPIO resources before exiting
    cleanup_gpio();

    return 0;
}

