#define FLAME_SENSOR_PIN 4  // GPIO 4
#define BUZZER_PIN 17       // GPIO 17
#define LED_PIN 27          // GPIO 27

#define ALARM_DURATION 5    // seconds

FILE *log_file;

bool alarm_active = false; // Global flag to prevent signal handler from activating alarm.

void logEvent(const char *message) {
  time_t now = time(NULL);
  struct tm *tstruct = localtime(&now);
  char buf[80];
  strftime(buf, sizeof(buf), "%Y-%m-%d.%X", tstruct);
  fprintf(log_file, "%s: %s\n", buf, message);
  fflush(log_file);
  std::cout << buf << ": " << message << std::endl; // Also print to console
}

class FireAlarm {
private:
  int flameSensorPin;
  int buzzerPin;
  int ledPin;

public:
  FireAlarm(int flameSensorPin, int buzzerPin, int ledPin)
      : flameSensorPin(flameSensorPin), buzzerPin(buzzerPin), ledPin(ledPin) {}

  int initialize() {
    if (gpioInitialise() < 0) {
      logEvent("pigpio initialisation failed");
      return -1;
    }
    logEvent("pigpio initialised");

    if (gpioSetMode(flameSensorPin, PI_INPUT) != 0) {
      logEvent("Failed to set flame sensor pin as input");
      gpioTerminate();
      return -1;
    }
    logEvent("Flame sensor pin set as input");

    if (gpioSetMode(buzzerPin, PI_OUTPUT) != 0) {
      logEvent("Failed to set buzzer pin as output");
      gpioTerminate();
      return -1;
    }
    logEvent("Buzzer pin set as output");

    if (gpioSetMode(ledPin, PI_OUTPUT) != 0) {
      logEvent("Failed to set LED pin as output");
      gpioTerminate();
      return -1;
    }
    logEvent("LED pin set as output");

    deactivateAlarm(); // Ensure alarm is off at startup

    return 0;
  }

  bool readSensor() {
    int sensorValue = gpioRead(flameSensorPin);
    if (sensorValue == PI_HIGH || sensorValue == PI_LOW) {
      logEvent("Flame sensor reading successful");
      return (sensorValue == PI_LOW); // Logic low indicates flame detected
    } else {
      logEvent("Error reading flame sensor. Attempting re-initialization.");
      // Attempt re-initialization (crude, but demonstrates error handling)
      gpioTerminate();
      if (gpioInitialise() < 0) {
        logEvent("pigpio re-initialisation failed");
        return false; // Indicate error
      }
      if (gpioSetMode(flameSensorPin, PI_INPUT) != 0) {
          logEvent("Failed to reset flame sensor pin as input");
          return false;
      }
      return false; // Return false to prevent immediate alarm activation
    }
  }

  void activateAlarm() {
      if (!alarm_active) {
          if (gpioWrite(buzzerPin, PI_HIGH) == 0 && gpioWrite(ledPin, PI_HIGH) == 0) {
              logEvent("Alarm activated");
              alarm_active = true;
          } else {
              logEvent("Error activating alarm");
          }
      }
  }

  void deactivateAlarm() {
    if (gpioWrite(buzzerPin, PI_LOW) == 0 && gpioWrite(ledPin, PI_LOW) == 0) {
      logEvent("Alarm deactivated");
      alarm_active = false;
    } else {
      logEvent("Error deactivating alarm");
    }
  }

  void cleanup() {
    deactivateAlarm();
    gpioTerminate();
    logEvent("pigpio terminated");
  }
};

FireAlarm *fireAlarm;

void signalHandler(int signal) {
  logEvent("Signal received, shutting down...");
  if (fireAlarm != nullptr) {
    fireAlarm->cleanup();
  }
  fclose(log_file);
  exit(0);
}

int main() {
  log_file = fopen("fire_alarm.log", "a");
  if (log_file == NULL) {
    perror("Error opening log file");
    return 1;
  }
  logEvent("Starting fire alarm system");

  fireAlarm = new FireAlarm(FLAME_SENSOR_PIN, BUZZER_PIN, LED_PIN);

  if (fireAlarm->initialize() != 0) {
    logEvent("Fire alarm initialization failed");
    fclose(log_file);
    return 1;
  }

  signal(SIGINT, signalHandler);
  signal(SIGTERM, signalHandler);

  while (true) {
    if (fireAlarm->readSensor()) {
      fireAlarm->activateAlarm();
      gpioDelay(ALARM_DURATION * 1000); // Delay for alarm duration
      fireAlarm->deactivateAlarm();
    }
    gpioDelay(200); // Delay to avoid excessive CPU usage
  }

  // The program should never reach here in normal operation due to the infinite
  // loop and signal handling.
  delete fireAlarm;
  fclose(log_file);
  return 0;
}

#include <stdio.h>
#include <wiringPi.h>
