// Define the GPIO pins connected to the L293D motor driver
#define MOTOR_1_IN1 17 // GPIO 17 (Physical pin 11)
#define MOTOR_1_IN2 18 // GPIO 18 (Physical pin 12)
#define MOTOR_2_IN1 22 // GPIO 22 (Physical pin 15)
#define MOTOR_2_IN2 23 // GPIO 23 (Physical pin 16)

// Function to move motors forward
void moveForward() {
    digitalWrite(MOTOR_1_IN1, HIGH);
    digitalWrite(MOTOR_1_IN2, LOW);
    digitalWrite(MOTOR_2_IN1, HIGH);
    digitalWrite(MOTOR_2_IN2, LOW);
    printf("Moving Forward...\n");
}

// Function to move motors backward (reverse)
void moveBackward() {
    digitalWrite(MOTOR_1_IN1, LOW);
    digitalWrite(MOTOR_1_IN2, HIGH);
    digitalWrite(MOTOR_2_IN1, LOW);
    digitalWrite(MOTOR_2_IN2, HIGH);
    printf("Moving Backward...\n");
}

// Function to stop motors
void stopMotors() {
    digitalWrite(MOTOR_1_IN1, LOW);
    digitalWrite(MOTOR_1_IN2, LOW);
    digitalWrite(MOTOR_2_IN1, LOW);
    digitalWrite(MOTOR_2_IN2, LOW);
    printf("Stopping Motors...\n");
}

int main() {
    // Initialize wiringPi using the BCM pin numbering scheme
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "wiringPiSetupGpio failed!\n");
        return 1;
    }

    // Set the motor control pins as output
    pinMode(MOTOR_1_IN1, OUTPUT);
    pinMode(MOTOR_1_IN2, OUTPUT);
    pinMode(MOTOR_2_IN1, OUTPUT);
    pinMode(MOTOR_2_IN2, OUTPUT);

    // Move forward for 3 seconds
    moveForward();
    sleep(3);

    // Stop for 2 seconds
    stopMotors();
    sleep(2);

    // Move backward for 3 seconds
    moveBackward();
    sleep(3);

    // Stop the motors
    stopMotors();

    printf("Program complete.\n");

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <time.h>
#include <string.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/spi/spidev.h>
#include <errno.h>

#define SPI_BUS 0
#define SPI_CE 0
#define SPI_DEVICE "/dev/spidev0.0"
#define ADC_CHANNEL 1  //Analog input channel 1
#define LOG_FILE "adc_log.txt"

// Function to read from the SPI ADC
int read_adc(int spi_fd, int channel)
{
    uint8_t tx_buf[3];
    uint8_t rx_buf[3];
    struct spi_ioc_transfer spi;
    int ret;

    // MCP3008 Command: Start bit (1), SGL/DIFF (1), D2-D0 (channel selection), MSBF (0)
    tx_buf[0] = 0x01;
    tx_buf[1] = (0x08 | ((channel & 0x07) << 4));
    tx_buf[2] = 0x00;

    memset(&spi, 0, sizeof(spi));
    spi.tx_buf = (unsigned long)tx_buf;
    spi.rx_buf = (unsigned long)rx_buf;
    spi.len = 3;
    spi.speed_hz = 1000000; // 1 MHz
    spi.delay_usecs = 0;
    spi.bits_per_word = 8;
    spi.cs_change = 0;

    ret = ioctl(spi_fd, SPI_IOC_MESSAGE(1), &spi);
    if (ret < 0) {
        perror("SPI_IOC_MESSAGE");
        return -1;
    }

    // Combine the received bytes to get the ADC value
    int adc_value = ((rx_buf[1] & 0x03) << 8) + rx_buf[2];
    return adc_value;
}

int main()
{
    int spi_fd;
    FILE *log_fp;
    time_t start_time, current_time;
    int adc_value;
    char timestamp[30];
    struct tm *timeinfo;

    // Open SPI device
    spi_fd = open(SPI_DEVICE, O_RDWR);
    if (spi_fd < 0) {
        perror("Failed to open SPI device");
        return 1;
    }

    // Open log file
    log_fp = fopen(LOG_FILE, "a");
    if (log_fp == NULL) {
        perror("Failed to open log file");
        close(spi_fd);
        return 1;
    }

    time(&start_time);
    printf("Monitoring ADC Channel %d for 10 minutes. Logging to %s\n", ADC_CHANNEL, LOG_FILE);

    // Record data for 10 minutes (600 seconds)
    while (difftime(time(NULL), start_time) < 600)
    {
        adc_value = read_adc(spi_fd, ADC_CHANNEL);
        if (adc_value < 0) {
            fprintf(stderr, "Error reading ADC value. Exiting.\n");
            break;
        }

        time(&current_time);
        timeinfo = localtime(&current_time);
        strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

        fprintf(log_fp, "%s, %d\n", timestamp, adc_value);
        fflush(log_fp); // Ensure data is written to file immediately

        usleep(100000); //Sample every 100ms
    }

    printf("Monitoring finished.\n");

    // Close resources
    fclose(log_fp);
    close(spi_fd);

    return 0;
}

