// Function to initialize the RGB LED pins
int initRgbLed(void) {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return -1;
    }

    if (softPwmCreate(RED_PIN, 0, PWM_RANGE) != 0) {
        fprintf(stderr, "Failed to create soft PWM for RED_PIN: %s\n", strerror(errno));
        return -1;
    }
    if (softPwmCreate(GREEN_PIN, 0, PWM_RANGE) != 0) {
        fprintf(stderr, "Failed to create soft PWM for GREEN_PIN: %s\n", strerror(errno));
        return -1;
    }
    if (softPwmCreate(BLUE_PIN, 0, PWM_RANGE) != 0) {
        fprintf(stderr, "Failed to create soft PWM for BLUE_PIN: %s\n", strerror(errno));
        return -1;
    }

    return 0;
}

// Function to set the RGB LED color
void setRgbColor(int red, int green, int blue) {
    softPwmWrite(RED_PIN, red);
    softPwmWrite(GREEN_PIN, green);
    softPwmWrite(BLUE_PIN, blue);
}

int main(void) {
