#define LAMP_PIN_1 1
#define LAMP_PIN_4 4
#define LAMP_PIN_5 5
#define MAX_SCHEDULE_ENTRIES 24
#define SCHEDULE_FILE "schedule.txt"

struct scheduleEntry {
    int hour;
    int minute;
    int second;
    int brightness;
};

// Function to parse the schedule file
int parseSchedule(const char *filename, struct scheduleEntry *schedule, int *count) {
    FILE *fp = fopen(filename, "r");
    if (fp == NULL) {
        fprintf(stderr, "Error: Could not open schedule file %s: %s\n", filename, strerror(errno));
        return -1;
    }

    char line[64]; // Increased buffer size
    int entryCount = 0;

    while (fgets(line, sizeof(line), fp) != NULL) {
        int h, m, s, b;
        if (sscanf(line, "%d:%d:%d,%d", &h, &m, &s, &b) == 4) {
            if (h >= 0 && h <= 23 && m >= 0 && m <= 59 && s >= 0 && s <= 59 && b >= 0 && b <= 100) {
                schedule[entryCount].hour = h;
                schedule[entryCount].minute = m;
                schedule[entryCount].second = s;
                schedule[entryCount].brightness = b;
                entryCount++;
                if (entryCount >= MAX_SCHEDULE_ENTRIES) {
                    fprintf(stderr, "Warning: Maximum schedule entries reached (%d).  Ignoring further entries.\n", MAX_SCHEDULE_ENTRIES);
                    break;
                }
            } else {
                fprintf(stderr, "Error: Invalid schedule entry format: %s", line);
            }
        } else {
            fprintf(stderr, "Error: Invalid schedule entry format: %s", line);
        }
    }

    fclose(fp);
    *count = entryCount;
    return 0;
}

// Function to set the brightness of a lamp using PWM
void setBrightness(int pin, int brightness) {
    int pwmValue = (int)((brightness / 100.0) * 1023.0); // Scale brightness (0-100) to PWM range (0-1023)
    pwmWrite(pin, pwmValue);
}

int main() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error: wiringPiSetup failed. Ensure you are running with root privileges and wiringPi is properly installed.\n");
        return 1;
    }

    pinMode(LAMP_PIN_1, PWM_OUTPUT);
    pinMode(LAMP_PIN_4, PWM_OUTPUT);
    pinMode(LAMP_PIN_5, PWM_OUTPUT);

    struct scheduleEntry schedule[MAX_SCHEDULE_ENTRIES];
    int scheduleCount = 0;

    if (parseSchedule(SCHEDULE_FILE, schedule, &scheduleCount) != 0) {
        return 1;
    }

    printf("Schedule loaded with %d entries.\n", scheduleCount);

    while (1) {
        time_t now = time(NULL);
        struct tm *currentTime = localtime(&now);

        int currentHour = currentTime->tm_hour;
        int currentMinute = currentTime->tm_min;
        int currentSecond = currentTime->tm_sec;

        for (int i = 0; i < scheduleCount; i++) {
            if (schedule[i].hour == currentHour &&
                schedule[i].minute == currentMinute &&
                schedule[i].second <= currentSecond && currentSecond <= schedule[i].second + 1 ){

                printf("Setting brightness to %d at %02d:%02d:%02d\n", schedule[i].brightness, currentHour, currentMinute, currentSecond);
                setBrightness(LAMP_PIN_1, schedule[i].brightness);
                setBrightness(LAMP_PIN_4, schedule[i].brightness);
                setBrightness(LAMP_PIN_5, schedule[i].brightness);
                break; // Match found, no need to check other entries for this second
            }
        }

        delay(1000); // Check every second
    }

    return 0;
}

