#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>

// Define GPIO pins
#define PIR_SENSOR_PIN 17
#define BUZZER_PIN 18

// Global variable to track program termination
volatile sig_atomic_t program_running = 1;

// Function prototypes
int setup_gpio();
int read_sensor();
void activate_buzzer();
void write_log();
void signal_handler(int signal);

// Signal handler function to catch SIGINT (Ctrl+C)
void signal_handler(int signal) {
    if (signal == SIGINT) {
        program_running = 0;
        printf("\nCaught SIGINT, exiting gracefully.\n");
    }
}

// Function to initialize GPIO pins using pigpio
int setup_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Indicate failure
    }

    if (gpioSetMode(PIR_SENSOR_PIN, PI_INPUT) != 0) {
        fprintf(stderr, "Failed to set PIR sensor pin to input\n");
        gpioTerminate();
        return 1;
    }

    if (gpioSetMode(BUZZER_PIN, PI_OUTPUT) != 0) {
        fprintf(stderr, "Failed to set buzzer pin to output\n");
        gpioTerminate();
        return 1;
    }

    return 0; // Indicate success
}

// Function to read the PIR sensor value
int read_sensor() {
    int sensor_value = gpioRead(PIR_SENSOR_PIN);
    return sensor_value;
}

// Function to activate the buzzer for 1 second
void activate_buzzer() {
    if (gpioWrite(BUZZER_PIN, 1) != 0) { // Turn buzzer on
        fprintf(stderr, "Failed to write to buzzer pin\n");
    }
    gpioDelay(1000); // Wait for 1 second (1000 milliseconds)
    if (gpioWrite(BUZZER_PIN, 0) != 0) { // Turn buzzer off
        fprintf(stderr, "Failed to write to buzzer pin\n");
    }
}

// Function to write a timestamped log entry to file
void write_log() {
    FILE *fp = fopen("motion_log.txt", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(fp, "%d-%02d-%02d %02d:%02d:%02d - Motion Detected\n", tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec);

    fclose(fp);
}

int main() {
    // Set up signal handling for graceful shutdown
    signal(SIGINT, signal_handler);

    // Initialize GPIO
    if (setup_gpio() != 0) {
        return 1; // Exit if GPIO setup fails
    }

    printf("PIR sensor monitoring started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        // Read sensor value
        int sensor_value = read_sensor();

        // Check for motion
        if (sensor_value == 1) {
            printf("Motion detected!\n");
            activate_buzzer(); // Activate the buzzer
            write_log();       // Write to log file
            gpioDelay(500);    // Debounce delay (adjust as needed)
        } else {
            gpioDelay(100);    // Small delay to reduce CPU usage
        }
    }

    // Clean up GPIO before exiting
    gpioTerminate();
    printf("GPIO terminated. Exiting.\n");
    return 0;
}

