#include <string.h>

// Define GPIO pins
#define PIR_SENSOR_PIN 17
#define RELAY_PIN 27

// Log file name
#define LOG_FILE "door_log.txt"

// Global variable for log file pointer
FILE *log_file = NULL;

// Function prototypes
int read_pir_sensor(int gpio_pin);
int activate_relay(int gpio_pin, int duration_ms);
int log_timestamp(const char *filename);
void signal_handler(int signal);

/**
 * @brief Reads the state of the PIR sensor.
 * @param gpio_pin The GPIO pin connected to the PIR sensor.
 * @return 1 if motion is detected, 0 otherwise. Returns -1 on error.
 */
int read_pir_sensor(int gpio_pin) {
    int sensor_value = gpioRead(gpio_pin);

    if (sensor_value < 0) {
        fprintf(stderr, "Error reading PIR sensor on GPIO %d\n", gpio_pin);
        return -1; // Indicate an error
    } else if (sensor_value != 0 && sensor_value != 1) {
        fprintf(stderr, "Unexpected value from PIR sensor on GPIO %d: %d\n", gpio_pin, sensor_value);
        return -1; //Indicate an error
    }

    return sensor_value;
}

/**
 * @brief Activates the relay for a specified duration.
 * @param gpio_pin The GPIO pin connected to the relay.
 * @param duration_ms The duration in milliseconds to activate the relay.
 * @return 0 on success, -1 on error.
 */
int activate_relay(int gpio_pin, int duration_ms) {
    if (gpioWrite(gpio_pin, 1) != 0) { // Set GPIO HIGH to activate relay
        fprintf(stderr, "Error setting GPIO %d HIGH\n", gpio_pin);
        return -1;
    }

    gpioDelay(duration_ms * 1000); // Delay for the specified duration

    if (gpioWrite(gpio_pin, 0) != 0) { // Set GPIO LOW to deactivate relay
        fprintf(stderr, "Error setting GPIO %d LOW\n", gpio_pin);
        return -1;
    }

    return 0;
}

/**
 * @brief Logs the current timestamp to a file in ISO 8601 format.
 * @param filename The name of the log file.
 * @return 0 on success, -1 on error.
 */
int log_timestamp(const char *filename) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[30];

    time(&rawtime);
    timeinfo = gmtime(&rawtime); // Use gmtime for UTC time

    if (strftime(timestamp, sizeof(timestamp), "%Y-%m-%dT%H:%M:%SZ", timeinfo) == 0) {
        fprintf(stderr, "Error formatting timestamp\n");
        return -1;
    }

    if (log_file == NULL) {
      log_file = fopen(filename, "a");
      if (log_file == NULL) {
          fprintf(stderr, "Error opening log file %s\n", filename);
          return -1;
      }
    }

    fprintf(log_file, "%s\n", timestamp);
    fflush(log_file); // Ensure the data is written to the file immediately

    return 0;
}

/**
 * @brief Signal handler for graceful shutdown.
 * @param signal The signal received.
 */
void signal_handler(int signal) {
    printf("Received signal %d, shutting down...\n", signal);
    gpioWrite(RELAY_PIN, 0); // Ensure relay is off
    gpioTerminate(); // Terminate pigpio
    if (log_file != NULL) {
        fclose(log_file);
    }
    exit(0);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Configure GPIO pins
    gpioSetMode(PIR_SENSOR_PIN, PI_INPUT);
    gpioSetMode(RELAY_PIN, PI_OUTPUT);

    // Set pull-down resistor for PIR sensor pin
    gpioSetPullUpDown(PIR_SENSOR_PIN, PI_PUD_DOWN);

    // Initialize the relay pin to LOW (off)
    gpioWrite(RELAY_PIN, 0);

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Monitoring for motion...\n");

    while (1) {
        int pir_value = read_pir_sensor(PIR_SENSOR_PIN);
        if (pir_value == -1) {
            fprintf(stderr, "Error reading PIR sensor, continuing...\n");
            gpioDelay(100); // Small delay to prevent flooding the error log
            continue;
        }

        if (pir_value == 1) {
            printf("Motion detected!\n");
            if (activate_relay(RELAY_PIN, 1000) == 0) { // Activate relay for 1 second
                printf("Relay activated for 1 second\n");
                if (log_timestamp(LOG_FILE) == 0) {
                    printf("Timestamp logged\n");
                } else {
                    fprintf(stderr, "Error logging timestamp\n");
                }
            } else {
                fprintf(stderr, "Error activating relay\n");
            }
            gpioDelay(5000); // Debounce delay - prevent multiple triggers
        }

        gpioDelay(100); // Check every 100ms
    }

    return 0; // This line will never be reached due to the infinite loop
}

