#include <unistd.h>

// MPU6050 I2C address
#define MPU6050_ADDR 0x68

// MPU6050 registers
#define MPU6050_ACCEL_XOUT_H 0x3B
#define MPU6050_PWR_MGMT_1 0x6B
#define MPU6050_SMPLRT_DIV 0x19
#define MPU6050_CONFIG 0x1A
#define MPU6050_GYRO_CONFIG 0x1B
#define MPU6050_ACCEL_CONFIG 0x1C

// I2C handle
static int i2c_handle;

// PWM GPIO pin (using hardware PWM on GPIO18)
#define PWM_GPIO 18

// Flag to indicate program termination
static volatile int terminate = 0;

// Signal handler for Ctrl+C
void signal_handler(int signal)
{
    terminate = 1;
    printf("\nCaught signal %d, terminating...\n", signal);
}

// Function to read a word (2 bytes) from the MPU6050
int read_mpu6050_word(int i2c_handle, int reg)
{
    return i2cReadWordData(i2c_handle, reg);
}

// Function to write a byte to the MPU6050
int write_mpu6050_byte(int i2c_handle, int reg, int data)
{
    return i2cWriteByteData(i2c_handle, reg, data);
}

// Function to read the raw 'x' axis acceleration value from the MPU6050
int read_mpu6050_x_acceleration(int i2c_handle)
{
    int raw_x_accel = read_mpu6050_word(i2c_handle, MPU6050_ACCEL_XOUT_H);
    return raw_x_accel;
}

// Kalman filter function
float kalman_filter(float measurement)
{
    // Static variables to maintain Kalman filter state
    static float process_noise = 1e-5; // Adjust based on process noise
    static float measurement_noise = 0.1; // Adjust based on sensor noise
    static float error_covariance = 1; // Initial estimate error
    static float state_estimate = 0;   // Initial state estimate

    // Kalman gain calculation
    float kalman_gain = error_covariance / (error_covariance + measurement_noise);

    // Update state estimate
    state_estimate = state_estimate + kalman_gain * (measurement - state_estimate);

    // Update error covariance
    error_covariance = (1 - kalman_gain) * error_covariance + process_noise;

    return state_estimate;
}

// PWM interrupt service routine
void pwm_isr(int gpio, int level, uint32_t tick)
{
    (void)gpio; // unused
    (void)level; // unused
    (void)tick; // unused

    // Read raw acceleration data
    int raw_x_accel = read_mpu6050_x_acceleration(i2c_handle);

    // Apply Kalman filter
    float filtered_x_accel = kalman_filter((float)raw_x_accel);

    // Print the filtered acceleration value
    printf("Filtered X Acceleration: %.2f\n", filtered_x_accel);
}

int main()
{
    // Initialize pigpio
    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C bus
    i2c_handle = i2cOpen(1, MPU6050_ADDR, 0); // Bus 1, address 0x68, no flags
    if (i2c_handle < 0)
    {
        fprintf(stderr, "I2C open failed: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Initialize MPU6050 (wake up, set sample rate, configure accelerometer)
    write_mpu6050_byte(i2c_handle, MPU6050_PWR_MGMT_1, 0); // Wake up MPU6050
    write_mpu6050_byte(i2c_handle, MPU6050_SMPLRT_DIV, 0);  // Set sample rate divider to 0 (full rate)
    write_mpu6050_byte(i2c_handle, MPU6050_CONFIG, 0);      // Disable FSYNC, set DLPF to 0
    write_mpu6050_byte(i2c_handle, MPU6050_GYRO_CONFIG, 0); // Set gyro full scale to +/- 250 degrees/sec
    write_mpu6050_byte(i2c_handle, MPU6050_ACCEL_CONFIG, 0); // Set accelerometer full scale to +/- 2g

    // Set PWM frequency to 20Hz (50ms period)
    gpioSetTimerFuncEx(0, 50, pwm_isr, 0); // Timer 0, 50ms period, ISR function

    // Set signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Main loop (wait for termination signal)
    printf("Running... Press Ctrl+C to terminate.\n");
    while (!terminate)
    {
        sleep(1);
    }

    // Cleanup
    gpioSetTimerFuncEx(0, 0, NULL, 0); // Disable the timer
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

