#include <errno.h>

// Define GPIO pins for Trigger and Echo.  Using WiringPi numbering.
#define TRIGGER_PIN  4
#define ECHO_PIN     5

// Constants for calculations
#define SOUND_SPEED_CM_PER_S 34000.0f  // Speed of sound in cm/s
#define MICROSECONDS_TO_SECONDS 1000000.0f

// Function prototypes
void initialize_ultrasonic_sensor(void);
float measure_distance_cm(void);

/**
 * @brief Initializes the GPIO pins for the ultrasonic sensor.
 */
void initialize_ultrasonic_sensor(void) {
    // Set GPIO pins to their respective modes
    pinMode(ECHO_PIN, INPUT);   // Echo pin is an input
    pinMode(TRIGGER_PIN, OUTPUT); // Trigger pin is an output

    // Ensure trigger pin is initially low
    digitalWrite(TRIGGER_PIN, LOW);
    delay(100); // Short delay to settle
}

/**
 * @brief Measures the distance in centimeters using the ultrasonic sensor.
 * @return The measured distance in centimeters, or -1.0 on error.
 */
float measure_distance_cm(void) {
    struct timeval start_time, end_time;
    long start_us, end_us, duration_us;
    float distance_cm;

    // Trigger the ultrasonic pulse
    digitalWrite(TRIGGER_PIN, LOW);
    delayMicroseconds(2);
    digitalWrite(TRIGGER_PIN, HIGH);
    delayMicroseconds(10);
    digitalWrite(TRIGGER_PIN, LOW);

    // Measure the echo pulse duration
    while (digitalRead(ECHO_PIN) == LOW) {
        if (gettimeofday(&start_time, NULL) == -1) {
            perror("gettimeofday start");
            return -1.0f; // Indicate error
        }
    }

    while (digitalRead(ECHO_PIN) == HIGH) {
        if (gettimeofday(&end_time, NULL) == -1) {
            perror("gettimeofday end");
            return -1.0f; // Indicate error
        }
    }

    // Calculate the duration of the echo pulse
    start_us = (start_time.tv_sec * 1000000) + start_time.tv_usec;
    end_us = (end_time.tv_sec * 1000000) + end_time.tv_usec;
    duration_us = end_us - start_us;

    // Calculate the distance in centimeters
    distance_cm = (float)duration_us / MICROSECONDS_TO_SECONDS * SOUND_SPEED_CM_PER_S / 2.0f;

    return distance_cm;
}

int main(void) {
    float distance;

    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return 1; // Exit if initialization fails
    }

    // Initialize the ultrasonic sensor
    initialize_ultrasonic_sensor();

    // Main loop
    while (1) {
        distance = measure_distance_cm();

        if (distance >= 0.0f) {
            // Print the measured distance
            printf("Distance: %.2f cm\n", distance);
        } else {
            fprintf(stderr, "Error measuring distance.\n");
        }

        delay(100); // Delay between measurements
    }

    return 0;
}

