// Global variables
static volatile int running = 1;
FILE *log_file = NULL;
float sensor_resistance_in_clean_air = 10.0; //kOhm, adjust based on MQ-3 datasheet and calibration

// Function prototypes
int spi_read_adc(int channel);
float calculate_alcohol_concentration(int adc_value);
int log_reading(float alcohol_concentration);
void control_buzzer(float alcohol_concentration);
void handle_signal(int sig);
float moving_average(int new_value);

// Circular buffer for moving average filter
int samples[NUM_SAMPLES];
int sample_index = 0;
int samples_filled = 0;


int main(void) {
