        if (adc_value < 0) {
            fprintf(stderr, "Error reading ADC value\n");
            delay(1000); // Wait before retrying
            continue;
        }

        // Calculate alcohol concentration
        float alcohol_concentration = calculate_alcohol_concentration(adc_value);

        // Apply moving average filter
        float filtered_concentration = moving_average(adc_value);

