#define MOTION_GPIO 17
#define BUZZER_GPIO 18

// Function to write to a file
int write_to_file(const char *path, const char *value) {
    int fd = open(path, O_WRONLY);
    if (fd < 0) {
        perror("Error opening file");
        return -1;
    }
    ssize_t bytes_written = write(fd, value, strlen(value));
    if (bytes_written < 0) {
        perror("Error writing to file");
        close(fd);
        return -1;
    }
    close(fd);
    return 0;
}

// Function to read from a file
int read_from_file(const char *path, char *buffer, size_t buffer_size) {
    int fd = open(path, O_RDONLY);
    if (fd < 0) {
        perror("Error opening file for reading");
        return -1;
    }
    ssize_t bytes_read = read(fd, buffer, buffer_size - 1);
    if (bytes_read < 0) {
        perror("Error reading from file");
        close(fd);
        return -1;
    }
    buffer[bytes_read] = '\0'; // Null-terminate the buffer
    close(fd);
    return 0;
}

// Function to export a GPIO
int export_gpio(int gpio) {
    char gpio_str[3];
    snprintf(gpio_str, sizeof(gpio_str), "%d", gpio);
    return write_to_file("/sys/class/gpio/export", gpio_str);
}

// Function to unexport a GPIO
int unexport_gpio(int gpio) {
    char gpio_str[3];
    snprintf(gpio_str, sizeof(gpio_str), "%d", gpio);
    return write_to_file("/sys/class/gpio/unexport", gpio_str);
}

// Function to set GPIO direction (in or out)
int set_gpio_direction(int gpio, const char *direction) {
    char path[50];
    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/direction", gpio);
    return write_to_file(path, direction);
}

// Function to read GPIO value
int read_gpio_value(int gpio) {
    char path[50];
    char value_str[3];
    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", gpio);
    if (read_from_file(path, value_str, sizeof(value_str)) != 0) {
        return -1;
    }
    return atoi(value_str);
}

// Function to write GPIO value
int write_gpio_value(int gpio, int value) {
    char path[50];
    char value_str[2];
    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", gpio);
    snprintf(value_str, sizeof(value_str), "%d", value);
    return write_to_file(path, value_str);
}

// Function to check if the current time is within the night mode hours (22:00 - 06:00)
int is_night_mode() {
    time_t rawtime;
    struct tm *timeinfo;
    time(&rawtime);
    timeinfo = localtime(&rawtime);

    int hour = timeinfo->tm_hour;

    return (hour >= 22 || hour < 6);
}

// Function to unexport GPIOs on exit
void cleanup() {
    unexport_gpio(MOTION_GPIO);
    unexport_gpio(BUZZER_GPIO);
    printf("GPIOs unexported.\n");
}

int main() {
    // Register the cleanup function to be called on exit
    if (atexit(cleanup) != 0) {
        perror("Failed to register cleanup function");
        return 1;
    }

    // Export GPIOs
    if (export_gpio(MOTION_GPIO) != 0) return 1;
    if (export_gpio(BUZZER_GPIO) != 0) return 1;

    // Set GPIO direction
    if (set_gpio_direction(MOTION_GPIO, "in") != 0) return 1;
    if (set_gpio_direction(BUZZER_GPIO, "out") != 0) return 1;

    printf("Motion detection started. Press Ctrl+C to exit.\n");

    while (1) {
        // Read motion sensor value
        int motion_detected = read_gpio_value(MOTION_GPIO);
        if (motion_detected < 0) {
            fprintf(stderr, "Error reading motion sensor value. Exiting.\n");
            break;
        }

        // Check for motion and night mode
        if (motion_detected == 1 && is_night_mode()) {
            // Activate buzzer
            if (write_gpio_value(BUZZER_GPIO, 1) != 0) {
                fprintf(stderr, "Error activating buzzer.\n");
            }
            printf("Motion detected! Buzzer activated.\n");
            sleep(1); // Buzzer on for 1 second
            if (write_gpio_value(BUZZER_GPIO, 0) != 0) {
                fprintf(stderr, "Error deactivating buzzer.\n");
            }
            sleep(5); // Wait 5 seconds before checking again
        } else {
            // No motion or not night mode
            sleep(1); // Check every 1 second
        }
    }

    return 0;
}

