#define LED_PIN 1   // WiringPi pin 1 (GPIO18)

// Function prototypes
void motionDetected(void);
void blinkLED(void);
void signalHandler(int signal);

// Global variables
volatile sig_atomic_t programRunning = 1;

// Function to blink the LED for 5 seconds
void blinkLED(void) {
    digitalWrite(LED_PIN, HIGH); // Turn LED on
    delay(5000);                 // Wait for 5 seconds
    digitalWrite(LED_PIN, LOW);  // Turn LED off
}

// Interrupt handler function for motion detection
void motionDetected(void) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    // Get current time
    time(&rawtime);
    timeinfo = localtime(&rawtime);

    // Format timestamp
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    // Log timestamp to file
    FILE *fp = fopen("motion_log.txt", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening motion_log.txt for writing!\n");
        perror("fopen");
        return;
    }

    if (fprintf(fp, "%s\n", timestamp) < 0) {
        fprintf(stderr, "Error writing to motion_log.txt!\n");
        fclose(fp);
        return;
    }

    if (fclose(fp) != 0) {
        fprintf(stderr, "Error closing motion_log.txt!\n");
        return;
    }

    printf("Motion detected at: %s\n", timestamp);

    // Blink the LED
    blinkLED();
}

// Signal handler function for Ctrl+C
void signalHandler(int signal) {
    printf("Caught signal %d\n", signal);
    programRunning = 0;

    // Disable interrupt handler
    wiringPiISR(PIR_PIN, INT_EDGE_RISING, NULL);

    // Turn off LED
    digitalWrite(LED_PIN, LOW);

    printf("Clean exit.\n");
    exit(0);
}

int main(void) {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error initializing wiringPi!\n");
        return 1;
    }

    // Configure PIR pin as input with pull-down resistor
    pinMode(PIR_PIN, INPUT);
    pullUpDnControl(PIR_PIN, PUD_DOWN);

    // Configure LED pin as output
    pinMode(LED_PIN, OUTPUT);

    // Register interrupt handler for motion detection
    if (wiringPiISR(PIR_PIN, INT_EDGE_RISING, motionDetected) < 0) {
        fprintf(stderr, "Error setting up interrupt handler!\n");
        return 1;
    }

    // Register signal handler for Ctrl+C
    signal(SIGINT, signalHandler);

    printf("Motion detection system running. Press Ctrl+C to exit.\n");

    // Main loop
    while (programRunning) {
        delay(100); // Minimal delay to avoid excessive CPU usage
    }

    return 0;
}

