    if (wiringPiISR(LOW_POWER_PIN, INT_EDGE_FALLING, &lowPowerDetected) != 0) {
        fprintf(stderr, "Error attaching interrupt: %s\n", strerror(errno));
        return 1; // Exit with an error code
    }

