    while (1) {
        delay(1000); // Delay for 1 second (adjust as needed)
    }

    return 0; // Exit normally (shouldn't reach here in this example)
}

// Interrupt service routine (ISR) for low power detection
void lowPowerDetected(void) {
    char timestampBuffer[TIMESTAMP_BUFFER_SIZE];

    // Get the current timestamp
    if (getCurrentTimestamp(timestampBuffer, TIMESTAMP_BUFFER_SIZE) == NULL) {
        fprintf(stderr, "Error getting timestamp.\n");
        return; // Exit the ISR if timestamp retrieval fails
    }

    // Log the low power detection event with the timestamp
    printf("%s: LOW POWER DETECTED on GPIO %d\n", timestampBuffer, LOW_POWER_PIN);
    fflush(stdout); // Ensure the output is immediately written to the console/log
}

// Function to get the current timestamp as a string
char* getCurrentTimestamp(char* timestampBuffer, size_t bufferSize) {
    time_t rawtime;
    struct tm* timeinfo;

    // Get the current time
    time(&rawtime);
    timeinfo = localtime(&rawtime);

    // Check for errors
    if (timeinfo == NULL) {
        perror("localtime");
        return NULL;
    }

    // Format the timestamp string
    if (strftime(timestampBuffer, bufferSize, "%Y-%m-%d %H:%M:%S", timeinfo) == 0) {
        fprintf(stderr, "Error formatting timestamp.\n");
        return NULL;
    }

    return timestampBuffer;
}

#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>

// Define GPIO pins for trigger and echo
#define TRIGGER_PIN 17
#define ECHO_PIN 18

// Speed of sound in air (343 m/s) converted to cm/us
#define SOUND_SPEED 0.0343

// Threshold distance for warning (20 cm)
#define WARNING_DISTANCE 20.0

// Global variables to store the start and end times of the echo pulse
static volatile uint32_t start_time = 0;
static volatile uint32_t end_time = 0;

// Callback function for echo pin changes
void echo_callback(int gpio, int level, uint32_t tick, void *user)
{
    if (gpio == ECHO_PIN)
    {
        if (level == 1) // Rising edge
        {
            start_time = tick;
        } else if (level == 0) // Falling edge
        {
            end_time = tick;

            // Calculate pulse width in microseconds
            uint32_t pulse_width = end_time - start_time;

            // Calculate distance in centimeters
            float distance = (pulse_width * SOUND_SPEED) / 2.0;

            // Check if distance is below the warning threshold
            if (distance < WARNING_DISTANCE)
            {
                printf("Warning: Obstacle detected within 20cm! Distance: %.2f cm\n", distance);
            }
            else
            {
                printf("Distance: %.2f cm\n", distance);
            }
        }
    }
}

int main()
{
    // Initialize the pigpio library
    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO17 (trigger) as output
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);

    // Set GPIO18 (echo) as input
    gpioSetMode(ECHO_PIN, PI_INPUT);

    // Register callback function for echo pin changes
    gpioSetAlertFuncEx(ECHO_PIN, echo_callback, NULL);

    // Main loop to continuously trigger the sensor
    while (1)
    {
        // Trigger the sensor with a 10us pulse
        gpioWrite(TRIGGER_PIN, 1);
        gpioDelay(10); // Wait for 10 microseconds
        gpioWrite(TRIGGER_PIN, 0);

        // Wait for a short period before the next trigger (e.g., 50ms)
        gpioDelay(50000); // 50ms delay
    }

    // Terminate the pigpio library (this will never be reached in this example)
    gpioTerminate();

    return 0;
}

