#include <stdio.h>
#include <wiringPiI2C.h>
#include <wiringPi.h>
#include <stdint.h>
#include <unistd.h>

// ADS1115 I2C Address (default)
#define ADS1115_I2C_ADDR 0x48

// ADS1115 Register Addresses
#define ADS1115_REG_CONVERT 0x00
#define ADS1115_REG_CONFIG  0x01

// Configuration Register Settings
#define ADS1115_CONFIG_OS_SINGLE      0x8000  // Start single conversion
#define ADS1115_CONFIG_MUX_SINGLE_0   0x4000  // AIN0 to GND
#define ADS1115_CONFIG_PGA_4_096V     0x0000  // +/-4.096V range
#define ADS1115_CONFIG_MODE_SINGLE    0x0100  // Single-shot mode
#define ADS1115_CONFIG_DR_128SPS      0x0080  // 128 SPS
#define ADS1115_CONFIG_COMP_MODE_TRAD  0x0000  // Traditional comparator
#define ADS1115_CONFIG_COMP_POL_LOW    0x0000  // Active low comparator
#define ADS1115_CONFIG_COMP_LAT_NON    0x0000  // Non-latching comparator
#define ADS1115_CONFIG_COMP_QUE_DISABLE 0x0003  // Disable comparator

int main()
{
    int fd;
    int16_t adcValue;
    float voltage;

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed\n");
        return 1;
    }

    // Open I2C device
    fd = wiringPiI2CSetup(ADS1115_I2C_ADDR);
    if (fd == -1) {
        fprintf(stderr, "wiringPiI2CSetup failed\n");
        return 1;
    }

    // Configure ADS1115
    uint16_t config = ADS1115_CONFIG_OS_SINGLE | ADS1115_CONFIG_MUX_SINGLE_0 | ADS1115_CONFIG_PGA_4_096V |
                        ADS1115_CONFIG_MODE_SINGLE | ADS1115_CONFIG_DR_128SPS | ADS1115_CONFIG_COMP_MODE_TRAD |
                        ADS1115_CONFIG_COMP_POL_LOW | ADS1115_CONFIG_COMP_LAT_NON | ADS1115_CONFIG_COMP_QUE_DISABLE;

    wiringPiI2CWriteReg16(fd, ADS1115_REG_CONFIG, __builtin_bswap16(config));

    while (1) {
        // Wait for conversion to complete
        delay(100);

        // Read ADC value
        adcValue = __builtin_bswap16(wiringPiI2CReadReg16(fd, ADS1115_REG_CONVERT));

        // Calculate voltage (assuming +/-4.096V range)
        voltage = (float)adcValue * 4.096 / 32767.0;

        printf("ADC Value: %d, Voltage: %.3f V\n", adcValue, voltage);

        delay(500); // Delay between readings
    }

    return 0;
}

