#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <unistd.h>
#include <signal.h>

// Define GPIO pins
#define TRIGGER_PIN 23
#define ECHO_PIN 24
#define SERVO_PIN 17

// Function prototypes
void triggerSensor();
float getDistance();
void setServoAngle(int angle);
void cleanup(int signal);

// Global variable for graceful exit
volatile sig_atomic_t program_running = 1;

// Signal handler
void cleanup(int signal)
{
    program_running = 0;
    gpioTerminate();
    printf("\nProgram terminated gracefully.\n");
    exit(0);
}

// Function to trigger the ultrasonic sensor
void triggerSensor()
{
    gpioWrite(TRIGGER_PIN, 1);
    gpioDelay(10); // 10us trigger pulse
    gpioWrite(TRIGGER_PIN, 0);
}

// Function to measure distance using the ultrasonic sensor
float getDistance()
{
    long long start_tick, end_tick, diff_tick;

    gpioSetMode(ECHO_PIN, PI_INPUT);

    // Wait for the echo pin to go high (with timeout)
    int count = 0;
    while (gpioRead(ECHO_PIN) == 0 && count < 50000) // Timeout after 0.5 seconds
    {
        gpioDelay(10); //check every 10 us
        count++;
    }

    if (count >= 50000) {
        fprintf(stderr, "Timeout waiting for echo start.\n");
        return -1.0; // Timeout error
    }

    start_tick = gpioTick();

    // Wait for the echo pin to go low (with timeout)
    count = 0;
    while (gpioRead(ECHO_PIN) == 1 && count < 50000) // Timeout after 0.5 seconds
    {
        gpioDelay(10);
        count++;
    }

    if (count >= 50000) {
        fprintf(stderr, "Timeout waiting for echo end.\n");
        return -1.0; // Timeout error
    }

    end_tick = gpioTick();

    diff_tick = end_tick - start_tick;

    // Calculate distance in centimeters (speed of sound: 343 m/s)
    float distance = (float)diff_tick * 343.0 / 10000.0 / 2.0; // cm

    return distance;
}

// Function to set the servo angle
void setServoAngle(int angle)
{
    if (angle < 0) angle = 0;
    if (angle > 180) angle = 180;

    // Map angle (0-180) to pulse width (500-2500 us).  SG90 servo.
    int pulse_width = (int)(500.0 + (float)angle * (2000.0 / 180.0));

    gpioServo(SERVO_PIN, pulse_width);
}

int main()
{
    // Initialize pigpio
    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);
    gpioSetMode(SERVO_PIN, PI_OUTPUT);

    // Initialize trigger pin to low
    gpioWrite(TRIGGER_PIN, 0);

    // Set signal handler for Ctrl+C
    signal(SIGINT, cleanup);

    printf("Parking assist system running. Press Ctrl+C to exit.\n");

    while (program_running)
    {
        // Trigger the sensor
        triggerSensor();

        // Get the distance
        float distance = getDistance();

        if (distance < 0.0)
        {
            fprintf(stderr, "Sensor error. Retrying...\n");
        }
        else
        {
            printf("Distance: %.2f cm\n", distance);

            // Map distance to servo angle (20cm - 200cm -> 0 - 180 degrees)
            int angle = 0;
            if (distance <= 20) {
              angle = 180; //Very close
            } else if (distance >= 200) {
              angle = 0; //Far away
            } else {
              angle = (int)((200.0 - distance) / 180.0 * 100.0); //Inverted mapping
              angle = (int)(((distance - 20) / (200 - 20)) * 180); // Correct mapping
            }

            if (angle < 0) angle = 0;
            if (angle > 180) angle = 180;

            // Set the servo angle
            setServoAngle(angle);
        }

        // Delay before next measurement
        gpioDelay(100); // 100ms delay
    }

    return 0;
}

