#include <stdio.h>
#include <sys/ioctl.h>
#include <stdlib.h>
#include <math.h>

// Gertboard D to A is an 8-bit unit.

#define	B_SIZE	256

#include <wiringPi.h>
#include <gertboard.h>

int main (void)
{
  double angle ;
  int i, inputValue ;
  int  buffer [B_SIZE] ;
  int   cols ;
  struct winsize w ;


  printf ("Raspberry Pi Gertboard SPI test program\n") ;
  printf ("=======================================\n") ;

  ioctl (fileno (stdin), TIOCGWINSZ, &w);
  cols = w.ws_col - 2 ;

