// A 'key' which we can lock and unlock - values are 0 through 3
//	This is interpreted internally as a pthread_mutex by wiringPi
//	which is hiding some of that to make life simple.

#define	COUNT_KEY	0

// What BCM_GPIO input are we using?

#define	BUTTON_PIN	17

// Debounce time in mS

#define	DEBOUNCE_TIME	100


// globalCounter:
//	Global variable to count interrupts
//	Should be declared volatile to make sure the compiler doesn't cache it.

static volatile int globalCounter = 0 ;


/*
 * waitForIt:
 *	This is a thread created using the wiringPi simplified threading
 *	mechanism. It will wait on an interrupt on the button and increment
 *	a counter.
 *********************************************************************************
 */

PI_THREAD (waitForIt)
{
  int state = 0 ;
  int debounceTime = 0 ;

  (void)piHiPri (10) ;	// Set this thread to be high priority

  for (;;)
  {
    if (waitForInterrupt (BUTTON_PIN, -1) > 0)	// Got it
    {
// Bouncing?

      if (millis () < debounceTime)
      {
	debounceTime = millis () + DEBOUNCE_TIME ;
	continue ;
      }

// We have a valid one

      state ^= 1 ;

      piLock (COUNT_KEY) ;
	++globalCounter ;
      piUnlock (COUNT_KEY) ;

// Wait for key to be released

      while (digitalRead (BUTTON_PIN) == LOW)
	delay (1) ;

      debounceTime = millis () + DEBOUNCE_TIME ;
    }
  }
}


