   gpioSetAlertFunc(GPIO, callback); /* callback when GPIO changes state */

   while (1)
   {
      gpioWrite(GPIO, PI_OFF); /* drain capacitor */

      gpioDelay(200); /* microseconds */

      t1 = gpioTick();

      gpioSetMode(GPIO, PI_INPUT); /* start capacitor recharge */

      t2 = gpioTick();

